export interface ApocryphaVerseSeed { book: string; chapter: number; verse: number; text: string }

export const APOCRYPHA_FETCHED_VERSES: ApocryphaVerseSeed[] = [
  // 1 Enoch (1048 verses)
  { book: "1 Enoch", chapter: 1, verse: 1, text: "The words of the blessing of Enoch, wherewith he blessed the elect and righteous, who will be living in the day of tribulation, when all the wicked and godless are to be removed." },
  { book: "1 Enoch", chapter: 1, verse: 2, text: "And he took up his parable and said--Enoch a righteous man, whose eyes were opened by God, saw the vision of the Holy One in the heavens, which the angels showed me, and from them I heard everything, and from them I understood as I saw, but not for this generation, but for a remote one which is for to come." },
  { book: "1 Enoch", chapter: 1, verse: 3, text: "Concerning the elect I said, and took up my parable concerning them: \n\nThe Holy Great One will come forth from His dwelling," },
  { book: "1 Enoch", chapter: 1, verse: 4, text: "And the eternal God will tread upon the earth, (even) on Mount Sinai, And appear from His camp \nAnd appear in the strength of His might from the heaven of heavens." },
  { book: "1 Enoch", chapter: 1, verse: 5, text: "And all shall be smitten with fear \nAnd the Watchers shall quake, \nAnd great fear and trembling shall seize them unto the ends of the earth." },
  { book: "1 Enoch", chapter: 1, verse: 6, text: "And the high mountains shall be shaken, \nAnd the high hills shall be made low, \nAnd shall melt like wax before the flame" },
  { book: "1 Enoch", chapter: 1, verse: 7, text: "And the earth shall be wholly rent in sunder, \nAnd all that is upon the earth shall perish, \nAnd there shall be a judgement upon all (men)." },
  { book: "1 Enoch", chapter: 1, verse: 8, text: "But with the righteous He will make peace.\nAnd will protect the elect, \nAnd mercy shall be upon them.\n\nAnd they shall all belong to God, \nAnd they shall be prospered, \nAnd they shall all be blessed.\n\nAnd He will help them all, \nAnd light shall appear unto them, \nAnd He will make peace with them." },
  { book: "1 Enoch", chapter: 1, verse: 9, text: "And behold! He cometh with ten thousands of His holy ones \nTo execute judgement upon all, \nAnd to destroy all the ungodly:\n\nAnd to convict all flesh \nOf all the works of their ungodliness which they have ungodly committed, \nAnd of all the hard things which ungodly sinners have spoken against Him." },
  { book: "1 Enoch", chapter: 2, verse: 1, text: "Observe ye everything that takes place in the heaven, how they do not change their orbits, and the luminaries which are in the heaven, how they all rise and set in order each in its season, and transgress not against their appointed order." },
  { book: "1 Enoch", chapter: 2, verse: 2, text: "Behold ye the earth, and give heed to the things which take place upon it from first to last, how steadfast they are, how none of the things upon earth change, but all the works of God appear to you." },
  { book: "1 Enoch", chapter: 2, verse: 3, text: "Behold the summer and the winter, how the whole earth is filled with water, and clouds and dew and rain lie upon it." },
  { book: "1 Enoch", chapter: 3, verse: 1, text: "Observe and see how (in the winter) all the trees seem as though they had withered and shed all their leaves, except fourteen trees, which do not lose their foliage but retain the old foliage from two to three years till the new comes." },
  { book: "1 Enoch", chapter: 4, verse: 1, text: "And again, observe ye the days of summer how the sun is above the earth over against it. And you seek shade and shelter by reason of the heat of the sun, and the earth also burns with growing heat, and so you cannot tread on the earth, or on a rock by reason of its heat." },
  { book: "1 Enoch", chapter: 5, verse: 1, text: "Observe ye how the trees cover themselves with green leaves and bear fruit: wherefore give ye heed and know with regard to all His works, and recognize how He that liveth for ever hath made them so." },
  { book: "1 Enoch", chapter: 5, verse: 2, text: "And all His works go on thus from year to year for ever, and all the tasks which they accomplish for Him, and ⌈their tasks⌉ change not, but according as God hath ordained so is it done." },
  { book: "1 Enoch", chapter: 5, verse: 3, text: "And behold how the sea and the rivers in like manner accomplish and change not their tasks from His commandments." },
  { book: "1 Enoch", chapter: 5, verse: 4, text: "But ye--ye have not been steadfast, nor done the commandments of the Lord, \nBut ye have turned away and spoken proud and hard words \nWith your impure mouths against His greatness. Oh, ye hard-hearted, ye shall find no peace." },
  { book: "1 Enoch", chapter: 5, verse: 5, text: "Therefore shall ye execrate your days, \nAnd the years of your life shall perish, \nAnd the years of your destruction shall be multiplied in eternal execration, \nAnd ye shall find no mercy.\n\n[5:6a] In those days ye shall make your names an eternal execration unto all the righteous, \nb. And by you shall all who curse, curse, \nAnd all the sinners and godless shall imprecate by you, \n[5:7c] And for you the godless there shall be a curse.\n\n[5:6d] And all the . . . shall rejoice, \ne. And there shall be forgiveness of sins, \nf. And every mercy and peace and forbearance: \ng. There shall be salvation unto them, a goodly light. \n\ni. And for all of you sinners there shall be no salvation, \nj But on you all shall abide a curse. \n[5:7a] But for the elect there shall be light and joy and peace, \nb. And they shall inherit the earth." },
  { book: "1 Enoch", chapter: 5, verse: 8, text: "And then there shall be bestowed upon the elect wisdom, \nAnd they shall all live and never again sin, \nEither through ungodliness or through pride: \nBut they who are wise shall be humble." },
  { book: "1 Enoch", chapter: 5, verse: 9, text: "And they shall not again transgress, \nNor shall they sin all the days of their life, \nNor shall they die of (the divine) anger or wrath, \nBut they shall complete the number of the days of their life.\n\nAnd their lives shall be increased in peace, \nAnd the years of their joy shall be multiplied, \nIn eternal gladness and peace, \nAll the days of their life." },
  { book: "1 Enoch", chapter: 6, verse: 1, text: "And it came to pass when the children of men had multiplied that in those days were born unto them beautiful and comely daughters." },
  { book: "1 Enoch", chapter: 6, verse: 2, text: "And the angels, the children of the heaven, saw and lusted after them, and said to one another: 'Come, let us choose us wives from among the children of men and beget us children.'" },
  { book: "1 Enoch", chapter: 6, verse: 3, text: "And Semjâzâ, who was their leader, said unto them: 'I fear ye will not indeed agree to do this deed, and I alone shall have to pay the penalty of a great sin.'" },
  { book: "1 Enoch", chapter: 6, verse: 4, text: "And they all answered him and said: 'Let us all swear an oath, and all bind ourselves by mutual imprecations not to abandon this plan but to do this thing.'" },
  { book: "1 Enoch", chapter: 6, verse: 5, text: "Then sware they all together and bound themselves by mutual imprecations upon it." },
  { book: "1 Enoch", chapter: 6, verse: 6, text: "And they were in all two hundred; who descended in the days of Jared on the summit of Mount Hermon, and they called it Mount Hermon, because they had sworn and bound themselves by mutual imprecations upon it." },
  { book: "1 Enoch", chapter: 6, verse: 7, text: "And these are the names of their leaders: Sêmîazâz, their leader, Arâkîba, Râmêêl, Kôkabîêl, Tâmîêl, Râmîêl, Dânêl, Êzêqêêl, Barâqîjâl, Asâêl, Armârôs, Batârêl, Anânêl, Zaqîêl, Samsâpêêl, Satarêl, Tûrêl, Jômjâêl, Sariêl." },
  { book: "1 Enoch", chapter: 6, verse: 8, text: "These are their chiefs of tens." },
  { book: "1 Enoch", chapter: 7, verse: 1, text: "And all the others together with them took unto themselves wives, and each chose for himself one, and they began to go in unto them and to defile themselves with them, and they taught them charms and enchantments, and the cutting of roots, and made them acquainted with plants." },
  { book: "1 Enoch", chapter: 7, verse: 2, text: "And they became pregnant, and they bare great giants, whose height was three thousand ells:" },
  { book: "1 Enoch", chapter: 7, verse: 3, text: "Who consumed all the acquisitions of men. And when men could no longer sustain them," },
  { book: "1 Enoch", chapter: 7, verse: 4, text: "the giants turned against them and devoured mankind." },
  { book: "1 Enoch", chapter: 7, verse: 5, text: "And they began to sin against birds, and beasts, and reptiles, and fish, and to devour one another's flesh, and drink the blood." },
  { book: "1 Enoch", chapter: 7, verse: 6, text: "Then the earth laid accusation against the lawless ones." },
  { book: "1 Enoch", chapter: 8, verse: 1, text: "And Azâzêl taught men to make swords, and knives, and shields, and breastplates, and made known to them the metals of the earth and the art of working them, and bracelets, and ornaments, and the use of antimony, and the beautifying of the eyelids, and all kinds of costly stones, and all colouring tinctures." },
  { book: "1 Enoch", chapter: 8, verse: 2, text: "And there arose much godlessness, and they committed fornication, and they were led astray, and became corrupt in all their ways. Semjâzâ taught enchantments, and root-cuttings, Armârôs the resolving of enchantments, Barâqîjâl, (taught) astrology, Kôkabêl the constellations, Ezêqêêl the knowledge of the clouds, Araqiêl the signs of the earth, Shamsiêl the signs of the sun, and Sariêl the course of the moon. And as men perished, they cried, and their cry went up to heaven . . ." },
  { book: "1 Enoch", chapter: 9, verse: 1, text: "And then Michael, Uriel, Raphael, and Gabriel looked down from heaven and saw much blood being shed upon the earth, and all lawlessness being wrought upon the earth." },
  { book: "1 Enoch", chapter: 9, verse: 2, text: "And they said one to another: 'The earth made without inhabitant cries the voice of their crying up to the gates of heaven." },
  { book: "1 Enoch", chapter: 9, verse: 3, text: "And now to you, the holy ones of heaven, the souls of men make their suit, saying, \"Bring our cause before the Most High.\".'" },
  { book: "1 Enoch", chapter: 9, verse: 4, text: "And they said to the Lord of the ages: 'Lord of lords, God of gods, King of kings, and God of the ages, the throne of Thy glory (standeth) unto all the generations of the ages, and Thy name holy and glorious and blessed unto all the ages!" },
  { book: "1 Enoch", chapter: 9, verse: 5, text: "Thou hast made all things, and power over all things hast Thou: and all things are naked and open in Thy sight, and Thou seest all things, and nothing can hide itself from Thee." },
  { book: "1 Enoch", chapter: 9, verse: 6, text: "Thou seest what Azâzêl hath done, who hath taught all unrighteousness on earth and revealed the eternal secrets which were (preserved) in heaven, which men were striving to learn:" },
  { book: "1 Enoch", chapter: 9, verse: 7, text: "And Semjâzâ, to whom Thou hast given authority to bear rule over his associates." },
  { book: "1 Enoch", chapter: 9, verse: 8, text: "And they have gone to the daughters of men upon the earth, and have slept with the women, and have defiled themselves, and revealed to them all kinds of sins." },
  { book: "1 Enoch", chapter: 9, verse: 9, text: "And the women have borne giants, and the whole earth has thereby been filled with blood and unrighteousness." },
  { book: "1 Enoch", chapter: 9, verse: 10, text: "And now, behold, the souls of those who have died are crying and making their suit to the gates of heaven, and their lamentations have ascended: and cannot cease because of the lawless deeds which are wrought on the earth." },
  { book: "1 Enoch", chapter: 9, verse: 11, text: "And Thou knowest all things before they come to pass, and Thou seest these things and Thou dost suffer them, and Thou dost not say to us what we are to do to them in regard to these.'" },
  { book: "1 Enoch", chapter: 10, verse: 1, text: "Then said the Most High, the Holy and Great One spake, and sent Uriel to the son of Lamech, and said to him:" },
  { book: "1 Enoch", chapter: 10, verse: 2, text: "'Go to Noah and tell him in my name \"Hide thyself!\" and reveal to him the end that is approaching: that the whole earth will be destroyed, and a deluge is about to come upon the whole earth, and will destroy all that is on it." },
  { book: "1 Enoch", chapter: 10, verse: 3, text: "And now instruct him that he may escape and his seed may be preserved for all the generations of the world.'" },
  { book: "1 Enoch", chapter: 10, verse: 4, text: "And again the Lord said to Raphael: 'Bind Azâzêl hand and foot, and cast him into the darkness: and make an opening in the desert, which is in Dûdâêl, and cast him therein." },
  { book: "1 Enoch", chapter: 10, verse: 5, text: "And place upon him rough and jagged rocks, and cover him with darkness, and let him abide there for ever, and cover his face that he may not see light." },
  { book: "1 Enoch", chapter: 10, verse: 6, text: "And on the day of the great judgement he shall be cast into the fire. And heal the earth which the angels have corrupted, and proclaim the healing of the earth, that they may heal the plague, and that all the children of men may not perish through all the secret things that the Watchers have disclosed and have taught their sons." },
  { book: "1 Enoch", chapter: 10, verse: 8, text: "And the whole earth has been corrupted through the works that were taught by Azâzêl: to him ascribe all sin.'" },
  { book: "1 Enoch", chapter: 10, verse: 9, text: "And to Gabriel said the Lord: 'Proceed against the bastards and the reprobates, and against the children of fornication: and destroy the children of fornication and the children of the Watchers from amongst men and cause them to go forth: send them one against the other that they may destroy each other in battle: for length of days shall they not have." },
  { book: "1 Enoch", chapter: 10, verse: 10, text: "And no request that they (i.e. their fathers) make of thee shall be granted unto their fathers on their behalf; for they hope to live an eternal life, and that each one of them will live five hundred years.'" },
  { book: "1 Enoch", chapter: 10, verse: 11, text: "And the Lord said unto Michael: 'Go, bind Semjâzâ and his associates who have united themselves with women so as to have defiled themselves with them in all their uncleanness." },
  { book: "1 Enoch", chapter: 10, verse: 12, text: "And when their sons have slain one another, and they have seen the destruction of their beloved ones, bind them fast for seventy generations in the valleys of the earth, till the day of their judgement and of their consummation, till the judgement that is for ever and ever is consummated." },
  { book: "1 Enoch", chapter: 10, verse: 13, text: "In those days they shall be led off to the abyss of fire: and to the torment and the prison in which they shall be confined for ever. And whosoever shall be condemned and destroyed will from thenceforth be bound together with them to the end of all generations." },
  { book: "1 Enoch", chapter: 10, verse: 15, text: "And destroy all the spirits of the reprobate and the children of the Watchers, because they have wronged mankind. Destroy all wrong from the face of the earth and let every evil work come to an end: and let the plant of righteousness and truth appear: and it shall prove a blessing; the works of righteousness and truth shall be planted in truth and joy for evermore." },
  { book: "1 Enoch", chapter: 10, verse: 17, text: "And then shall all the righteous escape, \nAnd shall live till they beget thousands of children, \nAnd all the days of their youth and their old age shall they complete in peace." },
  { book: "1 Enoch", chapter: 10, verse: 18, text: "And then shall the whole earth be tilled in righteousness, and shall all be planted with trees and be full of blessing." },
  { book: "1 Enoch", chapter: 10, verse: 19, text: "And all desirable trees shall be planted on it, and they shall plant vines on it: and the vine which they plant thereon shall yield wine in abundance, and as for all the seed which is sown thereon each measure (of it) shall bear a thousand, and each measure of olives shall yield ten presses of oil." },
  { book: "1 Enoch", chapter: 10, verse: 20, text: "And cleanse thou the earth from all oppression, and from all unrighteousness, and from all sin, and from all godlessness: and all the uncleanness that is wrought upon the earth destroy from off the earth." },
  { book: "1 Enoch", chapter: 10, verse: 21, text: "And all the children of men shall become righteous, and all nations shall offer adoration and shall praise Me, and all shall worship Me. And the earth shall be cleansed from all defilement, and from all sin, and from all punishment, and from all torment, and I will never again send (them) upon it from generation to generation and for ever." },
  { book: "1 Enoch", chapter: 11, verse: 1, text: "And in those days I will open the store chambers of blessing which are in the heaven, so as to send them down upon the earth over the work and labour of the children of men." },
  { book: "1 Enoch", chapter: 11, verse: 2, text: "And truth and peace shall be associated together throughout all the days of the world and throughout all the generations of men.'" },
  { book: "1 Enoch", chapter: 12, verse: 1, text: "Before these things Enoch was hidden, and no one of the children of men knew where he was hidden, and where he abode, and what had become of him." },
  { book: "1 Enoch", chapter: 12, verse: 2, text: "And his activities had to do with the Watchers, and his days were with the holy ones." },
  { book: "1 Enoch", chapter: 12, verse: 3, text: "And I, Enoch was blessing the Lord of majesty and the King of the ages, and lo! the Watchers called me--Enoch the scribe--and said to me:" },
  { book: "1 Enoch", chapter: 12, verse: 4, text: "'Enoch, thou scribe of righteousness, go, declare to the Watchers of the heaven who have left the high heaven, the holy eternal place, and have defiled themselves with women, and have done as the children of earth do, and have taken unto themselves wives: \"Ye have wrought great destruction on the earth:" },
  { book: "1 Enoch", chapter: 12, verse: 5, text: "And ye shall have no peace nor forgiveness of sin: and inasmuch as they delight themselves in their children," },
  { book: "1 Enoch", chapter: 12, verse: 6, text: "The murder of their beloved ones shall they see, and over the destruction of their children shall they lament, and shall make supplication unto eternity, but mercy and peace shall ye not attain.\"'" },
  { book: "1 Enoch", chapter: 13, verse: 1, text: "And Enoch went and said: 'Azâzêl, thou shalt have no peace: a severe sentence has gone forth against thee to put thee in bonds:" },
  { book: "1 Enoch", chapter: 13, verse: 2, text: "And thou shalt not have toleration nor †request† granted to thee, because of the unrighteousness which thou hast taught, and because of all the works of godlessness and unrighteousness and sin which thou hast shown to men.'" },
  { book: "1 Enoch", chapter: 13, verse: 3, text: "Then I went and spoke to them all together, and they were all afraid, and fear and trembling seized them." },
  { book: "1 Enoch", chapter: 13, verse: 4, text: "And they besought me to draw up a petition for them that they might find forgiveness, and to read their petition in the presence of the Lord of heaven." },
  { book: "1 Enoch", chapter: 13, verse: 5, text: "For from thenceforward they could not speak (with Him) nor lift up their eyes to heaven for shame of their sins for which they had been condemned." },
  { book: "1 Enoch", chapter: 13, verse: 6, text: "Then I wrote out their petition, and the prayer in regard to their spirits and their deeds individually and in regard to their requests that they should have forgiveness and length of days." },
  { book: "1 Enoch", chapter: 13, verse: 7, text: "And I went off and sat down at the waters of Dan, in the land of Dan, to the south of the west of Hermon: I read their petition till I fell asleep." },
  { book: "1 Enoch", chapter: 13, verse: 8, text: "And behold a dream came to me, and visions fell down upon me, and I saw visions of chastisement, and a voice came bidding (me) I to tell it to the sons of heaven, and reprimand them." },
  { book: "1 Enoch", chapter: 13, verse: 9, text: "And when I awaked, I came unto them, and they were all sitting gathered together, weeping in 'Abelsjâîl, which is between Lebanon and Sênêsêr, with their faces covered." },
  { book: "1 Enoch", chapter: 13, verse: 10, text: "And I recounted before them all the visions which I had seen in sleep, and I began to speak the words of righteousness, and to reprimand the heavenly Watchers." },
  { book: "1 Enoch", chapter: 14, verse: 1, text: "The book of the words of righteousness, and of the reprimand of the eternal Watchers in accordance with the command of the Holy Great One in that vision." },
  { book: "1 Enoch", chapter: 14, verse: 2, text: "I saw in my sleep what I will now say with a tongue of flesh and with the breath of my mouth: which the Great One has given to men to converse therewith and understand with the heart." },
  { book: "1 Enoch", chapter: 14, verse: 3, text: "As He has created and given to man the power of understanding the word of wisdom, so hath He created me also and given me the power of reprimanding the Watchers, the children of heaven." },
  { book: "1 Enoch", chapter: 14, verse: 4, text: "I wrote out your petition, and in my vision it appeared thus, that your petition will not be granted unto you throughout all the days of eternity, and that judgement has been finally passed upon you: yea (your petition) will not be granted unto you." },
  { book: "1 Enoch", chapter: 14, verse: 5, text: "And from henceforth you shall not ascend into heaven unto all eternity, and in bonds of the earth the decree has gone forth to bind you for all the days of the world." },
  { book: "1 Enoch", chapter: 14, verse: 6, text: "And (that) previously you shall have seen the destruction of your beloved sons and ye shall have no pleasure in them, but they shall fall before you by the sword." },
  { book: "1 Enoch", chapter: 14, verse: 7, text: "And your petition on their behalf shall not be granted, nor yet on your own: even though you weep and pray and speak all the words contained in the writing which I have written." },
  { book: "1 Enoch", chapter: 14, verse: 8, text: "And the vision was shown to me thus: Behold, in the vision clouds invited me and a mist summoned me, and the course of the stars and the lightnings sped and hastened me, and the winds in the vision caused me to fly and lifted me upward, and bore me into heaven." },
  { book: "1 Enoch", chapter: 14, verse: 9, text: "And I went in till I drew nigh to a wall which is built of crystals and surrounded by tongues of fire: and it began to affright me. And I went into the tongues of fire and drew nigh to a large house which was built of crystals: and the walls of the house were like a tesselated floor (made) of crystals, and its groundwork was of crystal." },
  { book: "1 Enoch", chapter: 14, verse: 11, text: "Its ceiling was like the path of the stars and the lightnings, and between them were fiery cherubim, and their heaven was (clear as) water." },
  { book: "1 Enoch", chapter: 14, verse: 12, text: "A flaming fire surrounded the walls, and its portals blazed with fire." },
  { book: "1 Enoch", chapter: 14, verse: 13, text: "And I entered into that house, and it was hot as fire and cold as ice: there were no delights of life therein: fear covered me, and trembling got hold upon me." },
  { book: "1 Enoch", chapter: 14, verse: 14, text: "And as I quaked and trembled, I fell upon my face." },
  { book: "1 Enoch", chapter: 14, verse: 15, text: "And I beheld a vision, And lo! there was a second house, greater than the former, and the entire portal stood open before me, and it was built of flames of fire." },
  { book: "1 Enoch", chapter: 14, verse: 16, text: "And in every respect it so excelled in splendour and magnificence and extent that I cannot describe to you its splendour and its extent." },
  { book: "1 Enoch", chapter: 14, verse: 17, text: "And its floor was of fire, and above it were lightnings and the path of the stars, and its ceiling also was flaming fire." },
  { book: "1 Enoch", chapter: 14, verse: 18, text: "And I looked and saw therein a lofty throne: its appearance was as crystal, and the wheels thereof as the shining sun, and there was the vision of cherubim." },
  { book: "1 Enoch", chapter: 14, verse: 19, text: "And from underneath the throne came streams of flaming fire so that I could not look thereon." },
  { book: "1 Enoch", chapter: 14, verse: 20, text: "And the Great Glory sat thereon, and His raiment shone more brightly than the sun and was whiter than any snow." },
  { book: "1 Enoch", chapter: 14, verse: 21, text: "None of the angels could enter and could behold His face by reason of the magnificence and glory and no flesh could behold Him." },
  { book: "1 Enoch", chapter: 14, verse: 22, text: "The flaming fire was round about Him, and a great fire stood before Him, and none around could draw nigh Him: ten thousand times ten thousand (stood) before Him, yet He needed no counselor." },
  { book: "1 Enoch", chapter: 14, verse: 23, text: "And the most holy ones who were nigh to Him did not leave by night nor depart from Him." },
  { book: "1 Enoch", chapter: 14, verse: 24, text: "And until then I had been prostrate on my face, trembling: and the Lord called me with His own mouth, and said to me: 'Come hither, Enoch, and hear my word.'" },
  { book: "1 Enoch", chapter: 14, verse: 25, text: "And one of the holy ones came to me and waked me, and He made me rise up and approach the door: and I bowed my face downwards." },
  { book: "1 Enoch", chapter: 15, verse: 1, text: "And He answered and said to me, and I heard His voice: 'Fear not, Enoch, thou righteous man and scribe of righteousness: approach hither and hear my voice." },
  { book: "1 Enoch", chapter: 15, verse: 2, text: "And go, say to the Watchers of heaven, who have sent thee to intercede for them: \"You should intercede\" for men, and not men for you:" },
  { book: "1 Enoch", chapter: 15, verse: 3, text: "Wherefore have ye left the high, holy, and eternal heaven, and lain with women, and defiled yourselves with the daughters of men and taken to yourselves wives, and done like the children of earth, and begotten giants (as your) sons?" },
  { book: "1 Enoch", chapter: 15, verse: 4, text: "And though ye were holy, spiritual, living the eternal life, you have defiled yourselves with the blood of women, and have begotten (children) with the blood of flesh, and, as the children of men, have lusted after flesh and blood as those also do who die and perish." },
  { book: "1 Enoch", chapter: 15, verse: 5, text: "Therefore have I given them wives also that they might impregnate them, and beget children by them, that thus nothing might be wanting to them on earth." },
  { book: "1 Enoch", chapter: 15, verse: 6, text: "But you were formerly spiritual, living the eternal life, and immortal for all generations of the world." },
  { book: "1 Enoch", chapter: 15, verse: 7, text: "And therefore I have not appointed wives for you; for as for the spiritual ones of the heaven, in heaven is their dwelling." },
  { book: "1 Enoch", chapter: 15, verse: 8, text: "And now, the giants, who are produced from the spirits and flesh, shall be called evil spirits upon the earth, and on the earth shall be their dwelling." },
  { book: "1 Enoch", chapter: 15, verse: 9, text: "Evil spirits have proceeded from their bodies; because they are born from men, and from the holy Watchers is their beginning and primal origin; they shall be evil spirits on earth, and evil spirits shall they be called." },
  { book: "1 Enoch", chapter: 15, verse: 10, text: "As for the spirits of heaven, in heaven shall be their dwelling, but as for the spirits of the earth which were born upon the earth, on the earth shall be their dwelling." },
  { book: "1 Enoch", chapter: 15, verse: 11, text: "And the spirits of the giants afflict, oppress, destroy, attack, do battle, and work destruction on the earth, and cause trouble: they take no food, but nevertheless hunger and thirst, and cause offences. And these spirits shall rise up against the children of men and against the women, because they have proceeded from them." },
  { book: "1 Enoch", chapter: 16, verse: 1, text: "From the days of the slaughter and destruction and death of the giants, from the souls of whose flesh the spirits, having gone forth, shall destroy without incurring judgement--thus shall they destroy until the day of the consummation, the great judgement in which the age shall be consummated, over the Watchers and the godless, yea, shall be wholly consummated.\"" },
  { book: "1 Enoch", chapter: 16, verse: 2, text: "And now as to the Watchers who have sent thee to intercede for them, who had been aforetime in heaven, (say to them): \"You have been in heaven, but all the mysteries had not yet been revealed to you, and you knew worthless ones, and these in the hardness of your hearts you have made known to the women, and through these mysteries women and men work much evil on earth.\"" },
  { book: "1 Enoch", chapter: 16, verse: 4, text: "Say to them therefore: \"You have no peace.\"'" },
  { book: "1 Enoch", chapter: 17, verse: 1, text: "And they took and brought me to a place in which those who were there were like flaming fire, and, when they wished, they appeared as men." },
  { book: "1 Enoch", chapter: 17, verse: 2, text: "And they brought me to the place of darkness, and to a mountain the point of whose summit reached to heaven." },
  { book: "1 Enoch", chapter: 17, verse: 3, text: "And I saw the places of the luminaries and the treasuries of the stars and of the thunder and in the uttermost depths, where were a fiery bow and arrows and their quiver, and a fiery sword and all the lightnings." },
  { book: "1 Enoch", chapter: 17, verse: 4, text: "And they took me to the living waters, and to the fire of the west, which receives every setting of the sun." },
  { book: "1 Enoch", chapter: 17, verse: 5, text: "And I came to a river of fire in which the fire flows like water and discharges itself into the great sea towards the west." },
  { book: "1 Enoch", chapter: 17, verse: 6, text: "I saw the great rivers and came to the great river and to the great darkness, and went to the place where no flesh walks." },
  { book: "1 Enoch", chapter: 17, verse: 7, text: "I saw the mountains of the darkness of winter and the place whence all the waters of the deep flow." },
  { book: "1 Enoch", chapter: 17, verse: 8, text: "I saw the mouths of all the rivers of the earth and the mouth of the deep." },
  { book: "1 Enoch", chapter: 18, verse: 1, text: "I saw the treasuries of all the winds: I saw how He had furnished with them the whole creation and the firm foundations of the earth." },
  { book: "1 Enoch", chapter: 18, verse: 2, text: "And I saw the corner-stone of the earth: I saw the four winds which bear the earth and the firmament of the heaven." },
  { book: "1 Enoch", chapter: 18, verse: 3, text: "And I saw how the winds stretch out the vaults of heaven, and have their station between heaven and earth: these are the pillars of the heaven." },
  { book: "1 Enoch", chapter: 18, verse: 4, text: "I saw the winds of heaven which turn and bring the circumference of the sun and all the stars to their setting." },
  { book: "1 Enoch", chapter: 18, verse: 5, text: "I saw the winds on the earth carrying the clouds: I saw the paths of the angels. I saw at the end of the earth the firmament of the heaven above. And I proceeded and saw a place which burns day and night, where there are seven mountains of magnificent stones, three towards the east, and three towards the south." },
  { book: "1 Enoch", chapter: 18, verse: 7, text: "And as for those towards the east, one was of coloured stone, and one of pearl, and one of jacinth, and those towards the south of red stone." },
  { book: "1 Enoch", chapter: 18, verse: 8, text: "But the middle one reached to heaven like the throne of God, of alabaster, and the summit of the throne was of sapphire." },
  { book: "1 Enoch", chapter: 18, verse: 9, text: "And I saw a flaming fire. And beyond these mountains" },
  { book: "1 Enoch", chapter: 18, verse: 10, text: "is a region the end of the great earth: there the heavens were completed." },
  { book: "1 Enoch", chapter: 18, verse: 11, text: "And I saw a deep abyss, with columns of heavenly fire, and among them I saw columns of fire fall, which were beyond measure alike towards the height and towards the depth." },
  { book: "1 Enoch", chapter: 18, verse: 12, text: "And beyond that abyss I saw a place which had no firmament of the heaven above, and no firmly founded earth beneath it: there was no water upon it, and no birds, but it was a waste and horrible place." },
  { book: "1 Enoch", chapter: 18, verse: 13, text: "I saw there seven stars like great burning mountains, and to me, when I inquired regarding them," },
  { book: "1 Enoch", chapter: 18, verse: 14, text: "The angel said: 'This place is the end of heaven and earth: this has become a prison for the stars and the host of heaven." },
  { book: "1 Enoch", chapter: 18, verse: 15, text: "And the stars which roll over the fire are they which have transgressed the commandment of the Lord in the beginning of their rising, because they did not come forth at their appointed times." },
  { book: "1 Enoch", chapter: 18, verse: 16, text: "And He was wroth with them, and bound them till the time when their guilt should be consummated (even) for ten thousand years.'" },
  { book: "1 Enoch", chapter: 19, verse: 1, text: "And Uriel said to me: 'Here shall stand the angels who have connected themselves with women, and their spirits assuming many different forms are defiling mankind and shall lead them astray into sacrificing to demons as gods, (here shall they stand,) till the day of the great judgement in which they shall be judged till they are made an end of." },
  { book: "1 Enoch", chapter: 19, verse: 2, text: "And the women also of the angels who went astray shall become sirens.'" },
  { book: "1 Enoch", chapter: 19, verse: 3, text: "And I, Enoch, alone saw the vision, the ends of all things: and no man shall see as I have seen." },
  { book: "1 Enoch", chapter: 20, verse: 1, text: "And these are the names of the holy angels who watch." },
  { book: "1 Enoch", chapter: 20, verse: 2, text: "Uriel, one of the holy angels, who is over the world and over Tartarus." },
  { book: "1 Enoch", chapter: 20, verse: 3, text: "Raphael, one of the holy angels, who is over the spirits of men." },
  { book: "1 Enoch", chapter: 20, verse: 4, text: "Raguel, one of the holy angels who takes vengeance on the world of the luminaries." },
  { book: "1 Enoch", chapter: 20, verse: 5, text: "Michael, one of the holy angels, to wit, he that is set over the best part of mankind and over chaos." },
  { book: "1 Enoch", chapter: 20, verse: 6, text: "Saraqâêl, one of the holy angels, who is set over the spirits, who sin in the spirit." },
  { book: "1 Enoch", chapter: 20, verse: 7, text: "Gabriel, one of the holy angels, who is over Paradise and the serpents and the Cherubim." },
  { book: "1 Enoch", chapter: 20, verse: 8, text: "Remiel, one of the holy angels, whom God set over those who rise." },
  { book: "1 Enoch", chapter: 21, verse: 1, text: "And I proceeded to where things were chaotic." },
  { book: "1 Enoch", chapter: 21, verse: 2, text: "And I saw there something horrible: I saw neither a heaven above nor a firmly founded earth, but a place chaotic and horrible." },
  { book: "1 Enoch", chapter: 21, verse: 3, text: "And there I saw seven stars of the heaven bound together in it, like great mountains and burning with fire." },
  { book: "1 Enoch", chapter: 21, verse: 4, text: "Then I said: 'For what sin are they bound, and on what account have they been cast in hither?'" },
  { book: "1 Enoch", chapter: 21, verse: 5, text: "Then said Uriel, one of the holy angels, who was with me, and was chief over them, and said: 'Enoch, why dost thou ask, and why art thou eager for the truth?" },
  { book: "1 Enoch", chapter: 21, verse: 6, text: "These are of the number of the stars of heaven, which have transgressed the commandment of the Lord, and are bound here till ten thousand years, the time entailed by their sins, are consummated.'" },
  { book: "1 Enoch", chapter: 21, verse: 7, text: "And from thence I went to another place, which was still more horrible than the former, and I saw a horrible thing: a great fire there which burnt and blazed, and the place was cleft as far as the abyss, being full of great descending columns of fire: neither its extent or magnitude could I see, nor could I conjecture." },
  { book: "1 Enoch", chapter: 21, verse: 8, text: "Then I said: 'How fearful is the place and how terrible to look upon!'" },
  { book: "1 Enoch", chapter: 21, verse: 9, text: "Then Uriel answered me, one of the holy angels who was with me, and said unto me: 'Enoch, why hast thou such fear and affright?' And I answered: 'Because of this fearful place, and because of the spectacle of the pain.'" },
  { book: "1 Enoch", chapter: 21, verse: 10, text: "And he said unto me: 'This place is the prison of the angels, and here they will be imprisoned for ever.'" },
  { book: "1 Enoch", chapter: 22, verse: 1, text: "And thence I went to another place, and he showed me in the west another great and high mountain and of hard rock. \n\n **E**" },
  { book: "1 Enoch", chapter: 22, verse: 2, text: "And there was in it four hollow places, deep and wide and very smooth. How smooth are the hollow places and deep and dark to look at. \n\n**Gg**" },
  { book: "1 Enoch", chapter: 22, verse: 2, text: "And there were four hollow places in it, deep and very smooth: three of them were dark and one bright; and there was a fountain of water in its midst. And I said: 'How smooth are these hollow places, and deep and dark to view.'" },
  { book: "1 Enoch", chapter: 22, verse: 3, text: "Then Raphael answered, one of the holy angels who was with me, and said unto me: 'These hollow places have been created for this very purpose, that the spirits of the souls of the dead should assemble therein, yea that all the souls of the children of men should assemble here. And these places have been made to receive them till the day of their judgement and till their appointed period ⌈till the period appointed⌉, till the great judgement (comes) upon them.' \n\n **E**" },
  { book: "1 Enoch", chapter: 22, verse: 5, text: "I saw the spirits of the children of men who were dead, and their voice went forth to heaven and made suit." },
  { book: "1 Enoch", chapter: 22, verse: 5, text: "I saw (the spirit of) a dead man making suit, and his voice went forth to heaven and made suit." },
  { book: "1 Enoch", chapter: 22, verse: 6, text: "Then I asked Raphael the angel who was with me, and I said unto him: 'This spirit--whose is it whose voice goeth forth and maketh suit?' \n\n **Gg**" },
  { book: "1 Enoch", chapter: 22, verse: 6, text: "And I asked Raphael the angel who was with me, and I said unto him: 'This spirit which maketh suit, whose is it, whose voice goeth forth and maketh suit to heaven?'" },
  { book: "1 Enoch", chapter: 22, verse: 7, text: "And he answered me saying: 'This is the spirit which went forth from Abel, whom his brother Cain slew, and he makes his suit against him till his seed is destroyed from the face of the earth, and his seed is annihilated from amongst the seed of men.' \n\n**E**" },
  { book: "1 Enoch", chapter: 22, verse: 8, text: "Then I asked regarding it, and regarding all the hollow places: 'Why is one separated from the other?'" },
  { book: "1 Enoch", chapter: 22, verse: 8, text: "Then I asked regarding all the hollow places: 'Why is one separated from the other?'" },
  { book: "1 Enoch", chapter: 22, verse: 9, text: "And he answered me and said unto me: 'These three have been made that the spirits of the dead might be separated. And such a division has been made for the spirits of the righteous, in which there is the bright spring of water." },
  { book: "1 Enoch", chapter: 22, verse: 9, text: "And he answered me saying: 'These three have been made that the spirits of the dead might be separated. And this division has been made for the spirits of the righteous, in which there is the bright spring of water." },
  { book: "1 Enoch", chapter: 22, verse: 10, text: "And such has been made for sinners when they die and are buried in the earth and judgement has not been executed on them in their lifetime." },
  { book: "1 Enoch", chapter: 22, verse: 10, text: "And this has been made for sinners when they die and are buried in the earth and judgement has not been executed upon them in their lifetime." },
  { book: "1 Enoch", chapter: 22, verse: 11, text: "Here their spirits shall be set apart in this great pain till the great day of judgement and punishment and torment of those who curse for ever, and retribution for their spirits. There He shall bind them for ever." },
  { book: "1 Enoch", chapter: 22, verse: 11, text: "Here their spirits shall be set apart in this great pain, till the great day of judgement, scourgings, and torments of the accursed for ever, so that (there maybe) retribution for their spirits. There He shall bind them for ever." },
  { book: "1 Enoch", chapter: 22, verse: 12, text: "And such a division has been made for the spirits of those who make their suit, who make disclosures concerning their destruction, when they were slain in the days of the sinners." },
  { book: "1 Enoch", chapter: 22, verse: 12, text: "And this division has been made for the spirits of those who make their suit, who make disclosures concerning their destruction, when they were slain in the days of the sinners." },
  { book: "1 Enoch", chapter: 22, verse: 13, text: "Such has been made for the spirits of men who were not righteous but sinners, who were complete in transgression, and of the transgressors. they shall be companions: but their spirits shall not be slain in the day of judgement nor shall they be raised from thence." },
  { book: "1 Enoch", chapter: 22, verse: 13, text: "And this has been made for the spirits of men who shall not be righteous but sinners, who are godless, and of the lawless they shall be companions: but their spirits shall not be punished in the day of judgement nor shall they be raised from thence." },
  { book: "1 Enoch", chapter: 22, verse: 14, text: "Then I blessed the Lord of glory and said: 'Blessed be my Lord, the Lord of righteousness, who ruleth for ever.' \n\n**Gg**" },
  { book: "1 Enoch", chapter: 22, verse: 14, text: "Then I blessed the Lord of Glory and said: 'Blessed art Thou, Lord of righteousness, who rulest over the world.'" },
  { book: "1 Enoch", chapter: 23, verse: 1, text: "From thence I went to another place to the west of the ends of the earth." },
  { book: "1 Enoch", chapter: 23, verse: 2, text: "And I saw a burning fire which ran without resting, and paused not from its course day or night but (ran) regularly." },
  { book: "1 Enoch", chapter: 23, verse: 3, text: "And I asked saying: 'What is this which rests not?'" },
  { book: "1 Enoch", chapter: 23, verse: 4, text: "Then Raguel, one of the holy angels who was with me, answered me and said unto me: 'This course of fire which thou hast seen is the fire in the west which persecutes all the luminaries of heaven.'" },
  { book: "1 Enoch", chapter: 24, verse: 1, text: "And from thence I went to another place of the earth, and he showed me a mountain range of fire which burnt day and night." },
  { book: "1 Enoch", chapter: 24, verse: 2, text: "And I went beyond it and saw seven magnificent mountains all differing each from the other, and the stones (thereof) were magnificent and beautiful, magnificent as a whole, of glorious appearance and fair exterior: three towards the east, one founded on the other, and three towards the south, one upon the other, and deep rough ravines, no one of which joined with any other." },
  { book: "1 Enoch", chapter: 24, verse: 3, text: "And the seventh mountain was in the midst of these, and it excelled them in height, resembling the seat of a throne: and fragrant trees encircled the throne." },
  { book: "1 Enoch", chapter: 24, verse: 4, text: "And amongst them was a tree such as I had never yet smelt, neither was any amongst them nor were others like it: it had a fragrance beyond all fragrance, and its leaves and blooms and wood wither not for ever: and its fruit is beautiful, and its fruit resembles the dates of a palm." },
  { book: "1 Enoch", chapter: 24, verse: 5, text: "Then I said: 'How beautiful is this tree, and fragrant, and its leaves are fair, and its blooms very delightful in appearance.'" },
  { book: "1 Enoch", chapter: 24, verse: 6, text: "Then answered Michael, one of the holy and honoured angels who was with me, and was their leader." },
  { book: "1 Enoch", chapter: 25, verse: 1, text: "And he said unto me: 'Enoch, why dost thou ask me regarding the fragrance of the tree, and why dost thou wish to learn the truth?' Then I answered him saying: 'I wish to know about everything, but especially about this tree.' And he answered saying: 'This high mountain which thou hast seen, whose summit is like the throne of God, is His throne, where the Holy Great One, the Lord of Glory, the Eternal King, will sit, when He shall come down to visit the earth with goodness." },
  { book: "1 Enoch", chapter: 25, verse: 4, text: "And as for this fragrant tree no mortal is permitted to touch it till the great judgement, when He shall take vengeance on all and bring (everything) to its consummation for ever. It shall then be given to the righteous and holy." },
  { book: "1 Enoch", chapter: 25, verse: 5, text: "Its fruit shall be for food to the elect: it shall be transplanted to the holy place, to the temple of the Lord, the Eternal King." },
  { book: "1 Enoch", chapter: 25, verse: 6, text: "Then shall they rejoice with joy and be glad, \nAnd into the holy place shall they enter; \nAnd its fragrance shall be in their bones, \nAnd they shall live a long life on earth, \nSuch as thy fathers lived: \nAnd in their days shall no sorrow or plague \nOr torment or calamity touch them.'" },
  { book: "1 Enoch", chapter: 25, verse: 7, text: "Then blessed I the God of Glory, the Eternal King, who hath prepared such things for the righteous, and hath created them and promised to give to them." },
  { book: "1 Enoch", chapter: 26, verse: 1, text: "And I went from thence to the middle of the earth, and I saw a blessed place in which there were trees with branches abiding and blooming of a dismembered tree." },
  { book: "1 Enoch", chapter: 26, verse: 2, text: "And there I saw a holy mountain, and underneath the mountain to the east there was a stream and it flowed towards the south." },
  { book: "1 Enoch", chapter: 26, verse: 3, text: "And I saw towards the east another mountain higher than this, and between them a deep and narrow ravine: in it also ran a stream underneath the mountain." },
  { book: "1 Enoch", chapter: 26, verse: 4, text: "And to the west thereof there was another mountain, lower than the former and of small elevation, and a ravine deep and dry between them: and another deep and dry ravine was at the extremities of the three mountains." },
  { book: "1 Enoch", chapter: 26, verse: 5, text: "And all the ravines were deep and narrow, (being formed) of hard rock, and trees were not planted upon them." },
  { book: "1 Enoch", chapter: 26, verse: 6, text: "And I marvelled at the rocks, and I marvelled at the ravine, yea, I marvelled very much." },
  { book: "1 Enoch", chapter: 27, verse: 1, text: "Then said I: 'For what object is this blessed land, which is entirely filled with trees, and this accursed valley between?'" },
  { book: "1 Enoch", chapter: 27, verse: 2, text: "Then Uriel, one of the holy angels who was with me, answered and said: 'This accursed valley is for those who are accursed for ever: here shall all the accursed be gathered together who utter with their lips against the Lord unseemly words and of His glory speak hard things. \n\n**E** \n\nHere shall they be gathered together, and here shall be their place of judgement." },
  { book: "1 Enoch", chapter: 27, verse: 3, text: "In the last days there shall be upon them the spectacle of righteous judgement in the presence of the righteous for ever: here shall the merciful bless the Lord of glory, the Eternal King. \n\n**Gg** \n\nHere shall they be gathered together, and here shall be the place of their habitation." },
  { book: "1 Enoch", chapter: 27, verse: 3, text: "In the last times, in the days of the true judgement in the presence of the righteous for ever: here shall the godly bless the Lord of Glory, the Eternal King." },
  { book: "1 Enoch", chapter: 27, verse: 4, text: "In the days of judgement over the former, they shall bless Him for the mercy in accordance with which He has assigned them (their lot).'" },
  { book: "1 Enoch", chapter: 27, verse: 5, text: "Then I blessed the Lord of Glory and set forth His glory and lauded Him gloriously." },
  { book: "1 Enoch", chapter: 28, verse: 1, text: "And thence I went towards the east, into the midst of the mountain range of the desert, and I saw a wilderness and it was solitary, full of trees and plants." },
  { book: "1 Enoch", chapter: 28, verse: 2, text: "And water gushed forth from above." },
  { book: "1 Enoch", chapter: 28, verse: 3, text: "Rushing like a copious watercourse which flowed towards the north-west it caused clouds and dew to ascend on every side." },
  { book: "1 Enoch", chapter: 29, verse: 1, text: "And thence I went to another place in the desert, and approached to the east of this mountain range." },
  { book: "1 Enoch", chapter: 29, verse: 2, text: "And there I saw aromatic trees exhaling the fragrance of frankincense and myrrh, and the trees also were similar to the almond tree." },
  { book: "1 Enoch", chapter: 30, verse: 1, text: ".And beyond these, I went afar to the east, and I saw another place, a valley (full) of water." },
  { book: "1 Enoch", chapter: 30, verse: 2, text: "And therein there was a tree, the colour (?) of fragrant trees such as the mastic." },
  { book: "1 Enoch", chapter: 30, verse: 3, text: "And on the sides of those valleys I saw fragrant cinnamon. And beyond these I proceeded to the east." },
  { book: "1 Enoch", chapter: 31, verse: 1, text: "And I saw other mountains, and amongst them were ⌈groves of⌉ trees, and there flowed forth from them nectar, which is named sarara and galbanum." },
  { book: "1 Enoch", chapter: 31, verse: 2, text: "And beyond these mountains I saw another mountain to the east of the ends of the earth, whereon were aloe trees, and all the trees were full of stacte, being like almond-trees." },
  { book: "1 Enoch", chapter: 31, verse: 3, text: "And when one burnt it, it smelt sweeter than any fragrant odour.\n\n\n**E**" },
  { book: "1 Enoch", chapter: 32, verse: 1, text: "And after these fragrant odours, as I looked towards the north over the mountains I saw seven mountains full of choice nard and fragrant trees and cinnamon and pepper. \n\n**Gg**" },
  { book: "1 Enoch", chapter: 32, verse: 1, text: "To the north-east I beheld seven mountains full of choice nard and mastic and cinnamon and pepper." },
  { book: "1 Enoch", chapter: 32, verse: 2, text: "And thence I went over the summits of all these mountains, far towards the east ⌈of the earth⌉, and passed above the Erythraean sea and went far from it, and passed over the angel Zotîêl.\n\n**E**" },
  { book: "1 Enoch", chapter: 32, verse: 3, text: "And I came to the Garden of Righteousness, and saw beyond those trees many large trees growing there and of goodly fragrance, large, very beautiful and glorious, and the tree of wisdom whereof they eat and know great wisdom. \n\n**Gg**" },
  { book: "1 Enoch", chapter: 32, verse: 3, text: "And I came to the Garden of Righteousness, and from afar off trees more numerous than these trees and great--two trees there, very great, beautiful, and glorious, and magnificent, and the tree of knowledge, whose holy fruit they eat and know great wisdom." },
  { book: "1 Enoch", chapter: 32, verse: 4, text: "That tree is in height like the fir, and its leaves are like (those of) the Carob tree: and its fruit is like the clusters of the vine, very beautiful: and the fragrance of the tree penetrates afar." },
  { book: "1 Enoch", chapter: 32, verse: 5, text: "Then I said: 'How beautiful is the tree, and how attractive is its look!'" },
  { book: "1 Enoch", chapter: 32, verse: 6, text: "Then Raphael the holy angel, who was with me, answered me and said: 'This is the tree of wisdom, of which thy father old (in years) and thy aged mother, who were before thee, have eaten, and they learnt wisdom and their eyes were opened, and they knew that they were naked and they were driven out of the garden.'" },
  { book: "1 Enoch", chapter: 33, verse: 1, text: "And from thence I went to the ends of the earth and saw there great beasts, and each differed from the other; and (I saw) birds also differing in appearance and beauty and voice, the one differing from the other." },
  { book: "1 Enoch", chapter: 33, verse: 2, text: "And to the east of those beasts I saw the ends of the earth whereon the heaven rests, and the portals of the heaven open." },
  { book: "1 Enoch", chapter: 33, verse: 3, text: "And I saw how the stars of heaven come forth, and I counted the portals out of which they proceed, and wrote down all their outlets, of each individual star by itself, according to their number and their names, their courses and their positions, and their times and their months, as Uriel the holy angel who was with me showed me." },
  { book: "1 Enoch", chapter: 33, verse: 4, text: "He showed all things to me and wrote them down for me: also their names he wrote for me, and their laws and their companies." },
  { book: "1 Enoch", chapter: 34, verse: 1, text: "And from thence I went towards the north to the ends of the earth, and there I saw a great and glorious device at the ends of the whole earth." },
  { book: "1 Enoch", chapter: 34, verse: 2, text: "And here I saw three portals of heaven open in the heaven: through each of them proceed north winds: when they blow there is cold, hail, frost, snow, dew, and rain." },
  { book: "1 Enoch", chapter: 34, verse: 3, text: "And out of one portal they blow for good: but when they blow through the other two portals, it is with violence and affliction on the earth, and they blow with violence." },
  { book: "1 Enoch", chapter: 35, verse: 1, text: "And from thence I went towards the west to the ends of the earth, and saw there three portals of the heaven open such as I had seen in the east, the same number of portals, and the same number of outlets." },
  { book: "1 Enoch", chapter: 36, verse: 1, text: "And from thence I went to the south to the ends of the earth, and saw there three open portals of the heaven: and thence there come dew, rain, and wind." },
  { book: "1 Enoch", chapter: 36, verse: 2, text: "And from thence I went to the east to the ends of the heaven, and saw here the three eastern portals of heaven open and small portals above them." },
  { book: "1 Enoch", chapter: 36, verse: 3, text: "Through each of these small portals pass the stars of heaven and run their course to the west on the path which is shown to them." },
  { book: "1 Enoch", chapter: 36, verse: 4, text: "And as often as I saw I blessed always the Lord of Glory, and I continued to bless the Lord of Glory who has wrought great and glorious wonders, to show the greatness of His work to the angels and to spirits and to men, that they might praise His work and all His creation: that they might see the work of His might and praise the great work of His hands and bless Him for ever." },
  { book: "1 Enoch", chapter: 37, verse: 1, text: "The second vision which he saw, the vision of wisdom--which Enoch the son of Jared, the son of Mahalalel, the son of Cainan, the son of Enos, the son of Seth, the son of Adam, saw." },
  { book: "1 Enoch", chapter: 37, verse: 2, text: "And this is the beginning of the words of wisdom which I lifted up my voice to speak and say to those which dwell on earth: Hear, ye men of old time, and see, ye that come after, the words of the Holy One which I will speak before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 37, verse: 3, text: "It were better to declare (them only) to the men of old time, but even from those that come after we will not withhold the beginning of wisdom." },
  { book: "1 Enoch", chapter: 37, verse: 4, text: "Till the present day such wisdom has never been given by the Lord of Spirits as I have received according to my insight, according to the good pleasure of the Lord of Spirits by whom the lot of eternal life has been given to me." },
  { book: "1 Enoch", chapter: 37, verse: 5, text: "Now three parables were imparted to me, and I lifted up my voice and recounted them to those that dwell on the earth." },
  { book: "1 Enoch", chapter: 38, verse: 1, text: "The First Parable. \nWhen the congregation of the righteous shall appear,\nAnd sinners shall be judged for their sins, \nAnd shall be driven from the face of the earth:" },
  { book: "1 Enoch", chapter: 38, verse: 2, text: "And when the Righteous One shall appear before the eyes of the righteous, \nWhose elect works hang upon the Lord of Spirits,\nAnd light shall appear to the righteous and the elect who dwell on the earth, \nWhere then will be the dwelling of the sinners, \nAnd where the resting-place of those who have denied the Lord of Spirits? \nIt had been good for them if they had not been born." },
  { book: "1 Enoch", chapter: 38, verse: 3, text: "When the secrets of the righteous shall be revealed and the sinners judged, \nAnd the godless driven from the presence of the righteous and elect," },
  { book: "1 Enoch", chapter: 38, verse: 4, text: "From that time those that possess the earth shall no longer be powerful and exalted:\n\nAnd they shall not be able to behold the face of the holy, \nFor the Lord of Spirits has caused His light to appear \nOn the face of the holy, righteous, and elect." },
  { book: "1 Enoch", chapter: 38, verse: 5, text: "Then shall the kings and the mighty perish \nAnd be given into the hands of the righteous and holy." },
  { book: "1 Enoch", chapter: 38, verse: 6, text: "And thenceforward none shall seek for themselves mercy from the Lord of Spirits \nFor their life is at an end." },
  { book: "1 Enoch", chapter: 39, verse: 1, text: "And it shall come to pass in those days that elect and holy children will descend from the high heaven, and their seed will become one with the children of men." },
  { book: "1 Enoch", chapter: 39, verse: 2, text: "And in those days Enoch received books of zeal and wrath, and books of disquiet and expulsion.\n\nAnd mercy shall not be accorded to them, saith the Lord of Spirits." },
  { book: "1 Enoch", chapter: 39, verse: 3, text: "And in those days a whirlwind carried me off from the earth, \nAnd set me down at the end of the heavens." },
  { book: "1 Enoch", chapter: 39, verse: 4, text: "And there I saw another vision, the dwelling-places of the holy, \nAnd the resting-places of the righteous." },
  { book: "1 Enoch", chapter: 39, verse: 5, text: "Here mine eyes saw their dwellings with His righteous angels, \nAnd their resting-places with the holy.\n\nAnd they petitioned and interceded and prayed for the children of men, \nAnd righteousness flowed before them as water,\n\nAnd mercy like dew upon the earth: \nThus it is amongst them for ever and ever.\n\n[39:6a] And in that place mine eyes saw the Elect One of righteousness and of faith, \n[39:7a] And I saw his dwelling-place under the wings of the Lord of Spirits. \n[39:6b] And righteousness shall prevail in his days, \nAnd the righteous and elect shall be without number before Him for ever and ever. \n[39:7b] And all the righteous and elect before Him shall be strong as fiery lights, \nAnd their mouth shall be full of blessing,\n\nAnd their lips extol the name of the Lord of Spirits, \nAnd righteousness before Him shall never fail, \nAnd uprightness shall never fail before Him." },
  { book: "1 Enoch", chapter: 39, verse: 8, text: "There I wished to dwell, \nAnd my spirit longed for that dwelling-place:\n\nAnd there heretofore hath been my portion, \nFor so has it been established concerning me before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 39, verse: 9, text: "In those days I praised and extolled the name of the Lord of Spirits with blessings and praises, because He hath destined me for blessing and glory according to the good pleasure of the Lord of Spirits." },
  { book: "1 Enoch", chapter: 39, verse: 10, text: "For a long time my eyes regarded that place, and I blessed Him and praised Him, saying: 'Blessed is He, and may He be blessed from the beginning and for evermore." },
  { book: "1 Enoch", chapter: 39, verse: 11, text: "And before Him there is no ceasing. He knows before the world was created what is for ever and what will be from generation unto generation." },
  { book: "1 Enoch", chapter: 39, verse: 12, text: "Those who sleep not bless Thee: they stand before Thy glory and bless, praise, and extol, saying: \"Holy, holy, holy, is the Lord of Spirits: He filleth the earth with spirits.\"'" },
  { book: "1 Enoch", chapter: 39, verse: 13, text: "And here my eyes saw all those who sleep not: they stand before Him and bless and say: 'Blessed be Thou, and blessed be the name of the Lord for ever and ever.'" },
  { book: "1 Enoch", chapter: 39, verse: 14, text: "And my face was changed; for I could no longer behold." },
  { book: "1 Enoch", chapter: 40, verse: 1, text: "And after that I saw thousands of thousands and ten thousand times ten thousand, I saw a multitude beyond number and reckoning, who stood before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 40, verse: 2, text: "And on the four sides of the Lord of Spirits I saw four presences, different from those that sleep not, and I learnt their names: for the angel that went with me made known to me their names, and showed me all the hidden things." },
  { book: "1 Enoch", chapter: 40, verse: 3, text: "And I heard the voices of those four presences as they uttered praises before the Lord of glory." },
  { book: "1 Enoch", chapter: 40, verse: 4, text: "The first voice blesses the Lord of Spirits for ever and ever." },
  { book: "1 Enoch", chapter: 40, verse: 5, text: "And the second voice I heard blessing the Elect One and the elect ones who hang upon the Lord of Spirits." },
  { book: "1 Enoch", chapter: 40, verse: 6, text: "And the third voice I heard pray and intercede for those who dwell on the earth and supplicate in the name of the Lord of Spirits." },
  { book: "1 Enoch", chapter: 40, verse: 7, text: "And I heard the fourth voice fending off the Satans and forbidding them to come before the Lord of Spirits to accuse them who dwell on the earth." },
  { book: "1 Enoch", chapter: 40, verse: 8, text: "After that I asked the angel of peace who went with me, who showed me everything that is hidden: 'Who are these four presences which I have seen and whose words I have heard and written down?'" },
  { book: "1 Enoch", chapter: 40, verse: 9, text: "And he said to me: 'This first is Michael, the merciful and long-suffering: and the second, who is set over all the diseases and all the wounds of the children of men, is Raphael: and the third, who is set over all the powers, is Gabriel: and the fourth, who is set over the repentance unto hope of those who inherit eternal life, is named Phanuel.' And these are the four angels of the Lord of Spirits and the four voices I heard in those days." },
  { book: "1 Enoch", chapter: 41, verse: 1, text: "And after that I saw all the secrets of the heavens, and how the kingdom is divided, and how the actions of men are weighed in the balance." },
  { book: "1 Enoch", chapter: 41, verse: 2, text: "And there I saw the mansions of the elect and the mansions of the holy, and mine eyes saw there all the sinners being driven from thence which deny the name of the Lord of Spirits, and being dragged off: and they could not abide because of the punishment which proceeds from the Lord of Spirits." },
  { book: "1 Enoch", chapter: 41, verse: 3, text: "And there mine eyes saw the secrets of the lightning and of the thunder, and the secrets of the winds, how they are divided to blow over the earth, and the secrets of the clouds and dew, and there I saw from whence they proceed in that place and from whence they saturate the dusty earth." },
  { book: "1 Enoch", chapter: 41, verse: 4, text: "And there I saw closed chambers out of which the winds are divided, the chamber of the hail and winds, the chamber of the mist, and of the clouds, and the cloud thereof hovers over the earth from the beginning of the world." },
  { book: "1 Enoch", chapter: 41, verse: 5, text: "And I saw the chambers of the sun and moon, whence they proceed and whither they come again, and their glorious return, and how one is superior to the other, and their stately orbit, and how they do not leave their orbit, and they add nothing to their orbit and they take nothing from it, and they keep faith with each other, in accordance with the oath by which they are bound together." },
  { book: "1 Enoch", chapter: 41, verse: 6, text: "And first the sun goes forth and traverses his path according to the commandment of the Lord of Spirits, and mighty is His name for ever and ever." },
  { book: "1 Enoch", chapter: 41, verse: 7, text: "And after that I saw the hidden and the visible path of the moon, and she accomplishes the course of her path in that place by day and by night--the one holding a position opposite to the other before the Lord of Spirits. \n\nAnd they give thanks and praise and rest not; \nFor unto them is their thanksgiving rest." },
  { book: "1 Enoch", chapter: 41, verse: 8, text: "For the sun changes oft for a blessing or a curse, \nAnd the course of the path of the moon is light to the righteous \nAnd darkness to the sinners in the name of the Lord,\n\nWho made a separation between the light and the darkness, \nAnd divided the spirits of men,\n\nAnd strengthened the spirits of the righteous, \nIn the name of His righteousness." },
  { book: "1 Enoch", chapter: 41, verse: 9, text: "For no angel hinders and no power is able to hinder; for He appoints a judge for them all and He judges them all before Him." },
  { book: "1 Enoch", chapter: 42, verse: 1, text: "Wisdom found no place where she might dwell; \nThen a dwelling-place was assigned her in the heavens." },
  { book: "1 Enoch", chapter: 42, verse: 2, text: "Wisdom went forth to make her dwelling among the children of men, \nAnd found no dwelling-place:\n\nWisdom returned to her place, \nAnd took her seat among the angels." },
  { book: "1 Enoch", chapter: 42, verse: 3, text: "And unrighteousness went forth from her chambers: \nWhom she sought not she found, \nAnd dwelt with them, \n\nAs rain in a desert \nAnd dew on a thirsty land." },
  { book: "1 Enoch", chapter: 43, verse: 1, text: "And I saw other lightnings and the stars of heaven, and I saw how He called them all by their names and they hearkened unto Him." },
  { book: "1 Enoch", chapter: 43, verse: 2, text: "And I saw how they are weighed in a righteous balance according to their proportions of light: (I saw) the width of their spaces and the day of their appearing, and how their revolution produces lightning: and (I saw) their revolution according to the number of the angels, and (how) they keep faith with each other." },
  { book: "1 Enoch", chapter: 43, verse: 3, text: "And I asked the angel who went with me who showed me what was hidden: 'What are these?'" },
  { book: "1 Enoch", chapter: 43, verse: 4, text: "And he said to me: 'The Lord of Spirits hath showed thee their parabolic meaning (lit. 'their parable'): these are the names of the holy who dwell on the earth and believe in the name of the Lord of Spirits for ever and ever.'" },
  { book: "1 Enoch", chapter: 45, verse: 1, text: "And this is the Second Parable concerning those who deny the name of the dwelling of the holy ones and the Lord of Spirits." },
  { book: "1 Enoch", chapter: 45, verse: 2, text: "And into the heaven they shall not ascend, \nAnd on the earth they shall not come: \nSuch shall be the lot of the sinners \nWho have denied the name of the Lord of Spirits, \nWho are thus preserved for the day of suffering and tribulation." },
  { book: "1 Enoch", chapter: 45, verse: 3, text: "On that day Mine Elect One shall sit on the throne of glory \nAnd shall try their works, \nAnd their places of rest shall be innumerable.\n\nAnd their souls shall grow strong within them when they see Mine Elect Ones, \nAnd those who have called upon My glorious name:" },
  { book: "1 Enoch", chapter: 45, verse: 4, text: "Then will I cause Mine Elect One to dwell among them.\n\nAnd I will transform the heaven and make it an eternal blessing and light," },
  { book: "1 Enoch", chapter: 45, verse: 5, text: "And I will transform the earth and make it a blessing:\n\nAnd I will cause Mine elect ones to dwell upon it: \nBut the sinners and evil-doers shall not set foot thereon." },
  { book: "1 Enoch", chapter: 45, verse: 6, text: "For I have provided and satisfied with peace My righteous ones \nAnd have caused them to dwell before Me:\n\nBut for the sinners there is judgement impending with Me, \nSo that I shall destroy them from the face of the earth." },
  { book: "1 Enoch", chapter: 46, verse: 1, text: "And there I saw One who had a head of days, \nAnd His head was white like wool, \nAnd with Him was another being whose countenance had the appearance of a man, \nAnd his face was full of graciousness, like one of the holy angels." },
  { book: "1 Enoch", chapter: 46, verse: 2, text: "And I asked the angel who went with me and showed me all the hidden things, concerning that Son of Man, who he was, and whence he was, (and) why he went with the Head of Days?" },
  { book: "1 Enoch", chapter: 46, verse: 3, text: "And he answered and said unto me: \n\nThis is the son of Man who hath righteousness, \nWith whom dwelleth righteousness, \nAnd who revealeth all the treasures of that which is hidden,\n\nBecause the Lord of Spirits hath chosen him, \nAnd whose lot hath the pre-eminence before the Lord of Spirits in uprightness for ever." },
  { book: "1 Enoch", chapter: 46, verse: 5, text: "And he shall put down the kings from their thrones and kingdoms \nBecause they do not extol and praise Him, \nNor humbly acknowledge whence the kingdom was bestowed upon them." },
  { book: "1 Enoch", chapter: 46, verse: 6, text: "And he shall put down the countenance of the strong, \nAnd shall fill them with shame.\n\nAnd darkness shall be their dwelling, \nAnd worms shall be their bed, \nAnd they shall have no hope of rising from their beds, \nBecause they do not extol the name of the Lord of Spirits." },
  { book: "1 Enoch", chapter: 46, verse: 7, text: "And these are they who judge the stars of heaven, \nAnd raise their hands against the Most High, \nAnd tread upon the earth and dwell upon it.\n\nAnd all their deeds manifest unrighteousness, \nAnd their power rests upon their riches, \nAnd their faith is in the gods which they have made with their hands, \nAnd they deny the name of the Lord of Spirits," },
  { book: "1 Enoch", chapter: 46, verse: 8, text: "And they persecute the houses of His congregations, \nAnd the faithful who hang upon the name of the Lord of Spirits." },
  { book: "1 Enoch", chapter: 47, verse: 1, text: "And in those days shall have ascended the prayer of the righteous, \nAnd the blood of the righteous from the earth before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 47, verse: 2, text: "In those days the holy ones who dwell above in the heavens \nShall unite with one voice \nAnd supplicate and pray and praise, \nAnd give thanks and bless the name of the Lord of Spirits \nOn behalf of the blood of the righteous which has been shed, \nAnd that the prayer of the righteous may not be in vain before the Lord of Spirits, \nThat judgement may be done unto them, \nAnd that they may not have to suffer for ever." },
  { book: "1 Enoch", chapter: 47, verse: 3, text: "In those days I saw the Head of Days when He seated himself upon the throne of His glory, \nAnd the books of the living were opened before Him: \nAnd all His host which is in heaven above and His counselors stood before Him," },
  { book: "1 Enoch", chapter: 47, verse: 4, text: "And the hearts of the holy were filled with joy; \nBecause the number of the righteous had been offered, \nAnd the prayer of the righteous had been heard, \nAnd the blood of the righteous been required before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 48, verse: 1, text: "And in that place I saw the fountain of righteousness \nWhich was inexhaustible: \nAnd around it were many fountains of wisdom;\n\nAnd all the thirsty drank of them, \nAnd were filled with wisdom, \nAnd their dwellings were with the righteous and holy and elect." },
  { book: "1 Enoch", chapter: 48, verse: 2, text: "And at that hour that Son of Man was named \nIn the presence of the Lord of Spirits, \nAnd his name before the Head of Days." },
  { book: "1 Enoch", chapter: 48, verse: 3, text: "Yea, before the sun and the signs were created, \nBefore the stars of the heaven were made, \nHis name was named before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 48, verse: 4, text: "He shall be a staff to the righteous whereon to stay themselves and not fall, \nAnd he shall be the light of the Gentiles, \nAnd the hope of those who are troubled of heart." },
  { book: "1 Enoch", chapter: 48, verse: 5, text: "All who dwell on earth shall fall down and worship before him, \nAnd will praise and bless and celebrate with song the Lord of Spirits." },
  { book: "1 Enoch", chapter: 48, verse: 6, text: "And for this reason hath he been chosen and hidden before Him, \nBefore the creation of the world and for evermore." },
  { book: "1 Enoch", chapter: 48, verse: 7, text: "And the wisdom of the Lord of Spirits hath revealed him to the holy and righteous; \nFor he hath preserved the lot of the righteous, \nBecause they have hated and despised this world of unrighteousness, \nAnd have hated all its works and ways in the name of the Lord of Spirits: \nFor in his name they are saved, \nAnd according to his good pleasure hath it been in regard to their life." },
  { book: "1 Enoch", chapter: 48, verse: 8, text: "In these days downcast in countenance shall the kings of the earth have become, \nAnd the strong who possess the land because of the works of their hands;\n\nFor on the day of their anguish and affliction they shall not (be able to) save themselves," },
  { book: "1 Enoch", chapter: 48, verse: 9, text: "And I will give them over into the hands of Mine elect:\n\nAs straw in the fire so shall they burn before the face of the holy: \nAs lead in the water shall they sink before the face of the righteous,\nAnd no trace of them shall any more be found." },
  { book: "1 Enoch", chapter: 48, verse: 10, text: "And on the day of their affliction there shall be rest on the earth,\nAnd before them they shall fall and not rise again:\n\nAnd there shall be no one to take them with his hands and raise them: \nFor they have denied the Lord of Spirits and His Anointed. \nThe name of the Lord of Spirits be blessed." },
  { book: "1 Enoch", chapter: 49, verse: 1, text: "For wisdom is poured out like water,\nAnd glory faileth not before him for evermore." },
  { book: "1 Enoch", chapter: 49, verse: 2, text: "For he is mighty in all the secrets of righteousness, \nAnd unrighteousness shall disappear as a shadow, \nAnd have no continuance; \nBecause the Elect One standeth before the Lord of Spirits, \nAnd his glory is for ever and ever, \nAnd his might unto all generations." },
  { book: "1 Enoch", chapter: 49, verse: 3, text: "And in him dwells the spirit of wisdom, \nAnd the spirit which gives insight, \nAnd the spirit of understanding and of might,\nAnd the spirit of those who have fallen asleep in righteousness." },
  { book: "1 Enoch", chapter: 49, verse: 4, text: "And he shall judge the secret things, \nAnd none shall be able to utter a lying word before him; \nFor he is the Elect One before the Lord of Spirits according to His good pleasure." },
  { book: "1 Enoch", chapter: 50, verse: 1, text: "And in those days a change shall take place for the holy and elect, \nAnd the light of days shall abide upon them, \nAnd glory and honour shall turn to the holy," },
  { book: "1 Enoch", chapter: 50, verse: 2, text: "On the day of affliction on which evil shall have been treasured up against the sinners.\n\nAnd the righteous shall be victorious in the name of the Lord of Spirits: \nAnd He will cause the others to witness (this)\nThat they may repent \nAnd forgo the works of their hands." },
  { book: "1 Enoch", chapter: 50, verse: 3, text: "They shall have no honour through the name of the Lord of Spirits,\nYet through His name shall they be saved, \nAnd the Lord of Spirits will have compassion on them,\nFor His compassion is great." },
  { book: "1 Enoch", chapter: 50, verse: 4, text: "And He is righteous also in His judgement,\nAnd in the presence of His glory unrighteousness also shall not maintain itself: \nAt His judgement the unrepentant shall perish before Him." },
  { book: "1 Enoch", chapter: 50, verse: 5, text: "And from henceforth I will have no mercy on them, saith the Lord of Spirits." },
  { book: "1 Enoch", chapter: 51, verse: 1, text: "And in those days shall the earth also give back that which has been entrusted to it, \nAnd Sheol also shall give back that which it has received, \nAnd hell shall give back that which it owes.\n\n[51:5a] For in those days the Elect One shall arise," },
  { book: "1 Enoch", chapter: 51, verse: 2, text: "And he shall choose the righteous and holy from among them: \nFor the day has drawn nigh that they should be saved." },
  { book: "1 Enoch", chapter: 51, verse: 3, text: "And the Elect One shall in those days sit on My throne, \nAnd his mouth shall pour forth all the secrets of wisdom and counsel:\nFor the Lord of Spirits hath given (them) to him and hath glorified him." },
  { book: "1 Enoch", chapter: 51, verse: 4, text: "And in those days shall the mountains leap like rams,\nAnd the hills also shall skip like lambs satisfied with milk, \nAnd the faces of all the angels in heaven shall be lighted up with joy.\n\n[51:5b] And the earth shall rejoice, \nc. And the righteous shall dwell upon it, \nd. And the elect shall walk thereon." },
  { book: "1 Enoch", chapter: 52, verse: 1, text: "And after those days in that place where I had seen all the visions of that which is hidden--for I had been carried off in a whirlwind and they had borne me towards the west--" },
  { book: "1 Enoch", chapter: 52, verse: 2, text: "There mine eyes saw all the secret things of heaven that shall be, a mountain of iron, and a mountain of copper, and a mountain of silver, and a mountain of gold, and a mountain of soft metal, and a mountain of lead." },
  { book: "1 Enoch", chapter: 52, verse: 3, text: "And I asked the angel who went with me, saying, 'What things are these which I have seen in secret?'" },
  { book: "1 Enoch", chapter: 52, verse: 4, text: "And he said unto me: 'All these things which thou hast seen shall serve the dominion of His Anointed that he may be potent and mighty on the earth.'" },
  { book: "1 Enoch", chapter: 52, verse: 5, text: "And that angel of peace answered, saying unto me: 'Wait a little, and there shall be revealed unto thee all the secret things which surround the Lord of Spirits." },
  { book: "1 Enoch", chapter: 52, verse: 6, text: "And these mountains which thine eyes have seen, \nThe mountain of iron, and the mountain of copper, and the mountain of silver, \nAnd the mountain of gold, and the mountain of soft metal, and the mountain of lead, \nAll these shall be in the presence of the Elect One \nAs wax before the fire, \nAnd like the water which streams down from above upon those mountains, \nAnd they shall become powerless before his feet." },
  { book: "1 Enoch", chapter: 52, verse: 7, text: "And it shall come to pass in those days that none shall be saved, \nEither by gold or by silver, \nAnd none be able to escape." },
  { book: "1 Enoch", chapter: 52, verse: 8, text: "And there shall be no iron for war, \nNor shall one clothe oneself with a breastplate. \nBronze shall be of no service, \nAnd tin shall be of no service and shall not be esteemed, \nAnd lead shall not be desired." },
  { book: "1 Enoch", chapter: 52, verse: 9, text: "And all these things shall be denied and destroyed from the surface of the earth, \nWhen the Elect One shall appear before the face of the Lord of Spirits.'" },
  { book: "1 Enoch", chapter: 53, verse: 1, text: "There mine eyes saw a deep valley with open mouths, and all who dwell on the earth and sea and islands shall bring to him gifts and presents and tokens of homage, but that deep valley shall not become full." },
  { book: "1 Enoch", chapter: 53, verse: 2, text: "And their hands commit lawless deeds, \nAnd the sinners devour all whom they lawlessly oppress:\nYet the sinners shall be destroyed before the face of the Lord of Spirits,\nAnd they shall be banished from off the face of His earth, \nAnd they shall perish for ever and ever." },
  { book: "1 Enoch", chapter: 53, verse: 3, text: "For I saw all the angels of punishment abiding (there) and preparing all the instruments of Satan." },
  { book: "1 Enoch", chapter: 53, verse: 4, text: "And I asked the angel of peace who went with me: 'For whom are they preparing these instruments?'" },
  { book: "1 Enoch", chapter: 53, verse: 5, text: "And he said unto me: 'They prepare these for the kings and the mighty of this earth, that they may thereby be destroyed." },
  { book: "1 Enoch", chapter: 53, verse: 6, text: "And after this the Righteous and Elect One shall cause the house of his congregation to appear: henceforth they shall be no more hindered in the name of the Lord of Spirits." },
  { book: "1 Enoch", chapter: 53, verse: 7, text: "And these mountains shall not stand as the earth before his righteousness, \nBut the hills shall be as a fountain of water,\nAnd the righteous shall have rest from the oppression of sinners.'" },
  { book: "1 Enoch", chapter: 54, verse: 1, text: "And I looked and turned to another part of the earth, and saw there a deep valley with burning fire." },
  { book: "1 Enoch", chapter: 54, verse: 2, text: "And they brought the kings and the mighty, and began to cast them into this deep valley." },
  { book: "1 Enoch", chapter: 54, verse: 3, text: "And there mine eyes saw how they made these their instruments, iron chains of immeasurable weight." },
  { book: "1 Enoch", chapter: 54, verse: 4, text: "And I asked the angel of peace who went with me, saying: 'For whom are these chains being prepared?'" },
  { book: "1 Enoch", chapter: 54, verse: 5, text: "And he said unto me: 'These are being prepared for the hosts of Azâzêl, so that they may take them and cast them into the abyss of complete condemnation, and they shall cover their jaws with rough stones as the Lord of Spirits commanded." },
  { book: "1 Enoch", chapter: 54, verse: 6, text: "And Michael, and Gabriel, and Raphael, and Phanuel shall take hold of them on that great day, and cast them on that day into the burning furnace, that the Lord of Spirits may take vengeance on them for their unrighteousness in becoming subject to Satan and leading astray those who dwell on the earth.'" },
  { book: "1 Enoch", chapter: 54, verse: 7, text: "'And in those days shall punishment come from the Lord of Spirits, and he will open all the chambers of waters which are above the heavens, and of the fountains which are beneath the earth." },
  { book: "1 Enoch", chapter: 54, verse: 8, text: "And all the waters shall be joined with the waters: that which is above the heavens is the masculine, and the water which is beneath the earth is the feminine." },
  { book: "1 Enoch", chapter: 54, verse: 9, text: "And they shall destroy all who dwell on the earth and those who dwell under the ends of the heaven." },
  { book: "1 Enoch", chapter: 54, verse: 10, text: "And when they have recognized their unrighteousness which they have wrought on the earth, then by these shall they perish." },
  { book: "1 Enoch", chapter: 55, verse: 1, text: "And after that the Head of Days repented and said: 'In vain have I destroyed all who dwell on the earth.'" },
  { book: "1 Enoch", chapter: 55, verse: 2, text: "And He sware by His great name: 'Henceforth I will not do so to all who dwell on the earth, and I will set a sign in the heaven: and this shall be a pledge of good faith between Me and them for ever, so long as heaven is above the earth. And this is in accordance with My command.'" },
  { book: "1 Enoch", chapter: 55, verse: 3, text: "When I have desired to take hold of them by the hand of the angels on the day of tribulation and pain because of this, I will cause My chastisement and My wrath to abide upon them, saith God, the Lord of Spirits." },
  { book: "1 Enoch", chapter: 55, verse: 4, text: "Ye mighty kings who dwell on the earth, ye shall have to behold Mine Elect One, how he sits on the throne of glory and judges Azâzêl, and all his associates, and all his hosts in the name of the Lord of Spirits.'" },
  { book: "1 Enoch", chapter: 56, verse: 1, text: "And I saw there the hosts of the angels of punishment going, and they held scourges and chains of iron and bronze." },
  { book: "1 Enoch", chapter: 56, verse: 2, text: "And I asked the angel of peace who went with me, saying: 'To whom are these who hold the scourges going?'" },
  { book: "1 Enoch", chapter: 56, verse: 3, text: "And he said unto me: 'To their elect and beloved ones, that they may be cast into the chasm of the abyss of the valley." },
  { book: "1 Enoch", chapter: 56, verse: 4, text: "And then that valley shall be filled with their elect and beloved,\nAnd the days of their lives shall be at an end, \nAnd the days of their leading astray shall not thenceforward be reckoned." },
  { book: "1 Enoch", chapter: 56, verse: 5, text: "And in those days the angels shall return \nAnd hurl themselves to the east upon the Parthians and Medes: \nThey shall stir up the kings, so that a spirit of unrest shall come upon them, \nAnd they shall rouse them from their thrones,\nThat they may break forth as lions from their lairs, \nAnd as hungry wolves among their flocks." },
  { book: "1 Enoch", chapter: 56, verse: 6, text: "And they shall go up and tread under foot the land of His elect ones, \nAnd the land of His elect ones shall be before them a threshing-floor and a highway:" },
  { book: "1 Enoch", chapter: 56, verse: 7, text: "But the city of my righteous shall be a hindrance to their horses.\n\nAnd they shall begin to fight among themselves, \nAnd their right hand shall be strong against themselves,\n\nAnd a man shall not know his brother, \nNor a son his father or his mother,\n\nTill there be no number of the corpses through their slaughter, \nAnd their punishment be not in vain." },
  { book: "1 Enoch", chapter: 56, verse: 8, text: "In those days Sheol shall open its jaws, \nAnd they shall be swallowed up therein\n\nAnd their destruction shall be at an end; \nSheol shall devour the sinners in the presence of the elect.'" },
  { book: "1 Enoch", chapter: 57, verse: 1, text: "And it came to pass after this that I saw another host of wagons, and men riding thereon, and coming on the winds from the east, and from the west to the south." },
  { book: "1 Enoch", chapter: 57, verse: 2, text: "And the noise of their wagons was heard, and when this turmoil took place the holy ones from heaven remarked it, and the pillars of the earth were moved from their place, and the sound thereof was heard from the one end of heaven to the other, in one day." },
  { book: "1 Enoch", chapter: 57, verse: 3, text: "And they shall all fall down and worship the Lord of Spirits. And this is the end of the second Parable." },
  { book: "1 Enoch", chapter: 58, verse: 1, text: "And I began to speak the third Parable concerning the righteous and elect." },
  { book: "1 Enoch", chapter: 58, verse: 2, text: "Blessed are ye, ye righteous and elect, \nFor glorious shall be your lot." },
  { book: "1 Enoch", chapter: 58, verse: 3, text: "And the righteous shall be in the light of the sun, \nAnd the elect in the light of eternal life: \nThe days of their life shall be unending, \nAnd the days of the holy without number." },
  { book: "1 Enoch", chapter: 58, verse: 4, text: "And they shall seek the light and find righteousness with the Lord of Spirits: \nThere shall be peace to the righteous in the name of the Eternal Lord." },
  { book: "1 Enoch", chapter: 58, verse: 5, text: "And after this it shall be said to the holy in heaven \nThat they should seek out the secrets of righteousness, the heritage of faith: \nFor it has become bright as the sun upon earth, \nAnd the darkness is past." },
  { book: "1 Enoch", chapter: 58, verse: 6, text: "And there shall be a light that never endeth, \nAnd to a limit (lit. 'number') of days they shall not come, \nFor the darkness shall first have been destroyed, \nAnd the light established before the Lord of Spirits \nAnd the light of uprightness established for ever before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 59, verse: 1, text: "In those days mine eyes saw the secrets of the lightnings, and of the lights, and the judgements they execute (lit. 'their judgement'): and they lighten for a blessing or a curse as the Lord of Spirits willeth." },
  { book: "1 Enoch", chapter: 59, verse: 2, text: "And there I saw the secrets of the thunder, and how when it resounds above in the heaven, the sound thereof is heard, and he caused me to see the judgements executed on the earth, whether they be for well-being and blessing, or for a curse according to the word of the Lord of Spirits." },
  { book: "1 Enoch", chapter: 59, verse: 3, text: "And after that all the secrets of the lights and lightnings were shown to me, and they lighten for blessing and for satisfying." },
  { book: "1 Enoch", chapter: 60, verse: 1, text: "In the year five hundred, in the seventh month, on the fourteenth day of the month in the life of Enoch. In that Parable I saw how a mighty quaking made the heaven of heavens to quake, and the host of the Most High, and the angels, a thousand thousands and ten thousand times ten thousand, were disquieted with a great disquiet." },
  { book: "1 Enoch", chapter: 60, verse: 2, text: "And the Head of Days sat on the throne of His glory, and the angels and the righteous stood around Him." },
  { book: "1 Enoch", chapter: 60, verse: 3, text: "And a great trembling seized me, \nAnd fear took hold of me, \nAnd my loins gave way, \nAnd dissolved were my reins, \nAnd I fell upon my face." },
  { book: "1 Enoch", chapter: 60, verse: 4, text: "And Michael sent another angel from among the holy ones and he raised me up, and when he had raised me up my spirit returned; for I had not been able to endure the look of this host, and the commotion and the quaking of the heaven. And Michael said unto me: 'Why art thou disquieted with such a vision? Until this day lasted the day of His mercy; and He hath been merciful and long-suffering towards those who dwell on the earth." },
  { book: "1 Enoch", chapter: 60, verse: 6, text: "And when the day, and the power, and the punishment, and the judgement come, which the Lord of Spirits hath prepared for those who worship not the righteous law, and for those who deny the righteous judgement, and for those who take His name in vain--that day is prepared, for the elect a covenant, but for sinners an inquisition." },
  { book: "1 Enoch", chapter: 60, verse: 7, text: "And on that day were two monsters parted, a female monster named Leviathan, to dwell in the abysses of the ocean over the fountains of the waters." },
  { book: "1 Enoch", chapter: 60, verse: 8, text: "But the male is named Behemoth, who occupied with his breast a waste wilderness named Dûidâin, on the east of the garden where the elect and righteous dwell, where my grandfather was taken up, the seventh from Adam, the first man whom the Lord of Spirits created." },
  { book: "1 Enoch", chapter: 60, verse: 9, text: "And I besought the other angel that he should show me the might of those monsters, how they were parted on one day and cast, the one into the abysses of the sea, and the other unto the dry land of the wilderness." },
  { book: "1 Enoch", chapter: 60, verse: 10, text: "And he said to me: 'Thou son of man, herein thou dost seek to know what is hidden.'" },
  { book: "1 Enoch", chapter: 60, verse: 11, text: "And the other angel who went with me and showed me what was hidden told me what is first and last in the heaven in the height, and beneath the earth in the depth, and at the ends of the heaven, and on the foundation of the heaven." },
  { book: "1 Enoch", chapter: 60, verse: 12, text: "And the chambers of the winds, and how the winds are divided, and how they are weighed, and (how) the portals of the winds are reckoned, each according to the power of the wind, and the power of the lights of the moon, and according to the power that is fitting: and the divisions of the stars according to their names, and how all the divisions are divided." },
  { book: "1 Enoch", chapter: 60, verse: 13, text: "And the thunders according to the places where they fall, and all the divisions that are made among the lightnings that it may lighten, and their host that they may at once obey." },
  { book: "1 Enoch", chapter: 60, verse: 14, text: "For the thunder has †places of rest† (which) are assigned (to it) while it is waiting for its peal; and the thunder and lightning are inseparable, and although not one and undivided, they both go together through the spirit and separate not." },
  { book: "1 Enoch", chapter: 60, verse: 15, text: "For when the lightning lightens, the thunder utters its voice, and the spirit enforces a pause during the peal, and divides equally between them; for the treasury of their peals is like the sand, and each one of them as it peals is held in with a bridle, and turned back by the power of the spirit, and pushed forward according to the many quarters of the earth. And the spirit of the sea is masculine and strong, and according to the might of his strength he draws it back with a rein, and in like manner it is driven forward and disperses amid all the mountains of the earth." },
  { book: "1 Enoch", chapter: 60, verse: 17, text: "And the spirit of the hoar-frost is his own angel, and the spirit of the hail is a good angel." },
  { book: "1 Enoch", chapter: 60, verse: 18, text: "And the spirit of the snow has forsaken his chambers on account of his strength--there is a special spirit therein, and that which ascends from it is like smoke, and its name is frost." },
  { book: "1 Enoch", chapter: 60, verse: 19, text: "And the spirit of the mist is not united with them in their chambers, but it has a special chamber; for its course is †glorious† both in light and in darkness, and in winter and in summer, and in its chamber is an angel." },
  { book: "1 Enoch", chapter: 60, verse: 20, text: "And the spirit of the dew has its dwelling at the ends of the heaven, and is connected with the chambers of the rain, and its course is in winter and summer: and its clouds and the clouds of the mist are connected, and the one gives to the other." },
  { book: "1 Enoch", chapter: 60, verse: 21, text: "And when the spirit of the rain goes forth from its chamber, the angels come and open the chamber and lead it out, and when it is diffused over the whole earth it unites with the water on the earth. And whensoever it unites with the water on the earth . . ." },
  { book: "1 Enoch", chapter: 60, verse: 22, text: "For the waters are for those who dwell on the earth; for they are nourishment for the earth from the Most High who is in heaven: therefore there is a measure for the rain, and the angels take it in charge." },
  { book: "1 Enoch", chapter: 60, verse: 23, text: "And these things I saw towards the Garden of the Righteous." },
  { book: "1 Enoch", chapter: 60, verse: 24, text: "And the angel of peace who was with me said to me: 'These two monsters, prepared conformably to the greatness of God, shall feed . . ." },
  { book: "1 Enoch", chapter: 60, verse: 25, text: "When the punishment of the Lord of Spirits shall rest upon them, it shall rest in order that the punishment of the Lord of Spirits may not come, in vain, and it shall slay the children with their mothers and the children with their fathers. Afterwards the judgement shall take place according to His mercy and His patience.'" },
  { book: "1 Enoch", chapter: 61, verse: 1, text: "And I saw in those days how long cords were given to those angels, and they took to themselves wings and flew, and they went towards the north." },
  { book: "1 Enoch", chapter: 61, verse: 2, text: "And I asked the angel, saying unto him: 'Why have those (angels) taken these cords and gone off?' And he said unto me: 'They have gone to measure.'" },
  { book: "1 Enoch", chapter: 61, verse: 3, text: "And the angel who went with me said unto me: \n'These shall bring the measures of the righteous, \nAnd the ropes of the righteous to the righteous, \nThat they may stay themselves on the name of the Lord of Spirits for ever and ever." },
  { book: "1 Enoch", chapter: 61, verse: 4, text: "The elect shall begin to dwell with the elect,\nAnd those are the measures which shall be given to faith \nAnd which shall strengthen righteousness." },
  { book: "1 Enoch", chapter: 61, verse: 5, text: "And these measures shall reveal all the secrets of the depths of the earth, \nAnd those who have been destroyed by the desert, \nAnd those who have been devoured by the beasts, \nAnd those who have been devoured by the fish of the sea,\n\nThat they may return and stay themselves \nOn the day of the Elect One; \nFor none shall be destroyed before the Lord of Spirits,\nAnd none can be destroyed." },
  { book: "1 Enoch", chapter: 61, verse: 6, text: "And all who dwell above in the heaven received a command and power and one voice and one light like unto fire." },
  { book: "1 Enoch", chapter: 61, verse: 7, text: "And that One (with) their first words they blessed, \nAnd extolled and lauded with wisdom, \nAnd they were wise in utterance and in the spirit of life." },
  { book: "1 Enoch", chapter: 61, verse: 8, text: "And the Lord of Spirits placed the Elect one on the throne of glory. \nAnd he shall judge all the works of the holy above in the heaven, \nAnd in the balance shall their deeds be weighed" },
  { book: "1 Enoch", chapter: 61, verse: 9, text: "And when he shall lift up his countenance \nTo judge their secret ways according to the word of the name of the Lord of Spirits, \nAnd their path according to the way of the righteous judgement of the Lord of Spirits, \nThen shall they all with one voice speak and bless, \nAnd glorify and extol and sanctify the name of the Lord of Spirits." },
  { book: "1 Enoch", chapter: 61, verse: 10, text: "And He will summon all the host of the heavens, and all the holy ones above, and the host of God, the Cherubin, Seraphin and Ophannin, and all the angels of power, and all the angels of principalities, and the Elect One, and the other powers on the earth (and) over the water." },
  { book: "1 Enoch", chapter: 61, verse: 11, text: "On that day shall raise one voice, and bless and glorify and exalt in the spirit of faith, and in the spirit of wisdom, and in the spirit of patience, and in the spirit of mercy, and in the spirit of judgement and of peace, and in the spirit of goodness, and shall all say with one voice: \"Blessed is He, and may the name of the Lord of Spirits be blessed for ever and ever.\"" },
  { book: "1 Enoch", chapter: 61, verse: 12, text: "All who sleep not above in heaven shall bless Him: \nAll the holy ones who are in heaven shall bless Him, \nAnd all the elect who dwell in the garden of life:\n\nAnd every spirit of light who is able to bless, and glorify, and extol, and hallow Thy blessed name, \nAnd all flesh shall beyond measure glorify and bless Thy name for ever and ever." },
  { book: "1 Enoch", chapter: 61, verse: 13, text: "For great is the mercy of the Lord of Spirits, and He is long-suffering, \nAnd all His works and all that\nHe has created He has revealed to the righteous and elect \nIn the name of the Lord of Spirits." },
  { book: "1 Enoch", chapter: 62, verse: 1, text: "And thus the Lord commanded the kings and the mighty and the exalted, and those who dwell on the earth, and said: 'Open your eyes and lift up your horns if ye are able to recognize the Elect One.'" },
  { book: "1 Enoch", chapter: 62, verse: 2, text: "And the Lord of Spirits seated him on the throne of His glory, \nAnd the spirit of righteousness was poured out upon him, \nAnd the word of his mouth slays all the sinners, \nAnd all the unrighteous are destroyed from before his face." },
  { book: "1 Enoch", chapter: 62, verse: 3, text: "And there shall stand up in that day all the kings and the mighty, \nAnd the exalted and those who hold the earth,\nAnd they shall see and recognize \nHow he sits on the throne of his glory,\nAnd righteousness is judged before him, \nAnd no lying word is spoken before him." },
  { book: "1 Enoch", chapter: 62, verse: 4, text: "Then shall pain come upon them as on a woman in travail,\nAnd she has pain in bringing forth \nWhen her child enters the mouth of the womb, \nAnd she has pain in bringing forth." },
  { book: "1 Enoch", chapter: 62, verse: 5, text: "And one portion of them shall look on the other, \nAnd they shall be terrified, \nAnd they shall be downcast of countenance, \nAnd pain shall seize them, \nWhen they see that Son of Man \nSitting on the throne of his glory." },
  { book: "1 Enoch", chapter: 62, verse: 6, text: "And the kings and the mighty and all who possess the earth shall bless and glorify and extol him who rules over all, who was hidden." },
  { book: "1 Enoch", chapter: 62, verse: 7, text: "For from the beginning the Son of Man was hidden,\nAnd the Most High preserved him in the presence of His might, \nAnd revealed him to the elect." },
  { book: "1 Enoch", chapter: 62, verse: 8, text: "And the congregation of the elect and holy shall be sown, \nAnd all the elect shall stand before him on that day." },
  { book: "1 Enoch", chapter: 62, verse: 9, text: "And all the kings and the mighty and the exalted and those who rule the earth \nShall fall down before him on their faces, \nAnd worship and set their hope upon that Son of Man, \nAnd petition him and supplicate for mercy at his hands." },
  { book: "1 Enoch", chapter: 62, verse: 10, text: "Nevertheless that Lord of Spirits will so press them \nThat they shall hastily go forth from His presence, \nAnd their faces shall be filled with shame, \nAnd the darkness grow deeper on their faces." },
  { book: "1 Enoch", chapter: 62, verse: 11, text: "And He will deliver them to the angels for punishment, \nTo execute vengeance on them because they have oppressed His children and His elect" },
  { book: "1 Enoch", chapter: 62, verse: 12, text: "And they shall be a spectacle for the righteous and for His elect: \nThey shall rejoice over them, \nBecause the wrath of the Lord of Spirits resteth upon them, \nAnd His sword is drunk with their blood." },
  { book: "1 Enoch", chapter: 62, verse: 13, text: "And the righteous and elect shall be saved on that day, \nAnd they shall never thenceforward see the face of the sinners and unrighteous." },
  { book: "1 Enoch", chapter: 62, verse: 14, text: "And the Lord of Spirits will abide over them, \nAnd with that Son of Man shall they eat \nAnd lie down and rise up for ever and ever." },
  { book: "1 Enoch", chapter: 62, verse: 15, text: "And the righteous and elect shall have risen from the earth, \nAnd ceased to be of downcast countenance." },
  { book: "1 Enoch", chapter: 62, verse: 16, text: "And they shall have been clothed with garments of glory, \nAnd these shall be the garments of life from the Lord of Spirits: \nAnd your garments shall not grow old, \nNor your glory pass away before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 63, verse: 1, text: "In those days shall the mighty and the kings who possess the earth implore (Him) to grant them a little respite from His angels of punishment to whom they were delivered, that they might fall down and worship before the Lord of Spirits, and confess their sins before Him." },
  { book: "1 Enoch", chapter: 63, verse: 2, text: "And they shall bless and glorify the Lord of Spirits, and say: \n\n'Blessed is the Lord of Spirits and the Lord of kings, \nAnd the Lord of the mighty and the Lord of the rich, \nAnd the Lord of glory and the Lord of wisdom," },
  { book: "1 Enoch", chapter: 63, verse: 3, text: "And splendid in every secret thing is Thy power from generation to generation, \nAnd Thy glory for ever and ever:\n\nDeep are all Thy secrets and innumerable, \nAnd Thy righteousness is beyond reckoning." },
  { book: "1 Enoch", chapter: 63, verse: 4, text: "We have now learnt that we should glorify \nAnd bless the Lord of kings and Him who is king over all kings.'" },
  { book: "1 Enoch", chapter: 63, verse: 5, text: "And they shall say: \n'Would that we had rest to glorify and give thanks \nAnd confess our faith before His glory!" },
  { book: "1 Enoch", chapter: 63, verse: 6, text: "And now we long for a little rest but find it not: \nWe follow hard upon and obtain (it) not:\n\nAnd light has vanished from before us,\nAnd darkness is our dwelling-place for ever and ever:" },
  { book: "1 Enoch", chapter: 63, verse: 7, text: "For we have not believed before Him \nNor glorified the name of the Lord of Spirits, nor glorified our Lord\n\nBut our hope was in the sceptre of our kingdom, \nAnd in our glory." },
  { book: "1 Enoch", chapter: 63, verse: 8, text: "And in the day of our suffering and tribulation \nHe saves us not, \nAnd we find no respite for confession\n\nThat our Lord is true in all His works, and in His judgements and His justice, \nAnd His judgements have no respect of persons." },
  { book: "1 Enoch", chapter: 63, verse: 9, text: "And we pass away from before His face on account of our works, \nAnd all our sins are reckoned up in righteousness.'" },
  { book: "1 Enoch", chapter: 63, verse: 10, text: "Now they shall say unto themselves: 'Our souls are full of unrighteous gain, but it does not prevent us from descending from the midst thereof into the burden of Sheol.'" },
  { book: "1 Enoch", chapter: 63, verse: 11, text: "And after that their faces shall be filled with darkness \nAnd shame before that Son of Man, \nAnd they shall be driven from his presence, \nAnd the sword shall abide before his face in their midst." },
  { book: "1 Enoch", chapter: 63, verse: 12, text: "Thus spake the Lord of Spirits: 'This is the ordinance and judgement with respect to the mighty and the kings and the exalted and those who possess the earth before the Lord of Spirits.'" },
  { book: "1 Enoch", chapter: 64, verse: 1, text: "And other forms I saw hidden in that place." },
  { book: "1 Enoch", chapter: 64, verse: 2, text: "I heard the voice of the angel saying: 'These are the angels who descended to the earth, and revealed what was hidden to the children of men and seduced the children of men into committing sin.'" },
  { book: "1 Enoch", chapter: 65, verse: 1, text: "And in those days Noah saw the earth that it had sunk down and its destruction was nigh." },
  { book: "1 Enoch", chapter: 65, verse: 2, text: "And he arose from thence and went to the ends of the earth, and cried aloud to his grandfather Enoch: and Noah said three times with an embittered voice: Hear me, hear me, hear me.'" },
  { book: "1 Enoch", chapter: 65, verse: 3, text: "And I said unto him: 'Tell me what it is that is falling out on the earth that the earth is in such evil plight and shaken, lest perchance I shall perish with it?'" },
  { book: "1 Enoch", chapter: 65, verse: 4, text: "And thereupon there was a great commotion on the earth, and a voice was heard from heaven, and I fell on my face." },
  { book: "1 Enoch", chapter: 65, verse: 5, text: "And Enoch my grandfather came and stood by me, and said unto me: 'Why hast thou cried unto me with a bitter cry and weeping?" },
  { book: "1 Enoch", chapter: 65, verse: 6, text: "And a command has gone forth from the presence of the Lord concerning those who dwell on the earth that their ruin is accomplished because they have learnt all the secrets of the angels, and all the violence of the Satans, and all their powers--the most secret ones--and all the power of those who practice sorcery, and the power of witchcraft, and the power of those who make molten images for the whole earth:" },
  { book: "1 Enoch", chapter: 65, verse: 7, text: "And how silver is produced from the dust of the earth, and how soft metal originates in the earth." },
  { book: "1 Enoch", chapter: 65, verse: 8, text: "For lead and tin are not produced from the earth like the first: it is a fountain that produces them, and an angel stands therein, and that angel is pre-eminent.'" },
  { book: "1 Enoch", chapter: 65, verse: 9, text: "And after that my grandfather Enoch took hold of me by my hand and raised me up, and said unto me: 'Go, for I have asked the Lord of Spirits as touching this commotion on the earth." },
  { book: "1 Enoch", chapter: 65, verse: 10, text: "And He said unto me: \"Because of their unrighteousness their judgement has been determined upon and shall not be withheld by Me for ever. Because of the sorceries which they have searched out and learnt, the earth and those who dwell upon it shall be destroyed.\"" },
  { book: "1 Enoch", chapter: 65, verse: 11, text: "And these--they have no place of repentance for ever, because they have shown them what was hidden, and they are the damned: but as for thee, my son, the Lord of Spirits knows that thou art pure, and guiltless of this reproach concerning the secrets." },
  { book: "1 Enoch", chapter: 65, verse: 12, text: "And He has destined thy name to be among the holy, \nAnd will preserve thee amongst those who dwell on the earth, \nAnd has destined thy righteous seed both for kingship and for great honours, \nAnd from thy seed shall proceed a fountain of the righteous and holy without number for ever." },
  { book: "1 Enoch", chapter: 66, verse: 1, text: "And after that he showed me the angels of punishment who are prepared to come and let loose all the powers of the waters which are beneath in the earth in order to bring judgement and destruction on all who abide and dwell on the earth." },
  { book: "1 Enoch", chapter: 66, verse: 2, text: "And the Lord of Spirits gave commandment to the angels who were going forth, that they should not cause the waters to rise but should hold them in check; for those angels were over the powers of the waters." },
  { book: "1 Enoch", chapter: 66, verse: 3, text: "And I went away from the presence of Enoch." },
  { book: "1 Enoch", chapter: 67, verse: 1, text: "And in those days the word of God came unto me, and He said unto me: 'Noah, thy lot has come up before Me, a lot without blame, a lot of love and uprightness." },
  { book: "1 Enoch", chapter: 67, verse: 2, text: "And now the angels are making a wooden building, and when they have completed that task I will place My hand upon it and preserve it, and there shall come forth from it the seed of life, and a change shall set in so that the earth will not remain without inhabitant." },
  { book: "1 Enoch", chapter: 67, verse: 3, text: "And I will make fast thy seed before me for ever and ever, and I will spread abroad those who dwell with thee: it shall not be unfruitful on the face of the earth, but it shall be blessed and multiply on the earth in the name of the Lord.'" },
  { book: "1 Enoch", chapter: 67, verse: 4, text: "And He will imprison those angels, who have shown unrighteousness, in that burning valley which my grandfather Enoch had formerly shown to me in the west among the mountains of gold and silver and iron and soft metal and tin." },
  { book: "1 Enoch", chapter: 67, verse: 5, text: "And I saw that valley in which there was a great convulsion and a convulsion of the waters." },
  { book: "1 Enoch", chapter: 67, verse: 6, text: "And when all this took place, from that fiery molten metal and from the convulsion thereof in that place, there was produced a smell of sulphur, and it was connected with those waters, and that valley of the angels who had led astray mankind burned beneath that land." },
  { book: "1 Enoch", chapter: 67, verse: 7, text: "And through its valleys proceed streams of fire, where these angels are punished who had led astray those who dwell upon the earth." },
  { book: "1 Enoch", chapter: 67, verse: 8, text: "But those waters shall in those days serve for the kings and the mighty and the exalted, and those who dwell on the earth, for the healing of the body, but for the punishment of the spirit; now their spirit is full of lust, that they may be punished in their body, for they have denied the Lord of Spirits and see their punishment daily, and yet believe not in His name." },
  { book: "1 Enoch", chapter: 67, verse: 9, text: "And in proportion as the burning of their bodies becomes severe, a corresponding change shall take place in their spirit for ever and ever; for before the Lord of Spirits none shall utter an idle word." },
  { book: "1 Enoch", chapter: 67, verse: 10, text: "For the judgement shall come upon them, because they believe in the lust of their body and deny the Spirit of the Lord." },
  { book: "1 Enoch", chapter: 67, verse: 11, text: "And those same waters will undergo a change in those days; for when those angels are punished in these waters, these water-springs shall change their temperature, and when the angels ascend, this water of the springs shall change and become cold." },
  { book: "1 Enoch", chapter: 67, verse: 12, text: "And I heard Michael answering and saying: 'This judgement wherewith the angels are judged is a testimony for the kings and the mighty who possess the earth.'" },
  { book: "1 Enoch", chapter: 67, verse: 13, text: "Because these waters of judgement minister to the healing of the body of the kings and the lust of their body; therefore they will not see and will not believe that those waters will change and become a fire which burns for ever." },
  { book: "1 Enoch", chapter: 68, verse: 1, text: "And after that my grandfather Enoch gave me the teaching of all the secrets in the book in the Parables which had been given to him, and he put them together for me in the words of the book of the Parables." },
  { book: "1 Enoch", chapter: 68, verse: 2, text: "And on that day Michael answered Raphael and said: 'The power of the spirit transports and makes me to tremble because of the severity of the judgement of the secrets, the judgement of the angels: who can endure the severe judgement which has been executed, and before which they melt away?'" },
  { book: "1 Enoch", chapter: 68, verse: 3, text: "And Michael answered again, and said to Raphael: 'Who is he whose heart is not softened concerning it, and whose reins are not troubled by this word of judgement (that) has gone forth upon them because of those who have thus led them out?'" },
  { book: "1 Enoch", chapter: 68, verse: 4, text: "And it came to pass when he stood before the Lord of Spirits, Michael said thus to Raphael: 'I will not take their part under the eye of the Lord; for the Lord of Spirits has been angry with them because they do as if they were the Lord. Therefore all that is hidden shall come upon them for ever and ever; for neither angel nor man shall have his portion (in it), but alone they have received their judgement for ever and ever.'" },
  { book: "1 Enoch", chapter: 69, verse: 1, text: "And after this judgement they shall terrify and make them to tremble because they have shown this to those who dwell on the earth." },
  { book: "1 Enoch", chapter: 69, verse: 2, text: "And behold the names of those angels and these are their names: the first of them is Samjâzâ, the second Artâqîfâ, and the third Armên, the fourth Kôkabêl, the fifth Tûrâêl, the sixth Rûmjâl, the seventh Dânjâl, the eighth Nêqâêl, the ninth Barâqêl, the tenth Azâzêl, the eleventh Armârôs, the twelfth Batarjâl, the thirteenth Busasêjal, the fourteenth Hanânêl, the fifteenth Tûrêl, and the sixteenth Sîmâpêsîêl, the seventeenth Jetrêl, the eighteenth Tûmâêl, the nineteenth Tûrêl, the twentieth Rumâêl, the twenty-first Azâzêl." },
  { book: "1 Enoch", chapter: 69, verse: 3, text: "And these are the chiefs of their angels and their names, and their chief ones over hundreds and over fifties and over tens." },
  { book: "1 Enoch", chapter: 69, verse: 4, text: "The name of the first Jeqôn: that is, the one who led astray all the sons of God, and brought them down to the earth, and led them astray through the daughters of men." },
  { book: "1 Enoch", chapter: 69, verse: 5, text: "And the second was named Asbeêl: he imparted to the holy sons of God evil counsel, and led them astray so that they defiled their bodies with the daughters of men." },
  { book: "1 Enoch", chapter: 69, verse: 6, text: "And the third was named Gâdreêl: he it is who showed the children of men all the blows of death, and he led astray Eve, and showed the weapons of death to the sons of men the shield and the coat of mail, and the sword for battle, and all the weapons of death to the children of men." },
  { book: "1 Enoch", chapter: 69, verse: 7, text: "And from his hand they have proceeded against those who dwell on the earth from that day and for evermore." },
  { book: "1 Enoch", chapter: 69, verse: 8, text: "And the fourth was named Pênêmûe: he taught the children of men the bitter and the sweet, and he taught them all the secrets of their wisdom." },
  { book: "1 Enoch", chapter: 69, verse: 9, text: "And he instructed mankind in writing with ink and paper, and thereby many sinned from eternity to eternity and until this day." },
  { book: "1 Enoch", chapter: 69, verse: 10, text: "For men were not created for such a purpose, to give confirmation to their good faith with pen and ink." },
  { book: "1 Enoch", chapter: 69, verse: 11, text: "For men were created exactly like the angels, to the intent that they should continue pure and righteous, and death, which destroys everything, could not have taken hold of them, but through this their knowledge they are perishing, and through this power it is consuming me." },
  { book: "1 Enoch", chapter: 69, verse: 12, text: "And the fifth was named Kâsdejâ: this is he who showed the children of men all the wicked smitings of spirits and demons, and the smitings of the embryo in the womb, that it may pass away, and the smitings of the soul the bites of the serpent, and the smitings which befall through the noontide heat, the son of the serpent named Tabââĕt." },
  { book: "1 Enoch", chapter: 69, verse: 13, text: "And this is the task of Kâsbeêl, the chief of the oath which he showed to the holy ones when he dwelt high above in glory, and its name is Bîqâ." },
  { book: "1 Enoch", chapter: 69, verse: 14, text: "This (angel) requested Michael to show him the hidden name, that he might enunciate it in the oath, so that those might quake before that name and oath who revealed all that was in secret to the children of men." },
  { book: "1 Enoch", chapter: 69, verse: 15, text: "And this is the power of this oath, for it is powerful and strong, and he placed this oath Akâe in the hand of Michael." },
  { book: "1 Enoch", chapter: 69, verse: 16, text: "And these are the secrets of this oath . . . \n\nAnd they are strong through his oath:\nAnd the heaven was suspended before the world was created, \nAnd for ever." },
  { book: "1 Enoch", chapter: 69, verse: 17, text: "And through it the earth was founded upon the water, \nAnd from the secret recesses of the mountains come beautiful waters,\nFrom the creation of the world and unto eternity." },
  { book: "1 Enoch", chapter: 69, verse: 18, text: "And through that oath the sea was created, \nAnd as its foundation He set for it the sand against the time of (its) anger, \nAnd it dare not pass beyond it from the creation of the world unto eternity." },
  { book: "1 Enoch", chapter: 69, verse: 19, text: "And through that oath are the depths made fast, \nAnd abide and stir not from their place from eternity to eternity." },
  { book: "1 Enoch", chapter: 69, verse: 20, text: "And through that oath the sun and moon complete their course, \nAnd deviate not from their ordinance from eternity to eternity." },
  { book: "1 Enoch", chapter: 69, verse: 21, text: "And through that oath the stars complete their course, \nAnd He calls them by their names, \nAnd they answer Him from eternity to eternity." },
  { book: "1 Enoch", chapter: 69, verse: 22, text: "And in like manner the spirits of the water, and of the winds, and of all zephyrs, and (their) paths from all the quarters of the winds." },
  { book: "1 Enoch", chapter: 69, verse: 23, text: "And there are preserved the voices of the thunder and the light of the lightnings: and there are preserved the chambers of the hail and the chambers of the hoarfrost, and the chambers of the mist, and the chambers of the rain and the dew." },
  { book: "1 Enoch", chapter: 69, verse: 24, text: "And all these believe and give thanks before the Lord of Spirits, and glorify (Him) with all their power, and their food is in every act of thanksgiving: they thank and glorify and extol the name of the Lord of Spirits for ever and ever." },
  { book: "1 Enoch", chapter: 69, verse: 25, text: "And this oath is mighty over them \nAnd through it they are preserved and their paths are preserved, \nAnd their course is not destroyed. \n\nClose of the Third Parable." },
  { book: "1 Enoch", chapter: 69, verse: 26, text: "And there was great joy amongst them, \nAnd they blessed and glorified and extolled \nBecause the name of that Son of Man had been revealed unto them." },
  { book: "1 Enoch", chapter: 69, verse: 27, text: "And he sat on the throne of his glory, \nAnd the sum of judgement was given unto the Son of Man, \nAnd he caused the sinners to pass away and be destroyed from off the face of the earth, \nAnd those who have led the world astray." },
  { book: "1 Enoch", chapter: 69, verse: 28, text: "With chains shall they be bound, \nAnd in their assemblage-place of destruction shall they be imprisoned, \nAnd all their works vanish from the face of the earth." },
  { book: "1 Enoch", chapter: 69, verse: 29, text: "And from henceforth there shall be nothing corruptible; \nFor that Son of Man has appeared, \nAnd has seated himself on the throne of his glory, \nAnd all evil shall pass away before his face, \nAnd the word of that Son of Man shall go forth \nAnd be strong before the Lord of Spirits.\n\n  \n\nThis is the Third Parable of Enoch." },
  { book: "1 Enoch", chapter: 70, verse: 1, text: "And it came to pass after this that his name during his lifetime was raised aloft to that Son of Man and to the Lord of Spirits from amongst those who dwell on the earth." },
  { book: "1 Enoch", chapter: 70, verse: 2, text: "And he was raised aloft on the chariots of the spirit and his name vanished among them." },
  { book: "1 Enoch", chapter: 70, verse: 3, text: "And from that day I was no longer numbered amongst them: and he set me between the two winds, between the North and the West, where the angels took the cords to measure for me the place for the elect and righteous." },
  { book: "1 Enoch", chapter: 70, verse: 4, text: "And there I saw the first fathers and the righteous who from the beginning dwell in that place." },
  { book: "1 Enoch", chapter: 71, verse: 1, text: "And it came to pass after this that my spirit was translated \nAnd it ascended into the heavens:\nAnd I saw the holy sons of God.\n\nThey were stepping on flames of fire: \nTheir garments were white and their raiment, \nAnd their faces shone like snow." },
  { book: "1 Enoch", chapter: 71, verse: 2, text: "And I saw two streams of fire, \nAnd the light of that fire shone like hyacinth, \nAnd I fell on my face before the Lord of Spirits." },
  { book: "1 Enoch", chapter: 71, verse: 3, text: "And the angel Michael one of the archangels seized me by my right hand, \nAnd lifted me up and led me forth into all the secrets, \nAnd he showed me all the secrets of righteousness." },
  { book: "1 Enoch", chapter: 71, verse: 4, text: "And he showed me all the secrets of the ends of the heaven, \nAnd all the chambers of all the stars, and all the luminaries, \nWhence they proceed before the face of the holy ones." },
  { book: "1 Enoch", chapter: 71, verse: 5, text: "And he translated my spirit into the heaven of heavens,\nAnd I saw there as it were a structure built of crystals, \nAnd between those crystals tongues of living fire." },
  { book: "1 Enoch", chapter: 71, verse: 6, text: "And my spirit saw the girdle which girt that house of fire, \nAnd on its four sides were streams full of living fire, \nAnd they girt that house." },
  { book: "1 Enoch", chapter: 71, verse: 7, text: "And round about were Seraphin, Cherubic, and Ophannin: \nAnd these are they who sleep not \nAnd guard the throne of His glory." },
  { book: "1 Enoch", chapter: 71, verse: 8, text: "And I saw angels who could not be counted,\nA thousand thousands, and ten thousand times ten thousand, \nEncircling that house.\n\nAnd Michael, and Raphael, and Gabriel, and Phanuel, \nAnd the holy angels who are above the heavens, \nGo in and out of that house." },
  { book: "1 Enoch", chapter: 71, verse: 9, text: "And they came forth from that house, \nAnd Michael and Gabriel, Raphael and Phanuel, \nAnd many holy angels without number." },
  { book: "1 Enoch", chapter: 71, verse: 10, text: "And with them the Head of Days, \nHis head white and pure as wool, \nAnd His raiment indescribable." },
  { book: "1 Enoch", chapter: 71, verse: 11, text: "And I fell on my face, \nAnd my whole body became relaxed, \nAnd my spirit was transfigured;\n\nAnd I cried with a loud voice, \n. . .with the spirit of power, \nAnd blessed and glorified and extolled." },
  { book: "1 Enoch", chapter: 71, verse: 12, text: "And these blessings which went forth out of my mouth were well pleasing before that Head of Days." },
  { book: "1 Enoch", chapter: 71, verse: 13, text: "And that Head of Days came with Michael and Gabriel, Raphael and Phanuel, thousands and ten thousands of angels without number.\n\n[Lost passage wherein the Son of Man was described as accompanying the Head of Days, and Enoch asked one of the angels concerning the Son of Man as to who he was.]" },
  { book: "1 Enoch", chapter: 71, verse: 14, text: "And he (i.e. the angel) came to me and greeted me with His voice, and said unto me: \n\n'This is the Son of Man who is born unto righteousness; \nAnd righteousness abides over him, \nAnd the righteousness of the Head of Days forsakes him not.'" },
  { book: "1 Enoch", chapter: 71, verse: 15, text: "And he said unto me: 'He proclaims unto thee peace in the name of the world to come; \nFor from hence has proceeded peace since the creation of the world, \nAnd so shall it be unto thee for ever and for ever and ever." },
  { book: "1 Enoch", chapter: 71, verse: 16, text: "And all shall walk in his ways since righteousness never forsaketh him:\nWith him will be their dwelling-places, and with him their heritage, \nAnd they shall not be separated from him for ever and ever and ever." },
  { book: "1 Enoch", chapter: 71, verse: 17, text: "And so there shall be length of days with that Son of Man, \nAnd the righteous shall have peace and an upright way \nIn the name of the Lord of Spirits for ever and ever.'" },
  { book: "1 Enoch", chapter: 72, verse: 1, text: "The book of the courses of the luminaries of the heaven, the relations of each, according to their classes, their dominion and their seasons, according to their names and places of origin, and according to their months, which Uriel, the holy angel, who was with me, who is their guide, showed me; and he showed me all their laws exactly as they are, and how it is with regard to all the years of the world and unto eternity, till the new creation is accomplished which dureth till eternity." },
  { book: "1 Enoch", chapter: 72, verse: 2, text: "And this is the first law of the luminaries: the luminary the Sun has its rising in the eastern portals of the heaven, and its setting in the western portals of the heaven." },
  { book: "1 Enoch", chapter: 72, verse: 3, text: "And I saw six portals in which the sun rises, and six portals in which the sun sets: and the moon rises and sets in these portals, and the leaders of the stars and those whom they lead: six in the east and six in the west, and all following each other in accurately corresponding order: also many windows to the right and left of these portals." },
  { book: "1 Enoch", chapter: 72, verse: 4, text: "And first there goes forth the great luminary, named the Sun, and his circumference is like the circumference of the heaven, and he is quite filled with illuminating and heating fire." },
  { book: "1 Enoch", chapter: 72, verse: 5, text: "The chariot on which he ascends, the wind drives, and the sun goes down from the heaven and returns through the north in order to reach the east, and is so guided that he comes to the appropriate (lit. 'that') portal and shines in the face of the heaven." },
  { book: "1 Enoch", chapter: 72, verse: 6, text: "In this way he rises in the first month in the great portal, which is the fourth those six portals in the east." },
  { book: "1 Enoch", chapter: 72, verse: 7, text: "And in that fourth portal from which the sun rises in the first month are twelve window-openings, from which proceed a flame when they are opened in their season." },
  { book: "1 Enoch", chapter: 72, verse: 8, text: "When the sun rises in the heaven, he comes forth through that fourth portal thirty mornings in succession, and sets accurately in the fourth portal in the west of the heaven." },
  { book: "1 Enoch", chapter: 72, verse: 9, text: "And during this period the day becomes daily longer and the night nightly shorter to the thirtieth morning." },
  { book: "1 Enoch", chapter: 72, verse: 10, text: "On that day the day is longer than the night by a ninth part, and the day amounts exactly to ten parts and the night to eight parts." },
  { book: "1 Enoch", chapter: 72, verse: 11, text: "And the sun rises from that fourth portal, and sets in the fourth and returns to the fifth portal of the east thirty mornings, and rises from it and sets in the fifth portal." },
  { book: "1 Enoch", chapter: 72, verse: 12, text: "And then the day becomes longer by two parts and amounts to eleven parts, and the night becomes shorter and amounts to seven parts." },
  { book: "1 Enoch", chapter: 72, verse: 13, text: "And it returns to the east and enters into the sixth portal, and rises and sets in the sixth portal one and thirty mornings on account of its sign." },
  { book: "1 Enoch", chapter: 72, verse: 14, text: "On that day the day becomes longer than the night, and the day becomes double the night, and the day becomes twelve parts, and the night is shortened and becomes six parts." },
  { book: "1 Enoch", chapter: 72, verse: 15, text: "And the sun mounts up to make the day shorter and the night longer, and the sun returns to the east and enters into the sixth portal, and rises from it and sets thirty mornings." },
  { book: "1 Enoch", chapter: 72, verse: 16, text: "And when thirty mornings are accomplished, the day decreases by exactly one part, and becomes eleven parts, and the night seven." },
  { book: "1 Enoch", chapter: 72, verse: 17, text: "And the sun goes forth from that sixth portal in the west, and goes to the east and rises in the fifth portal for thirty mornings, and sets in the west again in the fifth western portal." },
  { book: "1 Enoch", chapter: 72, verse: 18, text: "On that day the day decreases by two parts, and amounts to ten parts and the night to eight parts." },
  { book: "1 Enoch", chapter: 72, verse: 19, text: "And the sun goes forth from that fifth portal and sets in the fifth portal of the west, and rises in the fourth portal for one and thirty mornings on account of its sign, and sets in the west." },
  { book: "1 Enoch", chapter: 72, verse: 20, text: "On that day the day is equalized with the night, and becomes of equal length, and the night amounts to nine parts and the day to nine parts." },
  { book: "1 Enoch", chapter: 72, verse: 21, text: "And the sun rises from that portal and sets in the west, and returns to the east and rises thirty mornings in the third portal and sets in the west in the third portal." },
  { book: "1 Enoch", chapter: 72, verse: 22, text: "And on that day the night becomes longer than the day, and night becomes longer than night, and day shorter than day till the thirtieth morning, and the night amounts exactly to ten parts and the day to eight parts." },
  { book: "1 Enoch", chapter: 72, verse: 23, text: "And the sun rises from that third portal and sets in the third portal in the west and returns to the east, and for thirty mornings rises in the second portal in the east, and in like manner sets in the second portal in the west of the heaven." },
  { book: "1 Enoch", chapter: 72, verse: 24, text: "And on that day the night amounts to eleven parts and the day to seven parts." },
  { book: "1 Enoch", chapter: 72, verse: 25, text: "And the sun rises on that day from that second portal and sets in the west in the second portal, and returns to the east into the first portal for one and thirty mornings, and sets in the first portal in the west of the heaven." },
  { book: "1 Enoch", chapter: 72, verse: 26, text: "And on that day the night becomes longer and amounts to the double of the day: and the night amounts exactly to twelve parts and the day to six." },
  { book: "1 Enoch", chapter: 72, verse: 27, text: "And the sun has (therewith) traversed the divisions of his orbit and turns again on those divisions of his orbit, and enters that portal thirty mornings and sets also in the west opposite to it." },
  { book: "1 Enoch", chapter: 72, verse: 28, text: "And on that night has the night decreased in length by a ninth part, and the night has become eleven parts and the day seven parts." },
  { book: "1 Enoch", chapter: 72, verse: 29, text: "And the sun has returned and entered into the second portal in the east, and returns on those his divisions of his orbit for thirty mornings, rising and setting." },
  { book: "1 Enoch", chapter: 72, verse: 30, text: "And on that day the night decreases in length, and the night amounts to ten parts and the day to eight." },
  { book: "1 Enoch", chapter: 72, verse: 31, text: "And on that day the sun rises from that portal, and sets in the west, and returns to the east, and rises in the third portal for one and thirty mornings, and sets in the west of the heaven." },
  { book: "1 Enoch", chapter: 72, verse: 32, text: "On that day the night decreases and amounts to nine parts, and the day to nine parts, and the night is equal to the day and the year is exactly as to its days three hundred and sixty-four." },
  { book: "1 Enoch", chapter: 72, verse: 33, text: "And the length of the day and of the night, and the shortness of the day and of the night arise--through the course of the sun these distinctions are made (lit. 'they are separated')." },
  { book: "1 Enoch", chapter: 72, verse: 34, text: "So it comes that its course becomes daily longer, and its course nightly shorter." },
  { book: "1 Enoch", chapter: 72, verse: 35, text: "And this is the law and the course of the sun, and his return as often as he returns sixty times and rises, i.e. the great luminary which is named the Sun, for ever and ever." },
  { book: "1 Enoch", chapter: 72, verse: 36, text: "And that which (thus) rises is the great luminary, and is so named according to its appearance, according as the Lord commanded." },
  { book: "1 Enoch", chapter: 72, verse: 37, text: "As he rises, so he sets and decreases not, and rests not, but runs day and night, and his light is sevenfold brighter than that of the moon; but as regards size they are both equal." },
  { book: "1 Enoch", chapter: 73, verse: 1, text: "And after this law I saw another law dealing with the smaller luminary, which is named the Moon." },
  { book: "1 Enoch", chapter: 73, verse: 2, text: "And her circumference is like the circumference of the heaven, and her chariot in which she rides is driven by the wind, and light is given to her in (definite) measure." },
  { book: "1 Enoch", chapter: 73, verse: 3, text: "And her rising and setting change every month: and her days are like the days of the sun, and when her light is uniform (i.e. full) it amounts to the seventh part of the light of the sun." },
  { book: "1 Enoch", chapter: 73, verse: 4, text: "And thus she rises. And her first phase in the east comes forth on the thirtieth morning: and on that day she becomes visible, and constitutes for you the first phase of the moon on the thirtieth day together with the sun in the portal where the sun rises." },
  { book: "1 Enoch", chapter: 73, verse: 5, text: "And the one half of her goes forth by a seventh part, and her whole circumference is empty, without light, with the exception of one-seventh part of it, (and) the fourteenth part of her light." },
  { book: "1 Enoch", chapter: 73, verse: 6, text: "And when she receives one-seventh part of the half of her light, her light amounts to one-seventh part and the half thereof." },
  { book: "1 Enoch", chapter: 73, verse: 7, text: "And she sets with the sun, and when the sun rises the moon rises with him and receives the half of one part of light, and in that night in the beginning of her morning in the commencement of the lunar day the moon sets with the sun, and is invisible that night with the fourteen parts and the half of one of them." },
  { book: "1 Enoch", chapter: 73, verse: 8, text: "And she rises on that day with exactly a seventh part, and comes forth and recedes from the rising of the sun, and in her remaining days she becomes bright in the (remaining) thirteen parts." },
  { book: "1 Enoch", chapter: 74, verse: 1, text: "And I saw another course, a law for her, (and) how according to that law she performs her monthly revolution." },
  { book: "1 Enoch", chapter: 74, verse: 2, text: "And all these Uriel, the holy angel who is the leader of them all, showed to me, and their positions, and I wrote down their positions as he showed them to me, and I wrote down their months as they were, and the appearance of their lights till fifteen days were accomplished." },
  { book: "1 Enoch", chapter: 74, verse: 3, text: "In single seventh parts she accomplishes all her light in the east, and in single seventh parts accomplishes all her darkness in the west." },
  { book: "1 Enoch", chapter: 74, verse: 4, text: "And in certain months she alters her settings, and in certain months she pursues her own peculiar course." },
  { book: "1 Enoch", chapter: 74, verse: 5, text: "In two months the moon sets with the sun in those two middle portals the third and the fourth." },
  { book: "1 Enoch", chapter: 74, verse: 6, text: "She goes forth for seven days, and turns about and returns again through the portal where the sun rises, and accomplishes all her light: and she recedes from the sun, and in eight days enters the sixth portal from which the sun goes forth." },
  { book: "1 Enoch", chapter: 74, verse: 7, text: "And when the sun goes forth from the fourth portal she goes forth seven days, until she goes forth from the fifth and turns back again in seven days into the fourth portal and accomplishes all her light: and she recedes and enters into the first portal in eight days." },
  { book: "1 Enoch", chapter: 74, verse: 8, text: "And she returns again in seven days into the fourth portal from which the sun goes forth." },
  { book: "1 Enoch", chapter: 74, verse: 9, text: "Thus I saw their position--how the moons rose and the sun set in those days." },
  { book: "1 Enoch", chapter: 74, verse: 10, text: "And if five years are added together the sun has an overplus of thirty days, and all the days which accrue to it for one of those five years, when they are full, amount to 364 days." },
  { book: "1 Enoch", chapter: 74, verse: 11, text: "And the overplus of the sun and of the stars amounts to six days: in 5 years 6 days every year come to 30 days: and the moon falls behind the sun and stars to the number of 30 days." },
  { book: "1 Enoch", chapter: 74, verse: 12, text: "And the sun and the stars bring in all the years exactly, so that they do not advance or delay their position by a single day unto eternity; but complete the years with perfect justice in 364 days." },
  { book: "1 Enoch", chapter: 74, verse: 13, text: "In 3 years there are 1092 days, and in 5 years 1820 days, so that in 8 years there are 2912 days." },
  { book: "1 Enoch", chapter: 74, verse: 14, text: "For the moon alone the days amount in 3 years to 1062 days, and in 5 years she falls 50 days behind: i.e. to the sum (of 1770) there is to be added (1000 and) 62 days." },
  { book: "1 Enoch", chapter: 74, verse: 15, text: "And in 5 years there are 1770 days, so that for the moon the days in 8 years amount to 2832 days." },
  { book: "1 Enoch", chapter: 74, verse: 16, text: "For in 8 years she falls behind to the amount of 80 days, all the days she falls behind in 8 years are 80." },
  { book: "1 Enoch", chapter: 74, verse: 17, text: "And the year is accurately completed in conformity with their world-stations and the stations of the sun, which rise from the portals through which it (the sun) rises and sets 30 days." },
  { book: "1 Enoch", chapter: 75, verse: 1, text: "And the leaders of the heads of the thousands, who are placed over the whole creation and over all the stars, have also to do with the four intercalary days, being inseparable from their office, according to the reckoning of the year, and these render service on the four days which are not reckoned in the reckoning of the year." },
  { book: "1 Enoch", chapter: 75, verse: 2, text: "And owing to them men go wrong therein, for those luminaries truly render service on the world-stations, one in the first portal, one in the third portal of the heaven, one in the fourth portal, and one in the sixth portal, and the exactness of the year is accomplished through its separate three hundred and sixty-four stations." },
  { book: "1 Enoch", chapter: 75, verse: 3, text: "For the signs and the times and the years and the days the angel Uriel showed to me, whom the Lord of glory hath set for ever over all the luminaries of the heaven, in the heaven and in the world, that they should rule on the face of the heaven and be seen on the earth, and be leaders for the day and the night, i.e. the sun, moon, and stars, and all the ministering creatures which make their revolution in all the chariots of the heaven." },
  { book: "1 Enoch", chapter: 75, verse: 4, text: "In like manner twelve doors Uriel showed me, open in the circumference of the sun's chariot in the heaven, through which the rays of the sun break forth: and from them is warmth diffused over the earth, when they are opened at their appointed seasons." },
  { book: "1 Enoch", chapter: 75, verse: 5, text: "And for the winds and the spirit of the dew when they are opened, standing open in the heavens at the ends." },
  { book: "1 Enoch", chapter: 75, verse: 6, text: "As for the twelve portals in the heaven, at the ends of the earth, out of which go forth the sun, moon, and stars, and all the works of heaven in the east and in the west," },
  { book: "1 Enoch", chapter: 75, verse: 7, text: "There are many windows open to the left and right of them, and one window at its (appointed) season produces warmth, corresponding (as these do) to those doors from which the stars come forth according as He has commanded them, and wherein they set corresponding to their number." },
  { book: "1 Enoch", chapter: 75, verse: 8, text: "And I saw chariots in the heaven, running in the world, above those portals in which revolve the stars that never set." },
  { book: "1 Enoch", chapter: 75, verse: 9, text: "And one is larger than all the rest, and it is that that makes its course through the entire world." },
  { book: "1 Enoch", chapter: 76, verse: 1, text: "And at the ends of the earth I saw twelve portals open to all the quarters (of the heaven), from which the winds go forth and blow over the earth." },
  { book: "1 Enoch", chapter: 76, verse: 2, text: "Three of them are open on the face (i.e. the east) of the heavens, and three in the west, and three on the right (i.e. the south) of the heaven, and three on the left (i.e. the north)." },
  { book: "1 Enoch", chapter: 76, verse: 3, text: "And the three first are those of the east, and three are of the north, and three after those on the left of the south, and three of the west." },
  { book: "1 Enoch", chapter: 76, verse: 4, text: "Through four of these come winds of blessing and prosperity, and from those eight come hurtful winds: when they are sent, they bring destruction on all the earth and on the water upon it, and on all who dwell thereon, and on everything which is in the water and on the land." },
  { book: "1 Enoch", chapter: 76, verse: 5, text: "And the first wind from those portals, called the east wind, comes forth through the first portal which is in the east, inclining towards the south: from it come forth desolation, drought, heat, and destruction." },
  { book: "1 Enoch", chapter: 76, verse: 6, text: "And through the second portal in the middle comes what is fitting, and from it there come rain and fruitfulness and prosperity and dew; and through the third portal which lies toward the north come cold and drought." },
  { book: "1 Enoch", chapter: 76, verse: 7, text: "And after these come forth the south winds through three portals: through the first portal of them inclining to the east comes forth a hot wind." },
  { book: "1 Enoch", chapter: 76, verse: 8, text: "And through the middle portal next to it there come forth fragrant smells, and dew and rain, and prosperity and health." },
  { book: "1 Enoch", chapter: 76, verse: 9, text: "And through the third portal lying to the west come forth dew and rain, locusts and desolation." },
  { book: "1 Enoch", chapter: 76, verse: 10, text: "And after these the north winds: from the seventh portal in the east come dew and rain, locusts and desolation." },
  { book: "1 Enoch", chapter: 76, verse: 11, text: "And from the middle portal come in a direct direction health and rain and dew and prosperity; and through the third portal in the west come cloud and hoar-frost, and snow and rain, and dew and locusts." },
  { book: "1 Enoch", chapter: 76, verse: 12, text: "And after these four are the west winds: through the first portal adjoining the north come forth dew and hoar-frost, and cold and snow and frost. And from the middle portal come forth dew and rain, and prosperity and blessing; and through the last portal which adjoins the south come forth drought and desolation, and burning and destruction." },
  { book: "1 Enoch", chapter: 76, verse: 14, text: "And the twelve portals of the four quarters of the heaven are therewith completed, and all their laws and all their plagues and all their benefactions have I shown to thee, my son Methuselah." },
  { book: "1 Enoch", chapter: 77, verse: 1, text: "And the first quarter is called the east, because it is the first: and the second, the south, because the Most High will descend there, yea, there in quite a special sense will He who is blessed for ever descend." },
  { book: "1 Enoch", chapter: 77, verse: 2, text: "And the west quarter is named the diminished, because there all the luminaries of the heaven wane and go down." },
  { book: "1 Enoch", chapter: 77, verse: 3, text: "And the fourth quarter, named the north, is divided into three parts: the first of them is for the dwelling of men: and the second contains seas of water, and the abysses and forests and rivers, and darkness and clouds; and the third part contains the garden of righteousness." },
  { book: "1 Enoch", chapter: 77, verse: 4, text: "I saw seven high mountains, higher than all the mountains which are on the earth: and thence comes forth hoar-frost, and days, seasons, and years pass away." },
  { book: "1 Enoch", chapter: 77, verse: 5, text: "I saw seven rivers on the earth larger than all the rivers: one of them coming from the west pours its waters into the Great Sea." },
  { book: "1 Enoch", chapter: 77, verse: 6, text: "And these two come from the north to the sea and pour their waters into the Erythraean Sea in the east." },
  { book: "1 Enoch", chapter: 77, verse: 7, text: "And the remaining four come forth on the side of the north to their own sea, two of them to the Erythraean Sea, and two into the Great Sea and discharge themselves there and some say: into the desert." },
  { book: "1 Enoch", chapter: 77, verse: 8, text: "Seven great islands I saw in the sea and in the mainland: two in the mainland and five in the Great Sea." },
  { book: "1 Enoch", chapter: 78, verse: 1, text: "And the names of the sun are the following: the first Orjârês, and the second Tômâs." },
  { book: "1 Enoch", chapter: 78, verse: 2, text: "And the moon has four names: the first name is Asônjâ, the second Eblâ, the third Benâsê, and the fourth Erâe." },
  { book: "1 Enoch", chapter: 78, verse: 3, text: "These are the two great luminaries: their circumference is like the circumference of the heaven, and the size of the circumference of both is alike." },
  { book: "1 Enoch", chapter: 78, verse: 4, text: "In the circumference of the sun there are seven portions of light which are added to it more than to the moon, and in definite measures it is transferred till the seventh portion of the sun is exhausted." },
  { book: "1 Enoch", chapter: 78, verse: 5, text: "And they set and enter the portals of the west, and make their revolution by the north, and come forth through the eastern portals on the face of the heaven." },
  { book: "1 Enoch", chapter: 78, verse: 6, text: "And when the moon rises one-fourteenth part appears in the heaven: the light becomes full in her: on the fourteenth day she accomplishes her light." },
  { book: "1 Enoch", chapter: 78, verse: 7, text: "And fifteen parts of light are transferred to her till the fifteenth day (when) her light is accomplished, according to the sign of the year, and she becomes fifteen parts, and the moon grows by (the addition of) fourteenth parts." },
  { book: "1 Enoch", chapter: 78, verse: 8, text: "And in her waning (the moon) decreases on the first day to fourteen parts of her light, on the second to thirteen parts of light, on the third to twelve, on the fourth to eleven, on the fifth to ten, on the sixth to nine, on the seventh to eight, on the eighth to seven, on the ninth to six, on the tenth to five, on the eleventh to four, on the twelfth to three, on the thirteenth to two, on the fourteenth to the half of a seventh, and all her remaining light disappears wholly on the fifteenth." },
  { book: "1 Enoch", chapter: 78, verse: 9, text: "And in certain months the month has twenty-nine days and once twenty-eight." },
  { book: "1 Enoch", chapter: 78, verse: 10, text: "And Uriel showed me another law: when light is transferred to the moon, and on which side it is transferred to her by the sun." },
  { book: "1 Enoch", chapter: 78, verse: 11, text: "During all the period during which the moon is growing in her light, she is transferring it to herself when opposite to the sun during fourteen days her light is accomplished in the heaven, and when she is illumined throughout, her light is accomplished full in the heaven." },
  { book: "1 Enoch", chapter: 78, verse: 12, text: "And on the first day she is called the new moon, for on that day the light rises upon her." },
  { book: "1 Enoch", chapter: 78, verse: 13, text: "She becomes full moon exactly on the day when the sun sets in the west, and from the east she rises at night, and the moon shines the whole night through till the sun rises over against her and the moon is seen over against the sun." },
  { book: "1 Enoch", chapter: 78, verse: 14, text: "On the side whence the light of the moon comes forth, there again she wanes till all the light vanishes and all the days of the month are at an end, and her circumference is empty, void of light." },
  { book: "1 Enoch", chapter: 78, verse: 15, text: "And three months she makes of thirty days, and at her time she makes three months of twenty-nine days each, in which she accomplishes her waning in the first period of time, and in the first portal for one hundred and seventy-seven days." },
  { book: "1 Enoch", chapter: 78, verse: 16, text: "And in the time of her going out she appears for three months (of) thirty days each, and for three months she appears (of) twenty-nine each." },
  { book: "1 Enoch", chapter: 78, verse: 17, text: "At night she appears like a man for twenty days each time, and by day she appears like the heaven, and there is nothing else in her save her light." },
  { book: "1 Enoch", chapter: 79, verse: 1, text: "And now, my son, I have shown thee everything, and the law of all the stars of the heaven is completed." },
  { book: "1 Enoch", chapter: 79, verse: 2, text: "And he showed me all the laws of these for every day, and for every season of bearing rule, and for every year, and for its going forth, and for the order prescribed to it every month and every week:" },
  { book: "1 Enoch", chapter: 79, verse: 3, text: "And the waning of the moon which takes place in the sixth portal: for in this sixth portal her light is accomplished, and after that there is the beginning of the waning:" },
  { book: "1 Enoch", chapter: 79, verse: 4, text: "And the waning which takes place in the first portal in its season, till one hundred and seventy-seven days are accomplished: reckoned according to weeks, twenty-five (weeks) and two days." },
  { book: "1 Enoch", chapter: 79, verse: 5, text: "She falls behind the sun and the order of the stars exactly five days in the course of one period, and when this place which thou seest has been traversed." },
  { book: "1 Enoch", chapter: 79, verse: 6, text: "Such is the picture and sketch of every luminary which Uriel the archangel, who is their leader, showed unto me." },
  { book: "1 Enoch", chapter: 80, verse: 1, text: "And in those days the angel Uriel answered and said to me: 'Behold, I have shown thee everything, Enoch, and I have revealed everything to thee that thou shouldst see this sun and this moon, and the leaders of the stars of the heaven and all those who turn them, their tasks and times and departures." },
  { book: "1 Enoch", chapter: 80, verse: 2, text: "And in the days of the sinners the years shall be shortened, \nAnd their seed shall be tardy on their lands and fields, \nAnd all things on the earth shall alter, \n\nAnd shall not appear in their time: \nAnd the rain shall be kept back \nAnd the heaven shall withhold (it)." },
  { book: "1 Enoch", chapter: 80, verse: 3, text: "And in those times the fruits of the earth shall be backward, \nAnd shall not grow in their time, \nAnd the fruits of the trees shall be withheld in their time." },
  { book: "1 Enoch", chapter: 80, verse: 4, text: "And the moon shall alter her order, \nAnd not appear at her time." },
  { book: "1 Enoch", chapter: 80, verse: 5, text: "And in those days the sun shall be seen and he shall journey in the evening on the extremity of the great chariot in the west \nAnd shall shine more brightly than accords with the order of light." },
  { book: "1 Enoch", chapter: 80, verse: 6, text: "And many chiefs of the stars shall transgress the order (prescribed). \nAnd these shall alter their orbits and tasks, \nAnd not appear at the seasons prescribed to them." },
  { book: "1 Enoch", chapter: 80, verse: 7, text: "And the whole order of the stars shall be concealed from the sinners, \nAnd the thoughts of those on the earth shall err concerning them, \nAnd they shall be altered from all their ways, \nYea, they shall err and take them to be gods." },
  { book: "1 Enoch", chapter: 80, verse: 8, text: "And evil shall be multiplied upon them, \nAnd punishment shall come upon them \nSo as to destroy all.'" },
  { book: "1 Enoch", chapter: 81, verse: 1, text: "And he said unto me: 'Observe, Enoch, these heavenly tablets, \nAnd read what is written thereon, \nAnd mark every individual fact.'" },
  { book: "1 Enoch", chapter: 81, verse: 2, text: "And I observed the heavenly tablets, and read everything which was written (thereon) and understood everything, and read the book of all the deeds of mankind, and of all the children of flesh that shall be upon the earth to the remotest generations." },
  { book: "1 Enoch", chapter: 81, verse: 3, text: "And forthwith I blessed the great Lord the King of glory for ever, in that He has made all the works of the world, \n\nAnd I extolled the Lord because of His patience, \nAnd blessed Him because of the children of men." },
  { book: "1 Enoch", chapter: 81, verse: 4, text: "And after that I said: 'Blessed is the man who dies in righteousness and goodness, \nConcerning whom there is no book of unrighteousness written, \nAnd against whom no day of judgement shall be found.'" },
  { book: "1 Enoch", chapter: 81, verse: 5, text: "And those seven holy ones brought me and placed me on the earth before the door of my house, and said to me: 'Declare everything to thy son Methuselah, and show to all thy children that no flesh is righteous in the sight of the Lord, for He is their Creator." },
  { book: "1 Enoch", chapter: 81, verse: 6, text: "One year we will leave thee with thy son, till thou givest thy (last) commands, that thou mayest teach thy children and record (it) for them, and testify to all thy children; and in the second year they shall take thee from their midst." },
  { book: "1 Enoch", chapter: 81, verse: 7, text: "Let thy heart be strong, \nFor the good shall announce righteousness to the good;\n\nThe righteous with the righteous shall rejoice, \nAnd shall offer congratulation to one another." },
  { book: "1 Enoch", chapter: 81, verse: 8, text: "But the sinners shall die with the sinners, \nAnd the apostate go down with the apostate." },
  { book: "1 Enoch", chapter: 81, verse: 9, text: "And those who practice righteousness shall die on account of the deeds of men, \nAnd be taken away on account of the doings of the godless.'" },
  { book: "1 Enoch", chapter: 81, verse: 10, text: "And in those days they ceased to speak to me, and I came to my people, blessing the Lord of the world." },
  { book: "1 Enoch", chapter: 82, verse: 1, text: "And now, my son Methuselah, all these things I am recounting to thee and writing down for thee, and I have revealed to thee everything, and given thee books concerning all these: so preserve, my son Methuselah, the books from thy father's hand, and (see) that thou deliver them to the generations of the world." },
  { book: "1 Enoch", chapter: 82, verse: 2, text: "I have given Wisdom to thee and to thy children, \nAnd thy children that shall be to thee, \nThat they may give it to their children for generations, \nThis wisdom (namely) that passeth their thought." },
  { book: "1 Enoch", chapter: 82, verse: 3, text: "And those who understand it shall not sleep, \nBut shall listen with the ear that they may learn this wisdom, \nAnd it shall please those that eat thereof better than good food." },
  { book: "1 Enoch", chapter: 82, verse: 4, text: "Blessed are all the righteous, blessed are all those who walk in the way of righteousness and sin not as the sinners, in the reckoning of all their days in which the sun traverses the heaven, entering into and departing from the portals for thirty days with the heads of thousands of the order of the stars, together with the four which are intercalated which divide the four portions of the year, which lead them and enter with them four days." },
  { book: "1 Enoch", chapter: 82, verse: 5, text: "Owing to them men shall be at fault and not reckon them in the whole reckoning of the year: yea, men shall be at fault, and not recognize them accurately." },
  { book: "1 Enoch", chapter: 82, verse: 6, text: "For they belong to the reckoning of the year and are truly recorded (thereon) for ever, one in the first portal and one in the third, and one in the fourth and one in the sixth, and the year is completed in three hundred and sixty-four days." },
  { book: "1 Enoch", chapter: 82, verse: 7, text: "And the account thereof is accurate and the recorded reckoning thereof exact; for the luminaries, and months and festivals, and years and days, has Uriel shown and revealed to me, to whom the Lord of the whole creation of the world hath subjected the host of heaven." },
  { book: "1 Enoch", chapter: 82, verse: 8, text: "And he has power over night and day in the heaven to cause the light to give light to men--sun, moon, and stars, and all the powers of the heaven which revolve in their circular chariots." },
  { book: "1 Enoch", chapter: 82, verse: 9, text: "And these are the orders of the stars, which set in their places, and in their seasons and festivals and months." },
  { book: "1 Enoch", chapter: 82, verse: 10, text: "And these are the names of those who lead them, who watch that they enter at their times, in their orders, in their seasons, in their months, in their periods of dominion, and in their positions." },
  { book: "1 Enoch", chapter: 82, verse: 11, text: "Their four leaders who divide the four parts of the year enter first; and after them the twelve leaders of the orders who divide the months; and for the three hundred and sixty (days) there are heads over thousands who divide the days; and for the four intercalary days there are the leaders which sunder the four parts of the year." },
  { book: "1 Enoch", chapter: 82, verse: 12, text: "And these heads over thousands are intercalated between leader and leader, each behind a station, but their leaders make the division." },
  { book: "1 Enoch", chapter: 82, verse: 13, text: "And these are the names of the leaders who divide the four parts of the year which are ordained: Mîlkî'êl, Hel'emmêlêk, and Mêl'êjal, and Nârêl." },
  { book: "1 Enoch", chapter: 82, verse: 14, text: "And the names of those who lead them: Adnâr'êl, and Îjâsûsa'êl, and 'Elômê'êl--these three follow the leaders of the orders, and there is one that follows the three leaders of the orders which follow those leaders of stations that divide the four parts of the year." },
  { book: "1 Enoch", chapter: 82, verse: 15, text: "In the beginning of the year Melkejâl rises first and rules, who is named Tam'âinî and sun, and all the days of his dominion whilst he bears rule are ninety-one days." },
  { book: "1 Enoch", chapter: 82, verse: 16, text: "And these are the signs of the days which are to be seen on earth in the days of his dominion: sweat, and heat, and calms; and all the trees bear fruit, and leaves are produced on all the trees, and the harvest of wheat, and the rose-flowers, and all the flowers which come forth in the field, but the trees of the winter season become withered." },
  { book: "1 Enoch", chapter: 82, verse: 17, text: "And these are the names of the leaders which are under them: Berka'êl, Zêlebs'êl, and another who is added a head of a thousand, called Hîlûjâsĕph: and the days of the dominion of this (leader) are at an end." },
  { book: "1 Enoch", chapter: 82, verse: 18, text: "The next leader after him is Hêl'emmêlêk, whom one names the shining sun, and all the days of his light are ninety-one days." },
  { book: "1 Enoch", chapter: 82, verse: 19, text: "And these are the signs of (his) days on the earth: glowing heat and dryness, and the trees ripen their fruits and produce all their fruits ripe and ready, and the sheep pair and become pregnant, and all the fruits of the earth are gathered in, and everything that is in the fields, and the winepress: these things take place in the days of his dominion." },
  { book: "1 Enoch", chapter: 82, verse: 20, text: "These are the names, and the orders, and the leaders of those heads of thousands: Gîdâ'îjal, Kê'êl, and Hê'êl, and the name of the head of a thousand which is added to them, Asfâ'êl': and the days of his dominion are at an end." },
  { book: "1 Enoch", chapter: 83, verse: 1, text: "And now, my son Methuselah, I will show thee all my visions which I have seen, recounting them before thee." },
  { book: "1 Enoch", chapter: 83, verse: 2, text: "Two visions I saw before I took a wife, and the one was quite unlike the other: the first when I was learning to write: the second before I took thy mother, (when) I saw a terrible vision. And regarding them I prayed to the Lord." },
  { book: "1 Enoch", chapter: 83, verse: 3, text: "I had laid me down in the house of my grandfather Mahalalel, (when) I saw in a vision how the heaven collapsed and was borne off and fell to the earth." },
  { book: "1 Enoch", chapter: 83, verse: 4, text: "And when it fell to the earth I saw how the earth was swallowed up in a great abyss, and mountains were suspended on mountains, and hills sank down on hills, and high trees were rent from their stems, and hurled down and sunk in the abyss." },
  { book: "1 Enoch", chapter: 83, verse: 5, text: "And thereupon a word fell into my mouth, and I lifted up (my voice) to cry aloud, and said: 'The earth is destroyed.'" },
  { book: "1 Enoch", chapter: 83, verse: 6, text: "And my grandfather Mahalalel waked me as I lay near him, and said unto me: 'Why dost thou cry so, my son, and why dost thou make such lamentation?'" },
  { book: "1 Enoch", chapter: 83, verse: 7, text: "And I recounted to him the whole vision which I had seen, and he said unto me: 'A terrible thing hast thou seen, my son, and of grave moment is thy dream-vision as to the secrets of all the sin of the earth: it must sink into the abyss and be destroyed with a great destruction." },
  { book: "1 Enoch", chapter: 83, verse: 8, text: "And now, my son, arise and make petition to the Lord of glory, since thou art a believer, that a remnant may remain on the earth, and that He may not destroy the whole earth." },
  { book: "1 Enoch", chapter: 83, verse: 9, text: "My son, from heaven all this will come upon the earth, and upon the earth there will be great destruction." },
  { book: "1 Enoch", chapter: 83, verse: 10, text: "After that I arose and prayed and implored and besought, and wrote down my prayer for the generations of the world, and I will show everything to thee, my son Methuselah." },
  { book: "1 Enoch", chapter: 83, verse: 11, text: "And when I had gone forth below and seen the heaven, and the sun rising in the east, and the moon setting in the west, and a few stars, and the whole earth, and everything as He had known it in the beginning, then I blessed the Lord of judgement and extolled Him because He had made the sun to go forth from the windows of the east, and he ascended and rose on the face of the heaven, and set out and kept traversing the path shown unto him." },
  { book: "1 Enoch", chapter: 84, verse: 1, text: "And I lifted up my hands in righteousness and blessed the Holy and Great One, and spake with the breath of my mouth, and with the tongue of flesh, which God has made for the children of the flesh of men, that they should speak therewith, and He gave them breath and a tongue and a mouth that they should speak therewith:" },
  { book: "1 Enoch", chapter: 84, verse: 2, text: "'Blessed be Thou, O Lord, King, \nGreat and mighty in Thy greatness, \nLord of the whole creation of the heaven, \nKing of kings and God of the whole world.\n\nAnd Thy power and kingship and greatness abide for ever and ever, \nAnd throughout all generations Thy dominion; \nAnd all the heavens are Thy throne for ever, \nAnd the whole earth Thy footstool for ever and ever." },
  { book: "1 Enoch", chapter: 84, verse: 3, text: "For Thou hast made and Thou rulest all things, \nAnd nothing is too hard for Thee, \nWisdom departs not from the place of Thy throne, \nNor turns away from Thy presence. \nAnd Thou knowest and seest and hearest everything, \nAnd there is nothing hidden from Thee for Thou seest everything." },
  { book: "1 Enoch", chapter: 84, verse: 4, text: "And now the angels of Thy heavens are guilty of trespass, \nAnd upon the flesh of men abideth Thy wrath until the great day of judgement." },
  { book: "1 Enoch", chapter: 84, verse: 5, text: "And now, O God and Lord and Great King, \nI implore and beseech Thee to fulfil my prayer, \nTo leave me a posterity on earth, \nAnd not destroy all the flesh of man, \nAnd make the earth without inhabitant, \nSo that there should be an eternal destruction." },
  { book: "1 Enoch", chapter: 84, verse: 6, text: "And now, my Lord, destroy from the earth the flesh which has aroused Thy wrath,\nBut the flesh of righteousness and uprightness establish as a plant of the eternal seed, \nAnd hide not Thy face from the prayer of Thy servant, O Lord.'" },
  { book: "1 Enoch", chapter: 85, verse: 1, text: "And after this I saw another dream, and I will show the whole dream to thee, my son." },
  { book: "1 Enoch", chapter: 85, verse: 2, text: "And Enoch lifted up (his voice) and spake to his son Methuselah: 'To thee, my son, will I speak: hear my words--incline thine ear to the dream-vision of thy father." },
  { book: "1 Enoch", chapter: 85, verse: 3, text: "Before I took thy mother Edna, I saw in a vision on my bed, and behold a bull came forth from the earth, and that bull was white; and after it came forth a heifer, and along with this (latter) came forth two bulls, one of them black and the other red." },
  { book: "1 Enoch", chapter: 85, verse: 4, text: "And that black bull gored the red one and pursued him over the earth, and thereupon I could no longer see that red bull." },
  { book: "1 Enoch", chapter: 85, verse: 5, text: "But that black bull grew and that heifer went with him, and I saw that many oxen proceeded from him which resembled and followed him." },
  { book: "1 Enoch", chapter: 85, verse: 6, text: "And that cow, that first one, went from the presence of that first bull in order to seek that red one, but found him not, and lamented with a great lamentation over him and sought him." },
  { book: "1 Enoch", chapter: 85, verse: 7, text: "And I looked till that first bull came to her and quieted her, and from that time onward she cried no more." },
  { book: "1 Enoch", chapter: 85, verse: 8, text: "And after that she bore another white bull, and after him she bore many bulls and black cows." },
  { book: "1 Enoch", chapter: 85, verse: 9, text: "And I saw in my sleep that white bull likewise grow and become a great white bull, and from Him proceeded many white bulls, and they resembled him. And they began to beget many white bulls, which resembled them, one following the other, (even) many." },
  { book: "1 Enoch", chapter: 86, verse: 1, text: "And again I saw with mine eyes as I slept, and I saw the heaven above, and behold a star fell from heaven, and it arose and eat and pastured amongst those oxen." },
  { book: "1 Enoch", chapter: 86, verse: 2, text: "And after that I saw the large and the black oxen, and behold they all changed their stalls and pastures and their cattle, and began to live with each other." },
  { book: "1 Enoch", chapter: 86, verse: 3, text: "And again I saw in the vision, and looked towards the heaven, and behold I saw many stars descend and cast themselves down from heaven to that first star, and they became bulls amongst those cattle and pastured with them amongst them." },
  { book: "1 Enoch", chapter: 86, verse: 4, text: "And I looked at them and saw, and behold they all let out their privy members, like horses, and began to cover the cows of the oxen, and they all became pregnant and bare elephants, camels, and asses." },
  { book: "1 Enoch", chapter: 86, verse: 5, text: "And all the oxen feared them and were affrighted at them, and began to bite with their teeth and to devour, and to gore with their horns." },
  { book: "1 Enoch", chapter: 86, verse: 6, text: "And they began, moreover, to devour those oxen; and behold all the children of the earth began to tremble and quake before them and to flee from them." },
  { book: "1 Enoch", chapter: 87, verse: 1, text: "And again I saw how they began to gore each other and to devour each other, and the earth began to cry aloud." },
  { book: "1 Enoch", chapter: 87, verse: 2, text: "And I raised mine eyes again to heaven, and I saw in the vision, and behold there came forth from heaven beings who were like white men: and four went forth from that place and three with them." },
  { book: "1 Enoch", chapter: 87, verse: 3, text: "And those three that had last come forth grasped me by my hand and took me up, away from the generations of the earth, and raised me up to a lofty place, and showed me a tower raised high above the earth, and all the hills were lower." },
  { book: "1 Enoch", chapter: 87, verse: 4, text: "And one said unto me: 'Remain here till thou seest everything that befalls those elephants, camels, and asses, and the stars and the oxen, and all of them.'" },
  { book: "1 Enoch", chapter: 88, verse: 1, text: "And I saw one of those four who had come forth first, and he seized that first star which had fallen from the heaven, and bound it hand and foot and cast it into an abyss: now that abyss was narrow and deep, and horrible and dark." },
  { book: "1 Enoch", chapter: 88, verse: 2, text: "And one of them drew a sword, and gave it to those elephants and camels and asses: then they began to smite each other, and the whole earth quaked because of them." },
  { book: "1 Enoch", chapter: 88, verse: 3, text: "And as I was beholding in the vision, lo, one of those four who had come forth stoned (them) from heaven, and gathered and took all the great stars whose privy members were like those of horses, and bound them all hand and foot, and cast them in an abyss of the earth." },
  { book: "1 Enoch", chapter: 89, verse: 1, text: "And one of those four went to that white bull and instructed him in a secret, without his being terrified: he was born a bull and became a man, and built for himself a great vessel and dwelt thereon; and three bulls dwelt with him in that vessel and they were covered in." },
  { book: "1 Enoch", chapter: 89, verse: 2, text: "And again I raised mine eyes towards heaven and saw a lofty roof, with seven water torrents thereon, and those torrents flowed with much water into an enclosure." },
  { book: "1 Enoch", chapter: 89, verse: 3, text: "And I saw again, and behold fountains were opened on the surface of that great enclosure, and that water began to swell and rise upon the surface, and I saw that enclosure till all its surface was covered with water." },
  { book: "1 Enoch", chapter: 89, verse: 4, text: "And the water, the darkness, and mist increased upon it; and as I looked at the height of that water, that water had risen above the height of that enclosure, and was streaming over that enclosure, and it stood upon the earth." },
  { book: "1 Enoch", chapter: 89, verse: 5, text: "And all the cattle of that enclosure were gathered together until I saw how they sank and were swallowed up and perished in that water." },
  { book: "1 Enoch", chapter: 89, verse: 6, text: "But that vessel floated on the water, while all the oxen and elephants and camels and asses sank to the bottom with all the animals, so that I could no longer see them, and they were not able to escape, (but) perished and sank into the depths." },
  { book: "1 Enoch", chapter: 89, verse: 7, text: "And again I saw in the vision till those water torrents were removed from that high roof, and the chasms of the earth were levelled up and other abysses were opened." },
  { book: "1 Enoch", chapter: 89, verse: 8, text: "Then the water began to run down into these, till the earth became visible; but that vessel settled on the earth, and the darkness retired and light appeared." },
  { book: "1 Enoch", chapter: 89, verse: 9, text: "But that white bull which had become a man came out of that vessel, and the three bulls with him, and one of those three was white like that bull, and one of them was red as blood, and one black: and that white bull departed from them." },
  { book: "1 Enoch", chapter: 89, verse: 10, text: "And they began to bring forth beasts of the field and birds, so that there arose different genera: lions, tigers, wolves, dogs, hyenas, wild boars, foxes, squirrels, swine, falcons, vultures, kites, eagles, and ravens; and among them was born a white bull." },
  { book: "1 Enoch", chapter: 89, verse: 11, text: "And they began to bite one another; but that white bull which was born amongst them begat a wild ass and a white bull with it, and the wild asses multiplied." },
  { book: "1 Enoch", chapter: 89, verse: 12, text: "But that bull which was born from him begat a black wild boar and a white sheep; and the former begat many boars, but that sheep begat twelve sheep." },
  { book: "1 Enoch", chapter: 89, verse: 13, text: "And when those twelve sheep had grown, they gave up one of them to the asses, and those asses again gave up that sheep to the wolves, and that sheep grew up among the wolves." },
  { book: "1 Enoch", chapter: 89, verse: 14, text: "And the Lord brought the eleven sheep to live with it and to pasture with it among the wolves: and they multiplied and became many flocks of sheep." },
  { book: "1 Enoch", chapter: 89, verse: 15, text: "And the wolves began to fear them, and they oppressed them until they destroyed their little ones, and they cast their young into a river of much water: but those sheep began to cry aloud on account of their little ones, and to complain unto their Lord." },
  { book: "1 Enoch", chapter: 89, verse: 16, text: "And a sheep which had been saved from the wolves fled and escaped to the wild asses; and I saw the sheep how they lamented and cried, and besought their Lord with all their might, till that Lord of the sheep descended at the voice of the sheep from a lofty abode, and came to them and pastured them." },
  { book: "1 Enoch", chapter: 89, verse: 17, text: "And He called that sheep which had escaped the wolves, and spake with it concerning the wolves that it should admonish them not to touch the sheep." },
  { book: "1 Enoch", chapter: 89, verse: 18, text: "And the sheep went to the wolves according to the word of the Lord, and another sheep met it and went with it, and the two went and entered together into the assembly of those wolves, and spake with them and admonished them not to touch the sheep from henceforth." },
  { book: "1 Enoch", chapter: 89, verse: 19, text: "And thereupon I saw the wolves, and how they oppressed the sheep exceedingly with all their power; and the sheep cried aloud." },
  { book: "1 Enoch", chapter: 89, verse: 20, text: "And the Lord came to the sheep and they began to smite those wolves: and the wolves began to make lamentation; but the sheep became quiet and forthwith ceased to cry out." },
  { book: "1 Enoch", chapter: 89, verse: 21, text: "And I saw the sheep till they departed from amongst the wolves; but the eyes of the wolves were blinded, and those wolves departed in pursuit of the sheep with all their power." },
  { book: "1 Enoch", chapter: 89, verse: 22, text: "And the Lord of the sheep went with them, as their leader, and all His sheep followed Him: and his face was dazzling and glorious and terrible to behold." },
  { book: "1 Enoch", chapter: 89, verse: 23, text: "But the wolves began to pursue those sheep till they reached a sea of water." },
  { book: "1 Enoch", chapter: 89, verse: 24, text: "And that sea was divided, and the water stood on this side and on that before their face, and their Lord led them and placed Himself between them and the wolves." },
  { book: "1 Enoch", chapter: 89, verse: 25, text: "And as those wolves did not yet see the sheep, they proceeded into the midst of that sea, and the wolves followed the sheep, and those wolves ran after them into that sea." },
  { book: "1 Enoch", chapter: 89, verse: 26, text: "And when they saw the Lord of the sheep, they turned to flee before His face, but that sea gathered itself together, and became as it had been created, and the water swelled and rose till it covered those wolves." },
  { book: "1 Enoch", chapter: 89, verse: 27, text: "And I saw till all the wolves who pursued those sheep perished and were drowned." },
  { book: "1 Enoch", chapter: 89, verse: 28, text: "But the sheep escaped from that water and went forth into a wilderness, where there was no water and no grass; and they began to open their eyes and to see; and I saw the Lord of the sheep pasturing them and giving them water and grass, and that sheep going and leading them." },
  { book: "1 Enoch", chapter: 89, verse: 29, text: "And that sheep ascended to the summit of that lofty rock, and the Lord of the sheep sent it to them." },
  { book: "1 Enoch", chapter: 89, verse: 30, text: "And after that I saw the Lord of the sheep who stood before them, and His appearance was great and terrible and majestic, and all those sheep saw Him and were afraid before His face." },
  { book: "1 Enoch", chapter: 89, verse: 31, text: "And they all feared and trembled because of Him, and they cried to that sheep with them which was amongst them: \"We are not able to stand before our Lord or to behold Him.\"" },
  { book: "1 Enoch", chapter: 89, verse: 32, text: "And that sheep which led them again ascended to the summit of that rock, but the sheep began to be blinded and to wander from the way which he had showed them, but that sheep wot not thereof." },
  { book: "1 Enoch", chapter: 89, verse: 33, text: "And the Lord of the sheep was wrathful exceedingly against them, and that sheep discovered it, and went down from the summit of the rock, and came to the sheep, and found the greatest part of them blinded and fallen away." },
  { book: "1 Enoch", chapter: 89, verse: 34, text: "And when they saw it they feared and trembled at its presence, and desired to return to their folds." },
  { book: "1 Enoch", chapter: 89, verse: 35, text: "And that sheep took other sheep with it, and came to those sheep which had fallen away, and began to slay them; and the sheep feared its presence, and thus that sheep brought back those sheep that had fallen away, and they returned to their folds." },
  { book: "1 Enoch", chapter: 89, verse: 36, text: "And I saw in this vision till that sheep became a man and built a house for the Lord of the sheep, and placed all the sheep in that house." },
  { book: "1 Enoch", chapter: 89, verse: 37, text: "And I saw till this sheep which had met that sheep which led them fell asleep: and I saw till all the great sheep perished and little ones arose in their place, and they came to a pasture, and approached a stream of water." },
  { book: "1 Enoch", chapter: 89, verse: 38, text: "Then that sheep, their leader which had become a man, withdrew from them and fell asleep, and all the sheep sought it and cried over it with a great crying." },
  { book: "1 Enoch", chapter: 89, verse: 39, text: "And I saw till they left off crying for that sheep and crossed that stream of water, and there arose the two sheep as leaders in the place of those which had led them and fallen asleep (lit. \"had fallen asleep and led them\")." },
  { book: "1 Enoch", chapter: 89, verse: 40, text: "And I saw till the sheep came to a goodly place, and a pleasant and glorious land, and I saw till those sheep were satisfied; and that house stood amongst them in the pleasant land." },
  { book: "1 Enoch", chapter: 89, verse: 41, text: "And sometimes their eyes were opened, and sometimes blinded, till another sheep arose and led them and brought them all back, and their eyes were opened." },
  { book: "1 Enoch", chapter: 89, verse: 42, text: "And the dogs and the foxes and the wild boars began to devour those sheep till the Lord of the sheep raised up another sheep a ram from their midst, which led them." },
  { book: "1 Enoch", chapter: 89, verse: 43, text: "And that ram began to butt on either side those dogs, foxes, and wild boars till he had destroyed them all." },
  { book: "1 Enoch", chapter: 89, verse: 44, text: "And that sheep whose eyes were opened saw that ram, which was amongst the sheep, till it forsook its glory and began to butt those sheep, and trampled upon them, and behaved itself unseemly." },
  { book: "1 Enoch", chapter: 89, verse: 45, text: "And the Lord of the sheep sent the lamb to another lamb and raised it to being a ram and leader of the sheep instead of that ram which had forsaken its glory." },
  { book: "1 Enoch", chapter: 89, verse: 46, text: "And it went to it and spake to it alone, and raised it to being a ram, and made it the prince and leader of the sheep; but during all these things those dogs oppressed the sheep." },
  { book: "1 Enoch", chapter: 89, verse: 47, text: "And the first ram pursued that second ram, and that second ram arose and fled before it; and I saw till those dogs pulled down the first ram." },
  { book: "1 Enoch", chapter: 89, verse: 48, text: "And that second ram arose and led the little sheep." },
  { book: "1 Enoch", chapter: 89, verse: 49, text: "And those sheep grew and multiplied; but all the dogs, and foxes, and wild boars feared and fled before it, and that ram butted and kiled the wild beasts, and those wild beasts had no longer any power among the sheep and robbed them no more of aught. [89:48b] And that ram begat many sheep and fell asleep; and a little sheep became ram in its stead, and became prince and leader of those sheep." },
  { book: "1 Enoch", chapter: 89, verse: 50, text: "And that house became great and broad, and it was built for those sheep: and a tower lofty and great was built on the house for the Lord of the sheep, and that house was low, but the tower was elevated and lofty, and the Lord of the sheep stood on that tower and they offered a full table before Him." },
  { book: "1 Enoch", chapter: 89, verse: 51, text: "And again I saw those sheep that they again erred and went many ways, and forsook that their house, and the Lord of the sheep called some from amongst the sheep and sent them to the sheep, but the sheep began to slay them." },
  { book: "1 Enoch", chapter: 89, verse: 52, text: "And one of them was saved and was not slain, and it sped away and cried aloud over the sheep; and they sought to slay it, but the Lord of the sheep saved it from the sheep, and brought it up to me, and caused it to dwell there." },
  { book: "1 Enoch", chapter: 89, verse: 53, text: "And many other sheep He sent to those sheep to testify unto them and lament over them." },
  { book: "1 Enoch", chapter: 89, verse: 54, text: "And after that I saw that when they forsook the house of the Lord and His tower they fell away entirely, and their eyes were blinded; and I saw the Lord of the sheep how He wrought much slaughter amongst them in their herds until those sheep invited that slaughter and betrayed His place." },
  { book: "1 Enoch", chapter: 89, verse: 55, text: "And He gave them over into the hands of the lions and tigers, and wolves and hyenas, and into the hand of the foxes, and to all the wild beasts, and those wild beasts began to tear in pieces those sheep." },
  { book: "1 Enoch", chapter: 89, verse: 56, text: "And I saw that He forsook that their house and their tower and gave them all into the hand of the lions, to tear and devour them, into the hand of all the wild beasts." },
  { book: "1 Enoch", chapter: 89, verse: 57, text: "And I began to cry aloud with all my power, and to appeal to the Lord of the sheep, and to represent to Him in regard to the sheep that they were devoured by all the wild beasts." },
  { book: "1 Enoch", chapter: 89, verse: 58, text: "But He remained unmoved, though He saw it, and rejoiced that they were devoured and swallowed and robbed, and left them to be devoured in the hand of all the beasts." },
  { book: "1 Enoch", chapter: 89, verse: 59, text: "And He called seventy shepherds, and cast those sheep to them that they might pasture them, and He spake to the shepherds and their companions: \"Let each individual of you pasture the sheep henceforward, and everything that I shall command you that do ye." },
  { book: "1 Enoch", chapter: 89, verse: 60, text: "And I will deliver them over unto you duly numbered, and tell you which of them are to be destroyed--and them destroy ye.\" And He gave over unto them those sheep." },
  { book: "1 Enoch", chapter: 89, verse: 61, text: "And He called another and spake unto him: \"Observe and mark everything that the shepherds will do to those sheep; for they will destroy more of them than I have commanded them." },
  { book: "1 Enoch", chapter: 89, verse: 62, text: "And every excess and the destruction which will be wrought through the shepherds, record (namely) how many they destroy according to my command, and how many according to their own caprice: record against every individual shepherd all the destruction he effects." },
  { book: "1 Enoch", chapter: 89, verse: 63, text: "And read out before me by number how many they destroy, and how many they deliver over for destruction, that I may have this as a testimony against them, and know every deed of the shepherds, that I may comprehend and see what they do, whether or not they abide by my command which I have commanded them." },
  { book: "1 Enoch", chapter: 89, verse: 64, text: "But they shall not know it, and thou shalt not declare it to them, nor admonish them, but only record against each individual all the destruction which the shepherds effect each in his time and lay it all before me.\"" },
  { book: "1 Enoch", chapter: 89, verse: 65, text: "And I saw till those shepherds pastured in their season, and they began to slay and to destroy more than they were bidden, and they delivered those sheep into the hand of the lions." },
  { book: "1 Enoch", chapter: 89, verse: 66, text: "And the lions and tigers eat and devoured the greater part of those sheep, and the wild boars eat along with them; and they burnt that tower and demolished that house." },
  { book: "1 Enoch", chapter: 89, verse: 67, text: "And I became exceedingly sorrowful over that tower because that house of the sheep was demolished, and afterwards I was unable to see if those sheep entered that house." },
  { book: "1 Enoch", chapter: 89, verse: 68, text: "And the shepherds and their associates delivered over those sheep to all the wild beasts, to devour them, and each one of them received in his time a definite number: it was written by the other in a book how many each one of them destroyed of them." },
  { book: "1 Enoch", chapter: 89, verse: 69, text: "And each one slew and destroyed many more than was prescribed; and I began to weep and lament on account of those sheep." },
  { book: "1 Enoch", chapter: 89, verse: 70, text: "And thus in the vision I saw that one who wrote, how he wrote down every one that was destroyed by those shepherds, day by day, and carried up and laid down and showed actually the whole book to the Lord of the sheep--(even) everything that they had done, and all that each one of them had made away with, and all that they had given over to destruction." },
  { book: "1 Enoch", chapter: 89, verse: 71, text: "And the book was read before the Lord of the sheep, and He took the book from his hand and read it and sealed it and laid it down." },
  { book: "1 Enoch", chapter: 89, verse: 72, text: "And forthwith I saw how the shepherds pastured for twelve hours, and behold three of those sheep turned back and came and entered and began to build up all that had fallen down of that house; but the wild boars tried to hinder them, but they were not able." },
  { book: "1 Enoch", chapter: 89, verse: 73, text: "And they began again to build as before, and they reared up that tower, and it was named the high tower; and they began again to place a table before the tower, but all the bread on it was polluted and not pure." },
  { book: "1 Enoch", chapter: 89, verse: 74, text: "And as touching all this the eyes of those sheep were blinded so that they saw not, and (the eyes of) their shepherds likewise; and they delivered them in large numbers to their shepherds for destruction, and they trampled the sheep with their feet and devoured them." },
  { book: "1 Enoch", chapter: 89, verse: 75, text: "And the Lord of the sheep remained unmoved till all the sheep were dispersed over the field and mingled with them (i.e. the beasts), and they (i.e. the shepherds) did not save them out of the hand of the beasts." },
  { book: "1 Enoch", chapter: 89, verse: 76, text: "And this one who wrote the book carried it up, and showed it and read it before the Lord of the sheep, and implored Him on their account, and besought Him on their account as he showed Him all the doings of the shepherds, and gave testimony before Him against all the shepherds. And he took the actual book and laid it down beside Him and departed." },
  { book: "1 Enoch", chapter: 90, verse: 1, text: "And I saw till that in this manner thirty-five shepherds undertook the pasturing (of the sheep), and they severally completed their periods as did the first; and others received them into their hands, to pasture them for their period, each shepherd in his own period." },
  { book: "1 Enoch", chapter: 90, verse: 2, text: "And after that I saw in my vision all the birds of heaven coming, the eagles, the vultures, the kites, the ravens; but the eagles led all the birds; and they began to devour those sheep, and to pick out their eyes and to devour their flesh." },
  { book: "1 Enoch", chapter: 90, verse: 3, text: "And the sheep cried out because their flesh was being devoured by the birds, and as for me I looked and lamented in my sleep over that shepherd who pastured the sheep." },
  { book: "1 Enoch", chapter: 90, verse: 4, text: "And I saw until those sheep were devoured by the dogs and eagles and kites, and they left neither flesh nor skin nor sinew remaining on them till only their bones stood there: and their bones too fell to the earth and the sheep became few." },
  { book: "1 Enoch", chapter: 90, verse: 5, text: "And I saw until that twenty-three had undertaken the pasturing and completed in their several periods fifty-eight times." },
  { book: "1 Enoch", chapter: 90, verse: 6, text: "But behold lambs were borne by those white sheep, and they began to open their eyes and to see, and to cry to the sheep." },
  { book: "1 Enoch", chapter: 90, verse: 7, text: "Yea, they cried to them, but they did not hearken to what they said to them, but were exceedingly deaf, and their eyes were very exceedingly blinded." },
  { book: "1 Enoch", chapter: 90, verse: 8, text: "And I saw in the vision how the ravens flew upon those lambs and took one of those lambs, and dashed the sheep in pieces and devoured them." },
  { book: "1 Enoch", chapter: 90, verse: 9, text: "And I saw till horns grew upon those lambs, and the ravens cast down their horns; and I saw till there sprouted a great horn of one of those sheep, and their eyes were opened." },
  { book: "1 Enoch", chapter: 90, verse: 10, text: "And it looked at them and their eyes opened, and it cried to the sheep, and the rams saw it and all ran to it." },
  { book: "1 Enoch", chapter: 90, verse: 11, text: "And notwithstanding all this those eagles and vultures and ravens and kites still kept tearing the sheep and swooping down upon them and devouring them: still the sheep remained silent, but the rams lamented and cried out." },
  { book: "1 Enoch", chapter: 90, verse: 12, text: "And those ravens fought and battled with it and sought to lay low its horn, but they had no power over it." },
  { book: "1 Enoch", chapter: 90, verse: 13, text: "And I saw till the shepherds and eagles and those vultures and kites came, and they cried to the ravens that they should break the horn of that ram, and they battled and fought with it, and it battled with them and cried that its help might come." },
  { book: "1 Enoch", chapter: 90, verse: 14, text: "And I saw till that man, who wrote down the names of the shepherds and carried up into the presence of the Lord of the sheep came and helped it and showed it everything: he had come down for the help of that ram." },
  { book: "1 Enoch", chapter: 90, verse: 15, text: "And I saw till the Lord of the sheep came unto them in wrath, and all who saw Him fled, and they all fell into His shadow from before His face." },
  { book: "1 Enoch", chapter: 90, verse: 16, text: "All the eagles and vultures and ravens and kites were gathered together, and there came with them all the sheep of the field, yea, they all came together, and helped each other to break that horn of the ram." },
  { book: "1 Enoch", chapter: 90, verse: 17, text: "And I saw that man, who wrote the book according to the command of the Lord, till he opened that book concerning the destruction which those twelve last shepherds had wrought, and showed that they had destroyed much more than their predecessors, before the Lord of the sheep." },
  { book: "1 Enoch", chapter: 90, verse: 18, text: "And I saw till the Lord of the sheep came unto them and took in His hand the staff of His wrath, and smote the earth, and the earth clave asunder, and all the beasts and all the birds of the heaven fell from among those sheep, and were swallowed up in the earth and it covered them." },
  { book: "1 Enoch", chapter: 90, verse: 19, text: "And I saw till a great sword was given to the sheep, and the sheep proceeded against all the beasts of the field to slay them, and all the beasts and the birds of the heaven fled before their face." },
  { book: "1 Enoch", chapter: 90, verse: 20, text: "And I saw till a throne was erected in the pleasant land, and the Lord of the sheep sat Himself thereon, and the other took the sealed books and opened those books before the Lord of the sheep." },
  { book: "1 Enoch", chapter: 90, verse: 21, text: "And the Lord called those men the seven first white ones, and commanded that they should bring before Him, beginning with the first star which led the way, all the stars whose privy members were like those of horses, and they brought them all before Him." },
  { book: "1 Enoch", chapter: 90, verse: 22, text: "And He said to that man who wrote before Him, being one of those seven white ones, and said unto him: \"Take those seventy shepherds to whom I delivered the sheep, and who taking them on their own authority slew more than I commanded them.\"" },
  { book: "1 Enoch", chapter: 90, verse: 23, text: "And behold they were all bound, I saw, and they all stood before Him." },
  { book: "1 Enoch", chapter: 90, verse: 24, text: "And the judgement was held first over the stars, and they were judged and found guilty, and went to the place of condemnation, and they were cast into an abyss, full of fire and flaming, and full of pillars of fire." },
  { book: "1 Enoch", chapter: 90, verse: 25, text: "And those seventy shepherds were judged and found guilty, and they were cast into that fiery abyss." },
  { book: "1 Enoch", chapter: 90, verse: 26, text: "And I saw at that time how a like abyss was opened in the midst of the earth, full of fire, and they brought those blinded sheep, and they were all judged and found guilty and cast into this fiery abyss, and they burned; now this abyss was to the right of that house." },
  { book: "1 Enoch", chapter: 90, verse: 27, text: "And I saw those sheep burning and their bones burning." },
  { book: "1 Enoch", chapter: 90, verse: 28, text: "And I stood up to see till they folded up that old house; and carried off all the pillars, and all the beams and ornaments of the house were at the same time folded up with it, and they carried it off and laid it in a place in the south of the land." },
  { book: "1 Enoch", chapter: 90, verse: 29, text: "And I saw till the Lord of the sheep brought a new house greater and loftier than that first, and set it up in the place of the first which had beer folded up: all its pillars were new, and its ornaments were new and larger than those of the first, the old one which He had taken away, and all the sheep were within it." },
  { book: "1 Enoch", chapter: 90, verse: 30, text: "And I saw all the sheep which had been left, and all the beasts on the earth, and all the birds of the heaven, falling down and doing homage to those sheep and making petition to and obeying them in every thing." },
  { book: "1 Enoch", chapter: 90, verse: 31, text: "And thereafter those three who were clothed in white and had seized me by my hand who had taken me up before, and the hand of that ram also seizing hold of me, they took me up and set me down in the midst of those sheep before the judgement took place." },
  { book: "1 Enoch", chapter: 90, verse: 32, text: "And those sheep were all white, and their wool was abundant and clean." },
  { book: "1 Enoch", chapter: 90, verse: 33, text: "And all that had been destroyed and dispersed, and all the beasts of the field, and all the birds of the heaven, assembled in that house, and the Lord of the sheep rejoiced with great joy because they were all good and had returned to His house." },
  { book: "1 Enoch", chapter: 90, verse: 34, text: "And I saw till they laid down that sword, which had been given to the sheep, and they brought it back into the house, and it was sealed before the presence of the Lord, and all the sheep were invited into that house, but it held them not." },
  { book: "1 Enoch", chapter: 90, verse: 35, text: "And the eyes of them all were opened, and they saw the good, and there was not one among them that did not see." },
  { book: "1 Enoch", chapter: 90, verse: 36, text: "And I saw that that house was large and broad and very full." },
  { book: "1 Enoch", chapter: 90, verse: 37, text: "And I saw that a white bull was born, with large horns and all the beasts of the field and all the birds of the air feared him and made petition to him all the time." },
  { book: "1 Enoch", chapter: 90, verse: 38, text: "And I saw till all their generations were transformed, and they all became white bulls; and the first among them became a lamb, and that lamb became a great animal and had great black horns on its head; and the Lord of the sheep rejoiced over it and over all the oxen." },
  { book: "1 Enoch", chapter: 90, verse: 39, text: "And I slept in their midst: and I awoke and saw everything." },
  { book: "1 Enoch", chapter: 90, verse: 40, text: "This is the vision which I saw while I slept, and I awoke and blessed the Lord of righteousness and gave Him glory." },
  { book: "1 Enoch", chapter: 90, verse: 41, text: "Then I wept with a great weeping and my tears stayed not till I could no longer endure it: when I saw, they flowed on account of what I had seen; for everything shall come and be fulfilled, and all the deeds of men in their order were shown to me." },
  { book: "1 Enoch", chapter: 90, verse: 42, text: "On that night I remembered the first dream, and because of it I wept and was troubled--because I had seen that vision.'" },
  { book: "1 Enoch", chapter: 91, verse: 1, text: "'And now, my son Methuselah, call to me all thy brothers \nAnd gather together to me all the sons of thy mother; \nFor the word calls me, \nAnd the spirit is poured out upon me, \nThat I may show you everything \nThat shall befall you for ever.'" },
  { book: "1 Enoch", chapter: 91, verse: 2, text: "And there upon Methuselah went and summoned to him all his brothers and assembled his relatives." },
  { book: "1 Enoch", chapter: 91, verse: 3, text: "And he spake unto all the children of righteousness and said: \n\n'Hear, ye sons of Enoch, all the words of your father, \nAnd hearken aright to the voice of my mouth; \nFor I exhort you and say unto you, beloved:\n\nLove uprightness and walk therein." },
  { book: "1 Enoch", chapter: 91, verse: 4, text: "And draw not nigh to uprightness with a double heart,\nAnd associate not with those of a double heart, \nBut walk in righteousness, my sons. \nAnd it shall guide you on good paths,\nAnd righteousness shall be your companion." },
  { book: "1 Enoch", chapter: 91, verse: 5, text: "For I know that violence must increase on the earth, \nAnd a great chastisement be executed on the earth, \nAnd all unrighteousness come to an end:\n\nYea, it shall be cut off from its roots, \nAnd its whole structure be destroyed." },
  { book: "1 Enoch", chapter: 91, verse: 6, text: "And unrighteousness shall again be consummated on the earth, \nAnd all the deeds of unrighteousness and of violence \nAnd transgression shall prevail in a twofold degree." },
  { book: "1 Enoch", chapter: 91, verse: 7, text: "And when sin and unrighteousness and blasphemy \nAnd violence in all kinds of deeds increase, \nAnd apostasy and transgression and uncleanness increase, \n\nA great chastisement shall come from heaven upon all these, \nAnd the holy Lord will come forth with wrath and chastisement \nTo execute judgement on earth." },
  { book: "1 Enoch", chapter: 91, verse: 8, text: "In those days violence shall be cut off from its roots, \nAnd the roots of unrighteousness together with deceit, \nAnd they shall be destroyed from under heaven." },
  { book: "1 Enoch", chapter: 91, verse: 9, text: "And all the idols of the heathen shall be abandoned,\nAnd the temples burned with fire, \nAnd they shall remove them from the whole earth,\n\nAnd they (i.e. the heathen) shall be cast into the judgement of fire, \nAnd shall perish in wrath and in grievous judgement for ever." },
  { book: "1 Enoch", chapter: 91, verse: 10, text: "And the righteous shall arise from their sleep, \nAnd wisdom shall arise and be given unto them." },
  { book: "1 Enoch", chapter: 91, verse: 11, text: "And after that the roots of unrighteousness shall be cut off, and the sinners shall be destroyed by the sword . . . shall be cut off from the blasphemers in every place, and those who plan violence and those who commit blasphemy shall perish by the sword." },
  { book: "1 Enoch", chapter: 91, verse: 12, text: "And after that there shall be another, the eighth week, that of righteousness, \nAnd a sword shall be given to it that a righteous judgement may be executed on the oppressors, \nAnd sinners shall be delivered into the hands of the righteous." },
  { book: "1 Enoch", chapter: 91, verse: 13, text: "And at its close they shall acquire houses through their righteousness,\nAnd a house shall be built for the Great King in glory for evermore, \n[91:14d] And all mankind shall look to the path of uprightness.\n\n[91:14a] And after that, in the ninth week, the righteous judgement shall be revealed to the whole world, \nb. And all the works of the godless shall vanish from all the earth, \nc. And the world shall be written down for destruction." },
  { book: "1 Enoch", chapter: 91, verse: 15, text: "And after this, in the tenth week in the seventh part, \nThere shall be the great eternal judgement, \nIn which He will execute vengeance amongst the angels." },
  { book: "1 Enoch", chapter: 91, verse: 16, text: "And the first heaven shall depart and pass away, \nAnd a new heaven shall appear, \nAnd all the powers of the heavens shall give sevenfold light." },
  { book: "1 Enoch", chapter: 91, verse: 17, text: "And after that there will be many weeks without number for ever, \nAnd all shall be in goodness and righteousness,\nAnd sin shall no more be mentioned for ever." },
  { book: "1 Enoch", chapter: 91, verse: 18, text: "And now I tell you, my sons, and show you \nThe paths of righteousness and the paths of violence. \nYea, I will show them to you again \nThat ye may know what will come to pass." },
  { book: "1 Enoch", chapter: 91, verse: 19, text: "And now, hearken unto me, my sons, \nAnd walk in the paths of righteousness, \nAnd walk not in the paths of violence; \nFor all who walk in the paths of unrighteousness shall perish for ever.'" },
  { book: "1 Enoch", chapter: 92, verse: 1, text: "The book written by Enoch--Enoch indeed wrote this complete doctrine of wisdom, (which is) praised of all men and a judge of all the earth for all my children who shall dwell on the earth. And for the future generations who shall observe uprightness and peace." },
  { book: "1 Enoch", chapter: 92, verse: 2, text: "Let not your spirit be troubled on account of the times; \nFor the Holy and Great One has appointed days for all things." },
  { book: "1 Enoch", chapter: 92, verse: 3, text: "And the righteous one shall arise from sleep, \nShall arise and walk in the paths of righteousness, \nAnd all his path and conversation shall be in eternal goodness and grace." },
  { book: "1 Enoch", chapter: 92, verse: 4, text: "He will be gracious to the righteous and give him eternal uprightness, \nAnd He will give him power so that he shall be (endowed) with goodness and righteousness. \nAnd he shall walk in eternal light." },
  { book: "1 Enoch", chapter: 92, verse: 5, text: "And sin shall perish in darkness for ever, \nAnd shall no more be seen from that day for evermore." },
  { book: "1 Enoch", chapter: 93, verse: 1, text: "And after that Enoch both gave and began to recount from the books. And Enoch said: \n\n'Concerning the children of righteousness and concerning the elect of the world, \nAnd concerning the plant of uprightness, I will speak these things, \nYea, I Enoch will declare (them) unto you, my sons:\n\nAccording to that which appeared to me in the heavenly vision, \nAnd which I have known through the word of the holy angels, \nAnd have learnt from the heavenly tablets.'" },
  { book: "1 Enoch", chapter: 93, verse: 3, text: "And Enoch began to recount from the books and said: \n'I was born the seventh in the first week, \nWhile judgement and righteousness still endured." },
  { book: "1 Enoch", chapter: 93, verse: 4, text: "And after me there shall arise in the second week great wickedness, \nAnd deceit shall have sprung up; \nAnd in it there shall be the first end.\n\nAnd in it a man shall be saved; \nAnd after it is ended unrighteousness shall grow up, \nAnd a law shall be made for the sinners." },
  { book: "1 Enoch", chapter: 93, verse: 5, text: "And after that in the third week at its close \nA man shall be elected as the plant of righteous judgement,\nAnd his posterity shall become the plant of righteousness for evermore." },
  { book: "1 Enoch", chapter: 93, verse: 6, text: "And after that in the fourth week, at its close, \nVisions of the holy and righteous shall be seen, \nAnd a law for all generations and an enclosure shall be made for them." },
  { book: "1 Enoch", chapter: 93, verse: 7, text: "And after that in the fifth week, at its close, \nThe house of glory and dominion shall be built for ever." },
  { book: "1 Enoch", chapter: 93, verse: 8, text: "And after that in the sixth week all who live in it shall be blinded, \nAnd the hearts of all of them shall godlessly forsake wisdom.\n\nAnd in it a man shall ascend; \nAnd at its close the house of dominion shall be burnt with fire, \nAnd the whole race of the chosen root shall be dispersed." },
  { book: "1 Enoch", chapter: 93, verse: 9, text: "And after that in the seventh week shall an apostate generation arise, \nAnd many shall be its deeds, \nAnd all its deeds shall be apostate." },
  { book: "1 Enoch", chapter: 93, verse: 10, text: "And at its close shall be elected \nThe elect righteous of the eternal plant of righteousness, \nTo receive sevenfold instruction concerning all His creation." },
  { book: "1 Enoch", chapter: 93, verse: 11, text: "For who is there of all the children of men that is able to hear the voice of the Holy One without being troubled? And who can think His thoughts? and who is there that can behold all the works of heaven?" },
  { book: "1 Enoch", chapter: 93, verse: 12, text: "And how should there be one who could behold the heaven, and who is there that could understand the things of heaven and see a soul or a spirit and could tell thereof, or ascend and see all their ends and think them or do like them?" },
  { book: "1 Enoch", chapter: 93, verse: 13, text: "And who is there of all men that could know what is the breadth and the length of the earth, and to whom has been shown the measure of all of them?" },
  { book: "1 Enoch", chapter: 93, verse: 14, text: "Or is there any one who could discern the length of the heaven and how great is its height, and upon what it is founded, and how great is the number of the stars, and where all the luminaries rest?" },
  { book: "1 Enoch", chapter: 94, verse: 1, text: "And now I say unto you, my sons, love righteousness and walk therein; \nFor the paths of righteousness are worthy of acceptation, \nBut the paths of unrighteousness shall suddenly be destroyed and vanish." },
  { book: "1 Enoch", chapter: 94, verse: 2, text: "And to certain men of a generation shall the paths of violence and of death be revealed,\nAnd they shall hold themselves afar from them, \nAnd shall not follow them." },
  { book: "1 Enoch", chapter: 94, verse: 3, text: "And now I say unto you the righteous: \nWalk not in the paths of wickedness, nor in the paths of death, \nAnd draw not nigh to them, lest ye be destroyed." },
  { book: "1 Enoch", chapter: 94, verse: 4, text: "But seek and choose for yourselves righteousness and an elect life, \nAnd walk in the paths of peace, \nAnd ye shall live and prosper." },
  { book: "1 Enoch", chapter: 94, verse: 5, text: "And hold fast my words in the thoughts of your hearts, \nAnd suffer them not to be effaced from your hearts;\n\nFor I know that sinners will tempt men to evilly-entreat wisdom, \nSo that no place may be found for her, \nAnd no manner of temptation may minish." },
  { book: "1 Enoch", chapter: 94, verse: 6, text: "Woe to those who build unrighteousness and oppression \nAnd lay deceit as a foundation; \nFor they shall be suddenly overthrown,\nAnd they shall have no peace." },
  { book: "1 Enoch", chapter: 94, verse: 7, text: "Woe to those who build their houses with sin; \nFor from all their foundations shall they be overthrown, \nAnd by the sword shall they fall.\n\nAnd those who acquire gold and silver in judgement suddenly shall perish." },
  { book: "1 Enoch", chapter: 94, verse: 8, text: "Woe to you, ye rich, for ye have trusted in your riches, \nAnd from your riches shall ye depart, \nBecause ye have not remembered the Most High in the days of your riches." },
  { book: "1 Enoch", chapter: 94, verse: 9, text: "Ye have committed blasphemy and unrighteousness, \nAnd have become ready for the day of slaughter, \nAnd the day of darkness and the day of the great judgement." },
  { book: "1 Enoch", chapter: 94, verse: 10, text: "Thus I speak and declare unto you: \nHe who hath created you will overthrow you, \nAnd for your fall there shall be no compassion, \nAnd your Creator will rejoice at your destruction." },
  { book: "1 Enoch", chapter: 94, verse: 11, text: "And your righteous ones in those days shall be \nA reproach to the sinners and the godless." },
  { book: "1 Enoch", chapter: 95, verse: 1, text: "Oh that mine eyes were a cloud of waters \nThat I might weep over you, \nAnd pour down my tears as a cloud of waters: \nThat so I might rest from my trouble of heart!" },
  { book: "1 Enoch", chapter: 95, verse: 2, text: "Who has permitted you to practice reproaches and wickedness? \nAnd so judgement shall overtake you, sinners." },
  { book: "1 Enoch", chapter: 95, verse: 3, text: "Fear not the sinners, ye righteous; \nFor again will the Lord deliver them into your hands, \nThat ye may execute judgement upon them according to your desires." },
  { book: "1 Enoch", chapter: 95, verse: 4, text: "Woe to you who fulminate anathemas which cannot be reversed: \nHealing shall therefore be far from you because of your sins." },
  { book: "1 Enoch", chapter: 95, verse: 5, text: "Woe to you who requite your neighbour with evil; \nFor ye shall be requited according to your works." },
  { book: "1 Enoch", chapter: 95, verse: 6, text: "Woe to you, lying witnesses, \nAnd to those who weigh out injustice, \nFor suddenly shall ye perish." },
  { book: "1 Enoch", chapter: 95, verse: 7, text: "Woe to you, sinners, for ye persecute the righteous; \nFor ye shall be delivered up and persecuted because of injustice, \nAnd heavy shall its yoke be upon you." },
  { book: "1 Enoch", chapter: 96, verse: 1, text: "Be hopeful, ye righteous; for suddenly shall the sinners perish before you, \nAnd ye shall have lordship over them according to your desires." },
  { book: "1 Enoch", chapter: 96, verse: 2, text: "And in the day of the tribulation of the sinners, \nYour children shall mount and rise as eagles, \nAnd higher than the vultures will be your nest, \nAnd ye shall ascend and enter the crevices of the earth, \nAnd the clefts of the rock for ever as coneys before the unrighteous, \nAnd the sirens shall sigh because of you and weep." },
  { book: "1 Enoch", chapter: 96, verse: 3, text: "Wherefore fear not, ye that have suffered; \nFor healing shall be your portion,\nAnd a bright light shall enlighten you, \nAnd the voice of rest ye shall hear from heaven." },
  { book: "1 Enoch", chapter: 96, verse: 4, text: "Woe unto you, ye sinners, for your riches make you appear like the righteous, \nBut your hearts convict you of being sinners, \nAnd this fact shall be a testimony against you for a memorial of (your) evil deeds." },
  { book: "1 Enoch", chapter: 96, verse: 5, text: "Woe to you who devour the finest of the wheat, \nAnd drink wine in large bowls, \nAnd tread under foot the lowly with your might." },
  { book: "1 Enoch", chapter: 96, verse: 6, text: "Woe to you who drink water from every fountain, \nFor suddenly shall ye be consumed and wither away, \nBecause ye have forsaken the fountain of life." },
  { book: "1 Enoch", chapter: 96, verse: 7, text: "Woe to you who work unrighteousness \nAnd deceit and blasphemy: \nIt shall be a memorial against you for evil." },
  { book: "1 Enoch", chapter: 96, verse: 8, text: "Woe to you, ye mighty, \nWho with might oppress the righteous; \nFor the day of your destruction is coming. \n\nIn those days many and good days shall come to the righteous--in the day of your judgement." },
  { book: "1 Enoch", chapter: 97, verse: 1, text: "Believe, ye righteous, that the sinners will become a shame \nAnd perish in the day of unrighteousness." },
  { book: "1 Enoch", chapter: 97, verse: 2, text: "Be it known unto you (ye sinners) that the Most High is mindful of your destruction, \nAnd the angels of heaven rejoice over your destruction." },
  { book: "1 Enoch", chapter: 97, verse: 3, text: "What will ye do, ye sinners, \nAnd whither will ye flee on that day of judgement, \nWhen ye hear the voice of the prayer of the righteous?" },
  { book: "1 Enoch", chapter: 97, verse: 4, text: "Yea, ye shall fare like unto them, \nAgainst whom this word shall be a testimony: \n\"Ye have been companions of sinners.\"" },
  { book: "1 Enoch", chapter: 97, verse: 5, text: "And in those days the prayer of the righteous shall reach unto the Lord, \nAnd for you the days of your judgement shall come." },
  { book: "1 Enoch", chapter: 97, verse: 6, text: "And all the words of your unrighteousness shall be read out before the Great Holy One, \nAnd your faces shall be covered with shame, \nAnd He will reject every work which is grounded on unrighteousness." },
  { book: "1 Enoch", chapter: 97, verse: 7, text: "Woe to you, ye sinners, who live on the mid ocean and on the dry land, \nWhose remembrance is evil against you." },
  { book: "1 Enoch", chapter: 97, verse: 8, text: "Woe to you who acquire silver and gold in unrighteousness and say: \n\"We have become rich with riches and have possessions; \nAnd have acquired everything we have desired." },
  { book: "1 Enoch", chapter: 97, verse: 9, text: "And now let us do what we purposed: \nFor we have gathered silver,\n[97:9d] And many are the husbandmen in our houses.\" \n[97:9e] And our granaries are (brim) full as with water," },
  { book: "1 Enoch", chapter: 97, verse: 10, text: "Yea and like water your lies shall flow away; \nFor your riches shall not abide \nBut speedily ascend from you;\n\nFor ye have acquired it all in unrighteousness,\nAnd ye shall be given over to a great curse." },
  { book: "1 Enoch", chapter: 98, verse: 1, text: "And now I swear unto you, to the wise and to the foolish, \nFor ye shall have manifold experiences on the earth." },
  { book: "1 Enoch", chapter: 98, verse: 2, text: "For ye men shall put on more adornments than a woman, \nAnd coloured garments more than a virgin: \nIn royalty and in grandeur and in power, \nAnd in silver and in gold and in purple, \nAnd in splendour and in food they shall be poured out as water." },
  { book: "1 Enoch", chapter: 98, verse: 3, text: "Therefore they shall be wanting in doctrine and wisdom, \nAnd they shall perish thereby together with their possessions; \nAnd with all their glory and their splendour, \nAnd in shame and in slaughter and in great destitution, \nTheir spirits shall be cast into the furnace of fire." },
  { book: "1 Enoch", chapter: 98, verse: 4, text: "I have sworn unto you, ye sinners, as a mountain has not become a slave, \nAnd a hill does not become the handmaid of a woman, \nEven so sin has not been sent upon the earth,\nBut man of himself has created it, \nAnd under a great curse shall they fall who commit it." },
  { book: "1 Enoch", chapter: 98, verse: 5, text: "And barrenness has not been given to the woman, \nBut on account of the deeds of her own hands she dies without children." },
  { book: "1 Enoch", chapter: 98, verse: 6, text: "I have sworn unto you, ye sinners, by the Holy Great One,\nThat all your evil deeds are revealed in the heavens, \nAnd that none of your deeds of oppression are covered and hidden." },
  { book: "1 Enoch", chapter: 98, verse: 7, text: "And do not think in your spirit nor say in your heart that ye do not know and that ye do not see that every sin is every day recorded in heaven in the presence of the Most High." },
  { book: "1 Enoch", chapter: 98, verse: 8, text: "From henceforth ye know that all your oppression wherewith ye oppress is written down every day till the day of your judgement." },
  { book: "1 Enoch", chapter: 98, verse: 9, text: "Woe to you, ye fools, for through your folly shall ye perish: and ye transgress against the wise, and so good hap shall not be your portion." },
  { book: "1 Enoch", chapter: 98, verse: 10, text: "And now, know ye that ye are prepared for the day of destruction: wherefore do not hope to live, ye sinners, but ye shall depart and die; for ye know no ransom; for ye are prepared for the day of the great judgement, for the day of tribulation and great shame for your spirits." },
  { book: "1 Enoch", chapter: 98, verse: 11, text: "Woe to you, ye obstinate of heart, who work wickedness and eat blood: \nWhence have ye good things to eat and to drink and to be filled? \n\n From all the good things which the Lord the Most High has placed in abundance on the earth; therefore ye shall have no peace." },
  { book: "1 Enoch", chapter: 98, verse: 12, text: "Woe to you who love the deeds of unrighteousness: wherefore do ye hope for good hap unto yourselves? know that ye shall be delivered into the hands of the righteous, and they shall cut off your necks and slay you, and have no mercy upon you." },
  { book: "1 Enoch", chapter: 98, verse: 13, text: "Woe to you who rejoice in the tribulation of the righteous; for no grave shall be dug for you." },
  { book: "1 Enoch", chapter: 98, verse: 14, text: "Woe to you who set at nought the words of the righteous; for ye shall have no hope of life." },
  { book: "1 Enoch", chapter: 98, verse: 15, text: "Woe to you who write down lying and godless words; for they write down their lies that men may hear them and act godlessly towards (their) neighbour." },
  { book: "1 Enoch", chapter: 98, verse: 16, text: "Therefore they shall have no peace but die a sudden death." },
  { book: "1 Enoch", chapter: 99, verse: 1, text: "Woe to you who work godlessness, \nAnd glory in lying and extol them: \nYe shall perish, and no happy life shall be yours." },
  { book: "1 Enoch", chapter: 99, verse: 2, text: "Woe to them who pervert the words of uprightness, \nAnd transgress the eternal law, \nAnd transform themselves into what they were not into sinners: \nThey shall be trodden under foot upon the earth." },
  { book: "1 Enoch", chapter: 99, verse: 3, text: "In those days make ready, ye righteous, to raise your prayers as a memorial, \nAnd place them as a testimony before the angels, \nThat they may place the sin of the sinners for a memorial before the Most High." },
  { book: "1 Enoch", chapter: 99, verse: 4, text: "In those days the nations shall be stirred up, \nAnd the families of the nations shall arise on the day of destruction." },
  { book: "1 Enoch", chapter: 99, verse: 5, text: "And in those days the destitute shall go forth and carry off their children, \nAnd they shall abandon them, so that their children shall perish through them:\nYea, they shall abandon their children (that are still) sucklings, and not return to them,\nAnd shall have no pity on their beloved ones." },
  { book: "1 Enoch", chapter: 99, verse: 6, text: "And again I swear to you, ye sinners, that sin is prepared for a day of unceasing bloodshed." },
  { book: "1 Enoch", chapter: 99, verse: 7, text: "And they who worship stones, and grave images of gold and silver and wood and stone and clay, and those who worship impure spirits and demons, and all kinds of idols not according to knowledge, shall get no manner of help from them." },
  { book: "1 Enoch", chapter: 99, verse: 8, text: "And they shall become godless by reason of the folly of their hearts, \nAnd their eyes shall be blinded through the fear of their hearts \nAnd through visions in their dreams." },
  { book: "1 Enoch", chapter: 99, verse: 9, text: "Through these they shall become godless and fearful;\nFor they shall have wrought all their work in a lie,\nAnd shall have worshiped a stone: \nTherefore in an instant shall they perish." },
  { book: "1 Enoch", chapter: 99, verse: 10, text: "But in those days blessed are all they who accept the words of wisdom, and understand them, \nAnd observe the paths of the Most High, and walk in the path of His righteousness, \nAnd become not godless with the godless; \nFor they shall be saved." },
  { book: "1 Enoch", chapter: 99, verse: 11, text: "Woe to you who spread evil to your neighbours; \nFor you shall be slain in Sheol." },
  { book: "1 Enoch", chapter: 99, verse: 12, text: "Woe to you who make deceitful and false measures, \nAnd (to them) who cause bitterness on the earth; \nFor they shall thereby be utterly consumed." },
  { book: "1 Enoch", chapter: 99, verse: 13, text: "Woe to you who build your houses through the grievous toil of others, \nAnd all their building materials are the bricks and stones of sin; \nI tell you ye shall have no peace." },
  { book: "1 Enoch", chapter: 99, verse: 14, text: "Woe to them who reject the measure and eternal heritage of their fathers \nAnd whose souls follow after idols; \nFor they shall have no rest." },
  { book: "1 Enoch", chapter: 99, verse: 15, text: "Woe to them who work unrighteousness and help oppression, \nAnd slay their neighbours until the day of the great judgement." },
  { book: "1 Enoch", chapter: 99, verse: 16, text: "For He shall cast down your glory, \nAnd bring affliction on your hearts, \nAnd shall arouse His fierce indignation, \nAnd destroy you all with the sword; \nAnd all the holy and righteous shall remember your sins." },
  { book: "1 Enoch", chapter: 100, verse: 1, text: "And in those days in one place the fathers together with their sons shall be smitten \nAnd brothers one with another shall fall in death \nTill the streams flow with their blood." },
  { book: "1 Enoch", chapter: 100, verse: 2, text: "For a man shall not withhold his hand from slaying his sons and his sons' sons, \nAnd the sinner shall not withhold his hand from his honoured brother:\nFrom dawn till sunset they shall slay one another." },
  { book: "1 Enoch", chapter: 100, verse: 3, text: "And the horse shall walk up to the breast in the blood of sinners, \nAnd the chariot shall be submerged to its height." },
  { book: "1 Enoch", chapter: 100, verse: 4, text: "In those days the angels shall descend into the secret places \nAnd gather together into one place all those who brought down sin \nAnd the Most High will arise on that day of judgement \nTo execute great judgement amongst sinners." },
  { book: "1 Enoch", chapter: 100, verse: 5, text: "And over all the righteous and holy He will appoint guardians from amongst the holy angels \nTo guard them as the apple of an eye, \nUntil He makes an end of all wickedness and all sin, \nAnd though the righteous sleep a long sleep, they have nought to fear." },
  { book: "1 Enoch", chapter: 100, verse: 6, text: "And (then) the children of the earth shall see the wise in security, \nAnd shall understand all the words of this book, \nAnd recognize that their riches shall not be able to save them \nIn the overthrow of their sins." },
  { book: "1 Enoch", chapter: 100, verse: 7, text: "Woe to you, sinners, on the day of strong anguish, \nYe who afflict the righteous and burn them with fire: \nYe shall be requited according to your works." },
  { book: "1 Enoch", chapter: 100, verse: 8, text: "Woe to you, ye obstinate of heart,\nWho watch in order to devise wickedness: \nTherefore shall fear come upon you \nAnd there shall be none to help you." },
  { book: "1 Enoch", chapter: 100, verse: 9, text: "Woe to you, ye sinners, on account of the words of your mouth, \nAnd on account of the deeds of your hands which your godlessness as wrought, \nIn blazing flames burning worse than fire shall ye burn." },
  { book: "1 Enoch", chapter: 100, verse: 10, text: "And now, know ye that from the angels He will inquire as to your deeds in heaven, from the sun and from the moon and from the stars in reference to your sins because upon the earth ye execute judgement on the righteous." },
  { book: "1 Enoch", chapter: 100, verse: 11, text: "And He will summon to testify against you every cloud and mist and dew and rain; for they shall all be withheld because of you from descending upon you, and they shall be mindful of your sins." },
  { book: "1 Enoch", chapter: 100, verse: 12, text: "And now give presents to the rain that it be not withheld from descending upon you, nor yet the dew, when it has received gold and silver from you that it may descend." },
  { book: "1 Enoch", chapter: 100, verse: 13, text: "When the hoar-frost and snow with their chilliness, and all the snow-storms with all their plagues fall upon you, in those days ye shall not be able to stand before them." },
  { book: "1 Enoch", chapter: 101, verse: 1, text: "Observe the heaven, ye children of heaven, and every work of the Most High, and fear ye Him and work no evil in His presence." },
  { book: "1 Enoch", chapter: 101, verse: 2, text: "If He closes the windows of heaven, and withholds the rain and the dew from descending on the earth on your account, what will ye do then?" },
  { book: "1 Enoch", chapter: 101, verse: 3, text: "And if He sends His anger upon you because of your deeds, ye cannot petition Him; for ye spake proud and insolent words against His righteousness: therefore ye shall have no peace." },
  { book: "1 Enoch", chapter: 101, verse: 4, text: "And see ye not the sailors of the ships, how their ships are tossed to and fro by the waves, and are shaken by the winds, and are in sore trouble?" },
  { book: "1 Enoch", chapter: 101, verse: 5, text: "And therefore do they fear because all their goodly possessions go upon the sea with them, and they have evil forebodings of heart that the sea will swallow them and they will perish therein." },
  { book: "1 Enoch", chapter: 101, verse: 6, text: "Are not the entire sea and all its waters, and all its movements, the work of the Most High, and has He not set limits to its doings, and confined it throughout by the sand?" },
  { book: "1 Enoch", chapter: 101, verse: 7, text: "And at His reproof it is afraid and dries up, and all its fish die and all that is in it; But ye sinners that are on the earth fear Him not." },
  { book: "1 Enoch", chapter: 101, verse: 8, text: "Has He not made the heaven and the earth, and all that is therein? Who has given understanding and wisdom to everything that moves on the earth and in the sea?" },
  { book: "1 Enoch", chapter: 101, verse: 9, text: "Do not the sailors of the ships fear the sea? Yet sinners fear not the Most High." },
  { book: "1 Enoch", chapter: 102, verse: 1, text: "In those days when He hath brought a grievous fire upon you, \nWhither will ye flee, and where will ye find deliverance? \nAnd when He launches forth His Word against you \nWill you not be affrighted and fear?" },
  { book: "1 Enoch", chapter: 102, verse: 2, text: "And all the luminaries shall be affrighted with great fear, \nAnd all the earth shall be affrighted and tremble and be alarmed." },
  { book: "1 Enoch", chapter: 102, verse: 3, text: "And all the angels shall execute their commands \nAnd shall seek to hide themselves from the presence of the Great Glory, \nAnd the children of earth shall tremble and quake; \nAnd ye sinners shall be cursed for ever, \nAnd ye shall have no peace." },
  { book: "1 Enoch", chapter: 102, verse: 4, text: "Fear ye not, ye souls of the righteous, \nAnd be hopeful ye that have died in righteousness." },
  { book: "1 Enoch", chapter: 102, verse: 5, text: "And grieve not if your soul into Sheol has descended in grief, \nAnd that in your life your body fared not according to your goodness, \nBut wait for the day of the judgement of sinners \nAnd for the day of cursing and chastisement." },
  { book: "1 Enoch", chapter: 102, verse: 6, text: "And yet when ye die the sinners speak over you:\n\"As we die, so die the righteous,\nAnd what benefit do they reap for their deeds?" },
  { book: "1 Enoch", chapter: 102, verse: 7, text: "Behold, even as we, so do they die in grief and darkness, \nAnd what have they more than we? \nFrom henceforth we are equal." },
  { book: "1 Enoch", chapter: 102, verse: 8, text: "And what will they receive and what will they see for ever?\nBehold, they too have died, \nAnd henceforth for ever shall they see no light.\"" },
  { book: "1 Enoch", chapter: 102, verse: 9, text: "I tell you, ye sinners, ye are content to eat and drink, and rob and sin, and strip men naked, and acquire wealth and see good days." },
  { book: "1 Enoch", chapter: 102, verse: 10, text: "Have ye seen the righteous how their end falls out, that no manner of violence is found in them till their death?" },
  { book: "1 Enoch", chapter: 102, verse: 11, text: "\"Nevertheless they perished and became as though they had not been, and their spirits descended into Sheol in tribulation.\"" },
  { book: "1 Enoch", chapter: 103, verse: 1, text: "Now, therefore, I swear to you, the righteous, by the glory of the Great and Honoured and Mighty One in dominion, and by His greatness I swear to you:" },
  { book: "1 Enoch", chapter: 103, verse: 2, text: "I know a mystery \nAnd have read the heavenly tablets, \nAnd have seen the holy books, \nAnd have found written therein and inscribed regarding them:" },
  { book: "1 Enoch", chapter: 103, verse: 3, text: "That all goodness and joy and glory are prepared for them, \nAnd written down for the spirits of those who have died in righteousness, \nAnd that manifold good shall be given to you in recompense for your labours,\nAnd that your lot is abundantly beyond the lot of the living." },
  { book: "1 Enoch", chapter: 103, verse: 4, text: "And the spirits of you who have died in righteousness shall live and rejoice, \nAnd their spirits shall not perish, nor their memorial from before the face of the Great One \nUnto all the generations of the world: wherefore no longer fear their contumely." },
  { book: "1 Enoch", chapter: 103, verse: 5, text: "Woe to you, ye sinners, when ye have died, \nIf ye die in the wealth of your sins, \nAnd those who are like you say regarding you: \n'Blessed are the sinners: they have seen all their days." },
  { book: "1 Enoch", chapter: 103, verse: 6, text: "And how they have died in prosperity and in wealth, \nAnd have not seen tribulation or murder in their life; \nAnd they have died in honour, \nAnd judgement has not been executed on them during their life.\"" },
  { book: "1 Enoch", chapter: 103, verse: 7, text: "Know ye, that their souls will be made to descend into Sheol \nAnd they shall be wretched in their great tribulation." },
  { book: "1 Enoch", chapter: 103, verse: 8, text: "And into darkness and chains and a burning flame where there is grievous judgement shall your spirits enter; \nAnd the great judgement shall be for all the generations of the world. \nWoe to you, for ye shall have no peace." },
  { book: "1 Enoch", chapter: 103, verse: 9, text: "Say not in regard to the righteous and good who are in life: \n\"In our troubled days we have toiled laboriously and experienced every trouble, \nAnd met with much evil and been consumed,\nAnd have become few and our spirit small." },
  { book: "1 Enoch", chapter: 103, verse: 10, text: "And we have been destroyed and have not found any to help us even with a word: \nWe have been tortured ⌈and destroyed⌉, and not hoped to see life from day to day." },
  { book: "1 Enoch", chapter: 103, verse: 11, text: "We hoped to be the head and have become the tail: \nWe have toiled laboriously and had no satisfaction in our toil; \nAnd we have become the food of the sinners and the unrighteous,\nAnd they have laid their yoke heavily upon us." },
  { book: "1 Enoch", chapter: 103, verse: 12, text: "They have had dominion over us that hated us and smote us; \nAnd to those that hated us we have bowed our necks \nBut they pitied us not." },
  { book: "1 Enoch", chapter: 103, verse: 13, text: "We desired to get away from them that we might escape and be at rest, \nBut found no place whereunto we should flee and be safe from them." },
  { book: "1 Enoch", chapter: 103, verse: 14, text: "And are complained to the rulers in our tribulation, \nAnd cried out against those who devoured us, \nBut they did not attend to our cries\nAnd would not hearken to our voice." },
  { book: "1 Enoch", chapter: 103, verse: 15, text: "And they helped those who robbed us and devoured us and those who made us few; and they concealed their oppression, and they did not remove from us the yoke of those that devoured us and dispersed us and murdered us, and they concealed their murder, and remembered not that they had lifted up their hands against us." },
  { book: "1 Enoch", chapter: 104, verse: 1, text: "I swear unto you, that in heaven the angels remember you for good before the glory of the Great One: and your names are written before the glory of the Great One." },
  { book: "1 Enoch", chapter: 104, verse: 2, text: "Be hopeful; for aforetime ye were put to shame through ill and affliction; but now ye shall shine as the lights of heaven, ye shall shine and ye shall be seen, and the portals of heaven shall be opened to you." },
  { book: "1 Enoch", chapter: 104, verse: 3, text: "And in your cry, cry for judgement, and it shall appear to you; for all your tribulation shall be visited on the rulers, and on all who helped those who plundered you." },
  { book: "1 Enoch", chapter: 104, verse: 4, text: "Be hopeful, and cast not away your hopes for ye shall have great joy as the angels of heaven." },
  { book: "1 Enoch", chapter: 104, verse: 5, text: "What shall ye be obliged to do? Ye shall not have to hide on the day of the great judgement and ye shall not be found as sinners, and the eternal judgement shall be far from you for all the generations of the world." },
  { book: "1 Enoch", chapter: 104, verse: 6, text: "And now fear not, ye righteous, when ye see the sinners growing strong and prospering in their ways: be not companions with them, but keep afar from their violence; for ye shall become companions of the hosts of heaven." },
  { book: "1 Enoch", chapter: 104, verse: 7, text: "And, although ye sinners say: \"All our sins shall not be searched out and be written down,\" nevertheless they shall write down all your sins every day." },
  { book: "1 Enoch", chapter: 104, verse: 8, text: "And now I show unto you that light and darkness, day and night, see all your sins." },
  { book: "1 Enoch", chapter: 104, verse: 9, text: "Be not godless in your hearts, and lie not and alter not the words of uprightness, nor charge with lying the words of the Holy Great One, nor take account of your idols; for all your lying and all your godlessness issue not in righteousness but in great sin." },
  { book: "1 Enoch", chapter: 104, verse: 10, text: "And now I know this mystery, that sinners will alter and pervert the words of righteousness in many ways, and will speak wicked words, and lie, and practice great deceits, and write books concerning their words." },
  { book: "1 Enoch", chapter: 104, verse: 11, text: "But when they write down truthfully all my words in their languages, and do not change or minish ought from my words but write them all down truthfully--all that I first testified concerning them." },
  { book: "1 Enoch", chapter: 104, verse: 12, text: "Then, I know another mystery, that books will be given to the righteous and the wise to become a cause of joy and uprightness and much wisdom." },
  { book: "1 Enoch", chapter: 104, verse: 13, text: "And to them shall the books be given, and they shall believe in them and rejoice over them, and then shall all the righteous who have learnt therefrom all the paths of uprightness be recompensed.'" },
  { book: "1 Enoch", chapter: 105, verse: 1, text: "In those days the Lord bade (them) to summon and testify to the children of earth concerning their wisdom: Show (it) unto them; for ye are their guides, and a recompense over the whole earth." },
  { book: "1 Enoch", chapter: 105, verse: 2, text: "For I and My son will be united with them for ever in the paths of uprightness in their lives; and ye shall have peace: rejoice, ye children of uprightness. Amen." },
  { book: "1 Enoch", chapter: 106, verse: 1, text: "And after some days my son Methuselah took a wife for his son Lamech, and she became pregnant by him and bore a son." },
  { book: "1 Enoch", chapter: 106, verse: 1, text: "said unto him: 'Behold, here am I, my son, wherefore hast thou come to me?'" },
  { book: "1 Enoch", chapter: 106, verse: 2, text: "And his body was white as snow and red as the blooming of a rose, and the hair of his head and his long locks were white as wool, and his eyes beautiful. And when he opened his eyes, he lighted up the whole house like the sun, and the whole house was very bright." },
  { book: "1 Enoch", chapter: 106, verse: 3, text: "And thereupon he arose in the hands of the midwife, opened his mouth, and conversed with the Lord of righteousness." },
  { book: "1 Enoch", chapter: 106, verse: 4, text: "And his father Lamech was afraid of him and fled, and came to his father Methuselah." },
  { book: "1 Enoch", chapter: 106, verse: 5, text: "And he said unto him: 'I have begotten a strange son, diverse from and unlike man, and resembling the sons of the God of heaven; and his nature is different and he is not like us, and his eyes are as the rays of the sun, and his countenance is glorious." },
  { book: "1 Enoch", chapter: 106, verse: 6, text: "And it seems to me that he is not sprung from me but from the angels, and I fear that in his days a wonder may be wrought on the earth." },
  { book: "1 Enoch", chapter: 106, verse: 7, text: "And now, my father, I am here to petition thee and implore thee that thou mayest go to Enoch, our father, and learn from him the truth, for his dwelling-place is amongst the angels.'" },
  { book: "1 Enoch", chapter: 106, verse: 8, text: "And when Methuselah heard the words of his son, he came to me to the ends of the earth; for he had heard that I was there, and he cried aloud, and I heard his voice and I came to him. And" },
  { book: "1 Enoch", chapter: 106, verse: 9, text: "And he answered and said: 'Because of a great cause of anxiety have I come to thee, and because of a disturbing vision have I approached." },
  { book: "1 Enoch", chapter: 106, verse: 10, text: "And now, my father, hear me: unto Lamech my son there hath been born a son, the like of whom there is none, and his nature is not like man's nature, and the colour of his body is whiter than snow and redder than the bloom of a rose, and the hair of his head is whiter than white wool, and his eyes are like the rays of the sun, and he opened his eyes and thereupon lighted up the whole house." },
  { book: "1 Enoch", chapter: 106, verse: 11, text: "And he arose in the hands of the midwife, and opened his mouth and blessed the Lord of heaven." },
  { book: "1 Enoch", chapter: 106, verse: 12, text: "And his father Lamech became afraid and fled to me, and did not believe that he was sprung from him, but that he was in the likeness of the angels of heaven; and behold I have come to thee that thou mayest make known to me the truth.'" },
  { book: "1 Enoch", chapter: 106, verse: 13, text: "And I, Enoch, answered and said unto him: 'The Lord will do a new thing on the earth, and this I have already seen in a vision, and make known to thee that in the generation of my father Jared some of the angels of heaven transgressed the word of the Lord." },
  { book: "1 Enoch", chapter: 106, verse: 14, text: "And behold they commit sin and transgress the law, and have united themselves with women and commit sin with them, and have married some of them, and have begot children by them." },
  { book: "1 Enoch", chapter: 106, verse: 15, text: "Yea, there shall come a great destruction over the whole earth, and there shall be a deluge and a great destruction for one year." },
  { book: "1 Enoch", chapter: 106, verse: 16, text: "And this son who has been born unto you shall be left on the earth, and his three children shall be saved with him: when all mankind that are on the earth shall die [he and his sons shall be saved]." },
  { book: "1 Enoch", chapter: 106, verse: 17, text: "And they shall produce on the earth giants not according to the spirit, but according to the flesh, and there shall be a great punishment on the earth, and the earth shall be cleansed from all impurity." },
  { book: "1 Enoch", chapter: 106, verse: 18, text: "And now make known to thy son Lamech that he who has been born is in truth his son, and call his name Noah; for he shall be left to you, and he and his sons shall be saved from the destruction, which shall come upon the earth on account of all the sin and all the unrighteousness, which shall be consummated on the earth in his days." },
  { book: "1 Enoch", chapter: 106, verse: 19, text: "And after that there shall be still more unrighteousness than that which was first consummated on the earth; for I know the mysteries of the holy ones; for He, the Lord, has showed me and informed me, and I have read (them) in the heavenly tablets." },
  { book: "1 Enoch", chapter: 107, verse: 1, text: "And I saw written on them that generation upon generation shall transgress, till a generation of righteousness arises, and transgression is destroyed and sin passes away from the earth, and all manner of good comes upon it." },
  { book: "1 Enoch", chapter: 107, verse: 2, text: "And now, my son, go and make known to thy son Lamech that this son, which has been born, is in truth his son, and that (this) is no lie.'" },
  { book: "1 Enoch", chapter: 107, verse: 3, text: "And when Methuselah had heard the words of his father Enoch--for he had shown to him everything in secret--he returned and showed (them) to him and called the name of that son Noah; for he will comfort the earth after all the destruction." },
  { book: "1 Enoch", chapter: 108, verse: 1, text: "Another book which Enoch wrote for his son Methuselah and for those who will come after him, and keep the law in the last days." },
  { book: "1 Enoch", chapter: 108, verse: 2, text: "Ye who have done good shall wait for those days till an end is made of those who work evil; and an end of the might of the transgressors." },
  { book: "1 Enoch", chapter: 108, verse: 3, text: "And wait ye indeed till sin has passed away, for their names shall be blotted out of the book of life and out of the holy books, and their seed shall be destroyed for ever, and their spirits shall be slain, and they shall cry and make lamentation in a place that is a chaotic wilderness, and in the fire shall they burn; for there is no earth there." },
  { book: "1 Enoch", chapter: 108, verse: 4, text: "And I saw there something like an invisible cloud; for by reason of its depth I could not look over, and I saw a flame of fire blazing brightly, and things like shining mountains circling and sweeping to and fro." },
  { book: "1 Enoch", chapter: 108, verse: 5, text: "And I asked one of the holy angels who was with me and said unto him: 'What is this shining thing? for it is not a heaven but only the flame of a blazing fire, and the voice of weeping and crying and lamentation and strong pain.'" },
  { book: "1 Enoch", chapter: 108, verse: 6, text: "And he said unto me: 'This place which thou seest--here are cast the spirits of sinners and blasphemers, and of those who work wickedness, and of those who pervert everything that the Lord hath spoken through the mouth of the prophets--(even) the things that shall be." },
  { book: "1 Enoch", chapter: 108, verse: 7, text: "For some of them are written and inscribed above in the heaven, in order that the angels may read them and know that which shall befall the sinners, and the spirits of the humble, and of those who have afflicted their bodies, and been recompensed by God; and of those who have been put to shame by wicked men:" },
  { book: "1 Enoch", chapter: 108, verse: 8, text: "Who love God and loved neither gold nor silver nor any of the good things which are in the world, but gave over their bodies to torture." },
  { book: "1 Enoch", chapter: 108, verse: 9, text: "Who, since they came into being, longed not after earthly food, but regarded everything as a passing breath, and lived accordingly, and the Lord tried them much, and their spirits were found pure so that they should bless His name." },
  { book: "1 Enoch", chapter: 108, verse: 10, text: "And all the blessings destined for them I have recounted in the books. And he hath assigned them their recompense, because they have been found to be such as loved heaven more than their life in the world, and though they were trodden under foot of wicked men, and experienced abuse and reviling from them and were put to shame, yet they blessed Me." },
  { book: "1 Enoch", chapter: 108, verse: 11, text: "And now I will summon the spirits of the good who belong to the generation of light, and I will transform those who were born in darkness, who in the flesh were not recompensed with such honour as their faithfulness deserved." },
  { book: "1 Enoch", chapter: 108, verse: 12, text: "And I will bring forth in shining light those who have loved My holy name, and I will seat each on the throne of his honour." },
  { book: "1 Enoch", chapter: 108, verse: 13, text: "And they shall be resplendent for times without number; for righteousness is the judgement of God; for to the faithful He will give faithfulness in the habitation of upright paths." },
  { book: "1 Enoch", chapter: 108, verse: 14, text: "And they shall see those who were, born in darkness led into darkness, while the righteous shall be resplendent." },
  { book: "1 Enoch", chapter: 108, verse: 15, text: "And the sinners shall cry aloud and see them resplendent, and they indeed will go where days and seasons are prescribed for them.'" },
  // 1 Esdras (448 verses)
  { book: "1 Esdras", chapter: 1, verse: 1, text: "And Josias held the feast of the passover in Jerusalem unto his Lord, and offered the passover the fourteenth day of the first month;" },
  { book: "1 Esdras", chapter: 1, verse: 2, text: "Having set the priests according to their daily courses, being arrayed in long garments, in the temple of the Lord." },
  { book: "1 Esdras", chapter: 1, verse: 3, text: "And he spake unto the Levites, the holy ministers of Israel, that they should hallow themselves unto the Lord, to set the holy ark of the Lord in the house that king Solomon the son of David had built:" },
  { book: "1 Esdras", chapter: 1, verse: 4, text: "And said, Ye shall no more bear the ark upon your shoulders: now therefore serve the Lord your God, and minister unto his people Israel, and prepare you after your families and kindreds," },
  { book: "1 Esdras", chapter: 1, verse: 5, text: "According as David the king of Israel prescribed, and according to the magnificence of Solomon his son: and standing in the temple according to the several dignity of the families of you the Levites, who minister in the presence of your brethren the children of Israel," },
  { book: "1 Esdras", chapter: 1, verse: 6, text: "Offer the passover in order, and make ready the sacrifices for your brethren, and keep the passover according to the commandment of the Lord, which was given unto Moses." },
  { book: "1 Esdras", chapter: 1, verse: 7, text: "And unto the people that was found there Josias gave thirty thousand lambs and kids, and three thousand calves: these things were given of the king’s allowance, according as he promised, to the people, to the priests, and to the Levites." },
  { book: "1 Esdras", chapter: 1, verse: 8, text: "And Helkias, Zacharias, and Syelus, the governors of the temple, gave to the priests for the passover two thousand and six hundred sheep, and three hundred calves." },
  { book: "1 Esdras", chapter: 1, verse: 9, text: "And Jeconias, and Samaias, and Nathanael his brother, and Assabias, and Ochiel, and Joram, captains over thousands, gave to the Levites for the passover five thousand sheep, and seven hundred calves." },
  { book: "1 Esdras", chapter: 1, verse: 10, text: "And when these things were done, the priests and Levites, having the unleavened bread, stood in very comely order according to the kindreds," },
  { book: "1 Esdras", chapter: 1, verse: 11, text: "And according to the several dignities of the fathers, before the people, to offer to the Lord, as it is written in the book of Moses: and thus did they in the morning." },
  { book: "1 Esdras", chapter: 1, verse: 12, text: "And they roasted the passover with fire, as appertaineth: as for the sacrifices, they sod them in brass pots and pans with a good savour," },
  { book: "1 Esdras", chapter: 1, verse: 13, text: "And set them before all the people: and afterward they prepared for themselves, and for the priests their brethren, the sons of Aaron." },
  { book: "1 Esdras", chapter: 1, verse: 14, text: "For the priests offered the fat until night: and the Levites prepared for themselves, and the priests their brethren, the sons of Aaron." },
  { book: "1 Esdras", chapter: 1, verse: 15, text: "The holy singers also, the sons of Asaph, were in their order, according to the appointment of David, to wit, Asaph, Zacharias, and Jeduthun, who was of the king’s retinue." },
  { book: "1 Esdras", chapter: 1, verse: 16, text: "Moreover the porters were at every gate; it was not lawful for any to go from his ordinary service: for their brethren the Levites prepared for them." },
  { book: "1 Esdras", chapter: 1, verse: 17, text: "Thus were the things that belonged to the sacrifices of the Lord accomplished in that day, that they might hold the passover," },
  { book: "1 Esdras", chapter: 1, verse: 18, text: "And offer sacrifices upon the altar of the Lord, according to the commandment of king Josias." },
  { book: "1 Esdras", chapter: 1, verse: 19, text: "So the children of Israel which were present held the passover at that time, and the feast of sweet bread seven days." },
  { book: "1 Esdras", chapter: 1, verse: 20, text: "And such a passover was not kept in Israel since the time of the prophet Samuel." },
  { book: "1 Esdras", chapter: 1, verse: 21, text: "Yea, all the kings of Israel held not such a passover as Josias, and the priests, and the Levites, and the Jews, held with all Israel that were found dwelling at Jerusalem." },
  { book: "1 Esdras", chapter: 1, verse: 22, text: "In the eighteenth year of the reign of Josias was this passover kept." },
  { book: "1 Esdras", chapter: 1, verse: 23, text: "And the works or Josias were upright before his Lord with an heart full of godliness." },
  { book: "1 Esdras", chapter: 1, verse: 24, text: "As for the things that came to pass in his time, they were written in former times, concerning those that sinned, and did wickedly against the Lord above all people and kingdoms, and how they grieved him exceedingly, so that the words of the Lord rose up against Israel." },
  { book: "1 Esdras", chapter: 1, verse: 25, text: "Now after all these acts of Josias it came to pass, that Pharaoh the king of Egypt came to raise war at Carchamis upon Euphrates: and Josias went out against him." },
  { book: "1 Esdras", chapter: 1, verse: 26, text: "But the king of Egypt sent to him, saying, What have I to do with thee, O king of Judea?" },
  { book: "1 Esdras", chapter: 1, verse: 27, text: "I am not sent out from the Lord God against thee; for my war is upon Euphrates: and now the Lord is with me, yea, the Lord is with me hasting me forward: depart from me, and be not against the Lord." },
  { book: "1 Esdras", chapter: 1, verse: 28, text: "Howbeit Josias did not turn back his chariot from him, but undertook to fight with him, not regarding the words of the prophet Jeremy spoken by the mouth of the Lord:" },
  { book: "1 Esdras", chapter: 1, verse: 29, text: "But joined battle with him in the plain of Magiddo, and the princes came against king Josias." },
  { book: "1 Esdras", chapter: 1, verse: 30, text: "Then said the king unto his servants, Carry me away out of the battle; for I am very weak. And immediately his servants took him away out of the battle." },
  { book: "1 Esdras", chapter: 1, verse: 31, text: "Then gat he up upon his second chariot; and being brought back to Jerusalem died, and was buried in his father’s sepulchre." },
  { book: "1 Esdras", chapter: 1, verse: 32, text: "And in all Jewry they mourned for Josias, yea, Jeremy the prophet lamented for Josias, and the chief men with the women made lamentation for him unto this day: and this was given out for an ordinance to be done continually in all the nation of Israel." },
  { book: "1 Esdras", chapter: 1, verse: 33, text: "These things are written in the book of the stories of the kings of Judah, and every one of the acts that Josias did, and his glory, and his understanding in the law of the Lord, and the things that he had done before, and the things now recited, are reported in the book of the kings of Israel and Judea." },
  { book: "1 Esdras", chapter: 1, verse: 34, text: "And the people took Joachaz the son of Josias, and made him king instead of Josias his father, when he was twenty and three years old." },
  { book: "1 Esdras", chapter: 1, verse: 35, text: "And he reigned in Judea and in Jerusalem three months: and then the king of Egypt deposed him from reigning in Jerusalem." },
  { book: "1 Esdras", chapter: 1, verse: 36, text: "And he set a tax upon the land of an hundred talents of silver and one talent of gold." },
  { book: "1 Esdras", chapter: 1, verse: 37, text: "The king of Egypt also made king Joacim his brother king of Judea and Jerusalem." },
  { book: "1 Esdras", chapter: 1, verse: 38, text: "And he bound Joacim and the nobles: but Zaraces his brother he apprehended, and brought him out of Egypt." },
  { book: "1 Esdras", chapter: 1, verse: 39, text: "Five and twenty years old was Joacim when he was made king in the land of Judea and Jerusalem; and he did evil before the Lord." },
  { book: "1 Esdras", chapter: 1, verse: 40, text: "Wherefore against him Nabuchodonosor the king of Babylon came up, and bound him with a chain of brass, and carried him into Babylon." },
  { book: "1 Esdras", chapter: 1, verse: 41, text: "Nabuchodonosor also took of the holy vessels of the Lord, and carried them away, and set them in his own temple at Babylon." },
  { book: "1 Esdras", chapter: 1, verse: 42, text: "But those things that are recorded of him, and of his uncleanness and impiety, are written in the chronicles of the kings." },
  { book: "1 Esdras", chapter: 1, verse: 43, text: "And Joacim his son reigned in his stead: he was made king being eighteen years old;" },
  { book: "1 Esdras", chapter: 1, verse: 44, text: "And reigned but three months and ten days in Jerusalem; and did evil before the Lord." },
  { book: "1 Esdras", chapter: 1, verse: 45, text: "So after a year Nabuchodonosor sent and caused him to be brought into Babylon with the holy vessels of the Lord;" },
  { book: "1 Esdras", chapter: 1, verse: 46, text: "And made Zedechias king of Judea and Jerusalem, when he was one and twenty years old; and he reigned eleven years:" },
  { book: "1 Esdras", chapter: 1, verse: 47, text: "And he did evil also in the sight of the Lord, and cared not for the words that were spoken unto him by the prophet Jeremy from the mouth of the Lord." },
  { book: "1 Esdras", chapter: 1, verse: 48, text: "And after that king Nabuchodonosor had made him to swear by the name of the Lord, he forswore himself, and rebelled; and hardening his neck, his heart, he transgressed the laws of the Lord God of Israel." },
  { book: "1 Esdras", chapter: 1, verse: 49, text: "The governors also of the people and of the priests did many things against the laws, and passed all the pollutions of all nations, and defiled the temple of the Lord, which was sanctified in Jerusalem." },
  { book: "1 Esdras", chapter: 1, verse: 50, text: "Nevertheless the God of their fathers sent by his messenger to call them back, because he spared them and his tabernacle also." },
  { book: "1 Esdras", chapter: 1, verse: 51, text: "But they had his messengers in derision; and, look, when the Lord spake unto them, they made a sport of his prophets:" },
  { book: "1 Esdras", chapter: 1, verse: 52, text: "So far forth, that he, being wroth with his people for their great ungodliness, commanded the kings of the Chaldees to come up against them;" },
  { book: "1 Esdras", chapter: 1, verse: 53, text: "Who slew their young men with the sword, yea, even within the compass of their holy temple, and spared neither young man nor maid, old man nor child, among them; for he delivered all into their hands." },
  { book: "1 Esdras", chapter: 1, verse: 54, text: "And they took all the holy vessels of the Lord, both great and small, with the vessels of the ark of God, and the king’s treasures, and carried them away into Babylon." },
  { book: "1 Esdras", chapter: 1, verse: 55, text: "As for the house of the Lord, they burnt it, and brake down the walls of Jerusalem, and set fire upon her towers:" },
  { book: "1 Esdras", chapter: 1, verse: 56, text: "And as for her glorious things, they never ceased till they had consumed and brought them all to nought: and the people that were not slain with the sword he carried unto Babylon:" },
  { book: "1 Esdras", chapter: 1, verse: 57, text: "Who became servants to him and his children, till the Persians reigned, to fulfil the word of the Lord spoken by the mouth of Jeremy:" },
  { book: "1 Esdras", chapter: 1, verse: 58, text: "Until the land had enjoyed her sabbaths, the whole time of her desolation shall she rest, until the full term of seventy years." },
  { book: "1 Esdras", chapter: 2, verse: 1, text: "In the first year of Cyrus king of the Persians, that the word of the Lord might be accomplished, that he had promised by the mouth of Jeremy;" },
  { book: "1 Esdras", chapter: 2, verse: 2, text: "The Lord raised up the spirit of Cyrus the king of the Persians, and he made proclamation through all his kingdom, and also by writing," },
  { book: "1 Esdras", chapter: 2, verse: 3, text: "Saying, Thus saith Cyrus king of the Persians; The Lord of Israel, the most high Lord, hath made me king of the whole world," },
  { book: "1 Esdras", chapter: 2, verse: 4, text: "And commanded me to build him an house at Jerusalem in Jewry." },
  { book: "1 Esdras", chapter: 2, verse: 5, text: "If therefore there be any of you that are of his people, let the Lord, even his Lord, be with him, and let him go up to Jerusalem that is in Judea, and build the house of the Lord of Israel: for he is the Lord that dwelleth in Jerusalem." },
  { book: "1 Esdras", chapter: 2, verse: 6, text: "Whosoever then dwell in the places about, let them help him, those, I say, that are his neighbours, with gold, and with silver," },
  { book: "1 Esdras", chapter: 2, verse: 7, text: "With gifts, with horses, and with cattle, and other things, which have been set forth by vow, for the temple of the Lord at Jerusalem." },
  { book: "1 Esdras", chapter: 2, verse: 8, text: "Then the chief of the families of Judea and of the tribe of Benjamin stood up; the priests also, and the Levites, and all they whose mind the Lord had moved to go up, and to build an house for the Lord at Jerusalem," },
  { book: "1 Esdras", chapter: 2, verse: 9, text: "And they that dwelt round about them, and helped them in all things with silver and gold, with horses and cattle, and with very many free gifts of a great number whose minds were stirred up thereto." },
  { book: "1 Esdras", chapter: 2, verse: 10, text: "King Cyrus also brought forth the holy vessels, which Nabuchodonosor had carried away from Jerusalem, and had set up in his temple of idols." },
  { book: "1 Esdras", chapter: 2, verse: 11, text: "Now when Cyrus king of the Persians had brought them forth, he delivered them to Mithridates his treasurer:" },
  { book: "1 Esdras", chapter: 2, verse: 12, text: "And by him they were delivered to Sanabassar the governor of Judea." },
  { book: "1 Esdras", chapter: 2, verse: 13, text: "And this was the number of them; A thousand golden cups, and a thousand of silver, censers of silver twenty nine, vials of gold thirty, and of silver two thousand four hundred and ten, and a thousand other vessels." },
  { book: "1 Esdras", chapter: 2, verse: 14, text: "So all the vessels of gold and of silver, which were carried away, were five thousand four hundred threescore and nine." },
  { book: "1 Esdras", chapter: 2, verse: 15, text: "These were brought back by Sanabassar, together with them of the captivity, from Babylon to Jerusalem." },
  { book: "1 Esdras", chapter: 2, verse: 16, text: "But in the time of Artexerxes king of the Persians Belemus, and Mithridates, and Tabellius, and Rathumus, and Beeltethmus, and Semellius the secretary, with others that were in commission with them, dwelling in Samaria and other places, wrote unto him against them that dwelt in Judea and Jerusalem these letters following;" },
  { book: "1 Esdras", chapter: 2, verse: 17, text: "To king Artexerxes our lord, Thy servants, Rathumus the storywriter, and Semellius the scribe, and the rest of their council, and the judges that are in Celosyria and Phenice." },
  { book: "1 Esdras", chapter: 2, verse: 18, text: "Be it now known to the lord king, that the Jews that are up from you to us, being come into Jerusalem, that rebellious and wicked city, do build the marketplaces, and repair the walls of it and do lay the foundation of the temple." },
  { book: "1 Esdras", chapter: 2, verse: 19, text: "Now if this city and the walls thereof be made up again, they will not only refuse to give tribute, but also rebel against kings." },
  { book: "1 Esdras", chapter: 2, verse: 20, text: "And forasmuch as the things pertaining to the temple are now in hand, we think it meet not to neglect such a matter," },
  { book: "1 Esdras", chapter: 2, verse: 21, text: "But to speak unto our lord the king, to the intent that, if it be thy pleasure it may be sought out in the books of thy fathers:" },
  { book: "1 Esdras", chapter: 2, verse: 22, text: "And thou shalt find in the chronicles what is written concerning these things, and shalt understand that that city was rebellious, troubling both kings and cities:" },
  { book: "1 Esdras", chapter: 2, verse: 23, text: "And that the Jews were rebellious, and raised always wars therein; for the which cause even this city was made desolate." },
  { book: "1 Esdras", chapter: 2, verse: 24, text: "Wherefore now we do declare unto thee, O lord the king, that if this city be built again, and the walls thereof set up anew, thou shalt from henceforth have no passage into Celosyria and Phenice." },
  { book: "1 Esdras", chapter: 2, verse: 25, text: "Then the king wrote back again to Rathumus the storywriter, to Beeltethmus, to Semellius the scribe, and to the rest that were in commission, and dwellers in Samaria and Syria and Phenice, after this manner;" },
  { book: "1 Esdras", chapter: 2, verse: 26, text: "I have read the epistle which ye have sent unto me: therefore I commanded to make diligent search, and it hath been found that that city was from the beginning practising against kings;" },
  { book: "1 Esdras", chapter: 2, verse: 27, text: "And the men therein were given to rebellion and war: and that mighty kings and fierce were in Jerusalem, who reigned and exacted tributes in Celosyria and Phenice." },
  { book: "1 Esdras", chapter: 2, verse: 28, text: "Now therefore I have commanded to hinder those men from building the city, and heed to be taken that there be no more done in it;" },
  { book: "1 Esdras", chapter: 2, verse: 29, text: "And that those wicked workers proceed no further to the annoyance of kings," },
  { book: "1 Esdras", chapter: 2, verse: 30, text: "Then king Artexerxes his letters being read, Rathumus, and Semellius the scribe, and the rest that were in commission with them, removing in haste toward Jerusalem with a troop of horsemen and a multitude of people in battle array, began to hinder the builders; and the building of the temple in Jerusalem ceased until the second year of the reign of Darius king of the Persians." },
  { book: "1 Esdras", chapter: 3, verse: 1, text: "Now when Darius reigned, he made a great feast unto all his subjects, and unto all his household, and unto all the princes of Media and Persia," },
  { book: "1 Esdras", chapter: 3, verse: 2, text: "And to all the governors and captains and lieutenants that were under him, from India unto Ethiopia, of an hundred twenty and seven provinces." },
  { book: "1 Esdras", chapter: 3, verse: 3, text: "And when they had eaten and drunken, and being satisfied were gone home, then Darius the king went into his bedchamber, and slept, and soon after awaked." },
  { book: "1 Esdras", chapter: 3, verse: 4, text: "Then three young men, that were of the guard that kept the king’s body, spake one to another;" },
  { book: "1 Esdras", chapter: 3, verse: 5, text: "Let every one of us speak a sentence: he that shall overcome, and whose sentence shall seem wiser than the others, unto him shall the king Darius give great gifts, and great things in token of victory:" },
  { book: "1 Esdras", chapter: 3, verse: 6, text: "As, to be clothed in purple, to drink in gold, and to sleep upon gold, and a chariot with bridles of gold, and an headtire of fine linen, and a chain about his neck:" },
  { book: "1 Esdras", chapter: 3, verse: 7, text: "And he shall sit next to Darius because of his wisdom, and shall be called Darius his cousin." },
  { book: "1 Esdras", chapter: 3, verse: 8, text: "And then every one wrote his sentence, sealed it, and laid it under king Darius his pillow;" },
  { book: "1 Esdras", chapter: 3, verse: 9, text: "And said that, when the king is risen, some will give him the writings; and of whose side the king and the three princes of Persia shall judge that his sentence is the wisest, to him shall the victory be given, as was appointed." },
  { book: "1 Esdras", chapter: 3, verse: 10, text: "The first wrote, Wine is the strongest." },
  { book: "1 Esdras", chapter: 3, verse: 11, text: "The second wrote, The king is strongest." },
  { book: "1 Esdras", chapter: 3, verse: 12, text: "The third wrote, Women are strongest: but above all things Truth beareth away the victory." },
  { book: "1 Esdras", chapter: 3, verse: 13, text: "Now when the king was risen up, they took their writings, and delivered them unto him, and so he read them:" },
  { book: "1 Esdras", chapter: 3, verse: 14, text: "And sending forth he called all the princes of Persia and Media, and the governors, and the captains, and the lieutenants, and the chief officers;" },
  { book: "1 Esdras", chapter: 3, verse: 15, text: "And sat him down in the royal seat of judgment; and the writings were read before them." },
  { book: "1 Esdras", chapter: 3, verse: 16, text: "And he said, Call the young men, and they shall declare their own sentences. So they were called, and came in." },
  { book: "1 Esdras", chapter: 3, verse: 17, text: "And he said unto them, Declare unto us your mind concerning the writings. Then began the first, who had spoken of the strength of wine;" },
  { book: "1 Esdras", chapter: 3, verse: 18, text: "And he said thus, O ye men, how exceeding strong is wine! it causeth all men to err that drink it:" },
  { book: "1 Esdras", chapter: 3, verse: 19, text: "It maketh the mind of the king and of the fatherless child to be all one; of the bondman and of the freeman, of the poor man and of the rich:" },
  { book: "1 Esdras", chapter: 3, verse: 20, text: "It turneth also every thought into jollity and mirth, so that a man remembereth neither sorrow nor debt:" },
  { book: "1 Esdras", chapter: 3, verse: 21, text: "And it maketh every heart rich, so that a man remembereth neither king nor governor; and it maketh to speak all things by talents:" },
  { book: "1 Esdras", chapter: 3, verse: 22, text: "And when they are in their cups, they forget their love both to friends and brethren, and a little after draw out swords:" },
  { book: "1 Esdras", chapter: 3, verse: 23, text: "But when they are from the wine, they remember not what they have done." },
  { book: "1 Esdras", chapter: 3, verse: 24, text: "O ye men, is not wine the strongest, that enforceth to do thus? And when he had so spoken, he held his peace." },
  { book: "1 Esdras", chapter: 4, verse: 1, text: "Then the second, that had spoken of the strength of the king, began to say," },
  { book: "1 Esdras", chapter: 4, verse: 2, text: "O ye men, do not men excel in strength that bear rule over sea and land and all things in them?" },
  { book: "1 Esdras", chapter: 4, verse: 3, text: "But yet the king is more mighty: for he is lord of all these things, and hath dominion over them; and whatsoever he commandeth them they do." },
  { book: "1 Esdras", chapter: 4, verse: 4, text: "If he bid them make war the one against the other, they do it: if he send them out against the enemies, they go, and break down mountains walls and towers." },
  { book: "1 Esdras", chapter: 4, verse: 5, text: "They slay and are slain, and transgress not the king’s commandment: if they get the victory, they bring all to the king, as well the spoil, as all things else." },
  { book: "1 Esdras", chapter: 4, verse: 6, text: "Likewise for those that are no soldiers, and have not to do with wars, but use husbandry, when they have reaped again that which they had sown, they bring it to the king, and compel one another to pay tribute unto the king." },
  { book: "1 Esdras", chapter: 4, verse: 7, text: "And yet he is but one man: if he command to kill, they kill; if he command to spare, they spare;" },
  { book: "1 Esdras", chapter: 4, verse: 8, text: "If he command to smite, they smite; if he command to make desolate, they make desolate; if he command to build, they build;" },
  { book: "1 Esdras", chapter: 4, verse: 9, text: "If he command to cut down, they cut down; if he command to plant, they plant." },
  { book: "1 Esdras", chapter: 4, verse: 10, text: "So all his people and his armies obey him: furthermore he lieth down, he eateth and drinketh, and taketh his rest:" },
  { book: "1 Esdras", chapter: 4, verse: 11, text: "And these keep watch round about him, neither may any one depart, and do his own business, neither disobey they him in any thing." },
  { book: "1 Esdras", chapter: 4, verse: 12, text: "O ye men, how should not the king be mightiest, when in such sort he is obeyed? And he held his tongue." },
  { book: "1 Esdras", chapter: 4, verse: 13, text: "Then the third, who had spoken of women, and of the truth, (this was Zorobabel) began to speak." },
  { book: "1 Esdras", chapter: 4, verse: 14, text: "O ye men, it is not the great king, nor the multitude of men, neither is it wine, that excelleth; who is it then that ruleth them, or hath the lordship over them? are they not women?" },
  { book: "1 Esdras", chapter: 4, verse: 15, text: "Women have borne the king and all the people that bear rule by sea and land." },
  { book: "1 Esdras", chapter: 4, verse: 16, text: "Even of them came they: and they nourished them up that planted the vineyards, from whence the wine cometh." },
  { book: "1 Esdras", chapter: 4, verse: 17, text: "These also make garments for men; these bring glory unto men; and without women cannot men be." },
  { book: "1 Esdras", chapter: 4, verse: 18, text: "Yea, and if men have gathered together gold and silver, or any other goodly thing, do they not love a woman which is comely in favour and beauty?" },
  { book: "1 Esdras", chapter: 4, verse: 19, text: "And letting all those things go, do they not gape, and even with open mouth fix their eyes fast on her; and have not all men more desire unto her than unto silver or gold, or any goodly thing whatsoever?" },
  { book: "1 Esdras", chapter: 4, verse: 20, text: "A man leaveth his own father that brought him up, and his own country, and cleaveth unto his wife." },
  { book: "1 Esdras", chapter: 4, verse: 21, text: "He sticketh not to spend his life with his wife. and remembereth neither father, nor mother, nor country." },
  { book: "1 Esdras", chapter: 4, verse: 22, text: "By this also ye must know that women have dominion over you: do ye not labour and toil, and give and bring all to the woman?" },
  { book: "1 Esdras", chapter: 4, verse: 23, text: "Yea, a man taketh his sword, and goeth his way to rob and to steal, to sail upon the sea and upon rivers;" },
  { book: "1 Esdras", chapter: 4, verse: 24, text: "And looketh upon a lion, and goeth in the darkness; and when he hath stolen, spoiled, and robbed, he bringeth it to his love." },
  { book: "1 Esdras", chapter: 4, verse: 25, text: "Wherefore a man loveth his wife better than father or mother." },
  { book: "1 Esdras", chapter: 4, verse: 26, text: "Yea, many there be that have run out of their wits for women, and become servants for their sakes." },
  { book: "1 Esdras", chapter: 4, verse: 27, text: "Many also have perished, have erred, and sinned, for women." },
  { book: "1 Esdras", chapter: 4, verse: 28, text: "And now do ye not believe me? is not the king great in his power? do not all regions fear to touch him?" },
  { book: "1 Esdras", chapter: 4, verse: 29, text: "Yet did I see him and Apame the king’s concubine, the daughter of the admirable Bartacus, sitting at the right hand of the king," },
  { book: "1 Esdras", chapter: 4, verse: 30, text: "And taking the crown from the king’s head, and setting it upon her own head; she also struck the king with her left hand." },
  { book: "1 Esdras", chapter: 4, verse: 31, text: "And yet for all this the king gaped and gazed upon her with open mouth: if she laughed upon him, he laughed also: but if she took any displeasure at him, the king was fain to flatter, that she might be reconciled to him again." },
  { book: "1 Esdras", chapter: 4, verse: 32, text: "O ye men, how can it be but women should be strong, seeing they do thus?" },
  { book: "1 Esdras", chapter: 4, verse: 33, text: "Then the king and the princes looked one upon another: so he began to speak of the truth." },
  { book: "1 Esdras", chapter: 4, verse: 34, text: "O ye men, are not women strong? great is the earth, high is the heaven, swift is the sun in his course, for he compasseth the heavens round about, and fetcheth his course again to his own place in one day." },
  { book: "1 Esdras", chapter: 4, verse: 35, text: "Is he not great that maketh these things? therefore great is the truth, and stronger than all things." },
  { book: "1 Esdras", chapter: 4, verse: 36, text: "All the earth crieth upon the truth, and the heaven blesseth it: all works shake and tremble at it, and with it is no unrighteous thing." },
  { book: "1 Esdras", chapter: 4, verse: 37, text: "Wine is wicked, the king is wicked, women are wicked, all the children of men are wicked, and such are all their wicked works; and there is no truth in them; in their unrighteousness also they shall perish." },
  { book: "1 Esdras", chapter: 4, verse: 38, text: "As for the truth, it endureth, and is always strong; it liveth and conquereth for evermore." },
  { book: "1 Esdras", chapter: 4, verse: 39, text: "With her there is no accepting of persons or rewards; but she doeth the things that are just, and refraineth from all unjust and wicked things; and all men do well like of her works." },
  { book: "1 Esdras", chapter: 4, verse: 40, text: "Neither in her judgment is any unrighteousness; and she is the strength, kingdom, power, and majesty, of all ages. Blessed be the God of truth." },
  { book: "1 Esdras", chapter: 4, verse: 41, text: "And with that he held his peace. And all the people then shouted, and said, Great is Truth, and mighty above all things." },
  { book: "1 Esdras", chapter: 4, verse: 42, text: "Then said the king unto him, Ask what thou wilt more than is appointed in the writing, and we will give it thee, because thou art found wisest; and thou shalt sit next me, and shalt be called my cousin." },
  { book: "1 Esdras", chapter: 4, verse: 43, text: "Then said he unto the king, Remember thy vow, which thou hast vowed to build Jerusalem, in the day when thou camest to thy kingdom," },
  { book: "1 Esdras", chapter: 4, verse: 44, text: "And to send away all the vessels that were taken away out of Jerusalem, which Cyrus set apart, when he vowed to destroy Babylon, and to send them again thither." },
  { book: "1 Esdras", chapter: 4, verse: 45, text: "Thou also hast vowed to build up the temple, which the Edomites burned when Judea was made desolate by the Chaldees." },
  { book: "1 Esdras", chapter: 4, verse: 46, text: "And now, O lord the king, this is that which I require, and which I desire of thee, and this is the princely liberality proceeding from thyself: I desire therefore that thou make good the vow, the performance whereof with thine own mouth thou hast vowed to the King of heaven." },
  { book: "1 Esdras", chapter: 4, verse: 47, text: "Then Darius the king stood up, and kissed him, and wrote letters for him unto all the treasurers and lieutenants and captains and governors, that they should safely convey on their way both him, and all those that go up with him to build Jerusalem." },
  { book: "1 Esdras", chapter: 4, verse: 48, text: "He wrote letters also unto the lieutenants that were in Celosyria and Phenice, and unto them in Libanus, that they should bring cedar wood from Libanus unto Jerusalem, and that they should build the city with him." },
  { book: "1 Esdras", chapter: 4, verse: 49, text: "Moreover he wrote for all the Jews that went out of his realm up into Jewry, concerning their freedom, that no officer, no ruler, no lieutenant, nor treasurer, should forcibly enter into their doors;" },
  { book: "1 Esdras", chapter: 4, verse: 50, text: "And that all the country which they hold should be free without tribute; and that the Edomites should give over the villages of the Jews which then they held:" },
  { book: "1 Esdras", chapter: 4, verse: 51, text: "Yea, that there should be yearly given twenty talents to the building of the temple, until the time that it were built;" },
  { book: "1 Esdras", chapter: 4, verse: 52, text: "And other ten talents yearly, to maintain the burnt offerings upon the altar every day, as they had a commandment to offer seventeen:" },
  { book: "1 Esdras", chapter: 4, verse: 53, text: "And that all they that went from Babylon to build the city should have free liberty, as well they as their posterity, and all the priests that went away." },
  { book: "1 Esdras", chapter: 4, verse: 54, text: "He wrote also concerning. the charges, and the priests’ vestments wherein they minister;" },
  { book: "1 Esdras", chapter: 4, verse: 55, text: "And likewise for the charges of the Levites, to be given them until the day that the house were finished, and Jerusalem builded up." },
  { book: "1 Esdras", chapter: 4, verse: 56, text: "And he commanded to give to all that kept the city pensions and wages." },
  { book: "1 Esdras", chapter: 4, verse: 57, text: "He sent away also all the vessels from Babylon, that Cyrus had set apart; and all that Cyrus had given in commandment, the same charged he also to be done, and sent unto Jerusalem." },
  { book: "1 Esdras", chapter: 4, verse: 58, text: "Now when this young man was gone forth, he lifted up his face to heaven toward Jerusalem, and praised the King of heaven," },
  { book: "1 Esdras", chapter: 4, verse: 59, text: "And said, From thee cometh victory, from thee cometh wisdom, and thine is the glory, and I am thy servant." },
  { book: "1 Esdras", chapter: 4, verse: 60, text: "Blessed art thou, who hast given me wisdom: for to thee I give thanks, O Lord of our fathers." },
  { book: "1 Esdras", chapter: 4, verse: 61, text: "And so he took the letters, and went out, and came unto Babylon, and told it all his brethren." },
  { book: "1 Esdras", chapter: 4, verse: 62, text: "And they praised the God of their fathers, because he had given them freedom and liberty" },
  { book: "1 Esdras", chapter: 4, verse: 63, text: "To go up, and to build Jerusalem, and the temple which is called by his name: and they feasted with instruments of musick and gladness seven days." },
  { book: "1 Esdras", chapter: 5, verse: 1, text: "After this were the principal men of the families chosen according to their tribes, to go up with their wives and sons and daughters, with their menservants and maidservants, and their cattle." },
  { book: "1 Esdras", chapter: 5, verse: 2, text: "And Darius sent with them a thousand horsemen, till they had brought them back to Jerusalem safely, and with musical instruments tabrets and flutes." },
  { book: "1 Esdras", chapter: 5, verse: 3, text: "And all their brethren played, and he made them go up together with them." },
  { book: "1 Esdras", chapter: 5, verse: 4, text: "And these are the names of the men which went up, according to their families among their tribes, after their several heads." },
  { book: "1 Esdras", chapter: 5, verse: 5, text: "The priests, the sons of Phinees the son of Aaron: Jesus the son of Josedec, the son of Saraias, and Joacim the son of Zorobabel, the son of Salathiel, of the house of David, out of the kindred of Phares, of the tribe of Judah;" },
  { book: "1 Esdras", chapter: 5, verse: 6, text: "Who spake wise sentences before Darius the king of Persia in the second year of his reign, in the month Nisan, which is the first month." },
  { book: "1 Esdras", chapter: 5, verse: 7, text: "And these are they of Jewry that came up from the captivity, where they dwelt as strangers, whom Nabuchodonosor the king of Babylon had carried away unto Babylon." },
  { book: "1 Esdras", chapter: 5, verse: 8, text: "And they returned unto Jerusalem, and to the other parts of Jewry, every man to his own city, who came with Zorobabel, with Jesus, Nehemias, and Zacharias, and Reesaias, Enenius, Mardocheus. Beelsarus, Aspharasus, Reelius, Roimus, and Baana, their guides." },
  { book: "1 Esdras", chapter: 5, verse: 9, text: "The number of them of the nation, and their governors, sons of Phoros, two thousand an hundred seventy and two; the sons of Saphat, four hundred seventy and two:" },
  { book: "1 Esdras", chapter: 5, verse: 10, text: "The sons of Ares, seven hundred fifty and six:" },
  { book: "1 Esdras", chapter: 5, verse: 11, text: "The sons of Phaath Moab, two thousand eight hundred and twelve:" },
  { book: "1 Esdras", chapter: 5, verse: 12, text: "The sons of Elam, a thousand two hundred fifty and four: the sons of Zathul, nine hundred forty and five: the sons of Corbe, seven hundred and five: the sons of Bani, six hundred forty and eight:" },
  { book: "1 Esdras", chapter: 5, verse: 13, text: "The sons of Bebai, six hundred twenty and three: the sons of Sadas, three thousand two hundred twenty and two:" },
  { book: "1 Esdras", chapter: 5, verse: 14, text: "The sons of Adonikam, six hundred sixty and seven: the sons of Bagoi, two thousand sixty and six: the sons of Adin, four hundred fifty and four:" },
  { book: "1 Esdras", chapter: 5, verse: 15, text: "The sons of Aterezias, ninety and two: the sons of Ceilan and Azetas threescore and seven: the sons of Azuran, four hundred thirty and two:" },
  { book: "1 Esdras", chapter: 5, verse: 16, text: "The sons of Ananias, an hundred and one: the sons of Arom, thirty two: and the sons of Bassa, three hundred twenty and three: the sons of Azephurith, an hundred and two:" },
  { book: "1 Esdras", chapter: 5, verse: 17, text: "The sons of Meterus, three thousand and five: the sons of Bethlomon, an hundred twenty and three:" },
  { book: "1 Esdras", chapter: 5, verse: 18, text: "They of Netophah, fifty and five: they of Anathoth, an hundred fifty and eight: they of Bethsamos, forty and two:" },
  { book: "1 Esdras", chapter: 5, verse: 19, text: "They of Kiriathiarius, twenty and five: they of Caphira and Beroth, seven hundred forty and three: they of Pira, seven hundred:" },
  { book: "1 Esdras", chapter: 5, verse: 20, text: "They of Chadias and Ammidoi, four hundred twenty and two: they of Cirama and Gabdes, six hundred twenty and one:" },
  { book: "1 Esdras", chapter: 5, verse: 21, text: "They of Macalon, an hundred twenty and two: they of Betolius, fifty and two: the sons of Nephis, an hundred fifty and six:" },
  { book: "1 Esdras", chapter: 5, verse: 22, text: "The sons of Calamolalus and Onus, seven hundred twenty and five: the sons of Jerechus, two hundred forty and five:" },
  { book: "1 Esdras", chapter: 5, verse: 23, text: "The sons of Annas, three thousand three hundred and thirty." },
  { book: "1 Esdras", chapter: 5, verse: 24, text: "The priests: the sons of Jeddu, the son of Jesus among the sons of Sanasib, nine hundred seventy and two: the sons of Meruth, a thousand fifty and two:" },
  { book: "1 Esdras", chapter: 5, verse: 25, text: "The sons of Phassaron, a thousand forty and seven: the sons of Carme, a thousand and seventeen." },
  { book: "1 Esdras", chapter: 5, verse: 26, text: "The Levites: the sons of Jessue, and Cadmiel, and Banuas, and Sudias, seventy and four." },
  { book: "1 Esdras", chapter: 5, verse: 27, text: "The holy singers: the sons of Asaph, an hundred twenty and eight." },
  { book: "1 Esdras", chapter: 5, verse: 28, text: "The porters: the sons of Salum, the sons of Jatal, the sons of Talmon, the sons of Dacobi, the sons of Teta, the sons of Sami, in all an hundred thirty and nine." },
  { book: "1 Esdras", chapter: 5, verse: 29, text: "The servants of the temple: the sons of Esau, the sons of Asipha, the sons of Tabaoth, the sons of Ceras, the sons of Sud, the sons of Phaleas, the sons of Labana, the sons of Graba," },
  { book: "1 Esdras", chapter: 5, verse: 30, text: "The sons of Acua, the sons of Uta, the sons of Cetab, the sons of Agaba, the sons of Subai, the sons of Anan, the sons of Cathua, the sons of Geddur," },
  { book: "1 Esdras", chapter: 5, verse: 31, text: "The sons of Airus, the sons of Daisan, the sons of Noeba, the sons of Chaseba, the sons of Gazera, the sons of Azia, the sons of Phinees, the sons of Azare, the sons of Bastai, the sons of Asana, the sons of Meani, the sons of Naphisi, the sons of Acub, the sons of Acipha, the sons of Assur, the sons of Pharacim, the sons of Basaloth," },
  { book: "1 Esdras", chapter: 5, verse: 32, text: "The sons of Meeda, the sons of Coutha, the sons of Charea, the sons of Charcus, the sons of Aserer, the sons of Thomoi, the sons of Nasith, the sons of Atipha." },
  { book: "1 Esdras", chapter: 5, verse: 33, text: "The sons of the servants of Solomon: the sons of Azaphion, the sons of Pharira, the sons of Jeeli, the sons of Lozon, the sons of Israel, the sons of Sapheth," },
  { book: "1 Esdras", chapter: 5, verse: 34, text: "The sons of Hagia, the sons of Pharacareth, the sons of Sabi, the sons of Sarothie, the sons of Masias, the sons of Gar, the sons of Addus, the sons of Suba, the sons of Apherra, the sons of Barodis, the sons of Sabat, the sons of Allom." },
  { book: "1 Esdras", chapter: 5, verse: 35, text: "All the ministers of the temple, and the sons of the servants of Solomon, were three hundred seventy and two." },
  { book: "1 Esdras", chapter: 5, verse: 36, text: "These came up from Thermeleth and Thelersas, Charaathalar leading them, and Aalar;" },
  { book: "1 Esdras", chapter: 5, verse: 37, text: "Neither could they shew their families, nor their stock, how they were of Israel: the sons of Ladan, the son of Ban, the sons of Necodan, six hundred fifty and two." },
  { book: "1 Esdras", chapter: 5, verse: 38, text: "And of the priests that usurped the office of the priesthood, and were not found: the sons of Obdia, the sons of Accoz, the sons of Addus, who married Augia one of the daughters of Barzelus, and was named after his name." },
  { book: "1 Esdras", chapter: 5, verse: 39, text: "And when the description of the kindred of these men was sought in the register, and was not found, they were removed from executing the office of the priesthood:" },
  { book: "1 Esdras", chapter: 5, verse: 40, text: "For unto them said Nehemias and Atharias, that they should not be partakers of the holy things, till there arose up an high priest clothed with doctrine and truth." },
  { book: "1 Esdras", chapter: 5, verse: 41, text: "So of Israel, from them of twelve years old and upward, they were all in number forty thousand, beside menservants and womenservants two thousand three hundred and sixty." },
  { book: "1 Esdras", chapter: 5, verse: 42, text: "Their menservants and handmaids were seven thousand three hundred forty and seven: the singing men and singing women, two hundred forty and five:" },
  { book: "1 Esdras", chapter: 5, verse: 43, text: "Four hundred thirty and five camels, seven thousand thirty and six horses, two hundred forty and five mules, five thousand five hundred twenty and five beasts used to the yoke." },
  { book: "1 Esdras", chapter: 5, verse: 44, text: "And certain of the chief of their families, when they came to the temple of God that is in Jerusalem, vowed to set up the house again in his own place according to their ability," },
  { book: "1 Esdras", chapter: 5, verse: 45, text: "And to give into the holy treasury of the works a thousand pounds of gold, five thousand of silver, and an hundred priestly vestments." },
  { book: "1 Esdras", chapter: 5, verse: 46, text: "And so dwelt the priests and the Levites and the people in Jerusalem, and in the country, the singers also and the porters; and all Israel in their villages." },
  { book: "1 Esdras", chapter: 5, verse: 47, text: "But when the seventh month was at hand, and when the children of Israel were every man in his own place, they came all together with one consent into the open place of the first gate which is toward the east." },
  { book: "1 Esdras", chapter: 5, verse: 48, text: "Then stood up Jesus the son of Josedec, and his brethren the priests and Zorobabel the son of Salathiel, and his brethren, and made ready the altar of the God of Israel," },
  { book: "1 Esdras", chapter: 5, verse: 49, text: "To offer burnt sacrifices upon it, according as it is expressly commanded in the book of Moses the man of God." },
  { book: "1 Esdras", chapter: 5, verse: 50, text: "And there were gathered unto them out of the other nations of the land, and they erected the altar upon his own place, because all the nations of the land were at enmity with them, and oppressed them; and they offered sacrifices according to the time, and burnt offerings to the Lord both morning and evening." },
  { book: "1 Esdras", chapter: 5, verse: 51, text: "Also they held the feast of tabernacles, as it is commanded in the law, and offered sacrifices daily, as was meet:" },
  { book: "1 Esdras", chapter: 5, verse: 52, text: "And after that, the continual oblations, and the sacrifice of the sabbaths, and of the new moons, and of all holy feasts." },
  { book: "1 Esdras", chapter: 5, verse: 53, text: "And all they that had made any vow to God began to offer sacrifices to God from the first day of the seventh month, although the temple of the Lord was not yet built." },
  { book: "1 Esdras", chapter: 5, verse: 54, text: "And they gave unto the masons and carpenters money, meat, and drink, with cheerfulness." },
  { book: "1 Esdras", chapter: 5, verse: 55, text: "Unto them of Zidon also and Tyre they gave carrs, that they should bring cedar trees from Libanus, which should be brought by floats to the haven of Joppa, according as it was commanded them by Cyrus king of the Persians." },
  { book: "1 Esdras", chapter: 5, verse: 56, text: "And in the second year and second month after his coming to the temple of God at Jerusalem began Zorobabel the son of Salathiel, and Jesus the son of Josedec, and their brethren, and the priests, and the Levites, and all they that were come unto Jerusalem out of the captivity:" },
  { book: "1 Esdras", chapter: 5, verse: 57, text: "And they laid the foundation of the house of God in the first day of the second month, in the second year after they were come to Jewry and Jerusalem." },
  { book: "1 Esdras", chapter: 5, verse: 58, text: "And they appointed the Levites from twenty years old over the works of the Lord. Then stood up Jesus, and his sons and brethren, and Cadmiel his brother, and the sons of Madiabun, with the sons of Joda the son of Eliadun, with their sons and brethren, all Levites, with one accord setters forward of the business, labouring to advance the works in the house of God. So the workmen built the temple of the Lord." },
  { book: "1 Esdras", chapter: 5, verse: 59, text: "And the priests stood arrayed in their vestments with musical instruments and trumpets; and the Levites the sons of Asaph had cymbals," },
  { book: "1 Esdras", chapter: 5, verse: 60, text: "Singing songs of thanksgiving, and praising the Lord, according as David the king of Israel had ordained." },
  { book: "1 Esdras", chapter: 5, verse: 61, text: "And they sung with loud voices songs to the praise of the Lord, because his mercy and glory is for ever in all Israel." },
  { book: "1 Esdras", chapter: 5, verse: 62, text: "And all the people sounded trumpets, and shouted with a loud voice, singing songs of thanksgiving unto the Lord for the rearing up of the house of the Lord." },
  { book: "1 Esdras", chapter: 5, verse: 63, text: "Also of the priests and Levites, and of the chief of their families, the ancients who had seen the former house came to the building of this with weeping and great crying." },
  { book: "1 Esdras", chapter: 5, verse: 64, text: "But many with trumpets and joy shouted with loud voice," },
  { book: "1 Esdras", chapter: 5, verse: 65, text: "Insomuch that the trumpets might not be heard for the weeping of the people: yet the multitude sounded marvellously, so that it was heard afar off." },
  { book: "1 Esdras", chapter: 5, verse: 66, text: "Wherefore when the enemies of the tribe of Judah and Benjamin heard it, they came to know what that noise of trumpets should mean." },
  { book: "1 Esdras", chapter: 5, verse: 67, text: "And they perceived that they that were of the captivity did build the temple unto the Lord God of Israel." },
  { book: "1 Esdras", chapter: 5, verse: 68, text: "So they went to Zorobabel and Jesus, and to the chief of the families, and said unto them, We will build together with you." },
  { book: "1 Esdras", chapter: 5, verse: 69, text: "For we likewise, as ye, do obey your Lord, and do sacrifice unto him from the days of Azbazareth the king of the Assyrians, who brought us hither." },
  { book: "1 Esdras", chapter: 5, verse: 70, text: "Then Zorobabel and Jesus and the chief of the families of Israel said unto them, It is not for us and you to build together an house unto the Lord our God." },
  { book: "1 Esdras", chapter: 5, verse: 71, text: "We ourselves alone will build unto the Lord of Israel, according as Cyrus the king of the Persians hath commanded us." },
  { book: "1 Esdras", chapter: 5, verse: 72, text: "But the heathen of the land lying heavy upon the inhabitants of Judea, and holding them strait, hindered their building;" },
  { book: "1 Esdras", chapter: 5, verse: 73, text: "And by their secret plots, and popular persuasions and commotions, they hindered the finishing of the building all the time that king Cyrus lived: so they were hindered from building for the space of two years, until the reign of Darius." },
  { book: "1 Esdras", chapter: 6, verse: 1, text: "Now in the second year of the reign of Darius, Aggeus and Zacharias the son of Addo, the prophets, prophesied unto the Jews in Jewry and Jerusalem in the name of the Lord God of Israel, which was upon them." },
  { book: "1 Esdras", chapter: 6, verse: 2, text: "Then stood up Zorobabel the son of Salatiel, and Jesus the son of Josedec, and began to build the house of the Lord at Jerusalem, the prophets of the Lord being with them, and helping them." },
  { book: "1 Esdras", chapter: 6, verse: 3, text: "At the same time came unto them Sisinnes the governor of Syria and Phenice, with Sathrabuzanes and his companions, and said unto them," },
  { book: "1 Esdras", chapter: 6, verse: 4, text: "By whose appointment do ye build this house and this roof, and perform all the other things? and who are the workmen that perform these things?" },
  { book: "1 Esdras", chapter: 6, verse: 5, text: "Nevertheless the elders of the Jews obtained favour, because the Lord had visited the captivity;" },
  { book: "1 Esdras", chapter: 6, verse: 6, text: "And they were not hindered from building, until such time as signification was given unto Darius concerning them, and an answer received." },
  { book: "1 Esdras", chapter: 6, verse: 7, text: "The copy of the letters which Sisinnes, governor of Syria and Phenice, and Sathrabuzanes, with their companions, rulers in Syria and Phenice, wrote and sent unto Darius; To king Darius, greeting:" },
  { book: "1 Esdras", chapter: 6, verse: 8, text: "Let all things be known unto our lord the king, that being come into the country of Judea, and entered into the city of Jerusalem we found in the city of Jerusalem the ancients of the Jews that were of the captivity" },
  { book: "1 Esdras", chapter: 6, verse: 9, text: "Building an house unto the Lord, great and new, of hewn and costly stones, and the timber already laid upon the walls." },
  { book: "1 Esdras", chapter: 6, verse: 10, text: "And those works are done with great speed, and the work goeth on prosperously in their hands, and with all glory and diligence is it made." },
  { book: "1 Esdras", chapter: 6, verse: 11, text: "Then asked we these elders, saying, By whose commandment build ye this house, and lay the foundations of these works?" },
  { book: "1 Esdras", chapter: 6, verse: 12, text: "Therefore to the intent that we might give knowledge unto thee by writing, we demanded of them who were the chief doers, and we required of them the names in writing of their principal men." },
  { book: "1 Esdras", chapter: 6, verse: 13, text: "So they gave us this answer, We are the servants of the Lord which made heaven and earth." },
  { book: "1 Esdras", chapter: 6, verse: 14, text: "And as for this house, it was builded many years ago by a king of Israel great and strong, and was finished." },
  { book: "1 Esdras", chapter: 6, verse: 15, text: "But when our fathers provoked God unto wrath, and sinned against the Lord of Israel which is in heaven, he gave them over into the power of Nabuchodonosor king of Babylon, of the Chaldees;" },
  { book: "1 Esdras", chapter: 6, verse: 16, text: "Who pulled down the house, and burned it, and carried away the people captives unto Babylon." },
  { book: "1 Esdras", chapter: 6, verse: 17, text: "But in the first year that king Cyrus reigned over the country of Babylon, Cyrus the king wrote to build up this house." },
  { book: "1 Esdras", chapter: 6, verse: 18, text: "And the holy vessels of gold and of silver, that Nabuchodonosor had carried away out of the house at Jerusalem, and had set them in his own temple those Cyrus the king brought forth again out of the temple at Babylon, and they were delivered to Zorobabel and to Sanabassarus the ruler," },
  { book: "1 Esdras", chapter: 6, verse: 19, text: "With commandment that he should carry away the same vessels, and put them in the temple at Jerusalem; and that the temple of the Lord should be built in his place." },
  { book: "1 Esdras", chapter: 6, verse: 20, text: "Then the same Sanabassarus, being come hither, laid the foundations of the house of the Lord at Jerusalem; and from that time to this being still a building, it is not yet fully ended." },
  { book: "1 Esdras", chapter: 6, verse: 21, text: "Now therefore, if it seem good unto the king, let search be made among the records of king Cyrus:" },
  { book: "1 Esdras", chapter: 6, verse: 22, text: "And if it be found that the building of the house of the Lord at Jerusalem hath been done with the consent of king Cyrus, and if our lord the king be so minded, let him signify unto us thereof." },
  { book: "1 Esdras", chapter: 6, verse: 23, text: "Then commanded king Darius to seek among the records at Babylon: and so at Ecbatane the palace, which is in the country of Media, there was found a roll wherein these things were recorded." },
  { book: "1 Esdras", chapter: 6, verse: 24, text: "In the first year of the reign of Cyrus king Cyrus commanded that the house of the Lord at Jerusalem should be built again, where they do sacrifice with continual fire:" },
  { book: "1 Esdras", chapter: 6, verse: 25, text: "Whose height shall be sixty cubits and the breadth sixty cubits, with three rows of hewn stones, and one row of new wood of that country; and the expences thereof to be given out of the house of king Cyrus:" },
  { book: "1 Esdras", chapter: 6, verse: 26, text: "And that the holy vessels of the house of the Lord, both of gold and silver, that Nabuchodonosor took out of the house at Jerusalem, and brought to Babylon, should be restored to the house at Jerusalem, and be set in the place where they were before." },
  { book: "1 Esdras", chapter: 6, verse: 27, text: "And also he commanded that Sisinnes the governor of Syria and Phenice, and Sathrabuzanes, and their companions, and those which were appointed rulers in Syria and Phenice, should be careful not to meddle with the place, but suffer Zorobabel, the servant of the Lord, and governor of Judea, and the elders of the Jews, to build the house of the Lord in that place." },
  { book: "1 Esdras", chapter: 6, verse: 28, text: "I have commanded also to have it built up whole again; and that they look diligently to help those that be of the captivity of the Jews, till the house of the Lord be finished:" },
  { book: "1 Esdras", chapter: 6, verse: 29, text: "And out of the tribute of Celosyria and Phenice a portion carefully to be given these men for the sacrifices of the Lord, that is, to Zorobabel the governor, for bullocks, and rams, and lambs;" },
  { book: "1 Esdras", chapter: 6, verse: 30, text: "And also corn, salt, wine, and oil, and that continually every year without further question, according as the priests that be in Jerusalem shall signify to be daily spent:" },
  { book: "1 Esdras", chapter: 6, verse: 31, text: "That offerings may be made to the most high God for the king and for his children, and that they may pray for their lives." },
  { book: "1 Esdras", chapter: 6, verse: 32, text: "And he commanded that whosoever should transgress, yea, or make light of any thing afore spoken or written, out of his own house should a tree be taken, and he thereon be hanged, and all his goods seized for the king." },
  { book: "1 Esdras", chapter: 6, verse: 33, text: "The Lord therefore, whose name is there called upon, utterly destroy every king and nation, that stretcheth out his hand to hinder or endamage that house of the Lord in Jerusalem." },
  { book: "1 Esdras", chapter: 6, verse: 34, text: "I Darius the king have ordained that according unto these things it be done with diligence." },
  { book: "1 Esdras", chapter: 7, verse: 1, text: "Then Sisinnes the governor of Celosyria and Phenice, and Sathrabuzanes, with their companions following the commandments of king Darius," },
  { book: "1 Esdras", chapter: 7, verse: 2, text: "Did very carefully oversee the holy works, assisting the ancients of the Jews and governors of the temple." },
  { book: "1 Esdras", chapter: 7, verse: 3, text: "And so the holy works prospered, when Aggeus and Zacharias the prophets prophesied." },
  { book: "1 Esdras", chapter: 7, verse: 4, text: "And they finished these things by the commandment of the Lord God of Israel, and with the consent of Cyrus, Darius, and Artexerxes, kings of Persia." },
  { book: "1 Esdras", chapter: 7, verse: 5, text: "And thus was the holy house finished in the three and twentieth day of the month Adar, in the sixth year of Darius king of the Persians" },
  { book: "1 Esdras", chapter: 7, verse: 6, text: "And the children of Israel, the priests, and the Levites, and others that were of the captivity, that were added unto them, did according to the things written in the book of Moses." },
  { book: "1 Esdras", chapter: 7, verse: 7, text: "And to the dedication of the temple of the Lord they offered an hundred bullocks two hundred rams, four hundred lambs;" },
  { book: "1 Esdras", chapter: 7, verse: 8, text: "And twelve goats for the sin of all Israel, according to the number of the chief of the tribes of Israel." },
  { book: "1 Esdras", chapter: 7, verse: 9, text: "The priests also and the Levites stood arrayed in their vestments, according to their kindreds, in the service of the Lord God of Israel, according to the book of Moses: and the porters at every gate." },
  { book: "1 Esdras", chapter: 7, verse: 10, text: "And the children of Israel that were of the captivity held the passover the fourteenth day of the first month, after that the priests and the Levites were sanctified." },
  { book: "1 Esdras", chapter: 7, verse: 11, text: "They that were of the captivity were not all sanctified together: but the Levites were all sanctified together." },
  { book: "1 Esdras", chapter: 7, verse: 12, text: "And so they offered the passover for all them of the captivity, and for their brethren the priests, and for themselves." },
  { book: "1 Esdras", chapter: 7, verse: 13, text: "And the children of Israel that came out of the captivity did eat, even all they that had separated themselves from the abominations of the people of the land, and sought the Lord." },
  { book: "1 Esdras", chapter: 7, verse: 14, text: "And they kept the feast of unleavened bread seven days, making merry before the Lord," },
  { book: "1 Esdras", chapter: 7, verse: 15, text: "For that he had turned the counsel of the king of Assyria toward them, to strengthen their hands in the works of the Lord God of Israel." },
  { book: "1 Esdras", chapter: 8, verse: 1, text: "And after these things, when Artexerxes the king of the Persians reigned came Esdras the son of Saraias, the son of Ezerias, the son of Helchiah, the son of Salum," },
  { book: "1 Esdras", chapter: 8, verse: 2, text: "The son of Sadduc, the son of Achitob, the son of Amarias, the son of Ezias, the son of Meremoth, the son of Zaraias, the son of Savias, the son of Boccas, the son of Abisum, the son of Phinees, the son of Eleazar, the son of Aaron the chief priest." },
  { book: "1 Esdras", chapter: 8, verse: 3, text: "This Esdras went up from Babylon, as a scribe, being very ready in the law of Moses, that was given by the God of Israel." },
  { book: "1 Esdras", chapter: 8, verse: 4, text: "And the king did him honour: for he found grace in his sight in all his requests." },
  { book: "1 Esdras", chapter: 8, verse: 5, text: "There went up with him also certain of the children of Israel, of the priest of the Levites, of the holy singers, porters, and ministers of the temple, unto Jerusalem," },
  { book: "1 Esdras", chapter: 8, verse: 6, text: "In the seventh year of the reign of Artexerxes, in the fifth month, this was the king’s seventh year; for they went from Babylon in the first day of the first month, and came to Jerusalem, according to the prosperous journey which the Lord gave them." },
  { book: "1 Esdras", chapter: 8, verse: 7, text: "For Esdras had very great skill, so that he omitted nothing of the law and commandments of the Lord, but taught all Israel the ordinances and judgments." },
  { book: "1 Esdras", chapter: 8, verse: 8, text: "Now the copy of the commission, which was written from Artexerxes the king, and came to Esdras the priest and reader of the law of the Lord, is this that followeth;" },
  { book: "1 Esdras", chapter: 8, verse: 9, text: "King Artexerxes unto Esdras the priest and reader of the law of the Lord sendeth greeting:" },
  { book: "1 Esdras", chapter: 8, verse: 10, text: "Having determined to deal graciously, I have given order, that such of the nation of the Jews, and of the priests and Levites being within our realm, as are willing and desirous should go with thee unto Jerusalem." },
  { book: "1 Esdras", chapter: 8, verse: 11, text: "As many therefore as have a mind thereunto, let them depart with thee, as it hath seemed good both to me and my seven friends the counsellors;" },
  { book: "1 Esdras", chapter: 8, verse: 12, text: "That they may look unto the affairs of Judea and Jerusalem, agreeably to that which is in the law of the Lord;" },
  { book: "1 Esdras", chapter: 8, verse: 13, text: "And carry the gifts unto the Lord of Israel to Jerusalem, which I and my friends have vowed, and all the gold and silver that in the country of Babylon can be found, to the Lord in Jerusalem," },
  { book: "1 Esdras", chapter: 8, verse: 14, text: "With that also which is given of the people for the temple of the Lord their God at Jerusalem: and that silver and gold may be collected for bullocks, rams, and lambs, and things thereunto appertaining;" },
  { book: "1 Esdras", chapter: 8, verse: 15, text: "To the end that they may offer sacrifices unto the Lord upon the altar of the Lord their God, which is in Jerusalem." },
  { book: "1 Esdras", chapter: 8, verse: 16, text: "And whatsoever thou and thy brethren will do with the silver and gold, that do, according to the will of thy God." },
  { book: "1 Esdras", chapter: 8, verse: 17, text: "And the holy vessels of the Lord, which are given thee for the use of the temple of thy God, which is in Jerusalem, thou shalt set before thy God in Jerusalem." },
  { book: "1 Esdras", chapter: 8, verse: 18, text: "And whatsoever thing else thou shalt remember for the use of the temple of thy God, thou shalt give it out of the king’s treasury." },
  { book: "1 Esdras", chapter: 8, verse: 19, text: "And I king Artexerxes have also commanded the keepers of the treasures in Syria and Phenice, that whatsoever Esdras the priest and the reader of the law of the most high God shall send for, they should give it him with speed," },
  { book: "1 Esdras", chapter: 8, verse: 20, text: "To the sum of an hundred talents of silver, likewise also of wheat even to an hundred cors, and an hundred pieces of wine, and other things in abundance." },
  { book: "1 Esdras", chapter: 8, verse: 21, text: "Let all things be performed after the law of God diligently unto the most high God, that wrath come not upon the kingdom of the king and his sons." },
  { book: "1 Esdras", chapter: 8, verse: 22, text: "I command you also, that ye require no tax, nor any other imposition, of any of the priests, or Levites, or holy singers, or porters, or ministers of the temple, or of any that have doings in this temple, and that no man have authority to impose any thing upon them." },
  { book: "1 Esdras", chapter: 8, verse: 23, text: "And thou, Esdras, according to the wisdom of God ordain judges and justices, that they may judge in all Syria and Phenice all those that know the law of thy God; and those that know it not thou shalt teach." },
  { book: "1 Esdras", chapter: 8, verse: 24, text: "And whosoever shall transgress the law of thy God, and of the king, shall be punished diligently, whether it be by death, or other punishment, by penalty of money, or by imprisonment." },
  { book: "1 Esdras", chapter: 8, verse: 25, text: "Then said Esdras the scribe, Blessed be the only Lord God of my fathers, who hath put these things into the heart of the king, to glorify his house that is in Jerusalem:" },
  { book: "1 Esdras", chapter: 8, verse: 26, text: "And hath honoured me in the sight of the king, and his counsellors, and all his friends and nobles." },
  { book: "1 Esdras", chapter: 8, verse: 27, text: "Therefore was I encouraged by the help of the Lord my God, and gathered together men of Israel to go up with me." },
  { book: "1 Esdras", chapter: 8, verse: 28, text: "And these are the chief according to their families and several dignities, that went up with me from Babylon in the reign of king Artexerxes:" },
  { book: "1 Esdras", chapter: 8, verse: 29, text: "Of the sons of Phinees, Gerson: of the sons of Ithamar, Gamael: of the sons of David, Lettus the son of Sechenias:" },
  { book: "1 Esdras", chapter: 8, verse: 30, text: "Of the sons of Pharez, Zacharias; and with him were counted an hundred and fifty men:" },
  { book: "1 Esdras", chapter: 8, verse: 31, text: "Of the sons of Pahath Moab, Eliaonias, the son of Zaraias, and with him two hundred men:" },
  { book: "1 Esdras", chapter: 8, verse: 32, text: "Of the sons of Zathoe, Sechenias the son of Jezelus, and with him three hundred men: of the sons of Adin, Obeth the son of Jonathan, and with him two hundred and fifty men:" },
  { book: "1 Esdras", chapter: 8, verse: 33, text: "Of the sons of Elam, Josias son of Gotholias, and with him seventy men:" },
  { book: "1 Esdras", chapter: 8, verse: 34, text: "Of the sons of Saphatias, Zaraias son of Michael, and with him threescore and ten men:" },
  { book: "1 Esdras", chapter: 8, verse: 35, text: "Of the sons of Joab, Abadias son of Jezelus, and with him two hundred and twelve men:" },
  { book: "1 Esdras", chapter: 8, verse: 36, text: "Of the sons of Banid, Assalimoth son of Josaphias, and with him an hundred and threescore men:" },
  { book: "1 Esdras", chapter: 8, verse: 37, text: "Of the sons of Babi, Zacharias son of Bebai, and with him twenty and eight men:" },
  { book: "1 Esdras", chapter: 8, verse: 38, text: "Of the sons of Astath, Johannes son of Acatan, and with him an hundred and ten men:" },
  { book: "1 Esdras", chapter: 8, verse: 39, text: "Of the sons of Adonikam the last, and these are the names of them, Eliphalet, Jewel, and Samaias, and with them seventy men:" },
  { book: "1 Esdras", chapter: 8, verse: 40, text: "Of the sons of Bago, Uthi the son of Istalcurus, and with him seventy men." },
  { book: "1 Esdras", chapter: 8, verse: 41, text: "And these I gathered together to the river called Theras, where we pitched our tents three days: and then I surveyed them." },
  { book: "1 Esdras", chapter: 8, verse: 42, text: "But when I had found there none of the priests and Levites," },
  { book: "1 Esdras", chapter: 8, verse: 43, text: "Then sent I unto Eleazar, and Iduel, and Masman," },
  { book: "1 Esdras", chapter: 8, verse: 44, text: "And Alnathan, and Mamaias, and Joribas, and Nathan, Eunatan, Zacharias, and Mosollamon, principal men and learned." },
  { book: "1 Esdras", chapter: 8, verse: 45, text: "And I bade them that they should go unto Saddeus the captain, who was in the place of the treasury:" },
  { book: "1 Esdras", chapter: 8, verse: 46, text: "And commanded them that they should speak unto Daddeus, and to his brethren, and to the treasurers in that place, to send us such men as might execute the priests’ office in the house of the Lord." },
  { book: "1 Esdras", chapter: 8, verse: 47, text: "And by the mighty hand of our Lord they brought unto us skilful men of the sons of Moli the son of Levi, the son of Israel, Asebebia, and his sons, and his brethren, who were eighteen." },
  { book: "1 Esdras", chapter: 8, verse: 48, text: "And Asebia, and Annus, and Osaias his brother, of the sons of Channuneus, and their sons, were twenty men." },
  { book: "1 Esdras", chapter: 8, verse: 49, text: "And of the servants of the temple whom David had ordained, and the principal men for the service of the Levites to wit, the servants of the temple two hundred and twenty, the catalogue of whose names were shewed." },
  { book: "1 Esdras", chapter: 8, verse: 50, text: "And there I vowed a fast unto the young men before our Lord, to desire of him a prosperous journey both for us and them that were with us, for our children, and for the cattle:" },
  { book: "1 Esdras", chapter: 8, verse: 51, text: "For I was ashamed to ask the king footmen, and horsemen, and conduct for safeguard against our adversaries." },
  { book: "1 Esdras", chapter: 8, verse: 52, text: "For we had said unto the king, that the power of the Lord our God should be with them that seek him, to support them in all ways." },
  { book: "1 Esdras", chapter: 8, verse: 53, text: "And again we besought our Lord as touching these things, and found him favourable unto us." },
  { book: "1 Esdras", chapter: 8, verse: 54, text: "Then I separated twelve of the chief of the priests, Esebrias, and Assanias, and ten men of their brethren with them:" },
  { book: "1 Esdras", chapter: 8, verse: 55, text: "And I weighed them the gold, and the silver, and the holy vessels of the house of our Lord, which the king, and his council, and the princes, and all Israel, had given." },
  { book: "1 Esdras", chapter: 8, verse: 56, text: "And when I had weighed it, I delivered unto them six hundred and fifty talents of silver, and silver vessels of an hundred talents, and an hundred talents of gold," },
  { book: "1 Esdras", chapter: 8, verse: 57, text: "And twenty golden vessels, and twelve vessels of brass, even of fine brass, glittering like gold." },
  { book: "1 Esdras", chapter: 8, verse: 58, text: "And I said unto them, Both ye are holy unto the Lord, and the vessels are holy, and the gold and the silver is a vow unto the Lord, the Lord of our fathers." },
  { book: "1 Esdras", chapter: 8, verse: 59, text: "Watch ye, and keep them till ye deliver them to the chief of the priests and Levites, and to the principal men of the families of Israel, in Jerusalem, into the chambers of the house of our God." },
  { book: "1 Esdras", chapter: 8, verse: 60, text: "So the priests and the Levites, who had received the silver and the gold and the vessels, brought them unto Jerusalem, into the temple of the Lord." },
  { book: "1 Esdras", chapter: 8, verse: 61, text: "And from the river Theras we departed the twelfth day of the first month, and came to Jerusalem by the mighty hand of our Lord, which was with us: and from the beginning of our journey the Lord delivered us from every enemy, and so we came to Jerusalem." },
  { book: "1 Esdras", chapter: 8, verse: 62, text: "And when we had been there three days, the gold and silver that was weighed was delivered in the house of our Lord on the fourth day unto Marmoth the priest the son of Iri." },
  { book: "1 Esdras", chapter: 8, verse: 63, text: "And with him was Eleazar the son of Phinees, and with them were Josabad the son of Jesu and Moeth the son of Sabban, Levites: all was delivered them by number and weight." },
  { book: "1 Esdras", chapter: 8, verse: 64, text: "And all the weight of them was written up the same hour." },
  { book: "1 Esdras", chapter: 8, verse: 65, text: "Moreover they that were come out of the captivity offered sacrifice unto the Lord God of Israel, even twelve bullocks for all Israel, fourscore and sixteen rams," },
  { book: "1 Esdras", chapter: 8, verse: 66, text: "Threescore and twelve lambs, goats for a peace offering, twelve; all of them a sacrifice to the Lord." },
  { book: "1 Esdras", chapter: 8, verse: 67, text: "And they delivered the king’s commandments unto the king’s stewards’ and to the governors of Celosyria and Phenice; and they honoured the people and the temple of God." },
  { book: "1 Esdras", chapter: 8, verse: 68, text: "Now when these things were done, the rulers came unto me, and said," },
  { book: "1 Esdras", chapter: 8, verse: 69, text: "The nation of Israel, the princes, the priests and Levites, have not put away from them the strange people of the land, nor the pollutions of the Gentiles to wit, of the Canaanites, Hittites, Pheresites, Jebusites, and the Moabites, Egyptians, and Edomites." },
  { book: "1 Esdras", chapter: 8, verse: 70, text: "For both they and their sons have married with their daughters, and the holy seed is mixed with the strange people of the land; and from the beginning of this matter the rulers and the great men have been partakers of this iniquity." },
  { book: "1 Esdras", chapter: 8, verse: 71, text: "And as soon as I had heard these things, I rent my clothes, and the holy garment, and pulled off the hair from off my head and beard, and sat me down sad and very heavy." },
  { book: "1 Esdras", chapter: 8, verse: 72, text: "So all they that were then moved at the word of the Lord God of Israel assembled unto me, whilst I mourned for the iniquity: but I sat still full of heaviness until the evening sacrifice." },
  { book: "1 Esdras", chapter: 8, verse: 73, text: "Then rising up from the fast with my clothes and the holy garment rent, and bowing my knees, and stretching forth my hands unto the Lord," },
  { book: "1 Esdras", chapter: 8, verse: 74, text: "I said, O Lord, I am confounded and ashamed before thy face;" },
  { book: "1 Esdras", chapter: 8, verse: 75, text: "For our sins are multiplied above our heads, and our ignorances have reached up unto heaven." },
  { book: "1 Esdras", chapter: 8, verse: 76, text: "For ever since the time of our fathers we have been and are in great sin, even unto this day." },
  { book: "1 Esdras", chapter: 8, verse: 77, text: "And for our sins and our fathers’ we with our brethren and our kings and our priests were given up unto the kings of the earth, to the sword, and to captivity, and for a prey with shame, unto this day." },
  { book: "1 Esdras", chapter: 8, verse: 78, text: "And now in some measure hath mercy been shewed unto us from thee, O Lord, that there should be left us a root and a name in the place of thy sanctuary;" },
  { book: "1 Esdras", chapter: 8, verse: 79, text: "And to discover unto us a light in the house of the Lord our God, and to give us food in the time of our servitude." },
  { book: "1 Esdras", chapter: 8, verse: 80, text: "Yea, when we were in bondage, we were not forsaken of our Lord; but he made us gracious before the kings of Persia, so that they gave us food;" },
  { book: "1 Esdras", chapter: 8, verse: 81, text: "Yea, and honoured the temple of our Lord, and raised up the desolate Sion, that they have given us a sure abiding in Jewry and Jerusalem." },
  { book: "1 Esdras", chapter: 8, verse: 82, text: "And now, O Lord, what shall we say, having these things? for we have transgressed thy commandments, which thou gavest by the hand of thy servants the prophets, saying," },
  { book: "1 Esdras", chapter: 8, verse: 83, text: "That the land, which ye enter into to possess as an heritage, is a land polluted with the pollutions of the strangers of the land, and they have filled it with their uncleanness." },
  { book: "1 Esdras", chapter: 8, verse: 84, text: "Therefore now shall ye not join your daughters unto their sons, neither shall ye take their daughters unto your sons." },
  { book: "1 Esdras", chapter: 8, verse: 85, text: "Moreover ye shall never seek to have peace with them, that ye may be strong, and eat the good things of the land, and that ye may leave the inheritance of the land unto your children for evermore." },
  { book: "1 Esdras", chapter: 8, verse: 86, text: "And all that is befallen is done unto us for our wicked works and great sins; for thou, O Lord, didst make our sins light," },
  { book: "1 Esdras", chapter: 8, verse: 87, text: "And didst give unto us such a root: but we have turned back again to transgress thy law, and to mingle ourselves with the uncleanness of the nations of the land." },
  { book: "1 Esdras", chapter: 8, verse: 88, text: "Mightest not thou be angry with us to destroy us, till thou hadst left us neither root, seed, nor name?" },
  { book: "1 Esdras", chapter: 8, verse: 89, text: "O Lord of Israel, thou art true: for we are left a root this day." },
  { book: "1 Esdras", chapter: 8, verse: 90, text: "Behold, now are we before thee in our iniquities, for we cannot stand any longer by reason of these things before thee." },
  { book: "1 Esdras", chapter: 8, verse: 91, text: "And as Esdras in his prayer made his confession, weeping, and lying flat upon the ground before the temple, there gathered unto him from Jerusalem a very great multitude of men and women and children: for there was great weeping among the multitude." },
  { book: "1 Esdras", chapter: 8, verse: 92, text: "Then Jechonias the son of Jeelus, one of the sons of Israel, called out, and said, O Esdras, we have sinned against the Lord God, we have married strange women of the nations of the land, and now is all Israel aloft." },
  { book: "1 Esdras", chapter: 8, verse: 93, text: "Let us make an oath to the Lord, that we will put away all our wives, which we have taken of the heathen, with their children," },
  { book: "1 Esdras", chapter: 8, verse: 94, text: "Like as thou hast decreed, and as many as do obey the law of the Lord." },
  { book: "1 Esdras", chapter: 8, verse: 95, text: "Arise and put in execution: for to thee doth this matter appertain, and we will be with thee: do valiantly." },
  { book: "1 Esdras", chapter: 8, verse: 96, text: "So Esdras arose, and took an oath of the chief of the priests and Levites of all Israel to do after these things; and so they sware." },
  { book: "1 Esdras", chapter: 9, verse: 1, text: "Then Esdras rising from the court of the temple went to the chamber of Joanan the son of Eliasib," },
  { book: "1 Esdras", chapter: 9, verse: 2, text: "And remained there, and did eat no meat nor drink water, mourning for the great iniquities of the multitude." },
  { book: "1 Esdras", chapter: 9, verse: 3, text: "And there was a proclamation in all Jewry and Jerusalem to all them that were of the captivity, that they should be gathered together at Jerusalem:" },
  { book: "1 Esdras", chapter: 9, verse: 4, text: "And that whosoever met not there within two or three days according as the elders that bare rule appointed, their cattle should be seized to the use of the temple, and himself cast out from them that were of the captivity." },
  { book: "1 Esdras", chapter: 9, verse: 5, text: "And in three days were all they of the tribe of Judah and Benjamin gathered together at Jerusalem the twentieth day of the ninth month." },
  { book: "1 Esdras", chapter: 9, verse: 6, text: "And all the multitude sat trembling in the broad court of the temple because of the present foul weather." },
  { book: "1 Esdras", chapter: 9, verse: 7, text: "So Esdras arose up, and said unto them, Ye have transgressed the law in marrying strange wives, thereby to increase the sins of Israel." },
  { book: "1 Esdras", chapter: 9, verse: 8, text: "And now by confessing give glory unto the Lord God of our fathers," },
  { book: "1 Esdras", chapter: 9, verse: 9, text: "And do his will, and separate yourselves from the heathen of the land, and from the strange women." },
  { book: "1 Esdras", chapter: 9, verse: 10, text: "Then cried the whole multitude, and said with a loud voice, Like as thou hast spoken, so will we do." },
  { book: "1 Esdras", chapter: 9, verse: 11, text: "But forasmuch as the people are many, and it is foul weather, so that we cannot stand without, and this is not a work of a day or two, seeing our sin in these things is spread far:" },
  { book: "1 Esdras", chapter: 9, verse: 12, text: "Therefore let the rulers of the multitude stay, and let all them of our habitations that have strange wives come at the time appointed," },
  { book: "1 Esdras", chapter: 9, verse: 13, text: "And with them the rulers and judges of every place, till we turn away the wrath of the Lord from us for this matter." },
  { book: "1 Esdras", chapter: 9, verse: 14, text: "Then Jonathan the son of Azael and Ezechias the son of Theocanus accordingly took this matter upon them: and Mosollam and Levis and Sabbatheus helped them." },
  { book: "1 Esdras", chapter: 9, verse: 15, text: "And they that were of the captivity did according to all these things." },
  { book: "1 Esdras", chapter: 9, verse: 16, text: "And Esdras the priest chose unto him the principal men of their families, all by name: and in the first day of the tenth month they sat together to examine the matter." },
  { book: "1 Esdras", chapter: 9, verse: 17, text: "So their cause that held strange wives was brought to an end in the first day of the first month." },
  { book: "1 Esdras", chapter: 9, verse: 18, text: "And of the priests that were come together, and had strange wives, there were found:" },
  { book: "1 Esdras", chapter: 9, verse: 19, text: "Of the sons of Jesus the son of Josedec, and his brethren; Matthelas and Eleazar, and Joribus and Joadanus." },
  { book: "1 Esdras", chapter: 9, verse: 20, text: "And they gave their hands to put away their wives and to offer rams to make reconcilement for their errors." },
  { book: "1 Esdras", chapter: 9, verse: 21, text: "And of the sons of Emmer; Ananias, and Zabdeus, and Eanes, and Sameius, and Hiereel, and Azarias." },
  { book: "1 Esdras", chapter: 9, verse: 22, text: "And of the sons of Phaisur; Elionas, Massias Israel, and Nathanael, and Ocidelus and Talsas." },
  { book: "1 Esdras", chapter: 9, verse: 23, text: "And of the Levites; Jozabad, and Semis, and Colius, who was called Calitas, and Patheus, and Judas, and Jonas." },
  { book: "1 Esdras", chapter: 9, verse: 24, text: "Of the holy singers; Eleazurus, Bacchurus." },
  { book: "1 Esdras", chapter: 9, verse: 25, text: "Of the porters; Sallumus, and Tolbanes." },
  { book: "1 Esdras", chapter: 9, verse: 26, text: "Of them of Israel, of the sons of Phoros; Hiermas, and Eddias, and Melchias, and Maelus, and Eleazar, and Asibias, and Baanias." },
  { book: "1 Esdras", chapter: 9, verse: 27, text: "Of the sons of Ela; Matthanias, Zacharias, and Hierielus, and Hieremoth, and Aedias." },
  { book: "1 Esdras", chapter: 9, verse: 28, text: "And of the sons of Zamoth; Eliadas, Elisimus, Othonias, Jarimoth, and Sabatus, and Sardeus." },
  { book: "1 Esdras", chapter: 9, verse: 29, text: "Of the sons of Babai; Johannes, and Ananias and Josabad, and Amatheis." },
  { book: "1 Esdras", chapter: 9, verse: 30, text: "Of the sons of Mani; Olamus, Mamuchus, Jedeus, Jasubus, Jasael, and Hieremoth." },
  { book: "1 Esdras", chapter: 9, verse: 31, text: "And of the sons of Addi; Naathus, and Moosias, Lacunus, and Naidus, and Mathanias, and Sesthel, Balnuus, and Manasseas." },
  { book: "1 Esdras", chapter: 9, verse: 32, text: "And of the sons of Annas; Elionas and Aseas, and Melchias, and Sabbeus, and Simon Chosameus." },
  { book: "1 Esdras", chapter: 9, verse: 33, text: "And of the sons of Asom; Altaneus, and Matthias, and Baanaia, Eliphalet, and Manasses, and Semei." },
  { book: "1 Esdras", chapter: 9, verse: 34, text: "And of the sons of Maani; Jeremias, Momdis, Omaerus, Juel, Mabdai, and Pelias, and Anos, Carabasion, and Enasibus, and Mamnitanaimus, Eliasis, Bannus, Eliali, Samis, Selemias, Nathanias: and of the sons of Ozora; Sesis, Esril, Azaelus, Samatus, Zambis, Josephus." },
  { book: "1 Esdras", chapter: 9, verse: 35, text: "And of the sons of Ethma; Mazitias, Zabadaias, Edes, Juel, Banaias." },
  { book: "1 Esdras", chapter: 9, verse: 36, text: "All these had taken strange wives, and they put them away with their children." },
  { book: "1 Esdras", chapter: 9, verse: 37, text: "And the priests and Levites, and they that were of Israel, dwelt in Jerusalem, and in the country, in the first day of the seventh month: so the children of Israel were in their habitations." },
  { book: "1 Esdras", chapter: 9, verse: 38, text: "And the whole multitude came together with one accord into the broad place of the holy porch toward the east:" },
  { book: "1 Esdras", chapter: 9, verse: 39, text: "And they spake unto Esdras the priest and reader, that he would bring the law of Moses, that was given of the Lord God of Israel." },
  { book: "1 Esdras", chapter: 9, verse: 40, text: "So Esdras the chief priest brought the law unto the whole multitude from man to woman, and to all the priests, to hear law in the first day of the seventh month." },
  { book: "1 Esdras", chapter: 9, verse: 41, text: "And he read in the broad court before the holy porch from morning unto midday, before both men and women; and the multitude gave heed unto the law." },
  { book: "1 Esdras", chapter: 9, verse: 42, text: "And Esdras the priest and reader of the law stood up upon a pulpit of wood, which was made for that purpose." },
  { book: "1 Esdras", chapter: 9, verse: 43, text: "And there stood up by him Mattathias, Sammus, Ananias, Azarias, Urias, Ezecias, Balasamus, upon the right hand:" },
  { book: "1 Esdras", chapter: 9, verse: 44, text: "And upon his left hand stood Phaldaius, Misael, Melchias, Lothasubus, and Nabarias." },
  { book: "1 Esdras", chapter: 9, verse: 45, text: "Then took Esdras the book of the law before the multitude: for he sat honourably in the first place in the sight of them all." },
  { book: "1 Esdras", chapter: 9, verse: 46, text: "And when he opened the law, they stood all straight up. So Esdras blessed the Lord God most High, the God of hosts, Almighty." },
  { book: "1 Esdras", chapter: 9, verse: 47, text: "And all the people answered, Amen; and lifting up their hands they fell to the ground, and worshipped the Lord." },
  { book: "1 Esdras", chapter: 9, verse: 48, text: "Also Jesus, Anus, Sarabias, Adinus, Jacubus, Sabateas, Auteas, Maianeas, and Calitas, Asrias, and Joazabdus, and Ananias, Biatas, the Levites, taught the law of the Lord, making them withal to understand it." },
  { book: "1 Esdras", chapter: 9, verse: 49, text: "Then spake Attharates unto Esdras the chief priest. and reader, and to the Levites that taught the multitude, even to all, saying," },
  { book: "1 Esdras", chapter: 9, verse: 50, text: "This day is holy unto the Lord; (for they all wept when they heard the law:)" },
  { book: "1 Esdras", chapter: 9, verse: 51, text: "Go then, and eat the fat, and drink the sweet, and send part to them that have nothing;" },
  { book: "1 Esdras", chapter: 9, verse: 52, text: "For this day is holy unto the Lord: and be not sorrowful; for the Lord will bring you to honour." },
  { book: "1 Esdras", chapter: 9, verse: 53, text: "So the Levites published all things to the people, saying, This day is holy to the Lord; be not sorrowful." },
  { book: "1 Esdras", chapter: 9, verse: 54, text: "Then went they their way, every one to eat and drink, and make merry, and to give part to them that had nothing, and to make great cheer;" },
  { book: "1 Esdras", chapter: 9, verse: 55, text: "Because they understood the words wherein they were instructed, and for the which they had been assembled." },
  // 1 Maccabees (924 verses)
  { book: "1 Maccabees", chapter: 1, verse: 1, text: "And it happened, after that Alexander son of Philip, the Macedonian, who came out of the land of Chettiim, had smitten Darius king of the Persians and Medes, that he reigned in his stead, the first over Greece," },
  { book: "1 Maccabees", chapter: 1, verse: 2, text: "And made many wars, and won many strong holds, and slew the kings of the earth," },
  { book: "1 Maccabees", chapter: 1, verse: 3, text: "And went through to the ends of the earth, and took spoils of many nations, insomuch that the earth was quiet before him; whereupon he was exalted and his heart was lifted up." },
  { book: "1 Maccabees", chapter: 1, verse: 4, text: "And he gathered a mighty strong host and ruled over countries, and nations, and kings, who became tributaries unto him." },
  { book: "1 Maccabees", chapter: 1, verse: 5, text: "And after these things he fell sick, and perceived that he should die." },
  { book: "1 Maccabees", chapter: 1, verse: 6, text: "Wherefore he called his servants, such as were honourable, and had been brought up with him from his youth, and parted his kingdom among them, while he was yet alive." },
  { book: "1 Maccabees", chapter: 1, verse: 7, text: "So Alexander reigned twelves years, and then died." },
  { book: "1 Maccabees", chapter: 1, verse: 8, text: "And his servants bare rule every one in his place." },
  { book: "1 Maccabees", chapter: 1, verse: 9, text: "And after his death they all put crowns upon themselves; so did their sons after them many years: and evils were multiplied in the earth." },
  { book: "1 Maccabees", chapter: 1, verse: 10, text: "And there came out of them a wicked root Antiochus surnamed Epiphanes, son of Antiochus the king, who had been an hostage at Rome, and he reigned in the hundred and thirty and seventh year of the kingdom of the Greeks." },
  { book: "1 Maccabees", chapter: 1, verse: 11, text: "In those days went there out of Israel wicked men, who persuaded many, saying, Let us go and make a covenant with the heathen that are round about us: for since we departed from them we have had much sorrow." },
  { book: "1 Maccabees", chapter: 1, verse: 12, text: "So this device pleased them well." },
  { book: "1 Maccabees", chapter: 1, verse: 13, text: "Then certain of the people were so forward herein, that they went to the king, who gave them licence to do after the ordinances of the heathen:" },
  { book: "1 Maccabees", chapter: 1, verse: 14, text: "Whereupon they built a place of exercise at Jerusalem according to the customs of the heathen:" },
  { book: "1 Maccabees", chapter: 1, verse: 15, text: "And made themselves uncircumcised, and forsook the holy covenant, and joined themselves to the heathen, and were sold to do mischief." },
  { book: "1 Maccabees", chapter: 1, verse: 16, text: "Now when the kingdom was established before Antiochus, he thought to reign over Egypt that he might have the dominion of two realms." },
  { book: "1 Maccabees", chapter: 1, verse: 17, text: "Wherefore he entered into Egypt with a great multitude, with chariots, and elephants, and horsemen, and a great navy," },
  { book: "1 Maccabees", chapter: 1, verse: 18, text: "And made war against Ptolemee king of Egypt: but Ptolemee was afraid of him, and fled; and many were wounded to death." },
  { book: "1 Maccabees", chapter: 1, verse: 19, text: "Thus they got the strong cities in the land of Egypt and he took the spoils thereof." },
  { book: "1 Maccabees", chapter: 1, verse: 20, text: "And after that Antiochus had smitten Egypt, he returned again in the hundred forty and third year, and went up against Israel and Jerusalem with a great multitude," },
  { book: "1 Maccabees", chapter: 1, verse: 21, text: "And entered proudly into the sanctuary, and took away the golden altar, and the candlestick of light, and all the vessels thereof," },
  { book: "1 Maccabees", chapter: 1, verse: 22, text: "And the table of the shewbread, and the pouring vessels, and the vials. and the censers of gold, and the veil, and the crown, and the golden ornaments that were before the temple, all which he pulled off." },
  { book: "1 Maccabees", chapter: 1, verse: 23, text: "He took also the silver and the gold, and the precious vessels: also he took the hidden treasures which he found." },
  { book: "1 Maccabees", chapter: 1, verse: 24, text: "And when he had taken all away, he went into his own land, having made a great massacre, and spoken very proudly." },
  { book: "1 Maccabees", chapter: 1, verse: 25, text: "Therefore there was a great mourning in Israel, in every place where they were;" },
  { book: "1 Maccabees", chapter: 1, verse: 26, text: "So that the princes and elders mourned, the virgins and young men were made feeble, and the beauty of women was changed." },
  { book: "1 Maccabees", chapter: 1, verse: 27, text: "Every bridegroom took up lamentation, and she that sat in the marriage chamber was in heaviness," },
  { book: "1 Maccabees", chapter: 1, verse: 28, text: "The land also was moved for the inhabitants thereof, and all the house of Jacob was covered with confusion." },
  { book: "1 Maccabees", chapter: 1, verse: 29, text: "And after two years fully expired the king sent his chief collector of tribute unto the cities of Juda, who came unto Jerusalem with a great multitude," },
  { book: "1 Maccabees", chapter: 1, verse: 30, text: "And spake peaceable words unto them, but all was deceit: for when they had given him credence, he fell suddenly upon the city, and smote it very sore, and destroyed much people of Israel." },
  { book: "1 Maccabees", chapter: 1, verse: 31, text: "And when he had taken the spoils of the city, he set it on fire, and pulled down the houses and walls thereof on every side." },
  { book: "1 Maccabees", chapter: 1, verse: 32, text: "But the women and children took they captive, and possessed the cattle." },
  { book: "1 Maccabees", chapter: 1, verse: 33, text: "Then builded they the city of David with a great and strong wall, and with mighty towers, and made it a strong hold for them." },
  { book: "1 Maccabees", chapter: 1, verse: 34, text: "And they put therein a sinful nation, wicked men, and fortified themselves therein." },
  { book: "1 Maccabees", chapter: 1, verse: 35, text: "They stored it also with armour and victuals, and when they had gathered together the spoils of Jerusalem, they laid them up there, and so they became a sore snare:" },
  { book: "1 Maccabees", chapter: 1, verse: 36, text: "For it was a place to lie in wait against the sanctuary, and an evil adversary to Israel." },
  { book: "1 Maccabees", chapter: 1, verse: 37, text: "Thus they shed innocent blood on every side of the sanctuary, and defiled it:" },
  { book: "1 Maccabees", chapter: 1, verse: 38, text: "Insomuch that the inhabitants of Jerusalem fled because of them: whereupon the city was made an habitation of strangers, and became strange to those that were born in her; and her own children left her." },
  { book: "1 Maccabees", chapter: 1, verse: 39, text: "Her sanctuary was laid waste like a wilderness, her feasts were turned into mourning, her sabbaths into reproach her honour into contempt." },
  { book: "1 Maccabees", chapter: 1, verse: 40, text: "As had been her glory, so was her dishonour increased, and her excellency was turned into mourning." },
  { book: "1 Maccabees", chapter: 1, verse: 41, text: "Moreover king Antiochus wrote to his whole kingdom, that all should be one people," },
  { book: "1 Maccabees", chapter: 1, verse: 42, text: "And every one should leave his laws: so all the heathen agreed according to the commandment of the king." },
  { book: "1 Maccabees", chapter: 1, verse: 43, text: "Yea, many also of the Israelites consented to his religion, and sacrificed unto idols, and profaned the sabbath." },
  { book: "1 Maccabees", chapter: 1, verse: 44, text: "For the king had sent letters by messengers unto Jerusalem and the cities of Juda that they should follow the strange laws of the land," },
  { book: "1 Maccabees", chapter: 1, verse: 45, text: "And forbid burnt offerings, and sacrifice, and drink offerings, in the temple; and that they should profane the sabbaths and festival days:" },
  { book: "1 Maccabees", chapter: 1, verse: 46, text: "And pollute the sanctuary and holy people:" },
  { book: "1 Maccabees", chapter: 1, verse: 47, text: "Set up altars, and groves, and chapels of idols, and sacrifice swine’s flesh, and unclean beasts:" },
  { book: "1 Maccabees", chapter: 1, verse: 48, text: "That they should also leave their children uncircumcised, and make their souls abominable with all manner of uncleanness and profanation:" },
  { book: "1 Maccabees", chapter: 1, verse: 49, text: "To the end they might forget the law, and change all the ordinances." },
  { book: "1 Maccabees", chapter: 1, verse: 50, text: "And whosoever would not do according to the commandment of the king, he said, he should die." },
  { book: "1 Maccabees", chapter: 1, verse: 51, text: "In the selfsame manner wrote he to his whole kingdom, and appointed overseers over all the people, commanding the cities of Juda to sacrifice, city by city." },
  { book: "1 Maccabees", chapter: 1, verse: 52, text: "Then many of the people were gathered unto them, to wit every one that forsook the law; and so they committed evils in the land;" },
  { book: "1 Maccabees", chapter: 1, verse: 53, text: "And drove the Israelites into secret places, even wheresoever they could flee for succour." },
  { book: "1 Maccabees", chapter: 1, verse: 54, text: "Now the fifteenth day of the month Casleu, in the hundred forty and fifth year, they set up the abomination of desolation upon the altar, and builded idol altars throughout the cities of Juda on every side;" },
  { book: "1 Maccabees", chapter: 1, verse: 55, text: "And burnt incense at the doors of their houses, and in the streets." },
  { book: "1 Maccabees", chapter: 1, verse: 56, text: "And when they had rent in pieces the books of the law which they found, they burnt them with fire." },
  { book: "1 Maccabees", chapter: 1, verse: 57, text: "And whosoever was found with any the book of the testament, or if any committed to the law, the king’s commandment was, that they should put him to death." },
  { book: "1 Maccabees", chapter: 1, verse: 58, text: "Thus did they by their authority unto the Israelites every month, to as many as were found in the cities." },
  { book: "1 Maccabees", chapter: 1, verse: 59, text: "Now the five and twentieth day of the month they did sacrifice upon the idol altar, which was upon the altar of God." },
  { book: "1 Maccabees", chapter: 1, verse: 60, text: "At which time according to the commandment they put to death certain women, that had caused their children to be circumcised." },
  { book: "1 Maccabees", chapter: 1, verse: 61, text: "And they hanged the infants about their necks, and rifled their houses, and slew them that had circumcised them." },
  { book: "1 Maccabees", chapter: 1, verse: 62, text: "Howbeit many in Israel were fully resolved and confirmed in themselves not to eat any unclean thing." },
  { book: "1 Maccabees", chapter: 1, verse: 63, text: "Wherefore the rather to die, that they might not be defiled with meats, and that they might not profane the holy covenant: so then they died." },
  { book: "1 Maccabees", chapter: 1, verse: 64, text: "And there was very great wrath upon Israel." },
  { book: "1 Maccabees", chapter: 2, verse: 1, text: "In those days arose Mattathias the son of John, the son of Simeon, a priest of the sons of Joarib, from Jerusalem, and dwelt in Modin." },
  { book: "1 Maccabees", chapter: 2, verse: 2, text: "And he had five sons, Joannan, called Caddis:" },
  { book: "1 Maccabees", chapter: 2, verse: 3, text: "Simon; called Thassi:" },
  { book: "1 Maccabees", chapter: 2, verse: 4, text: "Judas, who was called Maccabeus:" },
  { book: "1 Maccabees", chapter: 2, verse: 5, text: "Eleazar, called Avaran: and Jonathan, whose surname was Apphus." },
  { book: "1 Maccabees", chapter: 2, verse: 6, text: "And when he saw the blasphemies that were committed in Juda and Jerusalem," },
  { book: "1 Maccabees", chapter: 2, verse: 7, text: "He said, Woe is me! wherefore was I born to see this misery of my people, and of the holy city, and to dwell there, when it was delivered into the hand of the enemy, and the sanctuary into the hand of strangers?" },
  { book: "1 Maccabees", chapter: 2, verse: 8, text: "Her temple is become as a man without glory." },
  { book: "1 Maccabees", chapter: 2, verse: 9, text: "Her glorious vessels are carried away into captivity, her infants are slain in the streets, her young men with the sword of the enemy." },
  { book: "1 Maccabees", chapter: 2, verse: 10, text: "What nation hath not had a part in her kingdom and gotten of her spoils?" },
  { book: "1 Maccabees", chapter: 2, verse: 11, text: "All her ornaments are taken away; of a free woman she is become a bondslave." },
  { book: "1 Maccabees", chapter: 2, verse: 12, text: "And, behold, our sanctuary, even our beauty and our glory, is laid waste, and the Gentiles have profaned it." },
  { book: "1 Maccabees", chapter: 2, verse: 13, text: "To what end therefore shall we live any longer?" },
  { book: "1 Maccabees", chapter: 2, verse: 14, text: "Then Mattathias and his sons rent their clothes, and put on sackcloth, and mourned very sore." },
  { book: "1 Maccabees", chapter: 2, verse: 15, text: "In the mean while the king’s officers, such as compelled the people to revolt, came into the city Modin, to make them sacrifice." },
  { book: "1 Maccabees", chapter: 2, verse: 16, text: "And when many of Israel came unto them, Mattathias also and his sons came together." },
  { book: "1 Maccabees", chapter: 2, verse: 17, text: "Then answered the king’s officers, and said to Mattathias on this wise, Thou art a ruler, and an honourable and great man in this city, and strengthened with sons and brethren:" },
  { book: "1 Maccabees", chapter: 2, verse: 18, text: "Now therefore come thou first, and fulfil the king’s commandment, like as all the heathen have done, yea, and the men of Juda also, and such as remain at Jerusalem: so shalt thou and thy house be in the number of the king’s friends, and thou and thy children shall be honoured with silver and gold, and many rewards." },
  { book: "1 Maccabees", chapter: 2, verse: 19, text: "Then Mattathias answered and spake with a loud voice, Though all the nations that are under the king’s dominion obey him, and fall away every one from the religion of their fathers, and give consent to his commandments:" },
  { book: "1 Maccabees", chapter: 2, verse: 20, text: "Yet will I and my sons and my brethren walk in the covenant of our fathers." },
  { book: "1 Maccabees", chapter: 2, verse: 21, text: "God forbid that we should forsake the law and the ordinances." },
  { book: "1 Maccabees", chapter: 2, verse: 22, text: "We will not hearken to the king’s words, to go from our religion, either on the right hand, or the left." },
  { book: "1 Maccabees", chapter: 2, verse: 23, text: "Now when he had left speaking these words, there came one of the Jews in the sight of all to sacrifice on the altar which was at Modin, according to the king’s commandment." },
  { book: "1 Maccabees", chapter: 2, verse: 24, text: "Which thing when Mattathias saw, he was inflamed with zeal, and his reins trembled, neither could he forbear to shew his anger according to judgment: wherefore he ran, and slew him upon the altar." },
  { book: "1 Maccabees", chapter: 2, verse: 25, text: "Also the king’s commissioner, who compelled men to sacrifice, he killed at that time, and the altar he pulled down." },
  { book: "1 Maccabees", chapter: 2, verse: 26, text: "Thus dealt he zealously for the law of God like as Phinees did unto Zambri the son of Salom." },
  { book: "1 Maccabees", chapter: 2, verse: 27, text: "And Mattathias cried throughout the city with a loud voice, saying, Whosoever is zealous of the law, and maintaineth the covenant, let him follow me." },
  { book: "1 Maccabees", chapter: 2, verse: 28, text: "So he and his sons fled into the mountains, and left all that ever they had in the city." },
  { book: "1 Maccabees", chapter: 2, verse: 29, text: "Then many that sought after justice and judgment went down into the wilderness, to dwell there:" },
  { book: "1 Maccabees", chapter: 2, verse: 30, text: "Both they, and their children, and their wives; and their cattle; because afflictions increased sore upon them." },
  { book: "1 Maccabees", chapter: 2, verse: 31, text: "Now when it was told the king’s servants, and the host that was at Jerusalem, in the city of David, that certain men, who had broken the king’s commandment, were gone down into the secret places in the wilderness," },
  { book: "1 Maccabees", chapter: 2, verse: 32, text: "They pursued after them a great number, and having overtaken them, they camped against them, and made war against them on the sabbath day." },
  { book: "1 Maccabees", chapter: 2, verse: 33, text: "And they said unto them, Let that which ye have done hitherto suffice; come forth, and do according to the commandment of the king, and ye shall live." },
  { book: "1 Maccabees", chapter: 2, verse: 34, text: "But they said, We will not come forth, neither will we do the king’s commandment, to profane the sabbath day." },
  { book: "1 Maccabees", chapter: 2, verse: 35, text: "So then they gave them the battle with all speed." },
  { book: "1 Maccabees", chapter: 2, verse: 36, text: "Howbeit they answered them not, neither cast they a stone at them, nor stopped the places where they lay hid;" },
  { book: "1 Maccabees", chapter: 2, verse: 37, text: "But said, Let us die all in our innocency: heaven and earth will testify for us, that ye put us to death wrongfully." },
  { book: "1 Maccabees", chapter: 2, verse: 38, text: "So they rose up against them in battle on the sabbath, and they slew them, with their wives and children and their cattle, to the number of a thousand people." },
  { book: "1 Maccabees", chapter: 2, verse: 39, text: "Now when Mattathias and his friends understood hereof, they mourned for them right sore." },
  { book: "1 Maccabees", chapter: 2, verse: 40, text: "And one of them said to another, If we all do as our brethren have done, and fight not for our lives and laws against the heathen, they will now quickly root us out of the earth." },
  { book: "1 Maccabees", chapter: 2, verse: 41, text: "At that time therefore they decreed, saying, Whosoever shall come to make battle with us on the sabbath day, we will fight against him; neither will we die all, as our brethren that were murdered in the secret places." },
  { book: "1 Maccabees", chapter: 2, verse: 42, text: "Then came there unto him a company of Assideans who were mighty men of Israel, even all such as were voluntarily devoted unto the law." },
  { book: "1 Maccabees", chapter: 2, verse: 43, text: "Also all they that fled for persecution joined themselves unto them, and were a stay unto them." },
  { book: "1 Maccabees", chapter: 2, verse: 44, text: "So they joined their forces, and smote sinful men in their anger, and wicked men in their wrath: but the rest fled to the heathen for succour." },
  { book: "1 Maccabees", chapter: 2, verse: 45, text: "Then Mattathias and his friends went round about, and pulled down the altars:" },
  { book: "1 Maccabees", chapter: 2, verse: 46, text: "And what children soever they found within the coast of Israel uncircumcised, those they circumcised valiantly." },
  { book: "1 Maccabees", chapter: 2, verse: 47, text: "They pursued also after the proud men, and the work prospered in their hand." },
  { book: "1 Maccabees", chapter: 2, verse: 48, text: "So they recovered the law out of the hand of the Gentiles, and out of the hand of kings, neither suffered they the sinner to triumph." },
  { book: "1 Maccabees", chapter: 2, verse: 49, text: "Now when the time drew near that Mattathias should die, he said unto his sons, Now hath pride and rebuke gotten strength, and the time of destruction, and the wrath of indignation:" },
  { book: "1 Maccabees", chapter: 2, verse: 50, text: "Now therefore, my sons, be ye zealous for the law, and give your lives for the covenant of your fathers." },
  { book: "1 Maccabees", chapter: 2, verse: 51, text: "Call to remembrance what acts our fathers did in their time; so shall ye receive great honour and an everlasting name." },
  { book: "1 Maccabees", chapter: 2, verse: 52, text: "Was not Abraham found faithful in temptation, and it was imputed unto him for righteousness?" },
  { book: "1 Maccabees", chapter: 2, verse: 53, text: "Joseph in the time of his distress kept the commandment and was made lord of Egypt." },
  { book: "1 Maccabees", chapter: 2, verse: 54, text: "Phinees our father in being zealous and fervent obtained the covenant of an everlasting priesthood." },
  { book: "1 Maccabees", chapter: 2, verse: 55, text: "Jesus for fulfilling the word was made a judge in Israel." },
  { book: "1 Maccabees", chapter: 2, verse: 56, text: "Caleb for bearing witness before the congregation received the heritage of the land." },
  { book: "1 Maccabees", chapter: 2, verse: 57, text: "David for being merciful possessed the throne of an everlasting kingdom." },
  { book: "1 Maccabees", chapter: 2, verse: 58, text: "Elias for being zealous and fervent for the law was taken up into heaven." },
  { book: "1 Maccabees", chapter: 2, verse: 59, text: "Ananias, Azarias, and Misael, by believing were saved out of the flame." },
  { book: "1 Maccabees", chapter: 2, verse: 60, text: "Daniel for his innocency was delivered from the mouth of lions." },
  { book: "1 Maccabees", chapter: 2, verse: 61, text: "And thus consider ye throughout all ages, that none that put their trust in him shall be overcome." },
  { book: "1 Maccabees", chapter: 2, verse: 62, text: "Fear not then the words of a sinful man: for his glory shall be dung and worms." },
  { book: "1 Maccabees", chapter: 2, verse: 63, text: "To day he shall be lifted up and to morrow he shall not be found, because he is returned into his dust, and his thought is come to nothing." },
  { book: "1 Maccabees", chapter: 2, verse: 64, text: "Wherefore, ye my sons, be valiant and shew yourselves men in the behalf of the law; for by it shall ye obtain glory." },
  { book: "1 Maccabees", chapter: 2, verse: 65, text: "And behold, I know that your brother Simon is a man of counsel, give ear unto him alway: he shall be a father unto you." },
  { book: "1 Maccabees", chapter: 2, verse: 66, text: "As for Judas Maccabeus, he hath been mighty and strong, even from his youth up: let him be your captain, and fight the battle of the people." },
  { book: "1 Maccabees", chapter: 2, verse: 67, text: "Take also unto you all those that observe the law, and avenge ye the wrong of your people." },
  { book: "1 Maccabees", chapter: 2, verse: 68, text: "Recompense fully the heathen, and take heed to the commandments of the law." },
  { book: "1 Maccabees", chapter: 2, verse: 69, text: "So he blessed them, and was gathered to his fathers." },
  { book: "1 Maccabees", chapter: 2, verse: 70, text: "And he died in the hundred forty and sixth year, and his sons buried him in the sepulchres of his fathers at Modin, and all Israel made great lamentation for him." },
  { book: "1 Maccabees", chapter: 3, verse: 1, text: "Then his son Judas, called Maccabeus, rose up in his stead." },
  { book: "1 Maccabees", chapter: 3, verse: 2, text: "And all his brethren helped him, and so did all they that held with his father, and they fought with cheerfulness the battle of Israel." },
  { book: "1 Maccabees", chapter: 3, verse: 3, text: "So he gat his people great honour, and put on a breastplate as a giant, and girt his warlike harness about him, and he made battles, protecting the host with his sword." },
  { book: "1 Maccabees", chapter: 3, verse: 4, text: "In his acts he was like a lion, and like a lion’s whelp roaring for his prey." },
  { book: "1 Maccabees", chapter: 3, verse: 5, text: "For He pursued the wicked, and sought them out, and burnt up those that vexed his people." },
  { book: "1 Maccabees", chapter: 3, verse: 6, text: "Wherefore the wicked shrunk for fear of him, and all the workers of iniquity were troubled, because salvation prospered in his hand." },
  { book: "1 Maccabees", chapter: 3, verse: 7, text: "He grieved also many kings, and made Jacob glad with his acts, and his memorial is blessed for ever." },
  { book: "1 Maccabees", chapter: 3, verse: 8, text: "Moreover he went through the cities of Juda, destroying the ungodly out of them, and turning away wrath from Israel:" },
  { book: "1 Maccabees", chapter: 3, verse: 9, text: "So that he was renowned unto the utmost part of the earth, and he received unto him such as were ready to perish." },
  { book: "1 Maccabees", chapter: 3, verse: 10, text: "Then Apollonius gathered the Gentiles together, and a great host out of Samaria, to fight against Israel." },
  { book: "1 Maccabees", chapter: 3, verse: 11, text: "Which thing when Judas perceived, he went forth to meet him, and so he smote him, and slew him: many also fell down slain, but the rest fled." },
  { book: "1 Maccabees", chapter: 3, verse: 12, text: "Wherefore Judas took their spoils, and Apollonius’ sword also, and therewith he fought all his life long." },
  { book: "1 Maccabees", chapter: 3, verse: 13, text: "Now when Seron, a prince of the army of Syria, heard say that Judas had gathered unto him a multitude and company of the faithful to go out with him to war;" },
  { book: "1 Maccabees", chapter: 3, verse: 14, text: "He said, I will get me a name and honour in the kingdom; for I will go fight with Judas and them that are with him, who despise the king’s commandment." },
  { book: "1 Maccabees", chapter: 3, verse: 15, text: "So he made him ready to go up, and there went with him a mighty host of the ungodly to help him, and to be avenged of the children of Israel." },
  { book: "1 Maccabees", chapter: 3, verse: 16, text: "And when he came near to the going up of Bethhoron, Judas went forth to meet him with a small company:" },
  { book: "1 Maccabees", chapter: 3, verse: 17, text: "Who, when they saw the host coming to meet them, said unto Judas, How shall we be able, being so few, to fight against so great a multitude and so strong, seeing we are ready to faint with fasting all this day?" },
  { book: "1 Maccabees", chapter: 3, verse: 18, text: "Unto whom Judas answered, It is no hard matter for many to be shut up in the hands of a few; and with the God of heaven it is all one, to deliver with a great multitude, or a small company:" },
  { book: "1 Maccabees", chapter: 3, verse: 19, text: "For the victory of battle standeth not in the multitude of an host; but strength cometh from heaven." },
  { book: "1 Maccabees", chapter: 3, verse: 20, text: "They come against us in much pride and iniquity to destroy us, and our wives and children, and to spoil us:" },
  { book: "1 Maccabees", chapter: 3, verse: 21, text: "But we fight for our lives and our laws." },
  { book: "1 Maccabees", chapter: 3, verse: 22, text: "Wherefore the Lord himself will overthrow them before our face: and as for you, be ye not afraid of them." },
  { book: "1 Maccabees", chapter: 3, verse: 23, text: "Now as soon as he had left off speaking, he leapt suddenly upon them, and so Seron and his host was overthrown before him." },
  { book: "1 Maccabees", chapter: 3, verse: 24, text: "And they pursued them from the going down of Bethhoron unto the plain, where were slain about eight hundred men of them; and the residue fled into the land of the Philistines." },
  { book: "1 Maccabees", chapter: 3, verse: 25, text: "Then began the fear of Judas and his brethren, and an exceeding great dread, to fall upon the nations round about them:" },
  { book: "1 Maccabees", chapter: 3, verse: 26, text: "Insomuch as his fame came unto the king, and all nations talked of the battles of Judas." },
  { book: "1 Maccabees", chapter: 3, verse: 27, text: "Now when king Antiochus heard these things, he was full of indignation: wherefore he sent and gathered together all the forces of his realm, even a very strong army." },
  { book: "1 Maccabees", chapter: 3, verse: 28, text: "He opened also his treasure, and gave his soldiers pay for a year, commanding them to be ready whensoever he should need them." },
  { book: "1 Maccabees", chapter: 3, verse: 29, text: "Nevertheless, when he saw that the money of his treasures failed and that the tributes in the country were small, because of the dissension and plague, which he had brought upon the land in taking away the laws which had been of old time;" },
  { book: "1 Maccabees", chapter: 3, verse: 30, text: "He feared that he should not be able to bear the charges any longer, nor to have such gifts to give so liberally as he did before: for he had abounded above the kings that were before him." },
  { book: "1 Maccabees", chapter: 3, verse: 31, text: "Wherefore, being greatly perplexed in his mind, he determined to go into Persia, there to take the tributes of the countries, and to gather much money." },
  { book: "1 Maccabees", chapter: 3, verse: 32, text: "So he left Lysias, a nobleman, and one of the blood royal, to oversee the affairs of the king from the river Euphrates unto the borders of Egypt:" },
  { book: "1 Maccabees", chapter: 3, verse: 33, text: "And to bring up his son Antiochus, until he came again." },
  { book: "1 Maccabees", chapter: 3, verse: 34, text: "Moreover he delivered unto him the half of his forces, and the elephants, and gave him charge of all things that he would have done, as also concerning them that dwelt in Juda and Jerusalem:" },
  { book: "1 Maccabees", chapter: 3, verse: 35, text: "To wit, that he should send an army against them, to destroy and root out the strength of Israel, and the remnant of Jerusalem, and to take away their memorial from that place;" },
  { book: "1 Maccabees", chapter: 3, verse: 36, text: "And that he should place strangers in all their quarters, and divide their land by lot." },
  { book: "1 Maccabees", chapter: 3, verse: 37, text: "So the king took the half of the forces that remained, and departed from Antioch, his royal city, the hundred forty and seventh year; and having passed the river Euphrates, he went through the high countries." },
  { book: "1 Maccabees", chapter: 3, verse: 38, text: "Then Lysias chose Ptolemee the son of Dorymenes, Nicanor, and Gorgias, mighty men of the king’s friends:" },
  { book: "1 Maccabees", chapter: 3, verse: 39, text: "And with them he sent forty thousand footmen, and seven thousand horsemen, to go into the land of Juda, and to destroy it, as the king commanded." },
  { book: "1 Maccabees", chapter: 3, verse: 40, text: "So they went forth with all their power, and came and pitched by Emmaus in the plain country." },
  { book: "1 Maccabees", chapter: 3, verse: 41, text: "And the merchants of the country, hearing the fame of them, took silver and gold very much, with servants, and came into the camp to buy the children of Israel for slaves: a power also of Syria and of the land of the Philistines joined themselves unto them." },
  { book: "1 Maccabees", chapter: 3, verse: 42, text: "Now when Judas and his brethren saw that miseries were multiplied, and that the forces did encamp themselves in their borders: for they knew how the king had given commandment to destroy the people, and utterly abolish them;" },
  { book: "1 Maccabees", chapter: 3, verse: 43, text: "They said one to another, Let us restore the decayed fortune of our people, and let us fight for our people and the sanctuary." },
  { book: "1 Maccabees", chapter: 3, verse: 44, text: "Then was the congregation gathered together, that they might be ready for battle, and that they might pray, and ask mercy and compassion." },
  { book: "1 Maccabees", chapter: 3, verse: 45, text: "Now Jerusalem lay void as a wilderness, there was none of her children that went in or out: the sanctuary also was trodden down, and aliens kept the strong hold; the heathen had their habitation in that place; and joy was taken from Jacob, and the pipe with the harp ceased." },
  { book: "1 Maccabees", chapter: 3, verse: 46, text: "Wherefore the Israelites assembled themselves together, and came to Maspha, over against Jerusalem; for in Maspha was the place where they prayed aforetime in Israel." },
  { book: "1 Maccabees", chapter: 3, verse: 47, text: "Then they fasted that day, and put on sackcloth, and cast ashes upon their heads, and rent their clothes," },
  { book: "1 Maccabees", chapter: 3, verse: 48, text: "And laid open the book of the law, wherein the heathen had sought to paint the likeness of their images." },
  { book: "1 Maccabees", chapter: 3, verse: 49, text: "They brought also the priests’ garments, and the firstfruits, and the tithes: and the Nazarites they stirred up, who had accomplished their days." },
  { book: "1 Maccabees", chapter: 3, verse: 50, text: "Then cried they with a loud voice toward heaven, saying, What shall we do with these, and whither shall we carry them away?" },
  { book: "1 Maccabees", chapter: 3, verse: 51, text: "For thy sanctuary is trodden down and profaned, and thy priests are in heaviness, and brought low." },
  { book: "1 Maccabees", chapter: 3, verse: 52, text: "And lo, the heathen are assembled together against us to destroy us: what things they imagine against us, thou knowest." },
  { book: "1 Maccabees", chapter: 3, verse: 53, text: "How shall we be able to stand against them, except thou, O God, be our help?" },
  { book: "1 Maccabees", chapter: 3, verse: 54, text: "Then sounded they with trumpets, and cried with a loud voice." },
  { book: "1 Maccabees", chapter: 3, verse: 55, text: "And after this Judas ordained captains over the people, even captains over thousands, and over hundreds, and over fifties, and over tens." },
  { book: "1 Maccabees", chapter: 3, verse: 56, text: "But as for such as were building houses, or had betrothed wives, or were planting vineyards, or were fearful, those he commanded that they should return, every man to his own house, according to the law." },
  { book: "1 Maccabees", chapter: 3, verse: 57, text: "So the camp removed, and pitched upon the south side of Emmaus." },
  { book: "1 Maccabees", chapter: 3, verse: 58, text: "And Judas said, arm yourselves, and be valiant men, and see that ye be in readiness against the morning, that ye may fight with these nations, that are assembled together against us to destroy us and our sanctuary:" },
  { book: "1 Maccabees", chapter: 3, verse: 59, text: "For it is better for us to die in battle, than to behold the calamities of our people and our sanctuary." },
  { book: "1 Maccabees", chapter: 3, verse: 60, text: "Nevertheless, as the will of God is in heaven, so let him do." },
  { book: "1 Maccabees", chapter: 4, verse: 1, text: "Then took Gorgias five thousand footmen, and a thousand of the best horsemen, and removed out of the camp by night;" },
  { book: "1 Maccabees", chapter: 4, verse: 2, text: "To the end he might rush in upon the camp of the Jews, and smite them suddenly. And the men of the fortress were his guides." },
  { book: "1 Maccabees", chapter: 4, verse: 3, text: "Now when Judas heard thereof he himself removed, and the valiant men with him, that he might smite the king’s army which was at Emmaus," },
  { book: "1 Maccabees", chapter: 4, verse: 4, text: "While as yet the forces were dispersed from the camp." },
  { book: "1 Maccabees", chapter: 4, verse: 5, text: "In the mean season came Gorgias by night into the camp of Judas: and when he found no man there, he sought them in the mountains: for said he, These fellows flee from us" },
  { book: "1 Maccabees", chapter: 4, verse: 6, text: "But as soon as it was day, Judas shewed himself in the plain with three thousand men, who nevertheless had neither armour nor swords to their minds." },
  { book: "1 Maccabees", chapter: 4, verse: 7, text: "And they saw the camp of the heathen, that it was strong and well harnessed, and compassed round about with horsemen; and these were expert of war." },
  { book: "1 Maccabees", chapter: 4, verse: 8, text: "Then said Judas to the men that were with him, Fear ye not their multitude, neither be ye afraid of their assault." },
  { book: "1 Maccabees", chapter: 4, verse: 9, text: "Remember how our fathers were delivered in the Red sea, when Pharaoh pursued them with an army." },
  { book: "1 Maccabees", chapter: 4, verse: 10, text: "Now therefore let us cry unto heaven, if peradventure the Lord will have mercy upon us, and remember the covenant of our fathers, and destroy this host before our face this day:" },
  { book: "1 Maccabees", chapter: 4, verse: 11, text: "That so all the heathen may know that there is one who delivereth and saveth Israel." },
  { book: "1 Maccabees", chapter: 4, verse: 12, text: "Then the strangers lifted up their eyes, and saw them coming over against them." },
  { book: "1 Maccabees", chapter: 4, verse: 13, text: "Wherefore they went out of the camp to battle; but they that were with Judas sounded their trumpets." },
  { book: "1 Maccabees", chapter: 4, verse: 14, text: "So they joined battle, and the heathen being discomfited fled into the plain." },
  { book: "1 Maccabees", chapter: 4, verse: 15, text: "Howbeit all the hindmost of them were slain with the sword: for they pursued them unto Gazera, and unto the plains of Idumea, and Azotus, and Jamnia, so that there were slain of them upon a three thousand men." },
  { book: "1 Maccabees", chapter: 4, verse: 16, text: "This done, Judas returned again with his host from pursuing them," },
  { book: "1 Maccabees", chapter: 4, verse: 17, text: "And said to the people, Be not greedy of the spoil inasmuch as there is a battle before us," },
  { book: "1 Maccabees", chapter: 4, verse: 18, text: "And Gorgias and his host are here by us in the mountain: but stand ye now against our enemies, and overcome them, and after this ye may boldly take the spoils." },
  { book: "1 Maccabees", chapter: 4, verse: 19, text: "As Judas was yet speaking these words, there appeared a part of them looking out of the mountain:" },
  { book: "1 Maccabees", chapter: 4, verse: 20, text: "Who when they perceived that the Jews had put their host to flight and were burning the tents; for the smoke that was seen declared what was done:" },
  { book: "1 Maccabees", chapter: 4, verse: 21, text: "When therefore they perceived these things, they were sore afraid, and seeing also the host of Judas in the plain ready to fight," },
  { book: "1 Maccabees", chapter: 4, verse: 22, text: "They fled every one into the land of strangers." },
  { book: "1 Maccabees", chapter: 4, verse: 23, text: "Then Judas returned to spoil the tents, where they got much gold, and silver, and blue silk, and purple of the sea, and great riches." },
  { book: "1 Maccabees", chapter: 4, verse: 24, text: "After this they went home, and sung a song of thanksgiving, and praised the Lord in heaven: because it is good, because his mercy endureth forever." },
  { book: "1 Maccabees", chapter: 4, verse: 25, text: "Thus Israel had a great deliverance that day." },
  { book: "1 Maccabees", chapter: 4, verse: 26, text: "Now all the strangers that had escaped came and told Lysias what had happened:" },
  { book: "1 Maccabees", chapter: 4, verse: 27, text: "Who, when he heard thereof, was confounded and discouraged, because neither such things as he would were done unto Israel, nor such things as the king commanded him were come to pass." },
  { book: "1 Maccabees", chapter: 4, verse: 28, text: "The next year therefore following Lysias gathered together threescore thousand choice men of foot, and five thousand horsemen, that he might subdue them." },
  { book: "1 Maccabees", chapter: 4, verse: 29, text: "So they came into Idumea, and pitched their tents at Bethsura, and Judas met them with ten thousand men." },
  { book: "1 Maccabees", chapter: 4, verse: 30, text: "And when he saw that mighty army, he prayed and said, Blessed art thou, O Saviour of Israel, who didst quell the violence of the mighty man by the hand of thy servant David, and gavest the host of strangers into the hands of Jonathan the son of Saul, and his armourbearer;" },
  { book: "1 Maccabees", chapter: 4, verse: 31, text: "Shut up this army in the hand of thy people Israel, and let them be confounded in their power and horsemen:" },
  { book: "1 Maccabees", chapter: 4, verse: 32, text: "Make them to be of no courage, and cause the boldness of their strength to fall away, and let them quake at their destruction:" },
  { book: "1 Maccabees", chapter: 4, verse: 33, text: "Cast them down with the sword of them that love thee, and let all those that know thy name praise thee with thanksgiving." },
  { book: "1 Maccabees", chapter: 4, verse: 34, text: "So they joined battle; and there were slain of the host of Lysias about five thousand men, even before them were they slain." },
  { book: "1 Maccabees", chapter: 4, verse: 35, text: "Now when Lysias saw his army put to flight, and the manliness of Judas’ soldiers, and how they were ready either to live or die valiantly, he went into Antiochia, and gathered together a company of strangers, and having made his army greater than it was, he purposed to come again into Judea." },
  { book: "1 Maccabees", chapter: 4, verse: 36, text: "Then said Judas and his brethren, Behold, our enemies are discomfited: let us go up to cleanse and dedicate the sanctuary." },
  { book: "1 Maccabees", chapter: 4, verse: 37, text: "Upon this all the host assembled themselves together, and went up into mount Sion." },
  { book: "1 Maccabees", chapter: 4, verse: 38, text: "And when they saw the sanctuary desolate, and the altar profaned, and the gates burned up, and shrubs growing in the courts as in a forest, or in one of the mountains, yea, and the priests’ chambers pulled down;" },
  { book: "1 Maccabees", chapter: 4, verse: 39, text: "They rent their clothes, and made great lamentation, and cast ashes upon their heads," },
  { book: "1 Maccabees", chapter: 4, verse: 40, text: "And fell down flat to the ground upon their faces, and blew an alarm with the trumpets, and cried toward heaven." },
  { book: "1 Maccabees", chapter: 4, verse: 41, text: "Then Judas appointed certain men to fight against those that were in the fortress, until he had cleansed the sanctuary." },
  { book: "1 Maccabees", chapter: 4, verse: 42, text: "So he chose priests of blameless conversation, such as had pleasure in the law:" },
  { book: "1 Maccabees", chapter: 4, verse: 43, text: "Who cleansed the sanctuary, and bare out the defiled stones into an unclean place." },
  { book: "1 Maccabees", chapter: 4, verse: 44, text: "And when as they consulted what to do with the altar of burnt offerings, which was profaned;" },
  { book: "1 Maccabees", chapter: 4, verse: 45, text: "They thought it best to pull it down, lest it should be a reproach to them, because the heathen had defiled it: wherefore they pulled it down," },
  { book: "1 Maccabees", chapter: 4, verse: 46, text: "And laid up the stones in the mountain of the temple in a convenient place, until there should come a prophet to shew what should be done with them." },
  { book: "1 Maccabees", chapter: 4, verse: 47, text: "Then they took whole stones according to the law, and built a new altar according to the former;" },
  { book: "1 Maccabees", chapter: 4, verse: 48, text: "And made up the sanctuary, and the things that were within the temple, and hallowed the courts." },
  { book: "1 Maccabees", chapter: 4, verse: 49, text: "They made also new holy vessels, and into the temple they brought the candlestick, and the altar of burnt offerings, and of incense, and the table." },
  { book: "1 Maccabees", chapter: 4, verse: 50, text: "And upon the altar they burned incense, and the lamps that were upon the candlestick they lighted, that they might give light in the temple." },
  { book: "1 Maccabees", chapter: 4, verse: 51, text: "Furthermore they set the loaves upon the table, and spread out the veils, and finished all the works which they had begun to make." },
  { book: "1 Maccabees", chapter: 4, verse: 52, text: "Now on the five and twentieth day of the ninth month, which is called the month Casleu, in the hundred forty and eighth year, they rose up betimes in the morning," },
  { book: "1 Maccabees", chapter: 4, verse: 53, text: "And offered sacrifice according to the law upon the new altar of burnt offerings, which they had made." },
  { book: "1 Maccabees", chapter: 4, verse: 54, text: "Look, at what time and what day the heathen had profaned it, even in that was it dedicated with songs, and citherns, and harps, and cymbals." },
  { book: "1 Maccabees", chapter: 4, verse: 55, text: "Then all the people fell upon their faces, worshipping and praising the God of heaven, who had given them good success." },
  { book: "1 Maccabees", chapter: 4, verse: 56, text: "And so they kept the dedication of the altar eight days and offered burnt offerings with gladness, and sacrificed the sacrifice of deliverance and praise." },
  { book: "1 Maccabees", chapter: 4, verse: 57, text: "They decked also the forefront of the temple with crowns of gold, and with shields; and the gates and the chambers they renewed, and hanged doors upon them." },
  { book: "1 Maccabees", chapter: 4, verse: 58, text: "Thus was there very great gladness among the people, for that the reproach of the heathen was put away." },
  { book: "1 Maccabees", chapter: 4, verse: 59, text: "Moreover Judas and his brethren with the whole congregation of Israel ordained, that the days of the dedication of the altar should be kept in their season from year to year by the space of eight days, from the five and twentieth day of the month Casleu, with mirth and gladness." },
  { book: "1 Maccabees", chapter: 4, verse: 60, text: "At that time also they builded up the mount Sion with high walls and strong towers round about, lest the Gentiles should come and tread it down as they had done before." },
  { book: "1 Maccabees", chapter: 4, verse: 61, text: "And they set there a garrison to keep it, and fortified Bethsura to preserve it; that the people might have a defence against Idumea." },
  { book: "1 Maccabees", chapter: 5, verse: 1, text: "Now when the nations round about heard that the altar was built and the sanctuary renewed as before, it displeased them very much." },
  { book: "1 Maccabees", chapter: 5, verse: 2, text: "Wherefore they thought to destroy the generation of Jacob that was among them, and thereupon they began to slay and destroy the people." },
  { book: "1 Maccabees", chapter: 5, verse: 3, text: "Then Judas fought against the children of Esau in Idumea at Arabattine, because they besieged Gael: and he gave them a great overthrow, and abated their courage, and took their spoils." },
  { book: "1 Maccabees", chapter: 5, verse: 4, text: "Also he remembered the injury of the children of Bean, who had been a snare and an offence unto the people, in that they lay in wait for them in the ways." },
  { book: "1 Maccabees", chapter: 5, verse: 5, text: "He shut them up therefore in the towers, and encamped against them, and destroyed them utterly, and burned the towers of that place with fire, and all that were therein." },
  { book: "1 Maccabees", chapter: 5, verse: 6, text: "Afterward he passed over to the children of Ammon, where he found a mighty power, and much people, with Timotheus their captain." },
  { book: "1 Maccabees", chapter: 5, verse: 7, text: "So he fought many battles with them, till at length they were discomfited before him; and he smote them." },
  { book: "1 Maccabees", chapter: 5, verse: 8, text: "And when he had taken Jazar, with the towns belonging thereto, he returned into Judea." },
  { book: "1 Maccabees", chapter: 5, verse: 9, text: "Then the heathen that were at Galaad assembled themselves together against the Israelites that were in their quarters, to destroy them; but they fled to the fortress of Dathema." },
  { book: "1 Maccabees", chapter: 5, verse: 10, text: "And sent letters unto Judas and his brethren, The heathen that are round about us are assembled together against us to destroy us:" },
  { book: "1 Maccabees", chapter: 5, verse: 11, text: "And they are preparing to come and take the fortress whereunto we are fled, Timotheus being captain of their host." },
  { book: "1 Maccabees", chapter: 5, verse: 12, text: "Come now therefore, and deliver us from their hands, for many of us are slain:" },
  { book: "1 Maccabees", chapter: 5, verse: 13, text: "Yea, all our brethren that were in the places of Tobie are put to death: their wives and their children also they have carried away captives, and borne away their stuff; and they have destroyed there about a thousand men." },
  { book: "1 Maccabees", chapter: 5, verse: 14, text: "While these letters were yet reading, behold, there came other messengers from Galilee with their clothes rent, who reported on this wise," },
  { book: "1 Maccabees", chapter: 5, verse: 15, text: "And said, They of Ptolemais, and of Tyrus, and Sidon, and all Galilee of the Gentiles, are assembled together against us to consume us." },
  { book: "1 Maccabees", chapter: 5, verse: 16, text: "Now when Judas and the people heard these words, there assembled a great congregation together, to consult what they should do for their brethren, that were in trouble, and assaulted of them." },
  { book: "1 Maccabees", chapter: 5, verse: 17, text: "Then said Judas unto Simon his brother, Choose thee out men, and go and deliver thy brethren that are in Galilee, for I and Jonathan my brother will go into the country of Galaad." },
  { book: "1 Maccabees", chapter: 5, verse: 18, text: "So he left Joseph the son of Zacharias, and Azarias, captains of the people, with the remnant of the host in Judea to keep it." },
  { book: "1 Maccabees", chapter: 5, verse: 19, text: "Unto whom he gave commandment, saying, Take ye the charge of this people, and see that ye make not war against the heathen until the time that we come again." },
  { book: "1 Maccabees", chapter: 5, verse: 20, text: "Now unto Simon were given three thousand men to go into Galilee, and unto Judas eight thousand men for the country of Galaad." },
  { book: "1 Maccabees", chapter: 5, verse: 21, text: "Then went Simon into Galilee, where he fought many battles with the heathen, so that the heathen were discomfited by him." },
  { book: "1 Maccabees", chapter: 5, verse: 22, text: "And he pursued them unto the gate of Ptolemais; and there were slain of the heathen about three thousand men, whose spoils he took." },
  { book: "1 Maccabees", chapter: 5, verse: 23, text: "And those that were in Galilee, and in Arbattis, with their wives and their children, and all that they had, took he away with him, and brought them into Judea with great joy." },
  { book: "1 Maccabees", chapter: 5, verse: 24, text: "Judas Maccabeus also and his brother Jonathan went over Jordan, and travelled three days’ journey in the wilderness," },
  { book: "1 Maccabees", chapter: 5, verse: 25, text: "Where they met with the Nabathites, who came unto them in a peaceable manner, and told them every thing that had happened to their brethren in the land of Galaad:" },
  { book: "1 Maccabees", chapter: 5, verse: 26, text: "And how that many of them were shut up in Bosora, and Bosor, and Alema, Casphor, Maked, and Carnaim; all these cities are strong and great:" },
  { book: "1 Maccabees", chapter: 5, verse: 27, text: "And that they were shut up in the rest of the cities of the country of Galaad, and that against to morrow they had appointed to bring their host against the forts, and to take them, and to destroy them all in one day." },
  { book: "1 Maccabees", chapter: 5, verse: 28, text: "Hereupon Judas and his host turned suddenly by the way of the wilderness unto Bosora; and when he had won the city, he slew all the males with the edge of the sword, and took all their spoils, and burned the city with fire," },
  { book: "1 Maccabees", chapter: 5, verse: 29, text: "From whence he removed by night, and went till he came to the fortress." },
  { book: "1 Maccabees", chapter: 5, verse: 30, text: "And betimes in the morning they looked up, and, behold, there was an innumerable people bearing ladders and other engines of war, to take the fortress: for they assaulted them." },
  { book: "1 Maccabees", chapter: 5, verse: 31, text: "When Judas therefore saw that the battle was begun, and that the cry of the city went up to heaven, with trumpets, and a great sound," },
  { book: "1 Maccabees", chapter: 5, verse: 32, text: "He said unto his host, Fight this day for your brethren." },
  { book: "1 Maccabees", chapter: 5, verse: 33, text: "So he went forth behind them in three companies, who sounded their trumpets, and cried with prayer." },
  { book: "1 Maccabees", chapter: 5, verse: 34, text: "Then the host of Timotheus, knowing that it was Maccabeus, fled from him: wherefore he smote them with a great slaughter; so that there were killed of them that day about eight thousand men." },
  { book: "1 Maccabees", chapter: 5, verse: 35, text: "This done, Judas turned aside to Maspha; and after he had assaulted it he took and slew all the males therein, and received the spoils thereof and and burnt it with fire." },
  { book: "1 Maccabees", chapter: 5, verse: 36, text: "From thence went he, and took Casphon, Maged, Bosor, and the other cities of the country of Galaad." },
  { book: "1 Maccabees", chapter: 5, verse: 37, text: "After these things gathered Timotheus another host and encamped against Raphon beyond the brook." },
  { book: "1 Maccabees", chapter: 5, verse: 38, text: "So Judas sent men to espy the host, who brought him word, saying, All the heathen that be round about us are assembled unto them, even a very great host." },
  { book: "1 Maccabees", chapter: 5, verse: 39, text: "He hath also hired the Arabians to help them and they have pitched their tents beyond the brook, ready to come and fight against thee. Upon this Judas went to meet them." },
  { book: "1 Maccabees", chapter: 5, verse: 40, text: "Then Timotheus said unto the captains of his host, When Judas and his host come near the brook, if he pass over first unto us, we shall not be able to withstand him; for he will mightily prevail against us:" },
  { book: "1 Maccabees", chapter: 5, verse: 41, text: "But if he be afraid, and camp beyond the river, we shall go over unto him, and prevail against him." },
  { book: "1 Maccabees", chapter: 5, verse: 42, text: "Now when Judas came near the brook, he caused the scribes of the people to remain by the brook: unto whom he gave commandment, saying, Suffer no man to remain in the camp, but let all come to the battle." },
  { book: "1 Maccabees", chapter: 5, verse: 43, text: "So he went first over unto them, and all the people after him: then all the heathen, being discomfited before him, cast away their weapons, and fled unto the temple that was at Carnaim." },
  { book: "1 Maccabees", chapter: 5, verse: 44, text: "But they took the city, and burned the temple with all that were therein. Thus was Carnaim subdued, neither could they stand any longer before Judas." },
  { book: "1 Maccabees", chapter: 5, verse: 45, text: "Then Judas gathered together all the Israelites that were in the country of Galaad, from the least unto the greatest, even their wives, and their children, and their stuff, a very great host, to the end they might come into the land of Judea." },
  { book: "1 Maccabees", chapter: 5, verse: 46, text: "Now when they came unto Ephron, (this was a great city in the way as they should go, very well fortified) they could not turn from it, either on the right hand or the left, but must needs pass through the midst of it." },
  { book: "1 Maccabees", chapter: 5, verse: 47, text: "Then they of the city shut them out, and stopped up the gates with stones." },
  { book: "1 Maccabees", chapter: 5, verse: 48, text: "Whereupon Judas sent unto them in peaceable manner, saying, Let us pass through your land to go into our own country, and none shall do you any hurt; we will only pass through on foot: howbeit they would not open unto him." },
  { book: "1 Maccabees", chapter: 5, verse: 49, text: "Wherefore Judas commanded a proclamation to be made throughout the host, that every man should pitch his tent in the place where he was." },
  { book: "1 Maccabees", chapter: 5, verse: 50, text: "So the soldiers pitched, and assaulted the city all that day and all that night, till at the length the city was delivered into his hands:" },
  { book: "1 Maccabees", chapter: 5, verse: 51, text: "Who then slew all the males with the edge of the sword, and rased the city, and took the spoils thereof, and passed through the city over them that were slain." },
  { book: "1 Maccabees", chapter: 5, verse: 52, text: "After this went they over Jordan into the great plain before Bethsan." },
  { book: "1 Maccabees", chapter: 5, verse: 53, text: "And Judas gathered together those that came behind, and exhorted the people all the way through, till they came into the land of Judea." },
  { book: "1 Maccabees", chapter: 5, verse: 54, text: "So they went up to mount Sion with joy and gladness, where they offered burnt offerings, because not one of them were slain until they had returned in peace." },
  { book: "1 Maccabees", chapter: 5, verse: 55, text: "Now what time as Judas and Jonathan were in the land of Galaad, and Simon his brother in Galilee before Ptolemais," },
  { book: "1 Maccabees", chapter: 5, verse: 56, text: "Joseph the son of Zacharias, and Azarias, captains of the garrisons, heard of the valiant acts and warlike deeds which they had done." },
  { book: "1 Maccabees", chapter: 5, verse: 57, text: "Wherefore they said, Let us also get us a name, and go fight against the heathen that are round about us." },
  { book: "1 Maccabees", chapter: 5, verse: 58, text: "So when they had given charge unto the garrison that was with them, they went toward Jamnia." },
  { book: "1 Maccabees", chapter: 5, verse: 59, text: "Then came Gorgias and his men out of the city to fight against them." },
  { book: "1 Maccabees", chapter: 5, verse: 60, text: "And so it was, that Joseph and Azaras were put to flight, and pursued unto the borders of Judea: and there were slain that day of the people of Israel about two thousand men." },
  { book: "1 Maccabees", chapter: 5, verse: 61, text: "Thus was there a great overthrow among the children of Israel, because they were not obedient unto Judas and his brethren, but thought to do some valiant act." },
  { book: "1 Maccabees", chapter: 5, verse: 62, text: "Moreover these men came not of the seed of those, by whose hand deliverance was given unto Israel." },
  { book: "1 Maccabees", chapter: 5, verse: 63, text: "Howbeit the man Judas and his brethren were greatly renowned in the sight of all Israel, and of all the heathen, wheresoever their name was heard of;" },
  { book: "1 Maccabees", chapter: 5, verse: 64, text: "Insomuch as the the people assembled unto them with joyful acclamations." },
  { book: "1 Maccabees", chapter: 5, verse: 65, text: "Afterward went Judas forth with his brethren, and fought against the children of Esau in the land toward the south, where he smote Hebron, and the towns thereof, and pulled down the fortress of it, and burned the towers thereof round about." },
  { book: "1 Maccabees", chapter: 5, verse: 66, text: "From thence he removed to go into the land of the Philistines, and passed through Samaria." },
  { book: "1 Maccabees", chapter: 5, verse: 67, text: "At that time certain priests, desirous to shew their valour, were slain in battle, for that they went out to fight unadvisedly." },
  { book: "1 Maccabees", chapter: 5, verse: 68, text: "So Judas turned to Azotus in the land of the Philistines, and when he had pulled down their altars, and burned their carved images with fire, and spoiled their cities, he returned into the land of Judea." },
  { book: "1 Maccabees", chapter: 6, verse: 1, text: "About that time king Antiochus travelling through the high countries heard say, that Elymais in the country of Persia was a city greatly renowned for riches, silver, and gold;" },
  { book: "1 Maccabees", chapter: 6, verse: 2, text: "And that there was in it a very rich temple, wherein were coverings of gold, and breastplates, and shields, which Alexander, son of Philip, the Macedonian king, who reigned first among the Grecians, had left there." },
  { book: "1 Maccabees", chapter: 6, verse: 3, text: "Wherefore he came and sought to take the city, and to spoil it; but he was not able, because they of the city, having had warning thereof," },
  { book: "1 Maccabees", chapter: 6, verse: 4, text: "Rose up against him in battle: so he fled, and departed thence with great heaviness, and returned to Babylon." },
  { book: "1 Maccabees", chapter: 6, verse: 5, text: "Moreover there came one who brought him tidings into Persia, that the armies, which went against the land of Judea, were put to flight:" },
  { book: "1 Maccabees", chapter: 6, verse: 6, text: "And that Lysias, who went forth first with a great power was driven away of the Jews; and that they were made strong by the armour, and power, and store of spoils, which they had gotten of the armies, whom they had destroyed:" },
  { book: "1 Maccabees", chapter: 6, verse: 7, text: "Also that they had pulled down the abomination, which he had set up upon the altar in Jerusalem, and that they had compassed about the sanctuary with high walls, as before, and his city Bethsura." },
  { book: "1 Maccabees", chapter: 6, verse: 8, text: "Now when the king heard these words, he was astonished and sore moved: whereupon he laid him down upon his bed, and fell sick for grief, because it had not befallen him as he looked for." },
  { book: "1 Maccabees", chapter: 6, verse: 9, text: "And there he continued many days: for his grief was ever more and more, and he made account that he should die." },
  { book: "1 Maccabees", chapter: 6, verse: 10, text: "Wherefore he called for all his friends, and said unto them, The sleep is gone from mine eyes, and my heart faileth for very care." },
  { book: "1 Maccabees", chapter: 6, verse: 11, text: "And I thought with myself, Into what tribulation am I come, and how great a flood of misery is it, wherein now I am! for I was bountiful and beloved in my power." },
  { book: "1 Maccabees", chapter: 6, verse: 12, text: "But now I remember the evils that I did at Jerusalem, and that I took all the vessels of gold and silver that were therein, and sent to destroy the inhabitants of Judea without a cause." },
  { book: "1 Maccabees", chapter: 6, verse: 13, text: "I perceive therefore that for this cause these troubles are come upon me, and, behold, I perish through great grief in a strange land." },
  { book: "1 Maccabees", chapter: 6, verse: 14, text: "Then called he for Philip, one of his friends, who he made ruler over all his realm," },
  { book: "1 Maccabees", chapter: 6, verse: 15, text: "And gave him the crown, and his robe, and his signet, to the end he should bring up his son Antiochus, and nourish him up for the kingdom." },
  { book: "1 Maccabees", chapter: 6, verse: 16, text: "So king Antiochus died there in the hundred forty and ninth year." },
  { book: "1 Maccabees", chapter: 6, verse: 17, text: "Now when Lysias knew that the king was dead, he set up Antiochus his son, whom he had brought up being young, to reign in his stead, and his name he called Eupator." },
  { book: "1 Maccabees", chapter: 6, verse: 18, text: "About this time they that were in the tower shut up the Israelites round about the sanctuary, and sought always their hurt, and the strengthening of the heathen." },
  { book: "1 Maccabees", chapter: 6, verse: 19, text: "Wherefore Judas, purposing to destroy them, called all the people together to besiege them." },
  { book: "1 Maccabees", chapter: 6, verse: 20, text: "So they came together, and besieged them in the hundred and fiftieth year, and he made mounts for shot against them, and other engines." },
  { book: "1 Maccabees", chapter: 6, verse: 21, text: "Howbeit certain of them that were besieged got forth, unto whom some ungodly men of Israel joined themselves:" },
  { book: "1 Maccabees", chapter: 6, verse: 22, text: "And they went unto the king, and said, How long will it be ere thou execute judgment, and avenge our brethren?" },
  { book: "1 Maccabees", chapter: 6, verse: 23, text: "We have been willing to serve thy father, and to do as he would have us, and to obey his commandments;" },
  { book: "1 Maccabees", chapter: 6, verse: 24, text: "For which cause they of our nation besiege the tower, and are alienated from us: moreover as many of us as they could light on they slew, and spoiled our inheritance." },
  { book: "1 Maccabees", chapter: 6, verse: 25, text: "Neither have they stretched out their hand against us only, but also against their borders." },
  { book: "1 Maccabees", chapter: 6, verse: 26, text: "And, behold, this day are they besieging the tower at Jerusalem, to take it: the sanctuary also and Bethsura have they fortified." },
  { book: "1 Maccabees", chapter: 6, verse: 27, text: "Wherefore if thou dost not prevent them quickly, they will do the greater things than these, neither shalt thou be able to rule them." },
  { book: "1 Maccabees", chapter: 6, verse: 28, text: "Now when the king heard this, he was angry, and gathered together all his friends, and the captains of his army, and those that had charge of the horse." },
  { book: "1 Maccabees", chapter: 6, verse: 29, text: "There came also unto him from other kingdoms, and from isles of the sea, bands of hired soldiers." },
  { book: "1 Maccabees", chapter: 6, verse: 30, text: "So that the number of his army was an hundred thousand footmen, and twenty thousand horsemen, and two and thirty elephants exercised in battle." },
  { book: "1 Maccabees", chapter: 6, verse: 31, text: "These went through Idumea, and pitched against Bethsura, which they assaulted many days, making engines of war; but they of Bethsura came out, and burned them with fire, and fought valiantly." },
  { book: "1 Maccabees", chapter: 6, verse: 32, text: "Upon this Judas removed from the tower, and pitched in Bathzacharias, over against the king’s camp." },
  { book: "1 Maccabees", chapter: 6, verse: 33, text: "Then the king rising very early marched fiercely with his host toward Bathzacharias, where his armies made them ready to battle, and sounded the trumpets." },
  { book: "1 Maccabees", chapter: 6, verse: 34, text: "And to the end they might provoke the elephants to fight, they shewed them the blood of grapes and mulberries." },
  { book: "1 Maccabees", chapter: 6, verse: 35, text: "Moreover they divided the beasts among the armies, and for every elephant they appointed a thousand men, armed with coats of mail, and with helmets of brass on their heads; and beside this, for every beast were ordained five hundred horsemen of the best." },
  { book: "1 Maccabees", chapter: 6, verse: 36, text: "These were ready at every occasion: wheresoever the beast was, and whithersoever the beast went, they went also, neither departed they from him." },
  { book: "1 Maccabees", chapter: 6, verse: 37, text: "And upon the beasts were there strong towers of wood, which covered every one of them, and were girt fast unto them with devices: there were also upon every one two and thirty strong men, that fought upon them, beside the Indian that ruled him." },
  { book: "1 Maccabees", chapter: 6, verse: 38, text: "As for the remnant of the horsemen, they set them on this side and that side at the two parts of the host giving them signs what to do, and being harnessed all over amidst the ranks." },
  { book: "1 Maccabees", chapter: 6, verse: 39, text: "Now when the sun shone upon the shields of gold and brass, the mountains glistered therewith, and shined like lamps of fire." },
  { book: "1 Maccabees", chapter: 6, verse: 40, text: "So part of the king’s army being spread upon the high mountains, and part on the valleys below, they marched on safely and in order." },
  { book: "1 Maccabees", chapter: 6, verse: 41, text: "Wherefore all that heard the noise of their multitude, and the marching of the company, and the rattling of the harness, were moved: for the army was very great and mighty." },
  { book: "1 Maccabees", chapter: 6, verse: 42, text: "Then Judas and his host drew near, and entered into battle, and there were slain of the king’s army six hundred men." },
  { book: "1 Maccabees", chapter: 6, verse: 43, text: "Eleazar also, surnamed Savaran, perceiving that one of the beasts, armed with royal harness, was higher than all the rest, and supposing that the king was upon him," },
  { book: "1 Maccabees", chapter: 6, verse: 44, text: "Put himself in jeopardy, to the end he might deliver his people, and get him a perpetual name:" },
  { book: "1 Maccabees", chapter: 6, verse: 45, text: "Wherefore he ran upon him courageously through the midst of the battle, slaying on the right hand and on the left, so that they were divided from him on both sides." },
  { book: "1 Maccabees", chapter: 6, verse: 46, text: "Which done, he crept under the elephant, and thrust him under, and slew him: whereupon the elephant fell down upon him, and there he died." },
  { book: "1 Maccabees", chapter: 6, verse: 47, text: "Howbeit the rest of the Jews seeing the strength of the king, and the violence of his forces, turned away from them." },
  { book: "1 Maccabees", chapter: 6, verse: 48, text: "Then the king’s army went up to Jerusalem to meet them, and the king pitched his tents against Judea, and against mount Sion." },
  { book: "1 Maccabees", chapter: 6, verse: 49, text: "But with them that were in Bethsura he made peace: for they came out of the city, because they had no victuals there to endure the siege, it being a year of rest to the land." },
  { book: "1 Maccabees", chapter: 6, verse: 50, text: "So the king took Bethsura, and set a garrison there to keep it." },
  { book: "1 Maccabees", chapter: 6, verse: 51, text: "As for the sanctuary, he besieged it many days: and set there artillery with engines and instruments to cast fire and stones, and pieces to cast darts and slings." },
  { book: "1 Maccabees", chapter: 6, verse: 52, text: "Whereupon they also made engines against their engines, and held them battle a long season." },
  { book: "1 Maccabees", chapter: 6, verse: 53, text: "Yet at the last, their vessels being without victuals, (for that it was the seventh year, and they in Judea that were delivered from the Gentiles, had eaten up the residue of the store;)" },
  { book: "1 Maccabees", chapter: 6, verse: 54, text: "There were but a few left in the sanctuary, because the famine did so prevail against them, that they were fain to disperse themselves, every man to his own place." },
  { book: "1 Maccabees", chapter: 6, verse: 55, text: "At that time Lysias heard say, that Philip, whom Antiochus the king, whiles he lived, had appointed to bring up his son Antiochus, that he might be king," },
  { book: "1 Maccabees", chapter: 6, verse: 56, text: "Was returned out of Persia and Media, and the king’s host also that went with him, and that he sought to take unto him the ruling of the affairs." },
  { book: "1 Maccabees", chapter: 6, verse: 57, text: "Wherefore he went in all haste, and said to the king and the captains of the host and the company, We decay daily, and our victuals are but small, and the place we lay siege unto is strong, and the affairs of the kingdom lie upon us:" },
  { book: "1 Maccabees", chapter: 6, verse: 58, text: "Now therefore let us be friends with these men, and make peace with them, and with all their nation;" },
  { book: "1 Maccabees", chapter: 6, verse: 59, text: "And covenant with them, that they shall live after their laws, as they did before: for they are therefore displeased, and have done all these things, because we abolished their laws." },
  { book: "1 Maccabees", chapter: 6, verse: 60, text: "So the king and the princes were content: wherefore he sent unto them to make peace; and they accepted thereof." },
  { book: "1 Maccabees", chapter: 6, verse: 61, text: "Also the king and the princes made an oath unto them: whereupon they went out of the strong hold." },
  { book: "1 Maccabees", chapter: 6, verse: 62, text: "Then the king entered into mount Sion; but when he saw the strength of the place, he broke his oath that he had made, and gave commandment to pull down the wall round about." },
  { book: "1 Maccabees", chapter: 6, verse: 63, text: "Afterward departed he in all haste, and returned unto Antiochia, where he found Philip to be master of the city: so he fought against him, and took the city by force." },
  { book: "1 Maccabees", chapter: 7, verse: 1, text: "In the hundred and one and fiftieth year Demetrius the son of Seleucus departed from Rome, and came up with a few men unto a city of the sea coast, and reigned there." },
  { book: "1 Maccabees", chapter: 7, verse: 2, text: "And as he entered into the palace of his ancestors, so it was, that his forces had taken Antiochus and Lysias, to bring them unto him." },
  { book: "1 Maccabees", chapter: 7, verse: 3, text: "Wherefore, when he knew it, he said, Let me not see their faces." },
  { book: "1 Maccabees", chapter: 7, verse: 4, text: "So his host slew them. Now when Demetrius was set upon the throne of his kingdom," },
  { book: "1 Maccabees", chapter: 7, verse: 5, text: "There came unto him all the wicked and ungodly men of Israel, having Alcimus, who was desirous to be high priest, for their captain:" },
  { book: "1 Maccabees", chapter: 7, verse: 6, text: "And they accused the people to the king, saying, Judas and his brethren have slain all thy friends, and driven us out of our own land." },
  { book: "1 Maccabees", chapter: 7, verse: 7, text: "Now therefore send some man whom thou trustest, and let him go and see what havock he hath made among us, and in the king’s land, and let him punish them with all them that aid them." },
  { book: "1 Maccabees", chapter: 7, verse: 8, text: "Then the king chose Bacchides, a friend of the king, who ruled beyond the flood, and was a great man in the kingdom, and faithful to the king," },
  { book: "1 Maccabees", chapter: 7, verse: 9, text: "And him he sent with that wicked Alcimus, whom he made high priest, and commanded that he should take vengeance of the children of Israel." },
  { book: "1 Maccabees", chapter: 7, verse: 10, text: "So they departed, and came with a great power into the land of Judea, where they sent messengers to Judas and his brethren with peaceable words deceitfully." },
  { book: "1 Maccabees", chapter: 7, verse: 11, text: "But they gave no heed to their words; for they saw that they were come with a great power." },
  { book: "1 Maccabees", chapter: 7, verse: 12, text: "Then did there assemble unto Alcimus and Bacchides a company of scribes, to require justice." },
  { book: "1 Maccabees", chapter: 7, verse: 13, text: "Now the Assideans were the first among the children of Israel that sought peace of them:" },
  { book: "1 Maccabees", chapter: 7, verse: 14, text: "For said they, One that is a priest of the seed of Aaron is come with this army, and he will do us no wrong." },
  { book: "1 Maccabees", chapter: 7, verse: 15, text: "So he spake unto them, peaceably, and sware unto them, saying, we will procure the harm neither of you nor your friends." },
  { book: "1 Maccabees", chapter: 7, verse: 16, text: "Whereupon they believed him: howbeit he took of them threescore men, and slew them in one day, according to the words which he wrote," },
  { book: "1 Maccabees", chapter: 7, verse: 17, text: "The flesh of thy saints have they cast out, and their blood have they shed round about Jerusalem, and there was none to bury them." },
  { book: "1 Maccabees", chapter: 7, verse: 18, text: "Wherefore the fear and dread of them fell upon all the people, who said, There is neither truth nor righteousness in them; for they have broken the covenant and oath that they made." },
  { book: "1 Maccabees", chapter: 7, verse: 19, text: "After this, removed Bacchides from Jerusalem, and pitched his tents in Bezeth, where he sent and took many of the men that had forsaken him, and certain of the people also, and when he had slain them, he cast them into the great pit." },
  { book: "1 Maccabees", chapter: 7, verse: 20, text: "Then committed he the country to Alcimus, and left with him a power to aid him: so Bacchides went to the king." },
  { book: "1 Maccabees", chapter: 7, verse: 21, text: "But Alcimus contended for the high priesthood." },
  { book: "1 Maccabees", chapter: 7, verse: 22, text: "And unto him resorted all such as troubled the people, who, after they had gotten the land of Juda into their power, did much hurt in Israel." },
  { book: "1 Maccabees", chapter: 7, verse: 23, text: "Now when Judas saw all the mischief that Alcimus and his company had done among the Israelites, even above the heathen," },
  { book: "1 Maccabees", chapter: 7, verse: 24, text: "He went out into all the coasts of Judea round about, and took vengeance of them that had revolted from him, so that they durst no more go forth into the country." },
  { book: "1 Maccabees", chapter: 7, verse: 25, text: "On the other side, when Alcimus saw that Judas and his company had gotten the upper hand, and knew that he was not able to abide their force, he went again to the king, and said all the worst of them that he could." },
  { book: "1 Maccabees", chapter: 7, verse: 26, text: "Then the king sent Nicanor, one of his honourable princes, a man that bare deadly hate unto Israel, with commandment to destroy the people." },
  { book: "1 Maccabees", chapter: 7, verse: 27, text: "So Nicanor came to Jerusalem with a great force; and sent unto Judas and his brethren deceitfully with friendly words, saying," },
  { book: "1 Maccabees", chapter: 7, verse: 28, text: "Let there be no battle between me and you; I will come with a few men, that I may see you in peace." },
  { book: "1 Maccabees", chapter: 7, verse: 29, text: "He came therefore to Judas, and they saluted one another peaceably. Howbeit the enemies were prepared to take away Judas by violence." },
  { book: "1 Maccabees", chapter: 7, verse: 30, text: "Which thing after it was known to Judas, to wit, that he came unto him with deceit, he was sore afraid of him, and would see his face no more." },
  { book: "1 Maccabees", chapter: 7, verse: 31, text: "Nicanor also, when he saw that his counsel was discovered, went out to fight against Judas beside Capharsalama:" },
  { book: "1 Maccabees", chapter: 7, verse: 32, text: "Where there were slain of Nicanor’s side about five thousand men, and the rest fled into the city of David." },
  { book: "1 Maccabees", chapter: 7, verse: 33, text: "After this went Nicanor up to mount Sion, and there came out of the sanctuary certain of the priests and certain of the elders of the people, to salute him peaceably, and to shew him the burnt sacrifice that was offered for the king." },
  { book: "1 Maccabees", chapter: 7, verse: 34, text: "But he mocked them, and laughed at them, and abused them shamefully, and spake proudly," },
  { book: "1 Maccabees", chapter: 7, verse: 35, text: "And sware in his wrath, saying, Unless Judas and his host be now delivered into my hands, if ever I come again in safety, I will burn up this house: and with that he went out in a great rage." },
  { book: "1 Maccabees", chapter: 7, verse: 36, text: "Then the priests entered in, and stood before the altar and the temple, weeping, and saying," },
  { book: "1 Maccabees", chapter: 7, verse: 37, text: "Thou, O Lord, didst choose this house to be called by thy name, and to be a house of prayer and petition for thy people:" },
  { book: "1 Maccabees", chapter: 7, verse: 38, text: "Be avenged of this man and his host, and let them fall by the sword: remember their blasphemies, and suffer them not to continue any longer." },
  { book: "1 Maccabees", chapter: 7, verse: 39, text: "So Nicanor went out of Jerusalem, and pitched his tents in Bethhoron, where an host out of Syria met him." },
  { book: "1 Maccabees", chapter: 7, verse: 40, text: "But Judas pitched in Adasa with three thousand men, and there he prayed, saying," },
  { book: "1 Maccabees", chapter: 7, verse: 41, text: "O Lord, when they that were sent from the king of the Assyrians blasphemed, thine angel went out, and smote an hundred fourscore and five thousand of them." },
  { book: "1 Maccabees", chapter: 7, verse: 42, text: "Even so destroy thou this host before us this day, that the rest may know that he hath spoken blasphemously against thy sanctuary, and judge thou him according to his wickedness." },
  { book: "1 Maccabees", chapter: 7, verse: 43, text: "So the thirteenth day of the month Adar the hosts joined battle: but Nicanor’s host was discomfited, and he himself was first slain in the battle." },
  { book: "1 Maccabees", chapter: 7, verse: 44, text: "Now when Nicanor’s host saw that he was slain, they cast away their weapons, and fled." },
  { book: "1 Maccabees", chapter: 7, verse: 45, text: "Then they pursued after them a day’s journey, from Adasa unto Gazera, sounding an alarm after them with their trumpets." },
  { book: "1 Maccabees", chapter: 7, verse: 46, text: "Whereupon they came forth out of all the towns of Judea round about, and closed them in; so that they, turning back upon them that pursued them, were all slain with the sword, and not one of them was left." },
  { book: "1 Maccabees", chapter: 7, verse: 47, text: "Afterwards they took the spoils, and the prey, and smote off Nicanors head, and his right hand, which he stretched out so proudly, and brought them away, and hanged them up toward Jerusalem." },
  { book: "1 Maccabees", chapter: 7, verse: 48, text: "For this cause the people rejoiced greatly, and they kept that day a day of great gladness." },
  { book: "1 Maccabees", chapter: 7, verse: 49, text: "Moreover they ordained to keep yearly this day, being the thirteenth of Adar." },
  { book: "1 Maccabees", chapter: 7, verse: 50, text: "Thus the land of Juda was in rest a little while." },
  { book: "1 Maccabees", chapter: 8, verse: 1, text: "Now Judas had heard of the the Romans, that they were mighty and valiant men, and such as would lovingly accept all that joined themselves unto them, and make a league of amity with all that came unto them;" },
  { book: "1 Maccabees", chapter: 8, verse: 2, text: "And that they were men of great valour. It was told him also of their wars and noble acts which they had done among the Galatians, and how they had conquered them, and brought them under tribute;" },
  { book: "1 Maccabees", chapter: 8, verse: 3, text: "And what they had done in the country of Spain, for the winning of the mines of the silver and gold which is there;" },
  { book: "1 Maccabees", chapter: 8, verse: 4, text: "And that by their policy and patience they had conquered all the place, though it were very far from them; and the kings also that came against them from the uttermost part of the earth, till they had discomfited them, and given them a great overthrow, so that the rest did give them tribute every year:" },
  { book: "1 Maccabees", chapter: 8, verse: 5, text: "Beside this, how they had discomfited in battle Philip, and Perseus, king of the Citims, with others that lifted up themselves against them, and had overcome them:" },
  { book: "1 Maccabees", chapter: 8, verse: 6, text: "How also Antiochus the great king of Asia, that came against them in battle, having an hundred and twenty elephants, with horsemen, and chariots, and a very great army, was discomfited by them;" },
  { book: "1 Maccabees", chapter: 8, verse: 7, text: "And how they took him alive, and covenanted that he and such as reigned after him should pay a great tribute, and give hostages, and that which was agreed upon," },
  { book: "1 Maccabees", chapter: 8, verse: 8, text: "And the country of India, and Media and Lydia and of the goodliest countries, which they took of him, and gave to king Eumenes:" },
  { book: "1 Maccabees", chapter: 8, verse: 9, text: "Moreover how the Grecians had determined to come and destroy them;" },
  { book: "1 Maccabees", chapter: 8, verse: 10, text: "And that they, having knowledge thereof sent against them a certain captain, and fighting with them slew many of them, and carried away captives their wives and their children, and spoiled them, and took possession of their lands, and pulled down their strong holds, and brought them to be their servants unto this day:" },
  { book: "1 Maccabees", chapter: 8, verse: 11, text: "It was told him besides, how they destroyed and brought under their dominion all other kingdoms and isles that at any time resisted them;" },
  { book: "1 Maccabees", chapter: 8, verse: 12, text: "But with their friends and such as relied upon them they kept amity: and that they had conquered kingdoms both far and nigh, insomuch as all that heard of their name were afraid of them:" },
  { book: "1 Maccabees", chapter: 8, verse: 13, text: "Also that, whom they would help to a kingdom, those reign; and whom again they would, they displace: finally, that they were greatly exalted:" },
  { book: "1 Maccabees", chapter: 8, verse: 14, text: "Yet for all this none of them wore a crown or was clothed in purple, to be magnified thereby:" },
  { book: "1 Maccabees", chapter: 8, verse: 15, text: "Moreover how they had made for themselves a senate house, wherein three hundred and twenty men sat in council daily, consulting alway for the people, to the end they might be well ordered:" },
  { book: "1 Maccabees", chapter: 8, verse: 16, text: "And that they committed their government to one man every year, who ruled over all their country, and that all were obedient to that one, and that there was neither envy nor emulation among them." },
  { book: "1 Maccabees", chapter: 8, verse: 17, text: "In consideration of these things, Judas chose Eupolemus the son of John, the son of Accos, and Jason the son of Eleazar, and sent them to Rome, to make a league of amity and confederacy with them," },
  { book: "1 Maccabees", chapter: 8, verse: 18, text: "And to intreat them that they would take the yoke from them; for they saw that the kingdom of the Grecians did oppress Israel with servitude." },
  { book: "1 Maccabees", chapter: 8, verse: 19, text: "They went therefore to Rome, which was a very great journey, and came into the senate, where they spake and said." },
  { book: "1 Maccabees", chapter: 8, verse: 20, text: "Judas Maccabeus with his brethren, and the people of the Jews, have sent us unto you, to make a confederacy and peace with you, and that we might be registered your confederates and friends." },
  { book: "1 Maccabees", chapter: 8, verse: 21, text: "So that matter pleased the Romans well." },
  { book: "1 Maccabees", chapter: 8, verse: 22, text: "And this is the copy of the epistle which the senate wrote back again in tables of brass, and sent to Jerusalem, that there they might have by them a memorial of peace and confederacy:" },
  { book: "1 Maccabees", chapter: 8, verse: 23, text: "Good success be to the Romans, and to the people of the Jews, by sea and by land for ever: the sword also and enemy be far from them," },
  { book: "1 Maccabees", chapter: 8, verse: 24, text: "If there come first any war upon the Romans or any of their confederates throughout all their dominion," },
  { book: "1 Maccabees", chapter: 8, verse: 25, text: "The people of the Jews shall help them, as the time shall be appointed, with all their heart:" },
  { book: "1 Maccabees", chapter: 8, verse: 26, text: "Neither shall they give any thing unto them that make war upon them, or aid them with victuals, weapons, money, or ships, as it hath seemed good unto the Romans; but they shall keep their covenants without taking any thing therefore." },
  { book: "1 Maccabees", chapter: 8, verse: 27, text: "In the same manner also, if war come first upon the nation of the Jews, the Romans shall help them with all their heart, according as the time shall be appointed them:" },
  { book: "1 Maccabees", chapter: 8, verse: 28, text: "Neither shall victuals be given to them that take part against them, or weapons, or money, or ships, as it hath seemed good to the Romans; but they shall keep their covenants, and that without deceit." },
  { book: "1 Maccabees", chapter: 8, verse: 29, text: "According to these articles did the Romans make a covenant with the people of the Jews." },
  { book: "1 Maccabees", chapter: 8, verse: 30, text: "Howbeit if hereafter the one party or the other shall think to meet to add or diminish any thing, they may do it at their pleasures, and whatsoever they shall add or take away shall be ratified." },
  { book: "1 Maccabees", chapter: 8, verse: 31, text: "And as touching the evils that Demetrius doeth to the Jews, we have written unto him, saying, Wherefore thou made thy yoke heavy upon our friends and confederates the Jews?" },
  { book: "1 Maccabees", chapter: 8, verse: 32, text: "If therefore they complain any more against thee, we will do them justice, and fight with thee by sea and by land." },
  { book: "1 Maccabees", chapter: 9, verse: 1, text: "Furthermore, when Demetrius heard the Nicanor and his host were slain in battle, he sent Bacchides and Alcimus into the land of Judea the second time, and with them the chief strength of his host:" },
  { book: "1 Maccabees", chapter: 9, verse: 2, text: "Who went forth by the way that leadeth to Galgala, and pitched their tents before Masaloth, which is in Arbela, and after they had won it, they slew much people." },
  { book: "1 Maccabees", chapter: 9, verse: 3, text: "Also the first month of the hundred fifty and second year they encamped before Jerusalem:" },
  { book: "1 Maccabees", chapter: 9, verse: 4, text: "From whence they removed, and went to Berea, with twenty thousand footmen and two thousand horsemen." },
  { book: "1 Maccabees", chapter: 9, verse: 5, text: "Now Judas had pitched his tents at Eleasa, and three thousand chosen men with him:" },
  { book: "1 Maccabees", chapter: 9, verse: 6, text: "Who seeing the multitude of the other army to he so great were sore afraid; whereupon many conveyed themselves out of the host, insomuch as abode of them no more but eight hundred men." },
  { book: "1 Maccabees", chapter: 9, verse: 7, text: "When Judas therefore saw that his host slipt away, and that the battle pressed upon him, he was sore troubled in mind, and much distressed, for that he had no time to gather them together." },
  { book: "1 Maccabees", chapter: 9, verse: 8, text: "Nevertheless unto them that remained he said, Let us arise and go up against our enemies, if peradventure we may be able to fight with them." },
  { book: "1 Maccabees", chapter: 9, verse: 9, text: "But they dehorted him, saying, We shall never be able: let us now rather save our lives, and hereafter we will return with our brethren, and fight against them: for we are but few." },
  { book: "1 Maccabees", chapter: 9, verse: 10, text: "Then Judas said, God forbid that I should do this thing, and flee away from them: if our time be come, let us die manfully for our brethren, and let us not stain our honour." },
  { book: "1 Maccabees", chapter: 9, verse: 11, text: "With that the host of Bacchides removed out of their tents, and stood over against them, their horsemen being divided into two troops, and their slingers and archers going before the host and they that marched in the foreward were all mighty men." },
  { book: "1 Maccabees", chapter: 9, verse: 12, text: "As for Bacchides, he was in the right wing: so the host drew near on the two parts, and sounded their trumpets." },
  { book: "1 Maccabees", chapter: 9, verse: 13, text: "They also of Judas’ side, even they sounded their trumpets also, so that the earth shook at the noise of the armies, and the battle continued from morning till night." },
  { book: "1 Maccabees", chapter: 9, verse: 14, text: "Now when Judas perceived that Bacchides and the strength of his army were on the right side, he took with him all the hardy men," },
  { book: "1 Maccabees", chapter: 9, verse: 15, text: "Who discomfited the right wing, and pursued them unto the mount Azotus." },
  { book: "1 Maccabees", chapter: 9, verse: 16, text: "But when they of the left wing saw that they of the right wing were discomfited, they followed upon Judas and those that were with him hard at the heels from behind:" },
  { book: "1 Maccabees", chapter: 9, verse: 17, text: "Whereupon there was a sore battle, insomuch as many were slain on both parts." },
  { book: "1 Maccabees", chapter: 9, verse: 18, text: "Judas also was killed, and the remnant fled." },
  { book: "1 Maccabees", chapter: 9, verse: 19, text: "Then Jonathan and Simon took Judas their brother, and buried him in the sepulchre of his fathers in Modin." },
  { book: "1 Maccabees", chapter: 9, verse: 20, text: "Moreover they bewailed him, and all Israel made great lamentation for him, and mourned many days, saying," },
  { book: "1 Maccabees", chapter: 9, verse: 21, text: "How is the valiant man fallen, that delivered Israel!" },
  { book: "1 Maccabees", chapter: 9, verse: 22, text: "As for the other things concerning Judas and his wars, and the noble acts which he did, and his greatness, they are not written: for they were very many." },
  { book: "1 Maccabees", chapter: 9, verse: 23, text: "Now after the death of Judas the wicked began to put forth their heads in all the coasts of Israel, and there arose up all such as wrought iniquity." },
  { book: "1 Maccabees", chapter: 9, verse: 24, text: "In those days also was there a very great famine, by reason whereof the country revolted, and went with them." },
  { book: "1 Maccabees", chapter: 9, verse: 25, text: "Then Bacchides chose the wicked men, and made them lords of the country." },
  { book: "1 Maccabees", chapter: 9, verse: 26, text: "And they made enquiry and search for Judas’ friends, and brought them unto Bacchides, who took vengeance of them, and used them despitefully." },
  { book: "1 Maccabees", chapter: 9, verse: 27, text: "So was there a great affliction in Israel, the like whereof was not since the time that a prophet was not seen among them." },
  { book: "1 Maccabees", chapter: 9, verse: 28, text: "For this cause all Judas’ friends came together, and said unto Jonathan," },
  { book: "1 Maccabees", chapter: 9, verse: 29, text: "Since thy brother Judas died, we have no man like him to go forth against our enemies, and Bacchides, and against them of our nation that are adversaries to us." },
  { book: "1 Maccabees", chapter: 9, verse: 30, text: "Now therefore we have chosen thee this day to be our prince and captain in his stead, that thou mayest fight our battles." },
  { book: "1 Maccabees", chapter: 9, verse: 31, text: "Upon this Jonathan took the governance upon him at that time, and rose up instead of his brother Judas." },
  { book: "1 Maccabees", chapter: 9, verse: 32, text: "But when Bacchides gat knowledge thereof, he sought for to slay him" },
  { book: "1 Maccabees", chapter: 9, verse: 33, text: "Then Jonathan, and Simon his brother, and all that were with him, perceiving that, fled into the wilderness of Thecoe, and pitched their tents by the water of the pool Asphar." },
  { book: "1 Maccabees", chapter: 9, verse: 34, text: "Which when Bacchides understood, he came near to Jordan with all his host upon the sabbath day." },
  { book: "1 Maccabees", chapter: 9, verse: 35, text: "Now Jonathan had sent his brother John, a captain of the people, to pray his friends the Nabathites, that they might leave with them their carriage, which was much." },
  { book: "1 Maccabees", chapter: 9, verse: 36, text: "But the children of Jambri came out of Medaba, and took John, and all that he had, and went their way with it." },
  { book: "1 Maccabees", chapter: 9, verse: 37, text: "After this came word to Jonathan and Simon his brother, that the children of Jambri made a great marriage, and were bringing the bride from Nadabatha with a great train, as being the daughter of one of the great princes of Chanaan." },
  { book: "1 Maccabees", chapter: 9, verse: 38, text: "Therefore they remembered John their brother, and went up, and hid themselves under the covert of the mountain:" },
  { book: "1 Maccabees", chapter: 9, verse: 39, text: "Where they lifted up their eyes, and looked, and, behold, there was much ado and great carriage: and the bridegroom came forth, and his friends and brethren, to meet them with drums, and instruments of musick, and many weapons." },
  { book: "1 Maccabees", chapter: 9, verse: 40, text: "Then Jonathan and they that were with him rose up against them from the place where they lay in ambush, and made a slaughter of them in such sort, as many fell down dead, and the remnant fled into the mountain, and they took all their spoils." },
  { book: "1 Maccabees", chapter: 9, verse: 41, text: "Thus was the marriage turned into mourning, and the noise of their melody into lamentation." },
  { book: "1 Maccabees", chapter: 9, verse: 42, text: "So when they had avenged fully the blood of their brother, they turned again to the marsh of Jordan." },
  { book: "1 Maccabees", chapter: 9, verse: 43, text: "Now when Bacchides heard hereof, he came on the sabbath day unto the banks of Jordan with a great power." },
  { book: "1 Maccabees", chapter: 9, verse: 44, text: "Then Jonathan said to his company, Let us go up now and fight for our lives, for it standeth not with us to day, as in time past:" },
  { book: "1 Maccabees", chapter: 9, verse: 45, text: "For, behold, the battle is before us and behind us, and the water of Jordan on this side and that side, the marsh likewise and wood, neither is there place for us to turn aside." },
  { book: "1 Maccabees", chapter: 9, verse: 46, text: "Wherefore cry ye now unto heaven, that ye may be delivered from the hand of your enemies." },
  { book: "1 Maccabees", chapter: 9, verse: 47, text: "With that they joined battle, and Jonathan stretched forth his hand to smite Bacchides, but he turned back from him." },
  { book: "1 Maccabees", chapter: 9, verse: 48, text: "Then Jonathan and they that were with him leapt into Jordan, and swam over unto the other bank: howbeit the other passed not over Jordan unto them." },
  { book: "1 Maccabees", chapter: 9, verse: 49, text: "So there were slain of Bacchides’ side that day about a thousand men." },
  { book: "1 Maccabees", chapter: 9, verse: 50, text: "Afterward returned Bacchides to Jerusalem and repaired the strong cites in Judea; the fort in Jericho, and Emmaus, and Bethhoron, and Bethel, and Thamnatha, Pharathoni, and Taphon, these did he strengthen with high walls, with gates and with bars." },
  { book: "1 Maccabees", chapter: 9, verse: 51, text: "And in them he set a garrison, that they might work malice upon Israel." },
  { book: "1 Maccabees", chapter: 9, verse: 52, text: "He fortified also the city Bethsura, and Gazera, and the tower, and put forces in them, and provision of victuals." },
  { book: "1 Maccabees", chapter: 9, verse: 53, text: "Besides, he took the chief men’s sons in the country for hostages, and put them into the tower at Jerusalem to be kept." },
  { book: "1 Maccabees", chapter: 9, verse: 54, text: "Moreover in the hundred fifty and third year, in the second month, Alcimus commanded that the wall of the inner court of the sanctuary should be pulled down; he pulled down also the works of the prophets" },
  { book: "1 Maccabees", chapter: 9, verse: 55, text: "And as he began to pull down, even at that time was Alcimus plagued, and his enterprizes hindered: for his mouth was stopped, and he was taken with a palsy, so that he could no more speak any thing, nor give order concerning his house." },
  { book: "1 Maccabees", chapter: 9, verse: 56, text: "So Alcimus died at that time with great torment." },
  { book: "1 Maccabees", chapter: 9, verse: 57, text: "Now when Bacchides saw that Alcimus was dead, he returned to the king: whereupon the land of Judea was in rest two years." },
  { book: "1 Maccabees", chapter: 9, verse: 58, text: "Then all the ungodly men held a council, saying, Behold, Jonathan and his company are at ease, and dwell without care: now therefore we will bring Bacchides hither, who shall take them all in one night." },
  { book: "1 Maccabees", chapter: 9, verse: 59, text: "So they went and consulted with him." },
  { book: "1 Maccabees", chapter: 9, verse: 60, text: "Then removed he, and came with a great host, and sent letters privily to his adherents in Judea, that they should take Jonathan and those that were with him: howbeit they could not, because their counsel was known unto them." },
  { book: "1 Maccabees", chapter: 9, verse: 61, text: "Wherefore they took of the men of the country, that were authors of that mischief, about fifty persons, and slew them." },
  { book: "1 Maccabees", chapter: 9, verse: 62, text: "Afterward Jonathan, and Simon, and they that were with him, got them away to Bethbasi, which is in the wilderness, and they repaired the decays thereof, and made it strong." },
  { book: "1 Maccabees", chapter: 9, verse: 63, text: "Which thing when Bacchides knew, he gathered together all his host, and sent word to them that were of Judea." },
  { book: "1 Maccabees", chapter: 9, verse: 64, text: "Then went he and laid siege against Bethbasi; and they fought against it a long season and made engines of war." },
  { book: "1 Maccabees", chapter: 9, verse: 65, text: "But Jonathan left his brother Simon in the city, and went forth himself into the country, and with a certain number went he forth." },
  { book: "1 Maccabees", chapter: 9, verse: 66, text: "And he smote Odonarkes and his brethren, and the children of Phasiron in their tent." },
  { book: "1 Maccabees", chapter: 9, verse: 67, text: "And when he began to smite them, and came up with his forces, Simon and his company went out of the city, and burned up the engines of war," },
  { book: "1 Maccabees", chapter: 9, verse: 68, text: "And fought against Bacchides, who was discomfited by them, and they afflicted him sore: for his counsel and travail was in vain." },
  { book: "1 Maccabees", chapter: 9, verse: 69, text: "Wherefore he was very wroth at the wicked men that gave him counsel to come into the country, inasmuch as he slew many of them, and purposed to return into his own country." },
  { book: "1 Maccabees", chapter: 9, verse: 70, text: "Whereof when Jonathan had knowledge, he sent ambassadors unto him, to the end he should make peace with him, and deliver them the prisoners." },
  { book: "1 Maccabees", chapter: 9, verse: 71, text: "Which thing he accepted, and did according to his demands, and sware unto him that he would never do him harm all the days of his life." },
  { book: "1 Maccabees", chapter: 9, verse: 72, text: "When therefore he had restored unto him the prisoners that he had taken aforetime out of the land of Judea, he returned and went his way into his own land, neither came he any more into their borders." },
  { book: "1 Maccabees", chapter: 9, verse: 73, text: "Thus the sword ceased from Israel: but Jonathan dwelt at Machmas, and began to govern the people; and he destroyed the ungodly men out of Israel." },
  { book: "1 Maccabees", chapter: 10, verse: 1, text: "In the hundred and sixtieth year Alexander, the son of Antiochus surnamed Epiphanes, went up and took Ptolemais: for the people had received him, by means whereof he reigned there," },
  { book: "1 Maccabees", chapter: 10, verse: 2, text: "Now when king Demetrius heard thereof, he gathered together an exceeding great host, and went forth against him to fight." },
  { book: "1 Maccabees", chapter: 10, verse: 3, text: "Moreover Demetrius sent letters unto Jonathan with loving words, so as he magnified him." },
  { book: "1 Maccabees", chapter: 10, verse: 4, text: "For said he, Let us first make peace with him, before he join with Alexander against us:" },
  { book: "1 Maccabees", chapter: 10, verse: 5, text: "Else he will remember all the evils that we have done against him, and against his brethren and his people." },
  { book: "1 Maccabees", chapter: 10, verse: 6, text: "Wherefore he gave him authority to gather together an host, and to provide weapons, that he might aid him in battle: he commanded also that the hostages that were in the tower should be delivered him." },
  { book: "1 Maccabees", chapter: 10, verse: 7, text: "Then came Jonathan to Jerusalem, and read the letters in the audience of all the people, and of them that were in the tower:" },
  { book: "1 Maccabees", chapter: 10, verse: 8, text: "Who were sore afraid, when they heard that the king had given him authority to gather together an host." },
  { book: "1 Maccabees", chapter: 10, verse: 9, text: "Whereupon they of the tower delivered their hostages unto Jonathan, and he delivered them unto their parents." },
  { book: "1 Maccabees", chapter: 10, verse: 10, text: "This done, Jonathan settled himself in Jerusalem, and began to build and repair the city." },
  { book: "1 Maccabees", chapter: 10, verse: 11, text: "And he commanded the workmen to build the walls and the mount Sion and about with square stones for fortification; and they did so." },
  { book: "1 Maccabees", chapter: 10, verse: 12, text: "Then the strangers, that were in the fortresses which Bacchides had built, fled away;" },
  { book: "1 Maccabees", chapter: 10, verse: 13, text: "Insomuch as every man left his place, and went into his own country." },
  { book: "1 Maccabees", chapter: 10, verse: 14, text: "Only at Bethsura certain of those that had forsaken the law and the commandments remained still: for it was their place of refuge." },
  { book: "1 Maccabees", chapter: 10, verse: 15, text: "Now when king Alexander had heard what promises Demetrius had sent unto Jonathan: when also it was told him of the battles and noble acts which he and his brethren had done, and of the pains that they had endured," },
  { book: "1 Maccabees", chapter: 10, verse: 16, text: "He said, Shall we find such another man? now therefore we will make him our friend and confederate." },
  { book: "1 Maccabees", chapter: 10, verse: 17, text: "Upon this he wrote a letter, and sent it unto him, according to these words, saying," },
  { book: "1 Maccabees", chapter: 10, verse: 18, text: "King Alexander to his brother Jonathan sendeth greeting:" },
  { book: "1 Maccabees", chapter: 10, verse: 19, text: "We have heard of thee, that thou art a man of great power, and meet to be our friend." },
  { book: "1 Maccabees", chapter: 10, verse: 20, text: "Wherefore now this day we ordain thee to be the high priest of thy nation, and to be called the king’s friend; (and therewithal he sent him a purple robe and a crown of gold:) and require thee to take our part, and keep friendship with us." },
  { book: "1 Maccabees", chapter: 10, verse: 21, text: "So in the seventh month of the hundred and sixtieth year, at the feast of the tabernacles, Jonathan put on the holy robe, and gathered together forces, and provided much armour." },
  { book: "1 Maccabees", chapter: 10, verse: 22, text: "Whereof when Demetrius heard, he was very sorry, and said," },
  { book: "1 Maccabees", chapter: 10, verse: 23, text: "What have we done, that Alexander hath prevented us in making amity with the Jews to strengthen himself?" },
  { book: "1 Maccabees", chapter: 10, verse: 24, text: "I also will write unto them words of encouragement, and promise them dignities and gifts, that I may have their aid." },
  { book: "1 Maccabees", chapter: 10, verse: 25, text: "He sent unto them therefore to this effect: King Demetrius unto the people of the Jews sendeth greeting:" },
  { book: "1 Maccabees", chapter: 10, verse: 26, text: "Whereas ye have kept covenants with us, and continued in our friendship, not joining yourselves with our enemies, we have heard hereof, and are glad." },
  { book: "1 Maccabees", chapter: 10, verse: 27, text: "Wherefore now continue ye still to be faithful unto us, and we will well recompense you for the things ye do in our behalf," },
  { book: "1 Maccabees", chapter: 10, verse: 28, text: "And will grant you many immunities, and give you rewards." },
  { book: "1 Maccabees", chapter: 10, verse: 29, text: "And now do I free you, and for your sake I release all the Jews, from tributes, and from the customs of salt, and from crown taxes," },
  { book: "1 Maccabees", chapter: 10, verse: 30, text: "And from that which appertaineth unto me to receive for the third part or the seed, and the half of the fruit of the trees, I release it from this day forth, so that they shall not be taken of the land of Judea, nor of the three governments which are added thereunto out of the country of Samaria and Galilee, from this day forth for evermore." },
  { book: "1 Maccabees", chapter: 10, verse: 31, text: "Let Jerusalem also be holy and free, with the borders thereof, both from tenths and tributes." },
  { book: "1 Maccabees", chapter: 10, verse: 32, text: "And as for the tower which is at Jerusalem, I yield up authority over it, and give the high priest, that he may set in it such men as he shall choose to keep it." },
  { book: "1 Maccabees", chapter: 10, verse: 33, text: "Moreover I freely set at liberty every one of the Jews, that were carried captives out of the land of Judea into any part of my kingdom, and I will that all my officers remit the tributes even of their cattle." },
  { book: "1 Maccabees", chapter: 10, verse: 34, text: "Furthermore I will that all the feasts, and sabbaths, and new moons, and solemn days, and the three days before the feast, and the three days after the feast shall be all of immunity and freedom for all the Jews in my realm." },
  { book: "1 Maccabees", chapter: 10, verse: 35, text: "Also no man shall have authority to meddle with or to molest any of them in any matter." },
  { book: "1 Maccabees", chapter: 10, verse: 36, text: "I will further, that there be enrolled among the king’s forces about thirty thousand men of the Jews, unto whom pay shall be given, as belongeth to all king’s forces." },
  { book: "1 Maccabees", chapter: 10, verse: 37, text: "And of them some shall be placed in the king’s strong holds, of whom also some shall be set over the affairs of the kingdom, which are of trust: and I will that their overseers and governors be of themselves, and that they live after their own laws, even as the king hath commanded in the land of Judea." },
  { book: "1 Maccabees", chapter: 10, verse: 38, text: "And concerning the three governments that are added to Judea from the country of Samaria, let them be joined with Judea, that they may be reckoned to be under one, nor bound to obey other authority than the high priest’s." },
  { book: "1 Maccabees", chapter: 10, verse: 39, text: "As for Ptolemais, and the land pertaining thereto, I give it as a free gift to the sanctuary at Jerusalem for the necessary expences of the sanctuary." },
  { book: "1 Maccabees", chapter: 10, verse: 40, text: "Moreover I give every year fifteen thousand shekels of silver out of the king’s accounts from the places appertaining." },
  { book: "1 Maccabees", chapter: 10, verse: 41, text: "And all the overplus, which the officers payed not in as in former time, from henceforth shall be given toward the works of the temple." },
  { book: "1 Maccabees", chapter: 10, verse: 42, text: "And beside this, the five thousand shekels of silver, which they took from the uses of the temple out of the accounts year by year, even those things shall be released, because they appertain to the priests that minister." },
  { book: "1 Maccabees", chapter: 10, verse: 43, text: "And whosoever they be that flee unto the temple at Jerusalem, or be within the liberties hereof, being indebted unto the king, or for any other matter, let them be at liberty, and all that they have in my realm." },
  { book: "1 Maccabees", chapter: 10, verse: 44, text: "For the building also and repairing of the works of the sanctuary expences shall be given of the king’s accounts." },
  { book: "1 Maccabees", chapter: 10, verse: 45, text: "Yea, and for the building of the walls of Jerusalem, and the fortifying thereof round about, expences shall be given out of the king’s accounts, as also for the building of the walls in Judea." },
  { book: "1 Maccabees", chapter: 10, verse: 46, text: "Now when Jonathan and the people heard these words, they gave no credit unto them, nor received them, because they remembered the great evil that he had done in Israel; for he had afflicted them very sore." },
  { book: "1 Maccabees", chapter: 10, verse: 47, text: "But with Alexander they were well pleased, because he was the first that entreated of true peace with them, and they were confederate with him always." },
  { book: "1 Maccabees", chapter: 10, verse: 48, text: "Then gathered king Alexander great forces, and camped over against Demetrius." },
  { book: "1 Maccabees", chapter: 10, verse: 49, text: "And after the two kings had joined battle, Demetrius’ host fled: but Alexander followed after him, and prevailed against them." },
  { book: "1 Maccabees", chapter: 10, verse: 50, text: "And he continued the battle very sore until the sun went down: and that day was Demetrius slain." },
  { book: "1 Maccabees", chapter: 10, verse: 51, text: "Afterward Alexander sent ambassadors to Ptolemee king of Egypt with a message to this effect:" },
  { book: "1 Maccabees", chapter: 10, verse: 52, text: "Forasmuch as I am come again to my realm, and am set in the throne of my progenitors, and have gotten the dominion, and overthrown Demetrius, and recovered our country;" },
  { book: "1 Maccabees", chapter: 10, verse: 53, text: "For after I had joined battle with him, both he and his host was discomfited by us, so that we sit in the throne of his kingdom:" },
  { book: "1 Maccabees", chapter: 10, verse: 54, text: "Now therefore let us make a league of amity together, and give me now thy daughter to wife: and I will be thy son in law, and will give both thee and her as according to thy dignity." },
  { book: "1 Maccabees", chapter: 10, verse: 55, text: "Then Ptolemee the king gave answer, saying, Happy be the day wherein thou didst return into the land of thy fathers, and satest in the throne of their kingdom." },
  { book: "1 Maccabees", chapter: 10, verse: 56, text: "And now will I do to thee, as thou hast written: meet me therefore at Ptolemais, that we may see one another; for I will marry my daughter to thee according to thy desire." },
  { book: "1 Maccabees", chapter: 10, verse: 57, text: "So Ptolemee went out of Egypt with his daughter Cleopatra, and they came unto Ptolemais in the hundred threescore and second year:" },
  { book: "1 Maccabees", chapter: 10, verse: 58, text: "Where king Alexander meeting him, he gave unto him his daughter Cleopatra, and celebrated her marriage at Ptolemais with great glory, as the manner of kings is." },
  { book: "1 Maccabees", chapter: 10, verse: 59, text: "Now king Alexander had written unto Jonathan, that he should come and meet him." },
  { book: "1 Maccabees", chapter: 10, verse: 60, text: "Who thereupon went honourably to Ptolemais, where he met the two kings, and gave them and their friends silver and gold, and many presents, and found favour in their sight." },
  { book: "1 Maccabees", chapter: 10, verse: 61, text: "At that time certain pestilent fellows of Israel, men of a wicked life, assembled themselves against him, to accuse him: but the king would not hear them." },
  { book: "1 Maccabees", chapter: 10, verse: 62, text: "Yea more than that, the king commanded to take off his garments, and clothe him in purple: and they did so." },
  { book: "1 Maccabees", chapter: 10, verse: 63, text: "And he made him sit by himself, and said into his princes, Go with him into the midst of the city, and make proclamation, that no man complain against him of any matter, and that no man trouble him for any manner of cause." },
  { book: "1 Maccabees", chapter: 10, verse: 64, text: "Now when his accusers saw that he was honored according to the proclamation, and clothed in purple, they fled all away." },
  { book: "1 Maccabees", chapter: 10, verse: 65, text: "So the king honoured him, and wrote him among his chief friends, and made him a duke, and partaker of his dominion." },
  { book: "1 Maccabees", chapter: 10, verse: 66, text: "Afterward Jonathan returned to Jerusalem with peace and gladness." },
  { book: "1 Maccabees", chapter: 10, verse: 67, text: "Furthermore in the; hundred threescore and fifth year came Demetrius son of Demetrius out of Crete into the land of his fathers:" },
  { book: "1 Maccabees", chapter: 10, verse: 68, text: "Whereof when king Alexander heard tell, he was right sorry, and returned into Antioch." },
  { book: "1 Maccabees", chapter: 10, verse: 69, text: "Then Demetrius made Apollonius the governor of Celosyria his general, who gathered together a great host, and camped in Jamnia, and sent unto Jonathan the high priest, saying," },
  { book: "1 Maccabees", chapter: 10, verse: 70, text: "Thou alone liftest up thyself against us, and I am laughed to scorn for thy sake, and reproached: and why dost thou vaunt thy power against us in the mountains?" },
  { book: "1 Maccabees", chapter: 10, verse: 71, text: "Now therefore, if thou trustest in thine own strength, come down to us into the plain field, and there let us try the matter together: for with me is the power of the cities." },
  { book: "1 Maccabees", chapter: 10, verse: 72, text: "Ask and learn who I am, and the rest that take our part, and they shall tell thee that thy foot is not able to to flight in their own land." },
  { book: "1 Maccabees", chapter: 10, verse: 73, text: "Wherefore now thou shalt not be able to abide the horsemen and so great a power in the plain, where is neither stone nor flint, nor place to flee unto." },
  { book: "1 Maccabees", chapter: 10, verse: 74, text: "So when Jonathan heard these words of Apollonius, he was moved in his mind, and choosing ten thousand men he went out of Jerusalem, where Simon his brother met him for to help him." },
  { book: "1 Maccabees", chapter: 10, verse: 75, text: "And he pitched his tents against Joppa: but; they of Joppa shut him out of the city, because Apollonius had a garrison there." },
  { book: "1 Maccabees", chapter: 10, verse: 76, text: "Then Jonathan laid siege unto it: whereupon they of the city let him in for fear: and so Jonathan won Joppa." },
  { book: "1 Maccabees", chapter: 10, verse: 77, text: "Whereof when Apollonius heard, he took three thousand horsemen, with a great host of footmen, and went to Azotus as one that journeyed, and therewithal drew him forth into the plain. because he had a great number of horsemen, in whom he put his trust." },
  { book: "1 Maccabees", chapter: 10, verse: 78, text: "Then Jonathan followed after him to Azotus, where the armies joined battle." },
  { book: "1 Maccabees", chapter: 10, verse: 79, text: "Now Apollonius had left a thousand horsemen in ambush." },
  { book: "1 Maccabees", chapter: 10, verse: 80, text: "And Jonathan knew that there was an ambushment behind him; for they had compassed in his host, and cast darts at the people, from morning till evening." },
  { book: "1 Maccabees", chapter: 10, verse: 81, text: "But the people stood still, as Jonathan had commanded them: and so the enemies’ horses were tired." },
  { book: "1 Maccabees", chapter: 10, verse: 82, text: "Then brought Simon forth his host, and set them against the footmen, (for the horsemen were spent) who were discomfited by him, and fled." },
  { book: "1 Maccabees", chapter: 10, verse: 83, text: "The horsemen also, being scattered in the field, fled to Azotus, and went into Bethdagon, their idol’s temple, for safety." },
  { book: "1 Maccabees", chapter: 10, verse: 84, text: "But Jonathan set fire on Azotus, and the cities round about it, and took their spoils; and the temple of Dagon, with them that were fled into it, he burned with fire." },
  { book: "1 Maccabees", chapter: 10, verse: 85, text: "Thus there were burned and slain with the sword well nigh eight thousand men." },
  { book: "1 Maccabees", chapter: 10, verse: 86, text: "And from thence Jonathan removed his host, and camped against Ascalon, where the men of the city came forth, and met him with great pomp." },
  { book: "1 Maccabees", chapter: 10, verse: 87, text: "After this returned Jonathan and his host unto Jerusalem, having any spoils." },
  { book: "1 Maccabees", chapter: 10, verse: 88, text: "Now when king Alexander heard these things, he honoured Jonathan yet more." },
  { book: "1 Maccabees", chapter: 10, verse: 89, text: "And sent him a buckle of gold, as the use is to be given to such as are of the king’s blood: he gave him also Accaron with the borders thereof in possession." },
  { book: "1 Maccabees", chapter: 11, verse: 1, text: "And the king of Egypt gathered together a great host, like the sand that lieth upon the sea shore, and many ships, and went about through deceit to get Alexander’s kingdom, and join it to his own." },
  { book: "1 Maccabees", chapter: 11, verse: 2, text: "Whereupon he took his journey into Spain in peaceable manner, so as they of the cities opened unto him, and met him: for king Alexander had commanded them so to do, because he was his brother in law." },
  { book: "1 Maccabees", chapter: 11, verse: 3, text: "Now as Ptolemee entered into the cities, he set in every one of them a garrison of soldiers to keep it." },
  { book: "1 Maccabees", chapter: 11, verse: 4, text: "And when he came near to Azotus, they shewed him the temple of Dagon that was burnt, and Azotus and the suburbs thereof that were destroyed, and the bodies that were cast abroad and them that he had burnt in the battle; for they had made heaps of them by the way where he should pass." },
  { book: "1 Maccabees", chapter: 11, verse: 5, text: "Also they told the king whatsoever Jonathan had done, to the intent he might blame him: but the king held his peace." },
  { book: "1 Maccabees", chapter: 11, verse: 6, text: "Then Jonathan met the king with great pomp at Joppa, where they saluted one another, and lodged." },
  { book: "1 Maccabees", chapter: 11, verse: 7, text: "Afterward Jonathan, when he had gone with the king to the river called Eleutherus, returned again to Jerusalem." },
  { book: "1 Maccabees", chapter: 11, verse: 8, text: "King Ptolemee therefore, having gotten the dominion of the cities by the sea unto Seleucia upon the sea coast, imagined wicked counsels against Alexander." },
  { book: "1 Maccabees", chapter: 11, verse: 9, text: "Whereupon he sent ambassadors unto king Demetrius, saying, Come, let us make a league betwixt us, and I will give thee my daughter whom Alexander hath, and thou shalt reign in thy father’s kingdom:" },
  { book: "1 Maccabees", chapter: 11, verse: 10, text: "For I repent that I gave my daughter unto him, for he sought to slay me." },
  { book: "1 Maccabees", chapter: 11, verse: 11, text: "Thus did he slander him, because he was desirous of his kingdom." },
  { book: "1 Maccabees", chapter: 11, verse: 12, text: "Wherefore he took his daughter from him, and gave her to Demetrius, and forsook Alexander, so that their hatred was openly known." },
  { book: "1 Maccabees", chapter: 11, verse: 13, text: "Then Ptolemee entered into Antioch, where he set two crowns upon his head, the crown of Asia, and of Egypt." },
  { book: "1 Maccabees", chapter: 11, verse: 14, text: "In the mean season was king Alexander in Cilicia, because those that dwelt in those parts had revolted from him." },
  { book: "1 Maccabees", chapter: 11, verse: 15, text: "But when Alexander heard of this, he came to war against him: whereupon king Ptolemee brought forth his host, and met him with a mighty power, and put him to flight." },
  { book: "1 Maccabees", chapter: 11, verse: 16, text: "So Alexander fled into Arabia there to be defended; but king Ptolemee was exalted:" },
  { book: "1 Maccabees", chapter: 11, verse: 17, text: "For Zabdiel the Arabian took off Alexander’s head, and sent it unto Ptolemee." },
  { book: "1 Maccabees", chapter: 11, verse: 18, text: "King Ptolemee also died the third day after, and they that were in the strong holds were slain one of another." },
  { book: "1 Maccabees", chapter: 11, verse: 19, text: "By this means Demetrius reigned in the hundred threescore and seventh year." },
  { book: "1 Maccabees", chapter: 11, verse: 20, text: "At the same time Jonathan gathered together them that were in Judea to take the tower that was in Jerusalem: and he made many engines of war against it." },
  { book: "1 Maccabees", chapter: 11, verse: 21, text: "Then came ungodly persons, who hated their own people, went unto the king, and told him that Jonathan besieged the tower," },
  { book: "1 Maccabees", chapter: 11, verse: 22, text: "Whereof when he heard, he was angry, and immediately removing, he came to Ptolemais, and wrote unto Jonathan, that he should not lay siege to the tower, but come and speak with him at Ptolemais in great haste." },
  { book: "1 Maccabees", chapter: 11, verse: 23, text: "Nevertheless Jonathan, when he heard this, commanded to besiege it still: and he chose certain of the elders of Israel and the priests, and put himself in peril;" },
  { book: "1 Maccabees", chapter: 11, verse: 24, text: "And took silver and gold, and raiment, and divers presents besides, and went to Ptolemais unto the king, where he found favour in his sight." },
  { book: "1 Maccabees", chapter: 11, verse: 25, text: "And though certain ungodly men of the people had made complaints against him," },
  { book: "1 Maccabees", chapter: 11, verse: 26, text: "Yet the king entreated him as his predecessors had done before, and promoted him in the sight of all his friends," },
  { book: "1 Maccabees", chapter: 11, verse: 27, text: "And confirmed him in the high priesthood, and in all the honours that he had before, and gave him preeminence among his chief friends." },
  { book: "1 Maccabees", chapter: 11, verse: 28, text: "Then Jonathan desired the king, that he would make Judea free from tribute, as also the three governments, with the country of Samaria; and he promised him three hundred talents." },
  { book: "1 Maccabees", chapter: 11, verse: 29, text: "So the king consented, and wrote letters unto Jonathan of all these things after this manner:" },
  { book: "1 Maccabees", chapter: 11, verse: 30, text: "King Demetrius unto his brother Jonathan, and unto the nation of the Jews, sendeth greeting:" },
  { book: "1 Maccabees", chapter: 11, verse: 31, text: "We send you here a copy of the letter which we did write unto our cousin Lasthenes concerning you, that ye might see it." },
  { book: "1 Maccabees", chapter: 11, verse: 32, text: "King Demetrius unto his father Lasthenes sendeth greeting:" },
  { book: "1 Maccabees", chapter: 11, verse: 33, text: "We are determined to do good to the people of the Jews, who are our friends, and keep covenants with us, because of their good will toward us." },
  { book: "1 Maccabees", chapter: 11, verse: 34, text: "Wherefore we have ratified unto them the borders of Judea, with the three governments of Apherema and Lydda and Ramathem, that are added unto Judea from the country of Samaria, and all things appertaining unto them, for all such as do sacrifice in Jerusalem, instead of the payments which the king received of them yearly aforetime out of the fruits of the earth and of trees." },
  { book: "1 Maccabees", chapter: 11, verse: 35, text: "And as for other things that belong unto us, of the tithes and customs pertaining unto us, as also the saltpits, and the crown taxes, which are due unto us, we discharge them of them all for their relief." },
  { book: "1 Maccabees", chapter: 11, verse: 36, text: "And nothing hereof shall be revoked from this time forth for ever." },
  { book: "1 Maccabees", chapter: 11, verse: 37, text: "Now therefore see that thou make a copy of these things, and let it be delivered unto Jonathan, and set upon the holy mount in a conspicuous place." },
  { book: "1 Maccabees", chapter: 11, verse: 38, text: "After this, when king Demetrius saw that the land was quiet before him, and that no resistance was made against him, he sent away all his forces, every one to his own place, except certain bands of strangers, whom he had gathered from the isles of the heathen: wherefore all the forces of his fathers hated him." },
  { book: "1 Maccabees", chapter: 11, verse: 39, text: "Moreover there was one Tryphon, that had been of Alexander’s part afore, who, seeing that all the host murmured against Demetrius, went to Simalcue the Arabian that brought up Antiochus the young son of Alexander," },
  { book: "1 Maccabees", chapter: 11, verse: 40, text: "And lay sore upon him to deliver him this young Antiochus, that he might reign in his father’s stead: he told him therefore all that Demetrius had done, and how his men of war were at enmity with him, and there he remained a long season." },
  { book: "1 Maccabees", chapter: 11, verse: 41, text: "In the mean time Jonathan sent unto king Demetrius, that he would cast those of the tower out of Jerusalem, and those also in the fortresses: for they fought against Israel." },
  { book: "1 Maccabees", chapter: 11, verse: 42, text: "So Demetrius sent unto Jonathan, saying, I will not only do this for thee and thy people, but I will greatly honour thee and thy nation, if opportunity serve." },
  { book: "1 Maccabees", chapter: 11, verse: 43, text: "Now therefore thou shalt do well, if thou send me men to help me; for all my forces are gone from me." },
  { book: "1 Maccabees", chapter: 11, verse: 44, text: "Upon this Jonathan sent him three thousand strong men unto Antioch: and when they came to the king, the king was very glad of their coming." },
  { book: "1 Maccabees", chapter: 11, verse: 45, text: "Howbeit they that were of the city gathered themselves together into the midst of the city, to the number of an hundred and twenty thousand men, and would have slain the king." },
  { book: "1 Maccabees", chapter: 11, verse: 46, text: "Wherefore the king fled into the court, but they of the city kept the passages of the city, and began to fight." },
  { book: "1 Maccabees", chapter: 11, verse: 47, text: "Then the king called to the Jews for help, who came unto him all at once, and dispersing themselves through the city slew that day in the city to the number of an hundred thousand." },
  { book: "1 Maccabees", chapter: 11, verse: 48, text: "Also they set fire on the city, and gat many spoils that day, and delivered the king." },
  { book: "1 Maccabees", chapter: 11, verse: 49, text: "So when they of the city saw that the Jews had got the city as they would, their courage was abated: wherefore they made supplication to the king, and cried, saying," },
  { book: "1 Maccabees", chapter: 11, verse: 50, text: "Grant us peace, and let the Jews cease from assaulting us and the city." },
  { book: "1 Maccabees", chapter: 11, verse: 51, text: "With that they cast away their weapons, and made peace; and the Jews were honoured in the sight of the king, and in the sight of all that were in his realm; and they returned to Jerusalem, having great spoils." },
  { book: "1 Maccabees", chapter: 11, verse: 52, text: "So king Demetrius sat on the throne of his kingdom, and the land was quiet before him." },
  { book: "1 Maccabees", chapter: 11, verse: 53, text: "Nevertheless he dissembled in all that ever he spake, and estranged himself from Jonathan, neither rewarded he him according to the benefits which he had received of him, but troubled him very sore." },
  { book: "1 Maccabees", chapter: 11, verse: 54, text: "After this returned Tryphon, and with him the young child Antiochus, who reigned, and was crowned." },
  { book: "1 Maccabees", chapter: 11, verse: 55, text: "Then there gathered unto him all the men of war, whom Demetrius had put away, and they fought against Demetrius, who turned his back and fled." },
  { book: "1 Maccabees", chapter: 11, verse: 56, text: "Moreover Tryphon took the elephants, and won Antioch." },
  { book: "1 Maccabees", chapter: 11, verse: 57, text: "At that time young Antiochus wrote unto Jonathan, saying, I confirm thee in the high priesthood, and appoint thee ruler over the four governments, and to be one of the king’s friends." },
  { book: "1 Maccabees", chapter: 11, verse: 58, text: "Upon this he sent him golden vessels to be served in, and gave him leave to drink in gold, and to be clothed in purple, and to wear a golden buckle." },
  { book: "1 Maccabees", chapter: 11, verse: 59, text: "His brother Simon also he made captain from the place called The ladder of Tyrus unto the borders of Egypt." },
  { book: "1 Maccabees", chapter: 11, verse: 60, text: "Then Jonathan went forth, and passed through the cities beyond the water, and all the forces of Syria gathered themselves unto him for to help him: and when he came to Ascalon, they of the city met him honourably." },
  { book: "1 Maccabees", chapter: 11, verse: 61, text: "From whence he went to Gaza, but they of Gaza shut him out; wherefore he laid siege unto it, and burned the suburbs thereof with fire, and spoiled them." },
  { book: "1 Maccabees", chapter: 11, verse: 62, text: "Afterward, when they of Gaza made supplication unto Jonathan, he made peace with them, and took the sons of their chief men for hostages, and sent them to Jerusalem, and passed through the country unto Damascus." },
  { book: "1 Maccabees", chapter: 11, verse: 63, text: "Now when Jonathan heard that Demetrius’ princes were come to Cades, which is in Galilee, with a great power, purposing to remove him out of the country," },
  { book: "1 Maccabees", chapter: 11, verse: 64, text: "He went to meet them, and left Simon his brother in the country." },
  { book: "1 Maccabees", chapter: 11, verse: 65, text: "Then Simon encamped against Bethsura and fought against it a long season, and shut it up:" },
  { book: "1 Maccabees", chapter: 11, verse: 66, text: "But they desired to have peace with him, which he granted them, and then put them out from thence, and took the city, and set a garrison in it." },
  { book: "1 Maccabees", chapter: 11, verse: 67, text: "As for Jonathan and his host, they pitched at the water of Gennesar, from whence betimes in the morning they gat them to the plain of Nasor." },
  { book: "1 Maccabees", chapter: 11, verse: 68, text: "And, behold, the host of strangers met them in the plain, who, having laid men in ambush for him in the mountains, came themselves over against him." },
  { book: "1 Maccabees", chapter: 11, verse: 69, text: "So when they that lay in ambush rose out of their places and joined battle, all that were of Jonathan’s side fled;" },
  { book: "1 Maccabees", chapter: 11, verse: 70, text: "Insomuch as there was not one of them left, except Mattathias the son of Absalom, and Judas the son of Calphi, the captains of the host." },
  { book: "1 Maccabees", chapter: 11, verse: 71, text: "Then Jonathan rent his clothes, and cast earth upon his head, and prayed." },
  { book: "1 Maccabees", chapter: 11, verse: 72, text: "Afterwards turning again to battle, he put them to flight, and so they ran away." },
  { book: "1 Maccabees", chapter: 11, verse: 73, text: "Now when his own men that were fled saw this, they turned again unto him, and with him pursued them to Cades, even unto their own tents, and there they camped." },
  { book: "1 Maccabees", chapter: 11, verse: 74, text: "So there were slain of the heathen that day about three thousand men: but Jonathan returned to Jerusalem." },
  { book: "1 Maccabees", chapter: 12, verse: 1, text: "Now when Jonathan saw that time served him, he chose certain men, and sent them to Rome, for to confirm and renew the friendship that they had with them." },
  { book: "1 Maccabees", chapter: 12, verse: 2, text: "He sent letters also to the Lacedemonians, and to other places, for the same purpose." },
  { book: "1 Maccabees", chapter: 12, verse: 3, text: "So they went unto Rome, and entered into the senate, and said, Jonathan the high priest, and the people of the Jews, sent us unto you, to the end ye should renew the friendship, which ye had with them, and league, as in former time." },
  { book: "1 Maccabees", chapter: 12, verse: 4, text: "Upon this the Romans gave them letters unto the governors of every place that they should bring them into the land of Judea peaceably." },
  { book: "1 Maccabees", chapter: 12, verse: 5, text: "And this is the copy of the letters which Jonathan wrote to the Lacedemonians:" },
  { book: "1 Maccabees", chapter: 12, verse: 6, text: "Jonathan the high priest, and the elders of the nation, and the priests, and the other of the Jews, unto the Lacedemonians their brethren send greeting:" },
  { book: "1 Maccabees", chapter: 12, verse: 7, text: "There were letters sent in times past unto Onias the high priest from Darius, who reigned then among you, to signify that ye are our brethren, as the copy here underwritten doth specify." },
  { book: "1 Maccabees", chapter: 12, verse: 8, text: "At which time Onias entreated the ambassador that was sent honourably, and received the letters, wherein declaration was made of the league and friendship." },
  { book: "1 Maccabees", chapter: 12, verse: 9, text: "Therefore we also, albeit we need none of these things, that we have the holy books of scripture in our hands to comfort us," },
  { book: "1 Maccabees", chapter: 12, verse: 10, text: "Have nevertheless attempted to send unto you for the renewing of brotherhood and friendship, lest we should become strangers unto you altogether: for there is a long time passed since ye sent unto us." },
  { book: "1 Maccabees", chapter: 12, verse: 11, text: "We therefore at all times without ceasing, both in our feasts, and other convenient days, do remember you in the sacrifices which we offer, and in our prayers, as reason is, and as it becometh us to think upon our brethren:" },
  { book: "1 Maccabees", chapter: 12, verse: 12, text: "And we are right glad of your honour." },
  { book: "1 Maccabees", chapter: 12, verse: 13, text: "As for ourselves, we have had great troubles and wars on every side, forsomuch as the kings that are round about us have fought against us." },
  { book: "1 Maccabees", chapter: 12, verse: 14, text: "Howbeit we would not be troublesome unto you, nor to others of our confederates and friends, in these wars:" },
  { book: "1 Maccabees", chapter: 12, verse: 15, text: "For we have help from heaven that succoureth us, so as we are delivered from our enemies, and our enemies are brought under foot." },
  { book: "1 Maccabees", chapter: 12, verse: 16, text: "For this cause we chose Numenius the son of Antiochus, and Antipater he son of Jason, and sent them unto the Romans, to renew the amity that we had with them, and the former league." },
  { book: "1 Maccabees", chapter: 12, verse: 17, text: "We commanded them also to go unto you, and to salute and to deliver you our letters concerning the renewing of our brotherhood." },
  { book: "1 Maccabees", chapter: 12, verse: 18, text: "Wherefore now ye shall do well to give us an answer thereto." },
  { book: "1 Maccabees", chapter: 12, verse: 19, text: "And this is the copy of the letters which Oniares sent." },
  { book: "1 Maccabees", chapter: 12, verse: 20, text: "Areus king of the Lacedemonians to Onias the high priest, greeting:" },
  { book: "1 Maccabees", chapter: 12, verse: 21, text: "It is found in writing, that the Lacedemonians and Jews are brethren, and that they are of the stock of Abraham:" },
  { book: "1 Maccabees", chapter: 12, verse: 22, text: "Now therefore, since this is come to our knowledge, ye shall do well to write unto us of your prosperity." },
  { book: "1 Maccabees", chapter: 12, verse: 23, text: "We do write back again to you, that your cattle and goods are our’s, and our’s are your’s We do command therefore our ambassadors to make report unto you on this wise." },
  { book: "1 Maccabees", chapter: 12, verse: 24, text: "Now when Jonathan heard that Demebius’ princes were come to fight against him with a greater host than afore," },
  { book: "1 Maccabees", chapter: 12, verse: 25, text: "He removed from Jerusalem, and met them in the land of Amathis: for he gave them no respite to enter his country." },
  { book: "1 Maccabees", chapter: 12, verse: 26, text: "He sent spies also unto their tents, who came again, and told him that they were appointed to come upon them in the night season." },
  { book: "1 Maccabees", chapter: 12, verse: 27, text: "Wherefore so soon as the sun was down, Jonathan commanded his men to watch, and to be in arms, that all the night long they might be ready to fight: also he sent forth centinels round about the host." },
  { book: "1 Maccabees", chapter: 12, verse: 28, text: "But when the adversaries heard that Jonathan and his men were ready for battle, they feared, and trembled in their hearts, and they kindled fires in their camp." },
  { book: "1 Maccabees", chapter: 12, verse: 29, text: "Howbeit Jonathan and his company knew it not till the morning: for they saw the lights burning." },
  { book: "1 Maccabees", chapter: 12, verse: 30, text: "Then Jonathan pursued after them, but overtook them not: for they were gone over the river Eleutherus." },
  { book: "1 Maccabees", chapter: 12, verse: 31, text: "Wherefore Jonathan turned to the Arabians, who were called Zabadeans, and smote them, and took their spoils." },
  { book: "1 Maccabees", chapter: 12, verse: 32, text: "And removing thence, he came to Damascus, and so passed through all the country," },
  { book: "1 Maccabees", chapter: 12, verse: 33, text: "Simon also went forth, and passed through the country unto Ascalon, and the holds there adjoining, from whence he turned aside to Joppa, and won it." },
  { book: "1 Maccabees", chapter: 12, verse: 34, text: "For he had heard that they would deliver the hold unto them that took Demetrius’ part; wherefore he set a garrison there to keep it." },
  { book: "1 Maccabees", chapter: 12, verse: 35, text: "After this came Jonathan home again, and calling the elders of the people together, he consulted with them about building strong holds in Judea," },
  { book: "1 Maccabees", chapter: 12, verse: 36, text: "And making the walls of Jerusalem higher, and raising a great mount between the tower and the city, for to separate it from the city, that so it might be alone, that men might neither sell nor buy in it." },
  { book: "1 Maccabees", chapter: 12, verse: 37, text: "Upon this they came together to build up the city, forasmuch as part of the wall toward the brook on the east side was fallen down, and they repaired that which was called Caphenatha." },
  { book: "1 Maccabees", chapter: 12, verse: 38, text: "Simon also set up Adida in Sephela, and made it strong with gates and bars." },
  { book: "1 Maccabees", chapter: 12, verse: 39, text: "Now Tryphon went about to get the kingdom of Asia, and to kill Antiochus the king, that he might set the crown upon his own head." },
  { book: "1 Maccabees", chapter: 12, verse: 40, text: "Howbeit he was afraid that Jonathan would not suffer him, and that he would fight against him; wherefore he sought a way how to take Jonathan, that he might kill him. So he removed, and came to Bethsan." },
  { book: "1 Maccabees", chapter: 12, verse: 41, text: "Then Jonathan went out to meet him with forty thousand men chosen for the battle, and came to Bethsan." },
  { book: "1 Maccabees", chapter: 12, verse: 42, text: "Now when Tryphon saw Jonathan came with so great a force, he durst not stretch his hand against him;" },
  { book: "1 Maccabees", chapter: 12, verse: 43, text: "But received him honourably, and commended him unto all his friends, and gave him gifts, and commanded his men of war to be as obedient unto him, as to himself." },
  { book: "1 Maccabees", chapter: 12, verse: 44, text: "Unto Jonathan also he said, Why hast thou brought all this people to so great trouble, seeing there is no war betwixt us?" },
  { book: "1 Maccabees", chapter: 12, verse: 45, text: "Therefore send them now home again, and choose a few men to wait on thee, and come thou with me to Ptolemais, for I will give it thee, and the rest of the strong holds and forces, and all that have any charge: as for me, I will return and depart: for this is the cause of my coming." },
  { book: "1 Maccabees", chapter: 12, verse: 46, text: "So Jonathan believing him did as he bade him, and sent away his host, who went into the land of Judea." },
  { book: "1 Maccabees", chapter: 12, verse: 47, text: "And with himself he retained but three thousand men, of whom he sent two thousand into Galilee, and one thousand went with him." },
  { book: "1 Maccabees", chapter: 12, verse: 48, text: "Now as soon as Jonathan entered into Ptolemais, they of Ptolemais shut the gates and took him, and all them that came with him they slew with the sword." },
  { book: "1 Maccabees", chapter: 12, verse: 49, text: "Then sent Tryphon an host of footmen and horsemen into Galilee, and into the great plain, to destroy all Jonathan’s company." },
  { book: "1 Maccabees", chapter: 12, verse: 50, text: "But when they knew that Jonathan and they that were with him were taken and slain, they encouraged one another; and went close together, prepared to fight." },
  { book: "1 Maccabees", chapter: 12, verse: 51, text: "They therefore that followed upon them, perceiving that they were ready to fight for their lives, turned back again." },
  { book: "1 Maccabees", chapter: 12, verse: 52, text: "Whereupon they all came into the land of Judea peaceably, and there they bewailed Jonathan, and them that were with him, and they were sore afraid; wherefore all Israel made great lamentation." },
  { book: "1 Maccabees", chapter: 12, verse: 53, text: "Then all the heathen that were round about then sought to destroy them: for said they, They have no captain, nor any to help them: now therefore let us make war upon them, and take away their memorial from among men." },
  { book: "1 Maccabees", chapter: 13, verse: 1, text: "Now when Simon heard that Tryphon had gathered together a great host to invade the land of Judea, and destroy it," },
  { book: "1 Maccabees", chapter: 13, verse: 2, text: "And saw that the people was in great trembling and fear, he went up to Jerusalem, and gathered the people together," },
  { book: "1 Maccabees", chapter: 13, verse: 3, text: "And gave them exhortation, saying, Ye yourselves know what great things I, and my brethren, and my father’s house, have done for the laws and the sanctuary, the battles also and troubles which we have seen." },
  { book: "1 Maccabees", chapter: 13, verse: 4, text: "By reason whereof all my brethren are slain for Israel’s sake, and I am left alone." },
  { book: "1 Maccabees", chapter: 13, verse: 5, text: "Now therefore be it far from me, that I should spare mine own life in any time of trouble: for I am no better than my brethren." },
  { book: "1 Maccabees", chapter: 13, verse: 6, text: "Doubtless I will avenge my nation, and the sanctuary, and our wives, and our children: for all the heathen are gathered to destroy us of very malice." },
  { book: "1 Maccabees", chapter: 13, verse: 7, text: "Now as soon as the people heard these words, their spirit revived." },
  { book: "1 Maccabees", chapter: 13, verse: 8, text: "And they answered with a loud voice, saying, Thou shalt be our leader instead of Judas and Jonathan thy brother." },
  { book: "1 Maccabees", chapter: 13, verse: 9, text: "Fight thou our battles, and whatsoever, thou commandest us, that will we do." },
  { book: "1 Maccabees", chapter: 13, verse: 10, text: "So then he gathered together all the men of war, and made haste to finish the walls of Jerusalem, and he fortified it round about." },
  { book: "1 Maccabees", chapter: 13, verse: 11, text: "Also he sent Jonathan the son of Absolom, and with him a great power, to Joppa: who casting out them that were therein remained there in it." },
  { book: "1 Maccabees", chapter: 13, verse: 12, text: "So Tryphon removed from Ptolemaus with a great power to invade the land of Judea, and Jonathan was with him in ward." },
  { book: "1 Maccabees", chapter: 13, verse: 13, text: "But Simon pitched his tents at Adida, over against the plain." },
  { book: "1 Maccabees", chapter: 13, verse: 14, text: "Now when Tryphon knew that Simon was risen up instead of his brother Jonathan, and meant to join battle with him, he sent messengers unto him, saying," },
  { book: "1 Maccabees", chapter: 13, verse: 15, text: "Whereas we have Jonathan thy brother in hold, it is for money that he is owing unto the king’s treasure, concerning the business that was committed unto him." },
  { book: "1 Maccabees", chapter: 13, verse: 16, text: "Wherefore now send an hundred talents of silver, and two of his sons for hostages, that when he is at liberty he may not revolt from us, and we will let him go." },
  { book: "1 Maccabees", chapter: 13, verse: 17, text: "Hereupon Simon, albeit he perceived that they spake deceitfully unto him yet sent he the money and the children, lest peradventure he should procure to himself great hatred of the people:" },
  { book: "1 Maccabees", chapter: 13, verse: 18, text: "Who might have said, Because I sent him not the money and the children, therefore is Jonathan dead." },
  { book: "1 Maccabees", chapter: 13, verse: 19, text: "So he sent them the children and the hundred talents: howbeit Tryphon dissembled neither would he let Jonathan go." },
  { book: "1 Maccabees", chapter: 13, verse: 20, text: "And after this came Tryphon to invade the land, and destroy it, going round about by the way that leadeth unto Adora: but Simon and his host marched against him in every place, wheresoever he went." },
  { book: "1 Maccabees", chapter: 13, verse: 21, text: "Now they that were in the tower sent messengers unto Tryphon, to the end that he should hasten his coming unto them by the wilderness, and send them victuals." },
  { book: "1 Maccabees", chapter: 13, verse: 22, text: "Wherefore Tryphon made ready all his horsemen to come that night: but there fell a very great snow, by reason whereof he came not. So he departed, and came into the country of Galaad." },
  { book: "1 Maccabees", chapter: 13, verse: 23, text: "And when he came near to Bascama he slew Jonathan, who was buried there." },
  { book: "1 Maccabees", chapter: 13, verse: 24, text: "Afterward Tryphon returned and went into his own land." },
  { book: "1 Maccabees", chapter: 13, verse: 25, text: "Then sent Simon, and took the bones of Jonathan his brother, and buried them in Modin, the city of his fathers." },
  { book: "1 Maccabees", chapter: 13, verse: 26, text: "And all Israel made great lamentation for him, and bewailed him many days." },
  { book: "1 Maccabees", chapter: 13, verse: 27, text: "Simon also built a monument upon the sepulchre of his father and his brethren, and raised it aloft to the sight, with hewn stone behind and before." },
  { book: "1 Maccabees", chapter: 13, verse: 28, text: "Moreover he set up seven pyramids, one against another, for his father, and his mother, and his four brethren." },
  { book: "1 Maccabees", chapter: 13, verse: 29, text: "And in these he made cunning devices, about the which he set great pillars, and upon the pillars he made all their armour for a perpetual memory, and by the armour ships carved, that they might be seen of all that sail on the sea." },
  { book: "1 Maccabees", chapter: 13, verse: 30, text: "This is the sepulchre which he made at Modin, and it standeth yet unto this day." },
  { book: "1 Maccabees", chapter: 13, verse: 31, text: "Now Tryphon dealt deceitfully with the young king Antiochus, and slew him." },
  { book: "1 Maccabees", chapter: 13, verse: 32, text: "And he reigned in his stead, and crowned himself king of Asia, and brought a great calamity upon the land." },
  { book: "1 Maccabees", chapter: 13, verse: 33, text: "Then Simon built up the strong holds in Judea, and fenced them about with high towers, and great walls, and gates, and bars, and laid up victuals therein." },
  { book: "1 Maccabees", chapter: 13, verse: 34, text: "Moreover Simon chose men, and sent to king Demetrius, to the end he should give the land an immunity, because all that Tryphon did was to spoil." },
  { book: "1 Maccabees", chapter: 13, verse: 35, text: "Unto whom king Demetrius answered and wrote after this manner:" },
  { book: "1 Maccabees", chapter: 13, verse: 36, text: "King Demetrius unto Simon the high priest, and friend of kings, as also unto the elders and nation of the Jews, sendeth greeting:" },
  { book: "1 Maccabees", chapter: 13, verse: 37, text: "The golden crown, and the scarlet robe, which ye sent unto us, we have received: and we are ready to make a stedfast peace with you, yea, and to write unto our officers, to confirm the immunities which we have granted." },
  { book: "1 Maccabees", chapter: 13, verse: 38, text: "And whatsoever covenants we have made with you shall stand; and the strong holds, which ye have builded, shall be your own." },
  { book: "1 Maccabees", chapter: 13, verse: 39, text: "As for any oversight or fault committed unto this day, we forgive it, and the crown tax also, which ye owe us: and if there were any other tribute paid in Jerusalem, it shall no more be paid." },
  { book: "1 Maccabees", chapter: 13, verse: 40, text: "And look who are meet among you to be in our court, let then be enrolled, and let there be peace betwixt us." },
  { book: "1 Maccabees", chapter: 13, verse: 41, text: "Thus the yoke of the heathen was taken away from Israel in the hundred and seventieth year." },
  { book: "1 Maccabees", chapter: 13, verse: 42, text: "Then the people of Israel began to write in their instruments and contracts, In the first year of Simon the high priest, the governor and leader of the Jews." },
  { book: "1 Maccabees", chapter: 13, verse: 43, text: "In those days Simon camped against Gaza and besieged it round about; he made also an engine of war, and set it by the city, and battered a certain tower, and took it." },
  { book: "1 Maccabees", chapter: 13, verse: 44, text: "And they that were in the engine leaped into the city; whereupon there was a great uproar in the city:" },
  { book: "1 Maccabees", chapter: 13, verse: 45, text: "Insomuch as the people of the city rent their clothes, and climbed upon the walls with their wives and children, and cried with a loud voice, beseeching Simon to grant them peace." },
  { book: "1 Maccabees", chapter: 13, verse: 46, text: "And they said, Deal not with us according to our wickedness, but according to thy mercy." },
  { book: "1 Maccabees", chapter: 13, verse: 47, text: "So Simon was appeased toward them, and fought no more against them, but put them out of the city, and cleansed the houses wherein the idols were, and so entered into it with songs and thanksgiving." },
  { book: "1 Maccabees", chapter: 13, verse: 48, text: "Yea, he put all uncleanness out of it, and placed such men there as would keep the law, and made it stronger than it was before, and built therein a dwellingplace for himself." },
  { book: "1 Maccabees", chapter: 13, verse: 49, text: "They also of the tower in Jerusalem were kept so strait, that they could neither come forth, nor go into the country, nor buy, nor sell: wherefore they were in great distress for want of victuals, and a great number of them perished through famine." },
  { book: "1 Maccabees", chapter: 13, verse: 50, text: "Then cried they to Simon, beseeching him to be at one with them: which thing he granted them; and when he had put them out from thence, he cleansed the tower from pollutions:" },
  { book: "1 Maccabees", chapter: 13, verse: 51, text: "And entered into it the three and twentieth day of the second month in the hundred seventy and first year, with thanksgiving, and branches of palm trees, and with harps, and cymbals, and with viols, and hymns, and songs: because there was destroyed a great enemy out of Israel." },
  { book: "1 Maccabees", chapter: 13, verse: 52, text: "He ordained also that that day should be kept every year with gladness. Moreover the hill of the temple that was by the tower he made stronger than it was, and there he dwelt himself with his company." },
  { book: "1 Maccabees", chapter: 13, verse: 53, text: "And when Simon saw that John his son was a valiant man, he made him captain of all the hosts; and he dwelt in Gazera." },
  { book: "1 Maccabees", chapter: 14, verse: 1, text: "Now in the hundred threescore and twelfth year king Demetrius gathered his forces together, and went into Media to get him help to fight against Tryphone." },
  { book: "1 Maccabees", chapter: 14, verse: 2, text: "But when Arsaces, the king of Persia and Media, heard that Demetrius was entered within his borders, he sent one of his princes to take him alive:" },
  { book: "1 Maccabees", chapter: 14, verse: 3, text: "Who went and smote the host of Demetrius, and took him, and brought him to Arsaces, by whom he was put in ward." },
  { book: "1 Maccabees", chapter: 14, verse: 4, text: "As for the land of Judea, that was quiet all the days of Simon; for he sought the good of his nation in such wise, as that evermore his authority and honour pleased them well." },
  { book: "1 Maccabees", chapter: 14, verse: 5, text: "And as he was honourable in all his acts, so in this, that he took Joppa for an haven, and made an entrance to the isles of the sea," },
  { book: "1 Maccabees", chapter: 14, verse: 6, text: "And enlarged the bounds of his nation, and recovered the country," },
  { book: "1 Maccabees", chapter: 14, verse: 7, text: "And gathered together a great number of captives, and had the dominion of Gazera, and Bethsura, and the tower, out of the which he took all uncleanness, neither was there any that resisted him." },
  { book: "1 Maccabees", chapter: 14, verse: 8, text: "Then did they till their ground in peace, and the earth gave her increase, and the trees of the field their fruit." },
  { book: "1 Maccabees", chapter: 14, verse: 9, text: "The ancient men sat all in the streets, communing together of good things, and the young men put on glorious and warlike apparel." },
  { book: "1 Maccabees", chapter: 14, verse: 10, text: "He provided victuals for the cities, and set in them all manner of munition, so that his honourable name was renowned unto the end of the world." },
  { book: "1 Maccabees", chapter: 14, verse: 11, text: "He made peace in the land, and Israel rejoiced with great joy:" },
  { book: "1 Maccabees", chapter: 14, verse: 12, text: "For every man sat under his vine and his fig tree, and there was none to fray them:" },
  { book: "1 Maccabees", chapter: 14, verse: 13, text: "Neither was there any left in the land to fight against them: yea, the kings themselves were overthrown in those days." },
  { book: "1 Maccabees", chapter: 14, verse: 14, text: "Moreover he strengthened all those of his people that were brought low: the law he searched out; and every contemner of the law and wicked person he took away." },
  { book: "1 Maccabees", chapter: 14, verse: 15, text: "He beautified the sanctuary, and multiplied vessels of the temple." },
  { book: "1 Maccabees", chapter: 14, verse: 16, text: "Now when it was heard at Rome, and as far as Sparta, that Jonathan was dead, they were very sorry." },
  { book: "1 Maccabees", chapter: 14, verse: 17, text: "But as soon as they heard that his brother Simon was made high priest in his stead, and ruled the country, and the cities therein:" },
  { book: "1 Maccabees", chapter: 14, verse: 18, text: "They wrote unto him in tables of brass, to renew the friendship and league which they had made with Judas and Jonathan his brethren:" },
  { book: "1 Maccabees", chapter: 14, verse: 19, text: "Which writings were read before the congregation at Jerusalem." },
  { book: "1 Maccabees", chapter: 14, verse: 20, text: "And this is the copy of the letters that the Lacedemonians sent; The rulers of the Lacedemonians, with the city, unto Simon the high priest, and the elders, and priests, and residue of the people of the Jews, our brethren, send greeting:" },
  { book: "1 Maccabees", chapter: 14, verse: 21, text: "The ambassadors that were sent unto our people certified us of your glory and honour: wherefore we were glad of their coming," },
  { book: "1 Maccabees", chapter: 14, verse: 22, text: "And did register the things that they spake in the council of the people in this manner; Numenius son of Antiochus, and Antipater son of Jason, the Jews’ ambassadors, came unto us to renew the friendship they had with us." },
  { book: "1 Maccabees", chapter: 14, verse: 23, text: "And it pleased the people to entertain the men honourably, and to put the copy of their ambassage in publick records, to the end the people of the Lacedemonians might have a memorial thereof: furthermore we have written a copy thereof unto Simon the high priest." },
  { book: "1 Maccabees", chapter: 14, verse: 24, text: "After this Simon sent Numenius to Rome with a great shield of gold of a thousand pound weight to confirm the league with them." },
  { book: "1 Maccabees", chapter: 14, verse: 25, text: "Whereof when the people heard, they said, What thanks shall we give to Simon and his sons?" },
  { book: "1 Maccabees", chapter: 14, verse: 26, text: "For he and his brethren and the house of his father have established Israel, and chased away in fight their enemies from them, and confirmed their liberty." },
  { book: "1 Maccabees", chapter: 14, verse: 27, text: "So then they wrote it in tables of brass, which they set upon pillars in mount Sion: and this is the copy of the writing; The eighteenth day of the month Elul, in the hundred threescore and twelfth year, being the third year of Simon the high priest," },
  { book: "1 Maccabees", chapter: 14, verse: 28, text: "At Saramel in the great congregation of the priests, and people, and rulers of the nation, and elders of the country, were these things notified unto us." },
  { book: "1 Maccabees", chapter: 14, verse: 29, text: "Forasmuch as oftentimes there have been wars in the country, wherein for the maintenance of their sanctuary, and the law, Simon the son of Mattathias, of the posterity of Jarib, together with his brethren, put themselves in jeopardy, and resisting the enemies of their nation did their nation great honour:" },
  { book: "1 Maccabees", chapter: 14, verse: 30, text: "(For after that Jonathan, having gathered his nation together, and been their high priest, was added to his people," },
  { book: "1 Maccabees", chapter: 14, verse: 31, text: "Their enemies prepared to invade their country, that they might destroy it, and lay hands on the sanctuary:" },
  { book: "1 Maccabees", chapter: 14, verse: 32, text: "At which time Simon rose up, and fought for his nation, and spent much of his own substance, and armed the valiant men of his nation and gave them wages," },
  { book: "1 Maccabees", chapter: 14, verse: 33, text: "And fortified the cities of Judea, together with Bethsura, that lieth upon the borders of Judea, where the armour of the enemies had been before; but he set a garrison of Jews there:" },
  { book: "1 Maccabees", chapter: 14, verse: 34, text: "Moreover he fortified Joppa, which lieth upon the sea, and Gazera, that bordereth upon Azotus, where the enemies had dwelt before: but he placed Jews there, and furnished them with all things convenient for the reparation thereof.)" },
  { book: "1 Maccabees", chapter: 14, verse: 35, text: "The people therefore sang the acts of Simon, and unto what glory he thought to bring his nation, made him their governor and chief priest, because he had done all these things, and for the justice and faith which he kept to his nation, and for that he sought by all means to exalt his people." },
  { book: "1 Maccabees", chapter: 14, verse: 36, text: "For in his time things prospered in his hands, so that the heathen were taken out of their country, and they also that were in the city of David in Jerusalem, who had made themselves a tower, out of which they issued, and polluted all about the sanctuary, and did much hurt in the holy place:" },
  { book: "1 Maccabees", chapter: 14, verse: 37, text: "But he placed Jews therein. and fortified it for the safety of the country and the city, and raised up the walls of Jerusalem." },
  { book: "1 Maccabees", chapter: 14, verse: 38, text: "King Demetrius also confirmed him in the high priesthood according to those things," },
  { book: "1 Maccabees", chapter: 14, verse: 39, text: "And made him one of his friends, and honoured him with great honour." },
  { book: "1 Maccabees", chapter: 14, verse: 40, text: "For he had heard say, that the Romans had called the Jews their friends and confederates and brethren; and that they had entertained the ambassadors of Simon honourably;" },
  { book: "1 Maccabees", chapter: 14, verse: 41, text: "Also that the Jews and priests were well pleased that Simon should be their governor and high priest for ever, until there should arise a faithful prophet;" },
  { book: "1 Maccabees", chapter: 14, verse: 42, text: "Moreover that he should be their captain, and should take charge of the sanctuary, to set them over their works, and over the country, and over the armour, and over the fortresses, that, I say, he should take charge of the sanctuary;" },
  { book: "1 Maccabees", chapter: 14, verse: 43, text: "Beside this, that he should be obeyed of every man, and that all the writings in the country should be made in his name, and that he should be clothed in purple, and wear gold:" },
  { book: "1 Maccabees", chapter: 14, verse: 44, text: "Also that it should be lawful for none of the people or priests to break any of these things, or to gainsay his words, or to gather an assembly in the country without him, or to be clothed in purple, or wear a buckle of gold;" },
  { book: "1 Maccabees", chapter: 14, verse: 45, text: "And whosoever should do otherwise, or break any of these things, he should be punished." },
  { book: "1 Maccabees", chapter: 14, verse: 46, text: "Thus it liked all the people to deal with Simon, and to do as hath been said." },
  { book: "1 Maccabees", chapter: 14, verse: 47, text: "Then Simon accepted hereof, and was well pleased to be high priest, and captain and governor of the Jews and priests, and to defend them all." },
  { book: "1 Maccabees", chapter: 14, verse: 48, text: "So they commanded that this writing should be put in tables of brass, and that they should be set up within the compass of the sanctuary in a conspicuous place;" },
  { book: "1 Maccabees", chapter: 14, verse: 49, text: "Also that the copies thereof should be laid up in the treasury, to the end that Simon and his sons might have them." },
  { book: "1 Maccabees", chapter: 15, verse: 1, text: "Moreover Antiochus son of Demetrius the king sent letters from the isles of the sea unto Simon the priest and prince of the Jews, and to all the people;" },
  { book: "1 Maccabees", chapter: 15, verse: 2, text: "The contents whereof were these: King Antiochus to Simon the high priest and prince of his nation, and to the people of the Jews, greeting:" },
  { book: "1 Maccabees", chapter: 15, verse: 3, text: "Forasmuch as certain pestilent men have usurped the kingdom of our fathers, and my purpose is to challenge it again, that I may restore it to the old estate, and to that end have gathered a multitude of foreign soldiers together, and prepared ships of war;" },
  { book: "1 Maccabees", chapter: 15, verse: 4, text: "My meaning also being to go through the country, that I may be avenged of them that have destroyed it, and made many cities in the kingdom desolate:" },
  { book: "1 Maccabees", chapter: 15, verse: 5, text: "Now therefore I confirm unto thee all the oblations which the kings before me granted thee, and whatsoever gifts besides they granted." },
  { book: "1 Maccabees", chapter: 15, verse: 6, text: "I give thee leave also to coin money for thy country with thine own stamp." },
  { book: "1 Maccabees", chapter: 15, verse: 7, text: "And as concerning Jerusalem and the sanctuary, let them be free; and all the armour that thou hast made, and fortresses that thou hast built, and keepest in thine hands, let them remain unto thee." },
  { book: "1 Maccabees", chapter: 15, verse: 8, text: "And if anything be, or shall be, owing to the king, let it be forgiven thee from this time forth for evermore." },
  { book: "1 Maccabees", chapter: 15, verse: 9, text: "Furthermore, when we have obtained our kingdom, we will honour thee, and thy nation, and thy temple, with great honour, so that your honour shall be known throughout the world." },
  { book: "1 Maccabees", chapter: 15, verse: 10, text: "In the hundred threescore and fourteenth year went Antiochus into the land of his fathers: at which time all the forces came together unto him, so that few were left with Tryphon." },
  { book: "1 Maccabees", chapter: 15, verse: 11, text: "Wherefore being pursued by king Antiochus, he fled unto Dora, which lieth by the sea side:" },
  { book: "1 Maccabees", chapter: 15, verse: 12, text: "For he saw that troubles came upon him all at once, and that his forces had forsaken him." },
  { book: "1 Maccabees", chapter: 15, verse: 13, text: "Then camped Antiochus against Dora, having with him an hundred and twenty thousand men of war, and eight thousand horsemen." },
  { book: "1 Maccabees", chapter: 15, verse: 14, text: "And when he had compassed the city round about, and joined ships close to the town on the sea side, he vexed the city by land and by sea, neither suffered he any to go out or in." },
  { book: "1 Maccabees", chapter: 15, verse: 15, text: "In the mean season came Numenius and his company from Rome, having letters to the kings and countries; wherein were written these things:" },
  { book: "1 Maccabees", chapter: 15, verse: 16, text: "Lucius, consul of the Romans unto king Ptolemee, greeting:" },
  { book: "1 Maccabees", chapter: 15, verse: 17, text: "The Jews’ ambassadors, our friends and confederates, came unto us to renew the old friendship and league, being sent from Simon the high priest, and from the people of the Jews:" },
  { book: "1 Maccabees", chapter: 15, verse: 18, text: "And they brought a shield of gold of a thousand pound." },
  { book: "1 Maccabees", chapter: 15, verse: 19, text: "We thought it good therefore to write unto the kings and countries, that they should do them no harm, nor fight against them, their cities, or countries, nor yet aid their enemies against them." },
  { book: "1 Maccabees", chapter: 15, verse: 20, text: "It seemed also good to us to receive the shield of them." },
  { book: "1 Maccabees", chapter: 15, verse: 21, text: "If therefore there be any pestilent fellows, that have fled from their country unto you, deliver them unto Simon the high priest, that he may punish them according to their own law." },
  { book: "1 Maccabees", chapter: 15, verse: 22, text: "The same things wrote he likewise unto Demetrius the king, and Attalus, to Ariarathes, and Arsaces," },
  { book: "1 Maccabees", chapter: 15, verse: 23, text: "And to all the countries and to Sampsames, and the Lacedemonians, and to Delus, and Myndus, and Sicyon, and Caria, and Samos, and Pamphylia, and Lycia, and Halicarnassus, and Rhodus, and Aradus, and Cos, and Side, and Aradus, and Gortyna, and Cnidus, and Cyprus, and Cyrene." },
  { book: "1 Maccabees", chapter: 15, verse: 24, text: "And the copy hereof they wrote to Simon the high priest." },
  { book: "1 Maccabees", chapter: 15, verse: 25, text: "So Antiochus the king camped against Dora the second day, assaulting it continually, and making engines, by which means he shut up Tryphon, that he could neither go out nor in." },
  { book: "1 Maccabees", chapter: 15, verse: 26, text: "At that time Simon sent him two thousand chosen men to aid him; silver also, and gold, and much armour." },
  { book: "1 Maccabees", chapter: 15, verse: 27, text: "Nevertheless he would not receive them, but brake all the covenants which he had made with him afore, and became strange unto him." },
  { book: "1 Maccabees", chapter: 15, verse: 28, text: "Furthermore he sent unto him Athenobius, one of his friends, to commune with him, and say, Ye withhold Joppa and Gazera; with the tower that is in Jerusalem, which are cities of my realm." },
  { book: "1 Maccabees", chapter: 15, verse: 29, text: "The borders thereof ye have wasted, and done great hurt in the land, and got the dominion of many places within my kingdom." },
  { book: "1 Maccabees", chapter: 15, verse: 30, text: "Now therefore deliver the cities which ye have taken, and the tributes of the places, whereof ye have gotten dominion without the borders of Judea:" },
  { book: "1 Maccabees", chapter: 15, verse: 31, text: "Or else give me for them five hundred talents of silver; and for the harm that ye have done, and the tributes of the cities, other five hundred talents: if not, we will come and fight against you" },
  { book: "1 Maccabees", chapter: 15, verse: 32, text: "So Athenobius the king’s friend came to Jerusalem: and when he saw the glory of Simon, and the cupboard of gold and silver plate, and his great attendance, he was astonished, and told him the king’s message." },
  { book: "1 Maccabees", chapter: 15, verse: 33, text: "Then answered Simon, and said unto him, We have neither taken other men’s land, nor holden that which appertaineth to others, but the inheritance of our fathers, which our enemies had wrongfully in possession a certain time." },
  { book: "1 Maccabees", chapter: 15, verse: 34, text: "Wherefore we, having opportunity, hold the inheritance of our fathers." },
  { book: "1 Maccabees", chapter: 15, verse: 35, text: "And whereas thou demandest Joppa and Gazera, albeit they did great harm unto the people in our country, yet will we give thee an hundred talents for them. Hereunto Athenobius answered him not a word;" },
  { book: "1 Maccabees", chapter: 15, verse: 36, text: "But returned in a rage to the king, and made report unto him of these speeches, and of the glory of Simon, and of all that he had seen: whereupon the king was exceeding wroth." },
  { book: "1 Maccabees", chapter: 15, verse: 37, text: "In the mean time fled Tryphon by ship unto Orthosias." },
  { book: "1 Maccabees", chapter: 15, verse: 38, text: "Then the king made Cendebeus captain of the sea coast, and gave him an host of footmen and horsemen," },
  { book: "1 Maccabees", chapter: 15, verse: 39, text: "And commanded him to remove his host toward Judea; also he commanded him to build up Cedron, and to fortify the gates, and to war against the people; but as for the king himself, he pursued Tryphon." },
  { book: "1 Maccabees", chapter: 15, verse: 40, text: "So Cendebeus came to Jamnia and began to provoke the people and to invade Judea, and to take the people prisoners, and slay them." },
  { book: "1 Maccabees", chapter: 15, verse: 41, text: "And when he had built up Cedrou, he set horsemen there, and an host of footmen, to the end that issuing out they might make outroads upon the ways of Judea, as the king had commanded him." },
  { book: "1 Maccabees", chapter: 16, verse: 1, text: "Then came up John from Gazera, and told Simon his father what Cendebeus had done." },
  { book: "1 Maccabees", chapter: 16, verse: 2, text: "Wherefore Simon called his two eldest sons, Judas and John, and said unto them, I, and my brethren, and my father’s house, have ever from my youth unto this day fought against the enemies of Israel; and things have prospered so well in our hands, that we have delivered Israel oftentimes." },
  { book: "1 Maccabees", chapter: 16, verse: 3, text: "But now I am old, and ye, by God’s mercy, are of a sufficient age: be ye instead of me and my brother, and go and fight for our nation, and the help from heaven be with you." },
  { book: "1 Maccabees", chapter: 16, verse: 4, text: "So he chose out of the country twenty thousand men of war with horsemen, who went out against Cendebeus, and rested that night at Modin." },
  { book: "1 Maccabees", chapter: 16, verse: 5, text: "And when as they rose in the morning, and went into the plain, behold, a mighty great host both of footmen and horsemen came against them: howbeit there was a water brook betwixt them." },
  { book: "1 Maccabees", chapter: 16, verse: 6, text: "So he and his people pitched over against them: and when he saw that the people were afraid to go over the water brook, he went first over himself, and then the men seeing him passed through after him." },
  { book: "1 Maccabees", chapter: 16, verse: 7, text: "That done, he divided his men, and set the horsemen in the midst of the footmen: for the enemies’ horsemen were very many." },
  { book: "1 Maccabees", chapter: 16, verse: 8, text: "Then sounded they with the holy trumpets: whereupon Cendebeus and his host were put to flight, so that many of them were slain, and the remnant gat them to the strong hold." },
  { book: "1 Maccabees", chapter: 16, verse: 9, text: "At that time was Judas John’s brother wounded; but John still followed after them, until he came to Cedron, which Cendebeus had built." },
  { book: "1 Maccabees", chapter: 16, verse: 10, text: "So they fled even unto the towers in the fields of Azotus; wherefore he burned it with fire: so that there were slain of them about two thousand men. Afterward he returned into the land of Judea in peace." },
  { book: "1 Maccabees", chapter: 16, verse: 11, text: "Moreover in the plain of Jericho was Ptolemeus the son of Abubus made captain, and he had abundance of silver and gold:" },
  { book: "1 Maccabees", chapter: 16, verse: 12, text: "For he was the high priest’s son in law." },
  { book: "1 Maccabees", chapter: 16, verse: 13, text: "Wherefore his heart being lifted up, he thought to get the country to himself, and thereupon consulted deceitfully against Simon and his sons to destroy them." },
  { book: "1 Maccabees", chapter: 16, verse: 14, text: "Now Simon was visiting the cities that were in the country, and taking care for the good ordering of them; at which time he came down himself to Jericho with his sons, Mattathias and Judas, in the hundred threescore and seventeenth year, in the eleventh month, called Sabat:" },
  { book: "1 Maccabees", chapter: 16, verse: 15, text: "Where the son of Abubus receiving them deceitfully into a little hold, called Docus, which he had built, made them a great banquet: howbeit he had hid men there." },
  { book: "1 Maccabees", chapter: 16, verse: 16, text: "So when Simon and his sons had drunk largely, Ptolemee and his men rose up, and took their weapons, and came upon Simon into the banqueting place, and slew him, and his two sons, and certain of his servants." },
  { book: "1 Maccabees", chapter: 16, verse: 17, text: "In which doing he committed a great treachery, and recompensed evil for good." },
  { book: "1 Maccabees", chapter: 16, verse: 18, text: "Then Ptolemee wrote these things, and sent to the king, that he should send him an host to aid him, and he would deliver him the country and cities." },
  { book: "1 Maccabees", chapter: 16, verse: 19, text: "He sent others also to Gazera to kill John: and unto the tribunes he sent letters to come unto him, that he might give them silver, and gold, and rewards." },
  { book: "1 Maccabees", chapter: 16, verse: 20, text: "And others he sent to take Jerusalem, and the mountain of the temple." },
  { book: "1 Maccabees", chapter: 16, verse: 21, text: "Now one had run afore to Gazera and told John that his father and brethren were slain, and, quoth he, Ptolemee hath sent to slay thee also." },
  { book: "1 Maccabees", chapter: 16, verse: 22, text: "Hereof when he heard, he was sore astonished: so he laid hands on them that were come to destroy him, and slew them; for he knew that they sought to make him away." },
  { book: "1 Maccabees", chapter: 16, verse: 23, text: "As concerning the rest of the acts of John, and his wars, and worthy deeds which he did, and the building of the walls which he made, and his doings," },
  { book: "1 Maccabees", chapter: 16, verse: 24, text: "Behold, these are written in the chronicles of his priesthood, from the time he was made high priest after his father." },
  // 1 Meqabyan (146 verses)
  { book: "1 Meqabyan", chapter: 1, verse: 1, text: "There was one man whose name was called Tseerutsaydan and he loved sin. He would boast in his horses' abundance and his troops' firmness beneath his authority." },
  { book: "1 Meqabyan", chapter: 1, verse: 2, text: "He had many priests who served his idols whom he worshipped, and for whom he bowed and sacrificed sacrifices by night and by daylight." },
  { book: "1 Meqabyan", chapter: 1, verse: 3, text: "But in his heart's dullness, it would seem to him that they gave him firmness and power." },
  { book: "1 Meqabyan", chapter: 1, verse: 4, text: "And in his heart, it would seem to him that they gave him authority in all his rule." },
  { book: "1 Meqabyan", chapter: 1, verse: 5, text: "And again, in formation time, it would seem to him that they gave him all the desired authority also." },
  { book: "1 Meqabyan", chapter: 1, verse: 6, text: "And he would sacrifice sacrifice for them day and night." },
  { book: "1 Meqabyan", chapter: 1, verse: 7, text: "He appointed priests who served his idols." },
  { book: "1 Meqabyan", chapter: 1, verse: 8, text: "While they ate from that defiled sacrifice, they would tell him, pretending that the idols eat night and day." },
  { book: "1 Meqabyan", chapter: 1, verse: 9, text: "Again, they would make other persons diligent like unto them - that they might sacrifice and eat. And again, they would make other persons diligent that they might sacrifice like unto them." },
  { book: "1 Meqabyan", chapter: 1, verse: 10, text: "But he would trust in his idols that don't profit nor benefit." },
  { book: "1 Meqabyan", chapter: 1, verse: 11, text: "By his timeframe being small - and in his heart's dullness - it would seem to him that they irked him - that they fed him and crowned him. It would seem to him that they irked him - for Satan had deafened his reasoning lest he know his creator who irked him, bringing him from not living towards living - or lest he with his kindreds know his creator who irked him, bringing him from not living towards living - that they might go toward Gehannem of Fiyah forever - it being judged upon them with him who call them gods without them being gods." },
  { book: "1 Meqabyan", chapter: 1, verse: 12, text: "As they are never well whenever, it is due that he might call them dead ones." },
  { book: "1 Meqabyan", chapter: 1, verse: 13, text: "As Satan's authority that misleads them will lodge in that idol image - and as he will tell them their reasoning according - and as he will reveal to them like unto what they loved - he will judge upon the idols wherein they believed and wherein 'Adam childran trust - whose reasoning was like unto ashes." },
  { book: "1 Meqabyan", chapter: 1, verse: 14, text: "And they will marvel upon the time they sight up that he fulfilled what they thought for them - and they will do him according for him reaching up till they sacrifice their daughter children and their male children birthed from their nature - up till they spill their daughter children and male children's blood that was clean." },
  { book: "1 Meqabyan", chapter: 1, verse: 15, text: "They were not sad, for Satan had enjoyed their sacrifice to fulfill their evil agreement. He wanted to drag them down to Gehenna with him, where there is no escape for eternity, and where they would receive torment." },
  { book: "1 Meqabyan", chapter: 1, verse: 16, text: "But that Tseerutsaydan were arrogant. He had fifty idols worked in a males pattern and twenty worked in a females pattern." },
  { book: "1 Meqabyan", chapter: 1, verse: 19, text: "They had five houses built for themselves, decorated with idols made of iron, brass, and lead." },
  { book: "1 Meqabyan", chapter: 1, verse: 20, text: "They adorned them with silver and gold, and covered them with curtains and tents." },
  { book: "1 Meqabyan", chapter: 1, verse: 21, text: "They appointed keepers for the idols and would continually sacrifice forty animals to them: ten fat oxen, ten barren cows, ten fat sheep, and ten barren goats, along with birds that had wings." },
  { book: "1 Meqabyan", chapter: 1, verse: 22, text: "They believed that their idols ate, so they presented them with fifty baskets of grapes and fifty dishes of wheat kneaded with oil." },
  { book: "1 Meqabyan", chapter: 1, verse: 23, text: "They told their priests to take and give the offerings to them, and they would eat what was slaughtered for them and drink the wine presented to them. If it was not enough, they would add more." },
  { book: "1 Meqabyan", chapter: 1, verse: 24, text: "They commanded all to eat and drink from the defiled sacrifice." },
  { book: "1 Meqabyan", chapter: 1, verse: 25, text: "But out of their evil malice, they sent troops throughout the kingdom to find anyone who did not offer sacrifices or bow down to the idols. They would capture and punish them with fire and sword before them, plunder their money, burn their homes, and destroy all their possessions." },
  { book: "1 Meqabyan", chapter: 1, verse: 26, text: "They said, \"For they are merciful and great, and they are angry with us for our wickedness. I will show punishment and tribulation to anyone who does not worship my idols and offer sacrifices to them." },
  { book: "1 Meqabyan", chapter: 1, verse: 27, text: "And I will show them punishment and tribulation, for they have angered the Earth, the Heaven, the sea, the wide moon, the sun, the stars, the rains, the winds, and all that live in this world to be food and to be satisfied with us.\"" },
  { book: "1 Meqabyan", chapter: 1, verse: 28, text: "But those who worship them will be punished with firm tribulation, and it will not be pleasant for them." },
  { book: "1 Meqabyan", chapter: 2, verse: 1, text: "There was a man born from the tribe of Benjamin whose name was called Maccabeus." },
  { book: "1 Meqabyan", chapter: 2, verse: 2, text: "He had three children who were handsome and totally warriors. They had been loved by all the people in the Midian and Median countries that were under the rule of the Seleucid King." },
  { book: "1 Meqabyan", chapter: 2, verse: 3, text: "And like the king commanded them when he found them: \"Don't you bow to the Seleucid idols? How about not sacrificing?" },
  { book: "1 Meqabyan", chapter: 2, verse: 4, text: "But if you refuse, we will seize and take you to the king, and we will destroy all your money as the king commanded.\"" },
  { book: "1 Meqabyan", chapter: 2, verse: 5, text: "These handsome youths replied to him, saying, \"As for Him whom we bow, there is our Father Creator who created the Earth and Heaven and everything within it, the sea, moon and sun, clouds, and stars. He is the True Creator whom we worship and in whom we believe.\"" },
  { book: "1 Meqabyan", chapter: 2, verse: 6, text: "And these youths of the king were four, and the servants who carried shields and spears were a hundred." },
  { book: "1 Meqabyan", chapter: 2, verse: 7, text: "And when they wanted to seize these holy ones, they escaped from their hands, and there were none who could touch them, for these youths were totally warriors in power, seizing shields and spears." },
  { book: "1 Meqabyan", chapter: 2, verse: 8, text: "And there was one among them who could strangle and kill a panther, and at that time, he would strangle it like a chicken." },
  { book: "1 Meqabyan", chapter: 2, verse: 9, text: "And there was one among them who killed a lion with one rock or struck it with a stick at one time." },
  { book: "1 Meqabyan", chapter: 2, verse: 10, text: "And there was one among them who killed a hundred people in formation with one sword, and their name and their deeds were thus. It was called in all" },
  { book: "1 Meqabyan", chapter: 2, verse: 11, text: "And they were warriors in power, and they had a thing being loved and comeliness." },
  { book: "1 Meqabyan", chapter: 2, verse: 12, text: "And again, their features and comeliness were wondrous. However, because they worshiped JAH and did not fear death, it was their reasoning and comeliness that surpassed all." },
  { book: "1 Meqabyan", chapter: 2, verse: 13, text: "And when they frightened the troops, there were none who could seize them, but those who were warriors escaped, proceeding toward a lofty mountain." },
  { book: "1 Meqabyan", chapter: 2, verse: 14, text: "And those troops returned to the city and shut the fortress gate. They terrorized the people, saying, \"Unless you bring those warriors, the Maccabees, we will burn your city in fire, and we will send for the king and destroy your country.\"" },
  { book: "1 Meqabyan", chapter: 2, verse: 15, text: "And at that time, the country people - both rich and poor, daughters and sons - a child whose father and mother died upon him and an old daughter, everyone proceeded and shouted togethe, and they straightened their necks toward the mountain and shouted toward them, saying, \"Don't destroy us and don't destroy our country for us.\"" },
  { book: "1 Meqabyan", chapter: 2, verse: 16, text: "At that time, they wept together and they feared, arising from JAH." },
  { book: "1 Meqabyan", chapter: 2, verse: 17, text: "Returning their faces eastward and stretching forth their hands, they begged toward JAH together, \"Lord, should we refuse these men who demolished" },
  { book: "1 Meqabyan", chapter: 2, verse: 18, text: "Yet they believed in silver and gold and in the stone and wood that a person's hands worked. But we don't love that we might hear that criminal word - who didn't believe Thy law.\" they said." },
  { book: "1 Meqabyan", chapter: 2, verse: 20, text: "But we don't love that we might see that criminal face nor hear his word,\" they said." },
  { book: "1 Meqabyan", chapter: 2, verse: 22, text: "But we believe in Thee, Lord who examines kidneys and reasonings - our fathers' Creator - Abraham and Isaac and Jacob who did Thy accord and lived firmly in Thy law." },
  { book: "1 Meqabyan", chapter: 2, verse: 23, text: "Thou examine a person's reasoning and help the sinner and the righteous one - and there be none hidden from Thee. And he who took refuge is revealed alongside Thee." },
  { book: "1 Meqabyan", chapter: 2, verse: 24, text: "But we have no other Creator apart from Thee." },
  { book: "1 Meqabyan", chapter: 2, verse: 25, text: "That we might give our bodies for death because of Thy glorified name - however be power and firmness and a shelter for us in this work that we are ruled for Thee." },
  { book: "1 Meqabyan", chapter: 2, verse: 26, text: "And on the time 'Israel entered toward Gibeon country, Thou heard Jacob's plea and now glorified God - we beg Thee.\"" },
  { book: "1 Meqabyan", chapter: 2, verse: 28, text: "Their features' comeliness became totally handsome and they shone more than the sun - and they became more handsome than formerly." },
  { book: "1 Meqabyan", chapter: 3, verse: 1, text: "Like unto you, these were the Most High JAH's slaves, Abya, Seela, and Fentos, who died and arose, so that you may also arise after your death, and your faces shall shine like the sun in the Kingdom of Heaven." },
  { book: "1 Meqabyan", chapter: 3, verse: 2, text: "And they went with those men and received martyrdom there." },
  { book: "1 Meqabyan", chapter: 3, verse: 3, text: "At that time, they begged, praised, and bowed to JAH. Death did not frighten them, nor did the king's punishment." },
  { book: "1 Meqabyan", chapter: 3, verse: 4, text: "They went towards those youths and were as meek as sheep that have no evil. Yet, they were not afraid. When they arrived towards them, they seized, beat, bound, whipped them, and delivered them to the king and stood them before him." },
  { book: "1 Meqabyan", chapter: 3, verse: 5, text: "The king answered them, saying, \"How can you stubborn ones not sacrifice and bow to my idols?\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 6, text: "The brothers who were cleansed from sin, honoured, chosen, and blessed, and shone like jewels with wondrous value - Seela, Abya, and Fentos - answered him with one word." },
  { book: "1 Meqabyan", chapter: 3, verse: 7, text: "They told the king, who was a plague, \"As for us, we will not bow nor sacrifice to defiled idols that have no knowledge or reasoning.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 8, text: "They again told him, \"We will not bow to idols that were silver and gold, that were made by hand, or that were stone and wood, that have no reasoning, soul, or knowledge, and that do not benefit their friends or harm their enemies.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 9, text: "The king asked them, \"Why do you do this? And as you know who insulted you and who wronged you, why do you insult the glorified idols?\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 10, text: "They answered him, saying, \"As they are like a trifle compared to us, we will insult them and will not glorify them.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 11, text: "The king said to them, \"I will punish you like your evil works and will destroy your beautiful faces with whipping, firm tribulation, and fire.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 13, text: "They answered him, saying, \"As for us, we will not sacrifice nor bow to defiled idols,\" and the king commanded that they be beaten with a fat stick, whipped with a whip, and splintered until their inner organs were visible." },
  { book: "1 Meqabyan", chapter: 3, verse: 14, text: "After this, they were bound and held in a jailhouse until the king's council decided to punish and kill them." },
  { book: "1 Meqabyan", chapter: 3, verse: 15, text: "They were taken without kindness, bound, and held in a firm imprisonment in a prison house, and they sat there for three nights and three days." },
  { book: "1 Meqabyan", chapter: 3, verse: 16, text: "And after the third day, the king commanded that a proclamation speaker should announce and that counselors, nobles, country elders, and officials should be gathered." },
  { book: "1 Meqabyan", chapter: 3, verse: 17, text: "And at that time, King Tseerutsaydan sat in a square, and he commanded that the honored ones, Seela, 'Abya, and Fentos, be brought before him, being wounded and bound." },
  { book: "1 Meqabyan", chapter: 3, verse: 18, text: "And the king told them, \"During these three days that you have sat, have you truly repented and turned away from your former evil ways?\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 19, text: "And the honored Jah soldiers answered him, saying, \"We have not worshiped the idols filled with sin and evil that you have set before us. We will not abandon the laws of JAH.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 20, text: "And the king, being angry, commanded that they be taken to a high place, their wounds reopened, and their blood flowed on the earth." },
  { book: "1 Meqabyan", chapter: 3, verse: 21, text: "And he commanded that they be burned with a torch lamp and that their flesh be charred, and his servants did as he commanded. But the honored men said to him, \"You, who have forgotten JAH's law, speak. Our reward shall be as great as the measure of your punishment.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 22, text: "And he commanded that bears, tigers, and lions, evil beasts, be sent upon them to eat their flesh with their bones." },
  { book: "1 Meqabyan", chapter: 3, verse: 23, text: "And he commanded those who kept the beasts to release them upon the men, and they did as they were commanded. The honored martyrs' feet were bound, and they were beaten and bound again with tent-stakes." },
  { book: "1 Meqabyan", chapter: 3, verse: 24, text: "And the beasts were flung upon them while they roared, but as they arrived toward the martyrs, they hailed and bowed to them." },
  { book: "1 Meqabyan", chapter: 3, verse: 25, text: "They returned towards their keepers while they roared, and they frightened their keepers. Then they were taken towards the square until they were delivered before the king." },
  { book: "1 Meqabyan", chapter: 3, verse: 26, text: "And seventy-five men from the criminal's army were killed there." },
  { book: "1 Meqabyan", chapter: 3, verse: 27, text: "Many persons panicked, some in anguish and others in fear, until the king quit his throne and fled. The beasts were seized with difficulty and taken to their lodgings." },
  { book: "1 Meqabyan", chapter: 3, verse: 28, text: "Seela, 'Abya, and Fentos, two brothers, came and released the prisoners from their bondage. They told them, \"Come, let us flee, lest these skeptics and criminals find us.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 29, text: "And those martyrs answered their brethren, saying, \"It is not fitting that we might flee after we have set up this testimony, as if you had feared. Go fleeing.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 30, text: "And those little brethren said, \"We will stand with you before the king, and if you die, we will die with you.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 31, text: "And after this, the king was on his lordship balcony and saw that these honored men were released and that all the five brethren stood together. Those chiefs who worked and punished the troops questioned whether they were brethren and told the king. The king was angry and shouted like a wild boar in the wilderness." },
  { book: "1 Meqabyan", chapter: 3, verse: 32, text: "And until the king was counseled by money to punish all the five brethren, he commanded that they might seize and add them to the prison house. They placed them in a prison house, binding them in firm imprisonment without kindness with a hollow stalk." },
  { book: "1 Meqabyan", chapter: 3, verse: 33, text: "And the king Tseerutsaydan said, \"These youths who erred wearied me. What should these men reason firmly for? And those who work evil are like those with power and firmness. If I say, 'They will return,' they will make their reasoning evil." },
  { book: "1 Meqabyan", chapter: 3, verse: 34, text: "And I will bring hardship on them like their evil measure. And I will burn their flesh in fire until it is charred ash, and then I will scatter their flesh ash like dust on the mountains.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 35, text: "And after he spoke this, he waited three days and commanded that those honored men be brought. At the time when those honored men approached him, he commanded that a fire be burned within the great pit oven and that a malice work be added to the flame of the fire, wherein they boiled a cat, the fat and soapberries, sea foam and resin, and sulfur." },
  { book: "1 Meqabyan", chapter: 3, verse: 36, text: "And at the time the fire flamed in the pit, the messengers went to the king and said, \"We did what you commanded us. Send the men who will be added.\"" },
  { book: "1 Meqabyan", chapter: 3, verse: 37, text: "And he commanded that they might receive and cast them into the fire pit, and the youths did as the king commanded them. At the time when those honored men entered into the fire, they gave their souls to JAH." },
  { book: "1 Meqabyan", chapter: 3, verse: 38, text: "And when the persons who cast them saw, angels received and took their souls to the Garden where Isaac, Abraham, and Jacob are, where the righteous ones are found." },
  { book: "1 Meqabyan", chapter: 4, verse: 1, text: "When the criminals were sentenced to death, he commanded that their flesh be burned in fire until it turned to ash, and then scattered in the wind. However, the fire could not burn the hair on the side of the corpses. Thus, they were sent away from the pit." },
  { book: "1 Meqabyan", chapter: 4, verse: 2, text: "Again, they set fire to them from morning until evening, but the fire could not burn them. Then they said, \"Let us cast their corpses into the sea.\"" },
  { book: "1 Meqabyan", chapter: 4, verse: 3, text: "So, they did as the king commanded, and cast them into the sea, even adding great stones, iron hearthstones, and a millstone that a donkey would grind by turning. Yet, the sea did not sink them, for the Spirit of JAH supported them. They floated on the sea, yet did not sink. The malice that was provoked against them failed to destroy them." },
  { book: "1 Meqabyan", chapter: 4, verse: 5, text: "The youths did as he commanded. Vultures and beasts did not touch the corpses. Birds and vultures veiled them with their wings from the burning sun, and the corpses of the five martyrs sat for fourteen days." },
  { book: "1 Meqabyan", chapter: 4, verse: 6, text: "When they were sighted, their bodies shone like the sun, and angels encircled their corpses like the light encircling the Tent." },
  { book: "1 Meqabyan", chapter: 4, verse: 7, text: "He sought counsel, but he did not know what to do. Finally, he dug a grave and buried the five martyrs' corpses." },
  { book: "1 Meqabyan", chapter: 4, verse: 8, text: "Later that night, as the king who had forgotten JAH's law lay in bed, the five martyrs appeared before him, standing and vexing him with swords." },
  { book: "1 Meqabyan", chapter: 4, verse: 9, text: "He thought they had entered his house at night to commit a crime. When he woke from his slumber, he was afraid and fled from his bedchamber to the hall. He feared that they would kill him for the crime he thought they had committed against him. His knees trembled in fear." },
  { book: "1 Meqabyan", chapter: 4, verse: 11, text: "They answered, \"Aren't we the ones you burned in the fire and commanded to be cast into the sea? JAH kept our bodies because we believed in Him. He did not let you destroy us. As those who believe in Him will not perish, let glory and praise be due to JAH. We who believed in Him did not shame in tribulation.\"" },
  { book: "1 Meqabyan", chapter: 4, verse: 14, text: "For I have wronged you, forgive my sin, for it was because of JAH's law that I received such kindness,\" he told them." },
  { book: "1 Meqabyan", chapter: 4, verse: 15, text: "And those honoured martyrs answered him saying, \"Because of the harm you have inflicted upon us, we will not repay you with harm. It is JAH who brings hardship upon a soul, and it is He who will judge you accordingly.\"" },
  { book: "1 Meqabyan", chapter: 4, verse: 16, text: "However, we were spared for your sake, as it seemed to you that you killed us. You showed us kindness despite our small numbers and our inability to reason." },
  { book: "1 Meqabyan", chapter: 4, verse: 17, text: "But you and the priests of your idols will descend into Gehenna, where there is no escape." },
  { book: "1 Meqabyan", chapter: 4, verse: 18, text: "Woe to your idols, before which you bowed down, forsaking JAH who was angry with you when you were scorned like spit. Woe to you who worship them, and do not know JAH who was angry with you and brought you from death to life. Are you who are standing here today not like smoke that will vanish tomorrow?" },
  { book: "1 Meqabyan", chapter: 4, verse: 19, text: "The king asked them, \"What do you command me to do for you, since you have shown me such love?\"" },
  { book: "1 Meqabyan", chapter: 4, verse: 20, text: "They replied, \"Save yourself from entering the Gehenna of Fire, but you cannot save us. We are the ones who teach you.\"" },
  { book: "1 Meqabyan", chapter: 4, verse: 26, text: "The king was alarmed and completely astonished. As all five drew their swords, he feared for his life and bowed to them." },
  { book: "1 Meqabyan", chapter: 4, verse: 28, text: "From that day on, the king no longer burned the corpses of the Tseerutsaydan who were completely arrogant, and they were hidden from his sight." },
  { book: "1 Meqabyan", chapter: 4, verse: 29, text: "As they have misled many for many eras, the idolaters reasoned in error and misled many others like them until they stopped following JAH's worship. It wasn't only them who erred." },
  { book: "1 Meqabyan", chapter: 4, verse: 30, text: "They sacrificed their daughters and sons to demons, practicing seduction and disturbances as their rationale. Satan taught them this, so they could practice seduction and disturbances that JAH detests." },
  { book: "1 Meqabyan", chapter: 4, verse: 31, text: "They married their mothers and abused their aunts and sisters, defiling their bodies while doing all these filthy works. Satan confirmed these perverse people's reasoning, and they said, \"We won't return.\"" },
  { book: "1 Meqabyan", chapter: 4, verse: 32, text: "But the Tseerutsaydan, who didn't know JAH's wrath, were completely arrogant and boasted in their idols." },
  { book: "1 Meqabyan", chapter: 4, verse: 33, text: "If they say, \"How will JAH give the Kingdom to people who don't know Him in LAW and in Worship?\" They will fully return to Him in repentance, and He tests them for this reason." },
  { book: "1 Meqabyan", chapter: 4, verse: 34, text: "But if they completely repent, He will love them and keep their Kingdom. However, if they refuse, the fire of Gehenna will punish them forever." },
  { book: "1 Meqabyan", chapter: 4, verse: 35, text: "It is fitting for a king to fear JAH's wrath like his lordship's reputation, and it is fitting for a judge to be ruled by JAH's wrath while judging righteously, like his Rule's reputation." },
  { book: "1 Meqabyan", chapter: 4, verse: 36, text: "It is fitting for elders, chiefs, envoys, and petty kings to be commanded by those who fear JAH's wrath according to their lordship's abundance measure." },
  { book: "1 Meqabyan", chapter: 4, verse: 37, text: "JAH is the Lord of Heaven and Earth, who instills all wrath, for there is no other Lord in Heaven or Earth who impoverishes or enriches. He is the One who honors and debases." },
  { book: "1 Meqabyan", chapter: 7, verse: 1, text: "And whether you are a king or a ruler, what important thing are you?" },
  { book: "1 Meqabyan", chapter: 7, verse: 2, text: "Isn't it JAH who created you, bringing you from not living to living, so that you might do His will and might live strengthened by His command and might fear His judgment? Just as you trouble your slaves and govern over them, so also there is JAH who troubles you and governs over you." },
  { book: "1 Meqabyan", chapter: 7, verse: 3, text: "Just as you beat without mercy those who committed sin, so also there is JAH who will strike you and lower you toward Gehenna where there are no exits until eternity." },
  { book: "1 Meqabyan", chapter: 7, verse: 4, text: "Just as you whip him who was not ruled by you and didn't bring a tribute to you, why is it that you don't offer a tribute to JAH?" },
  { book: "1 Meqabyan", chapter: 7, verse: 5, text: "Since He is the One who created you so that you love those who might fear you, and who crowned you over all creation so that you might keep His people faithful, why is it that you don't fear your Creator JAH?" },
  { book: "1 Meqabyan", chapter: 7, verse: 6, text: "Judge by what is just and true, just as JAH appointed you; yet do not show partiality or favor to small or great. Whom will you fear besides Him? Keep His worship and the Nine Commandments." },
  { book: "1 Meqabyan", chapter: 7, verse: 7, text: "Just as Moses commanded the children of Israel, saying, \"I have presented water and fire to you; extend your hand toward what you love,\" do not go either right or left." },
  { book: "1 Meqabyan", chapter: 7, verse: 8, text: "Hear His word that I tell you, so that you might hear His word and might do His command, lest you say, \"It is beyond the sea or beyond the deep or beyond the river; who will bring it to me so that I might see it and might hear His word and might do His command?\"" },
  { book: "1 Meqabyan", chapter: 7, verse: 9, text: "Lest you say, \"Who will go up to Heaven again and bring down that word of JAH to me so that I might hear and do it?\" The word of JAH is what has approached; behold, for you to teach it with your mouth and give alms by it with your hand." },
  { book: "1 Meqabyan", chapter: 7, verse: 10, text: "And you did not hear your Creator JAH unless you heard His Book, and you did not love Him nor keep His command unless you kept His Law. And you will enter Gehenna forever if you do not love His command and unless you do the will of JAH, who honored and made you famous, separating you from all your people so that you might keep them faithful; you will enter Gehenna forever." },
  { book: "1 Meqabyan", chapter: 7, verse: 11, text: "He made you above all, and He crowned you over all His people so that you might rule His people faithfully by what is just, while you remembered the name of your Creator who created you and gave you a kingdom." },
  { book: "1 Meqabyan", chapter: 7, verse: 12, text: "There are those whom you whip for wronging you, and there are those whom you pardon while you consider the work of JAH, and there are those for whom you judge by what is just, straightening your reasoning." },
  { book: "1 Meqabyan", chapter: 7, verse: 13, text: "And do not show favor or partiality when they argue before you, for earthly possessions are your wealth. Do not accept a bribe so that you might pardon the sinner and wrong the innocent person." },
  { book: "1 Meqabyan", chapter: 7, verse: 14, text: "If you do His will, JAH will multiply your days in this world for you; but if you sadden Him, He will diminish your days." },
  { book: "1 Meqabyan", chapter: 7, verse: 15, text: "Consider that you will rise after you die, and that you will be examined standing before Him for all the work you have done, whether it be good or evil." },
  { book: "1 Meqabyan", chapter: 7, verse: 16, text: "If you do good work, you will live in a Garden in the Kingdom of Heaven, in houses where kind kings live and where Light fills. For JAH does not shame your lordship or authority; but if you do evil work, you will live in See'ol Gehenna where evil kings live." },
  { book: "1 Meqabyan", chapter: 7, verse: 17, text: "But when you see your feared fame, your warriors' reward, your hanging shield and spear, and when you see your horses and your troops under your authority and those who beat drums and people who play the harp before you..." },
  { book: "1 Meqabyan", chapter: 7, verse: 18, text: "But when you see all this, you make your reasoning lofty, and you stiffen your collar of reasoning, and you do not think of JAH who gave you all this honor; however, when He told you, \"Quit all this,\" you are not one who quits it." },
  { book: "1 Meqabyan", chapter: 7, verse: 19, text: "For you have totally neglected the appointment He appointed you, and He shall give your lordship to another." },
  { book: "1 Meqabyan", chapter: 7, verse: 20, text: "For death shall suddenly come upon you, and judgment shall be done in the resurrection time, and as all human work shall be examined, He shall totally investigate and judge you." },
  { book: "1 Meqabyan", chapter: 7, verse: 21, text: "There are none who will honor this world's kings, for because He is the True Judge, in judgment time poor and wealthy will stand together. This world's nobles' crowns in which they boast shall fall." },
  { book: "1 Meqabyan", chapter: 7, verse: 22, text: "Judgment is prepared, and a soul shall quake; at that time sinners' and righteous ones' work shall be examined." },
  { book: "1 Meqabyan", chapter: 7, verse: 23, text: "And there are none who shall be hidden. When a daughter arrived for birthing, and when the fetus in her belly arrived for being birthed, just as she cannot prevent her womb, Earth also cannot prevent her lodgers that are upon her; she will return." },
  { book: "1 Meqabyan", chapter: 7, verse: 24, text: "And just as clouds cannot prevent rain unless they take and rain toward the place JAH commanded them, for JAH's word has created all, bringing them from not living to living, and for JAH's word again has brought all toward a grave; and all likewise - after resurrection time arrived - it is not possible that dead persons will not rise." },
  { book: "1 Meqabyan", chapter: 7, verse: 25, text: "Just as Moses spoke, saying, \"It is by words that proceed from JAH's tongue; yet it is not only by grain that a person is saved\"; and JAH's word again shall arouse all persons from graves." },
  { book: "1 Meqabyan", chapter: 7, verse: 26, text: "Behold, it was known that dead persons shall arise by JAH's word." },
  { book: "1 Meqabyan", chapter: 7, verse: 27, text: "And again JAH said thus in Deuteronomy because of nobles and kings who do His will, \"As the day has arrived when they are counted for destruction, I shall avenge and destroy them on the day when judgment is judged and at the time when their feet stumble,\" He said." },
  { book: "1 Meqabyan", chapter: 7, verse: 28, text: "And again JAH told those who know His judgment, \"Know that I was your Creator JAH, and that I kill and I save.\"" },
  { book: "1 Meqabyan", chapter: 7, verse: 30, text: "JAH said thus because of nobles and kings who did not keep His Law, \"As earthly kingdoms are passing, and as they pass from morning until evening, keep My order and My Law so that you might enter toward the Kingdom of Heaven that lives strengthened forever,\" He said." },
  { book: "1 Meqabyan", chapter: 7, verse: 31, text: "For JAH's calling of righteous ones is for glory, and of sinners for tribulation; He will make the sinner wretched but will honor righteous ones." },
  { book: "1 Meqabyan", chapter: 7, verse: 32, text: "He will dismiss the person who did not do His will, but He will appoint the person who did His will." },
  // 2 Esdras (874 verses)
  { book: "2 Esdras", chapter: 1, verse: 1, text: "The second book of the prophet Esdras, the son of Saraias, the son of Azarias, the son of Helchias, the son of Sadamias, the son of Sadoc, the son of Achitob," },
  { book: "2 Esdras", chapter: 1, verse: 2, text: "The son of Achias, the son of Phinees, the son of Heli, the son of Amarias, the son of Aziei, the son of Marimoth, the son of And he spake unto the of Borith, the son of Abisei, the son of Phinees, the son of Eleazar," },
  { book: "2 Esdras", chapter: 1, verse: 3, text: "The son of Aaron, of the tribe of Levi; which was captive in the land of the Medes, in the reign of Artexerxes king of the Persians." },
  { book: "2 Esdras", chapter: 1, verse: 4, text: "And the word of the Lord came unto me, saying," },
  { book: "2 Esdras", chapter: 1, verse: 5, text: "Go thy way, and shew my people their sinful deeds, and their children their wickedness which they have done against me; that they may tell their children’s children:" },
  { book: "2 Esdras", chapter: 1, verse: 6, text: "Because the sins of their fathers are increased in them: for they have forgotten me, and have offered unto strange gods." },
  { book: "2 Esdras", chapter: 1, verse: 7, text: "Am not I even he that brought them out of the land of Egypt, from the house of bondage? but they have provoked me unto wrath, and despised my counsels." },
  { book: "2 Esdras", chapter: 1, verse: 8, text: "Pull thou off then the hair of thy head, and cast all evil upon them, for they have not been obedient unto my law, but it is a rebellious people." },
  { book: "2 Esdras", chapter: 1, verse: 9, text: "How long shall I forbear them, into whom I have done so much good?" },
  { book: "2 Esdras", chapter: 1, verse: 10, text: "Many kings have I destroyed for their sakes; Pharaoh with his servants and all his power have I smitten down." },
  { book: "2 Esdras", chapter: 1, verse: 11, text: "All the nations have I destroyed before them, and in the east I have scattered the people of two provinces, even of Tyrus and Sidon, and have slain all their enemies." },
  { book: "2 Esdras", chapter: 1, verse: 12, text: "Speak thou therefore unto them, saying, Thus saith the Lord," },
  { book: "2 Esdras", chapter: 1, verse: 13, text: "I led you through the sea and in the beginning gave you a large and safe passage; I gave you Moses for a leader, and Aaron for a priest." },
  { book: "2 Esdras", chapter: 1, verse: 14, text: "I gave you light in a pillar of fire, and great wonders have I done among you; yet have ye forgotten me, saith the Lord." },
  { book: "2 Esdras", chapter: 1, verse: 15, text: "Thus saith the Almighty Lord, The quails were as a token to you; I gave you tents for your safeguard: nevertheless ye murmured there," },
  { book: "2 Esdras", chapter: 1, verse: 16, text: "And triumphed not in my name for the destruction of your enemies, but ever to this day do ye yet murmur." },
  { book: "2 Esdras", chapter: 1, verse: 17, text: "Where are the benefits that I have done for you? when ye were hungry and thirsty in the wilderness, did ye not cry unto me," },
  { book: "2 Esdras", chapter: 1, verse: 18, text: "Saying, Why hast thou brought us into this wilderness to kill us? it had been better for us to have served the Egyptians, than to die in this wilderness." },
  { book: "2 Esdras", chapter: 1, verse: 19, text: "Then had I pity upon your mournings, and gave you manna to eat; so ye did eat angels’ bread." },
  { book: "2 Esdras", chapter: 1, verse: 20, text: "When ye were thirsty, did I not cleave the rock, and waters flowed out to your fill? for the heat I covered you with the leaves of the trees." },
  { book: "2 Esdras", chapter: 1, verse: 21, text: "I divided among you a fruitful land, I cast out the Canaanites, the Pherezites, and the Philistines, before you: what shall I yet do more for you? saith the Lord." },
  { book: "2 Esdras", chapter: 1, verse: 22, text: "Thus saith the Almighty Lord, When ye were in the wilderness, in the river of the Amorites, being athirst, and blaspheming my name," },
  { book: "2 Esdras", chapter: 1, verse: 23, text: "I gave you not fire for your blasphemies, but cast a tree in the water, and made the river sweet." },
  { book: "2 Esdras", chapter: 1, verse: 24, text: "What shall I do unto thee, O Jacob? thou, Juda, wouldest not obey me: I will turn me to other nations, and unto those will I give my name, that they may keep my statutes." },
  { book: "2 Esdras", chapter: 1, verse: 25, text: "Seeing ye have forsaken me, I will forsake you also; when ye desire me to be gracious unto you, I shall have no mercy upon you." },
  { book: "2 Esdras", chapter: 1, verse: 26, text: "Whensoever ye shall call upon me, I will not hear you: for ye have defiled your hands with blood, and your feet are swift to commit manslaughter." },
  { book: "2 Esdras", chapter: 1, verse: 27, text: "Ye have not as it were forsaken me, but your own selves, saith the Lord." },
  { book: "2 Esdras", chapter: 1, verse: 28, text: "Thus saith the Almighty Lord, Have I not prayed you as a father his sons, as a mother her daughters, and a nurse her young babes," },
  { book: "2 Esdras", chapter: 1, verse: 29, text: "That ye would be my people, and I should be your God; that ye would be my children, and I should be your father?" },
  { book: "2 Esdras", chapter: 1, verse: 30, text: "I gathered you together, as a hen gathereth her chickens under her wings: but now, what shall I do unto you? I will cast you out from my face." },
  { book: "2 Esdras", chapter: 1, verse: 31, text: "When ye offer unto me, I will turn my face from you: for your solemn feastdays, your new moons, and your circumcisions, have I forsaken." },
  { book: "2 Esdras", chapter: 1, verse: 32, text: "I sent unto you my servants the prophets, whom ye have taken and slain, and torn their bodies in pieces, whose blood I will require of your hands, saith the Lord." },
  { book: "2 Esdras", chapter: 1, verse: 33, text: "Thus saith the Almighty Lord, Your house is desolate, I will cast you out as the wind doth stubble." },
  { book: "2 Esdras", chapter: 1, verse: 34, text: "And your children shall not be fruitful; for they have despised my commandment, and done the thing that is an evil before me." },
  { book: "2 Esdras", chapter: 1, verse: 35, text: "Your houses will I give to a people that shall come; which not having heard of me yet shall believe me; to whom I have shewed no signs, yet they shall do that I have commanded them." },
  { book: "2 Esdras", chapter: 1, verse: 36, text: "They have seen no prophets, yet they shall call their sins to remembrance, and acknowledge them." },
  { book: "2 Esdras", chapter: 1, verse: 37, text: "I take to witness the grace of the people to come, whose little ones rejoice in gladness: and though they have not seen me with bodily eyes, yet in spirit they believe the thing that I say." },
  { book: "2 Esdras", chapter: 1, verse: 38, text: "And now, brother, behold what glory; and see the people that come from the east:" },
  { book: "2 Esdras", chapter: 1, verse: 39, text: "Unto whom I will give for leaders, Abraham, Isaac, and Jacob, Oseas, Amos, and Micheas, Joel, Abdias, and Jonas," },
  { book: "2 Esdras", chapter: 1, verse: 40, text: "Nahum, and Abacuc, Sophonias, Aggeus, Zachary, and Malachy, which is called also an angel of the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 1, text: "Thus saith the Lord, I brought this people out of bondage, and I gave them my commandments by menservants the prophets; whom they would not hear, but despised my counsels." },
  { book: "2 Esdras", chapter: 2, verse: 2, text: "The mother that bare them saith unto them, Go your way, ye children; for I am a widow and forsaken." },
  { book: "2 Esdras", chapter: 2, verse: 3, text: "I brought you up with gladness; but with sorrow and heaviness have I lost you: for ye have sinned before the Lord your God, and done that thing that is evil before him." },
  { book: "2 Esdras", chapter: 2, verse: 4, text: "But what shall I now do unto you? I am a widow and forsaken: go your way, O my children, and ask mercy of the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 5, text: "As for me, O father, I call upon thee for a witness over the mother of these children, which would not keep my covenant," },
  { book: "2 Esdras", chapter: 2, verse: 6, text: "That thou bring them to confusion, and their mother to a spoil, that there may be no offspring of them." },
  { book: "2 Esdras", chapter: 2, verse: 7, text: "Let them be scattered abroad among the heathen, let their names be put out of the earth: for they have despised my covenant." },
  { book: "2 Esdras", chapter: 2, verse: 8, text: "Woe be unto thee, Assur, thou that hidest the unrighteous in thee! O thou wicked people, remember what I did unto Sodom and Gomorrha;" },
  { book: "2 Esdras", chapter: 2, verse: 9, text: "Whose land lieth in clods of pitch and heaps of ashes: even so also will I do unto them that hear me not, saith the Almighty Lord." },
  { book: "2 Esdras", chapter: 2, verse: 10, text: "Thus saith the Lord unto Esdras, Tell my people that I will give them the kingdom of Jerusalem, which I would have given unto Israel." },
  { book: "2 Esdras", chapter: 2, verse: 11, text: "Their glory also will I take unto me, and give these the everlasting tabernacles, which I had prepared for them." },
  { book: "2 Esdras", chapter: 2, verse: 12, text: "They shall have the tree of life for an ointment of sweet savour; they shall neither labour, nor be weary." },
  { book: "2 Esdras", chapter: 2, verse: 13, text: "Go, and ye shall receive: pray for few days unto you, that they may be shortened: the kingdom is already prepared for you: watch." },
  { book: "2 Esdras", chapter: 2, verse: 14, text: "Take heaven and earth to witness; for I have broken the evil in pieces, and created the good: for I live, saith the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 15, text: "Mother, embrace thy children, and bring them up with gladness, make their feet as fast as a pillar: for I have chosen thee, saith the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 16, text: "And those that be dead will I raise up again from their places, and bring them out of the graves: for I have known my name in Israel." },
  { book: "2 Esdras", chapter: 2, verse: 17, text: "Fear not, thou mother of the children: for I have chosen thee, saith the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 18, text: "For thy help will I send my servants Esau and Jeremy, after whose counsel I have sanctified and prepared for thee twelve trees laden with divers fruits," },
  { book: "2 Esdras", chapter: 2, verse: 19, text: "And as many fountains flowing with milk and honey, and seven mighty mountains, whereupon there grow roses and lilies, whereby I will fill thy children with joy." },
  { book: "2 Esdras", chapter: 2, verse: 20, text: "Do right to the widow, judge for the fatherless, give to the poor, defend the orphan, clothe the naked," },
  { book: "2 Esdras", chapter: 2, verse: 21, text: "Heal the broken and the weak, laugh not a lame man to scorn, defend the maimed, and let the blind man come into the sight of my clearness." },
  { book: "2 Esdras", chapter: 2, verse: 22, text: "Keep the old and young within thy walls." },
  { book: "2 Esdras", chapter: 2, verse: 23, text: "Wheresoever thou findest the dead, take them and bury them, and I will give thee the first place in my resurrection." },
  { book: "2 Esdras", chapter: 2, verse: 24, text: "Abide still, O my people, and take thy rest, for thy quietness still come." },
  { book: "2 Esdras", chapter: 2, verse: 25, text: "Nourish thy children, O thou good nurse; stablish their feet." },
  { book: "2 Esdras", chapter: 2, verse: 26, text: "As for the servants whom I have given thee, there shall not one of them perish; for I will require them from among thy number." },
  { book: "2 Esdras", chapter: 2, verse: 27, text: "Be not weary: for when the day of trouble and heaviness cometh, others shall weep and be sorrowful, but thou shalt be merry and have abundance." },
  { book: "2 Esdras", chapter: 2, verse: 28, text: "The heathen shall envy thee, but they shall be able to do nothing against thee, saith the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 29, text: "My hands shall cover thee, so that thy children shall not see hell." },
  { book: "2 Esdras", chapter: 2, verse: 30, text: "Be joyful, O thou mother, with thy children; for I will deliver thee, saith the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 31, text: "Remember thy children that sleep, for I shall bring them out of the sides of the earth, and shew mercy unto them: for I am merciful, saith the Lord Almighty." },
  { book: "2 Esdras", chapter: 2, verse: 32, text: "Embrace thy children until I come and shew mercy unto them: for my wells run over, and my grace shall not fail." },
  { book: "2 Esdras", chapter: 2, verse: 33, text: "I Esdras received a charge of the Lord upon the mount Oreb, that I should go unto Israel; but when I came unto them, they set me at nought, and despised the commandment of the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 34, text: "And therefore I say unto you, O ye heathen, that hear and understand, look for your Shepherd, he shall give you everlasting rest; for he is nigh at hand, that shall come in the end of the world." },
  { book: "2 Esdras", chapter: 2, verse: 35, text: "Be ready to the reward of the kingdom, for the everlasting light shall shine upon you for evermore." },
  { book: "2 Esdras", chapter: 2, verse: 36, text: "Flee the shadow of this world, receive the joyfulness of your glory: I testify my Saviour openly." },
  { book: "2 Esdras", chapter: 2, verse: 37, text: "O receive the gift that is given you, and be glad, giving thanks unto him that hath led you to the heavenly kingdom." },
  { book: "2 Esdras", chapter: 2, verse: 38, text: "Arise up and stand, behold the number of those that be sealed in the feast of the Lord;" },
  { book: "2 Esdras", chapter: 2, verse: 39, text: "Which are departed from the shadow of the world, and have received glorious garments of the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 40, text: "Take thy number, O Sion, and shut up those of thine that are clothed in white, which have fulfilled the law of the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 41, text: "The number of thy children, whom thou longedst for, is fulfilled: beseech the power of the Lord, that thy people, which have been called from the beginning, may be hallowed." },
  { book: "2 Esdras", chapter: 2, verse: 42, text: "I Esdras saw upon the mount Sion a great people, whom I could not number, and they all praised the Lord with songs." },
  { book: "2 Esdras", chapter: 2, verse: 43, text: "And in the midst of them there was a young man of a high stature, taller than all the rest, and upon every one of their heads he set crowns, and was more exalted; which I marvelled at greatly." },
  { book: "2 Esdras", chapter: 2, verse: 44, text: "So I asked the angel, and said, Sir, what are these?" },
  { book: "2 Esdras", chapter: 2, verse: 45, text: "He answered and said unto me, These be they that have put off the mortal clothing, and put on the immortal, and have confessed the name of God: now are they crowned, and receive palms." },
  { book: "2 Esdras", chapter: 2, verse: 46, text: "Then said I unto the angel, What young person is it that crowneth them, and giveth them palms in their hands?" },
  { book: "2 Esdras", chapter: 2, verse: 47, text: "So he answered and said unto me, It is the Son of God, whom they have confessed in the world. Then began I greatly to commend them that stood so stiffly for the name of the Lord." },
  { book: "2 Esdras", chapter: 2, verse: 48, text: "Then the angel said unto me, Go thy way, and tell my people what manner of things, and how great wonders of the Lord thy God, thou hast seen." },
  { book: "2 Esdras", chapter: 3, verse: 1, text: "In the thirtieth year after the ruin of the city I was in Babylon, and lay troubled upon my bed, and my thoughts came up over my heart:" },
  { book: "2 Esdras", chapter: 3, verse: 2, text: "For I saw the desolation of Sion, and the wealth of them that dwelt at Babylon." },
  { book: "2 Esdras", chapter: 3, verse: 3, text: "And my spirit was sore moved, so that I began to speak words full of fear to the most High, and said," },
  { book: "2 Esdras", chapter: 3, verse: 4, text: "O Lord, who bearest rule, thou spakest at the beginning, when thou didst plant the earth, and that thyself alone, and commandedst the people," },
  { book: "2 Esdras", chapter: 3, verse: 5, text: "And gavest a body unto Adam without soul, which was the workmanship of thine hands, and didst breathe into him the breath of life, and he was made living before thee." },
  { book: "2 Esdras", chapter: 3, verse: 6, text: "And thou leadest him into paradise, which thy right hand had planted, before ever the earth came forward." },
  { book: "2 Esdras", chapter: 3, verse: 7, text: "And unto him thou gavest commandment to love thy way: which he transgressed, and immediately thou appointedst death in him and in his generations, of whom came nations, tribes, people, and kindreds, out of number." },
  { book: "2 Esdras", chapter: 3, verse: 8, text: "And every people walked after their own will, and did wonderful things before thee, and despised thy commandments." },
  { book: "2 Esdras", chapter: 3, verse: 9, text: "And again in process of time thou broughtest the flood upon those that dwelt in the world, and destroyedst them." },
  { book: "2 Esdras", chapter: 3, verse: 10, text: "And it came to pass in every of them, that as death was to Adam, so was the flood to these." },
  { book: "2 Esdras", chapter: 3, verse: 11, text: "Nevertheless one of them thou leftest, namely, Noah with his household, of whom came all righteous men." },
  { book: "2 Esdras", chapter: 3, verse: 12, text: "And it happened, that when they that dwelt upon the earth began to multiply, and had gotten them many children, and were a great people, they began again to be more ungodly than the first." },
  { book: "2 Esdras", chapter: 3, verse: 13, text: "Now when they lived so wickedly before thee, thou didst choose thee a man from among them, whose name was Abraham." },
  { book: "2 Esdras", chapter: 3, verse: 14, text: "Him thou lovedst, and unto him only thou shewedst thy will:" },
  { book: "2 Esdras", chapter: 3, verse: 15, text: "And madest an everlasting covenant with him, promising him that thou wouldest never forsake his seed." },
  { book: "2 Esdras", chapter: 3, verse: 16, text: "And unto him thou gavest Isaac, and unto Isaac also thou gavest Jacob and Esau. As for Jacob, thou didst choose him to thee, and put by Esau: and so Jacob became a great multitude." },
  { book: "2 Esdras", chapter: 3, verse: 17, text: "And it came to pass, that when thou leadest his seed out of Egypt, thou broughtest them up to the mount Sinai." },
  { book: "2 Esdras", chapter: 3, verse: 18, text: "And bowing the heavens, thou didst set fast the earth, movedst the whole world, and madest the depths to tremble, and troubledst the men of that age." },
  { book: "2 Esdras", chapter: 3, verse: 19, text: "And thy glory went through four gates, of fire, and of earthquake, and of wind, and of cold; that thou mightest give the law unto the seed of Jacob, and diligence unto the generation of Israel." },
  { book: "2 Esdras", chapter: 3, verse: 20, text: "And yet tookest thou not away from them a wicked heart, that thy law might bring forth fruit in them." },
  { book: "2 Esdras", chapter: 3, verse: 21, text: "For the first Adam bearing a wicked heart transgressed, and was overcome; and so be all they that are born of him." },
  { book: "2 Esdras", chapter: 3, verse: 22, text: "Thus infirmity was made permanent; and the law (also) in the heart of the people with the malignity of the root; so that the good departed away, and the evil abode still." },
  { book: "2 Esdras", chapter: 3, verse: 23, text: "So the times passed away, and the years were brought to an end: then didst thou raise thee up a servant, called David:" },
  { book: "2 Esdras", chapter: 3, verse: 24, text: "Whom thou commandedst to build a city unto thy name, and to offer incense and oblations unto thee therein." },
  { book: "2 Esdras", chapter: 3, verse: 25, text: "When this was done many years, then they that inhabited the city forsook thee," },
  { book: "2 Esdras", chapter: 3, verse: 26, text: "And in all things did even as Adam and all his generations had done: for they also had a wicked heart:" },
  { book: "2 Esdras", chapter: 3, verse: 27, text: "And so thou gavest thy city over into the hands of thine enemies." },
  { book: "2 Esdras", chapter: 3, verse: 28, text: "Are their deeds then any better that inhabit Babylon, that they should therefore have the dominion over Sion?" },
  { book: "2 Esdras", chapter: 3, verse: 29, text: "For when I came thither, and had seen impieties without number, then my soul saw many evildoers in this thirtieth year, so that my heart failed me." },
  { book: "2 Esdras", chapter: 3, verse: 30, text: "For I have seen how thou sufferest them sinning, and hast spared wicked doers: and hast destroyed thy people, and hast preserved thine enemies, and hast not signified it." },
  { book: "2 Esdras", chapter: 3, verse: 31, text: "I do not remember how this way may be left: Are they then of Babylon better than they of Sion?" },
  { book: "2 Esdras", chapter: 3, verse: 32, text: "Or is there any other people that knoweth thee beside Israel? or what generation hath so believed thy covenants as Jacob?" },
  { book: "2 Esdras", chapter: 3, verse: 33, text: "And yet their reward appeareth not, and their labour hath no fruit: for I have gone here and there through the heathen, and I see that they flow in wealth, and think not upon thy commandments." },
  { book: "2 Esdras", chapter: 3, verse: 34, text: "Weigh thou therefore our wickedness now in the balance, and their’s also that dwell the world; and so shall thy name no where be found but in Israel." },
  { book: "2 Esdras", chapter: 3, verse: 35, text: "Or when was it that they which dwell upon the earth have not sinned in thy sight? or what people have so kept thy commandments?" },
  { book: "2 Esdras", chapter: 3, verse: 36, text: "Thou shalt find that Israel by name hath kept thy precepts; but not the heathen." },
  { book: "2 Esdras", chapter: 4, verse: 1, text: "And the angel that was sent unto me, whose name was Uriel, gave me an answer," },
  { book: "2 Esdras", chapter: 4, verse: 2, text: "And said, Thy heart hath gone to far in this world, and thinkest thou to comprehend the way of the most High?" },
  { book: "2 Esdras", chapter: 4, verse: 3, text: "Then said I, Yea, my lord. And he answered me, and said, I am sent to shew thee three ways, and to set forth three similitudes before thee:" },
  { book: "2 Esdras", chapter: 4, verse: 4, text: "Whereof if thou canst declare me one, I will shew thee also the way that thou desirest to see, and I shall shew thee from whence the wicked heart cometh." },
  { book: "2 Esdras", chapter: 4, verse: 5, text: "And I said, Tell on, my lord. Then said he unto me, Go thy way, weigh me the weight of the fire, or measure me the blast of the wind, or call me again the day that is past." },
  { book: "2 Esdras", chapter: 4, verse: 6, text: "Then answered I and said, What man is able to do that, that thou shouldest ask such things of me?" },
  { book: "2 Esdras", chapter: 4, verse: 7, text: "And he said unto me, If I should ask thee how great dwellings are in the midst of the sea, or how many springs are in the beginning of the deep, or how many springs are above the firmament, or which are the outgoings of paradise:" },
  { book: "2 Esdras", chapter: 4, verse: 8, text: "Peradventure thou wouldest say unto me, I never went down into the deep, nor as yet into hell, neither did I ever climb up into heaven." },
  { book: "2 Esdras", chapter: 4, verse: 9, text: "Nevertheless now have I asked thee but only of the fire and wind, and of the day wherethrough thou hast passed, and of things from which thou canst not be separated, and yet canst thou give me no answer of them." },
  { book: "2 Esdras", chapter: 4, verse: 10, text: "He said moreover unto me, Thine own things, and such as are grown up with thee, canst thou not know;" },
  { book: "2 Esdras", chapter: 4, verse: 11, text: "How should thy vessel then be able to comprehend the way of the Highest, and, the world being now outwardly corrupted to understand the corruption that is evident in my sight?" },
  { book: "2 Esdras", chapter: 4, verse: 12, text: "Then said I unto him, It were better that we were not at all, than that we should live still in wickedness, and to suffer, and not to know wherefore." },
  { book: "2 Esdras", chapter: 4, verse: 13, text: "He answered me, and said, I went into a forest into a plain, and the trees took counsel," },
  { book: "2 Esdras", chapter: 4, verse: 14, text: "And said, Come, let us go and make war against the sea that it may depart away before us, and that we may make us more woods." },
  { book: "2 Esdras", chapter: 4, verse: 15, text: "The floods of the sea also in like manner took counsel, and said, Come, let us go up and subdue the woods of the plain, that there also we may make us another country." },
  { book: "2 Esdras", chapter: 4, verse: 16, text: "The thought of the wood was in vain, for the fire came and consumed it." },
  { book: "2 Esdras", chapter: 4, verse: 17, text: "The thought of the floods of the sea came likewise to nought, for the sand stood up and stopped them." },
  { book: "2 Esdras", chapter: 4, verse: 18, text: "If thou wert judge now betwixt these two, whom wouldest thou begin to justify? or whom wouldest thou condemn?" },
  { book: "2 Esdras", chapter: 4, verse: 19, text: "I answered and said, Verily it is a foolish thought that they both have devised, for the ground is given unto the wood, and the sea also hath his place to bear his floods." },
  { book: "2 Esdras", chapter: 4, verse: 20, text: "Then answered he me, and said, Thou hast given a right judgment, but why judgest thou not thyself also?" },
  { book: "2 Esdras", chapter: 4, verse: 21, text: "For like as the ground is given unto the wood, and the sea to his floods: even so they that dwell upon the earth may understand nothing but that which is upon the earth: and he that dwelleth above the heavens may only understand the things that are above the height of the heavens." },
  { book: "2 Esdras", chapter: 4, verse: 22, text: "Then answered I and said, I beseech thee, O Lord, let me have understanding:" },
  { book: "2 Esdras", chapter: 4, verse: 23, text: "For it was not my mind to be curious of the high things, but of such as pass by us daily, namely, wherefore Israel is given up as a reproach to the heathen, and for what cause the people whom thou hast loved is given over unto ungodly nations, and why the law of our forefathers is brought to nought, and the written covenants come to none effect," },
  { book: "2 Esdras", chapter: 4, verse: 24, text: "And we pass away out of the world as grasshoppers, and our life is astonishment and fear, and we are not worthy to obtain mercy." },
  { book: "2 Esdras", chapter: 4, verse: 25, text: "What will he then do unto his name whereby we are called? of these things have I asked." },
  { book: "2 Esdras", chapter: 4, verse: 26, text: "Then answered he me, and said, The more thou searchest, the more thou shalt marvel; for the world hasteth fast to pass away," },
  { book: "2 Esdras", chapter: 4, verse: 27, text: "And cannot comprehend the things that are promised to the righteous in time to come: for this world is full of unrighteousness and infirmities." },
  { book: "2 Esdras", chapter: 4, verse: 28, text: "But as concerning the things whereof thou askest me, I will tell thee; for the evil is sown, but the destruction thereof is not yet come." },
  { book: "2 Esdras", chapter: 4, verse: 29, text: "If therefore that which is sown be not turned upside down, and if the place where the evil is sown pass not away, then cannot it come that is sown with good." },
  { book: "2 Esdras", chapter: 4, verse: 30, text: "For the grain of evil seed hath been sown in the heart of Adam from the beginning, and how much ungodliness hath it brought up unto this time? and how much shall it yet bring forth until the time of threshing come?" },
  { book: "2 Esdras", chapter: 4, verse: 31, text: "Ponder now by thyself, how great fruit of wickedness the grain of evil seed hath brought forth." },
  { book: "2 Esdras", chapter: 4, verse: 32, text: "And when the ears shall be cut down, which are without number, how great a floor shall they fill?" },
  { book: "2 Esdras", chapter: 4, verse: 33, text: "Then I answered and said, How, and when shall these things come to pass? wherefore are our years few and evil?" },
  { book: "2 Esdras", chapter: 4, verse: 34, text: "And he answered me, saying, Do not thou hasten above the most Highest: for thy haste is in vain to be above him, for thou hast much exceeded." },
  { book: "2 Esdras", chapter: 4, verse: 35, text: "Did not the souls also of the righteous ask question of these things in their chambers, saying, How long shall I hope on this fashion? when cometh the fruit of the floor of our reward?" },
  { book: "2 Esdras", chapter: 4, verse: 36, text: "And unto these things Uriel the archangel gave them answer, and said, Even when the number of seeds is filled in you: for he hath weighed the world in the balance." },
  { book: "2 Esdras", chapter: 4, verse: 37, text: "By measure hath he measured the times; and by number hath he numbered the times; and he doth not move nor stir them, until the said measure be fulfilled." },
  { book: "2 Esdras", chapter: 4, verse: 38, text: "Then answered I and said, O Lord that bearest rule, even we all are full of impiety." },
  { book: "2 Esdras", chapter: 4, verse: 39, text: "And for our sakes peradventure it is that the floors of the righteous are not filled, because of the sins of them that dwell upon the earth." },
  { book: "2 Esdras", chapter: 4, verse: 40, text: "So he answered me, and said, Go thy way to a woman with child, and ask of her when she hath fulfilled her nine months, if her womb may keep the birth any longer within her." },
  { book: "2 Esdras", chapter: 4, verse: 41, text: "Then said I, No, Lord, that can she not. And he said unto me, In the grave the chambers of souls are like the womb of a woman:" },
  { book: "2 Esdras", chapter: 4, verse: 42, text: "For like as a woman that travaileth maketh haste to escape the necessity of the travail: even so do these places haste to deliver those things that are committed unto them." },
  { book: "2 Esdras", chapter: 4, verse: 43, text: "From the beginning, look, what thou desirest to see, it shall be shewed thee." },
  { book: "2 Esdras", chapter: 4, verse: 44, text: "Then answered I and said, If I have found favour in thy sight, and if it be possible, and if I be meet therefore," },
  { book: "2 Esdras", chapter: 4, verse: 45, text: "Shew me then whether there be more to come than is past, or more past than is to come." },
  { book: "2 Esdras", chapter: 4, verse: 46, text: "What is past I know, but what is for to come I know not." },
  { book: "2 Esdras", chapter: 4, verse: 47, text: "And he said unto me, Stand up upon the right side, and I shall expound the similitude unto thee." },
  { book: "2 Esdras", chapter: 4, verse: 48, text: "So I stood, and saw, and, behold, an hot burning oven passed by before me: and it happened that when the flame was gone by I looked, and, behold, the smoke remained still." },
  { book: "2 Esdras", chapter: 4, verse: 49, text: "After this there passed by before me a watery cloud, and sent down much rain with a storm; and when the stormy rain was past, the drops remained still." },
  { book: "2 Esdras", chapter: 4, verse: 50, text: "Then said he unto me, Consider with thyself; as the rain is more than the drops, and as the fire is greater than the smoke; but the drops and the smoke remain behind: so the quantity which is past did more exceed." },
  { book: "2 Esdras", chapter: 4, verse: 51, text: "Then I prayed, and said, May I live, thinkest thou, until that time? or what shall happen in those days?" },
  { book: "2 Esdras", chapter: 4, verse: 52, text: "He answered me, and said, As for the tokens whereof thou askest me, I may tell thee of them in part: but as touching thy life, I am not sent to shew thee; for I do not know it." },
  { book: "2 Esdras", chapter: 5, verse: 1, text: "Nevertheless as coming the tokens, behold, the days shall come, that they which dwell upon earth shall be taken in a great number, and the way of truth shall be hidden, and the land shall be barren of faith." },
  { book: "2 Esdras", chapter: 5, verse: 2, text: "But iniquity shall be increased above that which now thou seest, or that thou hast heard long ago." },
  { book: "2 Esdras", chapter: 5, verse: 3, text: "And the land, that thou seest now to have root, shalt thou see wasted suddenly." },
  { book: "2 Esdras", chapter: 5, verse: 4, text: "But if the most High grant thee to live, thou shalt see after the third trumpet that the sun shall suddenly shine again in the night, and the moon thrice in the day:" },
  { book: "2 Esdras", chapter: 5, verse: 5, text: "And blood shall drop out of wood, and the stone shall give his voice, and the people shall be troubled:" },
  { book: "2 Esdras", chapter: 5, verse: 6, text: "And even he shall rule, whom they look not for that dwell upon the earth, and the fowls shall take their flight away together:" },
  { book: "2 Esdras", chapter: 5, verse: 7, text: "And the Sodomitish sea shall cast out fish, and make a noise in the night, which many have not known: but they shall all hear the voice thereof." },
  { book: "2 Esdras", chapter: 5, verse: 8, text: "There shall be a confusion also in many places, and the fire shall be oft sent out again, and the wild beasts shall change their places, and menstruous women shall bring forth monsters:" },
  { book: "2 Esdras", chapter: 5, verse: 9, text: "And salt waters shall be found in the sweet, and all friends shall destroy one another; then shall wit hide itself, and understanding withdraw itself into his secret chamber," },
  { book: "2 Esdras", chapter: 5, verse: 10, text: "And shall be sought of many, and yet not be found: then shall unrighteousness and incontinency be multiplied upon earth." },
  { book: "2 Esdras", chapter: 5, verse: 11, text: "One land also shall ask another, and say, Is righteousness that maketh a man righteous gone through thee? And it shall say, No." },
  { book: "2 Esdras", chapter: 5, verse: 12, text: "At the same time shall men hope, but nothing obtain: they shall labour, but their ways shall not prosper." },
  { book: "2 Esdras", chapter: 5, verse: 13, text: "To shew thee such tokens I have leave; and if thou wilt pray again, and weep as now, and fast even days, thou shalt hear yet greater things." },
  { book: "2 Esdras", chapter: 5, verse: 14, text: "Then I awaked, and an extreme fearfulness went through all my body, and my mind was troubled, so that it fainted." },
  { book: "2 Esdras", chapter: 5, verse: 15, text: "So the angel that was come to talk with me held me, comforted me, and set me up upon my feet." },
  { book: "2 Esdras", chapter: 5, verse: 16, text: "And in the second night it came to pass, that Salathiel the captain of the people came unto me, saying, Where hast thou been? and why is thy countenance so heavy?" },
  { book: "2 Esdras", chapter: 5, verse: 17, text: "Knowest thou not that Israel is committed unto thee in the land of their captivity?" },
  { book: "2 Esdras", chapter: 5, verse: 18, text: "Up then, and eat bread, and forsake us not, as the shepherd that leaveth his flock in the hands of cruel wolves." },
  { book: "2 Esdras", chapter: 5, verse: 19, text: "Then said I unto him, Go thy ways from me, and come not nigh me. And he heard what I said, and went from me." },
  { book: "2 Esdras", chapter: 5, verse: 20, text: "And so I fasted seven days, mourning and weeping, like as Uriel the angel commanded me." },
  { book: "2 Esdras", chapter: 5, verse: 21, text: "And after seven days so it was, that the thoughts of my heart were very grievous unto me again," },
  { book: "2 Esdras", chapter: 5, verse: 22, text: "And my soul recovered the spirit of understanding, and I began to talk with the most High again," },
  { book: "2 Esdras", chapter: 5, verse: 23, text: "And said, O Lord that bearest rule, of every wood of the earth, and of all the trees thereof, thou hast chosen thee one only vine:" },
  { book: "2 Esdras", chapter: 5, verse: 24, text: "And of all lands of the whole world thou hast chosen thee one pit: and of all the flowers thereof one lily:" },
  { book: "2 Esdras", chapter: 5, verse: 25, text: "And of all the depths of the sea thou hast filled thee one river: and of all builded cities thou hast hallowed Sion unto thyself:" },
  { book: "2 Esdras", chapter: 5, verse: 26, text: "And of all the fowls that are created thou hast named thee one dove: and of all the cattle that are made thou hast provided thee one sheep:" },
  { book: "2 Esdras", chapter: 5, verse: 27, text: "And among all the multitudes of people thou hast gotten thee one people: and unto this people, whom thou lovedst, thou gavest a law that is approved of all." },
  { book: "2 Esdras", chapter: 5, verse: 28, text: "And now, O Lord, why hast thou given this one people over unto many? and upon the one root hast thou prepared others, and why hast thou scattered thy only one people among many?" },
  { book: "2 Esdras", chapter: 5, verse: 29, text: "And they which did gainsay thy promises, and believed not thy covenants, have trodden them down." },
  { book: "2 Esdras", chapter: 5, verse: 30, text: "If thou didst so much hate thy people, yet shouldest thou punish them with thine own hands." },
  { book: "2 Esdras", chapter: 5, verse: 31, text: "Now when I had spoken these words, the angel that came to me the night afore was sent unto me," },
  { book: "2 Esdras", chapter: 5, verse: 32, text: "And said unto me, Hear me, and I will instruct thee; hearken to the thing that I say, and I shall tell thee more." },
  { book: "2 Esdras", chapter: 5, verse: 33, text: "And I said, Speak on, my Lord. Then said he unto me, Thou art sore troubled in mind for Israel’s sake: lovest thou that people better than he that made them?" },
  { book: "2 Esdras", chapter: 5, verse: 34, text: "And I said, No, Lord: but of very grief have I spoken: for my reins pain me every hour, while I labour to comprehend the way of the most High, and to seek out part of his judgment." },
  { book: "2 Esdras", chapter: 5, verse: 35, text: "And he said unto me, Thou canst not. And I said, Wherefore, Lord? whereunto was I born then? or why was not my mother’s womb then my grave, that I might not have seen the travail of Jacob, and the wearisome toil of the stock of Israel?" },
  { book: "2 Esdras", chapter: 5, verse: 36, text: "And he said unto me, Number me the things that are not yet come, gather me together the dross that are scattered abroad, make me the flowers green again that are withered," },
  { book: "2 Esdras", chapter: 5, verse: 37, text: "Open me the places that are closed, and bring me forth the winds that in them are shut up, shew me the image of a voice: and then I will declare to thee the thing that thou labourest to know." },
  { book: "2 Esdras", chapter: 5, verse: 38, text: "And I said, O Lord that bearest rule, who may know these things, but he that hath not his dwelling with men?" },
  { book: "2 Esdras", chapter: 5, verse: 39, text: "As for me, I am unwise: how may I then speak of these things whereof thou askest me?" },
  { book: "2 Esdras", chapter: 5, verse: 40, text: "Then said he unto me, Like as thou canst do none of these things that I have spoken of, even so canst thou not find out my judgment, or in the end the love that I have promised unto my people." },
  { book: "2 Esdras", chapter: 5, verse: 41, text: "And I said, Behold, O Lord, yet art thou nigh unto them that be reserved till the end: and what shall they do that have been before me, or we that be now, or they that shall come after us?" },
  { book: "2 Esdras", chapter: 5, verse: 42, text: "And he said unto me, I will liken my judgment unto a ring: like as there is no slackness of the last, even so there is no swiftness of the first." },
  { book: "2 Esdras", chapter: 5, verse: 43, text: "So I answered and said, Couldest thou not make those that have been made, and be now, and that are for to come, at once; that thou mightest shew thy judgment the sooner?" },
  { book: "2 Esdras", chapter: 5, verse: 44, text: "Then answered he me, and said, The creature may not haste above the maker; neither may the world hold them at once that shall be created therein." },
  { book: "2 Esdras", chapter: 5, verse: 45, text: "And I said, As thou hast said unto thy servant, that thou, which givest life to all, hast given life at once to the creature that thou hast created, and the creature bare it: even so it might now also bear them that now be present at once." },
  { book: "2 Esdras", chapter: 5, verse: 46, text: "And he said unto me, Ask the womb of a woman, and say unto her, If thou bringest forth children, why dost thou it not together, but one after another? pray her therefore to bring forth ten children at once." },
  { book: "2 Esdras", chapter: 5, verse: 47, text: "And I said, She cannot: but must do it by distance of time." },
  { book: "2 Esdras", chapter: 5, verse: 48, text: "Then said he unto me, Even so have I given the womb of the earth to those that be sown in it in their times." },
  { book: "2 Esdras", chapter: 5, verse: 49, text: "For like as a young child may not bring forth the things that belong to the aged, even so have I disposed the world which I created." },
  { book: "2 Esdras", chapter: 5, verse: 50, text: "And I asked, and said, Seeing thou hast now given me the way, I will proceed to speak before thee: for our mother, of whom thou hast told me that she is young, draweth now nigh unto age." },
  { book: "2 Esdras", chapter: 5, verse: 51, text: "He answered me, and said, Ask a woman that beareth children, and she shall tell thee." },
  { book: "2 Esdras", chapter: 5, verse: 52, text: "Say unto her, Wherefore are unto they whom thou hast now brought forth like those that were before, but less of stature?" },
  { book: "2 Esdras", chapter: 5, verse: 53, text: "And she shall answer thee, They that be born in the the strength of youth are of one fashion, and they that are born in the time of age, when the womb faileth, are otherwise." },
  { book: "2 Esdras", chapter: 5, verse: 54, text: "Consider thou therefore also, how that ye are less of stature than those that were before you." },
  { book: "2 Esdras", chapter: 5, verse: 55, text: "And so are they that come after you less than ye, as the creatures which now begin to be old, and have passed over the strength of youth." },
  { book: "2 Esdras", chapter: 5, verse: 56, text: "Then said I, Lord, I beseech thee, if I have found favour in thy sight, shew thy servant by whom thou visitest thy creature." },
  { book: "2 Esdras", chapter: 6, verse: 1, text: "And he said unto me, In the beginning, when the earth was made, before the borders of the world stood, or ever the winds blew," },
  { book: "2 Esdras", chapter: 6, verse: 2, text: "Before it thundered and lightened, or ever the foundations of paradise were laid," },
  { book: "2 Esdras", chapter: 6, verse: 3, text: "Before the fair flowers were seen, or ever the moveable powers were established, before the innumerable multitude of angels were gathered together," },
  { book: "2 Esdras", chapter: 6, verse: 4, text: "Or ever the heights of the air were lifted up, before the measures of the firmament were named, or ever the chimneys in Sion were hot," },
  { book: "2 Esdras", chapter: 6, verse: 5, text: "And ere the present years were sought out, and or ever the inventions of them that now sin were turned, before they were sealed that have gathered faith for a treasure:" },
  { book: "2 Esdras", chapter: 6, verse: 6, text: "Then did I consider these things, and they all were made through me alone, and through none other: by me also they shall be ended, and by none other." },
  { book: "2 Esdras", chapter: 6, verse: 7, text: "Then answered I and said, What shall be the parting asunder of the times? or when shall be the end of the first, and the beginning of it that followeth?" },
  { book: "2 Esdras", chapter: 6, verse: 8, text: "And he said unto me, From Abraham unto Isaac, when Jacob and Esau were born of him, Jacob’s hand held first the heel of Esau." },
  { book: "2 Esdras", chapter: 6, verse: 9, text: "For Esau is the end of the world, and Jacob is the beginning of it that followeth." },
  { book: "2 Esdras", chapter: 6, verse: 10, text: "The hand of man is betwixt the heel and the hand: other question, Esdras, ask thou not." },
  { book: "2 Esdras", chapter: 6, verse: 11, text: "I answered then and said, O Lord that bearest rule, if I have found favour in thy sight," },
  { book: "2 Esdras", chapter: 6, verse: 12, text: "I beseech thee, shew thy servant the end of thy tokens, whereof thou shewedst me part the last night." },
  { book: "2 Esdras", chapter: 6, verse: 13, text: "So he answered and said unto me, Stand up upon thy feet, and hear a mighty sounding voice." },
  { book: "2 Esdras", chapter: 6, verse: 14, text: "And it shall be as it were a great motion; but the place where thou standest shall not be moved." },
  { book: "2 Esdras", chapter: 6, verse: 15, text: "And therefore when it speaketh be not afraid: for the word is of the end, and the foundation of the earth is understood." },
  { book: "2 Esdras", chapter: 6, verse: 16, text: "And why? because the speech of these things trembleth and is moved: for it knoweth that the end of these things must be changed." },
  { book: "2 Esdras", chapter: 6, verse: 17, text: "And it happened, that when I had heard it I stood up upon my feet, and hearkened, and, behold, there was a voice that spake, and the sound of it was like the sound of many waters." },
  { book: "2 Esdras", chapter: 6, verse: 18, text: "And it said, Behold, the days come, that I will begin to draw nigh, and to visit them that dwell upon the earth," },
  { book: "2 Esdras", chapter: 6, verse: 19, text: "And will begin to make inquisition of them, what they be that have hurt unjustly with their unrighteousness, and when the affliction of Sion shall be fulfilled;" },
  { book: "2 Esdras", chapter: 6, verse: 20, text: "And when the world, that shall begin to vanish away, shall be finished, then will I shew these tokens: the books shall be opened before the firmament, and they shall see all together:" },
  { book: "2 Esdras", chapter: 6, verse: 21, text: "And the children of a year old shall speak with their voices, the women with child shall bring forth untimely children of three or four months old, and they shall live, and be raised up." },
  { book: "2 Esdras", chapter: 6, verse: 22, text: "And suddenly shall the sown places appear unsown, the full storehouses shall suddenly be found empty:" },
  { book: "2 Esdras", chapter: 6, verse: 23, text: "And the trumpet shall give a sound, which when every man heareth, they shall be suddenly afraid." },
  { book: "2 Esdras", chapter: 6, verse: 24, text: "At that time shall friends fight one against another like enemies, and the earth shall stand in fear with those that dwell therein, the springs of the fountains shall stand still, and in three hours they shall not run." },
  { book: "2 Esdras", chapter: 6, verse: 25, text: "Whosoever remaineth from all these that I have told thee shall escape, and see my salvation, and the end of your world." },
  { book: "2 Esdras", chapter: 6, verse: 26, text: "And the men that are received shall see it, who have not tasted death from their birth: and the heart of the inhabitants shall be changed, and turned into another meaning." },
  { book: "2 Esdras", chapter: 6, verse: 27, text: "For evil shall be put out, and deceit shall be quenched." },
  { book: "2 Esdras", chapter: 6, verse: 28, text: "As for faith, it shall flourish, corruption shall be overcome, and the truth, which hath been so long without fruit, shall be declared." },
  { book: "2 Esdras", chapter: 6, verse: 29, text: "And when he talked with me, behold, I looked by little and little upon him before whom I stood." },
  { book: "2 Esdras", chapter: 6, verse: 30, text: "And these words said he unto me; I am come to shew thee the time of the night to come." },
  { book: "2 Esdras", chapter: 6, verse: 31, text: "If thou wilt pray yet more, and fast seven days again, I shall tell thee greater things by day than I have heard." },
  { book: "2 Esdras", chapter: 6, verse: 32, text: "For thy voice is heard before the most High: for the Mighty hath seen thy righteous dealing, he hath seen also thy chastity, which thou hast had ever since thy youth." },
  { book: "2 Esdras", chapter: 6, verse: 33, text: "And therefore hath he sent me to shew thee all these things, and to say unto thee, Be of good comfort and fear not" },
  { book: "2 Esdras", chapter: 6, verse: 34, text: "And hasten not with the times that are past, to think vain things, that thou mayest not hasten from the latter times." },
  { book: "2 Esdras", chapter: 6, verse: 35, text: "And it came to pass after this, that I wept again, and fasted seven days in like manner, that I might fulfil the three weeks which he told me." },
  { book: "2 Esdras", chapter: 6, verse: 36, text: "And in the eighth night was my heart vexed within me again, and I began to speak before the most High." },
  { book: "2 Esdras", chapter: 6, verse: 37, text: "For my spirit was greatly set on fire, and my soul was in distress." },
  { book: "2 Esdras", chapter: 6, verse: 38, text: "And I said, O Lord, thou spakest from the beginning of the creation, even the first day, and saidst thus; Let heaven and earth be made; and thy word was a perfect work." },
  { book: "2 Esdras", chapter: 6, verse: 39, text: "And then was the spirit, and darkness and silence were on every side; the sound of man’s voice was not yet formed." },
  { book: "2 Esdras", chapter: 6, verse: 40, text: "Then commandedst thou a fair light to come forth of thy treasures, that thy work might appear." },
  { book: "2 Esdras", chapter: 6, verse: 41, text: "Upon the second day thou madest the spirit of the firmament, and commandedst it to part asunder, and to make a division betwixt the waters, that the one part might go up, and the other remain beneath." },
  { book: "2 Esdras", chapter: 6, verse: 42, text: "Upon the third day thou didst command that the waters should be gathered in the seventh part of the earth: six pats hast thou dried up, and kept them, to the intent that of these some being planted of God and tilled might serve thee." },
  { book: "2 Esdras", chapter: 6, verse: 43, text: "For as soon as thy word went forth the work was made." },
  { book: "2 Esdras", chapter: 6, verse: 44, text: "For immediately there was great and innumerable fruit, and many and divers pleasures for the taste, and flowers of unchangeable colour, and odours of wonderful smell: and this was done the third day." },
  { book: "2 Esdras", chapter: 6, verse: 45, text: "Upon the fourth day thou commandedst that the sun should shine, and the moon give her light, and the stars should be in order:" },
  { book: "2 Esdras", chapter: 6, verse: 46, text: "And gavest them a charge to do service unto man, that was to be made." },
  { book: "2 Esdras", chapter: 6, verse: 47, text: "Upon the fifth day thou saidst unto the seventh part, where the waters were gathered that it should bring forth living creatures, fowls and fishes: and so it came to pass." },
  { book: "2 Esdras", chapter: 6, verse: 48, text: "For the dumb water and without life brought forth living things at the commandment of God, that all people might praise thy wondrous works." },
  { book: "2 Esdras", chapter: 6, verse: 49, text: "Then didst thou ordain two living creatures, the one thou calledst Enoch, and the other Leviathan;" },
  { book: "2 Esdras", chapter: 6, verse: 50, text: "And didst separate the one from the other: for the seventh part, namely, where the water was gathered together, might not hold them both." },
  { book: "2 Esdras", chapter: 6, verse: 51, text: "Unto Enoch thou gavest one part, which was dried up the third day, that he should dwell in the same part, wherein are a thousand hills:" },
  { book: "2 Esdras", chapter: 6, verse: 52, text: "But unto Leviathan thou gavest the seventh part, namely, the moist; and hast kept him to be devoured of whom thou wilt, and when." },
  { book: "2 Esdras", chapter: 6, verse: 53, text: "Upon the sixth day thou gavest commandment unto the earth, that before thee it should bring forth beasts, cattle, and creeping things:" },
  { book: "2 Esdras", chapter: 6, verse: 54, text: "And after these, Adam also, whom thou madest lord of all thy creatures: of him come we all, and the people also whom thou hast chosen." },
  { book: "2 Esdras", chapter: 6, verse: 55, text: "All this have I spoken before thee, O Lord, because thou madest the world for our sakes" },
  { book: "2 Esdras", chapter: 6, verse: 56, text: "As for the other people, which also come of Adam, thou hast said that they are nothing, but be like unto spittle: and hast likened the abundance of them unto a drop that falleth from a vessel." },
  { book: "2 Esdras", chapter: 6, verse: 57, text: "And now, O Lord, behold, these heathen, which have ever been reputed as nothing, have begun to be lords over us, and to devour us." },
  { book: "2 Esdras", chapter: 6, verse: 58, text: "But we thy people, whom thou hast called thy firstborn, thy only begotten, and thy fervent lover, are given into their hands." },
  { book: "2 Esdras", chapter: 6, verse: 59, text: "If the world now be made for our sakes, why do we not possess an inheritance with the world? how long shall this endure?" },
  { book: "2 Esdras", chapter: 7, verse: 1, text: "And when I had made an end of speaking these words, there was sent unto me the angel which had been sent unto me the nights afore:" },
  { book: "2 Esdras", chapter: 7, verse: 2, text: "And he said unto me, Up, Esdras, and hear the words that I am come to tell thee." },
  { book: "2 Esdras", chapter: 7, verse: 3, text: "And I said, Speak on, my God. Then said he unto me, The sea is set in a wide place, that it might be deep and great." },
  { book: "2 Esdras", chapter: 7, verse: 4, text: "But put the case the entrance were narrow, and like a river;" },
  { book: "2 Esdras", chapter: 7, verse: 5, text: "Who then could go into the sea to look upon it, and to rule it? if he went not through the narrow, how could he come into the broad?" },
  { book: "2 Esdras", chapter: 7, verse: 6, text: "There is also another thing; A city is builded, and set upon a broad field, and is full of all good things:" },
  { book: "2 Esdras", chapter: 7, verse: 7, text: "The entrance thereof is narrow, and is set in a dangerous place to fall, like as if there were a fire on the right hand, and on the left a deep water:" },
  { book: "2 Esdras", chapter: 7, verse: 8, text: "And one only path between them both, even between the fire and the water, so small that there could but one man go there at once." },
  { book: "2 Esdras", chapter: 7, verse: 9, text: "If this city now were given unto a man for an inheritance, if he never shall pass the danger set before it, how shall he receive this inheritance?" },
  { book: "2 Esdras", chapter: 7, verse: 10, text: "And I said, It is so, Lord. Then said he unto me, Even so also is Israel’s portion." },
  { book: "2 Esdras", chapter: 7, verse: 11, text: "Because for their sakes I made the world: and when Adam transgressed my statutes, then was decreed that now is done." },
  { book: "2 Esdras", chapter: 7, verse: 12, text: "Then were the entrances of this world made narrow, full of sorrow and travail: they are but few and evil, full of perils,: and very painful." },
  { book: "2 Esdras", chapter: 7, verse: 13, text: "For the entrances of the elder world were wide and sure, and brought immortal fruit." },
  { book: "2 Esdras", chapter: 7, verse: 14, text: "If then they that live labour not to enter these strait and vain things, they can never receive those that are laid up for them." },
  { book: "2 Esdras", chapter: 7, verse: 15, text: "Now therefore why disquietest thou thyself, seeing thou art but a corruptible man? and why art thou moved, whereas thou art but mortal?" },
  { book: "2 Esdras", chapter: 7, verse: 16, text: "Why hast thou not considered in thy mind this thing that is to come, rather than that which is present?" },
  { book: "2 Esdras", chapter: 7, verse: 17, text: "Then answered I and said, O Lord that bearest rule, thou hast ordained in thy law, that the righteous should inherit these things, but that the ungodly should perish." },
  { book: "2 Esdras", chapter: 7, verse: 18, text: "Nevertheless the righteous shall suffer strait things, and hope for wide: for they that have done wickedly have suffered the strait things, and yet shall not see the wide." },
  { book: "2 Esdras", chapter: 7, verse: 19, text: "And he said unto me. There is no judge above God, and none that hath understanding above the Highest." },
  { book: "2 Esdras", chapter: 7, verse: 20, text: "For there be many that perish in this life, because they despise the law of God that is set before them." },
  { book: "2 Esdras", chapter: 7, verse: 21, text: "For God hath given strait commandment to such as came, what they should do to live, even as they came, and what they should observe to avoid punishment." },
  { book: "2 Esdras", chapter: 7, verse: 22, text: "Nevertheless they were not obedient unto him; but spake against him, and imagined vain things;" },
  { book: "2 Esdras", chapter: 7, verse: 23, text: "And deceived themselves by their wicked deeds; and said of the most High, that he is not; and knew not his ways:" },
  { book: "2 Esdras", chapter: 7, verse: 24, text: "But his law have they despised, and denied his covenants; in his statutes have they not been faithful, and have not performed his works." },
  { book: "2 Esdras", chapter: 7, verse: 25, text: "And therefore, Esdras, for the empty are empty things, and for the full are the full things." },
  { book: "2 Esdras", chapter: 7, verse: 26, text: "Behold, the time shall come, that these tokens which I have told thee shall come to pass, and the bride shall appear, and she coming forth shall be seen, that now is withdrawn from the earth." },
  { book: "2 Esdras", chapter: 7, verse: 27, text: "And whosoever is delivered from the foresaid evils shall see my wonders." },
  { book: "2 Esdras", chapter: 7, verse: 28, text: "For my son Jesus shall be revealed with those that be with him, and they that remain shall rejoice within four hundred years." },
  { book: "2 Esdras", chapter: 7, verse: 29, text: "After these years shall my son Christ die, and all men that have life." },
  { book: "2 Esdras", chapter: 7, verse: 30, text: "And the world shall be turned into the old silence seven days, like as in the former judgments: so that no man shall remain." },
  { book: "2 Esdras", chapter: 7, verse: 31, text: "And after seven days the world, that yet awaketh not, shall be raised up, and that shall die that is corrupt" },
  { book: "2 Esdras", chapter: 7, verse: 32, text: "And the earth shall restore those that are asleep in her, and so shall the dust those that dwell in silence, and the secret places shall deliver those souls that were committed unto them." },
  { book: "2 Esdras", chapter: 7, verse: 33, text: "And the most High shall appear upon the seat of judgment, and misery shall pass away, and the long suffering shall have an end:" },
  { book: "2 Esdras", chapter: 7, verse: 34, text: "But judgment only shall remain, truth shall stand, and faith shall wax strong:" },
  { book: "2 Esdras", chapter: 7, verse: 35, text: "And the work shall follow, and the reward shall be shewed, and the good deeds shall be of force, and wicked deeds shall bear no rule." },
  { book: "2 Esdras", chapter: 7, verse: 36, text: "Then said I, Abraham prayed first for the Sodomites, and Moses for the fathers that sinned in the wilderness:" },
  { book: "2 Esdras", chapter: 7, verse: 37, text: "And Jesus after him for Israel in the time of Achan:" },
  { book: "2 Esdras", chapter: 7, verse: 38, text: "And Samuel and David for the destruction: and Solomon for them that should come to the sanctuary:" },
  { book: "2 Esdras", chapter: 7, verse: 39, text: "And Helias for those that received rain; and for the dead, that he might live:" },
  { book: "2 Esdras", chapter: 7, verse: 40, text: "And Ezechias for the people in the time of Sennacherib: and many for many." },
  { book: "2 Esdras", chapter: 7, verse: 41, text: "Even so now, seeing corruption is grown up, and wickedness increased, and the righteous have prayed for the ungodly: wherefore shall it not be so now also?" },
  { book: "2 Esdras", chapter: 7, verse: 42, text: "He answered me, and said, This present life is not the end where much glory doth abide; therefore have they prayed for the weak." },
  { book: "2 Esdras", chapter: 7, verse: 43, text: "But the day of doom shall be the end of this time, and the beginning of the immortality for to come, wherein corruption is past," },
  { book: "2 Esdras", chapter: 7, verse: 44, text: "Intemperance is at an end, infidelity is cut off, righteousness is grown, and truth is sprung up." },
  { book: "2 Esdras", chapter: 7, verse: 45, text: "Then shall no man be able to save him that is destroyed, nor to oppress him that hath gotten the victory." },
  { book: "2 Esdras", chapter: 7, verse: 46, text: "I answered then and said, This is my first and last saying, that it had been better not to have given the earth unto Adam: or else, when it was given him, to have restrained him from sinning." },
  { book: "2 Esdras", chapter: 7, verse: 47, text: "For what profit is it for men now in this present time to live in heaviness, and after death to look for punishment?" },
  { book: "2 Esdras", chapter: 7, verse: 48, text: "O thou Adam, what hast thou done? for though it was thou that sinned, thou art not fallen alone, but we all that come of thee." },
  { book: "2 Esdras", chapter: 7, verse: 49, text: "For what profit is it unto us, if there be promised us an immortal time, whereas we have done the works that bring death?" },
  { book: "2 Esdras", chapter: 7, verse: 50, text: "And that there is promised us an everlasting hope, whereas ourselves being most wicked are made vain?" },
  { book: "2 Esdras", chapter: 7, verse: 51, text: "And that there are laid up for us dwellings of health and safety, whereas we have lived wickedly?" },
  { book: "2 Esdras", chapter: 7, verse: 52, text: "And that the glory of the most High is kept to defend them which have led a wary life, whereas we have walked in the most wicked ways of all?" },
  { book: "2 Esdras", chapter: 7, verse: 53, text: "And that there should be shewed a paradise, whose fruit endureth for ever, wherein is security and medicine, since we shall not enter into it?" },
  { book: "2 Esdras", chapter: 7, verse: 54, text: "(For we have walked in unpleasant places.)" },
  { book: "2 Esdras", chapter: 7, verse: 55, text: "And that the faces of them which have used abstinence shall shine above the stars, whereas our faces shall be blacker than darkness?" },
  { book: "2 Esdras", chapter: 7, verse: 56, text: "For while we lived and committed iniquity, we considered not that we should begin to suffer for it after death." },
  { book: "2 Esdras", chapter: 7, verse: 57, text: "Then answered he me, and said, This is the condition of the battle, which man that is born upon the earth shall fight;" },
  { book: "2 Esdras", chapter: 7, verse: 58, text: "That, if he be overcome, he shall suffer as thou hast said: but if he get the victory, he shall receive the thing that I say." },
  { book: "2 Esdras", chapter: 7, verse: 59, text: "For this is the life whereof Moses spake unto the people while he lived, saying, Choose thee life, that thou mayest live." },
  { book: "2 Esdras", chapter: 7, verse: 60, text: "Nevertheless they believed not him, nor yet the prophets after him, no nor me which have spoken unto them," },
  { book: "2 Esdras", chapter: 7, verse: 61, text: "That there should not be such heaviness in their destruction, as shall be joy over them that are persuaded to salvation." },
  { book: "2 Esdras", chapter: 7, verse: 62, text: "I answered then, and said, I know, Lord, that the most High is called merciful, in that he hath mercy upon them which are not yet come into the world," },
  { book: "2 Esdras", chapter: 7, verse: 63, text: "And upon those also that turn to his law;" },
  { book: "2 Esdras", chapter: 7, verse: 64, text: "And that he is patient, and long suffereth those that have sinned, as his creatures;" },
  { book: "2 Esdras", chapter: 7, verse: 65, text: "And that he is bountiful, for he is ready to give where it needeth;" },
  { book: "2 Esdras", chapter: 7, verse: 66, text: "And that he is of great mercy, for he multiplieth more and more mercies to them that are present, and that are past, and also to them which are to come." },
  { book: "2 Esdras", chapter: 7, verse: 67, text: "For if he shall not multiply his mercies, the world would not continue with them that inherit therein." },
  { book: "2 Esdras", chapter: 7, verse: 68, text: "And he pardoneth; for if he did not so of his goodness, that they which have committed iniquities might be eased of them, the ten thousandth part of men should not remain living." },
  { book: "2 Esdras", chapter: 7, verse: 69, text: "And being judge, if he should not forgive them that are cured with his word, and put out the multitude of contentions," },
  { book: "2 Esdras", chapter: 7, verse: 70, text: "There should be very few left peradventure in an innumerable multitude." },
  { book: "2 Esdras", chapter: 8, verse: 1, text: "And he answered me, saying, The most High hath made this world for many, but the world to come for few." },
  { book: "2 Esdras", chapter: 8, verse: 2, text: "I will tell thee a similitude, Esdras; As when thou askest the earth, it shall say unto thee, that it giveth much mould whereof earthen vessels are made, but little dust that gold cometh of: even so is the course of this present world." },
  { book: "2 Esdras", chapter: 8, verse: 3, text: "There be many created, but few shall be saved." },
  { book: "2 Esdras", chapter: 8, verse: 4, text: "So answered I and said, Swallow then down, O my soul, understanding, and devour wisdom." },
  { book: "2 Esdras", chapter: 8, verse: 5, text: "For thou hast agreed to give ear, and art willing to prophesy: for thou hast no longer space than only to live." },
  { book: "2 Esdras", chapter: 8, verse: 6, text: "O Lord, if thou suffer not thy servant, that we may pray before thee, and thou give us seed unto our heart, and culture to our understanding, that there may come fruit of it; how shall each man live that is corrupt, who beareth the place of a man?" },
  { book: "2 Esdras", chapter: 8, verse: 7, text: "For thou art alone, and we all one workmanship of thine hands, like as thou hast said." },
  { book: "2 Esdras", chapter: 8, verse: 8, text: "For when the body is fashioned now in the mother’s womb, and thou givest it members, thy creature is preserved in fire and water, and nine months doth thy workmanship endure thy creature which is created in her." },
  { book: "2 Esdras", chapter: 8, verse: 9, text: "But that which keepeth and is kept shall both be preserved: and when the time cometh, the womb preserved delivereth up the things that grew in it." },
  { book: "2 Esdras", chapter: 8, verse: 10, text: "For thou hast commanded out of the parts of the body, that is to say, out of the breasts, milk to be given, which is the fruit of the breasts," },
  { book: "2 Esdras", chapter: 8, verse: 11, text: "That the thing which is fashioned may be nourished for a time, till thou disposest it to thy mercy." },
  { book: "2 Esdras", chapter: 8, verse: 12, text: "Thou broughtest it up with thy righteousness, and nurturedst it in thy law, and reformedst it with thy judgment." },
  { book: "2 Esdras", chapter: 8, verse: 13, text: "And thou shalt mortify it as thy creature, and quicken it as thy work." },
  { book: "2 Esdras", chapter: 8, verse: 14, text: "If therefore thou shalt destroy him which with so great labour was fashioned, it is an easy thing to be ordained by thy commandment, that the thing which was made might be preserved." },
  { book: "2 Esdras", chapter: 8, verse: 15, text: "Now therefore, Lord, I will speak; touching man in general, thou knowest best; but touching thy people, for whose sake I am sorry;" },
  { book: "2 Esdras", chapter: 8, verse: 16, text: "And for thine inheritance, for whose cause I mourn; and for Israel, for whom I am heavy; and for Jacob, for whose sake I am troubled;" },
  { book: "2 Esdras", chapter: 8, verse: 17, text: "Therefore will I begin to pray before thee for myself and for them: for I see the falls of us that dwell in the land." },
  { book: "2 Esdras", chapter: 8, verse: 18, text: "But I have heard the swiftness of the judge which is to come." },
  { book: "2 Esdras", chapter: 8, verse: 19, text: "Therefore hear my voice, and understand my words, and I shall speak before thee. This is the beginning of the words of Esdras, before he was taken up: and I said," },
  { book: "2 Esdras", chapter: 8, verse: 20, text: "O Lord, thou that dwellest in everlastingness which beholdest from above things in the heaven and in the air;" },
  { book: "2 Esdras", chapter: 8, verse: 21, text: "Whose throne is inestimable; whose glory may not be comprehended; before whom the hosts of angels stand with trembling," },
  { book: "2 Esdras", chapter: 8, verse: 22, text: "Whose service is conversant in wind and fire; whose word is true, and sayings constant; whose commandment is strong, and ordinance fearful;" },
  { book: "2 Esdras", chapter: 8, verse: 23, text: "Whose look drieth up the depths, and indignation maketh the mountains to melt away; which the truth witnesseth:" },
  { book: "2 Esdras", chapter: 8, verse: 24, text: "O hear the prayer of thy servant, and give ear to the petition of thy creature." },
  { book: "2 Esdras", chapter: 8, verse: 25, text: "For while I live I will speak, and so long as I have understanding I will answer." },
  { book: "2 Esdras", chapter: 8, verse: 26, text: "O look not upon the sins of thy people; but on them which serve thee in truth." },
  { book: "2 Esdras", chapter: 8, verse: 27, text: "Regard not the wicked inventions of the heathen, but the desire of those that keep thy testimonies in afflictions." },
  { book: "2 Esdras", chapter: 8, verse: 28, text: "Think not upon those that have walked feignedly before thee: but remember them, which according to thy will have known thy fear." },
  { book: "2 Esdras", chapter: 8, verse: 29, text: "Let it not be thy will to destroy them which have lived like beasts; but to look upon them that have clearly taught thy law." },
  { book: "2 Esdras", chapter: 8, verse: 30, text: "Take thou no indignation at them which are deemed worse than beasts; but love them that always put their trust in thy righteousness and glory." },
  { book: "2 Esdras", chapter: 8, verse: 31, text: "For we and our fathers do languish of such diseases: but because of us sinners thou shalt be called merciful." },
  { book: "2 Esdras", chapter: 8, verse: 32, text: "For if thou hast a desire to have mercy upon us, thou shalt be called merciful, to us namely, that have no works of righteousness." },
  { book: "2 Esdras", chapter: 8, verse: 33, text: "For the just, which have many good works laid up with thee, shall out of their own deeds receive reward." },
  { book: "2 Esdras", chapter: 8, verse: 34, text: "For what is man, that thou shouldest take displeasure at him? or what is a corruptible generation, that thou shouldest be so bitter toward it?" },
  { book: "2 Esdras", chapter: 8, verse: 35, text: "For in truth them is no man among them that be born, but he hath dealt wickedly; and among the faithful there is none which hath not done amiss." },
  { book: "2 Esdras", chapter: 8, verse: 36, text: "For in this, O Lord, thy righteousness and thy goodness shall be declared, if thou be merciful unto them which have not the confidence of good works." },
  { book: "2 Esdras", chapter: 8, verse: 37, text: "Then answered he me, and said, Some things hast thou spoken aright, and according unto thy words it shall be." },
  { book: "2 Esdras", chapter: 8, verse: 38, text: "For indeed I will not think on the disposition of them which have sinned before death, before judgment, before destruction:" },
  { book: "2 Esdras", chapter: 8, verse: 39, text: "But I will rejoice over the disposition of the righteous, and I will remember also their pilgrimage, and the salvation, and the reward, that they shall have." },
  { book: "2 Esdras", chapter: 8, verse: 40, text: "Like as I have spoken now, so shall it come to pass." },
  { book: "2 Esdras", chapter: 8, verse: 41, text: "For as the husbandman soweth much seed upon the ground, and planteth many trees, and yet the thing that is sown good in his season cometh not up, neither doth all that is planted take root: even so is it of them that are sown in the world; they shall not all be saved." },
  { book: "2 Esdras", chapter: 8, verse: 42, text: "I answered then and said, If I have found grace, let me speak." },
  { book: "2 Esdras", chapter: 8, verse: 43, text: "Like as the husbandman’s seed perisheth, if it come not up, and receive not thy rain in due season; or if there come too much rain, and corrupt it:" },
  { book: "2 Esdras", chapter: 8, verse: 44, text: "Even so perisheth man also, which is formed with thy hands, and is called thine own image, because thou art like unto him, for whose sake thou hast made all things, and likened him unto the husbandman’s seed." },
  { book: "2 Esdras", chapter: 8, verse: 45, text: "Be not wroth with us but spare thy people, and have mercy upon thine own inheritance: for thou art merciful unto thy creature." },
  { book: "2 Esdras", chapter: 8, verse: 46, text: "Then answered he me, and said, Things present are for the present, and things to cometh for such as be to come." },
  { book: "2 Esdras", chapter: 8, verse: 47, text: "For thou comest far short that thou shouldest be able to love my creature more than I: but I have ofttimes drawn nigh unto thee, and unto it, but never to the unrighteous." },
  { book: "2 Esdras", chapter: 8, verse: 48, text: "In this also thou art marvellous before the most High:" },
  { book: "2 Esdras", chapter: 8, verse: 49, text: "In that thou hast humbled thyself, as it becometh thee, and hast not judged thyself worthy to be much glorified among the righteous." },
  { book: "2 Esdras", chapter: 8, verse: 50, text: "For many great miseries shall be done to them that in the latter time shall dwell in the world, because they have walked in great pride." },
  { book: "2 Esdras", chapter: 8, verse: 51, text: "But understand thou for thyself, and seek out the glory for such as be like thee." },
  { book: "2 Esdras", chapter: 8, verse: 52, text: "For unto you is paradise opened, the tree of life is planted, the time to come is prepared, plenteousness is made ready, a city is builded, and rest is allowed, yea, perfect goodness and wisdom." },
  { book: "2 Esdras", chapter: 8, verse: 53, text: "The root of evil is sealed up from you, weakness and the moth is hid from you, and corruption is fled into hell to be forgotten:" },
  { book: "2 Esdras", chapter: 8, verse: 54, text: "Sorrows are passed, and in the end is shewed the treasure of immortality." },
  { book: "2 Esdras", chapter: 8, verse: 55, text: "And therefore ask thou no more questions concerning the multitude of them that perish." },
  { book: "2 Esdras", chapter: 8, verse: 56, text: "For when they had taken liberty, they despised the most High, thought scorn of his law, and forsook his ways." },
  { book: "2 Esdras", chapter: 8, verse: 57, text: "Moreover they have trodden down his righteous," },
  { book: "2 Esdras", chapter: 8, verse: 58, text: "And said in their heart, that there is no God; yea, and that knowing they must die." },
  { book: "2 Esdras", chapter: 8, verse: 59, text: "For as the things aforesaid shalt receive you, so thirst and pain are prepared for them: for it was not his will that men should come to nought:" },
  { book: "2 Esdras", chapter: 8, verse: 60, text: "But they which be created have defiled the name of him that made them, and were unthankful unto him which prepared life for them." },
  { book: "2 Esdras", chapter: 8, verse: 61, text: "And therefore is my judgment now at hand." },
  { book: "2 Esdras", chapter: 8, verse: 62, text: "These things have I not shewed unto all men, but unto thee, and a few like thee. Then answered I and said," },
  { book: "2 Esdras", chapter: 8, verse: 63, text: "Behold, O Lord, now hast thou shewed me the multitude of the wonders, which thou wilt begin to do in the last times: but at what time, thou hast not shewed me." },
  { book: "2 Esdras", chapter: 9, verse: 1, text: "He answered me then, and said, Measure thou the time diligently in itself: and when thou seest part of the signs past, which I have told thee before," },
  { book: "2 Esdras", chapter: 9, verse: 2, text: "Then shalt thou understand, that it is the very same time, wherein the Highest will begin to visit the world which he made." },
  { book: "2 Esdras", chapter: 9, verse: 3, text: "Therefore when there shall be seen earthquakes and uproars of the people in the world:" },
  { book: "2 Esdras", chapter: 9, verse: 4, text: "Then shalt thou well understand, that the most High spake of those things from the days that were before thee, even from the beginning." },
  { book: "2 Esdras", chapter: 9, verse: 5, text: "For like as all that is made in the world hath a beginning and an end, and the end is manifest:" },
  { book: "2 Esdras", chapter: 9, verse: 6, text: "Even so the times also of the Highest have plain beginnings in wonder and powerful works, and endings in effects and signs." },
  { book: "2 Esdras", chapter: 9, verse: 7, text: "And every one that shall be saved, and shall be able to escape by his works, and by faith, whereby ye have believed," },
  { book: "2 Esdras", chapter: 9, verse: 8, text: "Shall be preserved from the said perils, and shall see my salvation in my land, and within my borders: for I have sanctified them for me from the beginning." },
  { book: "2 Esdras", chapter: 9, verse: 9, text: "Then shall they be in pitiful case, which now have abused my ways: and they that have cast them away despitefully shall dwell in torments." },
  { book: "2 Esdras", chapter: 9, verse: 10, text: "For such as in their life have received benefits, and have not known me;" },
  { book: "2 Esdras", chapter: 9, verse: 11, text: "And they that have loathed my law, while they had yet liberty, and, when as yet place of repentance was open unto them, understood not, but despised it;" },
  { book: "2 Esdras", chapter: 9, verse: 12, text: "The same must know it after death by pain." },
  { book: "2 Esdras", chapter: 9, verse: 13, text: "And therefore be thou not curious how the ungodly shall be punished, and when: but enquire how the righteous shall be saved, whose the world is, and for whom the world is created." },
  { book: "2 Esdras", chapter: 9, verse: 14, text: "Then answered I and said," },
  { book: "2 Esdras", chapter: 9, verse: 15, text: "I have said before, and now do speak, and will speak it also hereafter, that there be many more of them which perish, than of them which shall be saved:" },
  { book: "2 Esdras", chapter: 9, verse: 16, text: "Like as a wave is greater than a drop." },
  { book: "2 Esdras", chapter: 9, verse: 17, text: "And he answered me, saying, Like as the field is, so is also the seed; as the flowers be, such are the colours also; such as the workman is, such also is the work; and as the husbandman is himself, so is his husbandry also: for it was the time of the world." },
  { book: "2 Esdras", chapter: 9, verse: 18, text: "And now when I prepared the world, which was not yet made, even for them to dwell in that now live, no man spake against me." },
  { book: "2 Esdras", chapter: 9, verse: 19, text: "For then every one obeyed: but now the manners of them which are created in this world that is made are corrupted by a perpetual seed, and by a law which is unsearchable rid themselves." },
  { book: "2 Esdras", chapter: 9, verse: 20, text: "So I considered the world, and, behold, there was peril because of the devices that were come into it." },
  { book: "2 Esdras", chapter: 9, verse: 21, text: "And I saw, and spared it greatly, and have kept me a grape of the cluster, and a plant of a great people." },
  { book: "2 Esdras", chapter: 9, verse: 22, text: "Let the multitude perish then, which was born in vain; and let my grape be kept, and my plant; for with great labour have I made it perfect." },
  { book: "2 Esdras", chapter: 9, verse: 23, text: "Nevertheless, if thou wilt cease yet seven days more, (but thou shalt not fast in them," },
  { book: "2 Esdras", chapter: 9, verse: 24, text: "But go into a field of flowers, where no house is builded, and eat only the flowers of the field; taste no flesh, drink no wine, but eat flowers only;)" },
  { book: "2 Esdras", chapter: 9, verse: 25, text: "And pray unto the Highest continually, then will I come and talk with thee." },
  { book: "2 Esdras", chapter: 9, verse: 26, text: "So I went my way into the field which is called Ardath, like as he commanded me; and there I sat among the flowers, and did eat of the herbs of the field, and the meat of the same satisfied me." },
  { book: "2 Esdras", chapter: 9, verse: 27, text: "After seven days I sat upon the grass, and my heart was vexed within me, like as before:" },
  { book: "2 Esdras", chapter: 9, verse: 28, text: "And I opened my mouth, and began to talk before the most High, and said," },
  { book: "2 Esdras", chapter: 9, verse: 29, text: "O Lord, thou that shewest thyself unto us, thou wast shewed unto our fathers in the wilderness, in a place where no man treadeth, in a barren place, when they came out of Egypt." },
  { book: "2 Esdras", chapter: 9, verse: 30, text: "And thou spakest saying, Hear me, O Israel; and mark my words, thou seed of Jacob." },
  { book: "2 Esdras", chapter: 9, verse: 31, text: "For, behold, I sow my law in you, and it shall bring fruit in you, and ye shall be honoured in it for ever." },
  { book: "2 Esdras", chapter: 9, verse: 32, text: "But our fathers, which received the law, kept it not, and observed not thy ordinances: and though the fruit of thy law did not perish, neither could it, for it was thine;" },
  { book: "2 Esdras", chapter: 9, verse: 33, text: "Yet they that received it perished, because they kept not the thing that was sown in them." },
  { book: "2 Esdras", chapter: 9, verse: 34, text: "And, lo, it is a custom, when the ground hath received seed, or the sea a ship, or any vessel meat or drink, that, that being perished wherein it was sown or cast into," },
  { book: "2 Esdras", chapter: 9, verse: 35, text: "That thing also which was sown, or cast therein, or received, doth perish, and remaineth not with us: but with us it hath not happened so." },
  { book: "2 Esdras", chapter: 9, verse: 36, text: "For we that have received the law perish by sin, and our heart also which received it" },
  { book: "2 Esdras", chapter: 9, verse: 37, text: "Notwithstanding the law perisheth not, but remaineth in his force." },
  { book: "2 Esdras", chapter: 9, verse: 38, text: "And when I spake these things in my heart, I looked back with mine eyes, and upon the right side I saw a woman, and, behold, she mourned and wept with a loud voice, and was much grieved in heart, and her clothes were rent, and she had ashes upon her head." },
  { book: "2 Esdras", chapter: 9, verse: 39, text: "Then let I my thoughts go that I was in, and turned me unto her," },
  { book: "2 Esdras", chapter: 9, verse: 40, text: "And said unto her, Wherefore weepest thou? why art thou so grieved in thy mind?" },
  { book: "2 Esdras", chapter: 9, verse: 41, text: "And she said unto me, Sir, let me alone, that I may bewail myself, and add unto my sorrow, for I am sore vexed in my mind, and brought very low." },
  { book: "2 Esdras", chapter: 9, verse: 42, text: "And I said unto her, What aileth thee? tell me." },
  { book: "2 Esdras", chapter: 9, verse: 43, text: "She said unto me, I thy servant have been barren, and had no child, though I had an husband thirty years," },
  { book: "2 Esdras", chapter: 9, verse: 44, text: "And those thirty years I did nothing else day and night, and every hour, but make my, prayer to the Highest." },
  { book: "2 Esdras", chapter: 9, verse: 45, text: "After thirty years God heard me thine handmaid, looked upon my misery, considered my trouble, and gave me a son: and I was very glad of him, so was my husband also, and all my neighbours: and we gave great honour unto the Almighty." },
  { book: "2 Esdras", chapter: 9, verse: 46, text: "And I nourished him with great travail." },
  { book: "2 Esdras", chapter: 9, verse: 47, text: "So when he grew up, and came to the time that he should have a wife, I made a feast." },
  { book: "2 Esdras", chapter: 10, verse: 1, text: "And it so came to pass, that when my son was entered into his wedding chamber, he fell down, and died." },
  { book: "2 Esdras", chapter: 10, verse: 2, text: "Then we all overthrew the lights, and all my neighbours rose up to comfort me: so I took my rest unto the second day at night." },
  { book: "2 Esdras", chapter: 10, verse: 3, text: "And it came to pass, when they had all left off to comfort me, to the end I might be quiet; then rose I up by night and fled, and came hither into this field, as thou seest." },
  { book: "2 Esdras", chapter: 10, verse: 4, text: "And I do now purpose not to return into the city, but here to stay, and neither to eat nor drink, but continually to mourn and to fast until I die." },
  { book: "2 Esdras", chapter: 10, verse: 5, text: "Then left I the meditations wherein I was, and spake to her in anger, saying," },
  { book: "2 Esdras", chapter: 10, verse: 6, text: "Thou foolish woman above all other, seest thou not our mourning, and what happeneth unto us?" },
  { book: "2 Esdras", chapter: 10, verse: 7, text: "How that Sion our mother is full of all heaviness, and much humbled, mourning very sore?" },
  { book: "2 Esdras", chapter: 10, verse: 8, text: "And now, seeing we all mourn and are sad, for we are all in heaviness, art thou grieved for one son?" },
  { book: "2 Esdras", chapter: 10, verse: 9, text: "For ask the earth, and she shall tell thee, that it is she which ought to mourn for the fall of so many that grow upon her." },
  { book: "2 Esdras", chapter: 10, verse: 10, text: "For out of her came all at the first, and out of her shall all others come, and, behold, they walk almost all into destruction, and a multitude of them is utterly rooted out." },
  { book: "2 Esdras", chapter: 10, verse: 11, text: "Who then should make more mourning than she, that hath lost so great a multitude; and not thou, which art sorry but for one?" },
  { book: "2 Esdras", chapter: 10, verse: 12, text: "But if thou sayest unto me, My lamentation is not like the earth’s, because I have lost the fruit of my womb, which I brought forth with pains, and bare with sorrows;" },
  { book: "2 Esdras", chapter: 10, verse: 13, text: "But the earth not so: for the multitude present in it according to the course of the earth is gone, as it came:" },
  { book: "2 Esdras", chapter: 10, verse: 14, text: "Then say I unto thee, Like as thou hast brought forth with labour; even so the earth also hath given her fruit, namely, man, ever since the beginning unto him that made her." },
  { book: "2 Esdras", chapter: 10, verse: 15, text: "Now therefore keep thy sorrow to thyself, and bear with a good courage that which hath befallen thee." },
  { book: "2 Esdras", chapter: 10, verse: 16, text: "For if thou shalt acknowledge the determination of God to be just, thou shalt both receive thy son in time, and shalt be commended among women." },
  { book: "2 Esdras", chapter: 10, verse: 17, text: "Go thy way then into the city to thine husband." },
  { book: "2 Esdras", chapter: 10, verse: 18, text: "And she said unto me, That will I not do: I will not go into the city, but here will I die." },
  { book: "2 Esdras", chapter: 10, verse: 19, text: "So I proceeded to speak further unto her, and said," },
  { book: "2 Esdras", chapter: 10, verse: 20, text: "Do not so, but be counselled. by me: for how many are the adversities of Sion? be comforted in regard of the sorrow of Jerusalem." },
  { book: "2 Esdras", chapter: 10, verse: 21, text: "For thou seest that our sanctuary is laid waste, our altar broken down, our temple destroyed;" },
  { book: "2 Esdras", chapter: 10, verse: 22, text: "Our psaltery is laid on the ground, our song is put to silence, our rejoicing is at an end, the light of our candlestick is put out, the ark of our covenant is spoiled, our holy things are defiled, and the name that is called upon us is almost profaned: our children are put to shame, our priests are burnt, our Levites are gone into captivity, our virgins are defiled, and our wives ravished; our righteous men carried away, our little ones destroyed, our young men are brought in bondage, and our strong men are become weak;" },
  { book: "2 Esdras", chapter: 10, verse: 23, text: "And, which is the greatest of all, the seal of Sion hath now lost her honour; for she is delivered into the hands of them that hate us." },
  { book: "2 Esdras", chapter: 10, verse: 24, text: "And therefore shake off thy great heaviness, and put away the multitude of sorrows, that the Mighty may be merciful unto thee again, and the Highest shall give thee rest and ease from thy labour." },
  { book: "2 Esdras", chapter: 10, verse: 25, text: "And it came to pass while I was talking with her, behold, her face upon a sudden shined exceedingly, and her countenance glistered, so that I was afraid of her, and mused what it might be." },
  { book: "2 Esdras", chapter: 10, verse: 26, text: "And, behold, suddenly she made a great cry very fearful: so that the earth shook at the noise of the woman." },
  { book: "2 Esdras", chapter: 10, verse: 27, text: "And I looked, and, behold, the woman appeared unto me no more, but there was a city builded, and a large place shewed itself from the foundations: then was I afraid, and cried with a loud voice, and said," },
  { book: "2 Esdras", chapter: 10, verse: 28, text: "Where is Uriel the angel, who came unto me at the first? for he hath caused me to fall into many trances, and mine end is turned into corruption, and my prayer to rebuke." },
  { book: "2 Esdras", chapter: 10, verse: 29, text: "And as I was speaking these words behold, he came unto me, and looked upon me." },
  { book: "2 Esdras", chapter: 10, verse: 30, text: "And, lo, I lay as one that had been dead, and mine understanding was taken from me: and he took me by the right hand, and comforted me, and set me upon my feet, and said unto me," },
  { book: "2 Esdras", chapter: 10, verse: 31, text: "What aileth thee? and why art thou so disquieted? and why is thine understanding troubled, and the thoughts of thine heart?" },
  { book: "2 Esdras", chapter: 10, verse: 32, text: "And I said, Because thou hast forsaken me, and yet I did according to thy words, and I went into the field, and, lo, I have seen, and yet see, that I am not able to express." },
  { book: "2 Esdras", chapter: 10, verse: 33, text: "And he said unto me, Stand up manfully, and I will advise thee." },
  { book: "2 Esdras", chapter: 10, verse: 34, text: "Then said I, Speak on, my lord, in me; only forsake me not, lest I die frustrate of my hope." },
  { book: "2 Esdras", chapter: 10, verse: 35, text: "For I have seen that I knew not, and hear that I do not know." },
  { book: "2 Esdras", chapter: 10, verse: 36, text: "Or is my sense deceived, or my soul in a dream?" },
  { book: "2 Esdras", chapter: 10, verse: 37, text: "Now therefore I beseech thee that thou wilt shew thy servant of this vision." },
  { book: "2 Esdras", chapter: 10, verse: 38, text: "He answered me then, and said, Hear me, and I shall inform thee, and tell thee wherefore thou art afraid: for the Highest will reveal many secret things unto thee." },
  { book: "2 Esdras", chapter: 10, verse: 39, text: "He hath seen that thy way is right: for that thou sorrowest continually for thy people, and makest great lamentation for Sion." },
  { book: "2 Esdras", chapter: 10, verse: 40, text: "This therefore is the meaning of the vision which thou lately sawest:" },
  { book: "2 Esdras", chapter: 10, verse: 41, text: "Thou sawest a woman mourning, and thou begannest to comfort her:" },
  { book: "2 Esdras", chapter: 10, verse: 42, text: "But now seest thou the likeness of the woman no more, but there appeared unto thee a city builded." },
  { book: "2 Esdras", chapter: 10, verse: 43, text: "And whereas she told thee of the death of her son, this is the solution:" },
  { book: "2 Esdras", chapter: 10, verse: 44, text: "This woman, whom thou sawest is Sion: and whereas she said unto thee, even she whom thou seest as a city builded," },
  { book: "2 Esdras", chapter: 10, verse: 45, text: "Whereas, I say, she said unto thee, that she hath been thirty years barren: those are the thirty years wherein there was no offering made in her." },
  { book: "2 Esdras", chapter: 10, verse: 46, text: "But after thirty years Solomon builded the city and offered offerings: and then bare the barren a son." },
  { book: "2 Esdras", chapter: 10, verse: 47, text: "And whereas she told thee that she nourished him with labour: that was the dwelling in Jerusalem." },
  { book: "2 Esdras", chapter: 10, verse: 48, text: "But whereas she said unto thee, That my son coming into his marriage chamber happened to have a fail, and died: this was the destruction that came to Jerusalem." },
  { book: "2 Esdras", chapter: 10, verse: 49, text: "And, behold, thou sawest her likeness, and because she mourned for her son, thou begannest to comfort her: and of these things which have chanced, these are to be opened unto thee." },
  { book: "2 Esdras", chapter: 10, verse: 50, text: "For now the most High seeth that thou art grieved unfeignedly, and sufferest from thy whole heart for her, so hath he shewed thee the brightness of her glory, and the comeliness of her beauty:" },
  { book: "2 Esdras", chapter: 10, verse: 51, text: "And therefore I bade thee remain in the field where no house was builded:" },
  { book: "2 Esdras", chapter: 10, verse: 52, text: "For I knew that the Highest would shew this unto thee." },
  { book: "2 Esdras", chapter: 10, verse: 53, text: "Therefore I commanded thee to go into the field, where no foundation of any building was." },
  { book: "2 Esdras", chapter: 10, verse: 54, text: "For in the place wherein the Highest beginneth to shew his city, there can no man’s building be able to stand." },
  { book: "2 Esdras", chapter: 10, verse: 55, text: "And therefore fear not, let not thine heart be affrighted, but go thy way in, and see the beauty and greatness of the building, as much as thine eyes be able to see:" },
  { book: "2 Esdras", chapter: 10, verse: 56, text: "And then shalt thou hear as much as thine ears may comprehend." },
  { book: "2 Esdras", chapter: 10, verse: 57, text: "For thou art blessed above many other, and art called with the Highest; and so are but few." },
  { book: "2 Esdras", chapter: 10, verse: 58, text: "But to morrow at night thou shalt remain here;" },
  { book: "2 Esdras", chapter: 10, verse: 59, text: "And so shall the Highest shew thee visions of the high things, which the most High will do unto them that dwell upon the earth in the last days. So I slept that night and another, like as he commanded me." },
  { book: "2 Esdras", chapter: 11, verse: 1, text: "Then saw I a dream, and, behold, there came up from the sea an eagle, which had twelve feathered wings, and three heads." },
  { book: "2 Esdras", chapter: 11, verse: 2, text: "And I saw, and, behold, she spread her wings over all the earth, and all the winds of the air blew on her, and were gathered together." },
  { book: "2 Esdras", chapter: 11, verse: 3, text: "And I beheld, and out of her feathers there grew other contrary feathers; and they became little feathers and small." },
  { book: "2 Esdras", chapter: 11, verse: 4, text: "But her heads were at rest: the head in the midst was greater than the other, yet rested it with the residue." },
  { book: "2 Esdras", chapter: 11, verse: 5, text: "Moreover I beheld, and, lo, the eagle flew with her feathers, and reigned upon earth, and over them that dwelt therein." },
  { book: "2 Esdras", chapter: 11, verse: 6, text: "And I saw that all things under heaven were subject unto her, and no man spake against her, no, not one creature upon earth." },
  { book: "2 Esdras", chapter: 11, verse: 7, text: "And I beheld, and, lo, the eagle rose upon her talons, and spake to her feathers, saying," },
  { book: "2 Esdras", chapter: 11, verse: 8, text: "Watch not all at once: sleep every one in his own place, and watch by course:" },
  { book: "2 Esdras", chapter: 11, verse: 9, text: "But let the heads be preserved for the last." },
  { book: "2 Esdras", chapter: 11, verse: 10, text: "And I beheld, and, lo, the voice went not out of her heads, but from the midst of her body." },
  { book: "2 Esdras", chapter: 11, verse: 11, text: "And I numbered her contrary feathers, and, behold, there were eight of them." },
  { book: "2 Esdras", chapter: 11, verse: 12, text: "And I looked, and, behold, on the right side there arose one feather, and reigned over all the earth;" },
  { book: "2 Esdras", chapter: 11, verse: 13, text: "And so it was, that when it reigned, the end of it came, and the place thereof appeared no more: so the next following stood up. and reigned, and had a great time;" },
  { book: "2 Esdras", chapter: 11, verse: 14, text: "And it happened, that when it reigned, the end of it came also, like as the first, so that it appeared no more." },
  { book: "2 Esdras", chapter: 11, verse: 15, text: "Then came there a voice unto it, and said," },
  { book: "2 Esdras", chapter: 11, verse: 16, text: "Hear thou that hast borne rule over the earth so long: this I say unto thee, before thou beginnest to appear no more," },
  { book: "2 Esdras", chapter: 11, verse: 17, text: "There shall none after thee attain unto thy time, neither unto the half thereof." },
  { book: "2 Esdras", chapter: 11, verse: 18, text: "Then arose the third, and reigned as the other before, and appeared no more also." },
  { book: "2 Esdras", chapter: 11, verse: 19, text: "So went it with all the residue one after another, as that every one reigned, and then appeared no more." },
  { book: "2 Esdras", chapter: 11, verse: 20, text: "Then I beheld, and, lo, in process of time the feathers that followed stood up upon the right side, that they might rule also; and some of them ruled, but within a while they appeared no more:" },
  { book: "2 Esdras", chapter: 11, verse: 21, text: "For some of them were set up, but ruled not." },
  { book: "2 Esdras", chapter: 11, verse: 22, text: "After this I looked, and, behold, the twelve feathers appeared no more, nor the two little feathers:" },
  { book: "2 Esdras", chapter: 11, verse: 23, text: "And there was no more upon the eagle’s body, but three heads that rested, and six little wings." },
  { book: "2 Esdras", chapter: 11, verse: 24, text: "Then saw I also that two little feathers divided themselves from the six, and remained under the head that was upon the right side: for the four continued in their place." },
  { book: "2 Esdras", chapter: 11, verse: 25, text: "And I beheld, and, lo, the feathers that were under the wing thought to set up themselves and to have the rule." },
  { book: "2 Esdras", chapter: 11, verse: 26, text: "And I beheld, and, lo, there was one set up, but shortly it appeared no more." },
  { book: "2 Esdras", chapter: 11, verse: 27, text: "And the second was sooner away than the first." },
  { book: "2 Esdras", chapter: 11, verse: 28, text: "And I beheld, and, lo, the two that remained thought also in themselves to reign:" },
  { book: "2 Esdras", chapter: 11, verse: 29, text: "And when they so thought, behold, there awaked one of the heads that were at rest, namely, it that was in the midst; for that was greater than the two other heads." },
  { book: "2 Esdras", chapter: 11, verse: 30, text: "And then I saw that the two other heads were joined with it." },
  { book: "2 Esdras", chapter: 11, verse: 31, text: "And, behold, the head was turned with them that were with it, and did eat up the two feathers under the wing that would have reigned." },
  { book: "2 Esdras", chapter: 11, verse: 32, text: "But this head put the whole earth in fear, and bare rule in it over all those that dwelt upon the earth with much oppression; and it had the governance of the world more than all the wings that had been." },
  { book: "2 Esdras", chapter: 11, verse: 33, text: "And after this I beheld, and, lo, the head that was in the midst suddenly appeared no more, like as the wings." },
  { book: "2 Esdras", chapter: 11, verse: 34, text: "But there remained the two heads, which also in like sort ruled upon the earth, and over those that dwelt therein." },
  { book: "2 Esdras", chapter: 11, verse: 35, text: "And I beheld, and, lo, the head upon the right side devoured it that was upon the left side." },
  { book: "2 Esdras", chapter: 11, verse: 36, text: "Then I head a voice, which said unto me, Look before thee, and consider the thing that thou seest." },
  { book: "2 Esdras", chapter: 11, verse: 37, text: "And I beheld, and lo, as it were a roaring lion chased out of the wood: and I saw that he sent out a man’s voice unto the eagle, and said," },
  { book: "2 Esdras", chapter: 11, verse: 38, text: "Hear thou, I will talk with thee, and the Highest shall say unto thee," },
  { book: "2 Esdras", chapter: 11, verse: 39, text: "Art not thou it that remainest of the four beasts, whom I made to reign in my world, that the end of their times might come through them?" },
  { book: "2 Esdras", chapter: 11, verse: 40, text: "And the fourth came, and overcame all the beasts that were past, and had power over the world with great fearfulness, and over the whole compass of the earth with much wicked oppression; and so long time dwelt he upon the earth with deceit." },
  { book: "2 Esdras", chapter: 11, verse: 41, text: "For the earth hast thou not judged with truth." },
  { book: "2 Esdras", chapter: 11, verse: 42, text: "For thou hast afflicted the meek, thou hast hurt the peaceable, thou hast loved liars, and destroyed the dwellings of them that brought forth fruit, and hast cast down the walls of such as did thee no harm." },
  { book: "2 Esdras", chapter: 11, verse: 43, text: "Therefore is thy wrongful dealing come up unto the Highest, and thy pride unto the Mighty." },
  { book: "2 Esdras", chapter: 11, verse: 44, text: "The Highest also hath looked upon the proud times, and, behold, they are ended, and his abominations are fulfilled." },
  { book: "2 Esdras", chapter: 11, verse: 45, text: "And therefore appear no more, thou eagle, nor thy horrible wings, nor thy wicked feathers nor thy malicious heads, nor thy hurtful claws, nor all thy vain body:" },
  { book: "2 Esdras", chapter: 11, verse: 46, text: "That all the earth may be refreshed, and may return, being delivered from thy violence, and that she may hope for the judgment and mercy of him that made her." },
  { book: "2 Esdras", chapter: 12, verse: 1, text: "And it came to pass, whiles the lion spake these words unto the eagle, I saw," },
  { book: "2 Esdras", chapter: 12, verse: 2, text: "And, behold, the head that remained and the four wings appeared no more, and the two went unto it and set themselves up to reign, and their kingdom was small, and fill of uproar." },
  { book: "2 Esdras", chapter: 12, verse: 3, text: "And I saw, and, behold, they appeared no more, and the whole body of the eagle was burnt so that the earth was in great fear: then awaked I out of the trouble and trance of my mind, and from great fear, and said unto my spirit," },
  { book: "2 Esdras", chapter: 12, verse: 4, text: "Lo, this hast thou done unto me, in that thou searchest out the ways of the Highest." },
  { book: "2 Esdras", chapter: 12, verse: 5, text: "Lo, yet am I weary in my mind, and very weak in my spirit; and little strength is there in me, for the great fear wherewith I was afflicted this night." },
  { book: "2 Esdras", chapter: 12, verse: 6, text: "Therefore will I now beseech the Highest, that he will comfort me unto the end." },
  { book: "2 Esdras", chapter: 12, verse: 7, text: "And I said, Lord that bearest rule, if I have found grace before thy sight, and if I am justified with thee before many others, and if my prayer indeed be come up before thy face;" },
  { book: "2 Esdras", chapter: 12, verse: 8, text: "Comfort me then, and shew me thy servant the interpretation and plain difference of this fearful vision, that thou mayest perfectly comfort my soul." },
  { book: "2 Esdras", chapter: 12, verse: 9, text: "For thou hast judged me worthy to shew me the last times." },
  { book: "2 Esdras", chapter: 12, verse: 10, text: "And he said unto me, This is the interpretation of the vision:" },
  { book: "2 Esdras", chapter: 12, verse: 11, text: "The eagle, whom thou sawest come up from the sea, is the kingdom which was seen in the vision of thy brother Daniel." },
  { book: "2 Esdras", chapter: 12, verse: 12, text: "But it was not expounded unto him, therefore now I declare it unto thee." },
  { book: "2 Esdras", chapter: 12, verse: 13, text: "Behold, the days will come, that there shall rise up a kingdom upon earth, and it shall be feared above all the kingdoms that were before it." },
  { book: "2 Esdras", chapter: 12, verse: 14, text: "In the same shall twelve kings reign, one after another:" },
  { book: "2 Esdras", chapter: 12, verse: 15, text: "Whereof the second shall begin to reign, and shall have more time than any of the twelve." },
  { book: "2 Esdras", chapter: 12, verse: 16, text: "And this do the twelve wings signify, which thou sawest." },
  { book: "2 Esdras", chapter: 12, verse: 17, text: "As for the voice which thou heardest speak, and that thou sawest not to go out from the heads but from the midst of the body thereof, this is the interpretation:" },
  { book: "2 Esdras", chapter: 12, verse: 18, text: "That after the time of that kingdom there shall arise great strivings, and it shall stand in peril of failing: nevertheless it shall not then fall, but shall be restored again to his beginning." },
  { book: "2 Esdras", chapter: 12, verse: 19, text: "And whereas thou sawest the eight small under feathers sticking to her wings, this is the interpretation:" },
  { book: "2 Esdras", chapter: 12, verse: 20, text: "That in him there shall arise eight kings, whose times shall be but small, and their years swift." },
  { book: "2 Esdras", chapter: 12, verse: 21, text: "And two of them shall perish, the middle time approaching: four shall be kept until their end begin to approach: but two shall be kept unto the end." },
  { book: "2 Esdras", chapter: 12, verse: 22, text: "And whereas thou sawest three heads resting, this is the interpretation:" },
  { book: "2 Esdras", chapter: 12, verse: 23, text: "In his last days shall the most High raise up three kingdoms, and renew many things therein, and they shall have the dominion of the earth," },
  { book: "2 Esdras", chapter: 12, verse: 24, text: "And of those that dwell therein, with much oppression, above all those that were before them: therefore are they called the heads of the eagle." },
  { book: "2 Esdras", chapter: 12, verse: 25, text: "For these are they that shall accomplish his wickedness, and that shall finish his last end." },
  { book: "2 Esdras", chapter: 12, verse: 26, text: "And whereas thou sawest that the great head appeared no more, it signifieth that one of them shall die upon his bed, and yet with pain." },
  { book: "2 Esdras", chapter: 12, verse: 27, text: "For the two that remain shall be slain with the sword." },
  { book: "2 Esdras", chapter: 12, verse: 28, text: "For the sword of the one shall devour the other: but at the last shall he fall through the sword himself." },
  { book: "2 Esdras", chapter: 12, verse: 29, text: "And whereas thou sawest two feathers under the wings passing over the head that is on the right side;" },
  { book: "2 Esdras", chapter: 12, verse: 30, text: "It signifieth that these are they, whom the Highest hath kept unto their end: this is the small kingdom and full of trouble, as thou sawest." },
  { book: "2 Esdras", chapter: 12, verse: 31, text: "And the lion, whom thou sawest rising up out of the wood, and roaring, and speaking to the eagle, and rebuking her for her unrighteousness with all the words which thou hast heard;" },
  { book: "2 Esdras", chapter: 12, verse: 32, text: "This is the anointed, which the Highest hath kept for them and for their wickedness unto the end: he shall reprove them, and shall upbraid them with their cruelty." },
  { book: "2 Esdras", chapter: 12, verse: 33, text: "For he shall set them before him alive in judgment, and shall rebuke them, and correct them." },
  { book: "2 Esdras", chapter: 12, verse: 34, text: "For the rest of my people shall he deliver with mercy, those that have been pressed upon my borders, and he shall make them joyful until the coming of the day of judgment, whereof I have spoken unto thee from the the beginning." },
  { book: "2 Esdras", chapter: 12, verse: 35, text: "This is the dream that thou sawest, and these are the interpretations." },
  { book: "2 Esdras", chapter: 12, verse: 36, text: "Thou only hast been meet to know this secret of the Highest." },
  { book: "2 Esdras", chapter: 12, verse: 37, text: "Therefore write all these things that thou hast seen in a book, and hide them:" },
  { book: "2 Esdras", chapter: 12, verse: 38, text: "And teach them to the wise of the people, whose hearts thou knowest may comprehend and keep these secrets." },
  { book: "2 Esdras", chapter: 12, verse: 39, text: "But wait thou here thyself yet seven days more, that it may be shewed thee, whatsoever it pleaseth the Highest to declare unto thee. And with that he went his way." },
  { book: "2 Esdras", chapter: 12, verse: 40, text: "And it came to pass, when all the people saw that the seven days were past, and I not come again into the city, they gathered them all together, from the least unto the greatest, and came unto me, and said," },
  { book: "2 Esdras", chapter: 12, verse: 41, text: "What have we offended thee? and what evil have we done against thee, that thou forsakest us, and sittest here in this place?" },
  { book: "2 Esdras", chapter: 12, verse: 42, text: "For of all the prophets thou only art left us, as a cluster of the vintage, and as a candle in a dark place, and as a haven or ship preserved from the tempest." },
  { book: "2 Esdras", chapter: 12, verse: 43, text: "Are not the evils which are come to us sufficient?" },
  { book: "2 Esdras", chapter: 12, verse: 44, text: "If thou shalt forsake us, how much better had it been for us, if we also had been burned in the midst of Sion?" },
  { book: "2 Esdras", chapter: 12, verse: 45, text: "For we are not better than they that died there. And they wept with a loud voice. Then answered I them, and said," },
  { book: "2 Esdras", chapter: 12, verse: 46, text: "Be of good comfort, O Israel; and be not heavy, thou house of Jacob:" },
  { book: "2 Esdras", chapter: 12, verse: 47, text: "For the Highest hath you in remembrance, and the Mighty hath not forgotten you in temptation." },
  { book: "2 Esdras", chapter: 12, verse: 48, text: "As for me, I have not forsaken you, neither am I departed from you: but am come into this place, to pray for the desolation of Sion, and that I might seek mercy for the low estate of your sanctuary." },
  { book: "2 Esdras", chapter: 12, verse: 49, text: "And now go your way home every man, and after these days will I come unto you." },
  { book: "2 Esdras", chapter: 12, verse: 50, text: "So the people went their way into the city, like as I commanded them:" },
  { book: "2 Esdras", chapter: 12, verse: 51, text: "But I remained still in the field seven days, as the angel commanded me; and did eat only in those days of the flowers of the field, and had my meat of the herbs" },
  { book: "2 Esdras", chapter: 13, verse: 1, text: "And it came to pass after seven days, I dreamed a dream by night:" },
  { book: "2 Esdras", chapter: 13, verse: 2, text: "And, lo, there arose a wind from the sea, that it moved all the waves thereof." },
  { book: "2 Esdras", chapter: 13, verse: 3, text: "And I beheld, and, lo, that man waxed strong with the thousands of heaven: and when he turned his countenance to look, all the things trembled that were seen under him." },
  { book: "2 Esdras", chapter: 13, verse: 4, text: "And whensoever the voice went out of his mouth, all they burned that heard his voice, like as the earth faileth when it feeleth the fire." },
  { book: "2 Esdras", chapter: 13, verse: 5, text: "And after this I beheld, and, lo, there was gathered together a multitude of men, out of number, from the four winds of the heaven, to subdue the man that came out of the sea" },
  { book: "2 Esdras", chapter: 13, verse: 6, text: "But I beheld, and, lo, he had graved himself a great mountain, and flew up upon it." },
  { book: "2 Esdras", chapter: 13, verse: 7, text: "But I would have seen the region or place whereout the hill was graven, and I could not." },
  { book: "2 Esdras", chapter: 13, verse: 8, text: "And after this I beheld, and, lo, all they which were gathered together to subdue him were sore afraid, and yet durst fight." },
  { book: "2 Esdras", chapter: 13, verse: 9, text: "And, lo, as he saw the violence of the multitude that came, he neither lifted up his hand, nor held sword, nor any instrument of war:" },
  { book: "2 Esdras", chapter: 13, verse: 10, text: "But only I saw that he sent out of his mouth as it had been a blast of fire, and out of his lips a flaming breath, and out of his tongue he cast out sparks and tempests." },
  { book: "2 Esdras", chapter: 13, verse: 11, text: "And they were all mixed together; the blast of fire, the flaming breath, and the great tempest; and fell with violence upon the multitude which was prepared to fight, and burned them up every one, so that upon a sudden of an innumerable multitude nothing was to be perceived, but only dust and smell of smoke: when I saw this I was afraid." },
  { book: "2 Esdras", chapter: 13, verse: 12, text: "Afterward saw I the same man come down from the mountain, and call unto him another peaceable Multitude." },
  { book: "2 Esdras", chapter: 13, verse: 13, text: "And there came much people unto him, whereof some were glad, some were sorry, and some of them were bound, and other some brought of them that were offered: then was I sick through great fear, and I awaked, and said," },
  { book: "2 Esdras", chapter: 13, verse: 14, text: "Thou hast shewed thy servant these wonders from the beginning, and hast counted me worthy that thou shouldest receive my prayer:" },
  { book: "2 Esdras", chapter: 13, verse: 15, text: "Shew me now yet the interpretation of this dream." },
  { book: "2 Esdras", chapter: 13, verse: 16, text: "For as I conceive in mine understanding, woe unto them that shall be left in those days and much more woe unto them that are not left behind!" },
  { book: "2 Esdras", chapter: 13, verse: 17, text: "For they that were not left were in heaviness." },
  { book: "2 Esdras", chapter: 13, verse: 18, text: "Now understand I the things that are laid up in the latter days, which shall happen unto them, and to those that are left behind." },
  { book: "2 Esdras", chapter: 13, verse: 19, text: "Therefore are they come into great perils and many necessities, like as these dreams declare." },
  { book: "2 Esdras", chapter: 13, verse: 20, text: "Yet is it easier for him that is in danger to come into these things, than to pass away as a cloud out of the world, and not to see the things that happen in the last days. And he answered unto me, and said," },
  { book: "2 Esdras", chapter: 13, verse: 21, text: "The interpretation of the vision shall I shew thee, and I will open unto thee the thing that thou hast required." },
  { book: "2 Esdras", chapter: 13, verse: 22, text: "Whereas thou hast spoken of them that are left behind, this is the interpretation:" },
  { book: "2 Esdras", chapter: 13, verse: 23, text: "He that shall endure the peril in that time hath kept himself: they that be fallen into danger are such as have works, and faith toward the Almighty." },
  { book: "2 Esdras", chapter: 13, verse: 24, text: "Know this therefore, that they which be left behind are more blessed than they that be dead." },
  { book: "2 Esdras", chapter: 13, verse: 25, text: "This is the meaning of the vision: Whereas thou sawest a man coming up from the midst of the sea:" },
  { book: "2 Esdras", chapter: 13, verse: 26, text: "The same is he whom God the Highest hath kept a great season, which by his own self shall deliver his creature: and he shall order them that are left behind." },
  { book: "2 Esdras", chapter: 13, verse: 27, text: "And whereas thou sawest, that out of his mouth there came as a blast of wind, and fire, and storm;" },
  { book: "2 Esdras", chapter: 13, verse: 28, text: "And that he held neither sword, nor any instrument of war, but that the rushing in of him destroyed the whole multitude that came to subdue him; this is the interpretation:" },
  { book: "2 Esdras", chapter: 13, verse: 29, text: "Behold, the days come, when the most High will begin to deliver them that are upon the earth." },
  { book: "2 Esdras", chapter: 13, verse: 30, text: "And he shall come to the astonishment of them that dwell on the earth." },
  { book: "2 Esdras", chapter: 13, verse: 31, text: "And one shall undertake to fight against another, one city against another, one place against another, one people against another, and one realm against another." },
  { book: "2 Esdras", chapter: 13, verse: 32, text: "And the time shall be when these things shall come to pass, and the signs shall happen which I shewed thee before, and then shall my Son be declared, whom thou sawest as a man ascending." },
  { book: "2 Esdras", chapter: 13, verse: 33, text: "And when all the people hear his voice, every man shall in their own land leave the battle they have one against another." },
  { book: "2 Esdras", chapter: 13, verse: 34, text: "And an innumerable multitude shall be gathered together, as thou sawest them, willing to come, and to overcome him by fighting." },
  { book: "2 Esdras", chapter: 13, verse: 35, text: "But he shall stand upon the top of the mount Sion." },
  { book: "2 Esdras", chapter: 13, verse: 36, text: "And Sion shall come, and shall be shewed to all men, being prepared and builded, like as thou sawest the hill graven without hands." },
  { book: "2 Esdras", chapter: 13, verse: 37, text: "And this my Son shall rebuke the wicked inventions of those nations, which for their wicked life are fallen into the tempest;" },
  { book: "2 Esdras", chapter: 13, verse: 38, text: "And shall lay before them their evil thoughts, and the torments wherewith they shall begin to be tormented, which are like unto a flame: and he shall destroy them without labour by the law which is like unto me." },
  { book: "2 Esdras", chapter: 13, verse: 39, text: "And whereas thou sawest that he gathered another peaceable multitude unto him;" },
  { book: "2 Esdras", chapter: 13, verse: 40, text: "Those are the ten tribes, which were carried away prisoners out of their own land in the time of Osea the king, whom Salmanasar the king of Assyria led away captive, and he carried them over the waters, and so came they into another land." },
  { book: "2 Esdras", chapter: 13, verse: 41, text: "But they took this counsel among themselves, that they would leave the multitude of the heathen, and go forth into a further country, where never mankind dwelt," },
  { book: "2 Esdras", chapter: 13, verse: 42, text: "That they might there keep their statutes, which they never kept in their own land." },
  { book: "2 Esdras", chapter: 13, verse: 43, text: "And they entered into Euphrates by the narrow places of the river." },
  { book: "2 Esdras", chapter: 13, verse: 44, text: "For the most High then shewed signs for them, and held still the flood, till they were passed over." },
  { book: "2 Esdras", chapter: 13, verse: 45, text: "For through that country there was a great way to go, namely, of a year and a half: and the same region is called Arsareth." },
  { book: "2 Esdras", chapter: 13, verse: 46, text: "Then dwelt they there until the latter time; and now when they shall begin to come," },
  { book: "2 Esdras", chapter: 13, verse: 47, text: "The Highest shall stay the springs of the stream again, that they may go through: therefore sawest thou the multitude with peace." },
  { book: "2 Esdras", chapter: 13, verse: 48, text: "But those that be left behind of thy people are they that are found within my borders." },
  { book: "2 Esdras", chapter: 13, verse: 49, text: "Now when he destroyeth the multitude of the nations that are gathered together, he shall defend his people that remain." },
  { book: "2 Esdras", chapter: 13, verse: 50, text: "And then shall he shew them great wonders." },
  { book: "2 Esdras", chapter: 13, verse: 51, text: "Then said I, O Lord that bearest rule, shew me this: Wherefore have I seen the man coming up from the midst of the sea?" },
  { book: "2 Esdras", chapter: 13, verse: 52, text: "And he said unto me, Like as thou canst neither seek out nor know the things that are in the deep of the sea: even so can no man upon earth see my Son, or those that be with him, but in the day time." },
  { book: "2 Esdras", chapter: 13, verse: 53, text: "This is the interpretation of the dream which thou sawest, and whereby thou only art here lightened." },
  { book: "2 Esdras", chapter: 13, verse: 54, text: "For thou hast forsaken thine own way, and applied thy diligence unto my law, and sought it." },
  { book: "2 Esdras", chapter: 13, verse: 55, text: "Thy life hast thou ordered in wisdom, and hast called understanding thy mother." },
  { book: "2 Esdras", chapter: 13, verse: 56, text: "And therefore have I shewed thee the treasures of the Highest: after other three days I will speak other things unto thee, and declare unto thee mighty and wondrous things." },
  { book: "2 Esdras", chapter: 13, verse: 57, text: "Then went I forth into the field, giving praise and thanks greatly unto the most High because of his wonders which he did in time;" },
  { book: "2 Esdras", chapter: 13, verse: 58, text: "And because he governeth the same, and such things as fall in their seasons: and there I sat three days." },
  { book: "2 Esdras", chapter: 14, verse: 1, text: "And it came to pass upon the third day, I sat under an oak, and, behold, there came a voice out of a bush over against me, and said, Esdras, Esdras." },
  { book: "2 Esdras", chapter: 14, verse: 2, text: "And I said, Here am I, Lord And I stood up upon my feet." },
  { book: "2 Esdras", chapter: 14, verse: 3, text: "Then said he unto me, In the bush I did manifestly reveal myself unto Moses, and talked with him, when my people served in Egypt:" },
  { book: "2 Esdras", chapter: 14, verse: 4, text: "And I sent him and led my people out of Egypt, and brought him up to the mount of where I held him by me a long season," },
  { book: "2 Esdras", chapter: 14, verse: 5, text: "And told him many wondrous things, and shewed him the secrets of the times, and the end; and commanded him, saying," },
  { book: "2 Esdras", chapter: 14, verse: 6, text: "These words shalt thou declare, and these shalt thou hide." },
  { book: "2 Esdras", chapter: 14, verse: 7, text: "And now I say unto thee," },
  { book: "2 Esdras", chapter: 14, verse: 8, text: "That thou lay up in thy heart the signs that I have shewed, and the dreams that thou hast seen, and the interpretations which thou hast heard:" },
  { book: "2 Esdras", chapter: 14, verse: 9, text: "For thou shalt be taken away from all, and from henceforth thou shalt remain with my Son, and with such as be like thee, until the times be ended." },
  { book: "2 Esdras", chapter: 14, verse: 10, text: "For the world hath lost his youth, and the times begin to wax old." },
  { book: "2 Esdras", chapter: 14, verse: 11, text: "For the world is divided into twelve parts, and the ten parts of it are gone already, and half of a tenth part:" },
  { book: "2 Esdras", chapter: 14, verse: 12, text: "And there remaineth that which is after the half of the tenth part." },
  { book: "2 Esdras", chapter: 14, verse: 13, text: "Now therefore set thine house in order, and reprove thy people, comfort such of them as be in trouble, and now renounce corruption," },
  { book: "2 Esdras", chapter: 14, verse: 14, text: "Let go from thee mortal thoughts, cast away the burdens of man, put off now the weak nature," },
  { book: "2 Esdras", chapter: 14, verse: 15, text: "And set aside the thoughts that are most heavy unto thee, and haste thee to flee from these times." },
  { book: "2 Esdras", chapter: 14, verse: 16, text: "For yet greater evils than those which thou hast seen happen shall be done hereafter." },
  { book: "2 Esdras", chapter: 14, verse: 17, text: "For look how much the world shall be weaker through age, so much the more shall evils increase upon them that dwell therein." },
  { book: "2 Esdras", chapter: 14, verse: 18, text: "For the time is fled far away, and leasing is hard at hand: for now hasteth the vision to come, which thou hast seen." },
  { book: "2 Esdras", chapter: 14, verse: 19, text: "Then answered I before thee, and said," },
  { book: "2 Esdras", chapter: 14, verse: 20, text: "Behold, Lord, I will go, as thou hast commanded me, and reprove the people which are present: but they that shall be born afterward, who shall admonish them? thus the world is set in darkness, and they that dwell therein are without light." },
  { book: "2 Esdras", chapter: 14, verse: 21, text: "For thy law is burnt, therefore no man knoweth the things that are done of thee, or the work that shall begin." },
  { book: "2 Esdras", chapter: 14, verse: 22, text: "But if I have found grace before thee, send the Holy Ghost into me, and I shall write all that hath been done in the world since the beginning, which were written in thy law, that men may find thy path, and that they which will live in the latter days may live." },
  { book: "2 Esdras", chapter: 14, verse: 23, text: "And he answered me, saying, Go thy way, gather the people together, and say unto them, that they seek thee not for forty days." },
  { book: "2 Esdras", chapter: 14, verse: 24, text: "But look thou prepare thee many box trees, and take with thee Sarea, Dabria, Selemia, Ecanus, and Asiel, these five which are ready to write swiftly;" },
  { book: "2 Esdras", chapter: 14, verse: 25, text: "And come hither, and I shall light a candle of understanding in thine heart, which shall not be put out, till the things be performed which thou shalt begin to write." },
  { book: "2 Esdras", chapter: 14, verse: 26, text: "And when thou hast done, some things shalt thou publish, and some things shalt thou shew secretly to the wise: to morrow this hour shalt thou begin to write." },
  { book: "2 Esdras", chapter: 14, verse: 27, text: "Then went I forth, as he commanded, and gathered all the people together, and said," },
  { book: "2 Esdras", chapter: 14, verse: 28, text: "Hear these words, O Israel." },
  { book: "2 Esdras", chapter: 14, verse: 29, text: "Our fathers at the beginning were strangers in Egypt, from whence they were delivered:" },
  { book: "2 Esdras", chapter: 14, verse: 30, text: "And received the law of life, which they kept not, which ye also have transgressed after them." },
  { book: "2 Esdras", chapter: 14, verse: 31, text: "Then was the land, even the land of Sion, parted among you by lot: but your fathers, and ye yourselves, have done unrighteousness, and have not kept the ways which the Highest commanded you." },
  { book: "2 Esdras", chapter: 14, verse: 32, text: "And forasmuch as he is a righteous judge, he took from you in time the thing that he had given you." },
  { book: "2 Esdras", chapter: 14, verse: 33, text: "And now are ye here, and your brethren among you." },
  { book: "2 Esdras", chapter: 14, verse: 34, text: "Therefore if so be that ye will subdue your own understanding, and reform your hearts, ye shall be kept alive and after death ye shall obtain mercy." },
  { book: "2 Esdras", chapter: 14, verse: 35, text: "For after death shall the judgment come, when we shall live again: and then shall the names of the righteous be manifest, and the works of the ungodly shall be declared." },
  { book: "2 Esdras", chapter: 14, verse: 36, text: "Let no man therefore come unto me now, nor seek after me these forty days." },
  { book: "2 Esdras", chapter: 14, verse: 37, text: "So I took the five men, as he commanded me, and we went into the field, and remained there." },
  { book: "2 Esdras", chapter: 14, verse: 38, text: "And the next day, behold, a voice called me, saying, Esdras, open thy mouth, and drink that I give thee to drink." },
  { book: "2 Esdras", chapter: 14, verse: 39, text: "Then opened I my mouth, and, behold, he reached me a full cup, which was full as it were with water, but the colour of it was like fire." },
  { book: "2 Esdras", chapter: 14, verse: 40, text: "And I took it, and drank: and when I had drunk of it, my heart uttered understanding, and wisdom grew in my breast, for my spirit strengthened my memory:" },
  { book: "2 Esdras", chapter: 14, verse: 41, text: "And my mouth was opened, and shut no more." },
  { book: "2 Esdras", chapter: 14, verse: 42, text: "The Highest gave understanding unto the five men, and they wrote the wonderful visions of the night that were told, which they knew not: and they sat forty days, and they wrote in the day, and at night they ate bread." },
  { book: "2 Esdras", chapter: 14, verse: 43, text: "As for me. I spake in the day, and I held not my tongue by night." },
  { book: "2 Esdras", chapter: 14, verse: 44, text: "In forty days they wrote two hundred and four books." },
  { book: "2 Esdras", chapter: 14, verse: 45, text: "And it came to pass, when the forty days were filled, that the Highest spake, saying, The first that thou hast written publish openly, that the worthy and unworthy may read it:" },
  { book: "2 Esdras", chapter: 14, verse: 46, text: "But keep the seventy last, that thou mayest deliver them only to such as be wise among the people:" },
  { book: "2 Esdras", chapter: 14, verse: 47, text: "For in them is the spring of understanding, the fountain of wisdom, and the stream of knowledge." },
  { book: "2 Esdras", chapter: 14, verse: 48, text: "And I did so." },
  { book: "2 Esdras", chapter: 15, verse: 1, text: "Behold, speak thou in the ears of my people the words of prophecy, which I will put in thy mouth, saith the Lord:" },
  { book: "2 Esdras", chapter: 15, verse: 2, text: "And cause them to be written in paper: for they are faithful and true." },
  { book: "2 Esdras", chapter: 15, verse: 3, text: "Fear not the imaginations against thee, let not the incredulity of them trouble thee, that speak against thee." },
  { book: "2 Esdras", chapter: 15, verse: 4, text: "For all the unfaithful shall die in their unfaithfulness." },
  { book: "2 Esdras", chapter: 15, verse: 5, text: "Behold, saith the Lord, I will bring plagues upon the world; the sword, famine, death, and destruction." },
  { book: "2 Esdras", chapter: 15, verse: 6, text: "For wickedness hath exceedingly polluted the whole earth, and their hurtful works are fulfilled." },
  { book: "2 Esdras", chapter: 15, verse: 7, text: "Therefore saith the Lord," },
  { book: "2 Esdras", chapter: 15, verse: 8, text: "I will hold my tongue no more as touching their wickedness, which they profanely commit, neither will I suffer them in those things, in which they wickedly exercise themselves: behold, the innocent and righteous blood crieth unto me, and the souls of the just complain continually." },
  { book: "2 Esdras", chapter: 15, verse: 9, text: "And therefore, saith the Lord, I will surely avenge them, and receive unto me all the innocent blood from among them." },
  { book: "2 Esdras", chapter: 15, verse: 10, text: "Behold, my people is led as a flock to the slaughter: I will not suffer them now to dwell in the land of Egypt:" },
  { book: "2 Esdras", chapter: 15, verse: 11, text: "But I will bring them with a mighty hand and a stretched out arm, and smite Egypt with plagues, as before, and will destroy all the land thereof." },
  { book: "2 Esdras", chapter: 15, verse: 12, text: "Egypt shall mourn, and the foundation of it shall be smitten with the plague and punishment that God shall bring upon it." },
  { book: "2 Esdras", chapter: 15, verse: 13, text: "They that till the ground shall mourn: for their seeds shall fail through the blasting and hail, and with a fearful constellation." },
  { book: "2 Esdras", chapter: 15, verse: 14, text: "Woe to the world and them that dwell therein!" },
  { book: "2 Esdras", chapter: 15, verse: 15, text: "For the sword and their destruction draweth nigh, and one people shall stand up and fight against another, and swords in their hands." },
  { book: "2 Esdras", chapter: 15, verse: 16, text: "For there shall be sedition among men, and invading one another; they shall not regard their kings nor princes, and the course of their actions shall stand in their power." },
  { book: "2 Esdras", chapter: 15, verse: 17, text: "A man shall desire to go into a city, and shall not be able." },
  { book: "2 Esdras", chapter: 15, verse: 18, text: "For because of their pride the cities shall be troubled, the houses shall be destroyed, and men shall be afraid." },
  { book: "2 Esdras", chapter: 15, verse: 19, text: "A man shall have no pity upon his neighbour, but shall destroy their houses with the sword, and spoil their goods, because of the lack of bread, and for great tribulation." },
  { book: "2 Esdras", chapter: 15, verse: 20, text: "Behold, saith God, I will call together all the kings of the earth to reverence me, which are from the rising of the sun, from the south, from the east, and Libanus; to turn themselves one against another, and repay the things that they have done to them." },
  { book: "2 Esdras", chapter: 15, verse: 21, text: "Like as they do yet this day unto my chosen, so will I do also, and recompense in their bosom. Thus saith the Lord God;" },
  { book: "2 Esdras", chapter: 15, verse: 22, text: "My right hand shall not spare the sinners, and my sword shall not cease over them that shed innocent blood upon the earth." },
  { book: "2 Esdras", chapter: 15, verse: 23, text: "The fire is gone forth from his wrath, and hath consumed the foundations of the earth, and the sinners, like the straw that is kindled." },
  { book: "2 Esdras", chapter: 15, verse: 24, text: "Woe to them that sin, and keep not my commandments! saith the Lord." },
  { book: "2 Esdras", chapter: 15, verse: 25, text: "I will not spare them: go your way, ye children, from the power, defile not my sanctuary." },
  { book: "2 Esdras", chapter: 15, verse: 26, text: "For the Lord knoweth all them that sin against him, and therefore delivereth he them unto death and destruction." },
  { book: "2 Esdras", chapter: 15, verse: 27, text: "For now are the plagues come upon the whole earth and ye shall remain in them: for God shall not deliver you, because ye have sinned against him." },
  { book: "2 Esdras", chapter: 15, verse: 28, text: "Behold an horrible vision, and the appearance thereof from the east:" },
  { book: "2 Esdras", chapter: 15, verse: 29, text: "Where the nations of the dragons of Arabia shall come out with many chariots, and the multitude of them shall be carried as the wind upon earth, that all they which hear them may fear and tremble." },
  { book: "2 Esdras", chapter: 15, verse: 30, text: "Also the Carmanians raging in wrath shall go forth as the wild boars of the wood, and with great power shall they come, and join battle with them, and shall waste a portion of the land of the Assyrians." },
  { book: "2 Esdras", chapter: 15, verse: 31, text: "And then shall the dragons have the upper hand, remembering their nature; and if they shall turn themselves, conspiring together in great power to persecute them," },
  { book: "2 Esdras", chapter: 15, verse: 32, text: "Then these shall be troubled bled, and keep silence through their power, and shall flee." },
  { book: "2 Esdras", chapter: 15, verse: 33, text: "And from the land of the Assyrians shall the enemy besiege them, and consume some of them, and in their host shall be fear and dread, and strife among their kings." },
  { book: "2 Esdras", chapter: 15, verse: 34, text: "Behold clouds from the east and from the north unto the south, and they are very horrible to look upon, full of wrath and storm." },
  { book: "2 Esdras", chapter: 15, verse: 35, text: "They shall smite one upon another, and they shall smite down a great multitude of stars upon the earth, even their own star; and blood shall be from the sword unto the belly," },
  { book: "2 Esdras", chapter: 15, verse: 36, text: "And dung of men unto the camel’s hough." },
  { book: "2 Esdras", chapter: 15, verse: 37, text: "And there shall be great fearfulness and trembling upon earth: and they that see the wrath shall be afraid, and trembling shall come upon them." },
  { book: "2 Esdras", chapter: 15, verse: 38, text: "And then shall there come great storms from the south, and from the north, and another part from the west." },
  { book: "2 Esdras", chapter: 15, verse: 39, text: "And strong winds shall arise from the east, and shall open it; and the cloud which he raised up in wrath, and the star stirred to cause fear toward the east and west wind, shall be destroyed." },
  { book: "2 Esdras", chapter: 15, verse: 40, text: "The great and mighty clouds shall be puffed up full of wrath, and the star, that they may make all the earth afraid, and them that dwell therein; and they shall pour out over every high and eminent place an horrible star," },
  { book: "2 Esdras", chapter: 15, verse: 41, text: "Fire, and hail, and flying swords, and many waters, that all fields may be full, and all rivers, with the abundance of great waters." },
  { book: "2 Esdras", chapter: 15, verse: 42, text: "And they shall break down the cities and walls, mountains and hills, trees of the wood, and grass of the meadows, and their corn." },
  { book: "2 Esdras", chapter: 15, verse: 43, text: "And they shall go stedfastly unto Babylon, and make her afraid." },
  { book: "2 Esdras", chapter: 15, verse: 44, text: "They shall come to her, and besiege her, the star and all wrath shall they pour out upon her: then shall the dust and smoke go up unto the heaven, and all they that be about her shall bewail her." },
  { book: "2 Esdras", chapter: 15, verse: 45, text: "And they that remain under her shall do service unto them that have put her in fear." },
  { book: "2 Esdras", chapter: 15, verse: 46, text: "And thou, Asia, that art partaker of the hope of Babylon, and art the glory of her person:" },
  { book: "2 Esdras", chapter: 15, verse: 47, text: "Woe be unto thee, thou wretch, because thou hast made thyself like unto her; and hast decked thy daughters in whoredom, that they might please and glory in thy lovers, which have always desired to commit whoredom with thee." },
  { book: "2 Esdras", chapter: 15, verse: 48, text: "Thou hast followed her that is hated in all her works and inventions: therefore saith God," },
  { book: "2 Esdras", chapter: 15, verse: 49, text: "I will send plagues upon thee; widowhood, poverty, famine, sword, and pestilence, to waste thy houses with destruction and death." },
  { book: "2 Esdras", chapter: 15, verse: 50, text: "And the glory of thy Power shall be dried up as a flower, the heat shall arise that is sent over thee." },
  { book: "2 Esdras", chapter: 15, verse: 51, text: "Thou shalt be weakened as a poor woman with stripes, and as one chastised with wounds, so that the mighty and lovers shall not be able to receive thee." },
  { book: "2 Esdras", chapter: 15, verse: 52, text: "Would I with jealousy have so proceeded against thee, saith the Lord," },
  { book: "2 Esdras", chapter: 15, verse: 53, text: "If thou hadst not always slain my chosen, exalting the stroke of thine hands, and saying over their dead, when thou wast drunken," },
  { book: "2 Esdras", chapter: 15, verse: 54, text: "Set forth the beauty of thy countenance?" },
  { book: "2 Esdras", chapter: 15, verse: 55, text: "The reward of thy whoredom shall be in thy bosom, therefore shalt thou receive recompence." },
  { book: "2 Esdras", chapter: 15, verse: 56, text: "Like as thou hast done unto my chosen, saith the Lord, even so shall God do unto thee, and shall deliver thee into mischief" },
  { book: "2 Esdras", chapter: 15, verse: 57, text: "Thy children shall die of hunger, and thou shalt fall through the sword: thy cities shall be broken down, and all thine shall perish with the sword in the field." },
  { book: "2 Esdras", chapter: 15, verse: 58, text: "They that be in the mountains shall die of hunger, and eat their own flesh, and drink their own blood, for very hunger of bread, and thirst of water." },
  { book: "2 Esdras", chapter: 15, verse: 59, text: "Thou as unhappy shalt come through the sea, and receive plagues again." },
  { book: "2 Esdras", chapter: 15, verse: 60, text: "And in the passage they shall rush on the idle city, and shall destroy some portion of thy land, and consume part of thy glory, and shall return to Babylon that was destroyed." },
  { book: "2 Esdras", chapter: 15, verse: 61, text: "And thou shalt be cast down by them as stubble, and they shall be unto thee as fire;" },
  { book: "2 Esdras", chapter: 15, verse: 62, text: "And shall consume thee, and thy cities, thy land, and thy mountains; all thy woods and thy fruitful trees shall they burn up with fire." },
  { book: "2 Esdras", chapter: 15, verse: 63, text: "Thy children shall they carry away captive, and, look, what thou hast, they shall spoil it, and mar the beauty of thy face." },
  { book: "2 Esdras", chapter: 16, verse: 1, text: "Woe be unto thee, Babylon, and Asia! woe be unto thee, Egypt and Syria!" },
  { book: "2 Esdras", chapter: 16, verse: 2, text: "Gird up yourselves with cloths of sack and hair, bewail your children, and be sorry; for your destruction is at hand." },
  { book: "2 Esdras", chapter: 16, verse: 3, text: "A sword is sent upon you, and who may turn it back?" },
  { book: "2 Esdras", chapter: 16, verse: 4, text: "A fire is sent among you, and who may quench it?" },
  { book: "2 Esdras", chapter: 16, verse: 5, text: "Plagues are sent unto you, and what is he that may drive them away?" },
  { book: "2 Esdras", chapter: 16, verse: 6, text: "May any man drive away an hungry lion in the wood? or may any one quench the fire in stubble, when it hath begun to burn?" },
  { book: "2 Esdras", chapter: 16, verse: 7, text: "May one turn again the arrow that is shot of a strong archer?" },
  { book: "2 Esdras", chapter: 16, verse: 8, text: "The mighty Lord sendeth the plagues and who is he that can drive them away?" },
  { book: "2 Esdras", chapter: 16, verse: 9, text: "A fire shall go forth from his wrath, and who is he that may quench it?" },
  { book: "2 Esdras", chapter: 16, verse: 10, text: "He shall cast lightnings, and who shall not fear? he shall thunder, and who shall not be afraid?" },
  { book: "2 Esdras", chapter: 16, verse: 11, text: "The Lord shall threaten, and who shall not be utterly beaten to powder at his presence?" },
  { book: "2 Esdras", chapter: 16, verse: 12, text: "The earth quaketh, and the foundations thereof; the sea ariseth up with waves from the deep, and the waves of it are troubled, and the fishes thereof also, before the Lord, and before the glory of his power:" },
  { book: "2 Esdras", chapter: 16, verse: 13, text: "For strong is his right hand that bendeth the bow, his arrows that he shooteth are sharp, and shall not miss, when they begin to be shot into the ends of the world." },
  { book: "2 Esdras", chapter: 16, verse: 14, text: "Behold, the plagues are sent, and shall not return again, until they come upon the earth." },
  { book: "2 Esdras", chapter: 16, verse: 15, text: "The fire is kindled, and shall not be put out, till it consume the foundation of the earth." },
  { book: "2 Esdras", chapter: 16, verse: 16, text: "Like as an arrow which is shot of a mighty archer returneth not backward: even so the plagues that shall be sent upon earth shall not return again." },
  { book: "2 Esdras", chapter: 16, verse: 17, text: "Woe is me! woe is me! who will deliver me in those days?" },
  { book: "2 Esdras", chapter: 16, verse: 18, text: "The beginning of sorrows and great mournings; the beginning of famine and great death; the beginning of wars, and the powers shall stand in fear; the beginning of evils! what shall I do when these evils shall come?" },
  { book: "2 Esdras", chapter: 16, verse: 19, text: "Behold, famine and plague, tribulation and anguish, are sent as scourges for amendment." },
  { book: "2 Esdras", chapter: 16, verse: 20, text: "But for all these things they shall not turn from their wickedness, nor be always mindful of the scourges." },
  { book: "2 Esdras", chapter: 16, verse: 21, text: "Behold, victuals shall be so good cheap upon earth, that they shall think themselves to be in good case, and even then shall evils grow upon earth, sword, famine, and great confusion." },
  { book: "2 Esdras", chapter: 16, verse: 22, text: "For many of them that dwell upon earth shall perish of famine; and the other, that escape the hunger, shall the sword destroy." },
  { book: "2 Esdras", chapter: 16, verse: 23, text: "And the dead shall be cast out as dung, and there shall be no man to comfort them: for the earth shall be wasted, and the cities shall be cast down." },
  { book: "2 Esdras", chapter: 16, verse: 24, text: "There shall be no man left to till the earth, and to sow it" },
  { book: "2 Esdras", chapter: 16, verse: 25, text: "The trees shall give fruit, and who shall gather them?" },
  { book: "2 Esdras", chapter: 16, verse: 26, text: "The grapes shall ripen, and who shall tread them? for all places shall be desolate of men:" },
  { book: "2 Esdras", chapter: 16, verse: 27, text: "So that one man shall desire to see another, and to hear his voice." },
  { book: "2 Esdras", chapter: 16, verse: 28, text: "For of a city there shall be ten left, and two of the field, which shall hide themselves in the thick groves, and in the clefts of the rocks." },
  { book: "2 Esdras", chapter: 16, verse: 29, text: "As in an orchard of Olives upon every tree there are left three or four olives;" },
  { book: "2 Esdras", chapter: 16, verse: 30, text: "Or as when a vineyard is gathered, there are left some clusters of them that diligently seek through the vineyard:" },
  { book: "2 Esdras", chapter: 16, verse: 31, text: "Even so in those days there shall be three or four left by them that search their houses with the sword." },
  { book: "2 Esdras", chapter: 16, verse: 32, text: "And the earth shall be laid waste, and the fields thereof shall wax old, and her ways and all her paths shall grow full of thorns, because no man shall travel therethrough." },
  { book: "2 Esdras", chapter: 16, verse: 33, text: "The virgins shall mourn, having no bridegrooms; the women shall mourn, having no husbands; their daughters shall mourn, having no helpers." },
  { book: "2 Esdras", chapter: 16, verse: 34, text: "In the wars shall their bridegrooms be destroyed, and their husbands shall perish of famine." },
  { book: "2 Esdras", chapter: 16, verse: 35, text: "Hear now these things and understand them, ye servants of the Lord." },
  { book: "2 Esdras", chapter: 16, verse: 36, text: "Behold, the word of the Lord, receive it: believe not the gods of whom the Lord spake." },
  { book: "2 Esdras", chapter: 16, verse: 37, text: "Behold, the plagues draw nigh, and are not slack." },
  { book: "2 Esdras", chapter: 16, verse: 38, text: "As when a woman with child in the ninth month bringeth forth her son, with two or three hours of her birth great pains compass her womb, which pains, when the child cometh forth, they slack not a moment:" },
  { book: "2 Esdras", chapter: 16, verse: 39, text: "Even so shall not the plagues be slack to come upon the earth, and the world shall mourn, and sorrows shall come upon it on every side." },
  { book: "2 Esdras", chapter: 16, verse: 40, text: "O my people, hear my word: make you ready to thy battle, and in those evils be even as pilgrims upon the earth." },
  { book: "2 Esdras", chapter: 16, verse: 41, text: "He that selleth, let him be as he that fleeth away: and he that buyeth, as one that will lose:" },
  { book: "2 Esdras", chapter: 16, verse: 42, text: "He that occupieth merchandise, as he that hath no profit by it: and he that buildeth, as he that shall not dwell therein:" },
  { book: "2 Esdras", chapter: 16, verse: 43, text: "He that soweth, as if he should not reap: so also he that planteth the vineyard, as he that shall not gather the grapes:" },
  { book: "2 Esdras", chapter: 16, verse: 44, text: "They that marry, as they that shall get no children; and they that marry not, as the widowers." },
  { book: "2 Esdras", chapter: 16, verse: 45, text: "And therefore they that labour labour in vain:" },
  { book: "2 Esdras", chapter: 16, verse: 46, text: "For strangers shall reap their fruits, and spoil their goods, overthrow their houses, and take their children captives, for in captivity and famine shall they get children." },
  { book: "2 Esdras", chapter: 16, verse: 47, text: "And they that occupy their merchandise with robbery, the more they deck their cities, their houses, their possessions, and their own persons:" },
  { book: "2 Esdras", chapter: 16, verse: 48, text: "The more will I be angry with them for their sin, saith the Lord." },
  { book: "2 Esdras", chapter: 16, verse: 49, text: "Like as a whore envieth a right honest and virtuous woman:" },
  { book: "2 Esdras", chapter: 16, verse: 50, text: "So shall righteousness hate iniquity, when she decketh herself, and shall accuse her to her face, when he cometh that shall defend him that diligently searcheth out every sin upon earth." },
  { book: "2 Esdras", chapter: 16, verse: 51, text: "And therefore be ye not like thereunto, nor to the works thereof." },
  { book: "2 Esdras", chapter: 16, verse: 52, text: "For yet a little, and iniquity shall be taken away out of the earth, and righteousness shall reign among you." },
  { book: "2 Esdras", chapter: 16, verse: 53, text: "Let not the sinner say that he hath not sinned: for God shall burn coals of fire upon his head, which saith before the Lord God and his glory, I have not sinned." },
  { book: "2 Esdras", chapter: 16, verse: 54, text: "Behold, the Lord knoweth all the works of men, their imaginations, their thoughts, and their hearts:" },
  { book: "2 Esdras", chapter: 16, verse: 55, text: "Which spake but the word, Let the earth be made; and it was made: Let the heaven be made; and it was created." },
  { book: "2 Esdras", chapter: 16, verse: 56, text: "In his word were the stars made, and he knoweth the number of them." },
  { book: "2 Esdras", chapter: 16, verse: 57, text: "He searcheth the deep, and the treasures thereof; he hath measured the sea, and what it containeth." },
  { book: "2 Esdras", chapter: 16, verse: 58, text: "He hath shut the sea in the midst of the waters, and with his word hath he hanged the earth upon the waters." },
  { book: "2 Esdras", chapter: 16, verse: 59, text: "He spreadeth out the heavens like a vault; upon the waters hath he founded it." },
  { book: "2 Esdras", chapter: 16, verse: 60, text: "In the desert hath he made springs of water, and pools upon the tops of the mountains, that the floods might pour down from the high rocks to water the earth." },
  { book: "2 Esdras", chapter: 16, verse: 61, text: "He made man, and put his heart in the midst of the body, and gave him breath, life, and understanding." },
  { book: "2 Esdras", chapter: 16, verse: 62, text: "Yea and the Spirit of Almighty God, which made all things, and searcheth out all hidden things in the secrets of the earth," },
  { book: "2 Esdras", chapter: 16, verse: 63, text: "Surely he knoweth your inventions, and what ye think in your hearts, even them that sin, and would hide their sin." },
  { book: "2 Esdras", chapter: 16, verse: 64, text: "Therefore hath the Lord exactly searched out all your works, and he will put you all to shame." },
  { book: "2 Esdras", chapter: 16, verse: 65, text: "And when your sins are brought forth, ye shall be ashamed before men, and your own sins shall be your accusers in that day." },
  { book: "2 Esdras", chapter: 16, verse: 66, text: "What will ye do? or how will ye hide your sins before God and his angels?" },
  { book: "2 Esdras", chapter: 16, verse: 67, text: "Behold, God himself is the judge, fear him: leave off from your sins, and forget your iniquities, to meddle no more with them for ever: so shall God lead you forth, and deliver you from all trouble." },
  { book: "2 Esdras", chapter: 16, verse: 68, text: "For, behold, the burning wrath of a great multitude is kindled over you, and they shall take away certain of you, and feed you, being idle, with things offered unto idols." },
  { book: "2 Esdras", chapter: 16, verse: 69, text: "And they that consent unto them shall be had in derision and in reproach, and trodden under foot." },
  { book: "2 Esdras", chapter: 16, verse: 70, text: "For there shall be in every place, and in the next cities, a great insurrection upon those that fear the Lord." },
  { book: "2 Esdras", chapter: 16, verse: 71, text: "They shall be like mad men, sparing none, but still spoiling and destroying those that fear the Lord." },
  { book: "2 Esdras", chapter: 16, verse: 72, text: "For they shall waste and take away their goods, and cast them out of their houses." },
  { book: "2 Esdras", chapter: 16, verse: 73, text: "Then shall they be known, who are my chosen; and they shall be tried as the gold in the fire." },
  { book: "2 Esdras", chapter: 16, verse: 74, text: "Hear, O ye my beloved, saith the Lord: behold, the days of trouble are at hand, but I will deliver you from the same." },
  { book: "2 Esdras", chapter: 16, verse: 75, text: "Be ye not afraid neither doubt; for God is your guide," },
  { book: "2 Esdras", chapter: 16, verse: 76, text: "And the guide of them who keep my commandments and precepts, saith the Lord God: let not your sins weigh you down, and let not your iniquities lift up themselves." },
  { book: "2 Esdras", chapter: 16, verse: 77, text: "Woe be unto them that are bound with their sins, and covered with their iniquities like as a field is covered over with bushes, and the path thereof covered with thorns, that no man may travel through!" },
  { book: "2 Esdras", chapter: 16, verse: 78, text: "It is left undressed, and is cast into the fire to be consumed therewith." },
  // 2 Maccabees (555 verses)
  { book: "2 Maccabees", chapter: 1, verse: 1, text: "The brethren, the Jews that be at Jerusalem and in the land of Judea, wish unto the brethren, the Jews that are throughout Egypt health and peace:" },
  { book: "2 Maccabees", chapter: 1, verse: 2, text: "God be gracious unto you, and remember his covenant that he made with Abraham, Isaac, and Jacob, his faithful servants;" },
  { book: "2 Maccabees", chapter: 1, verse: 3, text: "And give you all an heart to serve him, and to do his will, with a good courage and a willing mind;" },
  { book: "2 Maccabees", chapter: 1, verse: 4, text: "And open your hearts in his law and commandments, and send you peace," },
  { book: "2 Maccabees", chapter: 1, verse: 5, text: "And hear your prayers, and be at one with you, and never forsake you in time of trouble." },
  { book: "2 Maccabees", chapter: 1, verse: 6, text: "And now we be here praying for you." },
  { book: "2 Maccabees", chapter: 1, verse: 7, text: "What time as Demetrius reigned, in the hundred threescore and ninth year, we the Jews wrote unto you in the extremity of trouble that came upon us in those years, from the time that Jason and his company revolted from the holy land and kingdom," },
  { book: "2 Maccabees", chapter: 1, verse: 8, text: "And burned the porch, and shed innocent blood: then we prayed unto the Lord, and were heard; we offered also sacrifices and fine flour, and lighted the lamps, and set forth the loaves." },
  { book: "2 Maccabees", chapter: 1, verse: 9, text: "And now see that ye keep the feast of tabernacles in the month Casleu." },
  { book: "2 Maccabees", chapter: 1, verse: 10, text: "In the hundred fourscore and eighth year, the people that were at Jerusalem and in Judea, and the council, and Judas, sent greeting and health unto Aristobulus, king Ptolemeus’ master, who was of the stock of the anointed priests, and to the Jews that were in Egypt:" },
  { book: "2 Maccabees", chapter: 1, verse: 11, text: "Insomuch as God hath delivered us from great perils, we thank him highly, as having been in battle against a king." },
  { book: "2 Maccabees", chapter: 1, verse: 12, text: "For he cast them out that fought within the holy city." },
  { book: "2 Maccabees", chapter: 1, verse: 13, text: "For when the leader was come into Persia, and the army with him that seemed invincible, they were slain in the temple of Nanea by the deceit of Nanea’s priests." },
  { book: "2 Maccabees", chapter: 1, verse: 14, text: "For Antiochus, as though he would marry her, came into the place, and his friends that were with him, to receive money in name of a dowry." },
  { book: "2 Maccabees", chapter: 1, verse: 15, text: "Which when the priests of Nanea had set forth, and he was entered with a small company into the compass of the temple, they shut the temple as soon as Antiochus was come in:" },
  { book: "2 Maccabees", chapter: 1, verse: 16, text: "And opening a privy door of the roof, they threw stones like thunderbolts, and struck down the captain, hewed them in pieces, smote off their heads and cast them to those that were without." },
  { book: "2 Maccabees", chapter: 1, verse: 17, text: "Blessed be our God in all things, who hath delivered up the ungodly." },
  { book: "2 Maccabees", chapter: 1, verse: 18, text: "Therefore whereas we are now purposed to keep the purification of the temple upon the five and twentieth day of the month Casleu, we thought it necessary to certify you thereof, that ye also might keep it, as the feast of the tabernacles, and of the fire, which was given us when Neemias offered sacrifice, after that he had builded the temple and the altar." },
  { book: "2 Maccabees", chapter: 1, verse: 19, text: "For when our fathers were led into Persia, the priests that were then devout took the fire of the altar privily, and hid it in an hollow place of a pit without water, where they kept it sure, so that the place was unknown to all men." },
  { book: "2 Maccabees", chapter: 1, verse: 20, text: "Now after many years, when it pleased God, Neemias, being sent from the king of Persia, did send of the posterity of those priests that had hid it to the fire: but when they told us they found no fire, but thick water;" },
  { book: "2 Maccabees", chapter: 1, verse: 21, text: "Then commanded he them to draw it up, and to bring it; and when the sacrifices were laid on, Neemias commanded the priests to sprinkle the wood and the things laid thereupon with the water." },
  { book: "2 Maccabees", chapter: 1, verse: 22, text: "When this was done, and the time came that the sun shone, which afore was hid in the cloud, there was a great fire kindled, so that every man marvelled." },
  { book: "2 Maccabees", chapter: 1, verse: 23, text: "And the priests made a prayer whilst the sacrifice was consuming, I say, both the priests, and all the rest, Jonathan beginning, and the rest answering thereunto, as Neemias did." },
  { book: "2 Maccabees", chapter: 1, verse: 24, text: "And the prayer was after this manner; O Lord, Lord God, Creator of all things, who art fearful and strong, and righteous, and merciful, and the only and gracious King," },
  { book: "2 Maccabees", chapter: 1, verse: 25, text: "The only giver of all things, the only just, almighty, and everlasting, thou that deliverest Israel from all trouble, and didst choose the fathers, and sanctify them:" },
  { book: "2 Maccabees", chapter: 1, verse: 26, text: "Receive the sacrifice for thy whole people Israel, and preserve thine own portion, and sanctify it." },
  { book: "2 Maccabees", chapter: 1, verse: 27, text: "Gather those together that are scattered from us, deliver them that serve among the heathen, look upon them that are despised and abhorred, and let the heathen know that thou art our God." },
  { book: "2 Maccabees", chapter: 1, verse: 28, text: "Punish them that oppress us, and with pride do us wrong." },
  { book: "2 Maccabees", chapter: 1, verse: 29, text: "Plant thy people again in thy holy place, as Moses hath spoken." },
  { book: "2 Maccabees", chapter: 1, verse: 30, text: "And the priests sung psalms of thanksgiving." },
  { book: "2 Maccabees", chapter: 1, verse: 31, text: "Now when the sacrifice was consumed, Neemias commanded the water that was left to be poured on the great stones." },
  { book: "2 Maccabees", chapter: 1, verse: 32, text: "When this was done, there was kindled a flame: but it was consumed by the light that shined from the altar." },
  { book: "2 Maccabees", chapter: 1, verse: 33, text: "So when this matter was known, it was told the king of Persia, that in the place, where the priests that were led away had hid the fire, there appeared water, and that Neemias had purified the sacrifices therewith." },
  { book: "2 Maccabees", chapter: 1, verse: 34, text: "Then the king, inclosing the place, made it holy, after he had tried the matter." },
  { book: "2 Maccabees", chapter: 1, verse: 35, text: "And the king took many gifts, and bestowed thereof on those whom he would gratify." },
  { book: "2 Maccabees", chapter: 1, verse: 36, text: "And Neemias called this thing Naphthar, which is as much as to say, a cleansing: but many men call it Nephi." },
  { book: "2 Maccabees", chapter: 2, verse: 1, text: "It is also found in the records, that Jeremy the prophet commanded them that were carried away to take of the fire, as it hath been signified:" },
  { book: "2 Maccabees", chapter: 2, verse: 2, text: "And how that the prophet, having given them the law, charged them not to forget the commandments of the Lord, and that they should not err in their minds, when they see images of silver and gold, with their ornaments." },
  { book: "2 Maccabees", chapter: 2, verse: 3, text: "And with other such speeches exhorted he them, that the law should not depart from their hearts." },
  { book: "2 Maccabees", chapter: 2, verse: 4, text: "It was also contained in the same writing, that the prophet, being warned of God, commanded the tabernacle and the ark to go with him, as he went forth into the mountain, where Moses climbed up, and saw the heritage of God." },
  { book: "2 Maccabees", chapter: 2, verse: 5, text: "And when Jeremy came thither, he found an hollow cave, wherein he laid the tabernacle, and the ark, and the altar of incense, and so stopped the door." },
  { book: "2 Maccabees", chapter: 2, verse: 6, text: "And some of those that followed him came to mark the way, but they could not find it." },
  { book: "2 Maccabees", chapter: 2, verse: 7, text: "Which when Jeremy perceived, he blamed them, saying, As for that place, it shall be unknown until the time that God gather his people again together, and receive them unto mercy." },
  { book: "2 Maccabees", chapter: 2, verse: 8, text: "Then shall the Lord shew them these things, and the glory of the Lord shall appear, and the cloud also, as it was shewed under Moses, and as when Solomon desired that the place might be honourably sanctified." },
  { book: "2 Maccabees", chapter: 2, verse: 9, text: "It was also declared, that he being wise offered the sacrifice of dedication, and of the finishing of the temple." },
  { book: "2 Maccabees", chapter: 2, verse: 10, text: "And as when Moses prayed unto the Lord, the fire came down from heaven, and consumed the sacrifices: even so prayed Solomon also, and the fire came down from heaven, and consumed the burnt offerings." },
  { book: "2 Maccabees", chapter: 2, verse: 11, text: "And Moses said, Because the sin offering was not to be eaten, it was consumed." },
  { book: "2 Maccabees", chapter: 2, verse: 12, text: "So Solomon kept those eight days." },
  { book: "2 Maccabees", chapter: 2, verse: 13, text: "The same things also were reported in the writings and commentaries of Neemias; and how he founding a library gathered together the acts of the kings, and the prophets, and of David, and the epistles of the kings concerning the holy gifts." },
  { book: "2 Maccabees", chapter: 2, verse: 14, text: "In like manner also Judas gathered together all those things that were lost by reason of the war we had, and they remain with us," },
  { book: "2 Maccabees", chapter: 2, verse: 15, text: "Wherefore if ye have need thereof, send some to fetch them unto you." },
  { book: "2 Maccabees", chapter: 2, verse: 16, text: "Whereas we then are about to celebrate the purification, we have written unto you, and ye shall do well, if ye keep the same days." },
  { book: "2 Maccabees", chapter: 2, verse: 17, text: "We hope also, that the God, that delivered all his people, and gave them all an heritage, and the kingdom, and the priesthood, and the sanctuary," },
  { book: "2 Maccabees", chapter: 2, verse: 18, text: "As he promised in the law, will shortly have mercy upon us, and gather us together out of every land under heaven into the holy place: for he hath delivered us out of great troubles, and hath purified the place." },
  { book: "2 Maccabees", chapter: 2, verse: 19, text: "Now as concerning Judas Maccabeus, and his brethren, and the purification of the great temple, and the dedication of the altar," },
  { book: "2 Maccabees", chapter: 2, verse: 20, text: "And the wars against Antiochus Epiphanes, and Eupator his son," },
  { book: "2 Maccabees", chapter: 2, verse: 21, text: "And the manifest signs that came from heaven unto those that behaved themselves manfully to their honour for Judaism: so that, being but a few, they overcame the whole country, and chased barbarous multitudes," },
  { book: "2 Maccabees", chapter: 2, verse: 22, text: "And recovered again the temple renowned all the world over, and freed the city, and upheld the laws which were going down, the Lord being gracious unto them with all favour:" },
  { book: "2 Maccabees", chapter: 2, verse: 23, text: "All these things, I say, being declared by Jason of Cyrene in five books, we will assay to abridge in one volume." },
  { book: "2 Maccabees", chapter: 2, verse: 24, text: "For considering the infinite number, and the difficulty which they find that desire to look into the narrations of the story, for the variety of the matter," },
  { book: "2 Maccabees", chapter: 2, verse: 25, text: "We have been careful, that they that will read may have delight, and that they that are desirous to commit to memory might have ease, and that all into whose hands it comes might have profit." },
  { book: "2 Maccabees", chapter: 2, verse: 26, text: "Therefore to us, that have taken upon us this painful labour of abridging, it was not easy, but a matter of sweat and watching;" },
  { book: "2 Maccabees", chapter: 2, verse: 27, text: "Even as it is no ease unto him that prepareth a banquet, and seeketh the benefit of others: yet for the pleasuring of many we will undertake gladly this great pains;" },
  { book: "2 Maccabees", chapter: 2, verse: 28, text: "Leaving to the author the exact handling of every particular, and labouring to follow the rules of an abridgement." },
  { book: "2 Maccabees", chapter: 2, verse: 29, text: "For as the master builder of a new house must care for the whole building; but he that undertaketh to set it out, and paint it, must seek out fit things for the adorning thereof: even so I think it is with us." },
  { book: "2 Maccabees", chapter: 2, verse: 30, text: "To stand upon every point, and go over things at large, and to be curious in particulars, belongeth to the first author of the story:" },
  { book: "2 Maccabees", chapter: 2, verse: 31, text: "But to use brevity, and avoid much labouring of the work, is to be granted to him that will make an abridgment." },
  { book: "2 Maccabees", chapter: 2, verse: 32, text: "Here then will we begin the story: only adding thus much to that which hath been said, that it is a foolish thing to make a long prologue, and to be short in the story itself." },
  { book: "2 Maccabees", chapter: 3, verse: 1, text: "Now when the holy city was inhabited with all peace, and the laws were kept very well, because of the godliness of Onias the high priest, and his hatred of wickedness," },
  { book: "2 Maccabees", chapter: 3, verse: 2, text: "It came to pass that even the kings themselves did honour the place, and magnify the temple with their best gifts;" },
  { book: "2 Maccabees", chapter: 3, verse: 3, text: "Insomuch that Seleucus of Asia of his own revenues bare all the costs belonging to the service of the sacrifices." },
  { book: "2 Maccabees", chapter: 3, verse: 4, text: "But one Simon of the tribe of Benjamin, who was made governor of the temple, fell out with the high priest about disorder in the city." },
  { book: "2 Maccabees", chapter: 3, verse: 5, text: "And when he could not overcome Onias, he gat him to Apollonius the son of Thraseas, who then was governor of Celosyria and Phenice," },
  { book: "2 Maccabees", chapter: 3, verse: 6, text: "And told him that the treasury in Jerusalem was full of infinite sums of money, so that the multitude of their riches, which did not pertain to the account of the sacrifices, was innumerable, and that it was possible to bring all into the king’s hand." },
  { book: "2 Maccabees", chapter: 3, verse: 7, text: "Now when Apollonius came to the king, and had shewed him of the money whereof he was told, the king chose out Heliodorus his treasurer, and sent him with a commandment to bring him the foresaid money." },
  { book: "2 Maccabees", chapter: 3, verse: 8, text: "So forthwith Heliodorus took his journey; under a colour of visiting the cities of Celosyria and Phenice, but indeed to fulfil the king’s purpose." },
  { book: "2 Maccabees", chapter: 3, verse: 9, text: "And when he was come to Jerusalem, and had been courteously received of the high priest of the city, he told him what intelligence was given of the money, and declared wherefore he came, and asked if these things were so indeed." },
  { book: "2 Maccabees", chapter: 3, verse: 10, text: "Then the high priest told him that there was such money laid up for the relief of widows and fatherless children:" },
  { book: "2 Maccabees", chapter: 3, verse: 11, text: "And that some of it belonged to Hircanus son of Tobias, a man of great dignity, and not as that wicked Simon had misinformed: the sum whereof in all was four hundred talents of silver, and two hundred of gold:" },
  { book: "2 Maccabees", chapter: 3, verse: 12, text: "And that it was altogether impossible that such wrongs should be done unto them, that had committed it to the holiness of the place, and to the majesty and inviolable sanctity of the temple, honoured over all the world." },
  { book: "2 Maccabees", chapter: 3, verse: 13, text: "But Heliodorus, because of the king’s commandment given him, said, That in any wise it must be brought into the king’s treasury." },
  { book: "2 Maccabees", chapter: 3, verse: 14, text: "So at the day which he appointed he entered in to order this matter: wherefore there was no small agony throughout the whole city." },
  { book: "2 Maccabees", chapter: 3, verse: 15, text: "But the priests, prostrating themselves before the altar in their priests’ vestments, called unto heaven upon him that made a law concerning things given to he kept, that they should safely be preserved for such as had committed them to be kept." },
  { book: "2 Maccabees", chapter: 3, verse: 16, text: "Then whoso had looked the high priest in the face, it would have wounded his heart: for his countenance and the changing of his colour declared the inward agony of his mind." },
  { book: "2 Maccabees", chapter: 3, verse: 17, text: "For the man was so compassed with fear and horror of the body, that it was manifest to them that looked upon him, what sorrow he had now in his heart." },
  { book: "2 Maccabees", chapter: 3, verse: 18, text: "Others ran flocking out of their houses to the general supplication, because the place was like to come into contempt." },
  { book: "2 Maccabees", chapter: 3, verse: 19, text: "And the women, girt with sackcloth under their breasts, abounded in the streets, and the virgins that were kept in ran, some to the gates, and some to the walls, and others looked out of the windows." },
  { book: "2 Maccabees", chapter: 3, verse: 20, text: "And all, holding their hands toward heaven, made supplication." },
  { book: "2 Maccabees", chapter: 3, verse: 21, text: "Then it would have pitied a man to see the falling down of the multitude of all sorts, and the fear of the high priest being in such an agony." },
  { book: "2 Maccabees", chapter: 3, verse: 22, text: "They then called upon the Almighty Lord to keep the things committed of trust safe and sure for those that had committed them." },
  { book: "2 Maccabees", chapter: 3, verse: 23, text: "Nevertheless Heliodorus executed that which was decreed." },
  { book: "2 Maccabees", chapter: 3, verse: 24, text: "Now as he was there present himself with his guard about the treasury, the Lord of spirits, and the Prince of all power, caused a great apparition, so that all that presumed to come in with him were astonished at the power of God, and fainted, and were sore afraid." },
  { book: "2 Maccabees", chapter: 3, verse: 25, text: "For there appeared unto them an horse with a terrible rider upon him, and adorned with a very fair covering, and he ran fiercely, and smote at Heliodorus with his forefeet, and it seemed that he that sat upon the horse had complete harness of gold." },
  { book: "2 Maccabees", chapter: 3, verse: 26, text: "Moreover two other young men appeared before him, notable in strength, excellent in beauty, and comely in apparel, who stood by him on either side; and scourged him continually, and gave him many sore stripes." },
  { book: "2 Maccabees", chapter: 3, verse: 27, text: "And Heliodorus fell suddenly unto the ground, and was compassed with great darkness: but they that were with him took him up, and put him into a litter." },
  { book: "2 Maccabees", chapter: 3, verse: 28, text: "Thus him, that lately came with a great train and with all his guard into the said treasury, they carried out, being unable to help himself with his weapons: and manifestly they acknowledged the power of God." },
  { book: "2 Maccabees", chapter: 3, verse: 29, text: "For he by the hand of God was cast down, and lay speechless without all hope of life." },
  { book: "2 Maccabees", chapter: 3, verse: 30, text: "But they praised the Lord, that had miraculously honoured his own place: for the temple; which a little afore was full of fear and trouble, when the Almighty Lord appeared, was filled with joy and gladness." },
  { book: "2 Maccabees", chapter: 3, verse: 31, text: "Then straightways certain of Heliodorus’ friends prayed Onias, that he would call upon the most High to grant him his life, who lay ready to give up the ghost." },
  { book: "2 Maccabees", chapter: 3, verse: 32, text: "So the high priest, suspecting lest the king should misconceive that some treachery had been done to Heliodorus by the Jews, offered a sacrifice for the health of the man." },
  { book: "2 Maccabees", chapter: 3, verse: 33, text: "Now as the high priest was making an atonement, the same young men in the same clothing appeared and stood beside Heliodorus, saying, Give Onias the high priest great thanks, insomuch as for his sake the Lord hath granted thee life:" },
  { book: "2 Maccabees", chapter: 3, verse: 34, text: "And seeing that thou hast been scourged from heaven, declare unto all men the mighty power of God. And when they had spoken these words, they appeared no more." },
  { book: "2 Maccabees", chapter: 3, verse: 35, text: "So Heliodorus, after he had offered sacrifice unto the Lord, and made great vows unto him that had saved his life, and saluted Onias, returned with his host to the king." },
  { book: "2 Maccabees", chapter: 3, verse: 36, text: "Then testified he to all men the works of the great God, which he had seen with his eyes." },
  { book: "2 Maccabees", chapter: 3, verse: 37, text: "And when the king Heliodorus, who might be a fit man to be sent yet once again to Jerusalem, he said," },
  { book: "2 Maccabees", chapter: 3, verse: 38, text: "If thou hast any enemy or traitor, send him thither, and thou shalt receive him well scourged, if he escape with his life: for in that place, no doubt; there is an especial power of God." },
  { book: "2 Maccabees", chapter: 3, verse: 39, text: "For he that dwelleth in heaven hath his eye on that place, and defendeth it; and he beateth and destroyeth them that come to hurt it." },
  { book: "2 Maccabees", chapter: 3, verse: 40, text: "And the things concerning Heliodorus, and the keeping of the treasury, fell out on this sort." },
  { book: "2 Maccabees", chapter: 4, verse: 1, text: "This Simon now, of whom we spake afore, having been a betrayer of the money, and of his country, slandered Onias, as if he had terrified Heliodorus, and been the worker of these evils." },
  { book: "2 Maccabees", chapter: 4, verse: 2, text: "Thus was he bold to call him a traitor, that had deserved well of the city, and tendered his own nation, and was so zealous of the laws." },
  { book: "2 Maccabees", chapter: 4, verse: 3, text: "But when their hatred went so far, that by one of Simon’s faction murders were committed," },
  { book: "2 Maccabees", chapter: 4, verse: 4, text: "Onias seeing the danger of this contention, and that Apollonius, as being the governor of Celosyria and Phenice, did rage, and increase Simon’s malice," },
  { book: "2 Maccabees", chapter: 4, verse: 5, text: "He went to the king, not to be an accuser of his countrymen, but seeking the good of all, both publick and private:" },
  { book: "2 Maccabees", chapter: 4, verse: 6, text: "For he saw that it was impossible that the state should continue quiet, and Simon leave his folly, unless the king did look thereunto." },
  { book: "2 Maccabees", chapter: 4, verse: 7, text: "But after the death of Seleucus, when Antiochus, called Epiphanes, took the kingdom, Jason the brother of Onias laboured underhand to be high priest," },
  { book: "2 Maccabees", chapter: 4, verse: 8, text: "Promising unto the king by intercession three hundred and threescore talents of silver, and of another revenue eighty talents:" },
  { book: "2 Maccabees", chapter: 4, verse: 9, text: "Beside this, he promised to assign an hundred and fifty more, if he might have licence to set him up a place for exercise, and for the training up of youth in the fashions of the heathen, and to write them of Jerusalem by the name of Antiochians." },
  { book: "2 Maccabees", chapter: 4, verse: 10, text: "Which when the king had granted, and he had gotten into his hand the rule he forthwith brought his own nation to Greekish fashion." },
  { book: "2 Maccabees", chapter: 4, verse: 11, text: "And the royal privileges granted of special favour to the Jews by the means of John the father of Eupolemus, who went ambassador to Rome for amity and aid, he took away; and putting down the governments which were according to the law, he brought up new customs against the law:" },
  { book: "2 Maccabees", chapter: 4, verse: 12, text: "For he built gladly a place of exercise under the tower itself, and brought the chief young men under his subjection, and made them wear a hat." },
  { book: "2 Maccabees", chapter: 4, verse: 13, text: "Now such was the height of Greek fashions, and increase of heathenish manners, through the exceeding profaneness of Jason, that ungodly wretch, and no high priest;" },
  { book: "2 Maccabees", chapter: 4, verse: 14, text: "That the priests had no courage to serve any more at the altar, but despising the temple, and neglecting the sacrifices, hastened to be partakers of the unlawful allowance in the place of exercise, after the game of Discus called them forth;" },
  { book: "2 Maccabees", chapter: 4, verse: 15, text: "Not setting by the honours of their fathers, but liking the glory of the Grecians best of all." },
  { book: "2 Maccabees", chapter: 4, verse: 16, text: "By reason whereof sore calamity came upon them: for they had them to be their enemies and avengers, whose custom they followed so earnestly, and unto whom they desired to be like in all things." },
  { book: "2 Maccabees", chapter: 4, verse: 17, text: "For it is not a light thing to do wickedly against the laws of God: but the time following shall declare these things." },
  { book: "2 Maccabees", chapter: 4, verse: 18, text: "Now when the game that was used every faith year was kept at Tyrus, the king being present," },
  { book: "2 Maccabees", chapter: 4, verse: 19, text: "This ungracious Jason sent special messengers from Jerusalem, who were Antiochians, to carry three hundred drachms of silver to the sacrifice of Hercules, which even the bearers thereof thought fit not to bestow upon the sacrifice, because it was not convenient, but to be reserved for other charges." },
  { book: "2 Maccabees", chapter: 4, verse: 20, text: "This money then, in regard of the sender, was appointed to Hercules’ sacrifice; but because of the bearers thereof, it was employed to the making of gallies." },
  { book: "2 Maccabees", chapter: 4, verse: 21, text: "Now when Apollonius the son of Menestheus was sent into Egypt for the coronation of king Ptolemeus Philometor, Antiochus, understanding him not to be well affected to his affairs, provided for his own safety: whereupon he came to Joppa, and from thence to Jerusalem:" },
  { book: "2 Maccabees", chapter: 4, verse: 22, text: "Where he was honourably received of Jason, and of the city, and was brought in with torch alight, and with great shoutings: and so afterward went with his host unto Phenice." },
  { book: "2 Maccabees", chapter: 4, verse: 23, text: "Three years afterward Jason sent Menelaus, the aforesaid Simon’s brother, to bear the money unto the king, and to put him in mind of certain necessary matters." },
  { book: "2 Maccabees", chapter: 4, verse: 24, text: "But he being brought to the presence of the king, when he had magnified him for the glorious appearance of his power, got the priesthood to himself, offering more than Jason by three hundred talents of silver." },
  { book: "2 Maccabees", chapter: 4, verse: 25, text: "So he came with the king’s mandate, bringing nothing worthy the high priesthood, but having the fury of a cruel tyrant, and the rage of a savage beast." },
  { book: "2 Maccabees", chapter: 4, verse: 26, text: "Then Jason, who had undermined his own brother, being undermined by another, was compelled to flee into the country of the Ammonites." },
  { book: "2 Maccabees", chapter: 4, verse: 27, text: "So Menelaus got the principality: but as for the money that he had promised unto the king, he took no good order for it, albeit Sostratis the ruler of the castle required it:" },
  { book: "2 Maccabees", chapter: 4, verse: 28, text: "For unto him appertained the gathering of the customs. Wherefore they were both called before the king." },
  { book: "2 Maccabees", chapter: 4, verse: 29, text: "Now Menelaus left his brother Lysimachus in his stead in the priesthood; and Sostratus left Crates, who was governor of the Cyprians." },
  { book: "2 Maccabees", chapter: 4, verse: 30, text: "While those things were in doing, they of Tarsus and Mallos made insurrection, because they were given to the king’s concubine, called Antiochus." },
  { book: "2 Maccabees", chapter: 4, verse: 31, text: "Then came the king in all haste to appease matters, leaving Andronicus, a man in authority, for his deputy." },
  { book: "2 Maccabees", chapter: 4, verse: 32, text: "Now Menelaus, supposing that he had gotten a convenient time, stole certain vessels of gold out of the temple, and gave some of them to Andronicus, and some he sold into Tyrus and the cities round about." },
  { book: "2 Maccabees", chapter: 4, verse: 33, text: "Which when Onias knew of a surety, he reproved him, and withdrew himself into a sanctuary at Daphne, that lieth by Antiochia." },
  { book: "2 Maccabees", chapter: 4, verse: 34, text: "Wherefore Menelaus, taking Andronicus apart, prayed, him to get Onias into his hands; who being persuaded thereunto, and coming to Onias in deceit, gave him his right hand with oaths; and though he were suspected by him, yet persuaded he him to come forth of the sanctuary: whom forthwith he shut up without regard of justice." },
  { book: "2 Maccabees", chapter: 4, verse: 35, text: "For the which cause not only the Jews, but many also of other nations, took great indignation, and were much grieved for the unjust murder of the man." },
  { book: "2 Maccabees", chapter: 4, verse: 36, text: "And when the king was come again from the places about Cilicia, the Jews that were in the city, and certain of the Greeks that abhorred the fact also, complained because Onias was slain without cause." },
  { book: "2 Maccabees", chapter: 4, verse: 37, text: "Therefore Antiochus was heartily sorry, and moved to pity, and wept, because of the sober and modest behaviour of him that was dead." },
  { book: "2 Maccabees", chapter: 4, verse: 38, text: "And being kindled with anger, forthwith he took away Andronicus his purple, and rent off his clothes, and leading him through the whole city unto that very place, where he had committed impiety against Onias, there slew he the cursed murderer. Thus the Lord rewarded him his punishment, as he had deserved." },
  { book: "2 Maccabees", chapter: 4, verse: 39, text: "Now when many sacrileges had been committed in the city by Lysimachus with the consent of Menelaus, and the fruit thereof was spread abroad, the multitude gathered themselves together against Lysimachus, many vessels of gold being already carried away." },
  { book: "2 Maccabees", chapter: 4, verse: 40, text: "Whereupon the common people rising, and being filled with rage, Lysimachus armed about three thousand men, and began first to offer violence; one Auranus being the leader, a man far gone in years, and no less in folly." },
  { book: "2 Maccabees", chapter: 4, verse: 41, text: "They then seeing the attempt of Lysimachus, some of them caught stones, some clubs, others taking handfuls of dust, that was next at hand, cast them all together upon Lysimachus, and those that set upon them." },
  { book: "2 Maccabees", chapter: 4, verse: 42, text: "Thus many of them they wounded, and some they struck to the ground, and all of them they forced to flee: but as for the churchrobber himself, him they killed beside the treasury." },
  { book: "2 Maccabees", chapter: 4, verse: 43, text: "Of these matters therefore there was an accusation laid against Menelaus." },
  { book: "2 Maccabees", chapter: 4, verse: 44, text: "Now when the king came to Tyrus, three men that were sent from the senate pleaded the cause before him:" },
  { book: "2 Maccabees", chapter: 4, verse: 45, text: "But Menelaus, being now convicted, promised Ptolemee the son of Dorymenes to give him much money, if he would pacify the king toward him." },
  { book: "2 Maccabees", chapter: 4, verse: 46, text: "Whereupon Ptolemee taking the king aside into a certain gallery, as it were to take the air, brought him to be of another mind:" },
  { book: "2 Maccabees", chapter: 4, verse: 47, text: "Insomuch that he discharged Menelaus from the accusations, who notwithstanding was cause of all the mischief: and those poor men, who, if they had told their cause, yea, before the Scythians, should have been judged innocent, them he condemned to death." },
  { book: "2 Maccabees", chapter: 4, verse: 48, text: "Thus they that followed the matter for the city, and for the people, and for the holy vessels, did soon suffer unjust punishment." },
  { book: "2 Maccabees", chapter: 4, verse: 49, text: "Wherefore even they of Tyrus, moved with hatred of that wicked deed, caused them to be honourably buried." },
  { book: "2 Maccabees", chapter: 4, verse: 50, text: "And so through the covetousness of them that were of power Menelaus remained still in authority, increasing in malice, and being a great traitor to the citizens." },
  { book: "2 Maccabees", chapter: 5, verse: 1, text: "About the same time Antiochus prepared his second voyage into Egypt:" },
  { book: "2 Maccabees", chapter: 5, verse: 2, text: "And then it happened, that through all the city, for the space almost of forty days, there were seen horsemen running in the air, in cloth of gold, and armed with lances, like a band of soldiers," },
  { book: "2 Maccabees", chapter: 5, verse: 3, text: "And troops of horsemen in array, encountering and running one against another, with shaking of shields, and multitude of pikes, and drawing of swords, and casting of darts, and glittering of golden ornaments, and harness of all sorts." },
  { book: "2 Maccabees", chapter: 5, verse: 4, text: "Wherefore every man prayed that that apparition might turn to good." },
  { book: "2 Maccabees", chapter: 5, verse: 5, text: "Now when there was gone forth a false rumour, as though Antiochus had been dead, Jason took at the least a thousand men, and suddenly made an assault upon the city; and they that were upon the walls being put back, and the city at length taken, Menelaus fled into the castle:" },
  { book: "2 Maccabees", chapter: 5, verse: 6, text: "But Jason slew his own citizens without mercy, not considering that to get the day of them of his own nation would be a most unhappy day for him; but thinking they had been his enemies, and not his countrymen, whom he conquered." },
  { book: "2 Maccabees", chapter: 5, verse: 7, text: "Howbeit for all this he obtained not the principality, but at the last received shame for the reward of his treason, and fled again into the country of the Ammonites." },
  { book: "2 Maccabees", chapter: 5, verse: 8, text: "In the end therefore he had an unhappy return, being accused before Aretas the king of the Arabians, fleeing from city to city, pursued of all men, hated as a forsaker of the laws, and being had in abomination as an open enemy of his country and countrymen, he was cast out into Egypt." },
  { book: "2 Maccabees", chapter: 5, verse: 9, text: "Thus he that had driven many out of their country perished in a strange land, retiring to the Lacedemonians, and thinking there to find succour by reason of his kindred:" },
  { book: "2 Maccabees", chapter: 5, verse: 10, text: "And he that had cast out many unburied had none to mourn for him, nor any solemn funerals at all, nor sepulchre with his fathers." },
  { book: "2 Maccabees", chapter: 5, verse: 11, text: "Now when this that was done came to the king’s car, he thought that Judea had revolted: whereupon removing out of Egypt in a furious mind, he took the city by force of arms," },
  { book: "2 Maccabees", chapter: 5, verse: 12, text: "And commanded his men of war not to spare such as they met, and to slay such as went up upon the houses." },
  { book: "2 Maccabees", chapter: 5, verse: 13, text: "Thus there was killing of young and old, making away of men, women, and children, slaying of virgins and infants." },
  { book: "2 Maccabees", chapter: 5, verse: 14, text: "And there were destroyed within the space of three whole days fourscore thousand, whereof forty thousand were slain in the conflict; and no fewer sold than slain." },
  { book: "2 Maccabees", chapter: 5, verse: 15, text: "Yet was he not content with this, but presumed to go into the most holy temple of all the world; Menelaus, that traitor to the laws, and to his own country, being his guide:" },
  { book: "2 Maccabees", chapter: 5, verse: 16, text: "And taking the holy vessels with polluted hands, and with profane hands pulling down the things that were dedicated by other kings to the augmentation and glory and honour of the place, he gave them away." },
  { book: "2 Maccabees", chapter: 5, verse: 17, text: "And so haughty was Antiochus in mind, that he considered not that the Lord was angry for a while for the sins of them that dwelt in the city, and therefore his eye was not upon the place." },
  { book: "2 Maccabees", chapter: 5, verse: 18, text: "For had they not been formerly wrapped in many sins, this man, as soon as he had come, had forthwith been scourged, and put back from his presumption, as Heliodorus was, whom Seleucus the king sent to view the treasury." },
  { book: "2 Maccabees", chapter: 5, verse: 19, text: "Nevertheless God did not choose the people for the place’s sake, but the place far the people’s sake." },
  { book: "2 Maccabees", chapter: 5, verse: 20, text: "And therefore the place itself, that was partaker with them of the adversity that happened to the nation, did afterward communicate in the benefits sent from the Lord: and as it was forsaken in the wrath of the Almighty, so again, the great Lord being reconciled, it was set up with all glory." },
  { book: "2 Maccabees", chapter: 5, verse: 21, text: "So when Antiochus had carried out of the temple a thousand and eight hundred talents, he departed in all haste unto Antiochia, weening in his pride to make the land navigable, and the sea passable by foot: such was the haughtiness of his mind." },
  { book: "2 Maccabees", chapter: 5, verse: 22, text: "And he left governors to vex the nation: at Jerusalem, Philip, for his country a Phrygian, and for manners more barbarous than he that set him there;" },
  { book: "2 Maccabees", chapter: 5, verse: 23, text: "And at Garizim, Andronicus; and besides, Menelaus, who worse than all the rest bare an heavy hand over the citizens, having a malicious mind against his countrymen the Jews." },
  { book: "2 Maccabees", chapter: 5, verse: 24, text: "He sent also that detestable ringleader Apollonius with an army of two and twenty thousand, commanding him to slay all those that were in their best age, and to sell the women and the younger sort:" },
  { book: "2 Maccabees", chapter: 5, verse: 25, text: "Who coming to Jerusalem, and pretending peace, did forbear till the holy day of the sabbath, when taking the Jews keeping holy day, he commanded his men to arm themselves." },
  { book: "2 Maccabees", chapter: 5, verse: 26, text: "And so he slew all them that were gone to the celebrating of the sabbath, and running through the city with weapons slew great multitudes." },
  { book: "2 Maccabees", chapter: 5, verse: 27, text: "But Judas Maccabeus with nine others, or thereabout, withdrew himself into the wilderness, and lived in the mountains after the manner of beasts, with his company, who fed on herbs continually, lest they should be partakers of the pollution." },
  { book: "2 Maccabees", chapter: 6, verse: 1, text: "Not long after this the king sent an old man of Athens to compel the Jews to depart from the laws of their fathers, and not to live after the laws of God:" },
  { book: "2 Maccabees", chapter: 6, verse: 2, text: "And to pollute also the temple in Jerusalem, and to call it the temple of Jupiter Olympius; and that in Garizim, of Jupiter the Defender of strangers, as they did desire that dwelt in the place." },
  { book: "2 Maccabees", chapter: 6, verse: 3, text: "The coming in of this mischief was sore and grievous to the people:" },
  { book: "2 Maccabees", chapter: 6, verse: 4, text: "For the temple was filled with riot and revelling by the Gentiles, who dallied with harlots, and had to do with women within the circuit of the holy places, and besides that brought in things that were not lawful." },
  { book: "2 Maccabees", chapter: 6, verse: 5, text: "The altar also was filled with profane things, which the law forbiddeth." },
  { book: "2 Maccabees", chapter: 6, verse: 6, text: "Neither was it lawful for a man to keep sabbath days or ancient fasts, or to profess himself at all to be a Jew." },
  { book: "2 Maccabees", chapter: 6, verse: 7, text: "And in the day of the king’s birth every month they were brought by bitter constraint to eat of the sacrifices; and when the fast of Bacchus was kept, the Jews were compelled to go in procession to Bacchus, carrying ivy." },
  { book: "2 Maccabees", chapter: 6, verse: 8, text: "Moreover there went out a decree to the neighbour cities of the heathen, by the suggestion of Ptolemee, against the Jews, that they should observe the same fashions, and be partakers of their sacrifices:" },
  { book: "2 Maccabees", chapter: 6, verse: 9, text: "And whoso would not conform themselves to the manners of the Gentiles should be put to death. Then might a man have seen the present misery." },
  { book: "2 Maccabees", chapter: 6, verse: 10, text: "For there were two women brought, who had circumcised their children; whom when they had openly led round about the city, the babes handing at their breasts, they cast them down headlong from the wall." },
  { book: "2 Maccabees", chapter: 6, verse: 11, text: "And others, that had run together into caves near by, to keep the sabbath day secretly, being discovered by Philip, were all burnt together, because they made a conscience to help themselves for the honour of the most sacred day." },
  { book: "2 Maccabees", chapter: 6, verse: 12, text: "Now I beseech those that read this book, that they be not discouraged for these calamities, but that they judge those punishments not to be for destruction, but for a chastening of our nation." },
  { book: "2 Maccabees", chapter: 6, verse: 13, text: "For it is a token of his great goodness, when wicked doers are not suffered any long time, but forthwith punished." },
  { book: "2 Maccabees", chapter: 6, verse: 14, text: "For not as with other nations, whom the Lord patiently forbeareth to punish, till they be come to the fulness of their sins, so dealeth he with us," },
  { book: "2 Maccabees", chapter: 6, verse: 15, text: "Lest that, being come to the height of sin, afterwards he should take vengeance of us." },
  { book: "2 Maccabees", chapter: 6, verse: 16, text: "And therefore he never withdraweth his mercy from us: and though he punish with adversity, yet doth he never forsake his people." },
  { book: "2 Maccabees", chapter: 6, verse: 17, text: "But let this that we at spoken be for a warning unto us. And now will we come to the declaring of the matter in a few words." },
  { book: "2 Maccabees", chapter: 6, verse: 18, text: "Eleazar, one of the principal scribes, an aged man, and of a well favoured countenance, was constrained to open his mouth, and to eat swine’s flesh." },
  { book: "2 Maccabees", chapter: 6, verse: 19, text: "But he, choosing rather to die gloriously, than to live stained with such an abomination, spit it forth, and came of his own accord to the torment," },
  { book: "2 Maccabees", chapter: 6, verse: 20, text: "As it behoved them to come, that are resolute to stand out against such things, as are not lawful for love of life to be tasted." },
  { book: "2 Maccabees", chapter: 6, verse: 21, text: "But they that had the charge of that wicked feast, for the old acquaintance they had with the man, taking him aside, besought him to bring flesh of his own provision, such as was lawful for him to use, and make as if he did eat of the flesh taken from the sacrifice commanded by the king;" },
  { book: "2 Maccabees", chapter: 6, verse: 22, text: "That in so doing he might be delivered from death, and for the old friendship with them find favour." },
  { book: "2 Maccabees", chapter: 6, verse: 23, text: "But he began to consider discreetly, and as became his age, and the excellency of his ancient years, and the honour of his gray head, whereon was come, and his most honest education from a child, or rather the holy law made and given by God: therefore he answered accordingly, and willed them straightways to send him to the grave." },
  { book: "2 Maccabees", chapter: 6, verse: 24, text: "For it becometh not our age, said he, in any wise to dissemble, whereby many young persons might think that Eleazar, being fourscore years old and ten, were now gone to a strange religion;" },
  { book: "2 Maccabees", chapter: 6, verse: 25, text: "And so they through mine hypocrisy, and desire to live a little time and a moment longer, should be deceived by me, and I get a stain to mine old age, and make it abominable." },
  { book: "2 Maccabees", chapter: 6, verse: 26, text: "For though for the present time I should be delivered from the punishment of men: yet should I not escape the hand of the Almighty, neither alive, nor dead." },
  { book: "2 Maccabees", chapter: 6, verse: 27, text: "Wherefore now, manfully changing this life, I will shew myself such an one as mine age requireth," },
  { book: "2 Maccabees", chapter: 6, verse: 28, text: "And leave a notable example to such as be young to die willingly and courageously for the honourable and holy laws. And when he had said these words, immediately he went to the torment:" },
  { book: "2 Maccabees", chapter: 6, verse: 29, text: "They that led him changing the good will they bare him a little before into hatred, because the foresaid speeches proceeded, as they thought, from a desperate mind." },
  { book: "2 Maccabees", chapter: 6, verse: 30, text: "But when he was ready to die with stripes, he groaned, and said, It is manifest unto the Lord, that hath the holy knowledge, that whereas I might have been delivered from death, I now endure sore pains in body by being beaten: but in soul am well content to suffer these things, because I fear him." },
  { book: "2 Maccabees", chapter: 6, verse: 31, text: "And thus this man died, leaving his death for an example of a noble courage, and a memorial of virtue, not only unto young men, but unto all his nation." },
  { book: "2 Maccabees", chapter: 7, verse: 1, text: "It came to pass also, that seven brethren with their mother were taken, and compelled by the king against the law to taste swine’s flesh, and were tormented with scourges and whips." },
  { book: "2 Maccabees", chapter: 7, verse: 2, text: "But one of them that spake first said thus, What wouldest thou ask or learn of us? we are ready to die, rather than to transgress the laws of our fathers." },
  { book: "2 Maccabees", chapter: 7, verse: 3, text: "Then the king, being in a rage, commanded pans and caldrons to be made hot:" },
  { book: "2 Maccabees", chapter: 7, verse: 4, text: "Which forthwith being heated, he commanded to cut out the tongue of him that spake first, and to cut off the utmost parts of his body, the rest of his brethren and his mother looking on." },
  { book: "2 Maccabees", chapter: 7, verse: 5, text: "Now when he was thus maimed in all his members, he commanded him being yet alive to be brought to the fire, and to be fried in the pan: and as the vapour of the pan was for a good space dispersed, they exhorted one another with the mother to die manfully, saying thus," },
  { book: "2 Maccabees", chapter: 7, verse: 6, text: "The Lord God looketh upon us, and in truth hath comfort in us, as Moses in his song, which witnessed to their faces, declared, saying, And he shall be comforted in his servants." },
  { book: "2 Maccabees", chapter: 7, verse: 7, text: "So when the first was dead after this number, they brought the second to make him a mocking stock: and when they had pulled off the skin of his head with the hair, they asked him, Wilt thou eat, before thou be punished throughout every member of thy body?" },
  { book: "2 Maccabees", chapter: 7, verse: 8, text: "But he answered in his own language, and said, No. Wherefore he also received the next torment in order, as the former did." },
  { book: "2 Maccabees", chapter: 7, verse: 9, text: "And when he was at the last gasp, he said, Thou like a fury takest us out of this present life, but the King of the world shall raise us up, who have died for his laws, unto everlasting life." },
  { book: "2 Maccabees", chapter: 7, verse: 10, text: "After him was the third made a mocking stock: and when he was required, he put out his tongue, and that right soon, holding forth his hands manfully." },
  { book: "2 Maccabees", chapter: 7, verse: 11, text: "And said courageously, These I had from heaven; and for his laws I despise them; and from him I hope to receive them again." },
  { book: "2 Maccabees", chapter: 7, verse: 12, text: "Insomuch that the king, and they that were with him, marvelled at the young man’s courage, for that he nothing regarded the pains." },
  { book: "2 Maccabees", chapter: 7, verse: 13, text: "Now when this man was dead also, they tormented and mangled the fourth in like manner." },
  { book: "2 Maccabees", chapter: 7, verse: 14, text: "So when he was ready to die he said thus, It is good, being put to death by men, to look for hope from God to be raised up again by him: as for thee, thou shalt have no resurrection to life." },
  { book: "2 Maccabees", chapter: 7, verse: 15, text: "Afterward they brought the fifth also, and mangled him." },
  { book: "2 Maccabees", chapter: 7, verse: 16, text: "Then looked he unto the king, and said, Thou hast power over men, thou art corruptible, thou doest what thou wilt; yet think not that our nation is forsaken of God;" },
  { book: "2 Maccabees", chapter: 7, verse: 17, text: "But abide a while, and behold his great power, how he will torment thee and thy seed." },
  { book: "2 Maccabees", chapter: 7, verse: 18, text: "After him also they brought the sixth, who being ready to die said, Be not deceived without cause: for we suffer these things for ourselves, having sinned against our God: therefore marvellous things are done unto us." },
  { book: "2 Maccabees", chapter: 7, verse: 19, text: "But think not thou, that takest in hand to strive against God, that thou shalt escape unpunished." },
  { book: "2 Maccabees", chapter: 7, verse: 20, text: "But the mother was marvellous above all, and worthy of honourable memory: for when she saw her seven sons slain within the space of one day, she bare it with a good courage, because of the hope that she had in the Lord." },
  { book: "2 Maccabees", chapter: 7, verse: 21, text: "Yea, she exhorted every one of them in her own language, filled with courageous spirits; and stirring up her womanish thoughts with a manly stomach, she said unto them," },
  { book: "2 Maccabees", chapter: 7, verse: 22, text: "I cannot tell how ye came into my womb: for I neither gave you breath nor life, neither was it I that formed the members of every one of you;" },
  { book: "2 Maccabees", chapter: 7, verse: 23, text: "But doubtless the Creator of the world, who formed the generation of man, and found out the beginning of all things, will also of his own mercy give you breath and life again, as ye now regard not your own selves for his laws’ sake." },
  { book: "2 Maccabees", chapter: 7, verse: 24, text: "Now Antiochus, thinking himself despised, and suspecting it to be a reproachful speech, whilst the youngest was yet alive, did not only exhort him by words, but also assured him with oaths, that he would make him both a rich and a happy man, if he would turn from the laws of his fathers; and that also he would take him for his friend, and trust him with affairs." },
  { book: "2 Maccabees", chapter: 7, verse: 25, text: "But when the young man would in no case hearken unto him, the king called his mother, and exhorted her that she would counsel the young man to save his life." },
  { book: "2 Maccabees", chapter: 7, verse: 26, text: "And when he had exhorted her with many words, she promised him that she would counsel her son." },
  { book: "2 Maccabees", chapter: 7, verse: 27, text: "But she bowing herself toward him, laughing the cruel tyrant to scorn, spake in her country language on this manner; O my son, have pity upon me that bare thee nine months in my womb, and gave thee such three years, and nourished thee, and brought thee up unto this age, and endured the troubles of education." },
  { book: "2 Maccabees", chapter: 7, verse: 28, text: "I beseech thee, my son, look upon the heaven and the earth, and all that is therein, and consider that God made them of things that were not; and so was mankind made likewise." },
  { book: "2 Maccabees", chapter: 7, verse: 29, text: "Fear not this tormentor, but, being worthy of thy brethren, take thy death that I may receive thee again in mercy with thy brethren." },
  { book: "2 Maccabees", chapter: 7, verse: 30, text: "Whiles she was yet speaking these words, the young man said, Whom wait ye for? I will not obey the king’s commandment: but I will obey the commandment of the law that was given unto our fathers by Moses." },
  { book: "2 Maccabees", chapter: 7, verse: 31, text: "And thou, that hast been the author of all mischief against the Hebrews, shalt not escape the hands of God." },
  { book: "2 Maccabees", chapter: 7, verse: 32, text: "For we suffer because of our sins." },
  { book: "2 Maccabees", chapter: 7, verse: 33, text: "And though the living Lord be angry with us a little while for our chastening and correction, yet shall he be at one again with his servants." },
  { book: "2 Maccabees", chapter: 7, verse: 34, text: "But thou, O godless man, and of all other most wicked, be not lifted up without a cause, nor puffed up with uncertain hopes, lifting up thy hand against the servants of God:" },
  { book: "2 Maccabees", chapter: 7, verse: 35, text: "For thou hast not yet escaped the judgment of Almighty God, who seeth all things." },
  { book: "2 Maccabees", chapter: 7, verse: 36, text: "For our brethren, who now have suffered a short pain, are dead under God’s covenant of everlasting life: but thou, through the judgment of God, shalt receive just punishment for thy pride." },
  { book: "2 Maccabees", chapter: 7, verse: 37, text: "But I, as my brethren, offer up my body and life for the laws of our fathers, beseeching God that he would speedily be merciful unto our nation; and that thou by torments and plagues mayest confess, that he alone is God;" },
  { book: "2 Maccabees", chapter: 7, verse: 38, text: "And that in me and my brethren the wrath of the Almighty, which is justly brought upon our nation, may cease." },
  { book: "2 Maccabees", chapter: 7, verse: 39, text: "Then the king, being in a rage, handed him worse than all the rest, and took it grievously that he was mocked." },
  { book: "2 Maccabees", chapter: 7, verse: 40, text: "So this man died undefiled, and put his whole trust in the Lord." },
  { book: "2 Maccabees", chapter: 7, verse: 41, text: "Last of all after the sons the mother died." },
  { book: "2 Maccabees", chapter: 7, verse: 42, text: "Let this be enough now to have spoken concerning the idolatrous feasts, and the extreme tortures." },
  { book: "2 Maccabees", chapter: 8, verse: 1, text: "Then Judas Maccabeus, and they that were with him, went privily into the towns, and called their kinsfolks together, and took unto them all such as continued in the Jews’ religion, and assembled about six thousand men." },
  { book: "2 Maccabees", chapter: 8, verse: 2, text: "And they called upon the Lord, that he would look upon the people that was trodden down of all; and also pity the temple profaned of ungodly men;" },
  { book: "2 Maccabees", chapter: 8, verse: 3, text: "And that he would have compassion upon the city, sore defaced, and ready to be made even with the ground; and hear the blood that cried unto him," },
  { book: "2 Maccabees", chapter: 8, verse: 4, text: "And remember the wicked slaughter of harmless infants, and the blasphemies committed against his name; and that he would shew his hatred against the wicked." },
  { book: "2 Maccabees", chapter: 8, verse: 5, text: "Now when Maccabeus had his company about him, he could not be withstood by the heathen: for the wrath of the Lord was turned into mercy." },
  { book: "2 Maccabees", chapter: 8, verse: 6, text: "Therefore he came at unawares, and burnt up towns and cities, and got into his hands the most commodious places, and overcame and put to flight no small number of his enemies." },
  { book: "2 Maccabees", chapter: 8, verse: 7, text: "But specially took he advantage of the night for such privy attempts, insomuch that the fruit of his holiness was spread every where." },
  { book: "2 Maccabees", chapter: 8, verse: 8, text: "So when Philip saw that this man increased by little and little, and that things prospered with him still more and more, he wrote unto Ptolemeus, the governor of Celosyria and Phenice, to yield more aid to the king’s affairs." },
  { book: "2 Maccabees", chapter: 8, verse: 9, text: "Then forthwith choosing Nicanor the son of Patroclus, one of his special friends, he sent him with no fewer than twenty thousand of all nations under him, to root out the whole generation of the Jews; and with him he joined also Gorgias a captain, who in matters of war had great experience." },
  { book: "2 Maccabees", chapter: 8, verse: 10, text: "So Nicanor undertook to make so much money of the captive Jews, as should defray the tribute of two thousand talents, which the king was to pay to the Romans." },
  { book: "2 Maccabees", chapter: 8, verse: 11, text: "Wherefore immediately he sent to the cities upon the sea coast, proclaiming a sale of the captive Jews, and promising that they should have fourscore and ten bodies for one talent, not expecting the vengeance that was to follow upon him from the Almighty God." },
  { book: "2 Maccabees", chapter: 8, verse: 12, text: "Now when word was brought unto Judas of Nicanor’s coming, and he had imparted unto those that were with him that the army was at hand," },
  { book: "2 Maccabees", chapter: 8, verse: 13, text: "They that were fearful, and distrusted the justice of God, fled, and conveyed themselves away." },
  { book: "2 Maccabees", chapter: 8, verse: 14, text: "Others sold all that they had left, and withal besought the Lord to deliver them, sold by the wicked Nicanor before they met together:" },
  { book: "2 Maccabees", chapter: 8, verse: 15, text: "And if not for their own sakes, yet for the covenants he had made with their fathers, and for his holy and glorious name’s sake, by which they were called." },
  { book: "2 Maccabees", chapter: 8, verse: 16, text: "So Maccabeus called his men together unto the number of six thousand, and exhorted them not to be stricken with terror of the enemy, nor to fear the great multitude of the heathen, who came wrongly against them; but to fight manfully," },
  { book: "2 Maccabees", chapter: 8, verse: 17, text: "And to set before their eyes the injury that they had unjustly done to the holy place, and the cruel handling of the city, whereof they made a mockery, and also the taking away of the government of their forefathers:" },
  { book: "2 Maccabees", chapter: 8, verse: 18, text: "For they, said he, trust in their weapons and boldness; but our confidence is in the Almighty who at a beck can cast down both them that come against us, and also all the world." },
  { book: "2 Maccabees", chapter: 8, verse: 19, text: "Moreover, he recounted unto them what helps their forefathers had found, and how they were delivered, when under Sennacherib an hundred fourscore and five thousand perished." },
  { book: "2 Maccabees", chapter: 8, verse: 20, text: "And he told them of the battle that they had in Babylon with the Galatians, how they came but eight thousand in all to the business, with four thousand Macedonians, and that the Macedonians being perplexed, the eight thousand destroyed an hundred and twenty thousand because of the help that they had from heaven, and so received a great booty." },
  { book: "2 Maccabees", chapter: 8, verse: 21, text: "Thus when he had made them bold with these words, and ready to die for the law and the country, he divided his army into four parts;" },
  { book: "2 Maccabees", chapter: 8, verse: 22, text: "And joined with himself his own brethren, leaders of each band, to wit Simon, and Joseph, and Jonathan, giving each one fifteen hundred men." },
  { book: "2 Maccabees", chapter: 8, verse: 23, text: "Also he appointed Eleazar to read the holy book: and when he had given them this watchword, The help of God; himself leading the first band," },
  { book: "2 Maccabees", chapter: 8, verse: 24, text: "And by the help of the Almighty they slew above nine thousand of their enemies, and wounded and maimed the most part of Nicanor’s host, and so put all to flight;" },
  { book: "2 Maccabees", chapter: 8, verse: 25, text: "And took their money that came to buy them, and pursued them far: but lacking time they returned:" },
  { book: "2 Maccabees", chapter: 8, verse: 26, text: "For it was the day before the sabbath, and therefore they would no longer pursue them." },
  { book: "2 Maccabees", chapter: 8, verse: 27, text: "So when they had gathered their armour together, and spoiled their enemies, they occupied themselves about the sabbath, yielding exceeding praise and thanks to the Lord, who had preserved them unto that day, which was the beginning of mercy distilling upon them." },
  { book: "2 Maccabees", chapter: 8, verse: 28, text: "And after the sabbath, when they had given part of the spoils to the maimed, and the widows, and orphans, the residue they divided among themselves and their servants." },
  { book: "2 Maccabees", chapter: 8, verse: 29, text: "When this was done, and they had made a common supplication, they besought the merciful Lord to be reconciled with his servants for ever." },
  { book: "2 Maccabees", chapter: 8, verse: 30, text: "Moreover of those that were with Timotheus and Bacchides, who fought against them, they slew above twenty thousand, and very easily got high and strong holds, and divided among themselves many spoils more, and made the maimed, orphans, widows, yea, and the aged also, equal in spoils with themselves." },
  { book: "2 Maccabees", chapter: 8, verse: 31, text: "And when they had gathered their armour together, they laid them up all carefully in convenient places, and the remnant of the spoils they brought to Jerusalem." },
  { book: "2 Maccabees", chapter: 8, verse: 32, text: "They slew also Philarches, that wicked person, who was with Timotheus, and had annoyed the Jews many ways." },
  { book: "2 Maccabees", chapter: 8, verse: 33, text: "Furthermore at such time as they kept the feast for the victory in their country they burnt Callisthenes, that had set fire upon the holy gates, who had fled into a little house; and so he received a reward meet for his wickedness." },
  { book: "2 Maccabees", chapter: 8, verse: 34, text: "As for that most ungracious Nicanor, who had brought a thousand merchants to buy the Jews," },
  { book: "2 Maccabees", chapter: 8, verse: 35, text: "He was through the help of the Lord brought down by them, of whom he made least account; and putting off his glorious apparel, and discharging his company, he came like a fugitive servant through the midland unto Antioch having very great dishonour, for that his host was destroyed." },
  { book: "2 Maccabees", chapter: 8, verse: 36, text: "Thus he, that took upon him to make good to the Romans their tribute by means of captives in Jerusalem, told abroad, that the Jews had God to fight for them, and therefore they could not be hurt, because they followed the laws that he gave them." },
  { book: "2 Maccabees", chapter: 9, verse: 1, text: "About that time came Antiochus with dishonour out of the country of Persia" },
  { book: "2 Maccabees", chapter: 9, verse: 2, text: "For he had entered the city called Persepolis, and went about to rob the temple, and to hold the city; whereupon the multitude running to defend themselves with their weapons put them to flight; and so it happened, that Antiochus being put to flight of the inhabitants returned with shame." },
  { book: "2 Maccabees", chapter: 9, verse: 3, text: "Now when he came to Ecbatane, news was brought him what had happened unto Nicanor and Timotheus." },
  { book: "2 Maccabees", chapter: 9, verse: 4, text: "Then swelling with anger. he thought to avenge upon the Jews the disgrace done unto him by those that made him flee. Therefore commanded he his chariotman to drive without ceasing, and to dispatch the journey, the judgment of God now following him. For he had spoken proudly in this sort, That he would come to Jerusalem and make it a common burying place of the Jews." },
  { book: "2 Maccabees", chapter: 9, verse: 5, text: "But the Lord Almighty, the God of Isreal, smote him with an incurable and invisible plague: or as soon as he had spoken these words, a pain of the bowels that was remediless came upon him, and sore torments of the inner parts;" },
  { book: "2 Maccabees", chapter: 9, verse: 6, text: "And that most justly: for he had tormented other men’s bowels with many and strange torments." },
  { book: "2 Maccabees", chapter: 9, verse: 7, text: "Howbeit he nothing at all ceased from his bragging, but still was filled with pride, breathing out fire in his rage against the Jews, and commanding to haste the journey: but it came to pass that he fell down from his chariot, carried violently; so that having a sore fall, all the members of his body were much pained." },
  { book: "2 Maccabees", chapter: 9, verse: 8, text: "And thus he that a little afore thought he might command the waves of the sea, (so proud was he beyond the condition of man) and weigh the high mountains in a balance, was now cast on the ground, and carried in an horselitter, shewing forth unto all the manifest power of God." },
  { book: "2 Maccabees", chapter: 9, verse: 9, text: "So that the worms rose up out of the body of this wicked man, and whiles he lived in sorrow and pain, his flesh fell away, and the filthiness of his smell was noisome to all his army." },
  { book: "2 Maccabees", chapter: 9, verse: 10, text: "And the man, that thought a little afore he could reach to the stars of heaven, no man could endure to carry for his intolerable stink." },
  { book: "2 Maccabees", chapter: 9, verse: 11, text: "Here therefore, being plagued, he began to leave off his great pride, and to come to the knowledge of himself by the scourge of God, his pain increasing every moment." },
  { book: "2 Maccabees", chapter: 9, verse: 12, text: "And when he himself could not abide his own smell, he said these words, It is meet to be subject unto God, and that a man that is mortal should not proudly think of himself if he were God." },
  { book: "2 Maccabees", chapter: 9, verse: 13, text: "This wicked person vowed also unto the Lord, who now no more would have mercy upon him, saying thus," },
  { book: "2 Maccabees", chapter: 9, verse: 14, text: "That the holy city (to the which he was going in haste to lay it even with the ground, and to make it a common buryingplace,) he would set at liberty:" },
  { book: "2 Maccabees", chapter: 9, verse: 15, text: "And as touching the Jews, whom he had judged not worthy so much as to be buried, but to be cast out with their children to be devoured of the fowls and wild beasts, he would make them all equals to the citizens of Athens:" },
  { book: "2 Maccabees", chapter: 9, verse: 16, text: "And the holy temple, which before he had spoiled, he would garnish with goodly gifts, and restore all the holy vessels with many more, and out of his own revenue defray the charges belonging to the sacrifices:" },
  { book: "2 Maccabees", chapter: 9, verse: 17, text: "Yea, and that also he would become a Jew himself, and go through all the world that was inhabited, and declare the power of God." },
  { book: "2 Maccabees", chapter: 9, verse: 18, text: "But for all this his pains would not cease: for the just judgment of God was come upon him: therefore despairing of his health, he wrote unto the Jews the letter underwritten, containing the form of a supplication, after this manner:" },
  { book: "2 Maccabees", chapter: 9, verse: 19, text: "Antiochus, king and governor, to the good Jews his citizens wisheth much joy, health, and prosperity:" },
  { book: "2 Maccabees", chapter: 9, verse: 20, text: "If ye and your children fare well, and your affairs be to your contentment, I give very great thanks to God, having my hope in heaven." },
  { book: "2 Maccabees", chapter: 9, verse: 21, text: "As for me, I was weak, or else I would have remembered kindly your honour and good will returning out of Persia, and being taken with a grievous disease, I thought it necessary to care for the common safety of all:" },
  { book: "2 Maccabees", chapter: 9, verse: 22, text: "Not distrusting mine health, but having great hope to escape this sickness." },
  { book: "2 Maccabees", chapter: 9, verse: 23, text: "But considering that even my father, at what time he led an army into the high countries. appointed a successor," },
  { book: "2 Maccabees", chapter: 9, verse: 24, text: "To the end that, if any thing fell out contrary to expectation, or if any tidings were brought that were grievous, they of the land, knowing to whom the state was left, might not be troubled:" },
  { book: "2 Maccabees", chapter: 9, verse: 25, text: "Again, considering how that the princes that are borderers and neighbours unto my kingdom wait for opportunities, and expect what shall be the event. I have appointed my son Antiochus king, whom I often committed and commended unto many of you, when I went up into the high provinces; to whom I have written as followeth:" },
  { book: "2 Maccabees", chapter: 9, verse: 26, text: "Therefore I pray and request you to remember the benefits that I have done unto you generally, and in special, and that every man will be still faithful to me and my son." },
  { book: "2 Maccabees", chapter: 9, verse: 27, text: "For I am persuaded that he understanding my mind will favourably and graciously yield to your desires." },
  { book: "2 Maccabees", chapter: 9, verse: 28, text: "Thus the murderer and blasphemer having suffered most grievously, as he entreated other men, so died he a miserable death in a strange country in the mountains." },
  { book: "2 Maccabees", chapter: 9, verse: 29, text: "And Philip, that was brought up with him, carried away his body, who also fearing the son of Antiochus went into Egypt to Ptolemeus Philometor." },
  { book: "2 Maccabees", chapter: 10, verse: 1, text: "Now Maccabeus and his company, the Lord guiding them, recovered the temple and the city:" },
  { book: "2 Maccabees", chapter: 10, verse: 2, text: "But the altars which the heathen had built in the open street, and also the chapels, they pulled down." },
  { book: "2 Maccabees", chapter: 10, verse: 3, text: "And having cleansed the temple they made another altar, and striking stones they took fire out of them, and offered a sacrifice after two years, and set forth incense, and lights, and shewbread." },
  { book: "2 Maccabees", chapter: 10, verse: 4, text: "When that was done, they fell flat down, and besought the Lord that they might come no more into such troubles; but if they sinned any more against him, that he himself would chasten them with mercy, and that they might not be delivered unto the blasphemous and barbarous nations." },
  { book: "2 Maccabees", chapter: 10, verse: 5, text: "Now upon the same day that the strangers profaned the temple, on the very same day it was cleansed again, even the five and twentieth day of the same month, which is Casleu." },
  { book: "2 Maccabees", chapter: 10, verse: 6, text: "And they kept the eight days with gladness, as in the feast of the tabernacles, remembering that not long afore they had held the feast of the tabernacles, when as they wandered in the mountains and dens like beasts." },
  { book: "2 Maccabees", chapter: 10, verse: 7, text: "Therefore they bare branches, and fair boughs, and palms also, and sang psalms unto him that had given them good success in cleansing his place." },
  { book: "2 Maccabees", chapter: 10, verse: 8, text: "They ordained also by a common statute and decree, That every year those days should be kept of the whole nation of the Jews." },
  { book: "2 Maccabees", chapter: 10, verse: 9, text: "And this was the end of Antiochus, called Epiphanes." },
  { book: "2 Maccabees", chapter: 10, verse: 10, text: "Now will we declare the acts of Antiochus Eupator, who was the son of this wicked man, gathering briefly the calamities of the wars." },
  { book: "2 Maccabees", chapter: 10, verse: 11, text: "So when he was come to the crown, he set one Lysias over the affairs of his realm, and appointed him his chief governor of Celosyria and Phenice." },
  { book: "2 Maccabees", chapter: 10, verse: 12, text: "For Ptolemeus, that was called Macron, choosing rather to do justice unto the Jews for the wrong that had been done unto them, endeavoured to continue peace with them." },
  { book: "2 Maccabees", chapter: 10, verse: 13, text: "Whereupon being accused of the king’s friends before Eupator, and called traitor at every word because he had left Cyprus, that Philometor had committed unto him, and departed to Antiochus Epiphanes, and seeing that he was in no honourable place, he was so discouraged, that he poisoned himself and died." },
  { book: "2 Maccabees", chapter: 10, verse: 14, text: "But when Gorgias was governor of the holds, he hired soldiers, and nourished war continually with the Jews:" },
  { book: "2 Maccabees", chapter: 10, verse: 15, text: "And therewithal the Idumeans, having gotten into their hands the most commodious holds, kept the Jews occupied, and receiving those that were banished from Jerusalem, they went about to nourish war." },
  { book: "2 Maccabees", chapter: 10, verse: 16, text: "Then they that were with Maccabeus made supplication, and besought God that he would be their helper; and so they ran with violence upon the strong holds of the Idumeans," },
  { book: "2 Maccabees", chapter: 10, verse: 17, text: "And assaulting them strongly, they won the holds, and kept off all that fought upon the wall, and slew all that fell into their hands, and killed no fewer than twenty thousand." },
  { book: "2 Maccabees", chapter: 10, verse: 18, text: "And because certain, who were no less than nine thousand, were fled together into two very strong castles, having all manner of things convenient to sustain the siege," },
  { book: "2 Maccabees", chapter: 10, verse: 19, text: "Maccabeus left Simon and Joseph, and Zaccheus also, and them that were with him, who were enough to besiege them, and departed himself unto those places which more needed his help." },
  { book: "2 Maccabees", chapter: 10, verse: 20, text: "Now they that were with Simon, being led with covetousness, were persuaded for money through certain of those that were in the castle, and took seventy thousand drachms, and let some of them escape." },
  { book: "2 Maccabees", chapter: 10, verse: 21, text: "But when it was told Maccabeus what was done, he called the governors of the people together, and accused those men, that they had sold their brethren for money, and set their enemies free to fight against them." },
  { book: "2 Maccabees", chapter: 10, verse: 22, text: "So he slew those that were found traitors, and immediately took the two castles." },
  { book: "2 Maccabees", chapter: 10, verse: 23, text: "And having good success with his weapons in all things he took in hand, he slew in the two holds more than twenty thousand." },
  { book: "2 Maccabees", chapter: 10, verse: 24, text: "Now Timotheus, whom the Jews had overcome before, when he had gathered a great multitude of foreign forces, and horses out of Asia not a few, came as though he would take Jewry by force of arms." },
  { book: "2 Maccabees", chapter: 10, verse: 25, text: "But when he drew near, they that were with Maccabeus turned themselves to pray unto God, and sprinkled earth upon their heads, and girded their loins with sackcloth," },
  { book: "2 Maccabees", chapter: 10, verse: 26, text: "And fell down at the foot of the altar, and besought him to be merciful to them, and to be an enemy to their enemies, and an adversary to their adversaries, as the law declareth." },
  { book: "2 Maccabees", chapter: 10, verse: 27, text: "So after the prayer they took their weapons, and went on further from the city: and when they drew near to their enemies, they kept by themselves." },
  { book: "2 Maccabees", chapter: 10, verse: 28, text: "Now the sun being newly risen, they joined both together; the one part having together with their virtue their refuge also unto the Lord for a pledge of their success and victory: the other side making their rage leader of their battle" },
  { book: "2 Maccabees", chapter: 10, verse: 29, text: "But when the battle waxed strong, there appeared unto the enemies from heaven five comely men upon horses, with bridles of gold, and two of them led the Jews," },
  { book: "2 Maccabees", chapter: 10, verse: 30, text: "And took Maccabeus betwixt them, and covered him on every side weapons, and kept him safe, but shot arrows and lightnings against the enemies: so that being confounded with blindness, and full of trouble, they were killed." },
  { book: "2 Maccabees", chapter: 10, verse: 31, text: "And there were slain of footmen twenty thousand and five hundred, and six hundred horsemen." },
  { book: "2 Maccabees", chapter: 10, verse: 32, text: "As for Timotheus himself, he fled into a very strong hold, called Gawra, where Chereas was governor." },
  { book: "2 Maccabees", chapter: 10, verse: 33, text: "But they that were with Maccabeus laid siege against the fortress courageously four days." },
  { book: "2 Maccabees", chapter: 10, verse: 34, text: "And they that were within, trusting to the strength of the place, blasphemed exceedingly, and uttered wicked words." },
  { book: "2 Maccabees", chapter: 10, verse: 35, text: "Nevertheless upon the fifth day early twenty young men of Maccabeus’ company, inflamed with anger because of the blasphemies, assaulted the wall manly, and with a fierce courage killed all that they met withal." },
  { book: "2 Maccabees", chapter: 10, verse: 36, text: "Others likewise ascending after them, whiles they were busied with them that were within, burnt the towers, and kindling fires burnt the blasphemers alive; and others broke open the gates, and, having received in the rest of the army, took the city," },
  { book: "2 Maccabees", chapter: 10, verse: 37, text: "And killed Timotheus, that was hid in a certain pit, and Chereas his brother, with Apollophanes." },
  { book: "2 Maccabees", chapter: 10, verse: 38, text: "When this was done, they praised the Lord with psalms and thanksgiving, who had done so great things for Israel, and given them the victory." },
  { book: "2 Maccabees", chapter: 11, verse: 1, text: "Not long after the, Lysias the king’s protector and cousin, who also managed the affairs, took sore displeasure for the things that were done." },
  { book: "2 Maccabees", chapter: 11, verse: 2, text: "And when he had gathered about fourscore thousand with all the horsemen, he came against the Jews, thinking to make the city an habitation of the Gentiles," },
  { book: "2 Maccabees", chapter: 11, verse: 3, text: "And to make a gain of the temple, as of the other chapels of the heathen, and to set the high priesthood to sale every year:" },
  { book: "2 Maccabees", chapter: 11, verse: 4, text: "Not at all considering the power of God but puffed up with his ten thousands of footmen, and his thousands of horsemen, and his fourscore elephants." },
  { book: "2 Maccabees", chapter: 11, verse: 5, text: "So he came to Judea, and drew near to Bethsura, which was a strong town, but distant from Jerusalem about five furlongs, and he laid sore siege unto it." },
  { book: "2 Maccabees", chapter: 11, verse: 6, text: "Now when they that were with Maccabeus heard that he besieged the holds, they and all the people with lamentation and tears besought the Lord that he would send a good angel to deliver Israel." },
  { book: "2 Maccabees", chapter: 11, verse: 7, text: "Then Maccabeus himself first of all took weapons, exhorting the other that they would jeopard themselves together with him to help their brethren: so they went forth together with a willing mind." },
  { book: "2 Maccabees", chapter: 11, verse: 8, text: "And as they were at Jerusalem, there appeared before them on horseback one in white clothing, shaking his armour of gold." },
  { book: "2 Maccabees", chapter: 11, verse: 9, text: "Then they praised the merciful God all together, and took heart, insomuch that they were ready not only to fight with men, but with most cruel beasts, and to pierce through walls of iron." },
  { book: "2 Maccabees", chapter: 11, verse: 10, text: "Thus they marched forward in their armour, having an helper from heaven: for the Lord was merciful unto them" },
  { book: "2 Maccabees", chapter: 11, verse: 11, text: "And giving a charge upon their enemies like lions, they slew eleven thousand footmen, and sixteen hundred horsemen, and put all the other to flight." },
  { book: "2 Maccabees", chapter: 11, verse: 12, text: "Many of them also being wounded escaped naked; and Lysias himself fled away shamefully, and so escaped." },
  { book: "2 Maccabees", chapter: 11, verse: 13, text: "Who, as he was a man of understanding, casting with himself what loss he had had, and considering that the Hebrews could not be overcome, because the Almighty God helped them, he sent unto them," },
  { book: "2 Maccabees", chapter: 11, verse: 14, text: "And persuaded them to agree to all reasonable conditions, and promised that he would persuade the king that he must needs be a friend unto them." },
  { book: "2 Maccabees", chapter: 11, verse: 15, text: "Then Maccabeus consented to all that Lysias desired, being careful of the common good; and whatsoever Maccabeus wrote unto Lysias concerning the Jews, the king granted it." },
  { book: "2 Maccabees", chapter: 11, verse: 16, text: "For there were letters written unto the Jews from Lysias to this effect: Lysias unto the people of the Jews sendeth greeting:" },
  { book: "2 Maccabees", chapter: 11, verse: 17, text: "John and Absolom, who were sent from you, delivered me the petition subscribed, and made request for the performance of the contents thereof." },
  { book: "2 Maccabees", chapter: 11, verse: 18, text: "Therefore what things soever were meet to be reported to the king, I have declared them, and he hath granted as much as might be." },
  { book: "2 Maccabees", chapter: 11, verse: 19, text: "And if then ye will keep yourselves loyal to the state, hereafter also will I endeavour to be a means of your good." },
  { book: "2 Maccabees", chapter: 11, verse: 20, text: "But of the particulars I have given order both to these and the other that came from me, to commune with you." },
  { book: "2 Maccabees", chapter: 11, verse: 21, text: "Fare ye well. The hundred and eight and fortieth year, the four and twentieth day of the month Dioscorinthius." },
  { book: "2 Maccabees", chapter: 11, verse: 22, text: "Now the king’s letter contained these words: King Antiochus unto his brother Lysias sendeth greeting:" },
  { book: "2 Maccabees", chapter: 11, verse: 23, text: "Since our father is translated unto the gods, our will is, that they that are in our realm live quietly, that every one may attend upon his own affairs." },
  { book: "2 Maccabees", chapter: 11, verse: 24, text: "We understand also that the Jews would not consent to our father, for to be brought unto the custom of the Gentiles, but had rather keep their own manner of living: for the which cause they require of us, that we should suffer them to live after their own laws." },
  { book: "2 Maccabees", chapter: 11, verse: 25, text: "Wherefore our mind is, that this nation shall be in rest, and we have determined to restore them their temple, that they may live according to the customs of their forefathers." },
  { book: "2 Maccabees", chapter: 11, verse: 26, text: "Thou shalt do well therefore to send unto them, and grant them peace, that when they are certified of our mind, they may be of good comfort, and ever go cheerfully about their own affairs." },
  { book: "2 Maccabees", chapter: 11, verse: 27, text: "And the letter of the king unto the nation of the Jews was after this manner: King Antiochus sendeth greeting unto the council, and the rest of the Jews:" },
  { book: "2 Maccabees", chapter: 11, verse: 28, text: "If ye fare well, we have our desire; we are also in good health." },
  { book: "2 Maccabees", chapter: 11, verse: 29, text: "Menelaus declared unto us, that your desire was to return home, and to follow your own business:" },
  { book: "2 Maccabees", chapter: 11, verse: 30, text: "Wherefore they that will depart shall have safe conduct till the thirtieth day of Xanthicus with security." },
  { book: "2 Maccabees", chapter: 11, verse: 31, text: "And the Jews shall use their own kind of meats and laws, as before; and none of them any manner of ways shall be molested for things ignorantly done." },
  { book: "2 Maccabees", chapter: 11, verse: 32, text: "I have sent also Menelaus, that he may comfort you." },
  { book: "2 Maccabees", chapter: 11, verse: 33, text: "Fare ye well. In the hundred forty and eighth year, and the fifteenth day of the month Xanthicus." },
  { book: "2 Maccabees", chapter: 11, verse: 34, text: "The Romans also sent unto them a letter containing these words: Quintus Memmius and Titus Manlius, ambassadors of the Romans, send greeting unto the people of the Jews." },
  { book: "2 Maccabees", chapter: 11, verse: 35, text: "Whatsoever Lysias the king’s cousin hath granted, therewith we also are well pleased." },
  { book: "2 Maccabees", chapter: 11, verse: 36, text: "But touching such things as he judged to be referred to the king, after ye have advised thereof, send one forthwith, that we may declare as it is convenient for you: for we are now going to Antioch." },
  { book: "2 Maccabees", chapter: 11, verse: 37, text: "Therefore send some with speed, that we may know what is your mind." },
  { book: "2 Maccabees", chapter: 11, verse: 38, text: "Farewell. This hundred and eight and fortieth year, the fifteenth day of the month Xanthicus." },
  { book: "2 Maccabees", chapter: 12, verse: 1, text: "When these covenants were made, Lysias went unto the king, and the Jews were about their husbandry." },
  { book: "2 Maccabees", chapter: 12, verse: 2, text: "But of the governours of several places, Timotheus, and Apollonius the son of Genneus, also Hieronymus, and Demophon, and beside them Nicanor the governor of Cyprus, would not suffer them to be quiet and live in peace." },
  { book: "2 Maccabees", chapter: 12, verse: 3, text: "The men of Joppa also did such an ungodly deed: they prayed the Jews that dwelt among them to go with their wives and children into the boats which they had prepared, as though they had meant them no hurt." },
  { book: "2 Maccabees", chapter: 12, verse: 4, text: "Who accepted of it according to the common decree of the city, as being desirous to live in peace, and suspecting nothing: but when they were gone forth into the deep, they drowned no less than two hundred of them." },
  { book: "2 Maccabees", chapter: 12, verse: 5, text: "When Judas heard of this cruelty done unto his countrymen, he commanded those that were with him to make them ready." },
  { book: "2 Maccabees", chapter: 12, verse: 6, text: "And calling upon God the righteous Judge, he came against those murderers of his brethren, and burnt the haven by night, and set the boats on fire, and those that fled thither he slew." },
  { book: "2 Maccabees", chapter: 12, verse: 7, text: "And when the town was shut up, he went backward, as if he would return to root out all them of the city of Joppa." },
  { book: "2 Maccabees", chapter: 12, verse: 8, text: "But when he heard that the Jamnites were minded to do in like manner unto the Jews that dwelt among them," },
  { book: "2 Maccabees", chapter: 12, verse: 9, text: "He came upon the Jamnites also by night, and set fire on the haven and the navy, so that the light of the fire was seen at Jerusalem two hundred and forty furlongs off." },
  { book: "2 Maccabees", chapter: 12, verse: 10, text: "Now when they were gone from thence nine furlongs in their journey toward Timotheus, no fewer than five thousand men on foot and five hundred horsemen of the Arabians set upon him." },
  { book: "2 Maccabees", chapter: 12, verse: 11, text: "Whereupon there was a very sore battle; but Judas’ side by the help of God got the victory; so that the Nomades of Arabia, being overcome, besought Judas for peace, promising both to give him cattle, and to pleasure him otherwise." },
  { book: "2 Maccabees", chapter: 12, verse: 12, text: "Then Judas, thinking indeed that they would be profitable in many things, granted them peace: whereupon they shook hands, and so they departed to their tents." },
  { book: "2 Maccabees", chapter: 12, verse: 13, text: "He went also about to make a bridge to a certain strong city, which was fenced about with walls, and inhabited by people of divers countries; and the name of it was Caspis." },
  { book: "2 Maccabees", chapter: 12, verse: 14, text: "But they that were within it put such trust in the strength of the walls and provision of victuals, that they behaved themselves rudely toward them that were with Judas, railing and blaspheming, and uttering such words as were not to be spoken." },
  { book: "2 Maccabees", chapter: 12, verse: 15, text: "Wherefore Judas with his company, calling upon the great Lord of the world, who without rams or engines of war did cast down Jericho in the time of Joshua, gave a fierce assault against the walls," },
  { book: "2 Maccabees", chapter: 12, verse: 16, text: "And took the city by the will of God, and made unspeakable slaughters, insomuch that a lake two furlongs broad near adjoining thereunto, being filled full, was seen running with blood." },
  { book: "2 Maccabees", chapter: 12, verse: 17, text: "Then departed they from thence seven hundred and fifty furlongs, and came to Characa unto the Jews that are called Tubieni." },
  { book: "2 Maccabees", chapter: 12, verse: 18, text: "But as for Timotheus, they found him not in the places: for before he had dispatched any thing, he departed from thence, having left a very strong garrison in a certain hold." },
  { book: "2 Maccabees", chapter: 12, verse: 19, text: "Howbeit Dositheus and Sosipater, who were of Maccabeus’ captains, went forth, and slew those that Timotheus had left in the fortress, above ten thousand men." },
  { book: "2 Maccabees", chapter: 12, verse: 20, text: "And Maccabeus ranged his army by bands, and set them over the bands, and went against Timotheus, who had about him an hundred and twenty thousand men of foot, and two thousand and five hundred horsemen." },
  { book: "2 Maccabees", chapter: 12, verse: 21, text: "Now when Timotheus had knowledge of Judas’ coming, he sent the women and children and the other baggage unto a fortress called Carnion: for the town was hard to besiege, and uneasy to come unto, by reason of the straitness of all the places." },
  { book: "2 Maccabees", chapter: 12, verse: 22, text: "But when Judas his first band came in sight, the enemies, being smitten with fear and terror through the appearing of him who seeth all things, fled amain, one running into this way, another that way, so as that they were often hurt of their own men, and wounded with the points of their own swords." },
  { book: "2 Maccabees", chapter: 12, verse: 23, text: "Judas also was very earnest in pursuing them, killing those wicked wretches, of whom he slew about thirty thousand men." },
  { book: "2 Maccabees", chapter: 12, verse: 24, text: "Moreover Timotheus himself fell into the hands of Dositheus and Sosipater, whom he besought with much craft to let him go with his life, because he had many of the Jews’ parents, and the brethren of some of them, who, if they put him to death, should not be regarded." },
  { book: "2 Maccabees", chapter: 12, verse: 25, text: "So when he had assured them with many words that he would restore them without hurt, according to the agreement, they let him go for the saving of their brethren." },
  { book: "2 Maccabees", chapter: 12, verse: 26, text: "Then Maccabeus marched forth to Carnion, and to the temple of Atargatis, and there he slew five and twenty thousand persons." },
  { book: "2 Maccabees", chapter: 12, verse: 27, text: "And after he had put to flight and destroyed them, Judas removed the host toward Ephron, a strong city, wherein Lysias abode, and a great multitude of divers nations, and the strong young men kept the walls, and defended them mightily: wherein also was great provision of engines and darts." },
  { book: "2 Maccabees", chapter: 12, verse: 28, text: "But when Judas and his company had called upon Almighty God, who with his power breaketh the strength of his enemies, they won the city, and slew twenty and five thousand of them that were within," },
  { book: "2 Maccabees", chapter: 12, verse: 29, text: "From thence they departed to Scythopolis, which lieth six hundred furlongs from Jerusalem," },
  { book: "2 Maccabees", chapter: 12, verse: 30, text: "But when the Jews that dwelt there had testified that the Scythopolitans dealt lovingly with them, and entreated them kindly in the time of their adversity;" },
  { book: "2 Maccabees", chapter: 12, verse: 31, text: "They gave them thanks, desiring them to be friendly still unto them: and so they came to Jerusalem, the feast of the weeks approaching." },
  { book: "2 Maccabees", chapter: 12, verse: 32, text: "And after the feast, called Pentecost, they went forth against Gorgias the governor of Idumea," },
  { book: "2 Maccabees", chapter: 12, verse: 33, text: "Who came out with three thousand men of foot and four hundred horsemen." },
  { book: "2 Maccabees", chapter: 12, verse: 34, text: "And it happened that in their fighting together a few of the Jews were slain." },
  { book: "2 Maccabees", chapter: 12, verse: 35, text: "At which time Dositheus, one of Bacenor’s company, who was on horseback, and a strong man, was still upon Gorgias, and taking hold of his coat drew him by force; and when he would have taken that cursed man alive, a horseman of Thracia coming upon him smote off his shoulder, so that Gorgias fled unto Marisa." },
  { book: "2 Maccabees", chapter: 12, verse: 36, text: "Now when they that were with Gorgias had fought long, and were weary, Judas called upon the Lord, that he would shew himself to be their helper and leader of the battle." },
  { book: "2 Maccabees", chapter: 12, verse: 37, text: "And with that he began in his own language, and sung psalms with a loud voice, and rushing unawares upon Gorgias’ men, he put them to flight." },
  { book: "2 Maccabees", chapter: 12, verse: 38, text: "So Judas gathered his host, and came into the city of Odollam, And when the seventh day came, they purified themselves, as the custom was, and kept the sabbath in the same place." },
  { book: "2 Maccabees", chapter: 12, verse: 39, text: "And upon the day following, as the use had been, Judas and his company came to take up the bodies of them that were slain, and to bury them with their kinsmen in their fathers’ graves." },
  { book: "2 Maccabees", chapter: 12, verse: 40, text: "Now under the coats of every one that was slain they found things consecrated to the idols of the Jamnites, which is forbidden the Jews by the law. Then every man saw that this was the cause wherefore they were slain." },
  { book: "2 Maccabees", chapter: 12, verse: 41, text: "All men therefore praising the Lord, the righteous Judge, who had opened the things that were hid," },
  { book: "2 Maccabees", chapter: 12, verse: 42, text: "Betook themselves unto prayer, and besought him that the sin committed might wholly be put out of remembrance. Besides, that noble Judas exhorted the people to keep themselves from sin, forsomuch as they saw before their eyes the things that came to pass for the sins of those that were slain." },
  { book: "2 Maccabees", chapter: 12, verse: 43, text: "And when he had made a gathering throughout the company to the sum of two thousand drachms of silver, he sent it to Jerusalem to offer a sin offering, doing therein very well and honestly, in that he was mindful of the resurrection:" },
  { book: "2 Maccabees", chapter: 12, verse: 44, text: "For if he had not hoped that they that were slain should have risen again, it had been superfluous and vain to pray for the dead." },
  { book: "2 Maccabees", chapter: 12, verse: 45, text: "And also in that he perceived that there was great favour laid up for those that died godly, it was an holy and good thought. Whereupon he made a reconciliation for the dead, that they might be delivered from sin." },
  { book: "2 Maccabees", chapter: 13, verse: 1, text: "In the hundred forty and ninth year it was told Judas, that Antiochus Eupator was coming with a great power into Judea," },
  { book: "2 Maccabees", chapter: 13, verse: 2, text: "And with him Lysias his protector, and ruler of his affairs, having either of them a Grecian power of footmen, an hundred and ten thousand, and horsemen five thousand and three hundred, and elephants two and twenty, and three hundred chariots armed with hooks." },
  { book: "2 Maccabees", chapter: 13, verse: 3, text: "Menelaus also joined himself with them, and with great dissimulation encouraged Antiochus, not for the safeguard of the country, but because he thought to have been made governor." },
  { book: "2 Maccabees", chapter: 13, verse: 4, text: "But the King of kings moved Antiochus’ mind against this wicked wretch, and Lysias informed the king that this man was the cause of all mischief, so that the king commanded to bring him unto Berea, and to put him to death, as the manner is in that place." },
  { book: "2 Maccabees", chapter: 13, verse: 5, text: "Now there was in that place a tower of fifty cubits high, full of ashes, and it had a round instrument which on every side hanged down into the ashes." },
  { book: "2 Maccabees", chapter: 13, verse: 6, text: "And whosoever was condemned of sacrilege, or had committed any other grievous crime, there did all men thrust him unto death." },
  { book: "2 Maccabees", chapter: 13, verse: 7, text: "Such a death it happened that wicked man to die, not having so much as burial in the earth; and that most justly:" },
  { book: "2 Maccabees", chapter: 13, verse: 8, text: "For inasmuch as he had committed many sins about the altar, whose fire and ashes were holy, he received his death in ashes." },
  { book: "2 Maccabees", chapter: 13, verse: 9, text: "Now the king came with a barbarous and haughty mind to do far worse to the Jews, than had been done in his father’s time." },
  { book: "2 Maccabees", chapter: 13, verse: 10, text: "Which things when Judas perceived, he commanded the multitude to call upon the Lord night and day, that if ever at any other time, he would now also help them, being at the point to be put from their law, from their country, and from the holy temple:" },
  { book: "2 Maccabees", chapter: 13, verse: 11, text: "And that he would not suffer the people, that had even now been but a little refreshed, to be in subjection to the blasphemous nations." },
  { book: "2 Maccabees", chapter: 13, verse: 12, text: "So when they had all done this together, and besought the merciful Lord with weeping and fasting, and lying flat upon the ground three days long, Judas, having exhorted them, commanded they should be in a readiness." },
  { book: "2 Maccabees", chapter: 13, verse: 13, text: "And Judas, being apart with the elders, determined, before the king’s host should enter into Judea, and get the city, to go forth and try the matter in fight by the help of the Lord." },
  { book: "2 Maccabees", chapter: 13, verse: 14, text: "So when he had committed all to the Creator of the world, and exhorted his soldiers to fight manfully, even unto death, for the laws, the temple, the city, the country, and the commonwealth, he camped by Modin:" },
  { book: "2 Maccabees", chapter: 13, verse: 15, text: "And having given the watchword to them that were about him, Victory is of God; with the most valiant and choice young men he went in into the king’s tent by night, and slew in the camp about four thousand men, and the chiefest of the elephants, with all that were upon him." },
  { book: "2 Maccabees", chapter: 13, verse: 16, text: "And at last they filled the camp with fear and tumult, and departed with good success." },
  { book: "2 Maccabees", chapter: 13, verse: 17, text: "This was done in the break of the day, because the protection of the Lord did help him." },
  { book: "2 Maccabees", chapter: 13, verse: 18, text: "Now when the king had taken a taste of the manliness of the Jews, he went about to take the holds by policy," },
  { book: "2 Maccabees", chapter: 13, verse: 19, text: "And marched toward Bethsura, which was a strong hold of the Jews: but he was put to flight, failed, and lost of his men:" },
  { book: "2 Maccabees", chapter: 13, verse: 20, text: "For Judas had conveyed unto them that were in it such things as were necessary." },
  { book: "2 Maccabees", chapter: 13, verse: 21, text: "But Rhodocus, who was in the Jews’ host, disclosed the secrets to the enemies; therefore he was sought out, and when they had gotten him, they put him in prison." },
  { book: "2 Maccabees", chapter: 13, verse: 22, text: "The king treated with them in Bethsum the second time, gave his hand, took their’s, departed, fought with Judas, was overcome;" },
  { book: "2 Maccabees", chapter: 13, verse: 23, text: "Heard that Philip, who was left over the affairs in Antioch, was desperately bent, confounded, intreated the Jews, submitted himself, and sware to all equal conditions, agreed with them, and offered sacrifice, honoured the temple, and dealt kindly with the place," },
  { book: "2 Maccabees", chapter: 13, verse: 24, text: "And accepted well of Maccabeus, made him principal governor from Ptolemais unto the Gerrhenians;" },
  { book: "2 Maccabees", chapter: 13, verse: 25, text: "Came to Ptolemais: the people there were grieved for the covenants; for they stormed, because they would make their covenants void:" },
  { book: "2 Maccabees", chapter: 13, verse: 26, text: "Lysias went up to the judgment seat, said as much as could be in defence of the cause, persuaded, pacified, made them well affected, returned to Antioch. Thus it went touching the king’s coming and departing." },
  { book: "2 Maccabees", chapter: 14, verse: 1, text: "After three years was Judas informed, that Demetrius the son of Seleucus, having entered by the haven of Tripolis with a great power and navy," },
  { book: "2 Maccabees", chapter: 14, verse: 2, text: "Had taken the country, and killed Antiochus, and Lysias his protector." },
  { book: "2 Maccabees", chapter: 14, verse: 3, text: "Now one Alcimus, who had been high priest, and had defiled himself wilfully in the times of their mingling with the Gentiles, seeing that by no means he could save himself, nor have any more access to the holy altar," },
  { book: "2 Maccabees", chapter: 14, verse: 4, text: "Came to king Demetrius in the hundred and one and fiftieth year, presenting unto him a crown of gold, and a palm, and also of the boughs which were used solemnly in the temple: and so that day he held his peace." },
  { book: "2 Maccabees", chapter: 14, verse: 5, text: "Howbeit having gotten opportunity to further his foolish enterprize, and being called into counsel by Demetrius, and asked how the Jews stood affected, and what they intended, he answered thereunto:" },
  { book: "2 Maccabees", chapter: 14, verse: 6, text: "Those of the Jews that he called Assideans, whose captain is Judas Maccabeus, nourish war and are seditious, and will not let the rest be in peace." },
  { book: "2 Maccabees", chapter: 14, verse: 7, text: "Therefore I, being deprived of mine ancestors’ honour, I mean the high priesthood, am now come hither:" },
  { book: "2 Maccabees", chapter: 14, verse: 8, text: "First, verily for the unfeigned care I have of things pertaining to the king; and secondly, even for that I intend the good of mine own countrymen: for all our nation is in no small misery through the unadvised dealing of them aforesaid." },
  { book: "2 Maccabees", chapter: 14, verse: 9, text: "Wherefore, O king, seeing knowest all these things, be careful for the country, and our nation, which is pressed on every side, according to the clemency that thou readily shewest unto all." },
  { book: "2 Maccabees", chapter: 14, verse: 10, text: "For as long as Judas liveth, it is not possible that the state should be quiet." },
  { book: "2 Maccabees", chapter: 14, verse: 11, text: "This was no sooner spoken of him, but others of the king’s friends, being maliciously set against Judas, did more incense Demetrius." },
  { book: "2 Maccabees", chapter: 14, verse: 12, text: "And forthwith calling Nicanor, who had been master of the elephants, and making him governor over Judea, he sent him forth," },
  { book: "2 Maccabees", chapter: 14, verse: 13, text: "Commanding him to slay Judas, and to scatter them that were with him, and to make Alcimus high priest of the great temple." },
  { book: "2 Maccabees", chapter: 14, verse: 14, text: "Then the heathen, that had fled out of Judea from Judas, came to Nicanor by flocks, thinking the harm and calamities of the Jews to be their welfare." },
  { book: "2 Maccabees", chapter: 14, verse: 15, text: "Now when the Jews heard of Nicanor’s coming, and that the heathen were up against them, they cast earth upon their heads, and made supplication to him that had established his people for ever, and who always helpeth his portion with manifestation of his presence." },
  { book: "2 Maccabees", chapter: 14, verse: 16, text: "So at the commandment of the captain they removed straightways from thence, and came near unto them at the town of Dessau." },
  { book: "2 Maccabees", chapter: 14, verse: 17, text: "Now Simon, Judas’ brother, had joined battle with Nicanor, but was somewhat discomfited through the sudden silence of his enemies." },
  { book: "2 Maccabees", chapter: 14, verse: 18, text: "Nevertheless Nicanor, hearing of the manliness of them that were with Judas, and the courageousness that they had to fight for their country, durst not try the matter by the sword." },
  { book: "2 Maccabees", chapter: 14, verse: 19, text: "Wherefore he sent Posidonius, and Theodotus, and Mattathias, to make peace." },
  { book: "2 Maccabees", chapter: 14, verse: 20, text: "So when they had taken long advisement thereupon, and the captain had made the multitude acquainted therewith, and it appeared that they were all of one mind, they consented to the covenants," },
  { book: "2 Maccabees", chapter: 14, verse: 21, text: "And appointed a day to meet in together by themselves: and when the day came, and stools were set for either of them," },
  { book: "2 Maccabees", chapter: 14, verse: 22, text: "Ludas placed armed men ready in convenient places, lest some treachery should be suddenly practised by the enemies: so they made a peaceable conference." },
  { book: "2 Maccabees", chapter: 14, verse: 23, text: "Now Nicanor abode in Jerusalem, and did no hurt, but sent away the people that came flocking unto him." },
  { book: "2 Maccabees", chapter: 14, verse: 24, text: "And he would not willingly have Judas out of his sight: for he love the man from his heart" },
  { book: "2 Maccabees", chapter: 14, verse: 25, text: "He prayed him also to take a wife, and to beget children: so he married, was quiet, and took part of this life." },
  { book: "2 Maccabees", chapter: 14, verse: 26, text: "But Alcimus, perceiving the love that was betwixt them, and considering the covenants that were made, came to Demetrius, and told him that Nicanor was not well affected toward the state; for that he had ordained Judas, a traitor to his realm, to be the king’s successor." },
  { book: "2 Maccabees", chapter: 14, verse: 27, text: "Then the king being in a rage, and provoked with the accusations of the most wicked man, wrote to Nicanor, signifying that he was much displeased with the covenants, and commanding him that he should send Maccabeus prisoner in all haste unto Antioch." },
  { book: "2 Maccabees", chapter: 14, verse: 28, text: "When this came to Nicanor’s hearing, he was much confounded in himself, and took it grievously that he should make void the articles which were agreed upon, the man being in no fault." },
  { book: "2 Maccabees", chapter: 14, verse: 29, text: "But because there was no dealing against the king, he watched his time to accomplish this thing by policy." },
  { book: "2 Maccabees", chapter: 14, verse: 30, text: "Notwithstanding, when Maccabeus saw that Nicanor began to be churlish unto him, and that he entreated him more roughly than he was wont, perceiving that such sour behaviour came not of good, he gathered together not a few of his men, and withdrew himself from Nicanor." },
  { book: "2 Maccabees", chapter: 14, verse: 31, text: "But the other, knowing that he was notably prevented by Judas’ policy, came into the great and holy temple, and commanded the priests, that were offering their usual sacrifices, to deliver him the man." },
  { book: "2 Maccabees", chapter: 14, verse: 32, text: "And when they sware that they could not tell where the man was whom he sought," },
  { book: "2 Maccabees", chapter: 14, verse: 33, text: "He stretched out his right hand toward the temple, and made an oath in this manner: If ye will not deliver me Judas as a prisoner, I will lay this temple of God even with the ground, and I will break down the altar, and erect a notable temple unto Bacchus." },
  { book: "2 Maccabees", chapter: 14, verse: 34, text: "After these words he departed. Then the priests lifted up their hands toward heaven, and besought him that was ever a defender of their nation, saying in this manner;" },
  { book: "2 Maccabees", chapter: 14, verse: 35, text: "Thou, O Lord of all things, who hast need of nothing, wast pleased that the temple of thine habitation should be among us:" },
  { book: "2 Maccabees", chapter: 14, verse: 36, text: "Therefore now, O holy Lord of all holiness, keep this house ever undefiled, which lately was cleansed, and stop every unrighteous mouth." },
  { book: "2 Maccabees", chapter: 14, verse: 37, text: "Now was there accused unto Nicanor one Razis, one of the elders of Jerusalem, a lover of his countrymen, and a man of very good report, who for his kindness was called a father of the Jews." },
  { book: "2 Maccabees", chapter: 14, verse: 38, text: "For in the former times, when they mingled not themselves with the Gentiles, he had been accused of Judaism, and did boldly jeopard his body and life with all vehemency for the religion of the Jews." },
  { book: "2 Maccabees", chapter: 14, verse: 39, text: "So Nicanor, willing to declare the hate that he bare unto the Jews, sent above five hundred men of war to take him:" },
  { book: "2 Maccabees", chapter: 14, verse: 40, text: "For he thought by taking him to do the Jews much hurt." },
  { book: "2 Maccabees", chapter: 14, verse: 41, text: "Now when the multitude would have taken the tower, and violently broken into the outer door, and bade that fire should be brought to burn it, he being ready to be taken on every side fell upon his sword;" },
  { book: "2 Maccabees", chapter: 14, verse: 42, text: "Choosing rather to die manfully, than to come into the hands of the wicked, to be abused otherwise than beseemed his noble birth:" },
  { book: "2 Maccabees", chapter: 14, verse: 43, text: "But missing his stroke through haste, the multitude also rushing within the doors, he ran boldly up to the wall, and cast himself down manfully among the thickest of them." },
  { book: "2 Maccabees", chapter: 14, verse: 44, text: "But they quickly giving back, and a space being made, he fell down into the midst of the void place." },
  { book: "2 Maccabees", chapter: 14, verse: 45, text: "Nevertheless, while there was yet breath within him, being inflamed with anger, he rose up; and though his blood gushed out like spouts of water, and his wounds were grievous, yet he ran through the midst of the throng; and standing upon a steep rock," },
  { book: "2 Maccabees", chapter: 14, verse: 46, text: "When as his blood was now quite gone, he plucked out his bowels, and taking them in both his hands, he cast them upon the throng, and calling upon the Lord of life and spirit to restore him those again, he thus died." },
  { book: "2 Maccabees", chapter: 15, verse: 1, text: "But Nicanor, hearing that Judas and his company were in the strong places about Samaria, resolved without any danger to set upon them on the sabbath day." },
  { book: "2 Maccabees", chapter: 15, verse: 2, text: "Nevertheless the Jews that were compelled to go with him said, O destroy not so cruelly and barbarously, but give honour to that day, which he, that seeth all things, hath honoured with holiness above all other days." },
  { book: "2 Maccabees", chapter: 15, verse: 3, text: "Then the most ungracious wretch demanded, if there were a Mighty one in heaven, that had commanded the sabbath day to be kept." },
  { book: "2 Maccabees", chapter: 15, verse: 4, text: "And when they said, There is in heaven a living Lord, and mighty, who commanded the seventh day to be kept:" },
  { book: "2 Maccabees", chapter: 15, verse: 5, text: "Then said the other, And I also am mighty upon earth, and I command to take arms, and to do the king’s business. Yet he obtained not to have his wicked will done." },
  { book: "2 Maccabees", chapter: 15, verse: 6, text: "So Nicanor in exceeding pride and haughtiness determined to set up a publick monument of his victory over Judas and them that were with him." },
  { book: "2 Maccabees", chapter: 15, verse: 7, text: "But Maccabeus had ever sure confidence that the Lord would help him:" },
  { book: "2 Maccabees", chapter: 15, verse: 8, text: "Wherefore he exhorted his people not to fear the coming of the heathen against them, but to remember the help which in former times they had received from heaven, and now to expect the victory and aid, which should come unto them from the Almighty." },
  { book: "2 Maccabees", chapter: 15, verse: 9, text: "And so comforting them out of the law and the prophets, and withal putting them in mind of the battles that they won afore, he made them more cheerful." },
  { book: "2 Maccabees", chapter: 15, verse: 10, text: "And when he had stirred up their minds, he gave them their charge, shewing them therewithal the falsehood of the heathen, and the breach of oaths." },
  { book: "2 Maccabees", chapter: 15, verse: 11, text: "Thus he armed every one of them, not so much with defence of shields and spears, as with comfortable and good words: and beside that, he told them a dream worthy to be believed, as if it had been so indeed, which did not a little rejoice them." },
  { book: "2 Maccabees", chapter: 15, verse: 12, text: "And this was his vision: That Onias, who had been high priest, a virtuous and a good man, reverend in conversation, gentle in condition, well spoken also, and exercised from a child in all points of virtue, holding up his hands prayed for the whole body of the Jews." },
  { book: "2 Maccabees", chapter: 15, verse: 13, text: "This done, in like manner there appeared a man with gray hairs, and exceeding glorious, who was of a wonderful and excellent majesty." },
  { book: "2 Maccabees", chapter: 15, verse: 14, text: "Then Onias answered, saying, This is a lover of the brethren, who prayeth much for the people, and for the holy city, to wit, Jeremias the prophet of God." },
  { book: "2 Maccabees", chapter: 15, verse: 15, text: "Whereupon Jeremias holding forth his right hand gave to Judas a sword of gold, and in giving it spake thus," },
  { book: "2 Maccabees", chapter: 15, verse: 16, text: "Take this holy sword, a gift from God, with the which thou shalt wound the adversaries." },
  { book: "2 Maccabees", chapter: 15, verse: 17, text: "Thus being well comforted by the words of Judas, which were very good, and able to stir them up to valour, and to encourage the hearts of the young men, they determined not to pitch camp, but courageously to set upon them, and manfully to try the matter by conflict, because the city and the sanctuary and the temple were in danger." },
  { book: "2 Maccabees", chapter: 15, verse: 18, text: "For the care that they took for their wives, and their children, their brethren, and folks, was in least account with them: but the greatest and principal fear was for the holy temple." },
  { book: "2 Maccabees", chapter: 15, verse: 19, text: "Also they that were in the city took not the least care, being troubled for the conflict abroad." },
  { book: "2 Maccabees", chapter: 15, verse: 20, text: "And now, when as all looked what should be the trial, and the enemies were already come near, and the army was set in array, and the beasts conveniently placed, and the horsemen set in wings," },
  { book: "2 Maccabees", chapter: 15, verse: 21, text: "Maccabeus seeing the coming of the multitude, and the divers preparations of armour, and the fierceness of the beasts, stretched out his hands toward heaven, and called upon the Lord that worketh wonders, knowing that victory cometh not by arms, but even as it seemeth good to him, he giveth it to such as are worthy:" },
  { book: "2 Maccabees", chapter: 15, verse: 22, text: "Therefore in his prayer he said after this manner; O Lord, thou didst send thine angel in the time of Ezekias king of Judea, and didst slay in the host of Sennacherib an hundred fourscore and five thousand:" },
  { book: "2 Maccabees", chapter: 15, verse: 23, text: "Wherefore now also, O Lord of heaven, send a good angel before us for a fear and dread unto them;" },
  { book: "2 Maccabees", chapter: 15, verse: 24, text: "And through the might of thine arm let those be stricken with terror, that come against thy holy people to blaspheme. And he ended thus." },
  { book: "2 Maccabees", chapter: 15, verse: 25, text: "Then Nicanor and they that were with him came forward with trumpets and songs." },
  { book: "2 Maccabees", chapter: 15, verse: 26, text: "But Judas and his company encountered the enemies with invocation and prayer." },
  { book: "2 Maccabees", chapter: 15, verse: 27, text: "So that fighting with their hands, and praying unto God with their hearts, they slew no less than thirty and five thousand men: for through the appearance of God they were greatly cheered." },
  { book: "2 Maccabees", chapter: 15, verse: 28, text: "Now when the battle was done, returning again with joy, they knew that Nicanor lay dead in his harness." },
  { book: "2 Maccabees", chapter: 15, verse: 29, text: "Then they made a great shout and a noise, praising the Almighty in their own language." },
  { book: "2 Maccabees", chapter: 15, verse: 30, text: "And Judas, who was ever the chief defender of the citizens both in body and mind, and who continued his love toward his countrymen all his life, commanded to strike off Nicanor’s head, and his hand with his shoulder, and bring them to Jerusalem." },
  { book: "2 Maccabees", chapter: 15, verse: 31, text: "So when he was there, and called them of his nation together, and set the priests before the altar, he sent for them that were of the tower," },
  { book: "2 Maccabees", chapter: 15, verse: 32, text: "And shewed them vile Nicanor’s head, and the hand of that blasphemer, which with proud brags he had stretched out against the holy temple of the Almighty." },
  { book: "2 Maccabees", chapter: 15, verse: 33, text: "And when he had cut out the tongue of that ungodly Nicanor, he commanded that they should give it by pieces unto the fowls, and hang up the reward of his madness before the temple." },
  { book: "2 Maccabees", chapter: 15, verse: 34, text: "So every man praised toward the heaven the glorious Lord, saying, Blessed be he that hath kept his own place undefiled." },
  { book: "2 Maccabees", chapter: 15, verse: 35, text: "He hanged also Nicanor’s head upon the tower, an evident and manifest sign unto all of the help of the Lord." },
  { book: "2 Maccabees", chapter: 15, verse: 36, text: "And they ordained all with a common decree in no case to let that day pass without solemnity, but to celebrate the thirtieth day of the twelfth month, which in the Syrian tongue is called Adar, the day before Mardocheus’ day." },
  { book: "2 Maccabees", chapter: 15, verse: 37, text: "Thus went it with Nicanor: and from that time forth the Hebrews had the city in their power. And here will I make an end." },
  { book: "2 Maccabees", chapter: 15, verse: 38, text: "And if I have done well, and as is fitting the story, it is that which I desired: but if slenderly and meanly, it is that which I could attain unto." },
  { book: "2 Maccabees", chapter: 15, verse: 39, text: "For as it is hurtful to drink wine or water alone; and as wine mingled with water is pleasant, and delighteth the taste: even so speech finely framed delighteth the ears of them that read the story. And here shall be an end." },
  // 2 Meqabyan (421 verses)
  { book: "2 Meqabyan", chapter: 1, verse: 1, text: "This is a book that tells how Meqabees found the Israelites in Mesopotamia, which is part of Syria, and killed them in that region, beginning from Jabbok all the way to the square of Jerusalem; and it tells how he destroyed the country." },
  { book: "2 Meqabyan", chapter: 1, verse: 2, text: "Because the Syrians, the Edomites, and the Amalekites were united with the Moabite man, Meqabees, who destroyed the land of Jerusalem—for they camped from Samaria to the square of Jerusalem and throughout its entire region—they killed in war, sparing no one except a few people who fled." },
  { book: "2 Meqabyan", chapter: 1, verse: 3, text: "When the children of Israel did wrong, the Lord aroused Meqabees, the man of Moab, against them, and he killed them with the sword." },
  { book: "2 Meqabyan", chapter: 1, verse: 4, text: "Because of this, the enemies of the Lord and the nations bragged over His honored country and swore by their crimes." },
  { book: "2 Meqabyan", chapter: 1, verse: 5, text: "The Philistines and the Edomites camped there; the Lord sent them because the people had been hypocritical regarding His Word, and they began to take revenge and destroy the Lord’s land." },
  { book: "2 Meqabyan", chapter: 1, verse: 6, text: "The country of Meqabees is Riemat, which is part of Moab; he arose from his country with power, and those with him also swore oaths." },
  { book: "2 Meqabyan", chapter: 1, verse: 7, text: "They camped in the region of Gilead, which is the lot of Mesopotamia up to Syria, so that they might destroy the Lord’s land. There, he begged the Amalekites and Philistines for help, giving them much silver, gold, chariots, and horses to be one with him in his crime." },
  { book: "2 Meqabyan", chapter: 1, verse: 8, text: "They came together and crushed the fortress; those who lived in it shed blood like water." },
  { book: "2 Meqabyan", chapter: 1, verse: 9, text: "They made Jerusalem like a hut in a vineyard (a temporary shelter); he made a voice heard within it and performed all the sinful works the Lord hates. They also defiled the Lord’s land, which was once filled with praise and honor." },
  { book: "2 Meqabyan", chapter: 1, verse: 10, text: "They made the flesh of your friends and the corpses of your servants food for the beasts of the wilderness and the birds of heaven." },
  { book: "2 Meqabyan", chapter: 1, verse: 11, text: "They robbed the orphans and the widows; without fearing the Lord, they acted as Satan taught them. Until the Lord, who examines the kidneys and the mind, was provoked to anger, they even ripped fetuses out of the bellies of pregnant women." },
  { book: "2 Meqabyan", chapter: 1, verse: 12, text: "They returned to their own country rejoicing because they had worked evil against the Lord’s people, taking the plunder they captured from the honored land." },
  { book: "2 Meqabyan", chapter: 1, verse: 13, text: "When they returned and entered their houses, they made celebrations, songs, and clapping." },
  { book: "2 Meqabyan", chapter: 2, verse: 1, text: "The prophet called Re`ay told him this: \"Rejoice today for a little while during your celebrations; but the Lord, whom Israel glorified, shall take revenge and destroy you in the punishment you did not doubt.\"" },
  { book: "2 Meqabyan", chapter: 2, verse: 2, text: "Will you say, ‘My horses are swift, and therefore I will escape by running’?" },
  { book: "2 Meqabyan", chapter: 2, verse: 3, text: "I tell you: the people who follow you are swifter than vultures. You will not escape from the Lord’s judgment and the destruction that shall come upon you." },
  { book: "2 Meqabyan", chapter: 2, verse: 4, text: "Will you say, ‘I wear iron clothes, so spears and bows cannot hurt me’? The Lord who honors Israel said: \"It is not by spears that I will take revenge and destroy you.\" He told him, \"I shall bring upon you heart sickness, itching, and rheumatism—sicknesses worse and firmer than the throw of a spear or the sting of a bow. Yet even by these things, I will not finish My revenge.\"" },
  { book: "2 Meqabyan", chapter: 2, verse: 5, text: "\"You have aroused My anger. I shall bring heart sickness upon you; you will lack anyone to help you, and you will not escape from My authority until I destroy the memory of your name from this world.\"" },
  { book: "2 Meqabyan", chapter: 2, verse: 6, text: "\"Because you hardened your mind and elevated yourself over My country, when I quickly do this thing in the blink of an eye, you will know that I was your Creator. You are before Me like grass before the wind that fire consumes, and like the dust that the wind scatters from the earth.\"" },
  { book: "2 Meqabyan", chapter: 2, verse: 7, text: "For you have aroused My anger and did not acknowledge your Creator; I shall neglect all your kindred, and I will not spare anyone who approaches your fortress." },
  { book: "2 Meqabyan", chapter: 2, verse: 8, text: "\"And now, turn away from all the sin you have committed. If you turn from your sin and seek peace in mourning and sadness before the Lord—if you beg Him with a clean mind—the Lord will forgive you all the sins you committed before Him,\" he told him." },
  { book: "2 Meqabyan", chapter: 2, verse: 9, text: "At that time, Meqabees wore dust and mourned before the Lord because of his sin, for the Lord was angry with him." },
  { book: "2 Meqabyan", chapter: 2, verse: 10, text: "For His eyes are revealed and He does not withhold; His ears are opened and He does not neglect. He does not make the word He spoke false, and He performs it quickly, for the Lord knew He would not hold back the punishment He spoke through the prophet’s word." },
  { book: "2 Meqabyan", chapter: 2, verse: 11, text: "He cast off his clothes, wore sackcloth, sprinkled dust on his head, and cried and wept before his Creator, the Lord, because of the sin he had committed." },
  { book: "2 Meqabyan", chapter: 3, verse: 1, text: "And the prophet came from Riemat and spoke to him (for Riemat, which is part of Moab, is near Syria)." },
  { book: "2 Meqabyan", chapter: 3, verse: 2, text: "He (Meqabees) dug a pit and entered it up to his neck, weeping bitter tears; he entered into repentance because of the sin he had committed before the Lord." },
  { book: "2 Meqabyan", chapter: 3, verse: 3, text: "And the Lord told the prophet: \"Return from the land of Judah to Riemat, to the Moabite official Meqabees. Tell him, 'The Lord says this to you.' Tell him, 'I, the Lord your Creator, sent you by My own Will to destroy My country. Do not say, \"I destroyed the honored city, Jerusalem, by the strength of my own power and the abundance of my army,\" for it was not you who did this thing.'\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 4, text: "\"For that city saddened Me with all its greed, treachery, and lustfulness.\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 5, text: "\"I neglected and cast her away by your hand. And now, the Lord has forgiven your sin because of the children you have fathered. It is not because of you, who hardened your mind and said, 'I encircled Jerusalem by my own authority and strength.'\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 6, text: "\"As those who doubt are not disciplined enough to enter repentance, do not be a doubter; enter into repentance now, being disciplined in your entire mind.\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 7, text: "However, those who enter into repentance with their whole mind and do not return to their old desires and sins are admired among all who have repented." },
  { book: "2 Meqabyan", chapter: 3, verse: 8, text: "Those who return to their Creator, the Lord, with discipline, mourning, sadness, bowing, and many pleas are admired. For He told them: \"You are My wealth, you who entered repentance after misleading others who repented.\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 9, text: "He told the arrogant Meqabees when he returned to Him in repentance after being misled: \"I forgive your sin because of your fear and alarm; for I am the Lord your Creator, who brings hardship upon children for the father's sin up to seven generations if the child continues in the father's sin, but who shows mercy up to ten thousand generations for those who love Me and keep My Law.\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 10, text: "\"And now I will establish My oath with you because of these children you have fathered.\" The Lord who rules all and honors Israel said: \"I will accept the repentance you made for the sin you committed.\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 11, text: "At that time, he came out of the pit and bowed to the prophet. He swore, saying: \"As I have saddened the Lord, let me do what you desire; let the Lord do so to me if I separate from you. As we had no Law, I did not live firmly in His Command like my fathers. You know that our fathers taught us to worship idols.\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 12, text: "\"I am a sinner who lived firmly in my sin, in the hardness of my mind and the arrogance of my thoughts, by which I saddened the Command of the Lord. But until now, I had not heard the word of the Lord’s servants, the prophets, and I did not live by the Law and the Command He gave me.\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 13, text: "The prophet told him, \"As there were none from your kindred before you who confessed their sin, I know that the Lord has received your repentance today.\"" },
  { book: "2 Meqabyan", chapter: 3, verse: 14, text: "\"But now, leave your idol worship and return to knowing the Lord so that your repentance may be true,\" he told him. He fell and bowed at the prophet's feet, and the prophet lifted him up and instructed him in all the good works required of him." },
  { book: "2 Meqabyan", chapter: 3, verse: 15, text: "And he returned to his house, doing exactly as the Lord commanded him." },
  { book: "2 Meqabyan", chapter: 3, verse: 16, text: "Meqabees turned his body to the worship of the Lord; he removed from his house the idols, the sorcery, the idol worshippers, the diviners, and the magicians." },
  { book: "2 Meqabyan", chapter: 3, verse: 17, text: "Morning and evening, just as the fathers do, he would examine the children he had captured and brought from Jerusalem in all the Lord’s Commands, His Order, and His Law." },
  { book: "2 Meqabyan", chapter: 3, verse: 18, text: "From the children he had captured, he appointed knowledgeable ones over his house." },
  { book: "2 Meqabyan", chapter: 3, verse: 19, text: "He also appointed knowledgeable children to teach the smaller children, showing them the bedding where they might learn the Law of the Lord that the children of Israel follow. He would hear from the captured children of Israel the Order, the Law, and the Nine Laws, realizing that the orders of the Moabites and the mosques they built were in vain." },
  { book: "2 Meqabyan", chapter: 3, verse: 20, text: "He destroyed those mosques, the idols, and the sorcery, as well as the sacrifices of goats and fattened sheep offered to idols morning and evening." },
  { book: "2 Meqabyan", chapter: 3, verse: 21, text: "He destroyed the idols he used to worship and believe in, those he sacrificed to at noon and in the afternoon, following the priests and the idols' desires." },
  { book: "2 Meqabyan", chapter: 3, verse: 22, text: "Previously, it seemed to him that they saved him in all things, and he did not scorn anything they told him." },
  { book: "2 Meqabyan", chapter: 3, verse: 23, text: "But Meqabees quit those works." },
  { book: "2 Meqabyan", chapter: 3, verse: 24, text: "After he heard the words of Ra`ay (the prophet), he completed his work in repentance. Even as the children of Israel would sadden the Lord, and then cry out to Him when He punished them with tribulation—all his people worked better deeds than the children of Israel did in that season." },
  { book: "2 Meqabyan", chapter: 3, verse: 25, text: "When the Lord heard that they were seized and abused by the nations who brought tribulation upon them, and that they cried to Him, He remembered the oath of their fathers; He would forgive them because of Isaac, Abraham, and Jacob." },
  { book: "2 Meqabyan", chapter: 3, verse: 26, text: "But when He saved them, they would forget the Lord who saved them from tribulation and return to worshipping idols." },
  { book: "2 Meqabyan", chapter: 3, verse: 27, text: "Then He would arouse nations against them to bring tribulation. When they were saddened by this, they would cry to the Lord; because He loved them as His own creation, He would be kind and forgive them." },
  { book: "2 Meqabyan", chapter: 3, verse: 28, text: "But once He protected them, they again returned to sin, saddening Him with the work of their hands and worshipping idols in their councils." },
  { book: "2 Meqabyan", chapter: 3, verse: 29, text: "So He would arouse against them the Moabites, Philistines, Syrians, Midianites, and Egyptians. When these enemies defeated them, they would cry and weep. When they were taxed and ruled over, the Lord would arouse princes for them to save them in the time He chose." },
  { book: "2 Meqabyan", chapter: 4, verse: 1, text: "In the time of Joshua, there was a day when the Lord saved them." },
  { book: "2 Meqabyan", chapter: 4, verse: 2, text: "In the time of Gideon, there was a day when He saved them." },
  { book: "2 Meqabyan", chapter: 4, verse: 3, text: "In the time of Samson, and in the time of Deborah, Barak, and Judith, there were days when He saved them. Whether concerning a son or a daughter, He would raise up princes for them so they might be saved from the hands of their enemies who brought tribulation upon them." },
  { book: "2 Meqabyan", chapter: 4, verse: 4, text: "And because God loved them, He would save them from those who brought tribulation upon them." },
  { book: "2 Meqabyan", chapter: 4, verse: 5, text: "They would be totally at peace in all the work He accomplished for them; they were peaceful in their land, in their seed, and in the multiplying of all their flocks in the wilderness and their livestock." },
  { book: "2 Meqabyan", chapter: 4, verse: 6, text: "He would bless their plants and their livestock for them, for He looked upon them with an Eye of Mercy. He would not diminish their livestock, for they were the children of kind persons, and He loved them completely." },
  { book: "2 Meqabyan", chapter: 4, verse: 7, text: "But at the time they were evil in their works, He would cast them into the hands of their enemies." },
  { book: "2 Meqabyan", chapter: 4, verse: 8, text: "And when He destroyed them, they would seek Him in worship; they would return from sin and walk toward God in repentance." },
  { book: "2 Meqabyan", chapter: 4, verse: 9, text: "And when they returned with their complete reasoning, He would atone for their sins. He would not remember their former sins against them, for He knew they were flesh and blood, that they had the misleading thoughts of this world, and that they had demons in them." },
  { book: "2 Meqabyan", chapter: 4, verse: 10, text: "But when Meqabees heard of this Order that the Lord worked in His place of worship, the Temple, he was moved to repentance." },
  { book: "2 Meqabyan", chapter: 4, verse: 11, text: "After he saw and heard this, he did not scorn doing good works; he did not scorn doing all the good works that the children of Israel did when the Lord forgave them. After they trespassed against His Law, they would weep and cry when the Lord chastised them, and again He would forgive them, and they would keep His Law." },
  { book: "2 Meqabyan", chapter: 4, verse: 12, text: "Meqabees likewise straightened his works; he kept His Law, and he lived firmly in the commands of the Lord, the Creator of Israel." },
  { book: "2 Meqabyan", chapter: 4, verse: 13, text: "At that time, after he heard all the works in which the children of Israel boast, he boasted like them in keeping the Law of the Lord." },
  { book: "2 Meqabyan", chapter: 4, verse: 14, text: "He urged his kindred and children to live firmly in the commands of the Lord and all His Law." },
  { book: "2 Meqabyan", chapter: 4, verse: 15, text: "He forbade what Israel forbade, and he heard and kept the Law that Israel kept. Even though his kindred was of the people of Moab, he forbade the food that Israel forbade." },
  { book: "2 Meqabyan", chapter: 4, verse: 16, text: "He sent forth tithes; he gave the firstborn of all he owned from his cows, sheep, and donkeys. Turning his face toward Jerusalem, he offered the sacrifices that Israel sacrificed." },
  { book: "2 Meqabyan", chapter: 4, verse: 17, text: "He offered sin offerings and vow sacrifices—sacrifices by which welfare is done, peace offerings, and the continual sacrifice." },
  { book: "2 Meqabyan", chapter: 4, verse: 18, text: "He gave his first crops; he crushed and poured the grapes as Israel pours them. He gave these to the priest whom he had appointed, and likewise, he did all that Israel does, and he offered sweet incense." },
  { book: "2 Meqabyan", chapter: 4, verse: 19, text: "He built a candlestick, a bowl, a seat, a tent, and the four links of rings. He provided pure oil for the lamps of the Holy of Holies and the curtain that Israel made in the Holy of Holies when they served the Lord." },
  { book: "2 Meqabyan", chapter: 4, verse: 20, text: "Just as they did good works while they lived firmly in His Order and Law—and the Lord did not neglect them or cast them into their enemies' hands—Meqabees also did good works like them." },
  { book: "2 Meqabyan", chapter: 4, verse: 21, text: "He prayed to the Lord, the Creator of Israel, every time, that He might be his Teacher and not separate him from the children of Israel whom He chose and who kept His Covenant." },
  { book: "2 Meqabyan", chapter: 4, verse: 22, text: "Again he prayed that He might give his children a place in Zion and a house in Jerusalem—that He might give them a Heavenly Seed of Virtue in Zion and a Heavenly House of the Soul in Jerusalem—and that He might save him from the destruction spoken by the tongue of the prophets, accepting his repentance and the mourning he wept before the Lord." },
  { book: "2 Meqabyan", chapter: 4, verse: 23, text: "He prayed that the Lord would not destroy his children in this world and that He would keep him in his going out and his coming in." },
  { book: "2 Meqabyan", chapter: 4, verse: 24, text: "The kindred of the Moabite people under the authority of Meqabees were pleased to believe, for their chief lived firmly in straight works. They observed his judgment and fulfilled his covenant; they rejected their own country’s language and laws, understanding that the work of Meqabees was superior and righteous." },
  { book: "2 Meqabyan", chapter: 4, verse: 25, text: "They would come to hear the charity and truthful judgments of Meqabees." },
  { book: "2 Meqabyan", chapter: 4, verse: 26, text: "He had much wealth; he had female and male slaves, camels, and donkeys. He had five hundred horses that wore breastplates. He totally defeated the Amalekites, the Philistines, and the Syrians; yet formerly, when he worshipped idols, they defeated him." },
  { book: "2 Meqabyan", chapter: 4, verse: 27, text: "He prevailed from the time he began worshipping the Lord onward; when he went to battle, no one defeated him." },
  { book: "2 Meqabyan", chapter: 4, verse: 28, text: "His enemies would come in the power of their idols to fight him; they would call on their idols' names and curse him. However, none defeated him, for he placed his faith in the Lord, his Creator." },
  { book: "2 Meqabyan", chapter: 4, verse: 29, text: "When he did this and defeated his enemies, he ruled the people under his authority." },
  { book: "2 Meqabyan", chapter: 4, verse: 30, text: "He would take revenge and destroy the enemies of the wronged; he judged with truth for the child whose mother and father were dead." },
  { book: "2 Meqabyan", chapter: 4, verse: 31, text: "He would receive widows in their time of trouble; he gave his food to satisfy the hungry and clothed the naked with his own clothes." },
  { book: "2 Meqabyan", chapter: 4, verse: 32, text: "He was pleased with the work of his hands; he gave money without grudging and gave tithes to the Temple. Meqabees died having lived in righteousness while doing these things." },
  { book: "2 Meqabyan", chapter: 5, verse: 1, text: "He died leaving his children who were small, and they grew up as their father taught them. They kept the order of their house and cared for all their kindred; they did not make the poor cry, nor the widows, nor the orphan." },
  { book: "2 Meqabyan", chapter: 5, verse: 2, text: "They feared the Lord and gave alms to the poor. They kept all the trusts their father told them. They comforted the orphans and widows in their trouble, acting as their mother and father. They rescued them from the hands of those who wronged them and calmed them from all the disturbance and sadness they found." },
  { book: "2 Meqabyan", chapter: 5, verse: 3, text: "They lived for five years while doing these things." },
  { book: "2 Meqabyan", chapter: 5, verse: 4, text: "After this, the Chaldean king, Tseerutsaydan, came. He destroyed their whole country, captured the children of Meqabees, and destroyed all their villages." },
  { book: "2 Meqabyan", chapter: 5, verse: 5, text: "He plundered all their money. The invaders lived firmly in all evil works and sin—in adultery, insult, and greed, not thinking of their Creator. Those who did not live by the Law of God and His Command, and who worshipped idols, seized them and took them to their own country." },
  { book: "2 Meqabyan", chapter: 5, verse: 6, text: "They ate what a beast had bitten, blood, and carcasses—everything that a scavenger kills and casts away, all that the Lord does not love. They had no order from the true Commands written in the Law (Torah/Oreet)." },
  { book: "2 Meqabyan", chapter: 5, verse: 7, text: "They did not know the Lord their Creator, who brought them forth from their mothers' wombs and fed them what was due, and who was their Medicine." },
  { book: "2 Meqabyan", chapter: 5, verse: 8, text: "They married their aunts and their father’s wives (stepmothers); they turned to robbery, evil, sin, and adultery. They have no order in the time of Judgment. They work all evil; they marry their aunts and sisters and have no Law." },
  { book: "2 Meqabyan", chapter: 5, verse: 9, text: "All their roads are dark and slippery, and their work is sin and adultery." },
  { book: "2 Meqabyan", chapter: 5, verse: 10, text: "But the children of Meqabees kept their Order; they would not eat what a scavenger killed nor what was found dead. They would not do the works that the children of the Chaldeans did, for many of their works are evil and were not written in this book—works done by sinners, doubters, criminals, and betrayers, totally filled with robbery and sin like the children of pagans." },
  { book: "2 Meqabyan", chapter: 5, verse: 11, text: "All the works the Lord God loves were not found among them." },
  { book: "2 Meqabyan", chapter: 5, verse: 12, text: "Furthermore, they would worship an idol called Baal-Peor; they trusted it as if it were the Lord their Creator, even though it was deaf and dumb. For it is an idol that a human hand worked; it is the work of a smith who works silver and gold—it has no breath or knowledge, and it has nothing it can see or hear." },
  { book: "2 Meqabyan", chapter: 5, verse: 13, text: "It does not eat or drink." },
  { book: "2 Meqabyan", chapter: 5, verse: 14, text: "It does not kill or save." },
  { book: "2 Meqabyan", chapter: 5, verse: 15, text: "It does not plant or uproot." },
  { book: "2 Meqabyan", chapter: 5, verse: 16, text: "It does not harm its enemy or benefit its friend." },
  { book: "2 Meqabyan", chapter: 5, verse: 17, text: "It does not impoverish or honor." },
  { book: "2 Meqabyan", chapter: 5, verse: 18, text: "It is a hindrance that misleads the lazy Chaldeans; yet it does not chastise or forgive." },
  { book: "2 Meqabyan", chapter: 6, verse: 1, text: "The enemy of God, Tseerutsaydan, who was arrogant, appointed priests of falsehood and vanity for his idols." },
  { book: "2 Meqabyan", chapter: 6, verse: 2, text: "He would offer sacrifices to them and pour out wine (grapes) for them." },
  { book: "2 Meqabyan", chapter: 6, verse: 3, text: "And it seemed to him as if the idols were actually eating and drinking." },
  { book: "2 Meqabyan", chapter: 6, verse: 4, text: "When dawn broke, he would give them cows, donkeys, and heifers; he offered sacrifices morning and evening, and he himself would eat from those defiled sacrifices." },
  { book: "2 Meqabyan", chapter: 6, verse: 5, text: "Furthermore, he would harass and force other people to sacrifice to his idols; it was not only he and his followers who did so." },
  { book: "2 Meqabyan", chapter: 6, verse: 6, text: "When they saw that the children of Meqabees were handsome and that they worshipped their Creator, the Lord, the idol priests desired to mislead them into offering sacrifices and eating from those hated offerings; but these honored children of Meqabees refused them." },
  { book: "2 Meqabyan", chapter: 6, verse: 7, text: "Because they kept their father’s command, remained firm in doing good works, and totally feared the Lord, they refused to agree." },
  { book: "2 Meqabyan", chapter: 6, verse: 8, text: "Consequently, the priests bound them, insulted them, and robbed them." },
  { book: "2 Meqabyan", chapter: 6, verse: 9, text: "They told King Tseerutsaydan that the children refused to sacrifice or bow down to his idols." },
  { book: "2 Meqabyan", chapter: 6, verse: 10, text: "Because of this, the king was provoked to anger; he was grieved and commanded that they be brought before him. When they stood before him, the king said to them regarding his idols, \"Offer a sacrifice to my idols.\"" },
  { book: "2 Meqabyan", chapter: 6, verse: 11, text: "But they spoke and told him, \"We will not answer you in this matter, and we will not offer sacrifices to your defiled idols.\"" },
  { book: "2 Meqabyan", chapter: 6, verse: 12, text: "He tried to terrify them with many threats, yet he was unable to overcome them, for they had disciplined their minds through faith in the Lord." },
  { book: "2 Meqabyan", chapter: 6, verse: 13, text: "He lit a fire and cast them into it, and they gave up their bodies for the Lord." },
  { book: "2 Meqabyan", chapter: 6, verse: 14, text: "After they died, they arose and appeared to him at night, drawing their swords while he reclined on his royal throne; and he was struck with total fear." },
  { book: "2 Meqabyan", chapter: 6, verse: 15, text: "He said, \"My lords—tell me truly—what should I do for you? Do not take my life in death, and I will do all that you command me.\"" },
  { book: "2 Meqabyan", chapter: 6, verse: 16, text: "They told him all that was required of him, saying, \"Remember that the Lord was your Creator. It is the Lord who shall remove you from this kingdom where you are arrogant, and who shall cast you down into the Gehenna of Fire with your father, the Devil. Since we worshipped our Creator, the Lord, without iniquity and did you no wrong, yet we bowed to Him in fear of His Divinity—just as you burned us in the fire, you will also meet your end through that same fire.\"" },
  { book: "2 Meqabyan", chapter: 6, verse: 17, text: "For He is the one who created all things: the Earth, the Heaven, the sea, and everything within them." },
  { book: "2 Meqabyan", chapter: 6, verse: 18, text: "And He is the one who created the moon, the sun, and the stars; the Lord is the author of all creation." },
  { book: "2 Meqabyan", chapter: 6, verse: 19, text: "For there is no other creator besides Him in Earth or Heaven; He is capable of all things, and nothing is impossible for Him. Since He is the one who kills and saves, who strikes with tribulation and who forgives—because we bowed to Him in fear of the Lord, yet you burned us in fire—you will finish your hardship in that same way,\" they told him." },
  { book: "2 Meqabyan", chapter: 6, verse: 20, text: "\"As He is the one who rules Earth and Heaven, there is no one who can escape from His authority." },
  { book: "2 Meqabyan", chapter: 6, verse: 21, text: "None of the creation He made has departed from His command, except for you, who are a criminal; and criminals like you, whose reasoning has been hidden by your father Satan. You, your priests, and your idols will descend together into Gehenna, where there is no exit for all eternity." },
  { book: "2 Meqabyan", chapter: 6, verse: 22, text: "Your teacher is Satan, who taught you this evil work so that you might do evil against us; yet since it is not only you who does this, you will all descend into Gehenna together." },
  { book: "2 Meqabyan", chapter: 6, verse: 23, text: "For you make your own self like your Creator, the Lord, yet you did not know the Lord who created you." },
  { book: "2 Meqabyan", chapter: 6, verse: 24, text: "You are arrogant in your idols and the work of your hands, until the Lord makes you wretched. He shall convict you of all your sin and iniquity that you worked in this world.\"" },
  { book: "2 Meqabyan", chapter: 7, verse: 1, text: "Woe to you who do not know the Lord who created you; woe to your idols which are like you; woe to you all. You shall feel a regret that will not profit you when you are seized in the distress of Sheol (the underworld). Woe to you who do not keep His Word and His Law." },
  { book: "2 Meqabyan", chapter: 7, verse: 2, text: "You will have no exit from there for eternity—you and your priests who sacrifice to idols as if they were your Creator, the Lord. For your idols have no breath or soul; they will not take revenge or destroy those who do evil to them, nor will they do good for those who do good to them." },
  { book: "2 Meqabyan", chapter: 7, verse: 3, text: "Woe to you who sacrifice to them, for they are the work of human hands where Satan lives, dwelling there to mislead the minds of lazy ones like you, so that he might lower you into the Gehenna of Fire—both you and the priests who serve the demons commanded for you and your idols." },
  { book: "2 Meqabyan", chapter: 7, verse: 4, text: "Because you do not know that nothing will profit you, you do wrong and you err." },
  { book: "2 Meqabyan", chapter: 7, verse: 5, text: "As for the animals that the Lord created to be food for you—even dogs and beasts—they are better than you; for besides their one death, there is no further condemnation upon them." },
  { book: "2 Meqabyan", chapter: 7, verse: 6, text: "But since you will die and receive hardship in the fire of Gehenna where there is no exit for all eternity, the animals are better off than you.\"" },
  { book: "2 Meqabyan", chapter: 7, verse: 7, text: "Having spoken this, they departed and were hidden from him." },
  { book: "2 Meqabyan", chapter: 7, verse: 8, text: "But Tseerutsaydan remained where he was, trembling and seized by a deep terror; and that fright did not leave him until dawn." },
  { book: "2 Meqabyan", chapter: 8, verse: 1, text: "He lived firmly established in the malice and arrogance of his mind." },
  { book: "2 Meqabyan", chapter: 8, verse: 2, text: "And as iron is called \"firm\"—just as Daniel saw it regarding his kingdom—he turned against the peoples and countries in his region." },
  { book: "2 Meqabyan", chapter: 8, verse: 3, text: "He lived firmly in evil, in all his laziness, and in the harassment of people." },
  { book: "2 Meqabyan", chapter: 8, verse: 4, text: "He totally destroyed what was spoken of formerly, and he consumed the wealth of others." },
  { book: "2 Meqabyan", chapter: 8, verse: 5, text: "For he was diligent in evil, like his father the Devil who strengthened his resolve (collar of reasoning), and he destroyed what remained with his army." },
  { book: "2 Meqabyan", chapter: 8, verse: 6, text: "He said, \"My era has become like the era of the Sun\"—yet he did not know the Lord was his Creator." },
  { book: "2 Meqabyan", chapter: 8, verse: 7, text: "And in his mind, he thought that the Sun originated from him." },
  { book: "2 Meqabyan", chapter: 8, verse: 8, text: "He rose up in power; he camped in the portion of the Tribe of Zebulun and began a military formation in Macedonia. He received his food from Samaria, and they gave him presents from Samaria." },
  { book: "2 Meqabyan", chapter: 8, verse: 9, text: "He camped in the regions of the nomads and reached as far as Sidon; he placed a tax upon Achaia and elevated his pride (collar of reasoning) as far as the flowing sea. He returned and sent messengers as far as the Indian Sea." },
  { book: "2 Meqabyan", chapter: 8, verse: 10, text: "And likewise, he elevated his pride even unto Heaven." },
  { book: "2 Meqabyan", chapter: 8, verse: 11, text: "He lived firmly in arrogance and evil, yet he would not humble his own self." },
  { book: "2 Meqabyan", chapter: 8, verse: 12, text: "His path led toward darkness, slipperiness, crime, and arrogance; toward the shedding of blood and tribulation." },
  { book: "2 Meqabyan", chapter: 8, verse: 13, text: "All his works were what the Lord hates. He acted according to the robbery and sin taught by his teacher, the Devil; he made the orphan cry and was not kind to the poor." },
  { book: "2 Meqabyan", chapter: 8, verse: 14, text: "He defeated and destroyed the kings of peoples by his authority." },
  { book: "2 Meqabyan", chapter: 8, verse: 15, text: "He ruled over the chiefs of enemies and many peoples, and he taxed them according to his own desire." },
  { book: "2 Meqabyan", chapter: 8, verse: 16, text: "Even if he destroyed, he did not stop; there was no person from whom he did not snatch wealth, from the Tarshish sea to the Jericho sea." },
  { book: "2 Meqabyan", chapter: 8, verse: 17, text: "He would bow to idols; he would eat what was found dead, blood, and what was cut by the sword and sacrificed to idols. All his work was without justice, for he had no justice. As he was one who terrified the people under his authority, he would tax them exactly as he pleased." },
  { book: "2 Meqabyan", chapter: 8, verse: 18, text: "As he did all that he desired, there was no fear of the Lord before him; he lived in malice before the Lord who created him." },
  { book: "2 Meqabyan", chapter: 8, verse: 19, text: "He did not act like his Creator; and just as he did evil to his companion when he was angry and seized him, the Lord shall also repay him with hardship." },
  { book: "2 Meqabyan", chapter: 8, verse: 20, text: "As the Lord has said: \"I shall take revenge and destroy sinful persons who do not live by My Command, so that I might destroy the mention of their name from this world.\" Just as He destroyed the peoples who preceded him, the Lord shall take revenge and destroy him when the time of destruction comes." },
  { book: "2 Meqabyan", chapter: 8, verse: 21, text: "And just as evil persons did evil things, they shall receive their hardship." },
  { book: "2 Meqabyan", chapter: 8, verse: 22, text: "But as commanded by the Lord, good works shall follow those who perform good works." },
  { book: "2 Meqabyan", chapter: 8, verse: 23, text: "For just as Joshua destroyed the five Canaanite kings in a cave in one day, and as he made the sun stand still in Gibeon by his prayer so that he might destroy their armies—the sun stood in the midst of heaven until he destroyed the armies of the Hivites, Canaanites, Perizzites, Hittites, and Jebusites—and just as he killed twenty thousand people at one time, and as he bound them, placing his foot on their necks, and as he killed them in the cave by the spear and placed a stone over them..." },
  { book: "2 Meqabyan", chapter: 8, verse: 24, text: "Tribulation like this shall find all persons who grieve the Lord with their evil works." },
  { book: "2 Meqabyan", chapter: 9, verse: 1, text: "O you weak man, who are not God—why are you proud? You who are seen today as a man are earthly ashes tomorrow, and you will be nothing but worms in your grave." },
  { book: "2 Meqabyan", chapter: 9, verse: 2, text: "For your teacher is the Devil, who brings the hardship of sin back upon himself because he misled our father, Adam. Sheol will find you, as it finds all who perform your sins." },
  { book: "2 Meqabyan", chapter: 9, verse: 3, text: "Because he strengthened his pride and made himself arrogant, he refused to bow before Adam, whom the Creator had made." },
  { book: "2 Meqabyan", chapter: 9, verse: 4, text: "You also have refused to bow before your Creator, the Lord, just as your teacher the Devil did." },
  { book: "2 Meqabyan", chapter: 9, verse: 5, text: "Like your ancestors before you, who did not know their Creator in worship and went toward Gehenna, you also will go toward Gehenna." },
  { book: "2 Meqabyan", chapter: 9, verse: 6, text: "Just as He took revenge and destroyed them because of the evil works they did in this world, and as they descended into Gehenna…" },
  { book: "2 Meqabyan", chapter: 9, verse: 7, text: "You also will descend into Gehenna just like them." },
  { book: "2 Meqabyan", chapter: 9, verse: 8, text: "Since you have aroused His anger and neglected to worship the Lord who gave you authority over the five kingdoms, do you think you will escape from the Lord’s authority?" },
  { book: "2 Meqabyan", chapter: 9, verse: 9, text: "You do not act according to His Will, and so He examines you. But if you do good works in this world, the Lord will accomplish all your work for you; He will complete and bless all the work you take into your hands. He will subject your ancient enemies and your present enemies to you." },
  { book: "2 Meqabyan", chapter: 9, verse: 10, text: "You will be at peace in your coming and going, in the children born of your nature, in your flocks, in your wealth, and in all work where you place your hand and all thoughts of your heart. As authority has been given to you from the Lord, all that you work, plant, or demolish will be commanded for you." },
  { book: "2 Meqabyan", chapter: 9, verse: 11, text: "However, if you will not hear the Word of the Lord nor live firmly in His Law—like the criminals who preceded you, who did not worship the Lord as is due and did not believe in His righteous Law—there is nothing by which you will escape the Lord’s authority, for the Lord’s judgment is Truth." },
  { book: "2 Meqabyan", chapter: 9, verse: 12, text: "All is totally revealed before Him; nothing is hidden from His sight." },
  { book: "2 Meqabyan", chapter: 9, verse: 13, text: "He is the one who takes away the authority of kings and overturns the thrones of the powerful." },
  { book: "2 Meqabyan", chapter: 9, verse: 14, text: "He is the one who elevates those who were brought low and lifts up those who have fallen." },
  { book: "2 Meqabyan", chapter: 9, verse: 15, text: "He is the one who looses the bound and raises the dead. As the dew of pardon is found with Him, in the time He chooses, He shall raise those whose flesh was destroyed and rotten and turned to dust." },
  { book: "2 Meqabyan", chapter: 9, verse: 16, text: "Having raised and judged those who worked evil, He will take them toward Gehenna, for they have grieved Him." },
  { book: "2 Meqabyan", chapter: 9, verse: 17, text: "For they are those who destroyed the Lord’s Order and His Law, and He will destroy their children from this world." },
  { book: "2 Meqabyan", chapter: 9, verse: 18, text: "As the work of kind persons is more difficult than the work of sinners, sinners do not love to live by the counsel of the righteous." },
  { book: "2 Meqabyan", chapter: 9, verse: 19, text: "As the Heavens are distant from the Earth, so is the work of the righteous distant from the work of evil persons." },
  { book: "2 Meqabyan", chapter: 9, verse: 20, text: "The work of sinners is robbery, sin, adultery, iniquity, greed, and treachery; it is being drunk on iniquity and stealing a person's money." },
  { book: "2 Meqabyan", chapter: 9, verse: 21, text: "It is the rushing toward the shedding of blood and toward useless destruction; it is making the orphan weep. It is the eating of blood, of animals found dead, and the flesh of camels and boars. It is going toward a woman in her blood before she is cleansed, or toward a woman in childbirth." },
  { book: "2 Meqabyan", chapter: 9, verse: 22, text: "All this is the work of sinners; it is the trap of Satan, a wide and prepared path that leads toward the eternal Gehenna and toward Sheol." },
  { book: "2 Meqabyan", chapter: 9, verse: 23, text: "But the path of the righteous is totally narrow; it leads toward welfare, innocence, humility, unity, and love. It involves prayer, fasting, and purity of the flesh; keeping away from what is useless, from eating what is strangled or found dead, and from adultery with another man’s wife." },
  { book: "2 Meqabyan", chapter: 9, verse: 24, text: "They keep from what was not commanded by the Law, from eating disgusting food, and from all hated works that the Lord does not love, for sinners do all these things." },
  { book: "2 Meqabyan", chapter: 9, verse: 25, text: "As for the righteous, they distance themselves from all works that the Lord does not love." },
  { book: "2 Meqabyan", chapter: 9, verse: 26, text: "He loves them and shall keep them from all their tribulation, guarding them like precious trust money." },
  { book: "2 Meqabyan", chapter: 9, verse: 27, text: "For they keep His Order and His Law and all that He loves; but Satan rules the sinners." },
  { book: "2 Meqabyan", chapter: 10, verse: 1, text: "Fear the Lord who created you and kept you until today; and you, the nobles and the kings, do not walk on the path of Satan." },
  { book: "2 Meqabyan", chapter: 10, verse: 2, text: "Live in the Law and Command of the Lord who rules all; do not walk on the path of Satan." },
  { book: "2 Meqabyan", chapter: 10, verse: 3, text: "As in the time when the children of Israel came toward Amalek to inherit the country of the Hittites, Canaanites, and Perizzites—Balak the son of Zippor and Balaam..." },
  { book: "2 Meqabyan", chapter: 10, verse: 4, text: "\"Whom you curse is cursed, and whom you bless is blessed.\" Do not go on Satan’s road, for he has said, \"I will give you much silver and gold to honor you, so that you might curse them for me, and having cursed them, destroy them for me.\"" },
  { book: "2 Meqabyan", chapter: 10, verse: 5, text: "For Balaam came making his reward for sorcery a motivation, and Balak the son of Zippor showed him the place where the children of Israel camped." },
  { book: "2 Meqabyan", chapter: 10, verse: 6, text: "For he performed his pessimism (divinations), offered his sacrifices, and slaughtered his fattened cows and sheep; for he desired to curse and destroy the children of Israel." },
  { book: "2 Meqabyan", chapter: 10, verse: 7, text: "But the curse was returned as a blessing; since the Lord did not wish for him to curse them by His Word, do not walk on the path of Satan." },
  { book: "2 Meqabyan", chapter: 10, verse: 8, text: "\"As you are the people the Lord chose, as you are the Lord’s Dwelling that shall come from Heaven, let those who curse you be cursed, and let those who bless you be blessed,\" he said." },
  { book: "2 Meqabyan", chapter: 10, verse: 9, text: "When he blessed them, Balak the son of Zippor was grieved and angry, and he commanded him again to curse them." },
  { book: "2 Meqabyan", chapter: 10, verse: 10, text: "For the people whom the Lord blessed had come to this country, and Balaam told him, \"I will not curse Israel, whom the Lord has blessed.\"" },
  { book: "2 Meqabyan", chapter: 10, verse: 11, text: "Balak said to Balaam, \"I desired that you would curse them for me, but you blessed them before me. If you had cursed them and asked me to give to you, I would have given you a house full of silver and gold. But you blessed them completely; you did nothing good for me, so I will do nothing good for you.\"" },
  { book: "2 Meqabyan", chapter: 10, verse: 12, text: "Balaam said, \"What the Lord tells me to speak with my tongue, I will speak; for I cannot dare to ignore the things of the Lord." },
  { book: "2 Meqabyan", chapter: 10, verse: 13, text: "I will not curse a blessed people, for the Lord shall be angry with me if I love money. I do not love money more than my soul." },
  { book: "2 Meqabyan", chapter: 10, verse: 14, text: "As the Lord told their father Jacob: 'Let those who bless you be blessed and those who curse you be cursed.' I will not curse the blessed Jacob; I do not love money more than my soul,\" he said. And as the Lord told him: \"He who blesses you is blessed...\"" },
  { book: "2 Meqabyan", chapter: 10, verse: 15, text: "\"...and a person who curses you unjustly is cursed.\" Complete your path and your work so that the Lord might love you." },
  { book: "2 Meqabyan", chapter: 10, verse: 16, text: "Do not be like those of old who grieved the Lord in their sin and whom He neglected—some of whom He destroyed in the Waters of Destruction (The Flood)." },
  { book: "2 Meqabyan", chapter: 10, verse: 17, text: "There are those whom He destroyed by the hands of their haters and enemies—evil persons who brought tribulation upon them, capturing their lords, priests, and prophets." },
  { book: "2 Meqabyan", chapter: 10, verse: 18, text: "They delivered them to a foreign country they did not know; they captured them, plundered their livestock, and destroyed their land." },
  { book: "2 Meqabyan", chapter: 10, verse: 19, text: "For they demolished the walls and ramparts of the honored city, Jerusalem, and they made Jerusalem like a plowed field." },
  { book: "2 Meqabyan", chapter: 10, verse: 20, text: "The priests were captured, the Law was demolished, and warriors fell in battle." },
  { book: "2 Meqabyan", chapter: 10, verse: 21, text: "The widows were captured; as they were taken, they wept for themselves, yet they did not weep for their dead husbands." },
  { book: "2 Meqabyan", chapter: 10, verse: 22, text: "The children wept and the elders were shamed; they showed no mercy to the grey-haired or the aged." },
  { book: "2 Meqabyan", chapter: 10, verse: 23, text: "They destroyed all they found in the country; they showed no mercy for beauty or for those in the Law. As the Lord was angry with His people, He permitted His Dwelling, the Temple, to be destroyed beforehand, and they were captured and taken to unknown countries and peoples." },
  { book: "2 Meqabyan", chapter: 10, verse: 24, text: "Because they grieved their Creator constantly, the Lord neglected the children of Israel and allowed Jerusalem to be plowed like a field." },
  { book: "2 Meqabyan", chapter: 10, verse: 25, text: "He is kind to them because of their fathers, but He did not destroy them all at once. Because He loved their fathers Isaac, Abraham, and Jacob—who reigned truly and lived firmly in the straight Law before their Creator—it is because of the fathers' kindness, and not their own, that He forgives them." },
  { book: "2 Meqabyan", chapter: 10, verse: 26, text: "And He appointed them to a twofold honor; they found two Kingdoms: on Earth and in Heaven." },
  { book: "2 Meqabyan", chapter: 10, verse: 27, text: "And you, the kings and nobles who live in this passing world: just as your fathers who lived firmly in the required work and preceded you inherited the Kingdom of Heaven—and as their names are beautiful to their children's children—think of them." },
  { book: "2 Meqabyan", chapter: 10, verse: 28, text: "And you, straighten your work, that He might straighten your Kingdom for you, and that your name might be remembered in a goodly way, like the righteous kings who preceded you and served the Lord with their beautiful lifestyles." },
  { book: "2 Meqabyan", chapter: 11, verse: 1, text: "Think of the Lord’s servant Moses, who was not angered when he kept this people in his humility and prayer, so that not even one person was destroyed. He prayed to the Lord in his innocence for his sister and brother who spoke against him and whom the Lord wished to destroy, saying: \"As they have wronged You, O Lord, pardon and do not neglect Your people.\" He atoned for their sin, for He remembered Moses, who was not annoyed." },
  { book: "2 Meqabyan", chapter: 11, verse: 2, text: "\"For I have wronged You; forgive me Your servant who am a sinner, for You are Merciful and a Pardoner; forgive them their sin.\"" },
  { book: "2 Meqabyan", chapter: 11, verse: 3, text: "And Moses likewise atoned for the sin of his sister and brother who spoke against him." },
  { book: "2 Meqabyan", chapter: 11, verse: 4, text: "Because of this, he was called innocent." },
  { book: "2 Meqabyan", chapter: 11, verse: 5, text: "The Lord loved him more than all the priests who were his brothers; for He appointed the priests, but the Lord made Moses like Himself among them." },
  { book: "2 Meqabyan", chapter: 11, verse: 6, text: "But He also sank into the Earth the children of Korah who challenged him; He lowered them into Sheol with their livestock and tents when they said, \"We are here in flesh and soul.\" As the Lord loved Moses and as he did not depart from His Command, every word he spoke was done as if it were the Word of the Lord." },
  { book: "2 Meqabyan", chapter: 11, verse: 7, text: "Unless you also destroy the Command of the Lord, the Lord will fulfill your desires, love your affairs, and keep your Kingdom for you." },
  { book: "2 Meqabyan", chapter: 11, verse: 8, text: "Asaph and the children of Korah who departed from Moses' command grumbled against him because he told them, \"Straighten your thoughts to be ruled by the Lord.\"" },
  { book: "2 Meqabyan", chapter: 11, verse: 9, text: "They grumbled, saying, \"Are we not also children of Levi who perform the work of the priesthood in the special Tent?\"" },
  { book: "2 Meqabyan", chapter: 11, verse: 10, text: "They went and offered incense, taking their censers to burn it; but the Lord did not accept their plea. They were burnt by the fire in their censers and melted like wax in a fire; not one of them remained. As it was said: their censers were honored by their bodies being burnt, but apart from the censers that entered the Lord’s Dwelling by His command, neither their clothes nor their bones remained." },
  { book: "2 Meqabyan", chapter: 11, verse: 11, text: "Because of this, the Lord told Aaron and Moses: \"Gather those censers toward the Tent; let them be an instrument for My Dwelling, for which I have prepared everything from the outside to the inside.\"" },
  { book: "2 Meqabyan", chapter: 11, verse: 12, text: "And he prepared the honored instruments of the Tent; he prepared the rings, the joiners, and the sea with the image of the Cherubim." },
  { book: "2 Meqabyan", chapter: 11, verse: 13, text: "He made the cups, the curtains, the grounds of the Tent for mobilization, the altar, and the jugs used for sacrifice in the special Tent." },
  { book: "2 Meqabyan", chapter: 11, verse: 14, text: "They offered the sacrifices according to their agreement—the welfare offerings, the sin offerings, the vow offerings, and the morning and evening sacrifices." },
  { book: "2 Meqabyan", chapter: 11, verse: 15, text: "All that He commanded Moses, he commanded them to perform in the special Tent." },
  { book: "2 Meqabyan", chapter: 11, verse: 16, text: "They did not scorn being ruled by their Creator, the Lord, so that His Name might be praised by them in the Tent of the Law of the Lord, who promised to give them the inheritance of their fathers—a land flowing with honey and milk—which He swore to Abraham." },
  { book: "2 Meqabyan", chapter: 11, verse: 17, text: "They did not scorn being ruled by their Creator, who swore to Isaac and established His worship for Jacob..." },
  { book: "2 Meqabyan", chapter: 11, verse: 18, text: "...and who established for Aaron and Moses the Tent where His worship is kept..." },
  { book: "2 Meqabyan", chapter: 11, verse: 19, text: "...and who established His worship for both Elijah and Samuel in the Temple and Tent that Solomon built, until it became the Dwelling of the Lord in Jerusalem—the place that honored Israel." },
  { book: "2 Meqabyan", chapter: 11, verse: 20, text: "For the Temple is a place of supplication and atonement for sin for those who live in innocence and for the priests." },
  { book: "2 Meqabyan", chapter: 11, verse: 21, text: "It is a place for those who do His Will, where He will hear their pleas..." },
  { book: "2 Meqabyan", chapter: 11, verse: 22, text: "...and the construction of the Law of the Lord that honored Israel." },
  { book: "2 Meqabyan", chapter: 11, verse: 23, text: "It is where sacrifices are offered and incense is burned, so that the Lord who honored Israel might be in a good fragrance." },
  { book: "2 Meqabyan", chapter: 11, verse: 24, text: "He would speak from the mercy seat (joiner) where He forgives in the special Tent; the Light of the Lord would be revealed to the children of Jacob whom He chose and to friends who live firmly in His Law and Command." },
  { book: "2 Meqabyan", chapter: 11, verse: 25, text: "But those who ignored the Law of the Lord will be like the children of Korah whom the Earth swallowed; likewise, sinners shall enter Gehenna, which has no exit for all eternity." },
  { book: "2 Meqabyan", chapter: 12, verse: 1, text: "Woe to you who did not keep the Law He commanded you in the Tent; woe to you nobles of Israel who did not do His Will, but followed your own will—which is arrogance, pride, greed, adultery, drinking, drunkenness, and swearing lies." },
  { book: "2 Meqabyan", chapter: 12, verse: 2, text: "Because of this, My anger is kindled. Like chaff is burnt before a fire, and like fire burns the mountain, and like a whirlwind blows away the crushed chaff from the Earth and scatters it toward Heaven until no trace is found in its place—My anger will destroy you like that." },
  { book: "2 Meqabyan", chapter: 12, verse: 3, text: "The Lord who honored Israel said: \"I shall likewise destroy all persons who work sin.\" Think of the Lord who rules all and for whom nothing is impossible." },
  { book: "2 Meqabyan", chapter: 12, verse: 4, text: "He loves those who love Him; and for those who live firmly in His Command, He will atone for their iniquity and their sin. Do not be dull or stingy of heart by not believing." },
  { book: "2 Meqabyan", chapter: 12, verse: 5, text: "Make your reasoning straight to be ruled by the Lord, and believe in Him so that you may strengthen your bodies; and I shall save you from the hand of your enemy in your day of tribulation." },
  { book: "2 Meqabyan", chapter: 12, verse: 6, text: "In your time of prayer, I tell you: Look, I am there with you in support. I shall save you from your enemy's hand. Because you have believed in Me, and because you have done My Command, and because you did not depart from My Law, and because you loved what I love—the Lord who rules all said: \"I will not neglect you on your day of tribulation.\"" },
  { book: "2 Meqabyan", chapter: 12, verse: 7, text: "He loves those who love Him, for He is a Pardoner and He is kind; He keeps those who keep His Law like a precious trust." },
  { book: "2 Meqabyan", chapter: 12, verse: 8, text: "He holds back His anger many times; because He knows they are flesh and blood and because He is a Pardoner, He did not destroy them all in His chastisement. When their souls are separated from their flesh, they shall return to their earthliness." },
  { book: "2 Meqabyan", chapter: 12, verse: 9, text: "As He created them, bringing them from non-existence to life, they will not know the place where they live until the Lord chooses to bring them again from non-existence to life. Again He separated their souls from their flesh, and the nature of the Earth returned to its earthliness." },
  { book: "2 Meqabyan", chapter: 12, verse: 10, text: "And again, His Will shall bring them from non-existence to life.\"" },
  { book: "2 Meqabyan", chapter: 12, verse: 11, text: "But Tseerutsaydan, who denied the Lord, increased his arrogance before the Lord; he made himself lofty until the day he died and left this world." },
  { book: "2 Meqabyan", chapter: 12, verse: 12, text: "He said, \"My era has become like the era of Heaven; I am the one who sends forth the Sun, and I shall not die for eternity.\"" },
  { book: "2 Meqabyan", chapter: 12, verse: 13, text: "Before he finished speaking this, the Angel of Death, whose name is Thilimyakos, descended and struck his heart. He died in that very hour. Because he did not praise his Creator, he was separated from his beautiful lifestyle and perished because of his great arrogance and evil works." },
  { book: "2 Meqabyan", chapter: 12, verse: 14, text: "When the army of the Chaldean king had camped in the city and country squares wishing to fight him, they found he was dead. They proceeded to destroy his country and plundered all his livestock; they did not spare the elders who were near the walls." },
  { book: "2 Meqabyan", chapter: 12, verse: 15, text: "They plundered all his wealth, took even his small money, burned his country with fire, and returned to their own land." },
  { book: "2 Meqabyan", chapter: 13, verse: 1, text: "But these five children of Meqabees, who believed, gave their bodies to death, refusing to eat the sacrifice offered to idols." },
  { book: "2 Meqabyan", chapter: 13, verse: 2, text: "For they knew that to be upright with God surpasses being upright with men, and God's anger is greater than the king's anger." },
  { book: "2 Meqabyan", chapter: 13, verse: 3, text: "Knowing that this world will totally pass away and that its pleasures will not last forever, they gave their bodies to the fire so they might be saved from the fire in Heaven." },
  { book: "2 Meqabyan", chapter: 13, verse: 4, text: "As they knew that being righteous in the Garden (Paradise) for one day is better than living many eras in this world—and that finding Your pardon for one hour, O Lord, is better than many eras—they gave their bodies to the fire." },
  { book: "2 Meqabyan", chapter: 13, verse: 5, text: "What is our era? It is like a shadow, or like passing wax that melts and perishes at the edge of a fire; is it not like that?" },
  { book: "2 Meqabyan", chapter: 13, verse: 6, text: "But You, Lord, live forever; Your era is never fulfilled, and the mention of Your Name is for generations to come." },
  { book: "2 Meqabyan", chapter: 13, verse: 7, text: "The children of Meqabees thought on all this; refusing to eat a disgusting sacrifice, they chose to believe in the Lord." },
  { book: "2 Meqabyan", chapter: 13, verse: 8, text: "Knowing they would arise with the dead, and acting because of the Lord—knowing that Judgment shall be judged after the Resurrection of the Council—for this reason they gave their bodies to martyrdom." },
  { book: "2 Meqabyan", chapter: 13, verse: 9, text: "You people who do not know or believe that the dead will rise—know that the Life they find later will surpass this passing earthly life. Because these five children of Meqabees together gave their bodies to death, and because their appearance was handsome, afterward they knew the Resurrection." },
  { book: "2 Meqabyan", chapter: 13, verse: 10, text: "Because they believed in Him, knowing all shall pass, and because they did not bow to idols or eat a disgusting sacrifice that gives no support, they gave their bodies to death to find thanks from the Lord." },
  { book: "2 Meqabyan", chapter: 13, verse: 11, text: "Because they knew He would make them righteous in flesh and soul in a later era, they did not consider this world's flavor or the tribulation of death a serious thing, even for those who had children and wives. Knowing the Resurrection would be in flesh and soul on the Day of Advent, they gave their bodies to death." },
  { book: "2 Meqabyan", chapter: 13, verse: 12, text: "And knowing that those who kept the Lord's Law—along with the nobles and kings who believed the Lord's Word and were kind—" },
  { book: "2 Meqabyan", chapter: 13, verse: 13, text: "shall live reigning for generations for many eras in the Kingdom of Heaven, where there is no sadness, tribulation, or death. Knowing in their reasoning what would be done later—how the world melts like wax in a fire—for this reason they gave their bodies to death." },
  { book: "2 Meqabyan", chapter: 13, verse: 14, text: "Believing that their faces would shine seven times brighter than the Sun, and that they would be joyful in His love when all arise in flesh and soul, they gave their bodies to death." },
  { book: "2 Meqabyan", chapter: 14, verse: 1, text: "But the beliefs of the Samaritans and the Jews—the Sadducees who do not believe the dead will rise, and the Pharisees—totally sadden me and trouble my reasoning. \"We will die tomorrow,\" the Jews say. \"Let us eat and drink, for we will die tomorrow; there is no peace we will see in the grave.\"" },
  { book: "2 Meqabyan", chapter: 14, verse: 2, text: "The Samaritans say, \"As our flesh will become dust, it won't arise.\"" },
  { book: "2 Meqabyan", chapter: 14, verse: 3, text: "Because the soul was invisible like the wind or a distant voice—look, it is here—and because it was what they call invisible, they say the soul won't arise if the flesh is dead. They say, \"When the Resurrection is done, then we will believe our souls are rising.\"" },
  { book: "2 Meqabyan", chapter: 14, verse: 4, text: "But as beasts and worms will eat the flesh in the grave, our flesh is seen by all; it will become dust and ashes." },
  { book: "2 Meqabyan", chapter: 14, verse: 5, text: "\"Those beasts who ate the flesh will become dust, for they have been like grass; they become dust as if they were never created, and their trace won't be found; so our flesh won't arise.\"" },
  { book: "2 Meqabyan", chapter: 14, verse: 6, text: "And the Pharisees say, \"We believe the dead will rise; however, He will bring and unite souls with another flesh that is in Heaven, not on Earth. For where will the destroyed and rotten flesh be found?\"" },
  { book: "2 Meqabyan", chapter: 14, verse: 7, text: "But the Sadducees say, \"After our soul has left our flesh, we won't arise with the dead; flesh and soul have no rising after they die.\"" },
  { book: "2 Meqabyan", chapter: 14, verse: 8, text: "Because of this, they are totally in error, and as they speak insults against the Lord's Divinity, their beliefs sadden me." },
  { book: "2 Meqabyan", chapter: 14, verse: 9, text: "As they did not believe the Lord who honors them, they have no hope of being saved; they have no hope of dying, rising, and being saved." },
  { book: "2 Meqabyan", chapter: 14, verse: 10, text: "O Jew who is blind in reasoning—when you were created from non-existence to life, even when scorned like spit—will you make the Lord ignorant, He who made you a person? Will the Lord who created you in His Image and Appearance fail to arouse and unite your flesh and soul?" },
  { book: "2 Meqabyan", chapter: 14, verse: 11, text: "Since you won't escape the Lord's authority, do not think such a thing; you will arise whether you wish to or not. For there is hardship you will receive in Sheol where you were seized when you died, and you shall be judged whether you wish it or not." },
  { book: "2 Meqabyan", chapter: 14, verse: 12, text: "For the sin found in demons, which demons place in your reasoning, is worked with you after you were born from your mother's womb, and it is worked abundantly as you grow up." },
  { book: "2 Meqabyan", chapter: 14, verse: 13, text: "They place it in your body when you die, and it will bring hardship upon them for having worked it." },
  { book: "2 Meqabyan", chapter: 14, verse: 14, text: "Just as there is sin in their mind, there are people who work sin being seized by it; their kind will be presented to demons." },
  { book: "2 Meqabyan", chapter: 14, verse: 15, text: "All sinners' souls shall come from the edge of Heaven where they are, and your sin likewise shall introduce you to Gehenna, pulling and bringing your soul from where it is." },
  { book: "2 Meqabyan", chapter: 14, verse: 16, text: "After your flesh has lived separate from your soul, the Lord's dew of charity shall arouse you, being seven-fold like the flesh of our father Adam." },
  { book: "2 Meqabyan", chapter: 14, verse: 17, text: "You who live in the grave, you also err in your error; let it not seem to you that you only mislead others. You say, \"The resurrection of the dead is not real,\" so that they might depart from the Lord's Command and err." },
  { book: "2 Meqabyan", chapter: 14, verse: 18, text: "He shall arouse you so He might give you your hardship according to the work you performed. Who will allow you to remain as dust?" },
  { book: "2 Meqabyan", chapter: 14, verse: 19, text: "At that time—whether your nature be wind in wind, or water in water, or earth in earth, or fire in fire—it shall come." },
  { book: "2 Meqabyan", chapter: 14, verse: 20, text: "And if a soul that dwelt in you is what lived in Sheol, she shall come." },
  { book: "2 Meqabyan", chapter: 14, verse: 21, text: "And the souls of the righteous that live in the Garden in glory shall come." },
  { book: "2 Meqabyan", chapter: 14, verse: 22, text: "But you—Jew, Samaritan, Pharisee, Sadducee—will live in Sheol until you are judged." },
  { book: "2 Meqabyan", chapter: 14, verse: 23, text: "At that time you will see that the Lord shall pay you hardship according to your sin because you misled people." },
  { book: "2 Meqabyan", chapter: 14, verse: 24, text: "Saying, \"The dead won't arise; since we will die, let us eat and drink\"—and because you sat in Moses' seat and misled others by your words—you will see that He shall pay you your hardship." },
  { book: "2 Meqabyan", chapter: 14, verse: 25, text: "Without knowing the Law (Torah), you taught the words of the books; because of this you erred. It would be better had you remained without learning than to mislead a person." },
  { book: "2 Meqabyan", chapter: 14, verse: 26, text: "It would have been better if you didn't know the word of the books, while you lead the Lord's people astray with your evil teaching and worthless words." },
  { book: "2 Meqabyan", chapter: 14, verse: 27, text: "For the Lord does not show favoritism; He shall give the grace and glory He prepared for His friends—those who teach good works—but you shall receive your reward according to your work and the things you spoke." },
  { book: "2 Meqabyan", chapter: 14, verse: 28, text: "There is nothing by which you will escape the authority of the Lord who shall judge you; He will pay you according to your work, for you and those you taught together will receive a sentence." },
  { book: "2 Meqabyan", chapter: 14, verse: 29, text: "Know that the dead shall arise; and if they are people who kept His Law, they shall arise. Just as the Earth sends forth grass when the rain falls, His Command shall send them forth from the grave; it is not possible for it to remain destroyed and rotten." },
  { book: "2 Meqabyan", chapter: 14, verse: 30, text: "As moist wood drinks dew and sends forth leaves when He satisfies the Earth with rain—as wheat bears fruit and grain produces buds—it is not possible to withhold the fruit if the Lord wills it..." },
  { book: "2 Meqabyan", chapter: 14, verse: 31, text: "...and as it is not possible for a woman who has conceived to close and prevent her womb when labor seizes her—as she cannot escape without giving birth..." },
  { book: "2 Meqabyan", chapter: 14, verse: 32, text: "...as dew has descended upon her being commanded by the Lord, she shall produce them all at once. After hearing the Lord's Word, a grave likewise cannot prevent the persons gathered within it from arising." },
  { book: "2 Meqabyan", chapter: 14, verse: 33, text: "Flesh shall be gathered in the place where the corpses fell; the places where souls live shall be opened; and souls shall return to the flesh from which they were formerly separated." },
  { book: "2 Meqabyan", chapter: 14, verse: 34, text: "When a drum is beaten, the dead shall quickly arise in the blink of an eye. Having arisen, they shall stand before the Lord, and He shall give them their reward according to the work of their hands." },
  { book: "2 Meqabyan", chapter: 14, verse: 35, text: "At that time you will see that you arise with the dead, and you will marvel at all the work you did in this world. When you see all your sins written before you, you will feel a useless regret." },
  { book: "2 Meqabyan", chapter: 14, verse: 36, text: "You know that you will arise with the dead and that you will receive your hardship according to the work you performed." },
  { book: "2 Meqabyan", chapter: 15, verse: 1, text: "But those who have found their reward through their good works shall be joyful at that time. Those who ignored the truth, saying, \"The dead will not rise,\" shall be sad in the hour they see that the dead have indeed arisen with their own useless, evil works." },
  { book: "2 Meqabyan", chapter: 15, verse: 2, text: "The works they performed shall convict them; they themselves will know they are convicted without a single person needing to argue against them." },
  { book: "2 Meqabyan", chapter: 15, verse: 3, text: "On the day when judgment and mourning are done—on the day when the Lord shall come, and the Final Judgment is decreed—those who forgot the Law of the Lord shall stand in their place." },
  { book: "2 Meqabyan", chapter: 15, verse: 4, text: "On the day of total darkness and thick mist, the day when flashes of light are seen and lightning is heard..." },
  { book: "2 Meqabyan", chapter: 15, verse: 5, text: "...and on the day of earthquakes, terror, heatwaves, and freezing frost..." },
  { book: "2 Meqabyan", chapter: 15, verse: 6, text: "...on the day when the evil person who did evil receives hardship, and the clean person who did clean work receives their reward, and those who forgot the Law of the Lord receive the hardship due to a sinner—they shall all stand in their appointed places." },
  { book: "2 Meqabyan", chapter: 15, verse: 7, text: "For on that day, a master will not be more honored than his slave; a mistress will not be more honored than her servant..." },
  { book: "2 Meqabyan", chapter: 15, verse: 8, text: "...the king will not be more honored than the poor man; the elder will not be more honored than the infant; the father will not be more honored than his child, and the mother will not be more honored than her child..." },
  { book: "2 Meqabyan", chapter: 15, verse: 9, text: "...the wealthy will not be more honored than the poor; the arrogant will not be more honored than the humble; the great will not be more honored than the small. That is the day when judgment is judged; the day they receive their sentence and hardship, and the day all shall receive hardship according to their sins." },
  { book: "2 Meqabyan", chapter: 15, verse: 10, text: "It is the day when those who did good works receive their reward, and those who sinned receive hardship." },
  { book: "2 Meqabyan", chapter: 15, verse: 11, text: "As it is the day when the rewarded are made joyful, those who forgot the Law of the Lord shall stand in their place. Those who acted as liars, who misinterpreted the books while saying, \"The dead will not rise\"—they shall behold the Resurrection." },
  { book: "2 Meqabyan", chapter: 15, verse: 12, text: "At that time, the sinners of this world, who did no good works, shall weep over the sins they committed, for sadness has found them without any comfort." },
  { book: "2 Meqabyan", chapter: 15, verse: 13, text: "Likewise, the righteous who did good works—their joy shall never end, for they did good works while they were in this world." },
  { book: "2 Meqabyan", chapter: 15, verse: 14, text: "For they knew they would arise after they died, and they did not depart from the Law of their Creator." },
  { book: "2 Meqabyan", chapter: 15, verse: 15, text: "Because they did not depart from His Law, they shall inherit two blessings: He multiplied their seed in this world and He honored their children." },
  { book: "2 Meqabyan", chapter: 15, verse: 16, text: "He bequeathed to them the Kingdom of Heaven, where the welfare He swore to their fathers shall be found in the hour the dead arise and the rich become poor." },
  { book: "2 Meqabyan", chapter: 15, verse: 17, text: "Those who worked sin, who did not believe the dead would rise, who did not keep the Law of the Lord, and who did not think of the Day of Rising, shall weep." },
  { book: "2 Meqabyan", chapter: 15, verse: 18, text: "At that time, they will see the tribulation that finds them, which shall have no end; where there is no comfort or welfare, only a sadness in their minds that knows no rest." },
  { book: "2 Meqabyan", chapter: 15, verse: 19, text: "A fire that does not perish and worms that do not sleep shall find them." },
  { book: "2 Meqabyan", chapter: 15, verse: 20, text: "In the place where their flesh is, fire, sulphur, whirlwinds, frost, hail, and sleet shall rain over them." },
  { book: "2 Meqabyan", chapter: 15, verse: 21, text: "For those who do not believe the dead will rise, there is the fire of Gehenna upon them." },
  { book: "2 Meqabyan", chapter: 16, verse: 1, text: "Please, consider your own body: your toenails, your fingernails, and the hair on your head—how they grow back quickly after you cut them. Know the Resurrection by this; for you have reasoning, religion, and knowledge." },
  { book: "2 Meqabyan", chapter: 16, verse: 2, text: "Regarding your nails and your hair, do you ask, \"Where do these come from?\" Is it not the Lord who prepared them to grow? Recognize the rising that shall happen to your own flesh—not another's flesh—so that you may know you will arise after you die." },
  { book: "2 Meqabyan", chapter: 16, verse: 3, text: "Because you misled people by saying, \"There is no Resurrection of the dead,\" when the dead arise, you will receive your hardship according to your sins and iniquity." },
  { book: "2 Meqabyan", chapter: 16, verse: 4, text: "Just as the seed you plant now will not refuse to grow—whether it be wheat or barley—you will see this truth in the hour your hardship arrives." },
  { book: "2 Meqabyan", chapter: 16, verse: 5, text: "Furthermore, the plant you sow does not say, \"I will not grow.\" Whether it is a fig tree or a grapevine, its fruit and leaves do not change their nature." },
  { book: "2 Meqabyan", chapter: 16, verse: 6, text: "If you plant grapes, they do not change into figs; if you plant figs, they do not change into grapes; if you sow wheat, it does not change into barley." },
  { book: "2 Meqabyan", chapter: 16, verse: 7, text: "Every seed, according to its kind—every fruit, every wood, every leaf, and every root—sends forth fruit, having received the blessing of the Dew of Pardon from the Lord. If you sow barley, it will not change into wheat." },
  { book: "2 Meqabyan", chapter: 16, verse: 8, text: "Likewise, as a grave produces flesh and soul, it shall produce persons exactly as the Lord sowed them within it. The flesh and soul the Lord sowed shall arise united. Those who did good works will not be changed into those who did evil, and those who did evil will not be changed into those who did good." },
  { book: "2 Meqabyan", chapter: 16, verse: 10, text: "In the hour when the drum is beaten, the dead shall arise by the Dew of Pardon found from the Lord. Those who did good works shall arise to the Resurrection of Life; their reward is the Garden of Joy that the Lord prepared for the righteous, where there is no tribulation or disease, and which is the dwelling of the clean who will never die again." },
  { book: "2 Meqabyan", chapter: 16, verse: 11, text: "But those who did evil works shall arise to the Resurrection of Final Judgment, along with the Devil who misled them..." },
  { book: "2 Meqabyan", chapter: 16, verse: 12, text: "...and with his armies—demons who do not love even one of Adam’s children to be saved." },
  { book: "2 Meqabyan", chapter: 16, verse: 13, text: "They shall descend to the edge of the darkness of Gehenna, where there is grinding of teeth and mourning; where there is no mercy or pardon, and no exit for all eternity. It is beneath Sheol forever. For they did no good works during their lives in this world while they were in the flesh." },
  { book: "2 Meqabyan", chapter: 16, verse: 14, text: "Because of this, they shall be judged in the hour that flesh and soul arise united." },
  { book: "2 Meqabyan", chapter: 16, verse: 15, text: "Woe to those who do not believe in the rising of flesh and soul, through which the Lord shows the abundance of His miracles. Everyone shall receive their reward according to their work and the labor of their hands." },
  { book: "2 Meqabyan", chapter: 17, verse: 1, text: "A wheat kernel will not grow or bear fruit unless it is first broken down (destroyed). But if a wheat kernel is broken down, it sends roots into the Earth, sends forth leaves, produces buds, and bears fruit." },
  { book: "2 Meqabyan", chapter: 17, verse: 2, text: "You know that a single wheat kernel becomes many kernels." },
  { book: "2 Meqabyan", chapter: 17, verse: 3, text: "Likewise, this kernel grows by rising up from water, wind, and the dew of the Earth. Wheat cannot bear fruit without the Sun, and the Sun serves in the place of fire." },
  { book: "2 Meqabyan", chapter: 17, verse: 4, text: "The wind serves in the place of a soul—for wheat cannot bear fruit without wind—and the water gives the Earth drink to satisfy it." },
  { book: "2 Meqabyan", chapter: 17, verse: 5, text: "After the Earth, which is ashes, drinks the water, it produces roots, and its tips grow high. It bears fruit according to how the Lord blessed it." },
  { book: "2 Meqabyan", chapter: 17, verse: 6, text: "A wheat kernel is an example of Adam, in whom dwells a living soul created by the Lord. Likewise, a grapevine drinks water and sends forth roots." },
  { book: "2 Meqabyan", chapter: 17, verse: 7, text: "The Dew of Pardon from the Lord gives drink to the long tips of the vines, sending water upward to the leaves. It buds from the heat of the Sun, and by the Will of the Lord, it bears fruit." },
  { book: "2 Meqabyan", chapter: 17, verse: 8, text: "It produces a good fragrance that makes the mind joyful. When eaten, it satisfies like water that quenches thirst or grain that satisfies hunger. When pressed, it becomes the blood of the cluster." },
  { book: "2 Meqabyan", chapter: 17, verse: 9, text: "As it is said in the Psalms: \"Wine makes a person's heart glad.\" When they drink it, it makes the heart joyful. When a person opens his mouth and drinks, he is filled, and the blood flows toward his heart." },
  { book: "2 Meqabyan", chapter: 17, verse: 10, text: "Because the drunkenness of grapes can mislead and deprive a man of his mind, it makes pits and cliffs seem like wide meadows; he does not notice the obstacles or thorns against his feet and hands." },
  { book: "2 Meqabyan", chapter: 17, verse: 11, text: "The Lord did this with the fruit and the vine so that His Name might be praised by those who believe the dead will rise and who do His Will." },
  { book: "2 Meqabyan", chapter: 17, verse: 12, text: "In the Kingdom of Heaven, He shall make those who believe in the Resurrection joyful." },
  { book: "2 Meqabyan", chapter: 18, verse: 1, text: "You people who do not believe the dead will rise—how great is your error! When you are taken to the place you do not know, you will feel useless regrets. Because you did not believe in the rising where the dead arise united in soul and flesh, and when you are cast into Gehenna..." },
  { book: "2 Meqabyan", chapter: 18, verse: 2, text: "whether you did good or evil, you will receive your reward according to your work. For you misled the minds of your companions by saying, \"We know that the dead, who are dust and ashes, will not rise.\"" },
  { book: "2 Meqabyan", chapter: 18, verse: 3, text: "Since their death has no exit, and since they have no power against the chastisement that shall come upon them, and since they were not firm in their tribulation—for this reason they misled their companions. They shall all stand in the Lord's Square." },
  { book: "2 Meqabyan", chapter: 18, verse: 4, text: "When He is angry with them in His wrath, they will be struck with total fear. Because they did not acknowledge they were created from non-existence to life, and because they spoke of the Lord's Law without understanding, they shall all be judged because they did evil." },
  { book: "2 Meqabyan", chapter: 18, verse: 5, text: "They do not know the Gehenna to which they will go. Because they were angry and crooked in their work, they taught their companions according to their own thirsty reasoning. They are evil ones who teach a crooked thing, saying, \"There is no Resurrection of the dead.\"" },
  { book: "2 Meqabyan", chapter: 18, verse: 6, text: "At that time, they shall know that the dead will rise, and they shall know they are judged because they did not believe in the Resurrection that is for all of Adam's children." },
  { book: "2 Meqabyan", chapter: 18, verse: 7, text: "For we are all Adam's children, and we have died because of Adam; the judgment of death has found us all from the Lord because of the error of our father, Adam." },
  { book: "2 Meqabyan", chapter: 18, verse: 8, text: "We will again arise there with our father Adam to receive our hardship according to the works we performed; for the world has been ruled by death because of Adam’s ignorance." },
  { book: "2 Meqabyan", chapter: 18, verse: 9, text: "Because Adam infringed upon the Lord's Command, we received hardship. Our flesh melted like wax in the grave, and our bodies perished." },
  { book: "2 Meqabyan", chapter: 18, verse: 10, text: "The Earth drank our marrow; we perished, and our beauty perished in the grave. Our flesh was buried, and our beautiful words were buried in the Earth." },
  { book: "2 Meqabyan", chapter: 18, verse: 11, text: "Worms came from our shining eyes; our features perished in the grave and became dust." },
  { book: "2 Meqabyan", chapter: 18, verse: 12, text: "Where is the beauty of the youth, who were attractive, whose stance was handsome, and whose words were successful? Where is the strength of the warriors?" },
  { book: "2 Meqabyan", chapter: 18, verse: 13, text: "Where are the kings' armies, or the lordship of the nobles? Where is the adornment of horses, the silver and gold, and the shining weapons? Did they not all perish?" },
  { book: "2 Meqabyan", chapter: 18, verse: 14, text: "Where is the sweet drink of the vine, or the flavor of food?" },
  { book: "2 Meqabyan", chapter: 19, verse: 1, text: "O Earth, who has gathered the nobles, the kings, the rich, the elders, the attractive daughters, and the beautiful ones—woe arises from you." },
  { book: "2 Meqabyan", chapter: 19, verse: 2, text: "O Earth, who gathered the warriors, the comely, those with fine limbs, those with reasoning and knowledge, and those whose words were as beautiful as a humming harp, a lyre, or the beat of a violin..." },
  { book: "2 Meqabyan", chapter: 19, verse: 3, text: "...and those who had a tune that brought joy like wine, and those whose eyes shone like the morning star..." },
  { book: "2 Meqabyan", chapter: 19, verse: 4, text: "...and those who sketched with firm right hands, those who lifted up what was given or withheld, those whose feet were beautiful to behold, and those who ran like rushing wheels—woe arises from you." },
  { book: "2 Meqabyan", chapter: 19, verse: 5, text: "O Death, who separated the souls of attractive persons from their flesh—woe arises from you, though you were sent by the Will of the Lord." },
  { book: "2 Meqabyan", chapter: 19, verse: 6, text: "As you have gathered many people whom the Lord produced from you and returned to you—O Earth, woe arises from you. We were found from you, we returned to you by the Will of the Lord, and we were joyful upon you by the Will of the Lord." },
  { book: "2 Meqabyan", chapter: 19, verse: 7, text: "You became a carpet for our corpses; we walked upon you, and we were buried within you. We ate your fruit, and you ate our flesh." },
  { book: "2 Meqabyan", chapter: 19, verse: 8, text: "We drank the water from your springs, and you drank our springs of blood. We ate the fruit of your earthliness, and you ate the flesh of our bodies." },
  { book: "2 Meqabyan", chapter: 19, verse: 9, text: "Just as the Lord commanded you to be our food, we ate grain from your earth that holds the beautiful dew; and you received the beauty of our flesh and turned it to dust for your food, just as the Lord commanded you." },
  { book: "2 Meqabyan", chapter: 19, verse: 10, text: "O Death, who gathered the powerful nobles and kings—woe arises from you. You did not fear their fame or their terror, acting as the Lord who created them commanded you. O Death, woe arises from you; you did not overlook the sufferer." },
  { book: "2 Meqabyan", chapter: 19, verse: 11, text: "You were not merciful to those with beautiful features; you did not spare the powerful or the warriors. You did not spare the poor or the rich, the kind or the evil, the children or the elders, the daughters or the sons." },
  { book: "2 Meqabyan", chapter: 19, verse: 12, text: "You did not spare those who thought of good things and did not depart from the Law, nor did you spare those who were like animals in their works, who thought of evil, yet were beautiful in their features, their lifestyle, and their words. O Death, woe arises from you." },
  { book: "2 Meqabyan", chapter: 19, verse: 13, text: "You did not spare those whose words were angry and whose mouths were full of curses. You gathered those who live in darkness and in light, and their souls are in your places. O Death, woe arises from you." },
  { book: "2 Meqabyan", chapter: 19, verse: 14, text: "And the Earth gathered the flesh of all who lived, whether in caves or in the ground, until the drum is beaten and the dead arise." },
  { book: "2 Meqabyan", chapter: 19, verse: 15, text: "As the dead shall arise quickly, in the blink of an eye, by the Lord’s Command when the drum is beaten—those who did evil works shall receive hardship according to the measure of their sins, and those who did good works shall be joyful." },
  { book: "2 Meqabyan", chapter: 20, verse: 1, text: "Believe me, all the work we did in this world will not remain hidden when we stand before Him in fear and trembling." },
  { book: "2 Meqabyan", chapter: 20, verse: 2, text: "In the hour when we have no provisions for our path and no clothes for our bodies..." },
  { book: "2 Meqabyan", chapter: 20, verse: 3, text: "...in the hour when we have no staff for our hands or shoes for our feet..." },
  { book: "2 Meqabyan", chapter: 20, verse: 4, text: "...and in the hour when we do not know the paths where the demons take us—whether it be slippery or smooth, dark, filled with thorns or nettles, or a depth of water or a pit—believe me, the works we did in this world will not remain hidden." },
  { book: "2 Meqabyan", chapter: 20, verse: 5, text: "We will not know the demons who take us, nor will we hear their words." },
  { book: "2 Meqabyan", chapter: 20, verse: 6, text: "As they are black ones and lead us toward darkness, we will not see their faces." },
  { book: "2 Meqabyan", chapter: 20, verse: 7, text: "As the prophet spoke, saying: \"In the hour my soul was separated from my flesh—Lord, my Lord, You know my path. They hid a trap on the path where I went, and I looked to return to the right, but I lacked anyone who knew me; I have nothing there by which I will escape.\" As they take us toward darkness, we will not see their faces." },
  { book: "2 Meqabyan", chapter: 20, verse: 8, text: "Because he knows the demons ridicule him and will lead him toward a path he does not know, he speaks this. If he turns left or right, there is no one who knows him." },
  { book: "2 Meqabyan", chapter: 20, verse: 9, text: "He is alone among demons, and there is no one who knows him." },
  { book: "2 Meqabyan", chapter: 20, verse: 10, text: "Angels of Light, who are subtle, are sent to the righteous to receive their souls and take them toward a place of Light—toward the Garden where welfare is found." },
  { book: "2 Meqabyan", chapter: 20, verse: 11, text: "Demons and Angels of Darkness are sent to receive the sinners and take them toward Gehenna, which was prepared for them to receive hardship for the sins they committed." },
  { book: "2 Meqabyan", chapter: 20, verse: 12, text: "Woe to the souls of sinners who are taken toward destruction, who have no welfare or rest, no escape from the tribulation that finds them, and no departure from Gehenna for all eternity." },
  { book: "2 Meqabyan", chapter: 20, verse: 13, text: "Because they lived firmly in the work of Cain, perished by the price of Balaam’s iniquity, and lacked a plan—woe to the sinners. For their excuse was to receive interest and gifts, and in their transgression, they took a foreigner’s money that was not their own." },
  { book: "2 Meqabyan", chapter: 20, verse: 14, text: "They shall receive their hardship in Gehenna for the sins they committed." },
  { book: "2 Meqabyan", chapter: 21, verse: 1, text: "Where are those who gather the money of a foreigner, which was not the work of their hands nor their own money?" },
  { book: "2 Meqabyan", chapter: 21, verse: 2, text: "For they took a person's money for nothing; they shall be gathered without knowing the day of death that will arrive for them, and they will leave their money to a stranger." },
  { book: "2 Meqabyan", chapter: 21, verse: 3, text: "Like their fathers, they are a kindred of sinners who worry and seize other sinners, whether by theft or robbery; and their children will not find joy in their fathers' money." },
  { book: "2 Meqabyan", chapter: 21, verse: 4, text: "Because they gathered it in transgression, it is like misty urine, or like smoke scattered by the wind, or like wilting grass, or like wax melting before a fire. As the glory of sinners shall perish like that, their fathers' money will benefit no one. As David spoke, saying: \"I saw a sinful man..." },
  { book: "2 Meqabyan", chapter: 21, verse: 5, text: "...being honored and famous like a cordia or a cypress tree; but when I returned, he was gone. I searched and did not find his place.\" There is no one whom their fathers' money will profit or benefit." },
  { book: "2 Meqabyan", chapter: 21, verse: 6, text: "Because they gathered money through transgression, it seemed to them they would not die. Just as those who wrong their companions will not boast, the destruction of sinners comes suddenly." },
  { book: "2 Meqabyan", chapter: 21, verse: 7, text: "You lazy ones, think: you will perish, and your money will perish with you. Though your silver and gold abound, they shall rust." },
  { book: "2 Meqabyan", chapter: 21, verse: 8, text: "If you birth many children, they shall be for many graves; if you build many houses, they shall be demolished." },
  { book: "2 Meqabyan", chapter: 21, verse: 10, text: "Whether in a house or a forest, in the wilderness or a pasture, in the vineyard or the grain floor—it will not be found." },
  { book: "2 Meqabyan", chapter: 21, verse: 11, text: "Because you did not keep the Lord's Command, He will not save you or your household from tribulation. Sadness shall come upon you from all your enemies, and you will not find joy in the children born of your nature." },
  { book: "2 Meqabyan", chapter: 21, verse: 12, text: "But from His abundance, He will not trouble those who kept His Order and Law. He gives to all who ask Him, and He blesses their children and the fruit of their land." },
  { book: "2 Meqabyan", chapter: 21, verse: 13, text: "He makes them rulers over the peoples in their area so they might rule rather than be ruled; He gives them His plenty in their pasture." },
  { book: "2 Meqabyan", chapter: 21, verse: 14, text: "He blesses all they take in their hands—the field fruit and the livestock—and He makes them joyful in their children." },
  { book: "2 Meqabyan", chapter: 21, verse: 15, text: "He does not diminish their livestock; He saves them from all tribulation, weariness, illness, and destruction—from the enemies they do not know and those they do." },
  { book: "2 Meqabyan", chapter: 21, verse: 16, text: "He will advocate for them in the time of Judgment and save them from evil and tribulation. In the first era, if a priest lived who performed the work of the Tent, kept the Law, and lived in the Lord's Will, the people would give him the tithe and the firstborn of man and livestock; and the Lord would save them from all tribulation." },
  { book: "2 Meqabyan", chapter: 21, verse: 17, text: "As Moses commanded Joshua, son of Nun, there were cities of sanctuary in all their land, for those who killed by accident or intent, until judgment was decided..." },
  { book: "2 Meqabyan", chapter: 21, verse: 18, text: "If a person killed a soul, he would be measured there so that he might be saved." },
  { book: "2 Meqabyan", chapter: 21, verse: 19, text: "He told them, \"Examine if there was a previous quarrel. If it was by an axe, a stone, or wood that fell from his hand unknowingly—if he says, 'That person died by accident'—examine and save him. If it was unintentional, let him be saved." },
  { book: "2 Meqabyan", chapter: 21, verse: 20, text: "But if he did it knowingly, he will receive hardship for his sin, and no one will pardon him. If it was unintentional, examine and save him so he does not die.\"" },
  { book: "2 Meqabyan", chapter: 21, verse: 21, text: "He worked for them so they might distance themselves from sin; Moses worked like this for the children of Israel so they would not depart from the Lord's Law." },
  { book: "2 Meqabyan", chapter: 21, verse: 22, text: "He commanded the children of Adam to live firmly in the Lord's Command: to abstain from worshipping idols, eating what is found dead, and eating what is strangled or cut by a sword. They were to distance themselves from all evil work so they might distance themselves from all that is improper." },
  { book: "2 Meqabyan", chapter: 21, verse: 23, text: "He commanded them not to depart from the Command He established in the pattern of the Tent in Heaven, so they might save their bodies and find a dwelling with their fathers." },
  { book: "2 Meqabyan", chapter: 21, verse: 24, text: "As they were born of Seth and Adam, who did the Will of the Lord, those who believe in the Lord’s Word and live in His Command will be called the children of the righteous." },
  { book: "2 Meqabyan", chapter: 21, verse: 25, text: "As we are Adam's children, and as He created us in His Image and Appearance to do good works that please the Lord, He will not reject us." },
  { book: "2 Meqabyan", chapter: 21, verse: 26, text: "He will not separate His friends. If we do good works, we shall inherit the Kingdom of Heaven, where welfare is found with those who do good." },
  { book: "2 Meqabyan", chapter: 21, verse: 27, text: "He loves those who ask Him with a clean heart; He hears them in their prayer and accepts the repentance of those who are disciplined. He gives strength and power to those who keep His Order, Law, and Command." },
  { book: "2 Meqabyan", chapter: 21, verse: 28, text: "Those who did His Will shall be joyful with Him in His Kingdom forever; whether they preceded us or come after, they will offer praise to Him from today until eternity." },
  // 3 Maccabees (228 verses)
  { book: "3 Maccabees", chapter: 1, verse: 1, text: "ὁ δὲ Φιλοπάτωρ παρὰ τῶν ἀνακομισθέντων μαθὼν τὴν γενομένην τῶν ὑπ’ αὐτοῦ κρατουμένων τόπων ἀφαίρεσιν ὑπὸ Ἀντιόχου παραγγείλας ταῖς πάσαις δυνάμεσιν πεζικαῖς τε καὶ ἱππικαῖς καὶ τὴν ἀδελφὴν Ἀρσινόην συμπαραλαβὼν ἐξώρμησεν μέχρι τῶν κατὰ Ῥαφίαν τόπων ὅπου παρεμβεβλήκεισαν οἱ περὶ Ἀντίοχον" },
  { book: "3 Maccabees", chapter: 1, verse: 2, text: "Θεόδοτος δέ τις ἐκπληρῶσαι τὴν ἐπιβουλὴν διανοηθεὶς παραλαβὼν τῶν προϋποτεταγμένων αὐτῷ ὅπλων Πτολεμαϊκῶν τὰ κράτιστα διεκομίσθη νύκτωρ ἐπὶ τὴν τοῦ Πτολεμαίου σκηνὴν ὡς μόνος κτεῖναι αὐτὸν καὶ ἐν τούτῳ διαλῦσαι τὸν πόλεμον" },
  { book: "3 Maccabees", chapter: 1, verse: 3, text: "τοῦτον δὲ διαγαγὼν Δοσίθεος ὁ Δριμύλου λεγόμενος τὸ γένος Ιουδαῖος ὕστερον δὲ μεταβαλὼν τὰ νόμιμα καὶ τῶν πατρίων δογμάτων ἀπηλλοτριωμένος ἄσημόν τινα κατέκλινεν ἐν τῇ σκηνῇ ὃν συνέβη κομίσασθαι τὴν ἐκείνου κόλασιν" },
  { book: "3 Maccabees", chapter: 1, verse: 4, text: "γενομένης δὲ καρτερᾶς μάχης καὶ τῶν πραγμάτων μᾶλλον ἐρρωμένων τῷ Ἀντιόχῳ ἱκανῶς ἡ Ἀρσινόη ἐπιπορευσαμένη τὰς δυνάμεις παρεκάλει μετὰ οἴκτου καὶ δακρύων τοὺς πλοκάμους λελυμένη βοηθεῖν ἑαυτοῖς τε καὶ τοῖς τέκνοις καὶ γυναιξὶν θαρραλέως ἐπαγγελλομένη δώσειν νικήσασιν ἑκάστῳ δύο μνᾶς χρυσίου" },
  { book: "3 Maccabees", chapter: 1, verse: 5, text: "καὶ οὕτως συνέβη τοὺς ἀντιπάλους ἐν χειρονομίαις διαφθαρῆναι πολλοὺς δὲ καὶ δοριαλώτους συλλημφθῆναι" },
  { book: "3 Maccabees", chapter: 1, verse: 6, text: "κατακρατήσας δὲ τῆς ἐπιβουλῆς ἔκρινεν τὰς πλησίον πόλεις ἐπελθὼν παρακαλέσαι" },
  { book: "3 Maccabees", chapter: 1, verse: 7, text: "ποιήσας δὲ τοῦτο καὶ τοῖς τεμένεσι δωρεὰς ἀπονείμας εὐθαρσεῖς τοὺς ὑποτεταγμένους κατέστησεν" },
  { book: "3 Maccabees", chapter: 1, verse: 8, text: "τῶν δὲ Ιουδαίων διαπεμψαμένων πρὸς αὐτὸν ἀπὸ τῆς γερουσίας καὶ τῶν πρεσβυτέρων τοὺς ἀσπασομένους αὐτὸν καὶ ξένια κομιοῦντας καὶ ἐπὶ τοῖς συμβεβηκόσιν χαρισομένους συνέβη μᾶλλον αὐτὸν προθυμηθῆναι ὡς τάχιστα πρὸς αὐτοὺς παραγενέσθαι" },
  { book: "3 Maccabees", chapter: 1, verse: 9, text: "διακομισθεὶς δὲ εἰς Ιεροσόλυμα καὶ θύσας τῷ μεγίστῳ θεῷ καὶ χάριτας ἀποδοὺς καὶ τῶν ἑξῆς τι τῷ τόπῳ ποιήσας καὶ δὴ παραγενόμενος εἰς τὸν τόπον καὶ τῇ σπουδαιότητι καὶ εὐπρεπείᾳ καταπλαγείς" },
  { book: "3 Maccabees", chapter: 1, verse: 10, text: "θαυμάσας δὲ καὶ τὴν τοῦ ἱεροῦ εὐταξίαν ἐνεθυμήθη βουλεύσασθαι εἰς τὸν ναὸν εἰσελθεῖν" },
  { book: "3 Maccabees", chapter: 1, verse: 11, text: "τῶν δὲ εἰπόντων μὴ καθήκειν γίνεσθαι τοῦτο διὰ τὸ μηδὲ τοῖς ἐκ τοῦ ἔθνους ἐξεῖναι εἰσιέναι μηδὲ πᾶσιν τοῖς ἱερεῦσιν ἀλλ’ ἢ μόνῳ τῷ προηγουμένῳ πάντων ἀρχιερεῖ καὶ τούτῳ κατ’ ἐνιαυτὸν ἅπαξ ὁ δὲ οὐδαμῶς ἐπείθετο" },
  { book: "3 Maccabees", chapter: 1, verse: 12, text: "τοῦ τε νόμου παραναγνωσθέντος οὐδ’ ὧς ἀπέλιπεν προφερόμενος ἑαυτὸν δεῖν εἰσελθεῖν λέγων καὶ εἰ ἐκεῖνοι ἐστέρηνται ταύτης τῆς τιμῆς ἐμὲ δὲ οὐ δεῖ" },
  { book: "3 Maccabees", chapter: 1, verse: 13, text: "καὶ ἐπυνθάνετο διὰ τίνα αἰτίαν εἰσερχόμενον αὐτὸν εἰς πᾶν τέμενος οὐθεὶς ἐκώλυσεν τῶν παρόντων" },
  { book: "3 Maccabees", chapter: 1, verse: 14, text: "καί τις ἀπρονοήτως ἔφη κακῶς αὐτὸ τοῦτο τερατεύεσθαι" },
  { book: "3 Maccabees", chapter: 1, verse: 15, text: "γενομένου δέ φησιν τούτου διά τινα αἰτίαν οὐχὶ πάντως εἰσελεύσεσθαι καὶ θελόντων αὐτῶν καὶ μή" },
  { book: "3 Maccabees", chapter: 1, verse: 16, text: "τῶν δὲ ἱερέων ἐν πάσαις ταῖς ἐσθήσεσιν προσπεσόντων καὶ δεομένων τοῦ μεγίστου θεοῦ βοηθεῖν τοῖς ἐνεστῶσιν καὶ τὴν ὁρμὴν τοῦ κακῶς ἐπιβαλλομένου μεταθεῖναι κραυγῆς τε μετὰ δακρύων τὸ ἱερὸν ἐμπλησάντων" },
  { book: "3 Maccabees", chapter: 1, verse: 17, text: "οἱ κατὰ τὴν πόλιν ἀπολειπόμενοι ταραχθέντες ἐξεπήδησαν ἄδηλον τιθέμενοι τὸ γινόμενον" },
  { book: "3 Maccabees", chapter: 1, verse: 18, text: "αἵ τε κατάκλειστοι παρθένοι ἐν θαλάμοις σὺν ταῖς τεκούσαις ἐξώρμησαν καὶ ἀπέδωκαν κόνει τὰς κόμας πασάμεναι γόου τε καὶ στεναγμῶν ἐνεπίμπλων τὰς πλατείας" },
  { book: "3 Maccabees", chapter: 1, verse: 19, text: "αἱ δὲ καὶ προσαρτίως ἐσταλμέναι τοὺς πρὸς ἀπάντησιν διατεταγμένους παστοὺς καὶ τὴν ἁρμόζουσαν αἰδὼ παραλείπουσαι δρόμον ἄτακτον ἐν τῇ πόλει συνίσταντο" },
  { book: "3 Maccabees", chapter: 1, verse: 20, text: "τὰ δὲ νεογνὰ τῶν τέκνων αἱ πρὸς τούτοις μητέρες καὶ τιθηνοὶ παραλείπουσαι ἄλλως καὶ ἄλλως αἱ μὲν κατ’ οἴκους αἱ δὲ κατὰ τὰς ἀγυιάς ἀνεπιστρέπτως εἰς τὸ πανυπέρτατον ἱερὸν ἠθροίζοντο" },
  { book: "3 Maccabees", chapter: 1, verse: 21, text: "ποικίλη δὲ ἦν τῶν εἰς τοῦτο συλλεγέντων ἡ δέησις ἐπὶ τοῖς ἀνοσίως ὑπ’ ἐκείνου κατεγχειρουμένοις" },
  { book: "3 Maccabees", chapter: 1, verse: 22, text: "σύν τε τούτοις οἱ περὶ τῶν πολιτῶν θρασυνθέντες οὐκ ἠνείχοντο τέλεον αὐτοῦ ἐπικειμένου καὶ τὸ τῆς προθέσεως ἐκπληροῦν διανοουμένου" },
  { book: "3 Maccabees", chapter: 1, verse: 23, text: "φωνήσαντες δὲ τὴν ὁρμὴν ἐπὶ τὰ ὅπλα ποιήσασθαι καὶ θαρραλέως ὑπὲρ τοῦ πατρῴου νόμου τελευτᾶν ἱκανὴν ἐποίησαν ἐν τῷ τόπῳ τραχύτητα μόλις δὲ ὑπό τε τῶν γεραιῶν καὶ τῶν πρεσβυτέρων ἀποτραπέντες ἐπὶ τὴν αὐτὴν τῆς δεήσεως παρῆσαν στάσιν" },
  { book: "3 Maccabees", chapter: 1, verse: 24, text: "καὶ τὸ μὲν πλῆθος ὡς ἔμπροσθεν ἐν τούτοις ἀνεστρέφετο δεόμενον" },
  { book: "3 Maccabees", chapter: 1, verse: 25, text: "οἱ δὲ περὶ τὸν βασιλέα πρεσβύτεροι πολλαχῶς ἐπειρῶντο τὸν ἀγέρωχον αὐτοῦ νοῦν ἐξιστάνειν τῆς ἐντεθυμημένης ἐπιβουλῆς" },
  { book: "3 Maccabees", chapter: 1, verse: 26, text: "θρασυνθεὶς δὲ καὶ πάντα παραπέμψας ἤδη καὶ πρόσβασιν ἐποιεῖτο τέλος ἐπιθήσειν δοκῶν τῷ προειρημένῳ" },
  { book: "3 Maccabees", chapter: 1, verse: 27, text: "ταῦτα οὖν καὶ οἱ περὶ αὐτὸν ὄντες θεωροῦντες ἐτράπησαν εἰς τὸ σὺν τοῖς ἡμετέροις ἐπικαλεῖσθαι τὸν πᾶν κράτος ἔχοντα τοῖς παροῦσιν ἐπαμῦναι μὴ παριδόντα τὴν ἄνομον καὶ ὑπερήφανον πρᾶξιν" },
  { book: "3 Maccabees", chapter: 1, verse: 28, text: "ἐκ δὲ τῆς πυκνοτάτης τε καὶ ἐμπόνου τῶν ὄχλων συναγομένης κραυγῆς ἀνείκαστός τις ἦν βοή" },
  { book: "3 Maccabees", chapter: 1, verse: 29, text: "δοκεῖν γὰρ ἦν μὴ μόνον τοὺς ἀνθρώπους ἀλλὰ καὶ τὰ τείχη καὶ τὸ πᾶν ἔδαφος ἠχεῖν ἅτε δὴ τῶν πάντων τότε θάνατον ἀλλασσομένων ἀντὶ τῆς τοῦ τόπου βεβηλώσεως" },
  { book: "3 Maccabees", chapter: 2, verse: 1, text: "ὁ μὲν οὖν ἀρχιερεὺς Σιμων ἐξ ἐναντίας τοῦ ναοῦ κάμψας τὰ γόνατα καὶ τὰς χεῖρας προτείνας εὐτάκτως ἐποιήσατο τὴν δέησιν τοιαύτην" },
  { book: "3 Maccabees", chapter: 2, verse: 2, text: "κύριε κύριε βασιλεῦ τῶν οὐρανῶν καὶ δέσποτα πάσης κτίσεως ἅγιε ἐν ἁγίοις μόναρχε παντοκράτωρ πρόσχες ἡμῖν καταπονουμένοις ὑπὸ ἀνοσίου καὶ βεβήλου θράσει καὶ σθένει πεφρυαγμένου" },
  { book: "3 Maccabees", chapter: 2, verse: 3, text: "σὺ γὰρ ὁ κτίσας τὰ πάντα καὶ τῶν ὅλων ἐπικρατῶν δυνάστης δίκαιος εἶ καὶ τοὺς ὕβρει καὶ ἀγερωχίᾳ τι πράσσοντας κρίνεις" },
  { book: "3 Maccabees", chapter: 2, verse: 4, text: "σὺ τοὺς ἔμπροσθεν ἀδικίαν ποιήσαντας ἐν οἷς καὶ γίγαντες ἦσαν ῥώμῃ καὶ θράσει πεποιθότες διέφθειρας ἐπαγαγὼν αὐτοῖς ἀμέτρητον ὕδωρ" },
  { book: "3 Maccabees", chapter: 2, verse: 5, text: "σὺ τοὺς ὑπερηφανίαν ἐργαζομένους Σοδομίτας διαδήλους ταῖς κακίαις γενομένους πυρὶ καὶ θείῳ κατέφλεξας παράδειγμα τοῖς ἐπιγινομένοις καταστήσας" },
  { book: "3 Maccabees", chapter: 2, verse: 6, text: "σὺ τὸν θρασὺν Φαραω καταδουλωσάμενον τὸν λαόν σου τὸν ἅγιον Ισραηλ ποικίλαις καὶ πολλαῖς δοκιμάσας τιμωρίαις ἐγνώρισας τὴν σὴν δύναμιν ἐφ’ οἷς ἐγνώρισας τὸ μέγα σου κράτος" },
  { book: "3 Maccabees", chapter: 2, verse: 7, text: "καὶ ἐπιδιώξαντα αὐτὸν σὺν ἅρμασιν καὶ ὄχλων πλήθει ἐπέκλυσας βάθει θαλάσσης τοὺς δὲ ἐμπιστεύσαντας ἐπὶ σοὶ τῷ τῆς ἁπάσης κτίσεως δυναστεύοντι σώους διεκόμισας" },
  { book: "3 Maccabees", chapter: 2, verse: 8, text: "οἳ καὶ συνιδόντες ἔργα σῆς χειρὸς ᾔνεσάν σε τὸν παντοκράτορα" },
  { book: "3 Maccabees", chapter: 2, verse: 9, text: "σύ βασιλεῦ κτίσας τὴν ἀπέραντον καὶ ἀμέτρητον γῆν ἐξελέξω τὴν πόλιν ταύτην καὶ ἡγίασας τὸν τόπον τοῦτον εἰς ὄνομά σοι τῷ τῶν ἁπάντων ἀπροσδεεῖ καὶ παρεδόξασας ἐν ἐπιφανείᾳ μεγαλοπρεπεῖ σύστασιν ποιησάμενος αὐτοῦ πρὸς δόξαν τοῦ μεγάλου καὶ ἐντίμου ὀνόματός σου" },
  { book: "3 Maccabees", chapter: 2, verse: 10, text: "καὶ ἀγαπῶν τὸν οἶκον τοῦ Ισραηλ ἐπηγγείλω διότι ἐὰν γένηται ἡμῶν ἀποστροφὴ καὶ καταλάβῃ ἡμᾶς στενοχωρία καὶ ἐλθόντες εἰς τὸν τόπον τοῦτον δεηθῶμεν εἰσακούσῃ τῆς δεήσεως ἡμῶν" },
  { book: "3 Maccabees", chapter: 2, verse: 11, text: "καὶ δὴ πιστὸς εἶ καὶ ἀληθινός" },
  { book: "3 Maccabees", chapter: 2, verse: 12, text: "ἐπεὶ δὲ πλεονάκις θλιβέντων τῶν πατέρων ἡμῶν ἐβοήθησας αὐτοῖς ἐν τῇ ταπεινώσει καὶ ἐρρύσω αὐτοὺς ἐκ μεγάλων κακῶν" },
  { book: "3 Maccabees", chapter: 2, verse: 13, text: "ἰδοὺ δὲ νῦν ἅγιε βασιλεῦ διὰ τὰς πολλὰς καὶ μεγάλας ἡμῶν ἁμαρτίας καταπονούμεθα καὶ ὑπετάγημεν τοῖς ἐχθροῖς ἡμῶν καὶ παρείμεθα ἐν ἀδυναμίαις" },
  { book: "3 Maccabees", chapter: 2, verse: 14, text: "ἐν δὲ τῇ ἡμετέρᾳ καταπτώσει ὁ θρασὺς καὶ βέβηλος οὗτος ἐπιτηδεύει καθυβρίσαι τὸν ἐπὶ τῆς γῆς ἀναδεδειγμένον τῷ ὀνόματι τῆς δόξης σου ἅγιον τόπον" },
  { book: "3 Maccabees", chapter: 2, verse: 15, text: "τὸ μὲν γὰρ κατοικητήριόν σου οὐρανὸς τοῦ οὐρανοῦ ἀνέφικτος ἀνθρώποις ἐστίν" },
  { book: "3 Maccabees", chapter: 2, verse: 16, text: "ἀλλὰ ἐπεὶ εὐδοκήσας τὴν δόξαν σου ἐν τῷ λαῷ σου Ισραηλ ἡγίασας τὸν τόπον τοῦτον" },
  { book: "3 Maccabees", chapter: 2, verse: 17, text: "μὴ ἐκδικήσῃς ἡμᾶς ἐν τῇ τούτων ἀκαθαρσίᾳ μηδὲ εὐθύνῃς ἡμᾶς ἐν βεβηλώσει ἵνα μὴ καυχήσωνται οἱ παράνομοι ἐν θυμῷ αὐτῶν μηδὲ ἀγαλλιάσωνται ἐν ὑπερηφανίᾳ γλώσσης αὐτῶν λέγοντες" },
  { book: "3 Maccabees", chapter: 2, verse: 18, text: "ἡμεῖς κατεπατήσαμεν τὸν οἶκον τοῦ ἁγιασμοῦ ὡς καταπατοῦνται οἱ οἶκοι τῶν προσοχθισμάτων" },
  { book: "3 Maccabees", chapter: 2, verse: 19, text: "ἀπάλειψον τὰς ἁμαρτίας ἡμῶν καὶ διασκέδασον τὰς ἀμβλακίας ἡμῶν καὶ ἐπίφανον τὸ ἔλεός σου κατὰ τὴν ὥραν ταύτην" },
  { book: "3 Maccabees", chapter: 2, verse: 20, text: "ταχὺ προκαταλαβέτωσαν ἡμᾶς οἱ οἰκτιρμοί σου καὶ δὸς αἰνέσεις ἐν τῷ στόματι τῶν καταπεπτωκότων καὶ συντετριμμένων τὰς ψυχὰς ποιήσας ἡμῖν εἰρήνην" },
  { book: "3 Maccabees", chapter: 2, verse: 21, text: "ἐνταῦθα ὁ πάντων ἐπόπτης θεὸς καὶ προπάτωρ ἅγιος ἐν ἁγίοις εἰσακούσας τῆς ἐνθέσμου λιτανείας τὸν ὕβρει καὶ θράσει μεγάλως ἐπηρμένον ἐμάστιξεν αὐτὸν" },
  { book: "3 Maccabees", chapter: 2, verse: 22, text: "ἔνθεν καὶ ἔνθεν κραδάνας αὐτὸν ὡς κάλαμον ὑπὸ ἀνέμου ὥστε κατ’ ἐδάφους ἄπρακτον ἔτι καὶ τοῖς μέλεσιν παραλελυμένον μηδὲ φωνῆσαι δύνασθαι δικαίᾳ περιπεπληγμένον κρίσει" },
  { book: "3 Maccabees", chapter: 2, verse: 23, text: "ὅθεν οἵ τε φίλοι καὶ σωματοφύλακες ὀξεῖαν ἰδόντες τὴν καταλαβοῦσαν αὐτὸν εὔθυναν φοβούμενοι μὴ καὶ τὸ ζῆν ἐκλείπῃ ταχέως αὐτὸν ἐξείλκυσαν ὑπερβάλλοντι καταπεπληγμένοι φόβῳ" },
  { book: "3 Maccabees", chapter: 2, verse: 24, text: "ἐν χρόνῳ δὲ ὕστερον ἀναλεξάμενος αὑτὸν οὐδαμῶς εἰς μετάμελον ἦλθεν ἐπιτιμηθείς ἀπειλὰς δὲ πικρὰς θέμενος ἀνέλυσεν" },
  { book: "3 Maccabees", chapter: 2, verse: 25, text: "διακομισθεὶς δὲ εἰς τὴν Αἴγυπτον καὶ τὰ τῆς κακίας ἐπαύξων διά τε τῶν προαποδεδειγμένων συμποτῶν καὶ ἑταίρων τοῦ παντὸς δικαίου κεχωρισμένων" },
  { book: "3 Maccabees", chapter: 2, verse: 26, text: "οὐ μόνον ταῖς ἀναριθμήτοις ἀσελγείαις διηρκέσθη ἀλλὰ καὶ ἐπὶ τοσοῦτον θράσους προῆλθεν ὥστε δυσφημίας ἐν τοῖς τόποις συνίστασθαι καὶ πολλοὺς τῶν φίλων ἀτενίζοντας εἰς τὴν τοῦ βασιλέως πρόθεσιν καὶ αὐτοὺς ἕπεσθαι τῇ ἐκείνου θελήσει" },
  { book: "3 Maccabees", chapter: 2, verse: 27, text: "προέθετο δημοσίᾳ κατὰ τοῦ ἔθνους διαδοῦναι ψόγον ἐπὶ τοῦ κατὰ τὴν αὐλὴν πύργου στήλην ἀναστήσας ἐκόλαψεν γραφὴν" },
  { book: "3 Maccabees", chapter: 2, verse: 28, text: "μηδένα τῶν μὴ θυόντων εἰς τὰ ἱερὰ αὐτῶν εἰσιέναι πάντας δὲ τοὺς Ιουδαίους εἰς λαογραφίαν καὶ οἰκετικὴν διάθεσιν ἀχθῆναι τοὺς δὲ ἀντιλέγοντας βίᾳ φερομένους τοῦ ζῆν μεταστῆσαι" },
  { book: "3 Maccabees", chapter: 2, verse: 29, text: "τούς τε ἀπογραφομένους χαράσσεσθαι καὶ διὰ πυρὸς εἰς τὸ σῶμα παρασήμῳ Διονύσου κισσοφύλλῳ οὓς καὶ καταχωρίσαι εἰς τὴν προσυνεσταλμένην αὐθεντίαν" },
  { book: "3 Maccabees", chapter: 2, verse: 30, text: "ἵνα δὲ μὴ τοῖς πᾶσιν ἀπεχθόμενος φαίνηται ὑπέγραψεν ἐὰν δέ τινες ἐξ αὐτῶν προαιρῶνται ἐν τοῖς κατὰ τὰς τελετὰς μεμυημένοις ἀναστρέφεσθαι τούτους ἰσοπολίτας Ἀλεξανδρεῦσιν εἶναι" },
  { book: "3 Maccabees", chapter: 2, verse: 31, text: "ἔνιοι μὲν οὖν ἐπιπολαίως τὰς τῆς πόλεως εὐσεβείας ἐπιβάθρας στυγοῦντες εὐχερῶς ἑαυτοὺς ἐδίδοσαν ὡς μεγάλης τινὸς κοινωνήσοντες εὐκλείας ἀπὸ τῆς ἐσομένης τῷ βασιλεῖ συναναστροφῆς" },
  { book: "3 Maccabees", chapter: 2, verse: 32, text: "οἱ δὲ πλεῖστοι γενναίᾳ ψυχῇ ἐνίσχυσαν καὶ οὐ διέστησαν τῆς εὐσεβείας τά τε χρήματα περὶ τοῦ ζῆν ἀντικαταλλασσόμενοι ἀδεῶς ἐπειρῶντο ἑαυτοὺς ῥύσασθαι ἐκ τῶν ἀπογραφῶν" },
  { book: "3 Maccabees", chapter: 2, verse: 33, text: "εὐέλπιδές τε καθειστήκεισαν ἀντιλήμψεως τεύξασθαι καὶ τοὺς ἀποχωροῦντας ἐξ αὐτῶν ἐβδελύσσοντο καὶ ὡς πολεμίους τοῦ ἔθνους ἔκρινον καὶ τῆς κοινῆς συναναστροφῆς καὶ εὐχρηστίας ἐστέρουν" },
  { book: "3 Maccabees", chapter: 3, verse: 1, text: "ἃ καὶ μεταλαμβάνων ὁ δυσσεβὴς ἐπὶ τοσοῦτον ἐξεχόλησεν ὥστε οὐ μόνον τοῖς κατὰ Ἀλεξάνδρειαν διοργίζεσθαι ἀλλὰ καὶ τοῖς ἐν τῇ χώρᾳ βαρυτέρως ἐναντιωθῆναι καὶ προστάξαι σπεύσαντας συναγαγεῖν πάντας ἐπὶ τὸ αὐτὸ καὶ χειρίστῳ μόρῳ τοῦ ζῆν μεταστῆσαι" },
  { book: "3 Maccabees", chapter: 3, verse: 2, text: "τούτων δὲ οἰκονομουμένων φήμη δυσμενὴς ἐξηχεῖτο κατὰ τοῦ γένους ἀνθρώποις συμφρονοῦσιν εἰς κακοποίησιν ἀφορμῆς διδομένης εἰς διάθεσιν ὡς ἂν ἀπὸ τῶν νομίμων αὐτοὺς κωλυόντων" },
  { book: "3 Maccabees", chapter: 3, verse: 3, text: "οἱ δὲ Ιουδαῖοι τὴν μὲν πρὸς τοὺς βασιλεῖς εὔνοιαν καὶ πίστιν ἀδιάστροφον ἦσαν φυλάσσοντες" },
  { book: "3 Maccabees", chapter: 3, verse: 4, text: "σεβόμενοι δὲ τὸν θεὸν καὶ τῷ τούτου νόμῳ πολιτευόμενοι χωρισμὸν ἐποίουν ἐπὶ τῷ κατὰ τὰς τροφάς δῑ ἣν αἰτίαν ἐνίοις ἀπεχθεῖς ἐφαίνοντο" },
  { book: "3 Maccabees", chapter: 3, verse: 5, text: "τῇ δὲ τῶν δικαίων εὐπραξίᾳ κοσμοῦντες τὴν συναναστροφὴν ἅπασιν ἀνθρώποις εὐδόκιμοι καθειστήκεισαν" },
  { book: "3 Maccabees", chapter: 3, verse: 6, text: "τὴν μὲν οὖν περὶ τοῦ γένους ἐν πᾶσιν θρυλουμένην εὐπραξίαν οἱ ἀλλόφυλοι οὐδαμῶς διηριθμήσαντο" },
  { book: "3 Maccabees", chapter: 3, verse: 7, text: "τὴν δὲ περὶ τῶν προσκυνήσεων καὶ τροφῶν διάστασιν ἐθρύλουν φάσκοντες μήτε τῷ βασιλεῖ μήτε ταῖς δυνάμεσιν ὁμοσπόνδους τοὺς ἀνθρώπους γίνεσθαι δυσμενεῖς δὲ εἶναι καὶ μέγα τι τοῖς πράγμασιν ἐναντιουμένους καὶ οὐ τῷ τυχόντι περιῆψαν ψόγῳ" },
  { book: "3 Maccabees", chapter: 3, verse: 8, text: "οἱ δὲ κατὰ τὴν πόλιν Ἕλληνες οὐδὲν ἠδικημένοι ταραχὴν ἀπροσδόκητον περὶ τοὺς ἀνθρώπους θεωροῦντες καὶ συνδρομὰς ἀπροσκόπους γινομένας βοηθεῖν μὲν οὐκ ἔσθενον τυραννικὴ γὰρ ἦν ἡ διάθεσις παρεκάλουν δὲ καὶ δυσφόρως εἶχον καὶ μεταπεσεῖσθαι ταῦτα ὑπελάμβανον" },
  { book: "3 Maccabees", chapter: 3, verse: 9, text: "μὴ γὰρ οὕτω παροραθήσεσθαι τηλικοῦτο σύστεμα μηδὲν ἠγνοηκός" },
  { book: "3 Maccabees", chapter: 3, verse: 10, text: "ἤδη δὲ καί τινες γείτονές τε καὶ φίλοι καὶ συμπραγματευόμενοι μυστικῶς τινας ἐπισπώμενοι πίστεις ἐδίδουν συνασπιεῖν καὶ πᾶν ἐκτενὲς προσοίσεσθαι πρὸς ἀντίλημψιν" },
  { book: "3 Maccabees", chapter: 3, verse: 11, text: "ἐκεῖνος μὲν οὖν τῇ κατὰ τὸ παρὸν εὐημερίᾳ γεγαυρωμένος καὶ οὐ καθορῶν τὸ τοῦ μεγίστου θεοῦ κράτος ὑπολαμβάνων δὲ διηνεκῶς ἐν τῇ αὐτῇ διαμενεῖν βουλῇ ἔγραψεν κατ’ αὐτῶν ἐπιστολὴν τήνδε" },
  { book: "3 Maccabees", chapter: 3, verse: 12, text: "βασιλεὺς Πτολεμαῖος Φιλοπάτωρ τοῖς κατ’ Αἴγυπτον καὶ κατὰ τόπον στρατηγοῖς καὶ στρατιώταις χαίρειν καὶ ἐρρῶσθαι" },
  { book: "3 Maccabees", chapter: 3, verse: 13, text: "ἔρρωμαι δὲ καὶ αὐτὸς ἐγὼ καὶ τὰ πράγματα ἡμῶν" },
  { book: "3 Maccabees", chapter: 3, verse: 14, text: "τῆς εἰς τὴν Ἀσίαν γενομένης ἡμῖν ἐπιστρατείας ἧς ἴστε καὶ αὐτοί τῇ τῶν θεῶν ἀπροπτώτῳ συμμαχίᾳ κατὰ λόγον ἐπὶ τέλος ἀχθείσης" },
  { book: "3 Maccabees", chapter: 3, verse: 15, text: "ἡγησάμεθα μὴ βίᾳ δόρατος ἐπιεικείᾳ δὲ καὶ πολλῇ φιλανθρωπίᾳ τιθηνήσασθαι τὰ κατοικοῦντα Κοίλην Συρίαν καὶ Φοινίκην ἔθνη εὖ ποιῆσαί τε ἀσμένως" },
  { book: "3 Maccabees", chapter: 3, verse: 16, text: "καὶ τοῖς κατὰ πόλιν ἱεροῖς ἀπονείμαντες προσόδους πλείστας προήχθημεν καὶ εἰς τὰ Ιεροσόλυμα ἀναβάντες τιμῆσαι τὸ ἱερὸν τῶν ἀλιτηρίων καὶ μηδέποτε ληγόντων τῆς ἀνοίας" },
  { book: "3 Maccabees", chapter: 3, verse: 17, text: "οἱ δὲ λόγῳ μὲν τὴν ἡμετέραν ἀποδεξάμενοι παρουσίαν τῷ δὲ πράγματι νόθως προθυμηθέντων ἡμῶν εἰσελθεῖν εἰς τὸν ναὸν αὐτῶν καὶ τοῖς ἐκπρεπέσιν καὶ καλλίστοις ἀναθήμασιν τιμῆσαι" },
  { book: "3 Maccabees", chapter: 3, verse: 18, text: "τύφοις φερόμενοι παλαιοτέροις εἶρξαν ἡμᾶς τῆς εἰσόδου λειπόμενοι τῆς ἡμετέρας ἀλκῆς δῑ ἣν ἔχομεν πρὸς ἅπαντας ἀνθρώπους φιλανθρωπίαν" },
  { book: "3 Maccabees", chapter: 3, verse: 19, text: "τὴν δὲ αὐτῶν εἰς ἡμᾶς δυσμένειαν ἔκδηλον καθιστάντες ὡς μονώτατοι τῶν ἐθνῶν βασιλεῦσιν καὶ τοῖς ἑαυτῶν εὐεργέταις ὑψαυχενοῦντες οὐδὲν γνήσιον βούλονται φέρειν" },
  { book: "3 Maccabees", chapter: 3, verse: 20, text: "ἡμεῖς δὲ τῇ τούτων ἀνοίᾳ συμπεριενεχθέντες καὶ μετὰ νίκης διακομισθέντες εἰς τὴν Αἴγυπτον τοῖς πᾶσιν ἔθνεσιν φιλανθρώπως ἀπαντήσαντες καθὼς ἔπρεπεν ἐποιήσαμεν" },
  { book: "3 Maccabees", chapter: 3, verse: 21, text: "ἐν δὲ τούτοις πρὸς τοὺς ὁμοφύλους αὐτῶν ἀμνησικακίαν ἅπασιν γνωρίζοντες διά τε τὴν συμμαχίαν καὶ τὰ πεπιστευμένα μετὰ ἁπλότητος αὐτοῖς ἀρχῆθεν μύρια πράγματα τολμήσαντες ἐξαλλοιῶσαι ἐβουλήθημεν καὶ πολιτείας αὐτοὺς Ἀλεξανδρέων καταξιῶσαι καὶ μετόχους τῶν ἀεὶ ἱερῶν καταστῆσαι" },
  { book: "3 Maccabees", chapter: 3, verse: 22, text: "οἱ δὲ τοὐναντίον ἐκδεχόμενοι καὶ τῇ συμφύτῳ κακοηθείᾳ τὸ καλὸν ἀπωσάμενοι διηνεκῶς δὲ εἰς τὸ φαῦλον ἐκνεύοντες" },
  { book: "3 Maccabees", chapter: 3, verse: 23, text: "οὐ μόνον ἀπεστρέψαντο τὴν ἀτίμητον πολιτείαν ἀλλὰ καὶ βδελύσσονται λόγῳ τε καὶ σιγῇ τοὺς ἐν αὐτοῖς ὀλίγους πρὸς ἡμᾶς γνησίως διακειμένους παρ’ ἕκαστα ὑφορώμενοι μετὰ τῆς δυσκλεεστάτης ἐμβιώσεως διὰ τάχους ἡμᾶς καταστρέψαι τὰ πράγματα" },
  { book: "3 Maccabees", chapter: 3, verse: 24, text: "διὸ καὶ τεκμηρίοις καλῶς πεπεισμένοι τούτους κατὰ πάντα δυσνοεῖν ἡμῖν τρόπον καὶ προνοούμενοι μήποτε αἰφνιδίου μετέπειτα ταραχῆς ἐνστάσης ἡμῖν τοὺς δυσσεβεῖς τούτους κατὰ νώτου προδότας καὶ βαρβάρους ἔχωμεν πολεμίους" },
  { book: "3 Maccabees", chapter: 3, verse: 25, text: "προστετάχαμεν ἅμα τῷ προσπεσεῖν τὴν ἐπιστολὴν τήνδε αὐθωρὶ τοὺς ἐννεμομένους σὺν γυναιξὶ καὶ τέκνοις μετὰ ὕβρεων καὶ σκυλμῶν ἀποστεῖλαι πρὸς ἡμᾶς ἐν δεσμοῖς σιδηροῖς πάντοθεν κατακεκλεισμένους εἰς ἀνήκεστον καὶ δυσκλεῆ πρέποντα δυσμενέσι φόνον" },
  { book: "3 Maccabees", chapter: 3, verse: 26, text: "τούτων γὰρ ὁμοῦ κολασθέντων διειλήφαμεν εἰς τὸν ἐπίλοιπον χρόνον τελείως ἡμῖν τὰ πράγματα ἐν εὐσταθείᾳ καὶ τῇ βελτίστῃ διαθέσει κατασταθήσεσθαι" },
  { book: "3 Maccabees", chapter: 3, verse: 27, text: "ὃς δ’ ἂν σκεπάσῃ τινὰ τῶν Ιουδαίων ἀπὸ γεραιοῦ μέχρι νηπίου καὶ μέχρι τῶν ὑπομαστιδίων αἰσχίσταις βασάνοις ἀποτυμπανισθήσεται πανοικίᾳ" },
  { book: "3 Maccabees", chapter: 3, verse: 28, text: "μηνύειν δὲ τὸν βουλόμενον ἐφ’ ᾧ τὴν οὐσίαν τοῦ ἐμπίπτοντος ὑπὸ τὴν εὔθυναν λήμψεται καὶ ἐκ τοῦ βασιλικοῦ ἀργυρίου δραχμὰς δισχιλίας καὶ τῇ ἐλευθερίᾳ στεφανωθήσεται" },
  { book: "3 Maccabees", chapter: 3, verse: 29, text: "πᾶς δὲ τόπος οὗ ἐὰν φωραθῇ τὸ σύνολον σκεπαζόμενος Ιουδαῖος ἄβατος καὶ πυριφλεγὴς γινέσθω καὶ πάσῃ θνητῇ φύσει καθ’ ἅπαν ἄχρηστος φανήσεται εἰς τὸν ἀεὶ χρόνον" },
  { book: "3 Maccabees", chapter: 3, verse: 30, text: "καὶ ὁ μὲν τῆς ἐπιστολῆς τύπος οὕτως ἐγέγραπτο" },
  { book: "3 Maccabees", chapter: 4, verse: 1, text: "πάντῃ δέ ὅπου προσέπιπτεν τοῦτο τὸ πρόσταγμα δημοτελὴς συνίστατο τοῖς ἔθνεσιν εὐωχία μετὰ ἀλαλαγμῶν καὶ χαρᾶς ὡς ἂν τῆς προκατεσκιρωμένης αὐτοῖς πάλαι κατὰ διάνοιαν μετὰ παρρησίας νῦν ἐκφαινομένης ἀπεχθείας" },
  { book: "3 Maccabees", chapter: 4, verse: 2, text: "τοῖς δὲ Ιουδαίοις ἄληκτον πένθος ἦν καὶ πανόδυρτος μετὰ δακρύων βοὴ στεναγμοῖς πεπυρωμένης πάντοθεν αὐτῶν τῆς καρδίας ὀλοφυρομένων τὴν ἀπροσδόκητον ἐξαίφνης αὐτοῖς ἐπικριθεῖσαν ὀλεθρίαν" },
  { book: "3 Maccabees", chapter: 4, verse: 3, text: "τίς νομὸς ἢ πόλις ἢ τίς τὸ σύνολον οἰκητὸς τόπος ἢ τίνες ἀγυιαὶ κοπετοῦ καὶ γόων ἐπ’ αὐτοῖς οὐκ ἐνεπιπλῶντο" },
  { book: "3 Maccabees", chapter: 4, verse: 4, text: "οὕτως γὰρ μετὰ πικρίας ἀνοίκτου ψυχῆς ὑπὸ τῶν κατὰ πόλιν στρατηγῶν ὁμοθυμαδὸν ἐξαπεστέλλοντο ὥστε ἐπὶ ταῖς ἐξάλλοις τιμωρίαις καί τινας τῶν ἐχθρῶν λαμβάνοντας πρὸ τῶν ὀφθαλμῶν τὸν κοινὸν ἔλεον καὶ λογιζομένους τὴν ἄδηλον τοῦ βίου καταστροφὴν δακρύειν αὐτῶν τὴν δυσάθλιον ἐξαποστολήν" },
  { book: "3 Maccabees", chapter: 4, verse: 5, text: "ἤγετο γὰρ γεραιῶν πλῆθος πολιᾷ πεπυκασμένων τὴν ἐκ τοῦ γήρως νωθρότητα ποδῶν ἐπίκυφον ἀνατροπῆς ὁρμῇ βιαίας ἁπάσης αἰδοῦς ἄνευ πρὸς ὀξεῖαν καταχρωμένων πορείαν" },
  { book: "3 Maccabees", chapter: 4, verse: 6, text: "αἱ δὲ ἄρτι πρὸς βίου κοινωνίαν γαμικὸν ὑπεληλυθυῖαι παστὸν νεάνιδες ἀντὶ τέρψεως μεταλαβοῦσαι γόους καὶ κόνει τὴν μυροβρεχῆ πεφυρμέναι κόμην ἀκαλύπτως δὲ ἀγόμεναι θρῆνον ἀνθ’ ὑμεναίων ὁμοθυμαδὸν ἐξῆρχον ὡς ἐσπαραγμέναι σκυλμοῖς ἀλλοεθνέσιν" },
  { book: "3 Maccabees", chapter: 4, verse: 7, text: "δέσμιαι δὲ δημοσίᾳ μέχρι τῆς εἰς τὸ πλοῖον ἐμβολῆς εἵλκοντο μετὰ βίας" },
  { book: "3 Maccabees", chapter: 4, verse: 8, text: "οἵ τε τούτων συνζυγεῖς βρόχοις ἀντὶ στεφέων τοὺς αὐχένας περιπεπλεγμένοι μετὰ ἀκμαίας νεανικῆς ἡλικίας ἀντὶ εὐωχίας καὶ νεωτερικῆς ῥᾳθυμίας τὰς ἐπιλοίπους τῶν γάμων ἡμέρας ἐν θρήνοις διῆγον παρὰ πόδας ἤδη τὸν ᾅδην ὁρῶντες κείμενον" },
  { book: "3 Maccabees", chapter: 4, verse: 9, text: "κατήχθησαν δὲ θηρίων τρόπον ἀγόμενοι σιδηροδέσμοις ἀνάγκαις οἱ μὲν τοῖς ζυγοῖς τῶν πλοίων προσηλωμένοι τοὺς τραχήλους οἱ δὲ τοὺς πόδας ἀρρήκτοις κατησφαλισμένοι πέδαις" },
  { book: "3 Maccabees", chapter: 4, verse: 10, text: "ἔτι καὶ τῷ καθύπερθε πυκνῷ σανιδώματι διακειμένῳ ὅπως πάντοθεν ἐσκοτισμένοι τοὺς ὀφθαλμοὺς ἀγωγὴν ἐπιβούλων ἐν παντὶ τῷ κατάπλῳ λαμβάνωσιν" },
  { book: "3 Maccabees", chapter: 4, verse: 11, text: "τούτων δὲ ἐπὶ τὴν λεγομένην Σχεδίαν ἀχθέντων καὶ τοῦ παράπλου περανθέντος καθὼς ἦν δεδογματισμένον τῷ βασιλεῖ προσέταξεν αὐτοὺς ἐν τῷ πρὸ τῆς πόλεως ἱπποδρόμῳ παρεμβαλεῖν ἀπλάτῳ καθεστῶτι περιμέτρῳ καὶ πρὸς παραδειγματισμὸν ἄγαν εὐκαιροτάτῳ καθεστῶτι πᾶσι τοῖς καταπορευομένοις εἰς τὴν πόλιν καὶ τοῖς ἐκ τούτων εἰς τὴν χώραν στελλομένοις πρὸς ἐκδημίαν πρὸς τὸ μηδὲ ταῖς δυνάμεσιν αὐτοῦ κοινωνεῖν μηδὲ τὸ σύνολον καταξιῶσαι περιβόλων" },
  { book: "3 Maccabees", chapter: 4, verse: 12, text: "ὡς δὲ τοῦτο ἐγενήθη ἀκούσας τοὺς ἐκ τῆς πόλεως ὁμοεθνεῖς κρυβῇ ἐκπορευομένους πυκνότερον ἀποδύρεσθαι τὴν ἀκλεῆ τῶν ἀδελφῶν ταλαιπωρίαν" },
  { book: "3 Maccabees", chapter: 4, verse: 13, text: "διοργισθεὶς προσέταξεν καὶ τούτοις ὁμοῦ τὸν αὐτὸν τρόπον ἐπιμελῶς ὡς ἐκείνοις ποιῆσαι μὴ λειπομένοις κατὰ μηδένα τρόπον τῆς ἐκείνων τιμωρίας" },
  { book: "3 Maccabees", chapter: 4, verse: 14, text: "ἀπογραφῆναι δὲ πᾶν τὸ φῦλον ἐξ ὀνόματος οὐκ εἰς τὴν ἔμπροσθεν βραχεῖ προδεδηλωμένην τῶν ἔργων κατάπονον λατρείαν στρεβλωθέντας δὲ ταῖς παρηγγελμέναις αἰκίαις τὸ τέλος ἀφανίσαι μιᾶς ὑπὸ καιρὸν ἡμέρας" },
  { book: "3 Maccabees", chapter: 4, verse: 15, text: "ἐγίνετο μὲν οὖν ἡ τούτων ἀπογραφὴ μετὰ πικρᾶς σπουδῆς καὶ φιλοτίμου προσεδρείας ἀπὸ ἀνατολῶν ἡλίου μέχρι δυσμῶν ἀνήνυτον λαμβάνουσα τὸ τέλος ἐπὶ ἡμέρας τεσσαράκοντα" },
  { book: "3 Maccabees", chapter: 4, verse: 16, text: "μεγάλως δὲ καὶ διηνεκῶς ὁ βασιλεὺς χαρᾷ πεπληρωμένος συμπόσια ἐπὶ πάντων τῶν εἰδώλων συνιστάμενος πεπλανημένῃ πόρρω τῆς ἀληθείας φρενὶ καὶ βεβήλῳ στόματι τὰ μὲν κωφὰ καὶ μὴ δυνάμενα αὐτοῖς λαλεῖν ἢ ἀρήγειν ἐπαινῶν εἰς δὲ τὸν μέγιστον θεὸν τὰ μὴ καθήκοντα λαλῶν" },
  { book: "3 Maccabees", chapter: 4, verse: 17, text: "μετὰ δὲ τὸ προειρημένον τοῦ χρόνου διάστημα προσηνέγκαντο οἱ γραμματεῖς τῷ βασιλεῖ μηκέτι ἰσχύειν τὴν τῶν Ιουδαίων ἀπογραφὴν ποιεῖσθαι διὰ τὴν ἀμέτρητον αὐτῶν πληθὺν" },
  { book: "3 Maccabees", chapter: 4, verse: 18, text: "καίπερ ὄντων ἔτι κατὰ τὴν χώραν τῶν πλειόνων τῶν μὲν κατὰ τὰς οἰκίας ἔτι συνεστηκότων τῶν δὲ καὶ κατὰ τόπον ὡς ἀδυνάτου καθεστῶτος πᾶσιν τοῖς ἐπ’ Αἴγυπτον στρατηγοῖς" },
  { book: "3 Maccabees", chapter: 4, verse: 19, text: "ἀπειλήσαντος δὲ αὐτοῖς σκληρότερον ὡς δεδωροκοπημένοις εἰς μηχανὴν τῆς ἐκφυγῆς συνέβη σαφῶς αὐτὸν περὶ τούτου πιστωθῆναι" },
  { book: "3 Maccabees", chapter: 4, verse: 20, text: "λεγόντων μετὰ ἀποδείξεως καὶ τὴν χαρτηρίαν ἤδη καὶ τοὺς γραφικοὺς καλάμους ἐν οἷς ἐχρῶντο ἐκλελοιπέναι" },
  { book: "3 Maccabees", chapter: 4, verse: 21, text: "τοῦτο δὲ ἦν ἐνέργεια τῆς τοῦ βοηθοῦντος τοῖς Ιουδαίοις ἐξ οὐρανοῦ προνοίας ἀνικήτου" },
  { book: "3 Maccabees", chapter: 5, verse: 1, text: "τότε προσκαλεσάμενος Ἕρμωνα τὸν πρὸς τῇ τῶν ἐλεφάντων ἐπιμελείᾳ βαρείᾳ μεμεστωμένος ὀργῇ καὶ χόλῳ κατὰ πᾶν ἀμετάθετος" },
  { book: "3 Maccabees", chapter: 5, verse: 2, text: "ἐκέλευσεν ὑπὸ τὴν ἐπερχομένην ἡμέραν δαψιλέσι δράκεσι λιβανωτοῦ καὶ οἴνῳ πλείονι ἀκράτῳ ἅπαντας τοὺς ἐλέφαντας ποτίσαι ὄντας τὸν ἀριθμὸν πεντακοσίους καὶ ἀγριωθέντας τῇ τοῦ πόματος ἀφθόνῳ χορηγίᾳ εἰσαγαγεῖν πρὸς συνάντησιν τοῦ μόρου τῶν Ιουδαίων" },
  { book: "3 Maccabees", chapter: 5, verse: 3, text: "ὁ μὲν τάδε προστάσσων ἐτρέπετο πρὸς τὴν εὐωχίαν συναγαγὼν τοὺς μάλιστα τῶν φίλων καὶ τῆς στρατιᾶς ἀπεχθῶς ἔχοντας πρὸς τοὺς Ιουδαίους" },
  { book: "3 Maccabees", chapter: 5, verse: 4, text: "ὁ δὲ ἐλεφαντάρχης τὸ προσταγὲν ἀραρότως Ἕρμων συνετέλει" },
  { book: "3 Maccabees", chapter: 5, verse: 5, text: "οἵ τε πρὸς τούτοις λειτουργοὶ κατὰ τὴν ἑσπέραν ἐξιόντες τὰς τῶν ταλαιπωρούντων ἐδέσμευον χεῖρας τήν τε λοιπὴν ἐμηχανῶντο περὶ αὐτοὺς ἀσφάλειαν ἔννυχον δόξαντες ὁμοῦ λήμψεσθαι τὸ φῦλον πέρας τῆς ὀλεθρίας" },
  { book: "3 Maccabees", chapter: 5, verse: 6, text: "οἱ δὲ πάσης σκέπης ἔρημοι δοκοῦντες εἶναι τοῖς ἔθνεσιν Ιουδαῖοι διὰ τὴν πάντοθεν περιέχουσαν αὐτοὺς μετὰ δεσμῶν ἀνάγκην" },
  { book: "3 Maccabees", chapter: 5, verse: 7, text: "τὸν παντοκράτορα κύριον καὶ πάσης δυνάμεως δυναστεύοντα ἐλεήμονα θεὸν αὐτῶν καὶ πατέρα δυσκαταπαύστῳ βοῇ πάντες μετὰ δακρύων ἐπεκαλέσαντο δεόμενοι" },
  { book: "3 Maccabees", chapter: 5, verse: 8, text: "τὴν κατ’ αὐτῶν μεταστρέψαι βουλὴν ἀνοσίαν καὶ ῥύσασθαι αὐτοὺς μετὰ μεγαλομεροῦς ἐπιφανείας ἐκ τοῦ παρὰ πόδας ἐν ἑτοίμῳ μόρου" },
  { book: "3 Maccabees", chapter: 5, verse: 9, text: "τούτων μὲν οὖν ἐκτενῶς ἡ λιτανεία ἀνέβαινεν εἰς τὸν οὐρανόν" },
  { book: "3 Maccabees", chapter: 5, verse: 10, text: "ὁ δὲ Ἕρμων τοὺς ἀνηλεεῖς ἐλέφαντας ποτίσας πεπληρωμένους τῆς τοῦ οἴνου πολλῆς χορηγίας καὶ τοῦ λιβάνου μεμεστωμένους ὄρθριος ἐπὶ τὴν αὐλὴν παρῆν περὶ τούτων προσαγγεῖλαι τῷ βασιλεῖ" },
  { book: "3 Maccabees", chapter: 5, verse: 11, text: "τὸ δὲ ἀπ’ αἰῶνος χρόνου κτίσμα καλὸν ἐν νυκτὶ καὶ ἡμέρᾳ ἐπιβαλλόμενον ὑπὸ τοῦ χαριζομένου πᾶσιν οἷς ἂν αὐτὸς θελήσῃ ὕπνου μέρος ἀπέστειλεν εἰς τὸν βασιλέα" },
  { book: "3 Maccabees", chapter: 5, verse: 12, text: "καὶ ἡδίστῳ καὶ βαθεῖ κατεσχέθη τῇ ἐνεργείᾳ τοῦ δεσπότου τῆς ἀθέσμου μὲν προθέσεως πολὺ διεσφαλμένος τοῦ δὲ ἀμεταθέτου λογισμοῦ μεγάλως διεψευσμένος" },
  { book: "3 Maccabees", chapter: 5, verse: 13, text: "οἵ τε Ιουδαῖοι τὴν προσημανθεῖσαν ὥραν διαφυγόντες τὸν ἅγιον ᾔνουν θεὸν αὐτῶν καὶ πάλιν ἠξίουν τὸν εὐκατάλλακτον δεῖξαι μεγαλοσθενοῦς ἑαυτοῦ χειρὸς κράτος ἔθνεσιν ὑπερηφάνοις" },
  { book: "3 Maccabees", chapter: 5, verse: 14, text: "μεσούσης δὲ ἤδη δεκάτης ὥρας σχεδὸν ὁ πρὸς ταῖς κλήσεσιν τεταγμένος ἀθρόους τοὺς κλητοὺς ἰδὼν ἔνυξεν προσελθὼν τὸν βασιλέα" },
  { book: "3 Maccabees", chapter: 5, verse: 15, text: "καὶ μόλις διεγείρας ὑπέδειξε τὸν τῆς συμποσίας καιρὸν ἤδη παρατρέχοντα τὸν περὶ τούτων λόγον ποιούμενος" },
  { book: "3 Maccabees", chapter: 5, verse: 16, text: "ὃν ὁ βασιλεὺς λογισάμενος καὶ τραπεὶς εἰς τὸν πότον ἐκέλευσεν τοὺς παραγεγονότας ἐπὶ τὴν συμποσίαν ἄντικρυς ἀνακλῖναι αὐτοῦ" },
  { book: "3 Maccabees", chapter: 5, verse: 17, text: "οὗ καὶ γενομένου παρῄνει εἰς εὐωχίαν δόντας ἑαυτοὺς τὸ παρὸν τῆς συμποσίας ἐπὶ πολὺ γεραιρομένους εἰς εὐφροσύνην καταθέσθαι μέρος" },
  { book: "3 Maccabees", chapter: 5, verse: 18, text: "ἐπὶ πλεῖον δὲ προβαινούσης τῆς ὁμιλίας τὸν Ἕρμωνα προσκαλεσάμενος ὁ βασιλεὺς μετὰ πικρᾶς ἀπειλῆς ἐπυνθάνετο τίνος ἕνεκεν αἰτίας εἰάθησαν οἱ Ιουδαῖοι τὴν περιοῦσαν ἡμέραν περιβεβιωκότες" },
  { book: "3 Maccabees", chapter: 5, verse: 19, text: "τοῦ δὲ ὑποδείξαντος ἔτι νυκτὸς τὸ προσταγὲν ἐπὶ τέλος ἀγειοχέναι καὶ τῶν φίλων αὐτῷ προσμαρτυρησάντων" },
  { book: "3 Maccabees", chapter: 5, verse: 20, text: "τὴν ὠμότητα χείρονα Φαλάριδος ἐσχηκὼς ἔφη τῷ τῆς σήμερον ὕπνῳ χάριν ἔχειν αὐτούς ἀνυπερθέτως δὲ εἰς τὴν ἐπιτελοῦσαν ἡμέραν κατὰ τὸ ὅμοιον ἑτοίμασον τοὺς ἐλέφαντας ἐπὶ τὸν τῶν ἀθεμίτων Ιουδαίων ἀφανισμόν" },
  { book: "3 Maccabees", chapter: 5, verse: 21, text: "εἰπόντος δὲ τοῦ βασιλέως ἀσμένως πάντες μετὰ χαρᾶς οἱ παρόντες ὁμοῦ συναινέσαντες εἰς τὸν ἴδιον οἶκον ἕκαστος ἀνέλυσεν" },
  { book: "3 Maccabees", chapter: 5, verse: 22, text: "καὶ οὐχ οὕτως εἰς ὕπνον κατεχρήσαντο τὸν χρόνον τῆς νυκτός ὡς εἰς τὸ παντοίους μηχανᾶσθαι τοῖς ταλαιπώροις δοκοῦσιν ἐμπαιγμούς" },
  { book: "3 Maccabees", chapter: 5, verse: 23, text: "ἄρτι δὲ ἀλεκτρυὼν ἐκέκραγεν ὄρθριος καὶ τὰ θηρία καθωπλικὼς ὁ Ἕρμων ἐν τῷ μεγάλῳ περιστύλῳ διεκίνει" },
  { book: "3 Maccabees", chapter: 5, verse: 24, text: "τὰ δὲ κατὰ τὴν πόλιν πλήθη συνήθροιστο πρὸς τὴν οἰκτροτάτην θεωρίαν προσδοκῶντα τὴν πρωίαν μετὰ σπουδῆς" },
  { book: "3 Maccabees", chapter: 5, verse: 25, text: "οἱ δὲ Ιουδαῖοι κατὰ τὸν ἀμερῆ ψυχουλκούμενοι χρόνον πολύδακρυν ἱκετείαν ἐν μέλεσιν γοεροῖς τείνοντες τὰς χεῖρας εἰς τὸν οὐρανὸν ἐδέοντο τοῦ μεγίστου θεοῦ πάλιν αὐτοῖς βοηθῆσαι συντόμως" },
  { book: "3 Maccabees", chapter: 5, verse: 26, text: "οὔπω δὲ ἡλίου βολαὶ κατεσπείροντο καὶ τοῦ βασιλέως τοὺς φίλους ἐκδεχομένου ὁ Ἕρμων παραστὰς ἐκάλει πρὸς τὴν ἔξοδον ὑποδεικνύων τὸ πρόθυμον τοῦ βασιλέως ἐν ἑτοίμῳ κεῖσθαι" },
  { book: "3 Maccabees", chapter: 5, verse: 27, text: "τοῦ δὲ ἀποδεξαμένου καὶ καταπλαγέντος ἐπὶ τῇ παρανόμῳ ἐξόδῳ κατὰ πᾶν ἀγνωσίᾳ κεκρατημένος ἐπυνθάνετο τί τὸ πρᾶγμα ἐφ’ οὗ τοῦτο αὐτῷ μετὰ σπουδῆς τετέλεσται" },
  { book: "3 Maccabees", chapter: 5, verse: 28, text: "τοῦτο δὲ ἦν ἡ ἐνέργεια τοῦ πάντα δεσποτεύοντος θεοῦ τῶν πρὶν αὐτῷ μεμηχανημένων λήθην κατὰ διάνοιαν ἐντεθεικότος" },
  { book: "3 Maccabees", chapter: 5, verse: 29, text: "ὑπεδείκνυεν ὁ Ἕρμων καὶ πάντες οἱ φίλοι τὰ θηρία καὶ τὰς δυνάμεις ἡτοιμάσθαι βασιλεῦ κατὰ τὴν σὴν ἐκτενῆ πρόθεσιν" },
  { book: "3 Maccabees", chapter: 5, verse: 30, text: "ὁ δὲ ἐπὶ τοῖς ῥηθεῖσιν πληρωθεὶς βαρεῖ χόλῳ διὰ τὸ περὶ τούτων προνοίᾳ θεοῦ διεσκεδάσθαι πᾶν αὐτοῦ τὸ νόημα ἐνατενίσας μετὰ ἀπειλῆς εἶπεν" },
  { book: "3 Maccabees", chapter: 5, verse: 31, text: "ὅσοι γονεῖς παρῆσαν ἢ παίδων γόνοι τήνδε θηρσὶν ἀγρίοις ἐσκεύασα ἂν δαψιλῆ θοῖναν ἀντὶ τῶν ἀνεγκλήτων ἐμοὶ καὶ προγόνοις ἐμοῖς ἀποδεδειγμένων ὁλοσχερῆ βεβαίαν πίστιν ἐξόχως Ιουδαίων" },
  { book: "3 Maccabees", chapter: 5, verse: 32, text: "καίπερ εἰ μὴ διὰ τὴν τῆς συντροφίας στοργὴν καὶ τῆς χρείας τὸ ζῆν ἀντὶ τούτων ἐστερήθης" },
  { book: "3 Maccabees", chapter: 5, verse: 33, text: "οὕτως ὁ Ἕρμων ἀπροσδόκητον ἐπικίνδυνον ὑπήνεγκεν ἀπειλὴν καὶ τῇ ὁράσει καὶ τῷ προσώπῳ συνεστάλη" },
  { book: "3 Maccabees", chapter: 5, verse: 34, text: "ὁ καθεῖς δὲ τῶν φίλων σκυθρωπῶς ὑπεκρέων τοὺς συνηθροισμένους ἀπέλυσαν ἕκαστον ἐπὶ τὴν ἰδίαν ἀσχολίαν" },
  { book: "3 Maccabees", chapter: 5, verse: 35, text: "οἵ τε Ιουδαῖοι τὰ παρὰ τοῦ βασιλέως ἀκούσαντες τὸν ἐπιφανῆ θεὸν κύριον βασιλέα τῶν βασιλέων ᾔνουν καὶ τῆσδε τῆς βοηθείας αὐτοῦ τετευχότες" },
  { book: "3 Maccabees", chapter: 5, verse: 36, text: "κατὰ δὲ τοὺς αὐτοὺς νόμους ὁ βασιλεὺς συστησάμενος πᾶν τὸ συμπόσιον εἰς εὐφροσύνην τραπῆναι παρεκάλει" },
  { book: "3 Maccabees", chapter: 5, verse: 37, text: "τὸν δὲ Ἕρμωνα προσκαλεσάμενος μετὰ ἀπειλῆς εἶπεν ποσάκις δὲ δεῖ σοι περὶ τούτων αὐτῶν προστάττειν ἀθλιώτατε" },
  { book: "3 Maccabees", chapter: 5, verse: 38, text: "τοὺς ἐλέφαντας ἔτι καὶ νῦν καθόπλισον εἰς τὴν αὔριον ἐπὶ τὸν τῶν Ιουδαίων ἀφανισμόν" },
  { book: "3 Maccabees", chapter: 5, verse: 39, text: "οἱ δὲ συνανακείμενοι συγγενεῖς τὴν ἀσταθῆ διάνοιαν αὐτοῦ θαυμάζοντες προεφέροντο τάδε" },
  { book: "3 Maccabees", chapter: 5, verse: 40, text: "βασιλεῦ μέχρι τίνος ὡς ἀλόγους ἡμᾶς διαπειράζεις προστάσσων ἤδη τρίτον αὐτοὺς ἀφανίσαι καὶ πάλιν ἐπὶ τῶν πραγμάτων ἐκ μεταβολῆς ἀναλύων τὰ σοὶ δεδογμένα" },
  { book: "3 Maccabees", chapter: 5, verse: 41, text: "ὧν χάριν ἡ πόλις διὰ τὴν προσδοκίαν ὀχλεῖ καὶ πληθύουσα συστροφαῖς ἤδη καὶ κινδυνεύει πολλάκις διαρπασθῆναι" },
  { book: "3 Maccabees", chapter: 5, verse: 42, text: "ὅθεν ὁ κατὰ πάντα Φάλαρις βασιλεὺς ἐμπληθυνθεὶς ἀλογιστίας καὶ τὰς γινομένας πρὸς ἐπισκοπὴν τῶν Ιουδαίων ἐν αὐτῷ μεταβολὰς τῆς ψυχῆς παρ’ οὐδὲν ἡγούμενος ἀτελέστατον βεβαίως ὅρκον ὁρισάμενος τούτους μὲν ἀνυπερθέτως πέμψειν εἰς ᾅδην ἐν γόνασιν καὶ ποσὶν θηρίων ᾐκισμένους" },
  { book: "3 Maccabees", chapter: 5, verse: 43, text: "ἐπιστρατεύσαντα δὲ ἐπὶ τὴν Ιουδαίαν ἰσόπεδον πυρὶ καὶ δόρατι θήσεσθαι διὰ τάχους καὶ τὸν ἄβατον ἡμῖν αὐτῶν ναὸν πυρὶ πρηνέα ἐν τάχει τῶν συντελούντων ἐκεῖ θυσίας ἔρημον εἰς τὸν ἅπαντα χρόνον καταστήσειν" },
  { book: "3 Maccabees", chapter: 5, verse: 44, text: "τότε περιχαρεῖς ἀναλύσαντες οἱ φίλοι καὶ συγγενεῖς μετὰ πίστεως διέτασσον τὰς δυνάμεις ἐπὶ τοὺς εὐκαιροτάτους τόπους τῆς πόλεως πρὸς τὴν τήρησιν" },
  { book: "3 Maccabees", chapter: 5, verse: 45, text: "ὁ δὲ ἐλεφαντάρχης τὰ θηρία σχεδὸν ὡς εἰπεῖν εἰς κατάστεμα μανιῶδες ἀγειοχὼς εὐωδεστάτοις πόμασιν οἴνου λελιβανωμένου φοβερῶς κεκοσμημένα κατασκευαῖς" },
  { book: "3 Maccabees", chapter: 5, verse: 46, text: "περὶ τὴν ἕω τῆς πόλεως ἤδη πλήθεσιν ἀναριθμήτοις κατὰ τοῦ ἱπποδρόμου καταμεμεστωμένης εἰσελθὼν εἰς τὴν αὐλὴν ἐπὶ τὸ προκείμενον ὤτρυνε τὸν βασιλέα" },
  { book: "3 Maccabees", chapter: 5, verse: 47, text: "ὁ δὲ ὀργῇ βαρείᾳ γεμίσας δυσσεβῆ φρένα παντὶ τῷ βάρει σὺν τοῖς θηρίοις ἐξώρμησε βουλόμενος ἀτρώτῳ καρδίᾳ καὶ κόραις ὀφθαλμῶν θεάσασθαι τὴν ἐπίπονον καὶ ταλαίπωρον τῶν προσεσημαμμένων καταστροφήν" },
  { book: "3 Maccabees", chapter: 5, verse: 48, text: "ὡς δὲ τῶν ἐλεφάντων ἐξιόντων περὶ πύλην καὶ τῆς συνεπομένης ἐνόπλου δυνάμεως τῆς τε τοῦ πλήθους πορείας κονιορτὸν ἰδόντες καὶ βαρυηχῆ θόρυβον ἀκούσαντες οἱ Ιουδαῖοι" },
  { book: "3 Maccabees", chapter: 5, verse: 49, text: "ὑστάτην βίου ῥοπὴν αὐτοῖς ἐκείνην δόξαντες εἶναι τὸ τέλος τῆς ἀθλιωτάτης προσδοκίας εἰς οἶκτον καὶ γόους τραπέντες κατεφίλουν ἀλλήλους περιπλεκόμενοι τοῖς συγγενέσιν ἐπὶ τοὺς τραχήλους ἐπιπίπτοντες γονεῖς παισὶν καὶ μητέρες νεάνισιν ἕτεραι δὲ νεογνὰ πρὸς μαστοὺς ἔχουσαι βρέφη τελευταῖον ἕλκοντα γάλα" },
  { book: "3 Maccabees", chapter: 5, verse: 50, text: "οὐ μὴν δὲ ἀλλὰ καὶ τὰς ἔμπροσθεν αὐτῶν γεγενημένας ἀντιλήμψεις ἐξ οὐρανοῦ συνιδόντες πρηνεῖς ὁμοθυμαδὸν ῥίψαντες ἑαυτοὺς καὶ τὰ νήπια χωρίσαντες τῶν μαστῶν" },
  { book: "3 Maccabees", chapter: 5, verse: 51, text: "ἀνεβόησαν φωνῇ μεγάλῃ σφόδρα τὸν τῆς ἁπάσης δυνάμεως δυνάστην ἱκετεύοντες οἰκτῖραι μετὰ ἐπιφανείας αὐτοὺς ἤδη πρὸς πύλαις ᾅδου καθεστῶτας" },
  { book: "3 Maccabees", chapter: 6, verse: 1, text: "Ελεαζαρος δέ τις ἀνὴρ ἐπίσημος τῶν ἀπὸ τῆς χώρας ἱερέων ἐν πρεσβείῳ τὴν ἡλικίαν ἤδη λελογχὼς καὶ πάσῃ τῇ κατὰ τὸν βίον ἀρετῇ κεκοσμημένος τοὺς περὶ αὐτὸν καταστείλας πρεσβυτέρους ἐπικαλεῖσθαι τὸν ἅγιον θεὸν προσηύξατο τάδε" },
  { book: "3 Maccabees", chapter: 6, verse: 2, text: "βασιλεῦ μεγαλοκράτωρ ὕψιστε παντοκράτωρ θεὲ τὴν πᾶσαν διακυβερνῶν ἐν οἰκτιρμοῖς κτίσιν" },
  { book: "3 Maccabees", chapter: 6, verse: 3, text: "ἔπιδε ἐπὶ Αβρααμ σπέρμα ἐπὶ ἡγιασμένου τέκνα Ιακωβ μερίδος ἡγιασμένης σου λαὸν ἐν ξένῃ γῇ ξένον ἀδίκως ἀπολλύμενον πάτερ" },
  { book: "3 Maccabees", chapter: 6, verse: 4, text: "σὺ Φαραω πληθύνοντα ἅρμασιν τὸν πρὶν Αἰγύπτου ταύτης δυνάστην ἐπαρθέντα ἀνόμῳ θράσει καὶ γλώσσῃ μεγαλορρήμονι σὺν τῇ ὑπερηφάνῳ στρατιᾷ ποντοβρόχους ἀπώλεσας φέγγος ἐπιφάνας ἐλέους Ισραηλ γένει" },
  { book: "3 Maccabees", chapter: 6, verse: 5, text: "σὺ τὸν ἀναριθμήτοις δυνάμεσιν γαυρωθέντα Σενναχηριμ βαρὺν Ἀσσυρίων βασιλέα δόρατι τὴν πᾶσαν ὑποχείριον ἤδη λαβόντα γῆν καὶ μετεωρισθέντα ἐπὶ τὴν ἁγίαν σου πόλιν βαρέα λαλοῦντα κόμπῳ καὶ θράσει σύ δέσποτα ἔθραυσας ἔκδηλον δεικνὺς ἔθνεσιν πολλοῖς τὸ σὸν κράτος" },
  { book: "3 Maccabees", chapter: 6, verse: 6, text: "σὺ τοὺς κατὰ τὴν Βαβυλωνίαν τρεῖς ἑταίρους πυρὶ τὴν ψυχὴν αὐθαιρέτως δεδωκότας εἰς τὸ μὴ λατρεῦσαι τοῖς κενοῖς διάπυρον δροσίσας κάμινον ἐρρύσω μέχρι τριχὸς ἀπημάντους φλόγα πᾶσιν ἐπιπέμψας τοῖς ὑπεναντίοις" },
  { book: "3 Maccabees", chapter: 6, verse: 7, text: "σὺ τὸν διαβολαῖς φθόνου λέουσι κατὰ γῆς ῥιφέντα θηρσὶν βορὰν Δανιηλ εἰς φῶς ἀνήγαγες ἀσινῆ" },
  { book: "3 Maccabees", chapter: 6, verse: 8, text: "τόν τε βυθοτρεφοῦς ἐν γαστρὶ κήτους Ιωναν τηκόμενον ἀφιδὼν ἀπήμαντον πᾶσιν οἰκείοις ἀνέδειξας πάτερ" },
  { book: "3 Maccabees", chapter: 6, verse: 9, text: "καὶ νῦν μίσυβρι πολυέλεε τῶν ὅλων σκεπαστά τὸ τάχος ἐπιφάνηθι τοῖς ἀπὸ Ισραηλ γένους ὑπὸ ἐβδελυγμένων ἀνόμων ἐθνῶν ὑβριζομένοις" },
  { book: "3 Maccabees", chapter: 6, verse: 10, text: "εἰ δὲ ἀσεβείαις κατὰ τὴν ἀποικίαν ὁ βίος ἡμῶν ἐνέσχηται ῥυσάμενος ἡμᾶς ἀπὸ ἐχθρῶν χειρός ᾧ προαιρῇ δέσποτα ἀπόλεσον ἡμᾶς μόρῳ" },
  { book: "3 Maccabees", chapter: 6, verse: 11, text: "μὴ τοῖς ματαίοις οἱ ματαιόφρονες εὐλογησάτωσαν ἐπὶ τῇ τῶν ἠγαπημένων σου ἀπωλείᾳ λέγοντες οὐδὲ ὁ θεὸς αὐτῶν ἐρρύσατο αὐτούς" },
  { book: "3 Maccabees", chapter: 6, verse: 12, text: "σὺ δέ ὁ πᾶσαν ἀλκὴν καὶ δυναστείαν ἔχων ἅπασαν αἰώνιε νῦν ἔπιδε ἐλέησον ἡμᾶς τοὺς καθ’ ὕβριν ἀνόμων ἀλόγιστον ἐκ τοῦ ζῆν μεθισταμένους ἐν ἐπιβούλων τρόπῳ" },
  { book: "3 Maccabees", chapter: 6, verse: 13, text: "πτηξάτω δὲ ἔθνη σὴν δύναμιν ἀνίκητον σήμερον ἔντιμε δύναμιν ἔχων ἐπὶ σωτηρίᾳ Ιακωβ γένους" },
  { book: "3 Maccabees", chapter: 6, verse: 14, text: "ἱκετεύει σε τὸ πᾶν πλῆθος τῶν νηπίων καὶ οἱ τούτων γονεῖς μετὰ δακρύων" },
  { book: "3 Maccabees", chapter: 6, verse: 15, text: "δειχθήτω πᾶσιν ἔθνεσιν ὅτι μεθ’ ἡμῶν εἶ κύριε καὶ οὐκ ἀπέστρεψας τὸ πρόσωπόν σου ἀφ’ ἡμῶν ἀλλὰ καθὼς εἶπας ὅτι οὐδὲ ἐν τῇ γῇ τῶν ἐχθρῶν αὐτῶν ὄντων ὑπερεῖδον αὐτούς οὕτως ἐπιτέλεσον κύριε" },
  { book: "3 Maccabees", chapter: 6, verse: 16, text: "τοῦ δὲ Ελεαζαρου λήγοντος ἄρτι τῆς προσευχῆς ὁ βασιλεὺς σὺν τοῖς θηρίοις καὶ παντὶ τῷ τῆς δυνάμεως φρυάγματι κατὰ τὸν ἱππόδρομον παρῆγεν" },
  { book: "3 Maccabees", chapter: 6, verse: 17, text: "καὶ θεωρήσαντες οἱ Ιουδαῖοι μέγα εἰς οὐρανὸν ἀνέκραξαν ὥστε καὶ τοὺς παρακειμένους αὐλῶνας συνηχήσαντας ἀκατάσχετον πτόην ποιῆσαι παντὶ τῷ στρατοπέδῳ" },
  { book: "3 Maccabees", chapter: 6, verse: 18, text: "τότε ὁ μεγαλόδοξος παντοκράτωρ καὶ ἀληθινὸς θεὸς ἐπιφάνας τὸ ἅγιον αὐτοῦ πρόσωπον ἠνέῳξεν τὰς οὐρανίους πύλας ἐξ ὧν δεδοξασμένοι δύο φοβεροειδεῖς ἄγγελοι κατέβησαν φανεροὶ πᾶσιν πλὴν τοῖς Ιουδαίοις" },
  { book: "3 Maccabees", chapter: 6, verse: 19, text: "καὶ ἀντέστησαν καὶ τὴν δύναμιν τῶν ὑπεναντίων ἐπλήρωσαν ταραχῆς καὶ δειλίας καὶ ἀκινήτοις ἔδησαν πέδαις" },
  { book: "3 Maccabees", chapter: 6, verse: 20, text: "καὶ ὑπόφρικον καὶ τὸ τοῦ βασιλέως σῶμα ἐγενήθη καὶ λήθη τὸ θράσος αὐτοῦ τὸ βαρύθυμον ἔλαβεν" },
  { book: "3 Maccabees", chapter: 6, verse: 21, text: "καὶ ἀπέστρεψαν τὰ θηρία ἐπὶ τὰς συνεπομένας ἐνόπλους δυνάμεις καὶ κατεπάτουν αὐτὰς καὶ ὠλέθρευον" },
  { book: "3 Maccabees", chapter: 6, verse: 22, text: "καὶ μετεστράφη τοῦ βασιλέως ἡ ὀργὴ εἰς οἶκτον καὶ δάκρυα ὑπὲρ τῶν ἔμπροσθεν αὐτῷ μεμηχανευμένων" },
  { book: "3 Maccabees", chapter: 6, verse: 23, text: "ἀκούσας γὰρ τῆς κραυγῆς καὶ συνιδὼν πρηνεῖς ἅπαντας εἰς τὴν ἀπώλειαν δακρύσας μετ’ ὀργῆς τοῖς φίλοις διηπειλεῖτο λέγων" },
  { book: "3 Maccabees", chapter: 6, verse: 24, text: "παραβασιλεύετε καὶ τυράννους ὑπερβεβήκατε ὠμότητι καὶ ἐμὲ αὐτὸν τὸν ὑμῶν εὐεργέτην ἐπιχειρεῖτε τῆς ἀρχῆς ἤδη καὶ τοῦ πνεύματος μεθιστᾶν λάθρᾳ μηχανώμενοι τὰ μὴ συμφέροντα τῇ βασιλείᾳ" },
  { book: "3 Maccabees", chapter: 6, verse: 25, text: "τίς τοὺς κρατήσαντας ἡμῶν ἐν πίστει τὰ τῆς χώρας ὀχυρώματα τῆς οἰκίας ἀποστήσας ἕκαστον ἀλόγως ἤθροισεν ἐνθάδε" },
  { book: "3 Maccabees", chapter: 6, verse: 26, text: "τίς τοὺς ἐξ ἀρχῆς εὐνοίᾳ πρὸς ἡμᾶς κατὰ πάντα διαφέροντας πάντων ἐθνῶν καὶ τοὺς χειρίστους πλεονάκις ἀνθρώπων ἐπιδεδεγμένους κινδύνους οὕτως ἀθέσμως περιέβαλεν αἰκίαις" },
  { book: "3 Maccabees", chapter: 6, verse: 27, text: "λύσατε ἐκλύσατε ἄδικα δεσμά εἰς τὰ ἴδια μετ’ εἰρήνης ἐξαποστείλατε τὰ προπεπραγμένα παραιτησάμενοι" },
  { book: "3 Maccabees", chapter: 6, verse: 28, text: "ἀπολύσατε τοὺς υἱοὺς τοῦ παντοκράτορος ἐπουρανίου θεοῦ ζῶντος ὃς ἀφ’ ἡμετέρων μέχρι τοῦ νῦν προγόνων ἀπαραπόδιστον μετὰ δόξης εὐστάθειαν παρέχει τοῖς ἡμετέροις πράγμασιν" },
  { book: "3 Maccabees", chapter: 6, verse: 29, text: "ὁ μὲν οὖν ταῦτα ἔλεξεν οἱ δὲ ἐν ἀμερεῖ χρόνῳ λυθέντες τὸν ἅγιον σωτῆρα θεὸν αὐτῶν εὐλόγουν ἄρτι τὸν θάνατον ἐκπεφευγότες" },
  { book: "3 Maccabees", chapter: 6, verse: 30, text: "εἶτα ὁ βασιλεὺς εἰς τὴν πόλιν ἀπαλλαγεὶς τὸν ἐπὶ τῶν προσόδων προσκαλεσάμενος ἐκέλευσεν οἴνους τε καὶ τὰ λοιπὰ πρὸς εὐωχίαν ἐπιτήδεια τοῖς Ιουδαίοις χορηγεῖν ἐπὶ ἡμέρας ἑπτὰ κρίνας αὐτοὺς ἐν ᾧ τόπῳ ἔδοξαν τὸν ὄλεθρον ἀναλαμβάνειν ἐν τούτῳ ἐν εὐφροσύνῃ πάσῃ σωτήρια ἀγαγεῖν" },
  { book: "3 Maccabees", chapter: 6, verse: 31, text: "τότε οἱ τὸ πρὶν ἐπονείδιστοι καὶ πλησίον τοῦ ᾅδου μᾶλλον δὲ ἐπ’ αὐτῷ βεβηκότες ἀντὶ πικροῦ καὶ δυσαιάκτου μόρου κώθωνα σωτήριον συστησάμενοι τὸν εἰς πτῶσιν αὐτοῖς καὶ τάφον ἡτοιμασμένον τόπον κλισίαις κατεμερίσαντο πλήρεις χαρμονῆς" },
  { book: "3 Maccabees", chapter: 6, verse: 32, text: "καταλήξαντες δὲ θρήνων πανόδυρτον μέλος ἀνέλαβον ᾠδὴν πάτριον τὸν σωτῆρα καὶ τερατοποιὸν αἰνοῦντες θεόν οἰμωγήν τε πᾶσαν καὶ κωκυτὸν ἀπωσάμενοι χοροὺς συνίσταντο εὐφροσύνης εἰρηνικῆς σημεῖον" },
  { book: "3 Maccabees", chapter: 6, verse: 33, text: "ὡσαύτως δὲ καὶ ὁ βασιλεὺς περὶ τούτων συμπόσιον βαρὺ συναγαγὼν ἀδιαλείπτως εἰς οὐρανὸν ἀνθωμολογεῖτο μεγαλομερῶς ἐπὶ τῇ παραδόξῳ γενηθείσῃ αὐτῷ σωτηρίᾳ" },
  { book: "3 Maccabees", chapter: 6, verse: 34, text: "οἵ τε πρὶν εἰς ὄλεθρον καὶ οἰωνοβρώτους αὐτοὺς ἔσεσθαι τιθέμενοι καὶ μετὰ χαρᾶς ἀπογραψάμενοι κατεστέναξαν αἰσχύνην ἐφ’ ἑαυτοῖς περιβαλόμενοι καὶ τὴν πυρόπνουν τόλμαν ἀκλεῶς ἐσβεσμένοι" },
  { book: "3 Maccabees", chapter: 6, verse: 35, text: "οἵ τε Ιουδαῖοι καθὼς προειρήκαμεν συστησάμενοι τὸν προειρημένον χορὸν μετ’ εὐωχίας ἐν ἐξομολογήσεσιν ἱλαραῖς καὶ ψαλμοῖς διῆγον" },
  { book: "3 Maccabees", chapter: 6, verse: 36, text: "καὶ κοινὸν ὁρισάμενοι περὶ τούτων θεσμὸν ἐπὶ πᾶσαν τὴν παροικίαν αὐτῶν εἰς γενεὰς τὰς προειρημένας ἡμέρας ἄγειν ἔστησαν εὐφροσύνους οὐ πότου χάριν καὶ λιχνείας σωτηρίας δὲ τῆς διὰ θεὸν γενομένης αὐτοῖς" },
  { book: "3 Maccabees", chapter: 6, verse: 37, text: "ἐνέτυχον δὲ τῷ βασιλεῖ τὴν ἀπόλυσιν αὐτῶν εἰς τὰ ἴδια αἰτούμενοι" },
  { book: "3 Maccabees", chapter: 6, verse: 38, text: "ἀπογράφονται δὲ αὐτοὺς ἀπὸ πέμπτης καὶ εἰκάδος τοῦ Παχων ἕως τῆς τετάρτης τοῦ Επιφι ἐπὶ ἡμέρας τεσσαράκοντα συνίστανται δὲ αὐτῶν τὴν ἀπώλειαν ἀπὸ πέμπτης τοῦ Επιφι ἕως ἑβδόμης ἡμέραις τρισίν" },
  { book: "3 Maccabees", chapter: 6, verse: 39, text: "ἐν αἷς καὶ μεγαλοδόξως ἐπιφάνας τὸ ἔλεος αὐτοῦ ὁ τῶν πάντων δυνάστης ἀπταίστους αὐτοὺς ἐρρύσατο ὁμοθυμαδόν" },
  { book: "3 Maccabees", chapter: 6, verse: 40, text: "εὐωχοῦντο δὲ πάνθ’ ὑπὸ τοῦ βασιλέως χορηγούμενοι μέχρι τῆς τεσσαρεσκαιδεκάτης ἐν ᾗ καὶ τὴν ἐντυχίαν ἐποιήσαντο περὶ τῆς ἀπολύσεως αὐτῶν" },
  { book: "3 Maccabees", chapter: 6, verse: 41, text: "συναινέσας δὲ αὐτοῖς ὁ βασιλεὺς ἔγραψεν αὐτοῖς τὴν ὑπογεγραμμένην ἐπιστολὴν πρὸς τοὺς κατὰ πόλιν στρατηγοὺς μεγαλοψύχως τὴν ἐκτενίαν ἔχουσαν" },
  { book: "3 Maccabees", chapter: 7, verse: 1, text: "βασιλεὺς Πτολεμαῖος Φιλοπάτωρ τοῖς κατ’ Αἴγυπτον στρατηγοῖς καὶ πᾶσιν τοῖς τεταγμένοις ἐπὶ πραγμάτων χαίρειν καὶ ἐρρῶσθαι" },
  { book: "3 Maccabees", chapter: 7, verse: 2, text: "ἐρρώμεθα δὲ καὶ αὐτοὶ καὶ τὰ τέκνα ἡμῶν κατευθύναντος ἡμῖν τοῦ μεγάλου θεοῦ τὰ πράγματα καθὼς προαιρούμεθα" },
  { book: "3 Maccabees", chapter: 7, verse: 3, text: "τῶν φίλων τινὲς κατὰ κακοήθειαν πυκνότερον ἡμῖν παρακείμενοι συνέπεισαν ἡμᾶς εἰς τὸ τοὺς ὑπὸ τὴν βασιλείαν Ιουδαίους συναθροίσαντας σύστημα κολάσασθαι ξενιζούσαις ἀποστατῶν τιμωρίαις" },
  { book: "3 Maccabees", chapter: 7, verse: 4, text: "προφερόμενοι μηδέποτε εὐσταθήσειν τὰ πράγματα ἡμῶν δῑ ἣν ἔχουσιν οὗτοι πρὸς πάντα τὰ ἔθνη δυσμένειαν μέχρι ἂν συντελεσθῇ τοῦτο" },
  { book: "3 Maccabees", chapter: 7, verse: 5, text: "οἳ καὶ δεσμίους καταγαγόντες αὐτοὺς μετὰ σκυλμῶν ὡς ἀνδράποδα μᾶλλον δὲ ὡς ἐπιβούλους ἄνευ πάσης ἀνακρίσεως καὶ ἐξετάσεως ἐπεχείρησαν ἀνελεῖν νόμου Σκυθῶν ἀγριωτέραν ἐμπεπορπημένοι ὠμότητα" },
  { book: "3 Maccabees", chapter: 7, verse: 6, text: "ἡμεῖς δὲ ἐπὶ τούτοις σκληρότερον διαπειλησάμενοι καθ’ ἣν ἔχομεν πρὸς ἅπαντας ἀνθρώπους ἐπιείκειαν μόγις τὸ ζῆν αὐτοῖς χαρισάμενοι καὶ τὸν ἐπουράνιον θεὸν ἐγνωκότες ἀσφαλῶς ὑπερησπικότα τῶν Ιουδαίων ὡς πατέρα ὑπὲρ υἱῶν διὰ παντὸς συμμαχοῦντα" },
  { book: "3 Maccabees", chapter: 7, verse: 7, text: "τήν τε τοῦ φίλου ἣν ἔχουσιν βεβαίαν πρὸς ἡμᾶς καὶ τοὺς προγόνους ἡμῶν εὔνοιαν ἀναλογισάμενοι δικαίως ἀπολελύκαμεν πάσης καθ’ ὁντινοῦν αἰτίας τρόπον" },
  { book: "3 Maccabees", chapter: 7, verse: 8, text: "καὶ προστετάχαμεν ἑκάστῳ πάντας εἰς τὰ ἴδια ἐπιστρέφειν ἐν παντὶ τόπῳ μηθενὸς αὐτοὺς τὸ σύνολον καταβλάπτοντος μήτε ὀνειδίζειν περὶ τῶν γεγενημένων παρὰ λόγον" },
  { book: "3 Maccabees", chapter: 7, verse: 9, text: "γινώσκετε γὰρ ὅτι κατὰ τούτων ἐάν τι κακοτεχνήσωμεν πονηρὸν ἢ ἐπιλυπήσωμεν αὐτοὺς τὸ σύνολον οὐκ ἄνθρωπον ἀλλὰ τὸν πάσης δεσπόζοντα δυνάμεως θεὸν ὕψιστον ἀντικείμενον ἡμῖν ἐπ’ ἐκδικήσει τῶν πραγμάτων κατὰ πᾶν ἀφεύκτως διὰ παντὸς ἕξομεν ἔρρωσθε" },
  { book: "3 Maccabees", chapter: 7, verse: 10, text: "λαβόντες δὲ τὴν ἐπιστολὴν ταύτην οὐκ ἐσπούδασαν εὐθέως γενέσθαι περὶ τὴν ἄφοδον ἀλλὰ τὸν βασιλέα προσηξίωσαν τοὺς ἐκ τοῦ γένους τῶν Ιουδαίων τὸν ἅγιον θεὸν αὐθαιρέτως παραβεβηκότας καὶ τοῦ θεοῦ τὸν νόμον τυχεῖν δῑ αὐτῶν τῆς ὀφειλομένης κολάσεως" },
  { book: "3 Maccabees", chapter: 7, verse: 11, text: "προφερόμενοι τοὺς γαστρὸς ἕνεκεν τὰ θεῖα παραβεβηκότας προστάγματα μηδέποτε εὐνοήσειν μηδὲ τοῖς τοῦ βασιλέως πράγμασιν" },
  { book: "3 Maccabees", chapter: 7, verse: 12, text: "ὁ δὲ τἀληθὲς αὐτοὺς λέγειν παραδεξάμενος καὶ παραινέσας ἔδωκεν αὐτοῖς ἄδειαν πάντων ὅπως τοὺς παραβεβηκότας τοῦ θεοῦ τὸν νόμον ἐξολεθρεύσωσιν κατὰ πάντα τὸν ὑπὸ τὴν βασιλείαν αὐτοῦ τόπον μετὰ παρρησίας ἄνευ πάσης βασιλικῆς ἐξουσίας καὶ ἐπισκέψεως" },
  { book: "3 Maccabees", chapter: 7, verse: 13, text: "τότε κατευφημήσαντες αὐτόν ὡς πρέπον ἦν οἱ τούτων ἱερεῖς καὶ πᾶν τὸ πλῆθος ἐπιφωνήσαντες τὸ αλληλουια μετὰ χαρᾶς ἀνέλυσαν" },
  { book: "3 Maccabees", chapter: 7, verse: 14, text: "οὕτως τε τὸν ἐμπεσόντα τῶν μεμιαμμένων ὁμοεθνῆ κατὰ τὴν ὁδὸν ἐκολάζοντο καὶ μετὰ παραδειγματισμῶν ἀνῄρουν" },
  { book: "3 Maccabees", chapter: 7, verse: 15, text: "ἐκείνῃ δὲ τῇ ἡμέρᾳ ἀνεῖλον ὑπὲρ τοὺς τριακοσίους ἄνδρας ἣν καὶ ἤγαγον εὐφροσύνην μετὰ χαρᾶς βεβήλους χειρωσάμενοι" },
  { book: "3 Maccabees", chapter: 7, verse: 16, text: "αὐτοὶ δὲ οἱ μέχρι θανάτου τὸν θεὸν ἐσχηκότες παντελῆ σωτηρίας ἀπόλαυσιν εἰληφότες ἀνέζευξαν ἐκ τῆς πόλεως παντοίοις εὐωδεστάτοις ἄνθεσιν κατεστεμμένοι μετ’ εὐφροσύνης καὶ βοῆς ἐν αἴνοις καὶ παμμελέσιν ὕμνοις εὐχαριστοῦντες τῷ θεῷ τῶν πατέρων αὐτῶν αἰωνίῳ σωτῆρι τοῦ Ισραηλ" },
  { book: "3 Maccabees", chapter: 7, verse: 17, text: "παραγενηθέντες δὲ εἰς Πτολεμαίδα τὴν ὀνομαζομένην διὰ τὴν τοῦ τόπου ἰδιότητα ῥοδοφόρον ἐν ᾗ προσέμεινεν αὐτοὺς ὁ στόλος κατὰ κοινὴν αὐτῶν βουλὴν ἡμέρας ἑπτά" },
  { book: "3 Maccabees", chapter: 7, verse: 18, text: "ἐκεῖ ἐποίησαν πότον σωτήριον τοῦ βασιλέως χορηγήσαντος αὐτοῖς εὐψύχως τὰ πρὸς τὴν ἄφιξιν πάντα ἑκάστῳ ἕως εἰς τὴν ἰδίαν οἰκίαν" },
  { book: "3 Maccabees", chapter: 7, verse: 19, text: "καταχθέντες δὲ μετ’ εἰρήνης ἐν ταῖς πρεπούσαις ἐξομολογήσεσιν ὡσαύτως κἀκεῖ ἔστησαν καὶ ταύτας ἄγειν τὰς ἡμέρας ἐπὶ τὸν τῆς παροικίας αὐτῶν χρόνον εὐφροσύνους" },
  { book: "3 Maccabees", chapter: 7, verse: 20, text: "ἃς καὶ ἀνιερώσαντες ἐν στήλῃ κατὰ τὸν τῆς συμποσίας τόπον προσευχῆς καθιδρύσαντες ἀνέλυσαν ἀσινεῖς ἐλεύθεροι ὑπερχαρεῖς διά τε γῆς καὶ θαλάσσης καὶ ποταμοῦ ἀνασῳζόμενοι τῇ τοῦ βασιλέως ἐπιταγῇ ἕκαστος εἰς τὴν ἰδίαν" },
  { book: "3 Maccabees", chapter: 7, verse: 21, text: "καὶ πλείστην ἢ ἔμπροσθεν ἐν τοῖς ἐχθροῖς ἐξουσίαν ἐσχηκότες μετὰ δόξης καὶ φόβου τὸ σύνολον ὑπὸ μηδενὸς διασεισθέντες τῶν ὑπαρχόντων" },
  { book: "3 Maccabees", chapter: 7, verse: 22, text: "καὶ πάντα τὰ ἑαυτῶν πάντες ἐκομίσαντο ἐξ ἀπογραφῆς ὥστε τοὺς ἔχοντάς τι μετὰ φόβου μεγίστου ἀποδοῦναι αὐτοῖς τὰ μεγαλεῖα τοῦ μεγίστου θεοῦ ποιήσαντος τελείως ἐπὶ σωτηρίᾳ αὐτῶν" },
  { book: "3 Maccabees", chapter: 7, verse: 23, text: "εὐλογητὸς ὁ ῥύστης Ισραηλ εἰς τοὺς ἀεὶ χρόνους αμην" },
  // 3 Meqabyan (208 verses)
  { book: "3 Meqabyan", chapter: 1, verse: 1, text: "Christ shall bring joy to the people of Egypt; for He shall come to them in a later era to take revenge and destroy the Devil, who wronged the kind and innocent, who misled people, and who hates the work of his Creator." },
  { book: "3 Meqabyan", chapter: 1, verse: 2, text: "He shall take revenge and destroy him. He shall turn the Devil's lordship into misery and humiliation, for he has been arrogant in his reasoning." },
  { book: "3 Meqabyan", chapter: 1, verse: 3, text: "He shall turn his lordship into humiliation; for the Devil said, \"I will enter the midst of the sea, I will ascend to Heaven, I will look into the depths, and I will seize the children of Adam like bird chicks. Who is higher than I?\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 4, text: "\"Because I influenced their minds to distance them from the straight Law of the Lord—as I will grow stronger over those who live in this world unless they do the Lord’s Will—there is no one who will remove me from my authority,\" he said." },
  { book: "3 Meqabyan", chapter: 1, verse: 5, text: "\"For I will be the reason they return to a path that is smooth for going to Gehenna (Hell) with me.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 6, text: "\"Those who loved Him and kept His Law hate me for this reason; but those who departed from the Law of their Lord and who erred will come to me, love me, and keep my oath. As I make their reasoning evil and change their thoughts so they do not return to their Creator, they will do my bidding as I commanded them.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 7, text: "\"And when I show them the money of this world, I will mislead their reasoning from the straight Law; and when I show them beautiful and attractive daughters, I will distance them from the straight Law by these.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 8, text: "\"And when I show them shining Indian jewels, silver, and gold, I will distance them by these also from the straight Law, so they might return to my work.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 9, text: "\"And when I show them fine clothes, red silk, white silk, and linens, I will distance them by these also from the straight Law and return them to my thoughts. When I multiply their money and livestock like sand and show it to them, by this also I will return them to my work.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 10, text: "\"And when I show them jealousy born of arrogance over women, and show them anger and quarrels, by all this I will return them to my work.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 11, text: "\"And when I show them signs, I will dwell in the minds of their companions; I will place a sign for each individual in their own reasoning, showing them signs in words to mislead them.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 12, text: "\"And for those in whom I dwell, I will show them signs—whether it be in the movement of the stars, the passing of clouds, the flickering of fire, or the cries of beasts and birds. As they are my dwellings, I will place signs in their reasoning through all these things.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 13, text: "\"They will speak and give signs to their companions; and just as those naysayers told them, I will go before them and be a sign for them.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 14, text: "\"I will perform these signs for them so that those who examine them might be misled; they will pay wages to magicians and tell their companions, 'There are no experts like so-and-so, for whom things happen exactly as they spoke; they know prophecy, they distinguish good from evil, and all things happen according to their word.'\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 15, text: "\"I will be joyful when they speak this, so that those who perish and err because of me might increase and the children of Adam might perish. For the Lord humbled me from my rank because of their father, Adam, when I said, 'I will not bow to Adam, who is lower than me.'\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 16, text: "\"And I will take to destruction all his children who live firmly under my command. I have an oath from the Lord who created me, that all persons whom I mislead might descend to Gehenna with me.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 17, text: "\"When He increased His anger against me, and when He commanded that I be bound and cast into Gehenna—when my Creator commanded this—I interceded with my Lord. I pleaded before Him, saying: 'As You are angry with me, and as You have admonished me by Your punishment and chastised me by Your wrath—Lord, my Lord, grant me a delay that I might speak one thing before You.'\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 18, text: "\"And my Lord answered me, saying: 'Speak, I will hear you.' At that time I began my plea to Him, saying: 'Since I was humbled from my rank, let the people whom I mislead be like me in Gehenna, where I will receive tribulation.'\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 19, text: "\"'And let those who refused me, who did not err because of me, who did not keep my command, but who did Your Command, fulfilled Your Will, and kept Your Word—let them belong to Your Lordship. Since they did not err as I misled them, having refused what I taught them—when You loved me, let them now take the crown You once gave to me.'\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 20, text: "\"'Give them the crown of the authorities called Satans who were sent with me; seat them upon my throne at Your Right hand, which became a wilderness because of me and my hosts.'\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 21, text: "\"'And let them praise You as You desire; let them be like my hosts and like me. Because You hated me and loved those created from ashes and earth—as my authority has perished and theirs has been raised high—let them praise You as You desire.'\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 22, text: "\"My Lord answered me, saying: 'As you have misled them while they saw and heard, if you misled them without them loving My Order, let them belong to you according to your will and your word.'\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 23, text: "\"'If they leave the Word of the Books and My Command and come to you—and if you mislead them while their destruction also saddens Me—let them receive tribulation in Gehenna just like you,' He told me.\"" },
  { book: "3 Meqabyan", chapter: 1, verse: 24, text: "\"You shall receive tribulation in Gehenna until eternity; you shall have no exit from Gehenna forever—neither those whom you misled, nor you.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 1, text: "\"But I shall bequeath your throne of lordship to those whom you failed to mislead, like My servant Job.\" The Lord who rules all said: \"I will give the Kingdom of Heaven to those whom you failed to mislead.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 2, text: "\"And I (the Devil) provoke the children of Adam in all things; if it were possible for me to mislead them, I would not let them remain firm in good work. For I provoke all the children of Adam, and I make the pleasures of this world sweet to them.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 3, text: "\"Whether it be through the love of drink, food, and clothes; or through the love of material things; or through withholding and giving...\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 4, text: "\"...or through the desire to hear and see; or the desire to touch and go; or through increasing arrogance and possessions; or through the love of dreams and slumber...\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 5, text: "\"...or through increasing drunkenness and drinking; or through increasing insults and anger; or through speaking games and useless things...\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 6, text: "\"...or through quarrels and backbiting their companions; or through looking at the attractive daughters of this world; or through smelling perfumes and fragrances that mislead them...\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 7, text: "\"...I hate them through all this so that they cannot be saved. I distance them from the Law of the Lord so they might enter with me into the destruction by which I was humbled from my rank.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 8, text: "And the prophet told him: \"You who destroy people, perish! When you departed from the Law of the Lord and committed a crime in your stubbornness and arrogance—by saddening your Creator and not worshipping Him in your pride—will you still be arrogant toward the Lord’s creation?\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 9, text: "\"When your Creator was angry with you, He humbled you from your rank because of your evil work. Why do you lead Adam toward sin—he whom his Creator made from the earth, whom He made as a beloved being, and whom He placed for His praise?\" he told him." },
  { book: "3 Meqabyan", chapter: 2, verse: 10, text: "\"While you—who are subtle and were created from wind and fire—were arrogant in saying, 'I am the Creator'...\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 11, text: "\"...when you boasted, the Lord saw your evil work. After you and your hosts denied the Lord, He created Adam so that he might praise Him in your place, that he might praise His Name without ceasing.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 12, text: "\"Because you made yourself prouder than all the hosts of Angels who are like you, the Lord created Adam and his children so they might praise the Lord’s Name in place of the praise you and your rejected hosts once gave.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 13, text: "\"For this reason, the Lord destroyed you, separating you from all the Angelic chiefs like you. Your hosts, who were of one mind with you—you all went forth and erred from the praise of the Lord because of your useless arrogance and stubbornness. You were arrogant toward your Creator, and toward no other.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 14, text: "\"For this reason, He created Adam from the earth so He might be praised by humble beings. He gave him a Command and Law, saying: 'Do not eat from the fruit of the fig tree.'\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 15, text: "\"And He appointed him over all the creation He made. He notified him, saying: 'Do not eat from the one fig tree that brings death, lest you bring death upon yourself; yet you may eat fruit from all the trees in the midst of the Garden.'\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 16, text: "\"When you heard this Word, you placed treachery in his heart by the words you spoke through your tongue to Eve, who was formed from Adam’s rib.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 17, text: "\"You misled Adam, who was clean, with firm treachery so that you might make him a law-breaker just like you.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 18, text: "\"When you misled Eve—who was created like an innocent dove and did not know your malice—you made her betray through your success and your crooked words. After you misled Eve, who was created first, she also went and misled the Lord’s creation, Adam, who was also created from the earth.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 19, text: "\"You caused him to betray in a disturbance that did not come from his own arrogance; you made him deny his Creator's Word, and you destroyed Adam in your pride.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 20, text: "\"In your malice, you distanced him from his Creator’s Love; by your reasoning, you sent him away from the Garden where joy is; and by your hindrance, you made him give up the food of the Garden.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 21, text: "\"For from antiquity, you have quarreled with the innocent creation, Adam, so that you might lower him toward Sheol where you will receive hardship—sending him away from the Love that brought him forth and created him from non-existence into true life. By your lies, you made him thirst for a drink from the Garden.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 22, text: "\"And although he is earthly, the Lord made him like a subtle Angel who praises his Creator in his flesh, his soul, and his reasoning.\"" },
  { book: "3 Meqabyan", chapter: 2, verse: 23, text: "\"He created many thoughts for him, like the praise of harps in all their different styles.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 1, text: "\"But He created only one thought for you, so that you might give total praise while you were sent where your Creator sent you.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 2, text: "\"But to Adam were given five evil thoughts and five good thoughts—ten thoughts in total.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 3, text: "\"Furthermore, he has many thoughts like the waves of the sea, or like a whirlwind that scatters dust lifted from the earth, or like the shaking waves of the sea. From the abundance of his unnumbered thoughts in his heart—like unnumbered raindrops—such are the thoughts of Adam.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 4, text: "\"But your thought is only one. As you are not fleshly, you have no other thought.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 5, text: "\"But you dwelled in the mind of the snake; in evil treachery, you destroyed Adam, who was a single body. Eve heard the words of the snake, and having heard, she did as she was commanded.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 6, text: "\"After she ate the fig fruit, she came and misled the Lord’s first creation, Adam. She brought death upon him and upon her children because she broke her Creator’s Command.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 7, text: "\"They were sent out from the Garden by the Lord’s true Judgment. He comforted them in the land where they were sent through the children born of their nature and by the crops found in the earth; yet He did not end the quarrel with the Garden.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 8, text: "\"When you expelled them directly from the Garden, so that they might plant plants and raise children to be comforted—renewing their reasoning in the fruit of the earth that the earth prepared—and that they might be comforted by the fruit of the earth and the fruit of the Garden which the Lord gave them...\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 9, text: "\"...the Lord gave them trees more green than the trees of the Garden. Eve and Adam—whom you sent away from the Garden when they ate from it—were fully comforted from their sadness.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 10, text: "\"As the Lord knows how to comfort His creation, their minds were calmed because of their children and the crops found from the earth.\"" },
  { book: "3 Meqabyan", chapter: 3, verse: 11, text: "\"Although they were sent to this world that grows nettles and thorns, they strengthened their minds through water and grain.\"" },
  { book: "3 Meqabyan", chapter: 4, verse: 1, text: "The Lord has it in His power to ransom Adam, and He shall put you (the Devil) to shame. He will save a sheep from a wolf's mouth—that is, Adam from the Devil." },
  { book: "3 Meqabyan", chapter: 4, verse: 2, text: "However, you shall go toward Gehenna, taking with you the people whom you ruled." },
  { book: "3 Meqabyan", chapter: 4, verse: 3, text: "Those who kept the Law of their Creator, the Lord, shall be joyful with Him. He hid them from evil works so that He might make them His own treasure, and so they might praise Him with the honored Angels who did not break the Law of their Creator as you did." },
  { book: "3 Meqabyan", chapter: 4, verse: 4, text: "But the Lord—who chose you and gave you more than all the Angels like you so that you might praise Him with His servant Angels—withheld a lofty throne from you because of your arrogance." },
  { book: "3 Meqabyan", chapter: 4, verse: 5, text: "Instead, you became infamous and were called one who loves false godhood, and your hosts were called demons." },
  { book: "3 Meqabyan", chapter: 4, verse: 6, text: "But those who loved the Lord shall be His kindred, like the honored Angels; and the Seraphim and Cherubim who praise Him stretch forth their wings and praise Him without ceasing." },
  { book: "3 Meqabyan", chapter: 4, verse: 7, text: "But in your arrogance and laziness, you destroyed your own praise, though you were meant to praise Him always with your host and your kindred who were created in your likeness." },
  { book: "3 Meqabyan", chapter: 4, verse: 8, text: "Lest the praise of the Lord—who created you as a tenth tribe—be diminished when you forgot to praise Him; it seemed to you that it was impossible for Him to create another creation like you. And lest His praise be diminished when you were separated from the unity of your brothers, He created Adam in your place." },
  { book: "3 Meqabyan", chapter: 4, verse: 9, text: "But in the arrogance of your reasoning, you neglected the praise of the Lord who created you; therefore He was angry with you. He ridiculed you, bound you, and banished you to Gehenna along with your hosts." },
  { book: "3 Meqabyan", chapter: 4, verse: 10, text: "He brought soil from the Earth with His glorified Hands; and adding fire, water, and wind, He created Adam in His own Example and Features." },
  { book: "3 Meqabyan", chapter: 4, verse: 11, text: "He appointed him over all the creation He made by His authority, so that His praise might be fulfilled by the praise you should have given Him. Adam’s praise became one with the Angels’ praise, and their praise was equal." },
  { book: "3 Meqabyan", chapter: 4, verse: 12, text: "But in the stubbornness of your reasoning and your arrogance, you were humbled from your rank; and having departed from the Lordship of the One who created you, you destroyed yourself." },
  { book: "3 Meqabyan", chapter: 4, verse: 13, text: "Know that His praise was not diminished; for the Lord created Adam, who praised Him in the counsel of his reasoning, so that the praise of His Divinity would not be lessened." },
  { book: "3 Meqabyan", chapter: 4, verse: 14, text: "For He knows all things before they are done. He knew you before He created you—that you would demolish His Command. As there was a hidden counsel with Him before He created the world, when you denied Him, He created His servant Adam in His own Features and Example." },
  { book: "3 Meqabyan", chapter: 4, verse: 15, text: "Just as Solomon spoke, saying: \"Before the hills were created, and before the world was successfully made, and before the winds that are the foundations of the Earth were created...\"" },
  { book: "3 Meqabyan", chapter: 4, verse: 16, text: "\"...and before He established the foundations of the hills and mountains, and before the work of this world was set, and before the light of the moon and Sun shone, or the cycles of the stars were known...\"" },
  { book: "3 Meqabyan", chapter: 4, verse: 17, text: "\"...and before daylight and night alternated, and before the sea was bounded by sand—before any of the created beings were made...\"" },
  { book: "3 Meqabyan", chapter: 4, verse: 18, text: "\"...and before all that is seen today was seen, or any names called today were named—I, Solomon, was created.\" Angels like you, and His servant Adam, were already in the Lord's Mind." },
  { book: "3 Meqabyan", chapter: 4, verse: 19, text: "He created Adam so that His glorified Name might be praised when you mutinied, and so He might be praised by His humble servant Adam—who was created from Earth—when you became arrogant." },
  { book: "3 Meqabyan", chapter: 4, verse: 20, text: "For being in Heaven, the Lord hears the plea of the poor, and He loves the praise of the humble." },
  { book: "3 Meqabyan", chapter: 4, verse: 21, text: "He loves to save those in whom He dwells who fear Him; yet as He does not love the power of horses, and as He does not favor the lap of a concubine, the Lord shall ignore the deeds of the arrogant." },
  { book: "3 Meqabyan", chapter: 4, verse: 22, text: "And they shall weep while they cry out because of the sins they committed." },
  { book: "3 Meqabyan", chapter: 4, verse: 23, text: "You (the Devil) failed to plead in repentance." },
  { book: "3 Meqabyan", chapter: 4, verse: 24, text: "But Adam, who was created from Earth, returned in repentance, weeping bitterly before the Lord because of his sin." },
  { book: "3 Meqabyan", chapter: 4, verse: 25, text: "But in your stubbornness and your heart’s arrogance, you did not know the work of Love, nor did you know repentance. You failed to plead before your Creator, the Lord, in repentance, mourning, and sadness." },
  { book: "3 Meqabyan", chapter: 4, verse: 26, text: "But Adam, who is ashes and earth, returned to repentance in mourning and sadness, and he returned to humility and the work of Love." },
  { book: "3 Meqabyan", chapter: 4, verse: 27, text: "But you did not humble your reasoning or yourself before the Lord who created you." },
  { book: "3 Meqabyan", chapter: 4, verse: 28, text: "As for Adam, he humbled himself and pleaded regarding the iniquity he committed; he was not proud." },
  { book: "3 Meqabyan", chapter: 4, verse: 29, text: "As you have totally produced crime, it originated from you; yet it was not Adam who produced that error. In your arrogance, you took him with you toward your destruction." },
  { book: "3 Meqabyan", chapter: 4, verse: 30, text: "Before He created you both, He knew you were sinners; and knowing your works, He knew that what was done came from the arrogance of your heart." },
  { book: "3 Meqabyan", chapter: 4, verse: 31, text: "But He restored Adam—who was without arrogance or malice—through repentance, mourning, and sadness." },
  { book: "3 Meqabyan", chapter: 4, verse: 32, text: "For a person who does wrong and does not plead in repentance has multiplied his iniquity more than his earlier sins. In the arrogance of your heart, you failed to plead in repentance; but a person who pleads and weeps, entering repentance before his Creator, the Lord..." },
  { book: "3 Meqabyan", chapter: 4, verse: 33, text: "...he has truly repented. He has found the work by which he will be saved, so that he might fear the Heart of his Lord. He pleaded before his Creator with bowing and much repentance; and because of that earlier tribulation, the Lord shall lighten his sin so He is not angry with His servant, and He will forgive his former sins." },
  { book: "3 Meqabyan", chapter: 4, verse: 34, text: "If he does not return to his former sin and continues in this way, this is perfect repentance. Adam did not forget to think of his Creator nor to implore Him in repentance." },
  { book: "3 Meqabyan", chapter: 4, verse: 35, text: "And you (the Devil)—plead in repentance toward your Creator, and do not wrong them because they are flesh and blood; for the Lord who created them knows their weakness. Do not wrong the people He created by His authority." },
  { book: "3 Meqabyan", chapter: 4, verse: 36, text: "And after their souls are separated from their flesh, their flesh shall be dust until the day the Lord chooses." },
  { book: "3 Meqabyan", chapter: 5, verse: 1, text: "Know the Lord who created you; as He created you in His Features and Example while you are on Earth, do not forget the Lord who established you, saved you, and whom Israel glorified. He placed you in the Garden so you might be joyful and tend the Earth." },
  { book: "3 Meqabyan", chapter: 5, verse: 2, text: "When you broke His Command, He sent you away from the Garden toward this world—which He cursed because of you—that grows nettles and thorns." },
  { book: "3 Meqabyan", chapter: 5, verse: 3, text: "For you are Earth, and she (the ground) is Earth; you are dust, and she is dust; you are soil, and she is soil. You are fed by the grain found from her, and you will return to her. You will be soil until He chooses to raise you, and He shall examine the sins you committed and all your iniquity." },
  { book: "3 Meqabyan", chapter: 5, verse: 4, text: "Know what you will answer Him at that time. Think of the good and evil you did in this world; examine whether the evil or the good would abound—test yourself." },
  { book: "3 Meqabyan", chapter: 5, verse: 5, text: "If you do good, it is a good thing for you, so that you might be joyful on the day when the dead arise." },
  { book: "3 Meqabyan", chapter: 5, verse: 6, text: "But if you do evil, woe to you! For you will receive hardship according to the work of your hands and the evil of your reasoning. If you do an evil thing to your companion and do not fear the Lord, you will receive your hardship." },
  { book: "3 Meqabyan", chapter: 5, verse: 7, text: "And if you betray your companion, and if you call on the Lord’s Name and swear a lie—as you will receive hardship according to your work—woe to you." },
  { book: "3 Meqabyan", chapter: 5, verse: 8, text: "You tell lies to your companion, pretending they are the Truth, even though you know you spoke a lie." },
  { book: "3 Meqabyan", chapter: 5, verse: 9, text: "You persuade those around you with your falsehoods as if they were the Truth, multiplying things that are not true; you will receive hardship according to your sin. You deny your companion while telling him, \"I will give to you,\" what you have no intention of giving." },
  { book: "3 Meqabyan", chapter: 5, verse: 10, text: "When you say \"I will give\" in your pure reasoning, demons make use of you like dogs; they make you forget everything. Whether you withhold or desire to give, they do not know the person for whom they gather wealth. As it has been said: \"They shall grow fat\"—the money of this world appetizes you so that you might \"fatten\" the money that will not benefit you and that you will not eat." },
  { book: "3 Meqabyan", chapter: 5, verse: 11, text: "And again, as it has been said: \"Adam’s lying children make a false balance.\" As for them, they go from robbery to robbery; the money of this world appetizes you." },
  { book: "3 Meqabyan", chapter: 5, verse: 12, text: "O people, do not place your hope in distorted scales and balances, in stealing another’s money, in taking money through transgression, in infringing on your companion’s property, or in stealing his field. Avoid all the lies you do for your own profit at your companion’s expense." },
  { book: "3 Meqabyan", chapter: 5, verse: 13, text: "If you do this, you will receive your hardship according to your work." },
  { book: "3 Meqabyan", chapter: 5, verse: 14, text: "O people, be fed by the honest work of your hands; do not desire robbery. Do not love to rob and eat another’s money without justice or by what is not due." },
  { book: "3 Meqabyan", chapter: 5, verse: 15, text: "Even if you eat it, it will not satisfy you. When you die, you will leave it for another; even if you grow fat on it, it will not benefit you." },
  { book: "3 Meqabyan", chapter: 5, verse: 16, text: "And if your money increases, do not let it distort your reasoning. As the money of sinners is like smoke from a griddle that the wind takes away, the small amount of money accumulated in Truth is better than the wealth of sinners." },
  { book: "3 Meqabyan", chapter: 6, verse: 1, text: "Think of the day when you will die—when your soul is separated from your flesh, when you leave your money for another, and when you go on the path you do not know. Think of the tribulation that shall come upon you." },
  { book: "3 Meqabyan", chapter: 6, verse: 2, text: "The demons that will receive you are evil; their features are ugly and they are frightening in their appearance. They won't listen to your words, and you won't listen to theirs." },
  { book: "3 Meqabyan", chapter: 6, verse: 3, text: "Because you did not do the Will of your Creator, they will not hear you in your plea when you beg them; for this reason, they will completely terrify you." },
  { book: "3 Meqabyan", chapter: 6, verse: 4, text: "But those who fulfilled the Lord’s Will have no fear, for the demons fear them. However, demons shall ridicule the souls of sinners." },
  { book: "3 Meqabyan", chapter: 6, verse: 5, text: "But the souls of kind people shall be joyful with the Angels in happiness; they shall be made joyful because they scorned this world. But evil angels shall receive the souls of sinners." },
  { book: "3 Meqabyan", chapter: 6, verse: 6, text: "Angels of mercy shall receive the souls of kind and righteous people; they are sent from the Lord to comfort the souls of the righteous. Just as evil angels are sent from the Devil to ridicule the souls of sinners, demons shall receive the souls of sinners." },
  { book: "3 Meqabyan", chapter: 6, verse: 7, text: "O sinners, woe to you! Weep for yourselves before the day of your death arrives—before the time you reach the Lord." },
  { book: "3 Meqabyan", chapter: 6, verse: 8, text: "Enter into repentance in your current era before your time passes, so that you might live in joy and happiness without tribulation or disease. Since your time will not return once you have died, weep now." },
  { book: "3 Meqabyan", chapter: 6, verse: 9, text: "Lest you follow a vain path that distances you from the Lord, let love be lavished in your self-criticism, so that gluttony and excessive pleasure are not found in you. As a body that is sated without measure will not think of the Lord’s Name, the Devil's wealth shall dwell in it. Since the Holy Spirit won't dwell in such a person, let not those excessive pleasures be found in you." },
  { book: "3 Meqabyan", chapter: 6, verse: 10, text: "As Moses spoke: \"Jacob ate and was satisfied; he grew fat, tall, and wide, and the Lord who created him was separated from him.\"" },
  { book: "3 Meqabyan", chapter: 6, verse: 11, text: "\"And his lifestyle distanced him from the Lord.\" As a body sated without measure or moderation won't think of the Lord's Name, let not the love of excessive pleasures be found among you. Since a belly full without measure is like a boar or a wandering horse, let not immoderate eating, drinking, or adultery be found in you." },
  { book: "3 Meqabyan", chapter: 6, verse: 12, text: "But a person who eats in moderation shall live strengthened by the Lord’s support; he shall be firm like the horizon or like a tower with a stone fence. A person who forgets the Lord’s Law shall flee even when no one is chasing him." },
  { book: "3 Meqabyan", chapter: 6, verse: 13, text: "A kind person shall live in respect, like a lion." },
  { book: "3 Meqabyan", chapter: 6, verse: 14, text: "But those who do not love the Lord won't keep His Law, and their reasoning is not straight." },
  { book: "3 Meqabyan", chapter: 6, verse: 15, text: "The Lord shall bring sadness and alarm upon them while they are in this world—they will be seized with trembling and fright, and with countless tribulations. Their money will be snatched away, and they will be bound by their hands in chains by their masters..." },
  { book: "3 Meqabyan", chapter: 6, verse: 16, text: "...lest they be among those who rest from tribulation, and lest their lifestyle be one of joy. Lest they find rest during the alarming tribulations that come upon each of them, He shall bring sadness and alarm upon them." },
  { book: "3 Meqabyan", chapter: 7, verse: 1, text: "But as David spoke, saying: \"I have believed in the Lord; I will not fear, having said, 'What can a man do to me?'\"—there is no fright or alarm for those who believe in the Lord." },
  { book: "3 Meqabyan", chapter: 7, verse: 2, text: "And again, as he spoke, saying: \"If warriors surround me, I have believed in Him; I have asked one thing of the Lord, and that I seek\"—those who believe in Him have no fear upon them. A person who believes in Him shall live in Life forever, and he will not fear the arrival of an evil thing." },
  { book: "3 Meqabyan", chapter: 7, verse: 3, text: "Who is the person who was put to shame for believing in the Lord? Or who was ignored by Him for having a desire?" },
  { book: "3 Meqabyan", chapter: 7, verse: 4, text: "As He has said: \"I love him who loves Me, and I shall honor him who glorifies Me. I shall keep him who returns to Me in repentance.\" Who is the person who was shamed for believing in Him?" },
  { book: "3 Meqabyan", chapter: 7, verse: 5, text: "Judge with Truth and save the widow; save them so that the Lord might save you from all who oppose you in evil. Protect them; for the children of kind people are honored and given success, and He shall save your children after you, for they will not be troubled for lack of grain." },
  { book: "3 Meqabyan", chapter: 8, verse: 1, text: "Job believed in the Lord; because he did not neglect to praise his Creator, the Lord saved him from all the tribulation that the enemy of Adam's children, the Devil, brought upon him. He said, \"The Lord gave, the Lord withheld; it happened as the Lord desired for me; let the Name of the Lord be praised by all on Earth and in Heaven.\" Because he did not let his mind be saddened, the Lord saved him." },
  { book: "3 Meqabyan", chapter: 8, verse: 2, text: "When the Lord saw that Job’s heart was cleansed from sin, He received him with great honor." },
  { book: "3 Meqabyan", chapter: 8, verse: 3, text: "And He gave him wealth that abounded more than his previous wealth, because he had completely endured his tribulation. He cured him of his wounds because of his endurance through all the trials that came upon him." },
  { book: "3 Meqabyan", chapter: 8, verse: 4, text: "And if you, like him, endure the tribulation coming from the demons sent against you, you will be admired." },
  { book: "3 Meqabyan", chapter: 8, verse: 5, text: "Endure the tribulation so that the Lord might be a fortress of refuge for you against those who hate you, and that He might be a fortress of refuge for your children's children and those after you. Do not let your minds be saddened by the trials that come upon you; believe in Him, and He shall be your fortress." },
  { book: "3 Meqabyan", chapter: 8, verse: 6, text: "Beg Him, and He will hear you. Have hope, and He will forgive you. Beg Him, and He will be a Father to you." },
  { book: "3 Meqabyan", chapter: 8, verse: 7, text: "Think of Mordecai and Esther, Judith and Gideon, Deborah and Barak, Jephthah and Samson..." },
  { book: "3 Meqabyan", chapter: 8, verse: 8, text: "...and other persons like them who were disciplined to believe in the Lord and whose enemies did not defeat them." },
  { book: "3 Meqabyan", chapter: 8, verse: 9, text: "For the Lord is True, and He does not show favoritism. But those who love to commit sin against themselves receive hardship. All who fear Him and keep His Law shall preserve their bodies, and He shall give them love and honor." },
  { book: "3 Meqabyan", chapter: 8, verse: 10, text: "He shall make them joyful in their going out and their coming in, in their life and their death, and in their rising and sitting. For He saves, and He sets apart." },
  { book: "3 Meqabyan", chapter: 8, verse: 11, text: "For He brings sadness, and He brings pardon." },
  { book: "3 Meqabyan", chapter: 8, verse: 12, text: "He makes poor, and He honors; He makes wretched, and when He honors, He makes them joyful." },
  { book: "3 Meqabyan", chapter: 9, verse: 1, text: "Whether it be what is in Heaven or what is on Earth, whether it be subtle or stout—everything and all His wealth exists established in His Order." },
  { book: "3 Meqabyan", chapter: 9, verse: 2, text: "There is nothing that has departed from the Law and Order of the Lord, who created all the world. Even the track of a vulture that flies in Heaven—He commands it toward the destination He desires." },
  { book: "3 Meqabyan", chapter: 9, verse: 3, text: "He commands the path of the earth-snake that lives in a cave toward where He desires, and the path of a boat on the sea. Apart from the Lord alone, there is none who knows its path." },
  { book: "3 Meqabyan", chapter: 9, verse: 4, text: "And apart from the Lord alone, there is none who knows the path where a soul goes when it is separated from its flesh, whether it be a righteous or a sinful soul." },
  { book: "3 Meqabyan", chapter: 9, verse: 5, text: "Who knows where it will turn—whether it turns in the wilderness or upon a mountain? Or whether it flies like a bird, or is like the dew of Heaven that alights upon a mountain..." },
  { book: "3 Meqabyan", chapter: 9, verse: 6, text: "...or whether it is like the deep wind, or like lightning that straightens its own path..." },
  { book: "3 Meqabyan", chapter: 9, verse: 7, text: "...or whether it is like stars that shine in the deep, or like sand on a seashore piled in the deep..." },
  { book: "3 Meqabyan", chapter: 9, verse: 8, text: "...or whether it is like a foundation stone firmed up on the edge of the deep sea, or like a tree that gives beautiful fruit, growing by a water spout..." },
  { book: "3 Meqabyan", chapter: 9, verse: 9, text: "...or whether it is like the reed that the heat of the Sun burns, which the wind lifts and takes to another place where it did not grow, and whose trace is not found?" },
  { book: "3 Meqabyan", chapter: 9, verse: 10, text: "Or whether it is like misty vapor whose trace is not found? Who knows the Work of the Lord? Who are His counselors? With whom did He consult?" },
  { book: "3 Meqabyan", chapter: 9, verse: 11, text: "Since the Thoughts of the Lord are hidden from people, who can examine and know His Work?" },
  { book: "3 Meqabyan", chapter: 9, verse: 12, text: "As He created Earth upon Water and firmed her up without stakes, there are none who can know the Lord’s Counsel or His Wisdom. He created Heaven in His perfect Wisdom, firmed it up in the winds, and stretched forth a lofty cosmos like a tent." },
  { book: "3 Meqabyan", chapter: 9, verse: 13, text: "He commanded the clouds to rain upon the Earth, grew the grass, and grew fruits without number to be food for people, so that we might believe in the Lord and be joyful in unity." },
  { book: "3 Meqabyan", chapter: 9, verse: 14, text: "The Lord is the One who gives the children of Adam joy, fatness, and satisfaction. The Lord gives so that they might be satisfied and praise Him who gave them fruit from the Earth..." },
  { book: "3 Meqabyan", chapter: 9, verse: 15, text: "...and who dressed them in beautiful robes, giving them all love and plenty—the joy and happiness given to those who fulfill the Lord's Will." },
  { book: "3 Meqabyan", chapter: 9, verse: 16, text: "He gives love and honor in the house He prepared and in the Kingdom of Heaven to those fathers who keep the Lord’s Law." },
  { book: "3 Meqabyan", chapter: 9, verse: 17, text: "He gives love and honor in the place He prepared and in the Kingdom of Heaven to the fathers who lived firmly in His Worship and His Law, and who did not depart from it. He made them famous and raised them up to keep His Order and Law. I have seen what the Lord does for His friends in this world by weakening their enemies and keeping their bodies safe." },
  { book: "3 Meqabyan", chapter: 9, verse: 18, text: "I have seen that He gives them all they ask of Him and fulfills their desires. Do not depart from the Lord, but fulfill His Will." },
  { book: "3 Meqabyan", chapter: 9, verse: 19, text: "Do not depart from His Command and His Law, lest He be angry with you and destroy you at once—lest He be angry and whip you in the tribulation where you lived formerly. Do not depart from the Order of your fathers, lest your dwelling be in Gehenna, where there is no exit for eternity." },
  { book: "3 Meqabyan", chapter: 9, verse: 20, text: "Keep the Law of your Creator when your soul is separated from your flesh, so that He might do a good work for you when you stand before Him." },
  { book: "3 Meqabyan", chapter: 9, verse: 21, text: "For the Kingdoms of Earth and Heaven are His; Kingdom and capability are His; and kindness and pardon are only His." },
  { book: "3 Meqabyan", chapter: 9, verse: 22, text: "As He makes rich and poor, as He makes wretched and honors—keep the Lord's Law." },
  { book: "3 Meqabyan", chapter: 9, verse: 23, text: "And David spoke because of Him, saying: \"Man seems vain, and his time passes like a shadow.\"" },
  { book: "3 Meqabyan", chapter: 9, verse: 24, text: "He spoke of Him, saying: \"But Lord, You live forever, and the invocation of Your Name is for all generations.\"" },
  { book: "3 Meqabyan", chapter: 9, verse: 25, text: "And again he said: \"Your Kingdom is the Kingdom of all the world, and Your Rulership is for all generations.\" You returned a kingdom to David, taking it from Saul." },
  { book: "3 Meqabyan", chapter: 9, verse: 26, text: "But there is none who can appoint You; there is none who can dismiss You. You see all, yet there is none who can see You." },
  { book: "3 Meqabyan", chapter: 9, verse: 27, text: "Your Kingdom won't perish forever, for all generations. There is none who will rule Him, but He rules all. He sees all, but none see Him." },
  { book: "3 Meqabyan", chapter: 9, verse: 28, text: "As He created man in His Features and His example so that they might praise Him and know His Worship in straight reasoning without doubt, He examines and knows what the kidneys produce and what a mind thinks." },
  { book: "3 Meqabyan", chapter: 9, verse: 29, text: "Yet they bow to stone, to wood, and to silver and gold worked by a person's hand." },
  { book: "3 Meqabyan", chapter: 9, verse: 30, text: "They sacrifice sacrifices to them until the smoke of their sacrifice reaches Heaven, so that their sins remain firm before the Lord; yet they refused to worship the Lord who created them. He shall accuse them because of all the sins they committed in worshipping those idols." },
  { book: "3 Meqabyan", chapter: 9, verse: 31, text: "They learned to bow to idols and all improper, stained work—fortune-telling by stars, sorcery, idol worship, evil desires, and all the work the Lord does not love. They did not keep the Lord's Command which they had learned." },
  { book: "3 Meqabyan", chapter: 9, verse: 32, text: "Since they did not love to worship the Lord—though they could have saved their bodies from sin and iniquity through His servants the Angels and the wealth they praise before the Lord—they do all this while lacking good works." },
  { book: "3 Meqabyan", chapter: 9, verse: 33, text: "When they all arise together from the graves where they were buried and where their bodies perished, their souls shall stand empty before the Lord. But the souls of kind persons lived in the Kingdom of Heaven prepared for them." },
  { book: "3 Meqabyan", chapter: 9, verse: 34, text: "But the souls of sinners shall live in Gehenna. When the graves are opened, those who are dead shall arise, and souls shall return to the flesh from which they were formerly separated." },
  { book: "3 Meqabyan", chapter: 9, verse: 35, text: "Just as they were born in their nakedness from their mother’s belly, they shall stand in their nakedness before the Lord. The sins they committed from their infancy until that time shall be revealed." },
  { book: "3 Meqabyan", chapter: 9, verse: 36, text: "They shall receive the punishment for their sins upon their bodies; whether their sins were few or many, they shall receive hardship according to their sins." },
  { book: "3 Meqabyan", chapter: 10, verse: 1, text: "For the blood of the soul given by the Lord shall dwell in them as it did formerly. If you do not believe the dead will arise, observe how creatures arise in the rainy season without being born of a mother or father." },
  { book: "3 Meqabyan", chapter: 10, verse: 2, text: "He commanded them formerly by His Word to die." },
  { book: "3 Meqabyan", chapter: 10, verse: 3, text: "Their flesh being destroyed and rotten, yet renewed again, they shall arise as He desires." },
  { book: "3 Meqabyan", chapter: 10, verse: 4, text: "Again, when the rain falls and satisfies the Earth, they shall arise as they were created formerly." },
  { book: "3 Meqabyan", chapter: 10, verse: 5, text: "Just as those who are ever-living with a soul of blood, and those who live in this world, and those whom Water produces have been created—He having said, \"Let them be created\"—as the Lord’s authority dwells upon the Water, she gives them a soul of blood by His authority and His Word." },
  { book: "3 Meqabyan", chapter: 10, verse: 6, text: "Since they are created by His authority and Word without a father or mother—you who are blind in reasoning, who say, \"The dead won't arise\"—if you have knowledge or Wisdom, how can you say the dead won't arise by the Word of their Creator, the Lord?" },
  { book: "3 Meqabyan", chapter: 10, verse: 7, text: "As the dead—who were ashes and dust in the grave—shall arise by the Lord’s Word, as for you: enter into repentance and return to your religion." },
  { book: "3 Meqabyan", chapter: 10, verse: 8, text: "Just as His Word spoke formerly, they shall arise by the Dew of Pardon found from the Lord. That Word shall turn the whole world and arouse the dead as He desires." },
  { book: "3 Meqabyan", chapter: 10, verse: 9, text: "Know that you will arise and stand before Him; do not let it seem to you in your dullness of mind that you will remain in the grave." },
  { book: "3 Meqabyan", chapter: 10, verse: 10, text: "It is not so. You will arise and receive hardship according to the measure of the work you did, whether it was good or evil. Do not think you will remain there, for this is the Day when they will receive hardship." },
  { book: "3 Meqabyan", chapter: 10, verse: 11, text: "In the time of Resurrection, you will receive hardship for all the sins you committed. You will pay for the sins written from your infancy until that time; you will have no excuse or pretext for your sins, unlike the way you deny your sins in the work of this world." },
  { book: "3 Meqabyan", chapter: 10, verse: 12, text: "Just as you make your false word seem like truth before you, and make the lies you spoke seem like truth—you will have no such pretext there." },
  { book: "3 Meqabyan", chapter: 10, verse: 13, text: "Because your soul knows all the evil work you did, and because she will reveal it before her Creator, the Lord—as the Lord’s Word shall dwell upon you and speak against you—you have no reason to offer an excuse." },
  { book: "3 Meqabyan", chapter: 10, verse: 14, text: "You will be ashamed there because of the sins you committed. You might wish to be among those thanked for their beautiful work; so, lest you be shamed before man and Angels on the day of Judgment, quickly enter into repentance in this world before you arrive there." },
  { book: "3 Meqabyan", chapter: 10, verse: 15, text: "Those who praise the Lord with the Angels shall receive their reward from their Creator without shame, and they shall be joyful in the Kingdom of Heaven. However, unless you did good works while you were in the flesh, you have no portion with the righteous." },
  { book: "3 Meqabyan", chapter: 10, verse: 16, text: "Since you were not prepared while you had knowledge and while you had this world to enter repentance, there shall be useless regret upon you—especially because you did not give a morsel to the hungry when you had money." },
  { book: "3 Meqabyan", chapter: 10, verse: 17, text: "And because you did not clothe the naked when you had clothes, and you did not save the wronged when you had authority." },
  { book: "3 Meqabyan", chapter: 10, verse: 18, text: "Because you did not teach the sinner when you had knowledge, so that he might return and repent, and that the Lord might forgive him the sins he formerly did in ignorance. And because you did not fight the demons who quarrel with you when you had the Power to prevail." },
  { book: "3 Meqabyan", chapter: 10, verse: 19, text: "And because you did not fast or pray when you had the strength to weaken the power of youth over the flesh, and to subject yourself to Righteousness, which does not show favoritism to the flesh..." },
  { book: "3 Meqabyan", chapter: 10, verse: 20, text: "...which does not favor the pleasures of this world in fine drink and sweet food, nor adornment in fine clothes, silver, and gold..." },
  { book: "3 Meqabyan", chapter: 10, verse: 21, text: "...and as you did not fast or pray when you had the strength to subject yourself to Righteousness—which does not adorn itself in honored Indian jewels like emeralds and topazes—there shall be useless regret upon you. This is not the proper ornament for a person." },
  { book: "3 Meqabyan", chapter: 10, verse: 22, text: "The true ornament of a person is purity, wisdom, and knowledge—loving one another as is right, without envy, jealousy, doubt, or quarrels. It is loving your companion as yourself..." },
  { book: "3 Meqabyan", chapter: 10, verse: 23, text: "...and not doing evil to someone who did evil to you. This is true love, so that you might enter the Kingdom of Heaven given to those who endured tribulation. He might then give you the honored Kingdom and your reward for having hope in the Kingdom of Heaven at the time of Resurrection, along with those honored in knowledge and wisdom." },
  { book: "3 Meqabyan", chapter: 10, verse: 24, text: "Do not say, \"After we die we won't arise,\" for the Devil cuts off the hope of those who speak and think this, so they won't be saved at the Resurrection. They will realize they have hardship upon them when the Advent arrives. In the Resurrection, those who committed sin in ignorance will be deeply sad when their sins are brought back to them, for they did not believe they would arise on that Day." },
  { book: "3 Meqabyan", chapter: 10, verse: 25, text: "For this reason, they shall be reproached according to the measure of the evil work they did in this world, and they shall see the Resurrection they denied, by which they will arise together in the flesh." },
  { book: "3 Meqabyan", chapter: 10, verse: 26, text: "They shall weep at that time because they did not do good works. It would have been better for them to weep in this world, if possible, rather than be among those who weep in Gehenna." },
  { book: "3 Meqabyan", chapter: 10, verse: 27, text: "If we do not weep in this world by our own choice, demons will make us weep against our will in Gehenna. If we do not enter into repentance in this world, we prepare worthless and useless cries and mourning in Gehenna." },
  { book: "3 Meqabyan", chapter: 10, verse: 28, text: "Prepare good works, so that you might cross from death to Life, and go from this passing world toward the Kingdom of Heaven, to see the Light of the Kingdom that surpasses all light in this world." },
  { book: "3 Meqabyan", chapter: 10, verse: 29, text: "Refuse the pleasures of this world, so that you might be joyful beyond measure in the Kingdom of Heaven—in joys that are not fulfilled from today until eternity, along with those who believe the dead arise." },
  // 4 Maccabees (479 verses)
  { book: "4 Maccabees", chapter: 1, verse: 1, text: "φιλοσοφώτατον λόγον ἐπιδείκνυσθαι μέλλων εἰ αὐτοδέσποτός ἐστιν τῶν παθῶν ὁ εὐσεβὴς λογισμός συμβουλεύσαιμ’ ἂν ὑμῖν ὀρθῶς ὅπως προσέχητε προθύμως τῇ φιλοσοφίᾳ" },
  { book: "4 Maccabees", chapter: 1, verse: 2, text: "καὶ γὰρ ἀναγκαῖος εἰς ἐπιστήμην παντὶ ὁ λόγος καὶ ἄλλως τῆς μεγίστης ἀρετῆς λέγω δὴ φρονήσεως περιέχει ἔπαινον" },
  { book: "4 Maccabees", chapter: 1, verse: 3, text: "εἰ ἄρα τῶν σωφροσύνης κωλυτικῶν παθῶν ὁ λογισμὸς φαίνεται ἐπικρατεῖν γαστριμαργίας τε καὶ ἐπιθυμίας" },
  { book: "4 Maccabees", chapter: 1, verse: 4, text: "ἀλλὰ καὶ τῶν τῆς δικαιοσύνης ἐμποδιστικῶν παθῶν κυριεύειν ἀναφαίνεται οἷον κακοηθείας καὶ τῶν τῆς ἀνδρείας ἐμποδιστικῶν παθῶν θυμοῦ τε καὶ φόβου καὶ πόνου" },
  { book: "4 Maccabees", chapter: 1, verse: 5, text: "πῶς οὖν ἴσως εἴποιεν ἄν τινες εἰ τῶν παθῶν ὁ λογισμὸς κρατεῖ λήθης καὶ ἀγνοίας οὐ δεσπόζει γελοῖον ἐπιχειροῦντες λέγειν" },
  { book: "4 Maccabees", chapter: 1, verse: 6, text: "οὐ γὰρ τῶν αὑτοῦ παθῶν ὁ λογισμὸς κρατεῖ ἀλλὰ τῶν τῆς δικαιοσύνης καὶ ἀνδρείας καὶ σωφροσύνης ἐναντίων καὶ τούτων οὐχ ὥστε αὐτὰ καταλῦσαι ἀλλ’ ὥστε αὐτοῖς μὴ εἶξαι" },
  { book: "4 Maccabees", chapter: 1, verse: 7, text: "πολλαχόθεν μὲν οὖν καὶ ἀλλαχόθεν ἔχοιμ’ ἂν ὑμῖν ἐπιδεῖξαι ὅτι αὐτοκράτωρ ἐστὶν τῶν παθῶν ὁ λογισμός" },
  { book: "4 Maccabees", chapter: 1, verse: 8, text: "πολὺ δὲ πλέον τοῦτο ἀποδείξαιμι ἀπὸ τῆς ἀνδραγαθίας τῶν ὑπὲρ ἀρετῆς ἀποθανόντων Ελεαζαρου τε καὶ τῶν ἑπτὰ ἀδελφῶν καὶ τῆς τούτων μητρός" },
  { book: "4 Maccabees", chapter: 1, verse: 9, text: "ἅπαντες γὰρ οὗτοι τοὺς ἕως θανάτου πόνους ὑπεριδόντες ἐπεδείξαντο ὅτι περικρατεῖ τῶν παθῶν ὁ λογισμός" },
  { book: "4 Maccabees", chapter: 1, verse: 10, text: "τῶν μὲν οὖν ἀρετῶν ἔπεστί μοι ἐπαινεῖν τοὺς κατὰ τοῦτον τὸν καιρὸν ὑπὲρ τῆς καλοκἀγαθίας ἀποθανόντας μετὰ τῆς μητρὸς ἄνδρας τῶν δὲ τιμῶν μακαρίσαιμ’ ἄν" },
  { book: "4 Maccabees", chapter: 1, verse: 11, text: "θαυμασθέντες γὰρ οὐ μόνον ὑπὸ πάντων ἀνθρώπων ἐπὶ τῇ ἀνδρείᾳ καὶ ὑπομονῇ ἀλλὰ καὶ ὑπὸ τῶν αἰκισαμένων αἴτιοι κατέστησαν τοῦ καταλυθῆναι τὴν κατὰ τοῦ ἔθνους τυραννίδα νικήσαντες τὸν τύραννον τῇ ὑπομονῇ ὥστε καθαρισθῆναι δῑ αὐτῶν τὴν πατρίδα" },
  { book: "4 Maccabees", chapter: 1, verse: 12, text: "ἀλλὰ καὶ περὶ τούτου νῦν αὐτίκα δὴ λέγειν ἐξέσται ἀρξαμένῳ τῆς ὑποθέσεως ὅπερ εἴωθα ποιεῖν καὶ οὕτως εἰς τὸν περὶ αὐτῶν τρέψομαι λόγον δόξαν διδοὺς τῷ πανσόφῳ θεῷ" },
  { book: "4 Maccabees", chapter: 1, verse: 13, text: "ζητοῦμεν δὴ τοίνυν εἰ αὐτοκράτωρ ἐστὶν τῶν παθῶν ὁ λογισμός" },
  { book: "4 Maccabees", chapter: 1, verse: 14, text: "διακρίνομεν τί ποτέ ἐστιν λογισμὸς καὶ τί πάθος καὶ πόσαι παθῶν ἰδέαι καὶ εἰ πάντων ἐπικρατεῖ τούτων ὁ λογισμός" },
  { book: "4 Maccabees", chapter: 1, verse: 15, text: "λογισμὸς μὲν δὴ τοίνυν ἐστὶν νοῦς μετὰ ὀρθοῦ λόγου προτιμῶν τὸν σοφίας βίον" },
  { book: "4 Maccabees", chapter: 1, verse: 16, text: "σοφία δὴ τοίνυν ἐστὶν γνῶσις θείων καὶ ἀνθρωπίνων πραγμάτων καὶ τῶν τούτων αἰτιῶν" },
  { book: "4 Maccabees", chapter: 1, verse: 17, text: "αὕτη δὴ τοίνυν ἐστὶν ἡ τοῦ νόμου παιδεία δῑ ἧς τὰ θεῖα σεμνῶς καὶ τὰ ἀνθρώπινα συμφερόντως μανθάνομεν" },
  { book: "4 Maccabees", chapter: 1, verse: 18, text: "τῆς δὲ σοφίας ἰδέαι καθεστήκασιν φρόνησις καὶ δικαιοσύνη καὶ ἀνδρεία καὶ σωφροσύνη" },
  { book: "4 Maccabees", chapter: 1, verse: 19, text: "κυριωτάτη δὲ πάντων ἡ φρόνησις ἐξ ἧς δὴ τῶν παθῶν ὁ λογισμὸς ἐπικρατεῖ" },
  { book: "4 Maccabees", chapter: 1, verse: 20, text: "παθῶν δὲ φύσεις εἰσὶν αἱ περιεκτικώταται δύο ἡδονή τε καὶ πόνος τούτων δὲ ἑκάτερον καὶ περὶ τὸ σῶμα καὶ περὶ τὴν ψυχὴν πέφυκεν" },
  { book: "4 Maccabees", chapter: 1, verse: 21, text: "πολλαὶ δὲ καὶ περὶ τὴν ἡδονὴν καὶ τὸν πόνον παθῶν εἰσιν ἀκολουθίαι" },
  { book: "4 Maccabees", chapter: 1, verse: 22, text: "πρὸ μὲν οὖν τῆς ἡδονῆς ἐστιν ἐπιθυμία μετὰ δὲ τὴν ἡδονὴν χαρά" },
  { book: "4 Maccabees", chapter: 1, verse: 23, text: "πρὸ δὲ τοῦ πόνου ἐστὶν φόβος μετὰ δὲ τὸν πόνον λύπη" },
  { book: "4 Maccabees", chapter: 1, verse: 24, text: "θυμὸς δὲ κοινὸν πάθος ἐστὶν ἡδονῆς καὶ πόνου ἐὰν ἐννοηθῇ τις ὅτι αὐτῷ περιέπεσεν" },
  { book: "4 Maccabees", chapter: 1, verse: 25, text: "ἐν τῇ ἡδονῇ δὲ ἔνεστιν καὶ ἡ κακοήθης διάθεσις πολυτροπωτάτη πάντων οὖσα τῶν παθῶν" },
  { book: "4 Maccabees", chapter: 1, verse: 26, text: "καὶ τὰ μὲν ψυχῆς ἀλαζονεία καὶ φιλαργυρία καὶ φιλοδοξία καὶ φιλονεικία καὶ βασκανία" },
  { book: "4 Maccabees", chapter: 1, verse: 27, text: "κατὰ δὲ τὸ σῶμα παντοφαγία καὶ λαιμαργία καὶ μονοφαγία" },
  { book: "4 Maccabees", chapter: 1, verse: 28, text: "καθάπερ οὖν δυεῖν τοῦ σώματος καὶ τῆς ψυχῆς φυτῶν ὄντων ἡδονῆς τε καὶ πόνου πολλαὶ τούτων τῶν φυτῶν εἰσιν παραφυάδες" },
  { book: "4 Maccabees", chapter: 1, verse: 29, text: "ὧν ἑκάστην ὁ παγγέωργος λογισμὸς περικαθαίρων καὶ ἀποκνίζων καὶ περιπλέκων καὶ ἐπάρδων καὶ πάντα τρόπον μεταχέων ἐξημεροῖ τὰς τῶν ἠθῶν καὶ παθῶν ὕλας" },
  { book: "4 Maccabees", chapter: 1, verse: 30, text: "ὁ γὰρ λογισμὸς τῶν μὲν ἀρετῶν ἐστιν ἡγεμών τῶν δὲ παθῶν αὐτοκράτωρ ἐπιθεωρεῖτε τοίνυν πρῶτον διὰ τῶν κωλυτικῶν τῆς σωφροσύνης ἔργων ὅτι αὐτοδέσποτός ἐστιν τῶν παθῶν ὁ λογισμός" },
  { book: "4 Maccabees", chapter: 1, verse: 31, text: "σωφροσύνη δὴ τοίνυν ἐστὶν ἐπικράτεια τῶν ἐπιθυμιῶν" },
  { book: "4 Maccabees", chapter: 1, verse: 32, text: "τῶν δὲ ἐπιθυμιῶν αἱ μέν εἰσιν ψυχικαί αἱ δὲ σωματικαί καὶ τούτων ἀμφοτέρων ἐπικρατεῖν ὁ λογισμὸς φαίνεται" },
  { book: "4 Maccabees", chapter: 1, verse: 33, text: "ἐπεὶ πόθεν κινούμενοι πρὸς τὰς ἀπειρημένας τροφὰς ἀποστρεφόμεθα τὰς ἐξ αὐτῶν ἡδονάς οὐχ ὅτι δύναται τῶν ὀρέξεων ἐπικρατεῖν ὁ λογισμός ἐγὼ μὲν οἶμαι" },
  { book: "4 Maccabees", chapter: 1, verse: 34, text: "τοιγαροῦν ἐνύδρων ἐπιθυμοῦντες καὶ ὀρνέων καὶ τετραπόδων καὶ παντοίων βρωμάτων τῶν ἀπηγορευμένων ἡμῖν κατὰ τὸν νόμον ἀπεχόμεθα διὰ τὴν τοῦ λογισμοῦ ἐπικράτειαν" },
  { book: "4 Maccabees", chapter: 1, verse: 35, text: "ἀνέχεται γὰρ τὰ τῶν ὀρέξεων πάθη ὑπὸ τοῦ σώφρονος νοὸς ἀνακοπτόμενα καὶ φιμοῦται πάντα τὰ τοῦ σώματος κινήματα ὑπὸ τοῦ λογισμοῦ" },
  { book: "4 Maccabees", chapter: 2, verse: 1, text: "καὶ τί θαυμαστόν εἰ αἱ τῆς ψυχῆς ἐπιθυμίαι πρὸς τὴν τοῦ κάλλους μετουσίαν ἀκυροῦνται" },
  { book: "4 Maccabees", chapter: 2, verse: 2, text: "ταύτῃ γοῦν ὁ σώφρων Ιωσηφ ἐπαινεῖται ὅτι διανοίᾳ περιεκράτησεν τῆς ἡδυπαθείας" },
  { book: "4 Maccabees", chapter: 2, verse: 3, text: "νέος γὰρ ὢν καὶ ἀκμάζων πρὸς συνουσιασμὸν ἠκύρωσε τῷ λογισμῷ τὸν τῶν παθῶν οἶστρον" },
  { book: "4 Maccabees", chapter: 2, verse: 4, text: "καὶ οὐ μόνον δὲ τὴν τῆς ἡδυπαθείας οἰστρηλασίαν ὁ λογισμὸς ἐπικρατεῖν φαίνεται ἀλλὰ καὶ πάσης ἐπιθυμίας" },
  { book: "4 Maccabees", chapter: 2, verse: 5, text: "λέγει γοῦν ὁ νόμος οὐκ ἐπιθυμήσεις τὴν γυναῖκα τοῦ πλησίον σου οὐδὲ ὅσα τῷ πλησίον σού ἐστιν" },
  { book: "4 Maccabees", chapter: 2, verse: 6, text: "καίτοι ὅτε μὴ ἐπιθυμεῖν εἴρηκεν ἡμᾶς ὁ νόμος πολὺ πλέον πείσαιμ’ ἂν ὑμᾶς ὅτι τῶν ἐπιθυμιῶν κρατεῖν δύναται ὁ λογισμός ὥσπερ καὶ τῶν κωλυτικῶν τῆς δικαιοσύνης παθῶν" },
  { book: "4 Maccabees", chapter: 2, verse: 7, text: "ἐπεὶ τίνα τις τρόπον μονοφάγος ὢν τὸ ἦθος καὶ γαστρίμαργος ἢ καὶ μέθυσος μεταπαιδεύεται εἰ μὴ δῆλον ὅτι κύριός ἐστιν τῶν παθῶν ὁ λογισμός" },
  { book: "4 Maccabees", chapter: 2, verse: 8, text: "αὐτίκα γοῦν τῷ νόμῳ πολιτευόμενος κἂν φιλάργυρός τις ᾖ βιάζεται τὸν αὑτοῦ τρόπον τοῖς δεομένοις δανείζων χωρὶς τόκων καὶ τὸ δάνειον τῶν ἑβδομάδων ἐνστασῶν χρεοκοπούμενος" },
  { book: "4 Maccabees", chapter: 2, verse: 9, text: "κἂν φειδωλός τις ᾖ ὑπὸ τοῦ νόμου κρατεῖται διὰ τὸν λογισμὸν μήτε ἐπικαρπολογούμενος τοὺς ἀμητοὺς μήτε ἐπιρρωγολογούμενος τοὺς ἀμπελῶνας καὶ ἐπὶ τῶν ἑτέρων δὲ ἔστιν ἐπιγνῶναι τοῦτο ὅτι τῶν παθῶν ἐστιν ὁ λογισμὸς κρατῶν" },
  { book: "4 Maccabees", chapter: 2, verse: 10, text: "ὁ γὰρ νόμος καὶ τῆς πρὸς γονεῖς εὐνοίας κρατεῖ μὴ καταπροδιδοὺς τὴν ἀρετὴν δῑ αὐτοὺς" },
  { book: "4 Maccabees", chapter: 2, verse: 11, text: "καὶ τῆς πρὸς γαμετὴν φιλίας ἐπικρατεῖ διὰ τὴν παρανομίαν αὐτὴν ἀπελέγχων" },
  { book: "4 Maccabees", chapter: 2, verse: 12, text: "καὶ τῆς τέκνων φιλίας κυριεύει διὰ κακίαν αὐτὰ κολάζων" },
  { book: "4 Maccabees", chapter: 2, verse: 13, text: "καὶ τῆς φίλων συνηθείας δεσπόζει διὰ πονηρίαν αὐτοὺς ἐξελέγχων" },
  { book: "4 Maccabees", chapter: 2, verse: 14, text: "καὶ μὴ νομίσητε παράδοξον εἶναι ὅπου καὶ ἔχθρας ἐπικρατεῖν ὁ λογισμὸς δύναται διὰ τὸν νόμον μήτε δενδροτομῶν τὰ ἥμερα τῶν πολεμίων φυτά τὰ δὲ τῶν ἐχθρῶν τοῖς ἀπολέσασι διασῴζων καὶ τὰ πεπτωκότα συνεγείρων" },
  { book: "4 Maccabees", chapter: 2, verse: 15, text: "καὶ τῶν βιαιοτέρων δὲ παθῶν κρατεῖν ὁ λογισμὸς φαίνεται φιλαρχίας καὶ κενοδοξίας καὶ ἀλαζονείας καὶ μεγαλαυχίας καὶ βασκανίας" },
  { book: "4 Maccabees", chapter: 2, verse: 16, text: "πάντα γὰρ ταῦτα τὰ κακοήθη πάθη ὁ σώφρων νοῦς ἀπωθεῖται ὥσπερ καὶ τὸν θυμόν καὶ γὰρ τούτου δεσπόζει" },
  { book: "4 Maccabees", chapter: 2, verse: 17, text: "θυμούμενός γέ τοι Μωυσῆς κατὰ Δαθαν καὶ Αβιρων οὐ θυμῷ τι κατ’ αὐτῶν ἐποίησεν ἀλλὰ λογισμῷ τὸν θυμὸν διῄτησεν" },
  { book: "4 Maccabees", chapter: 2, verse: 18, text: "δυνατὸς γὰρ ὁ σώφρων νοῦς ὡς ἔφην κατὰ τῶν παθῶν ἀριστεῦσαι καὶ τὰ μὲν αὐτῶν μεταθεῖναι τὰ δὲ καὶ ἀκυρῶσαι" },
  { book: "4 Maccabees", chapter: 2, verse: 19, text: "ἐπεὶ διὰ τί ὁ πάνσοφος ἡμῶν πατὴρ Ιακωβ τοὺς περὶ Συμεων καὶ Λευιν αἰτιᾶται μὴ λογισμῷ τοὺς Σικιμίτας ἐθνηδὸν ἀποσφάξαντας λέγων ἐπικατάρατος ὁ θυμὸς αὐτῶν" },
  { book: "4 Maccabees", chapter: 2, verse: 20, text: "εἰ μὴ γὰρ ἐδύνατο τοῦ θυμοῦ ὁ λογισμὸς κρατεῖν οὐκ ἂν εἶπεν οὕτως" },
  { book: "4 Maccabees", chapter: 2, verse: 21, text: "ὁπηνίκα γὰρ ὁ θεὸς τὸν ἄνθρωπον κατεσκεύασεν τὰ πάθη αὐτοῦ καὶ τὰ ἤθη περιεφύτευσεν" },
  { book: "4 Maccabees", chapter: 2, verse: 22, text: "ἡνίκα δὲ ἐπὶ πάντων τὸν ἱερὸν ἡγεμόνα νοῦν διὰ τῶν αἰσθητηρίων ἐνεθρόνισεν" },
  { book: "4 Maccabees", chapter: 2, verse: 23, text: "καὶ τούτῳ νόμον ἔδωκεν καθ’ ὃν πολιτευόμενος βασιλεύσει βασιλείαν σώφρονά τε καὶ δικαίαν καὶ ἀγαθὴν καὶ ἀνδρείαν" },
  { book: "4 Maccabees", chapter: 2, verse: 24, text: "πῶς οὖν εἴποι τις ἄν εἰ τῶν παθῶν δεσπότης ἐστὶν ὁ λογισμός λήθης καὶ ἀγνοίας οὐ κρατεῖ" },
  { book: "4 Maccabees", chapter: 3, verse: 1, text: "ἔστιν δὲ κομιδῇ γελοῖος ὁ λόγος οὐ γὰρ τῶν ἑαυτοῦ παθῶν ὁ λογισμὸς ἐπικρατεῖν φαίνεται ἀλλὰ τῶν σωματικῶν" },
  { book: "4 Maccabees", chapter: 3, verse: 2, text: "οἷον ἐπιθυμίαν τις οὐ δύναται ἐκκόψαι ἡμῶν ἀλλὰ μὴ δουλωθῆναι τῇ ἐπιθυμίᾳ δύναται ὁ λογισμὸς παρασχέσθαι" },
  { book: "4 Maccabees", chapter: 3, verse: 3, text: "θυμόν τις οὐ δύναται ἐκκόψαι ὑμῶν τῆς ψυχῆς ἀλλὰ τῷ θυμῷ δυνατὸν τὸν λογισμὸν βοηθῆσαι" },
  { book: "4 Maccabees", chapter: 3, verse: 4, text: "κακοήθειάν τις ἡμῶν οὐ δύναται ἐκκόψαι ἀλλὰ τὸ μὴ καμφθῆναι τῇ κακοηθείᾳ δύναιτ’ ἂν ὁ λογισμὸς συμμαχῆσαι" },
  { book: "4 Maccabees", chapter: 3, verse: 5, text: "οὐ γὰρ ἐκριζωτὴς τῶν παθῶν ὁ λογισμός ἐστιν ἀλλὰ ἀνταγωνιστής" },
  { book: "4 Maccabees", chapter: 3, verse: 6, text: "ἔστιν γοῦν τοῦτο διὰ τῆς Δαυιδ τοῦ βασιλέως δίψης σαφέστερον ἐπιλογίσασθαι" },
  { book: "4 Maccabees", chapter: 3, verse: 7, text: "ἐπεὶ γὰρ δῑ ὅλης ἡμέρας προσβαλὼν τοῖς ἀλλοφύλοις ὁ Δαυιδ πολλοὺς αὐτῶν ἀπέκτεινεν μετὰ τῶν τοῦ ἔθνους στρατιωτῶν" },
  { book: "4 Maccabees", chapter: 3, verse: 8, text: "τότε δὴ γενομένης ἑσπέρας ἱδρῶν καὶ σφόδρα κεκμηκὼς ἐπὶ τὴν βασίλειον σκηνὴν ἦλθεν περὶ ἣν ὁ πᾶς τῶν προγόνων στρατὸς ἐστρατοπεδεύκει" },
  { book: "4 Maccabees", chapter: 3, verse: 9, text: "οἱ μὲν οὖν ἄλλοι πάντες ἐπὶ τὸ δεῖπνον ἦσαν" },
  { book: "4 Maccabees", chapter: 3, verse: 10, text: "ὁ δὲ βασιλεὺς ὡς μάλιστα διψῶν καίπερ ἀφθόνους ἔχων πηγάς οὐκ ἠδύνατο δῑ αὐτῶν ἰάσασθαι τὴν δίψαν" },
  { book: "4 Maccabees", chapter: 3, verse: 11, text: "ἀλλά τις αὐτὸν ἀλόγιστος ἐπιθυμία τοῦ παρὰ τοῖς πολεμίοις ὕδατος ἐπιτείνουσα συνέφρυγεν καὶ λύουσα κατέφλεγεν" },
  { book: "4 Maccabees", chapter: 3, verse: 12, text: "ὅθεν τῶν ὑπασπιστῶν ἐπὶ τῇ τοῦ βασιλέως ἐπιθυμίᾳ σχετλιαζόντων δύο νεανίσκοι στρατιῶται καρτεροὶ καταιδεσθέντες τὴν τοῦ βασιλέως ἐπιθυμίαν τὰς παντευχίας καθωπλίσαντο καὶ κάλπην λαβόντες ὑπερέβησαν τοὺς τῶν πολεμίων χάρακας" },
  { book: "4 Maccabees", chapter: 3, verse: 13, text: "καὶ λαθόντες τοὺς τῶν πυλῶν ἀκροφύλακας διεξῄεσαν ἀνερευνώμενοι κατὰ πᾶν τὸ τῶν πολεμίων στρατόπεδον" },
  { book: "4 Maccabees", chapter: 3, verse: 14, text: "καὶ ἀνευράμενοι τὴν πηγὴν ἐξ αὐτῆς θαρραλέως ἐκόμισαν τῷ βασιλεῖ τὸ ποτόν" },
  { book: "4 Maccabees", chapter: 3, verse: 15, text: "ὁ δὲ καίπερ τῇ δίψῃ διαπυρούμενος ἐλογίσατο πάνδεινον εἶναι κίνδυνον ψυχῇ λογισθὲν ἰσοδύναμον ποτὸν αἵματι" },
  { book: "4 Maccabees", chapter: 3, verse: 16, text: "ὅθεν ἀντιθεὶς τῇ ἐπιθυμίᾳ τὸν λογισμὸν ἔσπεισεν τὸ πόμα τῷ θεῷ" },
  { book: "4 Maccabees", chapter: 3, verse: 17, text: "δυνατὸς γὰρ ὁ σώφρων νοῦς νικῆσαι τὰς τῶν παθῶν ἀνάγκας καὶ σβέσαι τὰς τῶν οἴστρων φλεγμονὰς" },
  { book: "4 Maccabees", chapter: 3, verse: 18, text: "καὶ τὰς τῶν σωμάτων ἀλγηδόνας καθ’ ὑπερβολὴν οὔσας καταπαλαῖσαι καὶ τῇ καλοκἀγαθίᾳ τοῦ λογισμοῦ ἀποπτύσαι πάσας τὰς τῶν παθῶν ἐπικρατείας" },
  { book: "4 Maccabees", chapter: 3, verse: 19, text: "ἤδη δὲ καὶ ὁ καιρὸς ἡμᾶς καλεῖ ἐπὶ τὴν ἀπόδειξιν τῆς ἱστορίας τοῦ σώφρονος λογισμοῦ" },
  { book: "4 Maccabees", chapter: 3, verse: 20, text: "ἐπειδὴ γὰρ βαθεῖαν εἰρήνην διὰ τὴν εὐνομίαν οἱ πατέρες ἡμῶν εἶχον καὶ ἔπραττον καλῶς ὥστε καὶ τὸν τῆς Ἀσίας βασιλέα Σέλευκον τὸν Νικάνορα καὶ χρήματα εἰς τὴν ἱερουργίαν αὐτοῖς ἀφορίσαι καὶ τὴν πολιτείαν αὐτῶν ἀποδέχεσθαι" },
  { book: "4 Maccabees", chapter: 3, verse: 21, text: "τότε δή τινες πρὸς τὴν κοινὴν νεωτερίσαντες ὁμόνοιαν πολυτρόποις ἐχρήσαντο συμφοραῖς" },
  { book: "4 Maccabees", chapter: 4, verse: 1, text: "Σιμων γάρ τις πρὸς Ονιαν ἀντιπολιτευόμενος τόν ποτε τὴν ἀρχιερωσύνην ἔχοντα διὰ βίου καλὸν καὶ ἀγαθὸν ἄνδρα ἐπειδὴ πάντα τρόπον διαβάλλων ὑπὲρ τοῦ ἔθνους οὐκ ἴσχυσεν κακῶσαι φυγὰς ᾤχετο τὴν πατρίδα προδώσων" },
  { book: "4 Maccabees", chapter: 4, verse: 2, text: "ὅθεν ἥκων πρὸς Ἀπολλώνιον τὸν Συρίας τε καὶ Φοινίκης καὶ Κιλικίας στρατηγὸν ἔλεγεν" },
  { book: "4 Maccabees", chapter: 4, verse: 3, text: "εὔνους ὢν τοῖς τοῦ βασιλέως πράγμασιν ἥκω μηνύων πολλὰς ἰδιωτικῶν χρημάτων μυριάδας ἐν τοῖς Ιεροσολύμων γαζοφυλακίοις τεθησαυρίσθαι τοῖς ἱεροῖς μὴ ἐπικοινωνούσας καὶ προσήκειν ταῦτα Σελεύκῳ τῷ βασιλεῖ" },
  { book: "4 Maccabees", chapter: 4, verse: 4, text: "τούτων ἕκαστα γνοὺς ὁ Ἀπολλώνιος τὸν μὲν Σιμωνα τῆς εἰς τὸν βασιλέα κηδεμονίας ἐπαινεῖ πρὸς δὲ τὸν Σέλευκον ἀναβὰς κατεμήνυσε τὸν τῶν χρημάτων θησαυρόν" },
  { book: "4 Maccabees", chapter: 4, verse: 5, text: "καὶ λαβὼν τὴν περὶ αὐτῶν ἐξουσίαν ταχὺ εἰς τὴν πατρίδα ἡμῶν μετὰ τοῦ καταράτου Σιμωνος καὶ βαρυτάτου στρατοῦ" },
  { book: "4 Maccabees", chapter: 4, verse: 6, text: "προσελθὼν ταῖς τοῦ βασιλέως ἐντολαῖς ἥκειν ἔλεγεν ὅπως τὰ ἰδιωτικὰ τοῦ γαζοφυλακίου λάβοι χρήματα" },
  { book: "4 Maccabees", chapter: 4, verse: 7, text: "καὶ τοῦ ἔθνους πρὸς τὸν λόγον σχετλιάζοντος ἀντιλέγοντός τε πάνδεινον εἶναι νομίσαντες εἰ οἱ τὰς παρακαταθήκας πιστεύσαντες τῷ ἱερῷ θησαυρῷ στερηθήσονται ὡς οἷόν τε ἦν ἐκώλυον" },
  { book: "4 Maccabees", chapter: 4, verse: 8, text: "μετὰ ἀπειλῶν δὲ ὁ Ἀπολλώνιος ἀπῄει εἰς τὸ ἱερόν" },
  { book: "4 Maccabees", chapter: 4, verse: 9, text: "τῶν δὲ ἱερέων μετὰ γυναικῶν καὶ παιδίων ἐν τῷ ἱερῷ ἱκετευσάντων τὸν θεὸν ὑπερασπίσαι τοῦ ἱεροῦ καταφρονουμένου τόπου" },
  { book: "4 Maccabees", chapter: 4, verse: 10, text: "ἀνιόντος τε μετὰ καθωπλισμένης τῆς στρατιᾶς τοῦ Ἀπολλωνίου πρὸς τὴν τῶν χρημάτων ἁρπαγὴν οὐρανόθεν ἔφιπποι προυφάνησαν ἄγγελοι περιαστράπτοντες τοῖς ὅπλοις καὶ πολὺν αὐτοῖς φόβον τε καὶ τρόμον ἐνιέντες" },
  { book: "4 Maccabees", chapter: 4, verse: 11, text: "καταπεσών γέ τοι ἡμιθανὴς ὁ Ἀπολλώνιος ἐπὶ τὸν πάμφυλον τοῦ ἱεροῦ περίβολον τὰς χεῖρας ἐξέτεινεν εἰς τὸν οὐρανὸν καὶ μετὰ δακρύων τοὺς Εβραίους παρεκάλει ὅπως περὶ αὐτοῦ προσευξάμενοι τὸν οὐράνιον ἐξευμενίσωνται στρατόν" },
  { book: "4 Maccabees", chapter: 4, verse: 12, text: "ἔλεγεν γὰρ ἡμαρτηκὼς ὥστε καὶ ἀποθανεῖν ἄξιος ὑπάρχειν πᾶσίν τε ἀνθρώποις ὑμνήσειν σωθεὶς τὴν τοῦ ἱεροῦ τόπου μακαριότητα" },
  { book: "4 Maccabees", chapter: 4, verse: 13, text: "τούτοις ὑπαχθεὶς τοῖς λόγοις Ονιας ὁ ἀρχιερεύς καίπερ ἄλλως εὐλαβηθείς μήποτε νομίσειεν ὁ βασιλεὺς Σέλευκος ἐξ ἀνθρωπίνης ἐπιβουλῆς καὶ μὴ θείας δίκης ἀνῃρῆσθαι τὸν Ἀπολλώνιον ηὔξατο περὶ αὐτοῦ" },
  { book: "4 Maccabees", chapter: 4, verse: 14, text: "καὶ ὁ μὲν παραδόξως διασωθεὶς ᾤχετο δηλώσων τῷ βασιλεῖ τὰ συμβάντα αὐτῷ" },
  { book: "4 Maccabees", chapter: 4, verse: 15, text: "τελευτήσαντος δὲ Σελεύκου τοῦ βασιλέως διαδέχεται τὴν ἀρχὴν ὁ υἱὸς αὐτοῦ Ἀντίοχος ὁ Ἐπιφανής ἀνὴρ ὑπερήφανος καὶ δεινός" },
  { book: "4 Maccabees", chapter: 4, verse: 16, text: "ὃς καταλύσας τὸν Ονιαν τῆς ἀρχιερωσύνης Ιασονα τὸν ἀδελφὸν αὐτοῦ κατέστησεν ἀρχιερέα" },
  { book: "4 Maccabees", chapter: 4, verse: 17, text: "συνθέμενον δώσειν εἰ ἐπιτρέψειεν αὐτῷ τὴν ἀρχήν κατ’ ἐνιαυτὸν τρισχίλια ἑξακόσια ἑξήκοντα τάλαντα" },
  { book: "4 Maccabees", chapter: 4, verse: 18, text: "ὁ δὲ ἐπέτρεψεν αὐτῷ καὶ ἀρχιερᾶσθαι καὶ τοῦ ἔθνους ἀφηγεῖσθαι" },
  { book: "4 Maccabees", chapter: 4, verse: 19, text: "καὶ ἐξεδιῄτησεν τὸ ἔθνος καὶ ἐξεπολίτευσεν ἐπὶ πᾶσαν παρανομίαν" },
  { book: "4 Maccabees", chapter: 4, verse: 20, text: "ὥστε μὴ μόνον ἐπ’ αὐτῇ τῇ ἄκρᾳ τῆς πατρίδος ἡμῶν γυμνάσιον κατασκευάσαι ἀλλὰ καὶ καταλῦσαι τὴν τοῦ ἱεροῦ κηδεμονίαν" },
  { book: "4 Maccabees", chapter: 4, verse: 21, text: "ἐφ’ οἷς ἀγανακτήσασα ἡ θεία δίκη αὐτὸν αὐτοῖς τὸν Ἀντίοχον ἐπολέμωσεν" },
  { book: "4 Maccabees", chapter: 4, verse: 22, text: "ἐπειδὴ γὰρ πολεμῶν ἦν κατ’ Αἴγυπτον Πτολεμαίῳ ἤκουσέν τε ὅτι φήμης διαδοθείσης περὶ τοῦ τεθνάναι αὐτὸν ὡς ἔνι μάλιστα χαίροιεν οἱ Ιεροσολυμῖται ταχέως ἐπ’ αὐτοὺς ἀνέζευξεν" },
  { book: "4 Maccabees", chapter: 4, verse: 23, text: "καὶ ὡς ἐπόρθησεν αὐτούς δόγμα ἔθετο ὅπως εἴ τινες αὐτῶν φάνοιεν τῷ πατρίῳ πολιτευόμενοι νόμῳ θάνοιεν" },
  { book: "4 Maccabees", chapter: 4, verse: 24, text: "καὶ ἐπεὶ κατὰ μηδένα τρόπον ἴσχυεν καταλῦσαι διὰ τῶν δογμάτων τὴν τοῦ ἔθνους εὐνομίαν ἀλλὰ πάσας τὰς ἑαυτοῦ ἀπειλὰς καὶ τιμωρίας ἑώρα καταλυομένας" },
  { book: "4 Maccabees", chapter: 4, verse: 25, text: "ὥστε καὶ γυναῖκας ὅτι περιέτεμον τὰ παιδία μετὰ τῶν βρεφῶν κατακρημνισθῆναι προειδυίας ὅτι τοῦτο πείσονται" },
  { book: "4 Maccabees", chapter: 4, verse: 26, text: "ἐπεὶ οὖν τὰ δόγματα αὐτοῦ κατεφρονεῖτο ὑπὸ τοῦ λαοῦ αὐτὸς διὰ βασάνων ἕνα ἕκαστον τοῦ ἔθνους ἠνάγκαζεν μιαρῶν ἀπογευομένους τροφῶν ἐξόμνυσθαι τὸν Ιουδαϊσμόν" },
  { book: "4 Maccabees", chapter: 5, verse: 1, text: "προκαθίσας γέ τοι μετὰ τῶν συνέδρων ὁ τύραννος Ἀντίοχος ἐπί τινος ὑψηλοῦ τόπου καὶ τῶν στρατευμάτων αὐτῷ παρεστηκότων κυκλόθεν ἐνόπλων" },
  { book: "4 Maccabees", chapter: 5, verse: 2, text: "παρεκέλευεν τοῖς δορυφόροις ἕνα ἕκαστον Εβραῖον ἐπισπᾶσθαι καὶ κρεῶν ὑείων καὶ εἰδωλοθύτων ἀναγκάζειν ἀπογεύεσθαι" },
  { book: "4 Maccabees", chapter: 5, verse: 3, text: "εἰ δέ τινες μὴ θέλοιεν μιαροφαγῆσαι τούτους τροχισθέντας ἀναιρεθῆναι" },
  { book: "4 Maccabees", chapter: 5, verse: 4, text: "πολλῶν δὲ συναρπασθέντων εἷς πρῶτος ἐκ τῆς ἀγέλης ὀνόματι Ελεαζαρος τὸ γένος ἱερεύς τὴν ἐπιστήμην νομικὸς καὶ τὴν ἡλικίαν προήκων καὶ πολλοῖς τῶν περὶ τὸν τύραννον διὰ τὴν ἡλικίαν γνώριμος παρήχθη πλησίον αὐτοῦ" },
  { book: "4 Maccabees", chapter: 5, verse: 5, text: "καὶ αὐτὸν ἰδὼν ὁ Ἀντίοχος ἔφη" },
  { book: "4 Maccabees", chapter: 5, verse: 6, text: "ἐγὼ πρὶν ἄρξασθαι τῶν κατὰ σοῦ βασάνων ὦ πρεσβῦτα συμβουλεύσαιμ’ ἄν σοι ταῦτα ὅπως ἀπογευσάμενος τῶν ὑείων σῴζοιο" },
  { book: "4 Maccabees", chapter: 5, verse: 7, text: "αἰδοῦμαι γάρ σου τὴν ἡλικίαν καὶ τὴν πολιάν ἣν μετὰ τοσοῦτον ἔχων χρόνον οὔ μοι δοκεῖς φιλοσοφεῖν τῇ Ιουδαίων χρώμενος θρησκείᾳ" },
  { book: "4 Maccabees", chapter: 5, verse: 8, text: "διὰ τί γὰρ τῆς φύσεως κεχαρισμένης καλλίστην τὴν τοῦδε τοῦ ζῴου σαρκοφαγίαν βδελύττῃ" },
  { book: "4 Maccabees", chapter: 5, verse: 9, text: "καὶ γὰρ ἀνόητον τοῦτο τὸ μὴ ἀπολαύειν τῶν χωρὶς ὀνείδους ἡδέων καὶ ἄδικον ἀποστρέφεσθαι τὰς τῆς φύσεως χάριτας" },
  { book: "4 Maccabees", chapter: 5, verse: 10, text: "σὺ δέ μοι καὶ ἀνοητότερον ποιήσειν δοκεῖς εἰ κενοδοξῶν περὶ τὸ ἀληθὲς ἔτι κἀμοῦ καταφρονήσεις ἐπὶ τῇ ἰδίᾳ τιμωρίᾳ" },
  { book: "4 Maccabees", chapter: 5, verse: 11, text: "οὐκ ἐξυπνώσεις ἀπὸ τῆς φλυάρου φιλοσοφίας ὑμῶν καὶ ἀποσκεδάσεις τῶν λογισμῶν σου τὸν λῆρον καὶ ἄξιον τῆς ἡλικίας ἀναλαβὼν νοῦν φιλοσοφήσεις τὴν τοῦ συμφέροντος ἀλήθειαν" },
  { book: "4 Maccabees", chapter: 5, verse: 12, text: "καὶ προσκυνήσας μου τὴν φιλάνθρωπον παρηγορίαν οἰκτιρήσεις τὸ σεαυτοῦ γῆρας" },
  { book: "4 Maccabees", chapter: 5, verse: 13, text: "καὶ γὰρ ἐνθυμήθητι ὡς εἰ καί τίς ἐστιν τῆσδε τῆς θρησκείας ὑμῶν ἐποπτικὴ δύναμις συγγνωμονήσειεν ἄν σοι ἐπὶ πάσῃ δῑ ἀνάγκην παρανομίᾳ γινομένῃ" },
  { book: "4 Maccabees", chapter: 5, verse: 14, text: "τοῦτον τὸν τρόπον ἐπὶ τὴν ἔκθεσμον σαρκοφαγίαν ἐποτρύνοντος τοῦ τυράννου λόγον ᾔτησεν ὁ Ελεαζαρος" },
  { book: "4 Maccabees", chapter: 5, verse: 15, text: "καὶ λαβὼν τοῦ λέγειν ἐξουσίαν ἤρξατο δημηγορεῖν οὕτως" },
  { book: "4 Maccabees", chapter: 5, verse: 16, text: "ἡμεῖς Ἀντίοχε θείῳ πεπεισμένοι νόμῳ πολιτεύεσθαι οὐδεμίαν ἀνάγκην βιαιοτέραν εἶναι νομίζομεν τῆς πρὸς τὸν νόμον ἡμῶν εὐπειθείας" },
  { book: "4 Maccabees", chapter: 5, verse: 17, text: "διὸ δὴ κατ’ οὐδένα τρόπον παρανομεῖν ἀξιοῦμεν" },
  { book: "4 Maccabees", chapter: 5, verse: 18, text: "καίτοι εἰ κατὰ ἀλήθειαν μὴ ἦν ὁ νόμος ἡμῶν ὡς ὑπολαμβάνεις θεῖος ἄλλως δὲ ἐνομίζομεν αὐτὸν εἶναι θεῖον οὐδὲ οὕτως ἐξὸν ἦν ἡμῖν τὴν ἐπὶ τῇ εὐσεβείᾳ δόξαν ἀκυρῶσαι" },
  { book: "4 Maccabees", chapter: 5, verse: 19, text: "μὴ μικρὰν οὖν εἶναι νομίσῃς ταύτην εἰ μιαροφαγήσαιμεν ἁμαρτίαν" },
  { book: "4 Maccabees", chapter: 5, verse: 20, text: "τὸ γὰρ ἐπὶ μικροῖς καὶ μεγάλοις παρανομεῖν ἰσοδύναμόν ἐστιν" },
  { book: "4 Maccabees", chapter: 5, verse: 21, text: "δῑ ἑκατέρου γὰρ ὡς ὁμοίως ὁ νόμος ὑπερηφανεῖται" },
  { book: "4 Maccabees", chapter: 5, verse: 22, text: "χλευάζεις δὲ ἡμῶν τὴν φιλοσοφίαν ὥσπερ οὐ μετὰ εὐλογιστίας ἐν αὐτῇ βιούντων" },
  { book: "4 Maccabees", chapter: 5, verse: 23, text: "σωφροσύνην τε γὰρ ἡμᾶς ἐκδιδάσκει ὥστε πασῶν τῶν ἡδονῶν καὶ ἐπιθυμιῶν κρατεῖν καὶ ἀνδρείαν ἐξασκεῖ ὥστε πάντα πόνον ἑκουσίως ὑπομένειν" },
  { book: "4 Maccabees", chapter: 5, verse: 24, text: "καὶ δικαιοσύνην παιδεύει ὥστε διὰ πάντων τῶν ἠθῶν ἰσονομεῖν καὶ εὐσέβειαν ἐκδιδάσκει ὥστε μόνον τὸν ὄντα θεὸν σέβειν μεγαλοπρεπῶς" },
  { book: "4 Maccabees", chapter: 5, verse: 25, text: "διὸ οὐ μιαροφαγοῦμεν πιστεύοντες γὰρ θεοῦ καθεστάναι τὸν νόμον οἴδαμεν ὅτι κατὰ φύσιν ἡμῖν συμπαθεῖ νομοθετῶν ὁ τοῦ κόσμου κτίστης" },
  { book: "4 Maccabees", chapter: 5, verse: 26, text: "τὰ μὲν οἰκειωθησόμενα ἡμῶν ταῖς ψυχαῖς ἐπέτρεψεν ἐσθίειν τὰ δὲ ἐναντιωθησόμενα ἐκώλυσεν σαρκοφαγεῖν" },
  { book: "4 Maccabees", chapter: 5, verse: 27, text: "τυραννικὸν δὲ οὐ μόνον ἀναγκάζειν ἡμᾶς παρανομεῖν ἀλλὰ καὶ ἐσθίειν ὅπως τῇ ἐχθίστῃ ἡμῶν μιαροφαγίᾳ ταύτῃ ἐπεγγελάσῃς" },
  { book: "4 Maccabees", chapter: 5, verse: 28, text: "ἀλλ’ οὐ γελάσεις κατ’ ἐμοῦ τοῦτον τὸν γέλωτα" },
  { book: "4 Maccabees", chapter: 5, verse: 29, text: "οὔτε τοὺς ἱεροὺς τῶν προγόνων περὶ τοῦ φυλάξαι τὸν νόμον ὅρκους οὐ παρήσω" },
  { book: "4 Maccabees", chapter: 5, verse: 30, text: "οὐδ’ ἂν ἐκκόψειάς μου τὰ ὄμματα καὶ τὰ σπλάγχνα μου τήξειας" },
  { book: "4 Maccabees", chapter: 5, verse: 31, text: "οὐχ οὕτως εἰμὶ γέρων ἐγὼ καὶ ἄνανδρος ὥστε μοι διὰ τὴν εὐσέβειαν μὴ νεάζειν τὸν λογισμόν" },
  { book: "4 Maccabees", chapter: 5, verse: 32, text: "πρὸς ταῦτα τροχοὺς εὐτρέπιζε καὶ τὸ πῦρ ἐκφύσα σφοδρότερον" },
  { book: "4 Maccabees", chapter: 5, verse: 33, text: "οὐχ οὕτως οἰκτίρομαι τὸ ἐμαυτοῦ γῆρας ὥστε δῑ ἐμαυτοῦ τὸν πάτριον καταλῦσαι νόμον" },
  { book: "4 Maccabees", chapter: 5, verse: 34, text: "οὐ ψεύσομαί σε παιδευτὰ νόμε οὐδὲ ἐξομοῦμαί σε φίλη ἐγκράτεια" },
  { book: "4 Maccabees", chapter: 5, verse: 35, text: "οὐδὲ καταισχυνῶ σε φιλόσοφε λόγε οὐδὲ ἐξαρνήσομαί σε ἱερωσύνη τιμία καὶ νομοθεσίας ἐπιστήμη" },
  { book: "4 Maccabees", chapter: 5, verse: 36, text: "οὐδὲ μιανεῖς μου τὸ σεμνὸν γήρως στόμα οὐδὲ νομίμου βίου ἡλικίαν" },
  { book: "4 Maccabees", chapter: 5, verse: 37, text: "ἁγνόν με οἱ πατέρες εἰσδέξονται μὴ φοβηθέντα σου τὰς μέχρι θανάτου ἀνάγκας" },
  { book: "4 Maccabees", chapter: 5, verse: 38, text: "ἀσεβῶν μὲν γὰρ τυραννήσεις τῶν δὲ ἐμῶν ὑπὲρ τῆς εὐσεβείας λογισμῶν οὔτε λόγοις δεσπόσεις οὔτε δῑ ἔργων" },
  { book: "4 Maccabees", chapter: 6, verse: 1, text: "τοῦτον τὸν τρόπον ἀντιρρητορεύσαντα ταῖς τοῦ τυράννου παρηγορίαις παραστάντες οἱ δορυφόροι πικρῶς ἔσυραν ἐπὶ τὰ βασανιστήρια τὸν Ελεαζαρον" },
  { book: "4 Maccabees", chapter: 6, verse: 2, text: "καὶ πρῶτον μὲν περιέδυσαν τὸν γεραιὸν ἐγκοσμούμενον τῇ περὶ τὴν εὐσέβειαν εὐσχημοσύνῃ" },
  { book: "4 Maccabees", chapter: 6, verse: 3, text: "ἔπειτα περιαγκωνίσαντες ἑκατέρωθεν μάστιξιν κατῄκιζον" },
  { book: "4 Maccabees", chapter: 6, verse: 4, text: "πείσθητι ταῖς τοῦ βασιλέως ἐντολαῖς ἑτέρωθεν κήρυκος ἐπιβοῶντος" },
  { book: "4 Maccabees", chapter: 6, verse: 5, text: "ὁ δὲ μεγαλόφρων καὶ εὐγενὴς ὡς ἀληθῶς Ελεαζαρος ὥσπερ ἐν ὀνείρῳ βασανιζόμενος κατ’ οὐδένα τρόπον μετετρέπετο" },
  { book: "4 Maccabees", chapter: 6, verse: 6, text: "ἀλλὰ ὑψηλοὺς ἀνατείνας εἰς οὐρανὸν τοὺς ὀφθαλμοὺς ἀπεξαίνετο ταῖς μάστιξιν τὰς σάρκας ὁ γέρων καὶ κατερρεῖτο τῷ αἵματι καὶ τὰ πλευρὰ κατετιτρώσκετο" },
  { book: "4 Maccabees", chapter: 6, verse: 7, text: "καὶ πίπτων εἰς τὸ ἔδαφος ἀπὸ τοῦ μὴ φέρειν τὸ σῶμα τὰς ἀλγηδόνας ὀρθὸν εἶχεν καὶ ἀκλινῆ τὸν λογισμόν" },
  { book: "4 Maccabees", chapter: 6, verse: 8, text: "λάξ γέ τοι τῶν πικρῶν τις δορυφόρων εἰς τοὺς κενεῶνας ἐναλλόμενος ἔτυπτεν ὅπως ἐξανίσταιτο πίπτων" },
  { book: "4 Maccabees", chapter: 6, verse: 9, text: "ὁ δὲ ὑπέμενε τοὺς πόνους καὶ περιεφρόνει τῆς ἀνάγκης καὶ διεκαρτέρει τοὺς αἰκισμούς" },
  { book: "4 Maccabees", chapter: 6, verse: 10, text: "καὶ καθάπερ γενναῖος ἀθλητὴς τυπτόμενος ἐνίκα τοὺς βασανίζοντας ὁ γέρων" },
  { book: "4 Maccabees", chapter: 6, verse: 11, text: "ἱδρῶν γέ τοι τὸ πρόσωπον καὶ ἐπασθμαίνων σφοδρῶς καὶ ὑπ’ αὐτῶν τῶν βασανιζόντων ἐθαυμάζετο ἐπὶ τῇ εὐψυχίᾳ" },
  { book: "4 Maccabees", chapter: 6, verse: 12, text: "ὅθεν τὰ μὲν ἐλεῶντες τὰ τοῦ γήρως αὐτοῦ" },
  { book: "4 Maccabees", chapter: 6, verse: 13, text: "τὰ δὲ ἐν συμπαθείᾳ τῆς συνηθείας ὄντες τὰ δὲ ἐν θαυμασμῷ τῆς καρτερίας προσιόντες αὐτῷ τινες τοῦ βασιλέως ἔλεγον" },
  { book: "4 Maccabees", chapter: 6, verse: 14, text: "τί τοῖς κακοῖς τούτοις σεαυτὸν ἀλογίστως ἀπόλλεις Ελεαζαρ" },
  { book: "4 Maccabees", chapter: 6, verse: 15, text: "ἡμεῖς μέν τοι τῶν ἡψημένων βρωμάτων παραθήσομεν σὺ δὲ ὑποκρινόμενος τῶν ὑείων ἀπογεύεσθαι σώθητι" },
  { book: "4 Maccabees", chapter: 6, verse: 16, text: "καὶ ὁ Ελεαζαρος ὥσπερ πικρότερον διὰ τῆς συμβουλίας αἰκισθεὶς ἀνεβόησεν" },
  { book: "4 Maccabees", chapter: 6, verse: 17, text: "μὴ οὕτως κακῶς φρονήσαιμεν οἱ Αβρααμ παῖδες ὥστε μαλακοψυχήσαντας ἀπρεπὲς ἡμῖν δρᾶμα ὑποκρίνασθαι" },
  { book: "4 Maccabees", chapter: 6, verse: 18, text: "καὶ γὰρ ἀλόγιστον εἰ πρὸς ἀλήθειαν ζήσαντες τὸν μέχρι γήρως βίον καὶ τὴν ἐπ’ αὐτῷ δόξαν νομίμως φυλάσσοντες νῦν μεταβαλοίμεθα" },
  { book: "4 Maccabees", chapter: 6, verse: 19, text: "καὶ αὐτοὶ μὲν ἡμεῖς γενοίμεθα τοῖς νέοις ἀσεβείας τύπος ἵνα παράδειγμα γενώμεθα τῆς μιαροφαγίας" },
  { book: "4 Maccabees", chapter: 6, verse: 20, text: "αἰσχρὸν δὲ εἰ ἐπιβιώσομεν ὀλίγον χρόνον καὶ τοῦτον καταγελώμενοι πρὸς ἁπάντων ἐπὶ δειλίᾳ" },
  { book: "4 Maccabees", chapter: 6, verse: 21, text: "καὶ ὑπὸ μὲν τοῦ τυράννου καταφρονηθῶμεν ὡς ἄνανδροι τὸν δὲ θεῖον ἡμῶν νόμον μέχρι θανάτου μὴ προασπίσαιμεν" },
  { book: "4 Maccabees", chapter: 6, verse: 22, text: "πρὸς ταῦτα ὑμεῖς μέν ὦ Αβρααμ παῖδες εὐγενῶς ὑπὲρ τῆς εὐσεβείας τελευτᾶτε" },
  { book: "4 Maccabees", chapter: 6, verse: 23, text: "οἱ δὲ τοῦ τυράννου δορυφόροι τί μέλλετε" },
  { book: "4 Maccabees", chapter: 6, verse: 24, text: "πρὸς τὰς ἀνάγκας οὕτως μεγαλοφρονοῦντα αὐτὸν ἰδόντες καὶ μηδὲ πρὸς τὸν οἰκτιρμὸν αὐτῶν μεταβαλλόμενον ἐπὶ τὸ πῦρ αὐτὸν ἀνῆγον" },
  { book: "4 Maccabees", chapter: 6, verse: 25, text: "ἔνθα διὰ κακοτέχνων ὀργάνων καταφλέγοντες αὐτὸν ὑπερρίπτοσαν καὶ δυσώδεις χυλοὺς εἰς τοὺς μυκτῆρας αὐτοῦ κατέχεον" },
  { book: "4 Maccabees", chapter: 6, verse: 26, text: "ὁ δὲ μέχρι τῶν ὀστέων ἤδη κατακεκαυμένος καὶ μέλλων λιποθυμεῖν ἀνέτεινε τὰ ὄμματα πρὸς τὸν θεὸν καὶ εἶπεν" },
  { book: "4 Maccabees", chapter: 6, verse: 27, text: "σὺ οἶσθα θεέ παρόν μοι σῴζεσθαι βασάνοις καυστικαῖς ἀποθνῄσκω διὰ τὸν νόμον" },
  { book: "4 Maccabees", chapter: 6, verse: 28, text: "ἵλεως γενοῦ τῷ ἔθνει σου ἀρκεσθεὶς τῇ ἡμετέρᾳ ὑπὲρ αὐτῶν δίκῃ" },
  { book: "4 Maccabees", chapter: 6, verse: 29, text: "καθάρσιον αὐτῶν ποίησον τὸ ἐμὸν αἷμα καὶ ἀντίψυχον αὐτῶν λαβὲ τὴν ἐμὴν ψυχήν" },
  { book: "4 Maccabees", chapter: 6, verse: 30, text: "καὶ ταῦτα εἰπὼν ὁ ἱερὸς ἀνὴρ εὐγενῶς ταῖς βασάνοις ἐναπέθανεν καὶ μέχρι τῶν τοῦ θανάτου βασάνων ἀντέστη τῷ λογισμῷ διὰ τὸν νόμον" },
  { book: "4 Maccabees", chapter: 6, verse: 31, text: "ὁμολογουμένως οὖν δεσπότης τῶν παθῶν ἐστιν ὁ εὐσεβὴς λογισμός" },
  { book: "4 Maccabees", chapter: 6, verse: 32, text: "εἰ γὰρ τὰ πάθη τοῦ λογισμοῦ κεκρατήκει τούτοις ἂν ἀπέδομεν τὴν τῆς ἐπικρατείας μαρτυρίαν" },
  { book: "4 Maccabees", chapter: 6, verse: 33, text: "νυνὶ δὲ τοῦ λογισμοῦ τὰ πάθη νικήσαντος αὐτῷ προσηκόντως τὴν τῆς ἡγεμονίας προσνέμομεν ἐξουσίαν" },
  { book: "4 Maccabees", chapter: 6, verse: 34, text: "καὶ δίκαιόν ἐστιν ὁμολογεῖν ἡμᾶς τὸ κράτος εἶναι τοῦ λογισμοῦ ὅπου γε καὶ τῶν ἔξωθεν ἀλγηδόνων ἐπικρατεῖ ἐπεὶ καὶ γελοῖον" },
  { book: "4 Maccabees", chapter: 6, verse: 35, text: "καὶ οὐ μόνον τῶν ἀλγηδόνων ἐπιδείκνυμι κεκρατηκέναι τὸν λογισμόν ἀλλὰ καὶ τῶν ἡδονῶν κρατεῖν καὶ μηδὲν αὐταῖς ὑπείκειν" },
  { book: "4 Maccabees", chapter: 7, verse: 1, text: "ὥσπερ γὰρ ἄριστος κυβερνήτης ὁ τοῦ πατρὸς ἡμῶν Ελεαζαρου λογισμὸς πηδαλιουχῶν τὴν τῆς εὐσεβείας ναῦν ἐν τῷ τῶν παθῶν πελάγει" },
  { book: "4 Maccabees", chapter: 7, verse: 2, text: "καὶ καταικιζόμενος ταῖς τοῦ τυράννου ἀπειλαῖς καὶ καταντλούμενος ταῖς τῶν βασάνων τρικυμίαις" },
  { book: "4 Maccabees", chapter: 7, verse: 3, text: "κατ’ οὐδένα τρόπον ἔτρεψε τοὺς τῆς εὐσεβείας οἴακας ἕως οὗ ἔπλευσεν ἐπὶ τὸν τῆς ἀθανάτου νίκης λιμένα" },
  { book: "4 Maccabees", chapter: 7, verse: 4, text: "οὐχ οὕτως πόλις πολλοῖς καὶ ποικίλοις μηχανήμασιν ἀντέσχε ποτὲ πολιορκουμένη ὡς ὁ πανάγιος ἐκεῖνος τὴν ἱερὰν ψυχὴν αἰκισμοῖς τε καὶ στρέβλαις πυρπολούμενος ἐνίκησεν τοὺς πολιορκοῦντας διὰ τὸν ὑπερασπίζοντα τῆς εὐσεβείας λογισμόν" },
  { book: "4 Maccabees", chapter: 7, verse: 5, text: "ὥσπερ γὰρ πρόκρημνον ἄκραν τὴν ἑαυτοῦ διάνοιαν ὁ πατὴρ Ελεαζαρ ἐκτείνας περιέκλασεν τοὺς ἐπιμαινομένους τῶν παθῶν κλύδωνας" },
  { book: "4 Maccabees", chapter: 7, verse: 6, text: "ὦ ἄξιε τῆς ἱερωσύνης ἱερεῦ οὐκ ἐμίανας τοὺς ἱεροὺς ὀδόντας οὐδὲ τὴν θεοσέβειαν καὶ καθαρισμὸν χωρήσασαν γαστέρα ἐκοίνωσας μιαροφαγίᾳ" },
  { book: "4 Maccabees", chapter: 7, verse: 7, text: "ὦ σύμφωνε νόμου καὶ φιλόσοφε θείου βίου" },
  { book: "4 Maccabees", chapter: 7, verse: 8, text: "τοιούτους δεῖ εἶναι τοὺς δημιουργοῦντας τὸν νόμον ἰδίῳ αἵματι καὶ γενναίῳ ἱδρῶτι τοῖς μέχρι θανάτου πάθεσιν ὑπερασπίζοντας" },
  { book: "4 Maccabees", chapter: 7, verse: 9, text: "σύ πάτερ τὴν εὐνομίαν ἡμῶν διὰ τῶν ὑπομονῶν εἰς δόξαν ἐκύρωσας καὶ τὴν ἁγιαστίαν σεμνολογήσας οὐ κατέλυσας καὶ διὰ τῶν ἔργων ἐπιστοποίησας τοὺς τῆς θείας φιλοσοφίας σου λόγους" },
  { book: "4 Maccabees", chapter: 7, verse: 10, text: "ὦ βασάνων βιαιότερε γέρων καὶ πυρὸς εὐτονώτερε πρεσβῦτα καὶ παθῶν μέγιστε βασιλεῦ Ελεαζαρ" },
  { book: "4 Maccabees", chapter: 7, verse: 11, text: "ὥσπερ γὰρ ὁ πατὴρ Ααρων τῷ θυμιατηρίῳ καθωπλισμένος διὰ τοῦ ἐθνοπλήθους ἐπιτρέχων τὸν ἐμπυριστὴν ἐνίκησεν ἄγγελον" },
  { book: "4 Maccabees", chapter: 7, verse: 12, text: "οὕτως ὁ Ααρωνίδης Ελεαζαρ διὰ τοῦ πυρὸς ὑπερτηκόμενος οὐ μετετράπη τὸν λογισμόν" },
  { book: "4 Maccabees", chapter: 7, verse: 13, text: "καίτοι τὸ θαυμασιώτατον γέρων ὢν λελυμένων μὲν ἤδη τῶν τοῦ σώματος τόνων περικεχαλασμένων δὲ τῶν σαρκῶν κεκμηκότων δὲ καὶ τῶν νεύρων ἀνενέασεν" },
  { book: "4 Maccabees", chapter: 7, verse: 14, text: "τῷ πνεύματι διὰ τοῦ λογισμοῦ καὶ τῷ Ισακίῳ λογισμῷ τὴν πολυκέφαλον στρέβλαν ἠκύρωσεν" },
  { book: "4 Maccabees", chapter: 7, verse: 15, text: "ὦ μακαρίου γήρως καὶ σεμνῆς πολιᾶς καὶ βίου νομίμου ὃν πιστὴ θανάτου σφραγὶς ἐτελείωσεν" },
  { book: "4 Maccabees", chapter: 7, verse: 16, text: "εἰ δὴ τοίνυν γέρων ἀνὴρ τῶν μέχρι θανάτου βασάνων περιεφρόνει δῑ εὐσέβειαν ὁμολογουμένως ἡγεμών ἐστιν τῶν παθῶν ὁ εὐσεβὴς λογισμός" },
  { book: "4 Maccabees", chapter: 7, verse: 17, text: "ἴσως δ’ ἂν εἴποιέν τινες τῶν παθῶν οὐ πάντες περικρατοῦσιν ὅτι οὐδὲ πάντες φρόνιμον ἔχουσιν τὸν λογισμόν" },
  { book: "4 Maccabees", chapter: 7, verse: 18, text: "ἀλλ’ ὅσοι τῆς εὐσεβείας προνοοῦσιν ἐξ ὅλης καρδίας οὗτοι μόνοι δύνανται κρατεῖν τῶν τῆς σαρκὸς παθῶν" },
  { book: "4 Maccabees", chapter: 7, verse: 19, text: "πιστεύοντες ὅτι θεῷ οὐκ ἀποθνῄσκουσιν ὥσπερ οὐδὲ οἱ πατριάρχαι ἡμῶν Αβρααμ καὶ Ισαακ καὶ Ιακωβ ἀλλὰ ζῶσιν τῷ θεῷ" },
  { book: "4 Maccabees", chapter: 7, verse: 20, text: "οὐδὲν οὖν ἐναντιοῦται τὸ φαίνεσθαί τινας παθοκρατεῖσθαι διὰ τὸν ἀσθενῆ λογισμόν" },
  { book: "4 Maccabees", chapter: 7, verse: 21, text: "ἐπεὶ τίς πρὸς ὅλον τὸν τῆς φιλοσοφίας κανόνα φιλοσοφῶν καὶ πεπιστευκὼς θεῷ" },
  { book: "4 Maccabees", chapter: 7, verse: 22, text: "καὶ εἰδὼς ὅτι διὰ τὴν ἀρετὴν πάντα πόνον ὑπομένειν μακάριόν ἐστιν οὐκ ἂν περικρατήσειεν τῶν παθῶν διὰ τὴν θεοσέβειαν" },
  { book: "4 Maccabees", chapter: 7, verse: 23, text: "μόνος γὰρ ὁ σοφὸς καὶ ἀνδρεῖός ἐστιν τῶν παθῶν κύριος" },
  { book: "4 Maccabees", chapter: 8, verse: 1, text: "διὰ τοῦτό γέ τοι καὶ μειρακίσκοι τῷ τῆς εὐσεβείας λογισμῷ φιλοσοφοῦντες χαλεπωτέρων βασανιστηρίων ἐπεκράτησαν" },
  { book: "4 Maccabees", chapter: 8, verse: 2, text: "ἐπειδὴ γὰρ κατὰ τὴν πρώτην πεῖραν ἐνικήθη περιφανῶς ὁ τύραννος μὴ δυνηθεὶς ἀναγκάσαι γέροντα μιαροφαγῆσαι τότε δὴ σφόδρα περιπαθῶς ἐκέλευσεν ἄλλους ἐκ τῆς λείας τῶν Εβραίων ἀγαγεῖν καὶ εἰ μὲν μιαροφαγήσαιεν ἀπολύειν φαγόντας εἰ δ’ ἀντιλέγοιεν πικρότερον βασανίζειν" },
  { book: "4 Maccabees", chapter: 8, verse: 3, text: "ταῦτα διαταξαμένου τοῦ τυράννου παρῆσαν ἀγόμενοι μετὰ γεραιᾶς μητρὸς ἑπτὰ ἀδελφοὶ καλοί τε καὶ αἰδήμονες καὶ γενναῖοι καὶ ἐν παντὶ χαρίεντες" },
  { book: "4 Maccabees", chapter: 8, verse: 4, text: "οὓς ἰδὼν ὁ τύραννος καθάπερ ἐν χορῷ μέσην τὴν μητέρα περιέχοντας ἥσθετο ἐπ’ αὐτοῖς καὶ τῆς εὐπρεπείας ἐκπλαγεὶς καὶ τῆς εὐγενείας προσεμειδίασεν αὐτοῖς καὶ πλησίον καλέσας ἔφη" },
  { book: "4 Maccabees", chapter: 8, verse: 5, text: "ὦ νεανίαι φιλοφρόνως ἐγὼ καθ’ ἑνὸς ἑκάστου ὑμῶν θαυμάζω τὸ κάλλος καὶ τὸ πλῆθος τοσούτων ἀδελφῶν ὑπερτιμῶν οὐ μόνον συμβουλεύω μὴ μανῆναι τὴν αὐτὴν τῷ προβασανισθέντι γέροντι μανίαν ἀλλὰ καὶ παρακαλῶ συνείξαντάς μοι τῆς ἐμῆς ἀπολαύειν φιλίας" },
  { book: "4 Maccabees", chapter: 8, verse: 6, text: "δυναίμην δ’ ἂν ὥσπερ κολάζειν τοὺς ἀπειθοῦντάς μου τοῖς ἐπιτάγμασιν οὕτω καὶ εὐεργετεῖν τοὺς εὐπειθοῦντάς μοι" },
  { book: "4 Maccabees", chapter: 8, verse: 7, text: "πιστεύσατε οὖν καὶ ἀρχὰς ἐπὶ τῶν ἐμῶν πραγμάτων ἡγεμονικὰς λήμψεσθε ἀρνησάμενοι τὸν πάτριον ὑμῶν τῆς πολιτείας θεσμόν" },
  { book: "4 Maccabees", chapter: 8, verse: 8, text: "καὶ μεταλαβόντες Ἑλληνικοῦ βίου καὶ μεταδιαιτηθέντες ἐντρυφήσατε ταῖς νεότησιν ὑμῶν" },
  { book: "4 Maccabees", chapter: 8, verse: 9, text: "ἐπεί ἐὰν ὀργίλως με διάθησθε διὰ τῆς ἀπειθείας ἀναγκάσετέ με ἐπὶ δειναῖς κολάσεσιν ἕνα ἕκαστον ὑμῶν διὰ τῶν βασάνων ἀπολέσαι" },
  { book: "4 Maccabees", chapter: 8, verse: 10, text: "κατελεήσατε οὖν ἑαυτούς οὓς καὶ ὁ πολέμιος ἔγωγε καὶ τῆς ἡλικίας καὶ τῆς εὐμορφίας οἰκτίρομαι" },
  { book: "4 Maccabees", chapter: 8, verse: 11, text: "οὐ διαλογιεῖσθε τοῦτο ὅτι οὐδὲν ὑμῖν ἀπειθήσασιν πλὴν τοῦ μετὰ στρεβλῶν ἀποθανεῖν ἀπόκειται" },
  { book: "4 Maccabees", chapter: 8, verse: 12, text: "ταῦτα δὲ λέγων ἐκέλευσεν εἰς τὸ ἔμπροσθεν τιθέναι τὰ βασανιστήρια ὅπως καὶ διὰ τοῦ φόβου πείσειεν αὐτοὺς μιαροφαγῆσαι" },
  { book: "4 Maccabees", chapter: 8, verse: 13, text: "ὡς δὲ τροχούς τε καὶ ἀρθρέμβολα στρεβλωτήριά τε καὶ τροχαντῆρας καὶ καταπέλτας καὶ λέβητας τήγανά τε καὶ δακτυλήθρας καὶ χεῖρας σιδηρᾶς καὶ σφῆνας καὶ τὰ ζώπυρα τοῦ πυρὸς οἱ δορυφόροι προέθεσαν ὑπολαβὼν ὁ τύραννος ἔφη" },
  { book: "4 Maccabees", chapter: 8, verse: 14, text: "μειράκια φοβήθητε καὶ ἣν σέβεσθε δίκην ἵλεως ὑμῖν ἔσται δῑ ἀνάγκην παρανομήσασιν" },
  { book: "4 Maccabees", chapter: 8, verse: 15, text: "οἱ δὲ ἀκούσαντες ἐπαγωγὰ καὶ ὁρῶντες δεινὰ οὐ μόνον οὐκ ἐφοβήθησαν ἀλλὰ καὶ ἀντεφιλοσόφησαν τῷ τυράννῳ καὶ διὰ τῆς εὐλογιστίας τὴν τυραννίδα αὐτοῦ κατέλυσαν" },
  { book: "4 Maccabees", chapter: 8, verse: 16, text: "καίτοι λογισώμεθα εἰ δειλόψυχοί τινες ἦσαν ἐν αὐτοῖς καὶ ἄνανδροι ποίοις ἂν ἐχρήσαντο λόγοις οὐχὶ τούτοις" },
  { book: "4 Maccabees", chapter: 8, verse: 17, text: "ὦ τάλανες ἡμεῖς καὶ λίαν ἀνόητοι βασιλέως ἡμᾶς καλοῦντος καὶ ἐπὶ εὐεργεσίᾳ παρακαλοῦντος εἰ πεισθείημεν αὐτῷ" },
  { book: "4 Maccabees", chapter: 8, verse: 18, text: "τί βουλήμασιν κενοῖς ἑαυτοὺς εὐφραίνομεν καὶ θανατηφόρον ἀπείθειαν τολμῶμεν" },
  { book: "4 Maccabees", chapter: 8, verse: 19, text: "οὐ φοβηθησόμεθα ἄνδρες ἀδελφοί τὰ βασανιστήρια καὶ λογιούμεθα τὰς τῶν βασάνων ἀπειλὰς καὶ φευξόμεθα τὴν κενοδοξίαν ταύτην καὶ ὀλεθροφόρον ἀλαζονείαν" },
  { book: "4 Maccabees", chapter: 8, verse: 20, text: "ἐλεήσωμεν τὰς ἑαυτῶν ἡλικίας καὶ κατοικτίρωμεν τὸ τῆς μητρὸς γῆρας" },
  { book: "4 Maccabees", chapter: 8, verse: 21, text: "καὶ ἐνθυμηθῶμεν ὅτι ἀπειθοῦντες τεθνηξόμεθα" },
  { book: "4 Maccabees", chapter: 8, verse: 22, text: "συγγνώσεται δὲ ἡμῖν καὶ ἡ θεία δίκη δῑ ἀνάγκην τὸν βασιλέα φοβηθεῖσιν" },
  { book: "4 Maccabees", chapter: 8, verse: 23, text: "τί ἐξάγομεν ἑαυτοὺς τοῦ ἡδίστου βίου καὶ ἀποστεροῦμεν ἑαυτοὺς τοῦ γλυκέος κόσμου" },
  { book: "4 Maccabees", chapter: 8, verse: 24, text: "μὴ βιαζώμεθα τὴν ἀνάγκην μηδὲ κενοδοξήσωμεν ἐπὶ τῇ ἑαυτῶν στρέβλῃ" },
  { book: "4 Maccabees", chapter: 8, verse: 25, text: "οὐδ’ αὐτὸς ὁ νόμος ἑκουσίως ἡμᾶς θανατοῖ φοβηθέντας τὰ βασανιστήρια" },
  { book: "4 Maccabees", chapter: 8, verse: 26, text: "πόθεν ἡμῖν ἡ τοσαύτη ἐντέτηκε φιλονεικία καὶ ἡ θανατηφόρος ἀρέσκει καρτερία παρὸν μετὰ ἀταραξίας ζῆν τῷ βασιλεῖ πεισθέντας" },
  { book: "4 Maccabees", chapter: 8, verse: 27, text: "ἀλλὰ τούτων οὐδὲν εἶπον οἱ νεανίαι βασανίζεσθαι μέλλοντες οὐδὲ ἐνεθυμήθησαν" },
  { book: "4 Maccabees", chapter: 8, verse: 28, text: "ἦσαν γὰρ περίφρονες τῶν παθῶν καὶ αὐτοκράτορες τῶν ἀλγηδόνων" },
  { book: "4 Maccabees", chapter: 8, verse: 29, text: "ὥστε ἅμα τῷ παύσασθαι τὸν τύραννον συμβουλεύοντα αὐτοῖς μιαροφαγῆσαι πάντες διὰ μιᾶς φωνῆς ὁμοῦ ὥσπερ ἀπὸ τῆς αὐτῆς ψυχῆς εἶπον" },
  { book: "4 Maccabees", chapter: 9, verse: 1, text: "τί μέλλεις ὦ τύραννε ἕτοιμοι γάρ ἐσμεν ἀποθνῄσκειν ἢ παραβαίνειν τὰς πατρίους ἡμῶν ἐντολάς" },
  { book: "4 Maccabees", chapter: 9, verse: 2, text: "αἰσχυνόμεθα γὰρ τοὺς προγόνους ἡμῶν εἰκότως εἰ μὴ τῇ τοῦ νόμου εὐπειθείᾳ καὶ συμβούλῳ Μωυσεῖ χρησαίμεθα" },
  { book: "4 Maccabees", chapter: 9, verse: 3, text: "σύμβουλε τύραννε παρανομίας μὴ ἡμᾶς μισῶν ὑπὲρ αὐτοὺς ἡμᾶς ἐλέα" },
  { book: "4 Maccabees", chapter: 9, verse: 4, text: "χαλεπώτερον γὰρ αὐτοῦ τοῦ θανάτου νομίζομεν εἶναί σου τὸν ἐπὶ τῇ παρανόμῳ σωτηρίᾳ ἡμῶν ἔλεον" },
  { book: "4 Maccabees", chapter: 9, verse: 5, text: "ἐκφοβεῖς δὲ ἡμᾶς τὸν διὰ τῶν βασάνων θάνατον ἡμῖν ἀπειλῶν ὥσπερ οὐχὶ πρὸ βραχέως παρ’ Ελεαζαρου μαθών" },
  { book: "4 Maccabees", chapter: 9, verse: 6, text: "εἰ δ’ οἱ γέροντες τῶν Εβραίων διὰ τὴν εὐσέβειαν καὶ βασανισμοὺς ὑπομείναντες εὐσέβησαν ἀποθάνοιμεν ἂν δικαιότερον ἡμεῖς οἱ νέοι τὰς βασάνους τῶν σῶν ἀναγκῶν ὑπεριδόντες ἃς καὶ ὁ παιδευτὴς ἡμῶν γέρων ἐνίκησεν" },
  { book: "4 Maccabees", chapter: 9, verse: 7, text: "πείραζε τοιγαροῦν τύραννε καὶ τὰς ἡμῶν ψυχὰς εἰ θανατώσεις διὰ τὴν εὐσέβειαν μὴ νομίσῃς ἡμᾶς βλάπτειν βασανίζων" },
  { book: "4 Maccabees", chapter: 9, verse: 8, text: "ἡμεῖς μὲν γὰρ διὰ τῆσδε τῆς κακοπαθείας καὶ ὑπομονῆς τὰ τῆς ἀρετῆς ἆθλα ἕξομεν καὶ ἐσόμεθα παρὰ θεῷ δῑ ὃν καὶ πάσχομεν" },
  { book: "4 Maccabees", chapter: 9, verse: 9, text: "σὺ δὲ διὰ τὴν ἡμῶν μιαιφονίαν αὐτάρκη καρτερήσεις ὑπὸ τῆς θείας δίκης αἰώνιον βάσανον διὰ πυρός" },
  { book: "4 Maccabees", chapter: 9, verse: 10, text: "ταῦτα αὐτῶν εἰπόντων οὐ μόνον ὡς κατὰ ἀπειθούντων ἐχαλέπαινεν ὁ τύραννος ἀλλὰ καὶ ὡς κατὰ ἀχαρίστων ὠργίσθη" },
  { book: "4 Maccabees", chapter: 9, verse: 11, text: "ὅθεν τὸν πρεσβύτατον αὐτῶν κελευσθέντες παρῆγον οἱ ὑπασπισταὶ καὶ διαρρήξαντες τὸν χιτῶνα διέδησαν τὰς χεῖρας αὐτοῦ καὶ τοὺς βραχίονας ἱμᾶσιν ἑκατέρωθεν" },
  { book: "4 Maccabees", chapter: 9, verse: 12, text: "ὡς δὲ τύπτοντες ταῖς μάστιξιν ἐκοπίασαν μηδὲν ἀνύοντες ἀνέβαλον αὐτὸν ἐπὶ τὸν τροχόν" },
  { book: "4 Maccabees", chapter: 9, verse: 13, text: "περὶ ὃν κατατεινόμενος ὁ εὐγενὴς νεανίας ἔξαρθρος ἐγίνετο" },
  { book: "4 Maccabees", chapter: 9, verse: 14, text: "καὶ κατὰ πᾶν μέλος κλώμενος ἐκακηγόρει λέγων" },
  { book: "4 Maccabees", chapter: 9, verse: 15, text: "τύραννε μιαρώτατε καὶ τῆς οὐρανίου δίκης ἐχθρὲ καὶ ὠμόφρων οὐκ ἀνδροφονήσαντά με τοῦτον καταικίζεις τὸν τρόπον οὐδὲ ἀσεβήσαντα ἀλλὰ θείου νόμου προασπίζοντα" },
  { book: "4 Maccabees", chapter: 9, verse: 16, text: "καὶ τῶν δορυφόρων λεγόντων ὁμολόγησον φαγεῖν ὅπως ἀπαλλαγῇς τῶν βασάνων" },
  { book: "4 Maccabees", chapter: 9, verse: 17, text: "ὁ δὲ εἶπεν οὐχ οὕτως ἰσχυρὸς ὑμῶν ἐστιν ὁ τροχός ὦ μιαροὶ διάκονοι ὥστε μου τὸν λογισμὸν ἄγξαι τέμνετέ μου τὰ μέλη καὶ πυροῦτέ μου τὰς σάρκας καὶ στρεβλοῦτε τὰ ἄρθρα" },
  { book: "4 Maccabees", chapter: 9, verse: 18, text: "διὰ πασῶν γὰρ ὑμᾶς πείσω τῶν βασάνων ὅτι μόνοι παῖδες Εβραίων ὑπὲρ ἀρετῆς εἰσιν ἀνίκητοι" },
  { book: "4 Maccabees", chapter: 9, verse: 19, text: "ταῦτα λέγοντι ὑπέστρωσαν πῦρ καὶ τὸ διερεθίζον τὸν τροχὸν προσεπικατέτεινον" },
  { book: "4 Maccabees", chapter: 9, verse: 20, text: "ἐμολύνετο δὲ πάντοθεν αἵματι ὁ τροχός καὶ ὁ σωρὸς τῆς ἀνθρακιᾶς τοῖς τῶν ἰχώρων ἐσβέννυτο σταλαγμοῖς καὶ περὶ τοὺς ἄξονας τοῦ ὀργάνου περιέρρεον αἱ σάρκες" },
  { book: "4 Maccabees", chapter: 9, verse: 21, text: "καὶ περιτετμημένον ἤδη ἔχων τὸ τῶν ὀστέων πῆγμα ὁ μεγαλόφρων καὶ Αβραμιαῖος νεανίας οὐκ ἐστέναξεν" },
  { book: "4 Maccabees", chapter: 9, verse: 22, text: "ἀλλ’ ὥσπερ ἐν πυρὶ μετασχηματιζόμενος εἰς ἀφθαρσίαν ὑπέμεινεν εὐγενῶς τὰς στρέβλας" },
  { book: "4 Maccabees", chapter: 9, verse: 23, text: "μιμήσασθέ με ἀδελφοί λέγων μή μου τὸν ἀγῶνα λειποτακτήσητε μηδὲ ἐξομόσησθέ μου τὴν τῆς εὐψυχίας ἀδελφότητα" },
  { book: "4 Maccabees", chapter: 9, verse: 24, text: "ἱερὰν καὶ εὐγενῆ στρατείαν στρατεύσασθε περὶ τῆς εὐσεβείας δῑ ἧς ἵλεως ἡ δικαία καὶ πάτριος ἡμῶν πρόνοια τῷ ἔθνει γενηθεῖσα τιμωρήσειεν τὸν ἀλάστορα τύραννον" },
  { book: "4 Maccabees", chapter: 9, verse: 25, text: "καὶ ταῦτα εἰπὼν ὁ ἱεροπρεπὴς νεανίας ἀπέρρηξεν τὴν ψυχήν" },
  { book: "4 Maccabees", chapter: 9, verse: 26, text: "θαυμασάντων δὲ πάντων τὴν καρτεροψυχίαν αὐτοῦ ἦγον οἱ δορυφόροι τὸν καθ’ ἡλικίαν τοῦ προτέρου δεύτερον καὶ σιδηρᾶς ἐναρμοσάμενοι χεῖρας ὀξέσι τοῖς ὄνυξιν ὀργάνῳ καὶ καταπέλτῃ προσέδησαν αὐτόν" },
  { book: "4 Maccabees", chapter: 9, verse: 27, text: "ὡς δ’ εἰ φαγεῖν βούλοιτο πρὶν βασανίζεσθαι πυνθανόμενοι τὴν εὐγενῆ γνώμην ἤκουσαν" },
  { book: "4 Maccabees", chapter: 9, verse: 28, text: "ἀπὸ τῶν τενόντων ταῖς σιδηραῖς χερσὶν ἐπισπασάμενοι μέχρι τῶν γενείων τὴν σάρκα πᾶσαν καὶ τὴν τῆς κεφαλῆς δορὰν οἱ παρδάλεοι θῆρες ἀπέσυρον ὁ δὲ ταύτην βαρέως τὴν ἀλγηδόνα καρτερῶν ἔλεγεν" },
  { book: "4 Maccabees", chapter: 9, verse: 29, text: "ὡς ἡδὺς πᾶς θανάτου τρόπος διὰ τὴν πάτριον ἡμῶν εὐσέβειαν ἔφη τε πρὸς τὸν τύραννον" },
  { book: "4 Maccabees", chapter: 9, verse: 30, text: "οὐ δοκεῖς πάντων ὠμότατε τύραννε πλέον ἐμοῦ σε βασανίζεσθαι ὁρῶν σου νικώμενον τὸν τῆς τυραννίδος ὑπερήφανον λογισμὸν ὑπὸ τῆς διὰ τὴν εὐσέβειαν ἡμῶν ὑπομονῆς" },
  { book: "4 Maccabees", chapter: 9, verse: 31, text: "ἐγὼ μὲν γὰρ ταῖς διὰ τὴν ἀρετὴν ἡδοναῖς τὸν πόνον ἐπικουφίζομαι" },
  { book: "4 Maccabees", chapter: 9, verse: 32, text: "σὺ δὲ ἐν ταῖς τῆς ἀσεβείας ἀπειλαῖς βασανίζῃ οὐκ ἐκφεύξῃ δέ μιαρώτατε τύραννε τὰς τῆς θείας ὀργῆς δίκας" },
  { book: "4 Maccabees", chapter: 10, verse: 1, text: "καὶ τούτου τὸν ἀοίδιμον θάνατον καρτερήσαντος ὁ τρίτος ἤγετο παρακαλούμενος πολλὰ ὑπὸ πολλῶν ὅπως ἀπογευσάμενος σῴζοιτο" },
  { book: "4 Maccabees", chapter: 10, verse: 2, text: "ὁ δὲ ἀναβοήσας ἔφη ἀγνοεῖτε ὅτι αὑτός με τοῖς ἀποθανοῦσιν ἔσπειρεν πατήρ καὶ ἡ αὐτὴ μήτηρ ἐγέννησεν καὶ ἐπὶ τοῖς αὐτοῖς ἀνετράφην δόγμασιν" },
  { book: "4 Maccabees", chapter: 10, verse: 3, text: "οὐκ ἐξόμνυμαι τὴν εὐγενῆ τῆς ἀδελφότητος συγγένειαν" },
  { book: "4 Maccabees", chapter: 10, verse: 5, text: "οἱ δὲ πικρῶς ἐνέγκαντες τὴν παρρησίαν τοῦ ἀνδρὸς ἀρθρεμβόλοις ὀργάνοις τὰς χεῖρας αὐτοῦ καὶ τοὺς πόδας ἐξήρθρουν καὶ ἐξ ἁρμῶν ἀναμοχλεύοντες ἐξεμέλιζον" },
  { book: "4 Maccabees", chapter: 10, verse: 6, text: "τοὺς δακτύλους καὶ τοὺς βραχίονας καὶ τὰ σκέλη καὶ τοὺς ἀγκῶνας περιέκλων" },
  { book: "4 Maccabees", chapter: 10, verse: 7, text: "καὶ κατὰ μηδένα τρόπον ἰσχύοντες αὐτὸν ἄγξαι περιλύσαντες τὰ ὄργανα σὺν ἄκραις ταῖς τῶν δακτύλων κορυφαῖς ἀπεσκύθιζον" },
  { book: "4 Maccabees", chapter: 10, verse: 8, text: "καὶ εὐθέως ἦγον ἐπὶ τὸν τροχόν περὶ ὃν ἐκ σπονδύλων ἐκμελιζόμενος ἑώρα τὰς ἑαυτοῦ σάρκας περιλακιζομένας καὶ κατὰ σπλάγχνων σταγόνας αἵματος ἀπορρεούσας" },
  { book: "4 Maccabees", chapter: 10, verse: 9, text: "μέλλων δὲ ἀποθνῄσκειν ἔφη" },
  { book: "4 Maccabees", chapter: 10, verse: 10, text: "ἡμεῖς μέν ὦ μιαρώτατε τύραννε διὰ παιδείαν καὶ ἀρετὴν θεοῦ ταῦτα πάσχομεν" },
  { book: "4 Maccabees", chapter: 10, verse: 11, text: "σὺ δὲ διὰ τὴν ἀσέβειαν καὶ μιαιφονίαν ἀκαταλύτους καρτερήσεις βασάνους" },
  { book: "4 Maccabees", chapter: 10, verse: 12, text: "καὶ τούτου θανόντος ἀδελφοπρεπῶς τὸν τέταρτον ἐπεσπῶντο λέγοντες" },
  { book: "4 Maccabees", chapter: 10, verse: 13, text: "μὴ μανῇς καὶ σὺ τοῖς ἀδελφοῖς σου τὴν αὐτὴν μανίαν ἀλλὰ πεισθεὶς τῷ βασιλεῖ σῷζε σεαυτόν" },
  { book: "4 Maccabees", chapter: 10, verse: 14, text: "ὁ δὲ αὐτοῖς ἔφη οὐχ οὕτως καυστικώτερον ἔχετε κατ’ ἐμοῦ τὸ πῦρ ὥστε με δειλανδρῆσαι" },
  { book: "4 Maccabees", chapter: 10, verse: 15, text: "μὰ τὸν μακάριον τῶν ἀδελφῶν μου θάνατον καὶ τὸν αἰώνιον τοῦ τυράννου ὄλεθρον καὶ τὸν ἀΐδιον τῶν εὐσεβῶν βίον οὐκ ἀρνήσομαι τὴν εὐγενῆ ἀδελφότητα" },
  { book: "4 Maccabees", chapter: 10, verse: 16, text: "ἐπινόει τύραννε βασάνους ἵνα καὶ δῑ αὐτῶν μάθῃς ὅτι ἀδελφός εἰμι τῶν προβασανισθέντων" },
  { book: "4 Maccabees", chapter: 10, verse: 17, text: "ταῦτα ἀκούσας ὁ αἱμοβόρος καὶ φονώδης καὶ παμμιαρώτατος Ἀντίοχος ἐκέλευσεν τὴν γλῶτταν αὐτοῦ ἐκτεμεῖν" },
  { book: "4 Maccabees", chapter: 10, verse: 18, text: "ὁ δὲ ἔφη κἂν ἀφέλῃς τὸ τῆς φωνῆς ὄργανον καὶ σιωπώντων ἀκούει ὁ θεός" },
  { book: "4 Maccabees", chapter: 10, verse: 19, text: "ἰδοὺ προκεχάλασται ἡ γλῶσσα τέμνε οὐ γὰρ παρὰ τοῦτο τὸν λογισμὸν ἡμῶν γλωττοτομήσεις" },
  { book: "4 Maccabees", chapter: 10, verse: 20, text: "ἡδέως ὑπὲρ τοῦ θεοῦ τὰ τοῦ σώματος μέλη ἀκρωτηριαζόμεθα" },
  { book: "4 Maccabees", chapter: 10, verse: 21, text: "σὲ δὲ ταχέως μετελεύσεται ὁ θεός τὴν γὰρ τῶν θείων ὕμνων μελῳδὸν γλῶτταν ἐκτέμνεις" },
  { book: "4 Maccabees", chapter: 11, verse: 1, text: "ὡς δὲ καὶ οὗτος ταῖς βασάνοις καταικισθεὶς ἐναπέθανεν ὁ πέμπτος παρεπήδησεν λέγων" },
  { book: "4 Maccabees", chapter: 11, verse: 2, text: "οὐ μέλλω τύραννε πρὸς τὸν ὑπὲρ τῆς ἀρετῆς βασανισμὸν παραιτεῖσθαι" },
  { book: "4 Maccabees", chapter: 11, verse: 3, text: "αὐτὸς δ’ ἀπ’ ἐμαυτοῦ παρῆλθον ὅπως κἀμὲ κατακτείνας περὶ πλειόνων ἀδικημάτων ὀφειλήσῃς τῇ οὐρανίῳ δίκῃ τιμωρίαν" },
  { book: "4 Maccabees", chapter: 11, verse: 4, text: "ὦ μισάρετε καὶ μισάνθρωπε τί δράσαντας ἡμᾶς τοῦτον πορθεῖς τὸν τρόπον" },
  { book: "4 Maccabees", chapter: 11, verse: 5, text: "ὅτι τὸν πάντων κτίστην εὐσεβοῦμεν καὶ κατὰ τὸν ἐνάρετον αὐτοῦ ζῶμεν νόμον" },
  { book: "4 Maccabees", chapter: 11, verse: 6, text: "ἀλλὰ ταῦτα τιμῶν οὐ βασάνων ἐστὶν ἄξια" },
  { book: "4 Maccabees", chapter: 11, verse: 9, text: "τοιαῦτα δὲ λέγοντα οἱ δορυφόροι δήσαντες αὐτὸν εἷλκον ἐπὶ τὸν καταπέλτην" },
  { book: "4 Maccabees", chapter: 11, verse: 10, text: "ἐφ’ ὃν δήσαντες αὐτὸν ἐπὶ τὰ γόνατα καὶ ταῦτα ποδάγραις σιδηραῖς ἐφαρμόσαντες τὴν ὀσφὺν αὐτοῦ περὶ τροχιαῖον σφῆνα κατέκαμψαν περὶ ὃν ὅλος περὶ τὸν τροχὸν σκορπίου τρόπον ἀνακλώμενος ἐξεμελίζετο" },
  { book: "4 Maccabees", chapter: 11, verse: 11, text: "κατὰ τοῦτον τὸν τρόπον καὶ τὸ πνεῦμα στενοχωρούμενος καὶ τὸ σῶμα ἀγχόμενος" },
  { book: "4 Maccabees", chapter: 11, verse: 12, text: "καλάς ἔλεγεν ἄκων ὦ τύραννε χάριτας ἡμῖν χαρίζῃ διὰ γενναιοτέρων πόνων ἐπιδείξασθαι παρέχων τὴν εἰς τὸν νόμον ἡμῶν καρτερίαν" },
  { book: "4 Maccabees", chapter: 11, verse: 13, text: "τελευτήσαντος δὲ καὶ τούτου ὁ ἕκτος ἤγετο μειρακίσκος ὃς πυνθανομένου τοῦ τυράννου εἰ βούλοιτο φαγὼν ἀπολύεσθαι ὁ δὲ ἔφη" },
  { book: "4 Maccabees", chapter: 11, verse: 14, text: "ἐγὼ τῇ μὲν ἡλικίᾳ τῶν ἀδελφῶν μού εἰμι νεώτερος τῇ δὲ διανοίᾳ ἡλικιώτης" },
  { book: "4 Maccabees", chapter: 11, verse: 15, text: "εἰς ταὐτὰ γὰρ γεννηθέντες καὶ ἀνατραφέντες ὑπὲρ τῶν αὐτῶν καὶ ἀποθνῄσκειν ὀφείλομεν ὁμοίως" },
  { book: "4 Maccabees", chapter: 11, verse: 16, text: "ὥστε εἴ σοι δοκεῖ βασανίζειν μὴ μιαροφαγοῦντα βασάνιζε" },
  { book: "4 Maccabees", chapter: 11, verse: 17, text: "ταῦτα αὐτὸν εἰπόντα παρῆγον ἐπὶ τὸν τροχόν" },
  { book: "4 Maccabees", chapter: 11, verse: 18, text: "ἐφ’ οὗ κατατεινόμενος ἐπιμελῶς καὶ ἐκσπονδυλιζόμενος ὑπεκαίετο" },
  { book: "4 Maccabees", chapter: 11, verse: 19, text: "καὶ ὀβελίσκους ὀξεῖς πυρώσαντες τοῖς νώτοις προσέφερον καὶ τὰ πλευρὰ διαπείραντες αὐτοῦ τὰ σπλάγχνα διέκαιον" },
  { book: "4 Maccabees", chapter: 11, verse: 20, text: "ὁ δὲ βασανιζόμενος ὦ ἱεροπρεποῦς ἀγῶνος ἔλεγεν ἐφ’ ὃν διὰ τὴν εὐσέβειαν εἰς γυμνασίαν πόνων ἀδελφοὶ τοσοῦτοι κληθέντες οὐκ ἐνικήθημεν" },
  { book: "4 Maccabees", chapter: 11, verse: 21, text: "ἀνίκητος γάρ ἐστιν ὦ τύραννε ἡ εὐσεβὴς ἐπιστήμη" },
  { book: "4 Maccabees", chapter: 11, verse: 22, text: "καλοκἀγαθίᾳ καθωπλισμένος τεθνήξομαι κἀγὼ μετὰ τῶν ἀδελφῶν μου" },
  { book: "4 Maccabees", chapter: 11, verse: 23, text: "μέγαν σοὶ καὶ αὐτὸς προσβάλλων ἀλάστορα καινουργὲ τῶν βασάνων καὶ πολέμιε τῶν ἀληθῶς εὐσεβούντων" },
  { book: "4 Maccabees", chapter: 11, verse: 24, text: "ἓξ μειράκια καταλελύκαμέν σου τὴν τυραννίδα" },
  { book: "4 Maccabees", chapter: 11, verse: 25, text: "τὸ γὰρ μὴ δυνηθῆναί σε μεταπεῖσαι τὸν λογισμὸν ἡμῶν μήτε βιάσασθαι πρὸς τὴν μιαροφαγίαν οὐ κατάλυσίς ἐστίν σου" },
  { book: "4 Maccabees", chapter: 11, verse: 26, text: "τὸ πῦρ σου ψυχρὸν ἡμῖν καὶ ἄπονοι οἱ καταπέλται καὶ ἀδύνατος ἡ βία σου" },
  { book: "4 Maccabees", chapter: 11, verse: 27, text: "οὐ γὰρ τυράννου ἀλλὰ θείου νόμου προεστήκασιν ἡμῶν οἱ δορυφόροι διὰ τοῦτο ἀνίκητον ἔχομεν τὸν λογισμόν" },
  { book: "4 Maccabees", chapter: 12, verse: 1, text: "ὡς δὲ καὶ οὗτος μακαρίως ἀπέθανεν καταβληθεὶς εἰς λέβητα ὁ ἕβδομος παρεγίνετο πάντων νεώτερος" },
  { book: "4 Maccabees", chapter: 12, verse: 2, text: "ὃν κατοικτίρας ὁ τύραννος καίπερ δεινῶς ὑπὸ τῶν ἀδελφῶν αὐτοῦ κακισθείς ὁρῶν ἤδη τὰ δεσμὰ περικείμενα πλησιέστερον αὐτὸν μετεπέμψατο καὶ παρηγορεῖν ἐπειρᾶτο λέγων" },
  { book: "4 Maccabees", chapter: 12, verse: 3, text: "τῆς μὲν τῶν ἀδελφῶν σου ἀπονοίας τὸ τέλος ὁρᾷς διὰ γὰρ ἀπείθειαν στρεβλωθέντες τεθνᾶσιν" },
  { book: "4 Maccabees", chapter: 12, verse: 4, text: "σὺ δὲ εἰ μὲν μὴ πεισθείης τάλας βασανισθεὶς καὶ αὐτὸς τεθνήξῃ πρὸ ὥρας" },
  { book: "4 Maccabees", chapter: 12, verse: 5, text: "πεισθεὶς δὲ φίλος ἔσῃ καὶ τῶν ἐπὶ τῆς βασιλείας ἀφηγήσῃ πραγμάτων" },
  { book: "4 Maccabees", chapter: 12, verse: 6, text: "καὶ ταῦτα παρακαλῶν τὴν μητέρα τοῦ παιδὸς μετεπέμψατο ὅπως αὐτὴν ἐλεήσας τοσούτων υἱῶν στερηθεῖσαν παρορμήσειεν ἐπὶ τὴν σωτήριον εὐπείθειαν τὸν περιλειπόμενον" },
  { book: "4 Maccabees", chapter: 12, verse: 7, text: "ὁ δὲ τῆς μητρὸς τῇ Εβραΐδι φωνῇ προτρεψαμένης αὐτόν ὡς ἐροῦμεν μετὰ μικρὸν ὕστερον" },
  { book: "4 Maccabees", chapter: 12, verse: 8, text: "λύσατέ μέ φησιν εἴπω τῷ βασιλεῖ καὶ τοῖς σὺν αὐτῷ φίλοις πᾶσιν" },
  { book: "4 Maccabees", chapter: 12, verse: 9, text: "καὶ ἐπιχαρέντες μάλιστα ἐπὶ τῇ ἐπαγγελίᾳ τοῦ παιδὸς ταχέως ἔλυσαν αὐτόν" },
  { book: "4 Maccabees", chapter: 12, verse: 10, text: "καὶ δραμὼν ἐπὶ πλησίον τῶν τηγάνων" },
  { book: "4 Maccabees", chapter: 12, verse: 11, text: "ἀνόσιέ φησιν καὶ πάντων πονηρῶν ἀσεβέστατε τύραννε οὐκ ᾐδέσθης παρὰ τοῦ θεοῦ λαβὼν τὰ ἀγαθὰ καὶ τὴν βασιλείαν τοὺς θεράποντας αὐτοῦ κατακτεῖναι καὶ τοὺς τῆς εὐσεβείας ἀσκητὰς στρεβλῶσαι" },
  { book: "4 Maccabees", chapter: 12, verse: 12, text: "ἀνθ’ ὧν ταμιεύσεταί σε ἡ δίκη πυκνοτέρῳ καὶ αἰωνίῳ πυρὶ καὶ βασάνοις αἳ εἰς ὅλον τὸν αἰῶνα οὐκ ἀνήσουσίν σε" },
  { book: "4 Maccabees", chapter: 12, verse: 13, text: "οὐκ ᾐδέσθης ἄνθρωπος ὤν θηριωδέστατε τοὺς ὁμοιοπαθεῖς καὶ ἐκ τῶν αὐτῶν γεγονότας στοιχείων γλωττοτομῆσαι καὶ τοῦτον καταικίσας τὸν τρόπον βασανίσαι" },
  { book: "4 Maccabees", chapter: 12, verse: 14, text: "ἀλλ’ οἱ μὲν εὐγενῶς ἀποθανόντες ἐπλήρωσαν τὴν εἰς τὸν θεὸν εὐσέβειαν σὺ δὲ κακῶς οἰμώξεις τοὺς τῆς ἀρετῆς ἀγωνιστὰς ἀναιτίως ἀποκτεῖνας" },
  { book: "4 Maccabees", chapter: 12, verse: 15, text: "ὅθεν καὶ αὐτὸς ἀποθνῄσκειν μέλλων ἔφη" },
  { book: "4 Maccabees", chapter: 12, verse: 16, text: "οὐκ ἀπαυτομολῶ τῆς τῶν ἀδελφῶν μου ἀριστείας" },
  { book: "4 Maccabees", chapter: 12, verse: 17, text: "ἐπικαλοῦμαι δὲ τὸν πατρῷον θεὸν ὅπως ἵλεως γένηται τῷ ἔθνει ἡμῶν" },
  { book: "4 Maccabees", chapter: 12, verse: 18, text: "σὲ δὲ καὶ ἐν τῷ νῦν βίῳ καὶ θανόντα τιμωρήσεται" },
  { book: "4 Maccabees", chapter: 12, verse: 19, text: "καὶ ταῦτα κατευξάμενος ἑαυτὸν ἔρριψε κατὰ τῶν τηγάνων καὶ οὕτως ἀπέδωκεν" },
  { book: "4 Maccabees", chapter: 13, verse: 1, text: "εἰ δὲ τοίνυν τῶν μέχρι θανάτου πόνων ὑπερεφρόνησαν οἱ ἑπτὰ ἀδελφοί συνομολογεῖται πανταχόθεν ὅτι αὐτοδέσποτός ἐστιν τῶν παθῶν ὁ εὐσεβὴς λογισμός" },
  { book: "4 Maccabees", chapter: 13, verse: 2, text: "εἰ γὰρ τοῖς πάθεσι δουλωθέντες ἐμιαροφάγησαν ἐλέγομεν ἂν τούτοις αὐτοὺς νενικῆσθαι" },
  { book: "4 Maccabees", chapter: 13, verse: 3, text: "νυνὶ δὲ οὐχ οὕτως ἀλλὰ τῷ ἐπαινουμένῳ παρὰ θεῷ λογισμῷ περιεγένοντο τῶν παθῶν" },
  { book: "4 Maccabees", chapter: 13, verse: 4, text: "ὧν οὐκ ἔστιν παριδεῖν τὴν ἡγεμονίαν τῆς διανοίας ἐπεκράτησαν γὰρ καὶ πάθους καὶ πόνων" },
  { book: "4 Maccabees", chapter: 13, verse: 5, text: "πῶς οὖν οὐκ ἔστιν τούτοις τὴν τῆς εὐλογιστίας παθοκράτειαν ὁμολογεῖν οἳ τῶν μὲν διὰ πυρὸς ἀλγηδόνων οὐκ ἐπεστράφησαν" },
  { book: "4 Maccabees", chapter: 13, verse: 6, text: "καθάπερ γὰρ προβλῆτες λιμένων πύργοι τὰς τῶν κυμάτων ἀπειλὰς ἀνακόπτοντες γαληνὸν παρέχουσι τοῖς εἰσπλέουσι τὸν ὅρμον" },
  { book: "4 Maccabees", chapter: 13, verse: 7, text: "οὕτως ἡ ἑπτάπυργος τῶν νεανίσκων εὐλογιστία τὸν τῆς εὐσεβείας ὀχυρώσασα λιμένα τὴν τῶν παθῶν ἐνίκησεν ἀκολασίαν" },
  { book: "4 Maccabees", chapter: 13, verse: 8, text: "ἱερὸν γὰρ εὐσεβείας στήσαντες χορὸν παρεθάρσυνον ἀλλήλους λέγοντες" },
  { book: "4 Maccabees", chapter: 13, verse: 9, text: "ἀδελφικῶς ἀποθάνωμεν ἀδελφοί περὶ τοῦ νόμου μιμησώμεθα τοὺς τρεῖς τοὺς ἐπὶ τῆς Ἀσσυρίας νεανίσκους οἳ τῆς ἰσοπολίτιδος καμίνου κατεφρόνησαν" },
  { book: "4 Maccabees", chapter: 13, verse: 10, text: "μὴ δειλανδρήσωμεν πρὸς τὴν τῆς εὐσεβείας ἐπίδειξιν" },
  { book: "4 Maccabees", chapter: 13, verse: 11, text: "καὶ ὁ μέν θάρρει ἀδελφέ ἔλεγεν ὁ δέ εὐγενῶς καρτέρησον" },
  { book: "4 Maccabees", chapter: 13, verse: 12, text: "ὁ δὲ καταμνησθεὶς ἔλεγεν μνήσθητε πόθεν ἐστέ ἢ τίνος πατρὸς χειρὶ σφαγιασθῆναι διὰ τὴν εὐσέβειαν ὑπέμεινεν Ισαακ" },
  { book: "4 Maccabees", chapter: 13, verse: 13, text: "εἷς δὲ ἕκαστος ἀλλήλους ὁμοῦ πάντες ἐφορῶντες φαιδροὶ καὶ μάλα θαρραλέοι ἑαυτούς ἔλεγον τῷ θεῷ ἀφιερώσωμεν ἐξ ὅλης τῆς καρδίας τῷ δόντι τὰς ψυχὰς καὶ χρήσωμεν τῇ περὶ τὸν νόμον φυλακῇ τὰ σώματα" },
  { book: "4 Maccabees", chapter: 13, verse: 14, text: "μὴ φοβηθῶμεν τὸν δοκοῦντα ἀποκτέννειν" },
  { book: "4 Maccabees", chapter: 13, verse: 15, text: "μέγας γὰρ ψυχῆς ἀγὼν καὶ κίνδυνος ἐν αἰωνίῳ βασάνῳ κείμενος τοῖς παραβᾶσι τὴν ἐντολὴν τοῦ θεοῦ" },
  { book: "4 Maccabees", chapter: 13, verse: 16, text: "καθοπλισώμεθα τοιγαροῦν τὴν τοῦ θείου λογισμοῦ παθοκρατείαν" },
  { book: "4 Maccabees", chapter: 13, verse: 17, text: "οὕτω γὰρ θανόντας ἡμᾶς Αβρααμ καὶ Ισαακ καὶ Ιακωβ ὑποδέξονται καὶ πάντες οἱ πατέρες ἐπαινέσουσιν" },
  { book: "4 Maccabees", chapter: 13, verse: 18, text: "καὶ ἑνὶ ἑκάστῳ τῶν ἀποσπωμένων αὐτῶν ἀδελφῶν ἔλεγον οἱ περιλειπόμενοι μὴ καταισχύνῃς ἡμᾶς ἀδελφέ μηδὲ ψεύσῃ τοὺς προαποθανόντας ἡμῶν ἀδελφούς" },
  { book: "4 Maccabees", chapter: 13, verse: 19, text: "οὐκ ἀγνοεῖτε δὲ τὰ τῆς ἀδελφότητος φίλτρα ἅπερ ἡ θεία καὶ πάνσοφος πρόνοια διὰ πατέρων τοῖς γεννωμένοις ἐμέρισεν καὶ διὰ τῆς μητρῴας φυτεύσασα γαστρός" },
  { book: "4 Maccabees", chapter: 13, verse: 20, text: "ἐν ᾗ τὸν ἴσον ἀδελφοὶ κατοικήσαντες χρόνον καὶ ἐν τῷ αὐτῷ χρόνῳ πλασθέντες καὶ ἀπὸ τοῦ αὐτοῦ αἵματος αὐξηθέντες καὶ διὰ τῆς αὐτῆς ψυχῆς τελεσφορηθέντες" },
  { book: "4 Maccabees", chapter: 13, verse: 21, text: "καὶ διὰ τῶν ἴσων ἀποτεχθέντες χρόνων καὶ ἀπὸ τῶν αὐτῶν γαλακτοποτοῦντες πηγῶν ἀφ’ ὧν συντρέφονται ἐναγκαλισμάτων φιλάδελφοι ψυχαί" },
  { book: "4 Maccabees", chapter: 13, verse: 22, text: "καὶ αὔξονται σφοδρότερον διὰ συντροφίας καὶ τῆς καθ’ ἡμέραν συνηθείας καὶ τῆς ἄλλης παιδείας καὶ τῆς ἡμετέρας ἐν νόμῳ θεοῦ ἀσκήσεως" },
  { book: "4 Maccabees", chapter: 13, verse: 23, text: "οὕτως δὴ τοίνυν καθεστηκυίης συμπαθοῦς τῆς φιλαδελφίας οἱ ἑπτὰ ἀδελφοὶ συμπαθέστερον ἔσχον πρὸς ἀλλήλους" },
  { book: "4 Maccabees", chapter: 13, verse: 24, text: "νόμῳ γὰρ τῷ αὐτῷ παιδευθέντες καὶ τὰς αὐτὰς ἐξασκήσαντες ἀρετὰς καὶ τῷ δικαίῳ συντραφέντες βίῳ μᾶλλον ἑαυτοὺς ἠγάπων" },
  { book: "4 Maccabees", chapter: 13, verse: 25, text: "ἡ γὰρ ὁμοζηλία τῆς καλοκἀγαθίας ἐπέτεινεν αὐτῶν τὴν πρὸς ἀλλήλους εὔνοιαν καὶ ὁμόνοιαν" },
  { book: "4 Maccabees", chapter: 13, verse: 26, text: "σὺν γὰρ τῇ εὐσεβείᾳ ποθεινοτέραν αὑτοῖς κατεσκεύαζον τὴν φιλαδελφίαν" },
  { book: "4 Maccabees", chapter: 13, verse: 27, text: "ἀλλ’ ὅμως καίπερ τῆς φύσεως καὶ τῆς συνηθείας καὶ τῶν τῆς ἀρετῆς ἠθῶν τὰ τῆς ἀδελφότητος αὐτοῖς φίλτρα συναυξόντων ἀνέσχοντο διὰ τὴν εὐσέβειαν τοὺς ἀδελφοὺς οἱ ὑπολειπόμενοι τοὺς καταικιζομένους ὁρῶντες μέχρι θανάτου βασανιζομένους" },
  { book: "4 Maccabees", chapter: 14, verse: 1, text: "προσέτι καὶ ἐπὶ τὸν αἰκισμὸν ἐποτρύνοντες ὡς μὴ μόνον τῶν ἀλγηδόνων περιφρονῆσαι αὐτούς ἀλλὰ καὶ τῶν τῆς φιλαδελφίας παθῶν κρατῆσαι" },
  { book: "4 Maccabees", chapter: 14, verse: 2, text: "ὦ βασιλέων λογισμοὶ βασιλικώτεροι καὶ ἐλευθέρων ἐλευθερώτεροι" },
  { book: "4 Maccabees", chapter: 14, verse: 3, text: "ὦ ἱερᾶς καὶ εὐαρμόστου περὶ τῆς εὐσεβείας τῶν ἑπτὰ ἀδελφῶν συμφωνίας" },
  { book: "4 Maccabees", chapter: 14, verse: 4, text: "οὐδεῖς ἐκ τῶν ἑπτὰ μειρακίων ἐδειλίασεν οὐδὲ πρὸς τὸν θάνατον ὤκνησεν" },
  { book: "4 Maccabees", chapter: 14, verse: 5, text: "ἀλλὰ πάντες ὥσπερ ἐπ’ ἀθανασίας ὁδὸν τρέχοντες ἐπὶ τὸν διὰ τῶν βασάνων θάνατον ἔσπευδον" },
  { book: "4 Maccabees", chapter: 14, verse: 6, text: "καθάπερ αἱ χεῖρες καὶ οἱ πόδες συμφώνως τοῖς τῆς ψυχῆς ἀφηγήμασιν κινοῦνται οὕτως οἱ ἱεροὶ μείρακες ἐκεῖνοι ὡς ὑπὸ ψυχῆς ἀθανάτου τῆς εὐσεβείας πρὸς τὸν ὑπὲρ αὐτῆς συνεφώνησαν θάνατον" },
  { book: "4 Maccabees", chapter: 14, verse: 7, text: "ὦ πανάγιε συμφώνων ἀδελφῶν ἑβδομάς καθάπερ γὰρ ἑπτὰ τῆς κοσμοποιίας ἡμέραι περὶ τὴν εὐσέβειαν" },
  { book: "4 Maccabees", chapter: 14, verse: 8, text: "οὕτως περὶ τὴν ἑβδομάδα χορεύοντες οἱ μείρακες ἐκύκλουν τὸν τῶν βασάνων φόβον καταλύοντες" },
  { book: "4 Maccabees", chapter: 14, verse: 9, text: "νῦν ἡμεῖς ἀκούοντες τὴν θλῖψιν τῶν νεανιῶν ἐκείνων φρίττομεν οἱ δὲ οὐ μόνον ὁρῶντες ἀλλ’ οὐδὲ μόνον ἀκούοντες τὸν παραχρῆμα ἀπειλῆς λόγον ἀλλὰ καὶ πάσχοντες ἐνεκαρτέρουν καὶ τοῦτο ταῖς διὰ πυρὸς ὀδύναις" },
  { book: "4 Maccabees", chapter: 14, verse: 10, text: "ὧν τί γένοιτο ἐπαλγέστερον ὀξεῖα γὰρ καὶ σύντομος οὖσα ἡ τοῦ πυρὸς δύναμις ταχέως διέλυεν τὰ σώματα" },
  { book: "4 Maccabees", chapter: 14, verse: 11, text: "καὶ μὴ θαυμαστὸν ἡγεῖσθε εἰ ὁ λογισμὸς περιεκράτησε τῶν ἀνδρῶν ἐκείνων ἐν ταῖς βασάνοις ὅπου γε καὶ γυναικὸς νοῦς πολυτροπωτέρων ὑπερεφρόνησεν ἀλγηδόνων" },
  { book: "4 Maccabees", chapter: 14, verse: 12, text: "ἡ μήτηρ γὰρ τῶν ἑπτὰ νεανίσκων ὑπήνεγκεν τὰς ἐφ’ ἑνὶ ἑκάστῳ τῶν τέκνων στρέβλας" },
  { book: "4 Maccabees", chapter: 14, verse: 13, text: "θεωρεῖτε δὲ πῶς πολύπλοκός ἐστιν ἡ τῆς φιλοτεκνίας στοργὴ ἕλκουσα πάντα πρὸς τὴν τῶν σπλάγχνων συμπάθειαν" },
  { book: "4 Maccabees", chapter: 14, verse: 14, text: "ὅπου γε καὶ τὰ ἄλογα ζῷα ὁμοίαν τὴν εἰς τὰ ἐξ αὐτῶν γεννώμενα συμπάθειαν καὶ στοργὴν ἔχει τοῖς ἀνθρώποις" },
  { book: "4 Maccabees", chapter: 14, verse: 15, text: "καὶ γὰρ τῶν πετεινῶν τὰ μὲν ἥμερα κατὰ τὰς οἰκίας ὀροφοιτοῦντα προασπίζει τῶν νεοττῶν" },
  { book: "4 Maccabees", chapter: 14, verse: 16, text: "τὰ δὲ κατὰ κορυφὰς ὀρέων καὶ φαράγγων ἀπορρῶγας καὶ δένδρων ὀπὰς καὶ τὰς τούτων ἄκρας ἐννοσσοποιησάμενα ἀποτίκτει καὶ τὸν προσιόντα κωλύει" },
  { book: "4 Maccabees", chapter: 14, verse: 17, text: "εἰ δὲ καὶ μὴ δύναιντο κωλύειν περιιπτάμενα κυκλόθεν αὐτῶν ἀλγοῦντα τῇ στοργῇ ἀνακαλούμενα τῇ ἰδίᾳ φωνῇ καθ’ ὃ δύναται βοηθεῖ τοῖς τέκνοις" },
  { book: "4 Maccabees", chapter: 14, verse: 18, text: "καὶ τί δεῖ τὴν διὰ τῶν ἀλόγων ζῴων ἐπιδεικνύναι πρὸς τὰ τέκνα συμπάθειαν" },
  { book: "4 Maccabees", chapter: 14, verse: 19, text: "ὅπου γε καὶ μέλισσαι περὶ τὸν τῆς κηρογονίας καιρὸν ἐπαμύνονται τοὺς προσιόντας καὶ καθάπερ σιδήρῳ τῷ κέντρῳ πλήσσουσι τοὺς προσιόντας τῇ νοσσιᾷ αὐτῶν καὶ ἀπαμύνουσιν ἕως θανάτου" },
  { book: "4 Maccabees", chapter: 14, verse: 20, text: "ἀλλ’ οὐχὶ τὴν Αβρααμ ὁμόψυχον τῶν νεανίσκων μητέρα μετεκίνησεν συμπάθεια τέκνων" },
  { book: "4 Maccabees", chapter: 15, verse: 1, text: "ὦ λογισμὲ τέκνων παθῶν τύραννε καὶ εὐσέβεια μητρὶ τέκνων ποθεινοτέρα" },
  { book: "4 Maccabees", chapter: 15, verse: 2, text: "μήτηρ δυεῖν προκειμένων εὐσεβείας καὶ τῆς ἑπτὰ υἱῶν σωτηρίας προσκαίρου κατὰ τὴν τοῦ τυράννου ὑπόσχεσιν" },
  { book: "4 Maccabees", chapter: 15, verse: 3, text: "τὴν εὐσέβειαν μᾶλλον ἠγάπησεν τὴν σῴζουσαν εἰς αἰωνίαν ζωὴν κατὰ θεόν" },
  { book: "4 Maccabees", chapter: 15, verse: 4, text: "ὦ τίνα τρόπον ἠθολογήσαιμι φιλότεκνα γονέων πάθη ψυχῆς τε καὶ μορφῆς ὁμοιότητα εἰς μικρὸν παιδὸς χαρακτῆρα θαυμάσιον ἐναποσφραγίζομεν μάλιστα διὰ τὸ τῶν παθῶν τοῖς γεννηθεῖσιν τὰς μητέρας τῶν πατέρων καθεστάναι συμπαθεστέρας" },
  { book: "4 Maccabees", chapter: 15, verse: 5, text: "ὅσῳ γὰρ καὶ ἀσθενόψυχοι καὶ πολυγονώτεραι ὑπάρχουσιν αἱ μητέρες τοσούτῳ μᾶλλόν εἰσιν φιλοτεκνότεραι" },
  { book: "4 Maccabees", chapter: 15, verse: 6, text: "πασῶν δὲ τῶν μητέρων ἐγένετο ἡ τῶν ἑπτὰ παίδων μήτηρ φιλοτεκνοτέρα ἥτις ἑπτὰ κυοφορίαις τὴν πρὸς αὐτοὺς ἐπιφυτευομένη φιλοστοργίαν" },
  { book: "4 Maccabees", chapter: 15, verse: 7, text: "καὶ διὰ πολλὰς τὰς καθ’ ἕκαστον αὐτῶν ὠδῖνας ἠναγκασμένη τὴν εἰς αὐτοὺς ἔχειν συμπάθειαν" },
  { book: "4 Maccabees", chapter: 15, verse: 8, text: "διὰ τὸν πρὸς τὸν θεὸν φόβον ὑπερεῖδεν τὴν τῶν τέκνων πρόσκαιρον σωτηρίαν" },
  { book: "4 Maccabees", chapter: 15, verse: 9, text: "οὐ μὴν δὲ ἀλλὰ καὶ διὰ τὴν καλοκἀγαθίαν τῶν υἱῶν καὶ τὴν πρὸς τὸν νόμον αὐτῶν εὐπείθειαν μείζω τὴν ἐν αὐτοῖς ἔσχεν φιλοστοργίαν" },
  { book: "4 Maccabees", chapter: 15, verse: 10, text: "δίκαιοί τε γὰρ ἦσαν καὶ σώφρονες καὶ ἀνδρεῖοι καὶ μεγαλόψυχοι καὶ φιλάδελφοι καὶ φιλομήτορες οὕτως ὥστε καὶ μέχρι θανάτου τὰ νόμιμα φυλάσσοντας πείθεσθαι αὐτῇ" },
  { book: "4 Maccabees", chapter: 15, verse: 11, text: "ἀλλ’ ὅμως καίπερ τοσούτων ὄντων τῶν περὶ τὴν φιλοτεκνίαν εἰς συμπάθειαν ἑλκόντων τὴν μητέρα ἐπ’ οὐδενὸς αὐτῶν τὸν λογισμὸν αὐτῆς αἱ παμποίκιλοι βάσανοι ἴσχυσαν μετατρέψαι" },
  { book: "4 Maccabees", chapter: 15, verse: 12, text: "ἀλλὰ καὶ καθ’ ἕνα παῖδα καὶ ὁμοῦ πάντας ἡ μήτηρ ἐπὶ τὸν τῆς εὐσεβείας προετρέπετο θάνατον" },
  { book: "4 Maccabees", chapter: 15, verse: 13, text: "ὦ φύσις ἱερὰ καὶ φίλτρα γονέων καὶ γένεσι φιλόστοργε καὶ τροφεία καὶ μητέρων ἀδάμαστα πάθη" },
  { book: "4 Maccabees", chapter: 15, verse: 14, text: "καθένα στρεβλούμενον καὶ φλεγόμενον ὁρῶσα μήτηρ οὐ μετεβάλλετο διὰ τὴν εὐσέβειαν" },
  { book: "4 Maccabees", chapter: 15, verse: 15, text: "τὰς σάρκας τῶν τέκνων ἑώρα περὶ τὸ πῦρ τηκομένας καὶ τοὺς τῶν ποδῶν καὶ χειρῶν δακτύλους ἐπὶ γῆς σπαίροντας καὶ τὰς τῶν κεφαλῶν μέχρι τῶν περὶ τὰ γένεια σάρκας ὥσπερ προσωπεῖα προκειμένας" },
  { book: "4 Maccabees", chapter: 15, verse: 16, text: "ὦ πικροτέρων νῦν πόνων πειρασθεῖσα μήτηρ ἤπερ τῶν ἐπ’ αὐτοῖς ὠδίνων" },
  { book: "4 Maccabees", chapter: 15, verse: 17, text: "ὦ μόνη γύναι τὴν εὐσέβειαν ὁλόκληρον ἀποκυήσασα" },
  { book: "4 Maccabees", chapter: 15, verse: 18, text: "οὐ μετέτρεψέν σε πρωτοτόκος ἀποπνέων οὐδὲ δεύτερος εἰς σὲ οἰκτρὸν βλέπων ἐν βασάνοις οὐ τρίτος ἀποψύχων" },
  { book: "4 Maccabees", chapter: 15, verse: 19, text: "οὐδὲ τοὺς ὀφθαλμοὺς ἑνὸς ἑκάστου θεωροῦσα ταυρηδὸν ἐπὶ τῶν βασάνων ὁρῶντας τὸν αὐτὸν αἰκισμὸν καὶ τοὺς μυκτῆρας προσημειουμένους τὸν θάνατον αὐτῶν οὐκ ἔκλαυσας" },
  { book: "4 Maccabees", chapter: 15, verse: 20, text: "ἐπὶ σαρξὶν τέκνων ὁρῶσα σάρκας τέκνων ἀποκαιομένας καὶ ἐπὶ χερσὶν χεῖρας ἀποτεμνομένας καὶ ἐπὶ κεφαλαῖς κεφαλὰς ἀποδειροτομουμένας καὶ ἐπὶ νεκροῖς νεκροὺς πίπτοντας καὶ πολυάνδριον ὁρῶσα τῶν τέκνων τὸ χωρίον διὰ τῶν βασάνων οὐκ ἐδάκρυσας" },
  { book: "4 Maccabees", chapter: 15, verse: 21, text: "οὐχ οὕτως σειρήνιοι μελῳδίαι οὐδὲ κύκνειοι πρὸς φιληκοΐαν φωναὶ τοὺς ἀκούοντας ἐφέλκονται ὡς τέκνων φωναὶ μετὰ βασάνων μητέρα φωνούντων" },
  { book: "4 Maccabees", chapter: 15, verse: 22, text: "πηλίκαις καὶ πόσαις τότε ἡ μήτηρ τῶν υἱῶν βασανιζομένων τροχοῖς τε καὶ καυτηρίοις ἐβασανίζετο βασάνοις" },
  { book: "4 Maccabees", chapter: 15, verse: 23, text: "ἀλλὰ τὰ σπλάγχνα αὐτῆς ὁ εὐσεβὴς λογισμὸς ἐν αὐτοῖς τοῖς πάθεσιν ἀνδρειώσας ἐπέτεινεν τὴν πρόσκαιρον φιλοτεκνίαν παριδεῖν" },
  { book: "4 Maccabees", chapter: 15, verse: 24, text: "καίπερ ἑπτὰ τέκνων ὁρῶσα ἀπώλειαν καὶ τὴν τῶν στρεβλῶν πολύπλοκον ποικιλίαν ἁπάσας ἡ γενναία μήτηρ ἐξέλυσεν διὰ τὴν πρὸς θεὸν πίστιν" },
  { book: "4 Maccabees", chapter: 15, verse: 25, text: "καθάπερ γὰρ ἐν βουλευτηρίῳ τῇ ἑαυτῆς ψυχῇ δεινοὺς ὁρῶσα συμβούλους φύσιν καὶ γένεσιν καὶ φιλοτεκνίαν καὶ τέκνων στρέβλας" },
  { book: "4 Maccabees", chapter: 15, verse: 26, text: "δύο ψήφους κρατοῦσα μήτηρ θανατηφόρον τε καὶ σωτήριον ὑπὲρ τέκνων" },
  { book: "4 Maccabees", chapter: 15, verse: 27, text: "οὐκ ἐπέγνω τὴν σῴζουσαν ἑπτὰ υἱοὺς πρὸς ὀλίγον χρόνον σωτηρίαν" },
  { book: "4 Maccabees", chapter: 15, verse: 28, text: "ἀλλὰ τῆς θεοσεβοῦς Αβρααμ καρτερίας ἡ θυγάτηρ ἐμνήσθη" },
  { book: "4 Maccabees", chapter: 15, verse: 29, text: "ὦ μήτηρ ἔθνους ἔκδικε τοῦ νόμου καὶ ὑπερασπίστρια τῆς εὐσεβείας καὶ τοῦ διὰ σπλάγχνων ἀγῶνος ἀθλοφόρε" },
  { book: "4 Maccabees", chapter: 15, verse: 30, text: "ὦ ἀρρένων πρὸς καρτερίαν γενναιοτέρα καὶ ἀνδρῶν πρὸς ὑπομονὴν ἀνδρειοτέρα" },
  { book: "4 Maccabees", chapter: 15, verse: 31, text: "καθάπερ γὰρ ἡ Νωε κιβωτὸς ἐν τῷ κοσμοπληθεῖ κατακλυσμῷ κοσμοφοροῦσα καρτερῶς ὑπέμεινεν τοὺς κλύδωνας" },
  { book: "4 Maccabees", chapter: 15, verse: 32, text: "οὕτως σὺ ἡ νομοφύλαξ πανταχόθεν ἐν τῷ τῶν παθῶν περιαντλουμένη κατακλυσμῷ καὶ καρτεροῖς ἀνέμοις ταῖς τῶν υἱῶν βασάνοις συνεχομένη γενναίως ὑπέμεινας τοὺς ὑπὲρ τῆς εὐσεβείας χειμῶνας" },
  { book: "4 Maccabees", chapter: 16, verse: 1, text: "εἰ δὲ τοίνυν καὶ γυνὴ καὶ γεραιὰ καὶ ἑπτὰ παίδων μήτηρ ὑπέμεινεν τὰς μέχρι θανάτου βασάνους τῶν τέκνων ὁρῶσα ὁμολογουμένως αὐτοκράτωρ ἐστὶν τῶν παθῶν ὁ εὐσεβὴς λογισμός" },
  { book: "4 Maccabees", chapter: 16, verse: 2, text: "ἀπέδειξα οὖν ὅτι οὐ μόνον ἄνδρες τῶν παθῶν ἐκράτησαν ἀλλὰ καὶ γυνὴ τῶν μεγίστων βασάνων ὑπερεφρόνησεν" },
  { book: "4 Maccabees", chapter: 16, verse: 3, text: "καὶ οὐχ οὕτως οἱ περὶ Δανιηλ λέοντες ἦσαν ἄγριοι οὐδὲ ἡ Μισαηλ ἐκφλεγομένη κάμινος λαβροτάτῳ πυρί ὡς ἡ τῆς φιλοτεκνίας περιέκαιεν ἐκείνην φύσις ὁρῶσαν αὐτῆς οὕτως ποικίλως βασανιζομένους τοὺς ἑπτὰ υἱούς" },
  { book: "4 Maccabees", chapter: 16, verse: 4, text: "ἀλλὰ τῷ λογισμῷ τῆς εὐσεβείας κατέσβεσεν τὰ τοσαῦτα καὶ τηλικαῦτα πάθη ἡ μήτηρ" },
  { book: "4 Maccabees", chapter: 16, verse: 5, text: "καὶ γὰρ τοῦτο ἐπιλογίσασθε ὅτι δειλόψυχος εἰ ἦν ἡ γυνὴ καίπερ μήτηρ οὖσα ὠλοφύρετο ἂν ἐπ’ αὐτοῖς καὶ ἴσως ἂν ταῦτα εἶπεν" },
  { book: "4 Maccabees", chapter: 16, verse: 6, text: "ὦ μελέα ἔγωγε καὶ πολλάκις τρισαθλία ἥτις ἑπτὰ παῖδας τεκοῦσα οὐδενὸς μήτηρ γεγένημαι" },
  { book: "4 Maccabees", chapter: 16, verse: 7, text: "ὦ μάταιοι ἑπτὰ κυοφορίαι καὶ ἀνόνητοι ἑπτὰ δεκάμηνοι καὶ ἄκαρποι τιθηνίαι καὶ ταλαίπωροι γαλακτοτροφίαι" },
  { book: "4 Maccabees", chapter: 16, verse: 8, text: "μάτην δὲ ἐφ’ ὑμῖν ὦ παῖδες πολλὰς ὑπέμεινα ὠδῖνας καὶ χαλεπωτέρας φροντίδας ἀνατροφῆς" },
  { book: "4 Maccabees", chapter: 16, verse: 9, text: "ὦ τῶν ἐμῶν παίδων οἱ μὲν ἄγαμοι οἱ δὲ γήμαντες ἀνόνητοι οὐκ ὄψομαι ὑμῶν τέκνα οὐδὲ μάμμη κληθεῖσα μακαρισθήσομαι" },
  { book: "4 Maccabees", chapter: 16, verse: 10, text: "ὦ ἡ πολύπαις καὶ καλλίπαις ἐγὼ γυνὴ χήρα καὶ μόνη πολύθρηνος" },
  { book: "4 Maccabees", chapter: 16, verse: 11, text: "οὐδ’ ἂν ἀποθάνω θάπτοντα τῶν υἱῶν ἕξω τινά" },
  { book: "4 Maccabees", chapter: 16, verse: 12, text: "ἀλλὰ τούτῳ τῷ θρήνῳ οὐδένα ὠλοφύρετο ἡ ἱερὰ καὶ θεοσεβὴς μήτηρ οὐδ’ ἵνα μὴ ἀποθάνωσιν ἀπέτρεπεν αὐτῶν τινα οὐδ’ ὡς ἀποθνῃσκόντων ἐλυπήθη" },
  { book: "4 Maccabees", chapter: 16, verse: 13, text: "ἀλλ’ ὥσπερ ἀδαμάντινον ἔχουσα τὸν νοῦν καὶ εἰς ἀθανασίαν ἀνατίκτουσα τὸν τῶν υἱῶν ἀριθμὸν μᾶλλον ὑπὲρ τῆς εὐσεβείας ἐπὶ τὸν θάνατον αὐτοὺς προετρέπετο ἱκετεύουσα" },
  { book: "4 Maccabees", chapter: 16, verse: 14, text: "ὦ μῆτερ δῑ εὐσέβειαν θεοῦ στρατιῶτι πρεσβῦτι καὶ γύναι διὰ καρτερίαν καὶ τύραννον ἐνίκησας καὶ ἔργοις δυνατωτέρα καὶ λόγοις εὑρέθης ἀνδρός" },
  { book: "4 Maccabees", chapter: 16, verse: 15, text: "καὶ γὰρ ὅτε συνελήμφθης μετὰ τῶν παίδων εἱστήκεις τὸν Ελεαζαρον ὁρῶσα βασανιζόμενον καὶ ἔλεγες τοῖς παισὶν ἐν τῇ Εβραΐδι φωνῇ" },
  { book: "4 Maccabees", chapter: 16, verse: 16, text: "ὦ παῖδες γενναῖος ὁ ἀγών ἐφ’ ὃν κληθέντες ὑπὲρ τῆς διαμαρτυρίας τοῦ ἔθνους ἐναγωνίσασθε προθύμως ὑπὲρ τοῦ πατρῴου νόμου" },
  { book: "4 Maccabees", chapter: 16, verse: 17, text: "καὶ γὰρ αἰσχρὸν τὸν μὲν γέροντα τοῦτον ὑπομένειν τὰς διὰ τὴν εὐσέβειαν ἀλγηδόνας ὑμᾶς δὲ τοὺς νεανίσκους καταπλαγῆναι τὰς βασάνους" },
  { book: "4 Maccabees", chapter: 16, verse: 18, text: "ἀναμνήσθητε ὅτι διὰ τὸν θεὸν τοῦ κόσμου μετελάβετε καὶ τοῦ βίου ἀπελαύσατε" },
  { book: "4 Maccabees", chapter: 16, verse: 19, text: "καὶ διὰ τοῦτο ὀφείλετε πάντα πόνον ὑπομένειν διὰ τὸν θεόν" },
  { book: "4 Maccabees", chapter: 16, verse: 20, text: "δῑ ὃν καὶ ὁ πατὴρ ἡμῶν Αβρααμ ἔσπευδεν τὸν ἐθνοπάτορα υἱὸν σφαγιάσαι Ισαακ καὶ τὴν πατρῴαν χεῖρα ξιφηφόρον καταφερομένην ἐπ’ αὐτὸν ὁρῶν οὐκ ἔπτηξεν" },
  { book: "4 Maccabees", chapter: 16, verse: 21, text: "καὶ Δανιηλ ὁ δίκαιος εἰς λέοντας ἐβλήθη καὶ Ανανιας καὶ Αζαριας καὶ Μισαηλ εἰς κάμινον πυρὸς ἀπεσφενδονήθησαν καὶ ὑπέμειναν διὰ τὸν θεόν" },
  { book: "4 Maccabees", chapter: 16, verse: 22, text: "καὶ ὑμεῖς οὖν τὴν αὐτὴν πίστιν πρὸς τὸν θεὸν ἔχοντες μὴ χαλεπαίνετε" },
  { book: "4 Maccabees", chapter: 16, verse: 23, text: "ἀλόγιστον γὰρ εἰδότας εὐσέβειαν μὴ ἀνθίστασθαι τοῖς πόνοις" },
  { book: "4 Maccabees", chapter: 16, verse: 24, text: "διὰ τούτων τῶν λόγων ἡ ἑπταμήτωρ ἕνα ἕκαστον τῶν υἱῶν παρακαλοῦσα ἀποθανεῖν ἔπεισεν μᾶλλον ἢ παραβῆναι τὴν ἐντολὴν τοῦ θεοῦ" },
  { book: "4 Maccabees", chapter: 16, verse: 25, text: "ἔτι δὲ καὶ ταῦτα εἰδότες ὅτι οἱ διὰ τὸν θεὸν ἀποθνῄσκοντες ζῶσιν τῷ θεῷ ὥσπερ Αβρααμ καὶ Ισαακ καὶ Ιακωβ καὶ πάντες οἱ πατριάρχαι" },
  { book: "4 Maccabees", chapter: 17, verse: 1, text: "ἔλεγον δὲ καὶ τῶν δορυφόρων τινὲς ὅτι ὡς ἔμελλεν συλλαμβάνεσθαι καὶ αὐτὴ πρὸς θάνατον ἵνα μὴ ψαύσειέν τις τοῦ σώματος αὐτῆς ἑαυτὴν ἔρριψε κατὰ τῆς πυρᾶς" },
  { book: "4 Maccabees", chapter: 17, verse: 2, text: "ὦ μήτηρ σὺν ἑπτὰ παισὶν καταλύσασα τὴν τοῦ τυράννου βίαν καὶ ἀκυρώσασα τὰς κακὰς ἐπινοίας αὐτοῦ καὶ δείξασα τὴν τῆς πίστεως γενναιότητα" },
  { book: "4 Maccabees", chapter: 17, verse: 3, text: "καθάπερ γὰρ σὺ στέγη ἐπὶ τοὺς στύλους τῶν παίδων γενναίως ἱδρυμένη ἀκλινὴς ὑπήνεγκας τὸν διὰ τῶν βασάνων σεισμόν" },
  { book: "4 Maccabees", chapter: 17, verse: 4, text: "θάρρει τοιγαροῦν ὦ μήτηρ ἱερόψυχε τὴν ἐλπίδα τῆς ὑπομονῆς βεβαίαν ἔχουσα πρὸς τὸν θεόν" },
  { book: "4 Maccabees", chapter: 17, verse: 5, text: "οὐχ οὕτως σελήνη κατ’ οὐρανὸν σὺν ἄστροις σεμνὴ καθέστηκεν ὡς σὺ τοὺς ἰσαστέρους ἑπτὰ παῖδας φωταγωγήσασα πρὸς τὴν εὐσέβειαν ἔντιμος καθέστηκας θεῷ καὶ ἐστήρισαι σὺν αὐτοῖς ἐν οὐρανῷ" },
  { book: "4 Maccabees", chapter: 17, verse: 6, text: "ἦν γὰρ ἡ παιδοποιία σου ἀπὸ Αβρααμ τοῦ πατρός" },
  { book: "4 Maccabees", chapter: 17, verse: 7, text: "εἰ δὲ ἐξὸν ἡμῖν ἦν ὥσπερ ἐπί τινος ζωγραφῆσαι τὴν τῆς εὐσεβείας σου ἱστορίαν οὐκ ἂν ἔφριττον οἱ θεωροῦντες ὁρῶντες μητέρα ἑπτὰ τέκνων δῑ εὐσέβειαν ποικίλας βασάνους μέχρι θανάτου ὑπομείνασαν" },
  { book: "4 Maccabees", chapter: 17, verse: 8, text: "καὶ γὰρ ἄξιον ἦν καὶ ἐπ’ αὐτοῦ τοῦ ἐπιταφίου ἀναγράψαι καὶ ταῦτα τοῖς ἀπὸ τοῦ ἔθνους εἰς μνείαν λεγόμενα" },
  { book: "4 Maccabees", chapter: 17, verse: 9, text: "ἐνταῦθα γέρων ἱερεὺς καὶ γυνὴ γεραιὰ καὶ ἑπτὰ παῖδες ἐγκεκήδευνται διὰ τυράννου βίαν τὴν Εβραίων πολιτείαν καταλῦσαι θέλοντος" },
  { book: "4 Maccabees", chapter: 17, verse: 10, text: "οἳ καὶ ἐξεδίκησαν τὸ γένος εἰς θεὸν ἀφορῶντες καὶ μέχρι θανάτου τὰς βασάνους ὑπομείναντες" },
  { book: "4 Maccabees", chapter: 17, verse: 11, text: "ἀληθῶς γὰρ ἦν ἀγὼν θεῖος ὁ δῑ αὐτῶν γεγενημένος" },
  { book: "4 Maccabees", chapter: 17, verse: 12, text: "ἠθλοθέτει γὰρ τότε ἀρετὴ δῑ ὑπομονῆς δοκιμάζουσα τὸ νῖκος ἀφθαρσία ἐν ζωῇ πολυχρονίῳ" },
  { book: "4 Maccabees", chapter: 17, verse: 13, text: "Ελεαζαρ δὲ προηγωνίζετο ἡ δὲ μήτηρ τῶν ἑπτὰ παίδων ἐνήθλει οἱ δὲ ἀδελφοὶ ἠγωνίζοντο" },
  { book: "4 Maccabees", chapter: 17, verse: 14, text: "ὁ τύραννος ἀντηγωνίζετο ὁ δὲ κόσμος καὶ ὁ τῶν ἀνθρώπων βίος ἐθεώρει" },
  { book: "4 Maccabees", chapter: 17, verse: 15, text: "θεοσέβεια δὲ ἐνίκα τοὺς ἑαυτῆς ἀθλητὰς στεφανοῦσα" },
  { book: "4 Maccabees", chapter: 17, verse: 16, text: "τίνες οὐκ ἐθαύμασαν τοὺς τῆς θείας νομοθεσίας ἀθλητάς τίνες οὐκ ἐξεπλάγησαν" },
  { book: "4 Maccabees", chapter: 17, verse: 17, text: "αὐτός γέ τοι ὁ τύραννος καὶ ὅλον τὸ συμβούλιον ἐθαύμασαν αὐτῶν τὴν ὑπομονήν" },
  { book: "4 Maccabees", chapter: 17, verse: 18, text: "δῑ ἣν καὶ τῷ θείῳ νῦν παρεστήκασιν θρόνῳ καὶ τὸν μακάριον βιοῦσιν αἰῶνα" },
  { book: "4 Maccabees", chapter: 17, verse: 19, text: "καὶ γάρ φησιν ὁ Μωυσῆς καὶ πάντες οἱ ἡγιασμένοι ὑπὸ τὰς χεῖράς σου" },
  { book: "4 Maccabees", chapter: 17, verse: 20, text: "καὶ οὗτοι οὖν ἁγιασθέντες διὰ θεὸν τετίμηνται οὐ μόνον ταύτῃ τῇ τιμῇ ἀλλὰ καὶ τῷ δῑ αὐτοὺς τὸ ἔθνος ἡμῶν τοὺς πολεμίους μὴ ἐπικρατῆσαι" },
  { book: "4 Maccabees", chapter: 17, verse: 21, text: "καὶ τὸν τύραννον τιμωρηθῆναι καὶ τὴν πατρίδα καθαρισθῆναι ὥσπερ ἀντίψυχον γεγονότας τῆς τοῦ ἔθνους ἁμαρτίας" },
  { book: "4 Maccabees", chapter: 17, verse: 22, text: "καὶ διὰ τοῦ αἵματος τῶν εὐσεβῶν ἐκείνων καὶ τοῦ ἱλαστηρίου τοῦ θανάτου αὐτῶν ἡ θεία πρόνοια τὸν Ισραηλ προκακωθέντα διέσωσεν" },
  { book: "4 Maccabees", chapter: 17, verse: 23, text: "πρὸς γὰρ τὴν ἀνδρείαν αὐτῶν τῆς ἀρετῆς καὶ τὴν ἐπὶ ταῖς βασάνοις αὐτῶν ὑπομονὴν ὁ τύραννος ἀπιδὼν ἀνεκήρυξεν ὁ Ἀντίοχος τοῖς στρατιώταις αὐτοῦ εἰς ὑπόδειγμα τὴν ἐκείνων ὑπομονὴν" },
  { book: "4 Maccabees", chapter: 17, verse: 24, text: "ἔσχεν τε αὐτοὺς γενναίους καὶ ἀνδρείους εἰς πεζομαχίαν καὶ πολιορκίαν καὶ ἐκπορθήσας ἐνίκησεν πάντας τοὺς πολεμίους" },
  { book: "4 Maccabees", chapter: 18, verse: 1, text: "ὦ τῶν Αβραμιαίων σπερμάτων ἀπόγονοι παῖδες Ισραηλῖται πείθεσθε τῷ νόμῳ τούτῳ καὶ πάντα τρόπον εὐσεβεῖτε" },
  { book: "4 Maccabees", chapter: 18, verse: 2, text: "γινώσκοντες ὅτι τῶν παθῶν ἐστιν δεσπότης ὁ εὐσεβὴς λογισμὸς καὶ οὐ μόνον τῶν ἔνδοθεν ἀλλὰ καὶ τῶν ἔξωθεν πόνων" },
  { book: "4 Maccabees", chapter: 18, verse: 3, text: "ἀνθ’ ὧν διὰ τὴν εὐσέβειαν προέμενοι τὰ σώματα τοῖς πόνοις ἐκεῖνοι οὐ μόνον ὑπὸ τῶν ἀνθρώπων ἐθαυμάσθησαν ἀλλὰ καὶ θείας μερίδος κατηξιώθησαν" },
  { book: "4 Maccabees", chapter: 18, verse: 4, text: "καὶ δῑ αὐτοὺς εἰρήνευσεν τὸ ἔθνος καὶ τὴν εὐνομίαν τὴν ἐπὶ τῆς πατρίδος ἀνανεωσάμενοι ἐκπεπόρθηκαν τοὺς πολεμίους" },
  { book: "4 Maccabees", chapter: 18, verse: 5, text: "καὶ ὁ τύραννος Ἀντίοχος καὶ ἐπὶ γῆς τετιμώρηται καὶ ἀποθανὼν κολάζεται ὡς γὰρ οὐδὲν οὐδαμῶς ἴσχυσεν ἀναγκάσαι τοὺς Ιεροσολυμίτας ἀλλοφυλῆσαι καὶ τῶν πατρίων ἐθῶν ἐκδιαιτηθῆναι τότε ἀπάρας ἀπὸ τῶν Ιεροσολύμων ἐστράτευσεν ἐπὶ Πέρσας" },
  { book: "4 Maccabees", chapter: 18, verse: 6, text: "ἔλεγεν δὲ ἡ μήτηρ τῶν ἑπτὰ παίδων καὶ ταῦτα τὰ δικαιώματα τοῖς τέκνοις" },
  { book: "4 Maccabees", chapter: 18, verse: 7, text: "ὅτι ἐγὼ ἐγενήθην παρθένος ἁγνὴ οὐδὲ ὑπερέβην πατρικὸν οἶκον ἐφύλασσον δὲ τὴν ᾠκοδομημένην πλευράν" },
  { book: "4 Maccabees", chapter: 18, verse: 8, text: "οὐδὲ ἔφθειρέν με λυμεὼν ἐρημίας φθορεὺς ἐν πεδίῳ οὐδὲ ἐλυμήνατό μου τὰ ἁγνὰ τῆς παρθενίας λυμεὼν ἀπάτης ὄφις" },
  { book: "4 Maccabees", chapter: 18, verse: 9, text: "ἔμεινα δὲ χρόνον ἀκμῆς σὺν ἀνδρί τούτων δὲ ἐνηλίκων γενομένων ἐτελεύτησεν ὁ πατὴρ αὐτῶν μακάριος μὲν ἐκεῖνος τὸν γὰρ τῆς εὐτεκνίας βίον ἐπιζήσας τὸν τῆς ἀτεκνίας οὐκ ὠδυνήθη καιρόν" },
  { book: "4 Maccabees", chapter: 18, verse: 10, text: "ὃς ἐδίδασκεν ὑμᾶς ἔτι ὢν σὺν ὑμῖν τὸν νόμον καὶ τοὺς προφήτας" },
  { book: "4 Maccabees", chapter: 18, verse: 11, text: "τὸν ἀναιρεθέντα Αβελ ὑπὸ Καιν ἀνεγίνωσκέν τε ὑμῖν καὶ τὸν ὁλοκαρπούμενον Ισαακ καὶ τὸν ἐν φυλακῇ Ιωσηφ" },
  { book: "4 Maccabees", chapter: 18, verse: 12, text: "ἔλεγεν δὲ ὑμῖν τὸν ζηλωτὴν Φινεες ἐδίδασκέν τε ὑμᾶς τοὺς ἐν πυρὶ Ανανιαν καὶ Αζαριαν καὶ Μισαηλ" },
  { book: "4 Maccabees", chapter: 18, verse: 13, text: "ἐδόξαζεν δὲ καὶ τὸν ἐν λάκκῳ λεόντων Δανιηλ ὃν ἐμακάριζεν" },
  { book: "4 Maccabees", chapter: 18, verse: 14, text: "ὑπεμίμνῃσκεν δὲ ὑμᾶς καὶ τὴν Ησαιου γραφὴν τὴν λέγουσαν κἂν διὰ πυρὸς διέλθῃς φλὸξ οὐ κατακαύσει σε" },
  { book: "4 Maccabees", chapter: 18, verse: 15, text: "τὸν ὑμνογράφον ἐμελῴδει ὑμῖν Δαυιδ λέγοντα πολλαὶ αἱ θλίψεις τῶν δικαίων" },
  { book: "4 Maccabees", chapter: 18, verse: 16, text: "τὸν Σαλωμῶντα ἐπαροιμίαζεν ὑμῖν λέγοντα ξύλον ζωῆς ἐστιν τοῖς ποιοῦσιν αὐτοῦ τὸ θέλημα" },
  { book: "4 Maccabees", chapter: 18, verse: 17, text: "τὸν Ιεζεκιηλ ἐπιστοποίει τὸν λέγοντα εἰ ζήσεται τὰ ὀστᾶ τὰ ξηρὰ ταῦτα" },
  { book: "4 Maccabees", chapter: 18, verse: 18, text: "ᾠδὴν μὲν γάρ ἣν ἐδίδαξεν Μωυσῆς οὐκ ἐπελάθετο διδάσκων τὴν λέγουσαν" },
  { book: "4 Maccabees", chapter: 18, verse: 19, text: "ἐγὼ ἀποκτενῶ καὶ ζῆν ποιήσω αὕτη ἡ ζωὴ ὑμῶν καὶ ἡ μακρότης τῶν ἡμερῶν" },
  { book: "4 Maccabees", chapter: 18, verse: 20, text: "ὦ πικρᾶς τῆς τότε ἡμέρας καὶ οὐ πικρᾶς ὅτε ὁ πικρὸς Ἑλλήνων τύραννος πῦρ πυρὶ σβέσας λέβησιν ὠμοῖς καὶ ζέουσι θυμοῖς ἀγαγὼν ἐπὶ τὸν καταπέλτην καὶ πάλιν τὰς βασάνους αὐτοῦ τοὺς ἑπτὰ παῖδας τῆς Αβρααμίτιδος" },
  { book: "4 Maccabees", chapter: 18, verse: 21, text: "τὰς τῶν ὀμμάτων κόρας ἐπήρωσεν καὶ γλώσσας ἐξέτεμεν καὶ βασάνοις ποικίλαις ἀπέκτεινεν" },
  { book: "4 Maccabees", chapter: 18, verse: 22, text: "ὑπὲρ ὧν ἡ θεία δίκη μετῆλθεν καὶ μετελεύσεται τὸν ἀλάστορα τύραννον" },
  { book: "4 Maccabees", chapter: 18, verse: 23, text: "οἱ δὲ Αβραμιαῖοι παῖδες σὺν τῇ ἀθλοφόρῳ μητρὶ εἰς πατέρων χορὸν συναγελάζονται ψυχὰς ἁγνὰς καὶ ἀθανάτους ἀπειληφότες παρὰ τοῦ θεοῦ" },
  { book: "4 Maccabees", chapter: 18, verse: 24, text: "ᾧ ἡ δόξα εἰς τοὺς αἰῶνας τῶν αἰώνων αμην" },
  // Baruch (213 verses)
  { book: "Baruch", chapter: 1, verse: 1, text: "And these are the words of the book, which Baruch the son of Nerias, the son of Maasias, the son of Sedecias, the son of Asadias, the son of Chelcias, wrote in Babylon," },
  { book: "Baruch", chapter: 1, verse: 2, text: "In the fifth year, and in the seventh day of the month, what time as the Chaldeans took Jerusalem, and burnt it with fire." },
  { book: "Baruch", chapter: 1, verse: 3, text: "And Baruch did read the words of this book in the hearing of Jechonias the son of Joachim king of Juda, and in the ears of all the people that came to hear the book," },
  { book: "Baruch", chapter: 1, verse: 4, text: "And in the hearing of the nobles, and of the king’s sons, and in the hearing of the elders, and of all the people, from the lowest unto the highest, even of all them that dwelt at Babylon by the river Sud." },
  { book: "Baruch", chapter: 1, verse: 5, text: "Whereupon they wept, fasted, and prayed before the Lord." },
  { book: "Baruch", chapter: 1, verse: 6, text: "They made also a collection of money according to every man’s power:" },
  { book: "Baruch", chapter: 1, verse: 7, text: "And they sent it to Jerusalem unto Joachim the high priest, the son of Chelcias, son of Salom, and to the priests, and to all the people which were found with him at Jerusalem," },
  { book: "Baruch", chapter: 1, verse: 8, text: "At the same time when he received the vessels of the house of the Lord, that were carried out of the temple, to return them into the land of Juda, the tenth day of the month Sivan, namely, silver vessels, which Sedecias the son of Josias king of Jada had made," },
  { book: "Baruch", chapter: 1, verse: 9, text: "After that Nabuchodonosor king of Babylon had carried away Jechonias, and the princes, and the captives, and the mighty men, and the people of the land, from Jerusalem, and brought them unto Babylon." },
  { book: "Baruch", chapter: 1, verse: 10, text: "And they said, Behold, we have sent you money to buy you burnt offerings, and sin offerings, and incense, and prepare ye manna, and offer upon the altar of the Lord our God;" },
  { book: "Baruch", chapter: 1, verse: 11, text: "And pray for the life of Nabuchodonosor king of Babylon, and for the life of Balthasar his son, that their days may be upon earth as the days of heaven:" },
  { book: "Baruch", chapter: 1, verse: 12, text: "And the Lord will give us strength, and lighten our eyes, and we shall live under the shadow of Nabuchodonosor king of Babylon, and under the shadow of Balthasar his son, and we shall serve them many days, and find favour in their sight." },
  { book: "Baruch", chapter: 1, verse: 13, text: "Pray for us also unto the Lord our God, for we have sinned against the Lord our God; and unto this day the fury of the Lord and his wrath is not turned from us." },
  { book: "Baruch", chapter: 1, verse: 14, text: "And ye shall read this book which we have sent unto you, to make confession in the house of the Lord, upon the feasts and solemn days." },
  { book: "Baruch", chapter: 1, verse: 15, text: "And ye shall say, To the Lord our God belongeth righteousness, but unto us the confusion of faces, as it is come to pass this day, unto them of Juda, and to the inhabitants of Jerusalem," },
  { book: "Baruch", chapter: 1, verse: 16, text: "And to our kings, and to our princes, and to our priests, and to our prophets, and to our fathers:" },
  { book: "Baruch", chapter: 1, verse: 17, text: "For we have sinned before the Lord," },
  { book: "Baruch", chapter: 1, verse: 18, text: "And disobeyed him, and have not hearkened unto the voice of the Lord our God, to walk in the commandments that he gave us openly:" },
  { book: "Baruch", chapter: 1, verse: 19, text: "Since the day that the Lord brought our forefathers out of the land of Egypt, unto this present day, we have been disobedient unto the Lord our God, and we have been negligent in not hearing his voice." },
  { book: "Baruch", chapter: 1, verse: 20, text: "Wherefore the evils cleaved unto us, and the curse, which the Lord appointed by Moses his servant at the time that he brought our fathers out of the land of Egypt, to give us a land that floweth with milk and honey, like as it is to see this day." },
  { book: "Baruch", chapter: 1, verse: 21, text: "Nevertheless we have not hearkened unto the voice of the Lord our God, according unto all the words of the prophets, whom he sent unto us:" },
  { book: "Baruch", chapter: 1, verse: 22, text: "But every man followed the imagination of his own wicked heart, to serve strange gods, and to do evil in the sight of the Lord our God." },
  { book: "Baruch", chapter: 2, verse: 1, text: "Therefore the Lord hath made good his word, which he pronounced against us, and against our judges that judged Israel, and against our kings, and against our princes, and against the men of Israel and Juda," },
  { book: "Baruch", chapter: 2, verse: 2, text: "To bring upon us great plagues, such as never happened under the whole heaven, as it came to pass in Jerusalem, according to the things that were written in the law of Moses;" },
  { book: "Baruch", chapter: 2, verse: 3, text: "That a man should eat the flesh of his own son, and the flesh of his own daughter." },
  { book: "Baruch", chapter: 2, verse: 4, text: "Moreover he hath delivered them to be in subjection to all the kingdoms that are round about us, to be as a reproach and desolation among all the people round about, where the Lord hath scattered them." },
  { book: "Baruch", chapter: 2, verse: 5, text: "Thus we were cast down, and not exalted, because we have sinned against the Lord our God, and have not been obedient unto his voice." },
  { book: "Baruch", chapter: 2, verse: 6, text: "To the Lord our God appertaineth righteousness: but unto us and to our fathers open shame, as appeareth this day." },
  { book: "Baruch", chapter: 2, verse: 7, text: "For all these plagues are come upon us, which the Lord hath pronounced against us" },
  { book: "Baruch", chapter: 2, verse: 8, text: "Yet have we not prayed before the Lord, that we might turn every one from the imaginations of his wicked heart." },
  { book: "Baruch", chapter: 2, verse: 9, text: "Wherefore the Lord watched over us for evil, and the Lord hath brought it upon us: for the Lord is righteous in all his works which he hath commanded us." },
  { book: "Baruch", chapter: 2, verse: 10, text: "Yet we have not hearkened unto his voice, to walk in the commandments of the Lord, that he hath set before us." },
  { book: "Baruch", chapter: 2, verse: 11, text: "And now, O Lord God of Israel, that hast brought thy people out of the land of Egypt with a mighty hand, and high arm, and with signs, and with wonders, and with great power, and hast gotten thyself a name, as appeareth this day:" },
  { book: "Baruch", chapter: 2, verse: 12, text: "O Lord our God, we have sinned, we have done ungodly, we have dealt unrighteously in all thine ordinances." },
  { book: "Baruch", chapter: 2, verse: 13, text: "Let thy wrath turn from us: for we are but a few left among the heathen, where thou hast scattered us." },
  { book: "Baruch", chapter: 2, verse: 14, text: "Hear our prayers, O Lord, and our petitions, and deliver us for thine own sake, and give us favour in the sight of them which have led us away:" },
  { book: "Baruch", chapter: 2, verse: 15, text: "That all the earth may know that thou art the Lord our God, because Israel and his posterity is called by thy name." },
  { book: "Baruch", chapter: 2, verse: 16, text: "O Lord, look down from thine holy house, and consider us: bow down thine ear, O Lord, to hear us." },
  { book: "Baruch", chapter: 2, verse: 17, text: "Open thine eyes, and behold; for the dead that are in the graves, whose souls are taken from their bodies, will give unto the Lord neither praise nor righteousness:" },
  { book: "Baruch", chapter: 2, verse: 18, text: "But the soul that is greatly vexed, which goeth stooping and feeble, and the eyes that fail, and the hungry soul, will give thee praise and righteousness, O Lord." },
  { book: "Baruch", chapter: 2, verse: 19, text: "Therefore we do not make our humble supplication before thee, O Lord our God, for the righteousness of our fathers, and of our kings." },
  { book: "Baruch", chapter: 2, verse: 20, text: "For thou hast sent out thy wrath and indignation upon us, as thou hast spoken by thy servants the prophets, saying," },
  { book: "Baruch", chapter: 2, verse: 21, text: "Thus saith the Lord, Bow down your shoulders to serve the king of Babylon: so shall ye remain in the land that I gave unto your fathers." },
  { book: "Baruch", chapter: 2, verse: 22, text: "But if ye will not hear the voice of the Lord, to serve the king of Babylon," },
  { book: "Baruch", chapter: 2, verse: 23, text: "I will cause to cease out of the cites of Judah, and from without Jerusalem, the voice of mirth, and the voice of joy, the voice of the bridegroom, and the voice of the bride: and the whole land shall be desolate of inhabitants." },
  { book: "Baruch", chapter: 2, verse: 24, text: "But we would not hearken unto thy voice, to serve the king of Babylon: therefore hast thou made good the words that thou spakest by thy servants the prophets, namely, that the bones of our kings, and the bones of our fathers, should be taken out of their place." },
  { book: "Baruch", chapter: 2, verse: 25, text: "And, lo, they are cast out to the heat of the day, and to the frost of the night, and they died in great miseries by famine, by sword, and by pestilence." },
  { book: "Baruch", chapter: 2, verse: 26, text: "And the house which is called by thy name hast thou laid waste, as it is to be seen this day, for the wickedness of the house of Israel and the house of Juda." },
  { book: "Baruch", chapter: 2, verse: 27, text: "O Lord our God, thou hast dealt with us after all thy goodness, and according to all that great mercy of thine," },
  { book: "Baruch", chapter: 2, verse: 28, text: "As thou spakest by thy servant Moses in the day when thou didst command him to write the law before the children of Israel, saying," },
  { book: "Baruch", chapter: 2, verse: 29, text: "If ye will not hear my voice, surely this very great multitude shall be turned into a small number among the nations, where I will scatter them." },
  { book: "Baruch", chapter: 2, verse: 30, text: "For I knew that they would not hear me, because it is a stiffnecked people: but in the land of their captivities they shall remember themselves." },
  { book: "Baruch", chapter: 2, verse: 31, text: "And shall know that I am the Lord their God: for I will give them an heart, and ears to hear:" },
  { book: "Baruch", chapter: 2, verse: 32, text: "And they shall praise me in the land of their captivity, and think upon my name," },
  { book: "Baruch", chapter: 2, verse: 33, text: "And return from their stiff neck, and from their wicked deeds: for they shall remember the way of their fathers, which sinned before the Lord." },
  { book: "Baruch", chapter: 2, verse: 34, text: "And I will bring them again into the land which I promised with an oath unto their fathers, Abraham, Isaac, and Jacob, and they shall be lords of it: and I will increase them, and they shall not be diminished." },
  { book: "Baruch", chapter: 2, verse: 35, text: "And I will make an everlasting covenant with them to be their God, and they shall be my people: and I will no more drive my people of Israel out of the land that I have given them." },
  { book: "Baruch", chapter: 3, verse: 1, text: "O Lord Almighty, God of Israel, the soul in anguish the troubled spirit, crieth unto thee." },
  { book: "Baruch", chapter: 3, verse: 2, text: "Hear, O Lord, and have mercy; art thou art merciful: and have pity upon us, because we have sinned before thee." },
  { book: "Baruch", chapter: 3, verse: 3, text: "For thou endurest for ever, and we perish utterly." },
  { book: "Baruch", chapter: 3, verse: 4, text: "O Lord Almighty, thou God of Israel, hear now the prayers of the dead Israelites, and of their children, which have sinned before thee, and not hearkened unto the voice of thee their God: for the which cause these plagues cleave unto us." },
  { book: "Baruch", chapter: 3, verse: 5, text: "Remember not the iniquities of our forefathers: but think upon thy power and thy name now at this time." },
  { book: "Baruch", chapter: 3, verse: 6, text: "For thou art the Lord our God, and thee, O Lord, will we praise." },
  { book: "Baruch", chapter: 3, verse: 7, text: "And for this cause thou hast put thy fear in our hearts, to the intent that we should call upon thy name, and praise thee in our captivity: for we have called to mind all the iniquity of our forefathers, that sinned before thee." },
  { book: "Baruch", chapter: 3, verse: 8, text: "Behold, we are yet this day in our captivity, where thou hast scattered us, for a reproach and a curse, and to be subject to payments, according to all the iniquities of our fathers, which departed from the Lord our God." },
  { book: "Baruch", chapter: 3, verse: 9, text: "Hear, Israel, the commandments of life: give ear to understand wisdom." },
  { book: "Baruch", chapter: 3, verse: 10, text: "How happeneth it Israel, that thou art in thine enemies’ land, that thou art waxen old in a strange country, that thou art defiled with the dead," },
  { book: "Baruch", chapter: 3, verse: 11, text: "That thou art counted with them that go down into the grave?" },
  { book: "Baruch", chapter: 3, verse: 12, text: "Thou hast forsaken the fountain of wisdom." },
  { book: "Baruch", chapter: 3, verse: 13, text: "For if thou hadst walked in the way of God, thou shouldest have dwelled in peace for ever." },
  { book: "Baruch", chapter: 3, verse: 14, text: "Learn where is wisdom, where is strength, where is understanding; that thou mayest know also where is length of days, and life, where is the light of the eyes, and peace." },
  { book: "Baruch", chapter: 3, verse: 15, text: "Who hath found out her place? or who hath come into her treasures ?" },
  { book: "Baruch", chapter: 3, verse: 16, text: "Where are the princes of the heathen become, and such as ruled the beasts upon the earth;" },
  { book: "Baruch", chapter: 3, verse: 17, text: "They that had their pastime with the fowls of the air, and they that hoarded up silver and gold, wherein men trust, and made no end of their getting?" },
  { book: "Baruch", chapter: 3, verse: 18, text: "For they that wrought in silver, and were so careful, and whose works are unsearchable," },
  { book: "Baruch", chapter: 3, verse: 19, text: "They are vanished and gone down to the grave, and others are come up in their steads." },
  { book: "Baruch", chapter: 3, verse: 20, text: "Young men have seen light, and dwelt upon the earth: but the way of knowledge have they not known," },
  { book: "Baruch", chapter: 3, verse: 21, text: "Nor understood the paths thereof, nor laid hold of it: their children were far off from that way." },
  { book: "Baruch", chapter: 3, verse: 22, text: "It hath not been heard of in Chanaan, neither hath it been seen in Theman." },
  { book: "Baruch", chapter: 3, verse: 23, text: "The Agarenes that seek wisdom upon earth, the merchants of Meran and of Theman, the authors of fables, and searchers out of understanding; none of these have known the way of wisdom, or remember her paths." },
  { book: "Baruch", chapter: 3, verse: 24, text: "O Israel, how great is the house of God! and how large is the place of his possession!" },
  { book: "Baruch", chapter: 3, verse: 25, text: "Great, and hath none end; high, and unmeasurable." },
  { book: "Baruch", chapter: 3, verse: 26, text: "There were the giants famous from the beginning, that were of so great stature, and so expert in war." },
  { book: "Baruch", chapter: 3, verse: 27, text: "Those did not the Lord choose, neither gave he the way of knowledge unto them:" },
  { book: "Baruch", chapter: 3, verse: 28, text: "But they were destroyed, because they had no wisdom, and perished through their own foolishness." },
  { book: "Baruch", chapter: 3, verse: 29, text: "Who hath gone up into heaven, and taken her, and brought her down from the clouds?" },
  { book: "Baruch", chapter: 3, verse: 30, text: "Who hath gone over the sea, and found her, and will bring her for pure gold?" },
  { book: "Baruch", chapter: 3, verse: 31, text: "No man knoweth her way, nor thinketh of her path." },
  { book: "Baruch", chapter: 3, verse: 32, text: "But he that knoweth all things knoweth her, and hath found her out with his understanding: he that prepared the earth for evermore hath filled it with fourfooted beasts:" },
  { book: "Baruch", chapter: 3, verse: 33, text: "He that sendeth forth light, and it goeth, calleth it again, and it obeyeth him with fear." },
  { book: "Baruch", chapter: 3, verse: 34, text: "The stars shined in their watches, and rejoiced: when he calleth them, they say, Here we be; and so with cheerfulness they shewed light unto him that made them." },
  { book: "Baruch", chapter: 3, verse: 35, text: "This is our God, and there shall none other be accounted of in comparison of him" },
  { book: "Baruch", chapter: 3, verse: 36, text: "He hath found out all the way of knowledge, and hath given it unto Jacob his servant, and to Israel his beloved." },
  { book: "Baruch", chapter: 3, verse: 37, text: "Afterward did he shew himself upon earth, and conversed with men." },
  { book: "Baruch", chapter: 4, verse: 1, text: "This is the book of the commandments of God, and the law that endureth for ever: all they that keep it shall come to life; but such as leave it shall die." },
  { book: "Baruch", chapter: 4, verse: 2, text: "Turn thee, O Jacob, and take hold of it: walk in the presence of the light thereof, that thou mayest be illuminated." },
  { book: "Baruch", chapter: 4, verse: 3, text: "Give not thine honour to another, nor the things that are profitable unto thee to a strange nation." },
  { book: "Baruch", chapter: 4, verse: 4, text: "O Israel, happy are we: for things that are pleasing to God are made known unto us." },
  { book: "Baruch", chapter: 4, verse: 5, text: "Be of good cheer, my people, the memorial of Israel." },
  { book: "Baruch", chapter: 4, verse: 6, text: "Ye were sold to the nations, not for your destruction: but because ye moved God to wrath, ye were delivered unto the enemies." },
  { book: "Baruch", chapter: 4, verse: 7, text: "For ye provoked him that made you by sacrificing unto devils, and not to God." },
  { book: "Baruch", chapter: 4, verse: 8, text: "Ye have forgotten the everlasting God, that brought you up; and ye have grieved Jerusalem, that nursed you." },
  { book: "Baruch", chapter: 4, verse: 9, text: "For when she saw the wrath of God coming upon you, she said, Hearken, O ye that dwell about Sion: God hath brought upon me great mourning;" },
  { book: "Baruch", chapter: 4, verse: 10, text: "For I saw the captivity of my sons and daughters, which the Everlasting brought upon them." },
  { book: "Baruch", chapter: 4, verse: 11, text: "With joy did I nourish them; but sent them away with weeping and mourning." },
  { book: "Baruch", chapter: 4, verse: 12, text: "Let no man rejoice over me, a widow, and forsaken of many, who for the sins of my children am left desolate; because they departed from the law of God." },
  { book: "Baruch", chapter: 4, verse: 13, text: "They knew not his statutes, nor walked in the ways of his commandments, nor trod in the paths of discipline in his righteousness." },
  { book: "Baruch", chapter: 4, verse: 14, text: "Let them that dwell about Sion come, and remember ye the captivity of my sons and daughters, which the Everlasting hath brought upon them." },
  { book: "Baruch", chapter: 4, verse: 15, text: "For he hath brought a nation upon them from far, a shameless nation, and of a strange language, who neither reverenced old man, nor pitied child." },
  { book: "Baruch", chapter: 4, verse: 16, text: "These have carried away the dear beloved children of the widow, and left her that was alone desolate without daughters." },
  { book: "Baruch", chapter: 4, verse: 17, text: "But what can I help you?" },
  { book: "Baruch", chapter: 4, verse: 18, text: "For he that brought these plagues upon you will deliver you from the hands of your enemies." },
  { book: "Baruch", chapter: 4, verse: 19, text: "Go your way, O my children, go your way: for I am left desolate." },
  { book: "Baruch", chapter: 4, verse: 20, text: "I have put off the clothing of peace, and put upon me the sackcloth of my prayer: I will cry unto the Everlasting in my days." },
  { book: "Baruch", chapter: 4, verse: 21, text: "Be of good cheer, O my children, cry unto the Lord, and he will deliver you from the power and hand of the enemies." },
  { book: "Baruch", chapter: 4, verse: 22, text: "For my hope is in the Everlasting, that he will save you; and joy is come unto me from the Holy One, because of the mercy which shall soon come unto you from the Everlasting our Saviour." },
  { book: "Baruch", chapter: 4, verse: 23, text: "For I sent you out with mourning and weeping: but God will give you to me again with joy and gladness for ever." },
  { book: "Baruch", chapter: 4, verse: 24, text: "Like as now the neighbours of Sion have seen your captivity: so shall they see shortly your salvation from our God which shall come upon you with great glory, and brightness of the Everlasting." },
  { book: "Baruch", chapter: 4, verse: 25, text: "My children, suffer patiently the wrath that is come upon you from God: for thine enemy hath persecuted thee; but shortly thou shalt see his destruction, and shalt tread upon his neck." },
  { book: "Baruch", chapter: 4, verse: 26, text: "My delicate ones have gone rough ways, and were taken away as a flock caught of the enemies." },
  { book: "Baruch", chapter: 4, verse: 27, text: "Be of good comfort, O my children, and cry unto God: for ye shall be remembered of him that brought these things upon you." },
  { book: "Baruch", chapter: 4, verse: 28, text: "For as it was your mind to go astray from God: so, being returned, seek him ten times more." },
  { book: "Baruch", chapter: 4, verse: 29, text: "For he that hath brought these plagues upon you shall bring you everlasting joy with your salvation." },
  { book: "Baruch", chapter: 4, verse: 30, text: "Take a good heart, O Jerusalem: for he that gave thee that name will comfort thee." },
  { book: "Baruch", chapter: 4, verse: 31, text: "Miserable are they that afflicted thee, and rejoiced at thy fall." },
  { book: "Baruch", chapter: 4, verse: 32, text: "Miserable are the cities which thy children served: miserable is she that received thy sons." },
  { book: "Baruch", chapter: 4, verse: 33, text: "For as she rejoiced at thy ruin, and was glad of thy fall: so shall she be grieved for her own desolation." },
  { book: "Baruch", chapter: 4, verse: 34, text: "For I will take away the rejoicing of her great multitude, and her pride shall be turned into mourning." },
  { book: "Baruch", chapter: 4, verse: 35, text: "For fire shall come upon her from the Everlasting, long to endure; and she shall be inhabited of devils for a great time." },
  { book: "Baruch", chapter: 4, verse: 36, text: "O Jerusalem, look about thee toward the east, and behold the joy that cometh unto thee from God." },
  { book: "Baruch", chapter: 4, verse: 37, text: "Lo, thy sons come, whom thou sentest away, they come gathered together from the east to the west by the word of the Holy One, rejoicing in the glory of God." },
  { book: "Baruch", chapter: 5, verse: 1, text: "Put off, O Jerusalem, the garment of mourning and affliction, and put on the comeliness of the glory that cometh from God for ever." },
  { book: "Baruch", chapter: 5, verse: 2, text: "Cast about thee a double garment of the righteousness which cometh from God; and set a diadem on thine head of the glory of the Everlasting." },
  { book: "Baruch", chapter: 5, verse: 3, text: "For God will shew thy brightness unto every country under heaven." },
  { book: "Baruch", chapter: 5, verse: 4, text: "For thy name shall be called of God for ever The peace of righteousness, and The glory of God’s worship." },
  { book: "Baruch", chapter: 5, verse: 5, text: "Arise, O Jerusalem, and stand on high, and look about toward the east, and behold thy children gathered from the west unto the east by the word of the Holy One, rejoicing in the remembrance of God." },
  { book: "Baruch", chapter: 5, verse: 6, text: "For they departed from thee on foot, and were led away of their enemies: but God bringeth them unto thee exalted with glory, as children of the kingdom." },
  { book: "Baruch", chapter: 5, verse: 7, text: "For God hath appointed that every high hill, and banks of long continuance, should be cast down, and valleys filled up, to make even the ground, that Israel may go safely in the glory of God," },
  { book: "Baruch", chapter: 5, verse: 8, text: "Moreover even the woods and every sweetsmelling tree shall overshadow Israel by the commandment of God." },
  { book: "Baruch", chapter: 5, verse: 9, text: "For God shall lead Israel with joy in the light of his glory with the mercy and righteousness that cometh from him." },
  { book: "Baruch", chapter: 6, verse: 1, text: "A copy of an epistle, which Jeremy sent unto them which were to be led captives into Babylon by the king of the Babylonians, to certify them, as it was commanded him of God." },
  { book: "Baruch", chapter: 6, verse: 2, text: "Because of the sins which ye have committed before God, ye shall be led away captives into Babylon by Nabuchodonosor king of the Babylonians." },
  { book: "Baruch", chapter: 6, verse: 3, text: "So when ye be come unto Babylon, ye shall remain there many years, and for a long season, namely, seven generations: and after that I will bring you away peaceably from thence." },
  { book: "Baruch", chapter: 6, verse: 4, text: "Now shall ye see in Babylon gods of silver, and of gold, and of wood, borne upon shoulders, which cause the nations to fear." },
  { book: "Baruch", chapter: 6, verse: 5, text: "Beware therefore that ye in no wise be like to strangers, neither be ye and of them, when ye see the multitude before them and behind them, worshipping them." },
  { book: "Baruch", chapter: 6, verse: 6, text: "But say ye in your hearts, O Lord, we must worship thee." },
  { book: "Baruch", chapter: 6, verse: 7, text: "For mine angel is with you, and I myself caring for your souls." },
  { book: "Baruch", chapter: 6, verse: 8, text: "As for their tongue, it is polished by the workman, and they themselves are gilded and laid over with silver; yet are they but false, and cannot speak." },
  { book: "Baruch", chapter: 6, verse: 9, text: "And taking gold, as it were for a virgin that loveth to go gay, they make crowns for the heads of their gods." },
  { book: "Baruch", chapter: 6, verse: 10, text: "Sometimes also the priests convey from their gods gold and silver, and bestow it upon themselves." },
  { book: "Baruch", chapter: 6, verse: 11, text: "Yea, they will give thereof to the common harlots, and deck them as men with garments, being gods of silver, and gods of gold, and wood." },
  { book: "Baruch", chapter: 6, verse: 12, text: "Yet cannot these gods save themselves from rust and moth, though they be covered with purple raiment." },
  { book: "Baruch", chapter: 6, verse: 13, text: "They wipe their faces because of the dust of the temple, when there is much upon them." },
  { book: "Baruch", chapter: 6, verse: 14, text: "And he that cannot put to death one that offendeth him holdeth a sceptre, as though he were a judge of the country." },
  { book: "Baruch", chapter: 6, verse: 15, text: "He hath also in his right hand a dagger and an axe: but cannot deliver himself from war and thieves." },
  { book: "Baruch", chapter: 6, verse: 16, text: "Whereby they are known not to be gods: therefore fear them not." },
  { book: "Baruch", chapter: 6, verse: 17, text: "For like as a vessel that a man useth is nothing worth when it is broken; even so it is with their gods: when they be set up in the temple, their eyes be full of dust through the feet of them that come in." },
  { book: "Baruch", chapter: 6, verse: 18, text: "And as the doors are made sure on every side upon him that offendeth the king, as being committed to suffer death: even so the priests make fast their temples with doors, with locks, and bars, lest their gods be spoiled with robbers." },
  { book: "Baruch", chapter: 6, verse: 19, text: "They light them candles, yea, more than for themselves, whereof they cannot see one." },
  { book: "Baruch", chapter: 6, verse: 20, text: "They are as one of the beams of the temple, yet they say their hearts are gnawed upon by things creeping out of the earth; and when they eat them and their clothes, they feel it not." },
  { book: "Baruch", chapter: 6, verse: 21, text: "Their faces are blacked through the smoke that cometh out of the temple." },
  { book: "Baruch", chapter: 6, verse: 22, text: "Upon their bodies and heads sit bats, swallows, and birds, and the cats also." },
  { book: "Baruch", chapter: 6, verse: 23, text: "By this ye may know that they are no gods: therefore fear them not." },
  { book: "Baruch", chapter: 6, verse: 24, text: "Notwithstanding the gold that is about them to make them beautiful, except they wipe off the rust, they will not shine: for neither when they were molten did they feel it." },
  { book: "Baruch", chapter: 6, verse: 25, text: "The things wherein there is no breath are bought for a most high price." },
  { book: "Baruch", chapter: 6, verse: 26, text: "They are borne upon shoulders, having no feet whereby they declare unto men that they be nothing worth." },
  { book: "Baruch", chapter: 6, verse: 27, text: "They also that serve them are ashamed: for if they fall to the ground at any time, they cannot rise up again of themselves: neither, if one set them upright, can they move of themselves: neither, if they be bowed down, can they make themselves straight: but they set gifts before them as unto dead men." },
  { book: "Baruch", chapter: 6, verse: 28, text: "As for the things that are sacrificed unto them, their priests sell and abuse; in like manner their wives lay up part thereof in salt; but unto the poor and impotent they give nothing of it." },
  { book: "Baruch", chapter: 6, verse: 29, text: "Menstruous women and women in childbed eat their sacrifices: by these things ye may know that they are no gods: fear them not." },
  { book: "Baruch", chapter: 6, verse: 30, text: "For how can they be called gods? because women set meat before the gods of silver, gold, and wood." },
  { book: "Baruch", chapter: 6, verse: 31, text: "And the priests sit in their temples, having their clothes rent, and their heads and beards shaven, and nothing upon their heads." },
  { book: "Baruch", chapter: 6, verse: 32, text: "They roar and cry before their gods, as men do at the feast when one is dead." },
  { book: "Baruch", chapter: 6, verse: 33, text: "The priests also take off their garments, and clothe their wives and children." },
  { book: "Baruch", chapter: 6, verse: 34, text: "Whether it be evil that one doeth unto them, or good, they are not able to recompense it: they can neither set up a king, nor put him down." },
  { book: "Baruch", chapter: 6, verse: 35, text: "In like manner, they can neither give riches nor money: though a man make a vow unto them, and keep it not, they will not require it." },
  { book: "Baruch", chapter: 6, verse: 36, text: "They can save no man from death, neither deliver the weak from the mighty." },
  { book: "Baruch", chapter: 6, verse: 37, text: "They cannot restore a blind man to his sight, nor help any man in his distress." },
  { book: "Baruch", chapter: 6, verse: 38, text: "They can shew no mercy to the widow, nor do good to the fatherless." },
  { book: "Baruch", chapter: 6, verse: 39, text: "Their gods of wood, and which are overlaid with gold and silver, are like the stones that be hewn out of the mountain: they that worship them shall be confounded." },
  { book: "Baruch", chapter: 6, verse: 40, text: "How should a man then think and say that they are gods, when even the Chaldeans themselves dishonour them?" },
  { book: "Baruch", chapter: 6, verse: 41, text: "Who if they shall see one dumb that cannot speak, they bring him, and intreat Bel that he may speak, as though he were able to understand." },
  { book: "Baruch", chapter: 6, verse: 42, text: "Yet they cannot understand this themselves, and leave them: for they have no knowledge." },
  { book: "Baruch", chapter: 6, verse: 43, text: "The women also with cords about them, sitting in the ways, burn bran for perfume: but if any of them, drawn by some that passeth by, lie with him, she reproacheth her fellow, that she was not thought as worthy as herself, nor her cord broken." },
  { book: "Baruch", chapter: 6, verse: 44, text: "Whatsoever is done among them is false: how may it then be thought or said that they are gods?" },
  { book: "Baruch", chapter: 6, verse: 45, text: "They are made of carpenters and goldsmiths: they can be nothing else than the workmen will have them to be." },
  { book: "Baruch", chapter: 6, verse: 46, text: "And they themselves that made them can never continue long; how should then the things that are made of them be gods?" },
  { book: "Baruch", chapter: 6, verse: 47, text: "For they left lies and reproaches to them that come after." },
  { book: "Baruch", chapter: 6, verse: 48, text: "For when there cometh any war or plague upon them, the priests consult with themselves, where they may be hidden with them." },
  { book: "Baruch", chapter: 6, verse: 49, text: "How then cannot men perceive that they be no gods, which can neither save themselves from war, nor from plague?" },
  { book: "Baruch", chapter: 6, verse: 50, text: "For seeing they be but of wood, and overlaid with silver and gold, it shall be known hereafter that they are false:" },
  { book: "Baruch", chapter: 6, verse: 51, text: "And it shall manifestly appear to all nations and kings that they are no gods, but the works of men’s hands, and that there is no work of God in them." },
  { book: "Baruch", chapter: 6, verse: 52, text: "Who then may not know that they are no gods?" },
  { book: "Baruch", chapter: 6, verse: 53, text: "For neither can they set up a king in the land, nor give rain unto men." },
  { book: "Baruch", chapter: 6, verse: 54, text: "Neither can they judge their own cause, nor redress a wrong, being unable: for they are as crows between heaven and earth." },
  { book: "Baruch", chapter: 6, verse: 55, text: "Whereupon when fire falleth upon the house of gods of wood, or laid over with gold or silver, their priests will flee away, and escape; but they themselves shall be burned asunder like beams." },
  { book: "Baruch", chapter: 6, verse: 56, text: "Moreover they cannot withstand any king or enemies: how can it then be thought or said that they be gods?" },
  { book: "Baruch", chapter: 6, verse: 57, text: "Neither are those gods of wood, and laid over with silver or gold, able to escape either from thieves or robbers." },
  { book: "Baruch", chapter: 6, verse: 58, text: "Whose gold, and silver, and garments wherewith they are clothed, they that are strong take, and go away withal: neither are they able to help themselves." },
  { book: "Baruch", chapter: 6, verse: 59, text: "Therefore it is better to be a king that sheweth his power, or else a profitable vessel in an house, which the owner shall have use of, than such false gods; or to be a door in an house, to keep such things therein, than such false gods. or a pillar of wood in a a palace, than such false gods." },
  { book: "Baruch", chapter: 6, verse: 60, text: "For sun, moon, and stars, being bright and sent to do their offices, are obedient." },
  { book: "Baruch", chapter: 6, verse: 61, text: "In like manner the lightning when it breaketh forth is easy to be seen; and after the same manner the wind bloweth in every country." },
  { book: "Baruch", chapter: 6, verse: 62, text: "And when God commandeth the clouds to go over the whole world, they do as they are bidden." },
  { book: "Baruch", chapter: 6, verse: 63, text: "And the fire sent from above to consume hills and woods doeth as it is commanded: but these are like unto them neither in shew nor power." },
  { book: "Baruch", chapter: 6, verse: 64, text: "Wherefore it is neither to be supposed nor said that they are gods, seeing, they are able neither to judge causes, nor to do good unto men." },
  { book: "Baruch", chapter: 6, verse: 65, text: "Knowing therefore that they are no gods, fear them not," },
  { book: "Baruch", chapter: 6, verse: 66, text: "For they can neither curse nor bless kings:" },
  { book: "Baruch", chapter: 6, verse: 67, text: "Neither can they shew signs in the heavens among the heathen, nor shine as the sun, nor give light as the moon." },
  { book: "Baruch", chapter: 6, verse: 68, text: "The beasts are better than they: for they can get under a cover and help themselves." },
  { book: "Baruch", chapter: 6, verse: 69, text: "It is then by no means manifest unto us that they are gods: therefore fear them not." },
  { book: "Baruch", chapter: 6, verse: 70, text: "For as a scarecrow in a garden of cucumbers keepeth nothing: so are their gods of wood, and laid over with silver and gold." },
  { book: "Baruch", chapter: 6, verse: 71, text: "And likewise their gods of wood, and laid over with silver and gold, are like to a white thorn in an orchard, that every bird sitteth upon; as also to a dead body, that is east into the dark." },
  { book: "Baruch", chapter: 6, verse: 72, text: "And ye shall know them to be no gods by the bright purple that rotteth upon them: and they themselves afterward shall be eaten, and shall be a reproach in the country." },
  { book: "Baruch", chapter: 6, verse: 73, text: "Better therefore is the just man that hath none idols: for he shall be far from reproach." },
  // Bel and the Dragon (42 verses)
  { book: "Bel and the Dragon", chapter: 1, verse: 1, text: "And king Astyages was gathered to his fathers, and Cyrus of Persia received his kingdom." },
  { book: "Bel and the Dragon", chapter: 1, verse: 2, text: "And Daniel conversed with the king, and was honoured above all his friends." },
  { book: "Bel and the Dragon", chapter: 1, verse: 3, text: "Now the Babylons had an idol, called Bel, and there were spent upon him every day twelve great measures of fine flour, and forty sheep, and six vessels of wine." },
  { book: "Bel and the Dragon", chapter: 1, verse: 4, text: "And the king worshipped it and went daily to adore it: but Daniel worshipped his own God. And the king said unto him, Why dost not thou worship Bel?" },
  { book: "Bel and the Dragon", chapter: 1, verse: 5, text: "Who answered and said, Because I may not worship idols made with hands, but the living God, who hath created the heaven and the earth, and hath sovereignty over all flesh." },
  { book: "Bel and the Dragon", chapter: 1, verse: 6, text: "Then said the king unto him, Thinkest thou not that Bel is a living God? seest thou not how much he eateth and drinketh every day?" },
  { book: "Bel and the Dragon", chapter: 1, verse: 7, text: "Then Daniel smiled, and said, O king, be not deceived: for this is but clay within, and brass without, and did never eat or drink any thing." },
  { book: "Bel and the Dragon", chapter: 1, verse: 8, text: "So the king was wroth, and called for his priests, and said unto them, If ye tell me not who this is that devoureth these expences, ye shall die." },
  { book: "Bel and the Dragon", chapter: 1, verse: 9, text: "But if ye can certify me that Bel devoureth them, then Daniel shall die: for he hath spoken blasphemy against Bel. And Daniel said unto the king, Let it be according to thy word." },
  { book: "Bel and the Dragon", chapter: 1, verse: 10, text: "Now the priests of Bel were threescore and ten, beside their wives and children. And the king went with Daniel into the temple of Bel." },
  { book: "Bel and the Dragon", chapter: 1, verse: 11, text: "So Bel’s priests said, Lo, we go out: but thou, O king, set on the meat, and make ready the wine, and shut the door fast and seal it with thine own signet;" },
  { book: "Bel and the Dragon", chapter: 1, verse: 12, text: "And to morrow when thou comest in, if thou findest not that Bel hath eaten up all, we will suffer death: or else Daniel, that speaketh falsely against us." },
  { book: "Bel and the Dragon", chapter: 1, verse: 13, text: "And they little regarded it: for under the table they had made a privy entrance, whereby they entered in continually, and consumed those things." },
  { book: "Bel and the Dragon", chapter: 1, verse: 14, text: "So when they were gone forth, the king set meats before Bel. Now Daniel had commanded his servants to bring ashes, and those they strewed throughout all the temple in the presence of the king alone: then went they out, and shut the door, and sealed it with the king’s signet, and so departed." },
  { book: "Bel and the Dragon", chapter: 1, verse: 15, text: "Now in the night came the priests with their wives and children, as they were wont to do, and did eat and drink up all." },
  { book: "Bel and the Dragon", chapter: 1, verse: 16, text: "In the morning betime the king arose, and Daniel with him." },
  { book: "Bel and the Dragon", chapter: 1, verse: 17, text: "And the king said, Daniel, are the seals whole? And he said, Yea, O king, they be whole." },
  { book: "Bel and the Dragon", chapter: 1, verse: 18, text: "And as soon as he had opened the dour, the king looked upon the table, and cried with a loud voice, Great art thou, O Bel, and with thee is no deceit at all." },
  { book: "Bel and the Dragon", chapter: 1, verse: 19, text: "Then laughed Daniel, and held the king that he should not go in, and said, Behold now the pavement, and mark well whose footsteps are these." },
  { book: "Bel and the Dragon", chapter: 1, verse: 20, text: "And the king said, I see the footsteps of men, women, and children. And then the king was angry," },
  { book: "Bel and the Dragon", chapter: 1, verse: 21, text: "And took the priests with their wives and children, who shewed him the privy doors, where they came in, and consumed such things as were upon the table." },
  { book: "Bel and the Dragon", chapter: 1, verse: 22, text: "Therefore the king slew them, and delivered Bel into Daniel’s power, who destroyed him and his temple." },
  { book: "Bel and the Dragon", chapter: 1, verse: 23, text: "And in that same place there was a great dragon, which they of Babylon worshipped." },
  { book: "Bel and the Dragon", chapter: 1, verse: 24, text: "And the king said unto Daniel, Wilt thou also say that this is of brass? lo, he liveth, he eateth and drinketh; thou canst not say that he is no living god: therefore worship him." },
  { book: "Bel and the Dragon", chapter: 1, verse: 25, text: "Then said Daniel unto the king, I will worship the Lord my God: for he is the living God." },
  { book: "Bel and the Dragon", chapter: 1, verse: 26, text: "But give me leave, O king, and I shall slay this dragon without sword or staff. The king said, I give thee leave." },
  { book: "Bel and the Dragon", chapter: 1, verse: 27, text: "Then Daniel took pitch, and fat, and hair, and did seethe them together, and made lumps thereof: this he put in the dragon’s mouth, and so the dragon burst in sunder : and Daniel said, Lo, these are the gods ye worship." },
  { book: "Bel and the Dragon", chapter: 1, verse: 28, text: "When they of Babylon heard that, they took great indignation, and conspired against the king, saying, The king is become a Jew, and he hath destroyed Bel, he hath slain the dragon, and put the priests to death." },
  { book: "Bel and the Dragon", chapter: 1, verse: 29, text: "So they came to the king, and said, Deliver us Daniel, or else we will destroy thee and thine house." },
  { book: "Bel and the Dragon", chapter: 1, verse: 30, text: "Now when the king saw that they pressed him sore, being constrained, he delivered Daniel unto them:" },
  { book: "Bel and the Dragon", chapter: 1, verse: 31, text: "Who cast him into the lions’ den: where he was six days." },
  { book: "Bel and the Dragon", chapter: 1, verse: 32, text: "And in the den there were seven lions, and they had given them every day two carcases, and two sheep: which then were not given to them, to the intent they might devour Daniel." },
  { book: "Bel and the Dragon", chapter: 1, verse: 33, text: "Now there was in Jewry a prophet, called Habbacuc, who had made pottage, and had broken bread in a bowl, and was going into the field, for to bring it to the reapers." },
  { book: "Bel and the Dragon", chapter: 1, verse: 34, text: "But the angel of the Lord said unto Habbacuc, Go, carry the dinner that thou hast into Babylon unto Daniel, who is in the lions’ den." },
  { book: "Bel and the Dragon", chapter: 1, verse: 35, text: "And Habbacuc said, Lord, I never saw Babylon; neither do I know where the den is." },
  { book: "Bel and the Dragon", chapter: 1, verse: 36, text: "Then the angel of the Lord took him by the crown, and bare him by the hair of his head, and through the vehemency of his spirit set him in Babylon over the den." },
  { book: "Bel and the Dragon", chapter: 1, verse: 37, text: "And Habbacuc cried, saying, O Daniel, Daniel, take the dinner which God hath sent thee." },
  { book: "Bel and the Dragon", chapter: 1, verse: 38, text: "And Daniel said, Thou hast remembered me, O God: neither hast thou forsaken them that seek thee and love thee." },
  { book: "Bel and the Dragon", chapter: 1, verse: 39, text: "So Daniel arose, and did eat: and the angel of the Lord set Habbacuc in his own place again immediately." },
  { book: "Bel and the Dragon", chapter: 1, verse: 40, text: "Upon the seventh day the king went to bewail Daniel: and when he came to the den, he looked in, and behold, Daniel was sitting." },
  { book: "Bel and the Dragon", chapter: 1, verse: 41, text: "Then cried the king with a loud voice, saying, Great art Lord God of Daniel, and there is none other beside thee." },
  { book: "Bel and the Dragon", chapter: 1, verse: 42, text: "And he drew him out, and cast those that were the cause of his destruction into the den: and they were devoured in a moment before his face." },
  // Jubilees (1305 verses)
  { book: "Jubilees", chapter: 1, verse: 1, text: "And it came to pass in the first year of the exodus of the children of Israel out of Egypt, in the third month, on the sixteenth day of the month, [2450 Anno Mundi] that God spake to Moses, saying: 'Come up to Me on the Mount, and I will give thee two tables of stone of the law and of the commandment, which I have written, that thou mayst teach them.'" },
  { book: "Jubilees", chapter: 1, verse: 2, text: "And Moses went up into the mount of God, and the glory of the Lord abode on Mount Sinai, and a cloud overshadowed it six days." },
  { book: "Jubilees", chapter: 1, verse: 3, text: "And He called to Moses on the seventh day out of the midst of the cloud, and the appearance of the glory of the Lord was like a flaming fire on the top of the mount." },
  { book: "Jubilees", chapter: 1, verse: 4, text: "And Moses was on the Mount forty days and forty nights, and God taught him the earlier and the later history of the division of all the days of the law and of the testimony." },
  { book: "Jubilees", chapter: 1, verse: 5, text: "And He said: 'Incline thine heart to every word which I shall speak to thee on this mount, and write them in a book in order that their generations may see how I have not forsaken them for all the evil which they have wrought in transgressing the covenant which I establish between Me and thee for their generations this day on Mount Sinai." },
  { book: "Jubilees", chapter: 1, verse: 6, text: "And thus it will come to pass when all these things come upon them, that they will recognise that I am more righteous than they in all their judgments and in all their actions, and they will recognise that I have been truly with them." },
  { book: "Jubilees", chapter: 1, verse: 7, text: "And do thou write for thyself all these words which I declare unto, thee this day, for I know their rebellion and their stiff neck, before I bring them into the land of which I sware to their fathers, to Abraham and to Isaac and to Jacob, saying: ' Unto your seed will I give a land flowing with milk and honey." },
  { book: "Jubilees", chapter: 1, verse: 8, text: "And they will eat and be satisfied, and they will turn to strange gods, to (gods) which cannot deliver them from aught of their tribulation: and this witness shall be heard for a witness against them. For they will forget all My commandments, (even) all that I command them, and they will walk after the Gentiles, and after their uncleanness, and after their shame, and will serve their gods, and these will prove unto them an offence and a tribulation and an affliction and a snare." },
  { book: "Jubilees", chapter: 1, verse: 9, text: "And many will perish and they will be taken captive, and will fall into the hands of the enemy, because they have forsaken My ordinances and My commandments, and the festivals of My covenant, and My sabbaths, and My holy place which I have hallowed for Myself in their midst, and My tabernacle, and My sanctuary, which I have hallowed for Myself in the midst of the land, that I should set my name upon it, and that it should dwell (there)." },
  { book: "Jubilees", chapter: 1, verse: 10, text: "And they will make to themselves high places and groves and graven images, and they will worship, each his own (graven image), so as to go astray, and they will sacrifice their children to demons, and to all the works of the error of their hearts." },
  { book: "Jubilees", chapter: 1, verse: 11, text: "And I will send witnesses unto them, that I may witness against them, but they will not hear, and will slay the witnesses also, and they will persecute those who seek the law, and they will abrogate and change everything so as to work evil before My eyes." },
  { book: "Jubilees", chapter: 1, verse: 12, text: "And I will hide My face from them, and I will deliver them into the hand of the Gentiles for captivity, and for a prey, and for devouring, and I will remove them from the midst of the land, and I will scatter them amongst the Gentiles." },
  { book: "Jubilees", chapter: 1, verse: 13, text: "And they will forget all My law and all My commandments and all My judgments, and will go astray as to new moons, and sabbaths, and festivals, and jubilees, and ordinances." },
  { book: "Jubilees", chapter: 1, verse: 14, text: "And after this they will turn to Me from amongst the Gentiles with all their heart and with all their soul and with all their strength, and I will gather them from amongst all the Gentiles, and they will seek me, so that I shall be found of them, when they seek me with all their heart and with all their soul." },
  { book: "Jubilees", chapter: 1, verse: 15, text: "And I will disclose to them abounding peace with righteousness, and I will remove them the plant of uprightness, with all My heart and with all My soul, and they shall be for a blessing and not for a curse, and they shall be the head and not the tail." },
  { book: "Jubilees", chapter: 1, verse: 16, text: "And I will build My sanctuary in their midst, and I will dwell with them, and I will be their God and they shall be My people in truth and righteousness." },
  { book: "Jubilees", chapter: 1, verse: 17, text: "And I will not forsake them nor fail them; for I am the Lord their God.'" },
  { book: "Jubilees", chapter: 1, verse: 18, text: "And Moses fell on his face and prayed and said, 'O Lord my God, do not forsake Thy people and Thy inheritance, so that they should wander in the error of their hearts, and do not deliver them into the hands of their enemies, the Gentiles, lest they should rule over them and cause them to sin against Thee." },
  { book: "Jubilees", chapter: 1, verse: 19, text: "Let thy mercy, O Lord, be lifted up upon Thy people, and create in them an upright spirit, and let not the spirit of Beliar rule over them to accuse them before Thee, and to ensnare them from all the paths of righteousness, so that they may perish from before Thy face." },
  { book: "Jubilees", chapter: 1, verse: 20, text: "But they are Thy people and Thy inheritance, which thou hast delivered with thy great power from the hands of the Egyptians: create in them a clean heart and a holy spirit, and let them not be ensnared in their sins from henceforth until eternity.'" },
  { book: "Jubilees", chapter: 1, verse: 21, text: "And the Lord said unto Moses: 'I know their contrariness and their thoughts and their stiffneckedness, and they will not be obedient till they confess their own sin and the sin of their fathers." },
  { book: "Jubilees", chapter: 1, verse: 22, text: "And after this they will turn to Me in all uprightness and with all (their) heart and with all (their) soul, and I will circumcise the foreskin of their heart and the foreskin of the heart of their seed, and I will create in them a holy spirit, and I will cleanse them so that they shall not turn away from Me from that day unto eternity." },
  { book: "Jubilees", chapter: 1, verse: 23, text: "And their souls will cleave to Me and to all My commandments, and they will fulfil My commandments, and I will be their Father and they shall be My children." },
  { book: "Jubilees", chapter: 1, verse: 24, text: "And they all shall be called children of the living God, and every angel and every spirit shall know, yea, they shall know that these are My children, and that I am their Father in uprightness and righteousness, and that I love them." },
  { book: "Jubilees", chapter: 1, verse: 25, text: "And do thou write down for thyself all these words which I declare unto thee on this mountain, the first and the last, which shall come to pass in all the divisions of the days in the law and in the testimony and in the weeks and the jubilees unto eternity, until I descend and dwell with them throughout eternity.'" },
  { book: "Jubilees", chapter: 1, verse: 26, text: "And He said to the angel of the presence: 'Write for Moses from the beginning of creation till My sanctuary has been built among them for all eternity." },
  { book: "Jubilees", chapter: 1, verse: 27, text: "And the Lord will appear to the eyes of all, and all shall know that I am the God of Israel and the Father of all the children of Jacob, and King on Mount Zion for all eternity. And Zion and Jerusalem shall be holy.'" },
  { book: "Jubilees", chapter: 1, verse: 28, text: "And the angel of the presence who went before the camp of Israel took the tables of the divisions of the years -from the time of the creation- of the law and of the testimony of the weeks of the jubilees, according to the individual years, according to all the number of the jubilees [according, to the individual years], from the day of the [new] creation when the heavens and the earth shall be renewed and all their creation according to the powers of the heaven, and according to all the creation of the earth, until the sanctuary of the Lord shall be made in Jerusalem on Mount Zion, and all the luminaries be renewed for healing and for peace and for blessing for all the elect of Israel, and that thus it may be from that day and unto all the days of the earth." },
  { book: "Jubilees", chapter: 2, verse: 1, text: "And the angel of the presence spake to Moses according to the word of the Lord, saying: Write the complete history of the creation, how in six days the Lord God finished all His works and all that He created, and kept Sabbath on the seventh day and hallowed it for all ages, and appointed it as a sign for all His works." },
  { book: "Jubilees", chapter: 2, verse: 2, text: "For on the first day He created the heavens which are above and the earth and the waters and all the spirits which serve before him -the angels of the presence, and the angels of sanctification, and the angels [of the spirit of fire and the angels] of the spirit of the winds, and the angels of the spirit of the clouds, and of darkness, and of snow and of hail and of hoar frost, and the angels of the voices and of the thunder and of the lightning, and the angels of the spirits of cold and of heat, and of winter and of spring and of autumn and of summer and of all the spirits of his creatures which are in the heavens and on the earth, (He created) the abysses and the darkness, eventide <and night>, and the light, dawn and day, which He hath prepared in the knowledge of his heart." },
  { book: "Jubilees", chapter: 2, verse: 3, text: "And thereupon we saw His works, and praised Him, and lauded before Him on account of all His works; for seven great works did He create on the first day." },
  { book: "Jubilees", chapter: 2, verse: 4, text: "And on the second day He created the firmament in the midst of the waters, and the waters were divided on that day -half of them went up above and half of them went down below the firmament (that was) in the midst over the face of the whole earth. And this was the only work (God) created on the second day." },
  { book: "Jubilees", chapter: 2, verse: 5, text: "And on the third day He commanded the waters to pass from off the face of the whole earth into one place, and the dry land to appear." },
  { book: "Jubilees", chapter: 2, verse: 6, text: "And the waters did so as He commanded them, and they retired from off the face of the earth into one place outside of this firmament, and the dry land appeared." },
  { book: "Jubilees", chapter: 2, verse: 7, text: "And on that day He created for them all the seas according to their separate gathering-places, and all the rivers, and the gatherings of the waters in the mountains and on all the earth, and all the lakes, and all the dew of the earth, and the seed which is sown, and all sprouting things, and fruit-bearing trees, and trees of the wood, and the garden of Eden, in Eden and all plants after their kind." },
  { book: "Jubilees", chapter: 2, verse: 8, text: "These four great works God created on the third day. And on the fourth day He created the sun and the moon and the stars, and set them in the firmament of the heaven, to give light upon all the earth, and to rule over the day and the night, and divide the light from the darkness." },
  { book: "Jubilees", chapter: 2, verse: 9, text: "And God appointed the sun to be a great sign on the earth for days and for sabbaths and for months and for feasts and for years and for sabbaths of years and for jubilees and for all seasons of the years." },
  { book: "Jubilees", chapter: 2, verse: 10, text: "And it divideth the light from the darkness [and] for prosperity, that all things may prosper which shoot and grow on the earth." },
  { book: "Jubilees", chapter: 2, verse: 11, text: "These three kinds He made on the fourth day. And on the fifth day He created great sea monsters in the depths of the waters, for these were the first things of flesh that were created by his hands, the fish and everything that moves in the waters, and everything that flies, the birds and all their kind." },
  { book: "Jubilees", chapter: 2, verse: 12, text: "And the sun rose above them to prosper (them), and above everything that was on the earth, everything that shoots out of the earth, and all fruit-bearing trees, and all flesh." },
  { book: "Jubilees", chapter: 2, verse: 13, text: "These three kinds He created on the fifth day. And on the sixth day He created all the animals of the earth, and all cattle, and everything that moves on the earth." },
  { book: "Jubilees", chapter: 2, verse: 14, text: "And after all this He created man, a man and a woman created He them, and gave him dominion over all that is upon the earth, and in the seas, and over everything that flies, and over beasts and over cattle, and over everything that moves on the earth, and over the whole earth, and over all this He gave him dominion." },
  { book: "Jubilees", chapter: 2, verse: 15, text: "And these four kinds He created on the sixth day. And there were altogether two and twenty kinds." },
  { book: "Jubilees", chapter: 2, verse: 16, text: "And He finished all his work on the sixth day -all that is in the heavens and on the earth, and in the seas and in the abysses, and in the light and in the darkness, and in everything." },
  { book: "Jubilees", chapter: 2, verse: 17, text: "And He gave us a great sign, the Sabbath day, that we should work six days, but keep Sabbath on the seventh day from all work." },
  { book: "Jubilees", chapter: 2, verse: 18, text: "And all the angels of the presence, and all the angels of sanctification, these two great classes -He hath bidden us to keep the Sabbath with Him in heaven and on earth." },
  { book: "Jubilees", chapter: 2, verse: 19, text: "And He said unto us: 'Behold, I will separate unto Myself a people from among all the peoples, and these shall keep the Sabbath day, and I will sanctify them unto Myself as My people, and will bless them; as I have sanctified the Sabbath day and do sanctify (it) unto Myself, even so will I bless them, and they shall be My people and I will be their God." },
  { book: "Jubilees", chapter: 2, verse: 20, text: "And I have chosen the seed of Jacob from amongst all that I have seen, and have written him down as My first-born son,and have sanctified him unto Myself for ever and ever; and I will teach them the Sabbath day, that they may keep Sabbath thereon from all work.'" },
  { book: "Jubilees", chapter: 2, verse: 21, text: "And thus He created therein a sign in accordance with which they should keep Sabbath with us on the seventh day, to eat and to drink, and to bless Him who has created all things as He has blessed and sanctified unto Himself a peculiar people above all peoples, and that they should keep Sabbath together with us." },
  { book: "Jubilees", chapter: 2, verse: 22, text: "And He caused His commands to ascend as a sweet savour acceptable before Him all the days . . ." },
  { book: "Jubilees", chapter: 2, verse: 23, text: "There (were) two and twenty heads of mankind from Adam to Jacob, and two and twenty kinds of work were made until the seventh day; this is blessed and holy; and the former also is blessed and holy; and this one serves with that one for sanctification and blessing." },
  { book: "Jubilees", chapter: 2, verse: 24, text: "And to this (Jacob and his seed) it was granted that they should always be the blessed and holy ones of the first testimony and law, even as He had sanctified and blessed the Sabbath day on the seventh day." },
  { book: "Jubilees", chapter: 2, verse: 25, text: "He created heaven and earth and everything that He created in six days, and God made the seventh day holy, for all His works; therefore He commanded on its behalf that, whoever does any work thereon shall die, and that he who defiles it shall surely die." },
  { book: "Jubilees", chapter: 2, verse: 26, text: "Wherefore do thou command the children of Israel to observe this day that they may keep it holy and not do thereon any work, and not to defile it, as it is holier than all other days." },
  { book: "Jubilees", chapter: 2, verse: 27, text: "And whoever profanes it shall surely die, and whoever does thereon any work shall surely die eternally, that the children of Israel may observe this day throughout their generations, and not be rooted out of the land; for it is a holy day and a blessed day." },
  { book: "Jubilees", chapter: 2, verse: 28, text: "And every one who observes it and keeps Sabbath thereon from all his work, will be holy and blessed throughout all days like unto us." },
  { book: "Jubilees", chapter: 2, verse: 29, text: "Declare and say to the children of Israel the law of this day both that they should keep Sabbath thereon, and that they should not forsake it in the error of their hearts; (and) that it is not lawful to do any work thereon which is unseemly, to do thereon their own pleasure, and that they should not prepare thereon anything to be eaten or drunk, and (that it is not lawful) to draw water, or bring in or take out thereon through their gates any burden, which they had not prepared for themselves on the sixth day in their dwellings." },
  { book: "Jubilees", chapter: 2, verse: 30, text: "And they shall not bring in nor take out from house to house on that day; for that day is more holy and blessed than any jubilee day of the jubilees; on this we kept Sabbath in the heavens before it was made known to any flesh to keep Sabbath thereon on the earth." },
  { book: "Jubilees", chapter: 2, verse: 31, text: "And the Creator of all things blessed it, but he did not sanctify all peoples and nations to keep Sabbath thereon, but Israel alone: them alone he permitted to eat and drink and to keep Sabbath thereon on the earth." },
  { book: "Jubilees", chapter: 2, verse: 32, text: "And the Creator of all things blessed this day which He had created for blessing and holiness and glory above all days." },
  { book: "Jubilees", chapter: 2, verse: 33, text: "This law and testimony was given to the children of Israel as a law for ever unto their generations." },
  { book: "Jubilees", chapter: 3, verse: 1, text: "And on the six days of the second week we brought, according to the word of God, unto Adam all the beasts, and all the cattle, and all the birds, and everything that moves on the earth, and everything that moves in the water, according to their kinds, and according to their types: the beasts on the first day; the cattle on the second day; the birds on the third day; and all that which moves on the earth on the fourth day; and that which moves in the water on the fifth day." },
  { book: "Jubilees", chapter: 3, verse: 2, text: "And Adam named them all by their respective names, and as he called them, so was their name." },
  { book: "Jubilees", chapter: 3, verse: 3, text: "And on these five days Adam saw all these, male and female, according to every kind that was on the earth, but he was alone and found no helpmeet for him." },
  { book: "Jubilees", chapter: 3, verse: 4, text: "And the Lord said unto us: 'It is not good that the man should be alone: let us make a helpmeet for him.'" },
  { book: "Jubilees", chapter: 3, verse: 5, text: "And the Lord our God caused a deep sleep to fall upon him, and he slept, and He took for the woman one rib from amongst his ribs, and this rib was the origin of the woman from amongst his ribs, and He built up the flesh in its stead, and built the woman." },
  { book: "Jubilees", chapter: 3, verse: 6, text: "And He awaked Adam out of his sleep and on awaking he rose on the sixth day, and He brought her to him, and he knew her, and said unto her: 'This is now bone of my bones and flesh of my flesh; she shall be called [my] wife; because she was taken from her husband.'" },
  { book: "Jubilees", chapter: 3, verse: 7, text: "Therefore shall man and wife be one and therefore shall a man leave his father and his mother, and cleave unto his wife, and they shall be one flesh." },
  { book: "Jubilees", chapter: 3, verse: 8, text: "In the first week was Adam created, and the rib -his wife: in the second week He showed her unto him: and for this reason the commandment was given to keep in their defilement, for a male seven days, and for a female twice seven days." },
  { book: "Jubilees", chapter: 3, verse: 9, text: "And after Adam had completed forty days in the land where he had been created, we brought him into the garden of Eden to till and keep it, but his wife they brought in on the eightieth day, and after this she entered into the garden of Eden." },
  { book: "Jubilees", chapter: 3, verse: 10, text: "And for this reason the commandment is written on the heavenly tablets in regard to her that gives birth: 'if she bears a male, she shall remain in her uncleanness seven days according to the first week of days, and thirty and three days shall she remain in the blood of her purifying, and she shall not touch any hallowed thing, nor enter into the sanctuary, until she accomplishes these days which (are enjoined) in the case of a male child." },
  { book: "Jubilees", chapter: 3, verse: 11, text: "But in the case of a female child she shall remain in her uncleanness two weeks of days, according to the first two weeks, and sixty-six days in the blood of her purification, and they will be in all eighty days.'" },
  { book: "Jubilees", chapter: 3, verse: 12, text: "And when she had completed these eighty days we brought her into the garden of Eden, for it is holier than all the earth besides and every tree that is planted in it is holy." },
  { book: "Jubilees", chapter: 3, verse: 13, text: "Therefore, there was ordained regarding her who bears a male or a female child the statute of those days that she should touch no hallowed thing, nor enter into the sanctuary until these days for the male or female child are accomplished." },
  { book: "Jubilees", chapter: 3, verse: 14, text: "This is the law and testimony which was written down for Israel, in order that they should observe (it) all the days." },
  { book: "Jubilees", chapter: 3, verse: 15, text: "And in the first week of the first jubilee, [1-7 A.M.] Adam and his wife were in the garden of Eden for seven years tilling and keeping it, and we gave him work and we instructed him to do everything that is suitable for tillage." },
  { book: "Jubilees", chapter: 3, verse: 16, text: "And he tilled (the garden), and was naked and knew it not, and was not ashamed, and he protected the garden from the birds and beasts and cattle, and gathered its fruit, and eat, and put aside the residue for himself and for his wife [and put aside that which was being kept]." },
  { book: "Jubilees", chapter: 3, verse: 17, text: "And after the completion of the seven years, which he had completed there, seven years exactly, [8 A.M.] and in the second month, on the seventeenth day (of the month), the serpent came and approached the woman, and the serpent said to the woman, 'Hath God commanded you, saying, Ye shall not eat of every tree of the garden?'" },
  { book: "Jubilees", chapter: 3, verse: 18, text: "And she said to it, 'Of all the fruit of the trees of the garden God hath said unto us, Eat; but of the fruit of the tree which is in the midst of the garden God hath said unto us, 'Ye shall not eat thereof, neither shall ye touch it, lest ye die.'" },
  { book: "Jubilees", chapter: 3, verse: 19, text: "And the serpent said unto the woman, 'Ye shall not surely die: for God doth know that on the day ye shall eat thereof, your eyes will be opened, and ye will be as gods, and ye will know good and evil." },
  { book: "Jubilees", chapter: 3, verse: 20, text: "And the woman saw the tree that it was agreeable and pleasant to the eye, and that its fruit was good for food, and she took thereof and eat." },
  { book: "Jubilees", chapter: 3, verse: 21, text: "And when she had first covered her shame with figleaves, she gave thereof to Adam and he eat, and his eyes were opened, and he saw that he was naked." },
  { book: "Jubilees", chapter: 3, verse: 22, text: "And he took figleaves and sewed (them) together, and made an apron for himself, and ,covered his shame." },
  { book: "Jubilees", chapter: 3, verse: 23, text: "And God cursed the serpent, and was wroth with it for ever . . ." },
  { book: "Jubilees", chapter: 3, verse: 24, text: "And He was wroth with the woman, because she harkened to the voice of the serpent, and did eat; and He said unto her: 'I will greatly multiply thy sorrow and thy pains: in sorrow thou shalt bring forth children, and thy return shall be unto thy husband, and he will rule over thee.'" },
  { book: "Jubilees", chapter: 3, verse: 25, text: "And to Adam also he said, ' Because thou hast harkened unto the voice of thy wife, and hast eaten of the tree of which I commanded thee that thou shouldst not eat thereof, cursed be the ground for thy sake: thorns and thistles shall it bring forth to thee, and thou shalt eat thy bread in the sweat of thy face, till thou returnest to the earth from whence thou wast taken; for earth thou art, and unto earth shalt thou return.'" },
  { book: "Jubilees", chapter: 3, verse: 26, text: "And He made for them coats of skin, and clothed them, and sent them forth from the Garden of Eden." },
  { book: "Jubilees", chapter: 3, verse: 27, text: "And on that day on which Adam went forth from the Garden, he offered as a sweet savour an offering, frankincense, galbanum, and stacte, and spices in the morning with the rising of the sun from the day when he covered his shame." },
  { book: "Jubilees", chapter: 3, verse: 28, text: "And on that day was closed the mouth of all beasts, and of cattle, and of birds, and of whatever walks, and of whatever moves, so that they could no longer speak: for they had all spoken one with another with one lip and with one tongue." },
  { book: "Jubilees", chapter: 3, verse: 29, text: "And He sent out of the Garden of Eden all flesh that was in the Garden of Eden, and all flesh was scattered according to its kinds, and according to its types unto the places which had been created for them." },
  { book: "Jubilees", chapter: 3, verse: 30, text: "And to Adam alone did He give (the wherewithal) to cover his shame, of all the beasts and cattle." },
  { book: "Jubilees", chapter: 3, verse: 31, text: "On this account, it is prescribed on the heavenly tablets as touching all those who know the judgment of the law, that they should cover their shame, and should not uncover themselves as the Gentiles uncover themselves." },
  { book: "Jubilees", chapter: 3, verse: 32, text: "And on the new moon of the fourth month, Adam and his wife went forth from the Garden of Eden, and they dwelt in the land of Elda in the land of their creation." },
  { book: "Jubilees", chapter: 3, verse: 33, text: "And Adam called the name of his wife Eve." },
  { book: "Jubilees", chapter: 3, verse: 34, text: "And they had no son till the first jubilee, [8 A.M.] and after this he knew her." },
  { book: "Jubilees", chapter: 3, verse: 35, text: "Now he tilled the land as he had been instructed in the Garden of Eden." },
  { book: "Jubilees", chapter: 4, verse: 1, text: "And in the third week in the second jubilee [64-70 A.M.] she gave birth to Cain, and in the fourth [71-77 A.M.] she gave birth to Abel, and in the fifth [78-84 A.M.] she gave birth to her daughter Âwân." },
  { book: "Jubilees", chapter: 4, verse: 2, text: "And in the first (year) of the third jubilee [99-105 A.M.], Cain slew Abel because (God) accepted the sacrifice of Abel, and did not accept the offering of Cain." },
  { book: "Jubilees", chapter: 4, verse: 3, text: "And he slew him in the field: and his blood cried from the ground to heaven, complaining because he had slain him." },
  { book: "Jubilees", chapter: 4, verse: 4, text: "And the Lord reproved Cain because of Abel, because he had slain him, and he made him a fugitive on the earth because of the blood of his brother, and he cursed him upon the earth." },
  { book: "Jubilees", chapter: 4, verse: 5, text: "And on this account it is written on the heavenly tables, 'Cursed is ,he who smites his neighbour treacherously, and let all who have seen and heard say, So be it; and the man who has seen and not declared (it), let him be accursed as the other.'" },
  { book: "Jubilees", chapter: 4, verse: 6, text: "And for this reason we announce when we come before the Lord our God all the sin which is committed in heaven and on earth, and in light and in darkness, and everywhere." },
  { book: "Jubilees", chapter: 4, verse: 7, text: "And Adam and his wife mourned for Abel four weeks of years, [99-127 A.M] and in the fourth year of the fifth week [130 A.M.] they became joyful, and Adam knew his wife again, and she bare him a son, and he called his name Seth; for he said 'GOD has raised up a second seed unto us on the earth instead of Abel; for Cain slew him.'" },
  { book: "Jubilees", chapter: 4, verse: 8, text: "And in the sixth week [134-40 A.M.] he begat his daughter Azûrâ." },
  { book: "Jubilees", chapter: 4, verse: 9, text: "And Cain took Âwân his sister to be his wife and she bare him Enoch at the close of the fourth jubilee. [190-196 A.M.] And in the first year of the first week of the fifth jubilee, [197 A.M.] houses were built on the earth, and Cain built a city, and called its name after the name of his son Enoch." },
  { book: "Jubilees", chapter: 4, verse: 10, text: "And Adam knew Eve his wife and she bare yet nine sons." },
  { book: "Jubilees", chapter: 4, verse: 11, text: "And in the fifth week of the fifth jubilee [225-31 A.M.] Seth took Azûrâ his sister to be his wife, and in the fourth (year of the sixth week) [235 A.M.] she bare him Enos." },
  { book: "Jubilees", chapter: 4, verse: 12, text: "He began to call on the name of the Lord on the earth." },
  { book: "Jubilees", chapter: 4, verse: 13, text: "And in the seventh jubilee in the third week [309-15 A.M.] Enos took Nôâm his sister to be his wife, and she bare him a son in the third year of the fifth week, and he called his name Kenan." },
  { book: "Jubilees", chapter: 4, verse: 14, text: "And at the close of the eighth jubilee [325, 386-3992 A.M.] Kenan took Mûalêlêth his sister to be his wife, and she bare him a son in the ninth jubilee, in the first week in the third year of this week, [395 A.M] and he called his name Mahalalel." },
  { book: "Jubilees", chapter: 4, verse: 15, text: "And in the second week of the tenth jubilee [449-55 A.M.] Mahalalel took unto him to wife DinaH, the daughter of Barakiel the daughter of his father's brother, and she bare him a son in the third week in the sixth year, [461 A.M.] and he called his name Jared, for in his days the angels of the Lord descended on the earth, those who are named the Watchers, that they should instruct the children of men, and that they should do judgment and uprightness on the earth." },
  { book: "Jubilees", chapter: 4, verse: 16, text: "And in the eleventh jubilee [512-18 A.M.] Jared took to himself a wife, and her name was Baraka, the daughter of Râsûjâl, a daughter of his father's brother, in the fourth week of this jubilee, [522 A.M.] and she bare him a son in the fifth week, in the fourth year of the jubilee, and he called his name Enoch." },
  { book: "Jubilees", chapter: 4, verse: 17, text: "And he was the first among men that are born on earth who learnt writing and knowledge and wisdom and who wrote down the signs of heaven according to the order of their months in a book, that men might know the seasons of the years according to the order of their separate months." },
  { book: "Jubilees", chapter: 4, verse: 18, text: "And he was the first to write a testimony and he testified to the sons of men among the generations of the earth, and recounted the weeks of the jubilees, and made known to them the days of the years, and set in order the months and recounted the Sabbaths of the years as we made (them), known to him." },
  { book: "Jubilees", chapter: 4, verse: 19, text: "And what was and what will be he saw in a vision of his sleep, as it will happen to the children of men throughout their generations until the day of judgment; he saw and understood everything, and wrote his testimony, and placed the testimony on earth for all the children of men and for their generations." },
  { book: "Jubilees", chapter: 4, verse: 20, text: "And in the twelfth jubilee, [582-88] in the seventh week thereof, he took to himself a wife, and her name was Edna, the daughter of Danel, the daughter of his father's brother, and in the sixth year in this week [587 A.M.] she bare him a son and he called his name Methuselah." },
  { book: "Jubilees", chapter: 4, verse: 21, text: "And he was moreover with the angels of God these six jubilees of years, and they showed him everything which is on earth and in the heavens, the rule of the sun, and he wrote down everything." },
  { book: "Jubilees", chapter: 4, verse: 22, text: "And he testified to the Watchers, who had sinned with the daughters of men; for these had begun to unite themselves, so as to be defiled, with the daughters of men, and Enoch testified against (them) all." },
  { book: "Jubilees", chapter: 4, verse: 23, text: "And he was taken from amongst the children of men, and we conducted him into the Garden of Eden in majesty and honour, and behold there he writes down the condemnation and judgment of the world, and all the wickedness of the children of men." },
  { book: "Jubilees", chapter: 4, verse: 24, text: "And on account of it (God) brought the waters of the flood upon all the land of Eden; for there he was set as a sign and that he should testify against all the children of men, that he should recount all the deeds of the generations until the day of condemnation." },
  { book: "Jubilees", chapter: 4, verse: 25, text: "And he burnt the incense of the sanctuary, (even) sweet spices acceptable before the Lord on the Mount." },
  { book: "Jubilees", chapter: 4, verse: 26, text: "For the Lord has four places on the earth, the Garden of Eden, and the Mount of the East, and this mountain on which thou art this day, Mount Sinai, and Mount Zion (which) will be sanctified in the new creation for a sanctification of the earth; through it will the earth be sanctified from all (its) guilt and its uncleanness through- out the generations of the world." },
  { book: "Jubilees", chapter: 4, verse: 27, text: "And in the fourteenth jubilee [652 A.M.] Methuselah took unto himself a wife, Edna the daughter of Azrial, the daughter of his father's brother, in the third week, in the first year of this week, [701-7 A.M.] and he begat a son and called his name Lamech." },
  { book: "Jubilees", chapter: 4, verse: 28, text: "And in the fifteenth jubilee in the third week Lamech took to himself a wife, and her name was Betenos the daughter of Baraki'il, the daughter of his father's brother, and in this week she bare him a son and he called his name Noah, saying, 'This one will comfort me for my trouble and all my work, and for the ground which the Lord hath cursed.'" },
  { book: "Jubilees", chapter: 4, verse: 29, text: "And at the close of the nineteenth jubilee, in the seventh week in the sixth year [930 A.M.] thereof, Adam died, and all his sons buried him in the land of his creation, and he was the first to be buried in the earth." },
  { book: "Jubilees", chapter: 4, verse: 30, text: "And he lacked seventy years of one thousand years; for one thousand years are as one day in the testimony of the heavens and therefore was it written concerning the tree of knowledge: 'On the day that ye eat thereof ye shall die.' For this reason he did not complete the years of this day; for he died during it." },
  { book: "Jubilees", chapter: 4, verse: 31, text: "At the close of this jubilee Cain was killed after him in the same year; for his house fell upon him and he died in the midst of his house, and he was killed by its stones; for with a stone he had killed Abel, and by a stone was he killed in righteous judgment." },
  { book: "Jubilees", chapter: 4, verse: 32, text: "For this reason it was ordained on the heavenly tablets: With the instrument with which a man kills his neighbour with the same shall he be killed; after the manner that he wounded him, in like manner shall they deal with him.'" },
  { book: "Jubilees", chapter: 4, verse: 33, text: "And in the twenty-fifth [1205 A.M.] jubilee Noah took to himself a wife, and her name was `Emzârâ, the daughter of Râkê'êl, the daughter of his father's brother, in the first year in the fifth week [1207 A.M.]: and in the third year thereof she bare him Shem, in the fifth year thereof [1209 A.M.] she bare him Ham, and in the first year in the sixth week [1212 A.M.] she bare him Japheth." },
  { book: "Jubilees", chapter: 5, verse: 1, text: "And it came to pass when the children of men began to multiply on the face of the earth and daughters were born unto them, that the angels of God saw them on a certain year of this jubilee, that they were beautiful to look upon; and they took themselves wives of all whom they chose, and they bare unto them sons and they were giants." },
  { book: "Jubilees", chapter: 5, verse: 2, text: "And lawlessness increased on the earth and all flesh corrupted its way, alike men and cattle and beasts and birds and everything that walks on the earth -all of them corrupted their ways and their orders, and they began to devour each other, and lawlessness increased on the earth and every imagination of the thoughts of all men (was) thus evil continually." },
  { book: "Jubilees", chapter: 5, verse: 3, text: "And God looked upon the earth, and behold it was corrupt, and all flesh had corrupted its orders, and all that were upon the earth had wrought all manner of evil before His eyes." },
  { book: "Jubilees", chapter: 5, verse: 4, text: "And He said that He would destroy man and all flesh upon the face of the earth which He had created." },
  { book: "Jubilees", chapter: 5, verse: 5, text: "But Noah found grace before the eyes of the Lord." },
  { book: "Jubilees", chapter: 5, verse: 6, text: "And against the angels whom He had sent upon the earth, He was exceedingly wroth, and He gave commandment to root them out of all their dominion, and He bade us to bind them in the depths of the earth, and behold they are bound in the midst of them, and are (kept) separate." },
  { book: "Jubilees", chapter: 5, verse: 7, text: "And against their sons went forth a command from before His face that they should be smitten with the sword, and be removed from under heaven." },
  { book: "Jubilees", chapter: 5, verse: 8, text: "And He said 'My spirit shall not always abide on man; for they also are flesh and their days shall be one hundred and twenty years'." },
  { book: "Jubilees", chapter: 5, verse: 9, text: "And He sent His sword into their midst that each should slay his neighbour, and they began to slay each other till they all fell by the sword and were destroyed from the earth." },
  { book: "Jubilees", chapter: 5, verse: 10, text: "And their fathers were witnesses (of their destruction), and after this they were bound in the depths of the earth for ever, until the day of the great condemnation, when judgment is executed on all those who have corrupted their ways and their works before the Lord." },
  { book: "Jubilees", chapter: 5, verse: 11, text: "And He destroyed all from their places, and there was not left one of them whom He judged not according to all their wickedness." },
  { book: "Jubilees", chapter: 5, verse: 12, text: "And he made for all his works a new and righteous nature, so that they should not sin in their whole nature for ever, but should be all righteous each in his kind alway." },
  { book: "Jubilees", chapter: 5, verse: 13, text: "And the judgment of all is ordained and written on the heavenly tablets in righteousness -even (the judgment of) all who depart from the path which is ordained for them to walk in; and if they walk not therein, judgment is written down for every creature and for every kind." },
  { book: "Jubilees", chapter: 5, verse: 14, text: "And there is nothing in heaven or on earth, or in light or in darkness, or in Sheol or in the depth, or in the place of darkness (which is not judged); and all their judgments are ordained and written and engraved." },
  { book: "Jubilees", chapter: 5, verse: 15, text: "In regard to all He will judge,the great according to his greatness, and the small according to his smallness, and each according to his way." },
  { book: "Jubilees", chapter: 5, verse: 16, text: "And He is not one who will regard the person (of any), nor is He one who will receive gifts, if He says that He will execute judgment on each: if one gave everything that is on the earth, He will not regard the gifts or the person (of any), nor accept anything at his hands, for He is a righteous judge." },
  { book: "Jubilees", chapter: 5, verse: 17, text: "[And of the children of Israel it has been written and ordained: If they turn to him in righteousness He will forgive all their transgressions and pardon all their sins." },
  { book: "Jubilees", chapter: 5, verse: 18, text: "It is written and ordained that He will show mercy to all who turn from all their guilt once each year.]" },
  { book: "Jubilees", chapter: 5, verse: 19, text: "And as for all those who corrupted their ways and their thoughts before the flood, no man's person was accepted save that of Noah alone; for his person was accepted in behalf of his sons, whom (God) saved from the waters of the flood on his account; for his heart was righteous in all his ways, according as it was commanded regarding him, and he had not departed from aught that was ordained for him." },
  { book: "Jubilees", chapter: 5, verse: 20, text: "And the Lord said that he would destroy everything which was upon the earth, both men and cattle, and" },
  { book: "Jubilees", chapter: 5, verse: 21, text: "beasts, and fowls of the air, and that which moveth on the earth. And He commanded Noah to make him an ark, that he might save himself from the waters of the flood." },
  { book: "Jubilees", chapter: 5, verse: 22, text: "And Noah made the ark in all respects as He commanded him, in the twenty-seventh jubilee of years, in the fifth week in the fifth year (on the new moon of the first month). [1307 A.M.]" },
  { book: "Jubilees", chapter: 5, verse: 23, text: "And he entered in the sixth (year) thereof, [1308 A.M.] in the second month, on the new moon of the second month, till the sixteenth; and he entered, and all that we brought to him, into the ark, and the Lord closed it from without on the seventeenth evening." },
  { book: "Jubilees", chapter: 5, verse: 24, text: "And the Lord opened seven flood-gates of heaven, And the mouths of the fountains of the great deep, seven mouths in number." },
  { book: "Jubilees", chapter: 5, verse: 25, text: "And the flood-gates began to pour down water from the heaven forty days and forty nights, And the fountains of the deep also sent up waters, until the whole world was full of water." },
  { book: "Jubilees", chapter: 5, verse: 26, text: "And the waters increased upon the earth: Fifteen cubits did the waters rise above all the high mountains, And the ark was lift up above the earth, And it moved upon the face of the waters." },
  { book: "Jubilees", chapter: 5, verse: 27, text: "And the water prevailed on the face of the earth five months -one hundred and fifty days." },
  { book: "Jubilees", chapter: 5, verse: 28, text: "And the ark went and rested on the top of Lubar, one of the mountains of Ararat." },
  { book: "Jubilees", chapter: 5, verse: 29, text: "And (on the new moon) in the fourth month the fountains of the great deep were closed and the flood-gates of heaven were restrained; and on the new moon of the seventh month all the mouths of the abysses of the earth were opened, and the water began to descend into the deep below." },
  { book: "Jubilees", chapter: 5, verse: 30, text: "And on the new moon of the tenth month the tops of the mountains were seen, and on the new moon of the first month the earth became visible." },
  { book: "Jubilees", chapter: 5, verse: 31, text: "And the waters disappeared from above the earth in the fifth week in the seventh year [1309 A.M.] thereof, and on the seventeenth day in the second month the earth was dry." },
  { book: "Jubilees", chapter: 5, verse: 32, text: "And on the twenty-seventh thereof he opened the ark, and sent forth from it beasts, and cattle, and birds, and every moving thing." },
  { book: "Jubilees", chapter: 6, verse: 1, text: "And on the new moon of the third month he went forth from the ark, and built an altar on that mountain." },
  { book: "Jubilees", chapter: 6, verse: 2, text: "And he made atonement for the earth, and took a kid and made atonement by its blood for all the guilt of the earth; for everything that had been on it had been destroyed, save those that were in the ark with Noah." },
  { book: "Jubilees", chapter: 6, verse: 3, text: "And he placed the fat thereof on the altar, and he took an ox, and a goat, and a sheep and kids, and salt, and a turtle-dove, and the young of a dove, and placed a burnt sacrifice on the altar, and poured thereon an offering mingled with oil, and sprinkled wine and strewed frankincense over everything, and caused a goodly savour to arise, acceptable before the Lord." },
  { book: "Jubilees", chapter: 6, verse: 4, text: "And the Lord smelt the goodly savour, and He made a covenant with him that there should not be any more a flood to destroy the earth; that all the days of the earth seed-time and harvest should never cease; cold and heat, and summer and winter, and day and night should not change their order, nor cease for ever." },
  { book: "Jubilees", chapter: 6, verse: 5, text: "'And you, increase ye and multiply upon the earth, and become many upon it, and be a blessing upon it. The fear of you and the dread of you I will inspire in everything that is on earth and in the sea." },
  { book: "Jubilees", chapter: 6, verse: 6, text: "And behold I have given unto you all beasts, and all winged things, and everything that moves on the earth, and the fish in the waters, and all things for food; as the green herbs, I have given you all things to eat." },
  { book: "Jubilees", chapter: 6, verse: 7, text: "But flesh, with the life thereof, with the blood, ye shall not eat; for the life of all flesh is in the blood, lest your blood of your lives be required. At the hand of every man, at the hand of every (beast) will I require the blood of man." },
  { book: "Jubilees", chapter: 6, verse: 8, text: "Whoso sheddeth man's blood by man shall his blood be shed, for in the image of God made He man." },
  { book: "Jubilees", chapter: 6, verse: 9, text: "And you, increase ye, and multiply on the earth.'" },
  { book: "Jubilees", chapter: 6, verse: 10, text: "And Noah and his sons swore that they would not eat any blood that was in any flesh, and he made a covenant before the Lord God for ever throughout all the generations of the earth in this month." },
  { book: "Jubilees", chapter: 6, verse: 11, text: "On this account He spake to thee that thou shouldst make a covenant with the children of Israel in this month upon the mountain with an oath, and that thou shouldst sprinkle blood upon them because of all the words of the covenant, which the Lord made with them for ever." },
  { book: "Jubilees", chapter: 6, verse: 12, text: "And this testimony is written concerning you that you should observe it continually, so that you should not eat on any day any blood of beasts or birds or cattle during all the days of the earth, and the man who eats the blood of beast or of cattle or of birds during all the days of the earth, he and his seed shall be rooted out of the land." },
  { book: "Jubilees", chapter: 6, verse: 13, text: "And do thou command the children of Israel to eat no blood, so that their names and their seed may be before the Lord our God continually." },
  { book: "Jubilees", chapter: 6, verse: 14, text: "And for this law there is no limit of days, for it is for ever. They shall observe it throughout their generations, so that they may continue supplicating on your behalf with blood before the altar; every day and at the time of morning and evening they shall seek forgiveness on your behalf perpetually before the Lord that they may keep it and not be rooted out." },
  { book: "Jubilees", chapter: 6, verse: 15, text: "And He gave to Noah and his sons a sign that there should not again be a flood on the earth." },
  { book: "Jubilees", chapter: 6, verse: 16, text: "He set His bow in the cloud for a sign of the eternal covenant that there should not again be a flood on the earth to destroy it all the days of the earth." },
  { book: "Jubilees", chapter: 6, verse: 17, text: "For this reason it is ordained and written on the heavenly tablets, that they should celebrate the feast of weeks in this month once a year, to renew the covenant every year." },
  { book: "Jubilees", chapter: 6, verse: 18, text: "And this whole festival was celebrated in heaven from the day of creation till the days of Noah -twenty-six jubilees and five weeks of years [1309-1659 A.M.]: and Noah and his sons observed it for seven jubilees and one week of years, till the day of Noah's death, and from the day of Noah's death his sons did away with (it) until the days of Abraham, and they eat blood." },
  { book: "Jubilees", chapter: 6, verse: 19, text: "But Abraham observed it, and Isaac and Jacob and his children observed it up to thy days, and in thy days the children of Israel forgot it until ye celebrated it anew on this mountain." },
  { book: "Jubilees", chapter: 6, verse: 20, text: "And do thou command the children of Israel to observe this festival in all their generations for a commandment unto them: one day in the year in this month they shall celebrate the festival." },
  { book: "Jubilees", chapter: 6, verse: 21, text: "For it is the feast of weeks and the feast of first fruits: this feast is twofold and of a double nature: according to what is written and engraven concerning it, celebrate it." },
  { book: "Jubilees", chapter: 6, verse: 22, text: "For I have written in the book of the first law, in that which I have written for thee, that thou shouldst celebrate it in its season, one day in the year, and I explained to thee its sacrifices that the children of Israel should remember and should celebrate it throughout their generations in this month, one day in every year." },
  { book: "Jubilees", chapter: 6, verse: 23, text: "And on the new moon of the first month, and on the new moon of the fourth month, and on the new moon of the seventh month, and on the new moon of the tenth month are the days of remembrance, and the days of the seasons in the four divisions of the year. These are written and ordained as a testimony for ever." },
  { book: "Jubilees", chapter: 6, verse: 24, text: "And Noah ordained them for himself as feasts for the generations for ever, so that they have become thereby a memorial unto him." },
  { book: "Jubilees", chapter: 6, verse: 25, text: "And on the new moon of the first month he was bidden to make for himself an ark, and on that (day) the earth became dry and he opened (the ark) and saw the earth." },
  { book: "Jubilees", chapter: 6, verse: 26, text: "And on the new moon of the fourth month the mouths of the depths of the abyss beneath were closed. And on the new moon of the seventh month all the mouths of the abysses of the earth were opened, and the waters began to descend into them." },
  { book: "Jubilees", chapter: 6, verse: 27, text: "And on the new moon of the tenth month the tops of the mountains were seen, and Noah was glad." },
  { book: "Jubilees", chapter: 6, verse: 28, text: "And on this account he ordained them for himself as feasts for a memorial for ever, and thus are they ordained." },
  { book: "Jubilees", chapter: 6, verse: 29, text: "And they placed them on the heavenly tablets, each had thirteen weeks; from one to another (passed) their memorial, from the first to the second, and from the second to the third, and from the third to the fourth." },
  { book: "Jubilees", chapter: 6, verse: 30, text: "And all the days of the commandment will be two and fifty weeks of days, and (these will make) the entire year complete. Thus it is engraven and ordained on the heavenly tablets." },
  { book: "Jubilees", chapter: 6, verse: 31, text: "And there is no neglecting (this commandment) for a single year or from year to year." },
  { book: "Jubilees", chapter: 6, verse: 32, text: "And command thou the children of Israel that they observe the years according to this reckoning- three hundred and sixty-four days, and (these) will constitute a complete year, and they will not disturb its time from its days and from its feasts; for everything will fall out in them according to their testimony, and they will not leave out any day nor disturb any feasts." },
  { book: "Jubilees", chapter: 6, verse: 33, text: "But if they do neglect and do not observe them according to His commandment, then they will disturb all their seasons and the years will be dislodged from this (order), [and they will disturb the seasons and the years will be dislodged] and they will neglect their ordinances." },
  { book: "Jubilees", chapter: 6, verse: 34, text: "And all the children of Israel will forget and will not find the path of the years, and will forget the new moons, and seasons, and sabbaths and they will go wrong as to all the order of the years." },
  { book: "Jubilees", chapter: 6, verse: 35, text: "For I know and from henceforth will I declare it unto thee, and it is not of my own devising; for the book (lies) written before me, and on the heavenly tablets the division of days is ordained, lest they forget the feasts of the covenant and walk according to the feasts of the Gentiles after their error and after their ignorance." },
  { book: "Jubilees", chapter: 6, verse: 36, text: "For there will be those who will assuredly make observations of the moon -how (it) disturbs the seasons and comes in from year to year ten days too soon." },
  { book: "Jubilees", chapter: 6, verse: 37, text: "For this reason the years will come upon them when they will disturb (the order), and make an abominable (day) the day of testimony, and an unclean day a feast day, and they will confound all the days, the holy with the unclean, and the unclean day with the holy; for they will go wrong as to the months and sabbaths and feasts and jubilees." },
  { book: "Jubilees", chapter: 6, verse: 38, text: "For this reason I command and testify to thee that thou mayst testify to them; for after thy death thy children will disturb (them), so that they will not make the year three hundred and sixty-four days only, and for this reason they will go wrong as to the new moons and seasons and sabbaths and festivals, and they will eat all kinds of blood with all kinds of flesh." },
  { book: "Jubilees", chapter: 7, verse: 1, text: "And in the seventh week in the first year [1317 A.M.] thereof, in this jubilee, Noah planted vines on the mountain on which the ark had rested, named Lubar, one of the Ararat Mountains, and they produced fruit in the fourth year, [1320 A.M.] and he guarded their fruit, and gathered it in this year in the seventh month." },
  { book: "Jubilees", chapter: 7, verse: 2, text: "And he made wine therefrom and put it into a vessel, and kept it until the fifth year, [1321 A.M.] until the first day, on the new moon of the first month." },
  { book: "Jubilees", chapter: 7, verse: 3, text: "And he celebrated with joy the day of this feast, and he made a burnt sacrifice unto the Lord, one young ox and one ram, and seven sheep, each a year old, and a kid of the goats, that he might make atonement thereby for himself and his sons." },
  { book: "Jubilees", chapter: 7, verse: 4, text: "And he prepared the kid first, and placed some of its blood on the flesh that was on the altar which he had made, and all the fat he laid on the altar where he made the burnt sacrifice, and the ox and the ram and the sheep, and he laid all their flesh upon the altar." },
  { book: "Jubilees", chapter: 7, verse: 5, text: "And he placed all their offerings mingled with oil upon it, and afterwards he sprinkled wine on the fire which he had previously made on the altar, and he placed incense on the altar and caused a sweet savour to ascend acceptable before the Lord his God." },
  { book: "Jubilees", chapter: 7, verse: 6, text: "And he rejoiced and drank of this wine, he and his children with joy." },
  { book: "Jubilees", chapter: 7, verse: 7, text: "And it was evening, and he went into his tent, and being drunken he lay down and slept, and was uncovered in his tent as he slept." },
  { book: "Jubilees", chapter: 7, verse: 8, text: "And Ham saw Noah his father naked, and went forth and told his two brethren without." },
  { book: "Jubilees", chapter: 7, verse: 9, text: "And Shem took his garment and arose, he and Japheth, and they placed the garment on their shoulders and went backward and covered the shame of their father, and their faces were backward." },
  { book: "Jubilees", chapter: 7, verse: 10, text: "And Noah awoke from his sleep and knew all that his younger son had done unto him, and he cursed his son and said: 'Cursed be Canaan; an enslaved servant shall he be unto his brethren.'" },
  { book: "Jubilees", chapter: 7, verse: 11, text: "And he blessed Shem, and said: 'Blessed be the Lord God of Shem, and Canaan shall be his servant." },
  { book: "Jubilees", chapter: 7, verse: 12, text: "God shall enlarge Japheth, and God shall dwell in the dwelling of Shem, and Canaan shall be his servant.'" },
  { book: "Jubilees", chapter: 7, verse: 13, text: "And Ham knew that his father had cursed his younger son, and he was displeased that he had cursed his son. and he parted from his father, he and his sons with him, Cush and Mizraim and Put and Canaan." },
  { book: "Jubilees", chapter: 7, verse: 14, text: "And he built for himself a city and called its name after the name of his wife Ne'elatama'uk." },
  { book: "Jubilees", chapter: 7, verse: 15, text: "And Japheth saw it, and became envious of his brother, and he too built for himself a city, and he called its name after the name of his wife 'Adataneses." },
  { book: "Jubilees", chapter: 7, verse: 16, text: "And Shem dwelt with his father Noah, and he built a city close to his father on the mountain, and he too called its name after the name of his wife Sedeqetelebab." },
  { book: "Jubilees", chapter: 7, verse: 17, text: "And behold these three cities are near Mount Lubar; Sedeqetelebab fronting the mountain on its east; and Na'eltama'uk on the south; 'Adatan'eses towards the west." },
  { book: "Jubilees", chapter: 7, verse: 18, text: "And these are the sons of Shem: Elam, and Asshur, and Arpachshad -this (son) was born two years after the flood- and Lud, and Aram." },
  { book: "Jubilees", chapter: 7, verse: 19, text: "The sons of Japheth: Gomer and Magog and Madai and Javan, Tubal and Meshech and Tiras: these are the sons of Noah." },
  { book: "Jubilees", chapter: 7, verse: 20, text: "And in the twenty-eighth jubilee [1324-1372 A.M.] Noah began to enjoin upon his sons' sons the ordinances and commandments, and all the judgments that he knew, and he exhorted his sons to observe righteousness, and to cover the shame of their flesh, and to bless their Creator, and honour father and mother, and love their neighbour, and guard their souls from fornication and uncleanness and all iniquity." },
  { book: "Jubilees", chapter: 7, verse: 21, text: "For owing to these three things came the flood upon the earth, namely, owing to the fornication wherein the Watchers against the law of their ordinances went a whoring after the daughters of men, and took themselves wives of all which they chose: and they made the beginning of uncleanness." },
  { book: "Jubilees", chapter: 7, verse: 22, text: "And they begat sons the Naphidim, and they were all unlike, and they devoured one another: and the Giants slew the Naphil, and the Naphil slew the Eljo, and the Eljo mankind, and one man another." },
  { book: "Jubilees", chapter: 7, verse: 23, text: "And every one sold himself to work iniquity and to shed much blood, and the earth was filled with iniquity." },
  { book: "Jubilees", chapter: 7, verse: 24, text: "And after this they sinned against the beasts and birds, and all that moves and walks on the earth: and much blood was shed on the earth, and every imagination and desire of men imagined vanity and evil continually." },
  { book: "Jubilees", chapter: 7, verse: 25, text: "And the Lord destroyed everything from off the face of the earth; because of the wickedness of their deeds, and because of the blood which they had shed in the midst of the earth He destroyed everything." },
  { book: "Jubilees", chapter: 7, verse: 26, text: "'And we were left, I and you, my sons, and everything that entered with us into the ark, and behold I see your works before me that ye do not walk in righteousness: for in the path of destruction ye have begun to walk, and ye are parting one from another, and are envious one of another, and (so it comes) that ye are not in harmony, my sons, each with his brother." },
  { book: "Jubilees", chapter: 7, verse: 27, text: "For I see, and behold the demons have begun (their) seductions against you and against your children and now I fear on your behalf, that after my death ye will shed the blood of men upon the earth, and that ye, too, will be destroyed from the face of the earth." },
  { book: "Jubilees", chapter: 7, verse: 28, text: "For whoso sheddeth man's blood, and whoso eateth the blood of any flesh, shall all be destroyed from the earth." },
  { book: "Jubilees", chapter: 7, verse: 29, text: "And there shall not be left any man that eateth blood, or that sheddeth the blood of man on the earth, Nor shall there be left to him any seed or descendants living under heaven; For into Sheol shall they go, And into the place of condemnation shall they descend, And into the darkness of the deep shall they all be removed by a violent death." },
  { book: "Jubilees", chapter: 7, verse: 30, text: "There shall be no blood seen upon you of all the blood there shall be all the days in which ye have killed any beasts or cattle or whatever flies upon the earth, and work ye a good work to your souls by covering that which has been shed on the face of the earth." },
  { book: "Jubilees", chapter: 7, verse: 31, text: "And ye shall not be like him who eats with blood, but guard yourselves that none may eat blood before you: cover the blood, for thus have I been commanded to testify to you and your children, together with all flesh." },
  { book: "Jubilees", chapter: 7, verse: 32, text: "And suffer not the soul to be eaten with the flesh, that your blood, which is your life, may not be required at the hand of any flesh that sheds (it) on the earth." },
  { book: "Jubilees", chapter: 7, verse: 33, text: "For the earth will not be clean from the blood which has been shed upon it; for (only) through the blood of him that shed it will the earth be purified throughout all its generations." },
  { book: "Jubilees", chapter: 7, verse: 34, text: "And now, my children, harken: work judgment and righteousness that ye maybe planted in righteousness over the face of the whole earth, and your glory lifted up before my God, who saved me from the waters of the flood." },
  { book: "Jubilees", chapter: 7, verse: 35, text: "And behold, ye will go and build for yourselves cities, and plant in them all the plants that are upon the earth, and moreover all fruit-bearing trees." },
  { book: "Jubilees", chapter: 7, verse: 36, text: "For three years the fruit of everything that is eaten will not be gathered: and in the fourth year its fruit will be accounted holy [and they will offer the first-fruits], acceptable before the Most High God, who created heaven and earth and all things. Let them offer in abundance the first of the wine and oil (as) first-fruits on the altar of the Lord, who receives it, and what is left let the servants of the house of the Lord eat before the altar which receives (it)." },
  { book: "Jubilees", chapter: 7, verse: 37, text: "And in the fifth year make ye the release so that ye release it in righteousness and uprightness, and ye shall be righteous, and all that you plant shall prosper." },
  { book: "Jubilees", chapter: 7, verse: 38, text: "For thus did Enoch, the father of your father command Methuselah, his son, and Methuselah his son Lamech, and Lamech commanded me all the things which his fathers commanded him." },
  { book: "Jubilees", chapter: 7, verse: 39, text: "And I also will give you commandment, my sons, as Enoch commanded his son in the first jubilees: whilst still living, the seventh in his generation, he commanded and testified to his son and to his son's sons until the day of his death.'" },
  { book: "Jubilees", chapter: 8, verse: 1, text: "In the twenty-ninth jubilee, in the first week, [1373 A.M.] in the beginning thereof Arpachshad took to himself a wife and her name was Rasu'eja, the daughter of Susan, the daughter of Elam, and she bare him a son in the third year in this week, [1375 A.M.] and he called his name Kainam." },
  { book: "Jubilees", chapter: 8, verse: 2, text: "And the son grew, and his father taught him writing, and he went to seek for himself a place where he might seize for himself a city." },
  { book: "Jubilees", chapter: 8, verse: 3, text: "And he found a writing which former (generations) had carved on the rock, and he read what was thereon, and he transcribed it and sinned owing to it; for it contained the teaching of the Watchers in accordance with which they used to observe the omens of the sun and moon and stars in all the signs of heaven." },
  { book: "Jubilees", chapter: 8, verse: 4, text: "And he wrote it down and said nothing regarding it; for he was afraid to speak to Noah about it lest he should be angry with him on account of it." },
  { book: "Jubilees", chapter: 8, verse: 5, text: "And in the thirtieth jubilee, [1429 A.M.] in the second week, in the first year thereof, he took to himself a wife, and her name was Melka, the daughter of Madai, the son of Japheth, and in the fourth year [1432 A.M.] he begat a son, and called his name Shelah; for he said: 'Truly I have been sent.'" },
  { book: "Jubilees", chapter: 8, verse: 6, text: "[And in the fourth year he was born], and Shelah grew up and took to himself a wife, and her name was Mu'ak, the daughter of Kesed, his father's brother, in the one and thirtieth jubilee, in the fifth week, in the first year [1499 A.M.] thereof." },
  { book: "Jubilees", chapter: 8, verse: 7, text: "And she bare him a son in the fifth year [1503 A.M.] thereof, and he called his name Eber: and he took unto himself a wife, and her name was 'Azûrâd, the daughter of Nebrod, in the thirty-second jubilee, in the seventh week, in the third year thereof. [1564 A.M.]" },
  { book: "Jubilees", chapter: 8, verse: 8, text: "And in the sixth year [1567 A.M.] thereof, she bare him son, and he called his name Peleg; for in the days when he was born the children of Noah began to divide the earth amongst themselves: for this reason he called his name Peleg." },
  { book: "Jubilees", chapter: 8, verse: 9, text: "And they divided (it) secretly amongst themselves, and told it to Noah." },
  { book: "Jubilees", chapter: 8, verse: 10, text: "And it came to pass in the beginning of the thirty-third jubilee [1569 A.M.] that they divided the earth into three parts, for Shem and Ham and Japheth, according to the inheritance of each, in the first year in the first week, when one of us who had been sent, was with them." },
  { book: "Jubilees", chapter: 8, verse: 11, text: "And he called his sons, and they drew nigh to him, they and their children, and he divided the earth into the lots, which his three sons were to take in possession, and they reached forth their hands, and took the writing out of the bosom of Noah, their father." },
  { book: "Jubilees", chapter: 8, verse: 12, text: "And there came forth on the writing as Shem's lot the middle of the earth which he should take as an inheritance for himself and for his sons for the generations of eternity, from the middle of the mountain range of Rafa, from the mouth of the water from the river Tina, and his portion goes towards the west through the midst of this river, and it extends till it reaches the water of the abysses, out of which this river goes forth and pours its waters into the sea Me'at, and this river flows into the great sea. And all that is towards the north is Japheth's, and all that is towards the south belongs to Shem." },
  { book: "Jubilees", chapter: 8, verse: 13, text: "And it extends till it reaches Karaso: this is in the bosom of the tongue which looks towards the south." },
  { book: "Jubilees", chapter: 8, verse: 14, text: "And his portion extends along the great sea, and it extends in a straight line till it reaches the west of the tongue which looks towards the south: for this sea is named the tongue of the Egyptian Sea." },
  { book: "Jubilees", chapter: 8, verse: 15, text: "And it turns from here towards the south towards the mouth of the great sea on the shore of (its) waters, and it extends to the west to 'Afra, and it extends till it reaches the waters of the river Gihon, and to the south of the waters of Gihon, to the banks of this river." },
  { book: "Jubilees", chapter: 8, verse: 16, text: "And it extends towards the east, till it reaches the Garden of Eden, to the south thereof, [to the south] and from the east of the whole land of Eden and of the whole east, it turns to the east and proceeds till it reaches the east of the mountain named Rafa, and it descends to the bank of the mouth of the river Tina." },
  { book: "Jubilees", chapter: 8, verse: 17, text: "This portion came forth by lot for Shem and his sons, that they should possess it for ever unto his generations for evermore." },
  { book: "Jubilees", chapter: 8, verse: 18, text: "And Noah rejoiced that this portion came forth for Shem and for his sons, and he remembered all that he had spoken with his mouth in prophecy; for he had said: 'Blessed be the Lord God of Shem And may the Lord dwell in the dwelling of Shem.'" },
  { book: "Jubilees", chapter: 8, verse: 19, text: "And he knew that the Garden of Eden is the holy of holies, and the dwelling of the Lord, and Mount Sinai the centre of the desert, and Mount Zion -the centre of the navel of the earth: these three were created as holy places facing each other." },
  { book: "Jubilees", chapter: 8, verse: 20, text: "And he blessed the God of gods, who had put the word of the Lord into his mouth, and the Lord for evermore." },
  { book: "Jubilees", chapter: 8, verse: 21, text: "And he knew that a blessed portion and a blessing had come to Shem and his sons unto the generations for ever -the whole land of Eden and the whole land of the Red Sea, and the whole land of the east and India, and on the Red Sea and the mountains thereof, and all the land of Bashan, and all the land of Lebanon and the islands of Kaftur, and all the mountains of Sanir and 'Amana, and the mountains of Asshur in the north, and all the land of Elam, Asshur, and Babel, and Susan and Ma'edai, and all the mountains of Ararat, and all the region beyond the sea, which is beyond the mountains of Asshur towards the north, a blessed and spacious land, and all that is in it is very good." },
  { book: "Jubilees", chapter: 8, verse: 22, text: "And for Ham came forth the second portion, beyond the Gihon towards the south to the right of the Garden, and it extends towards the south and it extends to all the mountains of fire, and it extends towards the west to the sea of 'Atel and it extends towards the west till it reaches the sea of Ma'uk -that (sea) into which everything which is not destroyed descends." },
  { book: "Jubilees", chapter: 8, verse: 23, text: "And it goes forth towards the north to the limits of Gadir, and it goes forth to the coast of the waters of the sea to the waters of the great sea till it draws near to the river Gihon, and goes along the river Gihon till it reaches the right of the Garden of Eden." },
  { book: "Jubilees", chapter: 8, verse: 24, text: "And this is the land which came forth for Ham as the portion which he was to occupy for ever for himself and his sons unto their generations for ever." },
  { book: "Jubilees", chapter: 8, verse: 25, text: "And for Japheth came forth the third portion beyond the river Tina to the north of the outflow of its waters, and it extends north- easterly to the whole region of Gog, and to all the country east thereof." },
  { book: "Jubilees", chapter: 8, verse: 26, text: "And it extends northerly to the north, and it extends to the mountains of Qelt towards the north, and towards the sea of Ma'uk, and it goes forth to the east of Gadir as far as the region of the waters of the sea." },
  { book: "Jubilees", chapter: 8, verse: 27, text: "And it extends until it approaches the west of Fara and it returns towards 'Aferag, and it extends easterly to the waters of the sea of Me'at." },
  { book: "Jubilees", chapter: 8, verse: 28, text: "And it extends to the region of the river Tina in a north-easterly direction until it approaches the boundary of its waters towards the mountain Rafa, and it turns round towards the north." },
  { book: "Jubilees", chapter: 8, verse: 29, text: "This is the land which came forth for Japheth and his sons as the portion of his inheritance which he should possess for himself and his sons, for their generations for ever; five great islands, and a great land in the north." },
  { book: "Jubilees", chapter: 8, verse: 30, text: "But it is cold, and the land of Ham is hot, and the land of Shem is neither hot nor cold, but it is of blended cold and heat." },
  { book: "Jubilees", chapter: 9, verse: 1, text: "And Ham divided amongst his sons, and the first portion came forth for Cush towards the east, and to the west of him for Mizraim, and to the west of him for Put, and to the west of him [and to the west thereof] on the sea for Canaan." },
  { book: "Jubilees", chapter: 9, verse: 2, text: "And Shem also divided amongst his sons, and the first portion came forth for Ham and his sons, to the east of the river Tigris till it approachcs the east, the whole land of India, and on the Red Sea on its coast, and the waters of Dedan, and all the mountains of Mebri and Ela, and all the land of Susan and all that is on the side of Pharnak to the Red Sea and the river Tina." },
  { book: "Jubilees", chapter: 9, verse: 3, text: "And for Asshur came forth the second Portion, all the land of Asshur and Nineveh and Shinar and to the border of India, and it ascends and skirts the river." },
  { book: "Jubilees", chapter: 9, verse: 4, text: "And for Arpachshad came forth the third portion, all the land of the region of the Chaldees to the east of the Euphrates, bordering on the Red Sea, and all the waters of the desert close to the tongue of the sea which looks towards Egypt, all the land of Lebanon and Sanir and 'Amana to the border of the Euphrates." },
  { book: "Jubilees", chapter: 9, verse: 5, text: "And for Aram there came forth the fourth portion, all the land of Mesopotamia between the Tigris and the Euphrates to the north of the Chaldees to the border of the mountains of Asshur and the land of 'Arara." },
  { book: "Jubilees", chapter: 9, verse: 6, text: "And there came forth for Lud the fifth portion, the mountains of Asshur and all appertaining to them till it reaches the Great Sea, and till it reaches the east of Asshur his brother." },
  { book: "Jubilees", chapter: 9, verse: 7, text: "And Japheth also divided the land of his inheritance amongst his sons." },
  { book: "Jubilees", chapter: 9, verse: 8, text: "And the first portion came forth for Gomer to the east from the north side to the river Tina; and in the north there came forth for Magog all the inner portions of the north until it reaches to the sea of Me'at." },
  { book: "Jubilees", chapter: 9, verse: 9, text: "And for Madai came forth as his portion that he should posses from the west of his two brothers to the islands, and to the coasts of the islands." },
  { book: "Jubilees", chapter: 9, verse: 10, text: "And for Javan came forth the fourth portion every island and the islands which are towards the border of Lud." },
  { book: "Jubilees", chapter: 9, verse: 11, text: "And for Tubal there came forth the fifth portion in the midst of the tongue which approaches towards the border of the portion of Lud to the second tongue, to the region beyond the second tongue unto the third tongue." },
  { book: "Jubilees", chapter: 9, verse: 12, text: "And for Meshech came forth the sixth portion, all the region beyond the third tongue till it approaches the east of Gadir." },
  { book: "Jubilees", chapter: 9, verse: 13, text: "And for Tiras there came forth the seventh portion, four great islands in the midst of the sea, which reach to the portion of Ham [and the islands of Kamaturi came out by lot for the sons of Arpachshad as his inheritance]." },
  { book: "Jubilees", chapter: 9, verse: 14, text: "And thus the sons of Noah divided unto their sons in the presence of Noah their father, and he bound them all by an oath, imprecating a curse on every one that sought to seize the portion which had not fallen (to him) by his lot." },
  { book: "Jubilees", chapter: 9, verse: 15, text: "And they all said, 'So be it; so be it ' for themselves and their sons for ever throughout their generations till the day of judgment, on which the Lord God shall judge them with a sword and with fire for all the unclean wickedness of their errors, wherewith they have filled the earth with transgression and uncleanness and fornication and sin." },
  { book: "Jubilees", chapter: 10, verse: 1, text: "And in the third week of this jubilee the unclean demons began to lead astray the children of the sons of Noah, and to make to err and destroy them." },
  { book: "Jubilees", chapter: 10, verse: 2, text: "And the sons of Noah came to Noah their father, and they told him concerning the demons which were leading astray and blinding and slaying his sons' sons." },
  { book: "Jubilees", chapter: 10, verse: 3, text: "And he prayed before the Lord his God, and said: 'God of the spirits of all flesh, who hast shown mercy unto me And hast saved me and my sons from the waters of the flood, And hast not caused me to perish as Thou didst the sons of perdition; For Thy grace has been great towards me, And great has been Thy mercy to my soul; Let Thy grace be lift up upon my sons, And let not wicked spirits rule over them Lest they should destroy them from the earth." },
  { book: "Jubilees", chapter: 10, verse: 4, text: "But do Thou bless me and my sons, that we may increase and Multiply and replenish the earth." },
  { book: "Jubilees", chapter: 10, verse: 5, text: "And Thou knowest how Thy Watchers, the fathers of these spirits, acted in my day: and as for these spirits which are living, imprison them and hold them fast in the place of condemnation, and let them not bring destruction on the sons of thy servant, my God; for these are malignant, and created in order to destroy." },
  { book: "Jubilees", chapter: 10, verse: 6, text: "And let them not rule over the spirits of the living; for Thou alone canst exercise dominion over them. And let them not have power over the sons of the righteous from henceforth and for evermore.'" },
  { book: "Jubilees", chapter: 10, verse: 7, text: "And the Lord our God bade us to bind all." },
  { book: "Jubilees", chapter: 10, verse: 8, text: "And the chief of the spirits, Mastêmâ, came and said: 'Lord, Creator, let some of them remain before me, and let them harken to my voice, and do all that I shall say unto them; for if some of them are not left to me, I shall not be able to execute the power of my will on the sons of men; for these are for corruption and leading astray before my judgment, for great is the wickedness of the sons of men.'" },
  { book: "Jubilees", chapter: 10, verse: 9, text: "And He said: 'Let the tenth part of them remain before him, and let nine parts descend into the place of condemnation.'" },
  { book: "Jubilees", chapter: 10, verse: 10, text: "And one of us He commanded that we should teach Noah all their medicines; for He knew that they would not walk in uprightness, nor strive in righteousness." },
  { book: "Jubilees", chapter: 10, verse: 11, text: "And we did according to all His words: all the malignant evil ones we bound in the place of condemnation and a tenth part of them we left that they might be subject before Satan on the earth." },
  { book: "Jubilees", chapter: 10, verse: 12, text: "And we explained to Noah all the medicines of their diseases, together with their seductions, how he might heal them with herbs of the earth." },
  { book: "Jubilees", chapter: 10, verse: 13, text: "And Noah wrote down all things in a book as we instructed him concerning every kind of medicine. Thus the evil spirits were precluded from (hurting) the sons of Noah." },
  { book: "Jubilees", chapter: 10, verse: 14, text: "And he gave all that he had written to Shem, his eldest son; for he loved him exceedingly above all his sons." },
  { book: "Jubilees", chapter: 10, verse: 15, text: "And Noah slept with his fathers, and was buried on Mount Lubar in the land of Ararat." },
  { book: "Jubilees", chapter: 10, verse: 16, text: "Nine hundred and fifty years he completed in his life, nineteen jubilees and two weeks and five years. [1659 A.M.]" },
  { book: "Jubilees", chapter: 10, verse: 17, text: "And in his life on earth he excelled the children of men save Enoch because of the righteousness, wherein he was perfect. For Enoch's office was ordained for a testimony to the generations of the world, so that he should recount all the deeds of generation unto generation, till the day of judgment." },
  { book: "Jubilees", chapter: 10, verse: 18, text: "And in the three and thirtieth jubilee, in the first year in the second week, Peleg took to himself a wife, whose name was Lomna the daughter of Sina'ar, and she bare him a son in the fourth year of this week, and he called his name Reu; for he said: 'Behold the children of men have become evil through the wicked purpose of building for themselves a city and a tower in the land of Shinar.'" },
  { book: "Jubilees", chapter: 10, verse: 19, text: "For they departed from the land of Ararat eastward to Shinar; for in his days they built the city and the tower, saying, 'Go to, let us ascend thereby into heaven.'" },
  { book: "Jubilees", chapter: 10, verse: 20, text: "And they began to build, and in the fourth week they made brick with fire, and the bricks served them for stone, and the clay with which they cemented them together was asphalt which comes out of the sea, and out of the fountains of water in the land of Shinar." },
  { book: "Jubilees", chapter: 10, verse: 21, text: "And they built it: forty and three years [1645-1688 A.M.] were they building it; its breadth was 203 bricks, and the height (of a brick) was the third of one; its height amounted to 5433 cubits and 2 palms, and (the extent of one wall was) thirteen stades (and of the other thirty stades)." },
  { book: "Jubilees", chapter: 10, verse: 22, text: "And the Lord our God said unto us: 'Behold, they are one people, and (this) they begin to do, and now nothing will be withholden from them. Go to, let us go down and confound their language, that they may not understand one another's speech, and they may be dispersed into cities and nations, and one purpose will no longer abide with them till the day of judgment.'" },
  { book: "Jubilees", chapter: 10, verse: 23, text: "And the Lord descended, and we descended with him to see the city and the tower which the children of men had built." },
  { book: "Jubilees", chapter: 10, verse: 24, text: "And he confounded their language, and they no longer understood one another's speech, and they ceased then to build the city and the tower." },
  { book: "Jubilees", chapter: 10, verse: 25, text: "For this reason the whole land of Shinar is called Babel, because the Lord did there confound all the language of the children of men, and from thence they were dispersed into their cities, each according to his language and his nation." },
  { book: "Jubilees", chapter: 10, verse: 26, text: "And the Lord sent a mighty wind against the tower and overthrew it upon the earth, and behold it was between Asshur and Babylon in the land of Shinar, and they called its name 'Overthrow'." },
  { book: "Jubilees", chapter: 10, verse: 27, text: "In the fourth week in the first year [1688 A.M.] in the beginning thereof in the four and thirtieth jubilee, were they dispersed from the land of Shinar." },
  { book: "Jubilees", chapter: 10, verse: 28, text: "And Ham and his sons went into the land which he was to occupy, which he acquired as his portion in the land of the south." },
  { book: "Jubilees", chapter: 10, verse: 29, text: "And Canaan saw the land of Lebanon to the river of Egypt, that it was very good, and he went not into the land of his inheritance to the west (that is to) the sea, and he dwelt in the land of Lebanon, eastward and westward from the border of Jordan and from the border of the sea." },
  { book: "Jubilees", chapter: 10, verse: 30, text: "And Ham, his father, and Cush and Mizraim his brothers said unto him: 'Thou hast settled in a land which is not thine, and which did not fall to us by lot: do not do so; for if thou dost do so, thou and thy sons will fall in the land and (be) accursed through sedition; for by sedition ye have settled, and by sedition will thy children fall, and thou shalt be rooted out for ever." },
  { book: "Jubilees", chapter: 10, verse: 31, text: "Dwell not in the dwelling of Shem; for to Shem and to his sons did it come by their lot." },
  { book: "Jubilees", chapter: 10, verse: 32, text: "Cursed art thou, and cursed shalt thou be beyond all the sons of Noah, by the curse by which we bound ourselves by an oath in the presence of the holy judge, and in the presence of Noah our father.'" },
  { book: "Jubilees", chapter: 10, verse: 33, text: "But he did not harken unto them, and dwelt in the land of Lebanon from Hamath to the entering of Egypt, he and his sons until this day." },
  { book: "Jubilees", chapter: 10, verse: 34, text: "And for this reason that land is named Canaan." },
  { book: "Jubilees", chapter: 10, verse: 35, text: "And Japheth and his sons went towards the sea and dwelt in the land of their portion, and Madai saw the land of the sea and it did not please him, and he begged a (portion) from Ham and Asshur and Arpachshad, his wife's brother, and he dwelt in the land of Media, near to his wife's brother until this day." },
  { book: "Jubilees", chapter: 10, verse: 36, text: "And he called his dwelling-place, and the dwelling-place of his sons, Media, after the name of their father Madai." },
  { book: "Jubilees", chapter: 11, verse: 1, text: "And in the thirty-fifth jubilee, in the third week, in the first year [1681 A.M.] thereof, Reu took to himself a wife, and her name was 'Ôrâ, the daughter of 'Ûr, the son of Kesed, and she bare him a son, and he called his name Sêrôh, in the seventh year of this week in this jubilee. [1687 A.M.]" },
  { book: "Jubilees", chapter: 11, verse: 2, text: "And the sons of Noah began to war on each other, to take captive and to slay each other, and to shed the blood of men on the earth, and to eat blood, and to build strong cities, and walls, and towers, and individuals (began) to exalt themselves above the nation, and to found the beginnings of kingdoms, and to go to war people against people, and nation against nation, and city against city, and all (began) to do evil, and to acquire arms, and to teach their sons war, and they began to capture cities, and to sell male and female slaves." },
  { book: "Jubilees", chapter: 11, verse: 3, text: "And 'Ûr, the son of Kesed, built the city of 'Ara of the Chaldees, and called its name after his own name and the name of his father. And they made for themselves molten images, and they worshipped each the idol, the molten image which they had made for themselves, and they began to make graven images and unclean simulacra, and malignant spirits assisted and seduced (them) into committing transgression and uncleanness." },
  { book: "Jubilees", chapter: 11, verse: 4, text: "And the prince Mastêmâ exerted himself to do all this, and he sent forth other spirits, those which were put under his hand, to do all manner of wrong and sin, and all manner of transgression, to corrupt and destroy, and to shed blood upon the earth." },
  { book: "Jubilees", chapter: 11, verse: 5, text: "For this reason he called the name of Sêrôh, Serug, for every one turned to do all manner of sin and transgression." },
  { book: "Jubilees", chapter: 11, verse: 6, text: "And he grew up, and dwelt in Ur of the Chaldees, near to the father of his wife's mother, and he worshipped idols, and he took to himself a wife in the thirty-sixth jubilee, in the fifth week, in the first year thereof, [1744 A.M.] and her name was Melka, the daughter of Kaber, the daughter of his father's brother." },
  { book: "Jubilees", chapter: 11, verse: 7, text: "And she bare him Nahor, in the first year of this week, and he grew and dwelt in Ur of the Chaldees, and his father taught him the researches of the Chaldees to divine and augur, according to the signs of heaven." },
  { book: "Jubilees", chapter: 11, verse: 8, text: "And in the thirty-seventh jubilee in the sixth week, in the first year thereof, [1800 A.M.] he took to himself a wife, and her name was 'Ijaska, the daughter of Nestag of the Chaldees." },
  { book: "Jubilees", chapter: 11, verse: 9, text: "And she bare him Terah in the seventh year of this week. [1806 A.M.]" },
  { book: "Jubilees", chapter: 11, verse: 10, text: "And the prince Mastêmâ sent ravens and birds to devour the seed which was sown in the land, in order to destroy the land, and rob the children of men of their labours. Before they could plough in the seed, the ravens picked (it) from the surface of the ground." },
  { book: "Jubilees", chapter: 11, verse: 11, text: "And for this reason he called his name Terah because the ravens and the birds reduced them to destitution and devoured their seed." },
  { book: "Jubilees", chapter: 11, verse: 12, text: "And the years began to be barren, owing to the birds, and they devoured all the fruit of the trees from the trees: it was only with great effort that they could save a little of all the fruit of the earth in their days." },
  { book: "Jubilees", chapter: 11, verse: 13, text: "And in this thirty-ninth jubilee, in the second week in the first year, [1870 A.M.] Terah took to himself a wife, and her name was 'Edna, the daughter of 'Abram, the daughter of his father's sister. And in the seventh year of this week [1876 A.M.] she bare him a son, and he called his name Abram, by the name of the father of his mother;" },
  { book: "Jubilees", chapter: 11, verse: 14, text: "for he had died before his daughter had conceived a son." },
  { book: "Jubilees", chapter: 11, verse: 15, text: "And the child began to understand the errors of the earth that all went astray after graven images and after uncleanness, and his father taught him writing, and he was two weeks of years old, [1890 A.M.] and he separated himself from his father, that he might not worship idols with him." },
  { book: "Jubilees", chapter: 11, verse: 16, text: "And he began to pray to the Creator of all things that He might save him from the errors of the children of men, and that his portion should not fall into error after uncleanness and vileness." },
  { book: "Jubilees", chapter: 11, verse: 17, text: "And the seed time came for the sowing of seed upon the land, and they all went forth together to protect their seed against the ravens, and Abram went forth with those that went, and the child was a lad of fourteen years." },
  { book: "Jubilees", chapter: 11, verse: 18, text: "And a cloud of ravens came to devour the seed, and Abram ran to meet them before they settled on the ground, and cried to them before they settled on the ground to devour the seed, and said, ' Descend not: return to the place whence ye came,' and they proceeded to turn back." },
  { book: "Jubilees", chapter: 11, verse: 19, text: "And he caused the clouds of ravens to turn back that day seventy times, and of all the ravens throughout all the land where Abram was there settled there not so much as one." },
  { book: "Jubilees", chapter: 11, verse: 20, text: "And all who were with him throughout all the land saw him cry out, and all the ravens turn back, and his name became great in all the land of the Chaldees." },
  { book: "Jubilees", chapter: 11, verse: 21, text: "And there came to him this year all those that wished to sow, and he went with them until the time of sowing ceased: and they sowed their land, and that year they brought enough grain home and eat and were satisfied." },
  { book: "Jubilees", chapter: 11, verse: 22, text: "And in the first year of the fifth week [1891 A.M.] Abram taught those who made implements for oxen, the artificers in wood, and they made a vessel above the ground, facing the frame of the plough, in order to put the seed thereon, and the seed fell down therefrom upon the share of the plough, and was hidden in the earth, and they no longer feared the ravens." },
  { book: "Jubilees", chapter: 11, verse: 23, text: "And after this manner they made (vessels) above the ground on all the frames of the ploughs, and they sowed and tilled all the land, according as Abram commanded them, and they no longer feared the birds." },
  { book: "Jubilees", chapter: 12, verse: 1, text: "And it came to pass in the sixth week, in the seventh year thereof, [1904 A.M.] that Abram said to Terah his father, saying, 'Father!'" },
  { book: "Jubilees", chapter: 12, verse: 2, text: "And he said, 'Behold, here am I, my son.' And he said, 'What help and profit have we from those idols which thou dost worship, And before which thou dost bow thyself?" },
  { book: "Jubilees", chapter: 12, verse: 3, text: "For there is no spirit in them, For they are dumb forms, and a misleading of the heart. Worship them not:" },
  { book: "Jubilees", chapter: 12, verse: 4, text: "Worship the God of heaven, Who causes the rain and the dew to descend on the earth And does everything upon the earth, And has created everything by His word, And all life is from before His face." },
  { book: "Jubilees", chapter: 12, verse: 5, text: "Why do ye worship things that have no spirit in them? For they are the work of (men's) hands, And on your shoulders do ye bear them, And ye have no help from them, But they are a great cause of shame to those who make them, And a misleading of the heart to those who worship them: Worship them not.'" },
  { book: "Jubilees", chapter: 12, verse: 6, text: "And his father said unto him, 'I also know it, my son, but what shall I do with a people who have made me to serve before them?" },
  { book: "Jubilees", chapter: 12, verse: 7, text: "And if I tell them the truth, they will slay me; for their soul cleaves to them to worship them and honour them." },
  { book: "Jubilees", chapter: 12, verse: 8, text: "Keep silent, my son, lest they slay thee.' And these words he spake to his two brothers, and they were angry with him and he kept silent." },
  { book: "Jubilees", chapter: 12, verse: 9, text: "And in the fortieth jubilee, in the second week, in the seventh year thereof, [1925 A.M.] Abram took to himself a wife, and her name was Sarai, the daughter of his father, and she became his wife." },
  { book: "Jubilees", chapter: 12, verse: 10, text: "And Haran, his brother, took to himself a wife in the third year of the third week, [1928 A.M.] and she bare him a son in the seventh year of this week, [1932 A.M.] and he called his name Lot." },
  { book: "Jubilees", chapter: 12, verse: 11, text: "And Nahor, his brother, took to himself a wife." },
  { book: "Jubilees", chapter: 12, verse: 12, text: "And in the sixtieth year of the life of Abram, that is, in the fourth week, in the fourth year thereof, [1936 A.M.] Abram arose by night, and burned the house of the idols, and he burned all that was in the house and no man knew it." },
  { book: "Jubilees", chapter: 12, verse: 13, text: "And they arose in the night and sought to save their gods from the midst of the fire." },
  { book: "Jubilees", chapter: 12, verse: 14, text: "And Haran hasted to save them, but the fire flamed over him, and he was burnt in the fire, and he died in Ur of the Chaldees before Terah his father, and they buried him in Ur of the Chaldees." },
  { book: "Jubilees", chapter: 12, verse: 15, text: "And Terah went forth from Ur of the Chaldees, he and his sons, to go into the land of Lebanon and into the land of Canaan, and he dwelt in the land of Haran, and Abram dwelt with Terah his father in Haran two weeks of years." },
  { book: "Jubilees", chapter: 12, verse: 16, text: "And in the sixth week, in the fifth year thereof, [1951 A.M.] Abram sat up throughout the night on the new moon of the seventh month to observe the stars from the evening to the morning, in order to see what would be the character of the year with regard to the rains, and he was alone as he sat and observed." },
  { book: "Jubilees", chapter: 12, verse: 17, text: "And a word came into his heart and he said: 'All the signs of the stars, and the signs of the moon and of the sun are all in the hand of the Lord. Why do I search (them) out?" },
  { book: "Jubilees", chapter: 12, verse: 18, text: "If He desires, He causes it to rain, morning and evening; And if He desires, He withholds it, And all things are in his hand.'" },
  { book: "Jubilees", chapter: 12, verse: 19, text: "And he prayed that night and said, 'My God, God Most High, Thou alone art my God, And Thee and Thy dominion have I chosen. And Thou hast created all things, And all things that are the work of thy hands." },
  { book: "Jubilees", chapter: 12, verse: 20, text: "Deliver me from the hands of evil spirits who have dominion over the thoughts of men's hearts, And let them not lead me astray from Thee, my God. And stablish Thou me and my seed for ever That we go not astray from henceforth and for evermore.'" },
  { book: "Jubilees", chapter: 12, verse: 21, text: "And he said, 'Shall I return unto Ur of the Chaldees who seek my face that I may return to them, am I to remain here in this place? The right path before Thee prosper it in the hands of Thy servant that he may fulfil (it) and that I may not walk in the deceitfulness of my heart, O my God.'" },
  { book: "Jubilees", chapter: 12, verse: 22, text: "And he made an end of speaking and praying, and behold the word of the Lord was sent to him through me, saying: 'Get thee up from thy country, and from thy kindred and from the house of thy father unto a land which I will show thee, and I shall make thee a great and numerous nation." },
  { book: "Jubilees", chapter: 12, verse: 23, text: "And I will bless thee And I will make thy name great, And thou shalt be blessed in the earth, And in Thee shall all families of the earth be blessed, And I will bless them that bless thee, And curse them that curse thee." },
  { book: "Jubilees", chapter: 12, verse: 24, text: "And I will be a God to thee and thy son, and to thy son's son, and to all thy seed: fear not, from henceforth and unto all generations of the earth I am thy God.'" },
  { book: "Jubilees", chapter: 12, verse: 25, text: "And the Lord God said: 'Open his mouth and his ears, that he may hear and speak with his mouth, with the language which has been revealed'; for it had ceased from the mouths of all the children of men from the day of the overthrow (of Babel)." },
  { book: "Jubilees", chapter: 12, verse: 26, text: "And I opened his mouth, and his ears and his lips, and I began to speak with him in Hebrew in the tongue of the creation." },
  { book: "Jubilees", chapter: 12, verse: 27, text: "And he took the books of his fathers, and these were written in Hebrew, and he transcribed them, and he began from henceforth to study them, and I made known to him that which he could not (understand), and he studied them during the six rainy months." },
  { book: "Jubilees", chapter: 12, verse: 28, text: "And it came to pass in the seventh year of the sixth week [1953 A.M.] that he spoke to his father and informed him, that he would leave Haran to go into the land of Canaan to see it and return to him." },
  { book: "Jubilees", chapter: 12, verse: 29, text: "And Terah his father said unto him; 'Go in peace: May the eternal God make thy path straight. And the Lord [(be) with thee, and] protect thee from all evil, And grant unto thee grace, mercy and favour before those who see thee, And may none of the children of men have power over thee to harm thee; Go in peace." },
  { book: "Jubilees", chapter: 12, verse: 30, text: "And if thou seest a land pleasant to thy eyes to dwell in, then arise and take me to thee and take Lot with thee, the son of Haran thy brother as thine own son: the Lord be with thee." },
  { book: "Jubilees", chapter: 12, verse: 31, text: "And Nahor thy brother leave with me till thou returnest in peace, and we go with thee all together.'" },
  { book: "Jubilees", chapter: 13, verse: 1, text: "And Abram journeyed from Haran, and he took Sarai, his wife, and Lot, his brother Haran's son, to the land of Canaan, and he came into Asshur, and proceeded to Shechem, and dwelt near a lofty oak." },
  { book: "Jubilees", chapter: 13, verse: 2, text: "And he saw, and, behold, the land was very pleasant from the entering of Hamath to the lofty oak." },
  { book: "Jubilees", chapter: 13, verse: 3, text: "And the Lord said to him: 'To thee and to thy seed will I give this land.'" },
  { book: "Jubilees", chapter: 13, verse: 4, text: "And he built an altar there, and he offered thereon a burnt sacrifice to the Lord, who had appeared to him." },
  { book: "Jubilees", chapter: 13, verse: 5, text: "And he removed from thence unto the mountain . . . Bethel on the west and Ai on the east, and pitched his tent there." },
  { book: "Jubilees", chapter: 13, verse: 6, text: "And he saw and behold, the land was very wide and good, and everything grew thereon -vines and figs and pomegranates, oaks and ilexes, and terebinths and oil trees, and cedars and cypresses and date trees, and all trees of the field, and there was water on the mountains." },
  { book: "Jubilees", chapter: 13, verse: 7, text: "And he blessed the Lord who had led him out of Ur of the Chaldees, and had brought him to this land." },
  { book: "Jubilees", chapter: 13, verse: 8, text: "And it came to pass in the first year, in the seventh week, on the new moon of the first month, 1954 A.M.] that he built an altar on this mountain, and called on the name of the Lord: 'Thou, the eternal God, art my God.'" },
  { book: "Jubilees", chapter: 13, verse: 9, text: "And he offered on the altar a burnt sacrifice unto the Lord that He should be with him and not forsake him all the days of his life." },
  { book: "Jubilees", chapter: 13, verse: 10, text: "And he removed from thence and went towards the south, and he came to Hebron and Hebron was built at that time, and he dwelt there two years, and he went (thence) into the land of the south, to Bealoth, and there was a famine in the land." },
  { book: "Jubilees", chapter: 13, verse: 11, text: "And Abram went into Egypt in the third year of the week, and he dwelt in Egypt five years before his wife was torn away from him." },
  { book: "Jubilees", chapter: 13, verse: 12, text: "Now Tanais in Egypt was at that time built- seven years after Hebron." },
  { book: "Jubilees", chapter: 13, verse: 13, text: "And it came to pass when Pharaoh seized Sarai, the wife of Abram that the Lord plagued Pharaoh and his house with great plagues because of Sarai, Abram's wife." },
  { book: "Jubilees", chapter: 13, verse: 14, text: "And Abram was very glorious by reason of possessions in sheep, and cattle, and asses, and horses, and camels, and menservants, and maidservants, and in silver and gold exceedingly. And Lot also his brother's son, was wealthy." },
  { book: "Jubilees", chapter: 13, verse: 15, text: "And Pharaoh gave back Sarai, the wife of Abram, and he sent him out of the land of Egypt, and he journeyed to the place where he had pitched his tent at the beginning, to the place of the altar, with Ai on the east, and Bethel on the west, and he blessed the Lord his God who had brought him back in peace." },
  { book: "Jubilees", chapter: 13, verse: 16, text: "And it came to pass in the forty-first jubilee in the third year of the first week, [1963 A.M.] that he returned to this place and offered thereon a burnt sacrifice, and called on the name of the Lord, and said: 'Thou, the most high God, art my God for ever and ever.'" },
  { book: "Jubilees", chapter: 13, verse: 17, text: "And in the fourth year of this week [1964 A.M.] Lot parted from him, and Lot dwelt in Sodom, and the men of Sodom were sinners exceedingly." },
  { book: "Jubilees", chapter: 13, verse: 18, text: "And it grieved him in his heart that his brother's son had parted from him; for he had no children." },
  { book: "Jubilees", chapter: 13, verse: 19, text: "In that year when Lot was taken captive, the Lord said unto Abram, after that Lot had parted from him, in the fourth year of this week: 'Lift up thine eyes from the place where thou art dwelling, northward and southward, and westward and eastward." },
  { book: "Jubilees", chapter: 13, verse: 20, text: "For all the land which thou seest I will give to thee and to thy seed for ever, and I will make thy seed as the sand of the sea: though a man may number the dust of the earth, yet thy seed shall not be numbered." },
  { book: "Jubilees", chapter: 13, verse: 21, text: "Arise, walk (through the land) in the length of it and the breadth of it, and see it all; for to thy seed will I give it.' And Abram went to Hebron, and dwelt there." },
  { book: "Jubilees", chapter: 13, verse: 22, text: "And in this year came Chedorlaomer, king of Elam, and Amraphel, king of Shinar, and Arioch king of Sellasar, and Tergal, king of nations, and slew the king of Gomorrah, and the king of Sodom fled, and many fell through wounds in the vale of Siddim, by the Salt Sea." },
  { book: "Jubilees", chapter: 13, verse: 23, text: "And they took captive Sodom and Adam and Zeboim, and they took captive Lot also, the son of Abram's brother, and all his possessions, and they went to Dan." },
  { book: "Jubilees", chapter: 13, verse: 24, text: "And one who had escaped came and told Abram that his brother's son had been taken captive and (Abram) armed his household servants . . ." },
  { book: "Jubilees", chapter: 13, verse: 25, text: ". . . . for Abram, and for his seed, a tenth of the first fruits to the Lord, and the Lord ordained it as an ordinance for ever that they should give it to the priests who served before Him, that they should possess it for ever." },
  { book: "Jubilees", chapter: 13, verse: 26, text: "And to this law there is no limit of days; for He hath ordained it for the generations for ever that they should give to the Lord the tenth of everything, of the seed and of the wine and of the oil and of the cattle and of the sheep." },
  { book: "Jubilees", chapter: 13, verse: 27, text: "And He gave (it) unto His priests to eat and to drink with joy before Him." },
  { book: "Jubilees", chapter: 13, verse: 28, text: "And the king of Sodom came to him and bowed himself before him, and said: 'Our Lord Abram, give unto us the souls which thou hast rescued, but let the booty be thine.'" },
  { book: "Jubilees", chapter: 13, verse: 29, text: "And Abram said unto him: 'I lift up my hands to the Most High God, that from a thread to a shoe-latchet I shall not take aught that is thine lest thou shouldst say, I have made Abram rich; save only what the young men have eaten, and the portion of the men who went with me -Aner, Eschol, and Mamre. These shall take their portion.'" },
  { book: "Jubilees", chapter: 14, verse: 1, text: "After these things, in the fourth year of this week, on the new moon of the third month, the word of the Lord came to Abram in a dream, saying: 'Fear not, Abram; I am thy defender, and thy reward will be exceeding great.'" },
  { book: "Jubilees", chapter: 14, verse: 2, text: "And he said: 'Lord, Lord, what wilt thou give me, seeing I go hence childless, and the son of Maseq, the son of my handmaid, is the Dammasek Eliezer: he will be my heir, and to me thou hast given no seed.'" },
  { book: "Jubilees", chapter: 14, verse: 3, text: "And he said unto him: 'This (man) will not be thy heir, but one that will come out of thine own bowels; he will be thine heir.'" },
  { book: "Jubilees", chapter: 14, verse: 4, text: "And He brought him forth abroad, and said unto him: 'Look toward heaven and number the stars if thou art able to number them.'" },
  { book: "Jubilees", chapter: 14, verse: 5, text: "And he looked toward heaven, and beheld the stars. And He said unto him: 'So shall thy seed be.'" },
  { book: "Jubilees", chapter: 14, verse: 6, text: "And he believed in the Lord, and it was counted to him for righteousness." },
  { book: "Jubilees", chapter: 14, verse: 7, text: "And He said unto him: 'I am the Lord that brought thee out of Ur of the Chaldees, to give thee the land of the Canaanites to possess it for ever; and I will be God unto thee and to thy seed after thee.'" },
  { book: "Jubilees", chapter: 14, verse: 8, text: "And he said: 'Lord, Lord, whereby shall I know that I shall inherit (it)?'" },
  { book: "Jubilees", chapter: 14, verse: 9, text: "And He said unto him: 'Take Me an heifer of three years, and a goat of three years, and a sheep of three years, and a turtle-dove, and a pigeon.'" },
  { book: "Jubilees", chapter: 14, verse: 10, text: "And he took all these in the middle of the month and he dwelt at the oak of Mamre, which is near Hebron." },
  { book: "Jubilees", chapter: 14, verse: 11, text: "And he built there an altar, and sacrificed all these; and he poured their blood upon the altar, and divided them in the midst, and laid them over against each other; but the birds divided he not." },
  { book: "Jubilees", chapter: 14, verse: 12, text: "And birds came down upon the pieces, and Abram drove them away, and did not suffer the birds to touch them." },
  { book: "Jubilees", chapter: 14, verse: 13, text: "And it came to pass, when the sun had set, that an ecstasy fell upon Abram, and lo ! an horror of great darkness fell upon him, and it was said unto Abram: 'Know of a surety that thy seed shall be a stranger in a land (that is) not theirs, and they shall bring them into bondage, and afflict them four hundred years." },
  { book: "Jubilees", chapter: 14, verse: 14, text: "And the nation also to whom they will be in bondage will I judge, and after that they shall come forth thence with much substance." },
  { book: "Jubilees", chapter: 14, verse: 15, text: "And thou shalt go to thy fathers in peace, and be buried in a good old age." },
  { book: "Jubilees", chapter: 14, verse: 16, text: "But in the fourth generation they shall return hither; for the iniquity of the Amorites is not yet full.'" },
  { book: "Jubilees", chapter: 14, verse: 17, text: "And he awoke from his sleep, and he arose, and the sun had set; and there was a flame, and behold ! a furnace was smoking, and a flame of fire passed between the pieces." },
  { book: "Jubilees", chapter: 14, verse: 18, text: "And on that day the Lord made a covenant with Abram, saying: 'To thy seed will I give this land, from the river of Egypt unto the great river, the river Euphrates, the Kenites, the Kenizzites, the Kadmonites, the Perizzites, and the Rephaim, the Phakorites, and the Hivites, and the Amorites, and the Canaanites, and the Girgashites, and the Jebusites." },
  { book: "Jubilees", chapter: 14, verse: 19, text: "And the day passed, and Abram offered the pieces, and the birds, and their fruit offerings, and their drink offerings, and the fire devoured them." },
  { book: "Jubilees", chapter: 14, verse: 20, text: "And on that day we made a covenant with Abram, according as we had covenanted with Noah in this month; and Abram renewed the festival and ordinance for himself for ever." },
  { book: "Jubilees", chapter: 14, verse: 21, text: "And Abram rejoiced, and made all these things known to Sarai his wife; and he believed that he would have seed, but she did not bear." },
  { book: "Jubilees", chapter: 14, verse: 22, text: "And Sarai advised her husband Abram, and said unto him: 'Go in unto Hagar, my Egyptian maid: it may be that I shall build up seed unto thee by her.'" },
  { book: "Jubilees", chapter: 14, verse: 23, text: "And Abram harkened unto the voice of Sarai his wife, and said unto her, 'Do (so).' And Sarai took Hagar, her maid, the Egyptian, and gave her to Abram, her husband, to be his wife." },
  { book: "Jubilees", chapter: 14, verse: 24, text: "And he went in unto her, and she conceived and bare him a son, and he called his name Ishmael, in the fifth year of this week [1965 A.M.]; and this was the eighty-sixth year in the life of Abram." },
  { book: "Jubilees", chapter: 15, verse: 1, text: "And in the fifth year of the fourth week of this jubilee, [1979 A.M.] in the third month, in the middle of the month, Abram celebrated the feast of the first-fruits of the grain harvest." },
  { book: "Jubilees", chapter: 15, verse: 2, text: "And he offered new offerings on the altar, the first-fruits of the produce, unto the Lord, an heifer and a goat and a sheep on the altar as a burnt sacrifice unto the Lord; their fruit offerings and their drink offerings he offered upon the altar with frankincense." },
  { book: "Jubilees", chapter: 15, verse: 3, text: "And the Lord appeared to Abram, and said unto him: 'I am God Almighty; approve thyself before me and be thou perfect." },
  { book: "Jubilees", chapter: 15, verse: 4, text: "And I will make My covenant between Me and thee, and I will multiply thee exceedingly.'" },
  { book: "Jubilees", chapter: 15, verse: 5, text: "And Abram fell on his face, and God talked with him, and said:" },
  { book: "Jubilees", chapter: 15, verse: 6, text: "'Behold my ordinance is with thee, And thou shalt be the father of many nations." },
  { book: "Jubilees", chapter: 15, verse: 7, text: "Neither shall thy name any more be called Abram, But thy name from henceforth, even for ever, shall be Abraham. For the father of many nations have I made thee." },
  { book: "Jubilees", chapter: 15, verse: 8, text: "And I will make thee very great, And I will make thee into nations, And kings shall come forth from thee." },
  { book: "Jubilees", chapter: 15, verse: 9, text: "And I shall establish My covenant between Me and thee, and thy seed after thee, throughout their generations, for an eternal covenant, so that I may be a God unto thee, and to thy seed after thee." },
  { book: "Jubilees", chapter: 15, verse: 10, text: "<And I will give to thee and to thy seed after thee> the land where thou hast been a sojourner, the land of Canaan, that thou mayst possess it for ever, and I will be their God.'" },
  { book: "Jubilees", chapter: 15, verse: 11, text: "And the Lord said unto Abraham: 'And as for thee, do thou keep my covenant, thou and thy seed after thee: and circumcise ye every male among you, and circumcise your foreskins, and it shall be a token of an eternal covenant between Me and you." },
  { book: "Jubilees", chapter: 15, verse: 12, text: "And the child on the eighth day ye shall circumcise, every male throughout your generations, him that is born in the house, or whom ye have bought with money from any stranger, whom ye have acquired who is not of thy seed." },
  { book: "Jubilees", chapter: 15, verse: 13, text: "He that is born in thy house shall surely be circumcised, and those whom thou hast bought with money shall be circumcised, and My covenant shall be in your flesh for an eternal ordinance." },
  { book: "Jubilees", chapter: 15, verse: 14, text: "And the uncircumcised male who is not circumcised in the flesh of his foreskin on the eighth day, that soul shall be cut off from his people, for he has broken My covenant.'" },
  { book: "Jubilees", chapter: 15, verse: 15, text: "And God said unto Abraham: 'As for Sarai thy wife, her name shall no more be called Sarai, but Sarah shall be her name." },
  { book: "Jubilees", chapter: 15, verse: 16, text: "And I will bless her, and give thee a son by her, and I will bless him, and he shall become a nation, and kings of nations shall proceed from him.'" },
  { book: "Jubilees", chapter: 15, verse: 17, text: "And Abraham fell on his face, and rejoiced, and said in his heart: 'Shall a son be born to him that is a hundred years old, and shall Sarah, who is ninety years old, bring forth?'" },
  { book: "Jubilees", chapter: 15, verse: 18, text: "And Abraham said unto God: 'O that Ishmael might live before thee!'" },
  { book: "Jubilees", chapter: 15, verse: 19, text: "And God said: 'Yea, and Sarah also shall bear thee a son, and thou shalt call his name Isaac, and I will establish My covenant with him, an everlasting covenant, and for his seed after him." },
  { book: "Jubilees", chapter: 15, verse: 20, text: "And as for Ishmael also have I heard thee, and behold I will bless him, and make him great, and multiply him exceedingly, and he shall beget twelve princes, and I will make him a great nation." },
  { book: "Jubilees", chapter: 15, verse: 21, text: "But My covenant will I establish with Isaac, whom Sarah shall bear to thee, in these days, in the next year.'" },
  { book: "Jubilees", chapter: 15, verse: 22, text: "And He left off speaking with him, and God went up from Abraham." },
  { book: "Jubilees", chapter: 15, verse: 23, text: "And Abraham did according as God had said unto him, and he took Ishmael his son, and all that were born in his house, and whom he had bought with his money, every male in his house, and circumcised the flesh of their foreskin." },
  { book: "Jubilees", chapter: 15, verse: 24, text: "And on the selfsame day was Abraham circumcised, and all the men of his house, <and those born in the house>, and all those, whom he had bought with money from the children of the stranger, were circumcised with him." },
  { book: "Jubilees", chapter: 15, verse: 25, text: "This law is for all the generations for ever, and there is no circumcision of the days, and no omission of one day out of the eight days; for it is an eternal ordinance, ordained and written on the heavenly tablets." },
  { book: "Jubilees", chapter: 15, verse: 26, text: "And every one that is born, the flesh of whose foreskin is not circumcised on the eighth day, belongs not to the children of the covenant which the Lord made with Abraham, but to the children of destruction; nor is there, moreover, any sign on him that he is the Lord's, but (he is destined) to be destroyed and slain from the earth, and to be rooted out of the earth, for he has broken the covenant of the Lord our God." },
  { book: "Jubilees", chapter: 15, verse: 27, text: "For all the angels of the presence and all the angels of sanctification have been so created from the day of their creation, and before the angels of the presence and the angels of sanctification He hath sanctified Israel, that they should be with Him and with His holy angels." },
  { book: "Jubilees", chapter: 15, verse: 28, text: "And do thou command the children of Israel and let them observe the sign of this covenant for their generations as an eternal ordinance, and they will not be rooted out of the land." },
  { book: "Jubilees", chapter: 15, verse: 29, text: "For the command is ordained for a covenant, that they should observe it for ever among all the children of Israel." },
  { book: "Jubilees", chapter: 15, verse: 30, text: "For Ishmael and his sons and his brothers and Esau, the Lord did not cause to approach Him, and he chose them not because they are the children of Abraham, because He knew them, but He chose Israel to be His people." },
  { book: "Jubilees", chapter: 15, verse: 31, text: "And He sanctified it, and gathered it from amongst all the children of men; for there are many nations and many peoples, and all are His, and over all hath He placed spirits in authority to lead them astray from Him." },
  { book: "Jubilees", chapter: 15, verse: 32, text: "But over Israel He did not appoint any angel or spirit, for He alone is their ruler, and He will preserve them and require them at the hand of His angels and His spirits, and at the hand of all His powers in order that He may preserve them and bless them, and that they may be His and He may be theirs from henceforth for ever." },
  { book: "Jubilees", chapter: 15, verse: 33, text: "And now I announce unto thee that the children of Israel will not keep true to this ordinance, and they will not circumcise their sons according to all this law; for in the flesh of their circumcision they will omit this circumcision of their sons, and all of them, sons of Beliar, will leave their sons uncircumcised as they were born." },
  { book: "Jubilees", chapter: 15, verse: 34, text: "And there will be great wrath from the Lord against the children of Israel. because they have forsaken His covenant and turned aside from His word, and provoked and blasphemed, inasmuch as they do not observe the ordinance of this law; for they have treated their members like the Gentiles, so that they may be removed and rooted out of the land. And there will no more be pardon or forgiveness unto them [so that there should be forgiveness and pardon] for all the sin of this eternal error." },
  { book: "Jubilees", chapter: 16, verse: 1, text: "And on the new moon of the fourth month we appeared unto Abraham, at the oak of Mamre, and we talked with him, and we announced to him that a son would be given to him by Sarah his wife." },
  { book: "Jubilees", chapter: 16, verse: 2, text: "And Sarah laughed, for she heard that we had spoken these words with Abraham, and we admonished her, and she became afraid, and denied that she had laughed on account of the words." },
  { book: "Jubilees", chapter: 16, verse: 3, text: "And we told her the name of her son, as his name is ordained and written in the heavenly tablets (i.e.) Isaac," },
  { book: "Jubilees", chapter: 16, verse: 4, text: "And (that) when we returned to her at a set time, she would have conceived a son." },
  { book: "Jubilees", chapter: 16, verse: 5, text: "And in this month the Lord executed his judgments on Sodom, and Gomorrah, and Zeboim, and all the region of the Jordan, and He burned them with fire and brimstone, and destroyed them until this day, even as [lo] I have declared unto thee all their works, that they are wicked and sinners exceedingly, and that they defile themselves and commit fornication in their flesh, and work uncleanness on the earth." },
  { book: "Jubilees", chapter: 16, verse: 6, text: "And, in like manner, God will execute judgment on the places where they have done according to the uncleanness of the Sodomites, like unto the judgment of Sodom." },
  { book: "Jubilees", chapter: 16, verse: 7, text: "But Lot we saved; for God remembered Abraham, and sent him out from the midst of the overthrow." },
  { book: "Jubilees", chapter: 16, verse: 8, text: "And he and his daughters committed sin upon the earth, such as had not been on the earth since the days of Adam till his time; for the man lay with his daughters." },
  { book: "Jubilees", chapter: 16, verse: 9, text: "And, behold, it was commanded and engraven concerning all his seed, on the heavenly tablets, to remove them and root them out, and to execute judgment upon them like the judgment of Sodom, and to leave no seed of the man on earth on the day of condemnation." },
  { book: "Jubilees", chapter: 16, verse: 10, text: "And in this month Abraham moved from Hebron, and departed and dwelt between Kadesh and Shur in the mountains of Gerar." },
  { book: "Jubilees", chapter: 16, verse: 11, text: "And in the middle of the fifth month he moved from thence, and dwelt at the Well of the Oath." },
  { book: "Jubilees", chapter: 16, verse: 12, text: "And in the middle of the sixth month the Lord visited Sarah and did unto her as He had spoken and she conceived." },
  { book: "Jubilees", chapter: 16, verse: 13, text: "And she bare a son in the third month, and in the middle of the month, at the time of which the Lord had spoken to Abraham, on the festival of the first fruits of the harvest, Isaac was born." },
  { book: "Jubilees", chapter: 16, verse: 14, text: "And Abraham circumcised his son on the eighth day: he was the first that was circumcised according to the covenant which is ordained for ever." },
  { book: "Jubilees", chapter: 16, verse: 15, text: "And in the sixth year of the fourth week we came to Abraham, to the Well of the Oath, and we appeared unto him [as we had told Sarah that we should return to her, and she would have conceived a son." },
  { book: "Jubilees", chapter: 16, verse: 16, text: "And we returned in the seventh month, and found Sarah with child before us] and we blessed him, and we announced to him all the things which had been decreed concerning him, that he should not die till he should beget six sons more, and should see (them) before he died; but (that) in Isaac should his name and seed be called:" },
  { book: "Jubilees", chapter: 16, verse: 17, text: "And (that) all the seed of his sons should be Gentiles, and be reckoned with the Gentiles; but from the sons of Isaac one should become a holy seed, and should not be reckoned among the Gentiles." },
  { book: "Jubilees", chapter: 16, verse: 18, text: "For he should become the portion of the Most High, and all his seed had fallen into the possession of God, that it should be unto the Lord a people for (His) possession above all nations and that it should become a kingdom and priests and a holy nation." },
  { book: "Jubilees", chapter: 16, verse: 19, text: "And we went our way, and we announced to Sarah all that we had told him, and they both rejoiced with exceeding great joy." },
  { book: "Jubilees", chapter: 16, verse: 20, text: "And he built there an altar to the Lord who had delivered him, and who was making him rejoice in the land of his sojourning, and he celebrated a festival of joy in this month seven days, near the altar which he had built at the Well of the Oath." },
  { book: "Jubilees", chapter: 16, verse: 21, text: "And he built booths for himself and for his servants on this festival, and he was the first to celebrate the feast of tabernacles on the earth." },
  { book: "Jubilees", chapter: 16, verse: 22, text: "And during these seven days he brought each day to the altar a burnt offering to the Lord, two oxen, two rams, seven sheep, one he-goat, for a sin offering, that he might atone thereby for himself and for his seed." },
  { book: "Jubilees", chapter: 16, verse: 23, text: "And, as a thank-offering, seven rams, seven kids, seven sheep, and seven he-goats, and their fruit offerings and their drink offerings; and he burnt all the fat thereof on the altar, a chosen offering unto the Lord for a sweet smelling savour." },
  { book: "Jubilees", chapter: 16, verse: 24, text: "And morning and evening he burnt fragrant substances, frankincense and galbanum, and stackte, and nard, and myrrh, and spice, and costum; all these seven he offered, crushed, mixed together in equal parts (and) pure." },
  { book: "Jubilees", chapter: 16, verse: 25, text: "And he celebrated this feast during seven days, rejoicing with all his heart and with all his soul, he and all those who were in his house, and there was no stranger with him, nor any that was uncircumcised." },
  { book: "Jubilees", chapter: 16, verse: 26, text: "And he blessed his Creator who had created him in his generation, for He had created him according to His good pleasure; for He knew and perceived that from him would arise the plant of righteousness for the eternal generations, and from him a holy seed, so that it should become like Him who had made all things." },
  { book: "Jubilees", chapter: 16, verse: 27, text: "And he blessed and rejoiced, and he called the name of this festival the festival of the Lord, a joy acceptable to the Most High God." },
  { book: "Jubilees", chapter: 16, verse: 28, text: "And we blessed him for ever, and all his seed after him throughout all the generations of the earth, because he celebrated this festival in its season, according to the testimony of the heavenly tablets." },
  { book: "Jubilees", chapter: 16, verse: 29, text: "For this reason it is ordained on the heavenly tablets concerning Israel, that they shall celebrate the feast of tabernacles seven days with joy, in the seventh month, acceptable before the Lord -a statute for ever throughout their generations every year." },
  { book: "Jubilees", chapter: 16, verse: 30, text: "And to this there is no limit of days; for it is ordained for ever regarding Israel that they should celebrate it and dwell in booths, and set wreaths upon their heads, and take leafy boughs, and willows from the brook." },
  { book: "Jubilees", chapter: 16, verse: 31, text: "And Abraham took branches of palm trees, and the fruit of goodly trees, and every day going round the altar with the branches seven times [a day] in the morning, he praised and gave thanks to his God for all things in joy." },
  { book: "Jubilees", chapter: 17, verse: 1, text: "And in the first year of the fifth week Isaac was weaned in this jubilee, [1982 A.M.] and Abraham made a great banquet in the third month, on the day his son Isaac was weaned." },
  { book: "Jubilees", chapter: 17, verse: 2, text: "And Ishmael, the son of Hagar, the Egyptian, was before the face of Abraham, his father, in his place, and Abraham rejoiced and blessed God because he had seen his sons and had not died childless." },
  { book: "Jubilees", chapter: 17, verse: 3, text: "And he remembered the words which He had spoken to him on the day on which Lot had parted from him, and he rejoiced because the Lord had given him seed upon the earth to inherit the earth, and he blessed with all his mouth the Creator of all things." },
  { book: "Jubilees", chapter: 17, verse: 4, text: "And Sarah saw Ishmael playing and dancing, and Abraham rejoicing with great joy, and she became jealous of Ishmael and said to Abraham, 'Cast out this bondwoman and her son; for the son of this bondwoman will not be heir with my son, Isaac.'" },
  { book: "Jubilees", chapter: 17, verse: 5, text: "And the thing was grievous in Abraham's sight, because of his maidservant and because of his son, that he should drive them from him." },
  { book: "Jubilees", chapter: 17, verse: 6, text: "And God said to Abraham 'Let it not be grievous in thy sight, because of the child and because of the bondwoman; in all that Sarah hath said unto thee, harken to her words and do (them); for in Isaac shall thy name and seed be called." },
  { book: "Jubilees", chapter: 17, verse: 7, text: "But as for the son of this bondwoman I will make him a great nation, because he is of thy seed.'" },
  { book: "Jubilees", chapter: 17, verse: 8, text: "And Abraham rose up early in the morning, and took bread and a bottle of water, and placed them on the shoulders of Hagar and the child, and sent her away." },
  { book: "Jubilees", chapter: 17, verse: 9, text: "And she departed and wandered in the wilderness of Beersheba, and the water in the bottle was spent, and the child thirsted, and was not able to go on, and fell down." },
  { book: "Jubilees", chapter: 17, verse: 10, text: "And his mother took him and cast him under an olive tree, and went and sat her down over against him, at the distance of a bow-shot; for she said, 'Let me not see the death of my child,' and as she sat she wept." },
  { book: "Jubilees", chapter: 17, verse: 11, text: "And an angel of God, one of the holy ones, said unto her, 'Why weepest thou, Hagar? Arise take the child, and hold him in thine hand; for God hath heard thy voice, and hath seen the child.'" },
  { book: "Jubilees", chapter: 17, verse: 12, text: "And she opened her eyes, and she saw a well of water, and she went and filled her bottle with water, and she gave her child to drink, and she arose and went towards the wilderness of Paran." },
  { book: "Jubilees", chapter: 17, verse: 13, text: "And the child grew and became an archer, and God was with him, and his mother took him a wife from among the daughters of Egypt." },
  { book: "Jubilees", chapter: 17, verse: 14, text: "And she bare him a son, and he called his name Nebaioth; for she said, 'The Lord was nigh to me when I called upon him.'" },
  { book: "Jubilees", chapter: 17, verse: 15, text: "And it came to pass in the seventh week, in the first year thereof, [2003 A.M.] in the first month in this jubilee, on the twelfth of this month, there were voices in heaven regarding Abraham, that he was faithful in all that He told him, and that he loved the Lord, and that in every affliction he was faithful." },
  { book: "Jubilees", chapter: 17, verse: 16, text: "And the prince Mastêmâ came and said before God, 'Behold, Abraham loves Isaac his son, and he delights in him above all things else; bid him offer him as a burnt-offering on the altar, and Thou wilt see if he will do this command, and Thou wilt know if he is faithful in everything wherein Thou dost try him." },
  { book: "Jubilees", chapter: 17, verse: 17, text: "And the Lord knew that Abraham was faithful in all his afflictions; for He had tried him through his country and with famine, and had tried him with the wealth of kings, and had tried him again through his wife, when she was torn (from him), and with circumcision; and had tried him through Ishmael and Hagar, his maid-servant, when he sent them away." },
  { book: "Jubilees", chapter: 17, verse: 18, text: "And in everything wherein He had tried him, he was found faithful, and his soul was not impatient, and he was not slow to act; for he was faithful and a lover of the Lord." },
  { book: "Jubilees", chapter: 18, verse: 1, text: "And God said to him, 'Abraham, Abraham'; and he said, 'Behold, (here) am I.'" },
  { book: "Jubilees", chapter: 18, verse: 2, text: "And he said, 'Take thy beloved son whom thou lovest, (even) Isaac, and go unto the high country, and offer him on one of the mountains which I will point out unto thee.'" },
  { book: "Jubilees", chapter: 18, verse: 3, text: "And he rose early in the morning and saddled his ass, and took his two young men with him, and Isaac his son, and clave the wood of the burnt offering, and he went to the place on the third day, and he saw the place afar off." },
  { book: "Jubilees", chapter: 18, verse: 4, text: "And he came to a well of water, and he said to his young men, 'Abide ye here with the ass, and I and the lad shall go (yonder), and when we have worshipped we shall come again to you.'" },
  { book: "Jubilees", chapter: 18, verse: 5, text: "And he took the wood of the burnt-offering and laid it on Isaac his son, and he took in his hand the fire and the knife, and they went both of them together to that place." },
  { book: "Jubilees", chapter: 18, verse: 6, text: "And Isaac said to his father, 'Father;' and he said, 'Here am I, my son.' And he said unto him, 'Behold the fire, and the knife, and the wood; but where is the sheep for the burnt-offering, father?'" },
  { book: "Jubilees", chapter: 18, verse: 7, text: "And he said, 'God will provide for himself a sheep for a burnt-offering, my son.' And he drew near to the place of the mount of God." },
  { book: "Jubilees", chapter: 18, verse: 8, text: "And he built an altar, and he placed the wood on the altar, and bound Isaac his son, and placed him on the wood which was upon the altar, and stretched forth his hand to take the knife to slay Isaac his son." },
  { book: "Jubilees", chapter: 18, verse: 9, text: "And I stood before him, and before the prince Mastêmâ, and the Lord said, 'Bid him not to lay his hand on the lad, nor to do anything to him, for I have shown that he fears the Lord.'" },
  { book: "Jubilees", chapter: 18, verse: 10, text: "And I called to him from heaven, and said unto him: 'Abraham, Abraham;' and he was terrified and said: 'Behold, (here) am I.'" },
  { book: "Jubilees", chapter: 18, verse: 11, text: "And I said unto him: 'Lay not thy hand upon the lad, neither do thou anything to him; for now I have shown that thou fearest the Lord, and hast not withheld thy son, thy first-born son, from me.'" },
  { book: "Jubilees", chapter: 18, verse: 12, text: "And the prince Mastêmâ was put to shame; and Abraham lifted up his eyes and looked, and, behold a ram caught . . . by his horns, and Abraham went and took the ram and offered it for a burnt-offering in the stead of his son." },
  { book: "Jubilees", chapter: 18, verse: 13, text: "And Abraham called that place 'The Lord hath seen', so that it is said in the mount the Lord hath seen: that is Mount Sion." },
  { book: "Jubilees", chapter: 18, verse: 14, text: "And the Lord called Abraham by his name a second time from heaven, as he caused us to appear to speak to him in the name of the Lord." },
  { book: "Jubilees", chapter: 18, verse: 15, text: "And he said: 'By Myself have I sworn, saith the Lord, Because thou hast done this thing, And hast not withheld thy son, thy beloved son, from Me, That in blessing I will bless thee, And in multiplying I will multiply thy seed As the stars of heaven, And as the sand which is on the seashore. And thy seed shall inherit the cities of its enemies," },
  { book: "Jubilees", chapter: 18, verse: 16, text: "And in thy seed shall all nations of the earth be blessed; Because thou hast obeyed My voice, And I have shown to all that thou art faithful unto Me in all that I have said unto thee: Go in peace.'" },
  { book: "Jubilees", chapter: 18, verse: 17, text: "And Abraham went to his young men, and they arose and went together to Beersheba, and Abraham [2010 A.M.] dwelt by the Well of the Oath." },
  { book: "Jubilees", chapter: 18, verse: 18, text: "And he celebrated this festival every year, seven days with joy, and he called it the festival of the Lord according to the seven days during which he went and returned in peace." },
  { book: "Jubilees", chapter: 18, verse: 19, text: "And accordingly has it been ordained and written on the heavenly tablets regarding Israel and its seed that they should observe this festival seven days with the joy of festival." },
  { book: "Jubilees", chapter: 19, verse: 1, text: "And in the first year of the first week in the forty-second jubilee, Abraham returned and dwelt opposite Hebron, that is Kirjath Arba, two weeks of years." },
  { book: "Jubilees", chapter: 19, verse: 2, text: "And in the first year of the third week of this jubilee the days of the life of Sarah were accomplished, and she died in Hebron." },
  { book: "Jubilees", chapter: 19, verse: 3, text: "And Abraham went to mourn over her and bury her, and we tried him [to see] if his spirit were patient and he were not indignant in the words of his mouth; and he was found patient in this, and was not disturbed." },
  { book: "Jubilees", chapter: 19, verse: 4, text: "For in patience of spirit he conversed with the children of Heth, to the intent that they should give him a place in which to bury his dead." },
  { book: "Jubilees", chapter: 19, verse: 5, text: "And the Lord gave him grace before all who saw him, and he besought in gentleness the sons of Heth, and they gave him the land of the double cave over against Mamre, that is Hebron, for four hundred pieces of silver." },
  { book: "Jubilees", chapter: 19, verse: 6, text: "And they besought him saying, We shall give it to thee for nothing; but he would not take it from their hands for nothing, for he gave the price of the place, the money in full, and he bowed down before them twice, and after this he buried his dead in the double cave." },
  { book: "Jubilees", chapter: 19, verse: 7, text: "And all the days of the life of Sarah were one hundred and twenty-seven years, that is, two jubilees and four weeks and one year: these are the days of the years of the life of Sarah." },
  { book: "Jubilees", chapter: 19, verse: 8, text: "This is the tenth trial wherewith Abraham was tried, and he was found faithful, patient in spirit." },
  { book: "Jubilees", chapter: 19, verse: 9, text: "And he said not a single word regarding the rumour in the land how that God had said that He would give it to him and to his seed after him, and he begged a place there to bury his dead; for he was found faithful, and was recorded on the heavenly tablets as the friend of God." },
  { book: "Jubilees", chapter: 19, verse: 10, text: "And in the fourth year thereof he took a wife for his son Isaac and her name was Rebecca [2020 A.M.] [the daughter of Bethuel, the son of Nahor, the brother of Abraham] the sister of Laban and daughter of Bethuel; and Bethuel was the son of Melca, who was the wife of Nahor, the brother of Abraham." },
  { book: "Jubilees", chapter: 19, verse: 11, text: "And Abraham took to himself a third wife, and her name was Keturah, from among the daughters of his household servants, for Hagar had died before Sarah. And she bare him six sons, Zimram, and Jokshan, and Medan, and Midian, and Ishbak, and Shuah, in the two weeks of years." },
  { book: "Jubilees", chapter: 19, verse: 12, text: "And in the sixth week, in the second year thereof, Rebecca bare to Isaac two sons, Jacob and Esau," },
  { book: "Jubilees", chapter: 19, verse: 13, text: "and [2046 A.M.] Jacob was a smooth and upright man, and Esau was fierce, a man of the field, and hairy, and Jacob dwelt in tents." },
  { book: "Jubilees", chapter: 19, verse: 14, text: "And the youths grew, and Jacob learned to write; but Esau did not learn, for he was a man of the field and a hunter, and he learnt war, and all his deeds were fierce." },
  { book: "Jubilees", chapter: 19, verse: 15, text: "And Abraham loved Jacob, but Isaac loved Esau." },
  { book: "Jubilees", chapter: 19, verse: 16, text: "And Abraham saw the deeds of Esau, and he knew that in Jacob should his name and seed be called; and he called Rebecca and gave commandment regarding Jacob, for he knew that she (too) loved Jacob much more than Esau." },
  { book: "Jubilees", chapter: 19, verse: 17, text: "And he said unto her: My daughter, watch over my son Jacob, For he shall be in my stead on the earth, And for a blessing in the midst of the children of men, And for the glory of the whole seed of Shem." },
  { book: "Jubilees", chapter: 19, verse: 18, text: "For I know that the Lord will choose him to be a people for possession unto Himself, above all peoples that are upon the face of the earth." },
  { book: "Jubilees", chapter: 19, verse: 19, text: "And behold, Isaac my son loves Esau more than Jacob, but I see that thou truly lovest Jacob." },
  { book: "Jubilees", chapter: 19, verse: 20, text: "Add still further to thy kindness to him, And let thine eyes be upon him in love; For he shall be a blessing unto us on the earth from henceforth unto all generations of the earth." },
  { book: "Jubilees", chapter: 19, verse: 21, text: "Let thy hands be strong And let thy heart rejoice in thy son Jacob; For I have loved him far beyond all my sons. He shall be blessed for ever, And his seed shall fill the whole earth." },
  { book: "Jubilees", chapter: 19, verse: 22, text: "If a man can number the sand of the earth, His seed also shall be numbered." },
  { book: "Jubilees", chapter: 19, verse: 23, text: "And all the blessings wherewith the Lord hath blessed me and my seed shall belong to Jacob and his seed alway." },
  { book: "Jubilees", chapter: 19, verse: 24, text: "And in his seed shall my name be blessed, and the name of my fathers, Shem, and Noab, and Enoch, and Mahalalel, and Enos, and Seth, and Adam." },
  { book: "Jubilees", chapter: 19, verse: 25, text: "And these shall serve To lay the foundations of the heaven, And to strengthen the earth, And to renew all the luminaries which are in the firmament." },
  { book: "Jubilees", chapter: 19, verse: 26, text: "And he called Jacob before the eyes of Rebecca his mother, and kissed him, and blessed him, and said:" },
  { book: "Jubilees", chapter: 19, verse: 27, text: "'Jacob, my beloved son, whom my soul loveth, may God bless thee from above the firmament, and may He give thee all the blessings wherewith He blessed Adam, and Enoch, and Noah, and Shem; and all the things of which He told me, and all the things which He promised to give me, may he cause to cleave to thee and to thy seed for ever, according to the days of heaven above the earth." },
  { book: "Jubilees", chapter: 19, verse: 28, text: "And the Spirits of Mastêmâ shall not rule over thee or over thy seed to turn thee from the Lord, who is thy God from henceforth for ever." },
  { book: "Jubilees", chapter: 19, verse: 29, text: "And may the Lord God be a father to thee and thou the first-born son, and to the people alway." },
  { book: "Jubilees", chapter: 19, verse: 30, text: "Go in peace, my son.' And they both went forth together from Abraham." },
  { book: "Jubilees", chapter: 19, verse: 31, text: "And Rebecca loved Jacob, with all her heart and with all her soul, very much more than Esau; but Isaac loved Esau much more than Jacob." },
  { book: "Jubilees", chapter: 20, verse: 1, text: "And in the forty-second jubilee, in the first year of the seventh week, Abraham called Ishmael, [2052 (2045?) A.M.] and his twelve sons, and Isaac and his two sons, and the six sons of Keturah, and their sons." },
  { book: "Jubilees", chapter: 20, verse: 2, text: "And he commanded them that they should observe the way of the Lord; that they should work righteousness, and love each his neighbour, and act on this manner amongst all men; that they should each so walk with regard to them as to do judgment and righteousness on the earth." },
  { book: "Jubilees", chapter: 20, verse: 3, text: "That they should circumcise their sons, according to the covenant which He had made with them, and not deviate to the right hand or the left of all the paths which the Lord had commanded us; and that we should keep ourselves from all fornication and uncleanness, [and renounce from amongst us all fornication and uncleanness]." },
  { book: "Jubilees", chapter: 20, verse: 4, text: "And if any woman or maid commit fornication amongst you, burn her with fire and let them not commit fornication with her after their eyes and their heart; and let them not take to themselves wives from the daughters of Canaan; for the seed of Canaan will be rooted out of the land." },
  { book: "Jubilees", chapter: 20, verse: 5, text: "And he told them of the judgment of the giants, and the judgment of the Sodomites, how they had been judged on account of their wickedness, and had died on account of their fornication, and uncleanness, and mutual corruption through fornication." },
  { book: "Jubilees", chapter: 20, verse: 6, text: "'And guard yourselves from all fornication and uncleanness, And from all pollution of sin, Lest ye make our name a curse, And your whole life a hissing, And all your sons to be destroyed by the sword, And ye become accursed like Sodom, And all your remnant as the sons of Gomorrah." },
  { book: "Jubilees", chapter: 20, verse: 7, text: "I implore you, my sons, love the God of heaven And cleave ye to all His commandments. And walk not after their idols, and after their uncleannesses," },
  { book: "Jubilees", chapter: 20, verse: 8, text: "And make not for yourselves molten or graven gods; For they are vanity, And there is no spirit in them; For they are work of (men's) hands, And all who trust in them, trust in nothing." },
  { book: "Jubilees", chapter: 20, verse: 9, text: "Serve them not, nor worship them, But serve ye the most high God, and worship Him continually: And hope for His countenance always, And work uprightness and righteousness before Him, That He may have pleasure in you and grant you His mercy, And send rain upon you morning and evening, And bless all your works which ye have wrought upon the earth, And bless thy bread and thy water, And bless the fruit of thy womb and the fruit of thy land, And the herds of thy cattle, and the flocks of thy sheep." },
  { book: "Jubilees", chapter: 20, verse: 10, text: "And ye will be for a blessing on the earth, And all nations of the earth will desire you, And bless your sons in my name, That they may be blessed as I am." },
  { book: "Jubilees", chapter: 20, verse: 11, text: "And he gave to Ishmael and to his sons, and to the sons of Keturah, gifts, and sent them away from Isaac his son, and he gave everything to Isaac his son." },
  { book: "Jubilees", chapter: 20, verse: 12, text: "And Ishmael and his sons, and the sons of Keturah and their sons, went together and dwelt from Paran to the entering in of Babylon in all the land which is towards the East facing the desert." },
  { book: "Jubilees", chapter: 20, verse: 13, text: "And these mingled with each other, and their name was called Arabs, and Ishmaelites." },
  { book: "Jubilees", chapter: 21, verse: 1, text: "And in the sixth year of the seventh week of this jubilee Abraham called Isaac his son, and [2057 (2050?) A.M.] commanded him: saying, 'I am become old, and know not the day of my death, and am full of my days." },
  { book: "Jubilees", chapter: 21, verse: 2, text: "And behold, I am one hundred and seventy-five years old, and throughout all the days of my life I have remembered the Lord, and sought with all my heart to do His will, and to walk uprightly in all His ways." },
  { book: "Jubilees", chapter: 21, verse: 3, text: "My soul has hated idols, <and I have despised those that served them, and I have given my heart and spirit> that I might observe to do the will of Him who created me." },
  { book: "Jubilees", chapter: 21, verse: 4, text: "For He is the living God, and He is holy and faithful, and He is righteous beyond all, and there is with Him no accepting of (men's) persons and no accepting of gifts; for God is righteous, and executeth judgment on all those who transgress His commandments and despise His covenant." },
  { book: "Jubilees", chapter: 21, verse: 5, text: "And do thou, my son, observe His commandments and His ordinances and His judgments, and walk not after the abominations and after the graven images and after the molten images." },
  { book: "Jubilees", chapter: 21, verse: 6, text: "And eat no blood at all of animals or cattle, or of any bird which flies in the heaven." },
  { book: "Jubilees", chapter: 21, verse: 7, text: "And if thou dost slay a victim as an acceptable peace offering, slay ye it, and pour out its blood upon the altar, and all the fat of the offering offer on the altar with fine flour and the meat offering mingled with oil, with its drink offering -offer them all together on the altar of burnt offering; it is a sweet savour before the Lord." },
  { book: "Jubilees", chapter: 21, verse: 8, text: "And thou wilt offer the fat of the sacrifice of thank offerings on the fire which is upon the altar, and the fat which is on the belly, and all the fat on the inwards and the two kidneys, and all the fat that is upon them, and upon the loins and liver thou shalt remove, together with the kidneys." },
  { book: "Jubilees", chapter: 21, verse: 9, text: "And offer all these for a sweet savour acceptable before the Lord, with its meat-offering and with its drink- offering, for a sweet savour, the bread of the offering unto the Lord." },
  { book: "Jubilees", chapter: 21, verse: 10, text: "And eat its meat on that day and on the second day, and let not the sun on the second day go down upon it till it is eaten, and let nothing be left over for the third day; for it is not acceptable [for it is not approved] and let it no longer be eaten, and all who eat thereof will bring sin upon themselves; for thus I have found it written in the books of my forefathers, and in the words of Enoch, and in the words of Noah." },
  { book: "Jubilees", chapter: 21, verse: 11, text: "And on all thy oblations thou shalt strew salt, and let not the salt of the covenant be lacking in all thy oblations before the Lord." },
  { book: "Jubilees", chapter: 21, verse: 12, text: "And as regards the wood of the sacrifices, beware lest thou bring (other) wood for the altar in addition to these: cypress, bay, almond, fir, pine, cedar, savin, fig, olive, myrrh, laurel, aspalathus." },
  { book: "Jubilees", chapter: 21, verse: 13, text: "And of these kinds of wood lay upon the altar under the sacrifice, such as have been tested as to their appearance, and do not lay (thereon) any split or dark wood, (but) hard and clean, without fault, a sound and new growth; and do not lay (thereon) old wood, [for its fragrance is gone] for there is no longer fragrance in it as before." },
  { book: "Jubilees", chapter: 21, verse: 14, text: "Besides these kinds of wood there is none other that thou shalt place (on the altar), for the fragrance is dispersed, and the smell of its fragrance goes not up to heaven." },
  { book: "Jubilees", chapter: 21, verse: 15, text: "Observe this commandment and do it, my son, that thou mayst be upright in all thy deeds." },
  { book: "Jubilees", chapter: 21, verse: 16, text: "And at all times be clean in thy body, and wash thyself with water before thou approachest to offer on the altar, and wash thy hands and thy feet before thou drawest near to the altar; and when thou art done sacrificing, wash again thy hands and thy feet." },
  { book: "Jubilees", chapter: 21, verse: 17, text: "And let no blood appear upon you nor upon your clothes; be on thy guard, my son, against blood, be on thy guard exceedingly; cover it with dust." },
  { book: "Jubilees", chapter: 21, verse: 18, text: "And do not eat any blood for it is the soul; eat no blood whatever." },
  { book: "Jubilees", chapter: 21, verse: 19, text: "And take no gifts for the blood of man, lest it be shed with impunity, without judgment; for it is the blood that is shed that causes the earth to sin, and the earth cannot be cleansed from the blood of man save by the blood of him who shed it." },
  { book: "Jubilees", chapter: 21, verse: 20, text: "And take no present or gift for the blood of man: blood for blood, that thou mayest be accepted before the Lord, the Most High God; for He is the defence of the good: and that thou mayest be preserved from all evil, and that He may save thee from every kind of death." },
  { book: "Jubilees", chapter: 21, verse: 21, text: "I see, my son, That all the works of the children of men are sin and wickedness, And all their deeds are uncleanness and an abomination and a pollution, And there is no righteousness with them." },
  { book: "Jubilees", chapter: 21, verse: 22, text: "Beware, lest thou shouldest walk in their ways And tread in their paths, And sin a sin unto death before the Most High God. Else He will [hide His face from thee And] give thee back into the hands of thy transgression, And root thee out of the land, and thy seed likewise from under heaven, And thy name and thy seed shall perish from the whole earth." },
  { book: "Jubilees", chapter: 21, verse: 23, text: "Turn away from all their deeds and all their uncleanness, And observe the ordinance of the Most High God, And do His will and be upright in all things." },
  { book: "Jubilees", chapter: 21, verse: 24, text: "And He will bless thee in all thy deeds, And will raise up from thee a plant of righteousness through all the earth, throughout all generations of the earth, And my name and thy name shall not be forgotten under heaven for ever." },
  { book: "Jubilees", chapter: 21, verse: 25, text: "Go, my son in peace. May the Most High God, my God and thy God, strengthen thee to do His will, And may He bless all thy seed and the residue of thy seed for the generations for ever, with all righteous blessings, That thou mayest be a blessing on all the earth.'" },
  { book: "Jubilees", chapter: 21, verse: 26, text: "And he went out from him rejoicing." },
  { book: "Jubilees", chapter: 22, verse: 1, text: "And it came to pass in the first week in the forty-fourth jubilee, in the second year, that is, the year in which Abraham died, that Isaac and Ishmael came from the Well of the Oath to celebrate the feast of weeks -that is, the feast of the first fruits of the harvest-to Abraham, their father, and Abraham rejoiced because his two sons had come." },
  { book: "Jubilees", chapter: 22, verse: 2, text: "For Isaac had many possessions in Beersheba, and Isaac was wont to go and see his possessions and to return to his father." },
  { book: "Jubilees", chapter: 22, verse: 3, text: "And in those days Ishmael came to see his father, and they both came together, and Isaac offered a sacrifice for a burnt offering, and presented it on the altar of his father which he had made in Hebron." },
  { book: "Jubilees", chapter: 22, verse: 4, text: "And he offered a thank offering and made a feast of joy before Ishmael, his brother: and Rebecca made new cakes from the new grain, and gave them to Jacob, her son, to take them to Abraham, his father, from the first fruits of the land, that he might eat and bless the Creator of all things before he died." },
  { book: "Jubilees", chapter: 22, verse: 5, text: "And Isaac, too, sent by the hand of Jacob to Abraham a best thank offering, that he might eat and drink." },
  { book: "Jubilees", chapter: 22, verse: 6, text: "And he eat and drank, and blessed the Most High God, Who hath created heaven and earth, Who hath made all the fat things of the earth, And given them to the children of men That they might eat and drink and bless their Creator." },
  { book: "Jubilees", chapter: 22, verse: 7, text: "'And now I give thanks unto Thee, my God, because thou hast caused me to see this day: behold, I am one hundred three score and fifteen years, an old man and full of days, and all my days have been unto me peace." },
  { book: "Jubilees", chapter: 22, verse: 8, text: "The sword of the adversary has not overcome me in all that Thou hast given me and my children all the days of my life until this day." },
  { book: "Jubilees", chapter: 22, verse: 9, text: "My God, may Thy mercy and Thy peace be upon Thy servant, and upon the seed of his sons, that they may be to Thee a chosen nation and an inheritance from amongst all the nations of the earth from henceforth unto all the days of the generations of the earth, unto all the ages.'" },
  { book: "Jubilees", chapter: 22, verse: 10, text: "And he called Jacob and said: 'My son Jacob, may the God of all bless thee and strengthen thee to do righteousness, and His will before Him, and may He choose thee and thy seed that ye may become a people for His inheritance according to His will alway." },
  { book: "Jubilees", chapter: 22, verse: 11, text: "And do thou, my son, Jacob, draw near and kiss me.' And he drew near and kissed him, and he said: 'Blessed be my son Jacob And all the sons of God Most High, unto all the ages: May God give unto thee a seed of righteousness; And some of thy sons may He sanctify in the midst of the whole earth; May nations serve thee, And all the nations bow themselves before thy seed." },
  { book: "Jubilees", chapter: 22, verse: 12, text: "Be strong in the presence of men, And exercise authority over all the seed of Seth. Then thy ways and the ways of thy sons will be justified, So that they shall become a holy nation." },
  { book: "Jubilees", chapter: 22, verse: 13, text: "May the Most High God give thee all the blessings Wherewith He has blessed me And wherewith He blessed Noah and Adam; May they rest on the sacred head of thy seed from generation to generation for ever." },
  { book: "Jubilees", chapter: 22, verse: 14, text: "And may He cleanse thee from all unrighteousness and impurity, That thou mayest be forgiven all the transgressions; which thou hast committed ignorantly. And may He strengthen thee, And bless thee. And mayest thou inherit the whole earth," },
  { book: "Jubilees", chapter: 22, verse: 15, text: "And may He renew His covenant with thee. That thou mayest be to Him a nation for His inheritance for all the ages, And that He may be to thee and to thy seed a God in truth and righteousness throughout all the days of the earth." },
  { book: "Jubilees", chapter: 22, verse: 16, text: "And do thou, my son Jacob, remember my words, And observe the commandments of Abraham, thy father: Separate thyself from the nations, And eat not with them: And do not according to their works, And become not their associate; For their works are unclean, And all their ways are a Pollution and an abomination and uncleanness." },
  { book: "Jubilees", chapter: 22, verse: 17, text: "They offer their sacrifices to the dead And they worship evil spirits, And they eat over the graves, And all their works are vanity and nothingness." },
  { book: "Jubilees", chapter: 22, verse: 18, text: "They have no heart to understand And their eyes do not see what their works are, And how they err in saying to a piece of wood: 'Thou art my God,' And to a stone: 'Thou art my Lord and thou art my deliverer.' [And they have no heart.]" },
  { book: "Jubilees", chapter: 22, verse: 19, text: "And as for thee, my son Jacob, May the Most High God help thee And the God of heaven bless thee And remove thee from their uncleanness and from all their error." },
  { book: "Jubilees", chapter: 22, verse: 20, text: "Be thou ware, my son Jacob, of taking a wife from any seed of the daughters of Canaan; For all his seed is to be rooted out of the earth." },
  { book: "Jubilees", chapter: 22, verse: 21, text: "For, owing to the transgression of Ham, Canaan erred, And all his seed shall be destroyed from off the earth and all the residue thereof, And none springing from him shall be saved on the day of judgment." },
  { book: "Jubilees", chapter: 22, verse: 22, text: "And as for all the worshippers of idols and the profane (b) There shall be no hope for them in the land of the living; (c) And there shall be no remembrance of them on the earth; (c) For they shall descend into Sheol, (d) And into the place of condemnation shall they go, As the children of Sodom were taken away from the earth So will all those who worship idols be taken away." },
  { book: "Jubilees", chapter: 22, verse: 23, text: "Fear not, my son Jacob, And be not dismayed, O son of Abraham: May the Most High God preserve thee from destruction, And from all the paths of error may he deliver thee." },
  { book: "Jubilees", chapter: 22, verse: 24, text: "This house have I built for myself that I might put my name upon it in the earth: [it is given to thee and to thy seed for ever], and it will be named the house of Abraham; it is given to thee and to thy seed for ever; for thou wilt build my house and establish my name before God for ever: thy seed and thy name will stand throughout all generations of the earth.'" },
  { book: "Jubilees", chapter: 22, verse: 25, text: "And he ceased commanding him and blessing him." },
  { book: "Jubilees", chapter: 22, verse: 26, text: "And the two lay together on one bed, and Jacob slept in the bosom of Abraham, his father's father and he kissed him seven times, and his affection and his heart rejoiced over him." },
  { book: "Jubilees", chapter: 22, verse: 27, text: "And he blessed him with all his heart and said: 'The Most High God, the God of all, and Creator of all, who brought me forth from Ur of the Chaldees that he might give me this land to inherit it for ever, and that I might establish a holy seed-blessed be the Most High for ever.'" },
  { book: "Jubilees", chapter: 22, verse: 28, text: "And he blessed Jacob and said: 'My son, over whom with all my heart and my affection I rejoice, may Thy grace and Thy mercy be lift up upon him and upon his seed alway." },
  { book: "Jubilees", chapter: 22, verse: 29, text: "And do not forsake him, nor set him at nought from henceforth unto the days of eternity, and may Thine eyes be opened upon him and upon his seed, that Thou mayst preserve him, and bless him, and mayest sanctify him as a nation for Thine inheritance;" },
  { book: "Jubilees", chapter: 22, verse: 30, text: "And bless him with all Thy blessings from henceforth unto all the days of eternity, and renew Thy covenant and Thy grace with him and with his seed according to all Thy good pleasure unto all the generations of the earth.'" },
  { book: "Jubilees", chapter: 23, verse: 1, text: "And he placed two fingers of Jacob on his eyes, and he blessed the God of gods, and he covered his face and stretched out his feet and slept the sleep of eternity, and was gathered to his fathers." },
  { book: "Jubilees", chapter: 23, verse: 2, text: "And notwithstanding all this Jacob was lying in his bosom, and knew not that Abraham, his father's father, was dead." },
  { book: "Jubilees", chapter: 23, verse: 3, text: "And Jacob awoke from his sleep, and behold Abraham was cold as ice, and he said 'Father, father'; but there was none that spake, and he knew that he was dead." },
  { book: "Jubilees", chapter: 23, verse: 4, text: "And he arose from his bosom and ran and told Rebecca, his mother; and Rebecca went to Isaac in the night, and told him; and they went together, and Jacob with them, and a lamp was in his hand, and when they had gone in they found Abraham lying dead." },
  { book: "Jubilees", chapter: 23, verse: 5, text: "And Isaac fell on the face of his father and wept and kissed him." },
  { book: "Jubilees", chapter: 23, verse: 6, text: "And the voices were heard in the house of Abraham, and Ishmael his son arose, and went to Abraham his father, and wept over Abraham his father, he and all the house of Abraham, and they wept with a great weeping." },
  { book: "Jubilees", chapter: 23, verse: 7, text: "And his sons Isaac and Ishmael buried him in the double cave, near Sarah his wife, and they wept for him forty days, all the men of his house, and Isaac and Ishmael, and all their sons, and all the sons of Keturah in their places; and the days of weeping for Abraham were ended." },
  { book: "Jubilees", chapter: 23, verse: 8, text: "And he lived three jubilees and four weeks of years, one hundred and seventy-five years, and completed the days of his life, being old and full of days." },
  { book: "Jubilees", chapter: 23, verse: 9, text: "For the days of the forefathers, of their life, were nineteen jubilees; and after the Flood they began to grow less than nineteen jubilees, and to decrease in jubilees, and to grow old quickly, and to be full of their days by reason of manifold tribulation and the wickedness of their ways, with the exception of Abraham." },
  { book: "Jubilees", chapter: 23, verse: 10, text: "For Abraham was perfect in all his deeds with the Lord, and well-pleasing in righteousness all the days of his life; and behold, he did not complete four jubilees in his life, when he had grown old by reason of the wickedness, and was full of his days." },
  { book: "Jubilees", chapter: 23, verse: 11, text: "And all the generations which shall arise from this time until the day of the great judgment shall grow old quickly, before they complete two jubilees, and their knowledge shall forsake them by reason of their old age Land all their know- ledge shall vanish away]." },
  { book: "Jubilees", chapter: 23, verse: 12, text: "And in those days, if a man live a jubilee and a-half of years, they shall say regarding him: 'He has lived long, and the greater part of his days are pain and sorrow and tribulation, and there is no peace:" },
  { book: "Jubilees", chapter: 23, verse: 13, text: "For calamity follows on calamity, and wound on wound, and tribulation on tribulation, and evil tidings on evil tidings, and illness on illness, and all evil judgments such as these, one with another, illness and overthrow, and snow and frost and ice, and fever, and chills, and torpor, and famine, and death, and sword, and captivity, and all kinds of calamities and pains.'" },
  { book: "Jubilees", chapter: 23, verse: 14, text: "And all these shall come on an evil generation, which transgresses on the earth: their works are uncleanness and fornication, and pollution and abominations." },
  { book: "Jubilees", chapter: 23, verse: 15, text: "Then they shall say: 'The days of the forefathers were many (even), unto a thousand years, and were good; but behold, the days of our life, if a man has lived many, are three score years and ten, and, if he is strong, four score years, and those evil, and there is no peace in the days of this evil generation.'" },
  { book: "Jubilees", chapter: 23, verse: 16, text: "And in that generation the sons shall convict their fathers and their elders of sin and unrighteousness, and of the words of their mouth and the great wickednesses which they perpetrate, and concerning their forsaking the covenant which the Lord made between them and Him, that they should observe and do all His commandments and His ordinances and all His laws, without departing either to the right hand or the left." },
  { book: "Jubilees", chapter: 23, verse: 17, text: "For all have done evil, and every mouth speaks iniquity and all their works are an uncleanness and an abomination, and all their ways are pollution, uncleanness and destruction." },
  { book: "Jubilees", chapter: 23, verse: 18, text: "Behold the earth shall be destroyed on account of all their works, and there shall be no seed of the vine, and no oil; for their works are altogether faithless, and they shall all perish together, beasts and cattle and birds, and all the fish of the sea, on account of the children of men." },
  { book: "Jubilees", chapter: 23, verse: 19, text: "And they shall strive one with another, the young with the old, and the old with the young, the poor with the rich, the lowly with the great, and the beggar with the prince, on account of the law and the covenant; for they have forgotten commandment, and covenant, and feasts, and months, and Sabbaths, and jubilees, and all judgments." },
  { book: "Jubilees", chapter: 23, verse: 20, text: "And they shall stand <with bows and> swords and war to turn them back into the way; but they shall not return until much blood has been shed on the earth, one by another." },
  { book: "Jubilees", chapter: 23, verse: 21, text: "And those who have escaped shall not return from their wickedness to the way of righteousness, but they shall all exalt themselves to deceit and wealth, that they may each take all that is his neighbour's, and they shall name the great name, but not in truth and not in righteousness, and they shall defile the holy of holies with their uncleanness and the corruption of their pollution." },
  { book: "Jubilees", chapter: 23, verse: 22, text: "And a great punishment shall befall the deeds of this generation from the Lord, and He will give them over to the sword and to judgment and to captivity, and to be plundered and devoured." },
  { book: "Jubilees", chapter: 23, verse: 23, text: "And He will wake up against them the sinners of the Gentiles, who have neither mercy nor compassion, and who shall respect the person of none, neither old nor young, nor any one, for they are more wicked and strong to do evil than all the children of men. And they shall use violence against Israel and transgression against Jacob, And much blood shall be shed upon the earth, And there shall be none to gather and none to bury." },
  { book: "Jubilees", chapter: 23, verse: 24, text: "In those days they shall cry aloud, And call and pray that they may be saved from the hand of the sinners, the Gentiles; But none shall be saved." },
  { book: "Jubilees", chapter: 23, verse: 25, text: "And the heads of the children shall be white with grey hair, And a child of three weeks shall appear old like a man of one hundred years, And their stature shall be destroyed by tribulation and oppression." },
  { book: "Jubilees", chapter: 23, verse: 26, text: "And in those days the children shall begin to study the laws, And to seek the commandments, And to return to the path of righteousness." },
  { book: "Jubilees", chapter: 23, verse: 27, text: "And the days shall begin to grow many and increase amongst those children of men Till their days draw nigh to one thousand years. And to a greater number of years than (before) was the number of the days." },
  { book: "Jubilees", chapter: 23, verse: 28, text: "And there shall be no old man Nor one who is <not> satisfied with his days, For all shall be (as) children and youths." },
  { book: "Jubilees", chapter: 23, verse: 29, text: "And all their days they shall complete and live in peace and in joy, And there shall be no Satan nor any evil destroyer; For all their days shall be days of blessing and healing." },
  { book: "Jubilees", chapter: 23, verse: 30, text: "And at that time the Lord will heal His servants, And they shall rise up and see great peace, And drive out their adversaries. And the righteous shall see and be thankful, And rejoice with joy for ever and ever, And shall see all their judgments and all their curses on their enemies." },
  { book: "Jubilees", chapter: 23, verse: 31, text: "And their bones shall rest in the earth, And their spirits shall have much joy, And they shall know that it is the Lord who executes judgment, And shows mercy to hundreds and thousands and to all that love Him" },
  { book: "Jubilees", chapter: 23, verse: 32, text: "And do thou, Moses, write down these words; for thus are they written, and they record (them) on the heavenly tablets for a testimony for the generations for ever." },
  { book: "Jubilees", chapter: 24, verse: 1, text: "And it came to pass after the death of Abraham, that the Lord blessed Isaac his son, and he arose from Hebron and went and dwelt at the Well of the Vision in the first year of the third week [2073 A.M.] of this jubilee, seven years." },
  { book: "Jubilees", chapter: 24, verse: 2, text: "And in the first year of the fourth week a famine began in the land, [2080 A.M.] besides the first famine, which had been in the days of Abraham." },
  { book: "Jubilees", chapter: 24, verse: 3, text: "And Jacob sod lentil pottage, and Esau came from the field hungry. And he said to Jacob his brother: 'Give me of this red pottage.' And Jacob said to him: 'Sell to me thy [primogeniture, this] birthright and I will give thee bread, and also some of this lentil pottage.'" },
  { book: "Jubilees", chapter: 24, verse: 4, text: "And Esau said in his heart: 'I shall die; of what profit to me is this birthright?" },
  { book: "Jubilees", chapter: 24, verse: 5, text: "'And he said to Jacob: 'I give it to thee.' And Jacob said: 'Swear to me, this day,' and he sware unto him." },
  { book: "Jubilees", chapter: 24, verse: 6, text: "And Jacob gave his brother Esau bread and pottage, and he eat till he was satisfied, and Esau despised his birthright; for this reason was Esau's name called Edom, on account of the red pottage which Jacob gave him for his birthright." },
  { book: "Jubilees", chapter: 24, verse: 7, text: "And Jacob became the elder, and Esau was brought down from his dignity." },
  { book: "Jubilees", chapter: 24, verse: 8, text: "And the famine was over the land, and Isaac departed to go down into Egypt in the second year of this week, and went to the king of the Philistines to Gerar, unto Abimelech." },
  { book: "Jubilees", chapter: 24, verse: 9, text: "And the Lord appeared unto him and said unto him: 'Go not down into Egypt; dwell in the land that I shall tell thee of, and sojourn in this land, and I will be with thee and bless thee." },
  { book: "Jubilees", chapter: 24, verse: 10, text: "For to thee and to thy seed will I give all this land, and I will establish My oath which I sware unto Abraham thy father, and I will multiply thy seed as the stars of heaven, and will give unto thy seed all this land." },
  { book: "Jubilees", chapter: 24, verse: 11, text: "And in thy seed shall all the nations of the earth be blessed, because thy father obeyed My voice, and kept My charge and My commandments, and My laws, and My ordinances, and My covenant; and now obey My voice and dwell in this land.'" },
  { book: "Jubilees", chapter: 24, verse: 12, text: "And he dwelt in Gelar three weeks of years." },
  { book: "Jubilees", chapter: 24, verse: 13, text: "And Abimelech charged concerning him, [2080-2101 A.M.] and concerning all that was his, saying: 'Any man that shall touch him or aught that is his shall surely die.'" },
  { book: "Jubilees", chapter: 24, verse: 14, text: "And Isaac waxed strong among the Philistines, and he got many possessions, oxen and sheep and camels and asses and a great household." },
  { book: "Jubilees", chapter: 24, verse: 15, text: "And he sowed in the land of the Philistines and brought in a hundred-fold, and Isaac became exceedingly great, and the Philistines envied him." },
  { book: "Jubilees", chapter: 24, verse: 16, text: "Now all the wells which the servants of Abraham had dug during the life of Abraham, the Philistines had stopped them after the death of Abraham, and filled them with earth." },
  { book: "Jubilees", chapter: 24, verse: 17, text: "And Abimelech said unto Isaac: 'Go from us, for thou art much mightier than we', and Isaac departed thence in the first year of the seventh week, and sojourned in the valleys of Gerar." },
  { book: "Jubilees", chapter: 24, verse: 18, text: "And they digged again the wells of water which the servants of Abraham, his father, had digged, and which the Philistines had closed after the death of Abraham his father, and he called their names as Abraham his father had named them." },
  { book: "Jubilees", chapter: 24, verse: 19, text: "And the servants of Isaac dug a well in the valley, and found living water, and the shepherds of Gerar strove with the shepherds of Isaac, saying: 'The water is ours'; and Isaac called the name of the well 'Perversity', because they had been perverse with us." },
  { book: "Jubilees", chapter: 24, verse: 20, text: "And they dug a second well, and they strove for that also, and he called its name 'Enmity'. And he arose from thence and they digged another well, and for that they strove not, and he called the name of it 'Room', and Isaac said: 'Now the Lord hath made room for us, and we have increased in the land.'" },
  { book: "Jubilees", chapter: 24, verse: 21, text: "And he went up from thence to the Well of the Oath in the first year of the first week in the [2108 A.M.] forty-fourth jubilee." },
  { book: "Jubilees", chapter: 24, verse: 22, text: "And the Lord appeared to him that night, on the new moon of the first month, and said unto him: 'I am the God of Abraham thy father; fear not, for I am with thee, and shall bless thee and shall surely multiply thy seed as the sand of the earth, for the sake of Abraham my servant.'" },
  { book: "Jubilees", chapter: 24, verse: 23, text: "And he built an altar there, which Abraham his father had first built, and he called upon the name of the Lord, and he offered sacrifice to the God of Abraham his father." },
  { book: "Jubilees", chapter: 24, verse: 24, text: "And they digged a well and they found living water." },
  { book: "Jubilees", chapter: 24, verse: 25, text: "And the servants of Isaac digged another well and did not find water, and they went and told Isaac that they had not found water, and Isaac said: 'I have sworn this day to the Philistines and this thing has been announced to us.'" },
  { book: "Jubilees", chapter: 24, verse: 26, text: "And he called the name of that place the Well of the Oath; for there he had sworn to Abimelech and Ahuzzath his friend and Phicol the prefect Or his host." },
  { book: "Jubilees", chapter: 24, verse: 27, text: "And Isaac knew that day that under constraint he had sworn to them to make peace with them." },
  { book: "Jubilees", chapter: 24, verse: 28, text: "And Isaac on that day cursed the Philistines and said: 'Cursed be the Philistines unto the day of wrath and indignation from the midst of all nations; may God make them a derision and a curse and an object of wrath and indignation in the hands of the sinners the Gentiles and in the hands of the Kittim." },
  { book: "Jubilees", chapter: 24, verse: 29, text: "And whoever escapes the sword of the enemy and the Kittim, may the righteous nation root out in judgment from under heaven; for they shall be the enemies and foes of my children throughout their generations upon the earth." },
  { book: "Jubilees", chapter: 24, verse: 30, text: "And no remnant shall be left to them, Nor one that shall be saved on the day of the wrath of judgment; For destruction and rooting out and expulsion from the earth is the whole seed of the Philistines (reserved), And there shall no longer be left for these Caphtorim a name or a seed on the earth." },
  { book: "Jubilees", chapter: 24, verse: 31, text: "For though he ascend unto heaven, Thence shall he be brought down, And though he make himself strong on earth, Thence shall he be dragged forth, And though he hide himself amongst the nations, Even from thence shall he be rooted out; And though he descend into Sheol, There also shall his condemnation be great, And there also he shall have no peace." },
  { book: "Jubilees", chapter: 24, verse: 32, text: "And if he go into captivity, By the hands of those that seek his life shall they slay him on the way, And neither name nor seed shall be left to him on all the earth; For into eternal malediction shall he depart.'" },
  { book: "Jubilees", chapter: 24, verse: 33, text: "And thus is it written and engraved concerning him on the heavenly tablets, to do unto him on the day of judgment, so that he may be rooted out of the earth." },
  { book: "Jubilees", chapter: 25, verse: 1, text: "And in the second year of this week in this jubilee, Rebecca called Jacob her son, and spake unto [2109 A.M.] him, saying: 'My son, do not take thee a wife of the daughters of Canaan, as Esau, thy brother, who took him two wives of the daughters of Canaan, and they have embittered my soul with all their unclean deeds: for all their deeds are fornication and lust, and there is no righteousness with them, for (their deeds) are evil." },
  { book: "Jubilees", chapter: 25, verse: 2, text: "And I, my son, love thee exceedingly, and my heart and my affection bless thee every hour of the day and watch of the night." },
  { book: "Jubilees", chapter: 25, verse: 3, text: "And now, my son, hearken to my voice, and do the will of thy mother, and do not take thee a wife of the daughters of this land, but only of the house of my father, and of my father's kindred. Thou shalt take thee a wife of the house of my father, and the Most High God will bless thee, and thy children shall be a righteous generation and a holy seed.'" },
  { book: "Jubilees", chapter: 25, verse: 4, text: "And then spake Jacob to Rebecca, his mother, and said unto her: 'Behold, mother, I am nine weeks of years old, and I neither know nor have I touched any woman, nor have I betrothed myself to any, nor even think of taking me a wife of the daughters of Canaan." },
  { book: "Jubilees", chapter: 25, verse: 5, text: "For I remember, mother, the words of Abraham, our father, for he commanded me not to take a wife of the daughters of Canaan, but to take me a wife from the seed of my father's house and from my kindred." },
  { book: "Jubilees", chapter: 25, verse: 6, text: "I have heard before that daughters have been born to Laban, thy brother, and I have set my heart on them to take a wife from amongst them." },
  { book: "Jubilees", chapter: 25, verse: 7, text: "And for this reason I have guarded myself in my spirit against sinning or being corrupted in all my ways throughout all the days of my life; for with regard to lust and fornication, Abraham, my father, gave me many commands." },
  { book: "Jubilees", chapter: 25, verse: 8, text: "And, despite all that he has commanded me, these two and twenty years my brother has striven with me, and spoken frequently to me and said: 'My brother, take to wife a sister of my two wives'; but I refuse to do as he has done." },
  { book: "Jubilees", chapter: 25, verse: 9, text: "I swear before thee, mother, that all the days of my life I will not take me a wife from the daughters of the seed of Canaan, and I will not act wickedly as my brother has done." },
  { book: "Jubilees", chapter: 25, verse: 10, text: "Fear not, mother; be assured that I shall do thy will and walk in uprightness, and not corrupt my ways for ever.'" },
  { book: "Jubilees", chapter: 25, verse: 11, text: "And thereupon she lifted up her face to heaven and extended the fingers of her hands, and opened her mouth and blessed the Most High God, who had created the heaven and the earth, and she gave Him thanks and praise." },
  { book: "Jubilees", chapter: 25, verse: 12, text: "And she said: 'Blessed be the Lord God, and may His holy name be blessed for ever and ever, who has given me Jacob as a pure son and a holy seed; for he is Thine, and Thine shall his seed be continually and throughout all the generations for evermore." },
  { book: "Jubilees", chapter: 25, verse: 13, text: "Bless him, O Lord, and place in my mouth the blessing of righteousness, that I may bless him.'" },
  { book: "Jubilees", chapter: 25, verse: 14, text: "And at that hour, when the spirit of righteousness descended into her mouth, she placed both her hands on the head of Jacob, and said:" },
  { book: "Jubilees", chapter: 25, verse: 15, text: "'Blessed art thou, Lord of righteousness and God of the ages And may He bless thee beyond all the generations of men. May He give thee, my Son, the path of righteousness, And reveal righteousness to thy seed." },
  { book: "Jubilees", chapter: 25, verse: 16, text: "And may He make thy sons many during thy life, And may they arise according to the number of the months of the year. And may their sons become many and great beyond the stars of heaven, And their numbers be more than the sand of the sea." },
  { book: "Jubilees", chapter: 25, verse: 17, text: "And may He give them this goodly land -as He said He would give it to Abraham and to his seed after him alway- And may they hold it as a possession for ever." },
  { book: "Jubilees", chapter: 25, verse: 18, text: "And may I see (born) unto thee, my son, blessed children during my life, And a blessed and holy seed may all thy seed be." },
  { book: "Jubilees", chapter: 25, verse: 19, text: "And as thou hast refreshed thy mother's spirit during her life, The womb of her that bare thee blesses thee thus, [My affection] and my breasts bless thee And my mouth and my tongue praise thee greatly." },
  { book: "Jubilees", chapter: 25, verse: 20, text: "Increase and spread over the earth, And may thy seed be perfect in the joy of heaven and earth for ever; And may thy seed rejoice, And on the great day of peace may it have peace." },
  { book: "Jubilees", chapter: 25, verse: 21, text: "And may thy name and thy seed endure to all the ages, And may the Most High God be their God, And may the God of righteousness dwell with them, And by them may His sanctuary be built unto all the ages." },
  { book: "Jubilees", chapter: 25, verse: 22, text: "Blessed be he that blesseth thee, And all flesh that curseth thee falsely, may it be cursed.'" },
  { book: "Jubilees", chapter: 25, verse: 23, text: "And she kissed him, and said to him; 'May the Lord of the world love thee As the heart of thy mother and her affection rejoice in thee and bless thee.' And she ceased from blessing." },
  { book: "Jubilees", chapter: 26, verse: 1, text: "And in the seventh year of this week Isaac called Esau, his elder Son, and said unto him: ' I am [2114 A.M.] old, my son, and behold my eyes are dim in seeing, and I know not the day of my death." },
  { book: "Jubilees", chapter: 26, verse: 2, text: "And now take thy hunting weapons thy quiver and thy bow, and go out to the field, and hunt and catch me (venison), my son, and make me savoury meat, such as my soul loveth, and bring it to me that I may eat, and that my soul may bless thee before I die.'" },
  { book: "Jubilees", chapter: 26, verse: 3, text: "But Rebecca heard Isaac speaking to Esau." },
  { book: "Jubilees", chapter: 26, verse: 4, text: "And Esau went forth early to the field to hunt and catch and bring home to his father." },
  { book: "Jubilees", chapter: 26, verse: 5, text: "And Rebecca called Jacob, her son, and said unto him: 'Behold, I heard Isaac, thy father, speak unto Esau, thy brother, saying: \"Hunt for me, and make me savoury meat, and bring (it) to me that" },
  { book: "Jubilees", chapter: 26, verse: 6, text: "I may eat and bless thee before the Lord before I die.\" And now, my son, obey my voice in that which I command thee: Go to thy flock and fetch me two good kids of the goats, and I will make them savoury meat for thy father, such as he loves, and thou shalt bring (it) to thy father that he may eat and bless thee before the Lord before he die, and that thou mayst be blessed.'" },
  { book: "Jubilees", chapter: 26, verse: 7, text: "And Jacob said to Rebecca his mother: 'Mother, I shall not withhold anything which my father would eat, and which would please him: only I fear, my mother, that he will recognise my voice and wish to touch me." },
  { book: "Jubilees", chapter: 26, verse: 8, text: "And thou knowest that I am smooth, and Esau, my brother, is hairy, and I shall appear before his eyes as an evildoer, and shall do a deed which he had not commanded me, and he will be wroth with me, and I shall bring upon myself a curse, and not a blessing.'" },
  { book: "Jubilees", chapter: 26, verse: 9, text: "And Rebecca, his mother, said unto him: 'Upon me be thy curse, my son, only obey my voice.'" },
  { book: "Jubilees", chapter: 26, verse: 10, text: "And Jacob obeyed the voice of Rebecca, his mother, and went and fetched two good and fat kids of the goats, and brought them to his mother, and his mother made them ~savoury meat~ such as he loved." },
  { book: "Jubilees", chapter: 26, verse: 11, text: "And Rebecca took the goodly rainment of Esau, her elder son, which was with her in the house, and she clothed Jacob, her younger son, (with them), and she put the skins of the kids upon his hands and on the exposed parts of his neck." },
  { book: "Jubilees", chapter: 26, verse: 12, text: "And she gave the meat and the bread which she had prepared into the hand of her son Jacob." },
  { book: "Jubilees", chapter: 26, verse: 13, text: "And Jacob went in to his father and said: 'I am thy son: I have done according as thou badest me: arise and sit and eat of that which I have caught, father, that thy soul may bless me.'" },
  { book: "Jubilees", chapter: 26, verse: 14, text: "And Isaac said to his son: 'How hast thou found so quickly, my son?" },
  { book: "Jubilees", chapter: 26, verse: 15, text: "'And Jacob said: 'Because <the Lord> thy God caused me to find.'" },
  { book: "Jubilees", chapter: 26, verse: 16, text: "And Isaac said unto him: 'Come near, that I may feel thee, my son, if thou art my son Esau or not.'" },
  { book: "Jubilees", chapter: 26, verse: 17, text: "And Jacob went near to Isaac, his father, and he felt him and said: 'The voice is Jacob's voice, but the hands are the hands of Esau,'" },
  { book: "Jubilees", chapter: 26, verse: 18, text: "and he discerned him not, because it was a dispensation from heaven to remove his power of perception and Isaac discerned not, for his hands were hairy as his brother Esau's, so that he blessed him." },
  { book: "Jubilees", chapter: 26, verse: 19, text: "And he said: 'Art thou my son Esau? ' and he said: 'I am thy son': and he said, 'Bring near to me that I may eat of that which thou hast caught, my son, that my soul may bless thee.'" },
  { book: "Jubilees", chapter: 26, verse: 20, text: "And he brought near to him, and he did eat, and he brought him wine and he drank." },
  { book: "Jubilees", chapter: 26, verse: 21, text: "And Isaac, his father, said unto him: 'Come near and kiss me, my son." },
  { book: "Jubilees", chapter: 26, verse: 22, text: "And he came near and kissed him. And he smelled the smell of his raiment, and he blessed him and said: 'Behold, the smell of my son is as the smell of a <full> field which the Lord hath blessed." },
  { book: "Jubilees", chapter: 26, verse: 23, text: "And may the Lord give thee of the dew of heaven And of the dew of the earth, and plenty of corn and oil: Let nations serve thee, And peoples bow down to thee." },
  { book: "Jubilees", chapter: 26, verse: 24, text: "Be lord over thy brethren, And let thy mother's sons bow down to thee; And may all the blessings wherewith the Lord hath blessed me and blessed Abraham, my father; Be imparted to thee and to thy seed for ever: Cursed be he that curseth thee, And blessed be he that blesseth thee.'" },
  { book: "Jubilees", chapter: 26, verse: 25, text: "And it came to pass as soon as Isaac had made an end of blessing his son Jacob, and Jacob had gone forth from Isaac his father he hid himself and Esau, his brother, came in from his hunting." },
  { book: "Jubilees", chapter: 26, verse: 26, text: "And he also made savoury meat, and brought (it) to his father, and said unto his father: 'Let my father arise, and eat of my venison that thy soul may bless me.'" },
  { book: "Jubilees", chapter: 26, verse: 27, text: "And Isaac, his father, said unto him: 'Who art thou? 'And he said unto him: 'I am thy first born, thy son Esau: I have done as thou hast commanded me.'" },
  { book: "Jubilees", chapter: 26, verse: 28, text: "And Isaac was very greatly astonished, and said: 'Who is he that hath hunted and caught and brought (it) to me, and I have eaten of all before thou camest, and have blessed him: (and) he shall be blessed, and all his seed for ever.'" },
  { book: "Jubilees", chapter: 26, verse: 29, text: "And it came to pass when Esau heard the words of his father Isaac that he cried with an exceeding great and bitter cry, and said unto his father: 'Bless me, (even) me also, father.'" },
  { book: "Jubilees", chapter: 26, verse: 30, text: "And he said unto him: 'Thy brother came with guile, and hath taken away thy blessing.' And he said: 'Now I know why his name is named Jacob: behold, he hath supplanted me these two times: he took away my birth-right, and now he hath taken away my blessing.'" },
  { book: "Jubilees", chapter: 26, verse: 31, text: "And he said: 'Hast thou not reserved a blessing for me, father?' and Isaac answered and said unto Esau: 'Behold, I have made him thy lord, And all his brethren have I given to him for servants, And with plenty of corn and wine and oil have I strengthened him: And what now shall I do for thee, my son?'" },
  { book: "Jubilees", chapter: 26, verse: 32, text: "And Esau said to Isaac, his father: 'Hast thou but one blessing, O father? Bless me, (even) me also, father: '" },
  { book: "Jubilees", chapter: 26, verse: 33, text: "And Esau lifted up his voice and wept. And Isaac answered and said unto him: 'Behold, far from the dew of the earth shall be thy dwelling, And far from the dew of heaven from above." },
  { book: "Jubilees", chapter: 26, verse: 34, text: "And by thy sword wilt thou live, And thou wilt serve thy brother. And it shall come to pass when thou becomest great, And dost shake his yoke from off thy neck, Thou shalt sin a complete sin unto death, And thy seed shall be rooted out from under heaven.'" },
  { book: "Jubilees", chapter: 26, verse: 35, text: "And Esau kept threatening Jacob because of the blessing wherewith his father blessed him, and he: said in his heart: 'May the days of mourning for my father now come, so that I may slay my brother Jacob.'" },
  { book: "Jubilees", chapter: 27, verse: 1, text: "And the words of Esau, her elder son, were told to Rebecca in a dream, and Rebecca sent and called Jacob her younger son," },
  { book: "Jubilees", chapter: 27, verse: 2, text: "and said unto him: 'Behold Esau thy brother will take vengeance on thee so as to kill thee." },
  { book: "Jubilees", chapter: 27, verse: 3, text: "Now, therefore, my son, obey my voice, and arise and flee thou to Laban, my brother, to Haran, and tarry with him a few days until thy brother's anger turns away, and he remove his anger from thee, and forget all that thou hast done; then I will send and fetch thee from thence.'" },
  { book: "Jubilees", chapter: 27, verse: 4, text: "And Jacob said: 'I am not afraid; if he wishes to kill me, I will kill him.'" },
  { book: "Jubilees", chapter: 27, verse: 5, text: "But she said unto him: 'Let me not be bereft of both my sons on one day.'" },
  { book: "Jubilees", chapter: 27, verse: 6, text: "And Jacob said to Rebecca his mother: 'Behold, thou knowest that my father has become old, and does not see because his eyes are dull, and if I leave him it will be evil in his eyes, because I leave him and go away from you, and my father will be angry, and will curse me. I will not go; when he sends me, then only will I go.'" },
  { book: "Jubilees", chapter: 27, verse: 7, text: "And Rebecca said to Jacob: 'I will go in and speak to him, and he will send thee away.'" },
  { book: "Jubilees", chapter: 27, verse: 8, text: "And Rebecca went in and said to Isaac: 'I loathe my life because of the two daughters of Heth, whom Esau has taken him as wives; and if Jacob take a wife from among the daughters of the land such as these, for what purpose do I further live, for the daughters of Canaan are evil.'" },
  { book: "Jubilees", chapter: 27, verse: 9, text: "And Isaac called Jacob and blessed him, and admonished him and said unto him: 'Do not take thee a wife of any of the daughters of Canaan;" },
  { book: "Jubilees", chapter: 27, verse: 10, text: "arise and go to Mesopotamia, to the house of Bethuel, thy mother's father, and take thee a wife from thence of the daughters of Laban, thy mother's brother." },
  { book: "Jubilees", chapter: 27, verse: 11, text: "And God Almighty bless thee and increase and multiply thee that thou mayest become a company of nations, and give thee the blessings of my father Abraham, to thee and to thy seed after thee, that thou mayest inherit the land of thy sojournings and all the land which God gave to Abraham: go, my son, in peace.'" },
  { book: "Jubilees", chapter: 27, verse: 12, text: "And Isaac sent Jacob away, and he went to Mesopotamia, to Laban the son of Bethuel the Syrian, the brother of Rebecca, Jacob's mother." },
  { book: "Jubilees", chapter: 27, verse: 13, text: "And it came to pass after Jacob had arisen to go to Mesopotamia that the spirit of Rebecca was grieved after her son, and she wept." },
  { book: "Jubilees", chapter: 27, verse: 14, text: "And Isaac said to Rebecca: 'My sister, weep not on account of Jacob, my son; for he goeth in peace, and in peace will he return." },
  { book: "Jubilees", chapter: 27, verse: 15, text: "The Most High God will preserve him from all evil, and will be with him; for He will not forsake him all his days;" },
  { book: "Jubilees", chapter: 27, verse: 16, text: "For I know that his ways will be prospered in all things wherever he goes, until he return in peace to us, and we see him in peace." },
  { book: "Jubilees", chapter: 27, verse: 17, text: "Fear not on his account, my sister, for he is on the upright path and he is a perfect man: and he is faithful and will not perish. Weep not.'" },
  { book: "Jubilees", chapter: 27, verse: 18, text: "And Isaac comforted Rebecca on account of her son Jacob, and blessed him." },
  { book: "Jubilees", chapter: 27, verse: 19, text: "And Jacob went from the Well of the Oath to go to Haran on the first year of the second week in the forty-fourth jubilee, and he came to Luz on the mountains, that is, Bethel, on the new moon of the first month of this week, [2115 A.M.] and he came to the place at even and turned from the way to the west of the road that night: and he slept there; for the sun had set." },
  { book: "Jubilees", chapter: 27, verse: 20, text: "And he took one of the stones of that place and laid <it at his head> under the tree, and he was journeying alone, and he slept." },
  { book: "Jubilees", chapter: 27, verse: 21, text: "And he dreamt that night, and behold a ladder set up on the earth, and the top of it reached to heaven, and behold, the angels of the Lord ascended and descended on it: and behold, the Lord stood upon it." },
  { book: "Jubilees", chapter: 27, verse: 22, text: "And he spake to Jacob and said: 'I am the Lord God of Abraham, thy father, and the God of Isaac; the land whereon thou art sleeping, to thee will I give it, and to thy seed after thee." },
  { book: "Jubilees", chapter: 27, verse: 23, text: "And thy seed shall be as the dust of the earth, and thou shalt increase to the west and to the east, to the north and the south, and in thee and in thy seed shall all the families of the nations be blessed." },
  { book: "Jubilees", chapter: 27, verse: 24, text: "And behold, I will be with thee, and will keep thee whithersoever thou goest, and I will bring thee again into this land in peace; for I will not leave thee until I do everything that I told thee of.'" },
  { book: "Jubilees", chapter: 27, verse: 25, text: "And Jacob awoke from his sleep, and said, 'Truly this place is the house of the Lord, and I knew it not.' And he was afraid and said: 'Dreadful is this place which is none other than the house of God, and this is the gate of heaven.'" },
  { book: "Jubilees", chapter: 27, verse: 26, text: "And Jacob arose early in the morning, and took the stone which he had put under his head and set it up as a pillar for a sign, and he poured oil upon the top of it. And he called the name of that place Bethel; but the name of the place was Luz at the first." },
  { book: "Jubilees", chapter: 27, verse: 27, text: "And Jacob vowed a vow unto the Lord, saying: 'If the Lord will be with me, and will keep me in this way that I go, and give me bread to eat and raiment to put on, so that I come again to my father's house in peace, then shall the Lord be my God, and this stone which I have set up as a pillar for a sign in this place, shall be the Lord's house, and of all that thou givest me, I shall give the tenth to thee, my God.'" },
  { book: "Jubilees", chapter: 28, verse: 1, text: "And he went on his journey, and came to the land of the east, to Laban, the brother of Rebecca, and he was with him, and served him for Rachel his daughter one week." },
  { book: "Jubilees", chapter: 28, verse: 2, text: "And in the first year of the third week [2122 A.M.] he said unto him: 'Give me my wife, for whom I have served thee seven years '; and Laban said unto Jacob: 'I will give thee thy wife.'" },
  { book: "Jubilees", chapter: 28, verse: 3, text: "And Laban made a feast, and took Leah his elder daughter, and gave (her) to Jacob as a wife, and gave her Zilpah his handmaid for an hand- maid; and Jacob did not know, for he thought that she was Rachel." },
  { book: "Jubilees", chapter: 28, verse: 4, text: "And he went in unto her, and behold, she was Leah; and Jacob was angry with Laban, and said unto him: 'Why hast thou dealt thus with me? Did not I serve thee for Rachel and not for Leah? Why hast thou wronged me?" },
  { book: "Jubilees", chapter: 28, verse: 5, text: "Take thy daughter, and I will go; for thou hast done evil to me.' For Jacob loved Rachel more than Leah; for Leah's eyes were weak, but her form was very handsome; but Rachel had beautiful eyes and a beautiful and very handsome form." },
  { book: "Jubilees", chapter: 28, verse: 6, text: "And Laban said to Jacob: 'It is not so done in our country, to give the younger before the elder.' And it is not right to do this; for thus it is ordained and written in the heavenly tablets, that no one should give his younger daughter before the elder; but the elder, one gives first and after her the younger -and the man who does so, they set down guilt against him in heaven, and none is righteous that does this thing, for this deed is evil before the Lord." },
  { book: "Jubilees", chapter: 28, verse: 7, text: "And command thou the children of Israel that they do not this thing; let them neither take nor give the younger before they have given the elder, for it is very wicked." },
  { book: "Jubilees", chapter: 28, verse: 8, text: "And Laban said to Jacob: 'Let the seven days of the feast of this one pass by, and I shall give thee Rachel, that thou mayst serve me another seven years, that thou mayst pasture my sheep as thou didst in the former week.'" },
  { book: "Jubilees", chapter: 28, verse: 9, text: "And on the day when the seven days of the feast of Leah had passed, Laban gave Rachel to Jacob, that he might serve him another seven years, and he gave to Rachel Bilhah, the sister of Zilpah, as a handmaid." },
  { book: "Jubilees", chapter: 28, verse: 10, text: "And he served yet other seven years for Rachel, for Leah had been given to him for nothing." },
  { book: "Jubilees", chapter: 28, verse: 11, text: "And the Lord opened the womb of Leah, and she conceived and bare Jacob a son, and he called his name Reuben, on the fourteenth day of the ninth month, in the first year of the third week. [2122 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 12, text: "But the womb of Rachel was closed, for the Lord saw that Leah was hated and Rachel loved." },
  { book: "Jubilees", chapter: 28, verse: 13, text: "And again Jacob went in unto Leah, and she conceived, and bare Jacob a second son, and he called his name Simeon, on the twenty-first of the tenth month, and in the third year of this week. [2124 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 14, text: "And again Jacob went in unto Leah, and she conceived, and bare him a third son, and he called his name Levi, in the new moon of the first month in the sixth year of this week. [2127 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 15, text: "And again Jacob went in unto her, and she conceived, and bare him a fourth son, and he called his name Judah, on the fifteenth of the third month, in the first year of the fourth week. [2129 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 16, text: "And on account of all this Rachel envied Leah, for she did not bear, and she said to Jacob: 'Give me children'; and Jacob said: 'Have I withheld from thee the fruits of thy womb? Have I forsaken thee?'" },
  { book: "Jubilees", chapter: 28, verse: 17, text: "And when Rachel saw that Leah had borne four sons to Jacob, Reuben and Simeon and Levi and Judah, she said unto him: 'Go in unto Bilhah my handmaid, and she will conceive, and bear a son unto me.' (And she gave (him) Bilhah her handmaid to wife)." },
  { book: "Jubilees", chapter: 28, verse: 18, text: "And he went in unto her, and she conceived, and bare him a son, and he called his name Dan, on the ninth of the sixth month, in the sixth year of the third week. [2127 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 19, text: "And Jacob went in again unto Bilhah a second time, and she conceived, and bare Jacob another son, and Rachel called his name Napthali, on the fifth of the seventh month, in the second year of the fourth week. [2130 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 20, text: "And when Leah saw that she had become sterile and did not bear, she envied Rachel, and she also gave her handmaid Zilpah to Jacob to wife, and she conceived, and bare a son, and Leah called his name Gad, on the twelfth of the eighth month, in the third year of the fourth week. [2131 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 21, text: "And he went in again unto her, and she conceived, and bare him a second son, and Leah called his name Asher, on the second of the eleventh month, in the fifth year of the fourth week. [2133 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 22, text: "And Jacob went in unto Leah, and she conceived, and bare a son, and she called his name Issachar, on the fourth of the fifth month, in the fourth year of the fourth week,[2132 A.M.] and she gave him to a nurse." },
  { book: "Jubilees", chapter: 28, verse: 23, text: "And Jacob went in again unto her, and she conceived, and bare two (children), a son and a daughter, and she called the name of the son Zabulon, and the name of the daughter Dinah, in the seventh of the seventh month, in the sixth year of the fourth week. [2134 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 24, text: "And the Lord was gracious to Rachel, and opened her womb, and she conceived, and bare a son, and she called his name Joseph, on the new moon of the fourth month, in the sixth year in this fourth week. [2134 A.M.]" },
  { book: "Jubilees", chapter: 28, verse: 25, text: "And in the days when Joseph was born, Jacob said to Laban: 'Give me my wives and sons, and let me go to my father Isaac, and let me make me an house; for I have completed the years in which I have served thee for thy two daughters, and I will go to the house of my father.'" },
  { book: "Jubilees", chapter: 28, verse: 26, text: "And Laban said to Jacob: 'Tarry with me for thy wages, and pasture my flock for me again, and take thy wages.'" },
  { book: "Jubilees", chapter: 28, verse: 27, text: "And they agreed with one another that he should give him as his wages those of the lambs and kids which were born black and spotted and white, (these) were to be his wages." },
  { book: "Jubilees", chapter: 28, verse: 28, text: "And all the sheep brought forth spotted and speckled and black, variously marked, and they brought forth again lambs like themselves, and all that were spotted were Jacob's and those which were not were Laban's." },
  { book: "Jubilees", chapter: 28, verse: 29, text: "And Jacob's possessions multiplied exceedingly, and he possessed oxen and sheep and asses and camels, and menservants and maid-servants." },
  { book: "Jubilees", chapter: 28, verse: 30, text: "And Laban and his sons envied Jacob, and Laban took back his sheep from him, and he observed him with evil intent." },
  { book: "Jubilees", chapter: 29, verse: 1, text: "And it came to pass when Rachel had borne Joseph, that Laban went to shear his sheep; for they were distant from him a three days' journey." },
  { book: "Jubilees", chapter: 29, verse: 2, text: "And Jacob saw that Laban was going to shear his sheep, and Jacob called Leah and Rachel, and spake kindly unto them that they should come with him to the land of Canaan." },
  { book: "Jubilees", chapter: 29, verse: 3, text: "For he told them how he had seen everything in a dream, even all that He had spoken unto him that he should return to his father's house, and they said: 'To every place whither thou goest we will go with thee.'" },
  { book: "Jubilees", chapter: 29, verse: 4, text: "And Jacob blessed the God of Isaac his father, and the God of Abraham his father's father, and he arose and mounted his wives and his children, and took all his possessions and crossed the river, and came to the land of Gilead, and Jacob hid his intention from Laban and told him not." },
  { book: "Jubilees", chapter: 29, verse: 5, text: "And in the seventh year of the fourth week Jacob turned (his face) toward Gilead in the first month, on the twenty-first thereof. [2135 A.M.] And Laban pursued after him and overtook Jacob in the mountain of Gilead in the third month, on the thirteenth thereof." },
  { book: "Jubilees", chapter: 29, verse: 6, text: "And the Lord did not suffer him to injure Jacob; for he appeared to him in a dream by night. And Laban spake to Jacob." },
  { book: "Jubilees", chapter: 29, verse: 7, text: "And on the fifteenth of those days Jacob made a feast for Laban, and for all who came with him, and Jacob sware to Laban that day, and Laban also to Jacob, that neither should cross the mountain of Gilead to the other with evil purpose." },
  { book: "Jubilees", chapter: 29, verse: 8, text: "And he made there a heap for a witness; wherefore the name of that place is called: 'The Heap of Witness,' after this heap." },
  { book: "Jubilees", chapter: 29, verse: 9, text: "But before they used to call the land of Gilead the land of the Rephaim; for it was the land of the Rephaim, and the Rephaim were born (there), giants whose height was ten, nine, eight down to seven cubits." },
  { book: "Jubilees", chapter: 29, verse: 10, text: "And their habitation was from the land of the children of Ammon to Mount Hermon, and the seats of their kingdom were Karnaim and Ashtaroth, and Edrei, and Misur, and Beon." },
  { book: "Jubilees", chapter: 29, verse: 11, text: "And the Lord destroyed them because of the evil of their deeds; for they were very malignant, and the Amorites dwelt in their stead, wicked and sinful, and there is no people to-day which has wrought to the full all their sins, and they have no longer length of life on the earth." },
  { book: "Jubilees", chapter: 29, verse: 12, text: "And Jacob sent away Laban, and he departed into Mesopotamia, the land of the East, and Jacob returned to the land of Gilead." },
  { book: "Jubilees", chapter: 29, verse: 13, text: "And he passed over the Jabbok in the ninth month, on the eleventh thereof. And on that day Esau, his brother, came to him, and he was reconciled to him, and departed from him unto the land of Seir, but Jacob dwelt in tents." },
  { book: "Jubilees", chapter: 29, verse: 14, text: "And in the first year of the fifth week in this jubilee [2136 A.M.] he crossed the Jordan, and dwelt beyond the Jordan, and he pastured his sheep from the sea of the heap unto Bethshan, and unto Dothan and unto the forest of Akrabbim." },
  { book: "Jubilees", chapter: 29, verse: 15, text: "And he sent to his father Isaac of all his substance, clothing, and food, and meat, and drink, and milk, and butter, and cheese, and some dates of the valley." },
  { book: "Jubilees", chapter: 29, verse: 16, text: "And to his mother Rebecca also four times a year, between the times of the months, between ploughing and reaping, and between autumn and the rain (season) and between winter and spring, to the tower of Abraham." },
  { book: "Jubilees", chapter: 29, verse: 17, text: "For Isaac had returned from the Well of the Oath and gone up to the tower of his father Abraham, and he dwelt there apart from his son Esau." },
  { book: "Jubilees", chapter: 29, verse: 18, text: "For in the days when Jacob went to Mesopotamia, Esau took to himself a wife Mahalath, the daughter of Ishmael, and he gathered together all the flocks of his father and his wives, and went Up and dwelt on Mount Seir, and left Isaac his father at the Well of the Oath alone." },
  { book: "Jubilees", chapter: 29, verse: 19, text: "And Isaac went up from the Well of the Oath and dwelt in the tower of Abraham his father on the mountains of Hebron," },
  { book: "Jubilees", chapter: 29, verse: 20, text: "And thither Jacob sent all that he did send to his father and his mother from time to time, all they needed, and they blessed Jacob with all their heart and with all their soul." },
  { book: "Jubilees", chapter: 30, verse: 1, text: "And in the first year of the sixth week [2143 A.M.] he went up to Salem, to the east of Shechem, in peace, in the fourth month." },
  { book: "Jubilees", chapter: 30, verse: 2, text: "And there they carried off Dinah, the daughter of Jacob, into the house of Shechem, the son of Hamor, the Hivite, the prince of the land, and he lay with her and defiled her, and she was a little girl, a child of twelve years." },
  { book: "Jubilees", chapter: 30, verse: 3, text: "And he besought his father and her brothers that she might be given to him to wife. And Jacob and his sons were wroth because of the men of Shechem; for they had defiled Dinah, their sister, and they spake to them with evil intent and dealt deceitfully with them and beguiled them." },
  { book: "Jubilees", chapter: 30, verse: 4, text: "And Simeon and Levi came unexpectedly to Shechem and executed judgment on all the men of Shechem, and slew all the men whom they found in it, and left not a single one remaining in it: they slew all in torments because they had dishonoured their sister Dinah." },
  { book: "Jubilees", chapter: 30, verse: 5, text: "And thus let it not again be done from henceforth that a daughter of Israel be defiled; for judgment is ordained in heaven against them that they should destroy with the sword all the men of the Shechemites because they had wrought shame in Israel." },
  { book: "Jubilees", chapter: 30, verse: 6, text: "And the Lord delivered them into the hands of the sons of Jacob that they might exterminate them with the sword and execute judgment upon them, and that it might not thus again be done in Israel that a virgin of Israel should be defiled." },
  { book: "Jubilees", chapter: 30, verse: 7, text: "And if there is any man who wishes in Israel to give his daughter or his sister to any man who is of the seed of the Gentiles he shall surely die, and they shall stone him with stones; for he hath wrought shame in Israel; and they shall burn the woman with fire, because she has dishonoured the name of the house of her father, and she shall be rooted out of Israel." },
  { book: "Jubilees", chapter: 30, verse: 8, text: "And let not an adulteress and no uncleanness be found in Israel throughout all the days of the generations of the earth; for Israel is holy unto the Lord, and every man who has defiled (it) shall surely die: they shall stone him with stones." },
  { book: "Jubilees", chapter: 30, verse: 9, text: "For thus has it been ordained and written in the heavenly tablets regarding all the seed of Israel: he who defileth (it) shall surely die, and he shall be stoned with stones." },
  { book: "Jubilees", chapter: 30, verse: 10, text: "And to this law there is no limit of days, and no remission, nor any atonement: but the man who has defiled his daughter shall be rooted out in the midst of all Israel, because he has given of his seed to Moloch, and wrought impiously so as to defile it." },
  { book: "Jubilees", chapter: 30, verse: 11, text: "And do thou, Moses, command the children of Israel and exhort them not to give their daughters to the Gentiles, and not to take for their sons any of the daughters of the Gentiles, for this is abominable before the Lord." },
  { book: "Jubilees", chapter: 30, verse: 12, text: "For this reason I have written for thee in the words of the Law all the deeds of the Shechemites, which they wrought against Dinah, and how the sons of Jacob spake, saying: 'We will not give our daughter to a man who is uncircumcised; for that were a reproach unto us.'" },
  { book: "Jubilees", chapter: 30, verse: 13, text: "And it is a reproach to Israel, to those who live, and to those that take the daughters of the Gentiles; for this is unclean and abominable to Israel." },
  { book: "Jubilees", chapter: 30, verse: 14, text: "And Israel will not be free from this uncleanness if it has a wife of the daughters of the Gentiles, or has given any of its daughters to a man who is of any of the Gentiles." },
  { book: "Jubilees", chapter: 30, verse: 15, text: "For there will be plague upon plague, and curse upon curse, and every judgment and plague and curse will come upon him: if he do this thing, or hide his eyes from those who commit uncleanness, or those who defile the sanctuary of the Lord, or those who profane His holy name, (then) will the whole nation together be judged for all the uncleanness and profanation of this man." },
  { book: "Jubilees", chapter: 30, verse: 16, text: "And there will be no respect of persons [and no consideration of persons] and no receiving at his hands of fruits and offerings and burnt-offerings and fat, nor the fragrance of sweet savour, so as to accept it: and so fare every man or woman in Israel who defiles the sanctuary." },
  { book: "Jubilees", chapter: 30, verse: 17, text: "For this reason I have commanded thee, saying: 'Testify this testimony to Israel: see how the Shechemites fared and their sons: how they were delivered into the hands of two sons of Jacob, and they slew them under tortures, and it was (reckoned) unto them for righteousness, and it is written down to them for righteousness." },
  { book: "Jubilees", chapter: 30, verse: 18, text: "And the seed of Levi was chosen for the priesthood, and to be Levites, that they might minister before the Lord, as we, continually, and that Levi and his sons may be blessed for ever; for he was zealous to execute righteousness and judgment and vengeance on all those who arose against Israel." },
  { book: "Jubilees", chapter: 30, verse: 19, text: "And so they inscribe as a testimony in his favour on the heavenly tablets blessing and righteousness before the God of all:" },
  { book: "Jubilees", chapter: 30, verse: 20, text: "And we remember the righteousness which the man fulfilled during his life, at all periods of the year; until a thousand generations they will record it, and it will come to him and to his descendants after him, and he has been recorded on the heavenly tablets as a friend and a righteous man." },
  { book: "Jubilees", chapter: 30, verse: 21, text: "All this account I have written for thee, and have commanded thee to say to the children of Israel, that they should not commit sin nor transgress the ordinances nor break the covenant which has been ordained for them, (but) that they should fulfil it and be recorded as friends." },
  { book: "Jubilees", chapter: 30, verse: 22, text: "But if they transgress and work uncleanness in every way, they will be recorded on the heavenly tablets as adversaries, and they will be destroyed out of the book of life, and they will be recorded in the book of those who will be destroyed and with those who will be rooted out of the earth." },
  { book: "Jubilees", chapter: 30, verse: 23, text: "And on the day when the sons of Jacob slew Shechem a writing was recorded in their favour in heaven that they had executed righteousness and uprightness and vengeance on the sinners, and it was written for a blessing." },
  { book: "Jubilees", chapter: 30, verse: 24, text: "And they brought Dinah, their sister, out of the house of Shechem, and they took captive everything that was in Shechem, their sheep and their oxen and their asses, and all their wealth, and all their flocks, and brought them all to Jacob their father." },
  { book: "Jubilees", chapter: 30, verse: 25, text: "And he reproached them because they had put the city to the sword for he feared those who dwelt in the land, the Canaanites and the Perizzites." },
  { book: "Jubilees", chapter: 30, verse: 26, text: "And the dread of the Lord was upon all the cities which are around about Shechem, and they did not rise to pursue after the sons of Jacob; for terror had fallen upon them." },
  { book: "Jubilees", chapter: 31, verse: 1, text: "And on the new moon of the month Jacob spake to all the people of his house. saying: 'Purify yourselves and change your garments, and let us arise and go up to Bethel, where I vowed a vow to Him on the day when I fled from the face of Esau my brother, because he has been with me and brought me into this land in peace, and put ye away the strange gods that arc among you.'" },
  { book: "Jubilees", chapter: 31, verse: 2, text: "And they gave up the strange gods and that which was in their ears and which was on their necks and the idols which Rachel stole from Laban her father she gave wholly to Jacob. And he burnt and brake them to pieces and destroyed them, and hid them under an oak which is in the land of Shechem." },
  { book: "Jubilees", chapter: 31, verse: 3, text: "And he went up on the new moon of the seventh month to Bethel. And he built an altar at the place where he had slept, and he set up a pillar there, and he sent word to his father Isaac to come to him to his sacrifice, and to his mother Rebecca." },
  { book: "Jubilees", chapter: 31, verse: 4, text: "And Isaac said: 'Let my son Jacob come, and let me see him before I die.'" },
  { book: "Jubilees", chapter: 31, verse: 5, text: "And Jacob went to his father Isaac and to his mother Rebecca, to the house of his father Abraham, and he took two of his sons with him, Levi and Judah, and he came to his father Isaac and to his mother Rebecca." },
  { book: "Jubilees", chapter: 31, verse: 6, text: "And Rebecca came forth from the tower to the front of it to kiss Jacob and embrace him; for her spirit had revived when she heard: 'Behold Jacob thy son has come'; and she kissed him." },
  { book: "Jubilees", chapter: 31, verse: 7, text: "And she saw his two sons, and she recognised them, and said unto him: 'Are these thy sons, my son?' and she embraced them and kissed them, and blessed them, saying: 'In you shall the seed of Abraham become illustrious, and ye shall prove a blessing on the earth.'" },
  { book: "Jubilees", chapter: 31, verse: 8, text: "And Jacob went in to Isaac his father, to the chamber where he lay, and his two sons were with him, and he took the hand of his father, and stooping down he kissed him, and Isaac clung to the neck of Jacob his son, and wept upon his neck." },
  { book: "Jubilees", chapter: 31, verse: 9, text: "And the darkness left the eyes of Isaac, and he saw the two sons of Jacob, Levi, and Judah, and he said: 'Are these thy sons, my son? for they are like thee.'" },
  { book: "Jubilees", chapter: 31, verse: 10, text: "And he said unto him that they were truly his sons: 'And thou hast truly seen that they are truly my sons'." },
  { book: "Jubilees", chapter: 31, verse: 11, text: "And they came near to him, and he turned and kissed them and embraced them both together." },
  { book: "Jubilees", chapter: 31, verse: 12, text: "And the spirit of prophecy came down into his mouth, and he took Levi by his right hand and Judah by his left." },
  { book: "Jubilees", chapter: 31, verse: 13, text: "And he turned to Levi first, and began to bless him first, and said unto him: 'May the God of all, the very Lord of all the ages, bless thee and thy children throughout all the ages." },
  { book: "Jubilees", chapter: 31, verse: 14, text: "And may the Lord give to thee and to thy seed greatness and great glory, and cause thee and thy seed, from among all flesh, to approach Him to serve in His sanctuary as the angels of the presence and as the holy ones. (Even) as they, shall the seed of thy sons be for glory and greatness and holiness, and may He make them great unto all the ages." },
  { book: "Jubilees", chapter: 31, verse: 15, text: "And they shall be judges and princes, and chiefs of all the seed of the sons of Jacob; They shall speak the word of the Lord in righteousness, And they shall judge all His judgments in righteousness. And they shall declare My ways to Jacob And My paths to Israel. The blessing of the Lord shall be given in their mouths To bless all the seed of the beloved." },
  { book: "Jubilees", chapter: 31, verse: 16, text: "Thy mother has called thy name Levi, And justly has she called thy name; Thou shalt be joined to the Lord And be the companion of all the sons of Jacob; Let His table be thine, And do thou and thy sons eat thereof; And may thy table be full unto all generations, And thy food fail not unto all the ages." },
  { book: "Jubilees", chapter: 31, verse: 17, text: "And let all who hate thee fall down before thee, And let all thy adversaries be rooted out and perish; And blessed be he that blesses thee, And cursed be every nation that curses thee.'" },
  { book: "Jubilees", chapter: 31, verse: 18, text: "And to Judah he said: 'May the Lord give thee strength and power to tread down all that hate thee; A prince shalt thou be, thou and one of thy sons, over the sons of Jacob; May thy name and the name of thy sons go forth and traverse every land and region. Then shall the Gentiles fear before thy face, And all the nations shall quake [And all the peoples shall quake]." },
  { book: "Jubilees", chapter: 31, verse: 19, text: "In thee shall be the help of Jacob, And in thee be found the salvation of Israel." },
  { book: "Jubilees", chapter: 31, verse: 20, text: "And when thou sittest on the throne of honour of thy righteousness There shall be great peace for all the seed of the sons of the beloved; Blessed be he that blesseth thee, And all that hate thee and afflict thee and curse thee Shall be rooted out and destroyed from the earth and be accursed.'" },
  { book: "Jubilees", chapter: 31, verse: 21, text: "And turning he kissed him again and embraced him, and rejoiced greatly; for he had seen the sons of Jacob his son in very truth." },
  { book: "Jubilees", chapter: 31, verse: 22, text: "And he went forth from between his feet and fell down and bowed down to him, and he blessed them and rested there with Isaac his father that night, and they eat and drank with joy." },
  { book: "Jubilees", chapter: 31, verse: 23, text: "And he made the two sons of Jacob sleep, the one on his right hand and the other on his left, and it was counted to him for righteousness." },
  { book: "Jubilees", chapter: 31, verse: 24, text: "And Jacob told his father everything during the night, how the Lord had shown him great mercy, and how he had prospered (him in) all his ways, and protected him from all evil." },
  { book: "Jubilees", chapter: 31, verse: 25, text: "And Isaac blessed the God of his father Abraham, who had not withdrawn his mercy and his righteousness from the sons of his servant Isaac." },
  { book: "Jubilees", chapter: 31, verse: 26, text: "And in the morning Jacob told his father Isaac the vow which he had vowed to the Lord, and the vision which he had seen, and that he had built an altar, and that everything was ready for the sacrifice to be made before the Lord as he had vowed, and that he had come to set him on an ass." },
  { book: "Jubilees", chapter: 31, verse: 27, text: "And Isaac said unto Jacob his son: 'I am not able to go with thee; for I am old and not able to bear the way: go, my son, in peace; for I am one hundred and sixty-five years this day; I am no longer able to journey; set thy mother (on an ass) and let her go with thee." },
  { book: "Jubilees", chapter: 31, verse: 28, text: "And I know, my son, that thou hast come on my account, and may this day be blessed on which thou hast seen me alive, and I also have seen thee, my son." },
  { book: "Jubilees", chapter: 31, verse: 29, text: "Mayest thou prosper and fulfil the vow which thou hast vowed; and put not off thy vow; for thou shalt be called to account as touching the vow; now therefore make haste to perform it, and may He be pleased who has made all things, to whom thou hast vowed the vow.'" },
  { book: "Jubilees", chapter: 31, verse: 30, text: "And he said to Rebecca: 'Go with Jacob thy son'; and Rebecca went with Jacob her son, and Deborah with her, and they came to Bethel." },
  { book: "Jubilees", chapter: 31, verse: 31, text: "And Jacob remembered the prayer with which his father had blessed him and his two sons, Levi and Judah, and he rejoiced and blessed the God of his fathers, Abraham and Isaac." },
  { book: "Jubilees", chapter: 31, verse: 32, text: "And he said: 'Now I know that I have an eternal hope, and my sons also, before the God of all'; and thus is it ordained concerning the two; and they record it as an eternal testimony unto them on the heavenly tablets how Isaac blessed them." },
  { book: "Jubilees", chapter: 32, verse: 1, text: "And he abode that night at Bethel, and Levi dreamed that they had ordained and made him the priest of the Most High God, him and his sons for ever; and he awoke from his sleep and blessed the Lord." },
  { book: "Jubilees", chapter: 32, verse: 2, text: "And Jacob rose early in the morning, on the fourteenth of this month, and he gave a tithe of all that came with him, both of men and cattle, both of gold and every vessel and garment, yea, he gave tithes of all." },
  { book: "Jubilees", chapter: 32, verse: 3, text: "And in those days Rachel became pregnant with her son Benjamin. And Jacob counted his sons from him upwards and Levi fell to the portion of the Lord, and his father clothed him in the garments of the priesthood and filled his hands." },
  { book: "Jubilees", chapter: 32, verse: 4, text: "And on the fifteenth of this month, he brought to the altar fourteen oxen from amongst the cattle, and twenty-eight rams, and forty-nine sheep, and seven lambs, and twenty-one kids of the goats as a burnt-offering on the altar of sacrifice, well pleasing for a sweet savour before God." },
  { book: "Jubilees", chapter: 32, verse: 5, text: "This was his offering, in consequence of the vow which he had vowed that he would give a tenth, with their fruit-offerings and their drink- offerings." },
  { book: "Jubilees", chapter: 32, verse: 6, text: "And when the fire had consumed it, he burnt incense on the fire over the fire, and for a thank-offering two oxen and four rams and four sheep, four he-goats, and two sheep of a year old, and two kids of the goats; and thus he did daily for seven days." },
  { book: "Jubilees", chapter: 32, verse: 7, text: "And he and all his sons and his men were eating (this) with joy there during seven days and blessing and thanking the Lord, who had delivered him out of all his tribulation and had given him his vow." },
  { book: "Jubilees", chapter: 32, verse: 8, text: "And he tithed all the clean animals, and made a burnt sacrifice, but the unclean animals he gave (not) to Levi his son, and he gave him all the souls of the men." },
  { book: "Jubilees", chapter: 32, verse: 9, text: "And Levi discharged the priestly office at Bethel before Jacob his father in preference to his ten brothers, and he was a priest there, and Jacob gave his vow: thus he tithed again the tithe to the Lord and sanctified it, and it became holy unto Him." },
  { book: "Jubilees", chapter: 32, verse: 10, text: "And for this reason it is ordained on the heavenly tablets as a law for the tithing again the tithe to eat before the Lord from year to year, in the place where it is chosen that His name should dwell, and to this law there is no limit of days for ever." },
  { book: "Jubilees", chapter: 32, verse: 11, text: "This ordinance is written that it may be fulfilled from year to year in eating the second tithe before the Lord in the place where it has been chosen, and nothing shall remain over from it from this year to the year following." },
  { book: "Jubilees", chapter: 32, verse: 12, text: "For in its year shall the seed be eaten till the days of the gathering of the seed of the year, and the wine till the days of the wine, and the oil till the days of its season." },
  { book: "Jubilees", chapter: 32, verse: 13, text: "And all that is left thereof and becomes old, let it be regarded as polluted: let it be burnt with fire, for it is unclean." },
  { book: "Jubilees", chapter: 32, verse: 14, text: "And thus let them eat it together in the sanctuary, and let them not suffer it to become old." },
  { book: "Jubilees", chapter: 32, verse: 15, text: "And all the tithes of the oxen and sheep shall be holy unto the Lord, and shall belong to his priests, which they will eat before Him from year to year; for thus is it ordained and engraven regarding the tithe on the heavenly tablets." },
  { book: "Jubilees", chapter: 32, verse: 16, text: "And on the following night, on the twenty-second day of this month, Jacob resolved to build that place, and to surround the court with a wall, and to sanctify it and make it holy for ever, for himself and his children after him." },
  { book: "Jubilees", chapter: 32, verse: 17, text: "And the Lord appeared to him by night and blessed him and said unto him: 'Thy name shall not be called Jacob, but Israel shall they name thy name.'" },
  { book: "Jubilees", chapter: 32, verse: 18, text: "And He said unto him again: 'I am the Lord who created the heaven and the earth, and I will increase thee and multiply thee exceedingly, and kings shall come forth from thee, and they shall judge everywhere wherever the foot of the sons of men has trodden." },
  { book: "Jubilees", chapter: 32, verse: 19, text: "And I will give to thy seed all the earth which is under heaven, and they shall judge all the nations according to their desires, and after that they shall get possession of the whole earth and inherit it for ever.'" },
  { book: "Jubilees", chapter: 32, verse: 20, text: "And He finished speaking with him, and He went up from him. and Jacob looked till He had ascended into heaven." },
  { book: "Jubilees", chapter: 32, verse: 21, text: "And he saw in a vision of the night, and behold an angel descended from heaven with seven tablets in his hands, and he gave them to Jacob, and he read them and knew all that was written therein which would befall him and his sons throughout all the ages." },
  { book: "Jubilees", chapter: 32, verse: 22, text: "And he showed him all that was written on the tablets, and said unto him: 'Do not build this place, and do not make it an eternal sanctuary, and do not dwell here; for this is not the place. Go to the house of Abraham thy father and dwell with Isaac thy father until the day of the death of thy father." },
  { book: "Jubilees", chapter: 32, verse: 23, text: "For in Egypt thou shalt die in peace, and in this land thou shalt be buried with honour in the sepulchre of thy fathers, with Abraham and Isaac." },
  { book: "Jubilees", chapter: 32, verse: 24, text: "Fear not, for as thou hast seen and read it, thus shall it all be; and do thou write down everything as thou hast seen and read.'" },
  { book: "Jubilees", chapter: 32, verse: 25, text: "And Jacob said: 'Lord, how can I remember all that I have read and seen? 'And he said unto him: 'I will bring all things to thy remembrance.'" },
  { book: "Jubilees", chapter: 32, verse: 26, text: "And he went up from him, and he awoke from his sleep, and he remembered everything which he had read and seen, and he wrote down all the words which he had read and seen." },
  { book: "Jubilees", chapter: 32, verse: 27, text: "And he celebrated there yet another day, and he sacrificed thereon according to all that he sacrificed on the former days, and called its name 'Addition,' for this day was added and the former days he called 'The Feast '." },
  { book: "Jubilees", chapter: 32, verse: 28, text: "And thus it was manifested that it should be, and it is written on the heavenly tablets: wherefore it was revealed to him that he should celebrate it, and add it to the seven days of the feast." },
  { book: "Jubilees", chapter: 32, verse: 29, text: "And its name was called 'Addition,' because that it was recorded amongst the days of the feast days, according to the number of the days of the year." },
  { book: "Jubilees", chapter: 32, verse: 30, text: "And in the night, on the twenty-third of this month, Deborah Rebecca's nurse died, and they buried her beneath the city under the oak of the river, and he called the name of this place, 'The river of Deborah,' and the oak, 'The oak of the mourning of Deborah.'" },
  { book: "Jubilees", chapter: 32, verse: 31, text: "And Rebecca went and returned to her house to his father Isaac, and Jacob sent by her hand rams and sheep and he-goats that she should prepare a meal for his father such as he desired." },
  { book: "Jubilees", chapter: 32, verse: 32, text: "And he went after his mother till he came to the land of Kabratan, and he dwelt there." },
  { book: "Jubilees", chapter: 32, verse: 33, text: "And Rachel bare a son in the night, and called his name 'Son of my sorrow '; for she suffered in giving him birth: but his father called his name Benjamin, on the eleventh of the eighth month in the first of the sixth week of this jubilee. [2143 A.M.]" },
  { book: "Jubilees", chapter: 32, verse: 34, text: "And Rachel died there and she was buried in the land of Ephrath, the same is Bethlehem, and Jacob built a pillar on the grave of Rachel, on the road above her grave." },
  { book: "Jubilees", chapter: 33, verse: 1, text: "And Jacob went and dwelt to the south of Magdaladra'ef. And he went to his father Isaac, he and Leah his wife, on the new moon of the tenth month." },
  { book: "Jubilees", chapter: 33, verse: 2, text: "And Reuben saw Bilhah, Rachel's maid, the concubine of his father, bathing in water in a secret place, and he loved her." },
  { book: "Jubilees", chapter: 33, verse: 3, text: "And he hid himself at night, and he entered the house of Bilhah [at night], and he found her sleeping alone on a bed in her house." },
  { book: "Jubilees", chapter: 33, verse: 4, text: "And he lay with her, and she awoke and saw, and behold Reuben was lying with her in the bed, and she uncovered the border of her covering and seized him, and cried out, and discovered that it was Reuben." },
  { book: "Jubilees", chapter: 33, verse: 5, text: "And she was ashamed because of him, and released her hand from him, and he fled." },
  { book: "Jubilees", chapter: 33, verse: 6, text: "And she lamented because of this thing exceedingly, and did not tell it to any one." },
  { book: "Jubilees", chapter: 33, verse: 7, text: "And when Jacob returned and sought her, she said unto him: 'I am not clean for thee, for I have been defiled as regards thee; for Reuben has defiled me, and has lain with me in the night, and I was asleep, and did not discover until he uncovered my skirt and slept with me.'" },
  { book: "Jubilees", chapter: 33, verse: 8, text: "And Jacob was exceedingly wroth with Reuben because he had lain with Bilhah, because he had uncovered his father's skirt." },
  { book: "Jubilees", chapter: 33, verse: 9, text: "And Jacob did not approach her again because Reuben had defiled her. And as for any man who uncovers his father's skirt his deed is wicked exceedingly, for he is abominable before the Lord." },
  { book: "Jubilees", chapter: 33, verse: 10, text: "For this reason it is written and ordained on the heavenly tablets that a man should not lie with his father's wife, and should not uncover his father's skirt, for this is unclean: they shall surely die together, the man who lies with his father's wife and the woman also, for they have wrought uncleanness on the earth." },
  { book: "Jubilees", chapter: 33, verse: 11, text: "And there shall be nothing unclean before our God in the nation which He has chosen for Himself as a possession." },
  { book: "Jubilees", chapter: 33, verse: 12, text: "And again, it is written a second time: 'Cursed be he who lieth with the wife of his father, for he hath uncovered his father's shame'; and all the holy ones of the Lord said 'So be it; so be it.'" },
  { book: "Jubilees", chapter: 33, verse: 13, text: "And do thou, Moses, command the children of Israel that they observe this word; for it (entails) a punishment of death; and it is unclean, and there is no atonement for ever to atone for the man who has committed this, but he is to be put to death and slain, and stoned with stones, and rooted out from the midst of the people of our God." },
  { book: "Jubilees", chapter: 33, verse: 14, text: "For to no man who does so in Israel is it permitted to remain alive a single day on the earth, for he is abominable and unclean." },
  { book: "Jubilees", chapter: 33, verse: 15, text: "And let them not say: to Reuben was granted life and forgiveness after he had lain with his father's concubine, and to her also though she had a husband, and her husband Jacob, his father, was still alive." },
  { book: "Jubilees", chapter: 33, verse: 16, text: "For until that time there had not been revealed the ordinance and judgment and law in its completeness for all, but in thy days (it has been revealed) as a law of seasons and of days, and an everlasting law for the everlasting generations." },
  { book: "Jubilees", chapter: 33, verse: 17, text: "And for this law there is no consummation of days, and no atonement for it, but they must both be rooted out in the midst of the nation: on the day whereon they committed it they shall slay them." },
  { book: "Jubilees", chapter: 33, verse: 18, text: "And do thou, Moses, write (it) down for Israel that they may observe it, and do according to these words, and not commit a sin unto death; for the Lord our God is judge, who respects not persons and accepts not gifts." },
  { book: "Jubilees", chapter: 33, verse: 19, text: "And tell them these words of the covenant, that they may hear and observe, and be on their guard with respect to them, and not be destroyed and rooted out of the land; for an uncleanness, and an abomination, and a contamination, and a pollution are all they who commit it on the earth before our God." },
  { book: "Jubilees", chapter: 33, verse: 20, text: "And there is no greater sin than the fornication which they commit on earth; for Israel is a holy nation unto the Lord its God, and a nation of inheritance, and a priestly and royal nation and for (His own) possession; and there shall no such uncleanness appear in the midst of the holy nation." },
  { book: "Jubilees", chapter: 33, verse: 21, text: "And in the third year of this sixth week [2145 A.M.] Jacob and all his sons went and dwelt in the house of Abraham, near Isaac his father and Rebecca his mother." },
  { book: "Jubilees", chapter: 33, verse: 22, text: "And these were the names of the sons of Jacob: the first-born Reuben, Simeon, Levi, Judah, Issachar, Zebulon, the sons of Leah; and the sons of Rachel, Joseph and Benjamin; and the sons of Bilhah, Dan and Naphtali; and the sons of Zilpah, Gad and Asher; and Dinah, the daughter of Leah, the only daughter of Jacob." },
  { book: "Jubilees", chapter: 33, verse: 23, text: "And they came and bowed themselves to Isaac and Rebecca, and when they saw them they blessed Jacob and all his sons, and Isaac rejoiced exceedingly, for he saw the sons of Jacob, his younger son and he blessed them." },
  { book: "Jubilees", chapter: 34, verse: 1, text: "And in the sixth year of this week of this forty-fourth jubilee [2148 A.M.] Jacob sent his sons to pasture their sheep, and his servants with them to the pastures of Shechem." },
  { book: "Jubilees", chapter: 34, verse: 2, text: "And the seven kings of the Amorites assembled themselves together against them, to slay them, hiding themselves under the trees, and to take their cattle as a prey." },
  { book: "Jubilees", chapter: 34, verse: 3, text: "And Jacob and Levi and Judah and Joseph were in the house with Isaac their father; for his spirit was sorrowful, and they could not leave him: and Benjamin was the youngest, and for this reason remained with his father." },
  { book: "Jubilees", chapter: 34, verse: 4, text: "And there came the king[s] of Taphu and the king[s] of 'Aresa, and the king[s] of Seragan, and the king[s] of Selo, and the king[s] of Ga'as, and the king of Bethoron, and the king of Ma'anisakir, and all those who dwell in these mountains (and) who dwell in the woods in the land of Canaan." },
  { book: "Jubilees", chapter: 34, verse: 5, text: "And they announced this to Jacob saying: 'Behold, the kings of the Amorites have surrounded thy sons, and plundered their herds.'" },
  { book: "Jubilees", chapter: 34, verse: 6, text: "And he arose from his house, he and his three sons and all the servants of his father, and his own servants, and he went against them with six thousand men, who carried swords." },
  { book: "Jubilees", chapter: 34, verse: 7, text: "And he slew them in the pastures of Shechem, and pursued those who fled, and he slew them with the edge of the sword, and he slew 'Aresa and Taphu and Saregan and Selo and 'Amani- sakir and Ga[ga]'as, and he recovered his herds." },
  { book: "Jubilees", chapter: 34, verse: 8, text: "And he prevailed over them, and imposed tribute on them that they should pay him tribute, five fruit products of their land, and he built Robel and Tamnatares." },
  { book: "Jubilees", chapter: 34, verse: 9, text: "And he returned in peace, and made peace with them, and they became his servants, until the day that he and his sons went down into Egypt." },
  { book: "Jubilees", chapter: 34, verse: 10, text: "And in the seventh year of this week [2149 A.M.] he sent Joseph to learn about the welfare of his brothers from his house to the land of Shechem, and he found them in the land of Dothan." },
  { book: "Jubilees", chapter: 34, verse: 11, text: "And they dealt treacherously with him, and formed a plot against him to slay him, but changing their minds, they sold him to Ishmaelite merchants, and they brought him down into Egypt, and they sold him to Potiphar, the eunuch of Pharaoh, the chief of the cooks, priest of the city of 'Elew." },
  { book: "Jubilees", chapter: 34, verse: 12, text: "And the sons of Jacob slaughtered a kid, and dipped the coat of Joseph in the blood, and sent (it) to Jacob their father on the tenth of the seventh month." },
  { book: "Jubilees", chapter: 34, verse: 13, text: "And he mourned all that night, for they had brought it to him in the evening, and he became feverish with mourning for his death, and he said: 'An evil beast hath devoured Joseph'; and all the members of his house [mourned with him that day, and they] were grieving and mourning with him all that day." },
  { book: "Jubilees", chapter: 34, verse: 14, text: "And his sons and his daughter rose up to comfort him, but he refused to be comforted for his son." },
  { book: "Jubilees", chapter: 34, verse: 15, text: "And on that day Bilhah heard that Joseph had perished, and she died mourning him, and she was living in Qafratef, and Dinah also, his daughter, died after Joseph had perished." },
  { book: "Jubilees", chapter: 34, verse: 16, text: "And there came these three mournings upon Israel in one month. And they buried Bilhah over against the tomb of Rachel, and Dinah also. his daughter, they buried there." },
  { book: "Jubilees", chapter: 34, verse: 17, text: "And he mourned for Joseph one year, and did not cease, for he said 'Let me go down to the grave mourning for my son'." },
  { book: "Jubilees", chapter: 34, verse: 18, text: "For this reason it is ordained for the children of Israel that they should afflict themselves on the tenth of the seventh month -on the day that the news which made him weep for Joseph came to Jacob his father- that they should make atonement for themselves thereon with a young goat on the tenth of the seventh month, once a year, for their sins; for they had grieved the affection of their father regarding Joseph his son." },
  { book: "Jubilees", chapter: 34, verse: 19, text: "And this day has been ordained that they should grieve thereon for their sins, and for all their transgressions and for all their errors, so that they might cleanse themselves on that day once a year." },
  { book: "Jubilees", chapter: 34, verse: 20, text: "And after Joseph perished, the sons of Jacob took unto themselves wives. The name of Reuben's wife is 'Ada; and the name of Simeon's wife is 'Adlba'a, a Canaanite; and the name of Levi's wife is Melka, of the daughters of Aram, of the seed of the sons of Terah; and the name of Judah's wife, Betasu'el, a Canaanite; and the name of Issachar's wife, Hezaqa: and the name of Zabulon's wife, Ni'iman; and the name of Dan's wife, 'Egla; and the name of Naphtali's wife, Rasu'u, of Mesopotamia; and the name of Gad's wife, Maka; and the name of Asher's wife, 'Ijona; and the name of Joseph's wife, Asenath, the Egyptian; and the name of Benjamin's wife, 'Ijasaka." },
  { book: "Jubilees", chapter: 34, verse: 21, text: "And Simeon repented, and took a second wife from Mesopotamia as his brothers." },
  { book: "Jubilees", chapter: 35, verse: 1, text: "And in the first year of the first week of the forty-fifth jubilee [2157 A.M.] Rebecca called Jacob, her son, and commanded him regarding his father and regarding his brother, that he should honour them all the days of his life." },
  { book: "Jubilees", chapter: 35, verse: 2, text: "And Jacob said: 'I will do everything as thou hast commanded me; for this thing will be honour and greatness to me, and righteousness before the Lord, that I should honour them." },
  { book: "Jubilees", chapter: 35, verse: 3, text: "And thou too, mother, knowest from the time I was born until this day, all my deeds and all that is in my heart, that I always think good concerning all." },
  { book: "Jubilees", chapter: 35, verse: 4, text: "And how should I not do this thing which thou hast commanded me, that I should honour my father and my brother!" },
  { book: "Jubilees", chapter: 35, verse: 5, text: "Tell me, mother, what perversity hast thou seen in me and I shall turn away from it, and mercy will be upon me.'" },
  { book: "Jubilees", chapter: 35, verse: 6, text: "And she said unto him: 'My son, I have not seen in thee all my days any perverse but (only) upright deeds. And yet I will tell thee the truth, my son: I shall die this year, and I shall not survive this year in my life; for I have seen in a dream the day of my death, that I should not live beyond a hundred and fifty-five years: and behold I have completed all the days of my life which I am to live.'" },
  { book: "Jubilees", chapter: 35, verse: 7, text: "And Jacob laughed at the words of his mother. because his mother had said unto him that she should die; and she was sitting opposite to him in possession of her strength, and she was not infirm in her strength; for she went in and out and saw, and her teeth were strong, and no ailment had touched her all the days of her life." },
  { book: "Jubilees", chapter: 35, verse: 8, text: "And Jacob said unto her: 'Blessed am I, mother, if my days approach the days of thy life, and my strength remain with me thus as thy strength: and thou wilt not die, for thou art jesting idly with me regarding thy death.'" },
  { book: "Jubilees", chapter: 35, verse: 9, text: "And she went in to Isaac and said unto him: 'One petition I make unto thee: make Esau swear that he will not injure Jacob, nor pursue him with enmity; for thou knowest Esau's thoughts that they are perverse from his youth, and there is no goodness in him; for he desires after thy death to kill him." },
  { book: "Jubilees", chapter: 35, verse: 10, text: "And thou knowest all that he has done since the day Jacob his brother went to Haran until this day: how he has forsaken us with his whole heart, and has done evil to us; thy flocks he has taken to himself, and carried off all thy possessions from before thy face." },
  { book: "Jubilees", chapter: 35, verse: 11, text: "And when we implored and besought him for what was our own, he did as a man who was taking pity on us." },
  { book: "Jubilees", chapter: 35, verse: 12, text: "And he is bitter against thee because thou didst bless Jacob thy perfect and upright son; for there is no evil but only goodness in him, and since he came from Haran unto this day he has not robbed us of aught, for he brings us everything in its season always, and rejoices with all his heart when we take at his hands and he blesses us, and has not parted from us since he came from Haran until this day, and he remains with us continually at home honouring us.'" },
  { book: "Jubilees", chapter: 35, verse: 13, text: "And Isaac said unto her: 'I, too, know and see the deeds of Jacob who is with us, how that with all his heart he honours us; but I loved Esau formerly more than Jacob, because he was the firstborn; but now I love Jacob more than Esau, for he has done manifold evil deeds, and there is no righteousness in him, for all his ways are unrighteousness and violence, [and there is no righteousness around him.]" },
  { book: "Jubilees", chapter: 35, verse: 14, text: "And now my heart is troubled because of all his deeds, and neither he nor his seed is to be saved, for they are those who will be destroyed from the earth and who will be rooted out from under heaven, for he has forsaken the God of Abraham and gone after his wives and after their uncleanness and after their error, he and his children." },
  { book: "Jubilees", chapter: 35, verse: 15, text: "And thou dost bid me make him swear that he will not slay Jacob his brother; even if he swear he will not abide by his oath, and he will not do good but evil only." },
  { book: "Jubilees", chapter: 35, verse: 16, text: "But if he desires to slay Jacob, his brother, into Jacob's hands will he be given, and he will not escape from his hands, [for he will descend into his hands.]" },
  { book: "Jubilees", chapter: 35, verse: 17, text: "And fear thou not on account of Jacob; for the guardian of Jacob is great and powerful and honoured, and praised more than the guardian of Esau.'" },
  { book: "Jubilees", chapter: 35, verse: 18, text: "And Rebecca sent and called Esau and he came to her, and she said unto him: 'I have a petition, my son, to make unto thee, and do thou promise to do it, my son.'" },
  { book: "Jubilees", chapter: 35, verse: 19, text: "And he said: 'I will do everything that thou sayest unto me, and I will not refuse thy petition.'" },
  { book: "Jubilees", chapter: 35, verse: 20, text: "And she said unto him: 'I ask you that the day I die, thou wilt take me in and bury me near Sarah, thy father's mother, and that thou and Jacob will love each other and that neither will desire evil against the other, but mutual love only, and (so) ye will prosper, my sons, and be honoured in the midst of the land, and no enemy will rejoice over you, and ye will be a blessing and a mercy in the eyes of all those that love you.'" },
  { book: "Jubilees", chapter: 35, verse: 21, text: "And he said: 'I will do all that thou hast told me, and I shall bury thee on the day thou diest near Sarah, my father's mother, as thou hast desired that her bones may be near thy bones." },
  { book: "Jubilees", chapter: 35, verse: 22, text: "And Jacob, my brother, also, I shall love above all flesh; for I have not a brother in all the earth but him only: and this is no great merit for me if I love him; for he is my brother, and we were sown together in thy body, and together came we forth from thy womb, and if I do not love my brother, whom shall I love?" },
  { book: "Jubilees", chapter: 35, verse: 23, text: "And I, myself, beg thee to exhort Jacob concerning me and concerning my sons, for I know that he will assuredly be king over me and my sons, for on the day my father blessed him he made him the higher and me the lower." },
  { book: "Jubilees", chapter: 35, verse: 24, text: "And I swear unto thee that I shall love him, and not desire evil against him all the days of my life but good only.'" },
  { book: "Jubilees", chapter: 35, verse: 25, text: "And he sware unto her regarding all this matter. And she called Jacob before the eyes of Esau, and gave him commandment according to the words which she had spoken to Esau." },
  { book: "Jubilees", chapter: 35, verse: 26, text: "And he said: 'I shall do thy pleasure; believe me that no evil will proceed from me or from my sons against Esau, and I shall be first in naught save in love only.'" },
  { book: "Jubilees", chapter: 35, verse: 27, text: "And they eat and drank, she and her sons that night, and she died, three jubilees and one week and one year old, on that night, and her two sons, Esau and Jacob, buried her in the double cave near Sarah, their father's mother." },
  { book: "Jubilees", chapter: 36, verse: 1, text: "And in the sixth year of this week [2162 A.M.] Isaac called his two sons Esau and Jacob, and they came to him, and he said unto them: 'My sons, I am going the way of my fathers, to the eternal house where my fathers are." },
  { book: "Jubilees", chapter: 36, verse: 2, text: "Wherefore bury me near Abraham my father, in the double cave in the field of Ephron the Hittite, where Abraham purchased a sepulchre to bury in; in the sepulchre which I digged for myself, there bury me." },
  { book: "Jubilees", chapter: 36, verse: 3, text: "And this I command you, my sons, that ye practise righteousness and uprightness on the earth, so that the Lord may bring upon you all that the Lord said that he would do to Abraham and to his seed." },
  { book: "Jubilees", chapter: 36, verse: 4, text: "And love one another, my sons, your brothers as a man who loves his own soul, and let each seek in what he may benefit his brother, and act together on the earth; and let them love each other as their own souls." },
  { book: "Jubilees", chapter: 36, verse: 5, text: "And concerning the question of idols, I command and admonish you to reject them and hate them, and love them not, for they are full of deception for those that worship them and for those that bow down to them." },
  { book: "Jubilees", chapter: 36, verse: 6, text: "Remember ye, my sons, the Lord God of Abraham your father, and how I too worshipped Him and served Him in righteousness and in joy, that He might multiply you and increase your seed as the stars of heaven in multitude, and establish you on the earth as the plant of righteousness which will not be rooted out unto all the generations for ever." },
  { book: "Jubilees", chapter: 36, verse: 7, text: "And now I shall make you swear a great oath -for there is no oath which is greater than it by the name glorious and honoured and great and splendid and wonderful and mighty, which created the heavens and the earth and all things together- that ye will fear Him and worship Him." },
  { book: "Jubilees", chapter: 36, verse: 8, text: "And that each will love his brother with affection and righteousness, and that neither will desire evil against his brother from henceforth for ever all the days of your life so that ye may prosper in all your deeds and not be destroyed." },
  { book: "Jubilees", chapter: 36, verse: 9, text: "And if either of you devises evil against his brother, know that from henceforth everyone that devises evil against his brother shall fall into his hand, and shall be rooted out of the land of the living, and his seed shall be destroyed from under heaven." },
  { book: "Jubilees", chapter: 36, verse: 10, text: "But on the day of turbulence and execration and indignation and anger, with flaming devouring fire as He burnt Sodom, so likewise will He burn his land and his city and all that is his, and he shall be blotted out of the book of the discipline of the children of men, and not be recorded in the book of life, but in that which is appointed to destruction, and he shall depart into eternal execration; so that their condemnation may be always renewed in hate and in execration and in wrath and in torment and in indignation and in plagues and in disease for ever." },
  { book: "Jubilees", chapter: 36, verse: 11, text: "I say and testify to you, my sons, according to the judgment which shall come upon the man who wishes to injure his brother." },
  { book: "Jubilees", chapter: 36, verse: 12, text: "And he divided all his possessions between the two on that day and he gave the larger portion to him that was the first-born, and the tower and all that was about it, and all that Abraham possessed at the Well of the Oath." },
  { book: "Jubilees", chapter: 36, verse: 13, text: "And he said: 'This larger portion I will give to the firstborn.'" },
  { book: "Jubilees", chapter: 36, verse: 14, text: "And Esau said, 'I have sold to Jacob and given my birthright to Jacob; to him let it be given, and I have not a single word to say regarding it, for it is his.'" },
  { book: "Jubilees", chapter: 36, verse: 15, text: "And Isaac said, 'May a blessing rest upon you, my sons, and upon your seed this day, for ye have given me rest, and my heart is not pained concerning the birthright, lest thou shouldest work wickedness on account of it." },
  { book: "Jubilees", chapter: 36, verse: 16, text: "May the Most High God bless the man that worketh righteousness, him and his seed for ever.'" },
  { book: "Jubilees", chapter: 36, verse: 17, text: "And he ended commanding them and blessing them, and they eat and drank together before him, and he rejoiced because there was one mind between them, and they went forth from him and rested that day and slept." },
  { book: "Jubilees", chapter: 36, verse: 18, text: "And Isaac slept on his bed that day rejoicing; and he slept the eternal sleep, and died one hundred and eighty years old. He completed twenty-five weeks and five years; and his two sons Esau and Jacob buried him." },
  { book: "Jubilees", chapter: 36, verse: 19, text: "And Esau went to the land of Edom, to the mountains of Seir, and dwelt there." },
  { book: "Jubilees", chapter: 36, verse: 20, text: "And Jacob dwelt in the mountains of Hebron, in the tower of the land of the sojournings of his father Abraham, and he worshipped the Lord with all his heart and according to the visible commands according as He had divided the days of his generations." },
  { book: "Jubilees", chapter: 36, verse: 21, text: "And Leah his wife died in the fourth year of the second week of the forty-fifth jubilee, [2167 A.M.] and he buried her in the double cave near Rebecca his mother to the left of the grave of Sarah, his father's mother" },
  { book: "Jubilees", chapter: 36, verse: 22, text: "and all her sons and his sons came to mourn over Leah his wife with him and to comfort him regarding her, for he was lamenting her for he loved her exceedingly after Rachel her sister died;" },
  { book: "Jubilees", chapter: 36, verse: 23, text: "for she was perfect and upright in all her ways and honoured Jacob,and all the days that she lived with him he did not hear from her mouth a harsh word, for she was gentle and peaceable and upright and honourable." },
  { book: "Jubilees", chapter: 36, verse: 24, text: "And he remembered all her deeds which she had done during her life and he lamented her exceedingly; for he loved her with all his heart and with all his soul." },
  { book: "Jubilees", chapter: 37, verse: 1, text: "And on the day that Isaac the father of Jacob and Esau died, [2162 A.M.] the sons of Esau heard that Isaac had given the portion of the elder to his younger son Jacob and they were very angry." },
  { book: "Jubilees", chapter: 37, verse: 2, text: "And they strove with their father, saying 'Why has thy father given Jacob the portion of the elder and passed over thee, although thou art the elder and Jacob the younger?'" },
  { book: "Jubilees", chapter: 37, verse: 3, text: "And he said unto them 'Because I sold my birthright to Jacob for a small mess of lentils, and on the day my father sent me to hunt and catch and bring him something that he should eat and bless me, he came with guile and brought my father food and drink, and my father blessed him and put me under his hand." },
  { book: "Jubilees", chapter: 37, verse: 4, text: "And now our father has caused us to swear, me and him, that we shall not mutually devise evil, either against his brother, and that we shall continue in love and in peace each with his brother and not make our ways corrupt.'" },
  { book: "Jubilees", chapter: 37, verse: 5, text: "And they said unto him, 'We shall not hearken unto thee to make peace with him; for our strength is greater than his strength, and we are more powerful than he; we shall go against him and slay him, and destroy him and his sons. And if thou wilt not go with us, we shall do hurt to thee also." },
  { book: "Jubilees", chapter: 37, verse: 6, text: "And now hearken unto us: Let us send to Aram and Philistia and Moab and Ammon, and let us choose for ourselves chosen men who are ardent for battle, and let us go against him and do battle with him, and let us exterminate him from the earth before he grows strong.'" },
  { book: "Jubilees", chapter: 37, verse: 7, text: "And their father said unto them, 'Do not go and do not make war with him lest ye fall before him.'" },
  { book: "Jubilees", chapter: 37, verse: 8, text: "And they said unto him, 'This too, is exactly thy mode of action from thy youth until this day, and thou art putting thy neck under his yoke." },
  { book: "Jubilees", chapter: 37, verse: 9, text: "We shall not hearken to these words.' And they sent to Aram, and to 'Aduram to the friend of their father, and they hired along with them one thousand fighting men, chosen men of war." },
  { book: "Jubilees", chapter: 37, verse: 10, text: "And there came to them from Moab and from the children of Ammon, those who were hired, one thousand chosen men, and from Philistia, one thousand chosen men of war, and from Edom and from the Horites one thousand chosen fighting men, and from the Kittim mighty men of war." },
  { book: "Jubilees", chapter: 37, verse: 11, text: "And they said unto their father: Go forth with them and lead them, else we shall slay thee.'" },
  { book: "Jubilees", chapter: 37, verse: 12, text: "And he was filled with wrath and indignation on seeing that his sons were forcing him to go before (them) to lead them against Jacob his brother." },
  { book: "Jubilees", chapter: 37, verse: 13, text: "But afterward he remembered all the evil which lay hidden in his heart against Jacob his brother; and he remembered not the oath which he had sworn to his father and to his mother that he would devise no evil all his days against Jacob his brother." },
  { book: "Jubilees", chapter: 37, verse: 14, text: "And notwithstanding all this, Jacob knew not that they were coming against him to battle, and he was mourning for Leah, his wife, until they approached very near to the tower with four thousand warriors and chosen men of war." },
  { book: "Jubilees", chapter: 37, verse: 15, text: "And the men of Hebron sent to him saying, 'Behold thy brother has come against thee, to fight thee, with four thousand girt with the sword, and they carry shields and weapons'; for they loved Jacob more than Esau. So they told him; for Jacob was a more liberal and merciful man than Esau." },
  { book: "Jubilees", chapter: 37, verse: 16, text: "But Jacob would not believe until they came very near to the tower." },
  { book: "Jubilees", chapter: 37, verse: 17, text: "And he closed the gates of the tower; and he stood on the battlements and spake to his brother Esau and said, 'Noble is the comfort wherewith thou hast come to comfort me for my wife who has died. Is this the oath that thou didst swear to thy father and again to thy mother before they died? Thou hast broken the oath, and on the moment that thou didst swear to thy father wast thou condemned.'" },
  { book: "Jubilees", chapter: 37, verse: 18, text: "And then Esau answered and said unto him, 'Neither the children of men nor the beasts of the earth have any oath of righteousness which in swearing they have sworn (an oath valid) for ever; but every day they devise evil one against another, and how each may slay his adversary and foe." },
  { book: "Jubilees", chapter: 37, verse: 19, text: "And thou dost hate me and my children for ever. And there is no observing the tie of brotherhood with thee." },
  { book: "Jubilees", chapter: 37, verse: 20, text: "Hear these words which I declare unto thee, If the boar can change its skin and make its bristles as soft as wool, Or if it can cause horns to sprout forth on its head like the horns of a stag or of a sheep, Then will I observe the tie of brotherhood with thee And if the breasts separated themselves from their mother, for thou hast not been a brother to me." },
  { book: "Jubilees", chapter: 37, verse: 21, text: "And if the wolves make peace with the lambs so as not to devour or do them violence, And if their hearts are towards them for good, Then there shall be peace in my heart towards thee" },
  { book: "Jubilees", chapter: 37, verse: 22, text: "And if the lion becomes the friend of the ox and makes peace with him And if he is bound under one yoke with him and ploughs with him, Then will I make peace with thee." },
  { book: "Jubilees", chapter: 37, verse: 23, text: "And when the raven becomes white as the raza, Then know that I have loved thee And shall make peace with thee Thou shalt be rooted out, And thy sons shall be rooted out, And there shall be no peace for thee'" },
  { book: "Jubilees", chapter: 37, verse: 24, text: "And when Jacob saw that he was (so) evilly disposed towards him with his heart, and with all his soul as to slay him, and that he had come springing like the wild boar which comes upon the spear that pierces and kills it, and recoils not from it;" },
  { book: "Jubilees", chapter: 37, verse: 25, text: "then he spake to his own and to his servants that they should attack him and all his companions." },
  { book: "Jubilees", chapter: 38, verse: 1, text: "And after that Judah spake to Jacob, his father, and said unto him: 'Bend thy bow, father, and send forth thy arrows and cast down the adversary and slay the enemy; and mayst thou have the power, for we shall not slay thy brother, for he is such as thou, and he is like thee let us give him (this) honour.'" },
  { book: "Jubilees", chapter: 38, verse: 2, text: "Then Jacob bent his bow and sent forth the arrow and struck Esau, his brother (on his right breast) and slew him." },
  { book: "Jubilees", chapter: 38, verse: 3, text: "And again he sent forth an arrow and struck 'Adoran the Aramaean, on the left breast, and drove him backward and slew him." },
  { book: "Jubilees", chapter: 38, verse: 4, text: "And then went forth the sons of Jacob, they and their servants, dividing themselves into companies on the four sides of the tower." },
  { book: "Jubilees", chapter: 38, verse: 5, text: "And Judah went forth in front, and Naphtali and Gad with him and fifty servants with him on the south side of the tower, and they slew all they found before them, and not one individual of them escaped." },
  { book: "Jubilees", chapter: 38, verse: 6, text: "And Levi and Dan and Asher went forth on the east side of the tower, and fifty (men) with them, and they slew the fighting men of Moab and Ammon." },
  { book: "Jubilees", chapter: 38, verse: 7, text: "And Reuben and Issachar and Zebulon went forth on the north side of the tower, and fifty men with them, and they slew the fighting men of the Philistines." },
  { book: "Jubilees", chapter: 38, verse: 8, text: "And Simeon and Benjamin and Enoch, Reuben's son, went forth on the west side of the tower, and fifty (men) with them, and they slew of Edom and of the Horites four hundred men, stout warriors; and six hundred fled, and four of the sons of Esau fled with them, and left their father lying slain, as he had fallen on the hill which is in 'Aduram." },
  { book: "Jubilees", chapter: 38, verse: 9, text: "And the sons of Jacob pursued after them to the mountains of Seir. And Jacob buried his brother on the hill which is in 'Aduram, and he returned to his house." },
  { book: "Jubilees", chapter: 38, verse: 10, text: "And the sons of Jacob pressed hard upon the sons of Esau in the mountains of Seir, and bowed their necks so that they became servants of the sons of Jacob." },
  { book: "Jubilees", chapter: 38, verse: 11, text: "And they sent to their father (to inquire) whether they should make peace with them or slay them." },
  { book: "Jubilees", chapter: 38, verse: 12, text: "And Jacob sent word to his sons that they should make peace, and they made peace with them, and placed the yoke of servitude upon them, so that they paid tribute to Jacob and to his sons always." },
  { book: "Jubilees", chapter: 38, verse: 13, text: "And they continued to pay tribute to Jacob until the day that he went down into Egypt." },
  { book: "Jubilees", chapter: 38, verse: 14, text: "And the sons of Edom have not got quit of the yoke of servitude which the twelve sons of Jacob had imposed on them until this day." },
  { book: "Jubilees", chapter: 38, verse: 15, text: "And these are the kings that reigned in Edom before there reigned any king over the children of Israel [until this day] in the land of Edom." },
  { book: "Jubilees", chapter: 38, verse: 16, text: "And Balaq, the son of Beor, reigned in Edom, and the name of his city was Danaba." },
  { book: "Jubilees", chapter: 38, verse: 17, text: "And Balaq died, and Jobab, the son of Zara of Boser, reigned in his stead." },
  { book: "Jubilees", chapter: 38, verse: 18, text: "And Jobab died, and 'Asam, of the land of Teman, reigned in his stead." },
  { book: "Jubilees", chapter: 38, verse: 19, text: "And 'Asam died, and 'Adath, the son of Barad, who slew Midian in the field of Moab, reigned in his stead, and the name of his city was Avith." },
  { book: "Jubilees", chapter: 38, verse: 20, text: "And 'Adath died, and Salman, from 'Amaseqa, reigned in his stead." },
  { book: "Jubilees", chapter: 38, verse: 21, text: "And Salman died,and Saul of Ra'aboth (by the) river, reigned in his stead." },
  { book: "Jubilees", chapter: 38, verse: 22, text: "And Saul died, and Ba'elunan, the son of Achbor, reigned in his stead." },
  { book: "Jubilees", chapter: 38, verse: 23, text: "And Ba'elunan, the son of Achbor died, and 'Adath reigned in his stead, and the name of his wife was Maitabith, the daughter of Matarat, the daughter of Metabedza'ab." },
  { book: "Jubilees", chapter: 38, verse: 24, text: "These are the kings who reigned in the land of Edom." },
  { book: "Jubilees", chapter: 39, verse: 1, text: "And Jacob dwelt in the land of his father's sojournings in the land of Canaan. These are the generations of Jacob." },
  { book: "Jubilees", chapter: 39, verse: 2, text: "And Joseph was seventeen years old when they took him down into the land of Egypt, and Potiphar, an eunuch of Pharaoh, the chief cook bought him." },
  { book: "Jubilees", chapter: 39, verse: 3, text: "And he set Joseph over all his house and the blessing of the Lord came upon the house of the Egyptian on account of Joseph, and the Lord prospered him in all that he did." },
  { book: "Jubilees", chapter: 39, verse: 4, text: "And the Egyptian committed everything into the hands of Joseph; for he saw that the Lord was with him, and that the Lord prospered him in all that he did." },
  { book: "Jubilees", chapter: 39, verse: 5, text: "And Joseph's appearance was comely [and very beautiful was his appearance], and his master's wife lifted up her eyes and saw Joseph, and she loved him and besought him to lie with her." },
  { book: "Jubilees", chapter: 39, verse: 6, text: "But he did not surrender his soul, and he remembered the Lord and the words which Jacob, his father, used to read from amongst the words of Abraham, that no man should commit fornication with a woman who has a husband; that for him the punishment of death has been ordained in the heavens before the Most High God, and the sin will be recorded against him in the eternal books continually before the Lord." },
  { book: "Jubilees", chapter: 39, verse: 7, text: "And Joseph remembered these words and refused to lie with her." },
  { book: "Jubilees", chapter: 39, verse: 8, text: "And she besought him for a year, but he refused and would not listen." },
  { book: "Jubilees", chapter: 39, verse: 9, text: "But she embraced him and held him fast in the house in order to force him to lie with her, and closed the doors of the house and held him fast; but he left his garment in her hands and broke through the door and fled without from her presence." },
  { book: "Jubilees", chapter: 39, verse: 10, text: "And the woman saw that he would not lie with her, and she calumniated him in the presence of his lord, saying 'Thy Hebrew servant, whom thou lovest, sought to force me so that he might lie with me; and it came to pass when I lifted up my voice that he fled and left his garment in my hands when I held him, and he brake through the door.'" },
  { book: "Jubilees", chapter: 39, verse: 11, text: "And the Egyptian saw the garment of Joseph and the broken door, and heard the words of his wife, and cast Joseph into prison into the place where the prisoners were kept whom the king imprisoned." },
  { book: "Jubilees", chapter: 39, verse: 12, text: "And he was there in the prison; and the Lord gave Joseph favour in the sight of the chief of the prison guards and compassion before him, for he saw that the Lord was with him, and that the Lord made all that he did to prosper." },
  { book: "Jubilees", chapter: 39, verse: 13, text: "And he committed all things into his hands, and the chief of the prison guards knew of nothing that was with him, for Joseph did every thing, and the Lord perfected it." },
  { book: "Jubilees", chapter: 39, verse: 14, text: "And he remained there two years. And in those days Pharaoh, king of Egypt was wroth against his two eunuchs, against the chief butler, and against the chief baker, and he put them in ward in the house of the chief cook, in the prison where Joseph was kept." },
  { book: "Jubilees", chapter: 39, verse: 15, text: "And the chief of the prison guards appointed Joseph to serve them; and he served before them." },
  { book: "Jubilees", chapter: 39, verse: 16, text: "And they both dreamed a dream, the chief butler and the chief baker, and they told it to Joseph." },
  { book: "Jubilees", chapter: 39, verse: 17, text: "And as he interpreted to them so it befell them, and Pharaoh restored the chief butler to his office and the (chief) baker he slew, as Joseph had interpreted to them." },
  { book: "Jubilees", chapter: 39, verse: 18, text: "But the chief butler forgot Joseph in the prison, although he had informed him what would befall him, and did not remember to inform Pharaoh how Joseph had told him, for he forgot." },
  { book: "Jubilees", chapter: 40, verse: 1, text: "And in those days Pharaoh dreamed two dreams in one night concerning a famine which was to be in all the land, and he awoke from his sleep and called all the interpreters of dreams that were in Egypt, and magicians, and told them his two dreams, and they were not able to declare (them)." },
  { book: "Jubilees", chapter: 40, verse: 2, text: "And then the chief butler remembered Joseph and spake of him to the king, and he brought him forth from the prison, and he to]d his two dreams before him." },
  { book: "Jubilees", chapter: 40, verse: 3, text: "And he said before Pharaoh that his two dreams were one, and he said unto him: 'Seven years shall come (in which there shall be) plenty over all the land of Egypt, and after that seven years of famine, such a famine as has not been in all the land." },
  { book: "Jubilees", chapter: 40, verse: 4, text: "And now let Pharaoh appoint overseers in all the land of Egypt, and let them store up food in every city throughout the days of the years of plenty, and there will be food for the seven years of famine, and the land will not perish through the famine, for it will be very severe.'" },
  { book: "Jubilees", chapter: 40, verse: 5, text: "And the Lord gave Joseph favour and mercy in the eyes of Pharaoh, and Pharaoh said unto his servants: 'We shall not find such a wise and discreet man as this man, for the spirit of the Lord is with him.'" },
  { book: "Jubilees", chapter: 40, verse: 6, text: "And he appointed him the second in all his kingdom and gave him authority over all Egypt, and caused him to ride in the second chariot of Pharaoh." },
  { book: "Jubilees", chapter: 40, verse: 7, text: "And he clothed him with byssus garments, and he put a gold chain upon his neck, and (a herald) proclaimed before him ' 'El 'El wa 'Abirer,' and placed a ring on his hand and made him ruler over all his house, and magnified him, and said unto him. 'Only on the throne shall I be greater than thou.'" },
  { book: "Jubilees", chapter: 40, verse: 8, text: "And Joseph ruled over all the land of Egypt, and all the princes of Pharaoh, and all his servants, and all who did the king's business loved him, for he walked in uprightness, for he was without pride and arrogance, and he had no respect of persons, and did not accept gifts, but he judged in uprightness all the people of the land." },
  { book: "Jubilees", chapter: 40, verse: 9, text: "And the land of Egypt was at peace before Pharaoh because of Joseph, for the Lord was with him, and gave him favour and mercy for all his generations before all those who knew him and those who heard concerning him, and Pharaoh's kingdom was well ordered, and there was no Satan and no evil person (therein)." },
  { book: "Jubilees", chapter: 40, verse: 10, text: "And the king called Joseph's name Sephantiphans, and gave Joseph to wife the daughter of Potiphar, the daughter of the priest of Heliopolis, the chief cook." },
  { book: "Jubilees", chapter: 40, verse: 11, text: "And on the day that Joseph stood before Pharaoh he was thirty years old [when he stood before Pharaoh]." },
  { book: "Jubilees", chapter: 40, verse: 12, text: "And in that year Isaac died. And it came to pass as Joseph had said in the interpretation of his two dreams, according as he had said it, there were seven years of plenty over all the land of Egypt, and the land of Egypt abundantly produced, one measure (producing) eighteen hundred measures." },
  { book: "Jubilees", chapter: 40, verse: 13, text: "And Joseph gathered food into every city until they were full of corn until they could no longer count and measure it for its multitude." },
  { book: "Jubilees", chapter: 41, verse: 1, text: "And in the forty-fifth jubilee, in the second week, (and) in the second year, [2165 A.M.] Judah took for his first-born Er, a wife from the daughters of Aram, named Tamar." },
  { book: "Jubilees", chapter: 41, verse: 2, text: "But he hated, and did not lie with her, because his mother was of the daughters of Canaan, and he wished to take him a wife of the kinsfolk of his mother, but Judah, his father, would not permit him." },
  { book: "Jubilees", chapter: 41, verse: 3, text: "And this Er, the first-born of Judah, was wicked, and the Lord slew him." },
  { book: "Jubilees", chapter: 41, verse: 4, text: "And Judah said unto Onan, his brother 'Go in unto thy brother's wife and perform the duty of a husband's brother unto her, and raise up seed unto thy brother.'" },
  { book: "Jubilees", chapter: 41, verse: 5, text: "And Onan knew that the seed would not be his, (but) his brother's only, and he went into the house of his brother's wife, and spilt the seed on the ground, and he was wicked in the eyes of the Lord, and He slew him." },
  { book: "Jubilees", chapter: 41, verse: 6, text: "And Judah said unto Tamar, his daughter-in-law: 'Remain in thy father's house as a widow till Shelah my son be grown up, and I shall give thee to him to wife.'" },
  { book: "Jubilees", chapter: 41, verse: 7, text: "And he grew up; but Bedsu'el, the wife of Judah, did not permit her son Shelah to marry. And Bedsu'el, the wife of Judah, died [2168 A.M.] in the fifth year of this week." },
  { book: "Jubilees", chapter: 41, verse: 8, text: "And in the sixth year Judah went up to shear his sheep at Timnah. [2169 A.M.] And they told Tamar: 'Behold thy father-in-law goeth up to Timnah to shear his sheep.'" },
  { book: "Jubilees", chapter: 41, verse: 9, text: "And she put off her widow's clothes, and put on a veil, and adorned herself, and sat in the gate adjoining the way to Timnah." },
  { book: "Jubilees", chapter: 41, verse: 10, text: "And as Judah was going along he found her, and thought her to be an harlot, and he said unto her: 'Let me come in unto thee'; and she said unto him Come in,' and he went in." },
  { book: "Jubilees", chapter: 41, verse: 11, text: "And she said unto him: 'Give me my hire'; and he said unto her: 'I have nothing in my hand save my ring that is on my finger, and my necklace, and my staff which is in my hand.'" },
  { book: "Jubilees", chapter: 41, verse: 12, text: "And she said unto him 'Give them to me until thou dost send me my hire', and he said unto her: 'I will send unto thee a kid of the goats'; and he gave them to her, and he went in unto her, and she conceived by him." },
  { book: "Jubilees", chapter: 41, verse: 13, text: "And Judah went unto his sheep, and she went to her father's house." },
  { book: "Jubilees", chapter: 41, verse: 14, text: "And Judah sent a kid of the goats by the hand of his shepherd, an Adullamite, and he found her not; and he asked the people of the place, saying: 'Where is the harlot who was here?' And they said unto him; 'There is no harlot here with us.'" },
  { book: "Jubilees", chapter: 41, verse: 15, text: "And he returned and informed him, and said unto him that he had not found her: 'I asked the people of the place, and they said unto me: \"There is no harlot here.\" '" },
  { book: "Jubilees", chapter: 41, verse: 16, text: "And he said: 'Let her keep (them) lest we become a cause of derision.' And when she had completed three months, it was manifest that she was with child, and they told Judah, saying: 'Behold Tamar, thy daughter-in-law, is with child by whoredom.'" },
  { book: "Jubilees", chapter: 41, verse: 17, text: "And Judah went to the house of her father, and said unto her father and her brothers: 'Bring her forth, and let them burn her, for she hath wrought uncleanness in Israel.'" },
  { book: "Jubilees", chapter: 41, verse: 18, text: "And it came to pass when they brought her forth to burn her that she sent to her father-in-law the ring and the necklace, and the staff, saying: 'Discern whose are these, for by him am I with child.'" },
  { book: "Jubilees", chapter: 41, verse: 19, text: "And Judah acknowledged, and said: 'Tamar is more righteous than I am." },
  { book: "Jubilees", chapter: 41, verse: 20, text: "And therefore let them burn her not' And for that reason she was not given to Shelah, and he did not again approach her." },
  { book: "Jubilees", chapter: 41, verse: 21, text: "And after that she bare two sons, Perez [2170 A.M.] and Zerah, in the seventh year of this second week." },
  { book: "Jubilees", chapter: 41, verse: 22, text: "And thereupon the seven years of fruitfulness were accomplished, of which Joseph spake to Pharaoh." },
  { book: "Jubilees", chapter: 41, verse: 23, text: "And Judah acknowledged that the deed which he had done was evil, for he had lain with his daughter-in-law, and he esteemed it hateful in his eyes, and he acknowledged that he had transgressed and gone astray, for he had uncovered the skirt of his son, and he began to lament and to supplicate before the Lord because of his transgression." },
  { book: "Jubilees", chapter: 41, verse: 24, text: "And we told him in a dream that it was forgiven him because he supplicated earnestly, and lamented, and did not again commit it." },
  { book: "Jubilees", chapter: 41, verse: 25, text: "And he received forgiveness because he turned from his sin and from his ignorance, for he transgressed greatly before our God; and every one that acts thus, every one who lies with his mother-in-law, let them burn him with fire that he may burn therein, for there is uncleanness and pollution upon them, with fire let them burn them." },
  { book: "Jubilees", chapter: 41, verse: 26, text: "And do thou command the children of Israel that there be no uncleanness amongst them, for every one who lies with his daughter-in-law or with his mother-in-law hath wrought uncleanness; with fire let them burn the man who has lain with her, and likewise the woman, and He will turn away wrath and punishment from Israel." },
  { book: "Jubilees", chapter: 41, verse: 27, text: "And unto Judah we said that his two sons had not lain with her, and for this reason his seed was stablished for a second generation, and would not be rooted out." },
  { book: "Jubilees", chapter: 41, verse: 28, text: "For in singleness of eye he had gone and sought for punishment, namely, according to the judgment of Abraham, which he had commanded his sons, Judah had sought to burn her with fire." },
  { book: "Jubilees", chapter: 42, verse: 1, text: "And in the first year of the third week of the forty-fifth jubilee the famine began to come into the [2171 A.M.] land, and the rain refused to be given to the earth, for none whatever fell." },
  { book: "Jubilees", chapter: 42, verse: 2, text: "And the earth grew barren, but in the land of Egypt there was food, for Joseph had gathered the seed of the land in the seven years of plenty and had preserved it." },
  { book: "Jubilees", chapter: 42, verse: 3, text: "And the Egyptians came to Joseph that he might give them food, and he opened the store-houses where was the grain of the first year, and he sold it to the people of the land for gold." },
  { book: "Jubilees", chapter: 42, verse: 4, text: "<Now the famine was very sore in the land of Canaan>, and Jacob heard that there was food in Egypt, and he sent his ten sons that they should procure food for him in Egypt; but Benjamin he did not send, and <the ten sons of Jacob> arrived <in Egypt> among those that went (there)." },
  { book: "Jubilees", chapter: 42, verse: 5, text: "And Joseph recognised them, but they did not recognise him, and he spake unto them and questioned them, and he said unto them; 'Are ye not spies and have ye not come to explore the approaches of the land? 'And he put them in ward." },
  { book: "Jubilees", chapter: 42, verse: 6, text: "And after that he set them free again, and detained Simeon alone and sent off his nine brothers." },
  { book: "Jubilees", chapter: 42, verse: 7, text: "And he filled their sacks with corn, and he put their gold in their sacks, and they did not know." },
  { book: "Jubilees", chapter: 42, verse: 8, text: "And he commanded them to bring their younger brother, for they had told him their father was living and their younger brother." },
  { book: "Jubilees", chapter: 42, verse: 9, text: "And they went up from the land of Egypt and they came to the land of Canaan; and they told their father all that had befallen them, and how the lord of the country had spoken roughly to them, and had seized Simeon till they should bring Benjamin." },
  { book: "Jubilees", chapter: 42, verse: 10, text: "And Jacob said: 'Me have ye bereaved of my children! Joseph is not and Simeon also is not, and ye will take Benjamin away. On me has your wickedness come." },
  { book: "Jubilees", chapter: 42, verse: 11, text: "'And he said: 'My son will not go down with you lest perchance he fall sick; for their mother gave birth to two sons, and one has perished, and this one also ye will take from me. If perchance he took a fever on the road, ye would bring down my old age with sorrow unto death.'" },
  { book: "Jubilees", chapter: 42, verse: 12, text: "For he saw that their money had been returned to every man in his sack, and for this reason he feared to send him." },
  { book: "Jubilees", chapter: 42, verse: 13, text: "And the famine increased and became sore in the land of Canaan, and in all lands save in the land of Egypt, for many of the children of the Egyptians had stored up their seed for food from the time when they saw Joseph gathering seed together and putting it in storehouses and preserving it for the years of famine." },
  { book: "Jubilees", chapter: 42, verse: 14, text: "And the people of Egypt fed themselves thereon during the first year of their famine." },
  { book: "Jubilees", chapter: 42, verse: 15, text: "But when Israel saw that the famine was very sore in the land, and that there was no deliverance, he said unto his sons: 'Go again, and procure food for us that we die not.'" },
  { book: "Jubilees", chapter: 42, verse: 16, text: "And they said: 'We shall not go; unless our youngest brother go with us, we shall not go.'" },
  { book: "Jubilees", chapter: 42, verse: 17, text: "And Israel saw that if he did not send him with them, they should all perish by reason of the famine" },
  { book: "Jubilees", chapter: 42, verse: 18, text: "And Reuben said: 'Give him into my hand, and if I do not bring him back to thee, slay my two sons instead of his soul.'" },
  { book: "Jubilees", chapter: 42, verse: 19, text: "And he said unto him: 'He shall not go with thee.' And Judah came near and said: 'Send him with me, and if I do not bring him back to thee, let me bear the blame before thee all the days of my life.'" },
  { book: "Jubilees", chapter: 42, verse: 20, text: "And he sent him with them in the second year of this week on the [2172 A.m.] first day of the month, and they came to the land of Egypt with all those who went, and (they had) presents in their hands, stacte and almonds and terebinth nuts and pure honey." },
  { book: "Jubilees", chapter: 42, verse: 21, text: "And they went and stood before Joseph, and he saw Benjamin his brother, and he knew him, and said unto them: 'Is this your youngest brother?' And they said unto him: 'It is he.' And he said 'The Lord be gracious to thee, my son!'" },
  { book: "Jubilees", chapter: 42, verse: 22, text: "And he sent him into his house and he brought forth Simeon unto them and he made a feast for them, and they presented to him the gift which they had brought in their hands." },
  { book: "Jubilees", chapter: 42, verse: 23, text: "And they eat before him and he gave them all a portion, but the portion of Benjamin was seven times larger than that of any of theirs." },
  { book: "Jubilees", chapter: 42, verse: 24, text: "And they eat and drank and arose and remained with their asses." },
  { book: "Jubilees", chapter: 42, verse: 25, text: "And Joseph devised a plan whereby he might learn their thoughts as to whether thoughts of peace prevailed amongst them, and he said to the steward who was over his house: 'Fill all their sacks with food, and return their money unto them into their vessels, and my cup, the silver cup out of which I drink, put it in the sack of the youngest, and send them away.'" },
  { book: "Jubilees", chapter: 43, verse: 1, text: "And he did as Joseph had told him, and filled all their sacks for them with food and put their money in their sacks, and put the cup in Benjamin's sack." },
  { book: "Jubilees", chapter: 43, verse: 2, text: "And early in the morning they departed, and it came to pass that, when they had gone from thence, Joseph said unto the steward of his house: 'Pursue them, run and seize them, saying, \"For good ye have requited me with evil; you have stolen from me the silver cup out of which my lord drinks.\" And bring back to me their youngest brother, and fetch (him) quickly before I go forth to my seat of judgment.'" },
  { book: "Jubilees", chapter: 43, verse: 3, text: "And he ran after them and said unto them according to these words." },
  { book: "Jubilees", chapter: 43, verse: 4, text: "And they said unto him: 'God forbid that thy servants should do this thing, and steal from the house of thy lord any utensil, and the money also which we found in our sacks the first time, we thy servants brought back from the land of Canaan." },
  { book: "Jubilees", chapter: 43, verse: 5, text: "How then should we steal any utensil? Behold here are we and our sacks search, and wherever thou findest the cup in the sack of any man amongst us, let him be slain, and we and our asses will serve thy lord.'" },
  { book: "Jubilees", chapter: 43, verse: 6, text: "And he said unto them: 'Not so, the man with whom I find, him only shall I take as a servant, and ye shall return in peace unto your house.'" },
  { book: "Jubilees", chapter: 43, verse: 7, text: "And as he was searching in their vessels, beginning with the eldest and ending with the youngest, it was found in Benjamin's sack." },
  { book: "Jubilees", chapter: 43, verse: 8, text: "And they rent their garments, and laded their asses, and returned to the city and came to the house of Joseph, and they all bowed themselves on their faces to the ground before him." },
  { book: "Jubilees", chapter: 43, verse: 9, text: "And Joseph said unto them: 'Ye have done evil.' And they said: 'What shall we say and how shall we defend ourselves? Our lord hath discovered the transgression of his servants; behold we are the servants of our lord, and our asses also." },
  { book: "Jubilees", chapter: 43, verse: 10, text: "'And Joseph said unto them: 'I too fear the Lord; as for you, go ye to your homes and let your brother be my servant, for ye have done evil. Know ye not that a man delights in his cup as I with this cup? And yet ye have stolen it from me.'" },
  { book: "Jubilees", chapter: 43, verse: 11, text: "And Judah said: 'O my lord, let thy servant, I pray thee, speak a word in my lord's ear two brothers did thy servant's mother bear to our father: one went away and was lost, and hath not been found, and he alone is left of his mother, and thy servant our father loves him, and his life also is bound up with the life of this (lad)." },
  { book: "Jubilees", chapter: 43, verse: 12, text: "And it will come to pass, when we go to thy servant our father, and the lad is not with us, that he will die, and we shall bring down our father with sorrow unto death." },
  { book: "Jubilees", chapter: 43, verse: 13, text: "Now rather let me, thy servant, abide instead of the boy as a bondsman unto my lord, and let the lad go with his brethren, for I became surety for him at the hand of thy servant our father, and if I do not bring him back, thy servant will hear the blame to our father for ever.'" },
  { book: "Jubilees", chapter: 43, verse: 14, text: "And Joseph saw that they were all accordant in goodness one with another, and he could not refrain himself, and he told them that he was Joseph." },
  { book: "Jubilees", chapter: 43, verse: 15, text: "And he conversed with them in the Hebrew tongue and fell on their neck and wept." },
  { book: "Jubilees", chapter: 43, verse: 16, text: "But they knew him not and they began to weep. And he said unto them: 'Weep not over me, but hasten and bring my father to me; and ye see that it is my mouth that speaketh and the eyes of my brother Benjamin see." },
  { book: "Jubilees", chapter: 43, verse: 17, text: "For behold this is the second year of the famine, and there are still five years without harvest or fruit of trees or ploughing." },
  { book: "Jubilees", chapter: 43, verse: 18, text: "Come down quickly ye and your households, so that ye perish not through the famine, and do not be grieved for your possessions, for the Lord sent me before you to set things in order that many people might live." },
  { book: "Jubilees", chapter: 43, verse: 19, text: "And tell my father that I am still alive, and ye, behold, ye see that the Lord has made me as a father to Pharaoh, and ruler over his house and over all the land of Egypt." },
  { book: "Jubilees", chapter: 43, verse: 20, text: "And tell my father of all my glory, and all the riches and glory that the Lord hath given me.'" },
  { book: "Jubilees", chapter: 43, verse: 21, text: "And by the command of the mouth of Pharaoh he gave them chariots and provisions for the way, and he gave them all many-coloured raiment and silver." },
  { book: "Jubilees", chapter: 43, verse: 22, text: "And to their father he sent raiment and silver and ten asses which carried corn, and he sent them away." },
  { book: "Jubilees", chapter: 43, verse: 23, text: "And they went up and told their father that Joseph was alive, and was measuring out corn to all the nations of the earth, and that he was ruler over all the land of Egypt." },
  { book: "Jubilees", chapter: 43, verse: 24, text: "And their father did not believe it, for he was beside himself in his mind; but when he saw the wagons which Joseph had sent, the life of his spirit revived, and he said: 'It is enough for me if Joseph lives; I will go down and see him before I die.'" },
  { book: "Jubilees", chapter: 44, verse: 1, text: "And Israel took his journey from Haran from his house on the new moon of the third month, and he went on the way of the Well of the Oath, and he offered a sacrifice to the God of his father Isaac on the seventh of this month." },
  { book: "Jubilees", chapter: 44, verse: 2, text: "And Jacob remembered the dream that he had seen at Bethel, and he feared to go down into Egypt." },
  { book: "Jubilees", chapter: 44, verse: 3, text: "And while he was thinking of sending word to Joseph to come to him, and that he would not go down, he remained there seven days, if perchance he could see a vision as to whether he should remain or go down." },
  { book: "Jubilees", chapter: 44, verse: 4, text: "And he celebrated the harvest festival of the first-fruits with old grain, for in all the land of Canaan there was not a handful of seed [in the land], for the famine was over all the beasts and cattle and birds, and also over man." },
  { book: "Jubilees", chapter: 44, verse: 5, text: "And on the sixteenth the Lord appeared unto him, and said unto him, 'Jacob, Jacob'; and he said, 'Here am I.' And He said unto him: 'I am the God of thy fathers, the God of Abraham and Isaac; fear not to go down into Egypt, for I will there make of thee a great nation I will go down with thee, and I will bring thee up (again), and in this land shalt thou be buried, and Joseph shall put his hands upon thy eyes." },
  { book: "Jubilees", chapter: 44, verse: 6, text: "Fear not; go down into Egypt.'" },
  { book: "Jubilees", chapter: 44, verse: 7, text: "And his sons rose up, and his sons' sons, and they placed their father and their possessions upon wagons." },
  { book: "Jubilees", chapter: 44, verse: 8, text: "And Israel rose up from the Well of the Oath on the sixteenth of this third month, and he went to the land of Egypt." },
  { book: "Jubilees", chapter: 44, verse: 9, text: "And Israel sent Judah before him to his son Joseph to examine the Land of Goshen, for Joseph had told his brothers that they should come and dwell there that they might be near him." },
  { book: "Jubilees", chapter: 44, verse: 10, text: "And this was the goodliest (land) in the land of Egypt, and near to him, for all (of them) and also for the cattle." },
  { book: "Jubilees", chapter: 44, verse: 11, text: "And these are the names of the sons of Jacob who went into Egypt with Jacob their father." },
  { book: "Jubilees", chapter: 44, verse: 12, text: "Reuben, the First-born of Israel; and these are the names of his sons Enoch, and Pallu, and Hezron and Carmi-five." },
  { book: "Jubilees", chapter: 44, verse: 13, text: "Simeon and his sons; and these are the names of his sons: Jemuel, and Jamin, and Ohad, and Jachin, and Zohar, and Shaul, the son of the Zephathite woman-seven." },
  { book: "Jubilees", chapter: 44, verse: 14, text: "Levi and his sons; and these are the names of his sons: Gershon, and Kohath, and Merari-four." },
  { book: "Jubilees", chapter: 44, verse: 15, text: "Judah and his sons; and these are the names of his sons: Shela, and Perez, and Zerah-four." },
  { book: "Jubilees", chapter: 44, verse: 16, text: "Issachar and his sons; and these are the names of his sons: Tola, and Phua, and Jasub, and Shimron-five." },
  { book: "Jubilees", chapter: 44, verse: 17, text: "Zebulon and his sons; and these are the names of his sons: Sered, and Elon, and Jahleel-four." },
  { book: "Jubilees", chapter: 44, verse: 18, text: "And these are the sons of Jacob and their sons whom Leah bore to Jacob in Mesopotamia, six, and their one sister, Dinah and all the souls of the sons of Leah, and their sons, who went with Jacob their father into Egypt, were twenty-nine, and Jacob their father being with them, they were thirty." },
  { book: "Jubilees", chapter: 44, verse: 19, text: "And the sons of Zilpah, Leah's handmaid, the wife of Jacob, who bore unto Jacob Gad and Ashur." },
  { book: "Jubilees", chapter: 44, verse: 20, text: "And these are the names of their sons who went with him into Egypt. The sons of Gad: Ziphion, and Haggi, and Shuni, and Ezbon, <and Eri>, and Areli, and Arodi-eight." },
  { book: "Jubilees", chapter: 44, verse: 21, text: "And the sons of Asher: Imnah, and Ishvah, <and Ishvi>, and Beriah, and Serah, their one sister-six." },
  { book: "Jubilees", chapter: 44, verse: 22, text: "All the souls were fourteen, and all those of Leah were forty-four." },
  { book: "Jubilees", chapter: 44, verse: 23, text: "And the sons of Rachel, the wife of Jacob: Joseph and Benjamin." },
  { book: "Jubilees", chapter: 44, verse: 24, text: "And there were born to Joseph in Egypt before his father came into Egypt, those whom Asenath, daughter of Potiphar priest of Heliopolis bare unto him, Manasseh, and Ephraim-three." },
  { book: "Jubilees", chapter: 44, verse: 25, text: "And the sons of Benjamin: Bela and Becher and Ashbel, Gera, and Naaman, and Ehi, and Rosh, and Muppim, and Huppim, and Ard-eleven." },
  { book: "Jubilees", chapter: 44, verse: 26, text: "And all the souls of Rachel were fourteen." },
  { book: "Jubilees", chapter: 44, verse: 27, text: "And the sons of Bilhah, the handmaid of Rachel, the wife of Jacob, whom she bare to Jacob, were Dan and Naphtali." },
  { book: "Jubilees", chapter: 44, verse: 28, text: "And these are the names of their sons who went with them into Egypt. And the sons of Dan were Hushim, and Samon, and Asudi. and 'Ijaka, and Salomon-six." },
  { book: "Jubilees", chapter: 44, verse: 29, text: "And they died the year in which they entered into Egypt, and there was left to Dan Hushim alone." },
  { book: "Jubilees", chapter: 44, verse: 30, text: "And these are the names of the sons of Naphtali Jahziel, and Guni and Jezer, and Shallum, and 'Iv." },
  { book: "Jubilees", chapter: 44, verse: 31, text: "And 'Iv, who was born after the years of famine, died in Egypt." },
  { book: "Jubilees", chapter: 44, verse: 32, text: "And all the souls of Rachel were twenty-six." },
  { book: "Jubilees", chapter: 44, verse: 33, text: "And all the souls of Jacob which went into Egypt were seventy souls. These are his children and his children's children, in all seventy, but five died in Egypt before Joseph, and had no children." },
  { book: "Jubilees", chapter: 44, verse: 34, text: "And in the land of Canaan two sons of Judah died, Er and Onan, and they had no children, and the children of Israel buried those who perished, and they were reckoned among the seventy Gentile nations." },
  { book: "Jubilees", chapter: 45, verse: 1, text: "And Israel went into the country of Egypt, into the land of Goshen, on the new moon of the fourth [2172 A.M]. month, in the second year of the third week of the forty-fifth jubilee." },
  { book: "Jubilees", chapter: 45, verse: 2, text: "And Joseph went to meet his father Jacob, to the land of Goshen, and he fell on his father's neck and wept." },
  { book: "Jubilees", chapter: 45, verse: 3, text: "And Israel said unto Joseph: 'Now let me die since I have seen thee, and now may the Lord God of Israel be blessed the God of Abraham and the God of Isaac who hath not withheld His mercy and His grace from His servant Jacob." },
  { book: "Jubilees", chapter: 45, verse: 4, text: "It is enough for me that I have seen thy face whilst I am yet alive; yea, true is the vision which I saw at Bethel. Blessed be the Lord my God for ever and ever, and blessed be His name.'" },
  { book: "Jubilees", chapter: 45, verse: 5, text: "And Joseph and his brothers eat bread before their father and drank wine, and Jacob rejoiced with exceeding great joy because he saw Joseph eating with his brothers and drinking before him, and he blessed the Creator of all things who had preserved him, and had preserved for him his twelve sons." },
  { book: "Jubilees", chapter: 45, verse: 6, text: "And Joseph had given to his father and to his brothers as a gift the right of dwelling in the land of Goshen and in Rameses and all the region round about, which he ruled over before Pharaoh. And Israel and his sons dwelt in the land of Goshen, the best part of the land of Egypt and Israel was one hundred and thirty years old when he came into Egypt." },
  { book: "Jubilees", chapter: 45, verse: 7, text: "And Joseph nourished his father and his brethren and also their possessions with bread as much as sufficed them for the seven years of the famine." },
  { book: "Jubilees", chapter: 45, verse: 8, text: "And the land of Egypt suffered by reason of the famine, and Joseph acquired all the land of Egypt for Pharaoh in return for food, and he got possession of the people and their cattle and everything for Pharaoh." },
  { book: "Jubilees", chapter: 45, verse: 9, text: "And the years of the famine were accomplished, and Joseph gave to the people in the land seed and food that they might sow (the land) in the eighth year, for the river had overflowed all the land of Egypt." },
  { book: "Jubilees", chapter: 45, verse: 10, text: "For in the seven years of the famine it had (not) overflowed and had irrigated only a few places on the banks of the river, but now it overflowed and the Egyptians sowed the land, and it bore much corn that year." },
  { book: "Jubilees", chapter: 45, verse: 11, text: "And this was the first year of [2178 A.M.] the fourth week of the forty-fifth jubilee." },
  { book: "Jubilees", chapter: 45, verse: 12, text: "And Joseph took of the corn of the harvest the fifth part for the king and left four parts for them for food and for seed, and Joseph made it an ordinance for the land of Egypt until this day." },
  { book: "Jubilees", chapter: 45, verse: 13, text: "And Israel lived in the land of Egypt seventeen years, and all the days which he lived were three jubilees, one hundred and forty-seven years, and he died in the fourth [2188 A.M.] year of the fifth week of the forty-fifth jubilee." },
  { book: "Jubilees", chapter: 45, verse: 14, text: "And Israel blessed his sons before he died and told them everything that would befall them in the land of Egypt; and he made known to them what would come upon them in the last days, and blessed them and gave to Joseph two portions in the land." },
  { book: "Jubilees", chapter: 45, verse: 15, text: "And he slept with his fathers, and he was buried in the double cave in the land of Canaan, near Abraham his father in the grave which he dug for himself in the double cave in the land of Hebron." },
  { book: "Jubilees", chapter: 45, verse: 16, text: "And he gave all his books and the books of his fathers to Levi his son that he might preserve them and renew them for his children until this day." },
  { book: "Jubilees", chapter: 46, verse: 1, text: "And it came to pass that after Jacob died the children of Israel multiplied in the land of Egypt, and they became a great nation, and they were of one accord in heart, so that brother loved brother and every man helped his brother, and they increased abundantly and multiplied exceedingly, ten [2242 A.M.] weeks of years, all the days of the life of Joseph." },
  { book: "Jubilees", chapter: 46, verse: 2, text: "And there was no Satan nor any evil all the days of the life of Joseph which he lived after his father Jacob, for all the Egyptians honoured the children of Israel all the days of the life of Joseph." },
  { book: "Jubilees", chapter: 46, verse: 3, text: "And Joseph died being a hundred and ten years old; seventeen years he lived in the land of Canaan, and ten years he was a servant, and three years in prison, and eighty years he was under the king, ruling all the land of Egypt." },
  { book: "Jubilees", chapter: 46, verse: 4, text: "And he died and all his brethren and all that generation." },
  { book: "Jubilees", chapter: 46, verse: 5, text: "And he commanded the children of Israel before he died that they should carry his bones with them when they went forth from the land of Egypt." },
  { book: "Jubilees", chapter: 46, verse: 6, text: "And he made them swear regarding his bones, for he knew that the Egyptians would not again bring forth and bury him in the land of Canaan, for Makamaron, king of Canaan, while dwelling in the land of Assyria, fought in the valley with the king of Egypt and slew him there, and pursued after the Egyptians to the gates of 'Ermon." },
  { book: "Jubilees", chapter: 46, verse: 7, text: "But he was not able to enter, for another, a new king, had become king of Egypt, and he was stronger than he, and he returned to the land of Canaan, and the gates of Egypt were closed, and none went out and none came into Egypt." },
  { book: "Jubilees", chapter: 46, verse: 8, text: "And Joseph died in the forty-sixth jubilee, in the sixth week, in the second year, and they buried him in the land of Egypt, and [2242 A.M.] all his brethren died after him." },
  { book: "Jubilees", chapter: 46, verse: 9, text: "And the king of Egypt went forth to war with the king of Canaan [2263 A.M.] in the forty-seventh jubilee, in the second week in the second year, and the children of Israel brought forth all the bones of the children of Jacob save the bones of Joseph, and they buried them in the field in the double cave in the mountain." },
  { book: "Jubilees", chapter: 46, verse: 10, text: "And the most (of them) returned to Egypt, but a few of them remained in the mountains of Hebron, and Amram thy father remained with them." },
  { book: "Jubilees", chapter: 46, verse: 11, text: "And the king of Canaan was victorious over the king of Egypt, and he closed the gates of Egypt." },
  { book: "Jubilees", chapter: 46, verse: 12, text: "And he devised an evil device against the children of Israel of afflicting them and he said unto the people of Egypt: 'Behold the people of the children of Israel have increased and multiplied more than we." },
  { book: "Jubilees", chapter: 46, verse: 13, text: "Come and let us deal wisely with them before they become too many, and let us afflict them with slavery before war come upon us and before they too fight against us; else they will join themselves unto our enemies and get them up out of our land, for their hearts and faces are towards the land of Canaan.'" },
  { book: "Jubilees", chapter: 46, verse: 14, text: "And he set over them taskmasters to afflict them with slavery; and they built strong cities for Pharaoh, Pithom, and Raamses and they built all the walls and all the fortifications which had fallen in the cities of Egypt." },
  { book: "Jubilees", chapter: 46, verse: 15, text: "And they made them serve with rigour, and the more they dealt evilly with them, the more they increased and multiplied." },
  { book: "Jubilees", chapter: 46, verse: 16, text: "And the people of Egypt abominated the children of Israel" },
  { book: "Jubilees", chapter: 47, verse: 1, text: "And in the seventh week, in the seventh year, in the forty-seventh jubilee, thy father went forth [2303 A.M.] from the land of Canaan, and thou wast born in the fourth week, in the sixth year thereof, in the [2330 A.M.] forty-eighth jubilee; this was the time of tribulation on the children of Israel." },
  { book: "Jubilees", chapter: 47, verse: 2, text: "And Pharaoh, king of Egypt, issued a command regarding them that they should cast all their male children which were born into the river." },
  { book: "Jubilees", chapter: 47, verse: 3, text: "And they cast them in for seven months until the day that thou wast born" },
  { book: "Jubilees", chapter: 47, verse: 4, text: "And thy mother hid thee for three months, and they told regarding her. And she made an ark for thee, and covered it with pitch and asphalt, and placed it in the flags on the bank of the river, and she placed thee in it seven days, and thy mother came by night and suckled thee, and by day Miriam, thy sister, guarded thee from the birds." },
  { book: "Jubilees", chapter: 47, verse: 5, text: "And in those days Tharmuth, the daughter of Pharaoh, came to bathe in the river, and she heard thy voice crying, and she told her maidens to bring thee forth, and they brought thee unto her." },
  { book: "Jubilees", chapter: 47, verse: 6, text: "And she took thee out of the ark, and she had compassion on thee." },
  { book: "Jubilees", chapter: 47, verse: 7, text: "And thy sister said unto her: 'Shall I go and call unto thee one of the Hebrew women to nurse and suckle this babe for thee?'" },
  { book: "Jubilees", chapter: 47, verse: 8, text: "And she said <unto her>: 'Go.' And she went and called thy mother Jochebed, and she gave her wages, and she nursed thee." },
  { book: "Jubilees", chapter: 47, verse: 9, text: "And afterwards, when thou wast grown up, they brought thee unto the daughter of Pharaoh, and thou didst become her son, and Amram thy father taught thee writing, and after thou hadst completed three weeks they brought thee into the royal court." },
  { book: "Jubilees", chapter: 47, verse: 10, text: "And thou wast three weeks of years at court until the time [2351-] when thou didst go forth from the royal court and didst see an Egyptian smiting thy friend who was [2372 A.M.] of the children of Israel, and thou didst slay him and hide him in the sand." },
  { book: "Jubilees", chapter: 47, verse: 11, text: "And on the second day thou didst and two of the children of Israel striving together, and thou didst say to him who was doing the wrong: 'Why dost thou smite thy brother?'" },
  { book: "Jubilees", chapter: 47, verse: 12, text: "And he was angry and indignant, and said: 'Who made thee a prince and a judge over us? Thinkest thou to kill me as thou killedst the Egyptian yesterday?' And thou didst fear and flee on account of these words." },
  { book: "Jubilees", chapter: 48, verse: 1, text: "And in the sixth year of the third week of the forty-ninth jubilee thou didst depart and dwell <in [2372 A.M.] the land of Midian>, five weeks and one year. And thou didst return into Egypt in the second week in the second year in the fiftieth jubilee." },
  { book: "Jubilees", chapter: 48, verse: 2, text: "And thou thyself knowest what He spake unto thee on [2410 A.M.] Mount Sinai, and what prince Mastêmâ desired to do with thee when thou wast returning into Egypt <on the way when thou didst meet him at the lodging-place>." },
  { book: "Jubilees", chapter: 48, verse: 3, text: "Did he not with all his power seek to slay thee and deliver the Egyptians out of thy hand when he saw that thou wast sent to execute judgment and vengeance on the Egyptians?" },
  { book: "Jubilees", chapter: 48, verse: 4, text: "And I delivered thee out of his hand, and thou didst perform the signs and wonders which thou wast sent to perform in Egypt against Pharaoh, and against all his house, and against his servants and his people." },
  { book: "Jubilees", chapter: 48, verse: 5, text: "And the Lord executed a great vengeance on them for Israel's sake, and smote them through (the plagues of) blood and frogs, lice and dog-flies, and malignant boils breaking forth in blains; and their cattle by death; and by hail-stones, thereby He destroyed everything that grew for them; and by locusts which devoured the residue which had been left by the hail, and by darkness; and <by the death> of the first-born of men and animals, and on all their idols the Lord took vengeance and burned them with fire." },
  { book: "Jubilees", chapter: 48, verse: 6, text: "And everything was sent through thy hand, that thou shouldst declare (these things) before they were done, and thou didst speak with the king of Egypt before all his servants and before his people." },
  { book: "Jubilees", chapter: 48, verse: 7, text: "And everything took place according to thy words; ten great and terrible judgments came on the land of Egypt that thou mightest execute vengeance on it for Israel." },
  { book: "Jubilees", chapter: 48, verse: 8, text: "And the Lord did everything for Israel's sake, and according to His covenant, which he had ordained with Abraham that He would take vengeance on them as they had brought them by force into bondage." },
  { book: "Jubilees", chapter: 48, verse: 9, text: "And the prince Mastêmâ stood up against thee, and sought to cast thee into the hands of Pharaoh, and he helped the Egyptian sorcerers," },
  { book: "Jubilees", chapter: 48, verse: 10, text: "and they stood up and wrought before thee the evils indeed we permitted them to work, but the remedies we did not allow to be wrought by their hands." },
  { book: "Jubilees", chapter: 48, verse: 11, text: "And the Lord smote them with malignant ulcers, and they were not able to stand, for we destroyed them so that they could not perform a single sign." },
  { book: "Jubilees", chapter: 48, verse: 12, text: "And notwithstanding all (these) signs and wonders the prince Mastêmâ was not put to shame because he took courage and cried to the Egyptians to pursue after thee with all the powers of the Egyptians, with their chariots, and with their horses, and with all the hosts of the peoples of Egypt." },
  { book: "Jubilees", chapter: 48, verse: 13, text: "And I stood between the Egyptians and Israel, and we delivered Israel out of his hand, and out of the hand of his people, and the Lord brought them through the midst of the sea as if it were dry land." },
  { book: "Jubilees", chapter: 48, verse: 14, text: "And all the peoples whom he brought to pursue after Israel, the Lord our God cast them into the midst of the sea, into the depths of the abyss beneath the children of Israel, even as the people of Egypt had cast their children into the river He took vengeance on 1,000,000 of them, and one thousand strong and energetic men were destroyed on account of one suckling of the children of thy people which they had thrown into the river." },
  { book: "Jubilees", chapter: 48, verse: 15, text: "And on the fourteenth day and on the fifteenth and on the sixteenth and on the seventeenth and on the eighteenth the prince Mastêmâ was bound and imprisoned behind the children of Israel that he might not accuse them." },
  { book: "Jubilees", chapter: 48, verse: 16, text: "And on the nineteenth we let them loose that they might help the Egyptians and pursue the children of Israel." },
  { book: "Jubilees", chapter: 48, verse: 17, text: "And he hardened their hearts and made them stubborn, and the device was devised by the Lord our God that He might smite the Egyptians and cast them into the sea." },
  { book: "Jubilees", chapter: 48, verse: 18, text: "And on the fourteenth we bound him that he might not accuse the children of Israel on the day when they asked the Egyptians for vessels and garments, vessels of silver, and vessels of gold, and vessels of bronze, in order to despoil the Egyptians in return for the bondage in which they had forced them to serve." },
  { book: "Jubilees", chapter: 48, verse: 19, text: "And we did not lead forth the children of Israel from Egypt empty handed." },
  { book: "Jubilees", chapter: 49, verse: 1, text: "Remember the commandment which the Lord commanded thee concerning the passover, that thou shouldst celebrate it in its season on the fourteenth of the first month, that thou shouldst kill it before it is evening, and that they should eat it by night on the evening of the fifteenth from the time of the setting of the sun." },
  { book: "Jubilees", chapter: 49, verse: 2, text: "For on this night -the beginning of the festival and the beginning of the joy- ye were eating the passover in Egypt, when all the powers of Mastêmâ had been let loose to slay all the first-born in the land of Egypt, from the first-born of Pharaoh to the first-born of the captive maid-servant in the mill, and to the cattle." },
  { book: "Jubilees", chapter: 49, verse: 3, text: "And this is the sign which the Lord gave them: Into every house on the lintels of which they saw the blood of a lamb of the first year, into (that) house they should not enter to slay, but should pass by (it), that all those should be saved that were in the house because the sign of the blood was on its lintels." },
  { book: "Jubilees", chapter: 49, verse: 4, text: "And the powers of the Lord did everything according as the Lord commanded them, and they passed by all the children of Israel, and the plague came not upon them to destroy from amongst them any soul either of cattle, or man, or dog." },
  { book: "Jubilees", chapter: 49, verse: 5, text: "And the plague was very grievous in Egypt, and there was no house in Egypt where there was not one dead, and weeping and lamentation." },
  { book: "Jubilees", chapter: 49, verse: 6, text: "And all Israel was eating the flesh of the paschal lamb, and drinking the wine, and was lauding, and blessing, and giving thanks to the Lord God of their fathers, and was ready to go forth from under the yoke of Egypt, and from the evil bondage." },
  { book: "Jubilees", chapter: 49, verse: 7, text: "And remember thou this day all the days of thy life, and observe it from year to year all the days of thy life, once a year, on its day, according to all the law thereof, and do not adjourn (it) from day to day, or from month to month." },
  { book: "Jubilees", chapter: 49, verse: 8, text: "For it is an eternal ordinance, and engraven on the heavenly tablets regarding all the children of Israel that they should observe it every year on its day once a year, throughout all their generations; and there is no limit of days, for this is ordained for ever." },
  { book: "Jubilees", chapter: 49, verse: 9, text: "And the man who is free from uncleanness, and does not come to observe it on occasion of its day, so as to bring an acceptable offering before the Lord, and to eat and to drink before the Lord on the day of its festival, that man who is clean and close at hand shall be cut off: because he offered not the oblation of the Lord in its appointed season, he shall take the guilt upon himself." },
  { book: "Jubilees", chapter: 49, verse: 10, text: "Let the children of Israel come and observe the passover on the day of its fixed time, on the fourteenth day of the first month, between the evenings, from the third part of the day to the third part of the night, for two portions of the day are given to the light, and a third part to the evening." },
  { book: "Jubilees", chapter: 49, verse: 11, text: "This is that which the Lord commanded thee that thou shouldst observe it between the evenings." },
  { book: "Jubilees", chapter: 49, verse: 12, text: "And it is not permissible to slay it during any period of the light, but during the period bordering on the evening, and let them eat it at the time of the evening, until the third part of the night, and whatever is left over of all its flesh from the third part of the night and onwards, let them burn it with fire." },
  { book: "Jubilees", chapter: 49, verse: 13, text: "And they shall not cook it with water, nor shall they eat it raw, but roast on the fire: they shall eat it with diligence, its head with the inwards thereof and its feet they shall roast with fire, and not break any bone thereof; for of the children of Israel no bone shall be crushed." },
  { book: "Jubilees", chapter: 49, verse: 14, text: "For this reason the Lord commanded the children of Israel to observe the passover on the day of its fixed time, and they shall not break a bone thereof; for it is a festival day, and a day commanded, and there may be no passing over from day to day, and month to month, but on the day of its festival let it be observed." },
  { book: "Jubilees", chapter: 49, verse: 15, text: "And do thou command the children of Israel to observe the passover throughout their days, every year, once a year on the day of its fixed time, and it shall come for a memorial well pleasing before the Lord, and no plague shall come upon them to slay or to smite in that year in which they celebrate the passover in its season in every respect according to His command." },
  { book: "Jubilees", chapter: 49, verse: 16, text: "And they shall not eat it outside the sanctuary of the Lord, but before the sanctuary of the Lord, and all the people of the congregation of Israel shall celebrate it in its appointed season." },
  { book: "Jubilees", chapter: 49, verse: 17, text: "And every man who has come upon its day shall eat it in the sanctuary of your God before the Lord from twenty years old and upward; for thus is it written and ordained that they should eat it in the sanctuary of the Lord." },
  { book: "Jubilees", chapter: 49, verse: 18, text: "And when the children of Israel come into the land which they are to possess, into the land of Canaan, and set up the tabernacle of the Lord in the midst of the land in one of their tribes until the sanctuary of the Lord has been built in the land, let them come and celebrate the passover in the midst of the tabernacle of the Lord, and let them slay it before the Lord from year to year." },
  { book: "Jubilees", chapter: 49, verse: 19, text: "And in the days when the house has been built in the name of the Lord in the land of their inheritance, they shall go there and slay the passover in the evening, at sunset, at the third part of the day." },
  { book: "Jubilees", chapter: 49, verse: 20, text: "And they shall offer its blood on the threshold of the altar, and shall place its fat on the fire which is upon the altar, and they shall eat its flesh roasted with fire in the court of the house which has been sanctified in the name of the Lord." },
  { book: "Jubilees", chapter: 49, verse: 21, text: "And they may not celebrate the passover in their cities, nor in any place save before the tabernacle of the Lord, or before His house where His name hath dwelt; and they shall not go astray from the Lord." },
  { book: "Jubilees", chapter: 49, verse: 22, text: "And do thou, Moses, command the children of Israel to observe the ordinances of the passover, as it was commanded unto thee; declare thou unto them every year and the day of its days, and the festival of unleavened bread, that they should eat unleavened bread seven days, (and) that they should observe its festival, and that they bring an oblation every day during those seven days of joy before the Lord on the altar of your God." },
  { book: "Jubilees", chapter: 49, verse: 23, text: "For ye celebrated this festival with haste when ye went forth from Egypt till ye entered into the wilderness of Shur; for on the shore of the sea ye completed it." },
  { book: "Jubilees", chapter: 50, verse: 1, text: "And after this law I made known to thee the days of the Sabbaths in the desert of Sin[ai], which is between Elim and Sinai." },
  { book: "Jubilees", chapter: 50, verse: 2, text: "And I told thee of the Sabbaths of the land on Mount Sinai, and I told thee of the jubilee years in the sabbaths of years: but the year thereof have I not told thee till ye enter the land which ye are to possess." },
  { book: "Jubilees", chapter: 50, verse: 3, text: "And the land also shall keep its sabbaths while they dwell upon it, and they shall know the jubilee year." },
  { book: "Jubilees", chapter: 50, verse: 4, text: "Wherefore I have ordained for thee the year-weeks and the years and the jubilees: there are forty-nine jubilees from the days of Adam until this day, [2410 A.M.] and one week and two years: and there are yet forty years to come (lit. 'distant') for learning the [2450 A.M.] commandments of the Lord, until they pass over into the land of Canaan, crossing the Jordan to the west." },
  { book: "Jubilees", chapter: 50, verse: 5, text: "And the jubilees shall pass by, until Israel is cleansed from all guilt of fornication, and uncleanness, and pollution, and sin, and error, and dwells with confidence in all the land, and there shall be no more a Satan or any evil one, and the land shall be clean from that time for evermore." },
  { book: "Jubilees", chapter: 50, verse: 6, text: "And behold the commandment regarding the Sabbaths -I have written (them) down for thee- and all the judgments of its laws." },
  { book: "Jubilees", chapter: 50, verse: 7, text: "Six days shalt thou labour, but on the seventh day is the Sabbath of the Lord your God. In it ye shall do no manner of work, ye and your sons, and your men- servants and your maid-servants, and all your cattle and the sojourner also who is with you." },
  { book: "Jubilees", chapter: 50, verse: 8, text: "And the man that does any work on it shall die: whoever desecrates that day, whoever lies with (his) wife, or whoever says he will do something on it, that he will set out on a journey thereon in regard to any buying or selling: and whoever draws water thereon which he had not prepared for himself on the sixth day, and whoever takes up any burden to carry it out of his tent or out of his house shall die." },
  { book: "Jubilees", chapter: 50, verse: 9, text: "Ye shall do no work whatever on the Sabbath day save what ye have prepared for yourselves on the sixth day, so as to eat, and drink, and rest, and keep Sabbath from all work on that day, and to bless the Lord your God, who has given you a day of festival and a holy day: and a day of the holy kingdom for all Israel is this day among their days for ever." },
  { book: "Jubilees", chapter: 50, verse: 10, text: "For great is the honour which the Lord has given to Israel that they should eat and drink and be satisfied on this festival day, and rest thereon from all labour which belongs to the labour of the children of men save burning frankincense and bringing oblations and sacrifices before the Lord for days and for Sabbaths." },
  { book: "Jubilees", chapter: 50, verse: 11, text: "This work alone shall be done on the Sabbath-days in the sanctuary of the Lord your God; that they may atone for Israel with sacrifice continually from day to day for a memorial well-pleasing before the Lord, and that He may receive them always from day to day according as thou hast been commanded." },
  { book: "Jubilees", chapter: 50, verse: 12, text: "And every man who does any work thereon, or goes a journey, or tills (his) farm, whether in his house or any other place, and whoever lights a fire, or rides on any beast, or travels by ship on the sea, and whoever strikes or kills anything, or slaughters a beast or a bird, or whoever catches an animal or a bird or a fish, or whoever fasts or makes war on the Sabbaths:" },
  { book: "Jubilees", chapter: 50, verse: 13, text: "The man who does any of these things on the Sabbath shall die, so that the children of Israel shall observe the Sabbaths according to the commandments regarding the Sabbaths of the land, as it is written in the tablets, which He gave into my hands that I should write out for thee the laws of the seasons, and the seasons according to the division of their days. Herewith is completed the account of the division of the days." },
  // Judith (339 verses)
  { book: "Judith", chapter: 1, verse: 1, text: "In the twelfth year of the reign of Nabuchodonosor, who reigned in Nineve, the great city; in the days of Arphaxad, which reigned over the Medes in Ecbatane," },
  { book: "Judith", chapter: 1, verse: 2, text: "And built in Ecbatane walls round about of stones hewn three cubits broad and six cubits long, and made the height of the wall seventy cubits, and the breadth thereof fifty cubits:" },
  { book: "Judith", chapter: 1, verse: 3, text: "And set the towers thereof upon the gates of it an hundred cubits high, and the breadth thereof in the foundation threescore cubits:" },
  { book: "Judith", chapter: 1, verse: 4, text: "And he made the gates thereof, even gates that were raised to the height of seventy cubits, and the breadth of them was forty cubits, for the going forth of his mighty armies, and for the setting in array of his footmen:" },
  { book: "Judith", chapter: 1, verse: 5, text: "Even in those days king Nabuchodonosor made war with king Arphaxad in the great plain, which is the plain in the borders of Ragau." },
  { book: "Judith", chapter: 1, verse: 6, text: "And there came unto him all they that dwelt in the hill country, and all that dwelt by Euphrates, and Tigris and Hydaspes, and the plain of Arioch the king of the Elymeans, and very many nations of the sons of Chelod, assembled themselves to the battle." },
  { book: "Judith", chapter: 1, verse: 7, text: "Then Nabuchodonosor king of the Assyrians sent unto all that dwelt in Persia, and to all that dwelt westward, and to those that dwelt in Cilicia, and Damascus, and Libanus, and Antilibanus, and to all that dwelt upon the sea coast," },
  { book: "Judith", chapter: 1, verse: 8, text: "And to those among the nations that were of Carmel, and Galaad, and the higher Galilee, and the great plain of Esdrelom," },
  { book: "Judith", chapter: 1, verse: 9, text: "And to all that were in Samaria and the cities thereof, and beyond Jordan unto Jerusalem, and Betane, and Chelus, and Kades, and the river of Egypt, and Taphnes, and Ramesse, and all the land of Gesem," },
  { book: "Judith", chapter: 1, verse: 10, text: "Until ye come beyond Tanis and Memphis, and to all the inhabitants of Egypt, until ye come to the borders of Ethiopia." },
  { book: "Judith", chapter: 1, verse: 11, text: "But all the inhabitants of the land made light of the commandment of Nabuchodonosor king of the Assyrians, neither went they with him to the battle; for they were not afraid of him: yea, he was before them as one man, and they sent away his ambassadors from them without effect, and with disgrace." },
  { book: "Judith", chapter: 1, verse: 12, text: "Therefore Nabuchodonosor was very angry with all this country, and sware by his throne and kingdom, that he would surely be avenged upon all those coasts of Cilicia, and Damascus, and Syria, and that he would slay with the sword all the inhabitants of the land of Moab, and the children of Ammon, and all Judea, and all that were in Egypt, till ye come to the borders of the two seas." },
  { book: "Judith", chapter: 1, verse: 13, text: "Then he marched in battle array with his power against king Arphaxad in the seventeenth year, and he prevailed in his battle: for he overthrew all the power of Arphaxad, and all his horsemen, and all his chariots," },
  { book: "Judith", chapter: 1, verse: 14, text: "And became lord of his cities, and came unto Ecbatane, and took the towers, and spoiled the streets thereof, and turned the beauty thereof into shame." },
  { book: "Judith", chapter: 1, verse: 15, text: "He took also Arphaxad in the mountains of Ragau, and smote him through with his darts, and destroyed him utterly that day." },
  { book: "Judith", chapter: 1, verse: 16, text: "So he returned afterward to Nineve, both he and all his company of sundry nations being a very great multitude of men of war, and there he took his ease, and banqueted, both he and his army, an hundred and twenty days." },
  { book: "Judith", chapter: 2, verse: 1, text: "And in the eighteenth year, the two and twentieth day of the first month, there was talk in the house of Nabuchodonosor king of the Assyrians that he should, as he said, avenge himself on all the earth." },
  { book: "Judith", chapter: 2, verse: 2, text: "So he called unto him all his officers, and all his nobles, and communicated with them his secret counsel, and concluded the afflicting of the whole earth out of his own mouth." },
  { book: "Judith", chapter: 2, verse: 3, text: "Then they decreed to destroy all flesh, that did not obey the commandment of his mouth." },
  { book: "Judith", chapter: 2, verse: 4, text: "And when he had ended his counsel, Nabuchodonosor king of the Assyrians called Holofernes the chief captain of his army, which was next unto him, and said unto him." },
  { book: "Judith", chapter: 2, verse: 5, text: "Thus saith the great king, the lord of the whole earth, Behold, thou shalt go forth from my presence, and take with thee men that trust in their own strength, of footmen an hundred and twenty thousand; and the number of horses with their riders twelve thousand." },
  { book: "Judith", chapter: 2, verse: 6, text: "And thou shalt go against all the west country, because they disobeyed my commandment." },
  { book: "Judith", chapter: 2, verse: 7, text: "And thou shalt declare unto that they prepare for me earth and water: for I will go forth in my wrath against them and will cover the whole face of the earth with the feet of mine army, and I will give them for a spoil unto them:" },
  { book: "Judith", chapter: 2, verse: 8, text: "So that their slain shall fill their valleys and brooks and the river shall be filled with their dead, till it overflow:" },
  { book: "Judith", chapter: 2, verse: 9, text: "And I will lead them captives to the utmost parts of all the earth." },
  { book: "Judith", chapter: 2, verse: 10, text: "Thou therefore shalt go forth. and take beforehand for me all their coasts: and if they will yield themselves unto thee, thou shalt reserve them for me till the day of their punishment." },
  { book: "Judith", chapter: 2, verse: 11, text: "But concerning them that rebel, let not thine eye spare them; but put them to the slaughter, and spoil them wheresoever thou goest." },
  { book: "Judith", chapter: 2, verse: 12, text: "For as I live, and by the power of my kingdom, whatsoever I have spoken, that will I do by mine hand." },
  { book: "Judith", chapter: 2, verse: 13, text: "And take thou heed that thou transgress none of the commandments of thy lord, but accomplish them fully, as I have commanded thee, and defer not to do them." },
  { book: "Judith", chapter: 2, verse: 14, text: "Then Holofernes went forth from the presence of his lord, and called all the governors and captains, and the officers of the army of Assur;" },
  { book: "Judith", chapter: 2, verse: 15, text: "And he mustered the chosen men for the battle, as his lord had commanded him, unto an hundred and twenty thousand, and twelve thousand archers on horseback;" },
  { book: "Judith", chapter: 2, verse: 16, text: "And he ranged them, as a great army is ordered for the war." },
  { book: "Judith", chapter: 2, verse: 17, text: "And he took camels and asses for their carriages, a very great number; and sheep and oxen and goats without number for their provision:" },
  { book: "Judith", chapter: 2, verse: 18, text: "And plenty of victual for every man of the army, and very much gold and silver out of the king’s house." },
  { book: "Judith", chapter: 2, verse: 19, text: "Then he went forth and all his power to go before king Nabuchodonosor in the voyage, and to cover all the face of the earth westward with their chariots, and horsemen, and their chosen footmen." },
  { book: "Judith", chapter: 2, verse: 20, text: "A great number also sundry countries came with them like locusts, and like the sand of the earth: for the multitude was without number." },
  { book: "Judith", chapter: 2, verse: 21, text: "And they went forth of Nineve three days’ journey toward the plain of Bectileth, and pitched from Bectileth near the mountain which is at the left hand of the upper Cilicia." },
  { book: "Judith", chapter: 2, verse: 22, text: "Then he took all his army, his footmen, and horsemen and chariots, and went from thence into the hill country;" },
  { book: "Judith", chapter: 2, verse: 23, text: "And destroyed Phud and Lud, and spoiled all the children of Rasses, and the children of Israel, which were toward the wilderness at the south of the land of the Chellians." },
  { book: "Judith", chapter: 2, verse: 24, text: "Then he went over Euphrates, and went through Mesopotamia, and destroyed all the high cities that were upon the river Arbonai, till ye come to the sea." },
  { book: "Judith", chapter: 2, verse: 25, text: "And he took the borders of Cilicia, and killed all that resisted him, and came to the borders of Japheth, which were toward the south, over against Arabia." },
  { book: "Judith", chapter: 2, verse: 26, text: "He compassed also all the children of Madian, and burned up their tabernacles, and spoiled their sheepcotes." },
  { book: "Judith", chapter: 2, verse: 27, text: "Then he went down into the plain of Damascus in the time of wheat harvest, and burnt up all their fields, and destroyed their flocks and herds, also he spoiled their cities, and utterly wasted their countries, and smote all their young men with the edge of the sword." },
  { book: "Judith", chapter: 2, verse: 28, text: "Therefore the fear and dread of him fell upon all the inhabitants of the sea coasts, which were in Sidon and Tyrus, and them that dwelt in Sur and Ocina, and all that dwelt in Jemnaan; and they that dwelt in Azotus and Ascalon feared him greatly." },
  { book: "Judith", chapter: 3, verse: 1, text: "So they sent ambassadors unto him to treat of peace, saying," },
  { book: "Judith", chapter: 3, verse: 2, text: "Behold, we the servants of Nabuchodonosor the great king lie before thee; use us as shall be good in thy sight." },
  { book: "Judith", chapter: 3, verse: 3, text: "Behold, our houses, and all our places, and all our fields of wheat, and flocks, and herds, and all the lodges of our tents lie before thy face; use them as it pleaseth thee." },
  { book: "Judith", chapter: 3, verse: 4, text: "Behold, even our cities and the inhabitants thereof are thy servants; come and deal with them as seemeth good unto thee." },
  { book: "Judith", chapter: 3, verse: 5, text: "So the men came to Holofernes, and declared unto him after this manner." },
  { book: "Judith", chapter: 3, verse: 6, text: "Then came he down toward the sea coast, both he and his army, and set garrisons in the high cities, and took out of them chosen men for aid." },
  { book: "Judith", chapter: 3, verse: 7, text: "So they and all the country round about received them with garlands, with dances, and with timbrels." },
  { book: "Judith", chapter: 3, verse: 8, text: "Yet he did cast down their frontiers, and cut down their groves: for he had decreed to destroy all the gods of the land, that all nations should worship Nabuchodonosor only, and that all tongues and tribes should call upon him as god." },
  { book: "Judith", chapter: 3, verse: 9, text: "Also he came over against Esdraelon near unto Judea, over against the great strait of Judea." },
  { book: "Judith", chapter: 3, verse: 10, text: "And he pitched between Geba and Scythopolis, and there he tarried a whole month, that he might gather together all the carriages of his army." },
  { book: "Judith", chapter: 4, verse: 1, text: "Now the children of Israel, that dwelt in Judea, heard all that Holofernes the chief captain of Nabuchodonosor king of the Assyrians had done to the nations, and after what manner he had spoiled all their temples, and brought them to nought." },
  { book: "Judith", chapter: 4, verse: 2, text: "Therefore they were exceedingly afraid of him, and were troubled for Jerusalem, and for the temple of the Lord their God:" },
  { book: "Judith", chapter: 4, verse: 3, text: "For they were newly returned from the captivity, and all the people of Judea were lately gathered together: and the vessels, and the altar, and the house, were sanctified after the profanation." },
  { book: "Judith", chapter: 4, verse: 4, text: "Therefore they sent into all the coasts of Samaria, and the villages and to Bethoron, and Belmen, and Jericho, and to Choba, and Esora, and to the valley of Salem:" },
  { book: "Judith", chapter: 4, verse: 5, text: "And possessed themselves beforehand of all the tops of the high mountains, and fortified the villages that were in them, and laid up victuals for the provision of war: for their fields were of late reaped." },
  { book: "Judith", chapter: 4, verse: 6, text: "Also Joacim the high priest, which was in those days in Jerusalem, wrote to them that dwelt in Bethulia, and Betomestham, which is over against Esdraelon toward the open country, near to Dothaim," },
  { book: "Judith", chapter: 4, verse: 7, text: "Charging them to keep the passages of the hill country: for by them there was an entrance into Judea, and it was easy to stop them that would come up, because the passage was straight, for two men at the most." },
  { book: "Judith", chapter: 4, verse: 8, text: "And the children of Israel did as Joacim the high priest had commanded them, with the ancients of all the people of Israel, which dwelt at Jerusalem." },
  { book: "Judith", chapter: 4, verse: 9, text: "Then every man of Israel cried to God with great fervency, and with great vehemency did they humble their souls:" },
  { book: "Judith", chapter: 4, verse: 10, text: "Both they, and their wives and their children, and their cattle, and every stranger and hireling, and their servants bought with money, put sackcloth upon their loins." },
  { book: "Judith", chapter: 4, verse: 11, text: "Thus every man and women, and the little children, and the inhabitants of Jerusalem, fell before the temple, and cast ashes upon their heads, and spread out their sackcloth before the face of the Lord: also they put sackcloth about the altar," },
  { book: "Judith", chapter: 4, verse: 12, text: "And cried to the God of Israel all with one consent earnestly, that he would not give their children for a prey, and their wives for a spoil, and the cities of their inheritance to destruction, and the sanctuary to profanation and reproach, and for the nations to rejoice at." },
  { book: "Judith", chapter: 4, verse: 13, text: "So God heard their prayers, and looked upon their afflictions: for the people fasted many days in all Judea and Jerusalem before the sanctuary of the Lord Almighty." },
  { book: "Judith", chapter: 4, verse: 14, text: "And Joacim the high priest, and all the priests that stood before the Lord, and they which ministered unto the Lord, had their loins girt with sackcloth, and offered the daily burnt offerings, with the vows and free gifts of the people," },
  { book: "Judith", chapter: 4, verse: 15, text: "And had ashes on their mitres, and cried unto the Lord with all their power, that he would look upon all the house of Israel graciously." },
  { book: "Judith", chapter: 5, verse: 1, text: "Then was it declared to Holofernes, the chief captain of the army of Assur, that the children of Israel had prepared for war, and had shut up the passages of the hill country, and had fortified all the tops of the high hills and had laid impediments in the champaign countries:" },
  { book: "Judith", chapter: 5, verse: 2, text: "Wherewith he was very angry, and called all the princes of Moab, and the captains of Ammon, and all the governors of the sea coast," },
  { book: "Judith", chapter: 5, verse: 3, text: "And he said unto them, Tell me now, ye sons of Chanaan, who this people is, that dwelleth in the hill country, and what are the cities that they inhabit, and what is the multitude of their army, and wherein is their power and strength, and what king is set over them, or captain of their army;" },
  { book: "Judith", chapter: 5, verse: 4, text: "And why have they determined not to come and meet me, more than all the inhabitants of the west." },
  { book: "Judith", chapter: 5, verse: 5, text: "Then said Achior, the captain of all the sons of Ammon, Let my lord now hear a word from the mouth of thy servant, and I will declare unto thee the truth concerning this people, which dwelleth near thee, and inhabiteth the hill countries: and there shall no lie come out of the mouth of thy servant." },
  { book: "Judith", chapter: 5, verse: 6, text: "This people are descended of the Chaldeans:" },
  { book: "Judith", chapter: 5, verse: 7, text: "And they sojourned heretofore in Mesopotamia, because they would not follow the gods of their fathers, which were in the land of Chaldea." },
  { book: "Judith", chapter: 5, verse: 8, text: "For they left the way of their ancestors, and worshipped the God of heaven, the God whom they knew: so they cast them out from the face of their gods, and they fled into Mesopotamia, and sojourned there many days." },
  { book: "Judith", chapter: 5, verse: 9, text: "Then their God commanded them to depart from the place where they sojourned, and to go into the land of Chanaan: where they dwelt, and were increased with gold and silver, and with very much cattle." },
  { book: "Judith", chapter: 5, verse: 10, text: "But when a famine covered all the land of Chanaan, they went down into Egypt, and sojourned there, while they were nourished, and became there a great multitude, so that one could not number their nation." },
  { book: "Judith", chapter: 5, verse: 11, text: "Therefore the king of Egypt rose up against them, and dealt subtilly with them, and brought them low with labouring in brick, and made them slaves." },
  { book: "Judith", chapter: 5, verse: 12, text: "Then they cried unto their God, and he smote all the land of Egypt with incurable plagues: so the Egyptians cast them out of their sight." },
  { book: "Judith", chapter: 5, verse: 13, text: "And God dried the Red sea before them," },
  { book: "Judith", chapter: 5, verse: 14, text: "And brought them to mount Sina, and Cades-Barne, and cast forth all that dwelt in the wilderness." },
  { book: "Judith", chapter: 5, verse: 15, text: "So they dwelt in the land of the Amorites, and they destroyed by their strength all them of Esebon, and passing over Jordan they possessed all the hill country." },
  { book: "Judith", chapter: 5, verse: 16, text: "And they cast forth before them the Chanaanite, the Pherezite, the Jebusite, and the Sychemite, and all the Gergesites, and they dwelt in that country many days." },
  { book: "Judith", chapter: 5, verse: 17, text: "And whilst they sinned not before their God, they prospered, because the God that hateth iniquity was with them." },
  { book: "Judith", chapter: 5, verse: 18, text: "But when they departed from the way which he appointed them, they were destroyed in many battles very sore, and were led captives into a land that was not their’s, and the temple of their God was cast to the ground, and their cities were taken by the enemies." },
  { book: "Judith", chapter: 5, verse: 19, text: "But now are they returned to their God, and are come up from the places where they were scattered, and have possessed Jerusalem, where their sanctuary is, and are seated in the hill country; for it was desolate." },
  { book: "Judith", chapter: 5, verse: 20, text: "Now therefore, my lord and governor, if there be any error against this people, and they sin against their God, let us consider that this shall be their ruin, and let us go up, and we shall overcome them." },
  { book: "Judith", chapter: 5, verse: 21, text: "But if there be no iniquity in their nation, let my lord now pass by, lest their Lord defend them, and their God be for them, and we become a reproach before all the world." },
  { book: "Judith", chapter: 5, verse: 22, text: "And when Achior had finished these sayings, all the people standing round about the tent murmured, and the chief men of Holofernes, and all that dwelt by the sea side, and in Moab, spake that he should kill him." },
  { book: "Judith", chapter: 5, verse: 23, text: "For, say they, we will not be afraid of the face of the children of Israel: for, lo, it is a people that have no strength nor power for a strong battle" },
  { book: "Judith", chapter: 5, verse: 24, text: "Now therefore, lord Holofernes, we will go up, and they shall be a prey to be devoured of all thine army." },
  { book: "Judith", chapter: 6, verse: 1, text: "And when the tumult of men that were about the council was ceased, Holofernes the chief captain of the army of Assur said unto Achior and all the Moabites before all the company of other nations," },
  { book: "Judith", chapter: 6, verse: 2, text: "And who art thou, Achior, and the hirelings of Ephraim, that thou hast prophesied against us as to day, and hast said, that we should not make war with the people of Israel, because their God will defend them? and who is God but Nabuchodonosor?" },
  { book: "Judith", chapter: 6, verse: 3, text: "He will send his power, and will destroy them from the face of the earth, and their God shall not deliver them: but we his servants will destroy them as one man; for they are not able to sustain the power of our horses." },
  { book: "Judith", chapter: 6, verse: 4, text: "For with them we will tread them under foot, and their mountains shall be drunken with their blood, and their fields shall be filled with their dead bodies, and their footsteps shall not be able to stand before us, for they shall utterly perish, saith king Nabuchodonosor, lord of all the earth: for he said, None of my words shall be in vain." },
  { book: "Judith", chapter: 6, verse: 5, text: "And thou, Achior, an hireling of Ammon, which hast spoken these words in the day of thine iniquity, shalt see my face no more from this day, until I take vengeance of this nation that came out of Egypt." },
  { book: "Judith", chapter: 6, verse: 6, text: "And then shall the sword of mine army, and the multitude of them that serve me, pass through thy sides, and thou shalt fall among their slain, when I return." },
  { book: "Judith", chapter: 6, verse: 7, text: "Now therefore my servants shall bring thee back into the hill country, and shall set thee in one of the cities of the passages:" },
  { book: "Judith", chapter: 6, verse: 8, text: "And thou shalt not perish, till thou be destroyed with them." },
  { book: "Judith", chapter: 6, verse: 9, text: "And if thou persuade thyself in thy mind that they shall be taken, let not thy countenance fall: I have spoken it, and none of my words shall be in vain." },
  { book: "Judith", chapter: 6, verse: 10, text: "Then Holofernes commanded his servants, that waited in his tent, to take Achior, and bring him to Bethulia, and deliver him into the hands of the children of Israel." },
  { book: "Judith", chapter: 6, verse: 11, text: "So his servants took him, and brought him out of the camp into the plain, and they went from the midst of the plain into the hill country, and came unto the fountains that were under Bethulia." },
  { book: "Judith", chapter: 6, verse: 12, text: "And when the men of the city saw them, they took up their weapons, and went out of the city to the top of the hill: and every man that used a sling kept them from coming up by casting of stones against them." },
  { book: "Judith", chapter: 6, verse: 13, text: "Nevertheless having gotten privily under the hill, they bound Achior, and cast him down, and left him at the foot of the hill, and returned to their lord." },
  { book: "Judith", chapter: 6, verse: 14, text: "But the Israelites descended from their city, and came unto him, and loosed him, and brought him to Bethulia, and presented him to the governors of the city:" },
  { book: "Judith", chapter: 6, verse: 15, text: "Which were in those days Ozias the son of Micha, of the tribe of Simeon, and Chabris the son of Gothoniel, and Charmis the son of Melchiel." },
  { book: "Judith", chapter: 6, verse: 16, text: "And they called together all the ancients of the city, and all their youth ran together, and their women, to the assembly, and they set Achior in the midst of all their people. Then Ozias asked him of that which was done." },
  { book: "Judith", chapter: 6, verse: 17, text: "And he answered and declared unto them the words of the council of Holofernes, and all the words that he had spoken in the midst of the princes of Assur, and whatsoever Holofernes had spoken proudly against the house of Israel." },
  { book: "Judith", chapter: 6, verse: 18, text: "Then the people fell down and worshipped God, and cried unto God. saying," },
  { book: "Judith", chapter: 6, verse: 19, text: "O Lord God of heaven, behold their pride, and pity the low estate of our nation, and look upon the face of those that are sanctified unto thee this day." },
  { book: "Judith", chapter: 6, verse: 20, text: "Then they comforted Achior, and praised him greatly." },
  { book: "Judith", chapter: 6, verse: 21, text: "And Ozias took him out of the assembly unto his house, and made a feast to the elders; and they called on the God of Israel all that night for help." },
  { book: "Judith", chapter: 7, verse: 1, text: "The next day Holofernes commanded all his army, and all his people which were come to take his part, that they should remove their camp against Bethulia, to take aforehand the ascents of the hill country, and to make war against the children of Israel." },
  { book: "Judith", chapter: 7, verse: 2, text: "Then their strong men removed their camps in that day, and the army of the men of war was an hundred and seventy thousand footmen, and twelve thousand horsemen, beside the baggage, and other men that were afoot among them, a very great multitude." },
  { book: "Judith", chapter: 7, verse: 3, text: "And they camped in the valley near unto Bethulia, by the fountain, and they spread themselves in breadth over Dothaim even to Belmaim, and in length from Bethulia unto Cynamon, which is over against Esdraelon." },
  { book: "Judith", chapter: 7, verse: 4, text: "Now the children of Israel, when they saw the multitude of them, were greatly troubled, and said every one to his neighbour, Now will these men lick up the face of the earth; for neither the high mountains, nor the valleys, nor the hills, are able to bear their weight." },
  { book: "Judith", chapter: 7, verse: 5, text: "Then every man took up his weapons of war, and when they had kindled fires upon their towers, they remained and watched all that night." },
  { book: "Judith", chapter: 7, verse: 6, text: "But in the second day Holofernes brought forth all his horsemen in the sight of the children of Israel which were in Bethulia," },
  { book: "Judith", chapter: 7, verse: 7, text: "And viewed the passages up to the city, and came to the fountains of their waters, and took them, and set garrisons of men of war over them, and he himself removed toward his people." },
  { book: "Judith", chapter: 7, verse: 8, text: "Then came unto him all the chief of the children of Esau, and all the governors of the people of Moab, and the captains of the sea coast, and said," },
  { book: "Judith", chapter: 7, verse: 9, text: "Let our lord now hear a word, that there be not an overthrow in thine army." },
  { book: "Judith", chapter: 7, verse: 10, text: "For this people of the children of Israel do not trust in their spears, but in the height of the mountains wherein they dwell, because it is not easy to come up to the tops of their mountains." },
  { book: "Judith", chapter: 7, verse: 11, text: "Now therefore, my lord, fight not against them in battle array, and there shall not so much as one man of thy people perish." },
  { book: "Judith", chapter: 7, verse: 12, text: "Remain in thy camp, and keep all the men of thine army, and let thy servants get into their hands the fountain of water, which issueth forth of the foot of the mountain:" },
  { book: "Judith", chapter: 7, verse: 13, text: "For all the inhabitants of Bethulia have their water thence; so shall thirst kill them, and they shall give up their city, and we and our people shall go up to the tops of the mountains that are near, and will camp upon them, to watch that none go out of the city." },
  { book: "Judith", chapter: 7, verse: 14, text: "So they and their wives and their children shall be consumed with fire, and before the sword come against them, they shall be overthrown in the streets where they dwell." },
  { book: "Judith", chapter: 7, verse: 15, text: "Thus shalt thou render them an evil reward; because they rebelled, and met not thy person peaceably." },
  { book: "Judith", chapter: 7, verse: 16, text: "And these words pleased Holofernes and all his servants, and he appointed to do as they had spoken." },
  { book: "Judith", chapter: 7, verse: 17, text: "So the camp of the children of Ammon departed, and with them five thousand of the Assyrians, and they pitched in the valley, and took the waters, and the fountains of the waters of the children of Israel." },
  { book: "Judith", chapter: 7, verse: 18, text: "Then the children of Esau went up with the children of Ammon, and camped in the hill country over against Dothaim: and they sent some of them toward the south, and toward the east over against Ekrebel, which is near unto Chusi, that is upon the brook Mochmur; and the rest of the army of the Assyrians camped in the plain, and covered the face of the whole land; and their tents and carriages were pitched to a very great multitude." },
  { book: "Judith", chapter: 7, verse: 19, text: "Then the children of Israel cried unto the Lord their God, because their heart failed, for all their enemies had compassed them round about, and there was no way to escape out from among them." },
  { book: "Judith", chapter: 7, verse: 20, text: "Thus all the company of Assur remained about them, both their footmen, chariots, and horsemen, four and thirty days, so that all their vessels of water failed all the inhabitants of Bethulia." },
  { book: "Judith", chapter: 7, verse: 21, text: "And the cisterns were emptied, and they had not water to drink their fill for one day; for they gave them drink by measure." },
  { book: "Judith", chapter: 7, verse: 22, text: "Therefore their young children were out of heart, and their women and young men fainted for thirst, and fell down in the streets of the city, and by the passages of the gates, and there was no longer any strength in them." },
  { book: "Judith", chapter: 7, verse: 23, text: "Then all the people assembled to Ozias, and to the chief of the city, both young men, and women, and children, and cried with a loud voice, and said before all the elders," },
  { book: "Judith", chapter: 7, verse: 24, text: "God be judge between us and you: for ye have done us great injury, in that ye have not required peace of the children of Assur." },
  { book: "Judith", chapter: 7, verse: 25, text: "For now we have no helper: but God hath sold us into their hands, that we should be thrown down before them with thirst and great destruction." },
  { book: "Judith", chapter: 7, verse: 26, text: "Now therefore call them unto you, and deliver the whole city for a spoil to the people of Holofernes, and to all his army." },
  { book: "Judith", chapter: 7, verse: 27, text: "For it is better for us to be made a spoil unto them, than to die for thirst: for we will be his servants, that our souls may live, and not see the death of our infants before our eyes, nor our wives nor our children to die." },
  { book: "Judith", chapter: 7, verse: 28, text: "We take to witness against you the heaven and the earth, and our God and Lord of our fathers, which punisheth us according to our sins and the sins of our fathers, that he do not according as we have said this day." },
  { book: "Judith", chapter: 7, verse: 29, text: "Then there was great weeping with one consent in the midst of the assembly; and they cried unto the Lord God with a loud voice." },
  { book: "Judith", chapter: 7, verse: 30, text: "Then said Ozias to them, Brethren, be of good courage, let us yet endure five days, in the which space the Lord our God may turn his mercy toward us; for he will not forsake us utterly." },
  { book: "Judith", chapter: 7, verse: 31, text: "And if these days pass, and there come no help unto us, I will do according to your word." },
  { book: "Judith", chapter: 7, verse: 32, text: "And he dispersed the people, every one to their own charge; and they went unto the walls and towers of their city, and sent the women and children into their houses: and they were very low brought in the city." },
  { book: "Judith", chapter: 8, verse: 1, text: "Now at that time Judith heard thereof, which was the daughter of Merari, the son of Ox, the son of Joseph, the son of Ozel, the son of Elcia, the son of Ananias, the son of Gedeon, the son of Raphaim, the son of Acitho, the son of Eliu, the son of Eliab, the son of Nathanael, the son of Samael, the son of Salasadal, the son of Israel." },
  { book: "Judith", chapter: 8, verse: 2, text: "And Manasses was her husband, of her tribe and kindred, who died in the barley harvest." },
  { book: "Judith", chapter: 8, verse: 3, text: "For as he stood overseeing them that bound sheaves in the field, the heat came upon his head, and he fell on his bed, and died in the city of Bethulia: and they buried him with his fathers in the field between Dothaim and Balamo." },
  { book: "Judith", chapter: 8, verse: 4, text: "So Judith was a widow in her house three years and four months." },
  { book: "Judith", chapter: 8, verse: 5, text: "And she made her a tent upon the top of her house, and put on sackcloth upon her loins and ware her widow’s apparel." },
  { book: "Judith", chapter: 8, verse: 6, text: "And she fasted all the days of her widowhood, save the eves of the sabbaths, and the sabbaths, and the eves of the new moons, and the new moons and the feasts and solemn days of the house of Israel." },
  { book: "Judith", chapter: 8, verse: 7, text: "She was also of a goodly countenance, and very beautiful to behold: and her husband Manasses had left her gold, and silver, and menservants and maidservants, and cattle, and lands; and she remained upon them." },
  { book: "Judith", chapter: 8, verse: 8, text: "And there was none that gave her an ill word; as she feared God greatly." },
  { book: "Judith", chapter: 8, verse: 9, text: "Now when she heard the evil words of the people against the governor, that they fainted for lack of water; for Judith had heard all the words that Ozias had spoken unto them, and that he had sworn to deliver the city unto the Assyrians after five days;" },
  { book: "Judith", chapter: 8, verse: 10, text: "Then she sent her waitingwoman, that had the government of all things that she had, to call Ozias and Chabris and Charmis, the ancients of the city." },
  { book: "Judith", chapter: 8, verse: 11, text: "And they came unto her, and she said unto them, Hear me now, O ye governors of the inhabitants of Bethulia: for your words that ye have spoken before the people this day are not right, touching this oath which ye made and pronounced between God and you, and have promised to deliver the city to our enemies, unless within these days the Lord turn to help you." },
  { book: "Judith", chapter: 8, verse: 12, text: "And now who are ye that have tempted God this day, and stand instead of God among the children of men?" },
  { book: "Judith", chapter: 8, verse: 13, text: "And now try the Lord Almighty, but ye shall never know any thing." },
  { book: "Judith", chapter: 8, verse: 14, text: "For ye cannot find the depth of the heart of man, neither can ye perceive the things that he thinketh: then how can ye search out God, that hath made all these things, and know his mind, or comprehend his purpose? Nay, my brethren, provoke not the Lord our God to anger." },
  { book: "Judith", chapter: 8, verse: 15, text: "For if he will not help us within these five days, he hath power to defend us when he will, even every day, or to destroy us before our enemies." },
  { book: "Judith", chapter: 8, verse: 16, text: "Do not bind the counsels of the Lord our God: for God is not as man, that he may be threatened; neither is he as the son of man, that he should be wavering." },
  { book: "Judith", chapter: 8, verse: 17, text: "Therefore let us wait for salvation of him, and call upon him to help us, and he will hear our voice, if it please him." },
  { book: "Judith", chapter: 8, verse: 18, text: "For there arose none in our age, neither is there any now in these days neither tribe, nor family, nor people, nor city among us, which worship gods made with hands, as hath been aforetime." },
  { book: "Judith", chapter: 8, verse: 19, text: "For the which cause our fathers were given to the sword, and for a spoil, and had a great fall before our enemies." },
  { book: "Judith", chapter: 8, verse: 20, text: "But we know none other god, therefore we trust that he will not despise us, nor any of our nation." },
  { book: "Judith", chapter: 8, verse: 21, text: "For if we be taken so, all Judea shall lie waste, and our sanctuary shall be spoiled; and he will require the profanation thereof at our mouth." },
  { book: "Judith", chapter: 8, verse: 22, text: "And the slaughter of our brethren, and the captivity of the country, and the desolation of our inheritance, will he turn upon our heads among the Gentiles, wheresoever we shall be in bondage; and we shall be an offence and a reproach to all them that possess us." },
  { book: "Judith", chapter: 8, verse: 23, text: "For our servitude shall not be directed to favour: but the Lord our God shall turn it to dishonour." },
  { book: "Judith", chapter: 8, verse: 24, text: "Now therefore, O brethren, let us shew an example to our brethren, because their hearts depend upon us, and the sanctuary, and the house, and the altar, rest upon us." },
  { book: "Judith", chapter: 8, verse: 25, text: "Moreover let us give thanks to the Lord our God, which trieth us, even as he did our fathers." },
  { book: "Judith", chapter: 8, verse: 26, text: "Remember what things he did to Abraham, and how he tried Isaac, and what happened to Jacob in Mesopotamia of Syria, when he kept the sheep of Laban his mother’s brother." },
  { book: "Judith", chapter: 8, verse: 27, text: "For he hath not tried us in the fire, as he did them, for the examination of their hearts, neither hath he taken vengeance on us: but the Lord doth scourge them that come near unto him, to admonish them." },
  { book: "Judith", chapter: 8, verse: 28, text: "Then said Ozias to her, All that thou hast spoken hast thou spoken with a good heart, and there is none that may gainsay thy words." },
  { book: "Judith", chapter: 8, verse: 29, text: "For this is not the first day wherein thy wisdom is manifested; but from the beginning of thy days all the people have known thy understanding, because the disposition of thine heart is good." },
  { book: "Judith", chapter: 8, verse: 30, text: "But the people were very thirsty, and compelled us to do unto them as we have spoken, and to bring an oath upon ourselves, which we will not break." },
  { book: "Judith", chapter: 8, verse: 31, text: "Therefore now pray thou for us, because thou art a godly woman, and the Lord will send us rain to fill our cisterns, and we shall faint no more." },
  { book: "Judith", chapter: 8, verse: 32, text: "Then said Judith unto them, Hear me, and I will do a thing, which shall go throughout all generations to the children of our nation." },
  { book: "Judith", chapter: 8, verse: 33, text: "Ye shall stand this night in the gate, and I will go forth with my waitingwoman: and within the days that ye have promised to deliver the city to our enemies the Lord will visit Israel by mine hand." },
  { book: "Judith", chapter: 8, verse: 34, text: "But enquire not ye of mine act: for I will not declare it unto you, till the things be finished that I do." },
  { book: "Judith", chapter: 8, verse: 35, text: "Then said Ozias and the princes unto her, Go in peace, and the Lord God be before thee, to take vengeance on our enemies." },
  { book: "Judith", chapter: 8, verse: 36, text: "So they returned from the tent, and went to their wards." },
  { book: "Judith", chapter: 9, verse: 1, text: "Judith fell upon her face, and put ashes upon her head, and uncovered the sackcloth wherewith she was clothed; and about the time that the incense of that evening was offered in Jerusalem in the house of the Lord Judith cried with a loud voice, and said," },
  { book: "Judith", chapter: 9, verse: 2, text: "O Lord God of my father Simeon, to whom thou gavest a sword to take vengeance of the strangers, who loosened the girdle of a maid to defile her, and discovered the thigh to her shame, and polluted her virginity to her reproach; for thou saidst, It shall not be so; and yet they did so:" },
  { book: "Judith", chapter: 9, verse: 3, text: "Wherefore thou gavest their rulers to be slain, so that they dyed their bed in blood, being deceived, and smotest the servants with their lords, and the lords upon their thrones;" },
  { book: "Judith", chapter: 9, verse: 4, text: "And hast given their wives for a prey, and their daughters to be captives, and all their spoils to be divided among thy dear children; which were moved with thy zeal, and abhorred the pollution of their blood, and called upon thee for aid: O God, O my God, hear me also a widow." },
  { book: "Judith", chapter: 9, verse: 5, text: "For thou hast wrought not only those things, but also the things which fell out before, and which ensued after; thou hast thought upon the things which are now, and which are to come." },
  { book: "Judith", chapter: 9, verse: 6, text: "Yea, what things thou didst determine were ready at hand, and said, Lo, we are here: for all thy ways are prepared, and thy judgments are in thy foreknowledge." },
  { book: "Judith", chapter: 9, verse: 7, text: "For, behold, the Assyrians are multiplied in their power; they are exalted with horse and man; they glory in the strength of their footmen; they trust in shield, and spear, and bow, and sling; and know not that thou art the Lord that breakest the battles: the Lord is thy name." },
  { book: "Judith", chapter: 9, verse: 8, text: "Throw down their strength in thy power, and bring down their force in thy wrath: for they have purposed to defile thy sanctuary, and to pollute the tabernacle where thy glorious name resteth and to cast down with sword the horn of thy altar." },
  { book: "Judith", chapter: 9, verse: 9, text: "Behold their pride, and send thy wrath upon their heads: give into mine hand, which am a widow, the power that I have conceived." },
  { book: "Judith", chapter: 9, verse: 10, text: "Smite by the deceit of my lips the servant with the prince, and the prince with the servant: break down their stateliness by the hand of a woman." },
  { book: "Judith", chapter: 9, verse: 11, text: "For thy power standeth not in multitude nor thy might in strong men: for thou art a God of the afflicted, an helper of the oppressed, an upholder of the weak, a protector of the forlorn, a saviour of them that are without hope." },
  { book: "Judith", chapter: 9, verse: 12, text: "I pray thee, I pray thee, O God of my father, and God of the inheritance of Israel, Lord of the heavens and earth, Creator of the waters, king of every creature, hear thou my prayer:" },
  { book: "Judith", chapter: 9, verse: 13, text: "And make my speech and deceit to be their wound and stripe, who have purposed cruel things against thy covenant, and thy hallowed house, and against the top of Sion, and against the house of the possession of thy children." },
  { book: "Judith", chapter: 9, verse: 14, text: "And make every nation and tribe to acknowledge that thou art the God of all power and might, and that there is none other that protecteth the people of Israel but thou." },
  { book: "Judith", chapter: 10, verse: 1, text: "Now after that she had ceased to cry unto the God of Israel, and had made an end of all these words." },
  { book: "Judith", chapter: 10, verse: 2, text: "She rose where she had fallen down, and called her maid, and went down into the house in the which she abode in the sabbath days, and in her feast days," },
  { book: "Judith", chapter: 10, verse: 3, text: "And pulled off the sackcloth which she had on, and put off the garments of her widowhood, and washed her body all over with water, and anointed herself with precious ointment, and braided the hair of her head, and put on a tire upon it, and put on her garments of gladness, wherewith she was clad during the life of Manasses her husband." },
  { book: "Judith", chapter: 10, verse: 4, text: "And she took sandals upon her feet, and put about her her bracelets, and her chains, and her rings, and her earrings, and all her ornaments, and decked herself bravely, to allure the eyes of all men that should see her." },
  { book: "Judith", chapter: 10, verse: 5, text: "Then she gave her maid a bottle of wine, and a cruse of oil, and filled a bag with parched corn, and lumps of figs, and with fine bread; so she folded all these things together, and laid them upon her." },
  { book: "Judith", chapter: 10, verse: 6, text: "Thus they went forth to the gate of the city of Bethulia, and found standing there Ozias and the ancients of the city, Chabris and Charmis." },
  { book: "Judith", chapter: 10, verse: 7, text: "And when they saw her, that her countenance was altered, and her apparel was changed, they wondered at her beauty very greatly, and said unto her." },
  { book: "Judith", chapter: 10, verse: 8, text: "The God, the God of our fathers give thee favour, and accomplish thine enterprizes to the glory of the children of Israel, and to the exaltation of Jerusalem. Then they worshipped God." },
  { book: "Judith", chapter: 10, verse: 9, text: "And she said unto them, Command the gates of the city to be opened unto me, that I may go forth to accomplish the things whereof ye have spoken with me. So they commanded the young men to open unto her, as she had spoken." },
  { book: "Judith", chapter: 10, verse: 10, text: "And when they had done so, Judith went out, she, and her maid with her; and the men of the city looked after her, until she was gone down the mountain, and till she had passed the valley, and could see her no more." },
  { book: "Judith", chapter: 10, verse: 11, text: "Thus they went straight forth in the valley: and the first watch of the Assyrians met her," },
  { book: "Judith", chapter: 10, verse: 12, text: "And took her, and asked her, Of what people art thou? and whence comest thou? and whither goest thou? And she said, I am a woman of the Hebrews, and am fled from them: for they shall be given you to be consumed:" },
  { book: "Judith", chapter: 10, verse: 13, text: "And I am coming before Holofernes the chief captain of your army, to declare words of truth; and I will shew him a way, whereby he shall go, and win all the hill country, without losing the body or life of any one of his men." },
  { book: "Judith", chapter: 10, verse: 14, text: "Now when the men heard her words, and beheld her countenance, they wondered greatly at her beauty, and said unto her," },
  { book: "Judith", chapter: 10, verse: 15, text: "Thou hast saved thy life, in that thou hast hasted to come down to the presence of our lord: now therefore come to his tent, and some of us shall conduct thee, until they have delivered thee to his hands." },
  { book: "Judith", chapter: 10, verse: 16, text: "And when thou standest before him, be not afraid in thine heart, but shew unto him according to thy word; and he will entreat thee well." },
  { book: "Judith", chapter: 10, verse: 17, text: "Then they chose out of them an hundred men to accompany her and her maid; and they brought her to the tent of Holofernes." },
  { book: "Judith", chapter: 10, verse: 18, text: "Then was there a concourse throughout all the camp: for her coming was noised among the tents, and they came about her, as she stood without the tent of Holofernes, till they told him of her." },
  { book: "Judith", chapter: 10, verse: 19, text: "And they wondered at her beauty, and admired the children of Israel because of her, and every one said to his neighbour, Who would despise this people, that have among them such women? surely it is not good that one man of them be left who being let go might deceive the whole earth." },
  { book: "Judith", chapter: 10, verse: 20, text: "And they that lay near Holofernes went out, and all his servants and they brought her into the tent." },
  { book: "Judith", chapter: 10, verse: 21, text: "Now Holofernes rested upon his bed under a canopy, which was woven with purple, and gold, and emeralds, and precious stones." },
  { book: "Judith", chapter: 10, verse: 22, text: "So they shewed him of her; and he came out before his tent with silver lamps going before him." },
  { book: "Judith", chapter: 10, verse: 23, text: "And when Judith was come before him and his servants they all marvelled at the beauty of her countenance; and she fell down upon her face, and did reverence unto him: and his servants took her up." },
  { book: "Judith", chapter: 11, verse: 1, text: "Then said Holofernes unto her, Woman, be of good comfort, fear not in thine heart: for I never hurt any that was willing to serve Nabuchodonosor, the king of all the earth." },
  { book: "Judith", chapter: 11, verse: 2, text: "Now therefore, if thy people that dwelleth in the mountains had not set light by me, I would not have lifted up my spear against them: but they have done these things to themselves." },
  { book: "Judith", chapter: 11, verse: 3, text: "But now tell me wherefore thou art fled from them, and art come unto us: for thou art come for safeguard; be of good comfort, thou shalt live this night, and hereafter:" },
  { book: "Judith", chapter: 11, verse: 4, text: "For none shall hurt thee, but entreat thee well, as they do the servants of king Nabuchodonosor my lord." },
  { book: "Judith", chapter: 11, verse: 5, text: "Then Judith said unto him, Receive the words of thy servant, and suffer thine handmaid to speak in thy presence, and I will declare no lie to my lord this night." },
  { book: "Judith", chapter: 11, verse: 6, text: "And if thou wilt follow the words of thine handmaid, God will bring the thing perfectly to pass by thee; and my lord shall not fail of his purposes." },
  { book: "Judith", chapter: 11, verse: 7, text: "As Nabuchodonosor king of all the earth liveth, and as his power liveth, who hath sent thee for the upholding of every living thing: for not only men shall serve him by thee, but also the beasts of the field, and the cattle, and the fowls of the air, shall live by thy power under Nabuchodonosor and all his house." },
  { book: "Judith", chapter: 11, verse: 8, text: "For we have heard of thy wisdom and thy policies, and it is reported in all the earth, that thou only art excellent in all the kingdom, and mighty in knowledge, and wonderful in feats of war." },
  { book: "Judith", chapter: 11, verse: 9, text: "Now as concerning the matter, which Achior did speak in thy council, we have heard his words; for the men of Bethulia saved him, and he declared unto them all that he had spoken unto thee." },
  { book: "Judith", chapter: 11, verse: 10, text: "Therefore, O lord and governor, respect not his word; but lay it up in thine heart, for it is true: for our nation shall not be punished, neither can sword prevail against them, except they sin against their God." },
  { book: "Judith", chapter: 11, verse: 11, text: "And now, that my lord be not defeated and frustrate of his purpose, even death is now fallen upon them, and their sin hath overtaken them, wherewith they will provoke their God to anger whensoever they shall do that which is not fit to be done:" },
  { book: "Judith", chapter: 11, verse: 12, text: "For their victuals fail them, and all their water is scant, and they have determined to lay hands upon their cattle, and purposed to consume all those things, that God hath forbidden them to eat by his laws:" },
  { book: "Judith", chapter: 11, verse: 13, text: "And are resolved to spend the firstfruits of the the tenths of wine and oil, which they had sanctified, and reserved for the priests that serve in Jerusalem before the face of our God; the which things it is not lawful for any of the people so much as to touch with their hands." },
  { book: "Judith", chapter: 11, verse: 14, text: "For they have sent some to Jerusalem, because they also that dwell there have done the like, to bring them a licence from the senate." },
  { book: "Judith", chapter: 11, verse: 15, text: "Now when they shall bring them word, they will forthwith do it, and they shall be given to thee to be destroyed the same day." },
  { book: "Judith", chapter: 11, verse: 16, text: "Wherefore I thine handmaid, knowing all this, am fled from their presence; and God hath sent me to work things with thee, whereat all the earth shall be astonished, and whosoever shall hear it." },
  { book: "Judith", chapter: 11, verse: 17, text: "For thy servant is religious, and serveth the God of heaven day and night: now therefore, my lord, I will remain with thee, and thy servant will go out by night into the valley, and I will pray unto God, and he will tell me when they have committed their sins:" },
  { book: "Judith", chapter: 11, verse: 18, text: "And I will come and shew it unto thee: then thou shalt go forth with all thine army, and there shall be none of them that shall resist thee." },
  { book: "Judith", chapter: 11, verse: 19, text: "And I will lead thee through the midst of Judea, until thou come before Jerusalem; and I will set thy throne in the midst thereof; and thou shalt drive them as sheep that have no shepherd, and a dog shall not so much as open his mouth at thee: for these things were told me according to my foreknowledge, and they were declared unto me, and I am sent to tell thee." },
  { book: "Judith", chapter: 11, verse: 20, text: "Then her words pleased Holofernes and all his servants; and they marvelled at her wisdom, and said," },
  { book: "Judith", chapter: 11, verse: 21, text: "There is not such a woman from one end of the earth to the other, both for beauty of face, and wisdom of words." },
  { book: "Judith", chapter: 11, verse: 22, text: "Likewise Holofernes said unto her. God hath done well to send thee before the people, that strength might be in our hands and destruction upon them that lightly regard my lord." },
  { book: "Judith", chapter: 11, verse: 23, text: "And now thou art both beautiful in thy countenance, and witty in thy words: surely if thou do as thou hast spoken thy God shall be my God, and thou shalt dwell in the house of king Nabuchodonosor, and shalt be renowned through the whole earth." },
  { book: "Judith", chapter: 12, verse: 1, text: "Then he commanded to bring her in where his plate was set; and bade that they should prepare for her of his own meats, and that she should drink of his own wine." },
  { book: "Judith", chapter: 12, verse: 2, text: "And Judith said, I will not eat thereof, lest there be an offence: but provision shall be made for me of the things that I have brought." },
  { book: "Judith", chapter: 12, verse: 3, text: "Then Holofernes said unto her, If thy provision should fail, how should we give thee the like? for there be none with us of thy nation." },
  { book: "Judith", chapter: 12, verse: 4, text: "Then said Judith unto him As thy soul liveth, my lord, thine handmaid shall not spend those things that I have, before the Lord work by mine hand the things that he hath determined." },
  { book: "Judith", chapter: 12, verse: 5, text: "Then the servants of Holofernes brought her into the tent, and she slept till midnight, and she arose when it was toward the morning watch," },
  { book: "Judith", chapter: 12, verse: 6, text: "And sent to Holofernes, saving, Let my lord now command that thine handmaid may go forth unto prayer." },
  { book: "Judith", chapter: 12, verse: 7, text: "Then Holofernes commanded his guard that they should not stay her: thus she abode in the camp three days, and went out in the night into the valley of Bethulia, and washed herself in a fountain of water by the camp." },
  { book: "Judith", chapter: 12, verse: 8, text: "And when she came out, she besought the Lord God of Israel to direct her way to the raising up of the children of her people." },
  { book: "Judith", chapter: 12, verse: 9, text: "So she came in clean, and remained in the tent, until she did eat her meat at evening." },
  { book: "Judith", chapter: 12, verse: 10, text: "And in the fourth day Holofernes made a feast to his own servants only, and called none of the officers to the banquet." },
  { book: "Judith", chapter: 12, verse: 11, text: "Then said he to Bagoas the eunuch, who had charge over all that he had, Go now, and persuade this Hebrew woman which is with thee, that she come unto us, and eat and drink with us." },
  { book: "Judith", chapter: 12, verse: 12, text: "For, lo, it will be a shame for our person, if we shall let such a woman go, not having had her company; for if we draw her not unto us, she will laugh us to scorn." },
  { book: "Judith", chapter: 12, verse: 13, text: "Then went Bagoas from the presence of Holofernes, and came to her, and he said, Let not this fair damsel fear to come to my lord, and to be honoured in his presence, and drink wine, and be merry with us and be made this day as one of the daughters of the Assyrians, which serve in the house of Nabuchodonosor." },
  { book: "Judith", chapter: 12, verse: 14, text: "Then said Judith unto him, Who am I now, that I should gainsay my lord? surely whatsoever pleaseth him I will do speedily, and it shall be my joy unto the day of my death." },
  { book: "Judith", chapter: 12, verse: 15, text: "So she arose, and decked herself with her apparel and all her woman’s attire, and her maid went and laid soft skins on the ground for her over against Holofernes, which she had received of Bagoas far her daily use, that she might sit and eat upon them." },
  { book: "Judith", chapter: 12, verse: 16, text: "Now when Judith came in and sat down, Holofernes his heart was ravished with her, and his mind was moved, and he desired greatly her company; for he waited a time to deceive her, from the day that he had seen her." },
  { book: "Judith", chapter: 12, verse: 17, text: "Then said Holofernes unto her, Drink now, and be merry with us." },
  { book: "Judith", chapter: 12, verse: 18, text: "So Judith said, I will drink now, my lord, because my life is magnified in me this day more than all the days since I was born." },
  { book: "Judith", chapter: 12, verse: 19, text: "Then she took and ate and drank before him what her maid had prepared." },
  { book: "Judith", chapter: 12, verse: 20, text: "And Holofernes took great delight in her, and drank more wine than he had drunk at any time in one day since he was born." },
  { book: "Judith", chapter: 13, verse: 1, text: "Now when the evening was come, his servants made haste to depart, and Bagoas shut his tent without, and dismissed the waiters from the presence of his lord; and they went to their beds: for they were all weary, because the feast had been long." },
  { book: "Judith", chapter: 13, verse: 2, text: "And Judith was left along in the tent, and Holofernes lying along upon his bed: for he was filled with wine." },
  { book: "Judith", chapter: 13, verse: 3, text: "Now Judith had commanded her maid to stand without her bedchamber, and to wait for her. coming forth, as she did daily: for she said she would go forth to her prayers, and she spake to Bagoas according to the same purpose." },
  { book: "Judith", chapter: 13, verse: 4, text: "So all went forth and none was left in the bedchamber, neither little nor great. Then Judith, standing by his bed, said in her heart, O Lord God of all power, look at this present upon the works of mine hands for the exaltation of Jerusalem." },
  { book: "Judith", chapter: 13, verse: 5, text: "For now is the time to help thine inheritance, and to execute thine enterprizes to the destruction of the enemies which are risen against us." },
  { book: "Judith", chapter: 13, verse: 6, text: "Then she came to the pillar of the bed, which was at Holofernes’ head, and took down his fauchion from thence," },
  { book: "Judith", chapter: 13, verse: 7, text: "And approached to his bed, and took hold of the hair of his head, and said, Strengthen me, O Lord God of Israel, this day." },
  { book: "Judith", chapter: 13, verse: 8, text: "And she smote twice upon his neck with all her might, and she took away his head from him." },
  { book: "Judith", chapter: 13, verse: 9, text: "And tumbled his body down from the bed, and pulled down the canopy from the pillars; and anon after she went forth, and gave Holofernes his head to her maid;" },
  { book: "Judith", chapter: 13, verse: 10, text: "And she put it in her bag of meat: so they twain went together according to their custom unto prayer: and when they passed the camp, they compassed the valley, and went up the mountain of Bethulia, and came to the gates thereof." },
  { book: "Judith", chapter: 13, verse: 11, text: "Then said Judith afar off, to the watchmen at the gate, Open, open now the gate: God, even our God, is with us, to shew his power yet in Jerusalem, and his forces against the enemy, as he hath even done this day." },
  { book: "Judith", chapter: 13, verse: 12, text: "Now when the men of her city heard her voice, they made haste to go down to the gate of their city, and they called the elders of the city." },
  { book: "Judith", chapter: 13, verse: 13, text: "And then they ran all together, both small and great, for it was strange unto them that she was come: so they opened the gate, and received them, and made a fire for a light, and stood round about them." },
  { book: "Judith", chapter: 13, verse: 14, text: "Then she said to them with a loud voice, Praise, praise God, praise God, I say, for he hath not taken away his mercy from the house of Israel, but hath destroyed our enemies by mine hands this night." },
  { book: "Judith", chapter: 13, verse: 15, text: "So she took the head out of the bag, and shewed it, and said unto them, behold the head of Holofernes, the chief captain of the army of Assur, and behold the canopy, wherein he did lie in his drunkenness; and the Lord hath smitten him by the hand of a woman." },
  { book: "Judith", chapter: 13, verse: 16, text: "As the Lord liveth, who hath kept me in my way that I went, my countenance hath deceived him to his destruction, and yet hath he not committed sin with me, to defile and shame me." },
  { book: "Judith", chapter: 13, verse: 17, text: "Then all the people were wonderfully astonished, and bowed themselves and worshipped God, and said with one accord, Blessed be thou, O our God, which hast this day brought to nought the enemies of thy people." },
  { book: "Judith", chapter: 13, verse: 18, text: "Then said Ozias unto her, O daughter, blessed art thou of the most high God above all the women upon the earth; and blessed be the Lord God, which hath created the heavens and the earth, which hath directed thee to the cutting off of the head of the chief of our enemies." },
  { book: "Judith", chapter: 13, verse: 19, text: "For this thy confidence shall not depart from the heart of men, which remember the power of God for ever." },
  { book: "Judith", chapter: 13, verse: 20, text: "And God turn these things to thee for a perpetual praise, to visit thee in good things because thou hast not spared thy life for the affliction of our nation, but hast revenged our ruin, walking a straight way before our God. And all the people said; So be it, so be it." },
  { book: "Judith", chapter: 14, verse: 1, text: "Then said Judith unto them, Hear me now, my brethren, and take this head, and hang it upon the highest place of your walls." },
  { book: "Judith", chapter: 14, verse: 2, text: "And so soon as the morning shall appear, and the sun shall come forth upon the earth, take ye every one his weapons, and go forth every valiant man out of the city, and set ye a captain over them, as though ye would go down into the field toward the watch of the Assyrians; but go not down." },
  { book: "Judith", chapter: 14, verse: 3, text: "Then they shall take their armour, and shall go into their camp, and raise up the captains of the army of Assur, and shall run to the tent of Holofernes, but shall not find him: then fear shall fall upon them, and they shall flee before your face." },
  { book: "Judith", chapter: 14, verse: 4, text: "So ye, and all that inhabit the coast of Israel, shall pursue them, and overthrow them as they go." },
  { book: "Judith", chapter: 14, verse: 5, text: "But before ye do these things, call me Achior the Ammonite, that he may see and know him that despised the house of Israel, and that sent him to us as it were to his death." },
  { book: "Judith", chapter: 14, verse: 6, text: "Then they called Achior out of the house of Ozias; and when he was come, and saw the head of Holofernes in a man’s hand in the assembly of the people, he fell down on his face, and his spirit failed." },
  { book: "Judith", chapter: 14, verse: 7, text: "But when they had recovered him, he fell at Judith’s feet, and reverenced her, and said, Blessed art thou in all the tabernacles of Juda, and in all nations, which hearing thy name shall be astonished." },
  { book: "Judith", chapter: 14, verse: 8, text: "Now therefore tell me all the things that thou hast done in these days. Then Judith declared unto him in the midst of the people all that she had done, from the day that she went forth until that hour she spake unto them." },
  { book: "Judith", chapter: 14, verse: 9, text: "And when she had left off speaking, the people shouted with a loud voice, and made a joyful noise in their city." },
  { book: "Judith", chapter: 14, verse: 10, text: "And when Achior had seen all that the God of Israel had done, he believed in God greatly, and circumcised the flesh of his foreskin, and was joined unto the house of Israel unto this day." },
  { book: "Judith", chapter: 14, verse: 11, text: "And as soon as the morning arose, they hanged the head of Holofernes upon the wall, and every man took his weapons, and they went forth by bands unto the straits of the mountain." },
  { book: "Judith", chapter: 14, verse: 12, text: "But when the Assyrians saw them, they sent to their leaders, which came to their captains and tribunes, and to every one of their rulers." },
  { book: "Judith", chapter: 14, verse: 13, text: "So they came to Holofernes’ tent, and said to him that had the charge of all his things, Waken now our lord: for the slaves have been bold to come down against us to battle, that they may be utterly destroyed." },
  { book: "Judith", chapter: 14, verse: 14, text: "Then went in Bagoas, and knocked at the door of the tent; for he thought that he had slept with Judith." },
  { book: "Judith", chapter: 14, verse: 15, text: "But because none answered, he opened it, and went into the bedchamber, and found him cast upon the floor dead, and his head was taken from him." },
  { book: "Judith", chapter: 14, verse: 16, text: "Therefore he cried with a loud voice, with weeping, and sighing, and a mighty cry, and rent his garments." },
  { book: "Judith", chapter: 14, verse: 17, text: "After he went into the tent where Judith lodged: and when he found her not, he leaped out to the people, and cried," },
  { book: "Judith", chapter: 14, verse: 18, text: "These slaves have dealt treacherously; one woman of the Hebrews hath brought shame upon the house of king Nabuchodonosor: for, behold, Holofernes lieth upon the ground without a head." },
  { book: "Judith", chapter: 14, verse: 19, text: "When the captains of the Assyrians’ army heard these words, they rent their coats and their minds were wonderfully troubled, and there was a cry and a very great noise throughout the camp." },
  { book: "Judith", chapter: 15, verse: 1, text: "And when they that were in the tents heard, they were astonished at the thing that was done." },
  { book: "Judith", chapter: 15, verse: 2, text: "And fear and trembling fell upon them, so that there was no man that durst abide in the sight of his neighbour, but rushing out all together, they fled into every way of the plain, and of the hill country." },
  { book: "Judith", chapter: 15, verse: 3, text: "They also that had camped in the mountains round about Bethulia fled away. Then the children of Israel, every one that was a warrior among them, rushed out upon them." },
  { book: "Judith", chapter: 15, verse: 4, text: "Then sent Ozias to Betomasthem, and to Bebai, and Chobai, and Cola and to all the coasts of Israel, such as should tell the things that were done, and that all should rush forth upon their enemies to destroy them." },
  { book: "Judith", chapter: 15, verse: 5, text: "Now when the children of Israel heard it, they all fell upon them with one consent, and slew them unto Chobai: likewise also they that came from Jerusalem, and from all the hill country, (for men had told them what things were done in the camp of their enemies) and they that were in Galaad, and in Galilee, chased them with a great slaughter, until they were past Damascus and the borders thereof." },
  { book: "Judith", chapter: 15, verse: 6, text: "And the residue that dwelt at Bethulia, fell upon the camp of Assur, and spoiled them, and were greatly enriched." },
  { book: "Judith", chapter: 15, verse: 7, text: "And the children of Israel that returned from the slaughter had that which remained; and the villages and the cities, that were in the mountains and in the plain, gat many spoils: for the multitude was very great." },
  { book: "Judith", chapter: 15, verse: 8, text: "Then Joacim the high priest, and the ancients of the children of Israel that dwelt in Jerusalem, came to behold the good things that God had shewed to Israel, and to see Judith, and to salute her." },
  { book: "Judith", chapter: 15, verse: 9, text: "And when they came unto her, they blessed her with one accord, and said unto her, Thou art the exaltation of Jerusalem, thou art the great glory of Israel, thou art the great rejoicing of our nation:" },
  { book: "Judith", chapter: 15, verse: 10, text: "Thou hast done all these things by thine hand: thou hast done much good to Israel, and God is pleased therewith: blessed be thou of the Almighty Lord for evermore. And all the people said, So be it." },
  { book: "Judith", chapter: 15, verse: 11, text: "And the people spoiled the camp the space of thirty days: and they gave unto Judith Holofernes his tent, and all his plate, and beds, and vessels, and all his stuff: and she took it and laid it on her mule; and made ready her carts, and laid them thereon." },
  { book: "Judith", chapter: 15, verse: 12, text: "Then all the women of Israel ran together to see her, and blessed her, and made a dance among them for her: and she took branches in her hand, and gave also to the women that were with her." },
  { book: "Judith", chapter: 15, verse: 13, text: "And they put a garland of olive upon her and her maid that was with her, and she went before all the people in the dance, leading all the women: and all the men of Israel followed in their armour with garlands, and with songs in their mouths." },
  { book: "Judith", chapter: 16, verse: 1, text: "Then Judith began to sing this thanksgiving in all Israel, and all the people sang after her this song of praise." },
  { book: "Judith", chapter: 16, verse: 2, text: "And Judith said, Begin unto my God with timbrels, sing unto my Lord with cymbals: tune unto him a new psalm: exalt him, and call upon his name." },
  { book: "Judith", chapter: 16, verse: 3, text: "For God breaketh the battles: for among the camps in the midst of the people he hath delivered me out of the hands of them that persecuted me." },
  { book: "Judith", chapter: 16, verse: 4, text: "Assur came out of the mountains from the north, he came with ten thousands of his army, the multitude whereof stopped the torrents, and their horsemen have covered the hills." },
  { book: "Judith", chapter: 16, verse: 5, text: "He bragged that he would burn up my borders, and kill my young men with the sword, and dash the sucking children against the ground, and make mine infants as a prey, and my virgins as a spoil." },
  { book: "Judith", chapter: 16, verse: 6, text: "But the Almighty Lord hath disappointed them by the hand of a woman." },
  { book: "Judith", chapter: 16, verse: 7, text: "For the mighty one did not fall by the young men, neither did the sons of the Titans smite him, nor high giants set upon him: but Judith the daughter of Merari weakened him with the beauty of her countenance." },
  { book: "Judith", chapter: 16, verse: 8, text: "For she put off the garment of her widowhood for the exaltation of those that were oppressed in Israel, and anointed her face with ointment, and bound her hair in a tire, and took a linen garment to deceive him." },
  { book: "Judith", chapter: 16, verse: 9, text: "Her sandals ravished his eyes, her beauty took his mind prisoner, and the fauchion passed through his neck." },
  { book: "Judith", chapter: 16, verse: 10, text: "The Persians quaked at her boldness, and the Medes were daunted at her hardiness." },
  { book: "Judith", chapter: 16, verse: 11, text: "Then my afflicted shouted for joy, and my weak ones cried aloud; but they were astonished: these lifted up their voices, but they were overthrown." },
  { book: "Judith", chapter: 16, verse: 12, text: "The sons of the damsels have pierced them through, and wounded them as fugitives’ children: they perished by the battle of the Lord." },
  { book: "Judith", chapter: 16, verse: 13, text: "I will sing unto the Lord a new song: O Lord, thou art great and glorious, wonderful in strength, and invincible." },
  { book: "Judith", chapter: 16, verse: 14, text: "Let all creatures serve thee: for thou spakest, and they were made, thou didst send forth thy spirit, and it created them, and there is none that can resist thy voice." },
  { book: "Judith", chapter: 16, verse: 15, text: "For the mountains shall be moved from their foundations with the waters, the rocks shall melt as wax at thy presence: yet thou art merciful to them that fear thee." },
  { book: "Judith", chapter: 16, verse: 16, text: "For all sacrifice is too little for a sweet savour unto thee, and all the fat is not sufficient for thy burnt offering: but he that feareth the Lord is great at all times." },
  { book: "Judith", chapter: 16, verse: 17, text: "Woe to the nations that rise up against my kindred! the Lord Almighty will take vengeance of them in the day of judgment, in putting fire and worms in their flesh; and they shall feel them, and weep for ever." },
  { book: "Judith", chapter: 16, verse: 18, text: "Now as soon as they entered into Jerusalem, they worshipped the Lord; and as soon as the people were purified, they offered their burnt offerings, and their free offerings, and their gifts." },
  { book: "Judith", chapter: 16, verse: 19, text: "Judith also dedicated all the stuff of Holofernes, which the people had given her, and gave the canopy, which she had taken out of his bedchamber, for a gift unto the Lord." },
  { book: "Judith", chapter: 16, verse: 20, text: "So the people continued feasting in Jerusalem before the sanctuary for the space of three months and Judith remained with them." },
  { book: "Judith", chapter: 16, verse: 21, text: "After this time every one returned to his own inheritance, and Judith went to Bethulia, and remained in her own possession, and was in her time honourable in all the country." },
  { book: "Judith", chapter: 16, verse: 22, text: "And many desired her, but none knew her all the days of her life, after that Manasses her husband was dead, and was gathered to his people." },
  { book: "Judith", chapter: 16, verse: 23, text: "But she increased more and more in honour, and waxed old in her husband’s house, being an hundred and five years old, and made her maid free; so she died in Bethulia: and they buried her in the cave of her husband Manasses." },
  { book: "Judith", chapter: 16, verse: 24, text: "And the house of Israel lamented her seven days: and before she died, she did distribute her goods to all them that were nearest of kindred to Manasses her husband, and to them that were the nearest of her kindred." },
  { book: "Judith", chapter: 16, verse: 25, text: "And there was none that made the children of Israel any more afraid in the days of Judith, nor a long time after her death." },
  // Prayer of Azariah (68 verses)
  { book: "Prayer of Azariah", chapter: 1, verse: 1, text: "And they walked in the midst of the fire, praising God, and blessing the Lord." },
  { book: "Prayer of Azariah", chapter: 1, verse: 2, text: "Then Azarias stood up, and prayed on this manner; and opening his mouth in the midst of the fire said," },
  { book: "Prayer of Azariah", chapter: 1, verse: 3, text: "Blessed art thou, O Lord God of our fathers: thy name is worthy to be praised and glorified for evermore:" },
  { book: "Prayer of Azariah", chapter: 1, verse: 4, text: "For thou art righteous in all the things that thou hast done to us: yea, true are all thy works, thy ways are right, and all thy judgments truth." },
  { book: "Prayer of Azariah", chapter: 1, verse: 5, text: "In all the things that thou hast brought upon us, and upon the holy city of our fathers, even Jerusalem, thou hast executed true judgment: for according to truth and judgment didst thou bring all these things upon us because of our sins." },
  { book: "Prayer of Azariah", chapter: 1, verse: 6, text: "For we have sinned and committed iniquity, departing from thee." },
  { book: "Prayer of Azariah", chapter: 1, verse: 7, text: "In all things have we trespassed, and not obeyed thy commandments, nor kept them, neither done as thou hast commanded us, that it might go well with us." },
  { book: "Prayer of Azariah", chapter: 1, verse: 8, text: "Wherefore all that thou hast brought upon us, and every thing that thou hast done to us, thou hast done in true judgment." },
  { book: "Prayer of Azariah", chapter: 1, verse: 9, text: "And thou didst deliver us into the hands of lawless enemies, most hateful forsakers of God, and to an unjust king, and the most wicked in all the world." },
  { book: "Prayer of Azariah", chapter: 1, verse: 10, text: "And now we cannot open our mouths, we are become a shame and reproach to thy servants; and to them that worship thee." },
  { book: "Prayer of Azariah", chapter: 1, verse: 11, text: "Yet deliver us not up wholly, for thy name’s sake, neither disannul thou thy covenant:" },
  { book: "Prayer of Azariah", chapter: 1, verse: 12, text: "And cause not thy mercy to depart from us, for thy beloved Abraham’s sake, for thy servant Issac’s sake, and for thy holy Israel’s sake;" },
  { book: "Prayer of Azariah", chapter: 1, verse: 13, text: "To whom thou hast spoken and promised, that thou wouldest multiply their seed as the stars of heaven, and as the sand that lieth upon the seashore." },
  { book: "Prayer of Azariah", chapter: 1, verse: 14, text: "For we, O Lord, are become less than any nation, and be kept under this day in all the world because of our sins." },
  { book: "Prayer of Azariah", chapter: 1, verse: 15, text: "Neither is there at this time prince, or prophet, or leader, or burnt offering, or sacrifice, or oblation, or incense, or place to sacrifice before thee, and to find mercy." },
  { book: "Prayer of Azariah", chapter: 1, verse: 16, text: "Nevertheless in a contrite heart and an humble spirit let us be accepted." },
  { book: "Prayer of Azariah", chapter: 1, verse: 17, text: "Like as in the burnt offerings of rams and bullocks, and like as in ten thousands of fat lambs: so let our sacrifice be in thy sight this day, and grant that we may wholly go after thee: for they shall not be confounded that put their trust in thee." },
  { book: "Prayer of Azariah", chapter: 1, verse: 18, text: "And now we follow thee with all our heart, we fear thee, and seek thy face." },
  { book: "Prayer of Azariah", chapter: 1, verse: 19, text: "Put us not to shame: but deal with us after thy lovingkindness, and according to the multitude of thy mercies." },
  { book: "Prayer of Azariah", chapter: 1, verse: 20, text: "Deliver us also according to thy marvellous works, and give glory to thy name, O Lord: and let all them that do thy servants hurt be ashamed;" },
  { book: "Prayer of Azariah", chapter: 1, verse: 21, text: "And let them be confounded in all their power and might, and let their strength be broken;" },
  { book: "Prayer of Azariah", chapter: 1, verse: 22, text: "And let them know that thou art God, the only God, and glorious over the whole world." },
  { book: "Prayer of Azariah", chapter: 1, verse: 23, text: "And the king’s servants, that put them in, ceased not to make the oven hot with rosin, pitch, tow, and small wood;" },
  { book: "Prayer of Azariah", chapter: 1, verse: 24, text: "So that the flame streamed forth above the furnace forty and nine cubits." },
  { book: "Prayer of Azariah", chapter: 1, verse: 25, text: "And it passed through, and burned those Chaldeans it found about the furnace." },
  { book: "Prayer of Azariah", chapter: 1, verse: 26, text: "But the angel of the Lord came down into the oven together with Azarias and his fellows, and smote the flame of the fire out of the oven;" },
  { book: "Prayer of Azariah", chapter: 1, verse: 27, text: "And made the midst of the furnace as it had been a moist whistling wind, so that the fire touched them not at all, neither hurt nor troubled them." },
  { book: "Prayer of Azariah", chapter: 1, verse: 28, text: "Then the three, as out of one mouth, praised, glorified, and blessed, God in the furnace, saying," },
  { book: "Prayer of Azariah", chapter: 1, verse: 29, text: "Blessed art thou, O Lord God of our fathers: and to be praised and exalted above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 30, text: "And blessed is thy glorious and holy name: and to be praised and exalted above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 31, text: "Blessed art thou in the temple of thine holy glory: and to be praised and glorified above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 32, text: "Blessed art thou that beholdest the depths, and sittest upon the cherubims: and to be praised and exalted above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 33, text: "Blessed art thou on the glorious throne of thy kingdom: and to be praised and glorified above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 34, text: "Blessed art thou in the firmament of heaven: and above all to be praised and glorified for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 35, text: "O all ye works of the Lord, bless ye the Lord : praise and exalt him above all for ever," },
  { book: "Prayer of Azariah", chapter: 1, verse: 36, text: "O ye heavens, bless ye the Lord : praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 37, text: "O ye angels of the Lord, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 38, text: "O all ye waters that be above the heaven, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 39, text: "O all ye powers of the Lord, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 40, text: "O ye sun and moon, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 41, text: "O ye stars of heaven, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 42, text: "O every shower and dew, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 43, text: "O all ye winds, bless ye the Lord: praise and exalt him above all for ever," },
  { book: "Prayer of Azariah", chapter: 1, verse: 44, text: "O ye fire and heat, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 45, text: "O ye winter and summer, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 46, text: "O ye dews and storms of snow, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 47, text: "O ye nights and days, bless ye the Lord: bless and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 48, text: "O ye light and darkness, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 49, text: "O ye ice and cold, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 50, text: "O ye frost and snow, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 51, text: "O ye lightnings and clouds, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 52, text: "O let the earth bless the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 53, text: "O ye mountains and little hills, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 54, text: "O all ye things that grow in the earth, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 55, text: "O ye mountains, bless ye the Lord: Praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 56, text: "O ye seas and rivers, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 57, text: "O ye whales, and all that move in the waters, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 58, text: "O all ye fowls of the air, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 59, text: "O all ye beasts and cattle, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 60, text: "O ye children of men, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 61, text: "O Israel, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 62, text: "O ye priests of the Lord, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 63, text: "O ye servants of the Lord, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 64, text: "O ye spirits and souls of the righteous, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 65, text: "O ye holy and humble men of heart, bless ye the Lord: praise and exalt him above all for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 66, text: "O Ananias, Azarias, and Misael, bless ye the Lord: praise and exalt him above all for ever: far he hath delivered us from hell, and saved us from the hand of death, and delivered us out of the midst of the furnace and burning flame: even out of the midst of the fire hath he delivered us." },
  { book: "Prayer of Azariah", chapter: 1, verse: 67, text: "O give thanks unto the Lord, because he is gracious: for his mercy endureth for ever." },
  { book: "Prayer of Azariah", chapter: 1, verse: 68, text: "O all ye that worship the Lord, bless the God of gods, praise him, and give him thanks: for his mercy endureth for ever." },
  // Psalm 151 (9 verses)
  { book: "Psalm 151", chapter: 1, verse: 0, text: "I. Ps. cli. A Thanksgiving of David." },
  { book: "Psalm 151", chapter: 1, verse: 1, text: "I was the youngest among my brethren, and a youth in my father's house." },
  { book: "Psalm 151", chapter: 1, verse: 2, text: "I used to feed my father's flock, and I found a lion and a wolf, and slew them and rent them." },
  { book: "Psalm 151", chapter: 1, verse: 3, text: "My hands made an organ, and my fingers fashioned a harp." },
  { book: "Psalm 151", chapter: 1, verse: 4, text: "Who will show me my Lord? He, my Lord, is become my God." },
  { book: "Psalm 151", chapter: 1, verse: 5, text: "He sent His angel and took me away from my father's flock, and anointed me with the oil of anointing." },
  { book: "Psalm 151", chapter: 1, verse: 6, text: "My brethren, the fair and the tall, in them the Lord had no pleasure." },
  { book: "Psalm 151", chapter: 1, verse: 7, text: "And I went forth to meet the Philistine, and he cursed me by his idols." },
  { book: "Psalm 151", chapter: 1, verse: 8, text: "But I drew his sword and cut off his head, and took away the reproach from the children of Israel." },
  // Sirach (1392 verses)
  { book: "Sirach", chapter: 1, verse: 1, text: "All wisdom cometh from the Lord, and is with him for ever." },
  { book: "Sirach", chapter: 1, verse: 2, text: "Who can number the sand of the sea, and the drops of rain, and the days of eternity?" },
  { book: "Sirach", chapter: 1, verse: 3, text: "Who can find out the height of heaven, and the breadth of the earth, and the deep, and wisdom?" },
  { book: "Sirach", chapter: 1, verse: 4, text: "Wisdom hath been created before all things, and the understanding of prudence from everlasting." },
  { book: "Sirach", chapter: 1, verse: 5, text: "The word of God most high is the fountain of wisdom; and her ways are everlasting commandments." },
  { book: "Sirach", chapter: 1, verse: 6, text: "To whom hath the root of wisdom been revealed? or who hath known her wise counsels?" },
  { book: "Sirach", chapter: 1, verse: 7, text: "Unto whom hath the knowledge of wisdom been made manifest? and who hath understood her great experience?" },
  { book: "Sirach", chapter: 1, verse: 8, text: "There is one wise and greatly to be feared, the Lord sitting upon his throne." },
  { book: "Sirach", chapter: 1, verse: 9, text: "He created her, and saw her, and numbered her, and poured her out upon all his works." },
  { book: "Sirach", chapter: 1, verse: 10, text: "She is with all flesh according to his gift, and he hath given her to them that love him." },
  { book: "Sirach", chapter: 1, verse: 11, text: "The fear of the Lord is honour, and glory, and gladness, and a crown of rejoicing." },
  { book: "Sirach", chapter: 1, verse: 12, text: "The fear of the Lord maketh a merry heart, and giveth joy, and gladness, and a long life." },
  { book: "Sirach", chapter: 1, verse: 13, text: "Whoso feareth the Lord, it shall go well with him at the last, and he shall find favour in the day of his death." },
  { book: "Sirach", chapter: 1, verse: 14, text: "To fear the Lord is the beginning of wisdom: and it was created with the faithful in the womb." },
  { book: "Sirach", chapter: 1, verse: 15, text: "She hath built an everlasting foundation with men, and she shall continue with their seed." },
  { book: "Sirach", chapter: 1, verse: 16, text: "To fear the Lord is fulness of wisdom, and filleth men with her fruits." },
  { book: "Sirach", chapter: 1, verse: 17, text: "She filleth all their house with things desirable, and the garners with her increase." },
  { book: "Sirach", chapter: 1, verse: 18, text: "The fear of the Lord is a crown of wisdom, making peace and perfect health to flourish; both which are the gifts of God: and it enlargeth their rejoicing that love him." },
  { book: "Sirach", chapter: 1, verse: 19, text: "Wisdom raineth down skill and knowledge of understanding standing, and exalteth them to honour that hold her fast." },
  { book: "Sirach", chapter: 1, verse: 20, text: "The root of wisdom is to fear the Lord, and the branches thereof are long life." },
  { book: "Sirach", chapter: 1, verse: 21, text: "The fear of the Lord driveth away sins: and where it is present, it turneth away wrath." },
  { book: "Sirach", chapter: 1, verse: 22, text: "A furious man cannot be justified; for the sway of his fury shall be his destruction." },
  { book: "Sirach", chapter: 1, verse: 23, text: "A patient man will tear for a time, and afterward joy shall spring up unto him." },
  { book: "Sirach", chapter: 1, verse: 24, text: "He will hide his words for a time, and the lips of many shall declare his wisdom." },
  { book: "Sirach", chapter: 1, verse: 25, text: "The parables of knowledge are in the treasures of wisdom: but godliness is an abomination to a sinner." },
  { book: "Sirach", chapter: 1, verse: 26, text: "If thou desire wisdom, keep the commandments, and the Lord shall give her unto thee." },
  { book: "Sirach", chapter: 1, verse: 27, text: "For the fear of the Lord is wisdom and instruction: and faith and meekness are his delight." },
  { book: "Sirach", chapter: 1, verse: 28, text: "Distrust not the fear of the Lord when thou art poor: and come not unto him with a double heart." },
  { book: "Sirach", chapter: 1, verse: 29, text: "Be not an hypocrite in the sight of men, and take good heed what thou speakest." },
  { book: "Sirach", chapter: 1, verse: 30, text: "Exalt not thyself, lest thou fall, and bring dishonour upon thy soul, and so God discover thy secrets, and cast thee down in the midst of the congregation, because thou camest not in truth to the fear of the Lord, but thy heart is full of deceit." },
  { book: "Sirach", chapter: 2, verse: 1, text: "My son, if thou come to serve the Lord, prepare thy soul for temptation." },
  { book: "Sirach", chapter: 2, verse: 2, text: "Set thy heart aright, and constantly endure, and make not haste in time of trouble." },
  { book: "Sirach", chapter: 2, verse: 3, text: "Cleave unto him, and depart not away, that thou mayest be increased at thy last end." },
  { book: "Sirach", chapter: 2, verse: 4, text: "Whatsoever is brought upon thee take cheerfully, and be patient when thou art changed to a low estate." },
  { book: "Sirach", chapter: 2, verse: 5, text: "For gold is tried in the fire, and acceptable men in the furnace of adversity." },
  { book: "Sirach", chapter: 2, verse: 6, text: "Believe in him, and he will help thee; order thy way aright, and trust in him." },
  { book: "Sirach", chapter: 2, verse: 7, text: "Ye that fear the Lord, wait for his mercy; and go not aside, lest ye fall." },
  { book: "Sirach", chapter: 2, verse: 8, text: "Ye that fear the Lord, believe him; and your reward shall not fail." },
  { book: "Sirach", chapter: 2, verse: 9, text: "Ye that fear the Lord, hope for good, and for everlasting joy and mercy." },
  { book: "Sirach", chapter: 2, verse: 10, text: "Look at the generations of old, and see; did ever any trust in the Lord, and was confounded? or did any abide in his fear, and was forsaken? or whom did he ever despise, that called upon him?" },
  { book: "Sirach", chapter: 2, verse: 11, text: "For the Lord is full of compassion and mercy, longsuffering, and very pitiful, and forgiveth sins, and saveth in time of affliction." },
  { book: "Sirach", chapter: 2, verse: 12, text: "Woe be to fearful hearts, and faint hands, and the sinner that goeth two ways!" },
  { book: "Sirach", chapter: 2, verse: 13, text: "Woe unto him that is fainthearted! for he believeth not; therefore shall he not be defended." },
  { book: "Sirach", chapter: 2, verse: 14, text: "Woe unto you that have lost patience! and what will ye do when the Lord shall visit you?" },
  { book: "Sirach", chapter: 2, verse: 15, text: "They that fear the Lord will not disobey his Word; and they that love him will keep his ways." },
  { book: "Sirach", chapter: 2, verse: 16, text: "They that fear the Lord will seek that which is well, pleasing unto him; and they that love him shall be filled with the law." },
  { book: "Sirach", chapter: 2, verse: 17, text: "They that fear the Lord will prepare their hearts, and humble their souls in his sight," },
  { book: "Sirach", chapter: 2, verse: 18, text: "Saying, We will fall into the hands of the Lord, and not into the hands of men: for as his majesty is, so is his mercy." },
  { book: "Sirach", chapter: 3, verse: 1, text: "Hear me your father, O children, and do thereafter, that ye may be safe." },
  { book: "Sirach", chapter: 3, verse: 2, text: "For the Lord hath given the father honour over the children, and hath confirmed the authority of the mother over the sons." },
  { book: "Sirach", chapter: 3, verse: 3, text: "Whoso honoureth his father maketh an atonement for his sins:" },
  { book: "Sirach", chapter: 3, verse: 4, text: "And he that honoureth his mother is as one that layeth up treasure." },
  { book: "Sirach", chapter: 3, verse: 5, text: "Whoso honoureth his father shall have joy of his own children; and when he maketh his prayer, he shall be heard." },
  { book: "Sirach", chapter: 3, verse: 6, text: "He that honoureth his father shall have a long life; and he that is obedient unto the Lord shall be a comfort to his mother." },
  { book: "Sirach", chapter: 3, verse: 7, text: "He that feareth the Lord will honour his father, and will do service unto his parents, as to his masters." },
  { book: "Sirach", chapter: 3, verse: 8, text: "Honour thy father and mother both in word and deed, that a blessing may come upon thee from them." },
  { book: "Sirach", chapter: 3, verse: 9, text: "For the blessing of the father establisheth the houses of children; but the curse of the mother rooteth out foundations." },
  { book: "Sirach", chapter: 3, verse: 10, text: "Glory not in the dishonour of thy father; for thy father’s dishonour is no glory unto thee." },
  { book: "Sirach", chapter: 3, verse: 11, text: "For the glory of a man is from the honour of his father; and a mother in dishonour is a reproach to the children." },
  { book: "Sirach", chapter: 3, verse: 12, text: "My son, help thy father in his age, and grieve him not as long as he liveth." },
  { book: "Sirach", chapter: 3, verse: 13, text: "And if his understanding fail, have patience with him; and despise him not when thou art in thy full strength." },
  { book: "Sirach", chapter: 3, verse: 14, text: "For the relieving of thy father shall not be forgotten: and instead of sins it shall be added to build thee up." },
  { book: "Sirach", chapter: 3, verse: 15, text: "In the day of thine affliction it shall be remembered; thy sins also shall melt away, as the ice in the fair warm weather." },
  { book: "Sirach", chapter: 3, verse: 16, text: "He that forsaketh his father is as a blasphemer; and he that angereth his mother is cursed: of God." },
  { book: "Sirach", chapter: 3, verse: 17, text: "My son, go on with thy business in meekness; so shalt thou be beloved of him that is approved." },
  { book: "Sirach", chapter: 3, verse: 18, text: "The greater thou art, the more humble thyself, and thou shalt find favour before the Lord." },
  { book: "Sirach", chapter: 3, verse: 19, text: "Many are in high place, and of renown: but mysteries are revealed unto the meek." },
  { book: "Sirach", chapter: 3, verse: 20, text: "For the power of the Lord is great, and he is honoured of the lowly." },
  { book: "Sirach", chapter: 3, verse: 21, text: "Seek not out things that are too hard for thee, neither search the things that are above thy strength." },
  { book: "Sirach", chapter: 3, verse: 22, text: "But what is commanded thee, think thereupon with reverence, for it is not needful for thee to see with thine eyes the things that are in secret." },
  { book: "Sirach", chapter: 3, verse: 23, text: "Be not curious in unnecessary matters: for more things are shewed unto thee than men understand." },
  { book: "Sirach", chapter: 3, verse: 24, text: "For many are deceived by their own vain opinion; and an evil suspicion hath overthrown their judgment." },
  { book: "Sirach", chapter: 3, verse: 25, text: "Without eyes thou shalt want light: profess not the knowledge therefore that thou hast not." },
  { book: "Sirach", chapter: 3, verse: 26, text: "A stubborn heart shall fare evil at the last; and he that loveth danger shall perish therein." },
  { book: "Sirach", chapter: 3, verse: 27, text: "An obstinate heart shall be laden with sorrows; and the wicked man shall heap sin upon sin." },
  { book: "Sirach", chapter: 3, verse: 28, text: "In the punishment of the proud there is no remedy; for the plant of wickedness hath taken root in him." },
  { book: "Sirach", chapter: 3, verse: 29, text: "The heart of the prudent will understand a parable; and an attentive ear is the desire of a wise man." },
  { book: "Sirach", chapter: 3, verse: 30, text: "Water will quench a flaming fire; and alms maketh an atonement for sins." },
  { book: "Sirach", chapter: 3, verse: 31, text: "And he that requiteth good turns is mindful of that which may come hereafter; and when he falleth, he shall find a stay." },
  { book: "Sirach", chapter: 4, verse: 1, text: "My son, defraud not the poor of his living, and make not the needy eyes to wait long." },
  { book: "Sirach", chapter: 4, verse: 2, text: "Make not an hungry soul sorrowful; neither provoke a man in his distress." },
  { book: "Sirach", chapter: 4, verse: 3, text: "Add not more trouble to an heart that is vexed; and defer not to give to him that is in need." },
  { book: "Sirach", chapter: 4, verse: 4, text: "Reject not the supplication of the afflicted; neither turn away thy face from a poor man." },
  { book: "Sirach", chapter: 4, verse: 5, text: "Turn not away thine eye from the needy, and give him none occasion to curse thee:" },
  { book: "Sirach", chapter: 4, verse: 6, text: "For if he curse thee in the bitterness of his soul, his prayer shall be heard of him that made him." },
  { book: "Sirach", chapter: 4, verse: 7, text: "Get thyself the love of the congregation, and bow thy head to a great man." },
  { book: "Sirach", chapter: 4, verse: 8, text: "Let it not grieve thee to bow down thine ear to the poor, and give him a friendly answer with meekness." },
  { book: "Sirach", chapter: 4, verse: 9, text: "Deliver him that suffereth wrong from the hand of the oppressor; and be not fainthearted when thou sittest in judgment." },
  { book: "Sirach", chapter: 4, verse: 10, text: "Be as a father unto the fatherless, and instead of an husband unto their mother: so shalt thou be as the son of the most High, and he shall love thee more than thy mother doth." },
  { book: "Sirach", chapter: 4, verse: 11, text: "Wisdom exalteth her children, and layeth hold of them that seek her." },
  { book: "Sirach", chapter: 4, verse: 12, text: "He that loveth her loveth life; and they that seek to her early shall be filled with joy." },
  { book: "Sirach", chapter: 4, verse: 13, text: "He that holdeth her fast shall inherit glory; and wheresoever she entereth, the Lord will bless." },
  { book: "Sirach", chapter: 4, verse: 14, text: "They that serve her shall minister to the Holy One: and them that love her the Lord doth love." },
  { book: "Sirach", chapter: 4, verse: 15, text: "Whoso giveth ear unto her shall judge the nations: and he that attendeth unto her shall dwell securely." },
  { book: "Sirach", chapter: 4, verse: 16, text: "If a man commit himself unto her, he shall inherit her; and his generation shall hold her in possession." },
  { book: "Sirach", chapter: 4, verse: 17, text: "For at the first she will walk with him by crooked ways, and bring fear and dread upon him, and torment him with her discipline, until she may trust his soul, and try him by her laws." },
  { book: "Sirach", chapter: 4, verse: 18, text: "Then will she return the straight way unto him, and comfort him, and shew him her secrets." },
  { book: "Sirach", chapter: 4, verse: 19, text: "But if he go wrong, she will forsake him, and give him over to his own ruin." },
  { book: "Sirach", chapter: 4, verse: 20, text: "Observe the opportunity, and beware of evil; and be not ashamed when it concerneth thy soul." },
  { book: "Sirach", chapter: 4, verse: 21, text: "For there is a shame that bringeth sin; and there is a shame which is glory and grace." },
  { book: "Sirach", chapter: 4, verse: 22, text: "Accept no person against thy soul, and let not the reverence of any man cause thee to fall." },
  { book: "Sirach", chapter: 4, verse: 23, text: "And refrain not to speak, when there is occasion to do good, and hide not thy wisdom in her beauty." },
  { book: "Sirach", chapter: 4, verse: 24, text: "For by speech wisdom shall be known: and learning by the word of the tongue." },
  { book: "Sirach", chapter: 4, verse: 25, text: "In no wise speak against the truth; but be abashed of the error of thine ignorance." },
  { book: "Sirach", chapter: 4, verse: 26, text: "Be not ashamed to confess thy sins; and force not the course of the river." },
  { book: "Sirach", chapter: 4, verse: 27, text: "Make not thyself an underling to a foolish man; neither accept the person of the mighty." },
  { book: "Sirach", chapter: 4, verse: 28, text: "Strive for the truth unto death, and the Lord shall fight for thee." },
  { book: "Sirach", chapter: 4, verse: 29, text: "Be not hasty in thy tongue, and in thy deeds slack and remiss." },
  { book: "Sirach", chapter: 4, verse: 30, text: "Be not as a lion in thy house, nor frantick among thy servants." },
  { book: "Sirach", chapter: 4, verse: 31, text: "Let not thine hand be stretched out to receive, and shut when thou shouldest repay." },
  { book: "Sirach", chapter: 5, verse: 1, text: "Set thy heart upon thy goods; and say not, I have enough for my life." },
  { book: "Sirach", chapter: 5, verse: 2, text: "Follow not thine own mind and thy strength, to walk in the ways of thy heart:" },
  { book: "Sirach", chapter: 5, verse: 3, text: "And say not, Who shall controul me for my works? for the Lord will surely revenge thy pride." },
  { book: "Sirach", chapter: 5, verse: 4, text: "Say not, I have sinned, and what harm hath happened unto me? for the Lord is longsuffering, he will in no wise let thee go." },
  { book: "Sirach", chapter: 5, verse: 5, text: "Concerning propitiation, be not without fear to add sin unto sin:" },
  { book: "Sirach", chapter: 5, verse: 6, text: "And say not His mercy is great; he will be pacified for the multitude of my sins: for mercy and wrath come from him, and his indignation resteth upon sinners." },
  { book: "Sirach", chapter: 5, verse: 7, text: "Make no tarrying to turn to the Lord, and put not off from day to day: for suddenly shall the wrath of the Lord come forth, and in thy security thou shalt be destroyed, and perish in the day of vengeance." },
  { book: "Sirach", chapter: 5, verse: 8, text: "Set not thine heart upon goods unjustly gotten, for they shall not profit thee in the day of calamity." },
  { book: "Sirach", chapter: 5, verse: 9, text: "Winnow not with every wind, and go not into every way: for so doth the sinner that hath a double tongue." },
  { book: "Sirach", chapter: 5, verse: 10, text: "Be stedfast in thy understanding; and let thy word be the same." },
  { book: "Sirach", chapter: 5, verse: 11, text: "Be swift to hear; and let thy life be sincere; and with patience give answer." },
  { book: "Sirach", chapter: 5, verse: 12, text: "If thou hast understanding, answer thy neighbour; if not, lay thy hand upon thy mouth." },
  { book: "Sirach", chapter: 5, verse: 13, text: "Honour and shame is in talk: and the tongue of man is his fall." },
  { book: "Sirach", chapter: 5, verse: 14, text: "Be not called a whisperer, and lie not in wait with thy tongue: for a foul shame is upon the thief, and an evil condemnation upon the double tongue." },
  { book: "Sirach", chapter: 5, verse: 15, text: "Be not ignorant of any thing in a great matter or a small." },
  { book: "Sirach", chapter: 6, verse: 1, text: "Instead of a friend become not an enemy; for thereby thou shalt inherit an ill name, shame, and reproach: even so shall a sinner that hath a double tongue." },
  { book: "Sirach", chapter: 6, verse: 2, text: "Extol not thyself in the counsel of thine own heart; that thy soul be not torn in pieces as a bull straying alone." },
  { book: "Sirach", chapter: 6, verse: 3, text: "Thou shalt eat up thy leaves, and lose thy fruit, and leave thyself as a dry tree." },
  { book: "Sirach", chapter: 6, verse: 4, text: "A wicked soul shall destroy him that hath it, and shall make him to be laughed to scorn of his enemies." },
  { book: "Sirach", chapter: 6, verse: 5, text: "Sweet language will multiply friends: and a fairspeaking tongue will increase kind greetings." },
  { book: "Sirach", chapter: 6, verse: 6, text: "Be in peace with many: nevertheless have but one counsellor of a thousand." },
  { book: "Sirach", chapter: 6, verse: 7, text: "If thou wouldest get a friend, prove him first and be not hasty to credit him." },
  { book: "Sirach", chapter: 6, verse: 8, text: "For some man is a friend for his own occasion, and will not abide in the day of thy trouble." },
  { book: "Sirach", chapter: 6, verse: 9, text: "And there is a friend, who being turned to enmity, and strife will discover thy reproach." },
  { book: "Sirach", chapter: 6, verse: 10, text: "Again, some friend is a companion at the table, and will not continue in the day of thy affliction." },
  { book: "Sirach", chapter: 6, verse: 11, text: "But in thy prosperity he will be as thyself, and will be bold over thy servants." },
  { book: "Sirach", chapter: 6, verse: 12, text: "If thou be brought low, he will be against thee, and will hide himself from thy face." },
  { book: "Sirach", chapter: 6, verse: 13, text: "Separate thyself from thine enemies, and take heed of thy friends." },
  { book: "Sirach", chapter: 6, verse: 14, text: "A faithfull friend is a strong defence: and he that hath found such an one hath found a treasure." },
  { book: "Sirach", chapter: 6, verse: 15, text: "Nothing doth countervail a faithful friend, and his excellency is invaluable." },
  { book: "Sirach", chapter: 6, verse: 16, text: "A faithful friend is the medicine of life; and they that fear the Lord shall find him." },
  { book: "Sirach", chapter: 6, verse: 17, text: "Whoso feareth the Lord shall direct his friendship aright: for as he is, so shall his neighbour be also." },
  { book: "Sirach", chapter: 6, verse: 18, text: "My son, gather instruction from thy youth up: so shalt thou find wisdom till thine old age." },
  { book: "Sirach", chapter: 6, verse: 19, text: "Come unto her as one that ploweth and soweth, and wait for her good fruits: for thou shalt not toil much in labouring about her, but thou shalt eat of her fruits right soon." },
  { book: "Sirach", chapter: 6, verse: 20, text: "She is very unpleasant to the unlearned: he that is without understanding will not remain with her." },
  { book: "Sirach", chapter: 6, verse: 21, text: "She will lie upon him as a mighty stone of trial; and he will cast her from him ere it be long." },
  { book: "Sirach", chapter: 6, verse: 22, text: "For wisdom is according to her name, and she is not manifest unto many." },
  { book: "Sirach", chapter: 6, verse: 23, text: "Give ear, my son, receive my advice, and refuse not my counsel," },
  { book: "Sirach", chapter: 6, verse: 24, text: "And put thy feet into her fetters, and thy neck into her chain." },
  { book: "Sirach", chapter: 6, verse: 25, text: "Bow down thy shoulder, and bear her, and be not grieved with her bonds." },
  { book: "Sirach", chapter: 6, verse: 26, text: "Come unto her with thy whole heart, and keep her ways with all thy power." },
  { book: "Sirach", chapter: 6, verse: 27, text: "Search, and seek, and she shall be made known unto thee: and when thou hast got hold of her, let her not go." },
  { book: "Sirach", chapter: 6, verse: 28, text: "For at the last thou shalt find her rest, and that shall be turned to thy joy." },
  { book: "Sirach", chapter: 6, verse: 29, text: "Then shall her fetters be a strong defence for thee, and her chains a robe of glory." },
  { book: "Sirach", chapter: 6, verse: 30, text: "For there is a golden ornament upon her, and her bands are purple lace." },
  { book: "Sirach", chapter: 6, verse: 31, text: "Thou shalt put her on as a robe of honour, and shalt put her about thee as a crown of joy." },
  { book: "Sirach", chapter: 6, verse: 32, text: "My son, if thou wilt, thou shalt be taught: and if thou wilt apply thy mind, thou shalt be prudent." },
  { book: "Sirach", chapter: 6, verse: 33, text: "If thou love to hear, thou shalt receive understanding: and if thou bow thine ear, thou shalt be wise," },
  { book: "Sirach", chapter: 6, verse: 34, text: "Stand in the multitude of the elders; and cleave unto him that is wise." },
  { book: "Sirach", chapter: 6, verse: 35, text: "Be willing to hear every godly discourse; and let not the parables of understanding escape thee." },
  { book: "Sirach", chapter: 6, verse: 36, text: "And if thou seest a man of understanding, get thee betimes unto him, and let thy foot wear the steps of his door." },
  { book: "Sirach", chapter: 6, verse: 37, text: "Let thy mind be upon the ordinances of the Lord and meditate continually in his commandments: he shall establish thine heart, and give thee wisdom at thine owns desire." },
  { book: "Sirach", chapter: 7, verse: 1, text: "Do no evil, so shall no harm come unto thee." },
  { book: "Sirach", chapter: 7, verse: 2, text: "Depart from the unjust, and iniquity shall turn away from thee." },
  { book: "Sirach", chapter: 7, verse: 3, text: "My son, sow not upon the furrows of unrighteousness, and thou shalt not reap them sevenfold." },
  { book: "Sirach", chapter: 7, verse: 4, text: "Seek not of the Lord preeminence, neither of the king the seat of honour." },
  { book: "Sirach", chapter: 7, verse: 5, text: "justify not thyself before the Lord; and boast not of thy wisdom before the king." },
  { book: "Sirach", chapter: 7, verse: 6, text: "Seek not to be judge, being not able to take away iniquity; lest at any time thou fear the person of the mighty, an stumblingblock in the way of thy uprightness." },
  { book: "Sirach", chapter: 7, verse: 7, text: "Offend not against the multitude of a city, and then thou shalt not cast thyself down among the people." },
  { book: "Sirach", chapter: 7, verse: 8, text: "Bind not one sin upon another; for in one thou shalt not be unpunished." },
  { book: "Sirach", chapter: 7, verse: 9, text: "Say not, God will look upon the multitude of my oblations, and when I offer to the most high God, he will accept it." },
  { book: "Sirach", chapter: 7, verse: 10, text: "Be not fainthearted when thou makest thy prayer, and neglect not to give alms." },
  { book: "Sirach", chapter: 7, verse: 11, text: "Laugh no man to scorn in the bitterness of his soul: for there is one which humbleth and exalteth." },
  { book: "Sirach", chapter: 7, verse: 12, text: "Devise not a lie against thy brother; neither do the like to thy friend." },
  { book: "Sirach", chapter: 7, verse: 13, text: "Use not to make any manner of lie: for the custom thereof is not good." },
  { book: "Sirach", chapter: 7, verse: 14, text: "Use not many words in a multitude of elders, and make not much babbling when thou prayest." },
  { book: "Sirach", chapter: 7, verse: 15, text: "Hate not laborious work, neither husbandry, which the most High hath ordained." },
  { book: "Sirach", chapter: 7, verse: 16, text: "Number not thyself among the multitude of sinners, but remember that wrath will not tarry long." },
  { book: "Sirach", chapter: 7, verse: 17, text: "Humble thyself greatly: for the vengeance of the ungodly is fire and worms." },
  { book: "Sirach", chapter: 7, verse: 18, text: "Change not a friend for any good by no means; neither a faithful brother for the gold of Ophir." },
  { book: "Sirach", chapter: 7, verse: 19, text: "Forego not a wise and good woman: for her grace is above gold." },
  { book: "Sirach", chapter: 7, verse: 20, text: "Whereas thy servant worketh truly, entreat him not evil. nor the hireling that bestoweth himself wholly for thee." },
  { book: "Sirach", chapter: 7, verse: 21, text: "Let thy soul love a good servant, and defraud him not of liberty." },
  { book: "Sirach", chapter: 7, verse: 22, text: "Hast thou cattle? have an eye to them: and if they be for thy profit, keep them with thee." },
  { book: "Sirach", chapter: 7, verse: 23, text: "Hast thou children? instruct them, and bow down their neck from their youth." },
  { book: "Sirach", chapter: 7, verse: 24, text: "Hast thou daughters? have a care of their body, and shew not thyself cheerful toward them." },
  { book: "Sirach", chapter: 7, verse: 25, text: "Marry thy daughter, and so shalt thou have performed a weighty matter: but give her to a man of understanding." },
  { book: "Sirach", chapter: 7, verse: 26, text: "Hast thou a wife after thy mind? forsake her not: but give not thyself over to a light woman." },
  { book: "Sirach", chapter: 7, verse: 27, text: "Honour thy father with thy whole heart, and forget not the sorrows of thy mother." },
  { book: "Sirach", chapter: 7, verse: 28, text: "Remember that thou wast begotten of them; and how canst thou recompense them the things that they have done for thee?" },
  { book: "Sirach", chapter: 7, verse: 29, text: "Fear the Lord with all thy soul, and reverence his priests." },
  { book: "Sirach", chapter: 7, verse: 30, text: "Love him that made thee with all thy strength, and forsake not his ministers." },
  { book: "Sirach", chapter: 7, verse: 31, text: "Fear the Lord, and honor the priest; and give him his portion, as it is commanded thee; the firstfruits, and the trespass offering, and the gift of the shoulders, and the sacrifice of sanctification, and the firstfruits of the holy things." },
  { book: "Sirach", chapter: 7, verse: 32, text: "And stretch thine hand unto the poor, that thy blessing may be perfected." },
  { book: "Sirach", chapter: 7, verse: 33, text: "A gift hath grace in the sight of every man living; and for the dead detain it not." },
  { book: "Sirach", chapter: 7, verse: 34, text: "Fail not to be with them that weep, and mourn with them that mourn." },
  { book: "Sirach", chapter: 7, verse: 35, text: "Be not slow to visit the sick: for that shall make thee to be beloved." },
  { book: "Sirach", chapter: 7, verse: 36, text: "Whatsoever thou takest in hand, remember the end, and thou shalt never do amiss." },
  { book: "Sirach", chapter: 8, verse: 1, text: "Strive not with a mighty man, lest thou fall into his hands." },
  { book: "Sirach", chapter: 8, verse: 2, text: "Be not at variance with a rich man, lest he overweigh thee: for gold hath destroyed many, and perverted the hearts of kings." },
  { book: "Sirach", chapter: 8, verse: 3, text: "Strive not with a man that is full of tongue, and heap not wood upon his fire." },
  { book: "Sirach", chapter: 8, verse: 4, text: "Jest not with a rude man, lest thy ancestors be disgraced." },
  { book: "Sirach", chapter: 8, verse: 5, text: "Reproach not a man that turneth from sin, but remember that we are all worthy of punishment." },
  { book: "Sirach", chapter: 8, verse: 6, text: "Dishonour not a man in his old age: for even some of us wax old." },
  { book: "Sirach", chapter: 8, verse: 7, text: "Rejoice not over thy greatest enemy being dead, but remember that we die all." },
  { book: "Sirach", chapter: 8, verse: 8, text: "Despise not the discourse of the wise, but acquaint thyself with their proverbs: for of them thou shalt learn instruction, and how to serve great men with ease." },
  { book: "Sirach", chapter: 8, verse: 9, text: "Miss not the discourse of the elders: for they also learned of their fathers, and of them thou shalt learn understanding, and to give answer as need requireth." },
  { book: "Sirach", chapter: 8, verse: 10, text: "Kindle not the coals of a sinner, lest thou be burnt with the flame of his fire." },
  { book: "Sirach", chapter: 8, verse: 11, text: "Rise not up in anger at the presence of an injurious person, lest he lie in wait to entrap thee in thy words" },
  { book: "Sirach", chapter: 8, verse: 12, text: "Lend not unto him that is mightier than thyself; for if thou lendest him, count it but lost." },
  { book: "Sirach", chapter: 8, verse: 13, text: "Be not surety above thy power: for if thou be surety, take care to pay it." },
  { book: "Sirach", chapter: 8, verse: 14, text: "Go not to law with a judge; for they will judge for him according to his honour." },
  { book: "Sirach", chapter: 8, verse: 15, text: "Travel not by the way with a bold fellow, lest he become grievous unto thee: for he will do according to his own will, and thou shalt perish with him through his folly." },
  { book: "Sirach", chapter: 8, verse: 16, text: "Strive not with an angry man, and go not with him into a solitary place: for blood is as nothing in his sight, and where there is no help, he will overthrow thee." },
  { book: "Sirach", chapter: 8, verse: 17, text: "Consult not with a fool; for he cannot keep counsel." },
  { book: "Sirach", chapter: 8, verse: 18, text: "Do no secret thing before a stranger; for thou knowest not what he will bring forth." },
  { book: "Sirach", chapter: 8, verse: 19, text: "Open not thine heart to every man, lest he requite thee with a shrewd turn." },
  { book: "Sirach", chapter: 9, verse: 1, text: "Be not jealous over the wife of thy bosom, and teach her not an evil lesson against thyself." },
  { book: "Sirach", chapter: 9, verse: 2, text: "Give not thy soul unto a woman to set her foot upon thy substance." },
  { book: "Sirach", chapter: 9, verse: 3, text: "Meet not with an harlot, lest thou fall into her snares." },
  { book: "Sirach", chapter: 9, verse: 4, text: "Use not much the company of a woman that is a singer, lest thou be taken with her attempts." },
  { book: "Sirach", chapter: 9, verse: 5, text: "Gaze not on a maid, that thou fall not by those things that are precious in her." },
  { book: "Sirach", chapter: 9, verse: 6, text: "Give not thy soul unto harlots, that thou lose not thine inheritance." },
  { book: "Sirach", chapter: 9, verse: 7, text: "Look not round about thee in the streets of the city, neither wander thou in the solitary place thereof." },
  { book: "Sirach", chapter: 9, verse: 8, text: "Turn away thine eye from a beautiful woman, and look not upon another’s beauty; for many have been deceived by the beauty of a woman; for herewith love is kindled as a fire." },
  { book: "Sirach", chapter: 9, verse: 9, text: "Sit not at all with another man’s wife, nor sit down with her in thine arms, and spend not thy money with her at the wine; lest thine heart incline unto her, and so through thy desire thou fall into destruction." },
  { book: "Sirach", chapter: 9, verse: 10, text: "Forsake not an old friend; for the new is not comparable to him: a new friend is as new wine; when it is old, thou shalt drink it with pleasure." },
  { book: "Sirach", chapter: 9, verse: 11, text: "Envy not the glory of a sinner: for thou knowest not what shall be his end." },
  { book: "Sirach", chapter: 9, verse: 12, text: "Delight not in the thing that the ungodly have pleasure in; but remember they shall not go unpunished unto their grave." },
  { book: "Sirach", chapter: 9, verse: 13, text: "Keep thee far from the man that hath power to kill; so shalt thou not doubt the fear of death: and if thou come unto him, make no fault, lest he take away thy life presently: remember that thou goest in the midst of snares, and that thou walkest upon the battlements of the city." },
  { book: "Sirach", chapter: 9, verse: 14, text: "As near as thou canst, guess at thy neighbour, and consult with the wise." },
  { book: "Sirach", chapter: 9, verse: 15, text: "Let thy talk be with the wise, and all thy communication in the law of the most High." },
  { book: "Sirach", chapter: 9, verse: 16, text: "And let just men eat and drink with thee; and let thy glorying be in the fear of the Lord." },
  { book: "Sirach", chapter: 9, verse: 17, text: "For the hand of the artificer the work shall be commended: and the wise ruler of the people for his speech." },
  { book: "Sirach", chapter: 9, verse: 18, text: "A man of an ill tongue is dangerous in his city; and he that is rash in his talk shall be hated." },
  { book: "Sirach", chapter: 10, verse: 1, text: "A wise judge will instruct his people; and the government of a prudent man is well ordered." },
  { book: "Sirach", chapter: 10, verse: 2, text: "As the judge of the people is himself, so are his officers; and what manner of man the ruler of the city is, such are all they that dwell therein." },
  { book: "Sirach", chapter: 10, verse: 3, text: "An unwise king destroyeth his people; but through the prudence of them which are in authority the city shall be inhabited." },
  { book: "Sirach", chapter: 10, verse: 4, text: "The power of the earth is in the hand of the Lord, and in due time he will set over it one that is profitable." },
  { book: "Sirach", chapter: 10, verse: 5, text: "In the hand of God is the prosperity of man: and upon the person of the scribe shall he lay his honour." },
  { book: "Sirach", chapter: 10, verse: 6, text: "Bear not hatred to thy neighbour for every wrong; and do nothing at all by injurious practices." },
  { book: "Sirach", chapter: 10, verse: 7, text: "Pride is hateful before God and man: and by both doth one commit iniquity." },
  { book: "Sirach", chapter: 10, verse: 8, text: "Because of unrighteous dealings, injuries, and riches got by deceit, the kingdom is translated from one people to another." },
  { book: "Sirach", chapter: 10, verse: 9, text: "Why is earth and ashes proud? There is not a more wicked thing than a covetous man: for such an one setteth his own soul to sale; because while he liveth he casteth away his bowels." },
  { book: "Sirach", chapter: 10, verse: 10, text: "The physician cutteth off a long disease; and he that is to day a king to morrow shall die." },
  { book: "Sirach", chapter: 10, verse: 11, text: "For when a man is dead, he shall inherit creeping things, beasts, and worms." },
  { book: "Sirach", chapter: 10, verse: 12, text: "The beginning of pride is when one departeth from God, and his heart is turned away from his Maker." },
  { book: "Sirach", chapter: 10, verse: 13, text: "For pride is the beginning of sin, and he that hath it shall pour out abomination: and therefore the Lord brought upon them strange calamities, and overthrew them utterly." },
  { book: "Sirach", chapter: 10, verse: 14, text: "The Lord hath cast down the thrones of proud princes, and set up the meek in their stead." },
  { book: "Sirach", chapter: 10, verse: 15, text: "The Lord hath plucked up the roots of the proud nations, and planted the lowly in their place." },
  { book: "Sirach", chapter: 10, verse: 16, text: "The Lord overthrew countries of the heathen, and destroyed them to the foundations of the earth." },
  { book: "Sirach", chapter: 10, verse: 17, text: "He took some of them away, and destroyed them, and hath made their memorial to cease from the earth." },
  { book: "Sirach", chapter: 10, verse: 18, text: "Pride was not made for men, nor furious anger for them that are born of a woman." },
  { book: "Sirach", chapter: 10, verse: 19, text: "They that fear the Lord are a sure seed, and they that love him an honourable plant: they that regard not the law are a dishonourable seed; they that transgress the commandments are a deceivable seed." },
  { book: "Sirach", chapter: 10, verse: 20, text: "Among brethren he that is chief is honorable; so are they that fear the Lord in his eyes." },
  { book: "Sirach", chapter: 10, verse: 21, text: "The fear of the Lord goeth before the obtaining of authority: but roughness and pride is the losing thereof." },
  { book: "Sirach", chapter: 10, verse: 22, text: "Whether he be rich, noble, or poor, their glory is the fear of the Lord." },
  { book: "Sirach", chapter: 10, verse: 23, text: "It is not meet to despise the poor man that hath understanding; neither is it convenient to magnify a sinful man." },
  { book: "Sirach", chapter: 10, verse: 24, text: "Great men, and judges, and potentates, shall be honoured; yet is there none of them greater than he that feareth the Lord." },
  { book: "Sirach", chapter: 10, verse: 25, text: "Unto the servant that is wise shall they that are free do service: and he that hath knowledge will not grudge when he is reformed." },
  { book: "Sirach", chapter: 10, verse: 26, text: "Be not overwise in doing thy business; and boast not thyself in the time of thy distress." },
  { book: "Sirach", chapter: 10, verse: 27, text: "Better is he that laboureth, and aboundeth in all things, than he that boasteth himself, and wanteth bread." },
  { book: "Sirach", chapter: 10, verse: 28, text: "My son, glorify thy soul in meekness, and give it honour according to the dignity thereof." },
  { book: "Sirach", chapter: 10, verse: 29, text: "Who will justify him that sinneth against his own soul? and who will honour him that dishonoureth his own life?" },
  { book: "Sirach", chapter: 10, verse: 30, text: "The poor man is honoured for his skill, and the rich man is honoured for his riches." },
  { book: "Sirach", chapter: 10, verse: 31, text: "He that is honoured in poverty, how much more in riches? and he that is dishonourable in riches, how much more in poverty?" },
  { book: "Sirach", chapter: 11, verse: 1, text: "Wisdom lifteth up the head of him that is of low degree, and maketh him to sit among great men." },
  { book: "Sirach", chapter: 11, verse: 2, text: "Commend not a man for his beauty; neither abhor a man for his outward appearance." },
  { book: "Sirach", chapter: 11, verse: 3, text: "The bee is little among such as fly; but her fruit is the chief of sweet things." },
  { book: "Sirach", chapter: 11, verse: 4, text: "Boast not of thy clothing and raiment, and exalt not thyself in the day of honour: for the works of the Lord are wonderful, and his works among men are hidden." },
  { book: "Sirach", chapter: 11, verse: 5, text: "Many kings have sat down upon the ground; and one that was never thought of hath worn the crown." },
  { book: "Sirach", chapter: 11, verse: 6, text: "Many mighty men have been greatly disgraced; and the honourable delivered into other men’s hands." },
  { book: "Sirach", chapter: 11, verse: 7, text: "Blame not before thou hast examined the truth: understand first, and then rebuke." },
  { book: "Sirach", chapter: 11, verse: 8, text: "Answer not before thou hast heard the cause: neither interrupt men in the midst of their talk." },
  { book: "Sirach", chapter: 11, verse: 9, text: "Strive not in a matter that concerneth thee not; and sit not in judgment with sinners." },
  { book: "Sirach", chapter: 11, verse: 10, text: "My son, meddle not with many matters: for if thou meddle much, thou shalt not be innocent; and if thou follow after, thou shalt not obtain, neither shalt thou escape by fleeing." },
  { book: "Sirach", chapter: 11, verse: 11, text: "There is one that laboureth, and taketh pains, and maketh haste, and is so much the more behind." },
  { book: "Sirach", chapter: 11, verse: 12, text: "Again, there is another that is slow, and hath need of help, wanting ability, and full of poverty; yet the eye of the Lord looked upon him for good, and set him up from his low estate," },
  { book: "Sirach", chapter: 11, verse: 13, text: "And lifted up his head from misery; so that many that saw from him is peace over all the" },
  { book: "Sirach", chapter: 11, verse: 14, text: "Prosperity and adversity, life and death, poverty and riches, come of the Lord." },
  { book: "Sirach", chapter: 11, verse: 15, text: "Wisdom, knowledge, and understanding of the law, are of the Lord: love, and the way of good works, are from him." },
  { book: "Sirach", chapter: 11, verse: 16, text: "Error and darkness had their beginning together with sinners: and evil shall wax old with them that glory therein." },
  { book: "Sirach", chapter: 11, verse: 17, text: "The gift of the Lord remaineth with the ungodly, and his favour bringeth prosperity for ever." },
  { book: "Sirach", chapter: 11, verse: 18, text: "There is that waxeth rich by his wariness and pinching, and this his the portion of his reward:" },
  { book: "Sirach", chapter: 11, verse: 19, text: "Whereas he saith, I have found rest, and now will eat continually of my goods; and yet he knoweth not what time shall come upon him, and that he must leave those things to others, and die." },
  { book: "Sirach", chapter: 11, verse: 20, text: "Be stedfast in thy covenant, and be conversant therein, and wax old in thy work." },
  { book: "Sirach", chapter: 11, verse: 21, text: "Marvel not at the works of sinners; but trust in the Lord, and abide in thy labour: for it is an easy thing in the sight of the Lord on the sudden to make a poor man rich." },
  { book: "Sirach", chapter: 11, verse: 22, text: "The blessing of the Lord is in the reward of the godly, and suddenly he maketh his blessing flourish." },
  { book: "Sirach", chapter: 11, verse: 23, text: "Say not, What profit is there of my service? and what good things shall I have hereafter?" },
  { book: "Sirach", chapter: 11, verse: 24, text: "Again, say not, I have enough, and possess many things, and what evil shall I have hereafter?" },
  { book: "Sirach", chapter: 11, verse: 25, text: "In the day of prosperity there is a forgetfulness of affliction: and in the day of affliction there is no more remembrance of prosperity." },
  { book: "Sirach", chapter: 11, verse: 26, text: "For it is an easy thing unto the Lord in the day of death to reward a man according to his ways." },
  { book: "Sirach", chapter: 11, verse: 27, text: "The affliction of an hour maketh a man forget pleasure: and in his end his deeds shall be discovered." },
  { book: "Sirach", chapter: 11, verse: 28, text: "Judge none blessed before his death: for a man shall be known in his children." },
  { book: "Sirach", chapter: 11, verse: 29, text: "Bring not every man into thine house: for the deceitful man hath many trains." },
  { book: "Sirach", chapter: 11, verse: 30, text: "Like as a partridge taken and kept in a cage, so is the heart of the proud; and like as a spy, watcheth he for thy fall:" },
  { book: "Sirach", chapter: 11, verse: 31, text: "For he lieth in wait, and turneth good into evil, and in things worthy praise will lay blame upon thee." },
  { book: "Sirach", chapter: 11, verse: 32, text: "Of a spark of fire a heap of coals is kindled: and a sinful man layeth wait for blood." },
  { book: "Sirach", chapter: 11, verse: 33, text: "Take heed of a mischievous man, for he worketh wickedness; lest he bring upon thee a perpetual blot." },
  { book: "Sirach", chapter: 11, verse: 34, text: "Receive a stranger into thine house, and he will disturb thee, and turn thee out of thine own." },
  { book: "Sirach", chapter: 12, verse: 1, text: "When thou wilt do good know to whom thou doest it; so shalt thou be thanked for thy benefits." },
  { book: "Sirach", chapter: 12, verse: 2, text: "Do good to the godly man, and thou shalt find a recompence; and if not from him, yet from the most High." },
  { book: "Sirach", chapter: 12, verse: 3, text: "There can no good come to him that is always occupied in evil, nor to him that giveth no alms." },
  { book: "Sirach", chapter: 12, verse: 4, text: "Give to the godly man, and help not a sinner." },
  { book: "Sirach", chapter: 12, verse: 5, text: "Do well unto him that is lowly, but give not to the ungodly: hold back thy bread, and give it not unto him, lest he overmaster thee thereby: for else thou shalt receive twice as much evil for all the good thou shalt have done unto him." },
  { book: "Sirach", chapter: 12, verse: 6, text: "For the most High hateth sinners, and will repay vengeance unto the ungodly, and keepeth them against the mighty day of their punishment." },
  { book: "Sirach", chapter: 12, verse: 7, text: "Give unto the good, and help not the sinner." },
  { book: "Sirach", chapter: 12, verse: 8, text: "A friend cannot be known in prosperity: and an enemy cannot be hidden in adversity." },
  { book: "Sirach", chapter: 12, verse: 9, text: "In the prosperity of a man enemies will be grieved: but in his adversity even a friend will depart." },
  { book: "Sirach", chapter: 12, verse: 10, text: "Never trust thine enemy: for like as iron rusteth, so is his wickedness." },
  { book: "Sirach", chapter: 12, verse: 11, text: "Though he humble himself, and go crouching, yet take good heed and beware of him, and thou shalt be unto him as if thou hadst wiped a lookingglass, and thou shalt know that his rust hath not been altogether wiped away." },
  { book: "Sirach", chapter: 12, verse: 12, text: "Set him not by thee, lest, when he hath overthrown thee, he stand up in thy place; neither let him sit at thy right hand, lest he seek to take thy seat, and thou at the last remember my words, and be pricked therewith." },
  { book: "Sirach", chapter: 12, verse: 13, text: "Who will pity a charmer that is bitten with a serpent, or any such as come nigh wild beasts?" },
  { book: "Sirach", chapter: 12, verse: 14, text: "So one that goeth to a sinner, and is defiled with him in his sins, who will pity?" },
  { book: "Sirach", chapter: 12, verse: 15, text: "For a while he will abide with thee, but if thou begin to fall, he will not tarry." },
  { book: "Sirach", chapter: 12, verse: 16, text: "An enemy speaketh sweetly with his lips, but in his heart he imagineth how to throw thee into a pit: he will weep with his eyes, but if he find opportunity, he will not be satisfied with blood." },
  { book: "Sirach", chapter: 12, verse: 17, text: "If adversity come upon thee, thou shalt find him there first; and though he pretend to help thee, yet shall he undermine thee." },
  { book: "Sirach", chapter: 12, verse: 18, text: "He will shake his head, and clap his hands, and whisper much, and change his countenance." },
  { book: "Sirach", chapter: 13, verse: 1, text: "He that toucheth pitch shall be defiled therewith; and he that hath fellowship with a proud man shall be like unto him." },
  { book: "Sirach", chapter: 13, verse: 2, text: "Burden not thyself above thy power while thou livest; and have no fellowship with one that is mightier and richer than thyself: for how agree the kettle and the earthen pot together? for if the one be smitten against the other, it shall be broken." },
  { book: "Sirach", chapter: 13, verse: 3, text: "The rich man hath done wrong, and yet he threateneth withal: the poor is wronged, and he must intreat also." },
  { book: "Sirach", chapter: 13, verse: 4, text: "If thou be for his profit, he will use thee: but if thou have nothing, he will forsake thee." },
  { book: "Sirach", chapter: 13, verse: 5, text: "If thou have any thing, he will live with thee: yea, he will make thee bare, and will not be sorry for it." },
  { book: "Sirach", chapter: 13, verse: 6, text: "If he have need of thee, he will deceive thee, and smile upon thee, and put thee in hope; he will speak thee fair, and say, What wantest thou?" },
  { book: "Sirach", chapter: 13, verse: 7, text: "And he will shame thee by his meats, until he have drawn thee dry twice or thrice, and at the last he will laugh thee to scorn afterward, when he seeth thee, he will forsake thee, and shake his head at thee." },
  { book: "Sirach", chapter: 13, verse: 8, text: "Beware that thou be not deceived and brought down in thy jollity." },
  { book: "Sirach", chapter: 13, verse: 9, text: "If thou be invited of a mighty man, withdraw thyself, and so much the more will he invite thee." },
  { book: "Sirach", chapter: 13, verse: 10, text: "Press thou not upon him, lest thou be put back; stand not far off, lest thou be forgotten." },
  { book: "Sirach", chapter: 13, verse: 11, text: "Affect not to be made equal unto him in talk, and believe not his many words: for with much communication will he tempt thee, and smiling upon thee will get out thy secrets:" },
  { book: "Sirach", chapter: 13, verse: 12, text: "But cruelly he will lay up thy words, and will not spare to do thee hurt, and to put thee in prison." },
  { book: "Sirach", chapter: 13, verse: 13, text: "Observe, and take good heed, for thou walkest in peril of thy overthrowing: when thou hearest these things, awake in thy sleep." },
  { book: "Sirach", chapter: 13, verse: 14, text: "Love the Lord all thy life, and call upon him for thy salvation." },
  { book: "Sirach", chapter: 13, verse: 15, text: "Every beast loveth his like, and every man loveth his neighbor." },
  { book: "Sirach", chapter: 13, verse: 16, text: "All flesh consorteth according to kind, and a man will cleave to his like." },
  { book: "Sirach", chapter: 13, verse: 17, text: "What fellowship hath the wolf with the lamb? so the sinner with the godly." },
  { book: "Sirach", chapter: 13, verse: 18, text: "What agreement is there between the hyena and a dog? and what peace between the rich and the poor?" },
  { book: "Sirach", chapter: 13, verse: 19, text: "As the wild ass is the lion’s prey in the wilderness: so the rich eat up the poor." },
  { book: "Sirach", chapter: 13, verse: 20, text: "As the proud hate humility: so doth the rich abhor the poor." },
  { book: "Sirach", chapter: 13, verse: 21, text: "A rich man beginning to fall is held up of his friends: but a poor man being down is thrust away by his friends." },
  { book: "Sirach", chapter: 13, verse: 22, text: "When a rich man is fallen, he hath many helpers: he speaketh things not to be spoken, and yet men justify him: the poor man slipped, and yet they rebuked him too; he spake wisely, and could have no place." },
  { book: "Sirach", chapter: 13, verse: 23, text: "When a rich man speaketh, every man holdeth his tongue, and, look, what he saith, they extol it to the clouds: but if the poor man speak, they say, What fellow is this? and if he stumble, they will help to overthrow him." },
  { book: "Sirach", chapter: 13, verse: 24, text: "Riches are good unto him that hath no sin, and poverty is evil in the mouth of the ungodly." },
  { book: "Sirach", chapter: 13, verse: 25, text: "The heart of a man changeth his countenance, whether it be for good or evil: and a merry heart maketh a cheerful countenance." },
  { book: "Sirach", chapter: 13, verse: 26, text: "A cheerful countenance is a token of a heart that is in prosperity; and the finding out of parables is a wearisome labour of the mind." },
  { book: "Sirach", chapter: 14, verse: 1, text: "Blessed is the man that hath not slipped with his mouth, and is not pricked with the multitude of sins." },
  { book: "Sirach", chapter: 14, verse: 2, text: "Blessed is he whose conscience hath not condemned him, and who is not fallen from his hope in the Lord." },
  { book: "Sirach", chapter: 14, verse: 3, text: "Riches are not comely for a niggard: and what should an envious man do with money?" },
  { book: "Sirach", chapter: 14, verse: 4, text: "He that gathereth by defrauding his own soul gathereth for others, that shall spend his goods riotously." },
  { book: "Sirach", chapter: 14, verse: 5, text: "He that is evil to himself, to whom will he be good? he shall not take pleasure in his goods." },
  { book: "Sirach", chapter: 14, verse: 6, text: "There is none worse than he that envieth himself; and this is a recompence of his wickedness." },
  { book: "Sirach", chapter: 14, verse: 7, text: "And if he doeth good, he doeth it unwillingly; and at the last he will declare his wickedness." },
  { book: "Sirach", chapter: 14, verse: 8, text: "The envious man hath a wicked eye; he turneth away his face, and despiseth men." },
  { book: "Sirach", chapter: 14, verse: 9, text: "A covetous man’s eye is not satisfied with his portion; and the iniquity of the wicked drieth up his soul." },
  { book: "Sirach", chapter: 14, verse: 10, text: "A wicked eye envieth his bread, and he is a niggard at his table." },
  { book: "Sirach", chapter: 14, verse: 11, text: "My son, according to thy ability do good to thyself, and give the Lord his due offering." },
  { book: "Sirach", chapter: 14, verse: 12, text: "Remember that death will not be long in coming, and that the covenant of the grave is not shewed unto thee." },
  { book: "Sirach", chapter: 14, verse: 13, text: "Do good unto thy friend before thou die, and according to thy ability stretch out thy hand and give to him." },
  { book: "Sirach", chapter: 14, verse: 14, text: "Defraud not thyself of the good day, and let not the part of a good desire overpass thee." },
  { book: "Sirach", chapter: 14, verse: 15, text: "Shalt thou not leave thy travails unto another? and thy labours to be divided by lot?" },
  { book: "Sirach", chapter: 14, verse: 16, text: "Give, and take, and sanctify thy soul; for there is no seeking of dainties in the grave." },
  { book: "Sirach", chapter: 14, verse: 17, text: "All flesh waxeth old as a garment: for the covenant from the beginning is, Thou shalt die the death." },
  { book: "Sirach", chapter: 14, verse: 18, text: "As of the green leaves on a thick tree, some fall, and some grow; so is the generation of flesh and blood, one cometh to an end, and another is born." },
  { book: "Sirach", chapter: 14, verse: 19, text: "Every work rotteth and consumeth away, and the worker thereof shall go withal." },
  { book: "Sirach", chapter: 14, verse: 20, text: "Blessed is the man that doth meditate good things in wisdom, and that reasoneth of holy things by his understanding." },
  { book: "Sirach", chapter: 14, verse: 21, text: "He that considereth her ways in his heart shall also have understanding in her secrets." },
  { book: "Sirach", chapter: 14, verse: 22, text: "Go after her as one that traceth, and lie in wait in her ways." },
  { book: "Sirach", chapter: 14, verse: 23, text: "He that prieth in at her windows shall also hearken at her doors." },
  { book: "Sirach", chapter: 14, verse: 24, text: "He that doth lodge near her house shall also fasten a pin in her walls." },
  { book: "Sirach", chapter: 14, verse: 25, text: "He shall pitch his tent nigh unto her, and shall lodge in a lodging where good things are." },
  { book: "Sirach", chapter: 14, verse: 26, text: "He shall set his children under her shelter, and shall lodge under her branches." },
  { book: "Sirach", chapter: 14, verse: 27, text: "By her he shall be covered from heat, and in her glory shall he dwell." },
  { book: "Sirach", chapter: 15, verse: 1, text: "He that feareth the Lord will do good, and he that hath the knowledge of the law shall obtain her." },
  { book: "Sirach", chapter: 15, verse: 2, text: "And as a mother shall she meet him, and receive him as a wife married of a virgin." },
  { book: "Sirach", chapter: 15, verse: 3, text: "With the bread of understanding shall she feed him, and give him the water of wisdom to drink." },
  { book: "Sirach", chapter: 15, verse: 4, text: "He shall be stayed upon her, and shall not be moved; and shall rely upon her, and shall not be confounded." },
  { book: "Sirach", chapter: 15, verse: 5, text: "She shall exalt him above his neighbours, and in the midst of the congregation shall she open his mouth." },
  { book: "Sirach", chapter: 15, verse: 6, text: "He shall find joy and a crown of gladness, and she shall cause him to inherit an everlasting name." },
  { book: "Sirach", chapter: 15, verse: 7, text: "But foolish men shall not attain unto her, and sinners shall not see her." },
  { book: "Sirach", chapter: 15, verse: 8, text: "For she is far from pride, and men that are liars cannot remember her." },
  { book: "Sirach", chapter: 15, verse: 9, text: "Praise is not seemly in the mouth of a sinner, for it was not sent him of the Lord." },
  { book: "Sirach", chapter: 15, verse: 10, text: "For praise shall be uttered in wisdom, and the Lord will prosper it." },
  { book: "Sirach", chapter: 15, verse: 11, text: "Say not thou, It is through the Lord that I fell away: for thou oughtest not to do the things that he hateth." },
  { book: "Sirach", chapter: 15, verse: 12, text: "Say not thou, He hath caused me to err: for he hath no need of the sinful man." },
  { book: "Sirach", chapter: 15, verse: 13, text: "The Lord hateth all abomination; and they that fear God love it not." },
  { book: "Sirach", chapter: 15, verse: 14, text: "He himself made man from the beginning, and left him in the hand of his counsel;" },
  { book: "Sirach", chapter: 15, verse: 15, text: "If thou wilt, to keep the commandments, and to perform acceptable faithfulness." },
  { book: "Sirach", chapter: 15, verse: 16, text: "He hath set fire and water before thee: stretch forth thy hand unto whether thou wilt." },
  { book: "Sirach", chapter: 15, verse: 17, text: "Before man is life and death; and whether him liketh shall be given him." },
  { book: "Sirach", chapter: 15, verse: 18, text: "For the wisdom of the Lord is great, and he is mighty in power, and beholdeth all things:" },
  { book: "Sirach", chapter: 15, verse: 19, text: "And his eyes are upon them that fear him, and he knoweth every work of man." },
  { book: "Sirach", chapter: 15, verse: 20, text: "He hath commanded no man to do wickedly, neither hath he given any man licence to sin." },
  { book: "Sirach", chapter: 16, verse: 1, text: "Desire not a multitude of unprofitable children, neither delight in ungodly sons." },
  { book: "Sirach", chapter: 16, verse: 2, text: "Though they multiply, rejoice not in them, except the fear of the Lord be with them." },
  { book: "Sirach", chapter: 16, verse: 3, text: "Trust not thou in their life, neither respect their multitude: for one that is just is better than a thousand; and better it is to die without children, than to have them that are ungodly." },
  { book: "Sirach", chapter: 16, verse: 4, text: "For by one that hath understanding shall the city be replenished: but the kindred of the wicked shall speedily become desolate." },
  { book: "Sirach", chapter: 16, verse: 5, text: "Many such things have I seen with mine eyes, and mine ear hath heard greater things than these." },
  { book: "Sirach", chapter: 16, verse: 6, text: "In the congregation of the ungodly shall a fire be kindled; and in a rebellious nation wrath is set on fire." },
  { book: "Sirach", chapter: 16, verse: 7, text: "He was not pacified toward the old giants, who fell away in the strength of their foolishness." },
  { book: "Sirach", chapter: 16, verse: 8, text: "Neither spared he the place where Lot sojourned, but abhorred them for their pride." },
  { book: "Sirach", chapter: 16, verse: 9, text: "He pitied not the people of perdition, who were taken away in their sins:" },
  { book: "Sirach", chapter: 16, verse: 10, text: "Nor the six hundred thousand footmen, who were gathered together in the hardness of their hearts." },
  { book: "Sirach", chapter: 16, verse: 11, text: "And if there be one stiffnecked among the people, it is marvel if he escape unpunished: for mercy and wrath are with him; he is mighty to forgive, and to pour out displeasure." },
  { book: "Sirach", chapter: 16, verse: 12, text: "As his mercy is great, so is his correction also: he judgeth a man according to his works" },
  { book: "Sirach", chapter: 16, verse: 13, text: "The sinner shall not escape with his spoils: and the patience of the godly shall not be frustrate." },
  { book: "Sirach", chapter: 16, verse: 14, text: "Make way for every work of mercy: for every man shall find according to his works." },
  { book: "Sirach", chapter: 16, verse: 15, text: "The Lord hardened Pharaoh, that he should not know him, that his powerful works might be known to the world." },
  { book: "Sirach", chapter: 16, verse: 16, text: "His mercy is manifest to every creature; and he hath separated his light from the darkness with an adamant." },
  { book: "Sirach", chapter: 16, verse: 17, text: "Say not thou, I will hide myself from the Lord: shall any remember me from above? I shall not be remembered among so many people: for what is my soul among such an infinite number of creatures?" },
  { book: "Sirach", chapter: 16, verse: 18, text: "Behold, the heaven, and the heaven of heavens, the deep, and the earth, and all that therein is, shall be moved when he shall visit." },
  { book: "Sirach", chapter: 16, verse: 19, text: "The mountains also and foundations of the earth be shaken with trembling, when the Lord looketh upon them." },
  { book: "Sirach", chapter: 16, verse: 20, text: "No heart can think upon these things worthily: and who is able to conceive his ways?" },
  { book: "Sirach", chapter: 16, verse: 21, text: "It is a tempest which no man can see: for the most part of his works are hid." },
  { book: "Sirach", chapter: 16, verse: 22, text: "Who can declare the works of his justice? or who can endure them? for his covenant is afar off, and the trial of all things is in the end." },
  { book: "Sirach", chapter: 16, verse: 23, text: "He that wanteth understanding will think upon vain things: and a foolish man erring imagineth follies." },
  { book: "Sirach", chapter: 16, verse: 24, text: "by son, hearken unto me, and learn knowledge, and mark my words with thy heart." },
  { book: "Sirach", chapter: 16, verse: 25, text: "I will shew forth doctrine in weight, and declare his knowledge exactly." },
  { book: "Sirach", chapter: 16, verse: 26, text: "The works of the Lord are done in judgment from the beginning: and from the time he made them he disposed the parts thereof." },
  { book: "Sirach", chapter: 16, verse: 27, text: "He garnished his works for ever, and in his hand are the chief of them unto all generations: they neither labour, nor are weary, nor cease from their works." },
  { book: "Sirach", chapter: 16, verse: 28, text: "None of them hindereth another, and they shall never disobey his word." },
  { book: "Sirach", chapter: 16, verse: 29, text: "After this the Lord looked upon the earth, and filled it with his blessings." },
  { book: "Sirach", chapter: 16, verse: 30, text: "With all manner of living things hath he covered the face thereof; and they shall return into it again." },
  { book: "Sirach", chapter: 17, verse: 1, text: "The Lord created man of the earth, and turned him into it again." },
  { book: "Sirach", chapter: 17, verse: 2, text: "He gave them few days, and a short time, and power also over the things therein." },
  { book: "Sirach", chapter: 17, verse: 3, text: "He endued them with strength by themselves, and made them according to his image," },
  { book: "Sirach", chapter: 17, verse: 4, text: "And put the fear of man upon all flesh, and gave him dominion over beasts and fowls." },
  { book: "Sirach", chapter: 17, verse: 5, text: "They received the use of the five operations of the Lord, and in the sixth place he imparted them understanding, and in the seventh speech, an interpreter of the cogitations thereof." },
  { book: "Sirach", chapter: 17, verse: 6, text: "Counsel, and a tongue, and eyes, ears, and a heart, gave he them to understand." },
  { book: "Sirach", chapter: 17, verse: 7, text: "Withal he filled them with the knowledge of understanding, and shewed them good and evil." },
  { book: "Sirach", chapter: 17, verse: 8, text: "He set his eye upon their hearts, that he might shew them the greatness of his works." },
  { book: "Sirach", chapter: 17, verse: 9, text: "He gave them to glory in his marvellous acts for ever, that they might declare his works with understanding." },
  { book: "Sirach", chapter: 17, verse: 10, text: "And the elect shall praise his holy name." },
  { book: "Sirach", chapter: 17, verse: 11, text: "Beside this he gave them knowledge, and the law of life for an heritage." },
  { book: "Sirach", chapter: 17, verse: 12, text: "He made an everlasting covenant with them, and shewed them his judgments." },
  { book: "Sirach", chapter: 17, verse: 13, text: "Their eyes saw the majesty of his glory, and their ears heard his glorious voice." },
  { book: "Sirach", chapter: 17, verse: 14, text: "And he said unto them, Beware of all unrighteousness; and he gave every man commandment concerning his neighbour." },
  { book: "Sirach", chapter: 17, verse: 15, text: "Their ways are ever before him, and shall not be hid from his eyes." },
  { book: "Sirach", chapter: 17, verse: 16, text: "Every man from his youth is given to evil; neither could they make to themselves fleshy hearts for stony." },
  { book: "Sirach", chapter: 17, verse: 17, text: "For in the division of the nations of the whole earth he set a ruler over every people; but Israel is the Lord’s portion:" },
  { book: "Sirach", chapter: 17, verse: 18, text: "Whom, being his firstborn, he nourisheth with discipline, and giving him the light of his love doth not forsake him." },
  { book: "Sirach", chapter: 17, verse: 19, text: "Therefore all their works are as the sun before him, and his eyes are continually upon their ways." },
  { book: "Sirach", chapter: 17, verse: 20, text: "None of their unrighteous deeds are hid from him, but all their sins are before the Lord" },
  { book: "Sirach", chapter: 17, verse: 21, text: "But the Lord being gracious and knowing his workmanship, neither left nor forsook them, but spared them." },
  { book: "Sirach", chapter: 17, verse: 22, text: "The alms of a man is as a signet with him, and he will keep the good deeds of man as the apple of the eye, and give repentance to his sons and daughters." },
  { book: "Sirach", chapter: 17, verse: 23, text: "Afterwards he will rise up and reward them, and render their recompence upon their heads." },
  { book: "Sirach", chapter: 17, verse: 24, text: "But unto them that repent, he granted them return, and comforted those that failed in patience." },
  { book: "Sirach", chapter: 17, verse: 25, text: "Return unto the Lord, and forsake thy sins, make thy prayer before his face, and offend less." },
  { book: "Sirach", chapter: 17, verse: 26, text: "Turn again to the most High, and turn away from iniquity: for he will lead thee out of darkness into the light of health, and hate thou abomination vehemently." },
  { book: "Sirach", chapter: 17, verse: 27, text: "Who shall praise the most High in the grave, instead of them which live and give thanks?" },
  { book: "Sirach", chapter: 17, verse: 28, text: "Thanksgiving perisheth from the dead, as from one that is not: the living and sound in heart shall praise the Lord." },
  { book: "Sirach", chapter: 17, verse: 29, text: "How great is the lovingkindness of the Lord our God, and his compassion unto such as turn unto him in holiness!" },
  { book: "Sirach", chapter: 17, verse: 30, text: "For all things cannot be in men, because the son of man is not immortal." },
  { book: "Sirach", chapter: 17, verse: 31, text: "What is brighter than the sun? yet the light thereof faileth; and flesh and blood will imagine evil." },
  { book: "Sirach", chapter: 17, verse: 32, text: "He vieweth the power of the height of heaven; and all men are but earth and ashes." },
  { book: "Sirach", chapter: 18, verse: 1, text: "He that liveth for ever Hath created all things in general." },
  { book: "Sirach", chapter: 18, verse: 2, text: "The Lord only is righteous, and there is none other but he," },
  { book: "Sirach", chapter: 18, verse: 3, text: "Who governeth the world with the palm of his hand, and all things obey his will: for he is the King of all, by his power dividing holy things among them from profane." },
  { book: "Sirach", chapter: 18, verse: 4, text: "To whom hath he given power to declare his works? and who shall find out his noble acts?" },
  { book: "Sirach", chapter: 18, verse: 5, text: "Who shall number the strength of his majesty? and who shall also tell out his mercies?" },
  { book: "Sirach", chapter: 18, verse: 6, text: "As for the wondrous works of the Lord, there may nothing be taken from them, neither may any thing be put unto them, neither can the ground of them be found out." },
  { book: "Sirach", chapter: 18, verse: 7, text: "When a man hath done, then he beginneth; and when he leaveth off, then he shall be doubtful." },
  { book: "Sirach", chapter: 18, verse: 8, text: "What is man, and whereto serveth he? what is his good, and what is his evil?" },
  { book: "Sirach", chapter: 18, verse: 9, text: "The number of a man’s days at the most are an hundred years." },
  { book: "Sirach", chapter: 18, verse: 10, text: "As a drop of water unto the sea, and a gravelstone in comparison of the sand; so are a thousand years to the days of eternity." },
  { book: "Sirach", chapter: 18, verse: 11, text: "Therefore is God patient with them, and poureth forth his mercy upon them." },
  { book: "Sirach", chapter: 18, verse: 12, text: "He saw and perceived their end to be evil; therefore he multiplied his compassion." },
  { book: "Sirach", chapter: 18, verse: 13, text: "The mercy of man is toward his neighbour; but the mercy of the Lord is upon all flesh: he reproveth, and nurtureth, and teacheth and bringeth again, as a shepherd his flock." },
  { book: "Sirach", chapter: 18, verse: 14, text: "He hath mercy on them that receive discipline, and that diligently seek after his judgments." },
  { book: "Sirach", chapter: 18, verse: 15, text: "My son, blemish not thy good deeds, neither use uncomfortable words when thou givest any thing." },
  { book: "Sirach", chapter: 18, verse: 16, text: "Shall not the dew asswage the heat? so is a word better than a gift." },
  { book: "Sirach", chapter: 18, verse: 17, text: "Lo, is not a word better than a gift? but both are with a gracious man." },
  { book: "Sirach", chapter: 18, verse: 18, text: "A fool will upbraid churlishly, and a gift of the envious consumeth the eyes." },
  { book: "Sirach", chapter: 18, verse: 19, text: "Learn before thou speak, and use physick or ever thou be sick." },
  { book: "Sirach", chapter: 18, verse: 20, text: "Before judgment examine thyself, and in the day of visitation thou shalt find mercy." },
  { book: "Sirach", chapter: 18, verse: 21, text: "Humble thyself before thou be sick, and in the time of sins shew repentance." },
  { book: "Sirach", chapter: 18, verse: 22, text: "Let nothing hinder thee to pay thy vow in due time, and defer not until death to be justified." },
  { book: "Sirach", chapter: 18, verse: 23, text: "Before thou prayest, prepare thyself; and be not as one that tempteth the Lord." },
  { book: "Sirach", chapter: 18, verse: 24, text: "Think upon the wrath that shall be at the end, and the time of vengeance, when he shall turn away his face." },
  { book: "Sirach", chapter: 18, verse: 25, text: "When thou hast enough, remember the time of hunger: and when thou art rich, think upon poverty and need." },
  { book: "Sirach", chapter: 18, verse: 26, text: "From the morning until the evening the time is changed, and all things are soon done before the Lord." },
  { book: "Sirach", chapter: 18, verse: 27, text: "A wise man will fear in every thing, and in the day of sinning he will beware of offence: but a fool will not observe time." },
  { book: "Sirach", chapter: 18, verse: 28, text: "Every man of understanding knoweth wisdom, and will give praise unto him that found her." },
  { book: "Sirach", chapter: 18, verse: 29, text: "They that were of understanding in sayings became also wise themselves, and poured forth exquisite parables." },
  { book: "Sirach", chapter: 18, verse: 30, text: "Go not after thy lusts, but refrain thyself from thine appetites." },
  { book: "Sirach", chapter: 18, verse: 31, text: "If thou givest thy soul the desires that please her, she will make thee a laughingstock to thine enemies that malign thee." },
  { book: "Sirach", chapter: 18, verse: 32, text: "Take not pleasure in much good cheer, neither be tied to the expence thereof." },
  { book: "Sirach", chapter: 18, verse: 33, text: "Be not made a beggar by banqueting upon borrowing, when thou hast nothing in thy purse: for thou shalt lie in wait for thine own life, and be talked on." },
  { book: "Sirach", chapter: 19, verse: 1, text: "A labouring man that A is given to drunkenness shall not be rich: and he that contemneth small things shall fall by little and little." },
  { book: "Sirach", chapter: 19, verse: 2, text: "Wine and women will make men of understanding to fall away: and he that cleaveth to harlots will become impudent." },
  { book: "Sirach", chapter: 19, verse: 3, text: "Moths and worms shall have him to heritage, and a bold man shall be taken away." },
  { book: "Sirach", chapter: 19, verse: 4, text: "He that is hasty to give credit is lightminded; and he that sinneth shall offend against his own soul." },
  { book: "Sirach", chapter: 19, verse: 5, text: "Whoso taketh pleasure in wickedness shall be condemned: but he that resisteth pleasures crowneth his life." },
  { book: "Sirach", chapter: 19, verse: 6, text: "He that can rule his tongue shall live without strife; and he that hateth babbling shall have less evil." },
  { book: "Sirach", chapter: 19, verse: 7, text: "Rehearse not unto another that which is told unto thee, and thou shalt fare never the worse." },
  { book: "Sirach", chapter: 19, verse: 8, text: "Whether it be to friend or foe, talk not of other men’s lives; and if thou canst without offence, reveal them not." },
  { book: "Sirach", chapter: 19, verse: 9, text: "For he heard and observed thee, and when time cometh he will hate thee." },
  { book: "Sirach", chapter: 19, verse: 10, text: "If thou hast heard a word, let it die with thee; and be bold, it will not burst thee." },
  { book: "Sirach", chapter: 19, verse: 11, text: "A fool travaileth with a word, as a woman in labour of a child." },
  { book: "Sirach", chapter: 19, verse: 12, text: "As an arrow that sticketh in a man’s thigh, so is a word within a fool’s belly." },
  { book: "Sirach", chapter: 19, verse: 13, text: "Admonish a friend, it may be he hath not done it: and if he have done it, that he do it no more." },
  { book: "Sirach", chapter: 19, verse: 14, text: "Admonish thy friend, it may be he hath not said it: and if he have, that he speak it not again." },
  { book: "Sirach", chapter: 19, verse: 15, text: "Admonish a friend: for many times it is a slander, and believe not every tale." },
  { book: "Sirach", chapter: 19, verse: 16, text: "There is one that slippeth in his speech, but not from his heart; and who is he that hath not offended with his tongue?" },
  { book: "Sirach", chapter: 19, verse: 17, text: "Admonish thy neighbour before thou threaten him; and not being angry, give place to the law of the most High." },
  { book: "Sirach", chapter: 19, verse: 18, text: "The fear of the Lord is the first step to be accepted of him, and wisdom obtaineth his love." },
  { book: "Sirach", chapter: 19, verse: 19, text: "The knowledge of the commandments of the Lord is the doctrine of life: and they that do things that please him shall receive the fruit of the tree of immortality." },
  { book: "Sirach", chapter: 19, verse: 20, text: "The fear of the Lord is all wisdom; and in all wisdom is the performance of the law, and the knowledge of his omnipotency." },
  { book: "Sirach", chapter: 19, verse: 21, text: "If a servant say to his master, I will not do as it pleaseth thee; though afterward he do it, he angereth him that nourisheth him." },
  { book: "Sirach", chapter: 19, verse: 22, text: "The knowledge of wickedness is not wisdom, neither at any time the counsel of sinners prudence." },
  { book: "Sirach", chapter: 19, verse: 23, text: "There is a wickedness, and the same an abomination; and there is a fool wanting in wisdom." },
  { book: "Sirach", chapter: 19, verse: 24, text: "He that hath small understanding, and feareth God, is better than one that hath much wisdom, and transgresseth the law of the most High." },
  { book: "Sirach", chapter: 19, verse: 25, text: "There is an exquisite subtilty, and the same is unjust; and there is one that turneth aside to make judgment appear; and there is a wise man that justifieth in judgment." },
  { book: "Sirach", chapter: 19, verse: 26, text: "There is a wicked man that hangeth down his head sadly; but inwardly he is full of deceit," },
  { book: "Sirach", chapter: 19, verse: 27, text: "Casting down his countenance, and making as if he heard not: where he is not known, he will do thee a mischief before thou be aware." },
  { book: "Sirach", chapter: 19, verse: 28, text: "And if for want of power he be hindered from sinning, yet when he findeth opportunity he will do evil." },
  { book: "Sirach", chapter: 19, verse: 29, text: "A man may be known by his look, and one that hath understanding by his countenance, when thou meetest him." },
  { book: "Sirach", chapter: 19, verse: 30, text: "A man’s attire, and excessive laughter, and gait, shew what he is." },
  { book: "Sirach", chapter: 20, verse: 1, text: "There is a reproof that is not comely: again, some man holdeth his tongue, and he is wise." },
  { book: "Sirach", chapter: 20, verse: 2, text: "It is much better to reprove, than to be angry secretly: and he that confesseth his fault shall be preserved from hurt." },
  { book: "Sirach", chapter: 20, verse: 3, text: "How good is it, when thou art reproved, to shew repentance! for so shalt thou escape wilful sin." },
  { book: "Sirach", chapter: 20, verse: 4, text: "As is the lust of an eunuch to deflower a virgin; so is he that executeth judgment with violence." },
  { book: "Sirach", chapter: 20, verse: 5, text: "There is one that keepeth silence, and is found wise: and another by much babbling becometh hateful." },
  { book: "Sirach", chapter: 20, verse: 6, text: "Some man holdeth his tongue, because he hath not to answer: and some keepeth silence, knowing his time." },
  { book: "Sirach", chapter: 20, verse: 7, text: "A wise man will hold his tongue till he see opportunity: but a babbler and a fool will regard no time." },
  { book: "Sirach", chapter: 20, verse: 8, text: "He that useth many words shall be abhorred; and he that taketh to himself authority therein shall be hated." },
  { book: "Sirach", chapter: 20, verse: 9, text: "There is a sinner that hath good success in evil things; and there is a gain that turneth to loss." },
  { book: "Sirach", chapter: 20, verse: 10, text: "There is a gift that shall not profit thee; and there is a gift whose recompence is double." },
  { book: "Sirach", chapter: 20, verse: 11, text: "There is an abasement because of glory; and there is that lifteth up his head from a low estate." },
  { book: "Sirach", chapter: 20, verse: 12, text: "There is that buyeth much for a little, and repayeth it sevenfold." },
  { book: "Sirach", chapter: 20, verse: 13, text: "A wise man by his words maketh him beloved: but the graces of fools shall be poured out." },
  { book: "Sirach", chapter: 20, verse: 14, text: "The gift of a fool shall do thee no good when thou hast it; neither yet of the envious for his necessity: for he looketh to receive many things for one." },
  { book: "Sirach", chapter: 20, verse: 15, text: "He giveth little, and upbraideth much; he openeth his mouth like a crier; to day he lendeth, and to morrow will he ask it again: such an one is to be hated of God and man." },
  { book: "Sirach", chapter: 20, verse: 16, text: "The fool saith, I have no friends, I have no thank for all my good deeds, and they that eat my bread speak evil of me." },
  { book: "Sirach", chapter: 20, verse: 17, text: "How oft, and of how many shall he be laughed to scorn! for he knoweth not aright what it is to have; and it is all one unto him as if he had it not." },
  { book: "Sirach", chapter: 20, verse: 18, text: "To slip upon a pavement is better than to slip with the tongue: so the fall of the wicked shall come speedily." },
  { book: "Sirach", chapter: 20, verse: 19, text: "An unseasonable tale will always be in the mouth of the unwise." },
  { book: "Sirach", chapter: 20, verse: 20, text: "A wise sentence shall be rejected when it cometh out of a fool’s mouth; for he will not speak it in due season." },
  { book: "Sirach", chapter: 20, verse: 21, text: "There is that is hindered from sinning through want: and when he taketh rest, he shall not be troubled." },
  { book: "Sirach", chapter: 20, verse: 22, text: "There is that destroyeth his own soul through bashfulness, and by accepting of persons overthroweth himself." },
  { book: "Sirach", chapter: 20, verse: 23, text: "There is that for bashfulness promiseth to his friend, and maketh him his enemy for nothing." },
  { book: "Sirach", chapter: 20, verse: 24, text: "A lie is a foul blot in a man, yet it is continually in the mouth of the untaught." },
  { book: "Sirach", chapter: 20, verse: 25, text: "A thief is better than a man that is accustomed to lie: but they both shall have destruction to heritage." },
  { book: "Sirach", chapter: 20, verse: 26, text: "The disposition of a liar is dishonourable, and his shame is ever with him." },
  { book: "Sirach", chapter: 20, verse: 27, text: "A wise man shall promote himself to honour with his words: and he that hath understanding will please great men." },
  { book: "Sirach", chapter: 20, verse: 28, text: "He that tilleth his land shall increase his heap: and he that pleaseth great men shall get pardon for iniquity." },
  { book: "Sirach", chapter: 20, verse: 29, text: "Presents and gifts blind the eyes of the wise, and stop up his mouth that he cannot reprove." },
  { book: "Sirach", chapter: 20, verse: 30, text: "Wisdom that is hid, and treasure that is hoarded up, what profit is in them both?" },
  { book: "Sirach", chapter: 20, verse: 31, text: "Better is he that hideth his folly than a man that hideth his wisdom." },
  { book: "Sirach", chapter: 20, verse: 32, text: "Necessary patience in seeking the Lord is better than he that leadeth his life without a guide." },
  { book: "Sirach", chapter: 21, verse: 1, text: "My son, hast thou sinned? do so no more, but ask pardon for thy former sins." },
  { book: "Sirach", chapter: 21, verse: 2, text: "Flee from sin as from the face of a serpent: for if thou comest too near it, it will bite thee: the teeth thereof are as the teeth of a lion, slaying the souls of men." },
  { book: "Sirach", chapter: 21, verse: 3, text: "All iniquity is as a two edged sword, the wounds whereof cannot be healed." },
  { book: "Sirach", chapter: 21, verse: 4, text: "To terrify and do wrong will waste riches: thus the house of proud men shall be made desolate." },
  { book: "Sirach", chapter: 21, verse: 5, text: "A prayer out of a poor man’s mouth reacheth to the ears of God, and his judgment cometh speedily." },
  { book: "Sirach", chapter: 21, verse: 6, text: "He that hateth to be reproved is in the way of sinners: but he that feareth the Lord will repent from his heart." },
  { book: "Sirach", chapter: 21, verse: 7, text: "An eloquent man is known far and near; but a man of understanding knoweth when he slippeth." },
  { book: "Sirach", chapter: 21, verse: 8, text: "He that buildeth his house with other men’s money is like one that gathereth himself stones for the tomb of his burial." },
  { book: "Sirach", chapter: 21, verse: 9, text: "The congregation of the wicked is like tow wrapped together: and the end of them is a flame of fire to destroy them." },
  { book: "Sirach", chapter: 21, verse: 10, text: "The way of sinners is made plain with stones, but at the end thereof is the pit of hell." },
  { book: "Sirach", chapter: 21, verse: 11, text: "He that keepeth the law of the Lord getteth the understanding thereof: and the perfection of the fear of the Lord is wisdom." },
  { book: "Sirach", chapter: 21, verse: 12, text: "He that is not wise will not be taught: but there is a wisdom which multiplieth bitterness." },
  { book: "Sirach", chapter: 21, verse: 13, text: "The knowledge of a wise man shall abound like a flood: and his counsel is like a pure fountain of life." },
  { book: "Sirach", chapter: 21, verse: 14, text: "The inner parts of a fool are like a broken vessel, and he will hold no knowledge as long as he liveth." },
  { book: "Sirach", chapter: 21, verse: 15, text: "If a skilful man hear a wise word, he will commend it, and add unto it: but as soon as one of no understanding heareth it, it displeaseth him, and he casteth it behind his back." },
  { book: "Sirach", chapter: 21, verse: 16, text: "The talking of a fool is like a burden in the way: but grace shall be found in the lips of the wise." },
  { book: "Sirach", chapter: 21, verse: 17, text: "They enquire at the mouth of the wise man in the congregation, and they shall ponder his words in their heart." },
  { book: "Sirach", chapter: 21, verse: 18, text: "As is a house that is destroyed, so is wisdom to a fool: and the knowledge of the unwise is as talk without sense." },
  { book: "Sirach", chapter: 21, verse: 19, text: "Doctrine unto fools is as fetters on the feet, and like manacles on the right hand." },
  { book: "Sirach", chapter: 21, verse: 20, text: "A fool lifteth up his voice with laughter; but a wise man doth scarce smile a little." },
  { book: "Sirach", chapter: 21, verse: 21, text: "Learning is unto a wise man as an ornament of gold, and like a bracelet upon his right arm." },
  { book: "Sirach", chapter: 21, verse: 22, text: "A foolish man’s foot is soon in his neighbour’s house: but a man of experience is ashamed of him." },
  { book: "Sirach", chapter: 21, verse: 23, text: "A fool will peep in at the door into the house: but he that is well nurtured will stand without." },
  { book: "Sirach", chapter: 21, verse: 24, text: "It is the rudeness of a man to hearken at the door: but a wise man will be grieved with the disgrace." },
  { book: "Sirach", chapter: 21, verse: 25, text: "The lips of talkers will be telling such things as pertain not unto them: but the words of such as have understanding are weighed in the balance." },
  { book: "Sirach", chapter: 21, verse: 26, text: "The heart of fools is in their mouth: but the mouth of the wise is in their heart." },
  { book: "Sirach", chapter: 21, verse: 27, text: "When the ungodly curseth Satan, he curseth his own soul." },
  { book: "Sirach", chapter: 21, verse: 28, text: "A whisperer defileth his own soul, and is hated wheresoever he dwelleth." },
  { book: "Sirach", chapter: 22, verse: 1, text: "A slothful man is compared to a filthy stone, and every one will hiss him out to his disgrace." },
  { book: "Sirach", chapter: 22, verse: 2, text: "A slothful man is compared to the filth of a dunghill: every man that takes it up will shake his hand." },
  { book: "Sirach", chapter: 22, verse: 3, text: "An evilnurtured man is the dishonour of his father that begat him: and a foolish daughter is born to his loss." },
  { book: "Sirach", chapter: 22, verse: 4, text: "A wise daughter shall bring an inheritance to her husband: but she that liveth dishonestly is her father’s heaviness." },
  { book: "Sirach", chapter: 22, verse: 5, text: "She that is bold dishonoureth both her father and her husband, but they both shall despise her." },
  { book: "Sirach", chapter: 22, verse: 6, text: "A tale out of season is as musick in mourning: but stripes and correction of wisdom are never out of time." },
  { book: "Sirach", chapter: 22, verse: 7, text: "Whoso teacheth a fool is as one that glueth a potsherd together, and as he that waketh one from a sound sleep." },
  { book: "Sirach", chapter: 22, verse: 8, text: "He that telleth a tale to a fool speaketh to one in a slumber: when he hath told his tale, he will say, What is the matter?" },
  { book: "Sirach", chapter: 22, verse: 9, text: "If children live honestly, and have wherewithal, they shall cover the baseness of their parents." },
  { book: "Sirach", chapter: 22, verse: 10, text: "But children, being haughty, through disdain and want of nurture do stain the nobility of their kindred." },
  { book: "Sirach", chapter: 22, verse: 11, text: "Weep for the dead, for he hath lost the light: and weep for the fool, for he wanteth understanding: make little weeping for the dead, for he is at rest: but the life of the fool is worse than death." },
  { book: "Sirach", chapter: 22, verse: 12, text: "Seven days do men mourn for him that is dead; but for a fool and an ungodly man all the days of his life." },
  { book: "Sirach", chapter: 22, verse: 13, text: "Talk not much with a fool, and go not to him that hath no understanding: beware of him, lest thou have trouble, and thou shalt never be defiled with his fooleries: depart from him, and thou shalt find rest, and never be disquieted with madness." },
  { book: "Sirach", chapter: 22, verse: 14, text: "What is heavier than lead? and what is the name thereof, but a fool?" },
  { book: "Sirach", chapter: 22, verse: 15, text: "Sand, and salt, and a mass of iron, is easier to bear, than a man without understanding." },
  { book: "Sirach", chapter: 22, verse: 16, text: "As timber girt and bound together in a building cannot be loosed with shaking: so the heart that is stablished by advised counsel shall fear at no time." },
  { book: "Sirach", chapter: 22, verse: 17, text: "A heart settled upon a thought of understanding is as a fair plaistering on the wall of a gallery." },
  { book: "Sirach", chapter: 22, verse: 18, text: "Pales set on an high place will never stand against the wind: so a fearful heart in the imagination of a fool cannot stand against any fear." },
  { book: "Sirach", chapter: 22, verse: 19, text: "He that pricketh the eye will make tears to fall: and he that pricketh the heart maketh it to shew her knowledge." },
  { book: "Sirach", chapter: 22, verse: 20, text: "Whoso casteth a stone at the birds frayeth them away: and he that upbraideth his friend breaketh friendship." },
  { book: "Sirach", chapter: 22, verse: 21, text: "Though thou drewest a sword at thy friend, yet despair not: for there may be a returning to favour." },
  { book: "Sirach", chapter: 22, verse: 22, text: "If thou hast opened thy mouth against thy friend, fear not; for there may be a reconciliation: except for upbraiding, or pride, or disclosing of secrets, or a treacherous wound: for for these things every friend will depart." },
  { book: "Sirach", chapter: 22, verse: 23, text: "Be faithful to thy neighbour in his poverty, that thou mayest rejoice in his prosperity: abide stedfast unto him in the time of his trouble, that thou mayest be heir with him in his heritage: for a mean estate is not always to be contemned: nor the rich that is foolish to be had in admiration." },
  { book: "Sirach", chapter: 22, verse: 24, text: "As the vapour and smoke of a furnace goeth before the fire; so reviling before blood." },
  { book: "Sirach", chapter: 22, verse: 25, text: "I will not be ashamed to defend a friend; neither will I hide myself from him." },
  { book: "Sirach", chapter: 22, verse: 26, text: "And if any evil happen unto me by him, every one that heareth it will beware of him." },
  { book: "Sirach", chapter: 22, verse: 27, text: "Who shall set a watch before my mouth, and a seal of wisdom upon my lips, that I fall not suddenly by them, and that my tongue destroy me not?" },
  { book: "Sirach", chapter: 23, verse: 1, text: "O Lord, Father and Governor of all my whole life, leave me not to their counsels, and let me not fall by them." },
  { book: "Sirach", chapter: 23, verse: 2, text: "Who will set scourges over my thoughts, and the discipline of wisdom over mine heart? that they spare me not for mine ignorances, and it pass not by my sins:" },
  { book: "Sirach", chapter: 23, verse: 3, text: "Lest mine ignorances increase, and my sins abound to my destruction, and I fall before mine adversaries, and mine enemy rejoice over me, whose hope is far from thy mercy." },
  { book: "Sirach", chapter: 23, verse: 4, text: "O Lord, Father and God of my life, give me not a proud look, but turn away from thy servants always a haughty mind." },
  { book: "Sirach", chapter: 23, verse: 5, text: "Turn away from me vain hopes and concupiscence, and thou shalt hold him up that is desirous always to serve thee." },
  { book: "Sirach", chapter: 23, verse: 6, text: "Let not the greediness of the belly nor lust of the flesh take hold of me; and give not over me thy servant into an impudent mind." },
  { book: "Sirach", chapter: 23, verse: 7, text: "Hear, O ye children, the discipline of the mouth: he that keepeth it shall never be taken in his lips." },
  { book: "Sirach", chapter: 23, verse: 8, text: "The sinner shall be left in his foolishness: both the evil speaker and the proud shall fall thereby." },
  { book: "Sirach", chapter: 23, verse: 9, text: "Accustom not thy mouth to swearing; neither use thyself to the naming of the Holy One." },
  { book: "Sirach", chapter: 23, verse: 10, text: "For as a servant that is continually beaten shall not be without a blue mark: so he that sweareth and nameth God continually shall not be faultless." },
  { book: "Sirach", chapter: 23, verse: 11, text: "A man that useth much swearing shall be filled with iniquity, and the plague shall never depart from his house: if he shall offend, his sin shall be upon him: and if he acknowledge not his sin, he maketh a double offence: and if he swear in vain, he shall not be innocent, but his house shall be full of calamities." },
  { book: "Sirach", chapter: 23, verse: 12, text: "There is a word that is clothed about with death: God grant that it be not found in the heritage of Jacob; for all such things shall be far from the godly, and they shall not wallow in their sins." },
  { book: "Sirach", chapter: 23, verse: 13, text: "Use not thy mouth to intemperate swearing, for therein is the word of sin." },
  { book: "Sirach", chapter: 23, verse: 14, text: "Remember thy father and thy mother, when thou sittest among great men. Be not forgetful before them, and so thou by thy custom become a fool, and wish that thou hadst not been born, and curse they day of thy nativity." },
  { book: "Sirach", chapter: 23, verse: 15, text: "The man that is accustomed to opprobrious words will never be reformed all the days of his life." },
  { book: "Sirach", chapter: 23, verse: 16, text: "Two sorts of men multiply sin, and the third will bring wrath: a hot mind is as a burning fire, it will never be quenched till it be consumed: a fornicator in the body of his flesh will never cease till he hath kindled a fire." },
  { book: "Sirach", chapter: 23, verse: 17, text: "All bread is sweet to a whoremonger, he will not leave off till he die." },
  { book: "Sirach", chapter: 23, verse: 18, text: "A man that breaketh wedlock, saying thus in his heart, Who seeth me? I am compassed about with darkness, the walls cover me, and no body seeth me; what need I to fear? the most High will not remember my sins:" },
  { book: "Sirach", chapter: 23, verse: 19, text: "Such a man only feareth the eyes of men, and knoweth not that the eyes of the Lord are ten thousand times brighter than the sun, beholding all the ways of men, and considering the most secret parts." },
  { book: "Sirach", chapter: 23, verse: 20, text: "He knew all things ere ever they were created; so also after they were perfected he looked upon them all." },
  { book: "Sirach", chapter: 23, verse: 21, text: "This man shall be punished in the streets of the city, and where he suspecteth not he shall be taken." },
  { book: "Sirach", chapter: 23, verse: 22, text: "Thus shall it go also with the wife that leaveth her husband, and bringeth in an heir by another." },
  { book: "Sirach", chapter: 23, verse: 23, text: "For first, she hath disobeyed the law of the most High; and secondly, she hath trespassed against her own husband; and thirdly, she hath played the whore in adultery, and brought children by another man." },
  { book: "Sirach", chapter: 23, verse: 24, text: "She shall be brought out into the congregation, and inquisition shall be made of her children." },
  { book: "Sirach", chapter: 23, verse: 25, text: "Her children shall not take root, and her branches shall bring forth no fruit." },
  { book: "Sirach", chapter: 23, verse: 26, text: "She shall leave her memory to be cursed, and her reproach shall not be blotted out." },
  { book: "Sirach", chapter: 23, verse: 27, text: "And they that remain shall know that there is nothing better than the fear of the Lord, and that there is nothing sweeter than to take heed unto the commandments of the Lord." },
  { book: "Sirach", chapter: 23, verse: 28, text: "It is great glory to follow the Lord, and to be received of him is long life." },
  { book: "Sirach", chapter: 24, verse: 1, text: "Wisdom shall praise herself, and shall glory in the midst of her people." },
  { book: "Sirach", chapter: 24, verse: 2, text: "In the congregation of the most High shall she open her mouth, and triumph before his power." },
  { book: "Sirach", chapter: 24, verse: 3, text: "I came out of the mouth of the most High, and covered the earth as a cloud." },
  { book: "Sirach", chapter: 24, verse: 4, text: "I dwelt in high places, and my throne is in a cloudy pillar." },
  { book: "Sirach", chapter: 24, verse: 5, text: "I alone compassed the circuit of heaven, and walked in the bottom of the deep." },
  { book: "Sirach", chapter: 24, verse: 6, text: "In the waves of the sea and in all the earth, and in every people and nation, I got a possession." },
  { book: "Sirach", chapter: 24, verse: 7, text: "With all these I sought rest: and in whose inheritance shall I abide?" },
  { book: "Sirach", chapter: 24, verse: 8, text: "So the Creator of all things gave me a commandment, and he that made me caused my tabernacle to rest, and said, Let thy dwelling be in Jacob, and thine inheritance in Israel." },
  { book: "Sirach", chapter: 24, verse: 9, text: "He created me from the beginning before the world, and I shall never fail." },
  { book: "Sirach", chapter: 24, verse: 10, text: "In the holy tabernacle I served before him; and so was I established in Sion." },
  { book: "Sirach", chapter: 24, verse: 11, text: "Likewise in the beloved city he gave me rest, and in Jerusalem was my power." },
  { book: "Sirach", chapter: 24, verse: 12, text: "And I took root in an honourable people, even in the portion of the Lord’s inheritance." },
  { book: "Sirach", chapter: 24, verse: 13, text: "I was exalted like a cedar in Libanus, and as a cypress tree upon the mountains of Hermon." },
  { book: "Sirach", chapter: 24, verse: 14, text: "I was exalted like a palm tree in En-gaddi, and as a rose plant in Jericho, as a fair olive tree in a pleasant field, and grew up as a plane tree by the water." },
  { book: "Sirach", chapter: 24, verse: 15, text: "I gave a sweet smell like cinnamon and aspalathus, and I yielded a pleasant odour like the best myrrh, as galbanum, and onyx, and sweet storax, and as the fume of frankincense in the tabernacle." },
  { book: "Sirach", chapter: 24, verse: 16, text: "As the turpentine tree I stretched out my branches, and my branches are the branches of honour and grace." },
  { book: "Sirach", chapter: 24, verse: 17, text: "As the vine brought I forth pleasant savour, and my flowers are the fruit of honour and riches." },
  { book: "Sirach", chapter: 24, verse: 18, text: "I am the mother of fair love, and fear, and knowledge, and holy hope: I therefore, being eternal, am given to all my children which are named of him." },
  { book: "Sirach", chapter: 24, verse: 19, text: "Come unto me, all ye that be desirous of me, and fill yourselves with my fruits." },
  { book: "Sirach", chapter: 24, verse: 20, text: "For my memorial is sweeter than honey, and mine inheritance than the honeycomb." },
  { book: "Sirach", chapter: 24, verse: 21, text: "They that eat me shall yet be hungry, and they that drink me shall yet be thirsty." },
  { book: "Sirach", chapter: 24, verse: 22, text: "He that obeyeth me shall never be confounded, and they that work by me shall not do amiss." },
  { book: "Sirach", chapter: 24, verse: 23, text: "All these things are the book of the covenant of the most high God, even the law which Moses commanded for an heritage unto the congregations of Jacob." },
  { book: "Sirach", chapter: 24, verse: 24, text: "Faint not to be strong in the Lord; that he may confirm you, cleave unto him: for the Lord Almighty is God alone, and beside him there is no other Saviour." },
  { book: "Sirach", chapter: 24, verse: 25, text: "He filleth all things with his wisdom, as Phison and as Tigris in the time of the new fruits." },
  { book: "Sirach", chapter: 24, verse: 26, text: "He maketh the understanding to abound like Euphrates, and as Jordan in the time of the harvest." },
  { book: "Sirach", chapter: 24, verse: 27, text: "He maketh the doctrine of knowledge appear as the light, and as Geon in the time of vintage." },
  { book: "Sirach", chapter: 24, verse: 28, text: "The first man knew her not perfectly: no more shall the last find her out." },
  { book: "Sirach", chapter: 24, verse: 29, text: "For her thoughts are more than the sea, and her counsels profounder than the great deep." },
  { book: "Sirach", chapter: 24, verse: 30, text: "I also came out as a brook from a river, and as a conduit into a garden." },
  { book: "Sirach", chapter: 24, verse: 31, text: "I said, I will water my best garden, and will water abundantly my garden bed: and, lo, my brook became a river, and my river became a sea." },
  { book: "Sirach", chapter: 24, verse: 32, text: "I will yet make doctrine to shine as the morning, and will send forth her light afar off." },
  { book: "Sirach", chapter: 24, verse: 33, text: "I will yet pour out doctrine as prophecy, and leave it to all ages for ever." },
  { book: "Sirach", chapter: 24, verse: 34, text: "Behold that I have not laboured for myself only, but for all them that seek wisdom." },
  { book: "Sirach", chapter: 25, verse: 1, text: "In three things I was beautified, and stood up beautiful both before God and men: the unity of brethren, the love of neighbours, a man and a wife that agree together." },
  { book: "Sirach", chapter: 25, verse: 2, text: "Three sorts of men my soul hateth, and I am greatly offended at their life: a poor man that is proud, a rich man that is a liar, and an old adulterer that doateth." },
  { book: "Sirach", chapter: 25, verse: 3, text: "If thou hast gathered nothing in thy youth, how canst thou find any thing in thine age?" },
  { book: "Sirach", chapter: 25, verse: 4, text: "O how comely a thing is judgment for gray hairs, and for ancient men to know counsel!" },
  { book: "Sirach", chapter: 25, verse: 5, text: "O how comely is the wisdom of old men, and understanding and counsel to men of honour." },
  { book: "Sirach", chapter: 25, verse: 6, text: "Much experience is the crown of old men, and the fear of God is their glory." },
  { book: "Sirach", chapter: 25, verse: 7, text: "There be nine things which I have judged in mine heart to be happy, and the tenth I will utter with my tongue: A man that hath joy of his children; and he that liveth to see the fall of his enemy:" },
  { book: "Sirach", chapter: 25, verse: 8, text: "Well is him that dwelleth with a wife of understanding, and that hath not slipped with his tongue, and that hath not served a man more unworthy than himself:" },
  { book: "Sirach", chapter: 25, verse: 9, text: "Well is him that hath found prudence, and he that speaketh in the ears of them that will hear:" },
  { book: "Sirach", chapter: 25, verse: 10, text: "O how great is he that findeth wisdom! yet is there none above him that feareth the Lord." },
  { book: "Sirach", chapter: 25, verse: 11, text: "But the love of the Lord passeth all things for illumination: he that holdeth it, whereto shall he be likened?" },
  { book: "Sirach", chapter: 25, verse: 12, text: "The fear of the Lord is the beginning of his love: and faith is the beginning of cleaving unto him." },
  { book: "Sirach", chapter: 25, verse: 13, text: "Give me any plague, but the plague of the heart: and any wickedness, but the wickedness of a woman:" },
  { book: "Sirach", chapter: 25, verse: 14, text: "And any affliction, but the affliction from them that hate me: and any revenge, but the revenge of enemies." },
  { book: "Sirach", chapter: 25, verse: 15, text: "There is no head above the head of a serpent; and there is no wrath above the wrath of an enemy." },
  { book: "Sirach", chapter: 25, verse: 16, text: "I had rather dwell with a lion and a dragon, than to keep house with a wicked woman." },
  { book: "Sirach", chapter: 25, verse: 17, text: "The wickedness of a woman changeth her face, and darkeneth her countenance like sackcloth." },
  { book: "Sirach", chapter: 25, verse: 18, text: "Her husband shall sit among his neighbours; and when he heareth it shall sigh bitterly." },
  { book: "Sirach", chapter: 25, verse: 19, text: "All wickedness is but little to the wickedness of a woman: let the portion of a sinner fall upon her." },
  { book: "Sirach", chapter: 25, verse: 20, text: "As the climbing up a sandy way is to the feet of the aged, so is a wife full of words to a quiet man." },
  { book: "Sirach", chapter: 25, verse: 21, text: "Stumble not at the beauty of a woman, and desire her not for pleasure." },
  { book: "Sirach", chapter: 25, verse: 22, text: "A woman, if she maintain her husband, is full of anger, impudence, and much reproach." },
  { book: "Sirach", chapter: 25, verse: 23, text: "A wicked woman abateth the courage, maketh an heavy countenance and a wounded heart: a woman that will not comfort her husband in distress maketh weak hands and feeble knees." },
  { book: "Sirach", chapter: 25, verse: 24, text: "Of the woman came the beginning of sin, and through her we all die." },
  { book: "Sirach", chapter: 25, verse: 25, text: "Give the water no passage; neither a wicked woman liberty to gad abroad." },
  { book: "Sirach", chapter: 25, verse: 26, text: "If she go not as thou wouldest have her, cut her off from thy flesh, and give her a bill of divorce, and let her go." },
  { book: "Sirach", chapter: 26, verse: 1, text: "Blessed is the man that hath a virtuous wife, for the number of his days shall be double." },
  { book: "Sirach", chapter: 26, verse: 2, text: "A virtuous woman rejoiceth her husband, and he shall fulfil the years of his life in peace." },
  { book: "Sirach", chapter: 26, verse: 3, text: "A good wife is a good portion, which shall be given in the portion of them that fear the Lord." },
  { book: "Sirach", chapter: 26, verse: 4, text: "Whether a man be rich or poor, if he have a good heart toward the Lord, he shall at all times rejoice with a cheerful countenance." },
  { book: "Sirach", chapter: 26, verse: 5, text: "There be three things that mine heart feareth; and for the fourth I was sore afraid: the slander of a city, the gathering together of an unruly multitude, and a false accusation: all these are worse than death." },
  { book: "Sirach", chapter: 26, verse: 6, text: "But a grief of heart and sorrow is a woman that is jealous over another woman, and a scourge of the tongue which communicateth with all." },
  { book: "Sirach", chapter: 26, verse: 7, text: "An evil wife is a yoke shaken to and fro: he that hath hold of her is as though he held a scorpion." },
  { book: "Sirach", chapter: 26, verse: 8, text: "A drunken woman and a gadder abroad causeth great anger, and she will not cover her own shame." },
  { book: "Sirach", chapter: 26, verse: 9, text: "The whoredom of a woman may be known in her haughty looks and eyelids." },
  { book: "Sirach", chapter: 26, verse: 10, text: "If thy daughter be shameless, keep her in straitly, lest she abuse herself through overmuch liberty." },
  { book: "Sirach", chapter: 26, verse: 11, text: "Watch over an impudent eye: and marvel not if she trespass against thee." },
  { book: "Sirach", chapter: 26, verse: 12, text: "She will open her mouth, as a thirsty traveller when he hath found a fountain, and drink of every water near her: by every hedge will she sit down, and open her quiver against every arrow." },
  { book: "Sirach", chapter: 26, verse: 13, text: "The grace of a wife delighteth her husband, and her discretion will fatten his bones." },
  { book: "Sirach", chapter: 26, verse: 14, text: "A silent and loving woman is a gift of the Lord; and there is nothing so much worth as a mind well instructed." },
  { book: "Sirach", chapter: 26, verse: 15, text: "A shamefaced and faithful woman is a double grace, and her continent mind cannot be valued." },
  { book: "Sirach", chapter: 26, verse: 16, text: "As the sun when it ariseth in the high heaven; so is the beauty of a good wife in the ordering of her house." },
  { book: "Sirach", chapter: 26, verse: 17, text: "As the clear light is upon the holy candlestick; so is the beauty of the face in ripe age." },
  { book: "Sirach", chapter: 26, verse: 18, text: "As the golden pillars are upon the sockets of silver; so are the fair feet with a constant heart." },
  { book: "Sirach", chapter: 26, verse: 19, text: "My son, keep the flower of thine age sound; and give not thy strength to strangers." },
  { book: "Sirach", chapter: 26, verse: 20, text: "When thou hast gotten a fruitful possession through all the field, sow it with thine own seed, trusting in the goodness of thy stock." },
  { book: "Sirach", chapter: 26, verse: 21, text: "So thy race which thou leavest shall be magnified, having the confidence of their good descent." },
  { book: "Sirach", chapter: 26, verse: 22, text: "An harlot shall be accounted as spittle; but a married woman is a tower against death to her husband." },
  { book: "Sirach", chapter: 26, verse: 23, text: "A wicked woman is given as a portion to a wicked man: but a godly woman is given to him that feareth the Lord." },
  { book: "Sirach", chapter: 26, verse: 24, text: "A dishonest woman contemneth shame: but an honest woman will reverence her husband." },
  { book: "Sirach", chapter: 26, verse: 25, text: "A shameless woman shall be counted as a dog; but she that is shamefaced will fear the Lord." },
  { book: "Sirach", chapter: 26, verse: 26, text: "A woman that honoureth her husband shall be judged wise of all; but she that dishonoureth him in her pride shall be counted ungodly of all." },
  { book: "Sirach", chapter: 26, verse: 27, text: "A loud crying woman and a scold shall be sought out to drive away the enemies." },
  { book: "Sirach", chapter: 26, verse: 28, text: "There be two things that grieve my heart; and the third maketh me angry: a man of war that suffereth poverty; and men of understanding that are not set by; and one that returneth from righteousness to sin; the Lord prepareth such an one for the sword." },
  { book: "Sirach", chapter: 26, verse: 29, text: "A merchant shall hardly keep himself from doing wrong; and an huckster shall not be freed from sin." },
  { book: "Sirach", chapter: 27, verse: 1, text: "Many have sinned for a small matter; and he that seeketh for abundance will turn his eyes away." },
  { book: "Sirach", chapter: 27, verse: 2, text: "As a nail sticketh fast between the joinings of the stones; so doth sin stick close between buying and selling." },
  { book: "Sirach", chapter: 27, verse: 3, text: "Unless a man hold himself diligently in the fear of the Lord, his house shall soon be overthrown." },
  { book: "Sirach", chapter: 27, verse: 4, text: "As when one sifteth with a sieve, the refuse remaineth; so the filth of man in his talk." },
  { book: "Sirach", chapter: 27, verse: 5, text: "The furnace proveth the potter’s vessels; so the trial of man is in his reasoning." },
  { book: "Sirach", chapter: 27, verse: 6, text: "The fruit declareth if the tree have been dressed; so is the utterance of a conceit in the heart of man." },
  { book: "Sirach", chapter: 27, verse: 7, text: "Praise no man before thou hearest him speak; for this is the trial of men." },
  { book: "Sirach", chapter: 27, verse: 8, text: "If thou followest righteousness, thou shalt obtain her, and put her on, as a glorious long robe." },
  { book: "Sirach", chapter: 27, verse: 9, text: "The birds will resort unto their like; so will truth return unto them that practise in her." },
  { book: "Sirach", chapter: 27, verse: 10, text: "As the lion lieth in wait for the prey; so sin for them that work iniquity." },
  { book: "Sirach", chapter: 27, verse: 11, text: "The discourse of a godly man is always with wisdom; but a fool changeth as the moon." },
  { book: "Sirach", chapter: 27, verse: 12, text: "If thou be among the indiscreet, observe the time; but be continually among men of understanding." },
  { book: "Sirach", chapter: 27, verse: 13, text: "The discourse of fools is irksome, and their sport is the wantonness of sin." },
  { book: "Sirach", chapter: 27, verse: 14, text: "The talk of him that sweareth much maketh the hair stand upright; and their brawls make one stop his ears." },
  { book: "Sirach", chapter: 27, verse: 15, text: "The strife of the proud is bloodshedding, and their revilings are grievous to the ear." },
  { book: "Sirach", chapter: 27, verse: 16, text: "Whoso discovereth secrets loseth his credit; and shall never find friend to his mind." },
  { book: "Sirach", chapter: 27, verse: 17, text: "Love thy friend, and be faithful unto him: but if thou betrayest his secrets, follow no more after him." },
  { book: "Sirach", chapter: 27, verse: 18, text: "For as a man hath destroyed his enemy; so hast thou lost the love of thy neighbor." },
  { book: "Sirach", chapter: 27, verse: 19, text: "As one that letteth a bird go out of his hand, so hast thou let thy neighbour go, and shalt not get him again" },
  { book: "Sirach", chapter: 27, verse: 20, text: "Follow after him no more, for he is too far off; he is as a roe escaped out of the snare." },
  { book: "Sirach", chapter: 27, verse: 21, text: "As for a wound, it may be bound up; and after reviling there may be reconcilement: but he that betrayeth secrets is without hope." },
  { book: "Sirach", chapter: 27, verse: 22, text: "He that winketh with the eyes worketh evil: and he that knoweth him will depart from him." },
  { book: "Sirach", chapter: 27, verse: 23, text: "When thou art present, he will speak sweetly, and will admire thy words: but at the last he will writhe his mouth, and slander thy sayings." },
  { book: "Sirach", chapter: 27, verse: 24, text: "I have hated many things, but nothing like him; for the Lord will hate him." },
  { book: "Sirach", chapter: 27, verse: 25, text: "Whoso casteth a stone on high casteth it on his own head; and a deceitful stroke shall make wounds." },
  { book: "Sirach", chapter: 27, verse: 26, text: "Whoso diggeth a pit shall fall therein: and he that setteth a trap shall be taken therein." },
  { book: "Sirach", chapter: 27, verse: 27, text: "He that worketh mischief, it shall fall upon him, and he shall not know whence it cometh." },
  { book: "Sirach", chapter: 27, verse: 28, text: "Mockery and reproach are from the proud; but vengeance, as a lion, shall lie in wait for them." },
  { book: "Sirach", chapter: 27, verse: 29, text: "They that rejoice at the fall of the righteous shall be taken in the snare; and anguish shall consume them before they die." },
  { book: "Sirach", chapter: 27, verse: 30, text: "Malice and wrath, even these are abominations; and the sinful man shall have them both." },
  { book: "Sirach", chapter: 28, verse: 1, text: "He that revengeth shall find vengeance from the Lord, and he will surely keep his sins in remembrance." },
  { book: "Sirach", chapter: 28, verse: 2, text: "Forgive thy neighbour the hurt that he hath done unto thee, so shall thy sins also be forgiven when thou prayest." },
  { book: "Sirach", chapter: 28, verse: 3, text: "One man beareth hatred against another, and doth he seek pardon from the Lord?" },
  { book: "Sirach", chapter: 28, verse: 4, text: "He sheweth no mercy to a man, which is like himself: and doth he ask forgiveness of his own sins?" },
  { book: "Sirach", chapter: 28, verse: 5, text: "If he that is but flesh nourish hatred, who will intreat for pardon of his sins?" },
  { book: "Sirach", chapter: 28, verse: 6, text: "Remember thy end, and let enmity cease; remember corruption and death, and abide in the commandments." },
  { book: "Sirach", chapter: 28, verse: 7, text: "Remember the commandments, and bear no malice to thy neighbour: remember the covenant of the Highest, and wink at ignorance." },
  { book: "Sirach", chapter: 28, verse: 8, text: "Abstain from strife, and thou shalt diminish thy sins: for a furious man will kindle strife," },
  { book: "Sirach", chapter: 28, verse: 9, text: "A sinful man disquieteth friends, and maketh debate among them that be at peace." },
  { book: "Sirach", chapter: 28, verse: 10, text: "As the matter of the fire is, so it burneth: and as a man’s strength is, so is his wrath; and according to his riches his anger riseth; and the stronger they are which contend, the more they will be inflamed." },
  { book: "Sirach", chapter: 28, verse: 11, text: "An hasty contention kindleth a fire: and an hasty fighting sheddeth blood." },
  { book: "Sirach", chapter: 28, verse: 12, text: "If thou blow the spark, it shall burn: if thou spit upon it, it shall be quenched: and both these come out of thy mouth." },
  { book: "Sirach", chapter: 28, verse: 13, text: "Curse the whisperer and doubletongued: for such have destroyed many that were at peace." },
  { book: "Sirach", chapter: 28, verse: 14, text: "A backbiting tongue hath disquieted many, and driven them from nation to nation: strong cities hath it pulled down, and overthrown the houses of great men." },
  { book: "Sirach", chapter: 28, verse: 15, text: "A backbiting tongue hath cast out virtuous women, and deprived them of their labours." },
  { book: "Sirach", chapter: 28, verse: 16, text: "Whoso hearkeneth unto it shall never find rest, and never dwell quietly." },
  { book: "Sirach", chapter: 28, verse: 17, text: "The stroke of the whip maketh marks in the flesh: but the stroke of the tongue breaketh the bones." },
  { book: "Sirach", chapter: 28, verse: 18, text: "Many have fallen by the edge of the sword: but not so many as have fallen by the tongue." },
  { book: "Sirach", chapter: 28, verse: 19, text: "Well is he that is defended through the venom thereof; who hath not drawn the yoke thereof, nor hath been bound in her bands." },
  { book: "Sirach", chapter: 28, verse: 20, text: "For the yoke thereof is a yoke of iron, and the bands thereof are bands of brass." },
  { book: "Sirach", chapter: 28, verse: 21, text: "The death thereof is an evil death, the grave were better than it." },
  { book: "Sirach", chapter: 28, verse: 22, text: "It shall not have rule over them that fear God, neither shall they be burned with the flame thereof." },
  { book: "Sirach", chapter: 28, verse: 23, text: "Such as forsake the Lord shall fall into it; and it shall burn in them, and not be quenched; it shall be sent upon them as a lion, and devour them as a leopard." },
  { book: "Sirach", chapter: 28, verse: 24, text: "Look that thou hedge thy possession about with thorns, and bind up thy silver and gold," },
  { book: "Sirach", chapter: 28, verse: 25, text: "And weigh thy words in a balance, and make a door and bar for thy mouth." },
  { book: "Sirach", chapter: 28, verse: 26, text: "Beware thou slide not by it, lest thou fall before him that lieth in wait." },
  { book: "Sirach", chapter: 29, verse: 1, text: "He that is merciful will lend unto his neighbour; and he that strengtheneth his hand keepeth the commandments." },
  { book: "Sirach", chapter: 29, verse: 2, text: "Lend to thy neighbour in time of his need, and pay thou thy neighbour again in due season." },
  { book: "Sirach", chapter: 29, verse: 3, text: "Keep thy word, and deal faithfully with him, and thou shalt always find the thing that is necessary for thee." },
  { book: "Sirach", chapter: 29, verse: 4, text: "Many, when a thing was lent them, reckoned it to be found, and put them to trouble that helped them." },
  { book: "Sirach", chapter: 29, verse: 5, text: "Till he hath received, he will kiss a man’s hand; and for his neighbour’s money he will speak submissly: but when he should repay, he will prolong the time, and return words of grief, and complain of the time." },
  { book: "Sirach", chapter: 29, verse: 6, text: "If he prevail, he shall hardly receive the half, and he will count as if he had found it: if not, he hath deprived him of his money, and he hath gotten him an enemy without cause: he payeth him with cursings and railings; and for honour he will pay him disgrace." },
  { book: "Sirach", chapter: 29, verse: 7, text: "Many therefore have refused to lend for other men’s ill dealing, fearing to be defrauded." },
  { book: "Sirach", chapter: 29, verse: 8, text: "Yet have thou patience with a man in poor estate, and delay not to shew him mercy." },
  { book: "Sirach", chapter: 29, verse: 9, text: "Help the poor for the commandment’s sake, and turn him not away because of his poverty." },
  { book: "Sirach", chapter: 29, verse: 10, text: "Lose thy money for thy brother and thy friend, and let it not rust under a stone to be lost." },
  { book: "Sirach", chapter: 29, verse: 11, text: "Lay up thy treasure according to the commandments of the most High, and it shall bring thee more profit than gold." },
  { book: "Sirach", chapter: 29, verse: 12, text: "Shut up alms in thy storehouses: and it shall deliver thee from all affliction." },
  { book: "Sirach", chapter: 29, verse: 13, text: "It shall fight for thee against thine enemies better than a mighty shield and strong spear." },
  { book: "Sirach", chapter: 29, verse: 14, text: "An honest man is surety for his neighbour: but he that is impudent will forsake him." },
  { book: "Sirach", chapter: 29, verse: 15, text: "Forget not the friendship of thy surety, for he hath given his life for thee." },
  { book: "Sirach", chapter: 29, verse: 16, text: "A sinner will overthrow the good estate of his surety:" },
  { book: "Sirach", chapter: 29, verse: 17, text: "And he that is of an unthankful mind will leave him in danger that delivered him." },
  { book: "Sirach", chapter: 29, verse: 18, text: "Suretiship hath undone many of good estate, and shaken them as a wave of the sea: mighty men hath it driven from their houses, so that they wandered among strange nations." },
  { book: "Sirach", chapter: 29, verse: 19, text: "A wicked man transgressing the commandments of the Lord shall fall into suretiship: and he that undertaketh and followeth other men’s business for gain shall fall into suits." },
  { book: "Sirach", chapter: 29, verse: 20, text: "Help thy neighbour according to thy power, and beware that thou thyself fall not into the same." },
  { book: "Sirach", chapter: 29, verse: 21, text: "The chief thing for life is water, and bread, and clothing, and an house to cover shame." },
  { book: "Sirach", chapter: 29, verse: 22, text: "Better is the life of a poor man in a mean cottage, than delicate fare in another man’s house." },
  { book: "Sirach", chapter: 29, verse: 23, text: "Be it little or much, hold thee contented, that thou hear not the reproach of thy house." },
  { book: "Sirach", chapter: 29, verse: 24, text: "For it is a miserable life to go from house to house: for where thou art a stranger, thou darest not open thy mouth." },
  { book: "Sirach", chapter: 29, verse: 25, text: "Thou shalt entertain, and feast, and have no thanks: moreover thou shalt hear bitter words:" },
  { book: "Sirach", chapter: 29, verse: 26, text: "Come, thou stranger, and furnish a table, and feed me of that thou hast ready." },
  { book: "Sirach", chapter: 29, verse: 27, text: "Give place, thou stranger, to an honourable man; my brother cometh to be lodged, and I have need of mine house." },
  { book: "Sirach", chapter: 29, verse: 28, text: "These things are grievous to a man of understanding; the upbraiding of houseroom, and reproaching of the lender." },
  { book: "Sirach", chapter: 30, verse: 1, text: "He that loveth his son causeth him oft to feel the rod, that he may have joy of him in the end." },
  { book: "Sirach", chapter: 30, verse: 2, text: "He that chastiseth his son shall have joy in him, and shall rejoice of him among his acquaintance." },
  { book: "Sirach", chapter: 30, verse: 3, text: "He that teacheth his son grieveth the enemy: and before his friends he shall rejoice of him." },
  { book: "Sirach", chapter: 30, verse: 4, text: "Though his father die, yet he is as though he were not dead: for he hath left one behind him that is like himself." },
  { book: "Sirach", chapter: 30, verse: 5, text: "While he lived, he saw and rejoiced in him: and when he died, he was not sorrowful." },
  { book: "Sirach", chapter: 30, verse: 6, text: "He left behind him an avenger against his enemies, and one that shall requite kindness to his friends." },
  { book: "Sirach", chapter: 30, verse: 7, text: "He that maketh too much of his son shall bind up his wounds; and his bowels will be troubled at every cry." },
  { book: "Sirach", chapter: 30, verse: 8, text: "An horse not broken becometh headstrong: and a child left to himself will be wilful." },
  { book: "Sirach", chapter: 30, verse: 9, text: "Cocker thy child, and he shall make thee afraid: play with him, and he will bring thee to heaviness." },
  { book: "Sirach", chapter: 30, verse: 10, text: "Laugh not with him, lest thou have sorrow with him, and lest thou gnash thy teeth in the end." },
  { book: "Sirach", chapter: 30, verse: 11, text: "Give him no liberty in his youth, and wink not at his follies." },
  { book: "Sirach", chapter: 30, verse: 12, text: "Bow down his neck while he is young, and beat him on the sides while he is a child, lest he wax stubborn, and be disobedient unto thee, and so bring sorrow to thine heart." },
  { book: "Sirach", chapter: 30, verse: 13, text: "Chastise thy son, and hold him to labour, lest his lewd behaviour be an offence unto thee." },
  { book: "Sirach", chapter: 30, verse: 14, text: "Better is the poor, being sound and strong of constitution, than a rich man that is afflicted in his body." },
  { book: "Sirach", chapter: 30, verse: 15, text: "Health and good estate of body are above all gold, and a strong body above infinite wealth." },
  { book: "Sirach", chapter: 30, verse: 16, text: "There is no riches above a sound body, and no joy above the joy of the heart." },
  { book: "Sirach", chapter: 30, verse: 17, text: "Death is better than a bitter life or continual sickness." },
  { book: "Sirach", chapter: 30, verse: 18, text: "Delicates poured upon a mouth shut up are as messes of meat set upon a grave." },
  { book: "Sirach", chapter: 30, verse: 19, text: "What good doeth the offering unto an idol? for neither can it eat nor smell: so is he that is persecuted of the Lord." },
  { book: "Sirach", chapter: 30, verse: 20, text: "He seeth with his eyes and groaneth, as an eunuch that embraceth a virgin and sigheth." },
  { book: "Sirach", chapter: 30, verse: 21, text: "Give not over thy mind to heaviness, and afflict not thyself in thine own counsel." },
  { book: "Sirach", chapter: 30, verse: 22, text: "The gladness of the heart is the life of man, and the joyfulness of a man prolongeth his days." },
  { book: "Sirach", chapter: 30, verse: 23, text: "Love thine own soul, and comfort thy heart, remove sorrow far from thee: for sorrow hath killed many, and there is no profit therein." },
  { book: "Sirach", chapter: 30, verse: 24, text: "Envy and wrath shorten the life, and carefulness bringeth age before the time." },
  { book: "Sirach", chapter: 30, verse: 25, text: "A cheerful and good heart will have a care of his meat and diet." },
  { book: "Sirach", chapter: 31, verse: 1, text: "Watching for riches consumeth the flesh, and the care thereof driveth away sleep." },
  { book: "Sirach", chapter: 31, verse: 2, text: "Watching care will not let a man slumber, as a sore disease breaketh sleep," },
  { book: "Sirach", chapter: 31, verse: 3, text: "The rich hath great labour in gathering riches together; and when he resteth, he is filled with his delicates." },
  { book: "Sirach", chapter: 31, verse: 4, text: "The poor laboureth in his poor estate; and when he leaveth off, he is still needy." },
  { book: "Sirach", chapter: 31, verse: 5, text: "He that loveth gold shall not be justified, and he that followeth corruption shall have enough thereof." },
  { book: "Sirach", chapter: 31, verse: 6, text: "Gold hath been the ruin of many, and their destruction was present." },
  { book: "Sirach", chapter: 31, verse: 7, text: "It is a stumblingblock unto them that sacrifice unto it, and every fool shall be taken therewith." },
  { book: "Sirach", chapter: 31, verse: 8, text: "Blessed is the rich that is found without blemish, and hath not gone after gold." },
  { book: "Sirach", chapter: 31, verse: 9, text: "Who is he? and we will call him blessed: for wonderful things hath he done among his people." },
  { book: "Sirach", chapter: 31, verse: 10, text: "Who hath been tried thereby, and found perfect? then let him glory. Who might offend, and hath not offended? or done evil, and hath not done it?" },
  { book: "Sirach", chapter: 31, verse: 11, text: "His goods shall be established, and the congregation shall declare his alms." },
  { book: "Sirach", chapter: 31, verse: 12, text: "If thou sit at a bountiful table, be not greedy upon it, and say not, There is much meat on it." },
  { book: "Sirach", chapter: 31, verse: 13, text: "Remember that a wicked eye is an evil thing: and what is created more wicked than an eye? therefore it weepeth upon every occasion." },
  { book: "Sirach", chapter: 31, verse: 14, text: "Stretch not thine hand whithersoever it looketh, and thrust it not with him into the dish." },
  { book: "Sirach", chapter: 31, verse: 15, text: "Judge not thy neighbour by thyself: and be discreet in every point." },
  { book: "Sirach", chapter: 31, verse: 16, text: "Eat as it becometh a man, those things which are set before thee; and devour note, lest thou be hated." },
  { book: "Sirach", chapter: 31, verse: 17, text: "Leave off first for manners’ sake; and be not unsatiable, lest thou offend." },
  { book: "Sirach", chapter: 31, verse: 18, text: "When thou sittest among many, reach not thine hand out first of all." },
  { book: "Sirach", chapter: 31, verse: 19, text: "A very little is sufficient for a man well nurtured, and he fetcheth not his wind short upon his bed." },
  { book: "Sirach", chapter: 31, verse: 20, text: "Sound sleep cometh of moderate eating: he riseth early, and his wits are with him: but the pain of watching, and choler, and pangs of the belly, are with an unsatiable man." },
  { book: "Sirach", chapter: 31, verse: 21, text: "And if thou hast been forced to eat, arise, go forth, vomit, and thou shalt have rest." },
  { book: "Sirach", chapter: 31, verse: 22, text: "My son, hear me, and despise me not, and at the last thou shalt find as I told thee: in all thy works be quick, so shall there no sickness come unto thee." },
  { book: "Sirach", chapter: 31, verse: 23, text: "Whoso is liberal of his meat, men shall speak well of him; and the report of his good housekeeping will be believed." },
  { book: "Sirach", chapter: 31, verse: 24, text: "But against him that is a niggard of his meat the whole city shall murmur; and the testimonies of his niggardness shall not be doubted of." },
  { book: "Sirach", chapter: 31, verse: 25, text: "Shew not thy valiantness in wine; for wine hath destroyed many." },
  { book: "Sirach", chapter: 31, verse: 26, text: "The furnace proveth the edge by dipping: so doth wine the hearts of the proud by drunkenness." },
  { book: "Sirach", chapter: 31, verse: 27, text: "Wine is as good as life to a man, if it be drunk moderately: what life is then to a man that is without wine? for it was made to make men glad." },
  { book: "Sirach", chapter: 31, verse: 28, text: "Wine measurably drunk and in season bringeth gladness of the heart, and cheerfulness of the mind:" },
  { book: "Sirach", chapter: 31, verse: 29, text: "But wine drunken with excess maketh bitterness of the mind, with brawling and quarrelling." },
  { book: "Sirach", chapter: 31, verse: 30, text: "Drunkenness increaseth the rage of a fool till he offend: it diminisheth strength, and maketh wounds." },
  { book: "Sirach", chapter: 31, verse: 31, text: "Rebuke not thy neighbour at the wine, and despise him not in his mirth: give him no despiteful words, and press not upon him with urging him to drink." },
  { book: "Sirach", chapter: 32, verse: 1, text: "If thou be made the master of a feast, lift not thyself up, but be among them as one of the rest; take diligent care for them, and so sit down." },
  { book: "Sirach", chapter: 32, verse: 2, text: "And when thou hast done all thy office, take thy place, that thou mayest be merry with them, and receive a crown for thy well ordering of the feast." },
  { book: "Sirach", chapter: 32, verse: 3, text: "Speak, thou that art the elder, for it becometh thee, but with sound judgment; and hinder not musick." },
  { book: "Sirach", chapter: 32, verse: 4, text: "Pour not out words where there is a musician, and shew not forth wisdom out of time." },
  { book: "Sirach", chapter: 32, verse: 5, text: "A concert of musick in a banquet of wine is as a signet of carbuncle set in gold." },
  { book: "Sirach", chapter: 32, verse: 6, text: "As a signet of an emerald set in a work of gold, so is the melody of musick with pleasant wine." },
  { book: "Sirach", chapter: 32, verse: 7, text: "Speak, young man, if there be need of thee: and yet scarcely when thou art twice asked." },
  { book: "Sirach", chapter: 32, verse: 8, text: "Let thy speech be short, comprehending much in few words; be as one that knoweth and yet holdeth his tongue." },
  { book: "Sirach", chapter: 32, verse: 9, text: "If thou be among great men, make not thyself equal with them; and when ancient men are in place, use not many words." },
  { book: "Sirach", chapter: 32, verse: 10, text: "Before the thunder goeth lightning; and before a shamefaced man shall go favour." },
  { book: "Sirach", chapter: 32, verse: 11, text: "Rise up betimes, and be not the last; but get thee home without delay." },
  { book: "Sirach", chapter: 32, verse: 12, text: "There take thy pastime, and do what thou wilt: but sin not by proud speech." },
  { book: "Sirach", chapter: 32, verse: 13, text: "And for these things bless him that made thee, and hath replenished thee with his good things." },
  { book: "Sirach", chapter: 32, verse: 14, text: "Whoso feareth the Lord will receive his discipline; and they that seek him early shall find favour." },
  { book: "Sirach", chapter: 32, verse: 15, text: "He that seeketh the law shall be filled therewith: but the hypocrite will be offended thereat." },
  { book: "Sirach", chapter: 32, verse: 16, text: "They that fear the Lord shall find judgment, and shall kindle justice as a light." },
  { book: "Sirach", chapter: 32, verse: 17, text: "A sinful man will not be reproved, but findeth an excuse according to his will." },
  { book: "Sirach", chapter: 32, verse: 18, text: "A man of counsel will be considerate; but a strange and proud man is not daunted with fear, even when of himself he hath done without counsel." },
  { book: "Sirach", chapter: 32, verse: 19, text: "Do nothing without advice; and when thou hast once done, repent not." },
  { book: "Sirach", chapter: 32, verse: 20, text: "Go not in a way wherein thou mayest fall, and stumble not among the stones." },
  { book: "Sirach", chapter: 32, verse: 21, text: "Be not confident in a plain way." },
  { book: "Sirach", chapter: 32, verse: 22, text: "And beware of thine own children." },
  { book: "Sirach", chapter: 32, verse: 23, text: "In every good work trust thy own soul; for this is the keeping of the commandments." },
  { book: "Sirach", chapter: 32, verse: 24, text: "He that believeth in the Lord taketh heed to the commandment; and he that trusteth in him shall fare never the worse." },
  { book: "Sirach", chapter: 33, verse: 1, text: "There shall no evil happen unto him that feareth the Lord; but in temptation even again he will deliver him." },
  { book: "Sirach", chapter: 33, verse: 2, text: "A wise man hateth not the law; but he that is an hypocrite therein is as a ship in a storm." },
  { book: "Sirach", chapter: 33, verse: 3, text: "A man of understanding trusteth in the law; and the law is faithful unto him, as an oracle." },
  { book: "Sirach", chapter: 33, verse: 4, text: "Prepare what to say, and so thou shalt be heard: and bind up instruction, and then make answer." },
  { book: "Sirach", chapter: 33, verse: 5, text: "The heart of the foolish is like a cartwheel; and his thoughts are like a rolling axletree." },
  { book: "Sirach", chapter: 33, verse: 6, text: "A stallion horse is as a mocking friend, he neigheth under every one that sitteth upon him." },
  { book: "Sirach", chapter: 33, verse: 7, text: "Why doth one day excel another, when as all the light of every day in the year is of the sun?" },
  { book: "Sirach", chapter: 33, verse: 8, text: "By the knowledge of the Lord they were distinguished: and he altered seasons and feasts." },
  { book: "Sirach", chapter: 33, verse: 9, text: "Some of them hath he made high days, and hallowed them, and some of them hath he made ordinary days." },
  { book: "Sirach", chapter: 33, verse: 10, text: "And all men are from the ground, and Adam was created of earth:" },
  { book: "Sirach", chapter: 33, verse: 11, text: "In much knowledge the Lord hath divided them, and made their ways diverse." },
  { book: "Sirach", chapter: 33, verse: 12, text: "Some of them hath he blessed and exalted and some of them he sanctified, and set near himself: but some of them hath he cursed and brought low, and turned out of their places." },
  { book: "Sirach", chapter: 33, verse: 13, text: "As the clay is in the potter’s hand, to fashion it at his pleasure: so man is in the hand of him that made him, to render to them as liketh him best." },
  { book: "Sirach", chapter: 33, verse: 14, text: "Good is set against evil, and life against death: so is the godly against the sinner, and the sinner against the godly." },
  { book: "Sirach", chapter: 33, verse: 15, text: "So look upon all the works of the most High; and there are two and two, one against another." },
  { book: "Sirach", chapter: 33, verse: 16, text: "I awaked up last of all, as one that gathereth after the grapegatherers: by the blessing of the Lord I profited, and trod my winepress like a gatherer of grapes." },
  { book: "Sirach", chapter: 33, verse: 17, text: "Consider that I laboured not for myself only, but for all them that seek learning." },
  { book: "Sirach", chapter: 33, verse: 18, text: "Hear me, O ye great men of the people, and hearken with your ears, ye rulers of the congregation." },
  { book: "Sirach", chapter: 33, verse: 19, text: "Give not thy son and wife, thy brother and friend, power over thee while thou livest, and give not thy goods to another: lest it repent thee, and thou intreat for the same again." },
  { book: "Sirach", chapter: 33, verse: 20, text: "As long as thou livest and hast breath in thee, give not thyself over to any." },
  { book: "Sirach", chapter: 33, verse: 21, text: "For better it is that thy children should seek to thee, than that thou shouldest stand to their courtesy." },
  { book: "Sirach", chapter: 33, verse: 22, text: "In all thy works keep to thyself the preeminence; leave not a stain in thine honour." },
  { book: "Sirach", chapter: 33, verse: 23, text: "At the time when thou shalt end thy days, and finish thy life, distribute thine inheritance." },
  { book: "Sirach", chapter: 33, verse: 24, text: "Fodder, a wand, and burdens, are for the ass; and bread, correction, and work, for a servant. ." },
  { book: "Sirach", chapter: 33, verse: 25, text: "If thou set thy servant to labour, thou shalt find rest: but if thou let him go idle, he shall seek liberty." },
  { book: "Sirach", chapter: 33, verse: 26, text: "A yoke and a collar do bow the neck: so are tortures and torments for an evil servant." },
  { book: "Sirach", chapter: 33, verse: 27, text: "Send him to labour, that he be not idle; for idleness teacheth much evil." },
  { book: "Sirach", chapter: 33, verse: 28, text: "Set him to work, as is fit for him: if he be not obedient, put on more heavy fetters." },
  { book: "Sirach", chapter: 33, verse: 29, text: "But be not excessive toward any; and without discretion do nothing." },
  { book: "Sirach", chapter: 33, verse: 30, text: "If thou have a servant, let him be unto thee as thyself, because thou hast bought him with a price." },
  { book: "Sirach", chapter: 33, verse: 31, text: "If thou have a servant, entreat him as a brother: for thou hast need of him, as of thine own soul: if thou entreat him evil, and he run from thee, which way wilt thou go to seek him?" },
  { book: "Sirach", chapter: 34, verse: 1, text: "The hopes of a man void of understanding are vain and false: and dreams lift up fools." },
  { book: "Sirach", chapter: 34, verse: 2, text: "Whoso regardeth dreams is like him that catcheth at a shadow, and followeth after the wind." },
  { book: "Sirach", chapter: 34, verse: 3, text: "The vision of dreams is the resemblance of one thing to another, even as the likeness of a face to a face." },
  { book: "Sirach", chapter: 34, verse: 4, text: "Of an unclean thing what can be cleansed? and from that thing which is false what truth can come?" },
  { book: "Sirach", chapter: 34, verse: 5, text: "Divinations, and soothsayings, and dreams, are vain: and the heart fancieth, as a woman’s heart in travail." },
  { book: "Sirach", chapter: 34, verse: 6, text: "If they be not sent from the most High in thy visitation, set not thy heart upon them." },
  { book: "Sirach", chapter: 34, verse: 7, text: "For dreams have deceived many, and they have failed that put their trust in them." },
  { book: "Sirach", chapter: 34, verse: 8, text: "The law shall be found perfect without lies: and wisdom is perfection to a faithful mouth." },
  { book: "Sirach", chapter: 34, verse: 9, text: "A man that hath travelled knoweth many things; and he that hath much experience will declare wisdom." },
  { book: "Sirach", chapter: 34, verse: 10, text: "He that hath no experience knoweth little: but he that hath travelled is full of prudence." },
  { book: "Sirach", chapter: 34, verse: 11, text: "When I travelled, I saw many things; and I understand more than I can express." },
  { book: "Sirach", chapter: 34, verse: 12, text: "I was ofttimes in danger of death: yet I was delivered because of these things." },
  { book: "Sirach", chapter: 34, verse: 13, text: "The spirit of those that fear the Lord shall live; for their hope is in him that saveth them." },
  { book: "Sirach", chapter: 34, verse: 14, text: "Whoso feareth the Lord shall not fear nor be afraid; for he is his hope." },
  { book: "Sirach", chapter: 34, verse: 15, text: "Blessed is the soul of him that feareth the Lord: to whom doth he look? and who is his strength?" },
  { book: "Sirach", chapter: 34, verse: 16, text: "For the eyes of the Lord are upon them that love him, he is their mighty protection and strong stay, a defence from heat, and a cover from the sun at noon, a preservation from stumbling, and an help from falling." },
  { book: "Sirach", chapter: 34, verse: 17, text: "He raiseth up the soul, and lighteneth the eyes: he giveth health, life, and blessing." },
  { book: "Sirach", chapter: 34, verse: 18, text: "He that sacrificeth of a thing wrongfully gotten, his offering is ridiculous; and the gifts of unjust men are not accepted." },
  { book: "Sirach", chapter: 34, verse: 19, text: "The most High is not pleased with the offerings of the wicked; neither is he pacified for sin by the multitude of sacrifices." },
  { book: "Sirach", chapter: 34, verse: 20, text: "Whoso bringeth an offering of the goods of the poor doeth as one that killeth the son before his father’s eyes." },
  { book: "Sirach", chapter: 34, verse: 21, text: "The bread of the needy is their life: he that defraudeth him thereof is a man of blood." },
  { book: "Sirach", chapter: 34, verse: 22, text: "He that taketh away his neighbour’s living slayeth him; and he that defraudeth the labourer of his hire is a bloodshedder." },
  { book: "Sirach", chapter: 34, verse: 23, text: "When one buildeth, and another pulleth down, what profit have they then but labour?" },
  { book: "Sirach", chapter: 34, verse: 24, text: "When one prayeth, and another curseth, whose voice will the Lord hear?" },
  { book: "Sirach", chapter: 34, verse: 25, text: "He that washeth himself after the touching of a dead body, if he touch it again, what availeth his washing?" },
  { book: "Sirach", chapter: 34, verse: 26, text: "So is it with a man that fasteth for his sins, and goeth again, and doeth the same: who will hear his prayer? or what doth his humbling profit him?" },
  { book: "Sirach", chapter: 35, verse: 1, text: "He that keepeth the law bringeth offerings enough: he that taketh heed to the commandment offereth a peace offering." },
  { book: "Sirach", chapter: 35, verse: 2, text: "He that requiteth a good turn offereth fine flour; and he that giveth alms sacrificeth praise." },
  { book: "Sirach", chapter: 35, verse: 3, text: "To depart from wickedness is a thing pleasing to the Lord; and to forsake unrighteousness is a propitiation." },
  { book: "Sirach", chapter: 35, verse: 4, text: "Thou shalt not appear empty before the Lord." },
  { book: "Sirach", chapter: 35, verse: 5, text: "For all these things are to be done because of the commandment." },
  { book: "Sirach", chapter: 35, verse: 6, text: "The offering of the righteous maketh the altar fat, and the sweet savour thereof is before the most High." },
  { book: "Sirach", chapter: 35, verse: 7, text: "The sacrifice of a just man is acceptable. and the memorial thereof shall never be forgotten." },
  { book: "Sirach", chapter: 35, verse: 8, text: "Give the Lord his honour with a good eye, and diminish not the firstfruits of thine hands." },
  { book: "Sirach", chapter: 35, verse: 9, text: "In all thy gifts shew a cheerful countenance, and dedicate thy tithes with gladness." },
  { book: "Sirach", chapter: 35, verse: 10, text: "Give unto the most High according as he hath enriched thee; and as thou hast gotten, give with a cheerful eye." },
  { book: "Sirach", chapter: 35, verse: 11, text: "For the Lord recompenseth, and will give thee seven times as much." },
  { book: "Sirach", chapter: 35, verse: 12, text: "Do not think to corrupt with gifts; for such he will not receive: and trust not to unrighteous sacrifices; for the Lord is judge, and with him is no respect of persons." },
  { book: "Sirach", chapter: 35, verse: 13, text: "He will not accept any person against a poor man, but will hear the prayer of the oppressed." },
  { book: "Sirach", chapter: 35, verse: 14, text: "He will not despise the supplication of the fatherless; nor the widow, when she poureth out her complaint." },
  { book: "Sirach", chapter: 35, verse: 15, text: "Do not the tears run down the widow’s cheeks? and is not her cry against him that causeth them to fall?" },
  { book: "Sirach", chapter: 35, verse: 16, text: "He that serveth the Lord shall be accepted with favour, and his prayer shall reach unto the clouds." },
  { book: "Sirach", chapter: 35, verse: 17, text: "The prayer of the humble pierceth the clouds: and till it come nigh, he will not be comforted; and will not depart, till the most High shall behold to judge righteously, and execute judgment." },
  { book: "Sirach", chapter: 35, verse: 18, text: "For the Lord will not be slack, neither will the Mighty be patient toward them, till he have smitten in sunder the loins of the unmerciful, and repayed vengeance to the heathen; till he have taken away the multitude of the proud, and broken the sceptre of the unrighteous;" },
  { book: "Sirach", chapter: 35, verse: 19, text: "Till he have rendered to every man according to his deeds, and to the works of men according to their devices; till he have judged the cause of his people, and made them to rejoice in his mercy." },
  { book: "Sirach", chapter: 35, verse: 20, text: "Mercy is seasonable in the time of affliction, as clouds of rain in the time of drought." },
  { book: "Sirach", chapter: 36, verse: 1, text: "Have mercy upon us, O Lord God of all, and behold us:" },
  { book: "Sirach", chapter: 36, verse: 2, text: "And send thy fear upon all the nations that seek not after thee." },
  { book: "Sirach", chapter: 36, verse: 3, text: "Lift up thy hand against the strange nations, and let them see thy power." },
  { book: "Sirach", chapter: 36, verse: 4, text: "As thou wast sanctified in us before them: so be thou magnified among them before us." },
  { book: "Sirach", chapter: 36, verse: 5, text: "And let them know thee, as we have known thee, that there is no God but only thou, O God." },
  { book: "Sirach", chapter: 36, verse: 6, text: "Shew new signs, and make other strange wonders: glorify thy hand and thy right arm, that they may set forth thy wondrous works." },
  { book: "Sirach", chapter: 36, verse: 7, text: "Raise up indignation, and pour out wrath: take away the adversary, and destroy the enemy." },
  { book: "Sirach", chapter: 36, verse: 8, text: "Sake the time short, remember the covenant, and let them declare thy wonderful works." },
  { book: "Sirach", chapter: 36, verse: 9, text: "Let him that escapeth be consumed by the rage of the fire; and let them perish that oppress the people." },
  { book: "Sirach", chapter: 36, verse: 10, text: "Smite in sunder the heads of the rulers of the heathen, that say, There is none other but we." },
  { book: "Sirach", chapter: 36, verse: 11, text: "Gather all the tribes of Jacob together, and inherit thou them, as from the beginning." },
  { book: "Sirach", chapter: 36, verse: 12, text: "O Lord, have mercy upon the people that is called by thy name, and upon Israel, whom thou hast named thy firstborn." },
  { book: "Sirach", chapter: 36, verse: 13, text: "O be merciful unto Jerusalem, thy holy city, the place of thy rest." },
  { book: "Sirach", chapter: 36, verse: 14, text: "Fill Sion with thine unspeakable oracles, and thy people with thy glory:" },
  { book: "Sirach", chapter: 36, verse: 15, text: "Give testimony unto those that thou hast possessed from the beginning, and raise up prophets that have been in thy name." },
  { book: "Sirach", chapter: 36, verse: 16, text: "Reward them that wait for thee, and let thy prophets be found faithful." },
  { book: "Sirach", chapter: 36, verse: 17, text: "O Lord, hear the prayer of thy servants, according to the blessing of Aaron over thy people, that all they which dwell upon the earth may know that thou art the Lord, the eternal God." },
  { book: "Sirach", chapter: 36, verse: 18, text: "The belly devoureth all meats, yet is one meat better than another." },
  { book: "Sirach", chapter: 36, verse: 19, text: "As the palate tasteth divers kinds of venison: so doth an heart of understanding false speeches." },
  { book: "Sirach", chapter: 36, verse: 20, text: "A froward heart causeth heaviness: but a man of experience will recompense him." },
  { book: "Sirach", chapter: 36, verse: 21, text: "A woman will receive every man, yet is one daughter better than another." },
  { book: "Sirach", chapter: 36, verse: 22, text: "The beauty of a woman cheereth the countenance, and a man loveth nothing better." },
  { book: "Sirach", chapter: 36, verse: 23, text: "If there be kindness, meekness, and comfort, in her tongue, then is not her husband like other men." },
  { book: "Sirach", chapter: 36, verse: 24, text: "He that getteth a wife beginneth a possession, a help like unto himself, and a pillar of rest." },
  { book: "Sirach", chapter: 36, verse: 25, text: "Where no hedge is, there the possession is spoiled: and he that hath no wife will wander up and down mourning." },
  { book: "Sirach", chapter: 36, verse: 26, text: "Who will trust a thief well appointed, that skippeth from city to city? so who will believe a man that hath no house, and lodgeth wheresoever the night taketh him?" },
  { book: "Sirach", chapter: 37, verse: 1, text: "Every friend saith, I am his friend also: but there is a friend, which is only a friend in name." },
  { book: "Sirach", chapter: 37, verse: 2, text: "Is it not a grief unto death, when a companion and friend is turned to an enemy?" },
  { book: "Sirach", chapter: 37, verse: 3, text: "O wicked imagination, whence camest thou in to cover the earth with deceit?" },
  { book: "Sirach", chapter: 37, verse: 4, text: "There is a companion, which rejoiceth in the prosperity of a friend, but in the time of trouble will be against him." },
  { book: "Sirach", chapter: 37, verse: 5, text: "There is a companion, which helpeth his friend for the belly, and taketh up the buckler against the enemy." },
  { book: "Sirach", chapter: 37, verse: 6, text: "Forget not thy friend in thy mind, and be not unmindful of him in thy riches." },
  { book: "Sirach", chapter: 37, verse: 7, text: "Every counsellor extolleth counsel; but there is some that counselleth for himself." },
  { book: "Sirach", chapter: 37, verse: 8, text: "Beware of a counsellor, and know before what need he hath; for he will counsel for himself; lest he cast the lot upon thee," },
  { book: "Sirach", chapter: 37, verse: 9, text: "And say unto thee, Thy way is good: and afterward he stand on the other side, to see what shall befall thee." },
  { book: "Sirach", chapter: 37, verse: 10, text: "Consult not with one that suspecteth thee: and hide thy counsel from such as envy thee." },
  { book: "Sirach", chapter: 37, verse: 11, text: "Neither consult with a woman touching her of whom she is jealous; neither with a coward in matters of war; nor with a merchant concerning exchange; nor with a buyer of selling; nor with an envious man of thankfulness; nor with an unmerciful man touching kindness; nor with the slothful for any work; nor with an hireling for a year of finishing work; nor with an idle servant of much business: hearken not unto these in any matter of counsel." },
  { book: "Sirach", chapter: 37, verse: 12, text: "But be continually with a godly man, whom thou knowest to keep the commandments of the Lord, whose, mind is according to thy mind, and will sorrow with thee, if thou shalt miscarry." },
  { book: "Sirach", chapter: 37, verse: 13, text: "And let the counsel of thine own heart stand: for there is no man more faithful unto thee than it." },
  { book: "Sirach", chapter: 37, verse: 14, text: "For a man’s mind is sometime wont to tell him more than seven watchmen, that sit above in an high tower." },
  { book: "Sirach", chapter: 37, verse: 15, text: "And above all this pray to the most High, that he will direct thy way in truth." },
  { book: "Sirach", chapter: 37, verse: 16, text: "Let reason go before every enterprize, and counsel before every action." },
  { book: "Sirach", chapter: 37, verse: 17, text: "The countenance is a sign of changing of the heart." },
  { book: "Sirach", chapter: 37, verse: 18, text: "Four manner of things appear: good and evil, life and death: but the tongue ruleth over them continually." },
  { book: "Sirach", chapter: 37, verse: 19, text: "There is one that is wise and teacheth many, and yet is unprofitable to himself." },
  { book: "Sirach", chapter: 37, verse: 20, text: "There is one that sheweth wisdom in words, and is hated: he shall be destitute of all food." },
  { book: "Sirach", chapter: 37, verse: 21, text: "For grace is not given, him from the Lord, because he is deprived of all wisdom." },
  { book: "Sirach", chapter: 37, verse: 22, text: "Another is wise to himself; and the fruits of understanding are commendable in his mouth." },
  { book: "Sirach", chapter: 37, verse: 23, text: "A wise man instructeth his people; and the fruits of his understanding fail not." },
  { book: "Sirach", chapter: 37, verse: 24, text: "A wise man shall be filled with blessing; and all they that see him shall count him happy." },
  { book: "Sirach", chapter: 37, verse: 25, text: "The days of the life of man may be numbered: but the days of Israel are innumerable." },
  { book: "Sirach", chapter: 37, verse: 26, text: "A wise man shall inherit glory among his people, and his name shall be perpetual." },
  { book: "Sirach", chapter: 37, verse: 27, text: "My son, prove thy soul in thy life, and see what is evil for it, and give not that unto it." },
  { book: "Sirach", chapter: 37, verse: 28, text: "For all things are not profitable for all men, neither hath every soul pleasure in every thing." },
  { book: "Sirach", chapter: 37, verse: 29, text: "Be not unsatiable in any dainty thing, nor too greedy upon meats:" },
  { book: "Sirach", chapter: 37, verse: 30, text: "For excess of meats bringeth sickness, and surfeiting will turn into choler." },
  { book: "Sirach", chapter: 37, verse: 31, text: "By surfeiting have many perished; but he that taketh heed prolongeth his life." },
  { book: "Sirach", chapter: 38, verse: 1, text: "Honour a physician with the honour due unto him for the uses which ye may have of him: for the Lord hath created him." },
  { book: "Sirach", chapter: 38, verse: 2, text: "For of the most High cometh healing, and he shall receive honour of the king." },
  { book: "Sirach", chapter: 38, verse: 3, text: "The skill of the physician shall lift up his head: and in the sight of great men he shall be in admiration." },
  { book: "Sirach", chapter: 38, verse: 4, text: "The Lord hath created medicines out of the earth; and he that is wise will not abhor them." },
  { book: "Sirach", chapter: 38, verse: 5, text: "Was not the water made sweet with wood, that the virtue thereof might be known?" },
  { book: "Sirach", chapter: 38, verse: 6, text: "And he hath given men skill, that he might be honoured in his marvellous works." },
  { book: "Sirach", chapter: 38, verse: 7, text: "With such doth he heal men, and taketh away their pains." },
  { book: "Sirach", chapter: 38, verse: 8, text: "Of such doth the apothecary make a confection; and of his works there is no end; and from him is peace over all the earth," },
  { book: "Sirach", chapter: 38, verse: 9, text: "My son, in thy sickness be not negligent: but pray unto the Lord, and he will make thee whole." },
  { book: "Sirach", chapter: 38, verse: 10, text: "Leave off from sin, and order thine hands aright, and cleanse thy heart from all wickedness." },
  { book: "Sirach", chapter: 38, verse: 11, text: "Give a sweet savour, and a memorial of fine flour; and make a fat offering, as not being." },
  { book: "Sirach", chapter: 38, verse: 12, text: "Then give place to the physician, for the Lord hath created him: let him not go from thee, for thou hast need of him." },
  { book: "Sirach", chapter: 38, verse: 13, text: "There is a time when in their hands there is good success." },
  { book: "Sirach", chapter: 38, verse: 14, text: "For they shall also pray unto the Lord, that he would prosper that, which they give for ease and remedy to prolong life." },
  { book: "Sirach", chapter: 38, verse: 15, text: "He that sinneth before his Maker, let him fall into the hand of the physician." },
  { book: "Sirach", chapter: 38, verse: 16, text: "My son, let tears fall down over the dead, and begin to lament, as if thou hadst suffered great harm thyself; and then cover his body according to the custom, and neglect not his burial." },
  { book: "Sirach", chapter: 38, verse: 17, text: "Weep bitterly, and make great moan, and use lamentation, as he is worthy, and that a day or two, lest thou be evil spoken of: and then comfort thyself for thy heaviness." },
  { book: "Sirach", chapter: 38, verse: 18, text: "For of heaviness cometh death, and the heaviness of the heart breaketh strength." },
  { book: "Sirach", chapter: 38, verse: 19, text: "In affliction also sorrow remaineth: and the life of the poor is the curse of the heart." },
  { book: "Sirach", chapter: 38, verse: 20, text: "Take no heaviness to heart: drive it away, and member the last end." },
  { book: "Sirach", chapter: 38, verse: 21, text: "Forget it not, for there is no turning again: thou shalt not do him good, but hurt thyself." },
  { book: "Sirach", chapter: 38, verse: 22, text: "Remember my judgment: for thine also shall be so; yesterday for me, and to day for thee." },
  { book: "Sirach", chapter: 38, verse: 23, text: "When the dead is at rest, let his remembrance rest; and be comforted for him, when his Spirit is departed from him." },
  { book: "Sirach", chapter: 38, verse: 24, text: "The wisdom of a learned man cometh by opportunity of leisure: and he that hath little business shall become wise." },
  { book: "Sirach", chapter: 38, verse: 25, text: "How can he get wisdom that holdeth the plough, and that glorieth in the goad, that driveth oxen, and is occupied in their labours, and whose talk is of bullocks?" },
  { book: "Sirach", chapter: 38, verse: 26, text: "He giveth his mind to make furrows; and is diligent to give the kine fodder." },
  { book: "Sirach", chapter: 38, verse: 27, text: "So every carpenter and workmaster, that laboureth night and day: and they that cut and grave seals, and are diligent to make great variety, and give themselves to counterfeit imagery, and watch to finish a work:" },
  { book: "Sirach", chapter: 38, verse: 28, text: "The smith also sitting by the anvil, and considering the iron work, the vapour of the fire wasteth his flesh, and he fighteth with the heat of the furnace: the noise of the hammer and the anvil is ever in his ears, and his eyes look still upon the pattern of the thing that he maketh; he setteth his mind to finish his work, and watcheth to polish it perfectly:" },
  { book: "Sirach", chapter: 38, verse: 29, text: "So doth the potter sitting at his work, and turning the wheel about with his feet, who is alway carefully set at his work, and maketh all his work by number;" },
  { book: "Sirach", chapter: 38, verse: 30, text: "He fashioneth the clay with his arm, and boweth down his strength before his feet; he applieth himself to lead it over; and he is diligent to make clean the furnace:" },
  { book: "Sirach", chapter: 38, verse: 31, text: "All these trust to their hands: and every one is wise in his work." },
  { book: "Sirach", chapter: 38, verse: 32, text: "Without these cannot a city be inhabited: and they shall not dwell where they will, nor go up and down:" },
  { book: "Sirach", chapter: 38, verse: 33, text: "They shall not be sought for in publick counsel, nor sit high in the congregation: they shall not sit on the judges’ seat, nor understand the sentence of judgment: they cannot declare justice and judgment; and they shall not be found where parables are spoken." },
  { book: "Sirach", chapter: 38, verse: 34, text: "But they will maintain the state of the world, and all their desire is in the work of their craft." },
  { book: "Sirach", chapter: 39, verse: 1, text: "But he that giveth his mind to the law of the most High, and is occupied in the meditation thereof, will seek out the wisdom of all the ancient, and be occupied in prophecies." },
  { book: "Sirach", chapter: 39, verse: 2, text: "He will keep the sayings of the renowned men: and where subtil parables are, he will be there also." },
  { book: "Sirach", chapter: 39, verse: 3, text: "He will seek out the secrets of grave sentences, and be conversant in dark parables." },
  { book: "Sirach", chapter: 39, verse: 4, text: "He shall serve among great men, and appear before princes: he will travel through strange countries; for he hath tried the good and the evil among men." },
  { book: "Sirach", chapter: 39, verse: 5, text: "He will give his heart to resort early to the Lord that made him, and will pray before the most High, and will open his mouth in prayer, and make supplication for his sins." },
  { book: "Sirach", chapter: 39, verse: 6, text: "When the great Lord will, he shall be filled with the spirit of understanding: he shall pour out wise sentences, and give thanks unto the Lord in his prayer." },
  { book: "Sirach", chapter: 39, verse: 7, text: "He shall direct his counsel and knowledge, and in his secrets shall he meditate." },
  { book: "Sirach", chapter: 39, verse: 8, text: "He shall shew forth that which he hath learned, and shall glory in the law of the covenant of the Lord." },
  { book: "Sirach", chapter: 39, verse: 9, text: "Many shall commend his understanding; and so long as the world endureth, it shall not be blotted out; his memorial shall not depart away, and his name shall live from generation to generation." },
  { book: "Sirach", chapter: 39, verse: 10, text: "Nations shall shew forth his wisdom, and the congregation shall declare his praise." },
  { book: "Sirach", chapter: 39, verse: 11, text: "If he die, he shall leave a greater name than a thousand: and if he live, he shall increase it." },
  { book: "Sirach", chapter: 39, verse: 12, text: "Yet have I more to say, which I have thought upon; for I am filled as the moon at the full." },
  { book: "Sirach", chapter: 39, verse: 13, text: "Hearken unto me, ye holy children, and bud forth as a rose growing by the brook of the field:" },
  { book: "Sirach", chapter: 39, verse: 14, text: "And give ye a sweet savour as frankincense, and flourish as a lily, send forth a smell, and sing a song of praise, bless the Lord in all his works." },
  { book: "Sirach", chapter: 39, verse: 15, text: "Magnify his name, and shew forth his praise with the songs of your lips, and with harps, and in praising him ye shall say after this manner:" },
  { book: "Sirach", chapter: 39, verse: 16, text: "All the works of the Lord are exceeding good, and whatsoever he commandeth shall be accomplished in due season." },
  { book: "Sirach", chapter: 39, verse: 17, text: "And none may say, What is this? wherefore is that? for at time convenient they shall all be sought out: at his commandment the waters stood as an heap, and at the words of his mouth the receptacles of waters." },
  { book: "Sirach", chapter: 39, verse: 18, text: "At his commandment is done whatsoever pleaseth him; and none can hinder, when he will save." },
  { book: "Sirach", chapter: 39, verse: 19, text: "The works of all flesh are before him, and nothing can be hid from his eyes." },
  { book: "Sirach", chapter: 39, verse: 20, text: "He seeth from everlasting to everlasting; and there is nothing wonderful before him." },
  { book: "Sirach", chapter: 39, verse: 21, text: "A man need not to say, What is this? wherefore is that? for he hath made all things for their uses." },
  { book: "Sirach", chapter: 39, verse: 22, text: "His blessing covered the dry land as a river, and watered it as a flood." },
  { book: "Sirach", chapter: 39, verse: 23, text: "As he hath turned the waters into saltness: so shall the heathen inherit his wrath." },
  { book: "Sirach", chapter: 39, verse: 24, text: "As his ways are plain unto the holy; so are they stumblingblocks unto the wicked." },
  { book: "Sirach", chapter: 39, verse: 25, text: "For the good are good things created from the beginning: so evil things for sinners." },
  { book: "Sirach", chapter: 39, verse: 26, text: "The principal things for the whole use of man’s life are water, fire, iron, and salt, flour of wheat, honey, milk, and the blood of the grape, and oil, and clothing." },
  { book: "Sirach", chapter: 39, verse: 27, text: "All these things are for good to the godly: so to the sinners they are turned into evil." },
  { book: "Sirach", chapter: 39, verse: 28, text: "There be spirits that are created for vengeance, which in their fury lay on sore strokes; in the time of destruction they pour out their force, and appease the wrath of him that made them." },
  { book: "Sirach", chapter: 39, verse: 29, text: "Fire, and hail, and famine, and death, all these were created for vengeance;" },
  { book: "Sirach", chapter: 39, verse: 30, text: "Teeth of wild beasts, and scorpions, serpents, and the sword punishing the wicked to destruction." },
  { book: "Sirach", chapter: 39, verse: 31, text: "They shall rejoice in his commandment, and they shall be ready upon earth, when need is; and when their time is come, they shall not transgress his word." },
  { book: "Sirach", chapter: 39, verse: 32, text: "Therefore from the beginning I was resolved, and thought upon these things, and have left them in writing." },
  { book: "Sirach", chapter: 39, verse: 33, text: "All the works of the Lord are good: and he will give every needful thing in due season." },
  { book: "Sirach", chapter: 39, verse: 34, text: "So that a man cannot say, This is worse than that: for in time they shall all be well approved." },
  { book: "Sirach", chapter: 39, verse: 35, text: "And therefore praise ye the Lord with the whole heart and mouth, and bless the name of the Lord." },
  { book: "Sirach", chapter: 40, verse: 1, text: "Great travail is created for every man, and an heavy yoke is upon the sons of Adam, from the day that they go out of their mother’s womb, till the day that they return to the mother of all things." },
  { book: "Sirach", chapter: 40, verse: 2, text: "Their imagination of things to come, and the day of death, trouble their thoughts, and cause fear of heart;" },
  { book: "Sirach", chapter: 40, verse: 3, text: "From him that sitteth on a throne of glory, unto him that is humbled in earth and ashes;" },
  { book: "Sirach", chapter: 40, verse: 4, text: "From him that weareth purple and a crown, unto him that is clothed with a linen frock." },
  { book: "Sirach", chapter: 40, verse: 5, text: "Wrath, and envy, trouble, and unquietness, fear of death, and anger, and strife, and in the time of rest upon his bed his night sleep, do change his knowledge." },
  { book: "Sirach", chapter: 40, verse: 6, text: "A little or nothing is his rest, and afterward he is in his sleep, as in a day of keeping watch, troubled in the vision of his heart, as if he were escaped out of a battle." },
  { book: "Sirach", chapter: 40, verse: 7, text: "When all is safe, he awaketh, and marvelleth that the fear was nothing." },
  { book: "Sirach", chapter: 40, verse: 8, text: "Such things happen unto all flesh, both man and beast, and that is sevenfold more upon sinners." },
  { book: "Sirach", chapter: 40, verse: 9, text: "Death, and bloodshed, strife, and sword, calamities, famine, tribulation, and the scourge;" },
  { book: "Sirach", chapter: 40, verse: 10, text: "These things are created for the wicked, and for their sakes came the flood." },
  { book: "Sirach", chapter: 40, verse: 11, text: "All things that are of the earth shall turn to the earth again: and that which is of the waters doth return into the sea." },
  { book: "Sirach", chapter: 40, verse: 12, text: "All bribery and injustice shall be blotted out: but true dealing shall endure for ever." },
  { book: "Sirach", chapter: 40, verse: 13, text: "The goods of the unjust shall be dried up like a river, and shall vanish with noise, like a great thunder in rain." },
  { book: "Sirach", chapter: 40, verse: 14, text: "While he openeth his hand he shall rejoice: so shall transgressors come to nought." },
  { book: "Sirach", chapter: 40, verse: 15, text: "The children of the ungodly shall not bring forth many branches: but are as unclean roots upon a hard rock." },
  { book: "Sirach", chapter: 40, verse: 16, text: "The weed growing upon every water and bank of a river shall be pulled up before all grass." },
  { book: "Sirach", chapter: 40, verse: 17, text: "Bountifulness is as a most fruitful garden, and mercifulness endureth for ever." },
  { book: "Sirach", chapter: 40, verse: 18, text: "To labour, and to be content with that a man hath, is a sweet life: but he that findeth a treasure is above them both." },
  { book: "Sirach", chapter: 40, verse: 19, text: "Children and the building of a city continue a man’s name: but a blameless wife is counted above them both." },
  { book: "Sirach", chapter: 40, verse: 20, text: "Wine and musick rejoice the heart: but the love of wisdom is above them both." },
  { book: "Sirach", chapter: 40, verse: 21, text: "The pipe and the psaltery make sweet melody: but a pleasant tongue is above them both." },
  { book: "Sirach", chapter: 40, verse: 22, text: "Thine eye desireth favour and beauty: but more than both corn while it is green." },
  { book: "Sirach", chapter: 40, verse: 23, text: "A friend and companion never meet amiss: but above both is a wife with her husband." },
  { book: "Sirach", chapter: 40, verse: 24, text: "Brethren and help are against time of trouble: but alms shall deliver more than them both." },
  { book: "Sirach", chapter: 40, verse: 25, text: "Gold and silver make the foot stand sure: but counsel is esteemed above them both." },
  { book: "Sirach", chapter: 40, verse: 26, text: "Riches and strength lift up the heart: but the fear of the Lord is above them both: there is no want in the fear of the Lord, and it needeth not to seek help." },
  { book: "Sirach", chapter: 40, verse: 27, text: "The fear of the Lord is a fruitful garden, and covereth him above all glory." },
  { book: "Sirach", chapter: 40, verse: 28, text: "My son, lead not a beggar’s life; for better it is to die than to beg." },
  { book: "Sirach", chapter: 40, verse: 29, text: "The life of him that dependeth on another man’s table is not to be counted for a life; for he polluteth himself with other men’s meat: but a wise man well nurtured will beware thereof." },
  { book: "Sirach", chapter: 40, verse: 30, text: "Begging is sweet in the mouth of the shameless: but in his belly there shall burn a fire." },
  { book: "Sirach", chapter: 41, verse: 1, text: "O death, how bitter is the remembrance of thee to a man that liveth at rest in his possessions, unto the man that hath nothing to vex him, and that hath prosperity in all things: yea, unto him that is yet able to receive meat!" },
  { book: "Sirach", chapter: 41, verse: 2, text: "O death, acceptable is thy sentence unto the needy, and unto him whose strength faileth, that is now in the last age, and is vexed with all things, and to him that despaireth, and hath lost patience!" },
  { book: "Sirach", chapter: 41, verse: 3, text: "Fear not the sentence of death, remember them that have been before thee, and that come after; for this is the sentence of the Lord over all flesh." },
  { book: "Sirach", chapter: 41, verse: 4, text: "And why art thou against the pleasure of the most High? there is no inquisition in the grave, whether thou have lived ten, or an hundred, or a thousand years." },
  { book: "Sirach", chapter: 41, verse: 5, text: "The children of sinners are abominable children, and they that are conversant in the dwelling of the ungodly." },
  { book: "Sirach", chapter: 41, verse: 6, text: "The inheritance of sinners’ children shall perish, and their posterity shall have a perpetual reproach." },
  { book: "Sirach", chapter: 41, verse: 7, text: "The children will complain of an ungodly father, because they shall be reproached for his sake." },
  { book: "Sirach", chapter: 41, verse: 8, text: "Woe be unto you, ungodly men, which have forsaken the law of the most high God! for if ye increase, it shall be to your destruction:" },
  { book: "Sirach", chapter: 41, verse: 9, text: "And if ye be born, ye shall be born to a curse: and if ye die, a curse shall be your portion." },
  { book: "Sirach", chapter: 41, verse: 10, text: "All that are of the earth shall turn to earth again: so the ungodly shall go from a curse to destruction." },
  { book: "Sirach", chapter: 41, verse: 11, text: "The mourning of men is about their bodies: but an ill name of sinners shall be blotted out." },
  { book: "Sirach", chapter: 41, verse: 12, text: "Have regard to thy name; for that shall continue with thee above a thousand great treasures of gold." },
  { book: "Sirach", chapter: 41, verse: 13, text: "A good life hath but few days: but a good name endureth for ever." },
  { book: "Sirach", chapter: 41, verse: 14, text: "My children, keep discipline in peace: for wisdom that is hid, and a treasure that is not seen, what profit is in them both?" },
  { book: "Sirach", chapter: 41, verse: 15, text: "A man that hideth his foolishness is better than a man that hideth his wisdom." },
  { book: "Sirach", chapter: 41, verse: 16, text: "Therefore be shamefaced according to my word: for it is not good to retain all shamefacedness; neither is it altogether approved in every thing." },
  { book: "Sirach", chapter: 41, verse: 17, text: "Be ashamed of whoredom before father and mother: and of a lie before a prince and a mighty man;" },
  { book: "Sirach", chapter: 41, verse: 18, text: "Of an offence before a judge and ruler; of iniquity before a congregation and people; of unjust dealing before thy partner and friend;" },
  { book: "Sirach", chapter: 41, verse: 19, text: "And of theft in regard of the place where thou sojournest, and in regard of the truth of God and his covenant; and to lean with thine elbow upon the meat; and of scorning to give and take;" },
  { book: "Sirach", chapter: 41, verse: 20, text: "And of silence before them that salute thee; and to look upon an harlot;" },
  { book: "Sirach", chapter: 41, verse: 21, text: "And to turn away thy face from thy kinsman; or to take away a portion or a gift; or to gaze upon another man’s wife." },
  { book: "Sirach", chapter: 41, verse: 22, text: "Or to be overbusy with his maid, and come not near her bed; or of upbraiding speeches before friends; and after thou hast given, upbraid not;" },
  { book: "Sirach", chapter: 41, verse: 23, text: "Or of iterating and speaking again that which thou hast heard; and of revealing of secrets." },
  { book: "Sirach", chapter: 41, verse: 24, text: "So shalt thou be truly shamefaced and find favour before all men." },
  { book: "Sirach", chapter: 42, verse: 1, text: "Of these things be not thou ashamed, and accept no person to sin thereby:" },
  { book: "Sirach", chapter: 42, verse: 2, text: "Of the law of the most High, and his covenant; and of judgment to justify the ungodly;" },
  { book: "Sirach", chapter: 42, verse: 3, text: "Of reckoning with thy partners and travellers; or of the gift of the heritage of friends;" },
  { book: "Sirach", chapter: 42, verse: 4, text: "Of exactness of balance and weights; or of getting much or little;" },
  { book: "Sirach", chapter: 42, verse: 5, text: "And of merchants’ indifferent selling; of much correction of children; and to make the side of an evil servant to bleed." },
  { book: "Sirach", chapter: 42, verse: 6, text: "Sure keeping is good, where an evil wife is; and shut up, where many hands are." },
  { book: "Sirach", chapter: 42, verse: 7, text: "Deliver all things in number and weight; and put all in writing that thou givest out, or receivest in." },
  { book: "Sirach", chapter: 42, verse: 8, text: "Be not ashamed to inform the unwise and foolish, and the extreme aged that contendeth with those that are young: thus shalt thou be truly learned, and approved of all men living." },
  { book: "Sirach", chapter: 42, verse: 9, text: "The father waketh for the daughter, when no man knoweth; and the care for her taketh away sleep: when she is young, lest she pass away the flower of her age; and being married, lest she should be hated:" },
  { book: "Sirach", chapter: 42, verse: 10, text: "In her virginity, lest she should be defiled and gotten with child in her father’s house; and having an husband, lest she should misbehave herself; and when she is married, lest she should be barren." },
  { book: "Sirach", chapter: 42, verse: 11, text: "Keep a sure watch over a shameless daughter, lest she make thee a laughingstock to thine enemies, and a byword in the city, and a reproach among the people, and make thee ashamed before the multitude." },
  { book: "Sirach", chapter: 42, verse: 12, text: "Behold not every body’s beauty, and sit not in the midst of women." },
  { book: "Sirach", chapter: 42, verse: 13, text: "For from garments cometh a moth, and from women wickedness." },
  { book: "Sirach", chapter: 42, verse: 14, text: "Better is the churlishness of a man than a courteous woman, a woman, I say, which bringeth shame and reproach." },
  { book: "Sirach", chapter: 42, verse: 15, text: "I will now remember the works of the Lord, and declare the things that I have seen: In the words of the Lord are his works." },
  { book: "Sirach", chapter: 42, verse: 16, text: "The sun that giveth light looketh upon all things, and the work thereof is full of the glory of the Lord." },
  { book: "Sirach", chapter: 42, verse: 17, text: "The Lord hath not given power to the saints to declare all his marvellous works, which the Almighty Lord firmly settled, that whatsoever is might be established for his glory." },
  { book: "Sirach", chapter: 42, verse: 18, text: "He seeketh out the deep, and the heart, and considereth their crafty devices: for the Lord knoweth all that may be known, and he beholdeth the signs of the world." },
  { book: "Sirach", chapter: 42, verse: 19, text: "He declareth the things that are past, and for to come, and revealeth the steps of hidden things." },
  { book: "Sirach", chapter: 42, verse: 20, text: "No thought escapeth him, neither any word is hidden from him." },
  { book: "Sirach", chapter: 42, verse: 21, text: "He hath garnished the excellent works of his wisdom, and he is from everlasting to everlasting: unto him may nothing be added, neither can he be diminished, and he hath no need of any counsellor." },
  { book: "Sirach", chapter: 42, verse: 22, text: "Oh how desirable are all his works! and that a man may see even to a spark." },
  { book: "Sirach", chapter: 42, verse: 23, text: "All these things live and remain for ever for all uses, and they are all obedient." },
  { book: "Sirach", chapter: 42, verse: 24, text: "All things are double one against another: and he hath made nothing imperfect." },
  { book: "Sirach", chapter: 42, verse: 25, text: "One thing establisheth the good or another: and who shall be filled with beholding his glory?" },
  { book: "Sirach", chapter: 43, verse: 1, text: "The pride of the height, the clear firmament, the beauty of heaven, with his glorious shew;" },
  { book: "Sirach", chapter: 43, verse: 2, text: "The sun when it appeareth, declaring at his rising a marvellous instrument, the work of the most High:" },
  { book: "Sirach", chapter: 43, verse: 3, text: "At noon it parcheth the country, and who can abide the burning heat thereof?" },
  { book: "Sirach", chapter: 43, verse: 4, text: "A man blowing a furnace is in works of heat, but the sun burneth the mountains three times more; breathing out fiery vapours, and sending forth bright beams, it dimmeth the eyes." },
  { book: "Sirach", chapter: 43, verse: 5, text: "Great is the Lord that made it; and at his commandment runneth hastily." },
  { book: "Sirach", chapter: 43, verse: 6, text: "He made the moon also to serve in her season for a declaration of times, and a sign of the world." },
  { book: "Sirach", chapter: 43, verse: 7, text: "From the moon is the sign of feasts, a light that decreaseth in her perfection." },
  { book: "Sirach", chapter: 43, verse: 8, text: "The month is called after her name, increasing wonderfully in her changing, being an instrument of the armies above, shining in the firmament of heaven;" },
  { book: "Sirach", chapter: 43, verse: 9, text: "The beauty of heaven, the glory of the stars, an ornament giving light in the highest places of the Lord." },
  { book: "Sirach", chapter: 43, verse: 10, text: "At the commandment of the Holy One they will stand in their order, and never faint in their watches." },
  { book: "Sirach", chapter: 43, verse: 11, text: "Look upon the rainbow, and praise him that made it; very beautiful it is in the brightness thereof." },
  { book: "Sirach", chapter: 43, verse: 12, text: "It compasseth the heaven about with a glorious circle, and the hands of the most High have bended it." },
  { book: "Sirach", chapter: 43, verse: 13, text: "By his commandment he maketh the snow to fall aplace, and sendeth swiftly the lightnings of his judgment." },
  { book: "Sirach", chapter: 43, verse: 14, text: "Through this the treasures are opened: and clouds fly forth as fowls." },
  { book: "Sirach", chapter: 43, verse: 15, text: "By his great power he maketh the clouds firm, and the hailstones are broken small." },
  { book: "Sirach", chapter: 43, verse: 16, text: "At his sight the mountains are shaken, and at his will the south wind bloweth." },
  { book: "Sirach", chapter: 43, verse: 17, text: "The noise of the thunder maketh the earth to tremble: so doth the northern storm and the whirlwind: as birds flying he scattereth the snow, and the falling down thereof is as the lighting of grasshoppers:" },
  { book: "Sirach", chapter: 43, verse: 18, text: "The eye marvelleth at the beauty of the whiteness thereof, and the heart is astonished at the raining of it." },
  { book: "Sirach", chapter: 43, verse: 19, text: "The hoarfrost also as salt he poureth on the earth, and being congealed, it lieth on the top of sharp stakes." },
  { book: "Sirach", chapter: 43, verse: 20, text: "When the cold north wind bloweth, and the water is congealed into ice, it abideth upon every gathering together of water, and clotheth the water as with a breastplate." },
  { book: "Sirach", chapter: 43, verse: 21, text: "It devoureth the mountains, and burneth the wilderness, and consumeth the grass as fire." },
  { book: "Sirach", chapter: 43, verse: 22, text: "A present remedy of all is a mist coming speedily, a dew coming after heat refresheth." },
  { book: "Sirach", chapter: 43, verse: 23, text: "By his counsel he appeaseth the deep, and planteth islands therein." },
  { book: "Sirach", chapter: 43, verse: 24, text: "They that sail on the sea tell of the danger thereof; and when we hear it with our ears, we marvel thereat." },
  { book: "Sirach", chapter: 43, verse: 25, text: "For therein be strange and wondrous works, variety of all kinds of beasts and whales created." },
  { book: "Sirach", chapter: 43, verse: 26, text: "By him the end of them hath prosperous success, and by his word all things consist." },
  { book: "Sirach", chapter: 43, verse: 27, text: "We may speak much, and yet come short: wherefore in sum, he is all." },
  { book: "Sirach", chapter: 43, verse: 28, text: "How shall we be able to magnify him? for he is great above all his works." },
  { book: "Sirach", chapter: 43, verse: 29, text: "The Lord is terrible and very great, and marvellous is his power." },
  { book: "Sirach", chapter: 43, verse: 30, text: "When ye glorify the Lord, exalt him as much as ye can; for even yet will he far exceed: and when ye exalt him, put forth all your strength, and be not weary; for ye can never go far enough." },
  { book: "Sirach", chapter: 43, verse: 31, text: "Who hath seen him, that he might tell us? and who can magnify him as he is?" },
  { book: "Sirach", chapter: 43, verse: 32, text: "There are yet hid greater things than these be, for we have seen but a few of his works." },
  { book: "Sirach", chapter: 43, verse: 33, text: "For the Lord hath made all things; and to the godly hath he given wisdom." },
  { book: "Sirach", chapter: 44, verse: 1, text: "Let us now praise famous men, and our fathers that begat us." },
  { book: "Sirach", chapter: 44, verse: 2, text: "The Lord hath wrought great glory by them through his great power from the beginning." },
  { book: "Sirach", chapter: 44, verse: 3, text: "Such as did bear rule in their kingdoms, men renowned for their power, giving counsel by their understanding, and declaring prophecies:" },
  { book: "Sirach", chapter: 44, verse: 4, text: "Leaders of the people by their counsels, and by their knowledge of learning meet for the people, wise and eloquent are their instructions:" },
  { book: "Sirach", chapter: 44, verse: 5, text: "Such as found out musical tunes, and recited verses in writing:" },
  { book: "Sirach", chapter: 44, verse: 6, text: "Rich men furnished with ability, living peaceably in their habitations:" },
  { book: "Sirach", chapter: 44, verse: 7, text: "All these were honoured in their generations, and were the glory of their times." },
  { book: "Sirach", chapter: 44, verse: 8, text: "There be of them, that have left a name behind them, that their praises might be reported." },
  { book: "Sirach", chapter: 44, verse: 9, text: "And some there be, which have no memorial; who are perished, as though they had never been; and are become as though they had never been born; and their children after them." },
  { book: "Sirach", chapter: 44, verse: 10, text: "But these were merciful men, whose righteousness hath not been forgotten." },
  { book: "Sirach", chapter: 44, verse: 11, text: "With their seed shall continually remain a good inheritance, and their children are within the covenant." },
  { book: "Sirach", chapter: 44, verse: 12, text: "Their seed standeth fast, and their children for their sakes." },
  { book: "Sirach", chapter: 44, verse: 13, text: "Their seed shall remain for ever, and their glory shall not be blotted out." },
  { book: "Sirach", chapter: 44, verse: 14, text: "Their bodies are buried in peace; but their name liveth for evermore." },
  { book: "Sirach", chapter: 44, verse: 15, text: "The people will tell of their wisdom, and the congregation will shew forth their praise." },
  { book: "Sirach", chapter: 44, verse: 16, text: "Enoch pleased the Lord, and was translated, being an example of repentance to all generations." },
  { book: "Sirach", chapter: 44, verse: 17, text: "Noah was found perfect and righteous; in the time of wrath he was taken in exchange for the world; therefore was he left as a remnant unto the earth, when the flood came." },
  { book: "Sirach", chapter: 44, verse: 18, text: "An everlasting covenant was made with him, that all flesh should perish no more by the flood." },
  { book: "Sirach", chapter: 44, verse: 19, text: "Abraham was a great father of many people: in glory was there none like unto him;" },
  { book: "Sirach", chapter: 44, verse: 20, text: "Who kept the law of the most High, and was in covenant with him: he established the covenant in his flesh; and when he was proved, he was found faithful." },
  { book: "Sirach", chapter: 44, verse: 21, text: "Therefore he assured him by an oath, that he would bless the nations in his seed, and that he would multiply him as the dust of the earth, and exalt his seed as the stars, and cause them to inherit from sea to sea, and from the river unto the utmost part of the land." },
  { book: "Sirach", chapter: 44, verse: 22, text: "With Isaac did he establish likewise for Abraham his father’s sake the blessing of all men, and the covenant, And made it rest upon the head of Jacob. He acknowledged him in his blessing, and gave him an heritage, and divided his portions; among the twelve tribes did he part them." },
  { book: "Sirach", chapter: 45, verse: 1, text: "And he brought out of him a merciful man, which found favour in the sight of all flesh, even Moses, beloved of God and men, whose memorial is blessed." },
  { book: "Sirach", chapter: 45, verse: 2, text: "He made him like to the glorious saints, and magnified him, so that his enemies stood in fear of him." },
  { book: "Sirach", chapter: 45, verse: 3, text: "By his words he caused the wonders to cease, and he made him glorious in the sight of kings, and gave him a commandment for his people, and shewed him part of his glory." },
  { book: "Sirach", chapter: 45, verse: 4, text: "He sanctified him in his faithfuless and meekness, and chose him out of all men." },
  { book: "Sirach", chapter: 45, verse: 5, text: "He made him to hear his voice, and brought him into the dark cloud, and gave him commandments before his face, even the law of life and knowledge, that he might teach Jacob his covenants, and Israel his judgments." },
  { book: "Sirach", chapter: 45, verse: 6, text: "He exalted Aaron, an holy man like unto him, even his brother, of the tribe of Levi." },
  { book: "Sirach", chapter: 45, verse: 7, text: "An everlasting covenant he made with him and gave him the priesthood among the people; he beautified him with comely ornaments, and clothed him with a robe of glory." },
  { book: "Sirach", chapter: 45, verse: 8, text: "He put upon him perfect glory; and strengthened him with rich garments, with breeches, with a long robe, and the ephod." },
  { book: "Sirach", chapter: 45, verse: 9, text: "And he compassed him with pomegranates, and with many golden bells round about, that as he went there might be a sound, and a noise made that might be heard in the temple, for a memorial to the children of his people;" },
  { book: "Sirach", chapter: 45, verse: 10, text: "With an holy garment, with gold, and blue silk, and purple, the work of the embroiderer, with a breastplate of judgment, and with Urim and Thummim;" },
  { book: "Sirach", chapter: 45, verse: 11, text: "With twisted scarlet, the work of the cunning workman, with precious stones graven like seals, and set in gold, the work of the jeweller, with a writing engraved for a memorial, after the number of the tribes of Israel." },
  { book: "Sirach", chapter: 45, verse: 12, text: "He set a crown of gold upon the mitre, wherein was engraved Holiness, an ornament of honour, a costly work, the desires of the eyes, goodly and beautiful." },
  { book: "Sirach", chapter: 45, verse: 13, text: "Before him there were none such, neither did ever any stranger put them on, but only his children and his children’s children perpetually." },
  { book: "Sirach", chapter: 45, verse: 14, text: "Their sacrifices shall be wholly consumed every day twice continually." },
  { book: "Sirach", chapter: 45, verse: 15, text: "Moses consecrated him, and anointed him with holy oil: this was appointed unto him by an everlasting covenant, and to his seed, so long as the heavens should remain, that they should minister unto him, and execute the office of the priesthood, and bless the people in his name." },
  { book: "Sirach", chapter: 45, verse: 16, text: "He chose him out of all men living to offer sacrifices to the Lord, incense, and a sweet savour, for a memorial, to make reconciliation for his people." },
  { book: "Sirach", chapter: 45, verse: 17, text: "He gave unto him his commandments, and authority in the statutes of judgments, that he should teach Jacob the testimonies, and inform Israel in his laws." },
  { book: "Sirach", chapter: 45, verse: 18, text: "Strangers conspired together against him, and maligned him in the wilderness, even the men that were of Dathan’s and Abiron’s side, and the congregation of Core, with fury and wrath." },
  { book: "Sirach", chapter: 45, verse: 19, text: "This the Lord saw, and it displeased him, and in his wrathful indignation were they consumed: he did wonders upon them, to consume them with the fiery flame." },
  { book: "Sirach", chapter: 45, verse: 20, text: "But he made Aaron more honourable, and gave him an heritage, and divided unto him the firstfruits of the increase; especially he prepared bread in abundance:" },
  { book: "Sirach", chapter: 45, verse: 21, text: "For they eat of the sacrifices of the Lord, which he gave unto him and his seed." },
  { book: "Sirach", chapter: 45, verse: 22, text: "Howbeit in the land of the people he had no inheritance, neither had he any portion among the people: for the Lord himself is his portion and inheritance." },
  { book: "Sirach", chapter: 45, verse: 23, text: "The third in glory is Phinees the son of Eleazar, because he had zeal in the fear of the Lord, and stood up with good courage of heart: when the people were turned back, and made reconciliation for Israel." },
  { book: "Sirach", chapter: 45, verse: 24, text: "Therefore was there a covenant of peace made with him, that he should be the chief of the sanctuary and of his people, and that he and his posterity should have the dignity of the priesthood for ever:" },
  { book: "Sirach", chapter: 45, verse: 25, text: "According to the covenant made with David son of Jesse, of the tribe of Juda, that the inheritance of the king should be to his posterity alone: so the inheritance of Aaron should also be unto his seed." },
  { book: "Sirach", chapter: 45, verse: 26, text: "God give you wisdom in your heart to judge his people in righteousness, that their good things be not abolished, and that their glory may endure for ever." },
  { book: "Sirach", chapter: 46, verse: 1, text: "Jesus the son a Nave was valiant in the wars, and was the successor of Moses in prophecies, who according to his name was made great for the saving of the elect of God, and taking vengeance of the enemies that rose up against them, that he might set Israel in their inheritance." },
  { book: "Sirach", chapter: 46, verse: 2, text: "How great glory gat he, when he did lift up his hands, and stretched out his sword against the cities!" },
  { book: "Sirach", chapter: 46, verse: 3, text: "Who before him so stood to it? for the Lord himself brought his enemies unto him." },
  { book: "Sirach", chapter: 46, verse: 4, text: "Did not the sun go back by his means? and was not one day as long as two?" },
  { book: "Sirach", chapter: 46, verse: 5, text: "He called upon the most high Lord, when the enemies pressed upon him on every side; and the great Lord heard him." },
  { book: "Sirach", chapter: 46, verse: 6, text: "And with hailstones of mighty power he made the battle to fall violently upon the nations, and in the descent of Beth-horon he destroyed them that resisted, that the nations might know all their strength, because he fought in the sight of the Lord, and he followed the Mighty One." },
  { book: "Sirach", chapter: 46, verse: 7, text: "In the time of Moses also he did a work of mercy, he and Caleb the son of Jephunne, in that they withstood the congregation, and withheld the people from sin, and appeased the wicked murmuring." },
  { book: "Sirach", chapter: 46, verse: 8, text: "And of six hundred thousand people on foot, they two were preserved to bring them in to the heritage, even unto the land that floweth with milk and honey." },
  { book: "Sirach", chapter: 46, verse: 9, text: "The Lord gave strength also unto Caleb, which remained with him unto his old age: so that he entered upon the high places of the land, and his seed obtained it for an heritage:" },
  { book: "Sirach", chapter: 46, verse: 10, text: "That all the children of Israel might see that it is good to follow the Lord." },
  { book: "Sirach", chapter: 46, verse: 11, text: "And concerning the judges, every one by name, whose heart went not a whoring, nor departed from the Lord, let their memory be blessed." },
  { book: "Sirach", chapter: 46, verse: 12, text: "Let their bones flourish out of their place, and let the name of them that were honoured be continued upon their children." },
  { book: "Sirach", chapter: 46, verse: 13, text: "Samuel, the prophet of the Lord, beloved of his Lord, established a kingdom, and anointed princes over his people." },
  { book: "Sirach", chapter: 46, verse: 14, text: "By the law of the Lord he judged the congregation, and the Lord had respect unto Jacob." },
  { book: "Sirach", chapter: 46, verse: 15, text: "By his faithfulness he was found a true prophet, and by his word he was known to be faithful in vision." },
  { book: "Sirach", chapter: 46, verse: 16, text: "He called upon the mighty Lord, when his enemies pressed upon him on every side, when he offered the sucking lamb." },
  { book: "Sirach", chapter: 46, verse: 17, text: "And the Lord thundered from heaven, and with a great noise made his voice to be heard." },
  { book: "Sirach", chapter: 46, verse: 18, text: "And he destroyed the rulers of the Tyrians, and all the princes of the Philistines." },
  { book: "Sirach", chapter: 46, verse: 19, text: "And before his long sleep he made protestations in the sight of the Lord and his anointed, I have not taken any man’s goods, so much as a shoe: and no man did accuse him." },
  { book: "Sirach", chapter: 46, verse: 20, text: "And after his death he prophesied, and shewed the king his end, and lifted up his voice from the earth in prophecy, to blot out the wickedness of the people." },
  { book: "Sirach", chapter: 47, verse: 1, text: "And after him rose up Nathan to prophesy in the time of David." },
  { book: "Sirach", chapter: 47, verse: 2, text: "As is the fat taken away from the peace offering, so was David chosen out of the children of Israel." },
  { book: "Sirach", chapter: 47, verse: 3, text: "He played with lions as with kids, and with bears as with lambs." },
  { book: "Sirach", chapter: 47, verse: 4, text: "Slew he not a giant, when he was yet but young? and did he not take away reproach from the people, when he lifted up his hand with the stone in the sling, and beat down the boasting of Goliath?" },
  { book: "Sirach", chapter: 47, verse: 5, text: "For he called upon the most high Lord; and he gave him strength in his right hand to slay that mighty warrior, and set up the horn of his people." },
  { book: "Sirach", chapter: 47, verse: 6, text: "So the people honoured him with ten thousands, and praised him in the blessings of the Lord, in that he gave him a crown of glory." },
  { book: "Sirach", chapter: 47, verse: 7, text: "For he destroyed the enemies on every side, and brought to nought the Philistines his adversaries, and brake their horn in sunder unto this day." },
  { book: "Sirach", chapter: 47, verse: 8, text: "In all his works he praised the Holy One most high with words of glory; with his whole heart he sung songs, and loved him that made him." },
  { book: "Sirach", chapter: 47, verse: 9, text: "He set singers also before the altar, that by their voices they might make sweet melody, and daily sing praises in their songs." },
  { book: "Sirach", chapter: 47, verse: 10, text: "He beautified their feasts, and set in order the solemn times until the end, that they might praise his holy name, and that the temple might sound from morning." },
  { book: "Sirach", chapter: 47, verse: 11, text: "The Lord took away his sins, and exalted his horn for ever: he gave him a covenant of kings, and a throne of glory in Israel." },
  { book: "Sirach", chapter: 47, verse: 12, text: "After him rose up a wise son, and for his sake he dwelt at large." },
  { book: "Sirach", chapter: 47, verse: 13, text: "Solomon reigned in a peaceable time, and was honoured; for God made all quiet round about him, that he might build an house in his name, and prepare his sanctuary for ever." },
  { book: "Sirach", chapter: 47, verse: 14, text: "How wise wast thou in thy youth and, as a flood, filled with understanding!" },
  { book: "Sirach", chapter: 47, verse: 15, text: "Thy soul covered the whole earth, and thou filledst it with dark parables." },
  { book: "Sirach", chapter: 47, verse: 16, text: "Thy name went far unto the islands; and for thy peace thou wast beloved." },
  { book: "Sirach", chapter: 47, verse: 17, text: "The countries marvelled at thee for thy songs, and proverbs, and parables, and interpretations." },
  { book: "Sirach", chapter: 47, verse: 18, text: "By the name of the Lord God, which is called the Lord God of Israel, thou didst gather gold as tin and didst multiply silver as lead." },
  { book: "Sirach", chapter: 47, verse: 19, text: "Thou didst bow thy loins unto women, and by thy body thou wast brought into subjection." },
  { book: "Sirach", chapter: 47, verse: 20, text: "Thou didst stain thy honour, and pollute thy seed: so that thou broughtest wrath upon thy children, and wast grieved for thy folly." },
  { book: "Sirach", chapter: 47, verse: 21, text: "So the kingdom was divided, and out of Ephraim ruled a rebellious kingdom." },
  { book: "Sirach", chapter: 47, verse: 22, text: "But the Lord will never leave off his mercy, neither shall any of his works perish, neither will he abolish the posterity of his elect, and the seed of him that loveth him he will not take away: wherefore he gave a remnant unto Jacob, and out of him a root unto David." },
  { book: "Sirach", chapter: 47, verse: 23, text: "Thus rested Solomon with his fathers, and of his seed he left behind him Roboam, even the foolishness of the people, and one that had no understanding, who turned away the people through his counsel. There was also Jeroboam the son of Nebat, who caused Israel to sin, and shewed Ephraim the way of sin:" },
  { book: "Sirach", chapter: 47, verse: 24, text: "And their sins were multiplied exceedingly, that they were driven out of the land." },
  { book: "Sirach", chapter: 47, verse: 25, text: "For they sought out all wickedness, till the vengeance came upon them." },
  { book: "Sirach", chapter: 48, verse: 1, text: "Then stood up Elias the prophet as fire, and his word burned like a lamp." },
  { book: "Sirach", chapter: 48, verse: 2, text: "He brought a sore famine upon them, and by his zeal he diminished their number." },
  { book: "Sirach", chapter: 48, verse: 3, text: "By the word of the Lord he shut up the heaven, and also three times brought down fire." },
  { book: "Sirach", chapter: 48, verse: 4, text: "O Elias, how wast thou honoured in thy wondrous deeds! and who may glory like unto thee!" },
  { book: "Sirach", chapter: 48, verse: 5, text: "Who didst raise up a dead man from death, and his soul from the place of the dead, by the word of the most High:" },
  { book: "Sirach", chapter: 48, verse: 6, text: "Who broughtest kings to destruction, and honorable men from their bed:" },
  { book: "Sirach", chapter: 48, verse: 7, text: "Who heardest the rebuke of the Lord in Sinai, and in Horeb the judgment of vengeance:" },
  { book: "Sirach", chapter: 48, verse: 8, text: "Who annointedst kings to take revenge, and prophets to succeed after him:" },
  { book: "Sirach", chapter: 48, verse: 9, text: "Who was taken up in a whirlwind of fire, and in a chariot of fiery horses:" },
  { book: "Sirach", chapter: 48, verse: 10, text: "Who wast ordained for reproofs in their times, to pacify the wrath of the Lord’s judgment, before it brake forth into fury, and to turn the heart of the father unto the son, and to restore the tribes of Jacob." },
  { book: "Sirach", chapter: 48, verse: 11, text: "Blessed are they that saw thee, and slept in love; for we shall surely live." },
  { book: "Sirach", chapter: 48, verse: 12, text: "Elias it was, who was covered with a whirlwind: and Eliseus was filled with his spirit: whilst he lived, he was not moved with the presence of any prince, neither could any bring him into subjection." },
  { book: "Sirach", chapter: 48, verse: 13, text: "No word could overcome him; and after his death his body prophesied." },
  { book: "Sirach", chapter: 48, verse: 14, text: "He did wonders in his life, and at his death were his works marvellous." },
  { book: "Sirach", chapter: 48, verse: 15, text: "For all this the people repented not, neither departed they from their sins, till they were spoiled and carried out of their land, and were scattered through all the earth: yet there remained a small people, and a ruler in the house of David:" },
  { book: "Sirach", chapter: 48, verse: 16, text: "Of whom some did that which was pleasing to God, and some multiplied sins." },
  { book: "Sirach", chapter: 48, verse: 17, text: "Ezekias fortified his city, and brought in water into the midst thereof: he digged the hard rock with iron, and made wells for waters." },
  { book: "Sirach", chapter: 48, verse: 18, text: "In his time Sennacherib came up, and sent Rabsaces, and lifted up his hand against Sion, and boasted proudly." },
  { book: "Sirach", chapter: 48, verse: 19, text: "Then trembled their hearts and hands, and they were in pain, as women in travail." },
  { book: "Sirach", chapter: 48, verse: 20, text: "But they called upon the Lord which is merciful, and stretched out their hands toward him: and immediately the Holy One heard them out of heaven, and delivered them by the ministry of Esay." },
  { book: "Sirach", chapter: 48, verse: 21, text: "He smote the host of the Assyrians, and his angel destroyed them." },
  { book: "Sirach", chapter: 48, verse: 22, text: "For Ezekias had done the thing that pleased the Lord, and was strong in the ways of David his father, as Esay the prophet, who was great and faithful in his vision, had commanded him." },
  { book: "Sirach", chapter: 48, verse: 23, text: "In his time the sun went backward, and he lengthened the king’s life." },
  { book: "Sirach", chapter: 48, verse: 24, text: "He saw by an excellent spirit what should come to pass at the last, and he comforted them that mourned in Sion." },
  { book: "Sirach", chapter: 48, verse: 25, text: "He shewed what should come to pass for ever, and secret things or ever they came." },
  { book: "Sirach", chapter: 49, verse: 1, text: "The remembrance of Josias is like the composition of the perfume that is made by the art of the apothecary: it is sweet as honey in all mouths, and as musick at a banquet of wine." },
  { book: "Sirach", chapter: 49, verse: 2, text: "He behaved himself uprightly in the conversion of the people, and took away the abominations of iniquity." },
  { book: "Sirach", chapter: 49, verse: 3, text: "He directed his heart unto the Lord, and in the time of the ungodly he established the worship of God." },
  { book: "Sirach", chapter: 49, verse: 4, text: "All, except David and Ezekias and Josias, were defective: for they forsook the law of the most High, even the kings of Juda failed." },
  { book: "Sirach", chapter: 49, verse: 5, text: "Therefore he gave their power unto others, and their glory to a strange nation." },
  { book: "Sirach", chapter: 49, verse: 6, text: "They burnt the chosen city of the sanctuary, and made the streets desolate, according to the prophecy of Jeremias." },
  { book: "Sirach", chapter: 49, verse: 7, text: "For they entreated him evil, who nevertheless was a prophet, sanctified in his mother’s womb, that he might root out, and afflict, and destroy; and that he might build up also, and plant." },
  { book: "Sirach", chapter: 49, verse: 8, text: "It was Ezekiel who saw the glorious vision, which was shewed him upon the chariot of the cherubims." },
  { book: "Sirach", chapter: 49, verse: 9, text: "For he made mention of the enemies under the figure of the rain, and directed them that went right." },
  { book: "Sirach", chapter: 49, verse: 10, text: "And of the twelve prophets let the memorial be blessed, and let their bones flourish again out of their place: for they comforted Jacob, and delivered them by assured hope." },
  { book: "Sirach", chapter: 49, verse: 11, text: "How shall we magnify Zorobabel? even he was as a signet on the right hand:" },
  { book: "Sirach", chapter: 49, verse: 12, text: "So was Jesus the son of Josedec: who in their time builded the house, and set up an holy temple to the Lord, which was prepared for everlasting glory." },
  { book: "Sirach", chapter: 49, verse: 13, text: "And among the elect was Neemias, whose renown is great, who raised up for us the walls that were fallen, and set up the gates and the bars, and raised up our ruins again." },
  { book: "Sirach", chapter: 49, verse: 14, text: "But upon the earth was no man created like Enoch; for he was taken from the earth." },
  { book: "Sirach", chapter: 49, verse: 15, text: "Neither was there a young man born like Joseph, a governor of his brethren, a stay of the people, whose bones were regarded of the Lord." },
  { book: "Sirach", chapter: 49, verse: 16, text: "Sem and Seth were in great honour among men, and so was Adam above every living thing in creation." },
  { book: "Sirach", chapter: 50, verse: 1, text: "Simon the high priest, the son of Onias, who in his life repaired the house again, and in his days fortified the temple:" },
  { book: "Sirach", chapter: 50, verse: 2, text: "And by him was built from the foundation the double height, the high fortress of the wall about the temple:" },
  { book: "Sirach", chapter: 50, verse: 3, text: "In his days the cistern to receive water, being in compass as the sea, was covered with plates of brass:" },
  { book: "Sirach", chapter: 50, verse: 4, text: "He took care of the temple that it should not fall, and fortified the city against besieging:" },
  { book: "Sirach", chapter: 50, verse: 5, text: "How was he honoured in the midst of the people in his coming out of the sanctuary!" },
  { book: "Sirach", chapter: 50, verse: 6, text: "He was as the morning star in the midst of a cloud, and as the moon at the full:" },
  { book: "Sirach", chapter: 50, verse: 7, text: "As the sun shining upon the temple of the most High, and as the rainbow giving light in the bright clouds:" },
  { book: "Sirach", chapter: 50, verse: 8, text: "And as the flower of roses in the spring of the year, as lilies by the rivers of waters, and as the branches of the frankincense tree in the time of summer:" },
  { book: "Sirach", chapter: 50, verse: 9, text: "As fire and incense in the censer, and as a vessel of beaten gold set with all manner of precious stones:" },
  { book: "Sirach", chapter: 50, verse: 10, text: "And as a fair olive tree budding forth fruit, and as a cypress tree which groweth up to the clouds." },
  { book: "Sirach", chapter: 50, verse: 11, text: "When he put on the robe of honour, and was clothed with the perfection of glory, when he went up to the holy altar, he made the garment of holiness honourable." },
  { book: "Sirach", chapter: 50, verse: 12, text: "When he took the portions out of the priests’ hands, he himself stood by the hearth of the altar, compassed about, as a young cedar in Libanus; and as palm trees compassed they him round about." },
  { book: "Sirach", chapter: 50, verse: 13, text: "So were all the sons of Aaron in their glory, and the oblations of the Lord in their hands, before all the congregation of Israel." },
  { book: "Sirach", chapter: 50, verse: 14, text: "And finishing the service at the altar, that he might adorn the offering of the most high Almighty," },
  { book: "Sirach", chapter: 50, verse: 15, text: "He stretched out his hand to the cup, and poured of the blood of the grape, he poured out at the foot of the altar a sweetsmelling savour unto the most high King of all." },
  { book: "Sirach", chapter: 50, verse: 16, text: "Then shouted the sons of Aaron, and sounded the silver trumpets, and made a great noise to be heard, for a remembrance before the most High." },
  { book: "Sirach", chapter: 50, verse: 17, text: "Then all the people together hasted, and fell down to the earth upon their faces to worship their Lord God Almighty, the most High." },
  { book: "Sirach", chapter: 50, verse: 18, text: "The singers also sang praises with their voices, with great variety of sounds was there made sweet melody." },
  { book: "Sirach", chapter: 50, verse: 19, text: "And the people besought the Lord, the most High, by prayer before him that is merciful, till the solemnity of the Lord was ended, and they had finished his service." },
  { book: "Sirach", chapter: 50, verse: 20, text: "Then he went down, and lifted up his hands over the whole congregation of the children of Israel, to give the blessing of the Lord with his lips, and to rejoice in his name." },
  { book: "Sirach", chapter: 50, verse: 21, text: "And they bowed themselves down to worship the second time, that they might receive a blessing from the most High." },
  { book: "Sirach", chapter: 50, verse: 22, text: "Now therefore bless ye the God of all, which only doeth wondrous things every where, which exalteth our days from the womb, and dealeth with us according to his mercy." },
  { book: "Sirach", chapter: 50, verse: 23, text: "He grant us joyfulness of heart, and that peace may be in our days in Israel for ever:" },
  { book: "Sirach", chapter: 50, verse: 24, text: "That he would confirm his mercy with us, and deliver us at his time!" },
  { book: "Sirach", chapter: 50, verse: 25, text: "There be two manner of nations which my heart abhorreth, and the third is no nation:" },
  { book: "Sirach", chapter: 50, verse: 26, text: "They that sit upon the mountain of Samaria, and they that dwell among the Philistines, and that foolish people that dwell in Sichem." },
  { book: "Sirach", chapter: 50, verse: 27, text: "Jesus the son of Sirach of Jerusalem hath written in this book the instruction of understanding and knowledge, who out of his heart poured forth wisdom." },
  { book: "Sirach", chapter: 50, verse: 28, text: "Blessed is he that shall be exercised in these things; and he that layeth them up in his heart shall become wise." },
  { book: "Sirach", chapter: 50, verse: 29, text: "For if he do them, he shall be strong to all things: for the light of the Lord leadeth him, who giveth wisdom to the godly. Blessed be the name of the Lord for ever. Amen, Amen." },
  { book: "Sirach", chapter: 51, verse: 1, text: "I will thank thee, O Lord and King, and praise thee, O God my Saviour: I do give praise unto thy name:" },
  { book: "Sirach", chapter: 51, verse: 2, text: "For thou art my defender and helper, and has preserved my body from destruction, and from the snare of the slanderous tongue, and from the lips that forge lies, and has been mine helper against mine adversaries:" },
  { book: "Sirach", chapter: 51, verse: 3, text: "And hast delivered me, according to the multitude of they mercies and greatness of thy name, from the teeth of them that were ready to devour me, and out of the hands of such as sought after my life, and from the manifold afflictions which I had;" },
  { book: "Sirach", chapter: 51, verse: 4, text: "From the choking of fire on every side, and from the midst of the fire which I kindled not;" },
  { book: "Sirach", chapter: 51, verse: 5, text: "From the depth of the belly of hell, from an unclean tongue, and from lying words." },
  { book: "Sirach", chapter: 51, verse: 6, text: "By an accusation to the king from an unrighteous tongue my soul drew near even unto death, my life was near to the hell beneath." },
  { book: "Sirach", chapter: 51, verse: 7, text: "They compassed me on every side, and there was no man to help me: I looked for the succour of men, but there was none." },
  { book: "Sirach", chapter: 51, verse: 8, text: "Then thought I upon thy mercy, O Lord, and upon thy acts of old, how thou deliverest such as wait for thee, and savest them out of the hands of the enemies." },
  { book: "Sirach", chapter: 51, verse: 9, text: "Then lifted I up my supplications from the earth, and prayed for deliverance from death." },
  { book: "Sirach", chapter: 51, verse: 10, text: "I called upon the Lord, the Father of my Lord, that he would not leave me in the days of my trouble, and in the time of the proud, when there was no help." },
  { book: "Sirach", chapter: 51, verse: 11, text: "I will praise thy name continually, and will sing praises with thanksgiving; and so my prayer was heard:" },
  { book: "Sirach", chapter: 51, verse: 12, text: "For thou savedst me from destruction, and deliveredst me from the evil time: therefore will I give thanks, and praise thee, and bless they name, O Lord." },
  { book: "Sirach", chapter: 51, verse: 13, text: "When I was yet young, or ever I went abroad, I desired wisdom openly in my prayer." },
  { book: "Sirach", chapter: 51, verse: 14, text: "I prayed for her before the temple, and will seek her out even to the end." },
  { book: "Sirach", chapter: 51, verse: 15, text: "Even from the flower till the grape was ripe hath my heart delighted in her: my foot went the right way, from my youth up sought I after her." },
  { book: "Sirach", chapter: 51, verse: 16, text: "I bowed down mine ear a little, and received her, and gat much learning." },
  { book: "Sirach", chapter: 51, verse: 17, text: "I profited therein, therefore will I ascribe glory unto him that giveth me wisdom." },
  { book: "Sirach", chapter: 51, verse: 18, text: "For I purposed to do after her, and earnestly I followed that which is good; so shall I not be confounded." },
  { book: "Sirach", chapter: 51, verse: 19, text: "My soul hath wrestled with her, and in my doings I was exact: I stretched forth my hands to the heaven above, and bewailed my ignorances of her." },
  { book: "Sirach", chapter: 51, verse: 20, text: "I directed my soul unto her, and I found her in pureness: I have had my heart joined with her from the beginning, therefore shall I not be forsaken." },
  { book: "Sirach", chapter: 51, verse: 21, text: "My heart was troubled in seeking her: therefore have I gotten a good possession." },
  { book: "Sirach", chapter: 51, verse: 22, text: "The Lord hath given me a tongue for my reward, and I will praise him therewith." },
  { book: "Sirach", chapter: 51, verse: 23, text: "Draw near unto me, ye unlearned, and dwell in the house of learning." },
  { book: "Sirach", chapter: 51, verse: 24, text: "Wherefore are ye slow, and what say ye to these things, seeing your souls are very thirsty?" },
  { book: "Sirach", chapter: 51, verse: 25, text: "I opened my mouth, and said, Buy her for yourselves without money." },
  { book: "Sirach", chapter: 51, verse: 26, text: "Put your neck under the yoke, and let your soul receive instruction: she is hard at hand to find." },
  { book: "Sirach", chapter: 51, verse: 27, text: "Behold with your eyes, how that I have but little labour, and have gotten unto me much rest." },
  { book: "Sirach", chapter: 51, verse: 28, text: "Get learning with a great sum of money, and get much gold by her." },
  { book: "Sirach", chapter: 51, verse: 29, text: "Let your soul rejoice in his mercy, and be not ashamed of his praise." },
  { book: "Sirach", chapter: 51, verse: 30, text: "Work your work betimes, and in his time he will give you your reward." },
  // Susanna (64 verses)
  { book: "Susanna", chapter: 1, verse: 1, text: "There dwelt a man in Babylon, called Joacim:" },
  { book: "Susanna", chapter: 1, verse: 2, text: "And he took a wife, whose name was Susanna, the daughter of Chelcias, a very fair woman, and one that feared the Lord." },
  { book: "Susanna", chapter: 1, verse: 3, text: "Her parents also were righteous, and taught their daughter according to the law of Moses." },
  { book: "Susanna", chapter: 1, verse: 4, text: "Now Joacim was a great rich man, and had a fair garden joining unto his house: and to him resorted the Jews; because he was more honourable than all others." },
  { book: "Susanna", chapter: 1, verse: 5, text: "The same year were appointed two of the ancients of the people to be judges, such as the Lord spake of, that wickedness came from Babylon from ancient judges, who seemed to govern the people." },
  { book: "Susanna", chapter: 1, verse: 6, text: "These kept much at Joacim’s house: and all that had any suits in law came unto them." },
  { book: "Susanna", chapter: 1, verse: 7, text: "Now when the people departed away at noon, Susanna went into her husband’s garden to walk." },
  { book: "Susanna", chapter: 1, verse: 8, text: "And the two elders saw her going in every day, and walking; so that their lust was inflamed toward her." },
  { book: "Susanna", chapter: 1, verse: 9, text: "And they perverted their own mind, and turned away their eyes, that they might not look unto heaven, nor remember just judgments." },
  { book: "Susanna", chapter: 1, verse: 10, text: "And albeit they both were wounded with her love, yet durst not one shew another his grief." },
  { book: "Susanna", chapter: 1, verse: 11, text: "For they were ashamed to declare their lust, that they desired to have to do with her." },
  { book: "Susanna", chapter: 1, verse: 12, text: "Yet they watched diligently from day to day to see her." },
  { book: "Susanna", chapter: 1, verse: 13, text: "And the one said to the other, Let us now go home: for it is dinner time." },
  { book: "Susanna", chapter: 1, verse: 14, text: "So when they were gone out, they parted the one from the other, and turning back again they came to the same place; and after that they had asked one another the cause, they acknowledged their lust: then appointed they a time both together, when they might find her alone." },
  { book: "Susanna", chapter: 1, verse: 15, text: "And it fell out, as they watched a fit time, she went in as before with two maids only, and she was desirous to wash herself in the garden: for it was hot." },
  { book: "Susanna", chapter: 1, verse: 16, text: "And there was no body there save the two elders, that had hid themselves, and watched her." },
  { book: "Susanna", chapter: 1, verse: 17, text: "Then she said to her maids, Bring me oil and washing balls, and shut the garden doors, that I may wash me." },
  { book: "Susanna", chapter: 1, verse: 18, text: "And they did as she bade them, and shut the garden doors, and went out themselves at privy doors to fetch the things that she had commanded them: but they saw not the elders, because they were hid." },
  { book: "Susanna", chapter: 1, verse: 19, text: "Now when the maids were gone forth, the two elders rose up, and ran unto her, saying," },
  { book: "Susanna", chapter: 1, verse: 20, text: "Behold, the garden doors are shut, that no man can see us, and we are in love with thee; therefore consent unto us, and lie with us." },
  { book: "Susanna", chapter: 1, verse: 21, text: "If thou wilt not, we will bear witness against thee, that a young man was with thee: and therefore thou didst send away thy maids from thee." },
  { book: "Susanna", chapter: 1, verse: 22, text: "Then Susanna sighed, and said, I am straitened on every side: for if I do this thing, it is death unto me: and if I do it not I cannot escape your hands." },
  { book: "Susanna", chapter: 1, verse: 23, text: "It is better for me to fall into your hands, and not do it, than to sin in the sight of the Lord." },
  { book: "Susanna", chapter: 1, verse: 24, text: "With that Susanna cried with a loud voice: and the two elders cried out against her." },
  { book: "Susanna", chapter: 1, verse: 25, text: "Then ran the one, and opened the garden door." },
  { book: "Susanna", chapter: 1, verse: 26, text: "So when the servants of the house heard the cry in the garden, they rushed in at the privy door, to see what was done unto her." },
  { book: "Susanna", chapter: 1, verse: 27, text: "But when the elders had declared their matter, the servants were greatly ashamed: for there was never such a report made of Susanna." },
  { book: "Susanna", chapter: 1, verse: 28, text: "And it came to pass the next day, when the people were assembled to her husband Joacim, the two elders came also full of mischievous imagination against Susanna to put her to death;" },
  { book: "Susanna", chapter: 1, verse: 29, text: "And said before the people, Send for Susanna, the daughter of Chelcias, Joacim’s wife. And so they sent." },
  { book: "Susanna", chapter: 1, verse: 30, text: "So she came with her father and mother, her children, and all her kindred." },
  { book: "Susanna", chapter: 1, verse: 31, text: "Now Susanna was a very delicate woman, and beauteous to behold." },
  { book: "Susanna", chapter: 1, verse: 32, text: "And these wicked men commanded to uncover her face, (for she was covered) that they might be filled with her beauty." },
  { book: "Susanna", chapter: 1, verse: 33, text: "Therefore her friends and all that saw her wept." },
  { book: "Susanna", chapter: 1, verse: 34, text: "Then the two elders stood up in the midst of the people, and laid their hands upon her head." },
  { book: "Susanna", chapter: 1, verse: 35, text: "And she weeping looked up toward heaven: for her heart trusted in the Lord." },
  { book: "Susanna", chapter: 1, verse: 36, text: "And the elders said, As we walked in the garden alone, this woman came in with two maids, and shut the garden doors, and sent the maids away." },
  { book: "Susanna", chapter: 1, verse: 37, text: "Then a young man, who there was hid, came unto her, and lay with her." },
  { book: "Susanna", chapter: 1, verse: 38, text: "Then we that stood in a corner of the garden, seeing this wickedness, ran unto them." },
  { book: "Susanna", chapter: 1, verse: 39, text: "And when we saw them together, the man we could not hold: for he was stronger than we, and opened the door, and leaped out." },
  { book: "Susanna", chapter: 1, verse: 40, text: "But having taken this woman, we asked who the young man was, but she would not tell us: these things do we testify." },
  { book: "Susanna", chapter: 1, verse: 41, text: "Then the assembly believed them as those that were the elders and judges of the people: so they condemned her to death." },
  { book: "Susanna", chapter: 1, verse: 42, text: "Then Susanna cried out with a loud voice, and said, O everlasting God, that knowest the secrets, and knowest all things before they be:" },
  { book: "Susanna", chapter: 1, verse: 43, text: "Thou knowest that they have borne false witness against me, and, behold, I must die; whereas I never did such things as these men have maliciously invented against me." },
  { book: "Susanna", chapter: 1, verse: 44, text: "And the Lord heard her voice." },
  { book: "Susanna", chapter: 1, verse: 45, text: "Therefore when she was led to be put to death, the Lord raised up the holy spirit of a young youth whose name was Daniel:" },
  { book: "Susanna", chapter: 1, verse: 46, text: "Who cried with a loud voice, I am clear from the blood of this woman." },
  { book: "Susanna", chapter: 1, verse: 47, text: "Then all the people turned them toward him, and said, What mean these words that thou hast spoken?" },
  { book: "Susanna", chapter: 1, verse: 48, text: "So he standing in the midst of them said, Are ye such fools, ye sons of Israel, that without examination or knowledge of the truth ye have condemned a daughter of Israel?" },
  { book: "Susanna", chapter: 1, verse: 49, text: "Return again to the place of judgment: for they have borne false witness against her." },
  { book: "Susanna", chapter: 1, verse: 50, text: "Wherefore all the people turned again in haste, and the elders said unto him, Come, sit down among us, and shew it us, seeing God hath given thee the honour of an elder." },
  { book: "Susanna", chapter: 1, verse: 51, text: "Then said Daniel unto them, Put these two aside one far from another, and I will examine them." },
  { book: "Susanna", chapter: 1, verse: 52, text: "So when they were put asunder one from another, he called one of them, and said unto him, O thou that art waxen old in wickedness, now thy sins which thou hast committed aforetime are come to light." },
  { book: "Susanna", chapter: 1, verse: 53, text: "For thou hast pronounced false judgment and hast condemned the innocent and hast let the guilty go free; albeit the Lord saith, The innocent and righteous shalt thou not slay." },
  { book: "Susanna", chapter: 1, verse: 54, text: "Now then, if thou hast seen her, tell me, Under what tree sawest thou them companying together? Who answered, Under a mastick tree." },
  { book: "Susanna", chapter: 1, verse: 55, text: "And Daniel said, Very well; thou hast lied against thine own head; for even now the angel of God hath received the sentence of God to cut thee in two." },
  { book: "Susanna", chapter: 1, verse: 56, text: "So he put him aside, and commanded to bring the other, and said unto him, O thou seed of Chanaan, and not of Juda, beauty hath deceived thee, and lust hath perverted thine heart." },
  { book: "Susanna", chapter: 1, verse: 57, text: "Thus have ye dealt with the daughters of Israel, and they for fear companied with you: but the daughter of Juda would not abide your wickedness." },
  { book: "Susanna", chapter: 1, verse: 58, text: "Now therefore tell me, Under what tree didst thou take them companying together? Who answered, Under an holm tree." },
  { book: "Susanna", chapter: 1, verse: 59, text: "Then said Daniel unto him, Well; thou hast also lied against thine own head: for the angel of God waiteth with the sword to cut thee in two, that he may destroy you." },
  { book: "Susanna", chapter: 1, verse: 60, text: "With that all the assembly cried out with a loud voice, and praised God, who saveth them that trust in him." },
  { book: "Susanna", chapter: 1, verse: 61, text: "And they arose against the two elders, for Daniel had convicted them of false witness by their own mouth:" },
  { book: "Susanna", chapter: 1, verse: 62, text: "And according to the law of Moses they did unto them in such sort as they maliciously intended to do to their neighbour: and they put them to death. Thus the innocent blood was saved the same day." },
  { book: "Susanna", chapter: 1, verse: 63, text: "Therefore Chelcias and his wife praised God for their daughter Susanna, with Joacim her husband, and all the kindred, because there was no dishonesty found in her." },
  { book: "Susanna", chapter: 1, verse: 64, text: "From that day forth was Daniel had in great reputation in the sight of the people." },
  // Tobit (244 verses)
  { book: "Tobit", chapter: 1, verse: 1, text: "The book of the words of Tobit, son of Tobiel, the son of Ananiel, the son of Aduel, the son of Gabael, of the seed of Asael, of the tribe of Nephthali;" },
  { book: "Tobit", chapter: 1, verse: 2, text: "Who in the time of Enemessar king of the Assyrians was led captive out of Thisbe, which is at the right hand of that city, which is called properly Nephthali in Galilee above Aser." },
  { book: "Tobit", chapter: 1, verse: 3, text: "I Tobit have walked all the days of my life in the ways of truth and justice, and I did many almsdeeds to my brethren, and my nation, who came with me to Nineve, into the land of the Assyrians." },
  { book: "Tobit", chapter: 1, verse: 4, text: "And when I was in mine own country, in the land of Israel being but young, all the tribe of Nephthali my father fell from the house of Jerusalem, which was chosen out of all the tribes of Israel, that all the tribes should sacrifice there, where the temple of the habitation of the most High was consecrated and built for all ages." },
  { book: "Tobit", chapter: 1, verse: 5, text: "Now all the tribes which together revolted, and the house of my father Nephthali, sacrificed unto the heifer Baal." },
  { book: "Tobit", chapter: 1, verse: 6, text: "But I alone went often to Jerusalem at the feasts, as it was ordained unto all the people of Israel by an everlasting decree, having the firstfruits and tenths of increase, with that which was first shorn; and them gave I at the altar to the priests the children of Aaron." },
  { book: "Tobit", chapter: 1, verse: 7, text: "The first tenth part of all increase I gave to the sons of Aaron, who ministered at Jerusalem: another tenth part I sold away, and went, and spent it every year at Jerusalem:" },
  { book: "Tobit", chapter: 1, verse: 8, text: "And the third I gave unto them to whom it was meet, as Debora my father’s mother had commanded me, because I was left an orphan by my father." },
  { book: "Tobit", chapter: 1, verse: 9, text: "Furthermore, when I was come to the age of a man, I married Anna of mine own kindred, and of her I begat Tobias." },
  { book: "Tobit", chapter: 1, verse: 10, text: "And when we were carried away captives to Nineve, all my brethren and those that were of my kindred did eat of the bread of the Gentiles." },
  { book: "Tobit", chapter: 1, verse: 11, text: "But I kept myself from eating;" },
  { book: "Tobit", chapter: 1, verse: 12, text: "Because I remembered God with all my heart." },
  { book: "Tobit", chapter: 1, verse: 13, text: "And the most High gave me grace and favour before Enemessar, so that I was his purveyor." },
  { book: "Tobit", chapter: 1, verse: 14, text: "And I went into Media, and left in trust with Gabael, the brother of Gabrias, at Rages a city of Media ten talents of silver." },
  { book: "Tobit", chapter: 1, verse: 15, text: "Now when Enemessar was dead, Sennacherib his son reigned in his stead; whose estate was troubled, that I could not go into Media." },
  { book: "Tobit", chapter: 1, verse: 16, text: "And in the time of Enemessar I gave many alms to my brethren, and gave my bread to the hungry," },
  { book: "Tobit", chapter: 1, verse: 17, text: "And my clothes to the naked: and if I saw any of my nation dead, or cast about the walls of Nineve, I buried him." },
  { book: "Tobit", chapter: 1, verse: 18, text: "And if the king Sennacherib had slain any, when he was come, and fled from Judea, I buried them privily; for in his wrath he killed many; but the bodies were not found, when they were sought for of the king." },
  { book: "Tobit", chapter: 1, verse: 19, text: "And when one of the Ninevites went and complained of me to the king, that I buried them, and hid myself; understanding that I was sought for to be put to death, I withdrew myself for fear." },
  { book: "Tobit", chapter: 1, verse: 20, text: "Then all my goods were forcibly taken away, neither was there any thing left me, beside my wife Anna and my son Tobias." },
  { book: "Tobit", chapter: 1, verse: 21, text: "And there passed not five and fifty days, before two of his sons killed him, and they fled into the mountains of Ararath; and Sarchedonus his son reigned in his stead; who appointed over his father’s accounts, and over all his affairs, Achiacharus my brother Anael’s son." },
  { book: "Tobit", chapter: 1, verse: 22, text: "And Achiacharus intreating for me, I returned to Nineve. Now Achiacharus was cupbearer, and keeper of the signet, and steward, and overseer of the accounts: and Sarchedonus appointed him next unto him: and he was my brother’s son." },
  { book: "Tobit", chapter: 2, verse: 1, text: "Now when I was come home again, and my wife Anna was restored unto me, with my son Tobias, in the feast of Pentecost, which is the holy feast of the seven weeks, there was a good dinner prepared me, in the which I sat down to eat." },
  { book: "Tobit", chapter: 2, verse: 2, text: "And when I saw abundance of meat, I said to my son, Go and bring what poor man soever thou shalt find out of our brethren, who is mindful of the Lord; and, lo, I tarry for thee." },
  { book: "Tobit", chapter: 2, verse: 3, text: "But he came again, and said, Father, one of our nation is strangled, and is cast out in the marketplace." },
  { book: "Tobit", chapter: 2, verse: 4, text: "Then before I had tasted of any meat, I started up, and took him up into a room until the going down of the sun." },
  { book: "Tobit", chapter: 2, verse: 5, text: "Then I returned, and washed myself, and ate my meat in heaviness," },
  { book: "Tobit", chapter: 2, verse: 6, text: "Remembering that prophecy of Amos, as he said, Your feasts shall be turned into mourning, and all your mirth into lamentation." },
  { book: "Tobit", chapter: 2, verse: 7, text: "Therefore I wept: and after the going down of the sun I went and made a grave, and buried him." },
  { book: "Tobit", chapter: 2, verse: 8, text: "But my neighbours mocked me, and said, This man is not yet afraid to be put to death for this matter: who fled away; and yet, lo, he burieth the dead again." },
  { book: "Tobit", chapter: 2, verse: 9, text: "The same night also I returned from the burial, and slept by the wall of my courtyard, being polluted and my face was uncovered:" },
  { book: "Tobit", chapter: 2, verse: 10, text: "And I knew not that there were sparrows in the wall, and mine eyes being open, the sparrows muted warm dung into mine eyes, and a whiteness came in mine eyes: and I went to the physicians, but they helped me not: moreover Achiacharus did nourish me, until I went into Elymais." },
  { book: "Tobit", chapter: 2, verse: 11, text: "And my wife Anna did take women’s works to do." },
  { book: "Tobit", chapter: 2, verse: 12, text: "And when she had sent them home to the owners, they paid her wages, and gave her also besides a kid." },
  { book: "Tobit", chapter: 2, verse: 13, text: "And when it was in my house, and began to cry, I said unto her, From whence is this kid? is it not stolen? render it to the owners; for it is not lawful to eat any thing that is stolen." },
  { book: "Tobit", chapter: 2, verse: 14, text: "But she replied upon me, It was given for a gift more than the wages. Howbeit I did not believe her, but bade her render it to the owners: and I was abashed at her. But she replied upon me, Where are thine alms and thy righteous deeds? behold, thou and all thy works are known." },
  { book: "Tobit", chapter: 3, verse: 1, text: "Then I being grieved did weep, and in my sorrow prayed, saying," },
  { book: "Tobit", chapter: 3, verse: 2, text: "O Lord, thou art just, and all thy works and all thy ways are mercy and truth, and thou judgest truly and justly for ever." },
  { book: "Tobit", chapter: 3, verse: 3, text: "Remember me, and look on me, punish me not for my sins and ignorances, and the sins of my fathers, who have sinned before thee:" },
  { book: "Tobit", chapter: 3, verse: 4, text: "For they obeyed not thy commandments: wherefore thou hast delivered us for a spoil, and unto captivity, and unto death, and for a proverb of reproach to all the nations among whom we are dispersed." },
  { book: "Tobit", chapter: 3, verse: 5, text: "And now thy judgments are many and true: deal with me according to my sins and my fathers’: because we have not kept thy commandments, neither have walked in truth before thee." },
  { book: "Tobit", chapter: 3, verse: 6, text: "Now therefore deal with me as seemeth best unto thee, and command my spirit to be taken from me, that I may be dissolved, and become earth: for it is profitable for me to die rather than to live, because I have heard false reproaches, and have much sorrow: command therefore that I may now be delivered out of this distress, and go into the everlasting place: turn not thy face away from me." },
  { book: "Tobit", chapter: 3, verse: 7, text: "It came to pass the same day, that in Ecbatane a city of Media, Sara the daughter of Raguel was also reproached by her father’s maids;" },
  { book: "Tobit", chapter: 3, verse: 8, text: "Because that she had been married to seven husbands, whom Asmodeus the evil spirit had killed, before they had lain with her. Dost thou not know, said they, that thou hast strangled thine husbands? thou hast had already seven husbands, neither wast thou named after any of them." },
  { book: "Tobit", chapter: 3, verse: 9, text: "Wherefore dost thou beat us for them? if they be dead, go thy ways after them, let us never see of thee either son or daughter." },
  { book: "Tobit", chapter: 3, verse: 10, text: "When she heard these things, she was very sorrowful, so that she thought to have strangled herself; and she said, I am the only daughter of my father, and if I do this, it shall be a reproach unto him, and I shall bring his old age with sorrow unto the grave." },
  { book: "Tobit", chapter: 3, verse: 11, text: "Then she prayed toward the window, and said, Blessed art thou, O Lord my God, and thine holy and glorious name is blessed and honourable for ever: let all thy works praise thee for ever." },
  { book: "Tobit", chapter: 3, verse: 12, text: "And now, O Lord, I set mine eyes and my face toward thee," },
  { book: "Tobit", chapter: 3, verse: 13, text: "And say, Take me out of the earth, that I may hear no more the reproach." },
  { book: "Tobit", chapter: 3, verse: 14, text: "Thou knowest, Lord, that I am pure from all sin with man," },
  { book: "Tobit", chapter: 3, verse: 15, text: "And that I never polluted my name, nor the name of my father, in the land of my captivity: I am the only daughter of my father, neither hath he any child to be his heir, neither any near kinsman, nor any son of his alive, to whom I may keep myself for a wife: my seven husbands are already dead; and why should I live? but if it please not thee that I should die, command some regard to be had of me, and pity taken of me, that I hear no more reproach." },
  { book: "Tobit", chapter: 3, verse: 16, text: "So the prayers of them both were heard before the majesty of the great God." },
  { book: "Tobit", chapter: 3, verse: 17, text: "And Raphael was sent to heal them both, that is, to scale away the whiteness of Tobit’s eyes, and to give Sara the daughter of Raguel for a wife to Tobias the son of Tobit; and to bind Asmodeus the evil spirit; because she belonged to Tobias by right of inheritance. The selfsame time came Tobit home, and entered into his house, and Sara the daughter of Raguel came down from her upper chamber." },
  { book: "Tobit", chapter: 4, verse: 1, text: "In that day Tobit remembered the money which he had committed to Gabael in Rages of Media," },
  { book: "Tobit", chapter: 4, verse: 2, text: "And said with himself, I have wished for death; wherefore do I not call for my son Tobias that I may signify to him of the money before I die?" },
  { book: "Tobit", chapter: 4, verse: 3, text: "And when he had called him, he said, My son, when I am dead, bury me; and despise not thy mother, but honour her all the days of thy life, and do that which shall please her, and grieve her not." },
  { book: "Tobit", chapter: 4, verse: 4, text: "Remember, my son, that she saw many dangers for thee, when thou wast in her womb: and when she is dead, bury her by me in one grave." },
  { book: "Tobit", chapter: 4, verse: 5, text: "My son, be mindful of the Lord our God all thy days, and let not thy will be set to sin, or to transgress his commandments: do uprightly all thy life long, and follow not the ways of unrighteousness." },
  { book: "Tobit", chapter: 4, verse: 6, text: "For if thou deal truly, thy doings shall prosperously succeed to thee, and to all them that live justly." },
  { book: "Tobit", chapter: 4, verse: 7, text: "Give alms of thy substance; and when thou givest alms, let not thine eye be envious, neither turn thy face from any poor, and the face of God shall not be turned away from thee." },
  { book: "Tobit", chapter: 4, verse: 8, text: "If thou hast abundance give alms accordingly: if thou have but a little, be not afraid to give according to that little:" },
  { book: "Tobit", chapter: 4, verse: 9, text: "For thou layest up a good treasure for thyself against the day of necessity." },
  { book: "Tobit", chapter: 4, verse: 10, text: "Because that alms do deliver from death, and suffereth not to come into darkness." },
  { book: "Tobit", chapter: 4, verse: 11, text: "For alms is a good gift unto all that give it in the sight of the most High." },
  { book: "Tobit", chapter: 4, verse: 12, text: "Beware of all whoredom, my son, and chiefly take a wife of the seed of thy fathers, and take not a strange woman to wife, which is not of thy father’s tribe: for we are the children of the prophets, Noe, Abraham, Isaac, and Jacob: remember, my son, that our fathers from the beginning, even that they all married wives of their own kindred, and were blessed in their children, and their seed shall inherit the land." },
  { book: "Tobit", chapter: 4, verse: 13, text: "Now therefore, my son, love thy brethren, and despise not in thy heart thy brethren, the sons and daughters of thy people, in not taking a wife of them: for in pride is destruction and much trouble, and in lewdness is decay and great want: for lewdness is the mother of famine." },
  { book: "Tobit", chapter: 4, verse: 14, text: "Let not the wages of any man, which hath wrought for thee, tarry with thee, but give him it out of hand: for if thou serve God, he will also repay thee: be circumspect my son, in all things thou doest, and be wise in all thy conversation." },
  { book: "Tobit", chapter: 4, verse: 15, text: "Do that to no man which thou hatest: drink not wine to make thee drunken: neither let drunkenness go with thee in thy journey." },
  { book: "Tobit", chapter: 4, verse: 16, text: "Give of thy bread to the hungry, and of thy garments to them that are naked; and according to thine abundance give alms: and let not thine eye be envious, when thou givest alms." },
  { book: "Tobit", chapter: 4, verse: 17, text: "Pour out thy bread on the burial of the just, but give nothing to the wicked." },
  { book: "Tobit", chapter: 4, verse: 18, text: "Ask counsel of all that are wise, and despise not any counsel that is profitable." },
  { book: "Tobit", chapter: 4, verse: 19, text: "Bless the Lord thy God alway, and desire of him that thy ways may be directed, and that all thy paths and counsels may prosper: for every nation hath not counsel; but the Lord himself giveth all good things, and he humbleth whom he will, as he will; now therefore, my son, remember my commandments, neither let them be put out of thy mind." },
  { book: "Tobit", chapter: 4, verse: 20, text: "And now I signify this to they that I committed ten talents to Gabael the son of Gabrias at Rages in Media." },
  { book: "Tobit", chapter: 4, verse: 21, text: "And fear not, my son, that we are made poor: for thou hast much wealth, if thou fear God, and depart from all sin, and do that which is pleasing in his sight." },
  { book: "Tobit", chapter: 5, verse: 1, text: "Tobias then answered and said, Father, I will do all things which thou hast commanded me:" },
  { book: "Tobit", chapter: 5, verse: 2, text: "But how can I receive the money, seeing I know him not?" },
  { book: "Tobit", chapter: 5, verse: 3, text: "Then he gave him the handwriting, and said unto him, Seek thee a man which may go with thee, whiles I yet live, and I will give him wages: and go and receive the money." },
  { book: "Tobit", chapter: 5, verse: 4, text: "Therefore when he went to seek a man, he found Raphael that was an angel." },
  { book: "Tobit", chapter: 5, verse: 5, text: "But he knew not; and he said unto him, Canst thou go with me to Rages? and knowest thou those places well?" },
  { book: "Tobit", chapter: 5, verse: 6, text: "To whom the angel said, I will go with thee, and I know the way well: for I have lodged with our brother Gabael." },
  { book: "Tobit", chapter: 5, verse: 7, text: "Then Tobias said unto him, Tarry for me, till I tell my father." },
  { book: "Tobit", chapter: 5, verse: 8, text: "Then he said unto him, Go and tarry not. So he went in and said to his father, Behold, I have found one which will go with me. Then he said, Call him unto me, that I may know of what tribe he is, and whether he be a trusty man to go with thee." },
  { book: "Tobit", chapter: 5, verse: 9, text: "So he called him, and he came in, and they saluted one another." },
  { book: "Tobit", chapter: 5, verse: 10, text: "Then Tobit said unto him, Brother, shew me of what tribe and family thou art." },
  { book: "Tobit", chapter: 5, verse: 11, text: "To whom he said, Dost thou seek for a tribe or family, or an hired man to go with thy son? Then Tobit said unto him, I would know, brother, thy kindred and name." },
  { book: "Tobit", chapter: 5, verse: 12, text: "Then he said, I am Azarias, the son of Ananias the great, and of thy brethren." },
  { book: "Tobit", chapter: 5, verse: 13, text: "Then Tobit said, Thou art welcome, brother; be not now angry with me, because I have enquired to know thy tribe and thy family; for thou art my brother, of an honest and good stock: for I know Ananias and Jonathas, sons of that great Samaias, as we went together to Jerusalem to worship, and offered the firstborn, and the tenths of the fruits; and they were not seduced with the error of our brethren: my brother, thou art of a good stock." },
  { book: "Tobit", chapter: 5, verse: 14, text: "But tell me, what wages shall I give thee? wilt thou a drachm a day, and things necessary, as to mine own son?" },
  { book: "Tobit", chapter: 5, verse: 15, text: "Yea, moreover, if ye return safe, I will add something to thy wages." },
  { book: "Tobit", chapter: 5, verse: 16, text: "So they were well pleased. Then said he to Tobias, Prepare thyself for the journey, and God send you a good journey. And when his son had prepared all things for the journey, his father said, Go thou with this man, and God, which dwelleth in heaven, prosper your journey, and the angel of God keep you company. So they went forth both, and the young man’s dog with them." },
  { book: "Tobit", chapter: 5, verse: 17, text: "But Anna his mother wept, and said to Tobit, Why hast thou sent away our son? is he not the staff of our hand, in going in and out before us?" },
  { book: "Tobit", chapter: 5, verse: 18, text: "Be not greedy to add money to money: but let it be as refuse in respect of our child." },
  { book: "Tobit", chapter: 5, verse: 19, text: "For that which the Lord hath given us to live with doth suffice us." },
  { book: "Tobit", chapter: 5, verse: 20, text: "Then said Tobit to her, Take no care, my sister; he shall return in safety, and thine eyes shall see him." },
  { book: "Tobit", chapter: 5, verse: 21, text: "For the good angel will keep him company, and his journey shall be prosperous, and he shall return safe." },
  { book: "Tobit", chapter: 5, verse: 22, text: "Then she made an end of weeping." },
  { book: "Tobit", chapter: 6, verse: 1, text: "And as they went on their journey, they came in the evening to the river Tigris, and they lodged there." },
  { book: "Tobit", chapter: 6, verse: 2, text: "And when the young man went down to wash himself, a fish leaped out of the river, and would have devoured him." },
  { book: "Tobit", chapter: 6, verse: 3, text: "Then the angel said unto him, Take the fish. And the young man laid hold of the fish, and drew it to land." },
  { book: "Tobit", chapter: 6, verse: 4, text: "To whom the angel said, Open the fish, and take the heart and the liver and the gall, and put them up safely." },
  { book: "Tobit", chapter: 6, verse: 5, text: "So the young man did as the angel commanded him; and when they had roasted the fish, they did eat it: then they both went on their way, till they drew near to Ecbatane." },
  { book: "Tobit", chapter: 6, verse: 6, text: "Then the young man said to the angel, Brother Azarias, to what use is the heart and the liver and the gall of the fish?" },
  { book: "Tobit", chapter: 6, verse: 7, text: "And he said unto him, Touching the heart and the liver, if a devil or an evil spirit trouble any, we must make a smoke thereof before the man or the woman, and the party shall be no more vexed." },
  { book: "Tobit", chapter: 6, verse: 8, text: "As for the gall, it is good to anoint a man that hath whiteness in his eyes, and he shall be healed." },
  { book: "Tobit", chapter: 6, verse: 9, text: "And when they were come near to Rages," },
  { book: "Tobit", chapter: 6, verse: 10, text: "The angel said to the young man, Brother, to day we shall lodge with Raguel, who is thy cousin; he also hath one only daughter, named Sara; I will speak for her, that she may be given thee for a wife." },
  { book: "Tobit", chapter: 6, verse: 11, text: "For to thee doth the right of her appertain, seeing thou only art of her kindred." },
  { book: "Tobit", chapter: 6, verse: 12, text: "And the maid is fair and wise: now therefore hear me, and I will speak to her father; and when we return from Rages we will celebrate the marriage: for I know that Raguel cannot marry her to another according to the law of Moses, but he shall be guilty of death, because the right of inheritance doth rather appertain to thee than to any other." },
  { book: "Tobit", chapter: 6, verse: 13, text: "Then the young man answered the angel, I have heard, brother Azarias that this maid hath been given to seven men, who all died in the marriage chamber." },
  { book: "Tobit", chapter: 6, verse: 14, text: "And now I am the only son of my father, and I am afraid, lest if I go in unto her, I die, as the other before: for a wicked spirit loveth her, which hurteth no body, but those which come unto her; wherefore I also fear lest I die, and bring my father’s and my mother’s life because of me to the grave with sorrow: for they have no other son to bury them." },
  { book: "Tobit", chapter: 6, verse: 15, text: "Then the angel said unto him, Dost thou not remember the precepts which thy father gave thee, that thou shouldest marry a wife of thine own kindred? wherefore hear me, O my brother; for she shall be given thee to wife; and make thou no reckoning of the evil spirit; for this same night shall she be given thee in marriage." },
  { book: "Tobit", chapter: 6, verse: 16, text: "And when thou shalt come into the marriage chamber, thou shalt take the ashes of perfume, and shalt lay upon them some of the heart and liver of the fish, and shalt make a smoke with it:" },
  { book: "Tobit", chapter: 6, verse: 17, text: "And the devil shall smell it, and flee away, and never come again any more: but when thou shalt come to her, rise up both of you, and pray to God which is merciful, who will have pity on you, and save you: fear not, for she is appointed unto thee from the beginning; and thou shalt preserve her, and she shall go with thee. Moreover I suppose that she shall bear thee children. Now when Tobias had heard these things, he loved her, and his heart was effectually joined to her." },
  { book: "Tobit", chapter: 7, verse: 1, text: "And when they were come to Ecbatane, they came to the house of Raguel, and Sara met them: and after they had saluted one another, she brought them into the house." },
  { book: "Tobit", chapter: 7, verse: 2, text: "Then said Raguel to Edna his wife, How like is this young man to Tobit my cousin!" },
  { book: "Tobit", chapter: 7, verse: 3, text: "And Raguel asked them, From whence are ye, brethren? To whom they said, We are of the sons of Nephthalim, which are captives in Nineve." },
  { book: "Tobit", chapter: 7, verse: 4, text: "Then he said to them, Do ye know Tobit our kinsman? And they said, We know him. Then said he, Is he in good health?" },
  { book: "Tobit", chapter: 7, verse: 5, text: "And they said, He is both alive, and in good health: and Tobias said, He is my father." },
  { book: "Tobit", chapter: 7, verse: 6, text: "Then Raguel leaped up, and kissed him, and wept," },
  { book: "Tobit", chapter: 7, verse: 7, text: "And blessed him, and said unto him, Thou art the son of an honest and good man. But when he had heard that Tobit was blind, he was sorrowful, and wept." },
  { book: "Tobit", chapter: 7, verse: 8, text: "And likewise Edna his wife and Sara his daughter wept. Moreover they entertained them cheerfully; and after that they had killed a ram of the flock, they set store of meat on the table. Then said Tobias to Raphael, Brother Azarias, speak of those things of which thou didst talk in the way, and let this business be dispatched." },
  { book: "Tobit", chapter: 7, verse: 9, text: "So he communicated the matter with Raguel: and Raguel said to Tobias, Eat and drink, and make merry:" },
  { book: "Tobit", chapter: 7, verse: 10, text: "For it is meet that thou shouldest marry my daughter: nevertheless I will declare unto thee the truth." },
  { book: "Tobit", chapter: 7, verse: 11, text: "I have given my daughter in marriage to seven men, who died that night they came in unto her: nevertheless for the present be merry. But Tobias said, I will eat nothing here, till we agree and swear one to another." },
  { book: "Tobit", chapter: 7, verse: 12, text: "Raguel said, Then take her from henceforth according to the manner, for thou art her cousin, and she is thine, and the merciful God give you good success in all things." },
  { book: "Tobit", chapter: 7, verse: 13, text: "Then he called his daughter Sara, and she came to her father, and he took her by the hand, and gave her to be wife to Tobias, saying, Behold, take her after the law of Moses, and lead her away to thy father. And he blessed them;" },
  { book: "Tobit", chapter: 7, verse: 14, text: "And called Edna his wife, and took paper, and did write an instrument of covenants, and sealed it." },
  { book: "Tobit", chapter: 7, verse: 15, text: "Then they began to eat." },
  { book: "Tobit", chapter: 7, verse: 16, text: "After Raguel called his wife Edna, and said unto her, Sister, prepare another chamber, and bring her in thither." },
  { book: "Tobit", chapter: 7, verse: 17, text: "Which when she had done as he had bidden her, she brought her thither: and she wept, and she received the tears of her daughter, and said unto her," },
  { book: "Tobit", chapter: 7, verse: 18, text: "Be of good comfort, my daughter; the Lord of heaven and earth give thee joy for this thy sorrow: be of good comfort, my daughter." },
  { book: "Tobit", chapter: 8, verse: 1, text: "And when they had supped, they brought Tobias in unto her." },
  { book: "Tobit", chapter: 8, verse: 2, text: "And as he went, he remembered the words of Raphael, and took the ashes of the perfumes, and put the heart and the liver of the fish thereupon, and made a smoke therewith." },
  { book: "Tobit", chapter: 8, verse: 3, text: "The which smell when the evil spirit had smelled, he fled into the utmost parts of Egypt, and the angel bound him." },
  { book: "Tobit", chapter: 8, verse: 4, text: "And after that they were both shut in together, Tobias rose out of the bed, and said, Sister, arise, and let us pray that God would have pity on us." },
  { book: "Tobit", chapter: 8, verse: 5, text: "Then began Tobias to say, Blessed art thou, O God of our fathers, and blessed is thy holy and glorious name for ever; let the heavens bless thee, and all thy creatures." },
  { book: "Tobit", chapter: 8, verse: 6, text: "Thou madest Adam, and gavest him Eve his wife for an helper and stay: of them came mankind: thou hast said, It is not good that man should be alone; let us make unto him an aid like unto himself." },
  { book: "Tobit", chapter: 8, verse: 7, text: "And now, O Lord, I take not this my sister for lust but uprightly: therefore mercifully ordain that we may become aged together." },
  { book: "Tobit", chapter: 8, verse: 8, text: "And she said with him, Amen." },
  { book: "Tobit", chapter: 8, verse: 9, text: "So they slept both that night. And Raguel arose, and went and made a grave," },
  { book: "Tobit", chapter: 8, verse: 10, text: "Saying, I fear lest he also be dead." },
  { book: "Tobit", chapter: 8, verse: 11, text: "But when Raguel was come into his house," },
  { book: "Tobit", chapter: 8, verse: 12, text: "He said unto his wife Edna. Send one of the maids, and let her see whether he be alive: if he be not, that we may bury him, and no man know it." },
  { book: "Tobit", chapter: 8, verse: 13, text: "So the maid opened the door, and went in, and found them both asleep," },
  { book: "Tobit", chapter: 8, verse: 14, text: "And came forth, and told them that he was alive." },
  { book: "Tobit", chapter: 8, verse: 15, text: "Then Raguel praised God, and said, O God, thou art worthy to be praised with all pure and holy praise; therefore let thy saints praise thee with all thy creatures; and let all thine angels and thine elect praise thee for ever." },
  { book: "Tobit", chapter: 8, verse: 16, text: "Thou art to be praised, for thou hast made me joyful; and that is not come to me which I suspected; but thou hast dealt with us according to thy great mercy." },
  { book: "Tobit", chapter: 8, verse: 17, text: "Thou art to be praised because thou hast had mercy of two that were the only begotten children of their fathers: grant them mercy, O Lord, and finish their life in health with joy and mercy." },
  { book: "Tobit", chapter: 8, verse: 18, text: "Then Raguel bade his servants to fill the grave." },
  { book: "Tobit", chapter: 8, verse: 19, text: "And he kept the wedding feast fourteen days." },
  { book: "Tobit", chapter: 8, verse: 20, text: "For before the days of the marriage were finished, Raguel had said unto him by an oath, that he should not depart till the fourteen days of the marriage were expired;" },
  { book: "Tobit", chapter: 8, verse: 21, text: "And then he should take the half of his goods, and go in safety to his father; and should have the rest when I and my wife be dead." },
  { book: "Tobit", chapter: 9, verse: 1, text: "Then Tobias called Raphael, and said unto him," },
  { book: "Tobit", chapter: 9, verse: 2, text: "Brother Azarias, take with thee a servant, and two camels, and go to Rages of Media to Gabael, and bring me the money, and bring him to the wedding." },
  { book: "Tobit", chapter: 9, verse: 3, text: "For Raguel hath sworn that I shall not depart." },
  { book: "Tobit", chapter: 9, verse: 4, text: "But my father counteth the days; and if I tarry long, he will be very sorry." },
  { book: "Tobit", chapter: 9, verse: 5, text: "So Raphael went out, and lodged with Gabael, and gave him the handwriting: who brought forth bags which were sealed up, and gave them to him." },
  { book: "Tobit", chapter: 9, verse: 6, text: "And early in the morning they went forth both together, and came to the wedding: and Tobias blessed his wife." },
  { book: "Tobit", chapter: 10, verse: 1, text: "Now Tobit his father counted every day: and when the days of the journey were expired, and they came not," },
  { book: "Tobit", chapter: 10, verse: 2, text: "Then Tobit said, Are they detained? or is Gabael dead, and there is no man to give him the money?" },
  { book: "Tobit", chapter: 10, verse: 3, text: "Therefore he was very sorry." },
  { book: "Tobit", chapter: 10, verse: 4, text: "Then his wife said unto him, My son is dead, seeing he stayeth long; and she began to wail him, and said," },
  { book: "Tobit", chapter: 10, verse: 5, text: "Now I care for nothing, my son, since I have let thee go, the light of mine eyes." },
  { book: "Tobit", chapter: 10, verse: 6, text: "To whom Tobit said, Hold thy peace, take no care, for he is safe." },
  { book: "Tobit", chapter: 10, verse: 7, text: "But she said, Hold thy peace, and deceive me not; my son is dead. And she went out every day into the way which they went, and did eat no meat on the daytime, and ceased not whole nights to bewail her son Tobias, until the fourteen days of the wedding were expired, which Raguel had sworn that he should spend there. Then Tobias said to Raguel, Let me go, for my father and my mother look no more to see me." },
  { book: "Tobit", chapter: 10, verse: 8, text: "But his father in law said unto him, Tarry with me, and I will send to thy father, and they shall declare unto him how things go with thee." },
  { book: "Tobit", chapter: 10, verse: 9, text: "But Tobias said, No; but let me go to my father." },
  { book: "Tobit", chapter: 10, verse: 10, text: "Then Raguel arose, and gave him Sara his wife, and half his goods, servants, and cattle, and money:" },
  { book: "Tobit", chapter: 10, verse: 11, text: "And he blessed them, and sent them away, saying, The God of heaven give you a prosperous journey, my children." },
  { book: "Tobit", chapter: 10, verse: 12, text: "And he said to his daughter, Honour thy father and thy mother in law, which are now thy parents, that I may hear good report of thee. And he kissed her. Edna also said to Tobias, The Lord of heaven restore thee, my dear brother, and grant that I may see thy children of my daughter Sara before I die, that I may rejoice before the Lord: behold, I commit my daughter unto thee of special trust; where are do not entreat her evil." },
  { book: "Tobit", chapter: 11, verse: 1, text: "After these things Tobias went his way, praising God that he had given him a prosperous journey, and blessed Raguel and Edna his wife, and went on his way till they drew near unto Nineve." },
  { book: "Tobit", chapter: 11, verse: 2, text: "Then Raphael said to Tobias, Thou knowest, brother, how thou didst leave thy father:" },
  { book: "Tobit", chapter: 11, verse: 3, text: "Let us haste before thy wife, and prepare the house." },
  { book: "Tobit", chapter: 11, verse: 4, text: "And take in thine hand the gall of the fish. So they went their way, and the dog went after them." },
  { book: "Tobit", chapter: 11, verse: 5, text: "Now Anna sat looking about toward the way for her son." },
  { book: "Tobit", chapter: 11, verse: 6, text: "And when she espied him coming, she said to his father, Behold, thy son cometh, and the man that went with him." },
  { book: "Tobit", chapter: 11, verse: 7, text: "Then said Raphael, I know, Tobias, that thy father will open his eyes." },
  { book: "Tobit", chapter: 11, verse: 8, text: "Therefore anoint thou his eyes with the gall, and being pricked therewith, he shall rub, and the whiteness shall fall away, and he shall see thee." },
  { book: "Tobit", chapter: 11, verse: 9, text: "Then Anna ran forth, and fell upon the neck of her son, and said unto him, Seeing I have seen thee, my son, from henceforth I am content to die. And they wept both." },
  { book: "Tobit", chapter: 11, verse: 10, text: "Tobit also went forth toward the door, and stumbled: but his son ran unto him," },
  { book: "Tobit", chapter: 11, verse: 11, text: "And took hold of his father: and he strake of the gall on his fathers’ eyes, saying, Be of good hope, my father." },
  { book: "Tobit", chapter: 11, verse: 12, text: "And when his eyes began to smart, he rubbed them;" },
  { book: "Tobit", chapter: 11, verse: 13, text: "And the whiteness pilled away from the corners of his eyes: and when he saw his son, he fell upon his neck." },
  { book: "Tobit", chapter: 11, verse: 14, text: "And he wept, and said, Blessed art thou, O God, and blessed is thy name for ever; and blessed are all thine holy angels:" },
  { book: "Tobit", chapter: 11, verse: 15, text: "For thou hast scourged, and hast taken pity on me: for, behold, I see my son Tobias. And his son went in rejoicing, and told his father the great things that had happened to him in Media." },
  { book: "Tobit", chapter: 11, verse: 16, text: "Then Tobit went out to meet his daughter in law at the gate of Nineve, rejoicing and praising God: and they which saw him go marvelled, because he had received his sight." },
  { book: "Tobit", chapter: 11, verse: 17, text: "But Tobias gave thanks before them, because God had mercy on him. And when he came near to Sara his daughter in law, he blessed her, saying, Thou art welcome, daughter: God be blessed, which hath brought thee unto us, and blessed be thy father and thy mother. And there was joy among all his brethren which were at Nineve." },
  { book: "Tobit", chapter: 11, verse: 18, text: "And Achiacharus, and Nasbas his brother’s son, came:" },
  { book: "Tobit", chapter: 11, verse: 19, text: "And Tobias’ wedding was kept seven days with great joy." },
  { book: "Tobit", chapter: 12, verse: 1, text: "Then Tobit called his son Tobias, and said unto him, My son, see that the man have his wages, which went with thee, and thou must give him more." },
  { book: "Tobit", chapter: 12, verse: 2, text: "And Tobias said unto him, O father, it is no harm to me to give him half of those things which I have brought:" },
  { book: "Tobit", chapter: 12, verse: 3, text: "For he hath brought me again to thee in safety, and made whole my wife, and brought me the money, and likewise healed thee." },
  { book: "Tobit", chapter: 12, verse: 4, text: "Then the old man said, It is due unto him." },
  { book: "Tobit", chapter: 12, verse: 5, text: "So he called the angel, and he said unto him, Take half of all that ye have brought and go away in safety." },
  { book: "Tobit", chapter: 12, verse: 6, text: "Then he took them both apart, and said unto them, Bless God, praise him, and magnify him, and praise him for the things which he hath done unto you in the sight of all that live. It is good to praise God, and exalt his name, and honourably to shew forth the works of God; therefore be not slack to praise him." },
  { book: "Tobit", chapter: 12, verse: 7, text: "It is good to keep close the secret of a king, but it is honourable to reveal the works of God. Do that which is good, and no evil shall touch you." },
  { book: "Tobit", chapter: 12, verse: 8, text: "Prayer is good with fasting and alms and righteousness. A little with righteousness is better than much with unrighteousness. It is better to give alms than to lay up gold:" },
  { book: "Tobit", chapter: 12, verse: 9, text: "For alms doth deliver from death, and shall purge away all sin. Those that exercise alms and righteousness shall be filled with life:" },
  { book: "Tobit", chapter: 12, verse: 10, text: "But they that sin are enemies to their own life." },
  { book: "Tobit", chapter: 12, verse: 11, text: "Surely I will keep close nothing from you. For I said, It was good to keep close the secret of a king, but that it was honourable to reveal the works of God." },
  { book: "Tobit", chapter: 12, verse: 12, text: "Now therefore, when thou didst pray, and Sara thy daughter in law, I did bring the remembrance of your prayers before the Holy One: and when thou didst bury the dead, I was with thee likewise." },
  { book: "Tobit", chapter: 12, verse: 13, text: "And when thou didst not delay to rise up, and leave thy dinner, to go and cover the dead, thy good deed was not hid from me: but I was with thee." },
  { book: "Tobit", chapter: 12, verse: 14, text: "And now God hath sent me to heal thee and Sara thy daughter in law." },
  { book: "Tobit", chapter: 12, verse: 15, text: "I am Raphael, one of the seven holy angels, which present the prayers of the saints, and which go in and out before the glory of the Holy One." },
  { book: "Tobit", chapter: 12, verse: 16, text: "Then they were both troubled, and fell upon their faces: for they feared." },
  { book: "Tobit", chapter: 12, verse: 17, text: "But he said unto them, Fear not, for it shall go well with you; praise God therefore." },
  { book: "Tobit", chapter: 12, verse: 18, text: "For not of any favour of mine, but by the will of our God I came; wherefore praise him for ever." },
  { book: "Tobit", chapter: 12, verse: 19, text: "All these days I did appear unto you; but I did neither eat nor drink, but ye did see a vision." },
  { book: "Tobit", chapter: 12, verse: 20, text: "Now therefore give God thanks: for I go up to him that sent me; but write all things which are done in a book." },
  { book: "Tobit", chapter: 12, verse: 21, text: "And when they arose, they saw him no more." },
  { book: "Tobit", chapter: 12, verse: 22, text: "Then they confessed the great and wonderful works of God, and how the angel of the Lord had appeared unto them." },
  { book: "Tobit", chapter: 13, verse: 1, text: "Then Tobit wrote a prayer of rejoicing, and said, Blessed be God that liveth for ever, and blessed be his kingdom." },
  { book: "Tobit", chapter: 13, verse: 2, text: "For he doth scourge, and hath mercy: he leadeth down to hell, and bringeth up again: neither is there any that can avoid his hand." },
  { book: "Tobit", chapter: 13, verse: 3, text: "Confess him before the Gentiles, ye children of Israel: for he hath scattered us among them." },
  { book: "Tobit", chapter: 13, verse: 4, text: "There declare his greatness, and extol him before all the living: for he is our Lord, and he is the God our Father for ever." },
  { book: "Tobit", chapter: 13, verse: 5, text: "And he will scourge us for our iniquities, and will have mercy again, and will gather us out of all nations, among whom he hath scattered us." },
  { book: "Tobit", chapter: 13, verse: 6, text: "If ye turn to him with your whole heart, and with your whole mind, and deal uprightly before him, then will he turn unto you, and will not hide his face from you. Therefore see what he will do with you, and confess him with your whole mouth, and praise the Lord of might, and extol the everlasting King. In the land of my captivity do I praise him, and declare his might and majesty to a sinful nation. O ye sinners, turn and do justice before him: who can tell if he will accept you, and have mercy on you?" },
  { book: "Tobit", chapter: 13, verse: 7, text: "I will extol my God, and my soul shall praise the King of heaven, and shall rejoice in his greatness." },
  { book: "Tobit", chapter: 13, verse: 8, text: "Let all men speak, and let all praise him for his righteousness." },
  { book: "Tobit", chapter: 13, verse: 9, text: "O Jerusalem, the holy city, he will scourge thee for thy children’s works, and will have mercy again on the sons of the righteous." },
  { book: "Tobit", chapter: 13, verse: 10, text: "Give praise to the Lord, for he is good: and praise the everlasting King, that his tabernacle may be builded in thee again with joy, and let him make joyful there in thee those that are captives, and love in thee for ever those that are miserable." },
  { book: "Tobit", chapter: 13, verse: 11, text: "Many nations shall come from far to the name of the Lord God with gifts in their hands, even gifts to the King of heaven; all generations shall praise thee with great joy." },
  { book: "Tobit", chapter: 13, verse: 12, text: "Cursed are all they which hate thee, and blessed shall all be which love thee for ever." },
  { book: "Tobit", chapter: 13, verse: 13, text: "Rejoice and be glad for the children of the just: for they shall be gathered together, and shall bless the Lord of the just." },
  { book: "Tobit", chapter: 13, verse: 14, text: "O blessed are they which love thee, for they shall rejoice in thy peace: blessed are they which have been sorrowful for all thy scourges; for they shall rejoice for thee, when they have seen all thy glory, and shall be glad for ever." },
  { book: "Tobit", chapter: 13, verse: 15, text: "Let my soul bless God the great King." },
  { book: "Tobit", chapter: 13, verse: 16, text: "For Jerusalem shall be built up with sapphires and emeralds, and precious stone: thy walls and towers and battlements with pure gold." },
  { book: "Tobit", chapter: 13, verse: 17, text: "And the streets of Jerusalem shall be paved with beryl and carbuncle and stones of Ophir." },
  { book: "Tobit", chapter: 13, verse: 18, text: "And all her streets shall say, Alleluia; and they shall praise him, saying, Blessed be God, which hath extolled it for ever." },
  { book: "Tobit", chapter: 14, verse: 1, text: "So Tobit made an end of praising God." },
  { book: "Tobit", chapter: 14, verse: 2, text: "And he was eight and fifty years old when he lost his sight, which was restored to him after eight years: and he gave alms, and he increased in the fear of the Lord God, and praised him." },
  { book: "Tobit", chapter: 14, verse: 3, text: "And when he was very aged he called his son, and the sons of his son, and said to him, My son, take thy children; for, behold, I am aged, and am ready to depart out of this life." },
  { book: "Tobit", chapter: 14, verse: 4, text: "Go into Media my son, for I surely believe those things which Jonas the prophet spake of Nineve, that it shall be overthrown; and that for a time peace shall rather be in Media; and that our brethren shall lie scattered in the earth from that good land: and Jerusalem shall be desolate, and the house of God in it shall be burned, and shall be desolate for a time;" },
  { book: "Tobit", chapter: 14, verse: 5, text: "And that again God will have mercy on them, and bring them again into the land, where they shall build a temple, but not like to the first, until the time of that age be fulfilled; and afterward they shall return from all places of their captivity, and build up Jerusalem gloriously, and the house of God shall be built in it for ever with a glorious building, as the prophets have spoken thereof." },
  { book: "Tobit", chapter: 14, verse: 6, text: "And all nations shall turn, and fear the Lord God truly, and shall bury their idols." },
  { book: "Tobit", chapter: 14, verse: 7, text: "So shall all nations praise the Lord, and his people shall confess God, and the Lord shall exalt his people; and all those which love the Lord God in truth and justice shall rejoice, shewing mercy to our brethren." },
  { book: "Tobit", chapter: 14, verse: 8, text: "And now, my son, depart out of Nineve, because that those things which the prophet Jonas spake shall surely come to pass." },
  { book: "Tobit", chapter: 14, verse: 9, text: "But keep thou the law and the commandments, and shew thyself merciful and just, that it may go well with thee." },
  { book: "Tobit", chapter: 14, verse: 10, text: "And bury me decently, and thy mother with me; but tarry no longer at Nineve. Remember, my son, how Aman handled Achiacharus that brought him up, how out of light he brought him into darkness, and how he rewarded him again: yet Achiacharus was saved, but the other had his reward: for he went down into darkness. Manasses gave alms, and escaped the snares of death which they had set for him: but Aman fell into the snare, and perished." },
  { book: "Tobit", chapter: 14, verse: 11, text: "Wherefore now, my son, consider what alms doeth, and how righteousness doth deliver. When he had said these things, he gave up the ghost in the bed, being an hundred and eight and fifty years old; and he buried him honourably." },
  { book: "Tobit", chapter: 14, verse: 12, text: "And when Anna his mother was dead, he buried her with his father. But Tobias departed with his wife and children to Ecbatane to Raguel his father in law," },
  { book: "Tobit", chapter: 14, verse: 13, text: "Where he became old with honour, and he buried his father and mother in law honourably, and he inherited their substance, and his father Tobit’s." },
  { book: "Tobit", chapter: 14, verse: 14, text: "And he died at Ecbatane in Media, being an hundred and seven and twenty years old." },
  { book: "Tobit", chapter: 14, verse: 15, text: "But before he died he heard of the destruction of Nineve, which was taken by Nabuchodonosor and Assuerus: and before his death he rejoiced over Nineve." },
  // Wisdom of Solomon (436 verses)
  { book: "Wisdom of Solomon", chapter: 1, verse: 1, text: "Love righteousness, ye that be judges of the earth: think of the Lord with a good (heart,) and in simplicity of heart seek him." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 2, text: "For he will be found of them that tempt him not; and sheweth himself unto such as do not distrust him." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 3, text: "For froward thoughts separate from God: and his power, when it is tried, reproveth the unwise." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 4, text: "For into a malicious soul wisdom shall not enter; nor dwell in the body that is subject unto sin." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 5, text: "For the holy spirit of discipline will flee deceit, and remove from thoughts that are without understanding, and will not abide when unrighteousness cometh in." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 6, text: "For wisdom is a loving spirit; and will not acquit a blasphemer of his words: for God is witness of his reins, and a true beholder of his heart, and a hearer of his tongue." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 7, text: "For the Spirit of the Lord filleth the world: and that which containeth all things hath knowledge of the voice." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 8, text: "Therefore he that speaketh unrighteous things cannot be hid: neither shall vengeance, when it punisheth, pass by him." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 9, text: "For inquisition shall be made into the counsels of the ungodly: and the sound of his words shall come unto the Lord for the manifestation of his wicked deeds." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 10, text: "For the ear of jealousy heareth all things: and the noise of murmurings is not hid." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 11, text: "Therefore beware of murmuring, which is unprofitable; and refrain your tongue from backbiting: for there is no word so secret, that shall go for nought: and the mouth that belieth slayeth the soul." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 12, text: "Seek not death in the error of your life: and pull not upon yourselves destruction with the works of your hands." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 13, text: "For God made not death: neither hath he pleasure in the destruction of the living." },
  { book: "Wisdom of Solomon", chapter: 1, verse: 14, text: "For he created all things, that they might have their being: and the generations of the world were healthful; and there is no poison of destruction in them, nor the kingdom of death upon the earth:" },
  { book: "Wisdom of Solomon", chapter: 1, verse: 15, text: "(For righteousness is immortal:)" },
  { book: "Wisdom of Solomon", chapter: 1, verse: 16, text: "But ungodly men with their works and words called it to them: for when they thought to have it their friend, they consumed to nought, and made a covenant with it, because they are worthy to take part with it." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 1, text: "For the ungodly said, reasoning with themselves, but not aright, Our life is short and tedious, and in the death of a man there is no remedy: neither was there any man known to have returned from the grave." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 2, text: "For we are born at all adventure: and we shall be hereafter as though we had never been: for the breath in our nostrils is as smoke, and a little spark in the moving of our heart:" },
  { book: "Wisdom of Solomon", chapter: 2, verse: 3, text: "Which being extinguished, our body shall be turned into ashes, and our spirit shall vanish as the soft air," },
  { book: "Wisdom of Solomon", chapter: 2, verse: 4, text: "And our name shall be forgotten in time, and no man shall have our works in remembrance, and our life shall pass away as the trace of a cloud, and shall be dispersed as a mist, that is driven away with the beams of the sun, and overcome with the heat thereof." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 5, text: "For our time is a very shadow that passeth away; and after our end there is no returning: for it is fast sealed, so that no man cometh again." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 6, text: "Come on therefore, let us enjoy the good things that are present: and let us speedily use the creatures like as in youth." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 7, text: "Let us fill ourselves with costly wine and ointments: and let no flower of the spring pass by us:" },
  { book: "Wisdom of Solomon", chapter: 2, verse: 8, text: "Let us crown ourselves with rosebuds, before they be withered:" },
  { book: "Wisdom of Solomon", chapter: 2, verse: 9, text: "Let none of us go without his part of our voluptuousness: let us leave tokens of our joyfulness in every place: for this is our portion, and our lot is this." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 10, text: "Let us oppress the poor righteous man, let us not spare the widow, nor reverence the ancient gray hairs of the aged." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 11, text: "Let our strength be the law of justice: for that which is feeble is found to be nothing worth." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 12, text: "Therefore let us lie in wait for the righteous; because he is not for our turn, and he is clean contrary to our doings: he upbraideth us with our offending the law, and objecteth to our infamy the transgressings of our education." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 13, text: "He professeth to have the knowledge of God: and he calleth himself the child of the Lord." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 14, text: "He was made to reprove our thoughts." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 15, text: "He is grievous unto us even to behold: for his life is not like other men’s, his ways are of another fashion." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 16, text: "We are esteemed of him as counterfeits: he abstaineth from our ways as from filthiness: he pronounceth the end of the just to be blessed, and maketh his boast that God is his father." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 17, text: "Let us see if his words be true: and let us prove what shall happen in the end of him." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 18, text: "For if the just man be the son of God, he will help him, and deliver him from the hand of his enemies." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 19, text: "Let us examine him with despitefulness and torture, that we may know his meekness, and prove his patience." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 20, text: "Let us condemn him with a shameful death: for by his own saying he shall be respected." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 21, text: "Such things they did imagine, and were deceived: for their own wickedness hath blinded them." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 22, text: "As for the mysteries of God, they knew them not: neither hoped they for the wages of righteousness, nor discerned a reward for blameless souls." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 23, text: "For God created man to be immortal, and made him to be an image of his own eternity." },
  { book: "Wisdom of Solomon", chapter: 2, verse: 24, text: "Nevertheless through envy of the devil came death into the world: and they that do hold of his side do find it." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 1, text: "But the souls of the righteous are in the hand of God, and there shall no torment touch them." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 2, text: "In the sight of the unwise they seemed to die: and their departure is taken for misery," },
  { book: "Wisdom of Solomon", chapter: 3, verse: 3, text: "And their going from us to be utter destruction: but they are in peace." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 4, text: "For though they be punished in the sight of men, yet is their hope full of immortality." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 5, text: "And having been a little chastised, they shall be greatly rewarded: for God proved them, and found them worthy for himself." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 6, text: "As gold in the furnace hath he tried them, and received them as a burnt offering." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 7, text: "And in the time of their visitation they shall shine, and run to and fro like sparks among the stubble." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 8, text: "They shall judge the nations, and have dominion over the people, and their Lord shall reign for ever." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 9, text: "They that put their trust in him shall understand the truth: and such as be faithful in love shall abide with him: for grace and mercy is to his saints, and he hath care for his elect." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 10, text: "But the ungodly shall be punished according to their own imaginations, which have neglected the righteous, and forsaken the Lord." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 11, text: "For whoso despiseth wisdom and nurture, he is miserable, and their hope is vain, their labours unfruitful, and their works unprofitable:" },
  { book: "Wisdom of Solomon", chapter: 3, verse: 12, text: "Their wives are foolish, and their children wicked:" },
  { book: "Wisdom of Solomon", chapter: 3, verse: 13, text: "Their offspring is cursed. Wherefore blessed is the barren that is undefiled, which hath not known the sinful bed: she shall have fruit in the visitation of souls." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 14, text: "And blessed is the eunuch, which with his hands hath wrought no iniquity, nor imagined wicked things against God: for unto him shall be given the special gift of faith, and an inheritance in the temple of the Lord more acceptable to his mind." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 15, text: "For glorious is the fruit of good labours: and the root of wisdom shall never fall away." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 16, text: "As for the children of adulterers, they shall not come to their perfection, and the seed of an unrighteous bed shall be rooted out." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 17, text: "For though they live long, yet shall they be nothing regarded: and their last age shall be without honour." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 18, text: "Or, if they die quickly, they have no hope, neither comfort in the day of trial." },
  { book: "Wisdom of Solomon", chapter: 3, verse: 19, text: "For horrible is the end of the unrighteous generation." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 1, text: "Better it is to have no children, and to have virtue: for the memorial thereof is immortal: because it is known with God, and with men." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 2, text: "When it is present, men take example at it; and when it is gone, they desire it: it weareth a crown, and triumpheth for ever, having gotten the victory, striving for undefiled rewards." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 3, text: "But the multiplying brood of the ungodly shall not thrive, nor take deep rooting from bastard slips, nor lay any fast foundation." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 4, text: "For though they flourish in branches for a time; yet standing not last, they shall be shaken with the wind, and through the force of winds they shall be rooted out." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 5, text: "The imperfect branches shall be broken off, their fruit unprofitable, not ripe to eat, yea, meet for nothing." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 6, text: "For children begotten of unlawful beds are witnesses of wickedness against their parents in their trial." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 7, text: "But though the righteous be prevented with death, yet shall he be in rest." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 8, text: "For honourable age is not that which standeth in length of time, nor that is measured by number of years." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 9, text: "But wisdom is the gray hair unto men, and an unspotted life is old age." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 10, text: "He pleased God, and was beloved of him: so that living among sinners he was translated." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 11, text: "Yea speedily was he taken away, lest that wickedness should alter his understanding, or deceit beguile his soul." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 12, text: "For the bewitching of naughtiness doth obscure things that are honest; and the wandering of concupiscence doth undermine the simple mind." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 13, text: "He, being made perfect in a short time, fulfilled a long time:" },
  { book: "Wisdom of Solomon", chapter: 4, verse: 14, text: "For his soul pleased the Lord: therefore hasted he to take him away from among the wicked." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 15, text: "This the people saw, and understood it not, neither laid they up this in their minds, That his grace and mercy is with his saints, and that he hath respect unto his chosen." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 16, text: "Thus the righteous that is dead shall condemn the ungodly which are living; and youth that is soon perfected the many years and old age of the unrighteous." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 17, text: "For they shall see the end of the wise, and shall not understand what God in his counsel hath decreed of him, and to what end the Lord hath set him in safety." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 18, text: "They shall see him, and despise him; but God shall laugh them to scorn: and they shall hereafter be a vile carcase, and a reproach among the dead for evermore." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 19, text: "For he shall rend them, and cast them down headlong, that they shall be speechless; and he shall shake them from the foundation; and they shall be utterly laid waste, and be in sorrow; and their memorial shall perish." },
  { book: "Wisdom of Solomon", chapter: 4, verse: 20, text: "And when they cast up the accounts of their sins, they shall come with fear: and their own iniquities shall convince them to their face." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 1, text: "Then shall the righteous man stand in great boldness before the face of such as have afflicted him, and made no account of his labours." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 2, text: "When they see it, they shall be troubled with terrible fear, and shall be amazed at the strangeness of his salvation, so far beyond all that they looked for." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 3, text: "And they repenting and groaning for anguish of spirit shall say within themselves, This was he, whom we had sometimes in derision, and a proverb of reproach:" },
  { book: "Wisdom of Solomon", chapter: 5, verse: 4, text: "We fools accounted his life madness, and his end to be without honour:" },
  { book: "Wisdom of Solomon", chapter: 5, verse: 5, text: "How is he numbered among the children of God, and his lot is among the saints!" },
  { book: "Wisdom of Solomon", chapter: 5, verse: 6, text: "Therefore have we erred from the way of truth, and the light of righteousness hath not shined unto us, and the sun of righteousness rose not upon us." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 7, text: "We wearied ourselves in the way of wickedness and destruction: yea, we have gone through deserts, where there lay no way: but as for the way of the Lord, we have not known it." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 8, text: "What hath pride profited us? or what good hath riches with our vaunting brought us?" },
  { book: "Wisdom of Solomon", chapter: 5, verse: 9, text: "All those things are passed away like a shadow, and as a post that hasted by;" },
  { book: "Wisdom of Solomon", chapter: 5, verse: 10, text: "And as a ship that passeth over the waves of the water, which when it is gone by, the trace thereof cannot be found, neither the pathway of the keel in the waves;" },
  { book: "Wisdom of Solomon", chapter: 5, verse: 11, text: "Or as when a bird hath flown through the air, there is no token of her way to be found, but the light air being beaten with the stroke of her wings and parted with the violent noise and motion of them, is passed through, and therein afterwards no sign where she went is to be found;" },
  { book: "Wisdom of Solomon", chapter: 5, verse: 12, text: "Or like as when an arrow is shot at a mark, it parteth the air, which immediately cometh together again, so that a man cannot know where it went through:" },
  { book: "Wisdom of Solomon", chapter: 5, verse: 13, text: "Even so we in like manner, as soon as we were born, began to draw to our end, and had no sign of virtue to shew; but were consumed in our own wickedness." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 14, text: "For the hope of the Godly is like dust that is blown away with the wind; like a thin froth that is driven away with the storm; like as the smoke which is dispersed here and there with a tempest, and passeth away as the remembrance of a guest that tarrieth but a day." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 15, text: "But the righteous live for evermore; their reward also is with the Lord, and the care of them is with the most High." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 16, text: "Therefore shall they receive a glorious kingdom, and a beautiful crown from the Lord’s hand: for with his right hand shall he cover them, and with his arm shall he protect them." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 17, text: "He shall take to him his jealousy for complete armour, and make the creature his weapon for the revenge of his enemies." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 18, text: "He shall put on righteousness as a breastplate, and true judgment instead of an helmet." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 19, text: "He shall take holiness for an invincible shield." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 20, text: "His severe wrath shall he sharpen for a sword, and the world shall fight with him against the unwise." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 21, text: "Then shall the right aiming thunderbolts go abroad; and from the clouds, as from a well drawn bow, shall they fly to the mark." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 22, text: "And hailstones full of wrath shall be cast as out of a stone bow, and the water of the sea shall rage against them, and the floods shall cruelly drown them." },
  { book: "Wisdom of Solomon", chapter: 5, verse: 23, text: "Yea, a mighty wind shall stand up against them, and like a storm shall blow them away: thus iniquity shall lay waste the whole earth, and ill dealing shall overthrow the thrones of the mighty." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 1, text: "Hear therefore, O ye kings, and understand; learn, ye that be judges of the ends of the earth." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 2, text: "Give ear, ye that rule the people, and glory in the multitude of nations." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 3, text: "For power is given you of the Lord, and sovereignty from the Highest, who shall try your works, and search out your counsels." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 4, text: "Because, being ministers of his kingdom, ye have not judged aright, nor kept the law, nor walked after the counsel of God;" },
  { book: "Wisdom of Solomon", chapter: 6, verse: 5, text: "Horribly and speedily shall he come upon you: for a sharp judgment shall be to them that be in high places." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 6, text: "For mercy will soon pardon the meanest: but mighty men shall be mightily tormented." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 7, text: "For he which is Lord over all shall fear no man’s person, neither shall he stand in awe of any man’s greatness: for he hath made the small and great, and careth for all alike." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 8, text: "But a sore trial shall come upon the mighty." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 9, text: "Unto you therefore, O kings, do I speak, that ye may learn wisdom, and not fall away." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 10, text: "For they that keep holiness holily shall be judged holy: and they that have learned such things shall find what to answer." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 11, text: "Wherefore set your affection upon my words; desire them, and ye shall be instructed." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 12, text: "Wisdom is glorious, and never fadeth away: yea, she is easily seen of them that love her, and found of such as seek her." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 13, text: "She preventeth them that desire her, in making herself first known unto them." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 14, text: "Whoso seeketh her early shall have no great travail: for he shall find her sitting at his doors." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 15, text: "To think therefore upon her is perfection of wisdom: and whoso watcheth for her shall quickly be without care." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 16, text: "For she goeth about seeking such as are worthy of her, sheweth herself favourably unto them in the ways, and meeteth them in every thought." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 17, text: "For the very true beginning of her is the desire of discipline; and the care of discipline is love;" },
  { book: "Wisdom of Solomon", chapter: 6, verse: 18, text: "And love is the keeping of her laws; and the giving heed unto her laws is the assurance of incorruption;" },
  { book: "Wisdom of Solomon", chapter: 6, verse: 19, text: "And incorruption maketh us near unto God:" },
  { book: "Wisdom of Solomon", chapter: 6, verse: 20, text: "Therefore the desire of wisdom bringeth to a kingdom." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 21, text: "If your delight be then in thrones and sceptres, O ye kings of the people, honour wisdom, that ye may reign for evermore." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 22, text: "As for wisdom, what she is, and how she came up, I will tell you, and will not hide mysteries from you: but will seek her out from the beginning of her nativity, and bring the knowledge of her into light, and will not pass over the truth." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 23, text: "Neither will I go with consuming envy; for such a man shall have no fellowship with wisdom." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 24, text: "But the multitude of the wise is the welfare of the world: and a wise king is the upholding of the people." },
  { book: "Wisdom of Solomon", chapter: 6, verse: 25, text: "Receive therefore instruction through my words, and it shall do you good." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 1, text: "I myself also am a mortal man, like to all, and the offspring of him that was first made of the earth," },
  { book: "Wisdom of Solomon", chapter: 7, verse: 2, text: "And in my mother’s womb was fashioned to be flesh in the time of ten months, being compacted in blood, of the seed of man, and the pleasure that came with sleep." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 3, text: "And when I was born, I drew in the common air, and fell upon the earth, which is of like nature, and the first voice which I uttered was crying, as all others do." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 4, text: "I was nursed in swaddling clothes, and that with cares." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 5, text: "For there is no king that had any other beginning of birth." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 6, text: "For all men have one entrance into life, and the like going out." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 7, text: "Wherefore I prayed, and understanding was given me: I called upon God, and the spirit of wisdom came to me." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 8, text: "I preferred her before sceptres and thrones, and esteemed riches nothing in comparison of her." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 9, text: "Neither compared I unto her any precious stone, because all gold in respect of her is as a little sand, and silver shall be counted as clay before her." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 10, text: "I loved her above health and beauty, and chose to have her instead of light: for the light that cometh from her never goeth out." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 11, text: "All good things together came to me with her, and innumerable riches in her hands." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 12, text: "And I rejoiced in them all, because wisdom goeth before them: and I knew not that she was the mother of them." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 13, text: "I learned diligently, and do communicate her liberally: I do not hide her riches." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 14, text: "For she is a treasure unto men that never faileth: which they that use become the friends of God, being commended for the gifts that come from learning." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 15, text: "God hath granted me to speak as I would, and to conceive as is meet for the things that are given me: because it is he that leadeth unto wisdom, and directeth the wise." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 16, text: "For in his hand are both we and our words; all wisdom also, and knowledge of workmanship." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 17, text: "For he hath given me certain knowledge of the things that are, namely, to know how the world was made, and the operation of the elements:" },
  { book: "Wisdom of Solomon", chapter: 7, verse: 18, text: "The beginning, ending, and midst of the times: the alterations of the turning of the sun, and the change of seasons:" },
  { book: "Wisdom of Solomon", chapter: 7, verse: 19, text: "The circuits of years, and the positions of stars:" },
  { book: "Wisdom of Solomon", chapter: 7, verse: 20, text: "The natures of living creatures, and the furies of wild beasts: the violence of winds, and the reasonings of men: the diversities of plants and the virtues of roots:" },
  { book: "Wisdom of Solomon", chapter: 7, verse: 21, text: "And all such things as are either secret or manifest, them I know." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 22, text: "For wisdom, which is the worker of all things, taught me: for in her is an understanding spirit holy, one only, manifold, subtil, lively, clear, undefiled, plain, not subject to hurt, loving the thing that is good quick, which cannot be letted, ready to do good," },
  { book: "Wisdom of Solomon", chapter: 7, verse: 23, text: "Kind to man, steadfast, sure, free from care, having all power, overseeing all things, and going through all understanding, pure, and most subtil, spirits." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 24, text: "For wisdom is more moving than any motion: she passeth and goeth through all things by reason of her pureness." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 25, text: "For she is the breath of the power of God, and a pure influence flowing from the glory of the Almighty: therefore can no defiled thing fall into her." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 26, text: "For she is the brightness of the everlasting light, the unspotted mirror of the power of God, and the image of his goodness." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 27, text: "And being but one, she can do all things: and remaining in herself, she maketh all things new: and in all ages entering into holy souls, she maketh them friends of God, and prophets." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 28, text: "For God loveth none but him that dwelleth with wisdom." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 29, text: "For she is more beautiful than the sun, and above all the order of stars: being compared with the light, she is found before it." },
  { book: "Wisdom of Solomon", chapter: 7, verse: 30, text: "For after this cometh night: but vice shall not prevail against wisdom." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 1, text: "Wisdom reacheth from one end to another mightily: and sweetly doth she order all things." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 2, text: "I loved her, and sought her out from my youth, I desired to make her my spouse, and I was a lover of her beauty." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 3, text: "In that she is conversant with God, she magnifieth her nobility: yea, the Lord of all things himself loved her." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 4, text: "For she is privy to the mysteries of the knowledge of God, and a lover of his works." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 5, text: "If riches be a possession to be desired in this life; what is richer than wisdom, that worketh all things?" },
  { book: "Wisdom of Solomon", chapter: 8, verse: 6, text: "And if prudence work; who of all that are is a more cunning workman than she?" },
  { book: "Wisdom of Solomon", chapter: 8, verse: 7, text: "And if a man love righteousness her labours are virtues: for she teacheth temperance and prudence, justice and fortitude: which are such things, as men can have nothing more profitable in their life." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 8, text: "If a man desire much experience, she knoweth things of old, and conjectureth aright what is to come: she knoweth the subtilties of speeches, and can expound dark sentences: she foreseeth signs and wonders, and the events of seasons and times." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 9, text: "Therefore I purposed to take her to me to live with me, knowing that she would be a counsellor of good things, and a comfort in cares and grief." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 10, text: "For her sake I shall have estimation among the multitude, and honour with the elders, though I be young." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 11, text: "I shall be found of a quick conceit in judgment, and shall be admired in the sight of great men." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 12, text: "When I hold my tongue, they shall bide my leisure, and when I speak, they shall give good ear unto me: if I talk much, they shall lay their hands upon their mouth." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 13, text: "Moreover by the means of her I shall obtain immortality, and leave behind me an everlasting memorial to them that come after me." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 14, text: "I shall set the people in order, and the nations shall be subject unto me." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 15, text: "Horrible tyrants shall be afraid, when they do but hear of me; I shall be found good among the multitude, and valiant in war." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 16, text: "After I am come into mine house, I will repose myself with her: for her conversation hath no bitterness; and to live with her hath no sorrow, but mirth and joy." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 17, text: "Now when I considered these things in myself, and pondered them in my heart, how that to be allied unto wisdom is immortality;" },
  { book: "Wisdom of Solomon", chapter: 8, verse: 18, text: "And great pleasure it is to have her friendship; and in the works of her hands are infinite riches; and in the exercise of conference with her, prudence; and in talking with her, a good report; I went about seeking how to take her to me." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 19, text: "For I was a witty child, and had a good spirit." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 20, text: "Yea rather, being good, I came into a body undefiled." },
  { book: "Wisdom of Solomon", chapter: 8, verse: 21, text: "Nevertheless, when I perceived that I could not otherwise obtain her, except God gave her me; and that was a point of wisdom also to know whose gift she was; I prayed unto the Lord, and besought him, and with my whole heart I said," },
  { book: "Wisdom of Solomon", chapter: 9, verse: 1, text: "O God of my fathers, and Lord of mercy, who hast made all things with thy word," },
  { book: "Wisdom of Solomon", chapter: 9, verse: 2, text: "And ordained man through thy wisdom, that he should have dominion over the creatures which thou hast made," },
  { book: "Wisdom of Solomon", chapter: 9, verse: 3, text: "And order the world according to equity and righteousness, and execute judgment with an upright heart:" },
  { book: "Wisdom of Solomon", chapter: 9, verse: 4, text: "Give me wisdom, that sitteth by thy throne; and reject me not from among thy children:" },
  { book: "Wisdom of Solomon", chapter: 9, verse: 5, text: "For I thy servant and son of thine handmaid am a feeble person, and of a short time, and too young for the understanding of judgment and laws." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 6, text: "For though a man be never so perfect among the children of men, yet if thy wisdom be not with him, he shall be nothing regarded." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 7, text: "Thou hast chosen me to be a king of thy people, and a judge of thy sons and daughters:" },
  { book: "Wisdom of Solomon", chapter: 9, verse: 8, text: "Thou hast commanded me to build a temple upon thy holy mount, and an altar in the city wherein thou dwellest, a resemblance of the holy tabernacle, which thou hast prepared from the beginning." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 9, text: "And wisdom was with thee: which knoweth thy works, and was present when thou madest the world, and knew what was acceptable in thy sight, and right in thy commandments." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 10, text: "O send her out of thy holy heavens, and from the throne of thy glory, that being present she may labour with me, that I may know what is pleasing unto thee." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 11, text: "For she knoweth and understandeth all things, and she shall lead me soberly in my doings, and preserve me in her power." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 12, text: "So shall my works be acceptable, and then shall I judge thy people righteously, and be worthy to sit in my father’s seat." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 13, text: "For what man is he that can know the counsel of God? or who can think what the will of the Lord is?" },
  { book: "Wisdom of Solomon", chapter: 9, verse: 14, text: "For the thoughts of mortal men are miserable, and our devices are but uncertain." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 15, text: "For the corruptible body presseth down the soul, and the earthy tabernacle weigheth down the mind that museth upon many things." },
  { book: "Wisdom of Solomon", chapter: 9, verse: 16, text: "And hardly do we guess aright at things that are upon earth, and with labour do we find the things that are before us: but the things that are in heaven who hath searched out?" },
  { book: "Wisdom of Solomon", chapter: 9, verse: 17, text: "And thy counsel who hath known, except thou give wisdom, and send thy Holy Spirit from above?" },
  { book: "Wisdom of Solomon", chapter: 9, verse: 18, text: "For so the ways of them which lived on the earth were reformed, and men were taught the things that are pleasing unto thee, and were saved through wisdom." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 1, text: "She preserved the first formed father of the world, that was created alone, and brought him out of his fall," },
  { book: "Wisdom of Solomon", chapter: 10, verse: 2, text: "And gave him power to rule all things." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 3, text: "But when the unrighteous went away from her in his anger, he perished also in the fury wherewith he murdered his brother." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 4, text: "For whose cause the earth being drowned with the flood, wisdom again preserved it, and directed the course of the righteous in a piece of wood of small value." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 5, text: "Moreover, the nations in their wicked conspiracy being confounded, she found out the righteous, and preserved him blameless unto God, and kept him strong against his tender compassion toward his son." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 6, text: "When the ungodly perished, she delivered the righteous man, who fled from the fire which fell down upon the five cities." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 7, text: "Of whose wickedness even to this day the waste land that smoketh is a testimony, and plants bearing fruit that never come to ripeness: and a standing pillar of salt is a monument of an unbelieving soul." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 8, text: "For regarding not wisdom, they gat not only this hurt, that they knew not the things which were good; but also left behind them to the world a memorial of their foolishness: so that in the things wherein they offended they could not so much as be hid." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 9, text: "But wisdom delivered from pain those that attended upon her." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 10, text: "When the righteous fled from his brother’s wrath she guided him in right paths, shewed him the kingdom of God, and gave him knowledge of holy things, made him rich in his travels, and multiplied the fruit of his labours." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 11, text: "In the covetousness of such as oppressed him she stood by him, and made him rich." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 12, text: "She defended him from his enemies, and kept him safe from those that lay in wait, and in a sore conflict she gave him the victory; that he might know that goodness is stronger than all." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 13, text: "When the righteous was sold, she forsook him not, but delivered him from sin: she went down with him into the pit," },
  { book: "Wisdom of Solomon", chapter: 10, verse: 14, text: "And left him not in bonds, till she brought him the sceptre of the kingdom, and power against those that oppressed him: as for them that had accused him, she shewed them to be liars, and gave him perpetual glory." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 15, text: "She delivered the righteous people and blameless seed from the nation that oppressed them." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 16, text: "She entered into the soul of the servant of the Lord, and withstood dreadful kings in wonders and signs;" },
  { book: "Wisdom of Solomon", chapter: 10, verse: 17, text: "Rendered to the righteous a reward of their labours, guided them in a marvellous way, and was unto them for a cover by day, and a light of stars in the night season;" },
  { book: "Wisdom of Solomon", chapter: 10, verse: 18, text: "Brought them through the Red sea, and led them through much water:" },
  { book: "Wisdom of Solomon", chapter: 10, verse: 19, text: "But she drowned their enemies, and cast them up out of the bottom of the deep." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 20, text: "Therefore the righteous spoiled the ungodly, and praised thy holy name, O Lord, and magnified with one accord thine hand, that fought for them." },
  { book: "Wisdom of Solomon", chapter: 10, verse: 21, text: "For wisdom opened the mouth of the dumb, and made the tongues of them that cannot speak eloquent." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 1, text: "She prospered their works in the hand of the holy prophet." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 2, text: "They went through the wilderness that was not inhabited, and pitched tents in places where there lay no way." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 3, text: "They stood against their enemies, and were avenged of their adversaries." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 4, text: "When they were thirsty, they called upon thee, and water was given them out of the flinty rock, and their thirst was quenched out of the hard stone." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 5, text: "For by what things their enemies were punished, by the same they in their need were benefited." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 6, text: "For instead of a perpetual running river troubled with foul blood," },
  { book: "Wisdom of Solomon", chapter: 11, verse: 7, text: "For a manifest reproof of that commandment, whereby the infants were slain, thou gavest unto them abundance of water by a means which they hoped not for:" },
  { book: "Wisdom of Solomon", chapter: 11, verse: 8, text: "Declaring by that thirst then how thou hadst punished their adversaries." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 9, text: "For when they were tried albeit but in mercy chastised, they knew how the ungodly were judged in wrath and tormented, thirsting in another manner than the just." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 10, text: "For these thou didst admonish and try, as a father: but the other, as a severe king, thou didst condemn and punish." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 11, text: "Whether they were absent or present, they were vexed alike." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 12, text: "For a double grief came upon them, and a groaning for the remembrance of things past." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 13, text: "For when they heard by their own punishments the other to be benefited, they had some feeling of the Lord." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 14, text: "For whom they respected with scorn, when he was long before thrown out at the casting forth of the infants, him in the end, when they saw what came to pass, they admired." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 15, text: "But for the foolish devices of their wickedness, wherewith being deceived they worshipped serpents void of reason, and vile beasts, thou didst send a multitude of unreasonable beasts upon them for vengeance;" },
  { book: "Wisdom of Solomon", chapter: 11, verse: 16, text: "That they might know, that wherewithal a man sinneth, by the same also shall he be punished." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 17, text: "For thy Almighty hand, that made the world of matter without form, wanted not means to send among them a multitude of bears or fierce lions," },
  { book: "Wisdom of Solomon", chapter: 11, verse: 18, text: "Or unknown wild beasts, full of rage, newly created, breathing out either a fiery vapour, or filthy scents of scattered smoke, or shooting horrible sparkles out of their eyes:" },
  { book: "Wisdom of Solomon", chapter: 11, verse: 19, text: "Whereof not only the harm might dispatch them at once, but also the terrible sight utterly destroy them." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 20, text: "Yea, and without these might they have fallen down with one blast, being persecuted of vengeance, and scattered abroad through the breath of thy power: but thou hast ordered all things in measure and number and weight." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 21, text: "For thou canst shew thy great strength at all times when thou wilt; and who may withstand the power of thine arm?" },
  { book: "Wisdom of Solomon", chapter: 11, verse: 22, text: "For the whole world before thee is as a little grain of the balance, yea, as a drop of the morning dew that falleth down upon the earth." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 23, text: "But thou hast mercy upon all; for thou canst do all things, and winkest at the sins of men, because they should amend." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 24, text: "For thou lovest all the things that are, and abhorrest nothing which thou hast made: for never wouldest thou have made any thing, if thou hadst hated it." },
  { book: "Wisdom of Solomon", chapter: 11, verse: 25, text: "And how could any thing have endured, if it had not been thy will? or been preserved, if not called by thee?" },
  { book: "Wisdom of Solomon", chapter: 11, verse: 26, text: "But thou sparest all: for they are thine, O Lord, thou lover of souls." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 1, text: "For thine incorruptible Spirit is in all things." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 2, text: "Therefore chastenest thou them by little and little that offend, and warnest them by putting them in remembrance wherein they have offended, that leaving their wickedness they may believe on thee, O Lord." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 3, text: "For it was thy will to destroy by the hands of our fathers both those old inhabitants of thy holy land," },
  { book: "Wisdom of Solomon", chapter: 12, verse: 4, text: "Whom thou hatedst for doing most odious works of witchcrafts, and wicked sacrifices;" },
  { book: "Wisdom of Solomon", chapter: 12, verse: 5, text: "And also those merciless murderers of children, and devourers of man’s flesh, and the feasts of blood," },
  { book: "Wisdom of Solomon", chapter: 12, verse: 6, text: "With their priests out of the midst of their idolatrous crew, and the parents, that killed with their own hands souls destitute of help:" },
  { book: "Wisdom of Solomon", chapter: 12, verse: 7, text: "That the land, which thou esteemedst above all other, might receive a worthy colony of God’s children." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 8, text: "Nevertheless even those thou sparedst as men, and didst send wasps, forerunners of thine host, to destroy them by little and little." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 9, text: "Not that thou wast unable to bring the ungodly under the hand of the righteous in battle, or to destroy them at once with cruel beasts, or with one rough word:" },
  { book: "Wisdom of Solomon", chapter: 12, verse: 10, text: "But executing thy judgments upon them by little and little, thou gavest them place of repentance, not being ignorant that they were a naughty generation, and that their malice was bred in them, and that their cogitation would never be changed." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 11, text: "For it was a cursed seed from the beginning; neither didst thou for fear of any man give them pardon for those things wherein they sinned." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 12, text: "For who shall say, What hast thou done? or who shall withstand thy judgment? or who shall accuse thee for the nations that perish, whom thou made? or who shall come to stand against thee, to be revenged for the unrighteous men?" },
  { book: "Wisdom of Solomon", chapter: 12, verse: 13, text: "For neither is there any God but thou that careth for all, to whom thou mightest shew that thy judgment is not unright." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 14, text: "Neither shall king or tyrant be able to set his face against thee for any whom thou hast punished." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 15, text: "Forsomuch then as thou art righteous thyself, thou orderest all things righteously: thinking it not agreeable with thy power to condemn him that hath not deserved to be punished." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 16, text: "For thy power is the beginning of righteousness, and because thou art the Lord of all, it maketh thee to be gracious unto all." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 17, text: "For when men will not believe that thou art of a full power, thou shewest thy strength, and among them that know it thou makest their boldness manifest." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 18, text: "But thou, mastering thy power, judgest with equity, and orderest us with great favour: for thou mayest use power when thou wilt." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 19, text: "But by such works hast thou taught thy people that the just man should be merciful, and hast made thy children to be of a good hope that thou givest repentance for sins." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 20, text: "For if thou didst punish the enemies of thy children, and the condemned to death, with such deliberation, giving them time and place, whereby they might be delivered from their malice:" },
  { book: "Wisdom of Solomon", chapter: 12, verse: 21, text: "With how great circumspection didst thou judge thine own sons, unto whose fathers thou hast sworn, and made covenants of good promises?" },
  { book: "Wisdom of Solomon", chapter: 12, verse: 22, text: "Therefore, whereas thou dost chasten us, thou scourgest our enemies a thousand times more, to the intent that, when we judge, we should carefully think of thy goodness, and when we ourselves are judged, we should look for mercy." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 23, text: "Wherefore, whereas men have lived dissolutely and unrighteously, thou hast tormented them with their own abominations." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 24, text: "For they went astray very far in the ways of error, and held them for gods, which even among the beasts of their enemies were despised, being deceived, as children of no understanding." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 25, text: "Therefore unto them, as to children without the use of reason, thou didst send a judgment to mock them." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 26, text: "But they that would not be reformed by that correction, wherein he dallied with them, shall feel a judgment worthy of God." },
  { book: "Wisdom of Solomon", chapter: 12, verse: 27, text: "For, look, for what things they grudged, when they were punished, that is, for them whom they thought to be gods; now being punished in them, when they saw it, they acknowledged him to be the true God, whom before they denied to know: and therefore came extreme damnation upon them." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 1, text: "Surely vain are all men by nature, who are ignorant of God, and could not out of the good things that are seen know him that is: neither by considering the works did they acknowledge the workmaster;" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 2, text: "But deemed either fire, or wind, or the swift air, or the circle of the stars, or the violent water, or the lights of heaven, to be the gods which govern the world." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 3, text: "With whose beauty if they being delighted took them to be gods; let them know how much better the Lord of them is: for the first author of beauty hath created them." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 4, text: "But if they were astonished at their power and virtue, let them understand by them, how much mightier he is that made them." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 5, text: "For by the greatness and beauty of the creatures proportionably the maker of them is seen." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 6, text: "But yet for this they are the less to be blamed: for they peradventure err, seeking God, and desirous to find him." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 7, text: "For being conversant in his works they search him diligently, and believe their sight: because the things are beautiful that are seen." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 8, text: "Howbeit neither are they to be pardoned." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 9, text: "For if they were able to know so much, that they could aim at the world; how did they not sooner find out the Lord thereof?" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 10, text: "But miserable are they, and in dead things is their hope, who call them gods, which are the works of men’s hands, gold and silver, to shew art in, and resemblances of beasts, or a stone good for nothing, the work of an ancient hand." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 11, text: "Now a carpenter that felleth timber, after he hath sawn down a tree meet for the purpose, and taken off all the bark skilfully round about, and hath wrought it handsomely, and made a vessel thereof fit for the service of man’s life;" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 12, text: "And after spending the refuse of his work to dress his meat, hath filled himself;" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 13, text: "And taking the very refuse among those which served to no use, being a crooked piece of wood, and full of knots, hath carved it diligently, when he had nothing else to do, and formed it by the skill of his understanding, and fashioned it to the image of a man;" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 14, text: "Or made it like some vile beast, laying it over with vermilion, and with paint colouring it red, and covering every spot therein;" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 15, text: "And when he had made a convenient room for it, set it in a wall, and made it fast with iron:" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 16, text: "For he provided for it that it might not fall, knowing that it was unable to help itself; for it is an image, and hath need of help:" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 17, text: "Then maketh he prayer for his goods, for his wife and children, and is not ashamed to speak to that which hath no life." },
  { book: "Wisdom of Solomon", chapter: 13, verse: 18, text: "For health he calleth upon that which is weak: for life prayeth to that which is dead; for aid humbly beseecheth that which hath least means to help: and for a good journey he asketh of that which cannot set a foot forward:" },
  { book: "Wisdom of Solomon", chapter: 13, verse: 19, text: "And for gaining and getting, and for good success of his hands, asketh ability to do of him, that is most unable to do any thing." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 1, text: "Again, one preparing himself to sail, and about to pass through the raging waves, calleth upon a piece of wood more rotten than the vessel that carrieth him." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 2, text: "For verily desire of gain devised that, and the workman built it by his skill." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 3, text: "But thy providence, O Father, governeth it: for thou hast made a way in the sea, and a safe path in the waves;" },
  { book: "Wisdom of Solomon", chapter: 14, verse: 4, text: "Shewing that thou canst save from all danger: yea, though a man went to sea without art." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 5, text: "Nevertheless thou wouldest not that the works of thy wisdom should be idle, and therefore do men commit their lives to a small piece of wood, and passing the rough sea in a weak vessel are saved." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 6, text: "For in the old time also, when the proud giants perished, the hope of the world governed by thy hand escaped in a weak vessel, and left to all ages a seed of generation." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 7, text: "For blessed is the wood whereby righteousness cometh." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 8, text: "But that which is made with hands is cursed, as well it, as he that made it: he, because he made it; and it, because, being corruptible, it was called god." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 9, text: "For the ungodly and his ungodliness are both alike hateful unto God." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 10, text: "For that which is made shall be punished together with him that made it." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 11, text: "Therefore even upon the idols of the Gentiles shall there be a visitation: because in the creature of God they are become an abomination, and stumblingblocks to the souls of men, and a snare to the feet of the unwise." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 12, text: "For the devising of idols was the beginning of spiritual fornication, and the invention of them the corruption of life." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 13, text: "For neither were they from the beginning, neither shall they be for ever." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 14, text: "For by the vain glory of men they entered into the world, and therefore shall they come shortly to an end." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 15, text: "For a father afflicted with untimely mourning, when he hath made an image of his child soon taken away, now honoured him as a god, which was then a dead man, and delivered to those that were under him ceremonies and sacrifices." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 16, text: "Thus in process of time an ungodly custom grown strong was kept as a law, and graven images were worshipped by the commandments of kings." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 17, text: "Whom men could not honour in presence, because they dwelt far off, they took the counterfeit of his visage from far, and made an express image of a king whom they honoured, to the end that by this their forwardness they might flatter him that was absent, as if he were present." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 18, text: "Also the singular diligence of the artificer did help to set forward the ignorant to more superstition." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 19, text: "For he, peradventure willing to please one in authority, forced all his skill to make the resemblance of the best fashion." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 20, text: "And so the multitude, allured by the grace of the work, took him now for a god, which a little before was but honoured." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 21, text: "And this was an occasion to deceive the world: for men, serving either calamity or tyranny, did ascribe unto stones and stocks the incommunicable name." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 22, text: "Moreover this was not enough for them, that they erred in the knowledge of God; but whereas they lived in the great war of ignorance, those so great plagues called they peace." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 23, text: "For whilst they slew their children in sacrifices, or used secret ceremonies, or made revellings of strange rites;" },
  { book: "Wisdom of Solomon", chapter: 14, verse: 24, text: "They kept neither lives nor marriages any longer undefiled: but either one slew another traitorously, or grieved him by adultery." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 25, text: "So that there reigned in all men without exception blood, manslaughter, theft, and dissimulation, corruption, unfaithfulness, tumults, perjury," },
  { book: "Wisdom of Solomon", chapter: 14, verse: 26, text: "Disquieting of good men, forgetfulness of good turns, defiling of souls, changing of kind, disorder in marriages, adultery, and shameless uncleanness." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 27, text: "For the worshipping of idols not to be named is the beginning, the cause, and the end, of all evil." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 28, text: "For either they are mad when they be merry, or prophesy lies, or live unjustly, or else lightly forswear themselves." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 29, text: "For insomuch as their trust is in idols, which have no life; though they swear falsely, yet they look not to be hurt." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 30, text: "Howbeit for both causes shall they be justly punished: both because they thought not well of God, giving heed unto idols, and also unjustly swore in deceit, despising holiness." },
  { book: "Wisdom of Solomon", chapter: 14, verse: 31, text: "For it is not the power of them by whom they swear: but it is the just vengeance of sinners, that punisheth always the offence of the ungodly." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 1, text: "But thou, O God, art gracious and true, longsuffering, and in mercy ordering all things," },
  { book: "Wisdom of Solomon", chapter: 15, verse: 2, text: "For if we sin, we are thine, knowing thy power: but we will not sin, knowing that we are counted thine." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 3, text: "For to know thee is perfect righteousness: yea, to know thy power is the root of immortality." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 4, text: "For neither did the mischievous invention of men deceive us, nor an image spotted with divers colours, the painter’s fruitless labour;" },
  { book: "Wisdom of Solomon", chapter: 15, verse: 5, text: "The sight whereof enticeth fools to lust after it, and so they desire the form of a dead image, that hath no breath." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 6, text: "Both they that make them, they that desire them, and they that worship them, are lovers of evil things, and are worthy to have such things to trust upon." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 7, text: "For the potter, tempering soft earth, fashioneth every vessel with much labour for our service: yea, of the same clay he maketh both the vessels that serve for clean uses, and likewise also all such as serve to the contrary: but what is the use of either sort, the potter himself is the judge." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 8, text: "And employing his labours lewdly, he maketh a vain god of the same clay, even he which a little before was made of earth himself, and within a little while after returneth to the same, out when his life which was lent him shall be demanded." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 9, text: "Notwithstanding his care is, not that he shall have much labour, nor that his life is short: but striveth to excel goldsmiths and silversmiths, and endeavoureth to do like the workers in brass, and counteth it his glory to make counterfeit things." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 10, text: "His heart is ashes, his hope is more vile than earth, and his life of less value than clay:" },
  { book: "Wisdom of Solomon", chapter: 15, verse: 11, text: "Forasmuch as he knew not his Maker, and him that inspired into him an active soul, and breathed in a living spirit." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 12, text: "But they counted our life a pastime, and our time here a market for gain: for, say they, we must be getting every way, though it be by evil means." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 13, text: "For this man, that of earthly matter maketh brittle vessels and graven images, knoweth himself to offend above all others." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 14, text: "And all the enemies of thy people, that hold them in subjection, are most foolish, and are more miserable than very babes." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 15, text: "For they counted all the idols of the heathen to be gods: which neither have the use of eyes to see, nor noses to draw breath, nor ears to hear, nor fingers of hands to handle; and as for their feet, they are slow to go." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 16, text: "For man made them, and he that borrowed his own spirit fashioned them: but no man can make a god like unto himself." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 17, text: "For being mortal, he worketh a dead thing with wicked hands: for he himself is better than the things which he worshippeth: whereas he lived once, but they never." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 18, text: "Yea, they worshipped those beasts also that are most hateful: for being compared together, some are worse than others." },
  { book: "Wisdom of Solomon", chapter: 15, verse: 19, text: "Neither are they beautiful, so much as to be desired in respect of beasts: but they went without the praise of God and his blessing." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 1, text: "Therefore by the like were they punished worthily, and by the multitude of beasts tormented." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 2, text: "Instead of which punishment, dealing graciously with thine own people, thou preparedst for them meat of a strange taste, even quails to stir up their appetite:" },
  { book: "Wisdom of Solomon", chapter: 16, verse: 3, text: "To the end that they, desiring food, might for the ugly sight of the beasts sent among them lothe even that, which they must needs desire; but these, suffering penury for a short space, might be made partakers of a strange taste." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 4, text: "For it was requisite, that upon them exercising tyranny should come penury, which they could not avoid: but to these it should only be shewed how their enemies were tormented." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 5, text: "For when the horrible fierceness of beasts came upon these, and they perished with the stings of crooked serpents, thy wrath endured not for ever:" },
  { book: "Wisdom of Solomon", chapter: 16, verse: 6, text: "But they were troubled for a small season, that they might be admonished, having a sign of salvation, to put them in remembrance of the commandment of thy law." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 7, text: "For he that turned himself toward it was not saved by the thing that he saw, but by thee, that art the Saviour of all." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 8, text: "And in this thou madest thine enemies confess, that it is thou who deliverest from all evil:" },
  { book: "Wisdom of Solomon", chapter: 16, verse: 9, text: "For them the bitings of grasshoppers and flies killed, neither was there found any remedy for their life: for they were worthy to be punished by such." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 10, text: "But thy sons not the very teeth of venomous dragons overcame: for thy mercy was ever by them, and healed them." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 11, text: "For they were pricked, that they should remember thy words; and were quickly saved, that not falling into deep forgetfulness, they might be continually mindful of thy goodness." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 12, text: "For it was neither herb, nor mollifying plaister, that restored them to health: but thy word, O Lord, which healeth all things." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 13, text: "For thou hast power of life and death: thou leadest to the gates of hell, and bringest up again." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 14, text: "A man indeed killeth through his malice: and the spirit, when it is gone forth, returneth not; neither the soul received up cometh again." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 15, text: "But it is not possible to escape thine hand." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 16, text: "For the ungodly, that denied to know thee, were scourged by the strength of thine arm: with strange rains, hails, and showers, were they persecuted, that they could not avoid, and through fire were they consumed." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 17, text: "For, which is most to be wondered at, the fire had more force in the water, that quencheth all things: for the world fighteth for the righteous." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 18, text: "For sometime the flame was mitigated, that it might not burn up the beasts that were sent against the ungodly; but themselves might see and perceive that they were persecuted with the judgment of God." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 19, text: "And at another time it burneth even in the midst of water above the power of fire, that it might destroy the fruits of an unjust land." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 20, text: "Instead whereof thou feddest thine own people with angels’ food, and didst send them from heaven bread prepared without their labour, able to content every man’s delight, and agreeing to every taste." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 21, text: "For thy sustenance declared thy sweetness unto thy children, and serving to the appetite of the eater, tempered itself to every man’s liking." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 22, text: "But snow and ice endured the fire, and melted not, that they might know that fire burning in the hail, and sparkling in the rain, did destroy the fruits of the enemies." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 23, text: "But this again did even forget his own strength, that the righteous might be nourished." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 24, text: "For the creature that serveth thee, who art the Maker increaseth his strength against the unrighteous for their punishment, and abateth his strength for the benefit of such as put their trust in thee." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 25, text: "Therefore even then was it altered into all fashions, and was obedient to thy grace, that nourisheth all things, according to the desire of them that had need:" },
  { book: "Wisdom of Solomon", chapter: 16, verse: 26, text: "That thy children, O Lord, whom thou lovest, might know, that it is not the growing of fruits that nourisheth man: but that it is thy word, which preserveth them that put their trust in thee." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 27, text: "For that which was not destroyed of the fire, being warmed with a little sunbeam, soon melted away:" },
  { book: "Wisdom of Solomon", chapter: 16, verse: 28, text: "That it might be known, that we must prevent the sun to give thee thanks, and at the dayspring pray unto thee." },
  { book: "Wisdom of Solomon", chapter: 16, verse: 29, text: "For the hope of the unthankful shall melt away as the winter’s hoar frost, and shall run away as unprofitable water." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 1, text: "For great are thy judgments, and cannot be expressed: therefore unnurtured souls have erred." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 2, text: "For when unrighteous men thought to oppress the holy nation; they being shut up in their houses, the prisoners of darkness, and fettered with the bonds of a long night, lay there exiled from the eternal providence." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 3, text: "For while they supposed to lie hid in their secret sins, they were scattered under a dark veil of forgetfulness, being horribly astonished, and troubled with strange apparitions." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 4, text: "For neither might the corner that held them keep them from fear: but noises as of waters falling down sounded about them, and sad visions appeared unto them with heavy countenances." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 5, text: "No power of the fire might give them light: neither could the bright flames of the stars endure to lighten that horrible night." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 6, text: "Only there appeared unto them a fire kindled of itself, very dreadful: for being much terrified, they thought the things which they saw to be worse than the sight they saw not." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 7, text: "As for the illusions of art magick, they were put down, and their vaunting in wisdom was reproved with disgrace." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 8, text: "For they, that promised to drive away terrors and troubles from a sick soul, were sick themselves of fear, worthy to be laughed at." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 9, text: "For though no terrible thing did fear them; yet being scared with beasts that passed by, and hissing of serpents," },
  { book: "Wisdom of Solomon", chapter: 17, verse: 10, text: "They died for fear, denying that they saw the air, which could of no side be avoided." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 11, text: "For wickedness, condemned by her own witness, is very timorous, and being pressed with conscience, always forecasteth grievous things." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 12, text: "For fear is nothing else but a betraying of the succours which reason offereth." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 13, text: "And the expectation from within, being less, counteth the ignorance more than the cause which bringeth the torment." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 14, text: "But they sleeping the same sleep that night, which was indeed intolerable, and which came upon them out of the bottoms of inevitable hell," },
  { book: "Wisdom of Solomon", chapter: 17, verse: 15, text: "Were partly vexed with monstrous apparitions, and partly fainted, their heart failing them: for a sudden fear, and not looked for, came upon them." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 16, text: "So then whosoever there fell down was straitly kept, shut up in a prison without iron bars," },
  { book: "Wisdom of Solomon", chapter: 17, verse: 17, text: "For whether he were husbandman, or shepherd, or a labourer in the field, he was overtaken, and endured that necessity, which could not be avoided: for they were all bound with one chain of darkness." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 18, text: "Whether it were a whistling wind, or a melodious noise of birds among the spreading branches, or a pleasing fall of water running violently," },
  { book: "Wisdom of Solomon", chapter: 17, verse: 19, text: "Or a terrible sound of stones cast down, or a running that could not be seen of skipping beasts, or a roaring voice of most savage wild beasts, or a rebounding echo from the hollow mountains; these things made them to swoon for fear." },
  { book: "Wisdom of Solomon", chapter: 17, verse: 20, text: "For the whole world shined with clear light, and none were hindered in their labour:" },
  { book: "Wisdom of Solomon", chapter: 17, verse: 21, text: "Over them only was spread an heavy night, an image of that darkness which should afterward receive them: but yet were they unto themselves more grievous than the darkness." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 1, text: "Nevertheless thy saints had a very great light, whose voice they hearing, and not seeing their shape, because they also had not suffered the same things, they counted them happy." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 2, text: "But for that they did not hurt them now, of whom they had been wronged before, they thanked them, and besought them pardon for that they had been enemies." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 3, text: "Instead whereof thou gavest them a burning pillar of fire, both to be a guide of the unknown journey, and an harmless sun to entertain them honourably." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 4, text: "For they were worthy to be deprived of light and imprisoned in darkness, who had kept thy sons shut up, by whom the uncorrupt light of the law was to be given unto the world." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 5, text: "And when they had determined to slay the babes of the saints, one child being cast forth, and saved, to reprove them, thou tookest away the multitude of their children, and destroyedst them altogether in a mighty water." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 6, text: "Of that night were our fathers certified afore, that assuredly knowing unto what oaths they had given credence, they might afterwards be of good cheer." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 7, text: "So of thy people was accepted both the salvation of the righteous, and destruction of the enemies." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 8, text: "For wherewith thou didst punish our adversaries, by the same thou didst glorify us, whom thou hadst called." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 9, text: "For the righteous children of good men did sacrifice secretly, and with one consent made a holy law, that the saints should be like partakers of the same good and evil, the fathers now singing out the songs of praise." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 10, text: "But on the other side there sounded an ill according cry of the enemies, and a lamentable noise was carried abroad for children that were bewailed." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 11, text: "The master and the servant were punished after one manner; and like as the king, so suffered the common person." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 12, text: "So they all together had innumerable dead with one kind of death; neither were the living sufficient to bury them: for in one moment the noblest offspring of them was destroyed." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 13, text: "For whereas they would not believe any thing by reason of the enchantments; upon the destruction of the firstborn, they acknowledged this people to be the sons of God." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 14, text: "For while all things were in quiet silence, and that night was in the midst of her swift course," },
  { book: "Wisdom of Solomon", chapter: 18, verse: 15, text: "Thine Almighty word leaped down from heaven out of thy royal throne, as a fierce man of war into the midst of a land of destruction," },
  { book: "Wisdom of Solomon", chapter: 18, verse: 16, text: "And brought thine unfeigned commandment as a sharp sword, and standing up filled all things with death; and it touched the heaven, but it stood upon the earth." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 17, text: "Then suddenly visions of horrible dreams troubled them sore, and terrors came upon them unlooked for." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 18, text: "And one thrown here, and another there, half dead, shewed the cause of his death." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 19, text: "For the dreams that troubled them did foreshew this, lest they should perish, and not know why they were afflicted." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 20, text: "Yea, the tasting of death touched the righteous also, and there was a destruction of the multitude in the wilderness: but the wrath endured not long." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 21, text: "For then the blameless man made haste, and stood forth to defend them; and bringing the shield of his proper ministry, even prayer, and the propitiation of incense, set himself against the wrath, and so brought the calamity to an end, declaring that he was thy servant." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 22, text: "So he overcame the destroyer, not with strength of body, nor force of arms, but with a word subdued him that punished, alleging the oaths and covenants made with the fathers." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 23, text: "For when the dead were now fallen down by heaps one upon another, standing between, he stayed the wrath, and parted the way to the living." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 24, text: "For in the long garment was the whole world, and in the four rows of the stones was the glory of the fathers graven, and thy Majesty upon the diadem of his head." },
  { book: "Wisdom of Solomon", chapter: 18, verse: 25, text: "Unto these the destroyer gave place, and was afraid of them: for it was enough that they only tasted of the wrath." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 1, text: "As for the ungodly, wrath came upon them without mercy unto the end: for he knew before what they would do;" },
  { book: "Wisdom of Solomon", chapter: 19, verse: 2, text: "How that having given them leave to depart, and sent them hastily away, they would repent and pursue them." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 3, text: "For whilst they were yet mourning and making lamentation at the graves of the dead, they added another foolish device, and pursued them as fugitives, whom they had intreated to be gone." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 4, text: "For the destiny, whereof they were worthy, drew them unto this end, and made them forget the things that had already happened, that they might fulfil the punishment which was wanting to their torments:" },
  { book: "Wisdom of Solomon", chapter: 19, verse: 5, text: "And that thy people might pass a wonderful way: but they might find a strange death." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 6, text: "For the whole creature in his proper kind was fashioned again anew, serving the peculiar commandments that were given unto them, that thy children might be kept without hurt:" },
  { book: "Wisdom of Solomon", chapter: 19, verse: 7, text: "As namely, a cloud shadowing the camp; and where water stood before, dry land appeared; and out of the Red sea a way without impediment; and out of the violent stream a green field:" },
  { book: "Wisdom of Solomon", chapter: 19, verse: 8, text: "Wherethrough all the people went that were defended with thy hand, seeing thy marvellous strange wonders." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 9, text: "For they went at large like horses, and leaped like lambs, praising thee, O Lord, who hadst delivered them." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 10, text: "For they were yet mindful of the things that were done while they sojourned in the strange land, how the ground brought forth flies instead of cattle, and how the river cast up a multitude of frogs instead of fishes." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 11, text: "But afterwards they saw a new generation of fowls, when, being led with their appetite, they asked delicate meats." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 12, text: "For quails came up unto them from the sea for their contentment." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 13, text: "And punishments came upon the sinners not without former signs by the force of thunders: for they suffered justly according to their own wickedness, insomuch as they used a more hard and hateful behaviour toward strangers." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 14, text: "For the Sodomites did not receive those, whom they knew not when they came: but these brought friends into bondage, that had well deserved of them." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 15, text: "And not only so, but peradventure some respect shall be had of those, because they used strangers not friendly:" },
  { book: "Wisdom of Solomon", chapter: 19, verse: 16, text: "But these very grievously afflicted them, whom they had received with feastings, and were already made partakers of the same laws with them." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 17, text: "Therefore even with blindness were these stricken, as those were at the doors of the righteous man: when, being compassed about with horrible great darkness, every one sought the passage of his own doors." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 18, text: "For the elements were changed in themselves by a kind of harmony, like as in a psaltery notes change the name of the tune, and yet are always sounds; which may well be perceived by the sight of the things that have been done." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 19, text: "For earthly things were turned into watery, and the things, that before swam in the water, now went upon the ground." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 20, text: "The fire had power in the water, forgetting his own virtue: and the water forgat his own quenching nature." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 21, text: "On the other side, the flames wasted not the flesh of the corruptible living things, though they walked therein; neither melted they the icy kind of heavenly meat that was of nature apt to melt." },
  { book: "Wisdom of Solomon", chapter: 19, verse: 22, text: "For in all things, O Lord, thou didst magnify thy people, and glorify them, neither didst thou lightly regard them: but didst assist them in every time and place." },
]
